const WORDS = [{"word":"-weise","en":"suffix forming adverbs of manner (e.g. 'normally', 'fortunately')","ru":"суффикс, образующий наречия образа действия («обычно», «к счастью»)","vi":"-khôn ngoan","fa":"-عاقلانه","examples":[{"de":"Normalerweise stehe ich um sieben Uhr auf.","en":"Normally I get up at seven o'clock.","ru":"Обычно я встаю в семь часов.","vi":"Tôi thường thức dậy lúc bảy giờ.","fa":"من معمولا ساعت هفت بیدار می شوم."},{"de":"Glücklicherweise hat es nicht geregnet.","en":"Fortunately, it didn't rain.","ru":"К счастью, дождя не было.","vi":"May mắn là trời không mưa.","fa":"خوشبختانه باران نبارید."}]},{"word":"der (Back-)Ofen","en":"oven","ru":"духовка; печь","vi":"lò nướng (nướng)","fa":"فر (پخت)","examples":[{"de":"Der Kuchen ist noch im Ofen.","en":"The cake is still in the oven.","ru":"Пирог ещё в духовке.","vi":"Bánh vẫn còn trong lò.","fa":"کیک هنوز در فر است."},{"de":"Heiz den Ofen auf 180 Grad vor.","en":"Preheat the oven to 180 degrees.","ru":"Разогрей духовку до 180 градусов.","vi":"Làm nóng lò ở 180 độ.","fa":"فر را با دمای 180 درجه گرم کنید."}]},{"word":"das (Back-)Rohr","en":"oven","ru":"духовка","vi":"ống (nướng)","fa":"لوله (پخت)","examples":[{"de":"Der Kuchen muss noch 20 Minuten im Backrohr bleiben.","en":"The cake still needs to stay in the oven for 20 minutes.","ru":"Пирог должен ещё 20 минут постоять в духовке.","vi":"Bánh cần để trong lò thêm 20 phút nữa.","fa":"کیک باید 20 دقیقه دیگر در فر بماند."},{"de":"Heiz das Rohr auf 180 Grad vor.","en":"Preheat the oven to 180 degrees.","ru":"Разогрей духовку до 180 градусов.","vi":"Làm nóng ống ở nhiệt độ 180 độ.","fa":"لوله را تا 180 درجه از قبل گرم کنید."}]},{"word":"(ein) paar","en":"a few; a couple of","ru":"несколько; пара","vi":"(a) ít","fa":"(الف) تعداد کمی","examples":[{"de":"Ich brauche noch ein paar Minuten.","en":"I still need a few minutes.","ru":"Мне нужно ещё несколько минут.","vi":"Tôi cần thêm vài phút nữa.","fa":"من به چند دقیقه دیگر نیاز دارم."},{"de":"Wir haben ein paar Freunde eingeladen.","en":"We invited a few friends.","ru":"Мы пригласили несколько друзей.","vi":"Chúng tôi đã mời một vài người bạn.","fa":"چند تا از دوستان را دعوت کردیم."}]},{"word":"die (Schlag-)Sahne/der (Schlag-)Rahm","en":"(whipped) cream","ru":"(взбитые) сливки","vi":"kem/kem (đánh bông)","fa":"خامه/خامه (هم زده).","examples":[{"de":"Auf den Kuchen kommt noch Schlagsahne.","en":"Whipped cream still goes on top of the cake.","ru":"На торт ещё добавляют взбитые сливки.","vi":"Ngoài ra còn có kem tươi trên bánh.","fa":"روی کیک خامه فرم گرفته هم هست."},{"de":"Möchtest du Rahm zu deinem Kaffee?","en":"Would you like cream with your coffee?","ru":"Хочешь сливки к своему кофе?","vi":"Bạn có muốn dùng kem với cà phê không?","fa":"آیا دوست دارید با قهوه خود خامه بخورید؟"}]},{"word":"(sich etwas) aussuchen","en":"to pick out, choose","ru":"выбирать (что-то себе)","vi":"chọn (cái gì đó).","fa":"انتخاب کردن (چیزی).","examples":[{"de":"Sie sucht sich ein schönes Kleid für die Party aus.","en":"She picks out a nice dress for the party.","ru":"Она выбирает себе красивое платье на вечеринку.","vi":"Cô chọn một chiếc váy đẹp cho bữa tiệc.","fa":"او یک لباس زیبا برای مهمانی انتخاب می کند."},{"de":"Such dir aus, welchen Film wir heute sehen wollen.","en":"Choose which movie we want to watch today.","ru":"Выбери, какой фильм мы посмотрим сегодня.","vi":"Hãy chọn bộ phim mà chúng ta muốn xem hôm nay.","fa":"انتخاب کنید کدام فیلم را امروز می خواهیم ببینیم."}]},{"word":"(sich etwas) kaufen","en":"to buy (oneself something)","ru":"покупать (себе что-то)","vi":"mua (cái gì đó).","fa":"خرید (چیزی).","examples":[{"de":"Ich möchte mir ein neues Fahrrad kaufen.","en":"I want to buy myself a new bicycle.","ru":"Я хочу купить себе новый велосипед.","vi":"Tôi muốn mua một chiếc xe đạp mới.","fa":"من می خواهم یک دوچرخه جدید بخرم."},{"de":"Sie hat sich zum Geburtstag ein schönes Kleid gekauft.","en":"She bought herself a nice dress for her birthday.","ru":"Она купила себе красивое платье на день рождения.","vi":"Cô ấy đã mua cho mình một chiếc váy thật đẹp nhân dịp sinh nhật.","fa":"او برای تولدش یک لباس زیبا برای خودش خرید."}]},{"word":"ab","en":"from; off/away","ru":"с; прочь","vi":"tắt","fa":"خاموش","examples":[{"de":"Ab morgen arbeite ich in einem neuen Büro.","en":"From tomorrow, I will work in a new office.","ru":"С завтрашнего дня я буду работать в новом офисе.","vi":"Bắt đầu từ ngày mai tôi sẽ làm việc ở văn phòng mới.","fa":"از فردا در دفتر جدید کار خواهم کرد."},{"de":"Der Knopf ist ab, ich muss ihn wieder annähen.","en":"The button has come off, I have to sew it back on.","ru":"Пуговица оторвалась, мне нужно пришить её обратно.","vi":"Nút bị tắt, tôi phải khâu lại.","fa":"دکمه خاموش است، باید دوباره آن را بدوزم."}]},{"word":"abbiegen","en":"to turn (off)","ru":"поворачивать","vi":"rẽ","fa":"چرخش","examples":[{"de":"An der nächsten Kreuzung müssen Sie links abbiegen.","en":"At the next intersection you have to turn left.","ru":"На следующем перекрёстке вам нужно повернуть налево.","vi":"Ở ngã tư tiếp theo bạn phải rẽ trái.","fa":"در تقاطع بعدی باید به چپ بپیچید."},{"de":"Er ist zu schnell abgebogen und fast gegen den Zaun gefahren.","en":"He turned too fast and almost crashed into the fence.","ru":"Он слишком быстро повернул и чуть не врезался в забор.","vi":"Anh ta quay quá nhanh và suýt tông vào hàng rào.","fa":"خیلی سریع چرخید و نزدیک بود به نرده برخورد کند."}]},{"word":"die Abbildung","en":"illustration; figure","ru":"иллюстрация; рисунок","vi":"hình minh họa","fa":"تصویر","examples":[{"de":"Auf Seite 12 finden Sie eine Abbildung des menschlichen Herzens.","en":"On page 12 you will find an illustration of the human heart.","ru":"На странице 12 вы найдёте иллюстрацию человеческого сердца.","vi":"Ở trang 12 bạn sẽ tìm thấy hình ảnh minh họa về trái tim con người.","fa":"در صفحه 12 تصویری از قلب انسان را خواهید دید."},{"de":"Die Abbildung zeigt, wie das Gerät zusammengebaut wird.","en":"The figure shows how the device is assembled.","ru":"На рисунке показано, как собирается устройство.","vi":"Hình minh họa cho thấy cách lắp ráp thiết bị.","fa":"تصویر نحوه مونتاژ دستگاه را نشان می دهد."}]},{"word":"das Abenteuer","en":"adventure","ru":"приключение","vi":"cuộc phiêu lưu","fa":"ماجراجویی","examples":[{"de":"Die Reise durch den Regenwald war ein echtes Abenteuer.","en":"The trip through the rainforest was a real adventure.","ru":"Путешествие по тропическому лесу было настоящим приключением.","vi":"Cuộc hành trình xuyên rừng nhiệt đới là một cuộc phiêu lưu thực sự.","fa":"سفر در جنگل های بارانی یک ماجراجویی واقعی بود."},{"de":"Kinder lieben Geschichten voller Abenteuer.","en":"Children love stories full of adventure.","ru":"Дети любят истории, полные приключений.","vi":"Trẻ em thích những câu chuyện đầy phiêu lưu.","fa":"کودکان داستان های پر از ماجراجویی را دوست دارند."}]},{"word":"aber","en":"but","ru":"но","vi":"nhưng","fa":"اما","examples":[{"de":"Ich wollte kommen, aber ich hatte keine Zeit.","en":"I wanted to come, but I had no time.","ru":"Я хотел прийти, но у меня не было времени.","vi":"Tôi muốn đến nhưng không có thời gian.","fa":"می خواستم بیام ولی وقت نکردم."},{"de":"Das Kleid ist schön, aber sehr teuer.","en":"The dress is beautiful, but very expensive.","ru":"Платье красивое, но очень дорогое.","vi":"Chiếc váy rất đẹp nhưng rất đắt.","fa":"لباسش قشنگه ولی خیلی گرونه"}]},{"word":"abfahren","en":"to depart, to leave","ru":"отправляться, уезжать","vi":"khởi hành","fa":"رفتن","examples":[{"de":"Der Zug fährt um acht Uhr ab.","en":"The train departs at eight o'clock.","ru":"Поезд отправляется в восемь часов.","vi":"Tàu khởi hành lúc tám giờ.","fa":"قطار ساعت هشت حرکت می کند."},{"de":"Wir müssen früh abfahren, um den Stau zu vermeiden.","en":"We have to leave early to avoid the traffic jam.","ru":"Нам нужно выехать рано, чтобы избежать пробки.","vi":"Chúng tôi phải đi sớm để tránh ùn tắc giao thông.","fa":"برای جلوگیری از ترافیک باید زودتر حرکت کنیم."}]},{"word":"die Abfahrt","en":"departure","ru":"отправление, отъезд","vi":"sự ra đi","fa":"خروج","examples":[{"de":"Die Abfahrt des Busses verzögert sich um zehn Minuten.","en":"The bus's departure is delayed by ten minutes.","ru":"Отправление автобуса задерживается на десять минут.","vi":"Chuyến xe buýt khởi hành bị trễ mười phút.","fa":"حرکت اتوبوس ده دقیقه تاخیر دارد."},{"de":"Bitte seien Sie eine Stunde vor Abfahrt am Bahnhof.","en":"Please be at the station one hour before departure.","ru":"Пожалуйста, будьте на вокзале за час до отправления.","vi":"Vui lòng có mặt tại nhà ga một giờ trước khi khởi hành.","fa":"لطفا یک ساعت قبل از حرکت در ایستگاه حضور داشته باشید."}]},{"word":"der Abfall","en":"waste; garbage","ru":"мусор, отходы","vi":"sự lãng phí","fa":"زباله","examples":[{"de":"Bitte werfen Sie den Abfall in die richtige Tonne.","en":"Please throw the waste into the correct bin.","ru":"Пожалуйста, выбрасывайте мусор в правильный контейнер.","vi":"Hãy vứt rác vào đúng thùng rác.","fa":"لطفا زباله ها را در سطل مناسب بریزید."},{"de":"In der Küche produzieren wir jeden Tag viel Abfall.","en":"In the kitchen we produce a lot of waste every day.","ru":"На кухне мы каждый день производим много отходов.","vi":"Chúng ta thải ra rất nhiều rác thải trong nhà bếp mỗi ngày.","fa":"ما روزانه زباله های زیادی در آشپزخانه تولید می کنیم."}]},{"word":"Abgase","en":"exhaust fumes","ru":"выхлопные газы","vi":"Khí thải","fa":"دود اگزوز","examples":[{"de":"Die Abgase der Autos verschmutzen die Luft in der Stadt.","en":"The exhaust fumes from cars pollute the air in the city.","ru":"Выхлопные газы автомобилей загрязняют воздух в городе.","vi":"Khí thải từ ô tô gây ô nhiễm không khí trong thành phố.","fa":"دود اگزوز خودروها هوای شهر را آلوده می کند."},{"de":"Neue Motoren produzieren weniger Abgase als alte.","en":"New engines produce fewer exhaust fumes than old ones.","ru":"Новые двигатели производят меньше выхлопных газов, чем старые.","vi":"Động cơ mới tạo ra ít khí thải hơn động cơ cũ.","fa":"موتورهای جدید گازهای خروجی کمتری نسبت به موتورهای قدیمی تولید می کنند."}]},{"word":"abgeben","en":"to hand in; to give away","ru":"сдавать, отдавать","vi":"cho đi","fa":"بخشید","examples":[{"de":"Ich muss meine Hausaufgabe bis Freitag abgeben.","en":"I have to hand in my homework by Friday.","ru":"Мне нужно сдать домашнее задание до пятницы.","vi":"Tôi phải nộp bài tập về nhà trước thứ Sáu.","fa":"تا جمعه باید تکالیفم را تحویل بدهم."},{"de":"Er hat sein altes Fahrrad an seinen Bruder abgegeben.","en":"He gave his old bike away to his brother.","ru":"Он отдал свой старый велосипед брату.","vi":"Anh ấy đã tặng chiếc xe đạp cũ của mình cho anh trai mình.","fa":"دوچرخه قدیمی خود را به برادرش داد."}]},{"word":"abhängen","en":"to depend (on)","ru":"зависеть (от)","vi":"phụ thuộc","fa":"بستگی دارد","examples":[{"de":"Es hängt vom Wetter ab, ob wir grillen.","en":"It depends on the weather whether we barbecue.","ru":"Это зависит от погоды, будем ли мы жарить на гриле.","vi":"Nó phụ thuộc vào thời tiết cho dù chúng ta nướng.","fa":"به آب و هوا بستگی دارد که کباب کنیم."},{"de":"Der Preis hängt von der Menge ab.","en":"The price depends on the quantity.","ru":"Цена зависит от количества.","vi":"Giá cả phụ thuộc vào số lượng.","fa":"قیمت بستگی به مقدار دارد."}]},{"word":"abheben","en":"to withdraw (money); to take off","ru":"снимать (деньги); взлетать","vi":"cất cánh","fa":"برخاستن","examples":[{"de":"Ich möchte 100 Euro von meinem Konto abheben.","en":"I would like to withdraw 100 euros from my account.","ru":"Я хочу снять 100 евро со своего счёта.","vi":"Tôi muốn rút 100 euro từ tài khoản của mình.","fa":"من می خواهم 100 یورو از حسابم برداشت کنم."},{"de":"Das Flugzeug hebt in zehn Minuten ab.","en":"The plane takes off in ten minutes.","ru":"Самолёт взлетает через десять минут.","vi":"Máy bay sẽ cất cánh trong mười phút nữa.","fa":"هواپیما ده دقیقه دیگر بلند می شود."}]},{"word":"abholen","en":"to pick up, to collect","ru":"забирать","vi":"nhặt lên","fa":"برداشتن","examples":[{"de":"Kannst du mich später vom Bahnhof abholen?","en":"Can you pick me up from the station later?","ru":"Ты можешь забрать меня позже с вокзала?","vi":"Bạn có thể đón tôi từ ga xe lửa sau được không?","fa":"آیا می توانید بعداً مرا از ایستگاه قطار ببرید؟"},{"de":"Ich muss das Paket bei der Post abholen.","en":"I have to pick up the package at the post office.","ru":"Мне нужно забрать посылку на почте.","vi":"Tôi phải nhận gói hàng ở bưu điện.","fa":"باید بسته را از اداره پست تحویل بگیرم."}]},{"word":"das Abitur","en":"school-leaving exam (German equivalent of A-levels)","ru":"аттестат зрелости, выпускной экзамен","vi":"bằng tốt nghiệp trung học","fa":"دیپلم دبیرستان","examples":[{"de":"Nächstes Jahr macht meine Schwester ihr Abitur.","en":"Next year my sister will take her Abitur (final exam).","ru":"В следующем году моя сестра сдаёт выпускные экзамены.","vi":"Em gái tôi sẽ tốt nghiệp trung học vào năm tới.","fa":"خواهرم سال آینده از دبیرستان فارغ التحصیل می شود."},{"de":"Ohne Abitur kann man in Deutschland nicht an der Universität studieren.","en":"Without the Abitur you cannot study at university in Germany.","ru":"Без аттестата зрелости нельзя учиться в университете в Германии.","vi":"Bạn không thể học đại học ở Đức nếu không có bằng tốt nghiệp trung học.","fa":"شما نمی توانید در آلمان بدون دیپلم دبیرستان در دانشگاه تحصیل کنید."}]},{"word":"ablehnen","en":"to reject, to decline","ru":"отклонять, отказывать","vi":"từ chối","fa":"رد کردن","examples":[{"de":"Die Firma hat meine Bewerbung abgelehnt.","en":"The company rejected my application.","ru":"Компания отклонила моё заявление.","vi":"Công ty đã từ chối đơn đăng ký của tôi.","fa":"شرکت درخواست من را رد کرد."},{"de":"Er hat die Einladung zur Party abgelehnt.","en":"He declined the invitation to the party.","ru":"Он отклонил приглашение на вечеринку.","vi":"Anh ấy đã từ chối lời mời tới bữa tiệc.","fa":"او دعوت به مهمانی را رد کرد."}]},{"word":"abmachen","en":"to agree on; to remove","ru":"договариваться; снимать","vi":"giải quyết","fa":"حل و فصل شود","examples":[{"de":"Wir haben abgemacht, uns um sechs Uhr zu treffen.","en":"We agreed to meet at six o'clock.","ru":"Мы договорились встретиться в шесть часов.","vi":"Chúng tôi đồng ý gặp nhau lúc sáu giờ.","fa":"قرار گذاشتیم که ساعت شش همدیگر را ببینیم."},{"de":"Kannst du das Preisschild vom Geschenk abmachen?","en":"Can you remove the price tag from the gift?","ru":"Можешь снять ценник с подарка?","vi":"Bạn có thể lấy bảng giá ra khỏi món quà được không?","fa":"آیا می توانید برچسب قیمت را از روی هدیه بردارید؟"}]},{"word":"die Abmeldung","en":"deregistration; cancellation","ru":"снятие с учёта; отмена регистрации","vi":"việc hủy đăng ký","fa":"لغو ثبت نام","examples":[{"de":"Vor dem Wegzug ist eine Abmeldung nötig.","en":"Before moving away, deregistration is required.","ru":"Перед отъездом нужно сняться с учёта.","vi":"Bạn phải hủy đăng ký trước khi chuyển đi.","fa":"قبل از حرکت باید از ثبت نام خارج شوید."},{"de":"Die Abmeldung vom Newsletter geht ganz einfach.","en":"Unsubscribing from the newsletter is very easy.","ru":"Отписаться от рассылки очень просто.","vi":"Việc hủy đăng ký nhận bản tin rất dễ dàng.","fa":"لغو اشتراک از خبرنامه بسیار آسان است."}]},{"word":"abnehmen","en":"to lose weight; to take off/decrease","ru":"худеть; снимать; уменьшаться","vi":"giảm cân","fa":"کاهش وزن","examples":[{"de":"Sie hat in den letzten Monaten fünf Kilo abgenommen.","en":"She has lost five kilos in the last few months.","ru":"За последние месяцы она похудела на пять килограммов.","vi":"Cô ấy đã giảm được 5 kg trong vài tháng qua.","fa":"او در چند ماه گذشته پنج کیلو وزن کم کرده است."},{"de":"Die Temperaturen nehmen im Herbst langsam ab.","en":"Temperatures slowly decrease in autumn.","ru":"Осенью температура постепенно снижается.","vi":"Nhiệt độ giảm dần vào mùa thu.","fa":"دمای هوا در پاییز به آرامی کاهش می یابد."}]},{"word":"das Abonnement","en":"subscription","ru":"подписка, абонемент","vi":"đăng ký","fa":"اشتراک","examples":[{"de":"Mein Abonnement für die Zeitschrift läuft im Dezember ab.","en":"My subscription to the magazine expires in December.","ru":"Моя подписка на журнал заканчивается в декабре.","vi":"Việc đăng ký tạp chí của tôi sẽ hết hạn vào tháng 12.","fa":"اشتراک من در این مجله در ماه دسامبر به پایان می رسد."},{"de":"Wir haben ein Abonnement für das Theater gekauft.","en":"We bought a subscription for the theater.","ru":"Мы купили абонемент в театр.","vi":"Chúng tôi đã mua đăng ký xem rạp.","fa":"ما اشتراک تئاتر خریدیم."}]},{"word":"abonnieren","en":"to subscribe","ru":"подписываться","vi":"đăng ký","fa":"مشترک شوید","examples":[{"de":"Ich habe die Tageszeitung abonniert.","en":"I have subscribed to the daily newspaper.","ru":"Я подписался на ежедневную газету.","vi":"Tôi đã đặt mua dài hạn tờ báo hàng ngày.","fa":"من مشترک روزنامه روزانه شده ام."},{"de":"Viele Leute abonnieren heute Streaming-Dienste statt Zeitschriften.","en":"Many people today subscribe to streaming services instead of magazines.","ru":"Сегодня многие подписываются на стриминговые сервисы вместо журналов.","vi":"Ngày nay nhiều người đăng ký dịch vụ phát trực tuyến thay vì tạp chí.","fa":"امروزه بسیاری از مردم به جای مجلات، مشترک خدمات پخش جریانی می شوند."}]},{"word":"absagen","en":"to cancel","ru":"отменять","vi":"hủy bỏ","fa":"لغو","examples":[{"de":"Wegen Regen mussten wir das Picknick absagen.","en":"Because of the rain we had to cancel the picnic.","ru":"Из-за дождя нам пришлось отменить пикник.","vi":"Chúng tôi phải hủy chuyến dã ngoại vì trời mưa.","fa":"به خاطر باران مجبور شدیم پیک نیک را لغو کنیم."},{"de":"Er hat den Termin beim Arzt kurzfristig abgesagt.","en":"He cancelled the doctor's appointment at short notice.","ru":"Он отменил приём у врача в последний момент.","vi":"Anh ấy đã hủy cuộc hẹn với bác sĩ trong thời gian ngắn.","fa":"او در کوتاه ترین زمان قرار ملاقات با پزشک را لغو کرد."}]},{"word":"der Abschluss","en":"conclusion; (school/university) degree","ru":"завершение; диплом","vi":"kết luận","fa":"نتیجه گیری","examples":[{"de":"Nach dem Abschluss ihres Studiums fand sie schnell eine Stelle.","en":"After completing her degree, she quickly found a job.","ru":"После окончания учёбы она быстро нашла работу.","vi":"Sau khi học xong, cô nhanh chóng tìm được việc làm.","fa":"پس از اتمام تحصیلاتش، به سرعت شغلی پیدا کرد."},{"de":"Zum Abschluss des Treffens haben alle noch einmal applaudiert.","en":"To conclude the meeting, everyone applauded once more.","ru":"В завершение встречи все ещё раз поаплодировали.","vi":"Kết thúc cuộc họp mọi người lại vỗ tay lần nữa.","fa":"در پایان جلسه دوباره همه کف زدند."}]},{"word":"der Abschnitt","en":"section, segment","ru":"раздел, участок","vi":"phần","fa":"بخش","examples":[{"de":"Lesen Sie bitte den ersten Abschnitt des Textes noch einmal.","en":"Please read the first section of the text again.","ru":"Пожалуйста, прочитайте ещё раз первый раздел текста.","vi":"Xin vui lòng đọc lại phần đầu tiên của văn bản.","fa":"لطفا بخش اول متن را دوباره بخوانید."},{"de":"Auf diesem Abschnitt der Autobahn gilt Tempo 100.","en":"On this section of the highway a speed limit of 100 applies.","ru":"На этом участке автомагистрали действует ограничение скорости 100.","vi":"Tốc độ giới hạn là 100 km/h trên đoạn đường cao tốc này.","fa":"سرعت مجاز در این بخش از بزرگراه 100 کیلومتر در ساعت است."}]},{"word":"abschreiben","en":"to copy; to write off","ru":"списывать","vi":"viết tắt","fa":"حذف کردن","examples":[{"de":"Er hat die Antworten von seinem Nachbarn abgeschrieben.","en":"He copied the answers from his neighbor.","ru":"Он списал ответы у соседа.","vi":"Anh ta sao chép câu trả lời từ người hàng xóm của mình.","fa":"او پاسخ های همسایه اش را کپی کرد."},{"de":"Die Firma musste die alte Maschine abschreiben.","en":"The company had to write off the old machine.","ru":"Компании пришлось списать старую машину.","vi":"Công ty đã phải loại bỏ chiếc máy cũ.","fa":"شرکت مجبور شد ماشین قدیمی را بنویسد."}]},{"word":"der Absender","en":"sender","ru":"отправитель","vi":"người gửi","fa":"فرستنده","examples":[{"de":"Auf dem Umschlag stand kein Absender.","en":"There was no sender on the envelope.","ru":"На конверте не было указано отправителя.","vi":"Không có địa chỉ gửi lại trên phong bì.","fa":"هیچ آدرس برگشتی روی پاکت وجود نداشت."},{"de":"Bitte notieren Sie den Absender oben links auf dem Brief.","en":"Please note the sender in the top left of the letter.","ru":"Пожалуйста, укажите отправителя в верхнем левом углу письма.","vi":"Vui lòng ghi chú người gửi ở phía trên bên trái của bức thư.","fa":"لطفاً به فرستنده در سمت چپ بالای نامه توجه کنید."}]},{"word":"die Absicht","en":"intention","ru":"намерение","vi":"ý định","fa":"قصد","examples":[{"de":"Es war nicht meine Absicht, dich zu ärgern.","en":"It was not my intention to annoy you.","ru":"У меня не было намерения тебя раздражать.","vi":"Tôi không có ý định làm bạn khó chịu.","fa":"قصدم ناراحت کردنت نبود"},{"de":"Sie hat die Absicht, im Sommer nach Spanien zu ziehen.","en":"She intends to move to Spain in the summer.","ru":"Она намерена переехать в Испанию летом.","vi":"Cô dự định chuyển đến Tây Ban Nha vào mùa hè.","fa":"او قصد دارد در تابستان به اسپانیا برود."}]},{"word":"absolut","en":"absolute(ly)","ru":"абсолютный, абсолютно","vi":"tuyệt đối","fa":"مطلقا","examples":[{"de":"Das ist absolut unmöglich.","en":"That is absolutely impossible.","ru":"Это абсолютно невозможно.","vi":"Điều đó là hoàn toàn không thể.","fa":"که کاملا غیر ممکن است."},{"de":"Ich bin mir absolut sicher, dass ich den Schlüssel hier gelassen habe.","en":"I am absolutely sure that I left the key here.","ru":"Я абсолютно уверен, что оставил ключ здесь.","vi":"Tôi hoàn toàn chắc chắn rằng tôi đã để chìa khóa ở đây.","fa":"من کاملاً مطمئن هستم که کلید را اینجا گذاشته ام."}]},{"word":"abstimmen","en":"to vote; to coordinate","ru":"голосовать; согласовывать","vi":"bỏ phiếu","fa":"رای دادن","examples":[{"de":"Am Sonntag stimmen wir über das neue Gesetz ab.","en":"On Sunday we vote on the new law.","ru":"В воскресенье мы голосуем по новому закону.","vi":"Vào Chủ Nhật chúng ta sẽ bỏ phiếu về luật mới.","fa":"روز یکشنبه به قانون جدید رای خواهیم داد."},{"de":"Wir müssen unsere Termine noch miteinander abstimmen.","en":"We still need to coordinate our schedules with each other.","ru":"Нам ещё нужно согласовать наши сроки друг с другом.","vi":"Chúng tôi vẫn phải sắp xếp các cuộc hẹn với nhau.","fa":"ما هنوز باید قرارهایمان را با یکدیگر هماهنگ کنیم."}]},{"word":"die Abteilung","en":"department","ru":"отдел","vi":"khoa","fa":"بخش","examples":[{"de":"Er arbeitet in der Abteilung für Marketing.","en":"He works in the marketing department.","ru":"Он работает в отделе маркетинга.","vi":"Anh ấy làm việc ở bộ phận tiếp thị.","fa":"او در بخش بازاریابی کار می کند."},{"de":"Die Schuhe finden Sie in der Abteilung im zweiten Stock.","en":"You will find the shoes in the department on the second floor.","ru":"Обувь вы найдёте в отделе на третьем этаже.","vi":"Những đôi giày có thể được tìm thấy trong gian hàng trên tầng hai.","fa":"کفش ها را می توان در بخش طبقه دوم پیدا کرد."}]},{"word":"der Abwart","en":"caretaker, janitor","ru":"смотритель, дворник","vi":"người canh gác","fa":"نگهبان","examples":[{"de":"Der Abwart repariert die kaputte Lampe im Treppenhaus.","en":"The caretaker is repairing the broken lamp in the stairwell.","ru":"Смотритель ремонтирует сломанную лампу в подъезде.","vi":"Người chăm sóc sửa chữa chiếc đèn bị hỏng ở cầu thang.","fa":"سرایدار لامپ شکسته راه پله را تعمیر می کند."},{"de":"Wenn die Heizung nicht funktioniert, rufen Sie bitte den Abwart an.","en":"If the heating doesn't work, please call the caretaker.","ru":"Если отопление не работает, позвоните, пожалуйста, смотрителю.","vi":"Nếu hệ thống sưởi không hoạt động, vui lòng gọi cho người bảo trì.","fa":"اگر گرمایش کار نمی کند، لطفا با تعمیرکار تماس بگیرید."}]},{"word":"abwärts","en":"downward(s)","ru":"вниз","vi":"đi xuống","fa":"به سمت پایین","examples":[{"de":"Der Weg führt steil abwärts zum See.","en":"The path leads steeply downward to the lake.","ru":"Тропа круто спускается вниз к озеру.","vi":"Con đường dẫn dốc xuống hồ.","fa":"مسیر با شیب تند به سمت دریاچه منتهی می شود."},{"de":"Mit der Wirtschaft geht es seit Monaten abwärts.","en":"The economy has been going downhill for months.","ru":"Экономика уже несколько месяцев идёт на спад.","vi":"Nền kinh tế đã đi xuống trong nhiều tháng.","fa":"ماه هاست که اقتصاد در حال نزول است."}]},{"word":"abwaschen","en":"to wash up, to wash off","ru":"мыть посуду; смывать","vi":"rửa sạch","fa":"شستن","examples":[{"de":"Nach dem Essen muss noch das Geschirr abgewaschen werden.","en":"After the meal, the dishes still need to be washed up.","ru":"После еды ещё нужно вымыть посуду.","vi":"Ăn xong vẫn phải rửa bát.","fa":"پس از صرف غذا، ظروف هنوز باید شسته شوند."},{"de":"Sie wusch sich den Schmutz von den Händen ab.","en":"She washed the dirt off her hands.","ru":"Она смыла грязь с рук.","vi":"Cô rửa sạch bụi bẩn trên tay.","fa":"خاک را از روی دستانش شست."}]},{"word":"abwesend","en":"absent","ru":"отсутствующий","vi":"vắng mặt","fa":"غایب","examples":[{"de":"Drei Schüler waren heute abwesend.","en":"Three students were absent today.","ru":"Три ученика сегодня отсутствовали.","vi":"Hôm nay có 3 học sinh vắng mặt.","fa":"سه دانش آموز امروز غایب بودند."},{"de":"Er wirkte während des Gesprächs völlig abwesend.","en":"He seemed completely absent-minded during the conversation.","ru":"Во время разговора он казался совершенно отсутствующим.","vi":"Anh ấy dường như hoàn toàn vắng mặt trong suốt cuộc trò chuyện.","fa":"در طول مکالمه کاملاً غایب به نظر می رسید."}]},{"word":"achten","en":"to pay attention to; to respect","ru":"обращать внимание; уважать","vi":"chú ý","fa":"توجه کنید","examples":[{"de":"Achten Sie bitte auf die Straßenschilder.","en":"Please pay attention to the road signs.","ru":"Пожалуйста, обращайте внимание на дорожные знаки.","vi":"Please pay attention to the street signs.","fa":"لطفا به تابلوهای خیابان توجه کنید."},{"de":"Wir sollten die Meinung anderer Menschen achten.","en":"We should respect the opinions of other people.","ru":"Нам следует уважать мнение других людей.","vi":"Chúng ta nên tôn trọng ý kiến ​​của người khác.","fa":"ما باید به نظرات دیگران احترام بگذاریم."}]},{"word":"die Adresse","en":"address","ru":"адрес","vi":"địa chỉ","fa":"آدرس","examples":[{"de":"Wie lautet Ihre neue Adresse?","en":"What is your new address?","ru":"Какой у вас новый адрес?","vi":"Địa chỉ mới của bạn là gì?","fa":"آدرس جدید شما چیست؟"},{"de":"Ich habe die Adresse des Hotels notiert.","en":"I noted down the address of the hotel.","ru":"Я записал адрес отеля.","vi":"Tôi đã viết địa chỉ của khách sạn.","fa":"آدرس هتل را یادداشت کردم."}]},{"word":"ähnlich","en":"similar","ru":"похожий, подобный","vi":"tương tự","fa":"مشابه","examples":[{"de":"Die beiden Schwestern sehen sich sehr ähnlich.","en":"The two sisters look very similar to each other.","ru":"Обе сестры очень похожи друг на друга.","vi":"Hai chị em trông rất giống nhau.","fa":"این دو خواهر خیلی شبیه هم هستند."},{"de":"Ich habe ein ähnliches Problem wie du.","en":"I have a similar problem to yours.","ru":"У меня похожая проблема, как у тебя.","vi":"Tôi có một vấn đề tương tự như bạn.","fa":"من هم مثل شما مشکلی دارم"}]},{"word":"die Ahnung","en":"idea, notion, clue","ru":"представление, догадка","vi":"linh cảm","fa":"قوز","examples":[{"de":"Ich habe keine Ahnung, wo meine Schlüssel sind.","en":"I have no idea where my keys are.","ru":"Я понятия не имею, где мои ключи.","vi":"Tôi không biết chìa khóa của mình ở đâu.","fa":"من نمی دانم کلیدهای من کجا هستند."},{"de":"Sie hatte eine Ahnung, dass etwas nicht stimmte.","en":"She had a hunch that something was wrong.","ru":"У неё было предчувствие, что что-то не так.","vi":"Cô linh cảm có điều gì đó không ổn.","fa":"او تصور می کرد که چیزی اشتباه است."}]},{"word":"die Aktion","en":"action; campaign, promotion","ru":"акция; действие","vi":"the action","fa":"عمل","examples":[{"de":"Der Supermarkt hat diese Woche eine Aktion mit reduzierten Preisen.","en":"The supermarket has a promotion with reduced prices this week.","ru":"В этом магазине на этой неделе акция со сниженными ценами.","vi":"Der Supermarkt hat diese Woche eine Aktion mit reduzierten Preisen.","fa":"این سوپرمارکت در این هفته یک تبلیغ با کاهش قیمت دارد."},{"de":"Die Feuerwehr startete sofort eine Aktion zur Rettung der Tiere.","en":"The fire department immediately launched an action to rescue the animals.","ru":"Пожарная служба немедленно начала акцию по спасению животных.","vi":"Lực lượng cứu hỏa ngay lập tức triển khai chiến dịch giải cứu các con vật.","fa":"آتش نشانی بلافاصله عملیات نجات حیوانات را آغاز کرد."}]},{"word":"aktiv","en":"active","ru":"активный","vi":"hoạt động","fa":"فعال","examples":[{"de":"Meine Großmutter ist trotz ihres Alters noch sehr aktiv.","en":"My grandmother is still very active despite her age.","ru":"Моя бабушка, несмотря на возраст, всё ещё очень активна.","vi":"Bà tôi vẫn còn rất năng động dù tuổi đã cao.","fa":"مادربزرگ من با وجود سنش هنوز خیلی فعال است."},{"de":"Er beteiligt sich aktiv an der Diskussion.","en":"He actively participates in the discussion.","ru":"Он активно участвует в обсуждении.","vi":"Anh ấy tích cực tham gia vào cuộc thảo luận.","fa":"او فعالانه در بحث شرکت می کند."}]},{"word":"aktuell","en":"current, up-to-date","ru":"актуальный, текущий","vi":"hiện tại","fa":"در حال حاضر","examples":[{"de":"Das ist die aktuelle Ausgabe der Zeitschrift.","en":"This is the current issue of the magazine.","ru":"Это текущий выпуск журнала.","vi":"Đây là số hiện tại của tạp chí.","fa":"این شماره فعلی مجله است."},{"de":"Die aktuelle Situation macht mir Sorgen.","en":"The current situation worries me.","ru":"Текущая ситуация меня беспокоит.","vi":"The current situation worries me.","fa":"وضعیت فعلی من را نگران می کند."}]},{"word":"akzeptieren","en":"to accept","ru":"принимать, соглашаться","vi":"chấp nhận","fa":"قبول کنید","examples":[{"de":"Er konnte die Entscheidung seines Chefs nicht akzeptieren.","en":"He could not accept his boss's decision.","ru":"Он не мог принять решение своего начальника.","vi":"Anh không thể chấp nhận quyết định của ông chủ.","fa":"او نمی توانست تصمیم رئیسش را بپذیرد."},{"de":"Wir akzeptieren auch Zahlungen mit Kreditkarte.","en":"We also accept payments by credit card.","ru":"Мы также принимаем оплату кредитной картой.","vi":"Chúng tôi cũng chấp nhận thanh toán bằng thẻ tín dụng.","fa":"ما همچنین پرداخت با کارت اعتباری را می پذیریم."}]},{"word":"der Alarm","en":"alarm","ru":"тревога, сигнализация","vi":"báo động","fa":"زنگ هشدار","examples":[{"de":"Plötzlich ging der Alarm im Gebäude los.","en":"Suddenly the alarm went off in the building.","ru":"Внезапно в здании сработала сигнализация.","vi":"Đột nhiên chuông báo động trong tòa nhà vang lên.","fa":"ناگهان زنگ در ساختمان به صدا درآمد."},{"de":"Bei Feuer sollten Sie sofort Alarm schlagen.","en":"In case of fire, you should raise the alarm immediately.","ru":"В случае пожара нужно немедленно поднять тревогу.","vi":"Nếu có hỏa hoạn, bạn nên phát ra âm thanh báo động ngay lập tức.","fa":"در صورت وقوع آتش سوزی باید فوراً زنگ خطر را به صدا در آورید."}]},{"word":"der Alkohol","en":"alcohol","ru":"алкоголь","vi":"rượu","fa":"الکل","examples":[{"de":"Er trinkt seit Jahren keinen Alkohol mehr.","en":"He hasn't drunk alcohol for years.","ru":"Он уже много лет не пьёт алкоголь.","vi":"Anh ấy đã không uống rượu trong nhiều năm rồi.","fa":"او سالها الکل ننوشیده است."},{"de":"Alkohol am Steuer ist in Deutschland verboten.","en":"Alcohol at the wheel is prohibited in Germany.","ru":"Употребление алкоголя за рулём в Германии запрещено.","vi":"Alkohol am Steuer ist ở Deutschland verboten.","fa":"مشروب الکلی و رانندگی در آلمان ممنوع است."}]},{"word":"all-","en":"all-, every- (prefix)","ru":"все-, каждый- (приставка)","vi":"tất cả-","fa":"همه-","examples":[{"de":"Kleine Streitigkeiten sind in einer Familie ganz alltäglich.","en":"Small quarrels are quite common (everyday) in a family.","ru":"Небольшие ссоры в семье — обычное, повседневное дело.","vi":"Những tranh cãi nhỏ là chuyện thường tình trong một gia đình.","fa":"دعواهای کوچک در یک خانواده رایج است."},{"de":"Ein Stau am Morgen ist in dieser Stadt alltäglich geworden.","en":"A traffic jam in the morning has become an everyday occurrence in this city.","ru":"Пробка по утрам стала обычным явлением в этом городе.","vi":"Ùn tắc giao thông buổi sáng đã trở nên phổ biến ở thành phố này.","fa":"ترافیک صبحگاهی در این شهر عادی شده است."}]},{"word":"allein","en":"alone","ru":"один, в одиночестве","vi":"một mình","fa":"به تنهایی","examples":[{"de":"Sie wohnt allein in einer kleinen Wohnung.","en":"She lives alone in a small apartment.","ru":"Она живёт одна в маленькой квартире.","vi":"Cô sống một mình trong một căn hộ nhỏ.","fa":"او به تنهایی در یک آپارتمان کوچک زندگی می کند."},{"de":"Ich möchte heute Abend lieber allein sein.","en":"I would rather be alone this evening.","ru":"Сегодня вечером я предпочёл бы побыть один.","vi":"Tôi thà ở một mình tối nay.","fa":"ترجیح میدم امشب تنها باشم"}]},{"word":"aller-","en":"-est of all (superlative prefix)","ru":"самый- (усилительная приставка превосходной степени)","vi":"tất cả-","fa":"همه-","examples":[{"de":"Das war der allerbeste Kuchen, den ich je gegessen habe.","en":"That was the very best cake I have ever eaten.","ru":"Это был самый лучший торт, который я когда-либо ел.","vi":"Đây là chiếc bánh ngon nhất mà tôi từng ăn.","fa":"این بهترین کیکی بود که تا به حال خوردم."},{"de":"Er kam als Allerletzter ins Ziel.","en":"He came in as the very last one at the finish line.","ru":"Он пришёл к финишу самым последним.","vi":"Anh ấy đã hoàn thành cuối cùng.","fa":"او آخر شد."}]},{"word":"allerdings","en":"however, though","ru":"однако, впрочем","vi":"tuy nhiên","fa":"با این حال","examples":[{"de":"Das Restaurant ist gut, allerdings auch ziemlich teuer.","en":"The restaurant is good, however also quite expensive.","ru":"Ресторан хороший, однако довольно дорогой.","vi":"Nhà hàng ngon nhưng cũng khá đắt.","fa":"رستوران خوب است، اما بسیار گران است."},{"de":"Ich komme gerne mit, allerdings erst nach der Arbeit.","en":"I would love to come along, though only after work.","ru":"Я с удовольствием приду, однако только после работы.","vi":"Tôi rất vui được đi cùng bạn, nhưng chỉ sau giờ làm việc thôi.","fa":"خوشحال می شوم با شما بیایم، اما فقط بعد از کار."}]},{"word":"allgemein","en":"general","ru":"общий, всеобщий","vi":"chung","fa":"عمومی","examples":[{"de":"Das ist eine allgemeine Regel, die für alle gilt.","en":"That is a general rule that applies to everyone.","ru":"Это общее правило, которое действует для всех.","vi":"Đây là nguyên tắc chung áp dụng cho tất cả mọi người.","fa":"این یک قانون کلی است که برای همه صدق می کند."},{"de":"Im Allgemeinen bin ich mit meinem Job zufrieden.","en":"In general, I am satisfied with my job.","ru":"В общем, я доволен своей работой.","vi":"Nói chung tôi hài lòng với công việc của mình.","fa":"در کل از شغلم راضی هستم."}]},{"word":"der Alltag","en":"everyday life, routine","ru":"повседневная жизнь, будни","vi":"cuộc sống hàng ngày","fa":"زندگی روزمره","examples":[{"de":"Nach dem Urlaub beginnt wieder der graue Alltag.","en":"After the vacation, the gray everyday routine begins again.","ru":"После отпуска снова начинаются серые будни.","vi":"Sau kỳ nghỉ, cuộc sống xám xịt thường ngày lại bắt đầu.","fa":"پس از تعطیلات، زندگی روزمره خاکستری دوباره آغاز می شود."},{"de":"Im Alltag habe ich kaum Zeit zum Lesen.","en":"In everyday life I hardly have time to read.","ru":"В повседневной жизни у меня почти нет времени на чтение.","vi":"Tôi hầu như không có thời gian để đọc trong cuộc sống hàng ngày.","fa":"در زندگی روزمره به سختی وقت برای مطالعه دارم."}]},{"word":"das Alphabet","en":"alphabet","ru":"алфавит","vi":"bảng chữ cái","fa":"الفبا","examples":[{"de":"Das deutsche Alphabet hat 26 Buchstaben und einige Sonderzeichen.","en":"The German alphabet has 26 letters and some special characters.","ru":"В немецком алфавите 26 букв и несколько специальных знаков.","vi":"Bảng chữ cái tiếng Đức có 26 chữ cái và một số ký tự đặc biệt.","fa":"الفبای آلمانی دارای 26 حرف و چند کاراکتر خاص است."},{"de":"Die Kinder lernen im ersten Schuljahr das Alphabet.","en":"The children learn the alphabet in their first year of school.","ru":"Дети учат алфавит в первом классе школы.","vi":"Trẻ em học bảng chữ cái trong năm học đầu tiên.","fa":"بچه ها در سال اول تحصیلی الفبا را یاد می گیرند."}]},{"word":"als","en":"than; when; as","ru":"чем; когда; как","vi":"như","fa":"به عنوان","examples":[{"de":"Sie ist größer als ihr Bruder.","en":"She is taller than her brother.","ru":"Она выше своего брата.","vi":"Cô ấy cao hơn anh trai cô ấy.","fa":"او از برادرش بلندتر است."},{"de":"Als ich klein war, wohnte ich auf dem Land.","en":"When I was little, I lived in the countryside.","ru":"Когда я был маленьким, я жил в деревне.","vi":"Hồi nhỏ tôi sống ở quê.","fa":"وقتی کوچک بودم، در کشور زندگی می کردم."}]},{"word":"also","en":"so, therefore","ru":"итак, следовательно","vi":"vậy","fa":"بنابراین","examples":[{"de":"Es regnet, also nehme ich einen Regenschirm mit.","en":"It's raining, so I'll take an umbrella.","ru":"Идёт дождь, поэтому я возьму зонт.","vi":"Trời đang mưa nên tôi mang theo ô.","fa":"باران می بارد، پس چتر برمی دارم."},{"de":"Also, dann sehen wir uns morgen um neun Uhr.","en":"So, then we'll see each other tomorrow at nine o'clock.","ru":"Итак, увидимся завтра в девять часов.","vi":"Vâng, hẹn gặp bạn vào lúc 9 giờ ngày mai.","fa":"خب فردا ساعت نه میبینمت"}]},{"word":"alt","en":"old","ru":"старый","vi":"cũ","fa":"قدیمی","examples":[{"de":"Mein Großvater ist schon 85 Jahre alt.","en":"My grandfather is already 85 years old.","ru":"Моему дедушке уже 85 лет.","vi":"Ông tôi đã 85 tuổi rồi.","fa":"پدربزرگ من در حال حاضر 85 سال دارد."},{"de":"Wir wohnen in einem alten Haus aus dem 19. Jahrhundert.","en":"We live in an old house from the 19th century.","ru":"Мы живём в старом доме XIX века.","vi":"Chúng tôi sống trong một ngôi nhà cổ từ thế kỷ 19.","fa":"ما در خانه ای قدیمی از قرن نوزدهم زندگی می کنیم."}]},{"word":"das Alter","en":"age","ru":"возраст","vi":"tuổi","fa":"سن","examples":[{"de":"In welchem Alter hast du das Schwimmen gelernt?","en":"At what age did you learn to swim?","ru":"В каком возрасте ты научился плавать?","vi":"Bạn học bơi lúc bao nhiêu tuổi?","fa":"از چه سنی شنا یاد گرفتی؟"},{"de":"Im Alter reist sie gerne durch Europa.","en":"In her old age, she likes to travel through Europe.","ru":"В пожилом возрасте она любит путешествовать по Европе.","vi":"Ở tuổi già, bà thích đi du lịch khắp châu Âu.","fa":"در دوران پیری از سفر در اروپا لذت می برد."}]},{"word":"alternativ","en":"alternative(ly)","ru":"альтернативный, альтернативно","vi":"cách khác","fa":"جایگزین","examples":[{"de":"Alternativ können wir auch mit dem Zug fahren.","en":"Alternatively, we could also go by train.","ru":"В качестве альтернативы мы можем поехать на поезде.","vi":"Ngoài ra, chúng ta cũng có thể đi tàu.","fa":"در غیر این صورت، می توانیم با قطار نیز سوار شویم."},{"de":"Immer mehr Menschen nutzen alternative Energiequellen.","en":"More and more people use alternative energy sources.","ru":"Всё больше людей используют альтернативные источники энергии.","vi":"Ngày càng có nhiều người sử dụng các nguồn năng lượng thay thế.","fa":"افراد بیشتری از منابع انرژی جایگزین استفاده می کنند."}]},{"word":"die Ampel","en":"traffic light","ru":"светофор","vi":"đèn giao thông","fa":"چراغ های راهنمایی","examples":[{"de":"Bitte warte, bis die Ampel grün wird.","en":"Please wait until the traffic light turns green.","ru":"Пожалуйста, подожди, пока светофор станет зелёным.","vi":"Vui lòng đợi cho đến khi đèn giao thông chuyển sang màu xanh.","fa":"لطفا صبر کنید تا چراغ راهنمایی سبز شود."},{"de":"An der Ampel ist gerade ein Unfall passiert.","en":"An accident just happened at the traffic light.","ru":"У светофора только что произошла авария.","vi":"Một vụ tai nạn vừa xảy ra ở đèn giao thông.","fa":"تصادف در چراغ راهنمایی اتفاق افتاد."}]},{"word":"das Amt","en":"official office, authority","ru":"ведомство, учреждение","vi":"văn phòng","fa":"دفتر","examples":[{"de":"Für den neuen Pass müssen Sie zum Amt gehen.","en":"For the new passport, you have to go to the office (authority).","ru":"Для получения нового паспорта нужно пойти в учреждение.","vi":"Bạn phải đến văn phòng để lấy hộ chiếu mới.","fa":"برای گرفتن پاسپورت جدید باید به اداره مراجعه کنید."},{"de":"Das Amt für Ausländerfragen befindet sich im Stadtzentrum.","en":"The office for foreigners' affairs is located in the city center.","ru":"Управление по делам иностранцев находится в центре города.","vi":"Văn phòng đối ngoại nằm ở trung tâm thành phố.","fa":"دفتر امور اتباع خارجی در مرکز شهر قرار دارد."}]},{"word":"an","en":"at, on","ru":"у, на, в (предлог)","vi":"trên","fa":"در","examples":[{"de":"Das Bild hängt an der Wand.","en":"The picture is hanging on the wall.","ru":"Картина висит на стене.","vi":"Bức tranh treo trên tường.","fa":"عکس روی دیوار آویزان است."},{"de":"Wir treffen uns am Freitag an der Bushaltestelle.","en":"We are meeting on Friday at the bus stop.","ru":"Мы встречаемся в пятницу у автобусной остановки.","vi":"Chúng ta sẽ gặp nhau ở trạm xe buýt vào thứ Sáu.","fa":"جمعه در ایستگاه اتوبوس همدیگر را می بینیم."}]},{"word":"analysieren","en":"to analyze","ru":"анализировать","vi":"phân tích","fa":"تجزیه و تحلیل کنید","examples":[{"de":"Der Lehrer bat uns, das Gedicht genau zu analysieren.","en":"The teacher asked us to analyze the poem carefully.","ru":"Учитель попросил нас внимательно проанализировать стихотворение.","vi":"Giáo viên yêu cầu chúng tôi phân tích bài thơ một cách cẩn thận.","fa":"معلم از ما خواست که شعر را با دقت تجزیه و تحلیل کنیم."},{"de":"Der Arzt analysiert zuerst die Blutwerte des Patienten.","en":"The doctor first analyzes the patient's blood values.","ru":"Врач сначала анализирует показатели крови пациента.","vi":"Đầu tiên bác sĩ sẽ phân tích giá trị máu của bệnh nhân.","fa":"پزشک ابتدا مقادیر خونی بیمار را تجزیه و تحلیل می کند."}]},{"word":"anbieten","en":"to offer","ru":"предлагать","vi":"đề nghị","fa":"پیشنهاد","examples":[{"de":"Das Hotel bietet seinen Gästen kostenloses WLAN an.","en":"The hotel offers its guests free WiFi.","ru":"Отель предлагает своим гостям бесплатный Wi-Fi.","vi":"Khách sạn cung cấp cho khách Wi-Fi miễn phí.","fa":"این هتل به مهمانان خود وای فای رایگان ارائه می دهد."},{"de":"Kann ich Ihnen etwas zu trinken anbieten?","en":"Can I offer you something to drink?","ru":"Могу я предложить вам что-нибудь выпить?","vi":"Tôi có thể mời bạn thứ gì đó để uống không?","fa":"آیا می توانم به شما چیزی برای نوشیدن پیشنهاد کنم؟"}]},{"word":"ander-","en":"other, different","ru":"другой, иной","vi":"khác-","fa":"دیگر-","examples":[{"de":"Ich hätte gern einen anderen Platz am Fenster.","en":"I would like a different seat by the window.","ru":"Я хотел бы другое место у окна.","vi":"Tôi muốn một chỗ ngồi khác cạnh cửa sổ.","fa":"من یک صندلی دیگر کنار پنجره می خواهم."},{"de":"Das ist eine ganz andere Angelegenheit.","en":"That is a completely different matter.","ru":"Это совсем другое дело.","vi":"Đó là một vấn đề hoàn toàn khác.","fa":"این یک موضوع کاملا متفاوت است."}]},{"word":"andererseits","en":"on the other hand","ru":"с другой стороны","vi":"mặt khác","fa":"از سوی دیگر","examples":[{"de":"Einerseits möchte ich reisen, andererseits fehlt mir das Geld.","en":"On one hand I want to travel, on the other hand I lack the money.","ru":"С одной стороны, я хочу путешествовать, с другой — у меня нет денег.","vi":"Một mặt tôi muốn đi du lịch, mặt khác tôi không có tiền.","fa":"از یک طرف می خواهم سفر کنم، از طرف دیگر پول ندارم."},{"de":"Er ist streng, andererseits aber auch sehr gerecht.","en":"He is strict, but on the other hand also very fair.","ru":"Он строгий, но, с другой стороны, очень справедливый.","vi":"Anh ấy nghiêm khắc nhưng mặt khác cũng rất công bằng.","fa":"او سختگیر است، اما از طرف دیگر بسیار منصف است."}]},{"word":"ändern","en":"to change","ru":"менять, изменять","vi":"thay đổi","fa":"تغییر دهید","examples":[{"de":"Ich möchte meinen Termin auf nächste Woche ändern.","en":"I would like to change my appointment to next week.","ru":"Я хотел бы перенести встречу на следующую неделю.","vi":"Tôi muốn đổi cuộc hẹn sang tuần sau.","fa":"من می خواهم قرارم را به هفته آینده تغییر دهم."},{"de":"Das Wetter hat sich plötzlich geändert.","en":"The weather changed suddenly.","ru":"Погода внезапно изменилась.","vi":"Thời tiết đột nhiên thay đổi.","fa":"هوا ناگهان تغییر کرد."}]},{"word":"anders","en":"differently, otherwise","ru":"по-другому, иначе","vi":"khác nhau","fa":"متفاوت است","examples":[{"de":"Diesmal machen wir es anders als sonst.","en":"This time we're doing it differently than usual.","ru":"На этот раз мы сделаем это иначе, чем обычно.","vi":"Lần này chúng tôi làm việc đó khác với thường lệ.","fa":"این بار ما آن را متفاوت از حد معمول انجام می دهیم."},{"de":"Sie denkt einfach anders als die meisten Leute.","en":"She simply thinks differently than most people.","ru":"Она просто думает иначе, чем большинство людей.","vi":"Cô ấy chỉ nghĩ khác với hầu hết mọi người.","fa":"او فقط متفاوت از بسیاری از مردم فکر می کند."}]},{"word":"anerkennen","en":"to acknowledge, to recognize","ru":"признавать","vi":"thừa nhận","fa":"تصدیق کند","examples":[{"de":"Der Chef hat ihre gute Arbeit endlich anerkannt.","en":"The boss finally acknowledged her good work.","ru":"Начальник наконец признал её хорошую работу.","vi":"Ông chủ cuối cùng đã công nhận việc làm tốt của cô.","fa":"رئیس بالاخره کار خوب او را تشخیص داد."},{"de":"Dieser Abschluss wird in vielen Ländern anerkannt.","en":"This degree is recognized in many countries.","ru":"Этот диплом признаётся во многих странах.","vi":"Bằng cấp này được công nhận ở nhiều nước.","fa":"این مدرک در بسیاری از کشورها به رسمیت شناخته شده است."}]},{"word":"anfangen","en":"to begin, to start","ru":"начинать","vi":"bắt đầu","fa":"شروع کنید","examples":[{"de":"Der Film fängt um 20 Uhr an.","en":"The movie starts at 8 p.m.","ru":"Фильм начинается в 20:00.","vi":"Phim bắt đầu lúc 8 giờ tối.","fa":"فیلم ساعت 20 شروع می شود."},{"de":"Ich möchte nächsten Monat mit einer neuen Sprache anfangen.","en":"I would like to start with a new language next month.","ru":"Я хочу начать изучать новый язык в следующем месяце.","vi":"Tôi muốn bắt đầu với một ngôn ngữ mới vào tháng tới.","fa":"من می خواهم ماه آینده با یک زبان جدید شروع کنم."}]},{"word":"angeben","en":"to state, indicate; to show off","ru":"указывать; хвастаться","vi":"chỉ định","fa":"مشخص کنید","examples":[{"de":"Bitte geben Sie Ihren Namen und Ihre Adresse an.","en":"Please state your name and your address.","ru":"Пожалуйста, укажите ваше имя и адрес.","vi":"Vui lòng bao gồm tên và địa chỉ của bạn.","fa":"لطفا نام و آدرس خود را ذکر کنید."},{"de":"Er gibt gern mit seinem neuen Auto an.","en":"He likes to show off with his new car.","ru":"Он любит хвастаться своей новой машиной.","vi":"Anh ấy thích khoe chiếc xe mới của mình.","fa":"او دوست دارد ماشین جدیدش را به نمایش بگذارد."}]},{"word":"der Angehörige","en":"relative, family member","ru":"родственник","vi":"người thân","fa":"خویشاوند","examples":[{"de":"Nur nahe Angehörige durften den Patienten besuchen.","en":"Only close relatives were allowed to visit the patient.","ru":"Только близкие родственники могли навещать пациента.","vi":"Chỉ người thân mới được phép vào thăm bệnh nhân.","fa":"فقط بستگان نزدیک اجازه ملاقات با بیمار را داشتند."},{"de":"Sie kümmert sich um ihre kranken Angehörigen.","en":"She takes care of her sick relatives.","ru":"Она заботится о своих больных родственниках.","vi":"Cô chăm sóc người thân bị bệnh của mình.","fa":"او از بستگان بیمار خود مراقبت می کند."}]},{"word":"angenehm","en":"pleasant","ru":"приятный","vi":"dễ chịu","fa":"دلپذیر","examples":[{"de":"Wir hatten einen sehr angenehmen Abend zusammen.","en":"We had a very pleasant evening together.","ru":"У нас был очень приятный вечер вместе.","vi":"Chúng tôi đã có một buổi tối rất vui vẻ bên nhau.","fa":"عصر بسیار خوبی را با هم سپری کردیم."},{"de":"Draußen herrscht heute eine angenehme Temperatur.","en":"There is a pleasant temperature outside today.","ru":"Сегодня на улице приятная температура.","vi":"Nhiệt độ bên ngoài hôm nay dễ chịu.","fa":"امروز هوای بیرون هوای مطبوعی است."}]},{"word":"die Angst","en":"fear","ru":"страх","vi":"nỗi sợ hãi","fa":"ترس","examples":[{"de":"Sie hat große Angst vor Spinnen.","en":"She is very afraid of spiders.","ru":"Она очень боится пауков.","vi":"Cô ấy rất sợ nhện.","fa":"او خیلی از عنکبوت می ترسد."},{"de":"Ich hatte Angst, den Zug zu verpassen.","en":"I was afraid of missing the train.","ru":"Я боялся опоздать на поезд.","vi":"Tôi sợ lỡ chuyến tàu.","fa":"می ترسیدم قطار را از دست بدهم."}]},{"word":"anhaben","en":"to be wearing","ru":"быть одетым в","vi":"có trên","fa":"دارند","examples":[{"de":"Sie hat heute ein rotes Kleid an.","en":"She is wearing a red dress today.","ru":"Сегодня на ней красное платье.","vi":"Hôm nay cô ấy mặc một chiếc váy màu đỏ.","fa":"اون امروز یه لباس قرمز پوشیده"},{"de":"Was hattest du gestern auf der Party an?","en":"What were you wearing at the party yesterday?","ru":"Что на тебе было надето вчера на вечеринке?","vi":"Bạn đã mặc gì đến bữa tiệc ngày hôm qua?","fa":"دیروز تو مهمونی چی پوشیدی؟"}]},{"word":"anklicken","en":"to click on","ru":"нажимать (мышью), кликать","vi":"bấm vào","fa":"کلیک کنید","examples":[{"de":"Klicken Sie auf das grüne Symbol, um fortzufahren.","en":"Click on the green icon to continue.","ru":"Нажмите на зелёный значок, чтобы продолжить.","vi":"Bấm vào biểu tượng màu xanh lá cây để tiếp tục.","fa":"برای ادامه روی آیکون سبز رنگ کلیک کنید."},{"de":"Ich habe versehentlich den falschen Link angeklickt.","en":"I accidentally clicked on the wrong link.","ru":"Я случайно кликнул не по той ссылке.","vi":"Tôi vô tình bấm vào liên kết sai.","fa":"من تصادفاً روی لینک اشتباه کلیک کردم."}]},{"word":"ankommen","en":"to arrive","ru":"прибывать, приезжать","vi":"đến","fa":"رسیدن","examples":[{"de":"Der Zug kommt um 14 Uhr in Berlin an.","en":"The train arrives in Berlin at 2 p.m.","ru":"Поезд прибывает в Берлин в 14:00.","vi":"Tàu đến Berlin lúc 2 giờ chiều.","fa":"قطار ساعت 2 بعد از ظهر به برلین می رسد."},{"de":"Wann kommst du morgen bei uns an?","en":"When will you arrive at our place tomorrow?","ru":"Когда ты завтра к нам приедешь?","vi":"Ngày mai khi nào bạn đến?","fa":"فردا کی میرسی؟"}]},{"word":"ankündigen","en":"to announce","ru":"объявлять, анонсировать","vi":"thông báo","fa":"اعلام کند","examples":[{"de":"Die Regierung hat neue Maßnahmen angekündigt.","en":"The government has announced new measures.","ru":"Правительство объявило о новых мерах.","vi":"Die Regierung hat neue Maßnahmen angekündigt.","fa":"دولت تدابیر جدیدی را اعلام کرده است."},{"de":"Der Sturm wurde schon gestern im Radio angekündigt.","en":"The storm was already announced on the radio yesterday.","ru":"О шторме уже вчера объявили по радио.","vi":"Cơn bão đã được thông báo trên đài phát thanh ngày hôm qua.","fa":"طوفان دیروز از رادیو اعلام شد."}]},{"word":"die Ankunft","en":"arrival","ru":"прибытие","vi":"sự xuất hiện","fa":"ورود","examples":[{"de":"Die Ankunft des Fluges verzögert sich um eine Stunde.","en":"The flight's arrival is delayed by an hour.","ru":"Прибытие рейса задерживается на час.","vi":"Chuyến bay đến bị trì hoãn một giờ.","fa":"رسیدن پرواز یک ساعت تاخیر دارد."},{"de":"Bei unserer Ankunft schien die Sonne.","en":"The sun was shining upon our arrival.","ru":"К нашему прибытию светило солнце.","vi":"Mặt trời đang chiếu sáng khi chúng tôi đến.","fa":"وقتی رسیدیم خورشید داشت می درخشید."}]},{"word":"die Anlage","en":"facility, plant; enclosure","ru":"установка, комплекс; приложение (к письму)","vi":"cơ sở","fa":"تسهیلات","examples":[{"de":"In der Nähe der Stadt gibt es eine große Sportanlage.","en":"Near the city there is a large sports facility.","ru":"Недалеко от города есть большой спортивный комплекс.","vi":"Có một khu liên hợp thể thao lớn gần thành phố.","fa":"یک مجموعه ورزشی بزرگ در نزدیکی شهر وجود دارد."},{"de":"Die Rechnung finden Sie in der Anlage zu dieser E-Mail.","en":"You will find the invoice in the attachment to this email.","ru":"Счёт вы найдёте в приложении к этому письму.","vi":"Bạn có thể tìm thấy hóa đơn được đính kèm với email này.","fa":"شما می توانید فاکتور پیوست شده به این ایمیل را پیدا کنید."}]},{"word":"die Anleitung","en":"instructions, manual","ru":"инструкция","vi":"hướng dẫn","fa":"دستورالعمل ها","examples":[{"de":"Lesen Sie zuerst die Anleitung, bevor Sie das Gerät benutzen.","en":"Read the instructions first before using the device.","ru":"Сначала прочитайте инструкцию, прежде чем пользоваться устройством.","vi":"Đọc hướng dẫn trước khi sử dụng thiết bị.","fa":"قبل از استفاده از دستگاه ابتدا دستورالعمل ها را بخوانید."},{"de":"Die Anleitung zum Zusammenbau des Regals war leicht verständlich.","en":"The instructions for assembling the shelf were easy to understand.","ru":"Инструкция по сборке полки была легко понятна.","vi":"Die Anleitung zum Zusammenbau des Regals war leicht verständlich.","fa":"دستورالعمل های مونتاژ قفسه به راحتی قابل درک بود."}]},{"word":"anmelden","en":"to register","ru":"регистрировать(ся), записывать(ся)","vi":"đăng nhập","fa":"وارد شوید","examples":[{"de":"Ich muss mich noch für den Deutschkurs anmelden.","en":"I still have to register for the German course.","ru":"Мне ещё нужно записаться на курс немецкого языка.","vi":"Tôi vẫn phải đăng ký khóa học tiếng Đức.","fa":"هنوز باید برای دوره آلمانی ثبت نام کنم."},{"de":"Neue Bewohner müssen sich innerhalb von zwei Wochen anmelden.","en":"New residents have to register within two weeks.","ru":"Новые жители должны зарегистрироваться в течение двух недель.","vi":"Cư dân mới phải đăng ký trong vòng hai tuần.","fa":"ساکنین جدید باید ظرف دو هفته ثبت نام کنند."}]},{"word":"die Anmeldung","en":"registration; sign-up","ru":"регистрация; запись","vi":"việc đăng ký","fa":"ثبت نام","examples":[{"de":"Die Anmeldung für den Kurs ist ab Montag möglich.","en":"Registration for the course is possible from Monday.","ru":"Запись на курс возможна с понедельника.","vi":"Có thể đăng ký khóa học từ thứ Hai.","fa":"ثبت نام دوره از روز دوشنبه امکان پذیر است."},{"de":"Nach dem Umzug muss man zur Anmeldung aufs Amt.","en":"After moving you have to go to the office to register.","ru":"После переезда нужно пойти в учреждение на регистрацию.","vi":"Sau khi chuyển đi bạn phải đến văn phòng để đăng ký.","fa":"پس از اسباب کشی برای ثبت نام باید به دفتر مراجعه کنید."}]},{"word":"annehmen","en":"to accept; to assume","ru":"принимать; предполагать","vi":"chấp nhận","fa":"قبول کنید","examples":[{"de":"Sie hat das Geschenk dankend angenommen.","en":"She gratefully accepted the gift.","ru":"Она с благодарностью приняла подарок.","vi":"She gratefully accepted the gift.","fa":"او با قدردانی هدیه را پذیرفت."},{"de":"Ich nehme an, dass er morgen wieder da ist.","en":"I assume that he will be back tomorrow.","ru":"Я предполагаю, что завтра он снова будет на месте.","vi":"Tôi cho rằng anh ấy sẽ trở lại vào ngày mai.","fa":"فکر کنم فردا برمیگرده"}]},{"word":"die Annonce","en":"advertisement, classified ad","ru":"объявление","vi":"quảng cáo","fa":"تبلیغ","examples":[{"de":"Er hat die Wohnung durch eine Annonce in der Zeitung gefunden.","en":"He found the apartment through an ad in the newspaper.","ru":"Он нашёл квартиру через объявление в газете.","vi":"Anh tìm thấy căn hộ thông qua một quảng cáo trên báo.","fa":"او آپارتمان را از طریق یک آگهی در روزنامه پیدا کرد."},{"de":"Sie hat eine Annonce aufgegeben, um ihr altes Auto zu verkaufen.","en":"She placed an ad to sell her old car.","ru":"Она подала объявление, чтобы продать свою старую машину.","vi":"Cô ấy đăng một quảng cáo để bán chiếc xe cũ của mình.","fa":"او یک آگهی برای فروش ماشین قدیمی خود گذاشت."}]},{"word":"die Anrede","en":"form of address, salutation","ru":"обращение (в письме)","vi":"lời chào","fa":"سلام","examples":[{"de":"In einem formellen Brief benutzt man die Anrede „Sehr geehrte Damen und Herren“.","en":"In a formal letter one uses the salutation 'Dear Sir or Madam'.","ru":"В официальном письме используется обращение «Уважаемые дамы и господа».","vi":"Trong một bức thư trang trọng, lời chào “Dear Sir or Madam” được sử dụng.","fa":"در نامه رسمی از سلام آقا یا خانم عزیز استفاده شده است."},{"de":"Welche Anrede ist bei einer E-Mail an den Professor passend?","en":"Which form of address is appropriate for an email to the professor?","ru":"Какое обращение уместно в письме профессору?","vi":"Lời chào nào là phù hợp khi gửi email cho giáo sư?","fa":"هنگام ارسال ایمیل به استاد چه سلامی مناسب است؟"}]},{"word":"der Anrufbeantworter","en":"answering machine","ru":"автоответчик","vi":"máy trả lời","fa":"منشی تلفنی","examples":[{"de":"Er war nicht zu Hause, also sprach ich auf den Anrufbeantworter.","en":"He wasn't home, so I left a message on the answering machine.","ru":"Его не было дома, поэтому я оставил сообщение на автоответчике.","vi":"Anh ấy không có nhà nên tôi để lại máy trả lời tự động.","fa":"او خانه نبود، من از منشی تلفنی خارج شدم."},{"de":"Bitte hinterlassen Sie nach dem Ton eine Nachricht auf dem Anrufbeantworter.","en":"Please leave a message on the answering machine after the beep.","ru":"Пожалуйста, оставьте сообщение на автоответчике после сигнала.","vi":"Vui lòng để lại tin nhắn trên máy trả lời sau tiếng chuông.","fa":"لطفا بعد از تون در منشی تلفنی پیام بگذارید."}]},{"word":"anrufen","en":"to call, to phone","ru":"звонить","vi":"gọi","fa":"تماس بگیرید","examples":[{"de":"Ruf mich bitte an, wenn du angekommen bist.","en":"Please call me when you have arrived.","ru":"Позвони мне, пожалуйста, когда приедешь.","vi":"Hãy gọi cho tôi khi bạn đến.","fa":"لطفا وقتی رسیدی با من تماس بگیر"},{"de":"Ich habe dich dreimal angerufen, aber niemand hat abgehoben.","en":"I called you three times, but nobody picked up.","ru":"Я звонил тебе три раза, но никто не ответил.","vi":"Tôi gọi cho bạn ba lần nhưng không ai bắt máy.","fa":"من سه بار با شما تماس گرفتم اما کسی نگرفت."}]},{"word":"die Ansage","en":"announcement","ru":"объявление (устное)","vi":"thông báo","fa":"اعلامیه","examples":[{"de":"Wegen einer Durchsage konnten wir die Ansage am Bahnhof kaum verstehen.","en":"Because of the announcement, we could hardly understand the message at the station.","ru":"Из-за объявления мы едва могли расслышать сообщение на вокзале.","vi":"Vì một thông báo nên chúng tôi khó có thể hiểu được thông báo ở ga xe lửa.","fa":"به دلیل یک اعلامیه، ما به سختی می‌توانستیم اطلاعیه ایستگاه قطار را بفهمیم."},{"de":"Die Ansage im Flugzeug informierte uns über die Landung.","en":"The announcement on the plane informed us about the landing.","ru":"Объявление в самолёте сообщило нам о посадке.","vi":"Thông báo trên máy bay thông báo cho chúng tôi về việc hạ cánh.","fa":"اعلامیه هواپیما به ما خبر فرود می داد."}]},{"word":"anschaffen","en":"to acquire, to purchase","ru":"приобретать","vi":"có được","fa":"بدست آوردن","examples":[{"de":"Wir wollen uns bald einen neuen Kühlschrank anschaffen.","en":"We want to acquire a new refrigerator soon.","ru":"Мы скоро хотим приобрести новый холодильник.","vi":"We want to buy a new refrigerator soon.","fa":"ما می خواهیم به زودی یک یخچال جدید بخریم."},{"de":"Er hat sich ein teures Fahrrad angeschafft.","en":"He acquired an expensive bicycle.","ru":"Он приобрёл дорогой велосипед.","vi":"Anh ấy đã mua một chiếc xe đạp đắt tiền.","fa":"او یک دوچرخه گران قیمت خرید."}]},{"word":"anschließen","en":"to connect; to join","ru":"подключать; присоединяться","vi":"kết nối","fa":"اتصال","examples":[{"de":"Kannst du bitte den Drucker an den Computer anschließen?","en":"Can you please connect the printer to the computer?","ru":"Можешь, пожалуйста, подключить принтер к компьютеру?","vi":"Bạn có thể vui lòng kết nối máy in với máy tính được không?","fa":"آیا می توانید چاپگر را به کامپیوتر وصل کنید؟"},{"de":"Ich schließe mich deiner Meinung an.","en":"I agree with (join) your opinion.","ru":"Я присоединяюсь к твоему мнению.","vi":"Ich schließe mich deiner Meinung an.","fa":"من با نظر شما موافقم"}]},{"word":"der Anschluss","en":"connection","ru":"соединение, подключение","vi":"sự kết nối","fa":"اتصال","examples":[{"de":"In Frankfurt haben wir Anschluss an den Zug nach München.","en":"In Frankfurt we have a connection to the train to Munich.","ru":"Во Франкфурте у нас пересадка на поезд в Мюнхен.","vi":"Tại Frankfurt, chúng tôi kết nối tàu đến Munich.","fa":"در فرانکفورت به قطار مونیخ متصل می شویم."},{"de":"Wir brauchen einen schnelleren Internetanschluss.","en":"We need a faster internet connection.","ru":"Нам нужно более быстрое подключение к интернету.","vi":"Chúng tôi cần kết nối internet nhanh hơn.","fa":"ما به اینترنت سریعتر نیاز داریم."}]},{"word":"anschnallen","en":"to fasten (a seatbelt)","ru":"пристёгивать(ся)","vi":"thắt dây an toàn","fa":"دست و پنجه نرم کردن","examples":[{"de":"Bitte schnallen Sie sich an, bevor das Auto losfährt.","en":"Please fasten your seatbelt before the car starts driving.","ru":"Пожалуйста, пристегнитесь, прежде чем машина тронется.","vi":"Vui lòng thắt dây an toàn trước khi xe chạy đi.","fa":"لطفا قبل از پیاده شدن خودرو کمربند ایمنی خود را ببندید."},{"de":"Alle Passagiere müssen sich beim Start anschnallen.","en":"All passengers must fasten their seatbelts during takeoff.","ru":"Все пассажиры должны пристегнуться во время взлёта.","vi":"Tất cả hành khách phải thắt dây an toàn khi cất cánh.","fa":"همه مسافران هنگام بلند شدن باید کمربند ایمنی خود را ببندند."}]},{"word":"ansehen","en":"to look at, to watch","ru":"смотреть, рассматривать","vi":"lượt xem","fa":"مشاهده کنید","examples":[{"de":"Wollen wir uns heute Abend einen Film ansehen?","en":"Shall we watch a movie tonight?","ru":"Может, посмотрим сегодня вечером фильм?","vi":"Tối nay chúng ta cùng xem phim nhé?","fa":"امشب فیلم ببینیم؟"},{"de":"Er sah sich die Fotos lange an.","en":"He looked at the photos for a long time.","ru":"Он долго рассматривал фотографии.","vi":"Anh nhìn những bức ảnh rất lâu.","fa":"مدت زیادی به عکس ها نگاه کرد."}]},{"word":"ansprechen","en":"to address, to speak to","ru":"обращаться (к кому-то), заговаривать","vi":"địa chỉ","fa":"آدرس","examples":[{"de":"Eine fremde Frau sprach mich auf der Straße an.","en":"A stranger (woman) spoke to me on the street.","ru":"Незнакомая женщина заговорила со мной на улице.","vi":"Eine fremde Frau sprach mich auf der Straße an.","fa":"زنی غریبه در خیابان با من صحبت کرد."},{"de":"Ich möchte dieses Thema kurz ansprechen.","en":"I would like to briefly address this topic.","ru":"Я хотел бы кратко затронуть эту тему.","vi":"Tôi muốn giải quyết ngắn gọn chủ đề này.","fa":"من می خواهم به طور خلاصه به این موضوع بپردازم."}]},{"word":"der Anspruch","en":"claim, entitlement","ru":"право, притязание","vi":"yêu cầu bồi thường","fa":"ادعا","examples":[{"de":"Sie hat Anspruch auf drei Wochen Urlaub im Jahr.","en":"She is entitled to three weeks of vacation per year.","ru":"Она имеет право на три недели отпуска в год.","vi":"Cô được hưởng ba tuần nghỉ phép mỗi năm.","fa":"او حق دارد سه هفته مرخصی در سال داشته باشد."},{"de":"Er erhebt keinen Anspruch auf das Erbe seines Onkels.","en":"He does not claim any right to his uncle's inheritance.","ru":"Он не претендует на наследство своего дяди.","vi":"Anh ta tuyên bố không có yêu cầu gì về quyền thừa kế của chú mình.","fa":"او ادعایی در مورد ارث عمویش ندارد."}]},{"word":"anstellen","en":"to employ, hire; to turn on","ru":"нанимать; включать; вставать в очередь","vi":"thuê","fa":"استخدام کنید","examples":[{"de":"Die Firma hat letzten Monat drei neue Mitarbeiter angestellt.","en":"The company hired three new employees last month.","ru":"В прошлом месяце компания наняла трёх новых сотрудников.","vi":"Công ty đã thuê ba nhân viên mới vào tháng trước.","fa":"این شرکت ماه گذشته سه کارمند جدید استخدام کرد."},{"de":"Wir mussten uns lange an der Kasse anstellen.","en":"We had to queue up for a long time at the checkout.","ru":"Нам пришлось долго стоять в очереди у кассы.","vi":"We had to queue for a long time at the checkout.","fa":"ما مجبور شدیم برای مدت طولانی در صندوق خانه صف بکشیم."}]},{"word":"der Antrag","en":"application, request (formal)","ru":"заявление, ходатайство","vi":"ứng dụng","fa":"برنامه","examples":[{"de":"Sie hat einen Antrag auf Kindergeld gestellt.","en":"She submitted an application for child benefit.","ru":"Она подала заявление на получение пособия на ребёнка.","vi":"Cô ấy đã nộp đơn xin trợ cấp nuôi con.","fa":"او درخواست کمک هزینه فرزند کرده است."},{"de":"Der Antrag auf ein Visum kann online gestellt werden.","en":"The application for a visa can be submitted online.","ru":"Заявление на визу можно подать онлайн.","vi":"Đơn xin thị thực có thể được nộp trực tuyến.","fa":"درخواست ویزا را می توان به صورت آنلاین ارسال کرد."}]},{"word":"antworten","en":"to answer","ru":"отвечать","vi":"câu trả lời","fa":"پاسخ دهید","examples":[{"de":"Bitte antworten Sie mir bis Freitag auf meine E-Mail.","en":"Please reply to my email by Friday.","ru":"Пожалуйста, ответьте мне на письмо до пятницы.","vi":"Vui lòng trả lời email của tôi trước thứ Sáu.","fa":"لطفا تا جمعه به ایمیل من پاسخ دهید."},{"de":"Er antwortete nicht auf meine Frage.","en":"He did not answer my question.","ru":"Он не ответил на мой вопрос.","vi":"Anh ấy không trả lời câu hỏi của tôi.","fa":"به سوال من جواب نداد"}]},{"word":"der Anwalt","en":"lawyer","ru":"адвокат","vi":"luật sư","fa":"وکیل","examples":[{"de":"Sie hat einen Anwalt eingeschaltet, um ihre Rechte durchzusetzen.","en":"She engaged a lawyer to enforce her rights.","ru":"Она наняла адвоката, чтобы отстоять свои права.","vi":"Cô đã thuê luật sư để thực thi quyền lợi của mình.","fa":"او برای احقاق حقوق خود وکیل گرفت."},{"de":"Mein Bruder arbeitet als Anwalt in einer großen Kanzlei.","en":"My brother works as a lawyer at a large law firm.","ru":"Мой брат работает адвокатом в крупной юридической фирме.","vi":"Anh trai tôi làm luật sư ở một công ty luật lớn.","fa":"برادرم در یک موسسه حقوقی بزرگ به عنوان وکیل کار می کند."}]},{"word":"anwenden","en":"to apply, to use","ru":"применять","vi":"áp dụng","fa":"اعمال شود","examples":[{"de":"Man sollte die neuen Regeln in der Praxis anwenden.","en":"One should apply the new rules in practice.","ru":"Новые правила следует применять на практике.","vi":"Các quy định mới nên được áp dụng vào thực tế.","fa":"قوانین جدید باید در عمل اعمال شود."},{"de":"Diese Methode wird häufig in der Medizin angewendet.","en":"This method is often used in medicine.","ru":"Этот метод часто применяется в медицине.","vi":"Phương pháp này thường được sử dụng trong y học.","fa":"این روش اغلب در پزشکی استفاده می شود."}]},{"word":"anwesend","en":"present","ru":"присутствующий","vi":"hiện tại","fa":"حاضر","examples":[{"de":"Bei der Sitzung waren alle Mitglieder anwesend.","en":"All members were present at the meeting.","ru":"На заседании присутствовали все члены.","vi":"Tất cả các thành viên đều có mặt tại cuộc họp.","fa":"همه اعضا در جلسه حضور داشتند."},{"de":"Der Lehrer prüft zu Beginn der Stunde, wer anwesend ist.","en":"The teacher checks at the beginning of the lesson who is present.","ru":"Учитель в начале урока проверяет, кто присутствует.","vi":"Khi bắt đầu bài học, giáo viên kiểm tra xem ai có mặt.","fa":"در ابتدای درس، معلم بررسی می کند که چه کسی حاضر است."}]},{"word":"anzeigen","en":"to display, indicate; to report (to police)","ru":"показывать, отображать; заявлять (в полицию)","vi":"hiển thị","fa":"نشان می دهد","examples":[{"de":"Das Thermometer zeigt 25 Grad an.","en":"The thermometer shows 25 degrees.","ru":"Термометр показывает 25 градусов.","vi":"Nhiệt kế hiển thị 25 độ.","fa":"دماسنج 25 درجه را نشان می دهد."},{"de":"Sie hat den Diebstahl bei der Polizei angezeigt.","en":"She reported the theft to the police.","ru":"Она заявила о краже в полицию.","vi":"Cô đã báo cáo vụ trộm cho cảnh sát.","fa":"دزدی را به پلیس گزارش داد."}]},{"word":"der Anzug","en":"suit","ru":"костюм","vi":"bộ đồ","fa":"کت و شلوار","examples":[{"de":"Er trägt einen dunklen Anzug zur Hochzeit.","en":"He wears a dark suit to the wedding.","ru":"Он надевает тёмный костюм на свадьбу.","vi":"Anh ấy mặc một bộ đồ tối màu đến đám cưới.","fa":"او برای عروسی کت و شلوار تیره می پوشد."},{"de":"Ich muss mir einen neuen Anzug für das Vorstellungsgespräch kaufen.","en":"I need to buy a new suit for the job interview.","ru":"Мне нужно купить новый костюм для собеседования.","vi":"Tôi phải mua một bộ đồ mới cho cuộc phỏng vấn.","fa":"برای مصاحبه باید کت و شلوار جدید بخرم."}]},{"word":"das Apartment","en":"apartment","ru":"квартира, апартаменты","vi":"căn hộ","fa":"آپارتمان","examples":[{"de":"Sie wohnt in einem kleinen Apartment im Stadtzentrum.","en":"She lives in a small apartment in the city center.","ru":"Она живёт в маленькой квартире в центре города.","vi":"Cô sống trong một căn hộ nhỏ ở trung tâm thành phố.","fa":"او در یک آپارتمان کوچک در مرکز شهر زندگی می کند."},{"de":"Wir mieten ein Apartment für unseren Urlaub.","en":"We are renting an apartment for our vacation.","ru":"Мы снимаем квартиру на время отпуска.","vi":"Chúng tôi thuê một căn hộ cho kỳ nghỉ của chúng tôi.","fa":"ما یک آپارتمان برای تعطیلات خود اجاره می کنیم."}]},{"word":"der Apfel","en":"apple","ru":"яблоко","vi":"quả táo","fa":"سیب","examples":[{"de":"Ich esse jeden Morgen einen Apfel.","en":"I eat an apple every morning.","ru":"Я ем яблоко каждое утро.","vi":"Tôi ăn một quả táo vào mỗi buổi sáng.","fa":"من هر روز صبح یک سیب می خورم."},{"de":"Der Apfel schmeckt süß und saftig.","en":"The apple tastes sweet and juicy.","ru":"Яблоко на вкус сладкое и сочное.","vi":"Táo có vị ngọt và mọng nước.","fa":"طعم سیب شیرین و آبدار است."}]},{"word":"die Apotheke","en":"pharmacy","ru":"аптека","vi":"hiệu thuốc","fa":"داروخانه","examples":[{"de":"Ich hole meine Medikamente in der Apotheke ab.","en":"I pick up my medication at the pharmacy.","ru":"Я забираю свои лекарства в аптеке.","vi":"Tôi lấy thuốc từ hiệu thuốc.","fa":"من داروهایم را از داروخانه می گیرم."},{"de":"Die Apotheke hat auch am Wochenende geöffnet.","en":"The pharmacy is open on weekends too.","ru":"Аптека открыта и по выходным.","vi":"Hiệu thuốc cũng mở cửa vào cuối tuần.","fa":"این داروخانه در روزهای آخر هفته نیز باز است."}]},{"word":"der Apparat","en":"apparatus, device","ru":"аппарат","vi":"bộ máy","fa":"دستگاه","examples":[{"de":"Der Arzt untersucht mich mit einem speziellen Apparat.","en":"The doctor examines me with a special device.","ru":"Врач осматривает меня с помощью специального аппарата.","vi":"Bác sĩ khám cho tôi bằng một thiết bị đặc biệt.","fa":"دکتر با دستگاه مخصوص معاینه ام می کند."},{"de":"Bleiben Sie bitte am Apparat, ich verbinde Sie.","en":"Please stay on the line, I'll connect you.","ru":"Пожалуйста, оставайтесь на линии, я вас соединю.","vi":"Xin vui lòng giữ máy và tôi sẽ nối máy cho bạn.","fa":"لطفا در خط بمانید و من شما را وصل خواهم کرد."}]},{"word":"der Appetit","en":"appetite","ru":"аппетит","vi":"sự thèm ăn","fa":"اشتها","examples":[{"de":"Guten Appetit!","en":"Enjoy your meal!","ru":"Приятного аппетита!","vi":"Chúc bạn ngon miệng!","fa":"اشتهای مبارک!"},{"de":"Nach dem langen Spaziergang habe ich großen Appetit.","en":"After the long walk I have a big appetite.","ru":"После долгой прогулки у меня отличный аппетит.","vi":"Sau chuyến đi bộ dài, tôi cảm thấy thèm ăn.","fa":"بعد از پیاده روی طولانی اشتهای زیادی دارم."}]},{"word":"die Aprikose","en":"apricot","ru":"абрикос","vi":"quả mơ","fa":"زردآلو","examples":[{"de":"Die Aprikosen sind im Sommer besonders süß.","en":"Apricots are especially sweet in summer.","ru":"Абрикосы особенно сладкие летом.","vi":"Quả mơ đặc biệt ngọt vào mùa hè.","fa":"زردآلو به خصوص در تابستان شیرین است."},{"de":"Sie kauft ein Kilo Aprikosen auf dem Markt.","en":"She buys a kilo of apricots at the market.","ru":"Она покупает килограмм абрикосов на рынке.","vi":"Cô ấy mua một kg mơ ở chợ.","fa":"او یک کیلو زردآلو از بازار می خرد."}]},{"word":"arbeiten","en":"to work","ru":"работать","vi":"làm việc","fa":"کار کردن","examples":[{"de":"Er arbeitet seit fünf Jahren in dieser Firma.","en":"He has been working at this company for five years.","ru":"Он работает в этой фирме уже пять лет.","vi":"Anh ấy đã làm việc ở công ty này được 5 năm.","fa":"او پنج سال است که در این شرکت کار می کند."},{"de":"Ich arbeite jeden Tag von acht bis vier.","en":"I work every day from eight to four.","ru":"Я работаю каждый день с восьми до четырёх.","vi":"Tôi làm việc từ tám đến bốn giờ mỗi ngày.","fa":"من هر روز از هشت تا چهار کار می کنم."}]},{"word":"der Arbeitgeber","en":"employer","ru":"работодатель","vi":"người sử dụng lao động","fa":"کارفرما","examples":[{"de":"Mein Arbeitgeber bietet flexible Arbeitszeiten an.","en":"My employer offers flexible working hours.","ru":"Мой работодатель предлагает гибкий график работы.","vi":"Chủ lao động của tôi đưa ra giờ làm việc linh hoạt.","fa":"کارفرمای من ساعات کاری انعطاف پذیری را ارائه می دهد."},{"de":"Der Arbeitgeber muss sich an das Gesetz halten.","en":"The employer has to comply with the law.","ru":"Работодатель обязан соблюдать закон.","vi":"Người sử dụng lao động phải tuân thủ pháp luật.","fa":"کارفرما باید قانون را رعایت کند."}]},{"word":"der Arbeitnehmer","en":"employee","ru":"работник; сотрудник","vi":"nhân viên","fa":"کارمند","examples":[{"de":"Jeder Arbeitnehmer hat ein Recht auf Urlaub.","en":"Every employee has a right to holiday.","ru":"Каждый работник имеет право на отпуск.","vi":"Mọi nhân viên đều có quyền nghỉ phép.","fa":"هر کارمند حق مرخصی دارد."},{"de":"Die Arbeitnehmer fordern höhere Löhne.","en":"The employees are demanding higher wages.","ru":"Работники требуют повышения зарплаты.","vi":"Công nhân đang đòi hỏi mức lương cao hơn.","fa":"کارگران خواهان افزایش دستمزد هستند."}]},{"word":"der Architekt","en":"architect","ru":"архитектор","vi":"kiến trúc sư","fa":"معمار","examples":[{"de":"Der Architekt plant ein neues Bürogebäude.","en":"The architect is planning a new office building.","ru":"Архитектор проектирует новое офисное здание.","vi":"Kiến trúc sư đang lên kế hoạch xây dựng một tòa nhà văn phòng mới.","fa":"معمار در حال برنامه ریزی یک ساختمان اداری جدید است."},{"de":"Sie möchte Architektin werden und Häuser entwerfen.","en":"She wants to become an architect and design houses.","ru":"Она хочет стать архитектором и проектировать дома.","vi":"Cô muốn trở thành một kiến ​​trúc sư và thiết kế nhà cửa.","fa":"او می خواهد معمار شود و خانه ها را طراحی کند."}]},{"word":"arm","en":"poor","ru":"бедный","vi":"nghèo nàn","fa":"فقیر","examples":[{"de":"Die Familie war früher sehr arm.","en":"The family used to be very poor.","ru":"Раньше семья была очень бедной.","vi":"Gia đình ngày xưa rất nghèo.","fa":"خانواده قبلاً بسیار فقیر بودند."},{"de":"Viele Menschen in dieser Region sind arm.","en":"Many people in this region are poor.","ru":"Многие люди в этом регионе бедны.","vi":"Nhiều người ở vùng này nghèo.","fa":"بسیاری از مردم این منطقه فقیر هستند."}]},{"word":"der Arm","en":"arm","ru":"рука (от плеча до кисти)","vi":"cánh tay","fa":"بازو","examples":[{"de":"Er hat sich beim Fußball den Arm gebrochen.","en":"He broke his arm playing football.","ru":"Он сломал руку, играя в футбол.","vi":"Anh ấy bị gãy tay khi chơi bóng đá.","fa":"او در بازی فوتبال دستش شکست."},{"de":"Sie trägt das Kind auf dem Arm.","en":"She carries the child in her arms.","ru":"Она несёт ребёнка на руках.","vi":"Cô bế đứa trẻ trên tay.","fa":"او کودک را در آغوش می گیرد."}]},{"word":"die Art","en":"kind, type; way, manner","ru":"вид, тип; способ","vi":"loại","fa":"نوع","examples":[{"de":"Das ist eine besondere Art von Musik.","en":"That is a special kind of music.","ru":"Это особый вид музыки.","vi":"Đây là một loại âm nhạc đặc biệt.","fa":"این یک نوع موسیقی خاص است."},{"de":"Er löst Probleme auf seine eigene Art.","en":"He solves problems in his own way.","ru":"Он решает проблемы по-своему.","vi":"Anh ấy giải quyết vấn đề theo cách riêng của mình.","fa":"او مشکلات را به روش خودش حل می کند."}]},{"word":"der Artikel","en":"article; item","ru":"статья; товар","vi":"bài báo","fa":"مقاله","examples":[{"de":"Ich habe einen interessanten Artikel in der Zeitung gelesen.","en":"I read an interesting article in the newspaper.","ru":"Я прочитал интересную статью в газете.","vi":"Tôi đọc được một bài viết thú vị trên báo.","fa":"مقاله جالبی در روزنامه خواندم."},{"de":"Dieser Artikel ist im Moment leider nicht vorrätig.","en":"This item is unfortunately out of stock at the moment.","ru":"К сожалению, этого товара сейчас нет в наличии.","vi":"Thật không may, mặt hàng này hiện đã hết hàng.","fa":"متاسفانه این کالا در حال حاضر موجود نیست."}]},{"word":"der Arzt","en":"doctor","ru":"врач","vi":"bác sĩ","fa":"دکتر","examples":[{"de":"Ich habe morgen einen Termin beim Arzt.","en":"I have an appointment with the doctor tomorrow.","ru":"Завтра у меня приём у врача.","vi":"Tôi có hẹn với bác sĩ vào ngày mai.","fa":"فردا با دکتر وقت دارم"},{"de":"Der Arzt untersucht den Patienten gründlich.","en":"The doctor examines the patient thoroughly.","ru":"Врач тщательно осматривает пациента.","vi":"Bác sĩ khám bệnh nhân kỹ lưỡng.","fa":"پزشک بیمار را به طور کامل معاینه می کند."}]},{"word":"das Asyl","en":"asylum","ru":"убежище","vi":"trại tị nạn","fa":"پناهندگی","examples":[{"de":"Der Flüchtling beantragt Asyl in Deutschland.","en":"The refugee applies for asylum in Germany.","ru":"Беженец подаёт заявление на убежище в Германии.","vi":"Người tị nạn nộp đơn xin tị nạn ở Đức.","fa":"این پناهنده در آلمان درخواست پناهندگی می کند."},{"de":"Viele Menschen suchen politisches Asyl in Europa.","en":"Many people seek political asylum in Europe.","ru":"Многие люди ищут политическое убежище в Европе.","vi":"Nhiều người đang xin tị nạn chính trị ở châu Âu.","fa":"بسیاری از مردم به دنبال پناهندگی سیاسی در اروپا هستند."}]},{"word":"atmen","en":"to breathe","ru":"дышать","vi":"thở","fa":"نفس بکش","examples":[{"de":"Nach dem Lauf musste er tief atmen.","en":"After the run he had to breathe deeply.","ru":"После пробежки ему нужно было глубоко дышать.","vi":"Sau khi chạy anh phải thở thật sâu.","fa":"بعد از دویدن مجبور شد نفس عمیقی بکشد."},{"de":"Atmen Sie ruhig ein und aus.","en":"Breathe in and out calmly.","ru":"Спокойно вдыхайте и выдыхайте.","vi":"Thở vào và thở ra một cách bình tĩnh.","fa":"با آرامش نفس به داخل و خارج کنید."}]},{"word":"auch","en":"also, too","ru":"тоже, также","vi":"cũng","fa":"همچنین","examples":[{"de":"Ich mag Kaffee, aber ich trinke auch gern Tee.","en":"I like coffee, but I also like drinking tea.","ru":"Мне нравится кофе, но я также люблю пить чай.","vi":"Tôi thích cà phê nhưng tôi cũng thích uống trà.","fa":"من قهوه را دوست دارم، اما نوشیدن چای را هم دوست دارم."},{"de":"Kommst du auch zur Party?","en":"Are you coming to the party too?","ru":"Ты тоже придёшь на вечеринку?","vi":"Bạn cũng đến dự tiệc à?","fa":"آیا شما هم به مهمانی می آیید؟"}]},{"word":"auf","en":"on, onto; open","ru":"на; открыто","vi":"trên","fa":"در","examples":[{"de":"Das Buch liegt auf dem Tisch.","en":"The book is lying on the table.","ru":"Книга лежит на столе.","vi":"Cuốn sách ở trên bàn.","fa":"کتاب روی میز است."},{"de":"Die Tür ist den ganzen Tag auf.","en":"The door is open all day.","ru":"Дверь открыта весь день.","vi":"Cửa mở cả ngày.","fa":"در تمام روز باز است."}]},{"word":"der Aufenthalt","en":"stay","ru":"пребывание","vi":"ở lại","fa":"اقامت","examples":[{"de":"Wir wünschen Ihnen einen angenehmen Aufenthalt.","en":"We wish you a pleasant stay.","ru":"Желаем вам приятного пребывания.","vi":"Chúng tôi chúc bạn một kỳ nghỉ thú vị.","fa":"اقامت خوشی را برای شما آرزومندیم."},{"de":"Der Aufenthalt in diesem Land war für mich sehr lehrreich.","en":"My stay in this country was very educational for me.","ru":"Пребывание в этой стране было для меня очень поучительным.","vi":"Thời gian ở đất nước này mang lại cho tôi rất nhiều kiến ​​thức.","fa":"اقامت من در این کشور برایم بسیار آموزشی بود."}]},{"word":"auffallen","en":"to stand out, be noticeable","ru":"бросаться в глаза, выделяться","vi":"nổi bật","fa":"برجسته شدن","examples":[{"de":"Ihr rotes Kleid fällt sofort auf.","en":"Her red dress stands out immediately.","ru":"Её красное платье сразу бросается в глаза.","vi":"Chiếc váy đỏ của cô gây chú ý ngay lập tức.","fa":"لباس قرمز او بلافاصله به چشم می خورد."},{"de":"Es fiel mir auf, dass er heute sehr müde aussah.","en":"I noticed that he looked very tired today.","ru":"Я заметил, что сегодня он выглядел очень уставшим.","vi":"Tôi nhận thấy hôm nay anh ấy trông rất mệt mỏi.","fa":"من متوجه شدم که او امروز بسیار خسته به نظر می رسد."}]},{"word":"auffordern","en":"to ask/tell someone to do something","ru":"призывать, требовать (сделать что-то)","vi":"nhắc nhở","fa":"سریع","examples":[{"de":"Der Lehrer forderte die Schüler auf, ruhig zu sein.","en":"The teacher told the students to be quiet.","ru":"Учитель призвал учеников вести себя тихо.","vi":"Giáo viên yêu cầu học sinh im lặng.","fa":"معلم از دانش آموزان خواست ساکت باشند."},{"de":"Die Polizei forderte ihn auf, seinen Ausweis zu zeigen.","en":"The police asked him to show his ID.","ru":"Полиция потребовала, чтобы он показал удостоверение личности.","vi":"Cảnh sát yêu cầu anh ta xuất trình giấy tờ tùy thân.","fa":"پلیس از او خواست شناسنامه خود را نشان دهد."}]},{"word":"aufführen","en":"to perform (a play)","ru":"исполнять, ставить (спектакль)","vi":"thực hiện","fa":"انجام دهد","examples":[{"de":"Das Theater führt heute Abend ein neues Stück auf.","en":"The theater is performing a new play tonight.","ru":"Сегодня вечером театр ставит новую пьесу.","vi":"Nhà hát sẽ biểu diễn một vở kịch mới tối nay.","fa":"این تئاتر امشب نمایش جدیدی را اجرا می کند."},{"de":"Die Schüler führen ein Weihnachtsstück auf.","en":"The students are performing a Christmas play.","ru":"Ученики ставят рождественскую пьесу.","vi":"Học sinh biểu diễn vở kịch Giáng sinh.","fa":"دانش آموزان یک نمایش کریسمس اجرا می کنند."}]},{"word":"die Aufführung","en":"performance (show)","ru":"постановка; спектакль","vi":"hiệu suất","fa":"عملکرد","examples":[{"de":"Die Aufführung des Stücks war ein großer Erfolg.","en":"The performance of the play was a great success.","ru":"Постановка пьесы имела большой успех.","vi":"Buổi biểu diễn của tác phẩm đã thành công tốt đẹp.","fa":"اجرای این قطعه موفقیت بزرگی بود."},{"de":"Nach der Aufführung gab es viel Applaus.","en":"There was a lot of applause after the performance.","ru":"После спектакля было много аплодисментов.","vi":"Có rất nhiều tiếng vỗ tay sau màn trình diễn.","fa":"پس از اجرا تشویق های زیادی به راه افتاد."}]},{"word":"die Aufgabe","en":"task, exercise","ru":"задача, задание","vi":"nhiệm vụ","fa":"وظیفه","examples":[{"de":"Die Lehrerin gibt den Schülern eine schwierige Aufgabe.","en":"The teacher gives the students a difficult task.","ru":"Учительница даёт ученикам сложное задание.","vi":"Giáo viên giao cho học sinh một bài tập khó.","fa":"معلم کار دشواری به دانش آموزان می دهد."},{"de":"Ich habe meine Hausaufgaben noch nicht gemacht.","en":"I haven't done my homework yet.","ru":"Я ещё не сделал домашнее задание.","vi":"Tôi vẫn chưa làm bài tập về nhà.","fa":"من هنوز تکالیفم را انجام نداده ام."}]},{"word":"aufgeben","en":"to give up; to mail (a parcel)","ru":"сдаваться, отказываться; отправлять (посылку)","vi":"từ bỏ","fa":"تسلیم شدن","examples":[{"de":"Er hat das Rauchen endlich aufgegeben.","en":"He has finally given up smoking.","ru":"Он наконец бросил курить.","vi":"Cuối cùng anh ấy đã bỏ thuốc lá.","fa":"بالاخره سیگار را ترک کرد."},{"de":"Ich muss noch ein Paket auf der Post aufgeben.","en":"I still need to mail a package at the post office.","ru":"Мне ещё нужно отправить посылку на почте.","vi":"Tôi vẫn phải gửi gói hàng ở bưu điện.","fa":"من هنوز باید یک بسته را به اداره پست تحویل دهم."}]},{"word":"aufhalten","en":"to hold up, delay; (sich aufhalten) to stay","ru":"задерживать; (sich aufhalten) находиться","vi":"dừng lại","fa":"توقف","examples":[{"de":"Der Stau hat uns eine Stunde aufgehalten.","en":"The traffic jam delayed us for an hour.","ru":"Пробка задержала нас на час.","vi":"Ùn tắc giao thông đã khiến chúng tôi bị trì hoãn trong một giờ.","fa":"ترافیک ما را یک ساعت معطل کرد."},{"de":"Er hält sich zurzeit in Berlin auf.","en":"He is currently staying in Berlin.","ru":"Сейчас он находится в Берлине.","vi":"Anh ấy hiện đang ở Berlin.","fa":"او در حال حاضر در برلین است."}]},{"word":"aufheben","en":"to pick up; to keep, save","ru":"поднимать; хранить","vi":"hủy bỏ","fa":"لغو","examples":[{"de":"Kannst du bitte den Stift vom Boden aufheben?","en":"Can you please pick up the pen from the floor?","ru":"Можешь поднять ручку с пола, пожалуйста?","vi":"Bạn có thể vui lòng nhặt cây bút từ dưới sàn lên được không?","fa":"لطفاً می توانید خودکار را از روی زمین بردارید؟"},{"de":"Ich hebe alte Briefe als Erinnerung auf.","en":"I keep old letters as a memento.","ru":"Я храню старые письма на память.","vi":"Tôi giữ những lá thư cũ làm kỷ niệm.","fa":"نامه های قدیمی را به عنوان خاطره نگه می دارم."}]},{"word":"aufhören","en":"to stop","ru":"прекращать, переставать","vi":"dừng lại","fa":"توقف","examples":[{"de":"Der Regen hat endlich aufgehört.","en":"The rain has finally stopped.","ru":"Дождь наконец прекратился.","vi":"Cơn mưa cuối cùng cũng đã tạnh.","fa":"بالاخره باران قطع شد."},{"de":"Hör auf zu schreien!","en":"Stop screaming!","ru":"Перестань кричать!","vi":"Đừng la hét nữa!","fa":"دست از جیغ زدن بردارید!"}]},{"word":"aufladen","en":"to charge (a battery); to load","ru":"заряжать; загружать","vi":"tính phí","fa":"شارژ","examples":[{"de":"Ich muss mein Handy noch aufladen.","en":"I still need to charge my phone.","ru":"Мне ещё нужно зарядить телефон.","vi":"Tôi vẫn cần sạc điện thoại của mình.","fa":"من هنوز باید گوشیم را شارژ کنم."},{"de":"Wir laden die Kisten auf den Lastwagen auf.","en":"We load the boxes onto the truck.","ru":"Мы грузим ящики на грузовик.","vi":"Chúng tôi chất các hộp lên xe tải.","fa":"جعبه ها را روی کامیون بار می کنیم."}]},{"word":"auflösen","en":"to dissolve, resolve; to disband","ru":"растворять; расформировывать","vi":"hòa tan","fa":"حل کردن","examples":[{"de":"Der Zucker löst sich schnell im warmen Wasser auf.","en":"The sugar dissolves quickly in warm water.","ru":"Сахар быстро растворяется в тёплой воде.","vi":"Đường tan nhanh trong nước ấm.","fa":"شکر به سرعت در آب گرم حل می شود."},{"de":"Die Firma wurde nach der Krise aufgelöst.","en":"The company was dissolved after the crisis.","ru":"После кризиса компания была расформирована.","vi":"Công ty đã bị giải thể sau cuộc khủng hoảng.","fa":"این شرکت پس از بحران منحل شد."}]},{"word":"aufmerksam","en":"attentive","ru":"внимательный","vi":"chú ý","fa":"توجه","examples":[{"de":"Die Schüler hören dem Lehrer aufmerksam zu.","en":"The students listen attentively to the teacher.","ru":"Ученики внимательно слушают учителя.","vi":"Học sinh chăm chú lắng nghe giáo viên giảng.","fa":"دانش آموزان با دقت به صحبت های معلم گوش می دهند."},{"de":"Er ist ein aufmerksamer Zuhörer.","en":"He is an attentive listener.","ru":"Он внимательный слушатель.","vi":"Anh ấy là một người biết lắng nghe.","fa":"او شنونده ای با دقت است."}]},{"word":"aufnehmen","en":"to record; to admit","ru":"записывать; принимать","vi":"ghi lại","fa":"رکورد","examples":[{"de":"Wir nehmen das Konzert auf Video auf.","en":"We record the concert on video.","ru":"Мы записываем концерт на видео.","vi":"Chúng tôi đang ghi lại buổi hòa nhạc trên video.","fa":"در حال ضبط کنسرت به صورت ویدئویی هستیم."},{"de":"Die Universität nimmt jedes Jahr neue Studenten auf.","en":"The university admits new students every year.","ru":"Университет ежегодно принимает новых студентов.","vi":"Trường đại học tiếp nhận sinh viên mới hàng năm.","fa":"این دانشگاه هر ساله دانشجوی جدید می پذیرد."}]},{"word":"aufpassen","en":"to pay attention, watch out; to look after","ru":"быть внимательным; присматривать","vi":"hãy cẩn thận","fa":"مراقب باشید","examples":[{"de":"Pass auf, das Glas ist heiß!","en":"Be careful, the glass is hot!","ru":"Осторожно, стакан горячий!","vi":"Hãy cẩn thận, kính rất nóng!","fa":"مراقب باشید، لیوان داغ است!"},{"de":"Kannst du kurz auf mein Kind aufpassen?","en":"Can you watch my child for a moment?","ru":"Можешь присмотреть за моим ребёнком?","vi":"Bạn có thể trông con tôi một lát được không?","fa":"آیا می توانید یک لحظه مراقب فرزند من باشید؟"}]},{"word":"aufräumen","en":"to tidy up","ru":"убирать, наводить порядок","vi":"dọn dẹp","fa":"پاک کردن","examples":[{"de":"Ich muss noch mein Zimmer aufräumen.","en":"I still need to tidy up my room.","ru":"Мне ещё нужно убрать свою комнату.","vi":"Tôi còn phải dọn phòng nữa.","fa":"هنوز باید اتاقم را تمیز کنم."},{"de":"Die Kinder räumen nach dem Spielen ihr Spielzeug auf.","en":"The children tidy up their toys after playing.","ru":"Дети убирают игрушки после игры.","vi":"Trẻ thu dọn đồ chơi sau khi chơi.","fa":"بچه ها بعد از بازی اسباب بازی های خود را مرتب می کنند."}]},{"word":"aufregen","en":"to upset; (sich aufregen) to get worked up","ru":"волновать; (sich aufregen) волноваться, нервничать","vi":"khó chịu","fa":"ناراحت","examples":[{"de":"Reg dich nicht so auf, alles wird gut.","en":"Don't get so upset, everything will be fine.","ru":"Не волнуйся так, всё будет хорошо.","vi":"Đừng buồn quá, mọi chuyện sẽ ổn thôi.","fa":"انقدر ناراحت نباش همه چی درست میشه"},{"de":"Die schlechte Nachricht hat sie sehr aufgeregt.","en":"The bad news upset her a lot.","ru":"Плохая новость сильно её взволновала.","vi":"Tin dữ khiến cô rất buồn.","fa":"خبر بد او را بسیار ناراحت کرد."}]},{"word":"die Aufregung","en":"excitement; agitation","ru":"волнение","vi":"sự phấn khích","fa":"هیجان","examples":[{"de":"Vor der Reise herrschte große Aufregung.","en":"There was great excitement before the trip.","ru":"Перед поездкой царило большое волнение.","vi":"Có sự phấn khích lớn trước chuyến đi.","fa":"قبل از سفر هیجان زیادی وجود داشت."},{"de":"Nach der ganzen Aufregung musste sie sich erst einmal hinsetzen.","en":"After all the excitement she had to sit down first.","ru":"После всего этого волнения ей сначала пришлось присесть.","vi":"Sau bao phấn khích, cô phải ngồi xuống trước.","fa":"بعد از کلی هیجان، اول باید بنشیند."}]},{"word":"aufstehen","en":"to get up, stand up","ru":"вставать","vi":"thức dậy","fa":"بلند شو","examples":[{"de":"Ich stehe jeden Morgen um sechs Uhr auf.","en":"I get up every morning at six o'clock.","ru":"Я встаю каждое утро в шесть часов.","vi":"Tôi thức dậy lúc sáu giờ mỗi sáng.","fa":"هر روز صبح ساعت شش بیدار می شوم."},{"de":"Er steht vom Stuhl auf und geht zur Tür.","en":"He gets up from the chair and goes to the door.","ru":"Он встаёт со стула и идёт к двери.","vi":"Anh đứng dậy khỏi ghế và đi ra cửa.","fa":"از روی صندلی بلند می شود و به سمت در می رود."}]},{"word":"der Auftrag","en":"order, assignment","ru":"заказ, поручение","vi":"thứ tự","fa":"سفارش","examples":[{"de":"Die Firma hat einen großen Auftrag bekommen.","en":"The company received a large order.","ru":"Компания получила крупный заказ.","vi":"Công ty đã nhận được một đơn đặt hàng lớn.","fa":"این شرکت سفارش بزرگی دریافت کرد."},{"de":"Ich erledige diesen Auftrag im Namen meines Chefs.","en":"I'm carrying out this task on behalf of my boss.","ru":"Я выполняю это поручение от имени своего начальника.","vi":"Tôi đang hoàn thành nhiệm vụ này thay mặt cho ông chủ của tôi.","fa":"من این وظیفه را از طرف رئیسم انجام می دهم."}]},{"word":"auftreten","en":"to appear, perform; to occur","ru":"выступать; возникать","vi":"xảy ra","fa":"رخ دهد","examples":[{"de":"Die Band tritt heute Abend live auf.","en":"The band performs live tonight.","ru":"Сегодня вечером группа выступает вживую.","vi":"Ban nhạc sẽ biểu diễn trực tiếp tối nay.","fa":"این گروه امشب اجرای زنده دارد."},{"de":"Bei der Arbeit können unerwartete Probleme auftreten.","en":"Unexpected problems can occur at work.","ru":"На работе могут возникнуть неожиданные проблемы.","vi":"Những vấn đề không mong muốn có thể phát sinh trong công việc.","fa":"ممکن است مشکلات غیرمنتظره ای در محل کار ایجاد شود."}]},{"word":"aufwachen","en":"to wake up","ru":"просыпаться","vi":"thức dậy","fa":"بیدار شو","examples":[{"de":"Ich wache normalerweise um sieben Uhr auf.","en":"I usually wake up at seven o'clock.","ru":"Я обычно просыпаюсь в семь часов.","vi":"Tôi thường thức dậy lúc bảy giờ.","fa":"من معمولا ساعت هفت از خواب بیدار می شوم."},{"de":"Das Baby ist mitten in der Nacht aufgewacht.","en":"The baby woke up in the middle of the night.","ru":"Ребёнок проснулся посреди ночи.","vi":"Đứa bé thức dậy vào giữa đêm.","fa":"بچه نیمه شب از خواب بیدار شد."}]},{"word":"aufwärts","en":"upwards","ru":"вверх","vi":"trở lên","fa":"به سمت بالا","examples":[{"de":"Der Weg führt steil aufwärts.","en":"The path leads steeply upwards.","ru":"Тропа круто ведёт вверх.","vi":"Con đường dẫn dốc lên trên.","fa":"مسیر با شیب تند به سمت بالا منتهی می شود."},{"de":"Nach der Krise geht es mit der Wirtschaft wieder aufwärts.","en":"After the crisis, the economy is improving again.","ru":"После кризиса экономика снова идёт на подъём.","vi":"Sau cuộc khủng hoảng, nền kinh tế đang được cải thiện trở lại.","fa":"پس از بحران، اقتصاد دوباره در حال بهبود است."}]},{"word":"der Aufzug","en":"elevator, lift","ru":"лифт","vi":"thang máy","fa":"آسانسور","examples":[{"de":"Der Aufzug ist leider defekt, wir müssen die Treppe nehmen.","en":"The elevator is unfortunately broken, we have to take the stairs.","ru":"Лифт, к сожалению, не работает, нам придётся идти по лестнице.","vi":"Thật không may thang máy bị hỏng, chúng tôi phải đi cầu thang bộ.","fa":"متاسفانه آسانسور خراب است، باید از پله ها برویم."},{"de":"Wir fahren mit dem Aufzug in den fünften Stock.","en":"We take the elevator to the fifth floor.","ru":"Мы поднимаемся на лифте на пятый этаж.","vi":"Chúng tôi đi thang máy lên tầng năm.","fa":"با آسانسور به طبقه پنجم می رویم."}]},{"word":"das Auge","en":"eye","ru":"глаз","vi":"con mắt","fa":"چشم","examples":[{"de":"Sie hat wunderschöne blaue Augen.","en":"She has beautiful blue eyes.","ru":"У неё красивые голубые глаза.","vi":"Cô ấy có đôi mắt xanh tuyệt đẹp.","fa":"او چشمان آبی زیبایی دارد."},{"de":"Ich reibe mir müde die Augen.","en":"I rub my tired eyes.","ru":"Я тру уставшие глаза.","vi":"Tôi dụi mắt mệt mỏi.","fa":"چشمانم را خسته می مالیم."}]},{"word":"der Augenblick","en":"moment","ru":"мгновение, момент","vi":"khoảnh khắc","fa":"لحظه","examples":[{"de":"Einen Augenblick, bitte, ich bin gleich da.","en":"One moment please, I'll be right there.","ru":"Одну минутку, пожалуйста, я сейчас подойду.","vi":"Xin vui lòng chờ một lát, tôi sẽ đến đó ngay.","fa":"فقط یک لحظه، لطفا، من یک لحظه دیگر آنجا خواهم بود."},{"de":"In diesem Augenblick klingelte das Telefon.","en":"At that moment the phone rang.","ru":"В этот момент зазвонил телефон.","vi":"Đúng lúc đó điện thoại reo.","fa":"در همان لحظه تلفن زنگ خورد."}]},{"word":"aus","en":"out of, from; off","ru":"из; выключено","vi":"ra ngoài","fa":"بیرون","examples":[{"de":"Er kommt aus Spanien.","en":"He comes from Spain.","ru":"Он родом из Испании.","vi":"Anh ấy đến từ Tây Ban Nha.","fa":"او از اسپانیا می آید."},{"de":"Mach bitte das Licht aus.","en":"Please turn off the light.","ru":"Пожалуйста, выключи свет.","vi":"Làm ơn tắt đèn đi.","fa":"لطفا چراغ ها را خاموش کنید"}]},{"word":"die Ausbildung","en":"vocational training, education","ru":"профессиональное обучение","vi":"việc đào tạo","fa":"آموزش","examples":[{"de":"Sie macht eine Ausbildung zur Krankenschwester.","en":"She is doing vocational training to become a nurse.","ru":"Она проходит обучение на медсестру.","vi":"Cô ấy đang được đào tạo để trở thành y tá.","fa":"او در حال آموزش پرستاری است."},{"de":"Nach der Schule beginnt er eine Ausbildung als Elektriker.","en":"After school he starts an apprenticeship as an electrician.","ru":"После школы он начинает обучение на электрика.","vi":"Sau giờ học, anh bắt đầu học nghề thợ điện.","fa":"پس از مدرسه، آموزش به عنوان برق را آغاز می کند."}]},{"word":"ausdrucken","en":"to print out","ru":"распечатывать","vi":"in ra","fa":"چاپ کنید","examples":[{"de":"Kannst du mir das Dokument ausdrucken?","en":"Can you print out the document for me?","ru":"Можешь распечатать мне этот документ?","vi":"Bạn có thể in tài liệu ra cho tôi được không?","fa":"آیا می توانید سند را برای من پرینت بگیرید؟"},{"de":"Ich drucke die Fahrkarte zu Hause aus.","en":"I print the ticket out at home.","ru":"Я распечатываю билет дома.","vi":"Tôi in vé ở nhà.","fa":"من بلیط را در خانه پرینت می کنم."}]},{"word":"ausdrücken","en":"to express","ru":"выражать","vi":"thể hiện","fa":"بیان کنید","examples":[{"de":"Er konnte seine Gefühle nur schwer ausdrücken.","en":"He found it hard to express his feelings.","ru":"Ему было трудно выражать свои чувства.","vi":"Anh ấy cảm thấy khó khăn khi bày tỏ cảm xúc của mình.","fa":"بیان احساساتش برایش سخت بود."},{"de":"Wie drückt man das auf Deutsch aus?","en":"How do you express that in German?","ru":"Как это выразить по-немецки?","vi":"Làm thế nào để bạn diễn đạt điều đó bằng tiếng Đức?","fa":"چگونه آن را به آلمانی بیان می کنید؟"}]},{"word":"auseinander","en":"apart","ru":"врозь, порознь, друг от друга","vi":"xa nhau","fa":"جدا","examples":[{"de":"Die Kinder sitzen weit auseinander.","en":"The children sit far apart.","ru":"Дети сидят далеко друг от друга.","vi":"Bọn trẻ ngồi cách xa nhau.","fa":"بچه ها دور از هم می نشینند."},{"de":"Er hat den Motor auseinandergenommen.","en":"He took the engine apart.","ru":"Он разобрал двигатель.","vi":"Anh tháo động cơ ra.","fa":"موتور را از هم جدا کرد."}]},{"word":"die Ausfahrt","en":"exit (highway)","ru":"выезд","vi":"lối ra","fa":"خروجی","examples":[{"de":"Nehmen Sie die nächste Ausfahrt von der Autobahn.","en":"Take the next exit from the highway.","ru":"Съезжайте на следующем выезде с автомагистрали.","vi":"Đi theo lối ra tiếp theo từ đường cao tốc.","fa":"از خروجی بعدی از بزرگراه خارج شوید."},{"de":"Die Ausfahrt zur Innenstadt ist gesperrt.","en":"The exit to the city center is closed.","ru":"Выезд в центр города закрыт.","vi":"Lối ra vào trung tâm thành phố đã bị đóng.","fa":"خروجی مرکز شهر بسته است."}]},{"word":"ausfallen","en":"to be cancelled; to fall out (hair)","ru":"отменяться; выпадать","vi":"thất bại","fa":"شکست بخورد","examples":[{"de":"Der Unterricht fällt heute wegen Krankheit des Lehrers aus.","en":"Class is cancelled today because the teacher is sick.","ru":"Сегодня урок отменяется из-за болезни учителя.","vi":"Hôm nay lớp học được nghỉ do giáo viên bị bệnh.","fa":"کلاس ها امروز به دلیل بیماری معلم لغو شد."},{"de":"Nach der Krankheit sind ihr die Haare ausgefallen.","en":"After the illness, her hair fell out.","ru":"После болезни у неё выпали волосы.","vi":"Sau cơn bệnh, tóc cô rụng dần.","fa":"بعد از بیماری موهایش ریخت."}]},{"word":"der Ausflug","en":"excursion, trip","ru":"экскурсия, поездка","vi":"chuyến tham quan","fa":"گشت و گذار","examples":[{"de":"Am Wochenende machen wir einen Ausflug in die Berge.","en":"On the weekend we're going on a trip to the mountains.","ru":"На выходных мы отправляемся на экскурсию в горы.","vi":"Vào cuối tuần chúng tôi sẽ đi du lịch lên núi.","fa":"آخر هفته میریم یه سفر به کوه."},{"de":"Die Schulklasse macht einen Ausflug ins Museum.","en":"The school class is going on a trip to the museum.","ru":"Школьный класс отправляется на экскурсию в музей.","vi":"Lớp học đi tham quan bảo tàng.","fa":"کلاس مدرسه به موزه می رود."}]},{"word":"ausfüllen","en":"to fill out (a form)","ru":"заполнять (анкету)","vi":"điền vào","fa":"پر کن","examples":[{"de":"Bitte füllen Sie das Formular vollständig aus.","en":"Please fill out the form completely.","ru":"Пожалуйста, заполните бланк полностью.","vi":"Vui lòng điền đầy đủ vào mẫu đơn.","fa":"لطفا فرم را به طور کامل پر کنید."},{"de":"Ich habe den Antrag schon ausgefüllt.","en":"I have already filled out the application.","ru":"Я уже заполнил заявление.","vi":"Tôi đã điền đơn rồi.","fa":"من قبلاً درخواست را پر کرده ام."}]},{"word":"die Ausgabe","en":"expense; edition, issue","ru":"расход; выпуск, издание","vi":"đầu ra","fa":"خروجی","examples":[{"de":"Unsere monatlichen Ausgaben sind gestiegen.","en":"Our monthly expenses have increased.","ru":"Наши ежемесячные расходы увеличились.","vi":"Chi phí hàng tháng của chúng tôi đã tăng lên.","fa":"هزینه های ماهانه ما افزایش یافته است."},{"de":"Diese Zeitschrift erscheint in einer neuen Ausgabe.","en":"This magazine is coming out in a new edition.","ru":"Этот журнал выходит новым выпуском.","vi":"Tạp chí này xuất hiện trong một ấn bản mới.","fa":"این مجله در نسخه جدید منتشر می شود."}]},{"word":"der Ausgang","en":"exit","ru":"выход","vi":"lối ra","fa":"خروجی","examples":[{"de":"Der Ausgang befindet sich am Ende des Flurs.","en":"The exit is at the end of the hallway.","ru":"Выход находится в конце коридора.","vi":"Lối ra nằm ở cuối hành lang.","fa":"خروجی در انتهای راهرو است."},{"de":"Bitte benutzen Sie im Notfall den nächsten Ausgang.","en":"In an emergency, please use the nearest exit.","ru":"В случае чрезвычайной ситуации, пожалуйста, воспользуйтесь ближайшим выходом.","vi":"Trong trường hợp khẩn cấp, vui lòng sử dụng lối thoát hiểm gần nhất.","fa":"در مواقع اضطراری لطفا از نزدیکترین خروجی استفاده کنید."}]},{"word":"ausgeben","en":"to spend (money); to distribute","ru":"тратить (деньги); раздавать","vi":"đầu ra","fa":"خروجی","examples":[{"de":"Er gibt viel Geld für Kleidung aus.","en":"He spends a lot of money on clothes.","ru":"Он тратит много денег на одежду.","vi":"Anh ấy chi rất nhiều tiền vào quần áo.","fa":"پول زیادی برای لباس خرج می کند."},{"de":"Die Lehrerin gibt die Prüfungsblätter aus.","en":"The teacher hands out the exam sheets.","ru":"Учительница раздаёт экзаменационные листы.","vi":"Giáo viên phát đề thi.","fa":"معلم برگه های امتحان را می دهد."}]},{"word":"ausgehen","en":"to go out; to run out","ru":"выходить (развлекаться); заканчиваться","vi":"đi ra ngoài","fa":"برو بیرون","examples":[{"de":"Am Samstag gehen wir mit Freunden aus.","en":"On Saturday we're going out with friends.","ru":"В субботу мы идём куда-то с друзьями.","vi":"Vào thứ bảy chúng tôi đi chơi với bạn bè.","fa":"شنبه با دوستان میریم بیرون."},{"de":"Uns ist das Benzin ausgegangen.","en":"We ran out of gas.","ru":"У нас закончился бензин.","vi":"Chúng tôi hết xăng.","fa":"بنزینمان تمام شد."}]},{"word":"ausgezeichnet","en":"excellent","ru":"отличный, превосходный","vi":"xuất sắc","fa":"عالی","examples":[{"de":"Das Essen in diesem Restaurant ist ausgezeichnet.","en":"The food in this restaurant is excellent.","ru":"Еда в этом ресторане превосходная.","vi":"Đồ ăn ở nhà hàng này rất tuyệt vời.","fa":"غذاهای این رستوران عالی است."},{"de":"Sie hat die Prüfung mit ausgezeichneten Ergebnissen bestanden.","en":"She passed the exam with excellent results.","ru":"Она сдала экзамен с отличными результатами.","vi":"Cô đã vượt qua kỳ thi với kết quả xuất sắc.","fa":"او امتحان را با نتایج عالی قبول کرد."}]},{"word":"die Aushilfe","en":"temporary worker, help","ru":"временный работник","vi":"sự giúp đỡ tạm thời","fa":"کمک موقت","examples":[{"de":"Wir suchen eine Aushilfe für das Wochenende.","en":"We're looking for a temporary worker for the weekend.","ru":"Мы ищем временного работника на выходные.","vi":"Chúng tôi đang tìm kiếm một công nhân tạm thời vào cuối tuần.","fa":"به دنبال کارگر موقت برای آخر هفته هستیم."},{"de":"Sie arbeitet als Aushilfe im Supermarkt.","en":"She works as a temp in the supermarket.","ru":"Она подрабатывает в супермаркете.","vi":"Cô làm công nhân tạm thời ở siêu thị.","fa":"او به عنوان کارگر موقت در سوپرمارکت کار می کند."}]},{"word":"die Auskunft","en":"information","ru":"справка, информация","vi":"thông tin","fa":"اطلاعات","examples":[{"de":"Können Sie mir eine Auskunft über die Zugverbindungen geben?","en":"Can you give me information about the train connections?","ru":"Можете дать мне справку о железнодорожном сообщении?","vi":"Bạn có thể cho tôi thông tin về các chuyến tàu kết nối được không?","fa":"آیا می توانید اطلاعاتی در مورد اتصالات قطار به من بدهید؟"},{"de":"Am Schalter erhalten Sie weitere Auskünfte.","en":"You can get further information at the counter.","ru":"У стойки вы можете получить дополнительную информацию.","vi":"Bạn có thể lấy thêm thông tin tại quầy.","fa":"اطلاعات بیشتر را می توانید از پیشخوان دریافت کنید."}]},{"word":"das Ausland","en":"foreign countries, abroad","ru":"заграница, за рубежом","vi":"nước ngoài","fa":"کشور خارجی","examples":[{"de":"Sie hat drei Jahre im Ausland gelebt.","en":"She lived abroad for three years.","ru":"Она три года жила за границей.","vi":"Cô sống ở nước ngoài được ba năm.","fa":"او سه سال در خارج از کشور زندگی کرد."},{"de":"Viele Studenten möchten ein Semester im Ausland studieren.","en":"Many students want to study a semester abroad.","ru":"Многие студенты хотят учиться семестр за границей.","vi":"Nhiều sinh viên muốn đi du học trong một học kỳ.","fa":"بسیاری از دانشجویان می خواهند برای یک ترم در خارج از کشور تحصیل کنند."}]},{"word":"ausmachen","en":"to turn off; to matter","ru":"выключать; иметь значение","vi":"làm ra","fa":"درست کردن","examples":[{"de":"Bitte mach den Fernseher aus.","en":"Please turn off the TV.","ru":"Пожалуйста, выключи телевизор.","vi":"Hãy tắt TV đi.","fa":"لطفا تلویزیون را خاموش کنید."},{"de":"Es macht mir nichts aus, früh aufzustehen.","en":"It doesn't matter to me to get up early.","ru":"Мне не составляет труда рано вставать.","vi":"Tôi không ngại dậy sớm.","fa":"بدم نمیاد زود بیدار بشم"}]},{"word":"die Ausnahme","en":"exception","ru":"исключение","vi":"ngoại lệ","fa":"استثنا","examples":[{"de":"Diese Regel hat keine Ausnahme.","en":"This rule has no exception.","ru":"У этого правила нет исключений.","vi":"Quy tắc này không có ngoại lệ.","fa":"این قاعده استثنا ندارد."},{"de":"Nur in Ausnahmefällen dürfen Handys benutzt werden.","en":"Mobile phones may only be used in exceptional cases.","ru":"Мобильными телефонами можно пользоваться только в исключительных случаях.","vi":"Điện thoại di động chỉ có thể được sử dụng trong những trường hợp đặc biệt.","fa":"تلفن های همراه فقط در موارد استثنایی قابل استفاده هستند."}]},{"word":"ausreichen","en":"to be sufficient, enough","ru":"быть достаточным, хватать","vi":"đủ","fa":"کافی","examples":[{"de":"Das Geld reicht leider nicht für den Urlaub aus.","en":"Unfortunately the money isn't enough for the vacation.","ru":"Денег, к сожалению, не хватает на отпуск.","vi":"Thật không may là không có đủ tiền cho kỳ nghỉ.","fa":"متأسفانه پول کافی برای تعطیلات وجود ندارد."},{"de":"Zwei Stunden reichen für diese Aufgabe völlig aus.","en":"Two hours are completely sufficient for this task.","ru":"Двух часов вполне достаточно для этого задания.","vi":"Hai giờ là hoàn toàn đủ cho nhiệm vụ này.","fa":"دو ساعت برای این کار کاملاً کافی است."}]},{"word":"ausreichend","en":"sufficient; enough","ru":"достаточный","vi":"đủ","fa":"کافی","examples":[{"de":"Wir haben ausreichend Zeit für die Aufgabe.","en":"We have sufficient time for the task.","ru":"У нас достаточно времени на задание.","vi":"Chúng tôi có đủ thời gian cho nhiệm vụ.","fa":"ما زمان کافی برای انجام وظیفه داریم."},{"de":"Das Licht ist zum Lesen nicht ausreichend.","en":"The light is not sufficient for reading.","ru":"Света недостаточно для чтения.","vi":"Ánh sáng không đủ để đọc.","fa":"نور برای خواندن کافی نیست."}]},{"word":"ausrichten","en":"to pass on (a message); to align","ru":"передавать (сообщение); выравнивать","vi":"căn chỉnh","fa":"تراز کردن","examples":[{"de":"Können Sie ihm bitte ausrichten, dass ich angerufen habe?","en":"Could you please tell him that I called?","ru":"Не могли бы вы передать ему, что я звонил?","vi":"Bạn có thể vui lòng nói với anh ấy là tôi đã gọi điện không?","fa":"میشه لطفا بهش بگی زنگ زدم؟"},{"de":"Die Bilder an der Wand sind gerade ausgerichtet.","en":"The pictures on the wall are aligned straight.","ru":"Картины на стене выровнены ровно.","vi":"Những bức tranh trên tường đều thẳng tắp.","fa":"تصاویر روی دیوار مستقیم هستند."}]},{"word":"ausschließen","en":"to exclude, rule out","ru":"исключать","vi":"loại trừ","fa":"حذف کردن","examples":[{"de":"Wir können einen Fehler nicht ausschließen.","en":"We cannot rule out a mistake.","ru":"Мы не можем исключить ошибку.","vi":"Chúng tôi không thể loại trừ một lỗi.","fa":"ما نمی توانیم یک خطا را رد کنیم."},{"de":"Der Verein hat das Mitglied wegen seines Verhaltens ausgeschlossen.","en":"The club excluded the member because of his behavior.","ru":"Клуб исключил члена из-за его поведения.","vi":"Câu lạc bộ đã trục xuất thành viên đó vì hành vi của anh ta.","fa":"باشگاه این عضو را به دلیل رفتارش اخراج کرد."}]},{"word":"ausschließlich","en":"exclusively, only","ru":"исключительно, только","vi":"độc quyền","fa":"منحصرا","examples":[{"de":"Dieses Angebot gilt ausschließlich für Neukunden.","en":"This offer applies exclusively to new customers.","ru":"Это предложение действует исключительно для новых клиентов.","vi":"Ưu đãi này chỉ có giá trị cho khách hàng mới.","fa":"این پیشنهاد فقط برای مشتریان جدید معتبر است."},{"de":"Er isst ausschließlich vegetarisches Essen.","en":"He eats exclusively vegetarian food.","ru":"Он ест исключительно вегетарианскую пищу.","vi":"Anh ấy chỉ ăn đồ chay.","fa":"او فقط غذای گیاهی می خورد."}]},{"word":"aussehen","en":"to look, appear","ru":"выглядеть","vi":"nhìn","fa":"نگاه کن","examples":[{"de":"Du siehst heute müde aus.","en":"You look tired today.","ru":"Ты сегодня выглядишь уставшим.","vi":"Hôm nay trông bạn có vẻ mệt mỏi.","fa":"امروز خسته به نظر میرسی"},{"de":"Das Essen sieht sehr lecker aus.","en":"The food looks very delicious.","ru":"Еда выглядит очень вкусно.","vi":"Thức ăn trông rất ngon.","fa":"غذا بسیار خوشمزه به نظر می رسد."}]},{"word":"außen","en":"outside, exterior","ru":"снаружи","vi":"bên ngoài","fa":"خارج","examples":[{"de":"Das Haus ist außen weiß gestrichen.","en":"The house is painted white on the outside.","ru":"Дом снаружи покрашен в белый цвет.","vi":"Ngôi nhà được sơn màu trắng ở bên ngoài.","fa":"بیرون خانه سفید رنگ شده است."},{"de":"Von außen sieht das Gebäude sehr modern aus.","en":"From the outside, the building looks very modern.","ru":"Снаружи здание выглядит очень современным.","vi":"Nhìn từ bên ngoài tòa nhà trông rất hiện đại.","fa":"از بیرون ساختمان بسیار مدرن به نظر می رسد."}]},{"word":"außer","en":"except, besides","ru":"кроме","vi":"ngoại trừ","fa":"جز","examples":[{"de":"Alle waren pünktlich außer ihm.","en":"Everyone was on time except him.","ru":"Все были вовремя, кроме него.","vi":"Mọi người đều đúng giờ ngoại trừ anh ấy.","fa":"همه سر وقت بودند جز او."},{"de":"Außer Kaffee trinke ich nichts am Morgen.","en":"Besides coffee, I don't drink anything in the morning.","ru":"Кроме кофе, я утром ничего не пью.","vi":"Tôi không uống gì vào buổi sáng ngoại trừ cà phê.","fa":"صبح ها جز قهوه چیزی نمی نوشم."}]},{"word":"außerdem","en":"besides, moreover","ru":"кроме того","vi":"ngoài ra","fa":"علاوه بر این","examples":[{"de":"Ich habe keine Zeit, außerdem bin ich müde.","en":"I don't have time, besides I'm tired.","ru":"У меня нет времени, кроме того, я устал.","vi":"Tôi không có thời gian và tôi mệt mỏi.","fa":"وقت ندارم و خسته ام."},{"de":"Die Wohnung ist günstig und außerdem sehr zentral gelegen.","en":"The apartment is cheap and, moreover, very centrally located.","ru":"Квартира недорогая и, кроме того, расположена очень центрально.","vi":"Căn hộ giá rẻ và cũng có vị trí rất trung tâm.","fa":"آپارتمان ارزان است و همچنین در مرکز قرار دارد."}]},{"word":"die Aussicht","en":"view; prospect","ru":"вид; перспектива","vi":"quan điểm","fa":"نمای","examples":[{"de":"Von diesem Berg hat man eine wunderschöne Aussicht.","en":"From this mountain you have a wonderful view.","ru":"С этой горы открывается прекрасный вид.","vi":"Có một cái nhìn đẹp từ ngọn núi này.","fa":"منظره زیبایی از این کوه وجود دارد."},{"de":"Er hat gute Aussichten auf den neuen Job.","en":"He has good prospects for the new job.","ru":"У него хорошие перспективы получить новую работу.","vi":"Anh ấy có triển vọng tốt cho công việc mới.","fa":"او چشم اندازهای خوبی برای شغل جدید دارد."}]},{"word":"aussprechen","en":"to pronounce; to express","ru":"произносить; высказывать","vi":"phát âm","fa":"تلفظ کنید","examples":[{"de":"Wie spricht man dieses Wort aus?","en":"How do you pronounce this word?","ru":"Как произносится это слово?","vi":"Bạn phát âm từ này như thế nào?","fa":"چگونه این کلمه را تلفظ می کنید؟"},{"de":"Sie spricht ihre Meinung immer offen aus.","en":"She always expresses her opinion openly.","ru":"Она всегда открыто высказывает своё мнение.","vi":"Cô ấy luôn nói ra suy nghĩ của mình một cách cởi mở.","fa":"او همیشه نظر خود را آشکارا بیان می کند."}]},{"word":"ausstellen","en":"to exhibit; to issue (a document)","ru":"выставлять; выдавать (документ)","vi":"triển lãm","fa":"نمایشگاه","examples":[{"de":"Das Museum stellt moderne Kunst aus.","en":"The museum exhibits modern art.","ru":"Музей выставляет современное искусство.","vi":"Bảo tàng trưng bày nghệ thuật hiện đại.","fa":"این موزه هنر مدرن را به نمایش می گذارد."},{"de":"Das Amt stellt einen neuen Reisepass aus.","en":"The office issues a new passport.","ru":"Ведомство выдаёт новый паспорт.","vi":"Văn phòng cấp hộ chiếu mới.","fa":"اداره یک پاسپورت جدید صادر می کند."}]},{"word":"die Ausstellung","en":"exhibition","ru":"выставка","vi":"cuộc triển lãm","fa":"نمایشگاه","examples":[{"de":"Die Ausstellung im Museum ist noch bis Mai zu sehen.","en":"The exhibition at the museum runs until May.","ru":"Выставку в музее можно посмотреть до мая.","vi":"Triển lãm trong bảo tàng có thể được nhìn thấy cho đến tháng Năm.","fa":"این نمایشگاه در موزه تا ماه می قابل مشاهده است."},{"de":"Wir haben in der Ausstellung viele Bilder gesehen.","en":"We saw many paintings at the exhibition.","ru":"На выставке мы увидели много картин.","vi":"Chúng tôi đã xem nhiều bức tranh trong triển lãm.","fa":"تصاویر زیادی در نمایشگاه دیدیم."}]},{"word":"auswählen","en":"to select, choose","ru":"выбирать","vi":"chọn","fa":"انتخاب کنید","examples":[{"de":"Bitte wählen Sie eine Option aus dem Menü aus.","en":"Please select an option from the menu.","ru":"Пожалуйста, выберите вариант из меню.","vi":"Vui lòng chọn một tùy chọn từ menu.","fa":"لطفاً یک گزینه را از منو انتخاب کنید."},{"de":"Der Trainer wählt die besten Spieler für das Team aus.","en":"The coach selects the best players for the team.","ru":"Тренер выбирает лучших игроков для команды.","vi":"Huấn luyện viên chọn những cầu thủ tốt nhất cho đội.","fa":"مربی بهترین بازیکنان را برای تیم انتخاب می کند."}]},{"word":"der Ausweis","en":"ID card","ru":"удостоверение личности","vi":"the ID card","fa":"کارت شناسایی","examples":[{"de":"Können Sie mir bitte Ihren Ausweis zeigen?","en":"Could you please show me your ID?","ru":"Не могли бы вы показать мне удостоверение личности?","vi":"Bạn có thể cho tôi xem ID của bạn được không?","fa":"لطفا شناسنامه خود را به من نشان دهید؟"},{"de":"Ich habe meinen Ausweis leider zu Hause vergessen.","en":"Unfortunately I forgot my ID at home.","ru":"К сожалению, я забыл удостоверение личности дома.","vi":"Thật không may, tôi quên CMND ở nhà.","fa":"متاسفانه شناسنامه ام را در خانه فراموش کردم."}]},{"word":"die Auswirkung","en":"effect; impact","ru":"воздействие; последствие","vi":"tác động","fa":"تاثیر","examples":[{"de":"Die Auswirkungen der Krise sind noch heute zu spüren.","en":"The effects of the crisis can still be felt today.","ru":"Последствия кризиса ощущаются и сегодня.","vi":"Những ảnh hưởng của cuộc khủng hoảng vẫn có thể được cảm nhận cho đến ngày nay.","fa":"اثرات این بحران هنوز هم امروز قابل احساس است."},{"de":"Zu wenig Schlaf hat negative Auswirkungen auf die Konzentration.","en":"Too little sleep has a negative impact on concentration.","ru":"Недостаток сна негативно влияет на концентрацию.","vi":"Ngủ quá ít có tác động tiêu cực đến khả năng tập trung.","fa":"خواب کم تاثیر منفی بر تمرکز دارد."}]},{"word":"ausziehen","en":"to move out; to take off (clothes)","ru":"съезжать; снимать (одежду)","vi":"cất cánh","fa":"برخاستن","examples":[{"de":"Wir ziehen nächsten Monat aus dieser Wohnung aus.","en":"We are moving out of this apartment next month.","ru":"В следующем месяце мы съезжаем из этой квартиры.","vi":"Chúng tôi sẽ chuyển khỏi căn hộ này vào tháng tới.","fa":"ماه آینده از این آپارتمان نقل مکان می کنیم."},{"de":"Zieh bitte deine nassen Schuhe aus.","en":"Please take off your wet shoes.","ru":"Пожалуйста, сними свои мокрые ботинки.","vi":"Hãy cởi giày ướt của bạn ra.","fa":"لطفا کفش های خیس خود را در بیاورید."}]},{"word":"das Auto","en":"car","ru":"автомобиль, машина","vi":"chiếc xe","fa":"ماشین","examples":[{"de":"Wir fahren mit dem Auto in den Urlaub.","en":"We are driving to our vacation by car.","ru":"Мы едем в отпуск на машине.","vi":"Chúng tôi đang đi nghỉ bằng ô tô.","fa":"ما با ماشین به تعطیلات می رویم."},{"de":"Sein neues Auto ist sehr schnell.","en":"His new car is very fast.","ru":"Его новая машина очень быстрая.","vi":"Chiếc xe mới của anh ấy chạy rất nhanh.","fa":"ماشین جدیدش خیلی سریعه."}]},{"word":"der Automat","en":"vending machine","ru":"автомат (торговый)","vi":"cái máy","fa":"دستگاه","examples":[{"de":"Am Automaten kann man Fahrkarten kaufen.","en":"You can buy tickets at the vending machine.","ru":"В автомате можно купить билеты.","vi":"You can buy tickets at the machine.","fa":"شما می توانید بلیط را از دستگاه خریداری کنید."},{"de":"Der Getränkeautomat ist leider kaputt.","en":"The drinks vending machine is unfortunately broken.","ru":"Автомат с напитками, к сожалению, сломан.","vi":"Thật không may, máy đồ uống bị hỏng.","fa":"متاسفانه دستگاه نوشیدنی خراب است."}]},{"word":"der Autor","en":"author","ru":"автор","vi":"tác giả","fa":"نویسنده","examples":[{"de":"Der Autor dieses Romans ist sehr bekannt.","en":"The author of this novel is very well known.","ru":"Автор этого романа очень известен.","vi":"Tác giả cuốn tiểu thuyết này rất nổi tiếng.","fa":"نویسنده این رمان بسیار شناخته شده است."},{"de":"Sie liest gern Bücher von diesem Autor.","en":"She likes reading books by this author.","ru":"Она любит читать книги этого автора.","vi":"Cô ấy thích đọc sách của tác giả này.","fa":"او از خواندن کتاب های این نویسنده لذت می برد."}]},{"word":"backen","en":"to bake","ru":"печь, выпекать","vi":"nướng","fa":"پختن","examples":[{"de":"Meine Mutter backt jeden Sonntag einen Kuchen.","en":"My mother bakes a cake every Sunday.","ru":"Моя мама печёт торт каждое воскресенье.","vi":"Mẹ tôi nướng bánh vào mỗi chủ nhật.","fa":"مادرم هر یکشنبه یک کیک می پزد."},{"de":"Wir backen zu Weihnachten Plätzchen.","en":"We bake cookies at Christmas.","ru":"На Рождество мы печём печенье.","vi":"Chúng tôi nướng bánh cho Giáng sinh.","fa":"ما برای کریسمس شیرینی می پزمیم."}]},{"word":"baden","en":"to bathe, swim","ru":"купаться","vi":"tắm","fa":"حمام کردن","examples":[{"de":"Im Sommer gehen wir oft im See baden.","en":"In summer we often go swimming in the lake.","ru":"Летом мы часто купаемся в озере.","vi":"Vào mùa hè chúng tôi thường đi bơi ở hồ.","fa":"در تابستان ما اغلب برای شنا در دریاچه می رویم."},{"de":"Das Kind badet gern in der Badewanne.","en":"The child likes bathing in the bathtub.","ru":"Ребёнок любит купаться в ванне.","vi":"Bé thích tắm trong bồn tắm.","fa":"کودک دوست دارد در وان حمام کند."}]},{"word":"die Bahn","en":"train, railway","ru":"поезд, железная дорога","vi":"đường sắt","fa":"راه آهن","examples":[{"de":"Ich fahre lieber mit der Bahn als mit dem Auto.","en":"I prefer to travel by train rather than by car.","ru":"Я предпочитаю ездить на поезде, а не на машине.","vi":"Tôi thích đi tàu hơn là đi ô tô.","fa":"ترجیح می دهم با قطار به جای ماشین سوار شوم."},{"de":"Die Bahn hatte heute zwanzig Minuten Verspätung.","en":"The train was twenty minutes late today.","ru":"Поезд сегодня опоздал на двадцать минут.","vi":"Hôm nay tàu trễ hai mươi phút.","fa":"قطار امروز بیست دقیقه تاخیر داشت."}]},{"word":"der Bahnhof","en":"train station","ru":"вокзал","vi":"ga xe lửa","fa":"ایستگاه قطار","examples":[{"de":"Wir treffen uns am Bahnhof um neun Uhr.","en":"We're meeting at the train station at nine o'clock.","ru":"Мы встречаемся на вокзале в девять часов.","vi":"Chúng ta sẽ gặp nhau ở ga xe lửa lúc chín giờ.","fa":"ساعت نه در ایستگاه قطار همدیگر را می بینیم."},{"de":"Der Hauptbahnhof liegt im Zentrum der Stadt.","en":"The main station is located in the city center.","ru":"Главный вокзал находится в центре города.","vi":"Nhà ga xe lửa chính nằm ở trung tâm thành phố.","fa":"ایستگاه اصلی قطار در مرکز شهر قرار دارد."}]},{"word":"der Bahnsteig","en":"platform","ru":"платформа (на вокзале)","vi":"nền tảng","fa":"پلت فرم","examples":[{"de":"Der Zug fährt von Bahnsteig drei ab.","en":"The train departs from platform three.","ru":"Поезд отправляется с третьей платформы.","vi":"Tàu khởi hành từ sân ga số ba.","fa":"قطار از سکوی سه حرکت می کند."},{"de":"Wir warten auf dem Bahnsteig auf den nächsten Zug.","en":"We are waiting on the platform for the next train.","ru":"Мы ждём следующий поезд на платформе.","vi":"Chúng tôi đợi chuyến tàu tiếp theo ở sân ga.","fa":"روی سکو منتظر قطار بعدی هستیم."}]},{"word":"bald","en":"soon","ru":"скоро","vi":"sớm thôi","fa":"به زودی","examples":[{"de":"Ich hoffe, wir sehen uns bald wieder.","en":"I hope we see each other again soon.","ru":"Надеюсь, мы скоро снова увидимся.","vi":"Tôi hy vọng chúng ta sẽ sớm gặp lại nhau.","fa":"امیدوارم به زودی دوباره همدیگر را ببینیم."},{"de":"Der Frühling kommt bald.","en":"Spring is coming soon.","ru":"Весна скоро наступит.","vi":"Mùa xuân đang đến sớm.","fa":"بهار به زودی می آید."}]},{"word":"der Balkon","en":"balcony","ru":"балкон","vi":"ban công","fa":"بالکن","examples":[{"de":"Unsere Wohnung hat einen großen Balkon.","en":"Our apartment has a large balcony.","ru":"В нашей квартире большой балкон.","vi":"Căn hộ của chúng tôi có một ban công rộng.","fa":"آپارتمان ما دارای یک بالکن بزرگ است."},{"de":"Im Sommer frühstücken wir gern auf dem Balkon.","en":"In summer we like to have breakfast on the balcony.","ru":"Летом мы любим завтракать на балконе.","vi":"Vào mùa hè, chúng tôi thích ăn sáng trên ban công.","fa":"در تابستان دوست داریم صبحانه را در بالکن بخوریم."}]},{"word":"der Ball","en":"ball","ru":"мяч","vi":"quả bóng","fa":"توپ","examples":[{"de":"Die Kinder spielen im Park mit einem Ball.","en":"The children are playing with a ball in the park.","ru":"Дети играют мячом в парке.","vi":"Bọn trẻ đang chơi bóng trong công viên.","fa":"بچه ها در پارک با توپ بازی می کنند."},{"de":"Wirf mir bitte den Ball zu.","en":"Please throw me the ball.","ru":"Брось мне мяч, пожалуйста.","vi":"Hãy ném cho tôi quả bóng.","fa":"لطفا توپ را به من پرتاب کن"}]},{"word":"das Ballett","en":"ballet","ru":"балет","vi":"múa ba lê","fa":"باله","examples":[{"de":"Meine Tochter nimmt seit zwei Jahren Ballettunterricht.","en":"My daughter has been taking ballet lessons for two years.","ru":"Моя дочь уже два года занимается балетом.","vi":"Con gái tôi đã học múa ba lê được hai năm.","fa":"دخترم دو سال است که کلاس باله می‌خواند."},{"de":"Wir haben gestern Abend ein Ballett im Theater gesehen.","en":"We watched a ballet at the theater last night.","ru":"Вчера вечером мы смотрели балет в театре.","vi":"Chúng tôi đã xem một vở ballet ở nhà hát tối qua.","fa":"دیشب یک باله در تئاتر دیدیم."}]},{"word":"die Banane","en":"banana","ru":"банан","vi":"quả chuối","fa":"موز","examples":[{"de":"Ich esse gern eine Banane zum Frühstück.","en":"I like eating a banana for breakfast.","ru":"Я люблю есть банан на завтрак.","vi":"Tôi thích ăn một quả chuối vào bữa sáng.","fa":"من دوست دارم برای صبحانه یک موز بخورم."},{"de":"Die Bananen im Supermarkt waren noch grün.","en":"The bananas at the supermarket were still green.","ru":"Бананы в супермаркете были ещё зелёными.","vi":"Những quả chuối trong siêu thị vẫn còn xanh.","fa":"موزهای سوپرمارکت هنوز سبز بودند."}]},{"word":"der Bancomat/Bankomat","en":"ATM","ru":"банкомат","vi":"ATM/ATM","fa":"ATM/ATM","examples":[{"de":"Ich hebe am Bankomat schnell etwas Bargeld ab.","en":"I quickly withdraw some cash at the ATM.","ru":"Я быстро снимаю наличные в банкомате.","vi":"Tôi nhanh chóng rút một ít tiền mặt từ máy ATM.","fa":"سریع مقداری پول نقد از خودپرداز برداشت می کنم."},{"de":"Der nächste Bancomat ist gleich um die Ecke.","en":"The nearest ATM is just around the corner.","ru":"Ближайший банкомат находится прямо за углом.","vi":"Máy ATM tiếp theo ở ngay góc đường.","fa":"دستگاه خودپرداز بعدی نزدیک است."}]},{"word":"die Bank","en":"bank; bench","ru":"банк; скамейка","vi":"ngân hàng","fa":"بانک","examples":[{"de":"Ich hebe Geld bei der Bank ab.","en":"I withdraw money from the bank.","ru":"Я снимаю деньги в банке.","vi":"Tôi rút tiền từ ngân hàng.","fa":"من از بانک پول برداشت می کنم."},{"de":"Wir setzen uns auf eine Bank im Park.","en":"We sit down on a bench in the park.","ru":"Мы садимся на скамейку в парке.","vi":"Chúng tôi ngồi trên một chiếc ghế dài trong công viên.","fa":"روی یک نیمکت در پارک می نشینیم."}]},{"word":"die Bankleitzahl","en":"bank sort code, routing number","ru":"банковский код (БИК)","vi":"số sắp xếp ngân hàng","fa":"شماره مرتب سازی بانک","examples":[{"de":"Für die Überweisung brauche ich Ihre Bankleitzahl.","en":"For the transfer I need your bank sort code.","ru":"Для перевода мне нужен ваш банковский код.","vi":"Tôi cần mã ngân hàng của bạn để chuyển khoản.","fa":"برای انتقال به کد بانک شما نیاز دارم."},{"de":"Die Bankleitzahl steht oben auf dem Kontoauszug.","en":"The bank sort code is at the top of the bank statement.","ru":"Банковский код указан вверху банковской выписки.","vi":"Số định tuyến ngân hàng nằm ở đầu bản sao kê tài khoản.","fa":"شماره مسیریابی بانک در بالای صورتحساب است."}]},{"word":"die Bankomat-Karte","en":"ATM card, debit card","ru":"банковская карта","vi":"thẻ ATM","fa":"کارت خودپرداز","examples":[{"de":"Ich bezahle im Geschäft meistens mit meiner Bankomat-Karte.","en":"I usually pay in the store with my debit card.","ru":"Я обычно расплачиваюсь в магазине своей банковской картой.","vi":"Tôi thường thanh toán tại các cửa hàng bằng thẻ ATM của mình.","fa":"من معمولاً با کارت خودپرداز خود در فروشگاه ها پرداخت می کنم."},{"de":"Ich habe meine Bankomat-Karte leider verloren.","en":"I unfortunately lost my debit card.","ru":"Я, к сожалению, потерял свою банковскую карту.","vi":"Thật không may, tôi bị mất thẻ ATM.","fa":"متأسفانه کارت خودپرداز خود را گم کردم."}]},{"word":"die Bar","en":"bar","ru":"бар","vi":"quán bar","fa":"نوار","examples":[{"de":"Am Abend gehen wir noch in eine Bar.","en":"In the evening we're going to a bar.","ru":"Вечером мы ещё пойдём в бар.","vi":"Buổi tối chúng tôi đi đến quán bar.","fa":"عصر به یک بار می رویم."},{"de":"Die Bar in unserem Hotel ist bis Mitternacht geöffnet.","en":"The bar in our hotel is open until midnight.","ru":"Бар в нашем отеле открыт до полуночи.","vi":"Quán bar trong khách sạn của chúng tôi mở cửa đến nửa đêm.","fa":"بار در هتل ما تا نیمه شب باز است."}]},{"word":"bar","en":"in cash","ru":"наличными","vi":"tiền mặt","fa":"پول نقد","examples":[{"de":"Ich bezahle lieber bar als mit Karte.","en":"I prefer to pay in cash rather than by card.","ru":"Я предпочитаю платить наличными, а не картой.","vi":"Tôi thích thanh toán bằng tiền mặt hơn là bằng thẻ.","fa":"من ترجیح می دهم نقدی پرداخت کنم تا کارت."},{"de":"Können Sie das auch bar bezahlen?","en":"Can you also pay that in cash?","ru":"Вы можете оплатить это также наличными?","vi":"Bạn cũng có thể thanh toán khoản này bằng tiền mặt không?","fa":"آیا می توانید این مبلغ را به صورت نقدی نیز پرداخت کنید؟"}]},{"word":"der Bart","en":"beard","ru":"борода","vi":"bộ râu","fa":"ریش","examples":[{"de":"Mein Großvater hat einen langen weißen Bart.","en":"My grandfather has a long white beard.","ru":"У моего дедушки длинная белая борода.","vi":"Ông tôi có bộ râu dài màu trắng.","fa":"پدربزرگ من ریش سفید بلندی دارد."},{"de":"Er lässt sich seit einem Jahr einen Bart wachsen.","en":"He has been growing a beard for a year.","ru":"Он отращивает бороду уже год.","vi":"Anh ấy đã nuôi râu được một năm.","fa":"او یک سال است که ریش گذاشته است."}]},{"word":"der Basketball","en":"basketball","ru":"баскетбол","vi":"bóng rổ","fa":"بسکتبال","examples":[{"de":"Die Jungen spielen nach der Schule Basketball.","en":"The boys play basketball after school.","ru":"Мальчики играют в баскетбол после школы.","vi":"Các cậu bé chơi bóng rổ sau giờ học.","fa":"پسرها بعد از مدرسه بسکتبال بازی می کنند."},{"de":"Er ist Mitglied im Basketballverein.","en":"He is a member of the basketball club.","ru":"Он состоит в баскетбольном клубе.","vi":"Anh ấy là thành viên của câu lạc bộ bóng rổ.","fa":"او عضو باشگاه بسکتبال است."}]},{"word":"basteln","en":"to do crafts","ru":"мастерить, заниматься рукоделием","vi":"thủ công","fa":"صنایع دستی","examples":[{"de":"Die Kinder basteln bunte Karten für Weihnachten.","en":"The children are making colorful cards for Christmas.","ru":"Дети мастерят разноцветные открытки на Рождество.","vi":"Các em làm những tấm thiệp đầy màu sắc đón Giáng sinh.","fa":"بچه ها برای کریسمس کارت های رنگارنگ درست می کنند."},{"de":"Am Wochenende bastle ich gern mit meinen Kindern.","en":"On weekends I like to do crafts with my children.","ru":"По выходным я люблю мастерить с детьми.","vi":"Vào cuối tuần, tôi thích làm đồ thủ công cùng các con.","fa":"در آخر هفته دوست دارم با فرزندانم کاردستی انجام دهم."}]},{"word":"die Batterie","en":"battery","ru":"батарейка, аккумулятор","vi":"pin","fa":"باتری","examples":[{"de":"Die Batterie meiner Fernbedienung ist leer.","en":"The battery of my remote control is dead.","ru":"Батарейка в моём пульте разряжена.","vi":"Pin điều khiển từ xa của tôi đã chết.","fa":"باتری ریموت کنترل من تمام شده است."},{"de":"Ich muss neue Batterien für die Taschenlampe kaufen.","en":"I need to buy new batteries for the flashlight.","ru":"Мне нужно купить новые батарейки для фонарика.","vi":"Tôi cần mua pin mới cho đèn pin.","fa":"برای چراغ قوه باید باتری نو بخرم."}]},{"word":"der Bauch","en":"belly, stomach","ru":"живот","vi":"dạ dày","fa":"معده","examples":[{"de":"Nach dem Essen tut mir der Bauch weh.","en":"My stomach hurts after eating.","ru":"После еды у меня болит живот.","vi":"Bụng tôi đau sau khi ăn.","fa":"معده ام بعد از خوردن غذا درد می کند."},{"de":"Er legte sich auf den Bauch.","en":"He lay down on his stomach.","ru":"Он лёг на живот.","vi":"Anh nằm sấp xuống.","fa":"روی شکم دراز کشید."}]},{"word":"bauen","en":"to build","ru":"строить","vi":"xây dựng","fa":"ساختن","examples":[{"de":"Meine Eltern bauen ein neues Haus.","en":"My parents are building a new house.","ru":"Мои родители строят новый дом.","vi":"Bố mẹ tôi đang xây một ngôi nhà mới.","fa":"پدر و مادرم در حال ساختن یک خانه جدید هستند."},{"de":"Die Stadt baut eine neue Brücke über den Fluss.","en":"The city is building a new bridge over the river.","ru":"Город строит новый мост через реку.","vi":"Thành phố đang xây dựng một cây cầu mới bắc qua sông.","fa":"شهر در حال ساخت یک پل جدید بر روی رودخانه است."}]},{"word":"der Bauer","en":"farmer","ru":"фермер, крестьянин","vi":"người nông dân","fa":"کشاورز","examples":[{"de":"Der Bauer arbeitet jeden Tag auf dem Feld.","en":"The farmer works in the field every day.","ru":"Фермер каждый день работает в поле.","vi":"Người nông dân làm việc trên cánh đồng hàng ngày.","fa":"کشاورز هر روز در مزرعه کار می کند."},{"de":"Der Bauer verkauft frisches Gemüse auf dem Markt.","en":"The farmer sells fresh vegetables at the market.","ru":"Фермер продаёт свежие овощи на рынке.","vi":"Người nông dân bán rau tươi ở chợ.","fa":"کشاورز سبزیجات تازه را در بازار می فروشد."}]},{"word":"der Baum","en":"tree","ru":"дерево","vi":"cái cây","fa":"درخت","examples":[{"de":"Im Garten steht ein großer Baum.","en":"There is a big tree in the garden.","ru":"В саду растёт большое дерево.","vi":"Có một cái cây lớn trong vườn.","fa":"یک درخت بزرگ در باغ وجود دارد."},{"de":"Im Herbst fallen die Blätter von den Bäumen.","en":"In autumn the leaves fall from the trees.","ru":"Осенью листья падают с деревьев.","vi":"Vào mùa thu, lá rụng khỏi cây.","fa":"در پاییز برگها از درختان می ریزند."}]},{"word":"beachten","en":"to pay attention to; to observe (rules)","ru":"соблюдать, обращать внимание","vi":"ghi chú","fa":"توجه داشته باشید","examples":[{"de":"Bitte beachten Sie die Verkehrsregeln.","en":"Please observe the traffic rules.","ru":"Пожалуйста, соблюдайте правила дорожного движения.","vi":"Hãy tuân thủ các quy định giao thông.","fa":"لطفا قوانین راهنمایی و رانندگی را رعایت کنید"},{"de":"Er hat die Warnung nicht beachtet.","en":"He didn't pay attention to the warning.","ru":"Он не обратил внимания на предупреждение.","vi":"Anh ta không chú ý đến lời cảnh báo.","fa":"او به هشدار توجه نکرد."}]},{"word":"der Beamte","en":"civil servant, official","ru":"чиновник, госслужащий","vi":"quan chức","fa":"رسمی","examples":[{"de":"Der Beamte prüft meine Unterlagen.","en":"The official checks my documents.","ru":"Чиновник проверяет мои документы.","vi":"Nhân viên kiểm tra giấy tờ của tôi.","fa":"افسر مدارکم را چک می کند."},{"de":"Mein Onkel ist Beamter bei der Stadtverwaltung.","en":"My uncle is a civil servant at the city administration.","ru":"Мой дядя — чиновник в городской администрации.","vi":"Chú tôi là một quan chức chính quyền thành phố.","fa":"عمویم یکی از مقامات شهرداری است."}]},{"word":"beantragen","en":"to apply for","ru":"подавать заявление (на что-л.)","vi":"áp dụng","fa":"اعمال شود","examples":[{"de":"Ich möchte ein neues Visum beantragen.","en":"I would like to apply for a new visa.","ru":"Я хочу подать заявление на новую визу.","vi":"Tôi muốn nộp đơn xin thị thực mới.","fa":"من می خواهم برای ویزای جدید اقدام کنم."},{"de":"Sie hat einen Kredit bei der Bank beantragt.","en":"She applied for a loan at the bank.","ru":"Она подала заявку на кредит в банке.","vi":"Cô đã nộp đơn xin vay tiền từ ngân hàng.","fa":"او برای دریافت وام از بانک اقدام کرد."}]},{"word":"beantworten","en":"to answer","ru":"отвечать (на что-л.)","vi":"câu trả lời","fa":"پاسخ دهید","examples":[{"de":"Können Sie meine Frage beantworten?","en":"Can you answer my question?","ru":"Вы можете ответить на мой вопрос?","vi":"Bạn có thể trả lời câu hỏi của tôi được không?","fa":"می توانید به سوال من پاسخ دهید؟"},{"de":"Der Lehrer beantwortet alle Fragen der Schüler.","en":"The teacher answers all the students' questions.","ru":"Учитель отвечает на все вопросы учеников.","vi":"Giáo viên giải đáp mọi thắc mắc của học sinh.","fa":"معلم به تمام سوالات دانش آموزان پاسخ می دهد."}]},{"word":"der Bedarf","en":"need, demand","ru":"потребность, спрос","vi":"sự cần thiết","fa":"نیاز","examples":[{"de":"Bei Bedarf können Sie mich anrufen.","en":"If needed, you can call me.","ru":"При необходимости вы можете мне позвонить.","vi":"Nếu cần thiết, bạn có thể gọi cho tôi.","fa":"در صورت لزوم می توانید با من تماس بگیرید."},{"de":"Der Bedarf an Fachkräften steigt.","en":"The demand for skilled workers is increasing.","ru":"Спрос на квалифицированных специалистов растёт.","vi":"Nhu cầu về công nhân lành nghề ngày càng tăng.","fa":"نیاز به کارگران ماهر در حال افزایش است."}]},{"word":"bedeuten","en":"to mean","ru":"означать","vi":"nghĩa là","fa":"معنی","examples":[{"de":"Was bedeutet dieses Wort?","en":"What does this word mean?","ru":"Что означает это слово?","vi":"Từ này có nghĩa là gì?","fa":"این کلمه به چه معناست؟"},{"de":"Sein Schweigen bedeutet nicht, dass er böse ist.","en":"His silence doesn't mean that he is angry.","ru":"Его молчание не означает, что он злится.","vi":"Sự im lặng của anh ấy không có nghĩa là anh ấy xấu xa.","fa":"سکوت او به معنای بد بودن او نیست."}]},{"word":"bedienen","en":"to serve; to operate","ru":"обслуживать","vi":"vận hành","fa":"عمل کنند","examples":[{"de":"Die Kellnerin bedient die Gäste freundlich.","en":"The waitress serves the guests kindly.","ru":"Официантка вежливо обслуживает гостей.","vi":"Cô hầu bàn phục vụ khách một cách thân thiện.","fa":"پیشخدمت به صورت دوستانه از مهمانان پذیرایی می کند."},{"de":"Kannst du diese Maschine bedienen?","en":"Can you operate this machine?","ru":"Ты умеешь пользоваться этой машиной?","vi":"Bạn có thể vận hành chiếc máy này không?","fa":"آیا می توانید با این دستگاه کار کنید؟"}]},{"word":"die Bedienungsanleitung","en":"instruction manual","ru":"инструкция по эксплуатации","vi":"hướng dẫn vận hành","fa":"دستورالعمل های عملیاتی","examples":[{"de":"Lies die Bedienungsanleitung, bevor du das Gerät benutzt.","en":"Read the instruction manual before using the device.","ru":"Прочитай инструкцию, прежде чем пользоваться прибором.","vi":"Đọc hướng dẫn sử dụng trước khi sử dụng thiết bị.","fa":"قبل از استفاده از دستگاه، دفترچه راهنما را مطالعه کنید."},{"de":"Die Bedienungsanleitung liegt dem Gerät bei.","en":"The instruction manual is included with the device.","ru":"Инструкция прилагается к прибору.","vi":"Các hướng dẫn vận hành được bao gồm trong thiết bị.","fa":"دستورالعمل های عملیاتی همراه با دستگاه است."}]},{"word":"die Bedingung","en":"condition","ru":"условие","vi":"điều kiện","fa":"شرط","examples":[{"de":"Ich akzeptiere die Bedingungen des Vertrags.","en":"I accept the conditions of the contract.","ru":"Я принимаю условия договора.","vi":"Tôi chấp nhận các điều khoản của hợp đồng.","fa":"من شرایط قرارداد را می پذیرم."},{"de":"Unter dieser Bedingung stimme ich zu.","en":"Under this condition I agree.","ru":"При этом условии я согласен.","vi":"Với điều kiện này tôi đồng ý.","fa":"به این شرط موافقم"}]},{"word":"beeinflussen","en":"to influence","ru":"влиять","vi":"ảnh hưởng","fa":"نفوذ","examples":[{"de":"Die Werbung beeinflusst unser Kaufverhalten.","en":"Advertising influences our buying behavior.","ru":"Реклама влияет на наше покупательское поведение.","vi":"Quảng cáo ảnh hưởng đến hành vi mua hàng của chúng ta.","fa":"تبلیغات بر رفتار خرید ما تأثیر می گذارد."},{"de":"Lass dich nicht von anderen beeinflussen.","en":"Don't let yourself be influenced by others.","ru":"Не позволяй другим влиять на тебя.","vi":"Đừng để người khác ảnh hưởng đến bạn.","fa":"اجازه ندهید دیگران بر شما تأثیر بگذارند."}]},{"word":"beenden","en":"to finish, end","ru":"заканчивать","vi":"kết thúc","fa":"تمام کردن","examples":[{"de":"Ich muss meine Arbeit noch heute beenden.","en":"I have to finish my work today.","ru":"Я должен закончить свою работу сегодня.","vi":"Hôm nay tôi phải hoàn thành công việc của mình.","fa":"امروز باید کارم را تمام کنم."},{"de":"Sie beendete das Gespräch schnell.","en":"She ended the conversation quickly.","ru":"Она быстро закончила разговор.","vi":"Cô nhanh chóng kết thúc cuộc trò chuyện.","fa":"او به سرعت گفتگو را تمام کرد."}]},{"word":"befreit","en":"freed, exempt","ru":"освобождённый","vi":"được giải thoát","fa":"آزاد شد","examples":[{"de":"Er ist von der Steuer befreit.","en":"He is exempt from tax.","ru":"Он освобождён от налога.","vi":"Anh ta được miễn thuế.","fa":"او از پرداخت مالیات معاف است."},{"de":"Die Geiseln wurden endlich befreit.","en":"The hostages were finally freed.","ru":"Заложников наконец освободили.","vi":"Các con tin cuối cùng đã được giải thoát.","fa":"گروگان ها سرانجام آزاد شدند."}]},{"word":"befriedigend","en":"satisfactory","ru":"удовлетворительный","vi":"thỏa đáng","fa":"رضایت بخش","examples":[{"de":"Ihre Leistung im Test war befriedigend.","en":"Her performance in the test was satisfactory.","ru":"Её результат в тесте был удовлетворительным.","vi":"Hiệu suất của họ trong bài kiểm tra là thỏa đáng.","fa":"عملکرد آنها در آزمون رضایت بخش بود."},{"de":"Die Note 'befriedigend' entspricht einer 3.","en":"The grade 'satisfactory' corresponds to a 3.","ru":"Оценка «удовлетворительно» соответствует тройке.","vi":"Điểm 'đạt yêu cầu' tương ứng với điểm 3.","fa":"نمره \"رضایت بخش\" با 3 مطابقت دارد."}]},{"word":"begegnen","en":"to meet, encounter","ru":"встречать(ся)","vi":"gặp phải","fa":"برخورد","examples":[{"de":"Ich bin ihr gestern im Park begegnet.","en":"I met her yesterday in the park.","ru":"Я встретил её вчера в парке.","vi":"Hôm qua tôi gặp cô ấy ở công viên.","fa":"دیروز در پارک با او آشنا شدم."},{"de":"Auf der Reise begegneten wir vielen interessanten Menschen.","en":"On the trip we met many interesting people.","ru":"В путешествии мы встретили много интересных людей.","vi":"Trong chuyến đi chúng tôi đã gặp nhiều người thú vị.","fa":"در سفر با افراد جالب زیادی آشنا شدیم."}]},{"word":"begeistert","en":"enthusiastic","ru":"воодушевлённый, в восторге","vi":"hồi hộp","fa":"هیجان زده","examples":[{"de":"Die Kinder waren begeistert von dem Zirkus.","en":"The children were thrilled with the circus.","ru":"Дети были в восторге от цирка.","vi":"Trẻ em rất hào hứng với buổi xiếc.","fa":"بچه ها مشتاق سیرک بودند."},{"de":"Er ist begeistert von seinem neuen Job.","en":"He is enthusiastic about his new job.","ru":"Он в восторге от своей новой работы.","vi":"Anh ấy rất hào hứng với công việc mới của mình.","fa":"او در مورد شغل جدید خود هیجان زده است."}]},{"word":"die Begeisterung","en":"enthusiasm","ru":"воодушевление; восторг","vi":"sự nhiệt tình","fa":"شور و شوق","examples":[{"de":"Die Kinder spielten mit großer Begeisterung.","en":"The children played with great enthusiasm.","ru":"Дети играли с большим воодушевлением.","vi":"Các em chơi rất nhiệt tình.","fa":"بچه ها با اشتیاق زیاد بازی می کردند."},{"de":"Seine Rede löste Begeisterung beim Publikum aus.","en":"His speech sparked enthusiasm in the audience.","ru":"Его речь вызвала восторг у публики.","vi":"Bài phát biểu của ông đã khơi dậy sự nhiệt tình trong khán giả.","fa":"سخنان او شور و شوق حاضران را برانگیخت."}]},{"word":"beginnen","en":"to begin","ru":"начинать(ся)","vi":"bắt đầu","fa":"آغاز شود","examples":[{"de":"Der Unterricht beginnt um acht Uhr.","en":"Class begins at eight o'clock.","ru":"Урок начинается в восемь часов.","vi":"Lớp học bắt đầu lúc tám giờ.","fa":"شروع کلاس ها ساعت هشت."},{"de":"Wir beginnen morgen mit dem neuen Projekt.","en":"We are starting the new project tomorrow.","ru":"Мы начинаем новый проект завтра.","vi":"Chúng tôi bắt đầu dự án mới vào ngày mai.","fa":"پروژه جدید را از فردا شروع می کنیم."}]},{"word":"begleiten","en":"to accompany","ru":"сопровождать","vi":"đi cùng","fa":"همراهی کنند","examples":[{"de":"Kannst du mich zum Arzt begleiten?","en":"Can you accompany me to the doctor?","ru":"Ты можешь сопроводить меня к врачу?","vi":"Bạn có thể đi cùng tôi tới gặp bác sĩ được không?","fa":"می توانید من را تا دکتر همراهی کنید؟"},{"de":"Der Vater begleitete seine Tochter zur Schule.","en":"The father accompanied his daughter to school.","ru":"Отец проводил дочь до школы.","vi":"Người cha đi cùng con gái tới trường.","fa":"پدر دخترش را تا مدرسه همراهی کرد."}]},{"word":"begrenzt","en":"limited","ru":"ограниченный","vi":"hạn chế","fa":"محدود است","examples":[{"de":"Die Anzahl der Plätze ist begrenzt.","en":"The number of seats is limited.","ru":"Количество мест ограничено.","vi":"Số lượng chỗ có hạn.","fa":"تعداد مکان ها محدود است."},{"de":"Wir haben nur begrenzte Zeit.","en":"We only have limited time.","ru":"У нас только ограниченное время.","vi":"Chúng tôi chỉ có thời gian hạn chế.","fa":"ما فقط زمان محدودی داریم."}]},{"word":"begründen","en":"to justify, give reasons for","ru":"обосновывать","vi":"biện minh","fa":"توجیه کند","examples":[{"de":"Sie musste ihre Entscheidung begründen.","en":"She had to justify her decision.","ru":"Ей пришлось обосновать своё решение.","vi":"Cô phải biện minh cho quyết định của mình.","fa":"او باید تصمیم خود را توجیه می کرد."},{"de":"Er konnte seine Meinung nicht gut begründen.","en":"He couldn't justify his opinion well.","ru":"Он не смог хорошо обосновать своё мнение.","vi":"Anh ấy không thể biện minh tốt cho ý kiến ​​​​của mình.","fa":"او نمی توانست نظر خود را به خوبی توجیه کند."}]},{"word":"begrüßen","en":"to greet, welcome","ru":"приветствовать","vi":"chào mừng","fa":"خوش آمدید","examples":[{"de":"Der Gastgeber begrüßte alle Gäste herzlich.","en":"The host warmly welcomed all the guests.","ru":"Хозяин сердечно приветствовал всех гостей.","vi":"Chủ nhà nồng nhiệt chào đón tất cả các vị khách.","fa":"میزبان به گرمی از همه مهمانان استقبال کرد."},{"de":"Ich begrüße meine Kollegen jeden Morgen.","en":"I greet my colleagues every morning.","ru":"Я приветствую своих коллег каждое утро.","vi":"Tôi chào đồng nghiệp của mình vào mỗi buổi sáng.","fa":"من هر روز صبح به همکارانم سلام می کنم."}]},{"word":"behalten","en":"to keep","ru":"оставлять, сохранять, держать","vi":"giữ","fa":"نگه دارید","examples":[{"de":"Du kannst das Buch behalten.","en":"You can keep the book.","ru":"Ты можешь оставить эту книгу себе.","vi":"Bạn có thể giữ cuốn sách.","fa":"می توانید کتاب را نگه دارید."},{"de":"Ich kann mir seinen Namen einfach nicht behalten.","en":"I just can't remember his name.","ru":"Я просто не могу запомнить его имя.","vi":"Tôi chỉ không thể nhớ tên anh ấy.","fa":"فقط اسمشو یادم نمیاد"}]},{"word":"behandeln","en":"to treat","ru":"лечить, обращаться (с кем-л.)","vi":"đối xử","fa":"درمان","examples":[{"de":"Der Arzt behandelt den Patienten mit Antibiotika.","en":"The doctor treats the patient with antibiotics.","ru":"Врач лечит пациента антибиотиками.","vi":"Bác sĩ điều trị cho bệnh nhân bằng kháng sinh.","fa":"پزشک بیمار را با آنتی بیوتیک درمان می کند."},{"de":"Man sollte alle Menschen fair behandeln.","en":"One should treat all people fairly.","ru":"Со всеми людьми нужно обращаться справедливо.","vi":"Mọi người nên được đối xử công bằng.","fa":"باید با همه منصفانه رفتار شود."}]},{"word":"die Behandlung","en":"treatment","ru":"лечение","vi":"việc điều trị","fa":"درمان","examples":[{"de":"Die Behandlung beim Zahnarzt tat gar nicht weh.","en":"The treatment at the dentist didn't hurt at all.","ru":"Лечение у стоматолога совсем не было болезненным.","vi":"Việc điều trị nha khoa không gây đau đớn gì cả.","fa":"درمان دندانپزشکی اصلاً ضرری نداشت."},{"de":"Ohne Behandlung wird die Krankheit schlimmer.","en":"Without treatment the illness gets worse.","ru":"Без лечения болезнь усугубляется.","vi":"Nếu không điều trị, bệnh sẽ nặng hơn.","fa":"بدون درمان، بیماری بدتر می شود."}]},{"word":"behaupten","en":"to claim, assert","ru":"утверждать","vi":"yêu sách","fa":"ادعا","examples":[{"de":"Er behauptet, dass er unschuldig ist.","en":"He claims that he is innocent.","ru":"Он утверждает, что он невиновен.","vi":"Anh ta khẳng định mình vô tội.","fa":"او ادعا می کند که بی گناه است."},{"de":"Sie behauptet immer, recht zu haben.","en":"She always claims to be right.","ru":"Она всегда утверждает, что права.","vi":"Cô ấy luôn khẳng định mình đúng.","fa":"او همیشه ادعا می کند که حق دارد."}]},{"word":"behindern","en":"to hinder, obstruct","ru":"мешать, препятствовать","vi":"cản trở","fa":"مانع شود","examples":[{"de":"Der Unfall behindert den Verkehr auf der Autobahn.","en":"The accident is obstructing traffic on the highway.","ru":"Авария затрудняет движение на автомагистрали.","vi":"Vụ tai nạn khiến giao thông trên đường bị gián đoạn.","fa":"این تصادف باعث اختلال در تردد در بزرگراه می شود."},{"de":"Bitte behindere mich nicht bei der Arbeit.","en":"Please don't hinder me at work.","ru":"Пожалуйста, не мешай мне работать.","vi":"Xin đừng can thiệp vào công việc của tôi.","fa":"لطفا در کار من دخالت نکنید"}]},{"word":"die Behörde","en":"authority, agency","ru":"ведомство, учреждение","vi":"cơ quan có thẩm quyền","fa":"اقتدار","examples":[{"de":"Ich muss zur Behörde, um meinen Pass zu verlängern.","en":"I have to go to the authority to renew my passport.","ru":"Мне нужно в учреждение, чтобы продлить паспорт.","vi":"Tôi phải đến cơ quan có thẩm quyền để gia hạn hộ chiếu.","fa":"برای تمدید گذرنامه باید به مقامات مراجعه کنم."},{"de":"Die Behörden haben neue Regeln erlassen.","en":"The authorities have issued new rules.","ru":"Власти издали новые правила.","vi":"Cơ quan chức năng đã ban hành các quy định mới.","fa":"مقامات قوانین جدیدی وضع کرده اند."}]},{"word":"bei","en":"at, with, near","ru":"у, при, во время","vi":"tại","fa":"در","examples":[{"de":"Ich wohne bei meinen Eltern.","en":"I live with my parents.","ru":"Я живу у родителей.","vi":"Tôi sống với bố mẹ tôi.","fa":"من با پدر و مادرم زندگی می کنم."},{"de":"Bei Regen bleiben wir zu Hause.","en":"In case of rain, we stay at home.","ru":"В случае дождя мы останемся дома.","vi":"Nếu trời mưa thì chúng ta ở nhà.","fa":"اگر باران ببارد در خانه می مانیم."}]},{"word":"beid-","en":"both","ru":"оба, обе","vi":"cả hai-","fa":"هر دو-","examples":[{"de":"Beide Kinder gehen in dieselbe Schule.","en":"Both children go to the same school.","ru":"Оба ребёнка ходят в одну школу.","vi":"Cả hai đứa trẻ đều học cùng trường.","fa":"هر دو بچه به یک مدرسه می روند."},{"de":"Ich habe beide Bücher gelesen.","en":"I have read both books.","ru":"Я прочитал обе книги.","vi":"Tôi đã đọc cả hai cuốn sách.","fa":"من هر دو کتاب را خوانده ام."}]},{"word":"das Bein","en":"leg","ru":"нога","vi":"cái chân","fa":"پا","examples":[{"de":"Er hat sich beim Skifahren das Bein gebrochen.","en":"He broke his leg while skiing.","ru":"Он сломал ногу, катаясь на лыжах.","vi":"Anh ấy bị gãy chân khi trượt tuyết.","fa":"هنگام اسکی پایش شکست."},{"de":"Der Tisch hat vier Beine.","en":"The table has four legs.","ru":"У стола четыре ножки.","vi":"Bàn có bốn chân.","fa":"میز چهار پایه دارد."}]},{"word":"beinahe","en":"almost","ru":"почти","vi":"gần như","fa":"تقریبا","examples":[{"de":"Ich wäre beinahe zu spät gekommen.","en":"I almost came too late.","ru":"Я чуть было не опоздал.","vi":"Tôi gần như đã muộn.","fa":"تقریبا دیر رسیدم."},{"de":"Das Glas wäre beinahe zerbrochen.","en":"The glass almost broke.","ru":"Стакан чуть не разбился.","vi":"Kính gần như vỡ.","fa":"شیشه تقریبا شکست."}]},{"word":"das Beispiel","en":"example","ru":"пример","vi":"ví dụ","fa":"مثال","examples":[{"de":"Kannst du mir ein Beispiel geben?","en":"Can you give me an example?","ru":"Можешь привести мне пример?","vi":"Bạn có thể cho tôi một ví dụ không?","fa":"میشه مثال بزنی؟"},{"de":"Zum Beispiel könnten wir am Wochenende wandern gehen.","en":"For example, we could go hiking at the weekend.","ru":"Например, мы могли бы пойти в поход на выходных.","vi":"Ví dụ, chúng ta có thể đi leo núi vào cuối tuần.","fa":"به عنوان مثال، ما می توانیم در تعطیلات آخر هفته به پیاده روی برویم."}]},{"word":"beißen","en":"to bite","ru":"кусать","vi":"cắn","fa":"گاز گرفتن","examples":[{"de":"Der Hund hat mich in den Arm gebissen.","en":"The dog bit me in the arm.","ru":"Собака укусила меня за руку.","vi":"Con chó cắn vào tay tôi.","fa":"سگ دستم را گاز گرفت."},{"de":"Pass auf, die Mücken beißen hier stark.","en":"Watch out, the mosquitoes bite hard here.","ru":"Осторожно, здесь сильно кусаются комары.","vi":"Hãy cẩn thận, muỗi cắn rất mạnh ở đây.","fa":"مراقب باشید، پشه‌ها اینجا به شدت نیش می‌زنند."}]},{"word":"der Beitrag","en":"contribution, fee","ru":"взнос, вклад","vi":"sự đóng góp","fa":"سهم","examples":[{"de":"Jedes Mitglied zahlt einen monatlichen Beitrag.","en":"Every member pays a monthly fee.","ru":"Каждый участник платит ежемесячный взнос.","vi":"Mỗi thành viên phải trả một khoản phí hàng tháng.","fa":"هر یک از اعضا هزینه ماهانه پرداخت می کند."},{"de":"Sie hat einen wichtigen Beitrag zum Projekt geleistet.","en":"She made an important contribution to the project.","ru":"Она внесла важный вклад в проект.","vi":"Cô ấy đã có đóng góp quan trọng cho dự án.","fa":"او سهم مهمی در این پروژه داشت."}]},{"word":"bekannt","en":"known, famous","ru":"известный","vi":"được biết đến","fa":"شناخته شده است","examples":[{"de":"Dieser Sänger ist in ganz Europa bekannt.","en":"This singer is known throughout Europe.","ru":"Этот певец известен по всей Европе.","vi":"Ca sĩ này được biết đến khắp châu Âu.","fa":"این خواننده در سراسر اروپا شناخته شده است."},{"de":"Sie ist eine bekannte Schriftstellerin.","en":"She is a well-known writer.","ru":"Она известная писательница.","vi":"Cô ấy là một nhà văn nổi tiếng.","fa":"او نویسنده ای سرشناس است."}]},{"word":"bekommen","en":"to get, receive","ru":"получать","vi":"nhận được","fa":"دریافت کنید","examples":[{"de":"Ich habe gestern einen Brief bekommen.","en":"I received a letter yesterday.","ru":"Я вчера получил письмо.","vi":"Tôi đã nhận được một lá thư ngày hôm qua.","fa":"دیروز نامه ای دریافت کردم."},{"de":"Er bekommt jeden Monat sein Gehalt pünktlich.","en":"He receives his salary on time every month.","ru":"Он получает зарплату вовремя каждый месяц.","vi":"Anh ấy nhận lương đúng hạn hàng tháng.","fa":"او هر ماه حقوقش را به موقع می گیرد."}]},{"word":"der Beleg","en":"receipt, proof","ru":"квитанция, доказательство","vi":"biên nhận","fa":"رسید","examples":[{"de":"Bitte heben Sie den Beleg für den Kauf auf.","en":"Please keep the receipt for the purchase.","ru":"Пожалуйста, сохраните чек о покупке.","vi":"Vui lòng giữ lại bằng chứng mua hàng.","fa":"لطفا مدرک خرید را نگه دارید."},{"de":"Ohne Beleg kann ich das Geld nicht zurückerstatten.","en":"Without a receipt I cannot refund the money.","ru":"Без чека я не могу вернуть деньги.","vi":"Nếu không có biên lai tôi không thể hoàn lại tiền.","fa":"بدون رسید نمی توانم پول را پس بدهم."}]},{"word":"beleidigen","en":"to insult","ru":"оскорблять","vi":"xúc phạm","fa":"توهین","examples":[{"de":"Er hat mich mit seinen Worten beleidigt.","en":"He insulted me with his words.","ru":"Он оскорбил меня своими словами.","vi":"Anh ta xúc phạm tôi bằng lời nói của mình.","fa":"با حرفش به من توهین کرد."},{"de":"Man sollte niemanden beleidigen, auch wenn man wütend ist.","en":"One shouldn't insult anyone, even when angry.","ru":"Не стоит никого оскорблять, даже если ты злишься.","vi":"Bạn không nên xúc phạm bất cứ ai, ngay cả khi bạn đang tức giận.","fa":"شما نباید به کسی توهین کنید، حتی اگر عصبانی هستید."}]},{"word":"beliebt","en":"popular","ru":"популярный","vi":"phổ biến","fa":"محبوب","examples":[{"de":"Dieses Restaurant ist bei Touristen sehr beliebt.","en":"This restaurant is very popular with tourists.","ru":"Этот ресторан очень популярен среди туристов.","vi":"Nhà hàng này rất nổi tiếng với khách du lịch.","fa":"این رستوران در بین گردشگران بسیار محبوب است."},{"de":"Sie ist eine beliebte Lehrerin an unserer Schule.","en":"She is a popular teacher at our school.","ru":"Она популярная учительница в нашей школе.","vi":"Cô ấy là một giáo viên nổi tiếng ở trường chúng tôi.","fa":"او یک معلم محبوب در مدرسه ما است."}]},{"word":"bemerken","en":"to notice","ru":"замечать","vi":"thông báo","fa":"اطلاع دهید","examples":[{"de":"Ich habe seinen Fehler sofort bemerkt.","en":"I noticed his mistake immediately.","ru":"Я сразу заметил его ошибку.","vi":"Tôi nhận ra sai lầm của anh ấy ngay lập tức.","fa":"بلافاصله متوجه اشتباه او شدم."},{"de":"Hast du bemerkt, dass die Tür offen ist?","en":"Did you notice that the door is open?","ru":"Ты заметил, что дверь открыта?","vi":"Bạn có để ý thấy cửa đang mở không?","fa":"متوجه باز بودن در شدی؟"}]},{"word":"benötigen","en":"to need, require","ru":"нуждаться (в чём-л.)","vi":"cần","fa":"نیاز دارند","examples":[{"de":"Für dieses Rezept benötigen wir frische Eier.","en":"For this recipe we need fresh eggs.","ru":"Для этого рецепта нам нужны свежие яйца.","vi":"Đối với công thức này, chúng ta cần trứng tươi.","fa":"برای این دستور به تخم مرغ تازه نیاز داریم."},{"de":"Ich benötige mehr Zeit, um das zu erledigen.","en":"I need more time to finish this.","ru":"Мне нужно больше времени, чтобы это закончить.","vi":"Tôi cần thêm thời gian để hoàn thành việc này.","fa":"برای انجام این کار به زمان بیشتری نیاز دارم."}]},{"word":"benutzen","en":"to use","ru":"использовать","vi":"sử dụng","fa":"استفاده کنید","examples":[{"de":"Darf ich deinen Computer benutzen?","en":"May I use your computer?","ru":"Можно мне воспользоваться твоим компьютером?","vi":"Tôi có thể sử dụng máy tính của bạn được không?","fa":"آیا می توانم از کامپیوتر شما استفاده کنم؟"},{"de":"Wir benutzen oft öffentliche Verkehrsmittel.","en":"We often use public transport.","ru":"Мы часто пользуемся общественным транспортом.","vi":"Chúng tôi thường sử dụng phương tiện giao thông công cộng.","fa":"ما اغلب از حمل و نقل عمومی استفاده می کنیم."}]},{"word":"das Benzin","en":"petrol, gasoline","ru":"бензин","vi":"xăng","fa":"بنزین","examples":[{"de":"Das Auto braucht wenig Benzin.","en":"The car uses little petrol.","ru":"Машина расходует мало бензина.","vi":"Chiếc xe cần ít xăng.","fa":"ماشین به بنزین کمی نیاز دارد."},{"de":"Wir müssen an der Tankstelle Benzin tanken.","en":"We need to fill up with petrol at the gas station.","ru":"Нам нужно заправиться бензином на заправке.","vi":"Chúng tôi phải đổ xăng ở trạm xăng.","fa":"پمپ بنزین باید بنزین بزنیم."}]},{"word":"beobachten","en":"to observe, watch","ru":"наблюдать","vi":"quan sát","fa":"مشاهده کنید","examples":[{"de":"Die Polizei beobachtet das Haus seit Tagen.","en":"The police have been observing the house for days.","ru":"Полиция уже несколько дней наблюдает за домом.","vi":"Cảnh sát đã theo dõi ngôi nhà trong nhiều ngày.","fa":"پلیس چند روزی است که خانه را زیر نظر دارد."},{"de":"Kinder beobachten gern Tiere im Zoo.","en":"Children like to watch animals at the zoo.","ru":"Дети любят наблюдать за животными в зоопарке.","vi":"Trẻ em thích thú ngắm nhìn các loài động vật trong vườn thú.","fa":"کودکان از تماشای حیوانات در باغ وحش لذت می برند."}]},{"word":"bequem","en":"comfortable","ru":"удобный","vi":"thoải mái","fa":"راحت","examples":[{"de":"Dieser Sessel ist sehr bequem.","en":"This armchair is very comfortable.","ru":"Это кресло очень удобное.","vi":"Chiếc ghế bành này rất thoải mái.","fa":"این صندلی بسیار راحت است."},{"de":"Ich trage gern bequeme Schuhe.","en":"I like to wear comfortable shoes.","ru":"Я люблю носить удобную обувь.","vi":"Tôi thích đi giày thoải mái.","fa":"من دوست دارم کفش راحتی بپوشم."}]},{"word":"beraten","en":"to advise","ru":"консультировать, советовать","vi":"khuyên nhủ","fa":"نصیحت کردن","examples":[{"de":"Der Verkäufer berät mich gern beim Kauf.","en":"The salesman is happy to advise me on my purchase.","ru":"Продавец охотно консультирует меня при покупке.","vi":"Người bán sẽ vui lòng tư vấn cho tôi về việc mua hàng.","fa":"فروشنده خوشحال خواهد شد که من را در مورد خرید راهنمایی کند."},{"de":"Ein Anwalt hat uns rechtlich beraten.","en":"A lawyer advised us legally.","ru":"Адвокат проконсультировал нас по правовым вопросам.","vi":"Một luật sư đã cho chúng tôi lời khuyên pháp lý.","fa":"یک وکیل به ما مشاوره حقوقی داد."}]},{"word":"berechnen","en":"to calculate","ru":"рассчитывать, вычислять","vi":"tính toán","fa":"محاسبه کنید","examples":[{"de":"Der Taxifahrer berechnet den Preis nach der Entfernung.","en":"The taxi driver calculates the price according to the distance.","ru":"Таксист рассчитывает цену по расстоянию.","vi":"Tài xế taxi tính giá theo quãng đường.","fa":"راننده تاکسی با توجه به مسافت قیمت را محاسبه می کند."},{"de":"Kannst du mir die Kosten berechnen?","en":"Can you calculate the costs for me?","ru":"Можешь рассчитать мне стоимость?","vi":"Bạn có thể tính toán chi phí cho tôi được không?","fa":"می توانید هزینه ها را برای من محاسبه کنید؟"}]},{"word":"der Bereich","en":"area, field","ru":"область, сфера","vi":"khu vực","fa":"منطقه","examples":[{"de":"Sie arbeitet im Bereich der Medizin.","en":"She works in the field of medicine.","ru":"Она работает в области медицины.","vi":"Cô ấy làm việc trong lĩnh vực y học.","fa":"او در زمینه پزشکی فعالیت می کند."},{"de":"Dieser Bereich des Parks ist für Kinder reserviert.","en":"This area of the park is reserved for children.","ru":"Эта зона парка предназначена для детей.","vi":"Khu vực này của công viên được dành riêng cho trẻ em.","fa":"این منطقه از پارک مخصوص کودکان است."}]},{"word":"bereit","en":"ready","ru":"готовый","vi":"sẵn sàng","fa":"آماده","examples":[{"de":"Bist du bereit für die Prüfung?","en":"Are you ready for the exam?","ru":"Ты готов к экзамену?","vi":"Bạn đã sẵn sàng cho kỳ thi chưa?","fa":"آیا برای امتحان آماده هستید؟"},{"de":"Das Essen ist bereit, wir können anfangen.","en":"The food is ready, we can start.","ru":"Еда готова, можем начинать.","vi":"Thức ăn đã sẵn sàng, chúng ta có thể bắt đầu.","fa":"غذا آماده است، می توانیم شروع کنیم."}]},{"word":"bereits","en":"already","ru":"уже","vi":"rồi","fa":"در حال حاضر","examples":[{"de":"Er ist bereits nach Hause gegangen.","en":"He has already gone home.","ru":"Он уже ушёл домой.","vi":"Anh ấy đã về nhà rồi.","fa":"او قبلاً به خانه رفته است."},{"de":"Wir haben das Problem bereits gelöst.","en":"We have already solved the problem.","ru":"Мы уже решили эту проблему.","vi":"Chúng tôi đã giải quyết được vấn đề.","fa":"ما قبلا مشکل را حل کرده ایم."}]},{"word":"der Berg","en":"mountain","ru":"гора","vi":"ngọn núi","fa":"کوه","examples":[{"de":"Wir wandern jedes Jahr in die Berge.","en":"We go hiking in the mountains every year.","ru":"Мы каждый год ходим в горы.","vi":"Chúng tôi leo núi hàng năm.","fa":"ما هر سال به کوه می رویم."},{"de":"Der höchste Berg Deutschlands ist die Zugspitze.","en":"The highest mountain in Germany is the Zugspitze.","ru":"Самая высокая гора Германии — Цугшпитце.","vi":"Ngọn núi cao nhất ở Đức là Zugspitze.","fa":"بلندترین کوه آلمان، زوگسپیتزه است."}]},{"word":"der Bericht","en":"report","ru":"отчёт; репортаж","vi":"báo cáo","fa":"گزارش","examples":[{"de":"Der Bericht muss bis Freitag fertig sein.","en":"The report has to be finished by Friday.","ru":"Отчёт должен быть готов к пятнице.","vi":"Báo cáo phải được hoàn thành trước thứ Sáu.","fa":"گزارش باید تا روز جمعه آماده شود."},{"de":"Im Bericht standen alle wichtigen Zahlen.","en":"All the important figures were in the report.","ru":"В отчёте были все важные цифры.","vi":"Tất cả những con số quan trọng đều có trong báo cáo.","fa":"همه اعداد مهم در گزارش بود."}]},{"word":"berichten","en":"to report","ru":"сообщать, докладывать","vi":"báo cáo","fa":"گزارش دهید","examples":[{"de":"Die Zeitung berichtet über den Unfall.","en":"The newspaper reports on the accident.","ru":"Газета сообщает об аварии.","vi":"Báo đưa tin về vụ tai nạn.","fa":"این روزنامه از این حادثه خبر می دهد."},{"de":"Er berichtete uns von seiner Reise.","en":"He told us about his trip.","ru":"Он рассказал нам о своей поездке.","vi":"Anh ấy kể cho chúng tôi nghe về chuyến đi của mình.","fa":"از سفرش به ما گفت."}]},{"word":"berücksichtigen","en":"to take into account; to consider","ru":"учитывать; принимать во внимание","vi":"tính đến","fa":"در نظر گرفتن","examples":[{"de":"Bei der Planung müssen wir das Wetter berücksichtigen.","en":"When planning we have to take the weather into account.","ru":"При планировании мы должны учитывать погоду.","vi":"Khi lập kế hoạch, chúng ta phải tính đến thời tiết.","fa":"هنگام برنامه ریزی باید آب و هوا را در نظر بگیریم."},{"de":"Ihre Wünsche werden natürlich berücksichtigt.","en":"Your wishes will of course be taken into account.","ru":"Ваши пожелания, разумеется, будут учтены.","vi":"Mong muốn của bạn tất nhiên sẽ được tính đến.","fa":"البته خواسته های شما مورد توجه قرار خواهد گرفت."}]},{"word":"der Beruf","en":"profession, job","ru":"профессия","vi":"nghề nghiệp","fa":"حرفه","examples":[{"de":"Was ist dein Beruf?","en":"What is your profession?","ru":"Кто ты по профессии?","vi":"Công việc của bạn là gì?","fa":"شغل شما چیست؟"},{"de":"Sie hat ihren Beruf mit Leidenschaft gewählt.","en":"She chose her profession with passion.","ru":"Она выбрала свою профессию с увлечением.","vi":"Cô chọn nghề bằng niềm đam mê.","fa":"او حرفه خود را با علاقه انتخاب کرد."}]},{"word":"beruhigen","en":"to calm down","ru":"успокаивать","vi":"bình tĩnh","fa":"آرام باش","examples":[{"de":"Die Mutter beruhigte das weinende Kind.","en":"The mother calmed the crying child.","ru":"Мать успокоила плачущего ребёнка.","vi":"Người mẹ dỗ dành đứa trẻ đang khóc.","fa":"مادر کودک گریان را آرام کرد."},{"de":"Beruhige dich, alles wird gut.","en":"Calm down, everything will be fine.","ru":"Успокойся, всё будет хорошо.","vi":"Hãy bình tĩnh, mọi chuyện sẽ ổn thôi.","fa":"آرام باش همه چیز درست خواهد شد."}]},{"word":"berühmt","en":"famous","ru":"знаменитый","vi":"nổi tiếng","fa":"معروف","examples":[{"de":"Dieser Maler ist weltberühmt.","en":"This painter is world-famous.","ru":"Этот художник всемирно известен.","vi":"Họa sĩ này nổi tiếng thế giới.","fa":"این نقاش شهرت جهانی دارد."},{"de":"Die Stadt ist berühmt für ihre Architektur.","en":"The city is famous for its architecture.","ru":"Город знаменит своей архитектурой.","vi":"Thành phố này nổi tiếng với kiến ​​trúc của nó.","fa":"این شهر به دلیل معماری خود مشهور است."}]},{"word":"beschädigen","en":"to damage","ru":"повреждать","vi":"thiệt hại","fa":"آسیب","examples":[{"de":"Der Sturm hat das Dach beschädigt.","en":"The storm damaged the roof.","ru":"Буря повредила крышу.","vi":"Cơn bão đã làm hư hỏng mái nhà.","fa":"طوفان به سقف خانه آسیب زد."},{"de":"Bitte beschädige das Buch nicht.","en":"Please don't damage the book.","ru":"Пожалуйста, не повреди книгу.","vi":"Xin đừng làm hỏng cuốn sách.","fa":"لطفا به کتاب آسیب ندهید."}]},{"word":"beschäftigen","en":"to employ; to occupy oneself with","ru":"нанимать (сотрудников), заниматься (чем-л.)","vi":"tuyển dụng","fa":"استخدام کردن","examples":[{"de":"Die Firma beschäftigt über hundert Mitarbeiter.","en":"The company employs over a hundred employees.","ru":"Компания нанимает более ста сотрудников.","vi":"Công ty có hơn một trăm người.","fa":"این شرکت بیش از صد نفر را استخدام می کند."},{"de":"Ich beschäftige mich gerade mit einem neuen Buch.","en":"I am currently occupied with a new book.","ru":"Я сейчас занимаюсь новой книгой.","vi":"Tôi hiện đang làm việc trên một cuốn sách mới.","fa":"در حال حاضر روی یک کتاب جدید کار می کنم."}]},{"word":"der Bescheid","en":"notification, information","ru":"уведомление, сообщение","vi":"thông báo","fa":"اطلاعیه","examples":[{"de":"Ich gebe dir morgen Bescheid.","en":"I'll let you know tomorrow.","ru":"Я дам тебе знать завтра.","vi":"Tôi sẽ cho bạn biết vào ngày mai.","fa":"فردا بهت خبر میدم"},{"de":"Wir haben noch keinen Bescheid vom Amt bekommen.","en":"We haven't received any notification from the office yet.","ru":"Мы ещё не получили уведомление от ведомства.","vi":"Chúng tôi chưa nhận được bất kỳ thông báo nào từ văn phòng.","fa":"ما هنوز هیچ اطلاعیه ای از دفتر دریافت نکرده ایم."}]},{"word":"beschließen","en":"to decide","ru":"решать, принимать решение","vi":"quyết định","fa":"تصمیم بگیرند","examples":[{"de":"Wir haben beschlossen, umzuziehen.","en":"We have decided to move.","ru":"Мы решили переехать.","vi":"Chúng tôi quyết định di chuyển.","fa":"تصمیم گرفتیم حرکت کنیم."},{"de":"Der Rat beschließt neue Regeln für die Stadt.","en":"The council decides on new rules for the city.","ru":"Совет принимает новые правила для города.","vi":"Hội đồng quyết định các quy định mới cho thành phố.","fa":"شورا در مورد قوانین جدید برای شهر تصمیم می گیرد."}]},{"word":"beschränken","en":"to limit, restrict","ru":"ограничивать","vi":"giới hạn","fa":"محدود کردن","examples":[{"de":"Die Stadt beschränkt den Verkehr in der Innenstadt.","en":"The city restricts traffic in the city center.","ru":"Город ограничивает движение в центре.","vi":"Thành phố đang hạn chế giao thông ở trung tâm thành phố.","fa":"شهر تردد در مرکز شهر را محدود کرده است."},{"de":"Wir müssen unsere Ausgaben beschränken.","en":"We need to limit our expenses.","ru":"Нам нужно ограничить наши расходы.","vi":"Chúng ta phải hạn chế chi tiêu.","fa":"ما باید هزینه هایمان را محدود کنیم."}]},{"word":"beschreiben","en":"to describe","ru":"описывать","vi":"mô tả","fa":"توصیف کنید","examples":[{"de":"Kannst du mir den Weg beschreiben?","en":"Can you describe the way to me?","ru":"Можешь описать мне дорогу?","vi":"Bạn có thể mô tả đường đi cho tôi được không?","fa":"میشه راه رو برام تعریف کنی؟"},{"de":"Sie beschrieb ihre Gefühle sehr genau.","en":"She described her feelings very precisely.","ru":"Она очень точно описала свои чувства.","vi":"Cô mô tả cảm xúc của mình rất chi tiết.","fa":"او احساسات خود را با جزئیات کامل توصیف کرد."}]},{"word":"die Beschwerde","en":"complaint","ru":"жалоба","vi":"khiếu nại","fa":"شکایت","examples":[{"de":"Ich möchte eine Beschwerde einreichen.","en":"I would like to file a complaint.","ru":"Я хотел бы подать жалобу.","vi":"Tôi muốn nộp đơn khiếu nại.","fa":"من می خواهم شکایت کنم."},{"de":"Nach mehreren Beschwerden wurde der Lärm endlich leiser.","en":"After several complaints the noise finally got quieter.","ru":"После нескольких жалоб шум наконец стал тише.","vi":"Sau vài lần phàn nàn, tiếng ồn ào cuối cùng cũng lắng xuống.","fa":"پس از چندین بار شکایت، سر و صدا در نهایت خاموش شد."}]},{"word":"besetzen","en":"to occupy","ru":"занимать","vi":"chiếm giữ","fa":"را اشغال کند","examples":[{"de":"Alle Plätze im Zug waren besetzt.","en":"All the seats on the train were occupied.","ru":"Все места в поезде были заняты.","vi":"Tất cả chỗ ngồi trên tàu đều đã có người ngồi.","fa":"تمام صندلی های قطار اشغال شده بود."},{"de":"Die Toilette ist gerade besetzt.","en":"The toilet is currently occupied.","ru":"Туалет сейчас занят.","vi":"Nhà vệ sinh hiện đang có người sử dụng.","fa":"سرویس بهداشتی در حال حاضر اشغال است."}]},{"word":"besichtigen","en":"to visit, view (a sight)","ru":"осматривать (достопримечательности)","vi":"chuyến thăm","fa":"بازدید کنید","examples":[{"de":"Wir wollen morgen das Schloss besichtigen.","en":"We want to visit the castle tomorrow.","ru":"Мы хотим завтра осмотреть замок.","vi":"Chúng tôi muốn đến thăm lâu đài vào ngày mai.","fa":"فردا می خواهیم از قلعه دیدن کنیم."},{"de":"Touristen besichtigen gern die alte Kirche.","en":"Tourists like to visit the old church.","ru":"Туристы любят осматривать старую церковь.","vi":"Khách du lịch thích đến thăm nhà thờ cổ.","fa":"گردشگران دوست دارند از کلیسای قدیمی دیدن کنند."}]},{"word":"besitzen","en":"to own, possess","ru":"владеть","vi":"sở hữu","fa":"خود","examples":[{"de":"Meine Familie besitzt ein kleines Haus auf dem Land.","en":"My family owns a small house in the countryside.","ru":"Моя семья владеет небольшим домом за городом.","vi":"Gia đình tôi sở hữu một ngôi nhà nhỏ ở nông thôn.","fa":"خانواده من یک خانه کوچک در کشور دارند."},{"de":"Er besitzt zwei Autos.","en":"He owns two cars.","ru":"У него есть две машины.","vi":"Anh ấy sở hữu hai chiếc ô tô.","fa":"او دو ماشین دارد."}]},{"word":"besonder-","en":"special, particular","ru":"особенный, особый","vi":"đặc biệt-","fa":"ویژه-","examples":[{"de":"Das war ein besonderer Tag für mich.","en":"That was a special day for me.","ru":"Это был особенный день для меня.","vi":"Đó là một ngày đặc biệt đối với tôi.","fa":"آن روز برای من روز خاصی بود."},{"de":"Ich mag besonders den Sommer.","en":"I especially like summer.","ru":"Мне особенно нравится лето.","vi":"Tôi đặc biệt thích mùa hè.","fa":"من به خصوص تابستان را دوست دارم."}]},{"word":"besorgen","en":"to get, procure","ru":"доставать, приобретать","vi":"nhận được","fa":"دریافت کنید","examples":[{"de":"Kannst du mir eine Fahrkarte besorgen?","en":"Can you get me a ticket?","ru":"Можешь достать мне билет?","vi":"Bạn có thể cho tôi một vé được không?","fa":"می توانید برای من بلیط بگیرید؟"},{"de":"Ich muss noch Brot für morgen besorgen.","en":"I still need to get bread for tomorrow.","ru":"Мне ещё нужно купить хлеб на завтра.","vi":"Tôi vẫn phải lấy bánh mì cho ngày mai.","fa":"من هنوز باید برای فردا نان بیاورم."}]},{"word":"besprechen","en":"to discuss","ru":"обсуждать","vi":"thảo luận","fa":"بحث کنید","examples":[{"de":"Wir sollten die Details morgen besprechen.","en":"We should discuss the details tomorrow.","ru":"Нам стоит обсудить детали завтра.","vi":"Chúng ta nên thảo luận chi tiết vào ngày mai.","fa":"فردا باید درباره جزئیات صحبت کنیم."},{"de":"Der Chef bespricht die Probleme mit dem Team.","en":"The boss discusses the problems with the team.","ru":"Начальник обсуждает проблемы с командой.","vi":"Sếp thảo luận các vấn đề với nhóm.","fa":"رئیس مشکلات را با تیم در میان می گذارد."}]},{"word":"die Besserung","en":"improvement, recovery","ru":"улучшение, выздоровление","vi":"sự cải tiến","fa":"بهبود","examples":[{"de":"Gute Besserung!","en":"Get well soon!","ru":"Выздоравливай!","vi":"Hãy sớm khỏe lại!","fa":"زود خوب شو"},{"de":"Nach der Operation zeigte er schnelle Besserung.","en":"After the operation he showed rapid improvement.","ru":"После операции он быстро пошёл на поправку.","vi":"Sau cuộc phẫu thuật, anh ấy đã cho thấy sự cải thiện nhanh chóng.","fa":"پس از عمل او بهبود سریعی را نشان داد."}]},{"word":"bestätigen","en":"to confirm","ru":"подтверждать","vi":"xác nhận","fa":"تایید کنید","examples":[{"de":"Bitte bestätigen Sie den Termin per E-Mail.","en":"Please confirm the appointment by email.","ru":"Пожалуйста, подтвердите встречу по электронной почте.","vi":"Vui lòng xác nhận cuộc hẹn qua email.","fa":"لطفا قرار ملاقات را از طریق ایمیل تایید کنید."},{"de":"Der Arzt bestätigte die Diagnose.","en":"The doctor confirmed the diagnosis.","ru":"Врач подтвердил диагноз.","vi":"Bác sĩ xác nhận chẩn đoán.","fa":"دکتر تشخیص را تایید کرد."}]},{"word":"bestehen","en":"to pass (an exam); to exist, consist","ru":"сдать (экзамен); существовать, состоять","vi":"tồn tại","fa":"وجود داشته باشد","examples":[{"de":"Ich habe die Prüfung bestanden!","en":"I passed the exam!","ru":"Я сдал экзамен!","vi":"Tôi đã vượt qua kỳ thi!","fa":"من در امتحان قبول شدم!"},{"de":"Das Team besteht aus zehn Mitgliedern.","en":"The team consists of ten members.","ru":"Команда состоит из десяти человек.","vi":"Đội ngũ bao gồm mười thành viên.","fa":"تیم متشکل از ده نفر است."}]},{"word":"bestehen aus","en":"to consist of","ru":"состоять из","vi":"bao gồm","fa":"متشکل از","examples":[{"de":"Das Team besteht aus fünf Personen.","en":"The team consists of five people.","ru":"Команда состоит из пяти человек.","vi":"Đội gồm có năm người.","fa":"تیم متشکل از پنج نفر است."},{"de":"Wasser besteht aus Wasserstoff und Sauerstoff.","en":"Water consists of hydrogen and oxygen.","ru":"Вода состоит из водорода и кислорода.","vi":"Nước bao gồm hydro và oxy.","fa":"آب از هیدروژن و اکسیژن تشکیل شده است."}]},{"word":"bestellen","en":"to order","ru":"заказывать","vi":"đặt hàng","fa":"سفارش دهید","examples":[{"de":"Wir bestellen jetzt das Essen.","en":"We are ordering the food now.","ru":"Мы сейчас заказываем еду.","vi":"Chúng ta sẽ gọi đồ ăn ngay bây giờ.","fa":"ما الان غذا را سفارش می دهیم."},{"de":"Sie hat ein neues Buch im Internet bestellt.","en":"She ordered a new book online.","ru":"Она заказала новую книгу в интернете.","vi":"Cô ấy đặt mua một cuốn sách mới trực tuyến.","fa":"او یک کتاب جدید آنلاین سفارش داد."}]},{"word":"bestimmt","en":"certain; definitely","ru":"определённый, наверняка","vi":"xác định","fa":"تعیین شده است","examples":[{"de":"Er kommt bestimmt zur Party.","en":"He will definitely come to the party.","ru":"Он наверняка придёт на вечеринку.","vi":"Anh ấy chắc chắn sẽ đến dự bữa tiệc.","fa":"او قطعا به مهمانی خواهد آمد."},{"de":"Es gibt bestimmte Regeln, die wir befolgen müssen.","en":"There are certain rules that we have to follow.","ru":"Есть определённые правила, которым мы должны следовать.","vi":"Có những quy tắc nhất định chúng ta phải tuân theo.","fa":"قوانین خاصی وجود دارد که باید از آنها پیروی کنیم."}]},{"word":"bestrafen","en":"to punish","ru":"наказывать","vi":"trừng phạt","fa":"مجازات","examples":[{"de":"Die Eltern bestrafen das Kind für die Lüge.","en":"The parents punish the child for the lie.","ru":"Родители наказывают ребёнка за ложь.","vi":"Cha mẹ trừng phạt con vì nói dối.","fa":"والدین کودک را به خاطر دروغ گفتن تنبیه می کنند."},{"de":"Der Fahrer wurde für das Falschparken bestraft.","en":"The driver was punished for parking illegally.","ru":"Водителя наказали за неправильную парковку.","vi":"Tài xế bị phạt vì đỗ xe trái phép.","fa":"راننده به دلیل پارک غیر مجاز جریمه شد."}]},{"word":"besuchen","en":"to visit","ru":"посещать","vi":"chuyến thăm","fa":"بازدید کنید","examples":[{"de":"Wir besuchen am Wochenende unsere Großeltern.","en":"We are visiting our grandparents at the weekend.","ru":"Мы навещаем бабушку с дедушкой на выходных.","vi":"Chúng tôi đến thăm ông bà vào cuối tuần.","fa":"آخر هفته به پدربزرگ و مادربزرگمان می‌رویم."},{"de":"Sie hat viele Länder in Europa besucht.","en":"She has visited many countries in Europe.","ru":"Она посетила много стран в Европе.","vi":"Cô đã đến thăm nhiều nước ở châu Âu.","fa":"او از بسیاری از کشورهای اروپایی بازدید کرده است."}]},{"word":"betonen","en":"to emphasise; to stress","ru":"подчёркивать","vi":"nhấn mạnh","fa":"تاکید کنید","examples":[{"de":"Der Lehrer betonte, wie wichtig die Hausaufgaben sind.","en":"The teacher stressed how important the homework is.","ru":"Учитель подчеркнул, как важна домашняя работа.","vi":"Giáo viên nhấn mạnh tầm quan trọng của bài tập về nhà.","fa":"معلم بر اهمیت تکالیف تاکید کرد."},{"de":"Ich möchte noch einmal betonen, dass das kein Scherz ist.","en":"I would like to emphasise once again that this is not a joke.","ru":"Я хочу ещё раз подчеркнуть, что это не шутка.","vi":"Tôi muốn nhắc lại rằng đây không phải là một trò đùa.","fa":"من می خواهم تکرار کنم که این یک شوخی نیست."}]},{"word":"betrachten","en":"to look at; to regard; to consider","ru":"рассматривать; смотреть","vi":"xem xét","fa":"در نظر بگیرید","examples":[{"de":"Sie betrachtete das Gemälde lange und still.","en":"She looked at the painting for a long time in silence.","ru":"Она долго и молча рассматривала картину.","vi":"Cô lặng lẽ nhìn bức tranh một lúc lâu.","fa":"بلند و آرام به نقاشی نگاه کرد."},{"de":"Ich betrachte ihn als guten Freund.","en":"I regard him as a good friend.","ru":"Я считаю его хорошим другом.","vi":"Tôi coi anh ấy là một người bạn tốt.","fa":"من او را دوست خوبی می دانم."}]},{"word":"der Betrag","en":"amount (of money)","ru":"сумма","vi":"số tiền","fa":"مقدار","examples":[{"de":"Bitte überweisen Sie den Betrag bis Freitag.","en":"Please transfer the amount by Friday.","ru":"Пожалуйста, переведите сумму до пятницы.","vi":"Vui lòng chuyển số tiền trước thứ Sáu.","fa":"لطفا تا جمعه مبلغ را واریز کنید."},{"de":"Der Gesamtbetrag beträgt 250 Euro.","en":"The total amount is 250 euros.","ru":"Общая сумма составляет 250 евро.","vi":"Tổng số tiền là 250 euro.","fa":"مبلغ کل 250 یورو است."}]},{"word":"betreuen","en":"to look after, care for","ru":"заботиться, присматривать","vi":"chăm sóc","fa":"مراقبت از","examples":[{"de":"Sie betreut ältere Menschen im Pflegeheim.","en":"She cares for elderly people in the nursing home.","ru":"Она заботится о пожилых людях в доме престарелых.","vi":"Cô chăm sóc người già trong viện dưỡng lão.","fa":"او از افراد مسن در خانه های سالمندان مراقبت می کند."},{"de":"Wer betreut die Kinder heute Nachmittag?","en":"Who is looking after the children this afternoon?","ru":"Кто присматривает за детьми сегодня днём?","vi":"Chiều nay ai trông trẻ?","fa":"چه کسی امروز بعد از ظهر از بچه ها مراقبت می کند؟"}]},{"word":"der Betrieb","en":"company, business operation","ru":"предприятие, производство","vi":"hoạt động","fa":"عملیات","examples":[{"de":"Mein Vater arbeitet in einem großen Betrieb.","en":"My father works in a large company.","ru":"Мой отец работает на крупном предприятии.","vi":"Bố tôi làm việc ở một công ty lớn.","fa":"پدرم در یک شرکت بزرگ کار می کند."},{"de":"Die Maschine ist außer Betrieb.","en":"The machine is out of operation.","ru":"Машина не работает.","vi":"Máy bị hỏng.","fa":"دستگاه از کار افتاده است."}]},{"word":"die Betriebsrätin","en":"works council member (female)","ru":"член производственного совета (женщина)","vi":"ủy viên hội đồng công trình","fa":"شورای کار","examples":[{"de":"Die Betriebsrätin vertritt die Interessen der Angestellten.","en":"The works council member represents the employees' interests.","ru":"Член производственного совета представляет интересы сотрудников.","vi":"Hội đồng công trình đại diện cho lợi ích của người lao động.","fa":"شوراي كار نماينده منافع كاركنان است."},{"de":"Unsere Betriebsrätin hat ein Treffen mit der Geschäftsführung organisiert.","en":"Our works council member organized a meeting with management.","ru":"Наш представитель производственного совета организовала встречу с руководством.","vi":"Thành viên hội đồng công trình của chúng tôi đã tổ chức một cuộc họp với ban quản lý.","fa":"عضو شورای کار ما جلسه ای با مدیریت ترتیب داد."}]},{"word":"betrügen","en":"to deceive, cheat","ru":"обманывать","vi":"gian lận","fa":"تقلب","examples":[{"de":"Er hat seine Geschäftspartner betrogen.","en":"He deceived his business partners.","ru":"Он обманул своих деловых партнёров.","vi":"Anh ta đã lừa dối các đối tác kinh doanh của mình.","fa":"او به شرکای تجاری خود خیانت کرد."},{"de":"Sie fühlte sich von ihrem Freund betrogen.","en":"She felt cheated by her boyfriend.","ru":"Она чувствовала себя обманутой своим парнем.","vi":"Cô cảm thấy bị bạn trai phản bội.","fa":"او احساس می کرد که توسط دوست پسرش خیانت شده است."}]},{"word":"betrunken","en":"drunk","ru":"пьяный","vi":"say rượu","fa":"مست","examples":[{"de":"Er war zu betrunken, um selbst zu fahren.","en":"He was too drunk to drive himself.","ru":"Он был слишком пьян, чтобы вести машину самому.","vi":"Anh ta quá say để tự lái xe.","fa":"او آنقدر مست بود که خودش نمی توانست رانندگی کند."},{"de":"Man sollte nicht betrunken Auto fahren.","en":"One shouldn't drive drunk.","ru":"Нельзя садиться за руль пьяным.","vi":"Bạn không nên lái xe khi say rượu.","fa":"شما نباید در حالت مستی رانندگی کنید."}]},{"word":"das Bett","en":"bed","ru":"кровать","vi":"cái giường","fa":"تخت","examples":[{"de":"Ich gehe früh ins Bett.","en":"I go to bed early.","ru":"Я рано ложусь спать.","vi":"Tôi đi ngủ sớm.","fa":"زود به رختخواب می روم."},{"de":"Das Bett im Hotelzimmer war sehr bequem.","en":"The bed in the hotel room was very comfortable.","ru":"Кровать в номере отеля была очень удобной.","vi":"Chiếc giường trong phòng khách sạn rất thoải mái.","fa":"تخت در اتاق هتل بسیار راحت بود."}]},{"word":"die Bevölkerung","en":"population","ru":"население","vi":"dân số","fa":"جمعیت","examples":[{"de":"Die Bevölkerung der Stadt wächst schnell.","en":"The population of the city is growing fast.","ru":"Население города быстро растёт.","vi":"Dân số thành phố đang tăng nhanh.","fa":"جمعیت این شهر به سرعت در حال افزایش است."},{"de":"Ein großer Teil der Bevölkerung lebt auf dem Land.","en":"A large part of the population lives in the countryside.","ru":"Значительная часть населения живёт в сельской местности.","vi":"Một bộ phận lớn dân số sống ở khu vực nông thôn.","fa":"بخش بزرگی از جمعیت در مناطق روستایی زندگی می کنند."}]},{"word":"bevor","en":"before","ru":"прежде чем, до того как","vi":"trước đây","fa":"قبل از","examples":[{"de":"Bevor du gehst, schalte bitte das Licht aus.","en":"Before you leave, please turn off the light.","ru":"Прежде чем уйти, выключи, пожалуйста, свет.","vi":"Trước khi rời đi, vui lòng tắt đèn.","fa":"قبل از رفتن لطفا چراغ ها را خاموش کنید."},{"de":"Wir müssen einkaufen, bevor die Geschäfte schließen.","en":"We have to go shopping before the shops close.","ru":"Нам нужно сходить за покупками, прежде чем магазины закроются.","vi":"Chúng ta phải mua sắm trước khi các cửa hàng đóng cửa.","fa":"ما باید قبل از بسته شدن مغازه ها خرید کنیم."}]},{"word":"bewegen","en":"to move","ru":"двигать(ся)","vi":"di chuyển","fa":"حرکت کنید","examples":[{"de":"Er kann seinen Arm nach der Operation kaum bewegen.","en":"He can barely move his arm after the operation.","ru":"Он едва может двигать рукой после операции.","vi":"Anh ấy hầu như không thể cử động cánh tay của mình sau ca phẫu thuật.","fa":"او پس از عمل به سختی می تواند بازوی خود را حرکت دهد."},{"de":"Das Kind bewegt sich sehr geschickt beim Tanzen.","en":"The child moves very skillfully while dancing.","ru":"Ребёнок очень ловко двигается во время танца.","vi":"Đứa trẻ di chuyển rất khéo léo trong khi nhảy.","fa":"کودک هنگام رقصیدن بسیار ماهرانه حرکت می کند."}]},{"word":"beweisen","en":"to prove","ru":"доказывать","vi":"chứng minh","fa":"ثابت کند","examples":[{"de":"Er konnte seine Unschuld beweisen.","en":"He was able to prove his innocence.","ru":"Он смог доказать свою невиновность.","vi":"Anh ta đã có thể chứng minh sự vô tội của mình.","fa":"او توانست بی گناهی خود را ثابت کند."},{"de":"Diese Ergebnisse beweisen, dass die Methode funktioniert.","en":"These results prove that the method works.","ru":"Эти результаты доказывают, что метод работает.","vi":"Những kết quả này chứng minh rằng phương pháp này hoạt động.","fa":"این نتایج ثابت می کند که روش کار می کند."}]},{"word":"die Bewerbung","en":"application (for a job)","ru":"заявление о приёме на работу","vi":"ứng dụng","fa":"برنامه","examples":[{"de":"Ich habe meine Bewerbung gestern abgeschickt.","en":"I sent off my application yesterday.","ru":"Я отправил своё заявление вчера.","vi":"Tôi đã gửi đơn đăng ký của mình ngày hôm qua.","fa":"من دیروز درخواستم رو فرستادم"},{"de":"Zur Bewerbung gehören ein Anschreiben und ein Lebenslauf.","en":"An application includes a cover letter and a CV.","ru":"Заявление включает сопроводительное письмо и резюме.","vi":"Hồ sơ bao gồm thư xin việc và CV.","fa":"این برنامه شامل یک جلد نامه و یک CV است."}]},{"word":"bewerten","en":"to evaluate; to rate; to grade","ru":"оценивать","vi":"đánh giá","fa":"ارزیابی کنید","examples":[{"de":"Der Lehrer bewertet die Aufsätze am Wochenende.","en":"The teacher grades the essays at the weekend.","ru":"Учитель оценивает сочинения на выходных.","vi":"Giáo viên chấm bài vào cuối tuần.","fa":"معلم انشاها را در آخر هفته نمره می دهد."},{"de":"Wie würdest du diesen Film bewerten?","en":"How would you rate this film?","ru":"Как бы ты оценил этот фильм?","vi":"Bạn đánh giá bộ phim này như thế nào?","fa":"به این فیلم چه امتیازی می دهید؟"}]},{"word":"der Bewohner","en":"resident, inhabitant","ru":"житель","vi":"cư dân","fa":"ساکن","examples":[{"de":"Die Bewohner des Hauses beschwerten sich über den Lärm.","en":"The residents of the building complained about the noise.","ru":"Жители дома пожаловались на шум.","vi":"Người dân trong nhà phàn nàn về tiếng ồn.","fa":"اهالی خانه از سر و صدا شکایت کردند."},{"de":"Alle Bewohner der Insel kennen sich.","en":"All the inhabitants of the island know each other.","ru":"Все жители острова знают друг друга.","vi":"Mọi người trên đảo đều biết nhau.","fa":"همه در جزیره یکدیگر را می شناسند."}]},{"word":"bezahlen","en":"to pay","ru":"платить","vi":"trả tiền","fa":"پرداخت کنید","examples":[{"de":"Wer bezahlt die Rechnung?","en":"Who is paying the bill?","ru":"Кто платит по счёту?","vi":"Ai thanh toán hóa đơn?","fa":"چه کسی قبض را پرداخت می کند؟"},{"de":"Ich habe die Miete schon bezahlt.","en":"I have already paid the rent.","ru":"Я уже заплатил за квартиру.","vi":"Tôi đã trả tiền thuê nhà rồi.","fa":"من قبلاً اجاره را پرداخت کرده ام."}]},{"word":"die Beziehung","en":"relationship","ru":"отношения, связь","vi":"mối quan hệ","fa":"رابطه","examples":[{"de":"Sie haben eine glückliche Beziehung.","en":"They have a happy relationship.","ru":"У них счастливые отношения.","vi":"Họ có một mối quan hệ hạnh phúc.","fa":"آنها رابطه شادی دارند."},{"de":"Die Beziehung zwischen den beiden Ländern hat sich verbessert.","en":"The relationship between the two countries has improved.","ru":"Отношения между двумя странами улучшились.","vi":"Mối quan hệ giữa hai nước đã được cải thiện.","fa":"روابط بین دو کشور بهبود یافته است."}]},{"word":"beziehungsweise","en":"or rather; respectively","ru":"или; точнее; соответственно","vi":"tương ứng","fa":"به ترتیب","examples":[{"de":"Wir treffen uns am Montag beziehungsweise Dienstag.","en":"We'll meet on Monday or rather Tuesday.","ru":"Мы встретимся в понедельник, точнее, во вторник.","vi":"Chúng tôi gặp nhau vào thứ Hai hoặc thứ Ba.","fa":"دوشنبه یا سه شنبه همدیگر را می بینیم."},{"de":"Die Männer und Frauen gingen in den linken beziehungsweise rechten Raum.","en":"The men and women went into the left and right room respectively.","ru":"Мужчины и женщины пошли в левую и правую комнаты соответственно.","vi":"Nam và nữ lần lượt đi vào phòng bên trái và bên phải.","fa":"مردان و زنان به ترتیب به اتاق چپ و راست رفتند."}]},{"word":"die Bibliothek","en":"library","ru":"библиотека","vi":"thư viện","fa":"کتابخانه","examples":[{"de":"Ich leihe mir Bücher aus der Bibliothek aus.","en":"I borrow books from the library.","ru":"Я беру книги в библиотеке.","vi":"Tôi mượn sách từ thư viện.","fa":"از کتابخانه کتاب امانت می‌گیرم."},{"de":"Die Universität hat eine große Bibliothek.","en":"The university has a large library.","ru":"В университете большая библиотека.","vi":"Trường đại học có một thư viện lớn.","fa":"این دانشگاه یک کتابخانه بزرگ دارد."}]},{"word":"das Bier","en":"beer","ru":"пиво","vi":"bia","fa":"آبجو","examples":[{"de":"Er trinkt gern ein kühles Bier nach der Arbeit.","en":"He likes to drink a cold beer after work.","ru":"Он любит выпить холодного пива после работы.","vi":"Anh ấy thích uống bia lạnh sau giờ làm việc.","fa":"او دوست دارد بعد از کار یک آبجو سرد بنوشد."},{"de":"In Deutschland gibt es viele verschiedene Biersorten.","en":"In Germany there are many different types of beer.","ru":"В Германии много разных сортов пива.","vi":"Có rất nhiều loại bia khác nhau ở Đức.","fa":"انواع مختلفی از آبجو در آلمان وجود دارد."}]},{"word":"bieten","en":"to offer","ru":"предлагать","vi":"đề nghị","fa":"پیشنهاد","examples":[{"de":"Das Hotel bietet einen tollen Service.","en":"The hotel offers great service.","ru":"Отель предлагает отличный сервис.","vi":"Khách sạn cung cấp dịch vụ tuyệt vời.","fa":"این هتل خدمات عالی ارائه می دهد."},{"de":"Die Firma bietet ihren Mitarbeitern flexible Arbeitszeiten.","en":"The company offers its employees flexible working hours.","ru":"Компания предлагает своим сотрудникам гибкий график работы.","vi":"Công ty cung cấp cho nhân viên thời gian làm việc linh hoạt.","fa":"این شرکت ساعات کاری انعطاف پذیری را به کارکنان خود ارائه می دهد."}]},{"word":"das Bild","en":"picture, image","ru":"картина, изображение","vi":"bức tranh","fa":"تصویر","examples":[{"de":"An der Wand hängt ein schönes Bild.","en":"A beautiful picture hangs on the wall.","ru":"На стене висит красивая картина.","vi":"Có một bức tranh đẹp treo trên tường.","fa":"یک عکس زیبا روی دیوار آویزان شده است."},{"de":"Kannst du mir ein Bild von deiner Reise zeigen?","en":"Can you show me a picture from your trip?","ru":"Можешь показать мне фотографию из своей поездки?","vi":"Bạn có thể cho tôi xem một bức ảnh từ chuyến đi của bạn được không?","fa":"میشه یه عکس از سفرت بهم نشون بدی؟"}]},{"word":"der Bildschirm","en":"screen; monitor","ru":"экран","vi":"màn hình","fa":"صفحه نمایش","examples":[{"de":"Der Bildschirm meines Laptops ist sehr groß.","en":"My laptop's screen is very big.","ru":"Экран моего ноутбука очень большой.","vi":"Màn hình máy tính xách tay của tôi rất lớn.","fa":"صفحه لپ تاپ من خیلی بزرگه"},{"de":"Bitte schau nicht die ganze Zeit auf den Bildschirm.","en":"Please don't look at the screen the whole time.","ru":"Пожалуйста, не смотри всё время на экран.","vi":"Làm ơn đừng nhìn vào màn hình mọi lúc.","fa":"لطفا همیشه به صفحه نمایش نگاه نکنید."}]},{"word":"die Bildung","en":"education","ru":"образование","vi":"giáo dục","fa":"آموزش و پرورش","examples":[{"de":"Bildung ist der Schlüssel zu einer besseren Zukunft.","en":"Education is the key to a better future.","ru":"Образование — ключ к лучшему будущему.","vi":"Giáo dục là chìa khóa cho một tương lai tốt đẹp hơn.","fa":"آموزش کلید آینده بهتر است."},{"de":"Der Staat investiert zu wenig in die Bildung.","en":"The state invests too little in education.","ru":"Государство слишком мало вкладывает в образование.","vi":"Nhà nước đầu tư quá ít vào giáo dục.","fa":"دولت خیلی کم در آموزش سرمایه گذاری می کند."}]},{"word":"das Billett","en":"ticket","ru":"билет","vi":"vé","fa":"بلیط","examples":[{"de":"Ich kaufe ein Billett für den Zug nach Zürich.","en":"I buy a ticket for the train to Zurich.","ru":"Я покупаю билет на поезд в Цюрих.","vi":"Tôi mua vé tàu đi Zurich.","fa":"بلیت قطار زوریخ می خرم."},{"de":"Hast du dein Billett schon am Automaten geholt?","en":"Have you already gotten your ticket from the machine?","ru":"Ты уже взял свой билет в автомате?","vi":"Bạn đã nhận được vé từ máy chưa?","fa":"آیا قبلا بلیط خود را از دستگاه دریافت کرده اید؟"}]},{"word":"billig","en":"cheap","ru":"дешёвый","vi":"giá rẻ","fa":"ارزان","examples":[{"de":"Dieses Restaurant ist sehr billig.","en":"This restaurant is very cheap.","ru":"Этот ресторан очень дешёвый.","vi":"Nhà hàng này rất rẻ.","fa":"این رستوران بسیار ارزان است."},{"de":"Ich suche ein billiges Hotel in der Stadt.","en":"I'm looking for a cheap hotel in the city.","ru":"Я ищу дешёвую гостиницу в городе.","vi":"Tôi đang tìm một khách sạn giá rẻ ở thành phố.","fa":"من به دنبال یک هتل ارزان در شهر هستم."}]},{"word":"die Biologie","en":"biology","ru":"биология","vi":"sinh học","fa":"زیست شناسی","examples":[{"de":"In der Schule hatten wir heute Biologie.","en":"We had biology at school today.","ru":"Сегодня в школе у нас была биология.","vi":"Ở trường hôm nay chúng tôi học môn sinh học.","fa":"امروز در مدرسه زیست شناسی داشتیم."},{"de":"Sie studiert Biologie an der Universität.","en":"She studies biology at university.","ru":"Она изучает биологию в университете.","vi":"Cô ấy nghiên cứu sinh học ở trường đại học.","fa":"او در دانشگاه زیست شناسی می خواند."}]},{"word":"die Birne","en":"pear; light bulb","ru":"груша; лампочка","vi":"quả lê","fa":"گلابی","examples":[{"de":"Ich esse gern eine süße Birne zum Frühstück.","en":"I like eating a sweet pear for breakfast.","ru":"Я люблю есть сладкую грушу на завтрак.","vi":"Tôi thích ăn một quả lê ngọt vào bữa sáng.","fa":"من دوست دارم برای صبحانه یک گلابی شیرین بخورم."},{"de":"Die Birne in der Küche ist kaputt, wir brauchen eine neue.","en":"The light bulb in the kitchen is broken, we need a new one.","ru":"Лампочка на кухне перегорела, нам нужна новая.","vi":"Bóng đèn trong bếp hỏng rồi, chúng ta cần một cái mới.","fa":"لامپ آشپزخانه خراب است، به یک لامپ جدید نیاز داریم."}]},{"word":"bis","en":"until; by","ru":"до","vi":"cho đến khi","fa":"تا","examples":[{"de":"Ich bleibe bis Freitag bei meinen Eltern.","en":"I'm staying at my parents' until Friday.","ru":"Я останусь у родителей до пятницы.","vi":"Tôi sẽ ở với bố mẹ cho đến thứ Sáu.","fa":"من تا جمعه پیش پدر و مادرم می مانم."},{"de":"Der Laden hat bis 20 Uhr geöffnet.","en":"The shop is open until 8 pm.","ru":"Магазин открыт до 20 часов.","vi":"Cửa hàng mở cửa đến 8 giờ tối.","fa":"فروشگاه تا ساعت 8 شب باز است."}]},{"word":"bisher","en":"so far; up to now","ru":"до сих пор","vi":"cho đến nay","fa":"تا کنون","examples":[{"de":"Bisher habe ich keine Antwort auf meine E-Mail bekommen.","en":"So far I haven't received an answer to my email.","ru":"До сих пор я не получил ответа на своё письмо.","vi":"Cho đến nay tôi vẫn chưa nhận được phản hồi cho email của mình.","fa":"تاکنون پاسخی به ایمیلم دریافت نکرده ام."},{"de":"Bisher war das Wetter im Urlaub sehr schön.","en":"So far the weather has been very nice on vacation.","ru":"До сих пор погода в отпуске была очень хорошей.","vi":"Cho đến nay thời tiết trong kỳ nghỉ rất đẹp.","fa":"تا الان در تعطیلات هوا خیلی خوب بوده است."}]},{"word":"bitten","en":"to ask; to request","ru":"просить","vi":"hỏi","fa":"بپرسید","examples":[{"de":"Ich möchte dich um einen Gefallen bitten.","en":"I'd like to ask you for a favor.","ru":"Я хотел бы попросить тебя об услуге.","vi":"Tôi muốn nhờ bạn một việc.","fa":"من می خواهم از شما یک لطفی بخواهم."},{"de":"Er bittet den Lehrer um mehr Zeit für die Prüfung.","en":"He asks the teacher for more time for the exam.","ru":"Он просит учителя дать больше времени на экзамен.","vi":"Anh ấy xin giáo viên cho thêm thời gian cho kỳ thi.","fa":"از معلم وقت بیشتری برای امتحان می خواهد."}]},{"word":"bitter","en":"bitter","ru":"горький","vi":"cay đắng","fa":"تلخ","examples":[{"de":"Der Kaffee ohne Zucker schmeckt sehr bitter.","en":"Coffee without sugar tastes very bitter.","ru":"Кофе без сахара очень горький на вкус.","vi":"Cà phê không đường có vị rất đắng.","fa":"قهوه بدون شکر طعم بسیار تلخی دارد."},{"de":"Diese Medizin ist sehr bitter.","en":"This medicine is very bitter.","ru":"Это лекарство очень горькое.","vi":"Thuốc này rất đắng.","fa":"این دارو بسیار تلخ است."}]},{"word":"blass","en":"pale","ru":"бледный","vi":"nhợt nhạt","fa":"رنگ پریده","examples":[{"de":"Du siehst heute sehr blass aus, geht es dir gut?","en":"You look very pale today, are you okay?","ru":"Ты сегодня выглядишь очень бледным, у тебя всё хорошо?","vi":"Hôm nay trông bạn xanh xao lắm, bạn ổn chứ?","fa":"امروز خیلی رنگ پریده به نظر می رسید، خوب هستید؟"},{"de":"Nach der Krankheit war ihr Gesicht blass.","en":"After the illness her face was pale.","ru":"После болезни её лицо было бледным.","vi":"Sau cơn bệnh, sắc mặt bà tái nhợt.","fa":"بعد از بیماری، صورتش رنگ پریده بود."}]},{"word":"das Blatt","en":"leaf; sheet of paper","ru":"лист","vi":"tờ giấy","fa":"ورق","examples":[{"de":"Im Herbst fallen die Blätter von den Bäumen.","en":"In autumn the leaves fall from the trees.","ru":"Осенью листья падают с деревьев.","vi":"Vào mùa thu, lá rụng khỏi cây.","fa":"در پاییز برگها از درختان می ریزند."},{"de":"Gib mir bitte ein Blatt Papier.","en":"Please give me a sheet of paper.","ru":"Дай мне, пожалуйста, лист бумаги.","vi":"Xin vui lòng cho tôi một mảnh giấy.","fa":"لطفا یک تکه کاغذ به من بدهید."}]},{"word":"bleiben","en":"to stay; to remain","ru":"оставаться","vi":"ở lại","fa":"ماندن","examples":[{"de":"Ich möchte heute Abend zu Hause bleiben.","en":"I want to stay home tonight.","ru":"Я хочу остаться сегодня вечером дома.","vi":"Tôi muốn ở nhà tối nay.","fa":"میخوام امشب خونه بمونم"},{"de":"Bleib bitte ruhig, es ist nichts Schlimmes passiert.","en":"Please stay calm, nothing bad has happened.","ru":"Пожалуйста, оставайся спокойным, ничего плохого не случилось.","vi":"Xin hãy bình tĩnh, không có chuyện gì xấu xảy ra cả.","fa":"لطفا آرام باشید، اتفاق بدی نیفتاده است."}]},{"word":"der Bleistift","en":"pencil","ru":"карандаш","vi":"cây bút chì","fa":"مداد","examples":[{"de":"Hast du einen Bleistift für die Mathe-Hausaufgaben?","en":"Do you have a pencil for the math homework?","ru":"У тебя есть карандаш для домашнего задания по математике?","vi":"Bạn có bút chì để làm bài tập toán không?","fa":"آیا برای تکالیف ریاضی خود مداد دارید؟"},{"de":"Der Bleistift ist abgebrochen, ich brauche einen Spitzer.","en":"The pencil broke, I need a sharpener.","ru":"Карандаш сломался, мне нужна точилка.","vi":"Bút chì bị gãy, tôi cần một cái gọt.","fa":"مداد شکست، من نیاز به تراش دارم."}]},{"word":"der Blick","en":"look; view; glance","ru":"взгляд","vi":"quan điểm","fa":"نمای","examples":[{"de":"Von hier hat man einen schönen Blick auf die Berge.","en":"From here you have a beautiful view of the mountains.","ru":"Отсюда открывается прекрасный вид на горы.","vi":"Từ đây bạn có thể ngắm nhìn những ngọn núi tuyệt đẹp.","fa":"از اینجا منظره زیبایی از کوه ها دارید."},{"de":"Sie warf einen kurzen Blick auf ihre Uhr.","en":"She glanced briefly at her watch.","ru":"Она бросила быстрый взгляд на часы.","vi":"Cô liếc nhìn đồng hồ.","fa":"نگاهی به ساعتش انداخت."}]},{"word":"blind","en":"blind","ru":"слепой","vi":"mù","fa":"کور","examples":[{"de":"Sein Großvater ist seit einem Unfall blind.","en":"His grandfather has been blind since an accident.","ru":"Его дедушка ослеп после аварии.","vi":"Ông nội của anh bị mù từ sau một tai nạn.","fa":"پدربزرگش پس از تصادف نابینا شده است."},{"de":"Blinde Menschen benutzen oft einen Blindenstock.","en":"Blind people often use a white cane.","ru":"Слепые люди часто используют трость.","vi":"Người mù thường sử dụng gậy.","fa":"افراد نابینا اغلب از عصا استفاده می کنند."}]},{"word":"blitzen","en":"to flash with lightning","ru":"сверкать (о молнии)","vi":"đèn flash","fa":"فلش","examples":[{"de":"Es blitzt und donnert schon seit einer Stunde.","en":"It's been flashing with lightning and thundering for an hour already.","ru":"Уже час сверкает молния и гремит гром.","vi":"Trời đang có sấm sét suốt một giờ đồng hồ.","fa":"یک ساعت است که رعد و برق و رعد و برق است."},{"de":"Als es blitzte, bekam das Kind Angst.","en":"When lightning flashed, the child got scared.","ru":"Когда сверкнула молния, ребёнок испугался.","vi":"Khi có sét, đứa trẻ trở nên sợ hãi.","fa":"وقتی رعد و برق آمد، بچه ترسید."}]},{"word":"blond","en":"blond","ru":"светловолосый","vi":"tóc vàng","fa":"بلوند","examples":[{"de":"Meine Schwester hat blonde Haare.","en":"My sister has blond hair.","ru":"У моей сестры светлые волосы.","vi":"Chị tôi có mái tóc vàng.","fa":"خواهر من موهای بلوند دارد."},{"de":"Das blonde Mädchen dort ist meine Kollegin.","en":"The blond girl over there is my colleague.","ru":"Та светловолосая девушка — моя коллега.","vi":"Cô gái tóc vàng đó là đồng nghiệp của tôi.","fa":"دختر بلوند آنجا همکار من است."}]},{"word":"bloß","en":"only; just","ru":"только, лишь","vi":"chỉ","fa":"فقط","examples":[{"de":"Ich wollte dir bloß helfen.","en":"I just wanted to help you.","ru":"Я лишь хотел тебе помочь.","vi":"Tôi chỉ muốn giúp bạn.","fa":"فقط میخواستم کمکت کنم"},{"de":"Sag mir bloß nicht, dass du den Termin vergessen hast!","en":"Just don't tell me you forgot the appointment!","ru":"Только не говори мне, что ты забыл о встрече!","vi":"Đừng nói với tôi là bạn quên hẹn nhé!","fa":"به من نگو ​​که قرار ملاقات را فراموش کرده ای!"}]},{"word":"blühen","en":"to bloom","ru":"цвести","vi":"nở hoa","fa":"شکوفه دادن","examples":[{"de":"Im Frühling blühen die Blumen im Garten.","en":"In spring the flowers bloom in the garden.","ru":"Весной цветы в саду цветут.","vi":"Vào mùa xuân hoa nở trong vườn.","fa":"در بهار گل ها در باغ شکوفا می شوند."},{"de":"Dieser Baum blüht jedes Jahr im April.","en":"This tree blooms every year in April.","ru":"Это дерево цветёт каждый год в апреле.","vi":"Cây này nở hoa vào tháng Tư hàng năm.","fa":"این درخت هر ماه آوریل شکوفا می شود."}]},{"word":"die Blume","en":"flower","ru":"цветок","vi":"bông hoa","fa":"گل","examples":[{"de":"Er hat seiner Freundin rote Blumen geschenkt.","en":"He gave his girlfriend red flowers.","ru":"Он подарил своей девушке красные цветы.","vi":"Anh tặng bạn gái những bông hoa màu đỏ.","fa":"او به دوست دخترش گل های قرمز داد."},{"de":"Im Garten wachsen viele bunte Blumen.","en":"Many colorful flowers grow in the garden.","ru":"В саду растёт много разноцветных цветов.","vi":"Nhiều loài hoa đủ màu sắc mọc trong vườn.","fa":"گل های رنگارنگ زیادی در باغ می رویند."}]},{"word":"die Bluse","en":"blouse","ru":"блузка","vi":"chiếc áo cánh","fa":"بلوز","examples":[{"de":"Sie trägt eine weiße Bluse zur Arbeit.","en":"She wears a white blouse to work.","ru":"Она носит белую блузку на работу.","vi":"Cô mặc áo sơ mi trắng đi làm.","fa":"او یک بلوز سفید به سر کار می پوشد."},{"de":"Diese Bluse passt gut zu deinem Rock.","en":"This blouse goes well with your skirt.","ru":"Эта блузка хорошо подходит к твоей юбке.","vi":"Chiếc áo này rất hợp với váy của bạn.","fa":"این بلوز به خوبی با دامن شما می آید."}]},{"word":"bluten","en":"to bleed","ru":"кровоточить","vi":"chảy máu","fa":"خونریزی","examples":[{"de":"Sein Finger blutet, er hat sich geschnitten.","en":"His finger is bleeding, he cut himself.","ru":"У него кровоточит палец, он порезался.","vi":"Ngón tay anh ấy đang chảy máu, anh ấy đã tự cắt mình.","fa":"انگشتش خون است، خودش را بریده است."},{"de":"Die Wunde hat lange geblutet.","en":"The wound bled for a long time.","ru":"Рана долго кровоточила.","vi":"Vết thương chảy máu đã lâu.","fa":"زخم برای مدت طولانی خونریزی کرد."}]},{"word":"der Boden","en":"floor; ground; soil","ru":"пол, земля, почва","vi":"sàn nhà","fa":"کف","examples":[{"de":"Das Kind spielt auf dem Boden im Wohnzimmer.","en":"The child is playing on the floor in the living room.","ru":"Ребёнок играет на полу в гостиной.","vi":"Đứa trẻ đang chơi trên sàn trong phòng khách.","fa":"کودک در اتاق نشیمن روی زمین بازی می کند."},{"de":"In diesem Garten ist der Boden sehr fruchtbar.","en":"In this garden the soil is very fertile.","ru":"В этом саду очень плодородная почва.","vi":"Đất ở khu vườn này rất màu mỡ.","fa":"خاک این باغ بسیار حاصلخیز است."}]},{"word":"der Bogen","en":"arch; sheet (of paper)","ru":"дуга; лист бумаги","vi":"cái cung","fa":"کمان","examples":[{"de":"Die Brücke hat einen schönen Bogen aus Stein.","en":"The bridge has a beautiful stone arch.","ru":"У этого моста красивая каменная арка.","vi":"Cây cầu có vòm đá rất đẹp.","fa":"پل دارای طاق سنگی زیبایی است."},{"de":"Ich brauche noch einen Bogen Papier für den Drucker.","en":"I still need a sheet of paper for the printer.","ru":"Мне ещё нужен лист бумаги для принтера.","vi":"Tôi cần một tờ giấy khác cho máy in.","fa":"من به یک برگه کاغذ دیگر برای چاپگر نیاز دارم."}]},{"word":"die Bohne","en":"bean","ru":"фасоль, боб","vi":"hạt đậu","fa":"لوبیا","examples":[{"de":"Zum Mittagessen gibt es grüne Bohnen mit Kartoffeln.","en":"For lunch there are green beans with potatoes.","ru":"На обед будет зелёная фасоль с картошкой.","vi":"Bữa trưa chúng tôi ăn đậu xanh với khoai tây.","fa":"برای ناهار لوبیا سبز با سیب زمینی داریم."},{"de":"Meine Oma pflanzt jedes Jahr Bohnen im Garten.","en":"My grandma plants beans in the garden every year.","ru":"Моя бабушка каждый год сажает фасоль в саду.","vi":"Bà tôi trồng đậu trong vườn hàng năm.","fa":"مادربزرگ من هر سال در باغ لوبیا می کارد."}]},{"word":"das Boot","en":"boat","ru":"лодка","vi":"chiếc thuyền","fa":"قایق","examples":[{"de":"Wir sind mit dem Boot über den See gefahren.","en":"We crossed the lake by boat.","ru":"Мы переплыли озеро на лодке.","vi":"Chúng tôi đi thuyền qua hồ.","fa":"با قایق از کنار دریاچه عبور کردیم."},{"de":"Am Wochenende mieten wir ein kleines Boot.","en":"On the weekend we're renting a small boat.","ru":"В выходные мы арендуем маленькую лодку.","vi":"Cuối tuần chúng tôi thuê một chiếc thuyền nhỏ.","fa":"در آخر هفته یک قایق کوچک کرایه می کنیم."}]},{"word":"böse","en":"angry; evil","ru":"злой, сердитый","vi":"tà ác","fa":"بد","examples":[{"de":"Meine Mutter war böse, weil ich zu spät kam.","en":"My mother was angry because I came too late.","ru":"Моя мама была сердита, потому что я пришёл слишком поздно.","vi":"Mẹ tôi tức giận vì tôi đến muộn.","fa":"مادرم به خاطر دیر آمدن من عصبانی بود."},{"de":"In dem Märchen gibt es eine böse Hexe.","en":"In the fairy tale there is an evil witch.","ru":"В этой сказке есть злая ведьма.","vi":"Trong truyện cổ tích có một mụ phù thủy độc ác.","fa":"در افسانه یک جادوگر شیطانی وجود دارد."}]},{"word":"die Botschaft","en":"embassy; message","ru":"посольство; послание","vi":"tin nhắn","fa":"پیام","examples":[{"de":"Für das Visum musste ich zur Botschaft gehen.","en":"For the visa I had to go to the embassy.","ru":"Для визы мне пришлось пойти в посольство.","vi":"Tôi phải đến đại sứ quán để xin visa.","fa":"برای ویزا باید برم سفارت."},{"de":"Er hinterließ ihr eine wichtige Botschaft.","en":"He left her an important message.","ru":"Он оставил ей важное послание.","vi":"Anh để lại cho cô một tin nhắn quan trọng.","fa":"او یک پیام مهم برای او گذاشت."}]},{"word":"braten","en":"to fry; to roast","ru":"жарить","vi":"chiên","fa":"سرخ کردن","examples":[{"de":"Sie brät das Fleisch in der Pfanne.","en":"She fries the meat in the pan.","ru":"Она жарит мясо на сковороде.","vi":"Cô chiên thịt trong chảo.","fa":"او گوشت را در تابه سرخ می کند."},{"de":"Wir braten am Sonntag ein Hähnchen.","en":"We're roasting a chicken on Sunday.","ru":"В воскресенье мы жарим курицу.","vi":"Chúng tôi sẽ nướng gà vào ngày chủ nhật.","fa":"یکشنبه داریم جوجه کباب میکنیم."}]},{"word":"brauchen","en":"to need","ru":"нуждаться","vi":"cần","fa":"نیاز دارند","examples":[{"de":"Ich brauche mehr Zeit für dieses Projekt.","en":"I need more time for this project.","ru":"Мне нужно больше времени для этого проекта.","vi":"Tôi cần thêm thời gian cho dự án này.","fa":"برای این پروژه به زمان بیشتری نیاز دارم."},{"de":"Brauchst du Hilfe beim Umzug?","en":"Do you need help with the move?","ru":"Тебе нужна помощь с переездом?","vi":"Bạn có cần giúp đỡ di chuyển?","fa":"آیا برای حرکت به کمک نیاز دارید؟"}]},{"word":"brechen","en":"to break","ru":"ломать","vi":"phá vỡ","fa":"شکستن","examples":[{"de":"Er hat sich beim Skifahren das Bein gebrochen.","en":"He broke his leg while skiing.","ru":"Он сломал ногу, катаясь на лыжах.","vi":"Anh ấy bị gãy chân khi trượt tuyết.","fa":"هنگام اسکی پایش شکست."},{"de":"Pass auf, dass das Glas nicht bricht!","en":"Be careful the glass doesn't break!","ru":"Осторожно, чтобы стекло не разбилось!","vi":"Hãy cẩn thận để không làm vỡ kính!","fa":"مراقب باشید که شیشه نشکند!"}]},{"word":"breit","en":"wide","ru":"широкий","vi":"rộng","fa":"گسترده","examples":[{"de":"Die Straße vor unserem Haus ist sehr breit.","en":"The street in front of our house is very wide.","ru":"Улица перед нашим домом очень широкая.","vi":"Con đường trước nhà chúng tôi rất rộng.","fa":"خیابون جلوی خونه ما خیلی عریضه."},{"de":"Er hat breite Schultern.","en":"He has broad shoulders.","ru":"У него широкие плечи.","vi":"Anh ấy có bờ vai rộng.","fa":"او شانه های پهنی دارد."}]},{"word":"bremsen","en":"to brake","ru":"тормозить","vi":"phanh","fa":"ترمز","examples":[{"de":"Der Fahrer musste plötzlich stark bremsen.","en":"The driver had to brake hard suddenly.","ru":"Водителю пришлось резко затормозить.","vi":"Tài xế bất ngờ phải phanh gấp.","fa":"راننده ناگهان مجبور شد به شدت ترمز کند."},{"de":"Auf nasser Straße sollte man vorsichtig bremsen.","en":"On a wet road you should brake carefully.","ru":"На мокрой дороге нужно тормозить осторожно.","vi":"Bạn nên phanh cẩn thận trên đường ướt.","fa":"در جاده های خیس باید با احتیاط ترمز کنید."}]},{"word":"brennen","en":"to burn","ru":"гореть","vi":"đốt cháy","fa":"سوختن","examples":[{"de":"Im Kamin brennt ein warmes Feuer.","en":"A warm fire is burning in the fireplace.","ru":"В камине горит тёплый огонь.","vi":"Ngọn lửa ấm áp đang cháy trong lò sưởi.","fa":"آتش گرمی در شومینه می سوزد."},{"de":"Meine Augen brennen vom Rauch.","en":"My eyes are burning from the smoke.","ru":"Мои глаза жжёт от дыма.","vi":"Mắt tôi bỏng rát vì khói.","fa":"چشمانم از دود می سوزد."}]},{"word":"der Brief","en":"letter","ru":"письмо","vi":"lá thư","fa":"نامه","examples":[{"de":"Ich habe meiner Freundin einen langen Brief geschrieben.","en":"I wrote my friend a long letter.","ru":"Я написал своей подруге длинное письмо.","vi":"Tôi đã viết một lá thư dài cho bạn gái của tôi.","fa":"من یک نامه طولانی به دوست دخترم نوشتم."},{"de":"Hast du den Brief schon zur Post gebracht?","en":"Have you already taken the letter to the post office?","ru":"Ты уже отнёс письмо на почту?","vi":"Bạn đã gửi thư chưa?","fa":"آیا قبلا نامه را پست کرده اید؟"}]},{"word":"die Brieftasche","en":"wallet","ru":"кошелёк, бумажник","vi":"cái ví","fa":"کیف پول","examples":[{"de":"Ich habe meine Brieftasche im Bus vergessen.","en":"I forgot my wallet on the bus.","ru":"Я забыл свой бумажник в автобусе.","vi":"Tôi quên ví trên xe buýt.","fa":"کیف پولم را در اتوبوس فراموش کردم."},{"de":"In seiner Brieftasche sind Geld und Ausweis.","en":"His wallet has money and an ID card in it.","ru":"В его бумажнике деньги и удостоверение личности.","vi":"Có tiền và giấy tờ tùy thân trong ví của anh ấy.","fa":"در کیف پولش پول و شناسنامه هست."}]},{"word":"der Briefumschlag","en":"envelope","ru":"конверт","vi":"phong bì","fa":"پاکت نامه","examples":[{"de":"Ich klebe die Briefmarke auf den Briefumschlag.","en":"I stick the stamp on the envelope.","ru":"Я приклеиваю марку на конверт.","vi":"Tôi dán tem lên phong bì.","fa":"مهر را روی پاکت می چسبانم."},{"de":"Sie legte das Foto in den Briefumschlag.","en":"She put the photo in the envelope.","ru":"Она положила фото в конверт.","vi":"Cô nhét bức ảnh vào phong bì.","fa":"او عکس را در پاکت گذاشت."}]},{"word":"die Brille","en":"glasses","ru":"очки","vi":"cái kính","fa":"عینک","examples":[{"de":"Ohne Brille kann ich nicht gut lesen.","en":"Without glasses I can't read well.","ru":"Без очков я плохо вижу при чтении.","vi":"Tôi không thể đọc tốt nếu không có kính.","fa":"بدون عینک نمی توانم خوب بخوانم."},{"de":"Er trägt seit Kurzem eine neue Brille.","en":"He's recently been wearing new glasses.","ru":"Он недавно начал носить новые очки.","vi":"Gần đây anh ấy đã bắt đầu đeo kính mới.","fa":"او اخیراً شروع به استفاده از عینک جدید کرده است."}]},{"word":"bringen","en":"to bring","ru":"приносить","vi":"mang theo","fa":"آوردن","examples":[{"de":"Kannst du mir bitte ein Glas Wasser bringen?","en":"Can you bring me a glass of water, please?","ru":"Можешь принести мне стакан воды?","vi":"Bạn có thể vui lòng mang cho tôi một cốc nước được không?","fa":"میشه لطفا یه لیوان آب برام بیارید؟"},{"de":"Der Kellner bringt uns gleich die Speisekarte.","en":"The waiter will bring us the menu shortly.","ru":"Официант сейчас принесёт нам меню.","vi":"Người phục vụ mang thực đơn đến cho chúng tôi ngay lập tức.","fa":"گارسون فوراً منو را برای ما می آورد."}]},{"word":"die Broschüre","en":"brochure","ru":"брошюра","vi":"tờ rơi","fa":"بروشور","examples":[{"de":"Am Bahnhof gibt es eine Broschüre über die Stadt.","en":"At the train station there's a brochure about the city.","ru":"На вокзале есть брошюра о городе.","vi":"Có một tập tài liệu về thành phố ở ga xe lửa.","fa":"یک بروشور در مورد شهر در ایستگاه قطار وجود دارد."},{"de":"Im Reisebüro bekam ich viele Broschüren.","en":"At the travel agency I got many brochures.","ru":"В турагентстве я получил много брошюр.","vi":"Tôi nhận được rất nhiều tài liệu quảng cáo tại công ty du lịch.","fa":"من بروشورهای زیادی در آژانس مسافرتی گرفتم."}]},{"word":"das Brot","en":"bread","ru":"хлеб","vi":"bánh mì","fa":"نان","examples":[{"de":"Jeden Morgen kaufe ich frisches Brot beim Bäcker.","en":"Every morning I buy fresh bread at the bakery.","ru":"Каждое утро я покупаю свежий хлеб в пекарне.","vi":"Mỗi sáng tôi mua bánh mì tươi từ tiệm bánh.","fa":"هر روز صبح از نانوایی نان تازه می خرم."},{"de":"Zum Frühstück esse ich Brot mit Marmelade.","en":"For breakfast I eat bread with jam.","ru":"На завтрак я ем хлеб с джемом.","vi":"Bữa sáng tôi ăn bánh mì với mứt.","fa":"برای صبحانه نان با مربا می خورم."}]},{"word":"das Brötchen","en":"bread roll","ru":"булочка","vi":"cái bánh bao","fa":"نان","examples":[{"de":"Wir haben heute Morgen frische Brötchen gekauft.","en":"We bought fresh bread rolls this morning.","ru":"Сегодня утром мы купили свежие булочки.","vi":"Chúng tôi đã mua bánh mì tươi sáng nay.","fa":"امروز صبح نان رول تازه خریدیم."},{"de":"Ein Brötchen mit Käse ist mein Lieblingsfrühstück.","en":"A roll with cheese is my favorite breakfast.","ru":"Булочка с сыром — мой любимый завтрак.","vi":"Bánh mì cuộn phô mai là bữa sáng yêu thích của tôi.","fa":"رول با پنیر صبحانه مورد علاقه من است."}]},{"word":"die Brücke","en":"bridge","ru":"мост","vi":"cây cầu","fa":"پل","examples":[{"de":"Wir überqueren die Brücke, um zum Bahnhof zu kommen.","en":"We cross the bridge to get to the train station.","ru":"Мы переходим мост, чтобы попасть на вокзал.","vi":"Chúng tôi băng qua cầu để đến ga xe lửa.","fa":"از روی پل عبور می کنیم تا به ایستگاه قطار برسیم."},{"de":"Diese Brücke über den Fluss ist sehr alt.","en":"This bridge over the river is very old.","ru":"Этот мост через реку очень старый.","vi":"Cây cầu bắc qua sông này rất cũ.","fa":"این پل روی رودخانه بسیار قدیمی است."}]},{"word":"der Bruder","en":"brother","ru":"брат","vi":"anh trai","fa":"برادر","examples":[{"de":"Mein Bruder ist zwei Jahre älter als ich.","en":"My brother is two years older than me.","ru":"Мой брат на два года старше меня.","vi":"Anh trai tôi hơn tôi hai tuổi.","fa":"برادرم دو سال از من بزرگتر است."},{"de":"Ich habe einen kleinen Bruder.","en":"I have a little brother.","ru":"У меня есть младший брат.","vi":"Tôi có một em trai.","fa":"من یک برادر کوچک دارم."}]},{"word":"die Brust","en":"chest; breast","ru":"грудь","vi":"ngực","fa":"قفسه سینه","examples":[{"de":"Nach dem Sturz tat ihm die Brust weh.","en":"After the fall his chest hurt.","ru":"После падения у него болела грудь.","vi":"Ngực anh đau sau cú ngã.","fa":"سینه اش بعد از زمین خوردن درد می کرد."},{"de":"Der Arzt hörte seine Brust ab.","en":"The doctor listened to his chest.","ru":"Врач прослушал его грудную клетку.","vi":"Bác sĩ lắng nghe lồng ngực của mình.","fa":"دکتر به قفسه سینه اش گوش داد."}]},{"word":"der Bub","en":"boy","ru":"мальчик","vi":"cậu bé","fa":"پسر","examples":[{"de":"Der kleine Bub spielt mit seinem Ball im Garten.","en":"The little boy is playing with his ball in the garden.","ru":"Маленький мальчик играет с мячом в саду.","vi":"Cậu bé chơi với quả bóng của mình trong vườn.","fa":"پسر کوچک در باغ با توپش بازی می کند."},{"de":"In der Schweiz sagt man oft \"Bub\" statt \"Junge\".","en":"In Switzerland people often say \"Bub\" instead of \"Junge\".","ru":"В Швейцарии часто говорят «Bub» вместо «Junge».","vi":"Ở Thụy Sĩ người ta thường nói “Bub” thay vì “Junge”.","fa":"در سوئیس مردم اغلب به جای \"Junge\" \"Bub\" می گویند."}]},{"word":"das Buch","en":"book","ru":"книга","vi":"cuốn sách","fa":"کتاب","examples":[{"de":"Ich lese gerade ein spannendes Buch.","en":"I'm currently reading an exciting book.","ru":"Я сейчас читаю увлекательную книгу.","vi":"Hiện tại tôi đang đọc một cuốn sách thú vị.","fa":"در حال حاضر مشغول خواندن یک کتاب هیجان انگیز هستم."},{"de":"Sie hat mir ein Buch zum Geburtstag geschenkt.","en":"She gave me a book for my birthday.","ru":"Она подарила мне книгу на день рождения.","vi":"Cô ấy tặng tôi một cuốn sách vào ngày sinh nhật của tôi.","fa":"او برای تولدم به من کتاب داد."}]},{"word":"buchen","en":"to book","ru":"бронировать","vi":"cuốn sách","fa":"کتاب","examples":[{"de":"Wir haben unseren Flug schon vor drei Monaten gebucht.","en":"We booked our flight three months ago already.","ru":"Мы забронировали наш рейс уже три месяца назад.","vi":"Chúng tôi đã đặt chuyến bay ba tháng trước.","fa":"ما پروازمان را سه ماه پیش رزرو کردیم."},{"de":"Ich möchte ein Zimmer für zwei Nächte buchen.","en":"I would like to book a room for two nights.","ru":"Я хотел бы забронировать номер на две ночи.","vi":"Tôi muốn đặt một phòng trong hai đêm.","fa":"من می خواهم یک اتاق برای دو شب رزرو کنم."}]},{"word":"die Buchhandlung","en":"bookshop","ru":"книжный магазин","vi":"hiệu sách","fa":"کتابفروشی","examples":[{"de":"In der Buchhandlung habe ich ein neues Wörterbuch gekauft.","en":"At the bookshop I bought a new dictionary.","ru":"В книжном магазине я купил новый словарь.","vi":"Tôi đã mua một cuốn từ điển mới ở hiệu sách.","fa":"از کتابفروشی یک دیکشنری جدید خریدم."},{"de":"Die Buchhandlung in der Altstadt ist sehr gemütlich.","en":"The bookshop in the old town is very cozy.","ru":"Книжный магазин в старом городе очень уютный.","vi":"Hiệu sách trong phố cổ rất ấm cúng.","fa":"کتابفروشی در شهر قدیمی بسیار دنج است."}]},{"word":"die Büchse","en":"can; tin; box","ru":"банка, коробка","vi":"cái lon","fa":"قوطی","examples":[{"de":"Sie öffnete eine Büchse Bohnen für das Abendessen.","en":"She opened a can of beans for dinner.","ru":"Она открыла банку фасоли на ужин.","vi":"Cô mở hộp đậu cho bữa tối.","fa":"یک قوطی لوبیا برای شام باز کرد."},{"de":"Der Hund frisst Futter aus der Büchse.","en":"The dog eats food from the can.","ru":"Собака ест корм из банки.","vi":"Con chó ăn thức ăn từ hộp.","fa":"سگ از قوطی غذا می خورد."}]},{"word":"buchstabieren","en":"to spell","ru":"произносить по буквам","vi":"đánh vần","fa":"طلسم","examples":[{"de":"Können Sie bitte Ihren Namen buchstabieren?","en":"Could you please spell your name?","ru":"Не могли бы вы произнести своё имя по буквам?","vi":"Bạn có thể vui lòng đánh vần tên của bạn?","fa":"میشه لطفا اسمتو بنویسی"},{"de":"Das Kind lernt gerade, einfache Wörter zu buchstabieren.","en":"The child is currently learning to spell simple words.","ru":"Ребёнок сейчас учится произносить простые слова по буквам.","vi":"Trẻ hiện đang học cách đánh vần những từ đơn giản.","fa":"کودک در حال حاضر در حال یادگیری املای کلمات ساده است."}]},{"word":"das Buffet","en":"buffet","ru":"фуршет, шведский стол","vi":"bữa tiệc buffet","fa":"بوفه","examples":[{"de":"Beim Frühstück gibt es ein großes Buffet mit vielen Speisen.","en":"At breakfast there's a large buffet with many dishes.","ru":"На завтраке большой шведский стол с множеством блюд.","vi":"Vào bữa sáng có tiệc buffet lớn với nhiều món ăn.","fa":"در وعده صبحانه یک بوفه بزرگ با غذاهای فراوان وجود دارد."},{"de":"Auf der Hochzeit stand ein reiches Buffet bereit.","en":"At the wedding a rich buffet was ready.","ru":"На свадьбе был приготовлен богатый фуршетный стол.","vi":"Tiệc buffet phong phú được phục vụ trong đám cưới.","fa":"یک بوفه غنی در مراسم عروسی موجود بود."}]},{"word":"die Bühne","en":"stage","ru":"сцена","vi":"sân khấu","fa":"صحنه","examples":[{"de":"Der Sänger stand allein auf der Bühne.","en":"The singer stood alone on the stage.","ru":"Певец стоял один на сцене.","vi":"Ca sĩ đứng một mình trên sân khấu.","fa":"خواننده روی صحنه تنها بود."},{"de":"Die Schauspieler betraten die Bühne.","en":"The actors entered the stage.","ru":"Актёры вышли на сцену.","vi":"Các diễn viên bước vào sân khấu.","fa":"بازیگران وارد صحنه شدند."}]},{"word":"bunt","en":"colorful","ru":"разноцветный","vi":"đầy màu sắc","fa":"رنگارنگ","examples":[{"de":"Die Kinder malten ein buntes Bild.","en":"The children painted a colorful picture.","ru":"Дети нарисовали разноцветную картину.","vi":"Các em đã vẽ nên một bức tranh đầy màu sắc.","fa":"بچه ها نقاشی رنگارنگ کشیدند."},{"de":"Im Herbst sind die Blätter bunt.","en":"In autumn the leaves are colorful.","ru":"Осенью листья разноцветные.","vi":"Vào mùa thu, lá có nhiều màu sắc.","fa":"در پاییز برگها رنگارنگ هستند."}]},{"word":"die Burg","en":"castle","ru":"крепость, замок","vi":"lâu đài","fa":"قلعه","examples":[{"de":"Wir haben am Wochenende eine alte Burg besichtigt.","en":"We visited an old castle on the weekend.","ru":"В выходные мы осмотрели старый замок.","vi":"Chúng tôi đến thăm một lâu đài cổ vào cuối tuần.","fa":"آخر هفته از یک قلعه قدیمی بازدید کردیم."},{"de":"Die Burg steht hoch oben auf einem Berg.","en":"The castle stands high up on a mountain.","ru":"Замок стоит высоко на горе.","vi":"Lâu đài đứng cao trên một ngọn núi.","fa":"این قلعه بر فراز کوهی قرار دارد."}]},{"word":"der Bürger","en":"citizen","ru":"гражданин","vi":"công dân","fa":"شهروند","examples":[{"de":"Jeder Bürger hat das Recht zu wählen.","en":"Every citizen has the right to vote.","ru":"Каждый гражданин имеет право голосовать.","vi":"Mọi công dân đều có quyền bầu cử.","fa":"هر شهروندی حق رای دارد."},{"de":"Die Bürger der Stadt protestierten gegen den Plan.","en":"The citizens of the city protested against the plan.","ru":"Жители города протестовали против этого плана.","vi":"Người dân thành phố phản đối kế hoạch này.","fa":"شهروندان این شهر به این طرح اعتراض کردند."}]},{"word":"das Büro","en":"office","ru":"офис","vi":"văn phòng","fa":"دفتر","examples":[{"de":"Ich arbeite von 9 bis 17 Uhr im Büro.","en":"I work in the office from 9 to 5.","ru":"Я работаю в офисе с 9 до 17 часов.","vi":"Tôi làm việc ở văn phòng từ 9 giờ sáng đến 5 giờ chiều.","fa":"من از ساعت 9 صبح تا 5 بعد از ظهر در دفتر کار می کنم."},{"de":"Ihr Büro liegt im dritten Stock.","en":"Her office is on the third floor.","ru":"Её офис находится на третьем этаже.","vi":"Văn phòng của cô ấy ở trên tầng ba.","fa":"دفتر او در طبقه سوم است."}]},{"word":"die Bürste","en":"brush","ru":"щётка","vi":"bàn chải","fa":"قلم مو","examples":[{"de":"Sie kämmt ihre Haare mit einer Bürste.","en":"She brushes her hair with a brush.","ru":"Она расчёсывает волосы щёткой.","vi":"Cô ấy chải tóc bằng lược.","fa":"موهایش را با برس شانه می کند."},{"de":"Mit dieser Bürste reinige ich meine Schuhe.","en":"I clean my shoes with this brush.","ru":"Этой щёткой я чищу свою обувь.","vi":"Tôi sử dụng bàn chải này để làm sạch giày của tôi.","fa":"من از این برس برای تمیز کردن کفش هایم استفاده می کنم."}]},{"word":"der Bus","en":"bus","ru":"автобус","vi":"xe buýt","fa":"اتوبوس","examples":[{"de":"Ich fahre jeden Tag mit dem Bus zur Arbeit.","en":"I take the bus to work every day.","ru":"Я каждый день езжу на автобусе на работу.","vi":"Tôi đi xe buýt đi làm hàng ngày.","fa":"من هر روز با اتوبوس سر کار می روم."},{"de":"Der Bus kommt in fünf Minuten.","en":"The bus arrives in five minutes.","ru":"Автобус приедет через пять минут.","vi":"Xe buýt sẽ đến trong năm phút nữa.","fa":"اتوبوس پنج دقیقه دیگر می آید."}]},{"word":"die Butter","en":"butter","ru":"масло (сливочное)","vi":"bơ","fa":"کره","examples":[{"de":"Ich streiche Butter auf mein Brot.","en":"I spread butter on my bread.","ru":"Я намазываю масло на хлеб.","vi":"Tôi phết bơ lên bánh mì của mình.","fa":"روی نانم کره زدم."},{"de":"Wir brauchen noch Butter zum Backen.","en":"We still need butter for baking.","ru":"Нам ещё нужно масло для выпечки.","vi":"Chúng ta vẫn cần bơ để nướng bánh.","fa":"هنوز برای پخت به کره نیاز داریم."}]},{"word":"das Café","en":"café","ru":"кафе","vi":"quán cà phê","fa":"کافه","examples":[{"de":"Wir treffen uns im Café um drei Uhr.","en":"We're meeting at the café at three o'clock.","ru":"Мы встречаемся в кафе в три часа.","vi":"Chúng ta sẽ gặp nhau ở quán cà phê lúc ba giờ.","fa":"ساعت سه در کافه همدیگر را می بینیم."},{"de":"Dieses Café serviert den besten Kuchen der Stadt.","en":"This café serves the best cake in the city.","ru":"Это кафе подаёт лучший торт в городе.","vi":"Quán cà phê này phục vụ bánh ngon nhất trong thị trấn.","fa":"این کافه بهترین کیک شهر را سرو می کند."}]},{"word":"die Cafeteria","en":"cafeteria","ru":"кафетерий, столовая","vi":"quán ăn tự phục vụ","fa":"کافه تریا","examples":[{"de":"In der Mittagspause essen wir in der Cafeteria.","en":"During lunch break we eat in the cafeteria.","ru":"В обеденный перерыв мы едим в кафетерии.","vi":"Trong giờ nghỉ trưa, chúng tôi ăn ở căng tin.","fa":"در زمان استراحت ناهار در کافه تریا غذا می خوریم."},{"de":"Die Cafeteria der Universität ist immer voll.","en":"The university cafeteria is always full.","ru":"Кафетерий университета всегда полон.","vi":"Căn tin của trường đại học luôn đầy ắp.","fa":"کافه تریا دانشگاه همیشه پر است."}]},{"word":"die Chance","en":"chance; opportunity","ru":"шанс","vi":"cơ hội","fa":"شانس","examples":[{"de":"Das ist deine Chance, den Job zu bekommen.","en":"This is your chance to get the job.","ru":"Это твой шанс получить эту работу.","vi":"Đây là cơ hội để bạn có được công việc.","fa":"این فرصت شماست تا شغل را بدست آورید."},{"de":"Er hat keine Chance mehr, das Spiel zu gewinnen.","en":"He no longer has a chance to win the game.","ru":"У него больше нет шанса выиграть игру.","vi":"Anh ta không còn cơ hội chiến thắng trong trò chơi nữa.","fa":"او دیگر شانسی برای بردن بازی ندارد."}]},{"word":"der Chef","en":"boss","ru":"начальник, шеф","vi":"ông chủ","fa":"رئیس","examples":[{"de":"Mein Chef ist sehr streng, aber fair.","en":"My boss is very strict but fair.","ru":"Мой начальник очень строгий, но справедливый.","vi":"Sếp của tôi rất nghiêm khắc nhưng công bằng.","fa":"رئیس من بسیار سختگیر اما منصف است."},{"de":"Ich muss morgen früh mit meinem Chef sprechen.","en":"I have to talk to my boss tomorrow morning.","ru":"Мне нужно поговорить с начальником завтра утром.","vi":"Sáng mai tôi phải nói chuyện với sếp của tôi.","fa":"فردا صبح باید با رئیسم صحبت کنم."}]},{"word":"chic/schick","en":"chic; stylish","ru":"шикарный, стильный","vi":"sang trọng/sang trọng","fa":"شیک / شیک","examples":[{"de":"Sie trägt heute ein sehr schickes Kleid.","en":"She's wearing a very chic dress today.","ru":"Сегодня она в очень стильном платье.","vi":"Hôm nay cô ấy mặc một chiếc váy rất sang trọng.","fa":"او امروز یک لباس بسیار شیک پوشیده است."},{"de":"Das neue Restaurant ist wirklich chic eingerichtet.","en":"The new restaurant is really chicly decorated.","ru":"Новый ресторан оформлен действительно шикарно.","vi":"Nhà hàng mới thực sự sang trọng.","fa":"رستوران جدید واقعا شیک است."}]},{"word":"der Coiffeur","en":"hairdresser","ru":"парикмахер","vi":"thợ làm tóc","fa":"آرایشگاه","examples":[{"de":"Ich habe morgen einen Termin beim Coiffeur.","en":"I have an appointment at the hairdresser's tomorrow.","ru":"У меня завтра запись к парикмахеру.","vi":"Tôi có cuộc hẹn với thợ làm tóc vào ngày mai.","fa":"فردا با آرایشگر وقت دارم."},{"de":"Der Coiffeur hat mir die Haare kurz geschnitten.","en":"The hairdresser cut my hair short.","ru":"Парикмахер коротко подстриг мне волосы.","vi":"Thợ làm tóc đã cắt tóc ngắn cho tôi.","fa":"آرایشگر موهایم را کوتاه کرد."}]},{"word":"die Couch","en":"couch; sofa","ru":"диван","vi":"chiếc ghế dài","fa":"کاناپه","examples":[{"de":"Am Abend liegen wir gerne auf der Couch und schauen fern.","en":"In the evening we like to lie on the couch and watch TV.","ru":"Вечером мы любим лежать на диване и смотреть телевизор.","vi":"Vào buổi tối, chúng tôi thích nằm trên ghế dài và xem TV.","fa":"عصرها دوست داریم روی مبل دراز بکشیم و تلویزیون تماشا کنیم."},{"de":"Die neue Couch im Wohnzimmer ist sehr bequem.","en":"The new couch in the living room is very comfortable.","ru":"Новый диван в гостиной очень удобный.","vi":"Chiếc ghế dài mới trong phòng khách rất thoải mái.","fa":"کاناپه جدید در اتاق نشیمن بسیار راحت است."}]},{"word":"der Cousin","en":"cousin","ru":"двоюродный брат","vi":"anh họ","fa":"پسر عمو","examples":[{"de":"Mein Cousin wohnt in Berlin.","en":"My cousin lives in Berlin.","ru":"Мой двоюродный брат живёт в Берлине.","vi":"Anh họ của tôi sống ở Berlin.","fa":"پسر عموی من در برلین زندگی می کند."},{"de":"Am Wochenende besuche ich meinen Cousin.","en":"On the weekend I'm visiting my cousin.","ru":"В выходные я навещу своего двоюродного брата.","vi":"Vào cuối tuần tôi đến thăm anh họ của tôi.","fa":"آخر هفته به دیدن پسر عمویم می‌روم."}]},{"word":"das Couvert","en":"envelope","ru":"конверт","vi":"phong bì","fa":"پاکت نامه","examples":[{"de":"Ich stecke den Brief in ein Couvert.","en":"I put the letter in an envelope.","ru":"Я кладу письмо в конверт.","vi":"Tôi bỏ lá thư vào phong bì.","fa":"نامه را در یک پاکت گذاشتم."},{"de":"Auf dem Couvert steht die Adresse des Empfängers.","en":"The recipient's address is on the envelope.","ru":"На конверте указан адрес получателя.","vi":"Địa chỉ người nhận được ghi trên phong bì.","fa":"آدرس گیرنده روی پاکت نوشته شده است."}]},{"word":"die Creme","en":"cream","ru":"крем","vi":"kem","fa":"کرم","examples":[{"de":"Sie trägt jeden Abend eine Creme für ihre Haut auf.","en":"She applies a cream for her skin every evening.","ru":"Она каждый вечер наносит крем для кожи.","vi":"Cô ấy thoa kem lên da vào mỗi buổi tối.","fa":"او هر روز غروب یک کرم روی پوستش می‌مالد."},{"de":"Nach dem Sonnenbad benutze ich eine kühlende Creme.","en":"After sunbathing I use a cooling cream.","ru":"После загара я использую охлаждающий крем.","vi":"Sau khi tắm nắng tôi sử dụng kem làm mát.","fa":"بعد از آفتاب گرفتن از کرم خنک کننده استفاده می کنم."}]},{"word":"da","en":"there; since/because","ru":"там; так как","vi":"ở đó","fa":"وجود دارد","examples":[{"de":"Da drüben steht mein Auto.","en":"My car is over there.","ru":"Там стоит моя машина.","vi":"Xe của tôi ở đằng kia.","fa":"ماشین من اونجاست"},{"de":"Da es regnet, bleiben wir zu Hause.","en":"Since it's raining, we're staying home.","ru":"Так как идёт дождь, мы останемся дома.","vi":"Vì trời mưa nên chúng tôi ở nhà.","fa":"از آنجایی که باران می بارد، ما در خانه می مانیم."}]},{"word":"dabei","en":"with it; while doing so","ru":"при этом","vi":"ở đó","fa":"وجود دارد","examples":[{"de":"Ich koche gern und höre dabei Musik.","en":"I like to cook and listen to music while doing so.","ru":"Я люблю готовить и при этом слушать музыку.","vi":"Tôi thích nấu ăn và nghe nhạc.","fa":"من آشپزی و گوش دادن به موسیقی را دوست دارم."},{"de":"Bist du am Samstag auch dabei?","en":"Are you joining in on Saturday too?","ru":"Ты тоже будешь участвовать в субботу?","vi":"Bạn cũng ở đó vào thứ bảy phải không?","fa":"شنبه هم هستی؟"}]},{"word":"das Dach","en":"roof","ru":"крыша","vi":"mái nhà","fa":"سقف","examples":[{"de":"Nach dem Sturm mussten sie das Dach reparieren.","en":"After the storm they had to repair the roof.","ru":"После шторма им пришлось починить крышу.","vi":"Sau cơn bão họ phải sửa lại mái nhà.","fa":"پس از طوفان مجبور شدند سقف را تعمیر کنند."},{"de":"Auf dem Dach unseres Hauses sind Solarzellen.","en":"There are solar panels on the roof of our house.","ru":"На крыше нашего дома есть солнечные батареи.","vi":"Có pin mặt trời trên mái nhà của chúng tôi.","fa":"در پشت بام خانه ما سلول های خورشیدی وجود دارد."}]},{"word":"dafür","en":"for it; in favor of it","ru":"за это","vi":"vì điều đó","fa":"برای آن","examples":[{"de":"Ich bin dafür, dass wir früher losfahren.","en":"I'm in favor of us leaving earlier.","ru":"Я за то, чтобы мы выехали пораньше.","vi":"Tôi ủng hộ việc rời đi sớm hơn.","fa":"من طرفدار زودتر رفتن هستم."},{"de":"Er hat hart gearbeitet, und dafür wurde er belohnt.","en":"He worked hard, and for that he was rewarded.","ru":"Он много работал, и за это его вознаградили.","vi":"Anh ấy đã làm việc chăm chỉ và được khen thưởng vì điều đó.","fa":"او سخت کار کرد و برای آن پاداش گرفت."}]},{"word":"dagegen","en":"against it","ru":"против этого","vi":"chống lại nó","fa":"در برابر آن","examples":[{"de":"Ich bin dagegen, dass wir das Projekt abbrechen.","en":"I'm against us cancelling the project.","ru":"Я против того, чтобы мы прекратили проект.","vi":"Tôi phản đối việc hủy bỏ dự án.","fa":"من مخالف لغو پروژه هستم."},{"de":"Hast du etwas dagegen, wenn ich das Fenster öffne?","en":"Do you mind if I open the window?","ru":"Ты не против, если я открою окно?","vi":"Bạn có phiền nếu tôi mở cửa sổ không?","fa":"آیا اشکالی ندارد که پنجره را باز کنم؟"}]},{"word":"daher","en":"therefore","ru":"поэтому","vi":"do đó","fa":"بنابراین","examples":[{"de":"Es regnet stark, daher bleibe ich lieber zu Hause.","en":"It's raining heavily, therefore I'd rather stay home.","ru":"Идёт сильный дождь, поэтому я лучше останусь дома.","vi":"Trời đang mưa to nên tôi thà ở nhà còn hơn.","fa":"باران شدیدی می بارد، پس ترجیح می دهم در خانه بمانم."},{"de":"Er kommt aus Wien, daher spricht er sehr gut Deutsch.","en":"He's from Vienna, that's why he speaks German very well.","ru":"Он из Вены, поэтому он очень хорошо говорит по-немецки.","vi":"Anh ấy đến từ Vienna nên nói tiếng Đức rất tốt.","fa":"او اهل وین است، بنابراین آلمانی را خیلی خوب صحبت می کند."}]},{"word":"dahin","en":"there; to that place","ru":"туда","vi":"ở đó","fa":"وجود دارد","examples":[{"de":"Wir fahren morgen dahin, wo wir letztes Jahr Urlaub gemacht haben.","en":"Tomorrow we're going there where we vacationed last year.","ru":"Завтра мы поедем туда, где отдыхали в прошлом году.","vi":"Ngày mai chúng ta sẽ đi đến nơi chúng ta đã đi nghỉ năm ngoái.","fa":"فردا میریم جایی که پارسال تعطیلات داشتیم."},{"de":"Bis dahin habe ich hoffentlich alles fertig.","en":"By then I'll hopefully have everything ready.","ru":"К тому времени я, надеюсь, всё закончу.","vi":"Hy vọng đến lúc đó tôi sẽ làm xong mọi việc.","fa":"امیدوارم تا آن زمان همه چیز تمام شده باشد."}]},{"word":"damals","en":"back then; at that time","ru":"тогда","vi":"hồi đó","fa":"آن زمان","examples":[{"de":"Damals wohnten wir noch in einem kleinen Dorf.","en":"Back then we still lived in a small village.","ru":"Тогда мы ещё жили в маленькой деревне.","vi":"Lúc đó chúng tôi vẫn sống ở một ngôi làng nhỏ.","fa":"در آن زمان ما هنوز در یک روستای کوچک زندگی می کردیم."},{"de":"Das Leben war damals viel einfacher.","en":"Life was much simpler back then.","ru":"Жизнь тогда была намного проще.","vi":"Cuộc sống hồi đó đơn giản hơn nhiều.","fa":"در آن زمان زندگی بسیار ساده تر بود."}]},{"word":"die Dame","en":"lady","ru":"дама","vi":"quý cô","fa":"خانم","examples":[{"de":"Die ältere Dame setzte sich neben mich in den Bus.","en":"The elderly lady sat down next to me on the bus.","ru":"Пожилая дама села рядом со мной в автобусе.","vi":"Người phụ nữ lớn tuổi ngồi cạnh tôi trên xe buýt.","fa":"خانم بزرگتر در اتوبوس کنار من نشست."},{"de":"Meine Damen und Herren, herzlich willkommen!","en":"Ladies and gentlemen, welcome!","ru":"Дамы и господа, добро пожаловать!","vi":"Thưa quý vị, xin chào mừng!","fa":"خانم ها و آقایان، خوش آمدید!"}]},{"word":"damit","en":"with it; so that","ru":"с этим; чтобы","vi":"với điều đó","fa":"با آن","examples":[{"de":"Ich habe einen Regenschirm, damit kann ich trocken bleiben.","en":"I have an umbrella, with it I can stay dry.","ru":"У меня есть зонт, с ним я могу остаться сухим.","vi":"Tôi có một chiếc ô để tôi có thể khô ráo.","fa":"من یک چتر دارم تا بتوانم خشک بمانم."},{"de":"Sie spricht langsam, damit alle sie verstehen.","en":"She speaks slowly so that everyone understands her.","ru":"Она говорит медленно, чтобы все её понимали.","vi":"Cô nói chậm để mọi người có thể hiểu được.","fa":"آهسته صحبت می کند تا همه او را بفهمند."}]},{"word":"danach","en":"after that; afterwards","ru":"после этого","vi":"sau đó","fa":"پس از آن","examples":[{"de":"Wir essen zu Mittag und gehen danach spazieren.","en":"We'll have lunch and go for a walk afterwards.","ru":"Мы пообедаем, а после этого пойдём гулять.","vi":"Chúng tôi ăn trưa và sau đó đi dạo.","fa":"ناهار می خوریم و بعد پیاده روی می کنیم."},{"de":"Zuerst die Hausaufgaben, danach kannst du spielen.","en":"First the homework, afterwards you can play.","ru":"Сначала домашнее задание, потом можешь играть.","vi":"Làm bài tập về nhà trước, sau đó mới có thể chơi.","fa":"اول تکالیف، بعد می توانید بازی کنید."}]},{"word":"daneben","en":"next to it; beside it","ru":"рядом с этим","vi":"bên cạnh nó","fa":"در کنار آن","examples":[{"de":"Das Sofa steht am Fenster, und daneben ist ein kleiner Tisch.","en":"The sofa is by the window, and next to it is a small table.","ru":"Диван стоит у окна, а рядом с ним стоит маленький столик.","vi":"Ghế sofa đặt cạnh cửa sổ và có một chiếc bàn nhỏ bên cạnh.","fa":"مبل کنار پنجره است و یک میز کوچک کنار آن قرار دارد."},{"de":"Die Kirche und das Rathaus daneben sind sehr alt.","en":"The church and the town hall next to it are very old.","ru":"Церковь и ратуша рядом с ней очень старые.","vi":"Nhà thờ và tòa thị chính bên cạnh rất cũ.","fa":"کلیسا و تالار شهر در کنار آن بسیار قدیمی هستند."}]},{"word":"danken","en":"to thank","ru":"благодарить","vi":"cảm ơn bạn","fa":"متشکرم","examples":[{"de":"Ich möchte dir für deine Hilfe danken.","en":"I would like to thank you for your help.","ru":"Я хочу поблагодарить тебя за помощь.","vi":"Tôi muốn cảm ơn sự giúp đỡ của bạn.","fa":"می خواهم از کمک شما تشکر کنم."},{"de":"Er dankte allen Gästen für ihr Kommen.","en":"He thanked all the guests for coming.","ru":"Он поблагодарил всех гостей за то, что пришли.","vi":"Ông cảm ơn tất cả các vị khách đã đến.","fa":"او از حضور همه مهمانان تشکر کرد."}]},{"word":"dann","en":"then","ru":"тогда, потом","vi":"sau đó","fa":"سپس","examples":[{"de":"Wir essen jetzt, und dann gehen wir ins Kino.","en":"We'll eat now, and then we'll go to the movies.","ru":"Мы сейчас поедим, а потом пойдём в кино.","vi":"Chúng ta sẽ ăn bây giờ và sau đó chúng ta sẽ đi xem phim.","fa":"حالا میخوریم و بعد میرویم سینما."},{"de":"Wenn du fertig bist, dann ruf mich an.","en":"When you're done, then call me.","ru":"Когда закончишь, тогда позвони мне.","vi":"Khi nào xong hãy gọi cho tôi.","fa":"وقتی کارتان تمام شد، با من تماس بگیرید."}]},{"word":"darstellen","en":"to depict; to represent","ru":"изображать, представлять","vi":"đại diện","fa":"نمایندگی کند","examples":[{"de":"Das Gemälde stellt eine Landschaft in den Alpen dar.","en":"The painting depicts a landscape in the Alps.","ru":"Картина изображает пейзаж в Альпах.","vi":"Bức tranh mô tả phong cảnh ở dãy Alps.","fa":"این نقاشی منظره ای را در کوه های آلپ به تصویر می کشد."},{"de":"Er stellt in seinem Vortrag die wichtigsten Ergebnisse dar.","en":"He presents the most important results in his talk.","ru":"В своём докладе он представляет самые важные результаты.","vi":"Ông trình bày những kết quả quan trọng nhất trong bài giảng của mình.","fa":"او مهمترین نتایج را در سخنرانی خود ارائه می کند."}]},{"word":"das/der (Schlag-)Obers","en":"(whipped) cream (Austrian)","ru":"(взбитые) сливки (австр.)","vi":"kem (đánh bông)","fa":"خامه ( فرم گرفته )","examples":[{"de":"Ich hätte gern einen Kaffee mit Schlagobers.","en":"I'd like a coffee with whipped cream.","ru":"Я хотел бы кофе со взбитыми сливками.","vi":"Tôi muốn một ly cà phê với kem tươi.","fa":"من یک قهوه با خامه می خواهم."},{"de":"Auf dem Kuchen ist eine große Portion Obers.","en":"There's a large portion of cream on the cake.","ru":"На торте большая порция сливок.","vi":"Có một phần lớn kem trên bánh.","fa":"روی کیک مقدار زیادی خامه وجود دارد."}]},{"word":"das/der Zvieri/Znüni","en":"mid-morning/afternoon snack (Swiss German)","ru":"перекус (швейц. — второй завтрак/полдник)","vi":"bữa ăn nhẹ/bữa trưa","fa":"میان وعده/ناهار","examples":[{"de":"Die Kinder essen in der Schule ihr Znüni.","en":"The children eat their morning snack at school.","ru":"Дети едят свой перекус в школе.","vi":"Các em ăn trưa tại trường.","fa":"بچه ها ناهار خود را در مدرسه می خورند."},{"de":"Zum Zvieri gibt es heute einen Apfel und ein Brot.","en":"For the afternoon snack today there is an apple and bread.","ru":"На полдник сегодня яблоко и хлеб.","vi":"Hôm nay chúng tôi có một quả táo và bánh mì cho bữa ăn nhẹ.","fa":"امروز یک سیب و نان برای میان وعده داریم."}]},{"word":"dass","en":"that (conjunction)","ru":"что","vi":"đó","fa":"که","examples":[{"de":"Ich glaube, dass er recht hat.","en":"I believe that he is right.","ru":"Я думаю, что он прав.","vi":"Tôi nghĩ anh ấy đúng.","fa":"من فکر می کنم حق با اوست."},{"de":"Sie hofft, dass es morgen nicht regnet.","en":"She hopes that it won't rain tomorrow.","ru":"Она надеется, что завтра не будет дождя.","vi":"Cô hy vọng ngày mai trời không mưa.","fa":"او امیدوار است فردا باران نبارد."}]},{"word":"die Datei","en":"file (computer)","ru":"файл","vi":"tập tin","fa":"فایل","examples":[{"de":"Ich habe die Datei versehentlich gelöscht.","en":"I accidentally deleted the file.","ru":"Я случайно удалил файл.","vi":"Tôi vô tình xóa tập tin.","fa":"من تصادفا فایل رو پاک کردم"},{"de":"Kannst du mir diese Datei per E-Mail schicken?","en":"Can you send me this file by email?","ru":"Можешь отправить мне этот файл по электронной почте?","vi":"Bạn có thể gửi email cho tôi tập tin này?","fa":"میشه این فایل رو برام ایمیل کنید؟"}]},{"word":"die Daten (Plural)","en":"data","ru":"данные","vi":"dữ liệu (số nhiều)","fa":"داده ها (جمع)","examples":[{"de":"Die persönlichen Daten werden vertraulich behandelt.","en":"Personal data is treated confidentially.","ru":"Личные данные обрабатываются конфиденциально.","vi":"Dữ liệu cá nhân sẽ được xử lý bí mật.","fa":"با داده های شخصی محرمانه رفتار خواهد شد."},{"de":"Wir müssen die Daten noch einmal überprüfen.","en":"We need to check the data once more.","ru":"Нам нужно ещё раз проверить данные.","vi":"Chúng ta cần kiểm tra lại dữ liệu.","fa":"باید دوباره داده ها را بررسی کنیم."}]},{"word":"das Datum","en":"date","ru":"дата","vi":"ngày","fa":"تاریخ","examples":[{"de":"Welches Datum haben wir heute?","en":"What's today's date?","ru":"Какое сегодня число?","vi":"Hôm nay là ngày gì?","fa":"امروز چه تاریخی است؟"},{"de":"Bitte geben Sie Ihr Geburtsdatum an.","en":"Please provide your date of birth.","ru":"Пожалуйста, укажите дату рождения.","vi":"Vui lòng nhập ngày sinh của bạn.","fa":"لطفا تاریخ تولد خود را وارد کنید"}]},{"word":"dauern","en":"to last; to take (time)","ru":"длиться","vi":"cuối cùng","fa":"آخرین","examples":[{"de":"Der Film dauert etwa zwei Stunden.","en":"The movie lasts about two hours.","ru":"Фильм длится около двух часов.","vi":"Bộ phim kéo dài khoảng hai giờ.","fa":"فیلم حدود دو ساعت طول می کشد."},{"de":"Wie lange dauert die Fahrt nach München?","en":"How long does the trip to Munich take?","ru":"Сколько длится поездка в Мюнхен?","vi":"Cuộc hành trình đến Munich mất bao lâu?","fa":"سفر به مونیخ چقدر طول می کشد؟"}]},{"word":"dauernd","en":"constantly","ru":"постоянно","vi":"liên tục","fa":"دائما","examples":[{"de":"Er beschwert sich dauernd über das Wetter.","en":"He constantly complains about the weather.","ru":"Он постоянно жалуется на погоду.","vi":"Anh ấy liên tục phàn nàn về thời tiết.","fa":"مدام از آب و هوا شاکی است."},{"de":"Mein Handy klingelt dauernd.","en":"My phone keeps ringing constantly.","ru":"Мой телефон постоянно звонит.","vi":"Điện thoại di động của tôi cứ đổ chuông.","fa":"موبایلم مدام زنگ می زند."}]},{"word":"die Decke","en":"blanket; ceiling","ru":"одеяло; потолок","vi":"trần nhà","fa":"سقف","examples":[{"de":"Nachts liege ich unter einer warmen Decke.","en":"At night I lie under a warm blanket.","ru":"Ночью я лежу под тёплым одеялом.","vi":"Ban đêm tôi nằm trong chăn ấm.","fa":"شب ها زیر یک پتوی گرم دراز می کشم."},{"de":"Die Decke im Wohnzimmer ist sehr hoch.","en":"The ceiling in the living room is very high.","ru":"Потолок в гостиной очень высокий.","vi":"Trần nhà trong phòng khách rất cao.","fa":"سقف اتاق نشیمن بسیار بلند است."}]},{"word":"dekorieren","en":"to decorate","ru":"украшать","vi":"trang trí","fa":"تزئین کنید","examples":[{"de":"Wir dekorieren das Zimmer für die Geburtstagsparty.","en":"We're decorating the room for the birthday party.","ru":"Мы украшаем комнату для дня рождения.","vi":"Chúng tôi trang trí phòng cho bữa tiệc sinh nhật.","fa":"ما اتاق را برای جشن تولد تزئین می کنیم."},{"de":"Zu Weihnachten dekorieren viele Menschen ihre Häuser.","en":"At Christmas many people decorate their houses.","ru":"На Рождество многие люди украшают свои дома.","vi":"Nhiều người trang trí nhà cửa vào dịp Giáng sinh.","fa":"بسیاری از مردم خانه های خود را در کریسمس تزئین می کنند."}]},{"word":"demnach","en":"accordingly; according to this","ru":"согласно этому; таким образом","vi":"tương ứng","fa":"بر این اساس","examples":[{"de":"Laut Plan sind wir demnach schon fast fertig.","en":"According to the plan, we are therefore almost done.","ru":"Согласно плану, мы таким образом почти закончили.","vi":"Theo kế hoạch, chúng tôi gần như đã hoàn thành.","fa":"طبق برنامه تقریباً کارمان تمام شده است."},{"de":"Die Zahlen sind gestiegen; demnach war die Werbung erfolgreich.","en":"The figures have risen; accordingly, the advertising was successful.","ru":"Цифры выросли; следовательно, реклама была успешной.","vi":"Các con số đã tăng lên; do đó quảng cáo đã thành công.","fa":"اعداد افزایش یافته است. بنابراین تبلیغات موفقیت آمیز بود."}]},{"word":"denken","en":"to think","ru":"думать","vi":"nghĩ","fa":"فکر کن","examples":[{"de":"Ich denke oft an meine Kindheit.","en":"I often think about my childhood.","ru":"Я часто думаю о своём детстве.","vi":"Tôi thường nghĩ về tuổi thơ của mình.","fa":"اغلب به دوران کودکی ام فکر می کنم."},{"de":"Was denkst du über diesen Plan?","en":"What do you think about this plan?","ru":"Что ты думаешь об этом плане?","vi":"Bạn nghĩ gì về kế hoạch này?","fa":"نظر شما در مورد این طرح چیست؟"}]},{"word":"das Denkmal","en":"monument","ru":"памятник","vi":"tượng đài","fa":"بنای یادبود","examples":[{"de":"In der Stadtmitte steht ein Denkmal für den berühmten Dichter.","en":"In the city center there's a monument for the famous poet.","ru":"В центре города стоит памятник знаменитому поэту.","vi":"Có một tượng đài cho nhà thơ nổi tiếng ở trung tâm thành phố.","fa":"بنای یادبود شاعر معروف در مرکز شهر وجود دارد."},{"de":"Touristen fotografieren gern das Denkmal.","en":"Tourists like to photograph the monument.","ru":"Туристы любят фотографировать памятник.","vi":"Khách du lịch thích chụp ảnh di tích.","fa":"گردشگران دوست دارند از این بنای تاریخی عکس بگیرند."}]},{"word":"denn","en":"because; for","ru":"так как, ведь","vi":"bởi vì","fa":"چون","examples":[{"de":"Ich kann heute nicht kommen, denn ich bin krank.","en":"I can't come today because I'm sick.","ru":"Я не могу прийти сегодня, так как я болею.","vi":"Hôm nay tôi không thể đến vì tôi bị ốm.","fa":"امروز نمیتونم بیام چون مریضم"},{"de":"Beeil dich, denn der Zug fährt gleich ab.","en":"Hurry up, because the train is about to leave.","ru":"Поспеши, ведь поезд вот-вот отправится.","vi":"Hãy nhanh lên vì tàu sắp khởi hành.","fa":"عجله کنید زیرا قطار در شرف حرکت است."}]},{"word":"dennoch","en":"nevertheless; nonetheless","ru":"тем не менее; всё же","vi":"tuy nhiên","fa":"با این وجود","examples":[{"de":"Es regnete stark; dennoch gingen wir spazieren.","en":"It was raining heavily; nevertheless we went for a walk.","ru":"Шёл сильный дождь; тем не менее мы пошли гулять.","vi":"Trời đang mưa rất to; tuy nhiên chúng tôi đã đi dạo.","fa":"باران شدیدی می بارید؛ با این حال رفتیم پیاده روی"},{"de":"Die Aufgabe war schwer, dennoch hat sie es geschafft.","en":"The task was hard, but she managed it nonetheless.","ru":"Задание было трудным, и всё же она справилась.","vi":"Nhiệm vụ khó khăn nhưng cô đã làm được.","fa":"کار سخت بود، اما او آن را انجام داد."}]},{"word":"derselbe","en":"the same","ru":"тот же самый","vi":"giống nhau","fa":"همان","examples":[{"de":"Wir wohnen im selben Haus.","en":"We live in the same house.","ru":"Мы живём в том же доме.","vi":"Chúng tôi sống trong cùng một ngôi nhà.","fa":"ما در یک خانه زندگی می کنیم."},{"de":"Er trägt jeden Tag denselben Pullover.","en":"He wears the same sweater every day.","ru":"Он каждый день носит один и тот же свитер.","vi":"Anh ấy mặc cùng một chiếc áo len mỗi ngày.","fa":"او هر روز همان ژاکت را می پوشد."}]},{"word":"deshalb","en":"therefore; that's why","ru":"поэтому","vi":"do đó","fa":"بنابراین","examples":[{"de":"Es war kalt, deshalb zog ich eine Jacke an.","en":"It was cold, that's why I put on a jacket.","ru":"Было холодно, поэтому я надел куртку.","vi":"Trời lạnh nên tôi mặc áo khoác vào.","fa":"هوا سرد بود، کت پوشیدم."},{"de":"Sie hat viel gelernt, deshalb hat sie die Prüfung bestanden.","en":"She studied a lot, that's why she passed the exam.","ru":"Она много училась, поэтому сдала экзамен.","vi":"Cô ấy đã học rất nhiều, đó là lý do tại sao cô ấy đã vượt qua kỳ thi.","fa":"او خیلی درس خواند، به همین دلیل در امتحان قبول شد."}]},{"word":"das Dessert","en":"dessert","ru":"десерт","vi":"món tráng miệng","fa":"دسر","examples":[{"de":"Zum Dessert gibt es heute Schokoladenkuchen.","en":"For dessert there's chocolate cake today.","ru":"На десерт сегодня будет шоколадный торт.","vi":"Món tráng miệng hôm nay chúng tôi có bánh sô-cô-la.","fa":"برای دسر امروز کیک شکلاتی داریم."},{"de":"Möchten Sie ein Dessert bestellen?","en":"Would you like to order a dessert?","ru":"Хотите заказать десерт?","vi":"Bạn có muốn gọi món tráng miệng không?","fa":"آیا می خواهید دسر سفارش دهید؟"}]},{"word":"deswegen","en":"therefore, that's why","ru":"поэтому","vi":"đó là lý do tại sao","fa":"به همین دلیل است","examples":[{"de":"Es regnet stark, deswegen bleibe ich heute zu Hause.","en":"It's raining heavily, that's why I'm staying home today.","ru":"Идёт сильный дождь, поэтому я сегодня останусь дома.","vi":"Trời mưa to quá nên hôm nay tôi ở nhà.","fa":"باران شدیدی می بارد، بنابراین من امروز در خانه می مانم."},{"de":"Er hat keine Zeit, deswegen kann er nicht kommen.","en":"He has no time, therefore he can't come.","ru":"У него нет времени, поэтому он не может прийти.","vi":"Anh ấy không có thời gian nên không thể đến được.","fa":"او وقت ندارد، پس نمی تواند بیاید."}]},{"word":"das Detail","en":"detail","ru":"деталь, подробность","vi":"chi tiết","fa":"جزئیات","examples":[{"de":"Er erklärte uns alle Details des Projekts.","en":"He explained all the details of the project to us.","ru":"Он объяснил нам все детали проекта.","vi":"Anh ấy đã giải thích tất cả các chi tiết của dự án cho chúng tôi.","fa":"او تمام جزئیات پروژه را برای ما توضیح داد."},{"de":"Ich möchte die Details später besprechen.","en":"I'd like to discuss the details later.","ru":"Я хотел бы обсудить подробности позже.","vi":"Tôi muốn thảo luận chi tiết sau.","fa":"می خواهم بعداً در مورد جزئیات صحبت کنم."}]},{"word":"deutlich","en":"clear, distinct","ru":"чёткий, ясный","vi":"rõ ràng","fa":"به وضوح","examples":[{"de":"Bitte sprich deutlicher, ich verstehe dich nicht.","en":"Please speak more clearly, I can't understand you.","ru":"Пожалуйста, говори яснее, я тебя не понимаю.","vi":"Bạn nói rõ hơn đi, mình chưa hiểu.","fa":"لطفا واضح تر صحبت کنید، من شما را درک نمی کنم."},{"de":"Die Verbesserung ist deutlich zu erkennen.","en":"The improvement is clearly recognizable.","ru":"Улучшение отчётливо заметно.","vi":"Sự cải thiện có thể nhìn thấy rõ ràng.","fa":"بهبود به وضوح قابل مشاهده است."}]},{"word":"der Dialekt","en":"dialect","ru":"диалект","vi":"phương ngữ","fa":"گویش","examples":[{"de":"In Bayern spricht man einen besonderen Dialekt.","en":"In Bavaria, people speak a special dialect.","ru":"В Баварии говорят на особом диалекте.","vi":"Ở Bavaria họ nói một phương ngữ đặc biệt.","fa":"در باواریا به گویش خاصی صحبت می کنند."},{"de":"Ich verstehe den Schweizer Dialekt nur schwer.","en":"I find it hard to understand the Swiss dialect.","ru":"Мне трудно понимать швейцарский диалект.","vi":"Tôi gặp khó khăn trong việc hiểu phương ngữ Thụy Sĩ.","fa":"من در درک لهجه سوئیسی مشکل دارم."}]},{"word":"der Dialog","en":"dialogue","ru":"диалог","vi":"cuộc đối thoại","fa":"دیالوگ","examples":[{"de":"Die Politiker suchen einen Dialog mit den Bürgern.","en":"The politicians are seeking a dialogue with the citizens.","ru":"Политики ищут диалог с гражданами.","vi":"Các chính trị gia tìm kiếm đối thoại với người dân.","fa":"سیاستمداران به دنبال گفتگو با شهروندان هستند."},{"de":"Im Deutschunterricht üben wir kurze Dialoge.","en":"In German class we practice short dialogues.","ru":"На уроке немецкого мы практикуем короткие диалоги.","vi":"Trong lớp học tiếng Đức, chúng tôi thực hành các đoạn hội thoại ngắn.","fa":"در کلاس آلمانی دیالوگ های کوتاه را تمرین می کنیم."}]},{"word":"die Diät","en":"diet","ru":"диета","vi":"chế độ ăn kiêng","fa":"رژیم غذایی","examples":[{"de":"Meine Mutter macht seit einem Monat eine Diät.","en":"My mother has been on a diet for a month.","ru":"Моя мама уже месяц сидит на диете.","vi":"Mẹ tôi đã ăn kiêng được một tháng.","fa":"مادرم یک ماه است که رژیم گرفته است."},{"de":"Der Arzt hat ihm eine strenge Diät verordnet.","en":"The doctor prescribed him a strict diet.","ru":"Врач прописал ему строгую диету.","vi":"Bác sĩ kê cho anh một chế độ ăn kiêng nghiêm ngặt.","fa":"دکتر برای او رژیم غذایی سختی تجویز کرد."}]},{"word":"dicht","en":"dense; sealed, tight","ru":"плотный, герметичный","vi":"đóng","fa":"بستن","examples":[{"de":"Der Wald hier ist sehr dicht.","en":"The forest here is very dense.","ru":"Лес здесь очень густой.","vi":"Rừng ở đây rất rậm rạp.","fa":"جنگل اینجا بسیار متراکم است."},{"de":"Das Fenster ist nicht dicht, es zieht.","en":"The window isn't sealed properly, there's a draft.","ru":"Окно неплотно закрыто, дует.","vi":"Cửa sổ không kín, đang có gió lùa.","fa":"پنجره تنگ نیست، در حال پیش نویس است."}]},{"word":"dick","en":"thick; fat","ru":"толстый","vi":"dày","fa":"ضخیم","examples":[{"de":"Das Buch ist sehr dick, über 800 Seiten.","en":"The book is very thick, over 800 pages.","ru":"Книга очень толстая, более 800 страниц.","vi":"Sách rất dày, hơn 800 trang.","fa":"کتاب بسیار قطور است، بیش از 800 صفحه."},{"de":"Im Winter ziehe ich eine dicke Jacke an.","en":"In winter I wear a thick jacket.","ru":"Зимой я надеваю толстую куртку.","vi":"Vào mùa đông tôi mặc một chiếc áo khoác dày.","fa":"در زمستان یک ژاکت ضخیم می پوشم."}]},{"word":"die/das Glace/Glacé","en":"ice cream","ru":"мороженое","vi":"kem/kem","fa":"بستنی/بستنی","examples":[{"de":"Im Sommer essen wir gerne ein Glace.","en":"In summer we like to eat ice cream.","ru":"Летом мы любим есть мороженое.","vi":"Vào mùa hè chúng tôi thích ăn kem.","fa":"در تابستان دوست داریم بستنی بخوریم."},{"de":"Welche Sorte Glace möchtest du: Schokolade oder Vanille?","en":"Which flavor of ice cream would you like: chocolate or vanilla?","ru":"Какое мороженое ты хочешь: шоколадное или ванильное?","vi":"Bạn muốn loại kem nào: sô cô la hay vani?","fa":"کدام نوع بستنی می خواهید: شکلاتی یا وانیلی؟"}]},{"word":"der Dieb","en":"thief","ru":"вор","vi":"tên trộm","fa":"دزد","examples":[{"de":"Der Dieb wurde von der Polizei gefasst.","en":"The thief was caught by the police.","ru":"Вора поймала полиция.","vi":"Tên trộm đã bị cảnh sát bắt.","fa":"دزد توسط پلیس دستگیر شد."},{"de":"Ein Dieb hat mein Fahrrad gestohlen.","en":"A thief stole my bicycle.","ru":"Вор украл мой велосипед.","vi":"Một tên trộm đã lấy trộm chiếc xe đạp của tôi.","fa":"دزد دوچرخه ام را دزدید"}]},{"word":"dienen","en":"to serve","ru":"служить","vi":"phục vụ","fa":"خدمت کنید","examples":[{"de":"Dieser Raum dient als Lager.","en":"This room serves as a storage room.","ru":"Это помещение служит складом.","vi":"Căn phòng này được dùng làm kho chứa đồ.","fa":"این اتاق به عنوان انبار عمل می کند."},{"de":"Er hat lange in der Armee gedient.","en":"He served in the army for a long time.","ru":"Он долго служил в армии.","vi":"Ông đã phục vụ trong quân đội một thời gian dài.","fa":"مدت زیادی در ارتش خدمت کرد."}]},{"word":"der Dienst","en":"service; duty","ru":"служба, дежурство","vi":"dịch vụ","fa":"خدمات","examples":[{"de":"Der Kellner ist heute im Dienst.","en":"The waiter is on duty today.","ru":"Официант сегодня на смене.","vi":"Hôm nay người phục vụ đang trực.","fa":"گارسون امروز در حال انجام وظیفه است."},{"de":"Die Firma bietet einen guten Kundendienst.","en":"The company offers good customer service.","ru":"Компания предлагает хорошее обслуживание клиентов.","vi":"Công ty cung cấp dịch vụ khách hàng tốt.","fa":"این شرکت خدمات خوبی به مشتریان ارائه می دهد."}]},{"word":"dies-","en":"this (stem of dieser/diese/dieses)","ru":"этот, эта, это","vi":"cái này-","fa":"این -","examples":[{"de":"Dieser Mann ist mein Nachbar.","en":"This man is my neighbor.","ru":"Этот мужчина — мой сосед.","vi":"Người đàn ông này là hàng xóm của tôi.","fa":"این مرد همسایه من است."},{"de":"Diese Woche habe ich viel zu tun.","en":"This week I have a lot to do.","ru":"На этой неделе у меня много дел.","vi":"Tôi có rất nhiều việc phải làm trong tuần này.","fa":"این هفته کارهای زیادی برای انجام دادن دارم."}]},{"word":"digital","en":"digital","ru":"цифровой","vi":"kỹ thuật số","fa":"دیجیتال","examples":[{"de":"Wir speichern alle Dokumente digital.","en":"We save all documents digitally.","ru":"Мы храним все документы в цифровом виде.","vi":"Chúng tôi lưu trữ tất cả các tài liệu kỹ thuật số.","fa":"ما تمام اسناد را به صورت دیجیتال ذخیره می کنیم."},{"de":"Meine Oma benutzt keine digitalen Geräte.","en":"My grandma doesn't use digital devices.","ru":"Моя бабушка не пользуется цифровыми устройствами.","vi":"Bà tôi không sử dụng thiết bị kỹ thuật số.","fa":"مادربزرگ من از دستگاه های دیجیتال استفاده نمی کند."}]},{"word":"das Ding","en":"thing","ru":"вещь","vi":"điều đó","fa":"چیز","examples":[{"de":"Räum bitte deine Dinge vom Tisch weg.","en":"Please clear your things off the table.","ru":"Убери, пожалуйста, свои вещи со стола.","vi":"Vui lòng dọn đồ đạc của bạn khỏi bàn.","fa":"لطفا وسایل خود را از روی میز پاک کنید."},{"de":"Das ist ein wichtiges Ding für mich.","en":"That's an important thing for me.","ru":"Это важная для меня вещь.","vi":"Đây là một điều quan trọng đối với tôi.","fa":"این برای من یک چیز مهم است."}]},{"word":"das Diplom","en":"diploma","ru":"диплом","vi":"bằng tốt nghiệp","fa":"دیپلم","examples":[{"de":"Sie hat ihr Diplom mit Auszeichnung bekommen.","en":"She received her diploma with honors.","ru":"Она получила диплом с отличием.","vi":"Cô đã nhận được bằng tốt nghiệp danh dự của mình.","fa":"او دیپلم خود را با ممتاز دریافت کرد."},{"de":"Nach dem Studium erhält man ein Diplom.","en":"After studying you receive a diploma.","ru":"После учёбы получают диплом.","vi":"Sau khi học bạn nhận được bằng tốt nghiệp.","fa":"پس از تحصیل دیپلم می گیرید."}]},{"word":"direkt","en":"direct, directly","ru":"прямой, прямо","vi":"trực tiếp","fa":"مستقیما","examples":[{"de":"Der Zug fährt direkt nach Berlin.","en":"The train goes directly to Berlin.","ru":"Поезд идёт прямо в Берлин.","vi":"Tàu đi thẳng đến Berlin.","fa":"قطار مستقیماً به برلین می رود."},{"de":"Frag ihn doch direkt, was er denkt.","en":"Just ask him directly what he thinks.","ru":"Спроси его прямо, что он думает.","vi":"Hãy hỏi trực tiếp anh ấy xem anh ấy nghĩ gì.","fa":"مستقیماً از او بپرسید که چه فکری می کند."}]},{"word":"der Direktor","en":"director, principal","ru":"директор","vi":"giám đốc","fa":"کارگردان","examples":[{"de":"Der Direktor der Schule begrüßte alle Schüler.","en":"The school principal welcomed all the students.","ru":"Директор школы поприветствовал всех учеников.","vi":"Hiệu trưởng nhà trường chào đón tất cả học sinh.","fa":"مدیر مدرسه به همه دانش آموزان خیر مقدم گفت."},{"de":"Sie spricht morgen mit dem Direktor der Firma.","en":"Tomorrow she is speaking with the company director.","ru":"Завтра она будет говорить с директором фирмы.","vi":"Cô ấy sẽ nói chuyện với giám đốc công ty vào ngày mai.","fa":"او فردا با مدیر شرکت صحبت می کند."}]},{"word":"die Diskothek","en":"disco, nightclub","ru":"дискотека","vi":"vũ trường","fa":"دیسکوتک","examples":[{"de":"Am Wochenende gehen wir in die Diskothek.","en":"On the weekend we're going to the disco.","ru":"На выходных мы идём на дискотеку.","vi":"Cuối tuần chúng tôi đi vũ trường.","fa":"آخر هفته به دیسکوتک می رویم."},{"de":"Die Diskothek hat erst um 22 Uhr geöffnet.","en":"The disco only opens at 10 p.m.","ru":"Дискотека открывается только в 22:00.","vi":"Sàn nhảy không mở cửa cho đến 10 giờ tối.","fa":"دیسکو تا ساعت 10 شب باز نمی شود."}]},{"word":"diskutieren","en":"to discuss","ru":"обсуждать","vi":"thảo luận","fa":"بحث کنید","examples":[{"de":"Wir diskutieren gerade über das neue Projekt.","en":"We are currently discussing the new project.","ru":"Мы сейчас обсуждаем новый проект.","vi":"Chúng tôi hiện đang thảo luận về dự án mới.","fa":"در حال حاضر در حال بحث در مورد پروژه جدید هستیم."},{"de":"In der Klasse diskutieren die Schüler über Politik.","en":"In class the students discuss politics.","ru":"В классе ученики обсуждают политику.","vi":"Trong lớp, học sinh thảo luận về chính trị.","fa":"در کلاس، دانش آموزان درباره سیاست بحث می کنند."}]},{"word":"die Distanz","en":"distance","ru":"расстояние, дистанция","vi":"khoảng cách","fa":"فاصله","examples":[{"de":"Zwischen den beiden Städten liegt eine große Distanz.","en":"There is a great distance between the two cities.","ru":"Между этими двумя городами большое расстояние.","vi":"Có một khoảng cách lớn giữa hai thành phố.","fa":"بین این دو شهر فاصله زیادی وجود دارد."},{"de":"Er hält immer eine gewisse Distanz zu Fremden.","en":"He always keeps a certain distance from strangers.","ru":"Он всегда держит дистанцию с незнакомыми людьми.","vi":"Anh ấy luôn giữ một khoảng cách nhất định với người lạ.","fa":"او همیشه فاصله خاصی را با غریبه ها حفظ می کند."}]},{"word":"doch","en":"still, after all; (contradicting a negative) yes it is/does","ru":"всё же, ведь; да нет же (в ответ на отрицание)","vi":"vâng","fa":"بله","examples":[{"de":"Kommst du nicht mit? – Doch, ich komme mit!","en":"Aren't you coming along? – Yes, I am!","ru":"Ты не пойдёшь с нами? — Да нет, пойду!","vi":"Bạn không đi cùng tôi à? - Ừ, tôi đi cùng cậu!","fa":"با من نمیای؟ - بله، من با شما می آیم!"},{"de":"Er ist doch noch ein Kind, sei nicht so streng.","en":"He's still just a child, don't be so strict.","ru":"Он же ещё ребёнок, не будь таким строгим.","vi":"Nó vẫn còn là một đứa trẻ, đừng khắt khe như vậy.","fa":"او هنوز بچه است، اینقدر سخت گیر نباش."}]},{"word":"der Doktor","en":"doctor","ru":"доктор, врач","vi":"bác sĩ","fa":"دکتر","examples":[{"de":"Sie hat in Chemie promoviert und ist jetzt Doktor.","en":"She earned her doctorate in chemistry and is now a doctor.","ru":"Она защитила докторскую по химии и теперь доктор наук.","vi":"Cô đã nhận bằng Tiến sĩ hóa học và hiện là bác sĩ.","fa":"او دکترای خود را در رشته شیمی دریافت کرد و اکنون دکتر است."},{"de":"Ich muss morgen zum Doktor gehen.","en":"I have to go to the doctor tomorrow.","ru":"Мне завтра нужно пойти к врачу.","vi":"Ngày mai tôi phải đi khám bác sĩ.","fa":"فردا باید برم دکتر"}]},{"word":"das Dokument","en":"document","ru":"документ","vi":"tài liệu","fa":"سند","examples":[{"de":"Bitte bringen Sie alle wichtigen Dokumente mit.","en":"Please bring all the important documents with you.","ru":"Пожалуйста, принесите все важные документы.","vi":"Vui lòng mang theo tất cả các tài liệu quan trọng với bạn.","fa":"لطفا تمام مدارک مهم را همراه داشته باشید."},{"de":"Ich habe das Dokument als PDF gespeichert.","en":"I saved the document as a PDF.","ru":"Я сохранил документ в формате PDF.","vi":"Tôi đã lưu tài liệu dưới dạng PDF.","fa":"من سند را به صورت PDF ذخیره کردم."}]},{"word":"donnern","en":"to thunder","ru":"греметь (о громе)","vi":"sấm sét","fa":"رعد و برق","examples":[{"de":"Draußen blitzt und donnert es sehr laut.","en":"Outside there's lightning and it's thundering very loudly.","ru":"На улице сверкает молния и громко гремит гром.","vi":"Bên ngoài có sấm sét và sấm sét rất lớn.","fa":"رعد و برق و رعد و برق بسیار شدید بیرون می آید."},{"de":"Es donnerte die ganze Nacht.","en":"It thundered all night.","ru":"Всю ночь гремел гром.","vi":"Nó sấm sét suốt đêm dài.","fa":"تمام شب رعد و برق می زد."}]},{"word":"doppelt","en":"double","ru":"двойной","vi":"gấp đôi","fa":"دو برابر کردن","examples":[{"de":"Er verdient doppelt so viel wie ich.","en":"He earns twice as much as I do.","ru":"Он зарабатывает вдвое больше меня.","vi":"Anh ấy kiếm được gấp đôi tôi.","fa":"او دو برابر من درآمد دارد."},{"de":"Bitte schicken Sie mir das Formular in doppelter Ausfertigung.","en":"Please send me the form in duplicate.","ru":"Пожалуйста, пришлите мне бланк в двух экземплярах.","vi":"Xin vui lòng gửi cho tôi mẫu đơn trùng lặp.","fa":"لطفا فرم را در دو نسخه برای من ارسال کنید."}]},{"word":"das Dorf","en":"village","ru":"деревня","vi":"ngôi làng","fa":"روستا","examples":[{"de":"Meine Großeltern wohnen in einem kleinen Dorf.","en":"My grandparents live in a small village.","ru":"Мои бабушка и дедушка живут в маленькой деревне.","vi":"Ông bà tôi sống ở một ngôi làng nhỏ.","fa":"پدربزرگ و مادربزرگ من در یک روستای کوچک زندگی می کنند."},{"de":"Das Dorf hat nur 200 Einwohner.","en":"The village has only 200 inhabitants.","ru":"В деревне всего 200 жителей.","vi":"Ngôi làng chỉ có 200 cư dân.","fa":"این روستا تنها 200 نفر سکنه دارد."}]},{"word":"dort","en":"there","ru":"там","vi":"ở đó","fa":"وجود دارد","examples":[{"de":"Siehst du das Haus? Dort wohne ich.","en":"Do you see that house? I live there.","ru":"Видишь тот дом? Там я живу.","vi":"Bạn có thấy ngôi nhà không? Tôi sống ở đó.","fa":"خانه را می بینی؟ من آنجا زندگی می کنم."},{"de":"Wir fahren nach Italien und bleiben dort zwei Wochen.","en":"We're going to Italy and staying there for two weeks.","ru":"Мы едем в Италию и останемся там на две недели.","vi":"Chúng tôi sẽ đến Ý và ở đó hai tuần.","fa":"ما به ایتالیا می رویم و دو هفته آنجا می مانیم."}]},{"word":"die Dose","en":"can, tin","ru":"банка, консервная банка","vi":"cái lon","fa":"قوطی","examples":[{"de":"Kannst du mir bitte eine Dose Tomaten geben?","en":"Can you give me a can of tomatoes, please?","ru":"Можешь дать мне банку помидоров, пожалуйста?","vi":"Bạn có thể vui lòng cho tôi một lon cà chua được không?","fa":"لطفا یک قوطی گوجه فرنگی به من بدهید؟"},{"de":"Er trinkt die Cola direkt aus der Dose.","en":"He drinks the cola straight from the can.","ru":"Он пьёт колу прямо из банки.","vi":"Anh ta uống Coke trực tiếp từ lon.","fa":"او کوکاکولا را مستقیماً از قوطی می نوشد."}]},{"word":"draußen","en":"outside","ru":"снаружи, на улице","vi":"bên ngoài","fa":"خارج","examples":[{"de":"Es ist kalt, zieh dir draußen eine Jacke an.","en":"It's cold, put on a jacket outside.","ru":"На улице холодно, надень куртку.","vi":"Trời lạnh, mặc áo khoác ra ngoài.","fa":"هوا سرد است، بیرون یک ژاکت بپوش."},{"de":"Die Kinder spielen draußen im Garten.","en":"The children are playing outside in the garden.","ru":"Дети играют на улице в саду.","vi":"Bọn trẻ đang chơi ngoài vườn.","fa":"بچه ها بیرون در باغ بازی می کنند."}]},{"word":"der Dreck","en":"dirt","ru":"грязь","vi":"bụi bẩn","fa":"خاک","examples":[{"de":"Nach der Wanderung war ich voller Dreck.","en":"After the hike I was covered in dirt.","ru":"После похода я был весь в грязи.","vi":"Sau khi đi bộ đường dài, người tôi đầy bụi bẩn.","fa":"بعد از پیاده روی من در خاک پوشیده شده بودم."},{"de":"Mach bitte den Dreck von der Straße weg.","en":"Please clean up the dirt from the street.","ru":"Пожалуйста, убери грязь с улицы.","vi":"Hãy dọn sạch bụi bẩn trên đường phố.","fa":"لطفا خاک را از خیابان پاک کنید."}]},{"word":"drehen","en":"to turn, to rotate; to film/shoot","ru":"вертеть, поворачивать; снимать (фильм)","vi":"xoay","fa":"چرخاندن","examples":[{"de":"Er dreht den Schlüssel im Schloss.","en":"He turns the key in the lock.","ru":"Он поворачивает ключ в замке.","vi":"Anh vặn chìa khóa vào ổ.","fa":"کلید را در قفل می چرخاند."},{"de":"Der Regisseur dreht einen neuen Film.","en":"The director is shooting a new film.","ru":"Режиссёр снимает новый фильм.","vi":"Đạo diễn đang làm một bộ phim mới.","fa":"این کارگردان در حال ساخت فیلم جدیدی است."}]},{"word":"drin","en":"inside, in it","ru":"внутри, там внутри","vi":"bên trong","fa":"داخل","examples":[{"de":"Ist noch Milch drin? – Nein, die Flasche ist leer.","en":"Is there still milk in it? – No, the bottle is empty.","ru":"Там ещё есть молоко? — Нет, бутылка пустая.","vi":"Có còn sữa trong đó không? – Không, chai rỗng rồi.","fa":"آیا هنوز شیر در آن وجود دارد؟ - نه، بطری خالی است."},{"de":"Bleib doch drin, draußen regnet es.","en":"Stay inside, it's raining outside.","ru":"Оставайся внутри, на улице дождь.","vi":"Ở trong nhà đi, ngoài trời đang mưa.","fa":"داخل بمون بیرون بیرون بارون میاد"}]},{"word":"dringend","en":"urgent, urgently","ru":"срочный, срочно","vi":"khẩn cấp","fa":"فوری","examples":[{"de":"Ich brauche dringend deine Hilfe.","en":"I urgently need your help.","ru":"Мне срочно нужна твоя помощь.","vi":"Tôi rất cần sự giúp đỡ của bạn.","fa":"من به کمک شما فوری نیاز دارم."},{"de":"Das ist eine dringende Angelegenheit.","en":"This is an urgent matter.","ru":"Это срочное дело.","vi":"Đây là một vấn đề khẩn cấp.","fa":"این یک موضوع فوری است."}]},{"word":"die Droge","en":"drug","ru":"наркотик","vi":"thuốc","fa":"دارو","examples":[{"de":"Drogen sind in Deutschland zum größten Teil verboten.","en":"Drugs are mostly illegal in Germany.","ru":"Наркотики в Германии в основном запрещены.","vi":"Thuốc hầu hết bị cấm ở Đức.","fa":"مواد مخدر بیشتر در آلمان ممنوع است."},{"de":"Er hat nie im Leben Drogen genommen.","en":"He has never taken drugs in his life.","ru":"Он никогда в жизни не принимал наркотики.","vi":"Anh ấy chưa bao giờ sử dụng ma túy trong đời.","fa":"او هرگز در زندگی خود مواد مخدر مصرف نکرده است."}]},{"word":"die Drogerie","en":"drugstore","ru":"магазин дрогери (хозяйственно-косметический)","vi":"hiệu thuốc","fa":"داروخانه","examples":[{"de":"Ich kaufe Shampoo und Zahnpasta in der Drogerie.","en":"I buy shampoo and toothpaste at the drugstore.","ru":"Я покупаю шампунь и зубную пасту в дрогери.","vi":"Tôi mua dầu gội và kem đánh răng ở hiệu thuốc.","fa":"من شامپو و خمیر دندان را از داروخانه می خرم."},{"de":"Die Drogerie um die Ecke hat lange geöffnet.","en":"The drugstore around the corner is open late.","ru":"Магазин дрогери за углом работает допоздна.","vi":"Hiệu thuốc gần góc phố mở cửa muộn.","fa":"داروخانه این گوشه تا دیروقت باز است."}]},{"word":"drüben","en":"over there","ru":"там, на той стороне","vi":"đằng kia","fa":"اونجا","examples":[{"de":"Meine Tante wohnt drüben, auf der anderen Straßenseite.","en":"My aunt lives over there, on the other side of the street.","ru":"Моя тётя живёт там, на другой стороне улицы.","vi":"Dì tôi sống ở đằng kia, bên kia đường.","fa":"عمه من آنجا زندگی می کند، آن طرف خیابان."},{"de":"Früher lebten meine Großeltern drüben in Ostdeutschland.","en":"In the past my grandparents lived over there in East Germany.","ru":"Раньше мои бабушка и дедушка жили там, в Восточной Германии.","vi":"Ông bà tôi từng sống ở Đông Đức.","fa":"پدربزرگ و مادربزرگ من قبلاً در آلمان شرقی زندگی می کردند."}]},{"word":"drucken","en":"to print","ru":"печатать (на принтере/в типографии)","vi":"in","fa":"چاپ کنید","examples":[{"de":"Kannst du mir das Dokument drucken?","en":"Can you print the document for me?","ru":"Можешь распечатать мне этот документ?","vi":"Bạn có thể in tài liệu cho tôi được không?","fa":"آیا می توانید سند را برای من چاپ کنید؟"},{"de":"Die Zeitung wird jeden Morgen neu gedruckt.","en":"The newspaper is printed fresh every morning.","ru":"Газета печатается заново каждое утро.","vi":"Báo được in lại vào mỗi buổi sáng.","fa":"روزنامه هر روز صبح تجدید چاپ می شود."}]},{"word":"drücken","en":"to press, to push","ru":"нажимать, давить","vi":"nhấn","fa":"را فشار دهید","examples":[{"de":"Bitte drücken Sie den grünen Knopf.","en":"Please press the green button.","ru":"Пожалуйста, нажмите зелёную кнопку.","vi":"Vui lòng nhấn nút màu xanh lá cây.","fa":"لطفا دکمه سبز رنگ را فشار دهید."},{"de":"Die neuen Schuhe drücken mich am Fuß.","en":"The new shoes are pinching my foot.","ru":"Новые туфли жмут мне ногу.","vi":"Đôi giày mới đè nặng lên đôi chân tôi.","fa":"کفش های جدید روی پاهایم سنگینی می کنند."}]},{"word":"dumm","en":"stupid","ru":"глупый","vi":"ngu ngốc","fa":"احمق","examples":[{"de":"Das war eine ziemlich dumme Idee.","en":"That was a pretty stupid idea.","ru":"Это была довольно глупая идея.","vi":"Đó là một ý tưởng khá ngu ngốc.","fa":"این یک ایده کاملا احمقانه بود."},{"de":"Er fühlte sich dumm, weil er die Antwort nicht wusste.","en":"He felt stupid because he didn't know the answer.","ru":"Он чувствовал себя глупо, потому что не знал ответа.","vi":"Anh cảm thấy thật ngu ngốc vì không biết câu trả lời.","fa":"او احساس حماقت می کرد زیرا جواب را نمی دانست."}]},{"word":"dunkel","en":"dark","ru":"тёмный","vi":"tối","fa":"تاریک","examples":[{"de":"Im Winter wird es früh dunkel.","en":"In winter it gets dark early.","ru":"Зимой рано темнеет.","vi":"Vào mùa đông trời tối sớm.","fa":"در زمستان هوا زود تاریک می شود."},{"de":"Sie trägt gern dunkle Kleidung.","en":"She likes to wear dark clothes.","ru":"Она любит носить тёмную одежду.","vi":"Cô ấy thích mặc quần áo tối màu.","fa":"او دوست دارد لباس های تیره بپوشد."}]},{"word":"dünn","en":"thin","ru":"тонкий, худой","vi":"gầy","fa":"نازک","examples":[{"de":"Das Papier ist sehr dünn.","en":"The paper is very thin.","ru":"Бумага очень тонкая.","vi":"Giấy rất mỏng.","fa":"کاغذ بسیار نازک است."},{"de":"Nach der Krankheit war er ziemlich dünn.","en":"After the illness he was quite thin.","ru":"После болезни он был довольно худым.","vi":"Sau cơn bệnh anh gầy đi rất nhiều.","fa":"بعد از بیماری او کاملاً لاغر شده بود."}]},{"word":"durch","en":"through","ru":"через, сквозь","vi":"thông qua","fa":"از طریق","examples":[{"de":"Wir gehen durch den Park nach Hause.","en":"We're walking through the park to get home.","ru":"Мы идём домой через парк.","vi":"Chúng tôi đi bộ về nhà qua công viên.","fa":"از پارک به خانه می رویم."},{"de":"Das Licht scheint durch das Fenster.","en":"The light shines through the window.","ru":"Свет проникает через окно.","vi":"Ánh sáng chiếu qua cửa sổ.","fa":"نور از پنجره می تابد."}]},{"word":"durcheinander","en":"mixed up, confused","ru":"в беспорядке, растерянный","vi":"lộn xộn","fa":"به هم ریخته","examples":[{"de":"Mein Zimmer ist total durcheinander.","en":"My room is a total mess.","ru":"У меня в комнате полный беспорядок.","vi":"Phòng của tôi hoàn toàn bừa bộn.","fa":"اتاق من کلا به هم ریخته است."},{"de":"Nach der Nachricht war sie ganz durcheinander.","en":"After the news she was completely confused and upset.","ru":"После этой новости она была совершенно растеряна.","vi":"Sau khi nghe tin, cô hoàn toàn bối rối.","fa":"بعد از شنیدن این خبر کاملا گیج شد."}]},{"word":"die Durchsage","en":"announcement","ru":"объявление (по громкой связи)","vi":"thông báo","fa":"اعلامیه","examples":[{"de":"Am Bahnhof hörten wir eine wichtige Durchsage.","en":"At the station we heard an important announcement.","ru":"На вокзале мы услышали важное объявление.","vi":"Tại ga xe lửa, chúng tôi nghe được một thông báo quan trọng.","fa":"در ایستگاه قطار یک اطلاعیه مهم شنیدیم."},{"de":"Die Durchsage im Flugzeug war leider sehr leise.","en":"The announcement on the plane was unfortunately very quiet.","ru":"Объявление в самолёте было, к сожалению, очень тихим.","vi":"Thật không may, thông báo trên máy bay rất im lặng.","fa":"متاسفانه اعلامیه در هواپیما بسیار بی سر و صدا بود."}]},{"word":"der Durchschnitt","en":"average","ru":"среднее значение","vi":"mức trung bình","fa":"میانگین","examples":[{"de":"Im Durchschnitt arbeite ich acht Stunden am Tag.","en":"On average, I work eight hours a day.","ru":"В среднем я работаю восемь часов в день.","vi":"Trung bình tôi làm việc tám giờ một ngày.","fa":"به طور متوسط روزی هشت ساعت کار می کنم."},{"de":"Ihre Note liegt über dem Durchschnitt der Klasse.","en":"Her grade is above the class average.","ru":"Её оценка выше среднего по классу.","vi":"Điểm của bạn cao hơn mức trung bình của lớp.","fa":"نمره شما بالاتر از میانگین کلاس است."}]},{"word":"durchsetzen","en":"to assert; to push through","ru":"добиваться; отстаивать","vi":"thi hành","fa":"اجرا کنند","examples":[{"de":"Sie konnte ihre Idee im Team durchsetzen.","en":"She managed to push her idea through in the team.","ru":"Ей удалось отстоять свою идею в команде.","vi":"Cô ấy đã có thể thực hiện ý tưởng của mình trong nhóm.","fa":"او توانست ایده خود را در تیم پیاده کند."},{"de":"Gegen die starke Konkurrenz konnte er sich durchsetzen.","en":"He managed to prevail against the strong competition.","ru":"Он смог одержать верх над сильной конкуренцией.","vi":"Anh ấy đã có thể giành chiến thắng trước sự cạnh tranh mạnh mẽ.","fa":"او توانست در برابر رقابت قدرتمند پیروز شود."}]},{"word":"dürfen","en":"to be allowed to, may","ru":"мочь, иметь разрешение","vi":"được phép","fa":"مجاز است","examples":[{"de":"Hier darf man nicht rauchen.","en":"Smoking is not allowed here.","ru":"Здесь нельзя курить.","vi":"Bạn không được phép hút thuốc ở đây.","fa":"اینجا اجازه سیگار کشیدن ندارید."},{"de":"Darf ich das Fenster öffnen?","en":"May I open the window?","ru":"Можно я открою окно?","vi":"Tôi có thể mở cửa sổ được không?","fa":"آیا می توانم پنجره را باز کنم؟"}]},{"word":"der Durst","en":"thirst","ru":"жажда","vi":"cơn khát","fa":"تشنگی","examples":[{"de":"Nach dem Sport hatte ich großen Durst.","en":"After the workout I was very thirsty.","ru":"После тренировки я сильно хотел пить.","vi":"Sau khi tập thể dục tôi rất khát nước.","fa":"بعد از ورزش خیلی تشنه بودم."},{"de":"Hast du Durst? Ich hole dir ein Glas Wasser.","en":"Are you thirsty? I'll get you a glass of water.","ru":"Ты хочешь пить? Я принесу тебе стакан воды.","vi":"Bạn có khát không? Tôi sẽ lấy cho bạn một cốc nước.","fa":"تشنه هستی؟ برات یه لیوان آب میارم"}]},{"word":"duzen","en":"to address informally (with 'du')","ru":"обращаться на «ты»","vi":"tên đầu tiên","fa":"نام کوچک","examples":[{"de":"In dieser Firma duzen sich alle Kollegen.","en":"In this company all colleagues use the informal 'du' with each other.","ru":"В этой компании все коллеги обращаются друг к другу на «ты».","vi":"Ở công ty này, tất cả các đồng nghiệp đều gọi tên nhau.","fa":"در این شرکت همه همکاران با شرایط اسمی هستند."},{"de":"Darf ich Sie duzen, oder bevorzugen Sie 'Sie'?","en":"May I use 'du' with you, or do you prefer 'Sie'?","ru":"Можно я буду обращаться к вам на «ты», или вы предпочитаете «вы»?","vi":"Tôi có thể sử dụng tên của bạn được không, hay bạn thích dùng 'bạn' hơn?","fa":"آیا می توانم از نام کوچک شما استفاده کنم یا \"شما\" را ترجیح می دهید؟"}]},{"word":"die e-card","en":"e-card (electronic health insurance card, Austria)","ru":"электронная карта (напр. медицинская карта в Австрии)","vi":"thẻ điện tử","fa":"کارت الکترونیکی","examples":[{"de":"Vergiss deine e-card nicht, wenn du zum Arzt gehst.","en":"Don't forget your e-card when you go to the doctor.","ru":"Не забудь свою электронную карту, когда пойдёшь к врачу.","vi":"Đừng quên thẻ điện tử của bạn khi bạn đi khám bác sĩ.","fa":"هنگام مراجعه به پزشک کارت الکترونیکی خود را فراموش نکنید."},{"de":"Ohne e-card musst du die Behandlung selbst bezahlen.","en":"Without the e-card you have to pay for the treatment yourself.","ru":"Без электронной карты тебе придётся самому платить за лечение.","vi":"Nếu không có thẻ điện tử, bạn phải tự chi trả chi phí điều trị.","fa":"بدون کارت الکترونیکی باید هزینه درمان را خودتان بپردازید."}]},{"word":"eben","en":"just (now); exactly, precisely","ru":"только что; именно","vi":"chỉ","fa":"فقط","examples":[{"de":"Ich habe eben mit ihr telefoniert.","en":"I just talked to her on the phone.","ru":"Я только что разговаривал с ней по телефону.","vi":"Tôi vừa nói chuyện với cô ấy qua điện thoại.","fa":"من فقط تلفنی با او صحبت کردم."},{"de":"Das ist eben das Problem.","en":"That's exactly the problem.","ru":"В этом-то и проблема.","vi":"Đó mới là vấn đề.","fa":"فقط مشکل همینه"}]},{"word":"ebenfalls","en":"likewise, also","ru":"также, тоже","vi":"cũng","fa":"همچنین","examples":[{"de":"Ich wünsche dir ebenfalls einen schönen Urlaub.","en":"I wish you a nice vacation as well.","ru":"Желаю и тебе хорошего отпуска.","vi":"Tôi cũng chúc bạn có một kỳ nghỉ vui vẻ.","fa":"من هم برای شما تعطیلات خوبی آرزو می کنم."},{"de":"Er kommt aus Spanien, seine Frau ebenfalls.","en":"He is from Spain, and his wife is too.","ru":"Он из Испании, его жена тоже.","vi":"Anh ấy đến từ Tây Ban Nha, vợ anh ấy cũng vậy.","fa":"او و همسرش از اسپانیا آمده است."}]},{"word":"ebenso","en":"just as, likewise","ru":"так же, точно так же","vi":"tương tự như vậy","fa":"به همین ترتیب","examples":[{"de":"Sie ist ebenso talentiert wie ihr Bruder.","en":"She is just as talented as her brother.","ru":"Она так же талантлива, как её брат.","vi":"Cô ấy cũng tài năng như anh trai mình.","fa":"او به اندازه برادرش با استعداد است."},{"de":"Ich finde den Film ebenso langweilig wie du.","en":"I find the film just as boring as you do.","ru":"Я нахожу этот фильм таким же скучным, как и ты.","vi":"Tôi thấy bộ phim cũng nhàm chán như bạn vậy.","fa":"به نظر من فیلم هم مثل شما خسته کننده است."}]},{"word":"die ec-Karte/EC-Karte","en":"debit card","ru":"дебетовая карта","vi":"thẻ EC/thẻ EC","fa":"کارت EC/کارت EC","examples":[{"de":"Ich bezahle meistens mit meiner EC-Karte.","en":"I usually pay with my debit card.","ru":"Обычно я плачу дебетовой картой.","vi":"Tôi thường thanh toán bằng thẻ ghi nợ của mình.","fa":"من معمولا با کارت بانکی پرداخت می کنم."},{"de":"Kann ich hier mit EC-Karte bezahlen?","en":"Can I pay by debit card here?","ru":"Здесь можно расплатиться дебетовой картой?","vi":"Tôi có thể thanh toán bằng thẻ EC ở đây không?","fa":"آیا می توانم با کارت EC اینجا پرداخت کنم؟"}]},{"word":"echt","en":"real, genuine; really","ru":"настоящий; действительно, правда","vi":"thực","fa":"واقعی","examples":[{"de":"Ist das ein echter Diamant?","en":"Is that a real diamond?","ru":"Это настоящий бриллиант?","vi":"Đó có phải là kim cương thật không?","fa":"آیا این یک الماس واقعی است؟"},{"de":"Das war echt ein toller Abend.","en":"That was really a great evening.","ru":"Это был действительно классный вечер.","vi":"Đó thực sự là một buổi tối tuyệt vời.","fa":"آن شب واقعاً عالی بود."}]},{"word":"das Eck","en":"corner","ru":"угол","vi":"góc","fa":"گوشه","examples":[{"de":"Der Kiosk steht am Eck der Straße.","en":"The kiosk is at the corner of the street.","ru":"Киоск стоит на углу улицы.","vi":"Ki-ốt nằm ở góc phố.","fa":"کیوسک نبش خیابان است."},{"de":"Wir treffen uns am Eck vor der Bäckerei.","en":"We're meeting at the corner in front of the bakery.","ru":"Мы встретимся на углу перед булочной.","vi":"Chúng tôi gặp nhau ở góc trước tiệm bánh.","fa":"در گوشه روبروی نانوایی همدیگر را می بینیم."}]},{"word":"die Ecke","en":"corner","ru":"угол","vi":"góc","fa":"گوشه","examples":[{"de":"Das Café ist gleich um die Ecke.","en":"The café is just around the corner.","ru":"Кафе прямо за углом.","vi":"Quán cà phê ở ngay góc đường.","fa":"کافه همین گوشه است."},{"de":"Stell den Tisch in die Ecke des Zimmers.","en":"Put the table in the corner of the room.","ru":"Поставь стол в угол комнаты.","vi":"Đặt cái bàn ở góc phòng.","fa":"میز را در گوشه اتاق قرار دهید."}]},{"word":"egal","en":"indifferent, doesn't matter","ru":"всё равно, безразлично","vi":"không vấn đề gì","fa":"مهم نیست","examples":[{"de":"Es ist mir egal, welchen Film wir sehen.","en":"It doesn't matter to me which film we watch.","ru":"Мне всё равно, какой фильм мы посмотрим.","vi":"Tôi không quan tâm chúng ta xem phim gì.","fa":"برایم مهم نیست چه فیلمی می بینیم."},{"de":"Egal was passiert, ich bleibe bei dir.","en":"No matter what happens, I'll stay with you.","ru":"Что бы ни случилось, я останусь с тобой.","vi":"Dù có chuyện gì xảy ra đi chăng nữa, tôi cũng sẽ ở bên em.","fa":"مهم نیست چه اتفاقی می افتد، من با شما می مانم."}]},{"word":"die Ehe","en":"marriage","ru":"брак","vi":"cuộc hôn nhân","fa":"ازدواج","examples":[{"de":"Sie führen seit zwanzig Jahren eine glückliche Ehe.","en":"They have had a happy marriage for twenty years.","ru":"Они уже двадцать лет живут в счастливом браке.","vi":"Họ đã có một cuộc hôn nhân hạnh phúc suốt hai mươi năm.","fa":"بیست سال است که ازدواج شادی داشته اند."},{"de":"Meine Eltern haben ihre Ehe vor 25 Jahren geschlossen.","en":"My parents got married 25 years ago.","ru":"Мои родители заключили брак 25 лет назад.","vi":"Bố mẹ tôi kết hôn cách đây 25 năm.","fa":"پدر و مادرم 25 سال پیش ازدواج کردند."}]},{"word":"eher","en":"rather, sooner","ru":"скорее, раньше","vi":"đúng hơn","fa":"بلکه","examples":[{"de":"Ich bin eher ein ruhiger Mensch.","en":"I am rather a quiet person.","ru":"Я скорее спокойный человек.","vi":"Tôi là người trầm lặng hơn.","fa":"من بیشتر آدم ساکتی هستم."},{"de":"Komm doch eher, dann haben wir mehr Zeit.","en":"Come sooner, then we'll have more time.","ru":"Приходи пораньше, тогда у нас будет больше времени.","vi":"Hãy đến sớm hơn, chúng ta sẽ có nhiều thời gian hơn.","fa":"زودتر بیا، پس وقت بیشتری خواهیم داشت."}]},{"word":"das Ehrenamt","en":"voluntary work; honorary post","ru":"волонтёрская деятельность; общественная должность","vi":"công việc tình nguyện","fa":"کار داوطلبانه","examples":[{"de":"Sie engagiert sich in ihrer Freizeit im Ehrenamt.","en":"In her free time she is involved in voluntary work.","ru":"В свободное время она занимается волонтёрством.","vi":"Cô ấy làm công việc tình nguyện vào thời gian rảnh rỗi.","fa":"او در اوقات فراغت خود کارهای داوطلبانه انجام می دهد."},{"de":"Ein Ehrenamt wird nicht bezahlt.","en":"Voluntary work is unpaid.","ru":"Волонтёрская деятельность не оплачивается.","vi":"Hoạt động tình nguyện không được trả lương.","fa":"داوطلبانه پرداخت نمی شود."}]},{"word":"ehrgeizig","en":"ambitious","ru":"честолюбивый; амбициозный","vi":"đầy tham vọng","fa":"جاه طلب","examples":[{"de":"Sie ist sehr ehrgeizig und will immer die Beste sein.","en":"She is very ambitious and always wants to be the best.","ru":"Она очень честолюбива и всегда хочет быть лучшей.","vi":"Cô ấy rất tham vọng và luôn muốn trở thành người giỏi nhất.","fa":"او بسیار جاه طلب است و همیشه می خواهد بهترین باشد."},{"de":"Das sind ziemlich ehrgeizige Ziele.","en":"Those are quite ambitious goals.","ru":"Это довольно амбициозные цели.","vi":"Đây là những mục tiêu khá tham vọng.","fa":"اینها اهداف بسیار بلندپروازانه ای هستند."}]},{"word":"ehrlich","en":"honest","ru":"честный","vi":"thành thật mà nói","fa":"صادقانه","examples":[{"de":"Sei ehrlich zu mir und sag die Wahrheit.","en":"Be honest with me and tell the truth.","ru":"Будь со мной честен и скажи правду.","vi":"Hãy thành thật với tôi và nói sự thật.","fa":"با من صادق باش و حقیقت را بگو."},{"de":"Er ist ein sehr ehrlicher Mensch.","en":"He is a very honest person.","ru":"Он очень честный человек.","vi":"Anh ấy là một người rất trung thực.","fa":"او فردی بسیار صادق است."}]},{"word":"das Ei","en":"egg","ru":"яйцо","vi":"quả trứng","fa":"تخم مرغ","examples":[{"de":"Zum Frühstück esse ich gern ein gekochtes Ei.","en":"For breakfast I like to eat a boiled egg.","ru":"На завтрак я люблю есть варёное яйцо.","vi":"Tôi thích ăn trứng luộc vào bữa sáng.","fa":"من دوست دارم صبحانه یک تخم مرغ آب پز بخورم."},{"de":"Für den Kuchen brauchst du drei Eier.","en":"For the cake you need three eggs.","ru":"Для торта тебе нужно три яйца.","vi":"Bạn cần ba quả trứng cho chiếc bánh.","fa":"برای کیک به سه عدد تخم مرغ نیاز دارید."}]},{"word":"die Eifersucht","en":"jealousy","ru":"ревность","vi":"sự ghen tị","fa":"حسادت","examples":[{"de":"Seine Eifersucht belastete die Beziehung.","en":"His jealousy put a strain on the relationship.","ru":"Его ревность омрачала отношения.","vi":"Sự ghen tuông của anh ấy khiến mối quan hệ trở nên căng thẳng.","fa":"حسادت او روابط را تحت فشار قرار داد."},{"de":"Aus Eifersucht sagte sie kein Wort.","en":"Out of jealousy she didn't say a word.","ru":"Из ревности она не сказала ни слова.","vi":"Cô không nói một lời vì ghen tị.","fa":"از روی حسادت حرفی نزد."}]},{"word":"eigen-","en":"own; (as prefix) self-, characteristic","ru":"свой, собственный; (как приставка) само-, особый","vi":"sở hữu","fa":"خود","examples":[{"de":"Jeder Mensch hat seine eigenen Eigenschaften.","en":"Every person has their own characteristics.","ru":"У каждого человека свои особенности.","vi":"Mỗi người đều có những đặc điểm riêng.","fa":"هر فردی ویژگی های خاص خود را دارد."},{"de":"Sein Verhalten wirkt manchmal etwas eigenartig.","en":"His behavior sometimes seems a bit odd.","ru":"Его поведение иногда кажется немного странным.","vi":"Hành vi của anh ấy đôi khi có vẻ hơi kỳ lạ.","fa":"رفتار او گاهی کمی عجیب به نظر می رسد."}]},{"word":"eigentlich","en":"actually, in fact","ru":"на самом деле, собственно","vi":"thực sự","fa":"در واقع","examples":[{"de":"Eigentlich wollte ich heute joggen gehen, aber es regnet.","en":"Actually, I wanted to go jogging today, but it's raining.","ru":"На самом деле я хотел сегодня пойти на пробежку, но идёт дождь.","vi":"Thực ra hôm nay tôi muốn chạy bộ nhưng trời đang mưa.","fa":"من واقعاً می خواستم امروز بروم دویدن، اما باران می بارد."},{"de":"Was machst du eigentlich beruflich?","en":"What do you actually do for a living?","ru":"А чем ты, собственно, занимаешься по работе?","vi":"Bạn thực sự làm gì để kiếm sống?","fa":"در واقع برای امرار معاش چه کار می کنید؟"}]},{"word":"eilen","en":"to hurry","ru":"спешить","vi":"vội vàng","fa":"عجله","examples":[{"de":"Sie eilte zum Bahnhof, um den Zug nicht zu verpassen.","en":"She hurried to the station so as not to miss the train.","ru":"Она спешила на вокзал, чтобы не опоздать на поезд.","vi":"Cô vội vã đến ga xe lửa để không bị lỡ chuyến tàu.","fa":"او با عجله به سمت ایستگاه قطار رفت تا قطار را از دست ندهد."},{"de":"Die Sache eilt, wir müssen sofort handeln.","en":"The matter is urgent, we have to act immediately.","ru":"Дело срочное, нам нужно действовать немедленно.","vi":"Vấn đề rất cấp bách, chúng ta phải hành động ngay.","fa":"موضوع فوری است، ما باید فورا اقدام کنیم."}]},{"word":"ein bisschen","en":"a little; a bit","ru":"немного","vi":"một chút","fa":"کمی","examples":[{"de":"Kannst du mir ein bisschen Zucker geben?","en":"Can you give me a little sugar?","ru":"Ты можешь дать мне немного сахара?","vi":"Bạn có thể cho tôi một ít đường được không?","fa":"میشه شکر بهم بدی"},{"de":"Ich bin ein bisschen müde heute.","en":"I'm a bit tired today.","ru":"Я немного устал сегодня.","vi":"Hôm nay tôi hơi mệt.","fa":"امروز کمی خسته ام."}]},{"word":"die Einbahnstraße","en":"one-way street","ru":"улица с односторонним движением","vi":"đường một chiều","fa":"خیابان یک طرفه","examples":[{"de":"Achtung, das ist eine Einbahnstraße!","en":"Watch out, this is a one-way street!","ru":"Осторожно, это улица с односторонним движением!","vi":"Hãy cẩn thận, đây là đường một chiều!","fa":"مواظب باشید این یک خیابان یک طرفه است!"},{"de":"Man darf in dieser Einbahnstraße nicht rückwärts fahren.","en":"You are not allowed to drive backwards on this one-way street.","ru":"На этой односторонней улице нельзя ехать задним ходом.","vi":"Bạn không được phép lùi trên đường một chiều này.","fa":"در این خیابان یک طرفه مجاز به عقب رفتن نیستید."}]},{"word":"einbrechen","en":"to break in (burglary)","ru":"вламываться, совершать кражу со взломом","vi":"đột nhập","fa":"شکستن","examples":[{"de":"In der Nacht sind Diebe in unser Haus eingebrochen.","en":"During the night, thieves broke into our house.","ru":"Ночью в наш дом вломились воры.","vi":"Kẻ trộm đột nhập vào nhà chúng tôi vào ban đêm.","fa":"دزدها شبانه وارد خانه ما شدند."},{"de":"Die Polizei warnt: In dieser Gegend wird oft eingebrochen.","en":"The police warn: there are frequent break-ins in this area.","ru":"Полиция предупреждает: в этом районе часто случаются кражи со взломом.","vi":"Cảnh sát cảnh báo: Những vụ đột nhập thường xuyên xảy ra ở khu vực này.","fa":"پلیس هشدار داد: سرقت در این منطقه رایج است."}]},{"word":"eindeutig","en":"clear, unambiguous","ru":"однозначный","vi":"rõ ràng","fa":"به وضوح","examples":[{"de":"Die Antwort auf diese Frage ist eindeutig.","en":"The answer to this question is clear.","ru":"Ответ на этот вопрос однозначен.","vi":"Câu trả lời cho câu hỏi này là rõ ràng.","fa":"پاسخ این سوال روشن است."},{"de":"Er hat sich eindeutig gegen den Vorschlag ausgesprochen.","en":"He clearly spoke out against the proposal.","ru":"Он однозначно высказался против этого предложения.","vi":"Ông rõ ràng đã phản đối đề xuất này.","fa":"او به وضوح با این پیشنهاد مخالفت کرده است."}]},{"word":"der Eindruck","en":"impression","ru":"впечатление","vi":"ấn tượng","fa":"تصور","examples":[{"de":"Sie hat einen guten Eindruck bei ihrem Chef hinterlassen.","en":"She made a good impression on her boss.","ru":"Она произвела хорошее впечатление на своего начальника.","vi":"Cô ấy đã để lại ấn tượng tốt với sếp của mình.","fa":"او تأثیر خوبی بر رئیس خود گذاشت."},{"de":"Mein erster Eindruck von der Stadt war positiv.","en":"My first impression of the city was positive.","ru":"Моё первое впечатление о городе было положительным.","vi":"Ấn tượng đầu tiên của tôi về thành phố là tích cực.","fa":"اولین برداشت من از شهر مثبت بود."}]},{"word":"einerseits","en":"on the one hand","ru":"с одной стороны","vi":"một mặt","fa":"از یک طرف","examples":[{"de":"Einerseits möchte ich reisen, andererseits fehlt mir das Geld.","en":"On the one hand I want to travel, on the other hand I lack the money.","ru":"С одной стороны, я хочу путешествовать, с другой — у меня нет денег.","vi":"Một mặt tôi muốn đi du lịch, mặt khác tôi không có tiền.","fa":"از یک طرف می خواهم سفر کنم، از طرف دیگر پول ندارم."},{"de":"Einerseits ist der Job gut bezahlt, aber sehr stressig.","en":"On the one hand, the job pays well, but it's very stressful.","ru":"С одной стороны, работа хорошо оплачивается, но очень напряжённая.","vi":"Một mặt, công việc được trả lương cao nhưng rất căng thẳng.","fa":"از یک طرف، این شغل با دستمزد خوب، اما بسیار پر استرس است."}]},{"word":"einfach","en":"simple, easy","ru":"простой","vi":"dễ dàng","fa":"آسان","examples":[{"de":"Die Aufgabe war wirklich einfach zu lösen.","en":"The task was really easy to solve.","ru":"Задачу было действительно легко решить.","vi":"Nhiệm vụ thực sự dễ dàng để giải quyết.","fa":"حل این کار واقعاً آسان بود."},{"de":"Ich hätte gern einen einfachen Fahrschein nach München.","en":"I'd like a one-way ticket to Munich.","ru":"Я бы хотел билет в один конец до Мюнхена.","vi":"Tôi muốn một vé một chiều tới Munich.","fa":"من یک بلیط یک طرفه به مونیخ می خواهم."}]},{"word":"die Einfahrt","en":"driveway, entrance (for vehicles)","ru":"въезд","vi":"lối vào","fa":"ورودی","examples":[{"de":"Bitte die Einfahrt nicht zuparken.","en":"Please do not block the driveway with your car.","ru":"Пожалуйста, не загораживайте въезд.","vi":"Vui lòng không đậu xe ở lối đi.","fa":"لطفا در خیابان پارک نکنید."},{"de":"Die Einfahrt zur Garage ist ziemlich eng.","en":"The entrance to the garage is quite narrow.","ru":"Въезд в гараж довольно узкий.","vi":"Lối vào gara khá hẹp.","fa":"ورودی گاراژ کاملاً باریک است."}]},{"word":"einfallen","en":"to occur to (someone), to come to mind","ru":"приходить в голову","vi":"xảy ra","fa":"رخ دهد","examples":[{"de":"Mir fällt sein Name gerade nicht ein.","en":"His name doesn't come to my mind right now.","ru":"Мне сейчас не приходит на ум его имя.","vi":"Tôi không thể nhớ tên anh ấy ngay bây giờ.","fa":"الان اسمش یادم نیست"},{"de":"Plötzlich fiel ihr eine gute Idee ein.","en":"Suddenly a good idea occurred to her.","ru":"Внезапно ей пришла в голову хорошая идея.","vi":"Đột nhiên cô nghĩ ra một ý hay.","fa":"ناگهان به فکر یک ایده خوب افتاد."}]},{"word":"der Einfluss","en":"influence","ru":"влияние","vi":"sự ảnh hưởng","fa":"نفوذ","examples":[{"de":"Seine Eltern hatten großen Einfluss auf seine Erziehung.","en":"His parents had a great influence on his upbringing.","ru":"Его родители оказали большое влияние на его воспитание.","vi":"Cha mẹ anh có ảnh hưởng lớn đến sự giáo dục của anh.","fa":"پدر و مادرش تأثیر زیادی در تربیت او داشتند."},{"de":"Sie versucht, keinen Einfluss auf die Entscheidung zu nehmen.","en":"She tries not to exert any influence on the decision.","ru":"Она старается не влиять на это решение.","vi":"Cô cố gắng không ảnh hưởng đến quyết định.","fa":"او سعی می کند در تصمیم گیری تأثیری نداشته باشد."}]},{"word":"einfügen","en":"to insert","ru":"вставлять","vi":"chèn","fa":"درج کنید","examples":[{"de":"Füge bitte ein Bild in das Dokument ein.","en":"Please insert an image into the document.","ru":"Пожалуйста, вставь картинку в документ.","vi":"Vui lòng chèn hình ảnh vào tài liệu.","fa":"لطفا یک تصویر در سند وارد کنید."},{"de":"Man kann den Text einfach kopieren und einfügen.","en":"You can simply copy and paste the text.","ru":"Текст можно просто скопировать и вставить.","vi":"Bạn chỉ có thể sao chép và dán văn bản.","fa":"به سادگی می توانید متن را کپی و پیست کنید."}]},{"word":"einführen","en":"to introduce","ru":"вводить, внедрять","vi":"giới thiệu","fa":"معرفی کنید","examples":[{"de":"Die Regierung will eine neue Steuer einführen.","en":"The government wants to introduce a new tax.","ru":"Правительство хочет ввести новый налог.","vi":"Chính phủ muốn giới thiệu một loại thuế mới.","fa":"دولت می خواهد مالیات جدیدی وضع کند."},{"de":"Er führte mich in die neue Software ein.","en":"He introduced me to the new software.","ru":"Он ознакомил меня с новым программным обеспечением.","vi":"Anh ấy đã giới thiệu cho tôi phần mềm mới.","fa":"نرم افزار جدید را به من معرفی کرد."}]},{"word":"der Eingang","en":"entrance","ru":"вход","vi":"lối vào","fa":"ورودی","examples":[{"de":"Der Eingang zum Museum ist auf der linken Seite.","en":"The entrance to the museum is on the left side.","ru":"Вход в музей находится с левой стороны.","vi":"Lối vào bảo tàng nằm ở bên trái.","fa":"ورودی موزه در سمت چپ است."},{"de":"Bitte warten Sie am Eingang auf mich.","en":"Please wait for me at the entrance.","ru":"Пожалуйста, подождите меня у входа.","vi":"Vui lòng đợi tôi ở lối vào.","fa":"لطفا در ورودی منتظر من باشید."}]},{"word":"einheitlich","en":"uniform, standardized","ru":"единый, единообразный","vi":"đồng phục","fa":"یکنواخت","examples":[{"de":"In der Schule tragen alle Schüler einheitliche Kleidung.","en":"At the school all students wear uniform clothing.","ru":"В этой школе все ученики носят единую форму.","vi":"Ở trường, tất cả học sinh đều mặc đồng phục.","fa":"در مدرسه، همه دانش آموزان لباس یکنواخت می پوشند."},{"de":"Die Preise sind in ganz Europa nicht einheitlich.","en":"Prices are not standardized throughout Europe.","ru":"Цены по всей Европе не единообразны.","vi":"Giá cả không đồng đều trên khắp châu Âu.","fa":"قیمت ها در سراسر اروپا یکسان نیست."}]},{"word":"einig-","en":"some (stem of 'einige')","ru":"некоторые, несколько","vi":"đồng ý-","fa":"موافقت -","examples":[{"de":"Ich habe einige Fragen zu diesem Thema.","en":"I have some questions about this topic.","ru":"У меня есть несколько вопросов по этой теме.","vi":"Tôi có một số câu hỏi về chủ đề này.","fa":"من چند سوال در مورد این موضوع دارم."},{"de":"Einige Leute waren mit der Entscheidung nicht zufrieden.","en":"Some people were not satisfied with the decision.","ru":"Некоторые люди были недовольны этим решением.","vi":"Một số người không hài lòng với quyết định này.","fa":"برخی از مردم از این تصمیم راضی نبودند."}]},{"word":"einkaufen","en":"to shop, to buy groceries","ru":"делать покупки, ходить за покупками","vi":"mua sắm","fa":"خرید","examples":[{"de":"Samstags gehe ich immer im Supermarkt einkaufen.","en":"On Saturdays I always go grocery shopping at the supermarket.","ru":"По субботам я всегда хожу за покупками в супермаркет.","vi":"Tôi luôn đi mua sắm ở siêu thị vào thứ Bảy.","fa":"من همیشه شنبه ها از سوپرمارکت خرید می کنم."},{"de":"Kannst du auf dem Heimweg noch Brot einkaufen?","en":"Can you buy some bread on the way home?","ru":"Можешь купить хлеб по дороге домой?","vi":"Bạn có thể mua bánh mì trên đường về nhà không?","fa":"آیا می توانید در راه خانه نان بخرید؟"}]},{"word":"das Einkommen","en":"income","ru":"доход","vi":"thu nhập","fa":"درآمد","examples":[{"de":"Sein monatliches Einkommen liegt über dem Durchschnitt.","en":"His monthly income is above average.","ru":"Его ежемесячный доход выше среднего.","vi":"Thu nhập hàng tháng của anh ấy trên mức trung bình.","fa":"درآمد ماهانه او بالاتر از حد متوسط است."},{"de":"Mit diesem Einkommen kann sie sich keine große Wohnung leisten.","en":"With this income she can't afford a large apartment.","ru":"С таким доходом она не может позволить себе большую квартиру.","vi":"Với mức thu nhập này, cô không đủ khả năng mua một căn hộ lớn.","fa":"با این درآمد او نمی تواند یک آپارتمان بزرگ را بخرد."}]},{"word":"einladen","en":"to invite","ru":"приглашать","vi":"mời","fa":"دعوت کنید","examples":[{"de":"Wir laden dich herzlich zu unserer Hochzeit ein.","en":"We warmly invite you to our wedding.","ru":"Мы сердечно приглашаем тебя на нашу свадьбу.","vi":"Chúng tôi trân trọng mời bạn đến dự đám cưới của chúng tôi.","fa":"ما صمیمانه شما را به عروسی خود دعوت می کنیم."},{"de":"Er hat mich zum Essen eingeladen.","en":"He invited me to dinner.","ru":"Он пригласил меня на ужин.","vi":"Anh ấy mời tôi đi ăn tối.","fa":"او مرا به شام ​​دعوت کرد."}]},{"word":"einmal","en":"once","ru":"однажды, один раз","vi":"một lần","fa":"یک بار","examples":[{"de":"Ich war schon einmal in Paris.","en":"I have already been to Paris once.","ru":"Я уже однажды был в Париже.","vi":"Tôi đã từng đến Paris trước đây.","fa":"من قبلاً به پاریس رفته بودم."},{"de":"Können Sie das bitte noch einmal erklären?","en":"Could you please explain that once more?","ru":"Не могли бы вы объяснить это ещё раз?","vi":"Bạn có thể vui lòng giải thích điều đó một lần nữa?","fa":"میشه لطفا دوباره توضیح بدید؟"}]},{"word":"einnehmen","en":"to take (medicine); to occupy","ru":"принимать (лекарство); занимать","vi":"lấy","fa":"گرفتن","examples":[{"de":"Nehmen Sie diese Tabletten dreimal täglich ein.","en":"Take these tablets three times a day.","ru":"Принимайте эти таблетки три раза в день.","vi":"Uống những viên thuốc này ba lần một ngày.","fa":"این قرص ها را سه بار در روز مصرف کنید."},{"de":"Die Firma nimmt eine führende Position auf dem Markt ein.","en":"The company occupies a leading position in the market.","ru":"Компания занимает лидирующую позицию на рынке.","vi":"Công ty chiếm vị trí dẫn đầu trên thị trường.","fa":"این شرکت جایگاه پیشرو در بازار را به خود اختصاص داده است."}]},{"word":"einpacken","en":"to pack, to wrap","ru":"упаковывать","vi":"đóng gói","fa":"بسته بندی کردن","examples":[{"de":"Vergiss nicht, deine Badesachen einzupacken.","en":"Don't forget to pack your swimming things.","ru":"Не забудь упаковать свои купальные принадлежности.","vi":"Đừng quên đóng gói đồ bơi của bạn.","fa":"فراموش نکنید که مایو خود را بسته بندی کنید."},{"de":"Die Verkäuferin packte das Geschenk schön ein.","en":"The saleswoman wrapped the gift nicely.","ru":"Продавщица красиво упаковала подарок.","vi":"Cô bán hàng gói quà rất đẹp.","fa":"خانم فروشنده کادو را به زیبایی بسته بندی کرد."}]},{"word":"einrichten","en":"to furnish, to set up","ru":"обустраивать, оборудовать","vi":"thiết lập","fa":"راه اندازی کنید","examples":[{"de":"Wir haben unsere neue Wohnung gemütlich eingerichtet.","en":"We furnished our new apartment cozily.","ru":"Мы уютно обустроили нашу новую квартиру.","vi":"Chúng tôi đã trang bị nội thất tiện nghi cho căn hộ mới của mình.","fa":"ما آپارتمان جدید خود را به راحتی مبله کرده ایم."},{"de":"Die Firma will ein neues Büro einrichten.","en":"The company wants to set up a new office.","ru":"Компания хочет оборудовать новый офис.","vi":"Công ty muốn thành lập một văn phòng mới.","fa":"این شرکت می خواهد دفتر جدیدی راه اندازی کند."}]},{"word":"einsam","en":"lonely","ru":"одинокий","vi":"cô đơn","fa":"تنها","examples":[{"de":"Seit dem Umzug fühlt er sich oft einsam.","en":"Since the move he often feels lonely.","ru":"После переезда он часто чувствует себя одиноким.","vi":"Kể từ khi chuyển đi, anh thường cảm thấy cô đơn.","fa":"از زمان نقل مکان، او اغلب احساس تنهایی کرده است."},{"de":"Alte Menschen sind manchmal sehr einsam.","en":"Elderly people are sometimes very lonely.","ru":"Пожилые люди иногда очень одиноки.","vi":"Người già đôi khi rất cô đơn.","fa":"افراد مسن گاهی خیلی تنها هستند."}]},{"word":"einschalten","en":"to switch on","ru":"включать","vi":"bật lên","fa":"روشن کن","examples":[{"de":"Bitte schalte das Licht ein, es ist dunkel.","en":"Please switch on the light, it's dark.","ru":"Пожалуйста, включи свет, темно.","vi":"Làm ơn bật đèn lên, trời tối quá.","fa":"لطفا چراغ ها را روشن کنید، تاریک است."},{"de":"Er schaltete den Fernseher ein, um die Nachrichten zu sehen.","en":"He switched on the TV to watch the news.","ru":"Он включил телевизор, чтобы посмотреть новости.","vi":"Anh bật TV để xem tin tức.","fa":"برای تماشای اخبار تلویزیون را روشن کرد."}]},{"word":"einschließlich","en":"including","ru":"включая, включительно","vi":"bao gồm cả","fa":"از جمله","examples":[{"de":"Der Preis beträgt 50 Euro, einschließlich Frühstück.","en":"The price is 50 euros, including breakfast.","ru":"Цена составляет 50 евро, включая завтрак.","vi":"Giá là 50 euro, bao gồm bữa sáng.","fa":"قیمت 50 یورو با احتساب صبحانه."},{"de":"Das Museum ist von Montag einschließlich Freitag geöffnet.","en":"The museum is open from Monday through Friday, inclusive.","ru":"Музей открыт с понедельника по пятницу включительно.","vi":"Bảo tàng mở cửa từ thứ Hai đến thứ Sáu.","fa":"موزه از دوشنبه تا جمعه باز است."}]},{"word":"das Einschreiben","en":"registered letter/mail","ru":"заказное письмо","vi":"thư đã đăng ký","fa":"نامه ثبت شده","examples":[{"de":"Ich habe den Brief als Einschreiben verschickt.","en":"I sent the letter by registered mail.","ru":"Я отправил письмо заказным.","vi":"Tôi đã gửi thư dưới dạng thư bảo đảm.","fa":"من نامه را به صورت پست سفارشی فرستادم."},{"de":"Für wichtige Dokumente sollte man ein Einschreiben benutzen.","en":"For important documents you should use registered mail.","ru":"Для важных документов следует пользоваться заказным письмом.","vi":"Bạn nên sử dụng thư bảo đảm cho các tài liệu quan trọng.","fa":"برای اسناد مهم باید از پست ثبت شده استفاده کنید."}]},{"word":"einsetzen","en":"to use, to deploy; to insert","ru":"использовать, задействовать; вставлять","vi":"chèn","fa":"درج کنید","examples":[{"de":"Die Firma setzt moderne Technik ein.","en":"The company deploys modern technology.","ru":"Компания использует современные технологии.","vi":"Công ty sử dụng công nghệ hiện đại.","fa":"این شرکت از تکنولوژی مدرن استفاده می کند."},{"de":"Er setzt sich sehr für den Umweltschutz ein.","en":"He is very committed to environmental protection.","ru":"Он активно борется за охрану окружающей среды.","vi":"Anh ấy rất quan tâm đến việc bảo vệ môi trường.","fa":"او به حفاظت از محیط زیست بسیار متعهد است."}]},{"word":"einsteigen","en":"to get in, to board (a vehicle)","ru":"садиться (в транспорт)","vi":"vào trong","fa":"وارد شوید","examples":[{"de":"Bitte einsteigen, der Zug fährt gleich ab!","en":"All aboard, the train is about to depart!","ru":"Просьба заходить, поезд сейчас отправляется!","vi":"Xin mời vào trong, tàu sắp khởi hành rồi!","fa":"لطفا سوار شوید، قطار به زودی حرکت می کند!"},{"de":"Sie stieg schnell in den Bus ein.","en":"She quickly got on the bus.","ru":"Она быстро села в автобус.","vi":"Cô nhanh chóng lên xe buýt.","fa":"سریع سوار اتوبوس شد."}]},{"word":"einstellen","en":"to adjust; to hire; to stop","ru":"настраивать; принимать на работу; прекращать","vi":"đặt","fa":"مجموعه","examples":[{"de":"Die Firma will fünf neue Mitarbeiter einstellen.","en":"The company wants to hire five new employees.","ru":"Компания хочет нанять пять новых сотрудников.","vi":"Công ty muốn thuê năm nhân viên mới.","fa":"این شرکت می خواهد پنج کارمند جدید استخدام کند."},{"de":"Kannst du die Lautstärke etwas leiser einstellen?","en":"Can you turn the volume down a bit?","ru":"Можешь сделать звук немного тише?","vi":"Bạn có thể giảm âm lượng xuống một chút được không?","fa":"میشه یه کم صدا رو کم کنید؟"}]},{"word":"eintragen","en":"to enter, to register (in writing)","ru":"вносить (в список/реестр)","vi":"nhập","fa":"وارد کنید","examples":[{"de":"Bitte tragen Sie Ihren Namen in die Liste ein.","en":"Please enter your name in the list.","ru":"Пожалуйста, впишите своё имя в список.","vi":"Hãy thêm tên của bạn vào danh sách.","fa":"لطفا نام خود را به لیست اضافه کنید."},{"de":"Der neue Termin wurde im Kalender eingetragen.","en":"The new appointment was entered in the calendar.","ru":"Новая встреча была внесена в календарь.","vi":"Cuộc hẹn mới đã được nhập vào lịch.","fa":"قرار جدید در تقویم درج شده است."}]},{"word":"eintreten","en":"to enter; to occur","ru":"входить; наступать (о событии)","vi":"nhập","fa":"وارد کنید","examples":[{"de":"Bitte treten Sie ein und nehmen Sie Platz.","en":"Please come in and take a seat.","ru":"Пожалуйста, входите и присаживайтесь.","vi":"Xin mời vào trong và ngồi.","fa":"لطفا بیایید و بنشینید."},{"de":"Falls der Notfall eintritt, rufen Sie sofort an.","en":"If the emergency occurs, call immediately.","ru":"Если наступит чрезвычайная ситуация, звоните немедленно.","vi":"Nếu trường hợp khẩn cấp xảy ra, hãy gọi ngay.","fa":"اگر شرایط اضطراری رخ داد، بلافاصله تماس بگیرید."}]},{"word":"einverstanden","en":"agreed, in agreement","ru":"согласен","vi":"đã đồng ý","fa":"موافقت کرد","examples":[{"de":"Bist du mit meinem Vorschlag einverstanden?","en":"Do you agree with my proposal?","ru":"Ты согласен с моим предложением?","vi":"Bạn có đồng ý với đề nghị của tôi không?","fa":"آیا با پیشنهاد من موافقید؟"},{"de":"Einverstanden, wir treffen uns um sechs Uhr.","en":"Agreed, we'll meet at six o'clock.","ru":"Договорились, встретимся в шесть часов.","vi":"Đồng ý, chúng ta sẽ gặp nhau lúc sáu giờ.","fa":"توافق کردیم، ساعت شش همدیگر را می بینیم."}]},{"word":"der Einwohner","en":"inhabitant, resident","ru":"житель","vi":"cư dân","fa":"ساکنان","examples":[{"de":"Die Stadt hat etwa eine Million Einwohner.","en":"The city has about one million inhabitants.","ru":"В городе проживает около миллиона жителей.","vi":"Thành phố có khoảng một triệu dân.","fa":"این شهر حدود یک میلیون نفر جمعیت دارد."},{"de":"Die Einwohner protestierten gegen den neuen Flughafen.","en":"The residents protested against the new airport.","ru":"Жители протестовали против нового аэропорта.","vi":"Người dân phản đối sân bay mới.","fa":"ساکنان به فرودگاه جدید اعتراض کردند."}]},{"word":"einzahlen","en":"to pay in; to deposit (money)","ru":"вносить (деньги), класть на счёт","vi":"đặt cọc","fa":"سپرده گذاری","examples":[{"de":"Ich möchte 200 Euro auf mein Konto einzahlen.","en":"I would like to deposit 200 euros into my account.","ru":"Я хотел бы внести 200 евро на свой счёт.","vi":"Tôi muốn gửi 200 euro vào tài khoản của mình.","fa":"من می خواهم 200 یورو به حسابم واریز کنم."},{"de":"Er zahlt jeden Monat einen Teil seines Gehalts ein.","en":"He pays in part of his salary every month.","ru":"Каждый месяц он вносит часть своей зарплаты.","vi":"Anh ấy trả một phần tiền lương hàng tháng.","fa":"او هر ماه بخشی از حقوق خود را پرداخت می کند."}]},{"word":"einzeln","en":"individual; single","ru":"отдельный, единичный","vi":"cá nhân","fa":"به صورت جداگانه","examples":[{"de":"Die Äpfel werden einzeln verpackt.","en":"The apples are packed individually.","ru":"Яблоки упаковываются по отдельности.","vi":"Táo được đóng gói riêng lẻ.","fa":"سیب ها به صورت تکی بسته بندی می شوند."},{"de":"Kann ich die Teile auch einzeln kaufen?","en":"Can I also buy the parts individually?","ru":"Можно ли купить детали по отдельности?","vi":"Tôi cũng có thể mua từng bộ phận riêng lẻ được không?","fa":"آیا می توانم قطعات را به صورت تکی هم بخرم؟"}]},{"word":"einziehen","en":"to move in (to a home)","ru":"въезжать, переезжать (в жильё)","vi":"chuyển đến","fa":"حرکت کن","examples":[{"de":"Wir ziehen nächste Woche in die neue Wohnung ein.","en":"We are moving into the new apartment next week.","ru":"На следующей неделе мы переезжаем в новую квартиру.","vi":"Chúng tôi sẽ chuyển đến căn hộ mới vào tuần tới.","fa":"هفته آینده به آپارتمان جدید نقل مکان می کنیم."},{"de":"Wann seid ihr in dieses Haus eingezogen?","en":"When did you move into this house?","ru":"Когда вы переехали в этот дом?","vi":"Bạn chuyển đến ngôi nhà này khi nào?","fa":"چه زمانی به این خانه نقل مکان کردید؟"}]},{"word":"einzig-","en":"only, sole (stem meaning 'unique/single')","ru":"единственный (основа со значением 'уникальный')","vi":"chỉ-","fa":"فقط-","examples":[{"de":"Dieses Gemälde ist wirklich einzigartig.","en":"This painting is truly unique.","ru":"Эта картина поистине уникальна.","vi":"Bức tranh này thực sự độc đáo.","fa":"این نقاشی واقعا منحصر به فرد است."},{"de":"Die Landschaft dort ist einzigartig schön.","en":"The landscape there is uniquely beautiful.","ru":"Пейзаж там уникально красив.","vi":"Phong cảnh ở đó đẹp độc đáo.","fa":"مناظر آنجا فوق العاده زیباست."}]},{"word":"das Eis","en":"ice; ice cream","ru":"лёд; мороженое","vi":"kem","fa":"بستنی","examples":[{"de":"Im Winter ist der See mit Eis bedeckt.","en":"In winter the lake is covered with ice.","ru":"Зимой озеро покрыто льдом.","vi":"Vào mùa đông mặt hồ được bao phủ bởi băng.","fa":"در زمستان دریاچه پوشیده از یخ است."},{"de":"Die Kinder essen gern Eis im Sommer.","en":"The children like eating ice cream in summer.","ru":"Дети любят есть мороженое летом.","vi":"Trẻ em thích ăn kem vào mùa hè.","fa":"بچه ها دوست دارند در تابستان بستنی بخورند."}]},{"word":"die Eisenbahn","en":"railway","ru":"железная дорога","vi":"đường sắt","fa":"راه آهن","examples":[{"de":"Die Eisenbahn verbindet die beiden Städte.","en":"The railway connects the two cities.","ru":"Железная дорога соединяет два города.","vi":"Đường sắt kết nối hai thành phố.","fa":"راه آهن این دو شهر را به هم متصل می کند."},{"de":"Früher sind wir oft mit der Eisenbahn gereist.","en":"In the past we often traveled by railway.","ru":"Раньше мы часто путешествовали на поезде.","vi":"Chúng tôi thường đi du lịch bằng tàu hỏa.","fa":"ما اغلب با قطار سفر می کردیم."}]},{"word":"elegant","en":"elegant","ru":"элегантный","vi":"thanh lịch","fa":"ظریف","examples":[{"de":"Sie trägt ein elegantes Kleid zur Feier.","en":"She is wearing an elegant dress to the party.","ru":"Она надела элегантное платье на праздник.","vi":"Cô mặc một chiếc váy thanh lịch cho lễ kỷ niệm.","fa":"او یک لباس شیک برای جشن می پوشد."},{"de":"Das Restaurant ist sehr elegant eingerichtet.","en":"The restaurant is furnished very elegantly.","ru":"Ресторан обставлен очень элегантно.","vi":"Nhà hàng được trang trí rất trang nhã.","fa":"رستوران بسیار شیک تزئین شده است."}]},{"word":"elektrisch","en":"electric","ru":"электрический","vi":"điện","fa":"برقی","examples":[{"de":"Wir haben ein elektrisches Auto gekauft.","en":"We bought an electric car.","ru":"Мы купили электрический автомобиль.","vi":"Chúng tôi đã mua một chiếc xe điện.","fa":"ما یک ماشین برقی خریدیم."},{"de":"Der elektrische Herd funktioniert nicht mehr.","en":"The electric stove no longer works.","ru":"Электрическая плита больше не работает.","vi":"Bếp điện không còn hoạt động nữa.","fa":"اجاق برقی دیگر کار نمی کند."}]},{"word":"die Eltern","en":"parents","ru":"родители","vi":"bố mẹ","fa":"والدین","examples":[{"de":"Meine Eltern wohnen auf dem Land.","en":"My parents live in the countryside.","ru":"Мои родители живут в деревне.","vi":"Bố mẹ tôi sống ở quê.","fa":"پدر و مادرم در کشور زندگی می کنند."},{"de":"Ich besuche meine Eltern jedes Wochenende.","en":"I visit my parents every weekend.","ru":"Я навещаю родителей каждые выходные.","vi":"Tôi đến thăm bố mẹ tôi vào mỗi cuối tuần.","fa":"آخر هفته به پدر و مادرم سر می زنم."}]},{"word":"empfangen","en":"to receive (guests, a signal)","ru":"принимать (гостей, сигнал)","vi":"đã nhận được","fa":"دریافت کرد","examples":[{"de":"Wir wurden herzlich von der Familie empfangen.","en":"We were warmly received by the family.","ru":"Семья тепло приняла нас.","vi":"Chúng tôi được gia đình chào đón nồng nhiệt.","fa":"خانواده به گرمی از ما استقبال کردند."},{"de":"Hier kann man kein WLAN-Signal empfangen.","en":"You can't receive a Wi-Fi signal here.","ru":"Здесь нельзя принять сигнал Wi-Fi.","vi":"Bạn không thể nhận được tín hiệu WiFi ở đây.","fa":"در اینجا نمی توانید سیگنال WiFi دریافت کنید."}]},{"word":"empfehlen","en":"to recommend","ru":"рекомендовать","vi":"đề nghị","fa":"توصیه می کنند","examples":[{"de":"Kannst du mir ein gutes Restaurant empfehlen?","en":"Can you recommend a good restaurant to me?","ru":"Можешь порекомендовать мне хороший ресторан?","vi":"Bạn có thể giới thiệu cho tôi một nhà hàng tốt được không?","fa":"آیا می توانید یک رستوران خوب به من معرفی کنید؟"},{"de":"Der Arzt empfiehlt mehr Bewegung.","en":"The doctor recommends more exercise.","ru":"Врач рекомендует больше двигаться.","vi":"Bác sĩ khuyên nên tập thể dục nhiều hơn.","fa":"پزشک ورزش بیشتر را توصیه می کند."}]},{"word":"enden","en":"to end","ru":"заканчиваться","vi":"kết thúc","fa":"پایان","examples":[{"de":"Der Film endet mit einem Happy End.","en":"The movie ends with a happy ending.","ru":"Фильм заканчивается счастливым концом.","vi":"Bộ phim kết thúc với một kết thúc có hậu.","fa":"فیلم با پایانی خوش به پایان می رسد."},{"de":"Wann endet der Kurs?","en":"When does the course end?","ru":"Когда заканчивается курс?","vi":"Khi nào khóa học kết thúc?","fa":"دوره چه زمانی تمام می شود؟"}]},{"word":"endlich","en":"finally, at last","ru":"наконец","vi":"cuối cùng","fa":"در نهایت","examples":[{"de":"Endlich ist das Wochenende da!","en":"Finally the weekend is here!","ru":"Наконец-то настали выходные!","vi":"Cuối tuần cuối cùng cũng đã đến!","fa":"آخر هفته بالاخره رسید!"},{"de":"Nach langem Warten kam der Bus endlich.","en":"After a long wait, the bus finally came.","ru":"После долгого ожидания автобус наконец приехал.","vi":"Sau một hồi chờ đợi cuối cùng xe buýt cũng đến.","fa":"بعد از مدت ها انتظار بالاخره اتوبوس آمد."}]},{"word":"die Energie","en":"energy","ru":"энергия","vi":"năng lượng","fa":"انرژی","examples":[{"de":"Wir sollten Energie sparen.","en":"We should save energy.","ru":"Нам следует экономить энергию.","vi":"Chúng ta nên tiết kiệm năng lượng.","fa":"ما باید در مصرف انرژی صرفه جویی کنیم."},{"de":"Diese Fabrik produziert Energie aus Sonnenlicht.","en":"This factory produces energy from sunlight.","ru":"Эта фабрика производит энергию из солнечного света.","vi":"Nhà máy này sản xuất năng lượng từ ánh sáng mặt trời.","fa":"این کارخانه از نور خورشید انرژی تولید می کند."}]},{"word":"eng","en":"narrow; tight","ru":"узкий; тесный","vi":"chặt chẽ","fa":"تنگ","examples":[{"de":"Die Straße in der Altstadt ist sehr eng.","en":"The street in the old town is very narrow.","ru":"Улица в старом городе очень узкая.","vi":"Đường phố trong phố cổ rất hẹp.","fa":"خیابان در شهر قدیمی بسیار باریک است."},{"de":"Diese Hose ist mir zu eng.","en":"These trousers are too tight for me.","ru":"Эти брюки мне слишком тесны.","vi":"Chiếc quần này quá chật đối với tôi.","fa":"این شلوار برای من خیلی تنگ است."}]},{"word":"der Enkel","en":"grandson","ru":"внук","vi":"cháu trai","fa":"نوه","examples":[{"de":"Mein Enkel besucht mich jeden Sommer.","en":"My grandson visits me every summer.","ru":"Мой внук навещает меня каждое лето.","vi":"Cháu trai tôi đến thăm tôi vào mỗi mùa hè.","fa":"نوه ام هر تابستان به دیدنم می آید."},{"de":"Die Großmutter spielt gerne mit ihrem Enkel.","en":"The grandmother likes to play with her grandson.","ru":"Бабушка любит играть со своим внуком.","vi":"Bà ngoại thích chơi với cháu trai.","fa":"مادربزرگ دوست دارد با نوه اش بازی کند."}]},{"word":"entdecken","en":"to discover","ru":"открывать, обнаруживать","vi":"khám phá","fa":"کشف کنید","examples":[{"de":"Kolumbus entdeckte Amerika im Jahr 1492.","en":"Columbus discovered America in 1492.","ru":"Колумб открыл Америку в 1492 году.","vi":"Columbus phát hiện ra châu Mỹ vào năm 1492.","fa":"کلمب آمریکا را در سال 1492 کشف کرد."},{"de":"Wir haben ein neues Café in der Stadt entdeckt.","en":"We discovered a new café in the city.","ru":"Мы обнаружили новое кафе в городе.","vi":"Chúng tôi phát hiện ra một quán cà phê mới trong thị trấn.","fa":"ما یک کافه جدید در شهر کشف کردیم."}]},{"word":"entfernen","en":"to remove","ru":"удалять, убирать","vi":"loại bỏ","fa":"حذف کنید","examples":[{"de":"Bitte entfernen Sie das Preisschild.","en":"Please remove the price tag.","ru":"Пожалуйста, удалите ценник.","vi":"Vui lòng xóa thẻ giá.","fa":"لطفا برچسب قیمت را بردارید"},{"de":"Der Fleck lässt sich nicht entfernen.","en":"The stain cannot be removed.","ru":"Пятно невозможно удалить.","vi":"Vết bẩn không thể được loại bỏ.","fa":"لکه را نمی توان پاک کرد."}]},{"word":"entgegenkommen","en":"to accommodate (someone), meet halfway","ru":"идти навстречу, уступать","vi":"chứa đựng","fa":"جای دادن","examples":[{"de":"Der Verkäufer ist uns beim Preis entgegengekommen.","en":"The seller met us halfway on the price.","ru":"Продавец пошёл нам навстречу в цене.","vi":"Người bán đã hỗ trợ chúng tôi về giá cả.","fa":"فروشنده ما را در قیمت جا داد."},{"de":"Mein Chef kommt mir bei den Arbeitszeiten entgegen.","en":"My boss accommodates me regarding working hours.","ru":"Мой начальник идёт мне навстречу по рабочему времени.","vi":"Sếp của tôi giúp đỡ tôi về giờ làm việc.","fa":"در مورد ساعات کار، رئیس من از من استقبال می کند."}]},{"word":"enthalten","en":"to contain","ru":"содержать","vi":"bao gồm","fa":"گنجانده شده است","examples":[{"de":"Diese Suppe enthält viel Salz.","en":"This soup contains a lot of salt.","ru":"Этот суп содержит много соли.","vi":"Món súp này chứa rất nhiều muối.","fa":"این سوپ حاوی مقدار زیادی نمک است."},{"de":"Der Preis enthält bereits die Mehrwertsteuer.","en":"The price already includes VAT.","ru":"Цена уже включает НДС.","vi":"Giá đã bao gồm VAT rồi.","fa":"قیمت از قبل شامل مالیات بر ارزش افزوده است."}]},{"word":"entlang","en":"along","ru":"вдоль","vi":"dọc theo","fa":"همراه","examples":[{"de":"Wir gehen den Fluss entlang.","en":"We are walking along the river.","ru":"Мы идём вдоль реки.","vi":"Chúng tôi đi dọc bờ sông.","fa":"در کنار رودخانه قدم می زنیم."},{"de":"Entlang der Straße stehen viele Bäume.","en":"Many trees stand along the street.","ru":"Вдоль улицы стоит много деревьев.","vi":"Có rất nhiều cây dọc theo con đường.","fa":"درختان زیادی در کنار جاده وجود دارد."}]},{"word":"entlassen","en":"to dismiss/lay off (from a job); to discharge","ru":"увольнять; выписывать (из больницы)","vi":"bị sa thải","fa":"اخراج شد","examples":[{"de":"Die Firma musste viele Mitarbeiter entlassen.","en":"The company had to lay off many employees.","ru":"Компании пришлось уволить многих сотрудников.","vi":"Công ty đã phải sa thải nhiều nhân viên.","fa":"شرکت مجبور شد بسیاری از کارمندان را اخراج کند."},{"de":"Der Patient wurde gestern aus dem Krankenhaus entlassen.","en":"The patient was discharged from the hospital yesterday.","ru":"Пациента вчера выписали из больницы.","vi":"Bệnh nhân đã được xuất viện ngày hôm qua.","fa":"بیمار دیروز از بیمارستان مرخص شد."}]},{"word":"entscheiden","en":"to decide","ru":"решать","vi":"quyết định","fa":"تصمیم بگیرند","examples":[{"de":"Ich kann mich nicht entscheiden, welches Kleid ich kaufen soll.","en":"I can't decide which dress to buy.","ru":"Я не могу решить, какое платье купить.","vi":"Tôi không thể quyết định nên mua chiếc váy nào.","fa":"من نمی توانم تصمیم بگیرم کدام لباس را بخرم."},{"de":"Wir müssen bald entscheiden, wohin wir in Urlaub fahren.","en":"We need to decide soon where we're going on vacation.","ru":"Нам нужно скоро решить, куда поехать в отпуск.","vi":"Chúng ta phải quyết định sớm nơi chúng ta sẽ đi nghỉ.","fa":"ما باید به زودی تصمیم بگیریم که به تعطیلات کجا برویم."}]},{"word":"die Entscheidung","en":"decision","ru":"решение","vi":"quyết định","fa":"تصمیم","examples":[{"de":"Das war die schwierigste Entscheidung meines Lebens.","en":"That was the most difficult decision of my life.","ru":"Это было самое трудное решение в моей жизни.","vi":"Đó là quyết định khó khăn nhất trong cuộc đời tôi.","fa":"این سخت ترین تصمیم زندگی من بود."},{"de":"Wir müssen bis morgen eine Entscheidung treffen.","en":"We have to make a decision by tomorrow.","ru":"Мы должны принять решение до завтра.","vi":"Chúng ta phải đưa ra quyết định vào ngày mai.","fa":"تا فردا باید تصمیم بگیریم."}]},{"word":"entschuldigen","en":"to excuse; sich entschuldigen: to apologize","ru":"извинять(ся)","vi":"xin lỗi","fa":"عذرخواهی کن","examples":[{"de":"Entschuldigen Sie bitte die Verspätung.","en":"Please excuse the delay.","ru":"Извините, пожалуйста, за опоздание.","vi":"Xin thứ lỗi cho sự chậm trễ.","fa":"لطفا تاخیر را ببخشید"},{"de":"Er hat sich für seinen Fehler entschuldigt.","en":"He apologized for his mistake.","ru":"Он извинился за свою ошибку.","vi":"Anh xin lỗi vì sai lầm của mình.","fa":"از اشتباهش عذرخواهی کرد."}]},{"word":"die Entschuldigung","en":"apology; excuse","ru":"извинение; оправдание","vi":"lời xin lỗi","fa":"عذرخواهی","examples":[{"de":"Er hat sich mit einer Entschuldigung bei mir gemeldet.","en":"He contacted me with an apology.","ru":"Он связался со мной с извинением.","vi":"Anh ấy đã liên lạc với tôi để xin lỗi.","fa":"او با من تماس گرفت و عذرخواهی کرد."},{"de":"Entschuldigung, wissen Sie, wo der Bahnhof ist?","en":"Excuse me, do you know where the train station is?","ru":"Извините, вы не знаете, где вокзал?","vi":"Xin lỗi, bạn có biết ga xe lửa ở đâu không?","fa":"ببخشید میدونید ایستگاه قطار کجاست؟"}]},{"word":"entsorgen","en":"to dispose of","ru":"утилизировать, избавляться от","vi":"vứt bỏ","fa":"دور انداختن","examples":[{"de":"Alte Batterien muss man richtig entsorgen.","en":"Old batteries must be disposed of properly.","ru":"Старые батарейки нужно правильно утилизировать.","vi":"Pin cũ phải được xử lý đúng cách.","fa":"باتری های قدیمی باید به درستی دور ریخته شوند."},{"de":"Wir entsorgen den Müll getrennt nach Papier und Plastik.","en":"We dispose of the waste separately by paper and plastic.","ru":"Мы утилизируем мусор раздельно по бумаге и пластику.","vi":"Chúng tôi xử lý rác thải riêng biệt thành giấy và nhựa.","fa":"زباله ها را به طور جداگانه در کاغذ و پلاستیک دفع می کنیم."}]},{"word":"entspannend","en":"relaxing","ru":"расслабляющий","vi":"thư giãn","fa":"آرامش بخش","examples":[{"de":"Ein Spaziergang im Wald ist sehr entspannend.","en":"A walk in the forest is very relaxing.","ru":"Прогулка в лесу очень расслабляет.","vi":"Đi dạo trong rừng rất thư giãn.","fa":"قدم زدن در جنگل بسیار آرامش بخش است."},{"de":"Nach der Arbeit finde ich Musik entspannend.","en":"After work I find music relaxing.","ru":"После работы музыка меня расслабляет.","vi":"Tôi thấy âm nhạc thư giãn sau giờ làm việc.","fa":"به نظرم موسیقی بعد از کار آرامش بخش است."}]},{"word":"entstehen","en":"to arise, come into being","ru":"возникать","vi":"phát sinh","fa":"بوجود می آیند","examples":[{"de":"Durch den Unfall entstand ein großer Stau.","en":"The accident caused a big traffic jam.","ru":"Из-за аварии возникла большая пробка.","vi":"Vụ tai nạn khiến giao thông ùn tắc lớn.","fa":"این تصادف باعث ایجاد ترافیک بزرگ شد."},{"de":"Hier soll bald ein neues Einkaufszentrum entstehen.","en":"A new shopping center is supposed to be built here soon.","ru":"Здесь скоро должен появиться новый торговый центр.","vi":"Một trung tâm mua sắm mới sẽ sớm được xây dựng ở đây.","fa":"به زودی یک مرکز خرید جدید در اینجا ساخته خواهد شد."}]},{"word":"enttäuschen","en":"to disappoint","ru":"разочаровывать","vi":"thất vọng","fa":"ناامید کردن","examples":[{"de":"Das Ergebnis hat mich sehr enttäuscht.","en":"The result disappointed me a lot.","ru":"Результат меня сильно разочаровал.","vi":"Kết quả thực sự làm tôi thất vọng.","fa":"نتیجه واقعاً من را ناامید کرد."},{"de":"Ich möchte meine Eltern nicht enttäuschen.","en":"I don't want to disappoint my parents.","ru":"Я не хочу разочаровывать своих родителей.","vi":"Tôi không muốn làm bố mẹ thất vọng.","fa":"من نمی خواهم پدر و مادرم را ناامید کنم."}]},{"word":"die Enttäuschung","en":"disappointment","ru":"разочарование","vi":"sự thất vọng","fa":"ناامیدی","examples":[{"de":"Die Niederlage war eine große Enttäuschung.","en":"The defeat was a big disappointment.","ru":"Поражение было большим разочарованием.","vi":"Trận thua là một nỗi thất vọng lớn.","fa":"شکست یک ناامیدی بزرگ بود."},{"de":"Zu meiner Enttäuschung war das Geschäft schon zu.","en":"To my disappointment the shop was already closed.","ru":"К моему разочарованию, магазин уже был закрыт.","vi":"Trước sự thất vọng của tôi, cửa hàng đã đóng cửa.","fa":"با ناامیدی من، فروشگاه قبلاً بسته بود."}]},{"word":"entweder ... oder","en":"either ... or","ru":"либо ... либо","vi":"hoặc...hoặc","fa":"یا...یا","examples":[{"de":"Wir können entweder ins Kino oder ins Theater gehen.","en":"We can go either to the cinema or to the theater.","ru":"Мы можем пойти либо в кино, либо в театр.","vi":"Chúng ta có thể đi xem phim hoặc đi xem kịch.","fa":"یا می توانیم سینما برویم یا تئاتر."},{"de":"Entweder du lernst jetzt, oder du fällst durch die Prüfung.","en":"Either you study now, or you'll fail the exam.","ru":"Либо ты учишься сейчас, либо провалишь экзамен.","vi":"Hoặc là bạn học bây giờ hoặc bạn trượt kỳ thi.","fa":"یا الان درس می خوانی یا در امتحان مردود می شوی."}]},{"word":"entwickeln","en":"to develop","ru":"развивать(ся)","vi":"phát triển","fa":"توسعه دهد","examples":[{"de":"Die Firma entwickelt eine neue App.","en":"The company is developing a new app.","ru":"Компания разрабатывает новое приложение.","vi":"Công ty đang phát triển một ứng dụng mới.","fa":"این شرکت در حال توسعه یک برنامه جدید است."},{"de":"Er hat sich in den letzten Jahren sehr entwickelt.","en":"He has developed a lot in recent years.","ru":"За последние годы он сильно изменился.","vi":"Anh ấy đã phát triển rất nhiều trong vài năm qua.","fa":"او در چند سال اخیر پیشرفت زیادی کرده است."}]},{"word":"die Entwicklung","en":"development","ru":"развитие","vi":"sự phát triển","fa":"توسعه","examples":[{"de":"Die technische Entwicklung schreitet immer schneller voran.","en":"Technical development is advancing ever faster.","ru":"Технологическое развитие идёт всё быстрее.","vi":"Sự phát triển kỹ thuật đang tiến triển nhanh hơn bao giờ hết.","fa":"توسعه فنی با سرعت بیشتری در حال پیشرفت است."},{"de":"Die Eltern beobachten die Entwicklung ihres Kindes genau.","en":"The parents closely observe their child's development.","ru":"Родители внимательно следят за развитием своего ребёнка.","vi":"Cha mẹ theo dõi chặt chẽ sự phát triển của con mình.","fa":"والدین به دقت رشد کودک خود را زیر نظر دارند."}]},{"word":"die Erde","en":"earth; soil","ru":"земля; почва","vi":"trái đất","fa":"زمین","examples":[{"de":"Die Erde dreht sich um die Sonne.","en":"The Earth revolves around the sun.","ru":"Земля вращается вокруг Солнца.","vi":"Trái đất quay quanh mặt trời.","fa":"زمین به دور خورشید می چرخد."},{"de":"Die Pflanze braucht gute Erde zum Wachsen.","en":"The plant needs good soil to grow.","ru":"Растению нужна хорошая почва, чтобы расти.","vi":"Cây cần đất tốt để phát triển.","fa":"این گیاه برای رشد به خاک مناسب نیاز دارد."}]},{"word":"das Ereignis","en":"event","ru":"событие","vi":"sự kiện","fa":"رویداد","examples":[{"de":"Die Hochzeit war ein wichtiges Ereignis für die Familie.","en":"The wedding was an important event for the family.","ru":"Свадьба была важным событием для семьи.","vi":"Đám cưới là một sự kiện quan trọng đối với gia đình.","fa":"عروسی یک رویداد مهم برای خانواده بود."},{"de":"In den Nachrichten wurde über das Ereignis berichtet.","en":"The news reported on the event.","ru":"В новостях сообщили об этом событии.","vi":"Sự kiện này đã được đưa tin trên bản tin.","fa":"این رویداد در اخبار منتشر شد."}]},{"word":"erfahren","en":"to find out, learn; (adj.) experienced","ru":"узнавать; (прил.) опытный","vi":"có kinh nghiệm","fa":"با تجربه","examples":[{"de":"Ich habe erst gestern von der Neuigkeit erfahren.","en":"I only found out about the news yesterday.","ru":"Я узнал об этой новости только вчера.","vi":"Tôi mới biết tin ngày hôm qua.","fa":"من تازه دیروز با خبر شدم."},{"de":"Sie ist eine sehr erfahrene Lehrerin.","en":"She is a very experienced teacher.","ru":"Она очень опытная учительница.","vi":"Cô ấy là một giáo viên rất giàu kinh nghiệm.","fa":"او یک معلم بسیار با تجربه است."}]},{"word":"die Erfahrung","en":"experience","ru":"опыт","vi":"trải nghiệm","fa":"تجربه","examples":[{"de":"Für diese Stelle braucht man mehrere Jahre Erfahrung.","en":"For this position you need several years of experience.","ru":"Для этой должности нужно несколько лет опыта.","vi":"Vị trí này yêu cầu nhiều năm kinh nghiệm.","fa":"این موقعیت مستلزم چندین سال تجربه است."},{"de":"Aus eigener Erfahrung weiß ich, wie schwer das ist.","en":"From my own experience I know how hard that is.","ru":"По собственному опыту я знаю, как это трудно.","vi":"Tôi biết từ kinh nghiệm của bản thân việc này khó khăn như thế nào.","fa":"من از تجربه خودم می دانم که این چقدر دشوار است."}]},{"word":"erfinden","en":"to invent","ru":"изобретать","vi":"phát minh","fa":"اختراع کردن","examples":[{"de":"Wer hat das Telefon erfunden?","en":"Who invented the telephone?","ru":"Кто изобрёл телефон?","vi":"Ai đã phát minh ra điện thoại?","fa":"چه کسی تلفن را اختراع کرد؟"},{"de":"Er erfindet gern Geschichten für seine Kinder.","en":"He likes inventing stories for his children.","ru":"Он любит придумывать истории для своих детей.","vi":"Anh ấy thích bịa ra những câu chuyện cho con mình.","fa":"او دوست دارد برای فرزندانش داستان بسازد."}]},{"word":"die Erfindung","en":"invention","ru":"изобретение","vi":"phát minh","fa":"اختراع","examples":[{"de":"Das Internet ist eine wichtige Erfindung.","en":"The internet is an important invention.","ru":"Интернет — важное изобретение.","vi":"Internet là một phát minh quan trọng.","fa":"اینترنت یک اختراع مهم است."},{"de":"Die Erfindung des Rades veränderte die Welt.","en":"The invention of the wheel changed the world.","ru":"Изобретение колеса изменило мир.","vi":"Việc phát minh ra bánh xe đã thay đổi thế giới.","fa":"اختراع چرخ دنیا را تغییر داد."}]},{"word":"der Erfolg","en":"success","ru":"успех","vi":"sự thành công","fa":"موفقیت","examples":[{"de":"Ich wünsche dir viel Erfolg bei der Prüfung.","en":"I wish you great success in the exam.","ru":"Желаю тебе большого успеха на экзамене.","vi":"Tôi chúc bạn thành công trong kỳ thi.","fa":"برای شما در امتحان آرزوی موفقیت دارم."},{"de":"Das neue Produkt war ein großer Erfolg.","en":"The new product was a great success.","ru":"Новый продукт имел большой успех.","vi":"Sản phẩm mới đã thành công rực rỡ.","fa":"محصول جدید یک موفقیت بزرگ بود."}]},{"word":"erfolgreich","en":"successful","ru":"успешный","vi":"thành công","fa":"موفق","examples":[{"de":"Die Firma ist in den letzten Jahren sehr erfolgreich.","en":"The company has been very successful in recent years.","ru":"Компания очень успешна в последние годы.","vi":"Công ty đã rất thành công trong những năm gần đây.","fa":"این شرکت در سال های اخیر بسیار موفق بوده است."},{"de":"Der Versuch war erfolgreich.","en":"The attempt was successful.","ru":"Попытка была успешной.","vi":"Nỗ lực đã thành công.","fa":"تلاش موفقیت آمیز بود."}]},{"word":"erforderlich","en":"required, necessary","ru":"необходимый, требуемый","vi":"bắt buộc","fa":"مورد نیاز است","examples":[{"de":"Für diese Stelle ist ein Studium erforderlich.","en":"A university degree is required for this position.","ru":"Для этой должности требуется высшее образование.","vi":"Vị trí này cần có bằng cấp.","fa":"مدرک تحصیلی برای این موقعیت الزامی است."},{"de":"Welche Unterlagen sind für den Antrag erforderlich?","en":"Which documents are required for the application?","ru":"Какие документы необходимы для заявления?","vi":"Những tài liệu cần thiết cho ứng dụng?","fa":"چه مدارکی برای درخواست نیاز است؟"}]},{"word":"erfordern","en":"to require","ru":"требовать (чего-л.)","vi":"yêu cầu","fa":"نیاز دارند","examples":[{"de":"Diese Arbeit erfordert viel Geduld.","en":"This work requires a lot of patience.","ru":"Эта работа требует много терпения.","vi":"Công việc này đòi hỏi rất nhiều sự kiên nhẫn.","fa":"این کار به صبر و حوصله زیادی نیاز دارد."},{"de":"Der Job erfordert gute Englischkenntnisse.","en":"The job requires good English skills.","ru":"Работа требует хорошего знания английского.","vi":"Công việc yêu cầu kỹ năng tiếng Anh tốt.","fa":"این شغل به مهارت خوب انگلیسی نیاز دارد."}]},{"word":"erfüllen","en":"to fulfill","ru":"исполнять, выполнять","vi":"thực hiện","fa":"برآورده کند","examples":[{"de":"Er hat sich seinen Traum erfüllt.","en":"He fulfilled his dream.","ru":"Он исполнил свою мечту.","vi":"Anh ấy đã thực hiện được ước mơ của mình.","fa":"او به آرزویش رسیده است."},{"de":"Die Bewerberin erfüllt alle Voraussetzungen.","en":"The applicant fulfills all the requirements.","ru":"Соискательница соответствует всем требованиям.","vi":"Người nộp đơn đáp ứng tất cả các yêu cầu.","fa":"متقاضی تمام شرایط را دارد."}]},{"word":"ergänzen","en":"to complete, add to, supplement","ru":"дополнять","vi":"bổ sung","fa":"مکمل","examples":[{"de":"Bitte ergänzen Sie die fehlenden Wörter im Text.","en":"Please fill in the missing words in the text.","ru":"Пожалуйста, дополните недостающие слова в тексте.","vi":"Hãy điền những từ còn thiếu trong đoạn văn.","fa":"لطفا کلمات جا افتاده در متن را پر کنید."},{"de":"Die beiden Kollegen ergänzen sich gut.","en":"The two colleagues complement each other well.","ru":"Эти два коллеги хорошо дополняют друг друга.","vi":"Hai đồng nghiệp bổ sung cho nhau rất tốt.","fa":"این دو همکار به خوبی یکدیگر را تکمیل می کنند."}]},{"word":"das Ergebnis","en":"result","ru":"результат","vi":"kết quả","fa":"نتیجه","examples":[{"de":"Das Ergebnis der Prüfung war sehr gut.","en":"The result of the exam was very good.","ru":"Результат экзамена был очень хорошим.","vi":"Kết quả của bài kiểm tra là rất tốt.","fa":"نتیجه آزمایش خیلی خوب بود."},{"de":"Wir warten noch auf das Ergebnis der Untersuchung.","en":"We are still waiting for the result of the examination.","ru":"Мы всё ещё ждём результат обследования.","vi":"Chúng tôi vẫn đang chờ kết quả điều tra.","fa":"ما همچنان منتظر نتیجه تحقیقات هستیم."}]},{"word":"erhalten","en":"to receive; to preserve","ru":"получать; сохранять","vi":"đã nhận được","fa":"دریافت کرد","examples":[{"de":"Ich habe gestern deinen Brief erhalten.","en":"I received your letter yesterday.","ru":"Я вчера получил твоё письмо.","vi":"Tôi đã nhận được thư của bạn ngày hôm qua.","fa":"نامه شما را دیروز دریافت کردم."},{"de":"Wir müssen die Natur für die nächste Generation erhalten.","en":"We must preserve nature for the next generation.","ru":"Мы должны сохранить природу для следующего поколения.","vi":"Chúng ta phải bảo tồn thiên nhiên cho thế hệ tiếp theo.","fa":"ما باید طبیعت را برای نسل آینده حفظ کنیم."}]},{"word":"erheblich","en":"considerable; significant","ru":"значительный; существенный","vi":"đáng kể","fa":"بطور قابل توجهی","examples":[{"de":"Die Kosten sind erheblich gestiegen.","en":"The costs have risen considerably.","ru":"Расходы значительно возросли.","vi":"Các chi phí đã tăng lên đáng kể.","fa":"هزینه ها به میزان قابل توجهی افزایش یافته است."},{"de":"Es gibt einen erheblichen Unterschied zwischen den Angeboten.","en":"There is a significant difference between the offers.","ru":"Между предложениями есть существенная разница.","vi":"Có một sự khác biệt đáng kể giữa các ưu đãi.","fa":"تفاوت قابل توجهی بین پیشنهادات وجود دارد."}]},{"word":"erhöhen","en":"to raise, increase","ru":"повышать","vi":"tăng lên","fa":"افزایش دهد","examples":[{"de":"Der Vermieter will die Miete erhöhen.","en":"The landlord wants to raise the rent.","ru":"Арендодатель хочет повысить арендную плату.","vi":"Chủ nhà muốn tăng tiền thuê nhà.","fa":"صاحبخانه می خواهد اجاره بها را افزایش دهد."},{"de":"Sport kann die Konzentration erhöhen.","en":"Exercise can increase concentration.","ru":"Спорт может повысить концентрацию.","vi":"Tập thể dục có thể làm tăng sự tập trung.","fa":"ورزش می تواند تمرکز را افزایش دهد."}]},{"word":"erinnern","en":"to remind; sich erinnern: to remember","ru":"напоминать; sich erinnern: вспоминать","vi":"nhớ","fa":"به یاد داشته باشید","examples":[{"de":"Kannst du mich morgen an den Termin erinnern?","en":"Can you remind me of the appointment tomorrow?","ru":"Можешь напомнить мне завтра о встрече?","vi":"Bạn có thể nhắc tôi về cuộc hẹn ngày mai được không?","fa":"میشه قرار فردا رو بهم یادآوری کنی؟"},{"de":"Ich erinnere mich gut an meine Kindheit.","en":"I remember my childhood well.","ru":"Я хорошо помню своё детство.","vi":"Tôi nhớ rất rõ thời thơ ấu của mình.","fa":"کودکی ام را خوب به یاد دارم."}]},{"word":"die Erinnerung","en":"memory; recollection","ru":"воспоминание","vi":"ký ức","fa":"حافظه","examples":[{"de":"Ich habe schöne Erinnerungen an meine Kindheit.","en":"I have fond memories of my childhood.","ru":"У меня приятные воспоминания о детстве.","vi":"Tôi có những kỷ niệm đẹp về thời thơ ấu của mình.","fa":"خاطرات خوبی از کودکی ام دارم."},{"de":"Zur Erinnerung an die Reise haben wir viele Fotos gemacht.","en":"As a memento of the trip, we took lots of photos.","ru":"На память о поездке мы сделали много фотографий.","vi":"Chúng tôi đã chụp rất nhiều ảnh để ghi nhớ chuyến đi.","fa":"برای یادآوری این سفر عکس های زیادی گرفتیم."}]},{"word":"erkennen","en":"to recognize","ru":"узнавать, распознавать","vi":"nhận ra","fa":"تشخیص دهد","examples":[{"de":"Ich habe ihn sofort erkannt, obwohl er sich verändert hat.","en":"I recognized him immediately, even though he has changed.","ru":"Я сразу его узнал, хотя он изменился.","vi":"Tôi nhận ra anh ngay lập tức, mặc dù anh đã thay đổi.","fa":"با وجود اینکه تغییر کرده بود، بلافاصله او را شناختم."},{"de":"Man kann das Problem schnell erkennen.","en":"One can quickly recognize the problem.","ru":"Проблему можно быстро распознать.","vi":"Bạn có thể nhanh chóng xác định vấn đề.","fa":"می توانید به سرعت مشکل را شناسایی کنید."}]},{"word":"erklären","en":"to explain","ru":"объяснять","vi":"giải thích","fa":"توضیح دهید","examples":[{"de":"Der Lehrer erklärt die Grammatik sehr gut.","en":"The teacher explains the grammar very well.","ru":"Учитель очень хорошо объясняет грамматику.","vi":"Thầy giảng ngữ pháp rất hay.","fa":"معلم گرامر را خیلی خوب توضیح می دهد."},{"de":"Kannst du mir erklären, wie das Gerät funktioniert?","en":"Can you explain to me how the device works?","ru":"Можешь объяснить мне, как работает это устройство?","vi":"Bạn có thể giải thích cho tôi cách hoạt động của thiết bị không?","fa":"میشه برام توضیح بدید دستگاه چطور کار میکنه؟"}]},{"word":"erlauben","en":"to allow, permit","ru":"разрешать","vi":"cho phép","fa":"اجازه می دهد","examples":[{"de":"Meine Eltern erlauben mir, am Wochenende länger auszugehen.","en":"My parents allow me to go out longer on weekends.","ru":"Родители разрешают мне гулять дольше по выходным.","vi":"Bố mẹ tôi cho phép tôi đi chơi lâu hơn vào cuối tuần.","fa":"والدینم به من اجازه می دهند آخر هفته ها بیشتر بیرون بروم."},{"de":"Rauchen ist hier nicht erlaubt.","en":"Smoking is not allowed here.","ru":"Курить здесь не разрешается.","vi":"Hút thuốc không được phép ở đây.","fa":"سیگار کشیدن در اینجا ممنوع است."}]},{"word":"erleben","en":"to experience","ru":"переживать, испытывать (событие)","vi":"kinh nghiệm","fa":"تجربه","examples":[{"de":"Wir haben im Urlaub viele schöne Dinge erlebt.","en":"We experienced many wonderful things on vacation.","ru":"В отпуске мы пережили много прекрасных моментов.","vi":"Chúng tôi đã trải nghiệm nhiều điều đẹp đẽ trong kỳ nghỉ.","fa":"ما در تعطیلات چیزهای زیبایی را تجربه کردیم."},{"de":"Er hat den Krieg als Kind erlebt.","en":"He experienced the war as a child.","ru":"Он пережил войну ребёнком.","vi":"Ông đã trải qua chiến tranh khi còn nhỏ.","fa":"او جنگ را از کودکی تجربه کرد."}]},{"word":"erledigen","en":"to take care of, complete (a task)","ru":"выполнять, улаживать (дело)","vi":"làm","fa":"انجام دهید","examples":[{"de":"Ich muss noch ein paar Einkäufe erledigen.","en":"I still need to take care of some shopping.","ru":"Мне ещё нужно сделать кое-какие покупки.","vi":"Tôi vẫn phải đi mua sắm.","fa":"هنوز باید خرید کنم."},{"de":"Hast du die Aufgabe schon erledigt?","en":"Have you already completed the task?","ru":"Ты уже выполнил задание?","vi":"Bạn đã hoàn thành nhiệm vụ chưa?","fa":"آیا قبلاً کار را انجام داده اید؟"}]},{"word":"erleichtern","en":"to make easier, ease","ru":"облегчать","vi":"tạo điều kiện thuận lợi","fa":"تسهیل کند","examples":[{"de":"Der neue Computer erleichtert uns die Arbeit.","en":"The new computer makes our work easier.","ru":"Новый компьютер облегчает нам работу.","vi":"Máy tính mới làm cho công việc của chúng tôi dễ dàng hơn.","fa":"کامپیوتر جدید کار ما را آسان می کند."},{"de":"Diese App erleichtert das Lernen von Vokabeln.","en":"This app makes learning vocabulary easier.","ru":"Это приложение облегчает изучение слов.","vi":"Ứng dụng này giúp việc học từ vựng dễ dàng hơn.","fa":"این برنامه یادگیری لغات را آسان تر می کند."}]},{"word":"die Ermäßigung","en":"discount, reduction (in price)","ru":"скидка","vi":"giảm giá","fa":"تخفیف","examples":[{"de":"Studenten bekommen eine Ermäßigung auf den Eintritt.","en":"Students get a discount on admission.","ru":"Студенты получают скидку на вход.","vi":"Sinh viên được giảm giá khi nhập học.","fa":"دانشجویان در پذیرش از تخفیف برخوردار می شوند."},{"de":"Gibt es eine Ermäßigung für Kinder?","en":"Is there a discount for children?","ru":"Есть ли скидка для детей?","vi":"Có giảm giá cho trẻ em không?","fa":"برای بچه ها تخفیف داره؟"}]},{"word":"ermöglichen","en":"to make possible; to enable","ru":"делать возможным; позволять","vi":"kích hoạt","fa":"فعال کردن","examples":[{"de":"Ein Stipendium ermöglichte ihr das Studium im Ausland.","en":"A scholarship made it possible for her to study abroad.","ru":"Стипендия позволила ей учиться за границей.","vi":"Một học bổng đã giúp cô đi du học.","fa":"بورسیه تحصیلی او را قادر به تحصیل در خارج از کشور کرد."},{"de":"Neue Technik ermöglicht schnelleres Arbeiten.","en":"New technology enables faster work.","ru":"Новые технологии позволяют работать быстрее.","vi":"Công nghệ mới cho phép làm việc nhanh hơn.","fa":"فناوری جدید کار سریعتر را امکان پذیر می کند."}]},{"word":"ernähren","en":"to feed, nourish; sich ernähren: to eat, feed oneself","ru":"кормить; sich ernähren: питаться","vi":"thức ăn","fa":"خوراک","examples":[{"de":"Sie ernährt ihre Familie mit dem Geld aus zwei Jobs.","en":"She feeds her family with money from two jobs.","ru":"Она содержит семью на деньги с двух работ.","vi":"Cô hỗ trợ gia đình bằng số tiền từ hai công việc.","fa":"او با پول دو شغل خرج خانواده اش را می دهد."},{"de":"Er ernährt sich sehr gesund.","en":"He eats very healthily.","ru":"Он питается очень здорово.","vi":"Anh ấy ăn uống rất khỏe mạnh.","fa":"او خیلی سالم غذا می خورد."}]},{"word":"die Ernährung","en":"nutrition; diet","ru":"питание","vi":"chế độ ăn kiêng","fa":"رژیم غذایی","examples":[{"de":"Eine gesunde Ernährung ist die halbe Miete.","en":"A healthy diet is half the battle.","ru":"Здоровое питание — это уже половина дела.","vi":"Một chế độ ăn uống lành mạnh là một nửa trận chiến.","fa":"یک رژیم غذایی سالم نیمی از کار است."},{"de":"Er achtet sehr auf seine Ernährung.","en":"He pays close attention to his diet.","ru":"Он очень внимательно относится к своему питанию.","vi":"Anh ấy rất chú ý đến chế độ ăn uống của mình.","fa":"او به رژیم غذایی خود اهمیت زیادی می دهد."}]},{"word":"erneuerbar","en":"renewable","ru":"возобновляемый","vi":"tái tạo","fa":"قابل تجدید","examples":[{"de":"Sonne und Wind sind erneuerbare Energiequellen.","en":"Sun and wind are renewable energy sources.","ru":"Солнце и ветер — возобновляемые источники энергии.","vi":"Mặt trời và gió là nguồn năng lượng tái tạo.","fa":"خورشید و باد منابع انرژی تجدیدپذیر هستند."},{"de":"Immer mehr Strom kommt aus erneuerbaren Quellen.","en":"More and more electricity comes from renewable sources.","ru":"Всё больше электроэнергии поступает из возобновляемых источников.","vi":"Ngày càng có nhiều điện đến từ các nguồn tái tạo.","fa":"برق بیشتر و بیشتر از منابع تجدید پذیر تامین می شود."}]},{"word":"ernst","en":"serious","ru":"серьёзный","vi":"nghiêm túc","fa":"به طور جدی","examples":[{"de":"Das ist eine ernste Angelegenheit.","en":"This is a serious matter.","ru":"Это серьёзное дело.","vi":"Đây là một vấn đề nghiêm trọng.","fa":"این یک موضوع جدی است."},{"de":"Er sah plötzlich sehr ernst aus.","en":"He suddenly looked very serious.","ru":"Он вдруг стал выглядеть очень серьёзно.","vi":"Anh ấy đột nhiên trông rất nghiêm túc.","fa":"او ناگهان بسیار جدی به نظر می رسد."}]},{"word":"die Ernte","en":"harvest","ru":"урожай","vi":"thu hoạch","fa":"برداشت","examples":[{"de":"Die Bauern sind mit der Ernte beschäftigt.","en":"The farmers are busy with the harvest.","ru":"Фермеры заняты сбором урожая.","vi":"Nông dân đang tất bật thu hoạch.","fa":"کشاورزان مشغول برداشت محصول هستند."},{"de":"Dieses Jahr war die Ernte besonders gut.","en":"This year the harvest was especially good.","ru":"В этом году урожай был особенно хорошим.","vi":"Năm nay thu hoạch đặc biệt tốt.","fa":"امسال برداشت به ویژه خوب بود."}]},{"word":"eröffnen","en":"to open (a business, account, exhibition)","ru":"открывать (бизнес, счёт, выставку)","vi":"mở","fa":"باز کردن","examples":[{"de":"Sie hat letzten Monat ein neues Geschäft eröffnet.","en":"She opened a new shop last month.","ru":"В прошлом месяце она открыла новый магазин.","vi":"Cô ấy đã mở một cửa hàng mới vào tháng trước.","fa":"او ماه گذشته یک فروشگاه جدید افتتاح کرد."},{"de":"Ich möchte ein Konto bei dieser Bank eröffnen.","en":"I would like to open an account at this bank.","ru":"Я хотел бы открыть счёт в этом банке.","vi":"Tôi muốn mở một tài khoản ở ngân hàng này.","fa":"من می خواهم در این بانک حساب باز کنم."}]},{"word":"erreichen","en":"to reach, achieve","ru":"достигать","vi":"đạt được","fa":"رسیدن","examples":[{"de":"Wir haben unser Ziel endlich erreicht.","en":"We have finally reached our goal.","ru":"Мы наконец достигли своей цели.","vi":"Cuối cùng chúng tôi đã đạt được mục tiêu của mình.","fa":"بالاخره به هدفمون رسیدیم."},{"de":"Ich kann ihn telefonisch nicht erreichen.","en":"I can't reach him by phone.","ru":"Я не могу дозвониться до него.","vi":"Tôi không thể liên lạc với anh ấy qua điện thoại.","fa":"با تلفن نمی توانم با او تماس بگیرم."}]},{"word":"erschöpft","en":"exhausted","ru":"измождённый, истощённый","vi":"kiệt sức","fa":"خسته","examples":[{"de":"Nach dem Marathon war sie völlig erschöpft.","en":"After the marathon she was completely exhausted.","ru":"После марафона она была совершенно измотана.","vi":"Sau cuộc chạy marathon cô ấy hoàn toàn kiệt sức.","fa":"پس از ماراتن او کاملا خسته بود."},{"de":"Ich bin heute Abend total erschöpft von der Arbeit.","en":"I am totally exhausted from work this evening.","ru":"Сегодня вечером я совершенно измотан работой.","vi":"Tôi hoàn toàn kiệt sức vì làm việc tối nay.","fa":"امروز عصر کاملا از سر کار خسته شدم."}]},{"word":"erschrecken","en":"to be startled, frightened","ru":"пугаться","vi":"sợ hãi","fa":"ترساندن","examples":[{"de":"Ich bin erschrocken, als das Telefon plötzlich klingelte.","en":"I got startled when the phone suddenly rang.","ru":"Я испугался, когда вдруг зазвонил телефон.","vi":"Tôi giật mình khi điện thoại đột nhiên reo lên.","fa":"وقتی ناگهان تلفن زنگ خورد، از جا پریدم."},{"de":"Sie erschrickt leicht bei lauten Geräuschen.","en":"She gets startled easily by loud noises.","ru":"Она легко пугается громких звуков.","vi":"Cô ấy dễ bị giật mình bởi những tiếng động lớn.","fa":"او به راحتی با صداهای بلند مبهوت می شود."}]},{"word":"ersetzen","en":"to replace","ru":"заменять","vi":"thay thế","fa":"جایگزین کنید","examples":[{"de":"Wir müssen den alten Drucker ersetzen.","en":"We need to replace the old printer.","ru":"Нам нужно заменить старый принтер.","vi":"Chúng ta cần thay thế máy in cũ.","fa":"باید چاپگر قدیمی را تعویض کنیم."},{"de":"Kein Buch kann persönliche Erfahrung ersetzen.","en":"No book can replace personal experience.","ru":"Ни одна книга не может заменить личный опыт.","vi":"Không có cuốn sách nào có thể thay thế được trải nghiệm cá nhân.","fa":"هیچ کتابی نمی تواند جایگزین تجربه شخصی شود."}]},{"word":"erst","en":"only, not until (temporal); first","ru":"только, лишь (о времени); сначала","vi":"đầu tiên","fa":"اول","examples":[{"de":"Der Zug kommt erst um 18 Uhr an.","en":"The train doesn't arrive until 6 p.m.","ru":"Поезд прибывает только в 18 часов.","vi":"Xe lửa không đến cho đến 6 giờ chiều.","fa":"قطار تا ساعت 6 عصر نمی رسد."},{"de":"Ich bin erst seit einer Woche hier.","en":"I've only been here for a week.","ru":"Я здесь только неделю.","vi":"Tôi mới ở đây được một tuần.","fa":"من فقط یک هفته اینجا هستم"}]},{"word":"erst-","en":"first (stem meaning 'first')","ru":"перво- (основа со значением 'первый')","vi":"đầu tiên-","fa":"اول -","examples":[{"de":"Das Hotel bietet einen erstklassigen Service.","en":"The hotel offers first-class service.","ru":"Отель предлагает первоклассный сервис.","vi":"Khách sạn cung cấp dịch vụ hạng nhất.","fa":"این هتل خدمات درجه یک ارائه می دهد."},{"de":"Dieses Restaurant serviert erstklassiges Essen.","en":"This restaurant serves first-class food.","ru":"Этот ресторан подаёт первоклассную еду.","vi":"Nhà hàng này phục vụ các món ăn chất lượng hàng đầu.","fa":"این رستوران غذاهایی با کیفیت عالی سرو می کند."}]},{"word":"erstellen","en":"to create, draw up (a document, plan)","ru":"составлять, создавать (документ)","vi":"tạo ra","fa":"ایجاد کنید","examples":[{"de":"Der Architekt erstellt einen Plan für das neue Haus.","en":"The architect draws up a plan for the new house.","ru":"Архитектор составляет план нового дома.","vi":"Kiến trúc sư tạo ra một kế hoạch cho ngôi nhà mới.","fa":"معمار نقشه ای برای خانه جدید ایجاد می کند."},{"de":"Ich muss noch eine Liste für den Einkauf erstellen.","en":"I still need to create a list for shopping.","ru":"Мне ещё нужно составить список покупок.","vi":"Tôi vẫn phải lập danh sách mua sắm.","fa":"من هنوز باید یک لیست خرید تهیه کنم."}]},{"word":"erwachsen","en":"grown-up, adult","ru":"взрослый (прил.)","vi":"người lớn","fa":"بالغ","examples":[{"de":"Seine Kinder sind schon erwachsen.","en":"His children are already grown up.","ru":"Его дети уже взрослые.","vi":"Các con của anh đều đã trưởng thành rồi.","fa":"فرزندان او در حال حاضر بالغ هستند."},{"de":"Sie benimmt sich sehr erwachsen für ihr Alter.","en":"She behaves very maturely for her age.","ru":"Она ведёт себя очень по-взрослому для своего возраста.","vi":"Cô ấy hành động rất chững chạc so với tuổi của mình.","fa":"او نسبت به سنش بسیار بالغ عمل می کند."}]},{"word":"der Erwachsene","en":"adult (person)","ru":"взрослый (человек)","vi":"người lớn","fa":"بزرگسال","examples":[{"de":"Der Eintritt kostet für Erwachsene zehn Euro.","en":"Admission costs ten euros for adults.","ru":"Вход стоит десять евро для взрослых.","vi":"Vé vào cửa có giá 10 euro cho người lớn.","fa":"هزینه ورودی برای بزرگسالان ده یورو است."},{"de":"Dieser Film ist nur für Erwachsene geeignet.","en":"This movie is suitable only for adults.","ru":"Этот фильм подходит только для взрослых.","vi":"Phim này chỉ phù hợp với người lớn thôi.","fa":"این فیلم فقط برای بزرگسالان مناسب است."}]},{"word":"erwähnen","en":"to mention","ru":"упоминать","vi":"đề cập đến","fa":"ذکر کنید","examples":[{"de":"Sie hat mit keinem Wort das Problem erwähnt.","en":"She didn't mention the problem with a single word.","ru":"Она ни словом не упомянула о проблеме.","vi":"Cô ấy không đề cập đến vấn đề gì cả.","fa":"او اصلاً به مشکل اشاره نکرد."},{"de":"Wie ich schon erwähnt habe, fängt die Sitzung um zehn an.","en":"As I already mentioned, the meeting starts at ten.","ru":"Как я уже упомянул, собрание начинается в десять.","vi":"Như tôi đã đề cập, cuộc họp bắt đầu lúc 10 giờ.","fa":"همانطور که اشاره کردم جلسه ساعت ده شروع می شود."}]},{"word":"die Erwärmung","en":"warming","ru":"потепление","vi":"sự nóng lên","fa":"گرم شدن","examples":[{"de":"Die globale Erwärmung lässt die Gletscher schmelzen.","en":"Global warming is melting the glaciers.","ru":"Глобальное потепление растапливает ледники.","vi":"Sự nóng lên toàn cầu đang khiến các sông băng tan chảy.","fa":"گرم شدن کره زمین باعث آب شدن یخچال های طبیعی می شود."},{"de":"Schon eine kleine Erwärmung kann große Folgen haben.","en":"Even a small amount of warming can have major consequences.","ru":"Даже небольшое потепление может иметь серьёзные последствия.","vi":"Ngay cả một lượng nhỏ sự nóng lên cũng có thể gây ra hậu quả lớn.","fa":"حتی مقدار کمی گرم شدن می تواند عواقب بزرگی داشته باشد."}]},{"word":"erwarten","en":"to expect","ru":"ожидать","vi":"mong đợi","fa":"انتظار می رود","examples":[{"de":"Wir erwarten Gäste zum Abendessen.","en":"We are expecting guests for dinner.","ru":"Мы ожидаем гостей к ужину.","vi":"Chúng tôi đang chờ khách đến ăn tối.","fa":"برای شام منتظر مهمان هستیم."},{"de":"Sie erwartet ein Kind im Herbst.","en":"She is expecting a baby in the fall.","ru":"Осенью она ждёт ребёнка.","vi":"Cô ấy đang mong đợi một đứa trẻ vào mùa thu.","fa":"او در پاییز در انتظار بچه دار شدن است."}]},{"word":"erzählen","en":"to tell (a story), narrate","ru":"рассказывать","vi":"nói","fa":"بگو","examples":[{"de":"Meine Oma erzählt gerne Geschichten aus ihrer Jugend.","en":"My grandma likes to tell stories from her youth.","ru":"Моя бабушка любит рассказывать истории из своей молодости.","vi":"Bà tôi thích kể những câu chuyện thời trẻ của bà.","fa":"مادربزرگم دوست دارد از دوران جوانی خود قصه بگوید."},{"de":"Erzähl mir, wie dein Tag war.","en":"Tell me how your day was.","ru":"Расскажи мне, как прошёл твой день.","vi":"Hãy kể cho tôi nghe ngày hôm nay của bạn thế nào.","fa":"بگو روزت چطور بود"}]},{"word":"erziehen","en":"to raise, bring up (a child)","ru":"воспитывать","vi":"giáo dục","fa":"آموزش دهد","examples":[{"de":"Die Eltern erziehen ihre Kinder zur Selbstständigkeit.","en":"The parents raise their children to be independent.","ru":"Родители воспитывают детей самостоятельными.","vi":"Cha mẹ nuôi dạy con cái có tính tự lập.","fa":"والدین فرزندان خود را مستقل تربیت می کنند."},{"de":"Es ist nicht einfach, drei Kinder zu erziehen.","en":"It is not easy to raise three children.","ru":"Непросто воспитывать троих детей.","vi":"Nuôi ba đứa con không hề dễ dàng.","fa":"بزرگ کردن سه فرزند آسان نیست."}]},{"word":"es","en":"it","ru":"оно; это","vi":"nó","fa":"آن را","examples":[{"de":"Es regnet heute den ganzen Tag.","en":"It is raining all day today.","ru":"Сегодня весь день идёт дождь.","vi":"Hôm nay trời mưa cả ngày.","fa":"امروز تمام روز باران می بارد."},{"de":"Wo ist das Buch? Es liegt auf dem Tisch.","en":"Where is the book? It's on the table.","ru":"Где книга? Она лежит на столе.","vi":"Cuốn sách ở đâu? Nó ở trên bàn.","fa":"کتاب کجاست؟ روی میز است."}]},{"word":"essen","en":"to eat","ru":"есть, кушать","vi":"ăn","fa":"خوردن","examples":[{"de":"Wir essen jeden Abend gemeinsam zu Hause.","en":"We eat together at home every evening.","ru":"Мы каждый вечер вместе едим дома.","vi":"Chúng tôi ăn cùng nhau ở nhà vào mỗi buổi tối.","fa":"هر روز عصر با هم در خانه غذا می خوریم."},{"de":"Was möchtest du heute zu Mittag essen?","en":"What would you like to eat for lunch today?","ru":"Что ты хочешь съесть сегодня на обед?","vi":"Bạn muốn ăn gì cho bữa trưa hôm nay?","fa":"دوست داری امروز ناهار چی بخوری؟"}]},{"word":"der Essig","en":"vinegar","ru":"уксус","vi":"giấm","fa":"سرکه","examples":[{"de":"Für den Salat brauchen wir Öl und Essig.","en":"For the salad we need oil and vinegar.","ru":"Для салата нам нужны масло и уксус.","vi":"Đối với món salad chúng ta cần dầu và giấm.","fa":"برای سالاد به روغن و سرکه نیاز داریم."},{"de":"Sie würzt die Soße mit etwas Essig.","en":"She seasons the sauce with a bit of vinegar.","ru":"Она приправляет соус небольшим количеством уксуса.","vi":"Cô nêm nước sốt với một ít giấm.","fa":"سس را با کمی سرکه مزه دار می کند."}]},{"word":"die Etage","en":"floor, storey","ru":"этаж","vi":"sàn nhà","fa":"کف","examples":[{"de":"Unsere Wohnung liegt in der dritten Etage.","en":"Our apartment is on the third floor.","ru":"Наша квартира находится на третьем этаже.","vi":"Căn hộ của chúng tôi ở trên tầng ba.","fa":"آپارتمان ما در طبقه سوم است."},{"de":"Der Aufzug fährt nicht in die oberste Etage.","en":"The elevator doesn't go to the top floor.","ru":"Лифт не едет на самый верхний этаж.","vi":"Thang máy không đi lên tầng trên cùng.","fa":"آسانسور به طبقه بالا نمی رود."}]},{"word":"etwa","en":"about, approximately","ru":"примерно, около","vi":"về","fa":"در مورد","examples":[{"de":"Die Fahrt dauert etwa zwei Stunden.","en":"The trip takes about two hours.","ru":"Поездка занимает примерно два часа.","vi":"Cuộc hành trình mất khoảng hai giờ.","fa":"سفر تقریبا دو ساعت طول می کشد."},{"de":"Er wiegt etwa achtzig Kilo.","en":"He weighs about eighty kilos.","ru":"Он весит примерно восемьдесят килограммов.","vi":"Anh ta nặng khoảng tám mươi kg.","fa":"او حدود هشتاد کیلو وزن دارد."}]},{"word":"etwas","en":"something; a little, somewhat","ru":"что-то; немного","vi":"cái gì đó","fa":"چیزی","examples":[{"de":"Möchtest du etwas trinken?","en":"Would you like something to drink?","ru":"Хочешь что-нибудь выпить?","vi":"Bạn có muốn uống gì không?","fa":"آیا می خواهید چیزی بنوشید؟"},{"de":"Ich bin heute etwas müde.","en":"I am somewhat tired today.","ru":"Сегодня я немного устал.","vi":"Hôm nay tôi hơi mệt.","fa":"امروز کمی خسته ام."}]},{"word":"eventuell","en":"possibly, perhaps","ru":"возможно, при случае","vi":"có thể","fa":"احتمالا","examples":[{"de":"Wir kommen eventuell etwas später.","en":"We might come a bit later.","ru":"Возможно, мы придём немного позже.","vi":"Chúng tôi có thể đến muộn hơn một chút.","fa":"شاید کمی دیرتر بیاییم"},{"de":"Eventuell brauchen wir noch einen zweiten Termin.","en":"We might possibly need a second appointment.","ru":"Возможно, нам понадобится ещё одна встреча.","vi":"Chúng ta có thể cần một cuộc hẹn thứ hai.","fa":"ممکن است به قرار دوم نیاز داشته باشیم."}]},{"word":"ewig","en":"eternal; (colloq.) forever, ages","ru":"вечный; (разг.) целую вечность","vi":"mãi mãi","fa":"برای همیشه","examples":[{"de":"Nichts ist ewig, alles verändert sich.","en":"Nothing is eternal, everything changes.","ru":"Ничто не вечно, всё меняется.","vi":"Không có gì tồn tại mãi mãi, mọi thứ đều thay đổi.","fa":"هیچ چیز برای همیشه ماندگار نیست، همه چیز تغییر می کند."},{"de":"Ich habe ewig auf den Bus gewartet.","en":"I waited an eternity for the bus.","ru":"Я целую вечность ждал автобус.","vi":"Tôi đợi xe buýt mãi mãi.","fa":"برای همیشه منتظر اتوبوس بودم."}]},{"word":"der Experte","en":"expert","ru":"эксперт","vi":"chuyên gia","fa":"کارشناس","examples":[{"de":"Ein Experte hat uns bei der Reparatur geholfen.","en":"An expert helped us with the repair.","ru":"Эксперт помог нам с ремонтом.","vi":"Một chuyên gia đã giúp chúng tôi sửa chữa.","fa":"یک متخصص در تعمیر به ما کمک کرد."},{"de":"Sie ist Expertin für erneuerbare Energien.","en":"She is an expert in renewable energy.","ru":"Она эксперт по возобновляемой энергии.","vi":"Cô ấy là chuyên gia về năng lượng tái tạo.","fa":"او متخصص انرژی های تجدیدپذیر است."}]},{"word":"der Export","en":"export","ru":"экспорт","vi":"xuất khẩu","fa":"صادرات","examples":[{"de":"Der Export von Autos ist wichtig für die Wirtschaft.","en":"The export of cars is important for the economy.","ru":"Экспорт автомобилей важен для экономики.","vi":"Việc xuất khẩu ô tô có ý nghĩa quan trọng đối với nền kinh tế.","fa":"صادرات خودرو برای اقتصاد مهم است."},{"de":"Die Firma lebt hauptsächlich vom Export.","en":"The company lives mainly on exports.","ru":"Компания живёт главным образом за счёт экспорта.","vi":"Công ty sống chủ yếu nhờ xuất khẩu.","fa":"این شرکت عمدتاً از طریق صادرات زندگی می کند."}]},{"word":"extra","en":"extra; specially, especially","ru":"дополнительно; специально","vi":"thêm","fa":"اضافی","examples":[{"de":"Ich habe die Karten extra für dich reserviert.","en":"I reserved the tickets especially for you.","ru":"Я забронировал билеты специально для тебя.","vi":"Tôi đã đặt vé đặc biệt cho bạn.","fa":"من بلیط ها را مخصوص شما رزرو کرده ام."},{"de":"Für das Gepäck muss man extra bezahlen.","en":"You have to pay extra for the luggage.","ru":"За багаж нужно платить дополнительно.","vi":"Bạn phải trả thêm tiền cho hành lý.","fa":"برای چمدان باید هزینه اضافی پرداخت کنید."}]},{"word":"extrem","en":"extreme","ru":"экстремальный, крайний","vi":"cực đoan","fa":"افراطی","examples":[{"de":"Die Hitze war diesen Sommer extrem.","en":"The heat was extreme this summer.","ru":"Жара этим летом была экстремальной.","vi":"Mùa hè năm nay nắng nóng cực độ.","fa":"تابستان امسال گرما شدید بود."},{"de":"Das war eine extrem schwierige Prüfung.","en":"That was an extremely difficult exam.","ru":"Это был крайне сложный экзамен.","vi":"Đây là một bài kiểm tra cực kỳ khó khăn.","fa":"این یک آزمون فوق العاده سخت بود."}]},{"word":"die Fabrik","en":"factory","ru":"фабрика, завод","vi":"nhà máy","fa":"کارخانه","examples":[{"de":"Mein Vater arbeitet in einer Fabrik.","en":"My father works in a factory.","ru":"Мой отец работает на заводе.","vi":"Bố tôi làm việc ở một nhà máy.","fa":"پدرم در یک کارخانه کار می کند."},{"de":"Die Fabrik produziert täglich tausend Autos.","en":"The factory produces a thousand cars daily.","ru":"Завод производит тысячу автомобилей в день.","vi":"Nhà máy sản xuất hàng nghìn chiếc ô tô mỗi ngày.","fa":"این کارخانه روزانه هزار خودرو تولید می کند."}]},{"word":"das Fach","en":"subject (school/academic); compartment","ru":"предмет (учебный); отделение (полки, шкафа)","vi":"chủ đề","fa":"موضوع","examples":[{"de":"Mathematik ist mein Lieblingsfach.","en":"Math is my favorite subject.","ru":"Математика — мой любимый предмет.","vi":"Toán học là môn học yêu thích của tôi.","fa":"ریاضی درس مورد علاقه من است."},{"de":"Leg die Dokumente in das obere Fach.","en":"Put the documents in the top compartment.","ru":"Положи документы в верхнее отделение.","vi":"Đặt tài liệu vào ngăn trên cùng.","fa":"اسناد را در محفظه بالایی قرار دهید."}]},{"word":"die Fähigkeit","en":"ability, skill","ru":"способность, умение","vi":"khả năng","fa":"توانایی","examples":[{"de":"Er hat die Fähigkeit, Probleme schnell zu lösen.","en":"He has the ability to solve problems quickly.","ru":"У него есть способность быстро решать проблемы.","vi":"Anh ấy có khả năng giải quyết vấn đề nhanh chóng.","fa":"او توانایی حل سریع مشکلات را دارد."},{"de":"Sprachliche Fähigkeiten sind im Beruf wichtig.","en":"Language skills are important in the profession.","ru":"Языковые способности важны в профессии.","vi":"Kỹ năng ngôn ngữ rất quan trọng trong công việc.","fa":"مهارت زبان در کار مهم است."}]},{"word":"die Fähigkeiten","en":"abilities; skills","ru":"способности; навыки","vi":"các kỹ năng","fa":"مهارت ها","examples":[{"de":"Sie hat die Fähigkeiten, ein Team zu leiten.","en":"She has the skills to lead a team.","ru":"У неё есть способности руководить командой.","vi":"Cô ấy có kỹ năng lãnh đạo một nhóm.","fa":"او مهارت رهبری یک تیم را دارد."},{"de":"Im Kurs entwickeln die Kinder neue Fähigkeiten.","en":"In the course the children develop new skills.","ru":"На курсе дети развивают новые навыки.","vi":"Trong suốt khóa học, trẻ em được phát triển các kỹ năng mới.","fa":"در طول دوره، کودکان مهارت های جدیدی را توسعه می دهند."}]},{"word":"fahren","en":"to drive; to go (by vehicle)","ru":"ехать, водить","vi":"lái xe","fa":"رانندگی کنید","examples":[{"de":"Wir fahren morgen mit dem Auto nach Berlin.","en":"Tomorrow we are driving to Berlin by car.","ru":"Завтра мы едем на машине в Берлин.","vi":"Ngày mai chúng ta sẽ đi Berlin bằng ô tô.","fa":"فردا با ماشین میریم برلین."},{"de":"Kannst du Fahrrad fahren?","en":"Can you ride a bike?","ru":"Ты умеешь кататься на велосипеде?","vi":"Bạn có thể đi xe đạp không?","fa":"آیا می توانی دوچرخه سواری کنی؟"}]},{"word":"die Fahrkarte","en":"(travel) ticket","ru":"проездной билет","vi":"vé","fa":"بلیط","examples":[{"de":"Ich habe meine Fahrkarte für den Zug schon online gekauft.","en":"I already bought my train ticket online.","ru":"Я уже купил билет на поезд онлайн.","vi":"Tôi đã mua vé tàu trực tuyến rồi.","fa":"من قبلا بلیط قطارم را آنلاین خریده ام."},{"de":"Ohne gültige Fahrkarte darf man nicht in den Zug einsteigen.","en":"You are not allowed to board the train without a valid ticket.","ru":"Без действующего билета нельзя садиться в поезд.","vi":"Bạn không được phép lên tàu nếu không có vé hợp lệ.","fa":"بدون بلیط معتبر اجازه سوار شدن به قطار را ندارید."}]},{"word":"das Fahrrad","en":"bicycle","ru":"велосипед","vi":"chiếc xe đạp","fa":"دوچرخه","examples":[{"de":"Ich fahre jeden Tag mit dem Fahrrad zur Arbeit.","en":"I ride my bicycle to work every day.","ru":"Я каждый день езжу на работу на велосипеде.","vi":"Tôi đạp xe đi làm hàng ngày.","fa":"من هر روز با دوچرخه به سر کار می روم."},{"de":"Sein Fahrrad wurde letzte Woche gestohlen.","en":"His bicycle was stolen last week.","ru":"Его велосипед украли на прошлой неделе.","vi":"Xe đạp của anh ấy đã bị đánh cắp vào tuần trước.","fa":"دوچرخه او هفته گذشته دزدیده شد."}]},{"word":"fair","en":"fair","ru":"честный, справедливый","vi":"công bằng","fa":"منصفانه","examples":[{"de":"Der Schiedsrichter hat fair entschieden.","en":"The referee made a fair decision.","ru":"Судья принял справедливое решение.","vi":"Trọng tài đã đưa ra quyết định công bằng.","fa":"داور تصمیم عادلانه ای گرفت."},{"de":"Wir sollten alle Mitarbeiter fair behandeln.","en":"We should treat all employees fairly.","ru":"Мы должны справедливо относиться ко всем сотрудникам.","vi":"Chúng ta nên đối xử công bằng với tất cả nhân viên.","fa":"ما باید با همه کارمندان منصفانه رفتار کنیم."}]},{"word":"der Faktor","en":"factor","ru":"фактор","vi":"yếu tố","fa":"عامل","examples":[{"de":"Zeit ist bei diesem Projekt ein wichtiger Faktor.","en":"Time is an important factor in this project.","ru":"Время — важный фактор в этом проекте.","vi":"Thời gian là một yếu tố quan trọng trong dự án này.","fa":"زمان عامل مهمی در این پروژه است."},{"de":"Gesunde Ernährung ist ein entscheidender Faktor für das Wohlbefinden.","en":"Healthy eating is a decisive factor for well-being.","ru":"Здоровое питание — решающий фактор для самочувствия.","vi":"Dinh dưỡng lành mạnh là yếu tố quan trọng để có được sức khỏe tốt.","fa":"تغذیه سالم عامل مهمی برای تندرستی است."}]},{"word":"der Fall","en":"case","ru":"случай","vi":"trường hợp","fa":"مورد","examples":[{"de":"In diesem Fall hast du recht.","en":"In this case you are right.","ru":"В этом случае ты прав.","vi":"Trong trường hợp này bạn đúng.","fa":"در این مورد حق با شماست."},{"de":"Der Polizist untersucht den Fall genau.","en":"The police officer is investigating the case closely.","ru":"Полицейский тщательно расследует это дело.","vi":"Cảnh sát đang điều tra vụ án chặt chẽ.","fa":"افسر پلیس این پرونده را از نزدیک بررسی می کند."}]},{"word":"fallen","en":"to fall","ru":"падать","vi":"ngã","fa":"سقوط","examples":[{"de":"Das Glas ist vom Tisch gefallen und zerbrochen.","en":"The glass fell off the table and broke.","ru":"Стакан упал со стола и разбился.","vi":"Chiếc ly rơi khỏi bàn và vỡ tan.","fa":"لیوان از روی میز افتاد و شکست."},{"de":"Im Herbst fallen die Blätter von den Bäumen.","en":"In autumn the leaves fall from the trees.","ru":"Осенью листья падают с деревьев.","vi":"Vào mùa thu, lá rụng khỏi cây.","fa":"در پاییز برگها از درختان می ریزند."}]},{"word":"fällig","en":"due (payment, date)","ru":"подлежащий оплате, наступивший срок","vi":"đến hạn","fa":"به دلیل","examples":[{"de":"Die Miete ist am Ersten des Monats fällig.","en":"The rent is due on the first of the month.","ru":"Арендная плата подлежит оплате первого числа месяца.","vi":"Tiền thuê nhà phải trả vào ngày đầu tiên của tháng.","fa":"پرداخت اجاره اول ماه می باشد."},{"de":"Die Rechnung ist bereits seit zwei Wochen fällig.","en":"The invoice has already been due for two weeks.","ru":"Счёт должен быть оплачен уже две недели.","vi":"Hóa đơn đã đến hạn thanh toán được hai tuần.","fa":"این لایحه در حال حاضر به مدت دو هفته سررسید شده است."}]},{"word":"falls","en":"in case, if","ru":"если, в случае если","vi":"nếu","fa":"اگر","examples":[{"de":"Falls es regnet, bleiben wir zu Hause.","en":"In case it rains, we'll stay home.","ru":"Если пойдёт дождь, мы останемся дома.","vi":"Nếu trời mưa thì chúng ta ở nhà.","fa":"اگر باران ببارد، ما در خانه می مانیم."},{"de":"Ruf mich an, falls du Hilfe brauchst.","en":"Call me if you need help.","ru":"Позвони мне, если тебе понадобится помощь.","vi":"Hãy gọi cho tôi nếu bạn cần giúp đỡ.","fa":"اگر به کمک نیاز دارید با من تماس بگیرید."}]},{"word":"falsch","en":"wrong, false, incorrect","ru":"неправильный, ложный","vi":"sai","fa":"اشتباه","examples":[{"de":"Diese Antwort ist leider falsch.","en":"Unfortunately, this answer is wrong.","ru":"К сожалению, этот ответ неправильный.","vi":"Thật không may, câu trả lời này là sai.","fa":"متاسفانه این پاسخ اشتباه است."},{"de":"Er hat die falsche Nummer gewählt.","en":"He dialed the wrong number.","ru":"Он набрал неправильный номер.","vi":"Anh gọi nhầm số rồi.","fa":"او شماره را اشتباه گرفت."}]},{"word":"die Familie","en":"family","ru":"семья","vi":"gia đình","fa":"خانواده","examples":[{"de":"Meine Familie ist mir sehr wichtig.","en":"My family is very important to me.","ru":"Моя семья очень важна для меня.","vi":"Gia đình tôi rất quan trọng với tôi.","fa":"خانواده ام برایم خیلی مهم است."},{"de":"Wir verbringen Weihnachten immer mit der ganzen Familie.","en":"We always spend Christmas with the whole family.","ru":"Рождество мы всегда проводим со всей семьёй.","vi":"Chúng tôi luôn đón Giáng sinh cùng cả gia đình.","fa":"ما همیشه کریسمس را با تمام خانواده می گذرانیم."}]},{"word":"der Familienstand","en":"marital status","ru":"семейное положение","vi":"tình trạng hôn nhân","fa":"وضعیت تاهل","examples":[{"de":"Bitte geben Sie Ihren Familienstand im Formular an.","en":"Please state your marital status on the form.","ru":"Пожалуйста, укажите ваше семейное положение в анкете.","vi":"Vui lòng cho biết tình trạng hôn nhân của bạn trong mẫu đơn.","fa":"لطفا وضعیت تاهل خود را در فرم ذکر کنید."},{"de":"Ihr Familienstand hat sich nach der Hochzeit geändert.","en":"Her marital status changed after the wedding.","ru":"Её семейное положение изменилось после свадьбы.","vi":"Tình trạng hôn nhân của cô thay đổi sau đám cưới.","fa":"وضعیت تاهل او بعد از عروسی تغییر کرد."}]},{"word":"fangen","en":"to catch","ru":"ловить","vi":"bắt","fa":"گرفتن","examples":[{"de":"Der Hund konnte den Ball gut fangen.","en":"The dog could catch the ball well.","ru":"Собака хорошо ловила мяч.","vi":"Con chó đã có thể bắt bóng tốt.","fa":"سگ به خوبی توانست توپ را بگیرد."},{"de":"Die Kinder spielen im Garten Fangen.","en":"The children are playing tag in the garden.","ru":"Дети играют в саду в салки.","vi":"Bọn trẻ đang chơi đuổi bắt trong vườn.","fa":"بچه ها در باغ مشغول بازی گرفتن هستند."}]},{"word":"die Fantasie/Phantasie","en":"imagination","ru":"воображение, фантазия","vi":"sự tưởng tượng/tưởng tượng","fa":"فانتزی / فانتزی","examples":[{"de":"Kinder haben oft eine sehr lebendige Fantasie.","en":"Children often have a very vivid imagination.","ru":"У детей часто очень живое воображение.","vi":"Trẻ em thường có trí tưởng tượng rất sống động.","fa":"کودکان اغلب تخیل بسیار روشنی دارند."},{"de":"Mit ein bisschen Fantasie kann man aus alten Möbeln etwas Neues machen.","en":"With a bit of imagination you can make something new out of old furniture.","ru":"С небольшой фантазией можно сделать из старой мебели что-то новое.","vi":"Với một chút trí tưởng tượng, bạn có thể biến đồ cũ thành đồ mới.","fa":"With a little imagination you can turn old furniture into something new."}]},{"word":"die Farbe","en":"color","ru":"цвет","vi":"màu sắc","fa":"رنگ","examples":[{"de":"Welche Farbe gefällt dir am besten?","en":"Which color do you like best?","ru":"Какой цвет тебе нравится больше всего?","vi":"Bạn thích màu nào nhất?","fa":"کدام رنگ را بیشتر دوست دارید؟"},{"de":"Wir haben die Wand in einer hellen Farbe gestrichen.","en":"We painted the wall in a light color.","ru":"Мы покрасили стену в светлый цвет.","vi":"Chúng tôi sơn tường màu sáng.","fa":"دیوار را با رنگ روشن رنگ کردیم."}]},{"word":"das Faschierte","en":"minced meat","ru":"фарш","vi":"sự băm nhỏ","fa":"چرخ شده","examples":[{"de":"Für die Soße brauchen wir ein halbes Kilo Faschiertes.","en":"For the sauce we need half a kilo of minced meat.","ru":"Для соуса нам нужно полкило фарша.","vi":"Đối với nước sốt chúng ta cần nửa kg thịt băm.","fa":"برای سس به نیم کیلو گوشت چرخ کرده نیاز داریم."},{"de":"Meine Oma macht die besten Laibchen aus Faschiertem.","en":"My grandma makes the best patties from minced meat.","ru":"Моя бабушка делает лучшие котлеты из фарша.","vi":"Bà tôi làm món chả thịt bằm ngon nhất.","fa":"مادربزرگ من بهترین قیمه های گوشت چرخ کرده را درست می کند."}]},{"word":"der Fasching","en":"carnival","ru":"карнавал","vi":"lễ hội","fa":"کارناوال","examples":[{"de":"Zu Fasching verkleiden sich die Kinder als Prinzessin oder Pirat.","en":"At carnival the children dress up as a princess or a pirate.","ru":"На карнавал дети наряжаются принцессами или пиратами.","vi":"Đối với lễ hội hóa trang, trẻ em hóa trang thành công chúa hoặc cướp biển.","fa":"برای کارناوال، بچه ها لباس پرنسس یا دزد دریایی می پوشند."},{"de":"In Köln wird der Fasching besonders groß gefeiert.","en":"In Cologne, carnival is celebrated on an especially large scale.","ru":"В Кёльне карнавал отмечают особенно масштабно.","vi":"Lễ hội hóa trang được tổ chức đặc biệt ở Cologne.","fa":"کارناوال به ویژه در کلن جشن گرفته می شود."}]},{"word":"die Fasnacht","en":"carnival","ru":"карнавал","vi":"lễ hội","fa":"کارناوال","examples":[{"de":"In Basel beginnt die Fasnacht traditionell um vier Uhr morgens.","en":"In Basel, carnival traditionally begins at four in the morning.","ru":"В Базеле карнавал традиционно начинается в четыре утра.","vi":"Ở Basel, Fasnacht theo truyền thống bắt đầu lúc bốn giờ sáng.","fa":"در بازل، Fasnacht به طور سنتی در ساعت چهار صبح آغاز می شود."},{"de":"Während der Fasnacht ziehen bunte Umzüge durch die Stadt.","en":"During carnival, colorful parades move through the city.","ru":"Во время карнавала по городу проходят пёстрые шествия.","vi":"Trong lễ hội hóa trang, các cuộc diễu hành đầy màu sắc di chuyển khắp thành phố.","fa":"در طول کارناوال، رژه های رنگارنگ در شهر حرکت می کنند."}]},{"word":"fassen","en":"to grasp; to hold","ru":"хватать, схватить","vi":"nắm bắt","fa":"درک کردن","examples":[{"de":"Er fasste das Kind an der Hand, bevor sie die Straße überquerten.","en":"He grabbed the child's hand before they crossed the street.","ru":"Он взял ребёнка за руку, прежде чем они перешли улицу.","vi":"Anh nắm lấy tay đứa trẻ trước khi họ băng qua đường.","fa":"دست کودک را قبل از عبور از خیابان گرفت."},{"de":"Ich kann es kaum fassen, dass wir schon fertig sind.","en":"I can hardly grasp that we're already finished.","ru":"Я едва могу поверить, что мы уже закончили.","vi":"Tôi không thể tin được là chúng ta đã xong việc.","fa":"من نمی توانم باور کنم که ما در حال حاضر تمام شده است."}]},{"word":"fast","en":"almost","ru":"почти","vi":"gần như","fa":"تقریبا","examples":[{"de":"Es ist fast neun Uhr, wir müssen los.","en":"It's almost nine o'clock, we have to go.","ru":"Уже почти девять часов, нам пора идти.","vi":"Đã gần chín giờ rồi, chúng ta phải đi thôi.","fa":"ساعت نزدیک نه است، باید بریم."},{"de":"Ich hätte fast den Bus verpasst.","en":"I almost missed the bus.","ru":"Я чуть не опоздал на автобус.","vi":"Tôi gần như đã lỡ chuyến xe buýt.","fa":"تقریباً اتوبوس را از دست دادم."}]},{"word":"faul","en":"lazy","ru":"ленивый","vi":"lười biếng","fa":"تنبل","examples":[{"de":"Sei nicht so faul und hilf mir beim Aufräumen!","en":"Don't be so lazy and help me tidy up!","ru":"Не будь таким ленивым и помоги мне убраться!","vi":"Đừng lười biếng thế và giúp tôi dọn dẹp nhé!","fa":"اینقدر تنبل نباش و به من کمک کن تمیز کنم!"},{"de":"An Sonntagen bin ich gern ein bisschen faul.","en":"On Sundays I like to be a bit lazy.","ru":"По воскресеньям я люблю немного полениться.","vi":"Tôi thích lười biếng một chút vào ngày chủ nhật.","fa":"من دوست دارم یکشنبه ها کمی تنبل باشم."}]},{"word":"faulenzen","en":"to laze around","ru":"бездельничать","vi":"lười biếng xung quanh","fa":"تنبلی در اطراف","examples":[{"de":"Im Urlaub will ich einfach nur am Strand faulenzen.","en":"On vacation I just want to laze around on the beach.","ru":"В отпуске я хочу просто бездельничать на пляже.","vi":"Khi tôi đi nghỉ, tôi chỉ muốn nằm dài trên bãi biển.","fa":"وقتی در تعطیلات هستم، فقط می خواهم در ساحل استراحت کنم."},{"de":"Statt zu lernen, hat er den ganzen Nachmittag gefaulenzt.","en":"Instead of studying, he lazed around all afternoon.","ru":"Вместо того чтобы учиться, он весь день бездельничал.","vi":"Thay vì học, anh lười biếng suốt buổi chiều.","fa":"به جای درس خواندن، تمام بعدازظهر را تنبلی می کرد."}]},{"word":"der Fauteuil","en":"armchair","ru":"кресло","vi":"chiếc ghế bành","fa":"صندلی راحتی","examples":[{"de":"Nach der Arbeit setzt sich mein Vater immer in seinen Fauteuil.","en":"After work my father always sits down in his armchair.","ru":"После работы мой отец всегда садится в своё кресло.","vi":"Sau giờ làm việc, bố tôi luôn ngồi xuống chiếc ghế bành.","fa":"پدرم بعد از کار همیشه روی صندلی راحتی اش می نشیند."},{"de":"Der alte Fauteuil im Wohnzimmer ist sehr bequem.","en":"The old armchair in the living room is very comfortable.","ru":"Старое кресло в гостиной очень удобное.","vi":"Chiếc ghế bành cũ trong phòng khách rất thoải mái.","fa":"The old armchair in the living room is very comfortable."}]},{"word":"fehlen","en":"to be missing","ru":"не хватать, отсутствовать","vi":"cô","fa":"خانم","examples":[{"de":"In diesem Satz fehlt ein Wort.","en":"A word is missing in this sentence.","ru":"В этом предложении не хватает слова.","vi":"Có một từ còn thiếu trong câu này.","fa":"یک کلمه در این جمله گم شده است."},{"de":"Drei Schüler fehlen heute wegen Krankheit.","en":"Three students are absent today due to illness.","ru":"Трое учеников сегодня отсутствуют по болезни.","vi":"Ba học sinh mất tích hôm nay do bị bệnh.","fa":"سه دانش آموز امروز به دلیل بیماری مفقود شده اند."}]},{"word":"der Fehler","en":"mistake","ru":"ошибка","vi":"lỗi","fa":"خطا","examples":[{"de":"Ich habe im Test nur einen Fehler gemacht.","en":"I only made one mistake in the test.","ru":"Я допустил только одну ошибку в тесте.","vi":"Tôi chỉ mắc một lỗi trong bài kiểm tra.","fa":"من فقط یک اشتباه در آزمون انجام دادم."},{"de":"Es tut mir leid, das war mein Fehler.","en":"I'm sorry, that was my mistake.","ru":"Извини, это была моя ошибка.","vi":"Tôi xin lỗi, đó là lỗi của tôi.","fa":"متاسفم، این اشتباه من بود."}]},{"word":"feiern","en":"to celebrate","ru":"праздновать","vi":"ăn mừng","fa":"جشن بگیرید","examples":[{"de":"Wir feiern heute Abend meinen Geburtstag.","en":"We are celebrating my birthday tonight.","ru":"Сегодня вечером мы празднуем мой день рождения.","vi":"Tối nay chúng ta tổ chức sinh nhật cho tôi.","fa":"ما امشب تولدم را جشن می گیریم."},{"de":"Nach der Prüfung wollen wir richtig feiern.","en":"After the exam we want to really celebrate.","ru":"После экзамена мы хотим как следует отпраздновать.","vi":"Sau kỳ thi chúng tôi thực sự muốn ăn mừng.","fa":"بعد از امتحان ما واقعاً می خواهیم جشن بگیریم."}]},{"word":"das Feld","en":"field","ru":"поле","vi":"cánh đồng","fa":"the field","examples":[{"de":"Die Bauern arbeiten seit dem Morgen auf dem Feld.","en":"The farmers have been working in the field since morning.","ru":"Крестьяне работают в поле с самого утра.","vi":"Những người nông dân đã làm việc trên đồng từ sáng.","fa":"کشاورزان از صبح در مزارع مشغول به کار هستند."},{"de":"Hinter unserem Haus liegt ein großes grünes Feld.","en":"Behind our house there is a large green field.","ru":"За нашим домом находится большое зелёное поле.","vi":"Có một cánh đồng xanh rộng lớn phía sau nhà chúng tôi.","fa":"پشت خانه ما یک زمین سبز بزرگ است."}]},{"word":"das Fenster","en":"window","ru":"окно","vi":"cửa sổ","fa":"پنجره","examples":[{"de":"Kannst du bitte das Fenster öffnen? Es ist so warm hier.","en":"Can you please open the window? It's so warm in here.","ru":"Можешь открыть окно? Здесь так тепло.","vi":"Bạn có thể vui lòng mở cửa sổ được không? Ở đây thật ấm áp.","fa":"میشه لطفا پنجره رو باز کن اینجا خیلی گرمه"},{"de":"Von meinem Fenster aus sehe ich den ganzen Park.","en":"From my window I can see the whole park.","ru":"Из моего окна виден весь парк.","vi":"Từ cửa sổ của tôi, tôi có thể nhìn thấy toàn bộ công viên.","fa":"از پنجره ام می توانم کل پارک را ببینم."}]},{"word":"die Ferien","en":"vacation, holidays","ru":"каникулы","vi":"những ngày nghỉ","fa":"تعطیلات","examples":[{"de":"Endlich beginnen morgen die Sommerferien!","en":"The summer vacation finally starts tomorrow!","ru":"Наконец завтра начинаются летние каникулы!","vi":"Kỳ nghỉ hè cuối cùng cũng bắt đầu vào ngày mai!","fa":"بالاخره از فردا تعطیلات تابستانی شروع می شود!"},{"de":"In den Ferien fahren wir jedes Jahr ans Meer.","en":"During the holidays we go to the sea every year.","ru":"На каникулах мы каждый год ездим на море.","vi":"Chúng tôi đi biển hàng năm vào kỳ nghỉ.","fa":"ما هر سال در تعطیلات به دریا می رویم."}]},{"word":"die Fernbedienung","en":"remote control","ru":"пульт дистанционного управления","vi":"điều khiển từ xa","fa":"کنترل از راه دور","examples":[{"de":"Wo ist die Fernbedienung für den Fernseher?","en":"Where is the remote control for the TV?","ru":"Где пульт от телевизора?","vi":"Điều khiển từ xa cho TV ở đâu?","fa":"ریموت کنترل تلویزیون کجاست؟"},{"de":"Die Batterien der Fernbedienung sind leer.","en":"The batteries of the remote control are empty.","ru":"Батарейки в пульте разрядились.","vi":"Pin của điều khiển từ xa đã hết.","fa":"باتری های کنترل از راه دور خالی هستند."}]},{"word":"fernsehen","en":"to watch TV","ru":"смотреть телевизор","vi":"xem tivi","fa":"تلویزیون تماشا کن","examples":[{"de":"Abends sieht die ganze Familie zusammen fern.","en":"In the evening the whole family watches TV together.","ru":"По вечерам вся семья вместе смотрит телевизор.","vi":"Buổi tối cả nhà cùng nhau xem TV.","fa":"عصرها همه خانواده با هم تلویزیون تماشا می کنند."},{"de":"Ich sehe nicht gern lange fern, ich lese lieber.","en":"I don't like watching TV for long, I prefer to read.","ru":"Я не люблю долго смотреть телевизор, предпочитаю читать.","vi":"Tôi không thích xem TV trong thời gian dài, tôi thích đọc sách hơn.","fa":"من دوست ندارم برای مدت طولانی تلویزیون ببینم، مطالعه را ترجیح می دهم."}]},{"word":"fertig","en":"ready, finished","ru":"готовый","vi":"đã hoàn thành","fa":"به پایان رسید","examples":[{"de":"Bist du fertig? Wir müssen jetzt los.","en":"Are you ready? We have to go now.","ru":"Ты готов? Нам пора идти.","vi":"Bạn đã sẵn sàng chưa? Chúng ta phải đi bây giờ.","fa":"آیا شما آماده اید؟ الان باید بریم"},{"de":"Ich bin mit meiner Hausaufgabe schon fertig.","en":"I'm already finished with my homework.","ru":"Я уже закончил домашнее задание.","vi":"Tôi đã làm xong bài tập về nhà rồi.","fa":"من قبلاً تکالیفم را تمام کرده ام."}]},{"word":"fest","en":"firm, fixed","ru":"твёрдый, крепкий; постоянный","vi":"đã sửa","fa":"ثابت","examples":[{"de":"Halt das Seil bitte ganz fest!","en":"Please hold the rope very firmly!","ru":"Держи верёвку крепко!","vi":"Hãy giữ chặt sợi dây!","fa":"لطفا طناب را محکم بگیرید!"},{"de":"Sie hat einen festen Job in einer großen Firma.","en":"She has a permanent job at a big company.","ru":"У неё постоянная работа в крупной компании.","vi":"Cô ấy có một công việc ổn định ở một công ty lớn.","fa":"او یک شغل دائمی در یک شرکت بزرگ دارد."}]},{"word":"das Fest","en":"celebration, festival","ru":"праздник","vi":"bữa tiệc","fa":"حزب","examples":[{"de":"Zur Hochzeit haben sie ein großes Fest organisiert.","en":"For the wedding they organized a big celebration.","ru":"На свадьбу они устроили большой праздник.","vi":"Họ tổ chức một bữa tiệc lớn cho đám cưới.","fa":"آنها یک جشن بزرگ برای عروسی ترتیب دادند."},{"de":"Das Dorf feiert jedes Jahr im Sommer ein Fest.","en":"The village celebrates a festival every summer.","ru":"В деревне каждое лето проводят праздник.","vi":"Làng tổ chức lễ hội vào mỗi mùa hè.","fa":"این روستا هر تابستان جشنواره ای را جشن می گیرد."}]},{"word":"festhalten","en":"to hold on to","ru":"держаться, крепко держать","vi":"chờ đã","fa":"نگه دارید","examples":[{"de":"Halt dich gut fest, der Bus fährt jetzt los!","en":"Hold on tight, the bus is about to leave!","ru":"Держись крепко, автобус сейчас тронется!","vi":"Hãy giữ chặt nhé, xe buýt sắp rời đi rồi!","fa":"محکم نگه دارید، اتوبوس در حال حرکت است!"},{"de":"Das Kind hielt die Hand seiner Mutter fest.","en":"The child held on to its mother's hand.","ru":"Ребёнок крепко держался за руку матери.","vi":"Cậu bé nắm chặt tay mẹ.","fa":"کودک دست مادرش را محکم گرفته بود."}]},{"word":"festlegen","en":"to determine, set","ru":"устанавливать, определять","vi":"đặt","fa":"مجموعه","examples":[{"de":"Wir müssen noch einen Termin für das Treffen festlegen.","en":"We still need to set a date for the meeting.","ru":"Нам ещё нужно назначить дату встречи.","vi":"Chúng ta vẫn cần phải ấn định ngày cho cuộc họp.","fa":"ما هنوز باید تاریخ ملاقات را تعیین کنیم."},{"de":"Die Regeln wurden schon vor Jahren festgelegt.","en":"The rules were established years ago.","ru":"Правила были установлены ещё несколько лет назад.","vi":"Các quy tắc đã được thiết lập từ nhiều năm trước.","fa":"قوانین سال ها پیش تعیین شده بود."}]},{"word":"festnehmen nimmt fest","en":"to arrest","ru":"арестовывать, задерживать","vi":"bắt giữ","fa":"دستگیری ها","examples":[{"de":"Die Polizei hat den Dieb noch am selben Abend festgenommen.","en":"The police arrested the thief that same evening.","ru":"Полиция задержала вора в тот же вечер.","vi":"Cảnh sát đã bắt giữ tên trộm ngay tối hôm đó.","fa":"پلیس دزد را عصر همان روز دستگیر کرد."},{"de":"Er wurde wegen Betrugs festgenommen.","en":"He was arrested for fraud.","ru":"Его арестовали за мошенничество.","vi":"Anh ta bị bắt vì tội lừa đảo.","fa":"به جرم کلاهبرداری دستگیر شد."}]},{"word":"die Festplatte","en":"hard drive","ru":"жёсткий диск","vi":"ổ cứng","fa":"هارد دیسک","examples":[{"de":"Meine Festplatte ist fast voll, ich muss Daten löschen.","en":"My hard drive is almost full, I need to delete data.","ru":"Мой жёсткий диск почти заполнен, нужно удалить данные.","vi":"Ổ cứng của tôi gần đầy, tôi phải xóa dữ liệu.","fa":"هاردم تقریبا پر شده باید دیتا رو پاک کنم."},{"de":"Die alte Festplatte war kaputt, deshalb habe ich eine neue gekauft.","en":"The old hard drive was broken, so I bought a new one.","ru":"Старый жёсткий диск сломался, поэтому я купил новый.","vi":"Ổ cứng cũ bị hỏng nên tôi mua cái mới.","fa":"هارد قدیمی خراب شده بود، برای همین یک هارد جدید خریدم."}]},{"word":"festsetzen","en":"to set, fix","ru":"устанавливать, назначать","vi":"sửa chữa","fa":"رفع کنید","examples":[{"de":"Der Preis für die Tickets wurde vom Veranstalter festgesetzt.","en":"The price for the tickets was set by the organizer.","ru":"Цена на билеты была установлена организатором.","vi":"Giá vé do ban tổ chức ấn định.","fa":"قیمت بلیط ها توسط برگزار کننده تعیین شده است."},{"de":"Man hat den Termin für die Prüfung schon festgesetzt.","en":"The date for the exam has already been set.","ru":"Дата экзамена уже назначена.","vi":"Ngày thi đã được ấn định.","fa":"تاریخ برگزاری آزمون قبلاً تعیین شده است."}]},{"word":"feststehen","en":"to be certain","ru":"быть точно установленным","vi":"đứng vững","fa":"محکم بایست","examples":[{"de":"Es steht noch nicht fest, wer den Preis gewinnt.","en":"It is not yet certain who will win the prize.","ru":"Пока не известно точно, кто выиграет приз.","vi":"Hiện vẫn chưa rõ ai sẽ giành được giải thưởng.","fa":"هنوز مشخص نیست چه کسی برنده جایزه خواهد شد."},{"de":"Der Termin für die Hochzeit steht schon fest.","en":"The date for the wedding is already fixed.","ru":"Дата свадьбы уже точно определена.","vi":"Ngày tổ chức đám cưới đã được định sẵn.","fa":"تاریخ عروسی از قبل تعیین شده است."}]},{"word":"feststellen","en":"to notice, find out","ru":"устанавливать, замечать, обнаруживать","vi":"xác định","fa":"تعیین کنید","examples":[{"de":"Der Arzt konnte keine Krankheit feststellen.","en":"The doctor could not find any illness.","ru":"Врач не смог обнаружить никакой болезни.","vi":"Bác sĩ không thể tìm ra bệnh gì.","fa":"دکتر هیچ بیماری پیدا نکرد."},{"de":"Ich habe erst zu Hause festgestellt, dass mein Schlüssel fehlt.","en":"I only noticed at home that my key was missing.","ru":"Только дома я заметил, что у меня пропал ключ.","vi":"Tôi chỉ phát hiện ra khi về đến nhà rằng chìa khóa của tôi đã bị mất.","fa":"فقط وقتی به خانه رسیدم متوجه شدم که کلیدم گم شده است."}]},{"word":"fett","en":"fatty, greasy","ru":"жирный","vi":"béo","fa":"چربی","examples":[{"de":"Das Essen im Restaurant war mir zu fett.","en":"The food at the restaurant was too greasy for me.","ru":"Еда в ресторане показалась мне слишком жирной.","vi":"Thức ăn trong nhà hàng quá béo đối với tôi.","fa":"غذای رستوران برای من خیلی چرب بود."},{"de":"Fettes Fleisch esse ich nicht so gern.","en":"I don't really like eating fatty meat.","ru":"Я не очень люблю жирное мясо.","vi":"Tôi thực sự không thích ăn thịt mỡ.","fa":"من زیاد دوست ندارم گوشت چرب بخورم."}]},{"word":"feucht","en":"damp, humid","ru":"влажный","vi":"ẩm ướt","fa":"مرطوب","examples":[{"de":"Nach dem Regen war die Luft noch feucht.","en":"After the rain the air was still humid.","ru":"После дождя воздух был ещё влажным.","vi":"Không khí vẫn ẩm ướt sau cơn mưa.","fa":"بعد از بارندگی هوا هنوز مرطوب بود."},{"de":"Wisch den Tisch mit einem feuchten Tuch ab.","en":"Wipe the table with a damp cloth.","ru":"Протри стол влажной тряпкой.","vi":"Lau bàn bằng vải ẩm.","fa":"میز را با یک پارچه مرطوب پاک کنید."}]},{"word":"das Feuer","en":"fire","ru":"огонь","vi":"ngọn lửa","fa":"آتش","examples":[{"de":"Wir haben am Strand ein Feuer gemacht.","en":"We made a fire on the beach.","ru":"Мы развели огонь на пляже.","vi":"Chúng tôi đốt lửa trên bãi biển.","fa":"در ساحل آتش زدیم."},{"de":"Bei dem Feuer wurde niemand verletzt.","en":"No one was injured in the fire.","ru":"Во время пожара никто не пострадал.","vi":"Không có ai bị thương trong vụ cháy.","fa":"در این آتش سوزی به کسی آسیب نرسید."}]},{"word":"das Fieber","en":"fever","ru":"температура, жар","vi":"cơn sốt","fa":"تب","examples":[{"de":"Mein Sohn hat hohes Fieber und muss im Bett bleiben.","en":"My son has a high fever and has to stay in bed.","ru":"У моего сына высокая температура, ему нужно лежать в постели.","vi":"Con trai tôi bị sốt cao và phải nằm trên giường.","fa":"پسرم تب شدید دارد و باید در رختخواب بماند."},{"de":"Bei Fieber sollte man viel trinken.","en":"When you have a fever you should drink a lot.","ru":"При температуре нужно много пить.","vi":"Nếu bị sốt thì nên uống nhiều.","fa":"اگر تب دارید باید زیاد بنوشید."}]},{"word":"die Figur","en":"figure","ru":"фигура","vi":"hình","fa":"شکل","examples":[{"de":"Sie achtet sehr auf ihre Figur und macht viel Sport.","en":"She pays close attention to her figure and does a lot of sports.","ru":"Она очень следит за своей фигурой и много занимается спортом.","vi":"Cô ấy rất chú ý đến hình thể của mình và chơi rất nhiều môn thể thao.","fa":"او به اندام خود اهمیت زیادی می دهد و ورزش های زیادی انجام می دهد."},{"de":"Im Museum stehen alte Figuren aus Holz.","en":"In the museum there are old wooden figures.","ru":"В музее стоят старые деревянные фигуры.","vi":"Có những bức tượng gỗ cũ trong bảo tàng.","fa":"مجسمه های چوبی قدیمی در موزه وجود دارد."}]},{"word":"der Film","en":"film, movie","ru":"фильм","vi":"bộ phim","fa":"فیلم","examples":[{"de":"Welchen Film wollen wir heute Abend sehen?","en":"Which film do we want to watch tonight?","ru":"Какой фильм мы посмотрим сегодня вечером?","vi":"Tối nay chúng ta muốn xem phim gì?","fa":"کدام فیلم را امشب می خواهیم ببینیم؟"},{"de":"Der neue Film hat mir sehr gut gefallen.","en":"I liked the new film very much.","ru":"Мне очень понравился новый фильм.","vi":"Tôi thực sự thích bộ phim mới.","fa":"من فیلم جدید را خیلی دوست داشتم."}]},{"word":"finanzieren","en":"to finance","ru":"финансировать","vi":"tài chính","fa":"امور مالی","examples":[{"de":"Wie wollt ihr den Hausbau finanzieren?","en":"How do you plan to finance building the house?","ru":"Как вы собираетесь финансировать строительство дома?","vi":"Bạn muốn tài trợ xây dựng một ngôi nhà như thế nào?","fa":"چگونه می خواهید بودجه ساخت خانه را تامین کنید؟"},{"de":"Das Projekt wird von der Stadt finanziert.","en":"The project is financed by the city.","ru":"Проект финансируется городом.","vi":"Dự án được thành phố tài trợ.","fa":"این پروژه توسط شهرداری تامین می شود."}]},{"word":"finden","en":"to find","ru":"находить; считать","vi":"tìm thấy","fa":"پیدا کردن","examples":[{"de":"Ich kann meinen Schlüssel nicht finden.","en":"I can't find my key.","ru":"Я не могу найти свой ключ.","vi":"Tôi không thể tìm thấy chìa khóa của mình.","fa":"من نمی توانم کلید خود را پیدا کنم."},{"de":"Wie findest du meine neue Frisur?","en":"What do you think of my new haircut?","ru":"Как тебе моя новая причёска?","vi":"Bạn nghĩ gì về kiểu tóc mới của tôi?","fa":"نظر شما در مورد مدل موی جدید من چیست؟"}]},{"word":"der Finger","en":"finger","ru":"палец","vi":"ngón tay","fa":"انگشت","examples":[{"de":"Ich habe mir beim Kochen in den Finger geschnitten.","en":"I cut my finger while cooking.","ru":"Я порезал палец во время готовки.","vi":"Tôi bị đứt tay khi đang nấu ăn.","fa":"هنگام آشپزی انگشتم را بریدم."},{"de":"Sie zeigte mit dem Finger auf die Karte.","en":"She pointed at the map with her finger.","ru":"Она указала пальцем на карту.","vi":"Cô chỉ tay vào bản đồ.","fa":"انگشتش را به سمت نقشه گرفت."}]},{"word":"die Firma","en":"company","ru":"фирма, компания","vi":"công ty","fa":"شرکت","examples":[{"de":"Er arbeitet seit zehn Jahren bei derselben Firma.","en":"He has been working at the same company for ten years.","ru":"Он работает в одной и той же компании уже десять лет.","vi":"Anh ấy đã làm việc ở cùng một công ty được mười năm.","fa":"او ده سال است که در همان شرکت کار می کند."},{"de":"Die Firma sucht neue Mitarbeiter.","en":"The company is looking for new employees.","ru":"Компания ищет новых сотрудников.","vi":"Công ty đang tìm kiếm nhân viên mới.","fa":"این شرکت به دنبال کارمندان جدید است."}]},{"word":"flach","en":"flat","ru":"плоский, ровный","vi":"bằng phẳng","fa":"تخت","examples":[{"de":"Das Land hier ist sehr flach, es gibt kaum Berge.","en":"The land here is very flat, there are hardly any mountains.","ru":"Местность здесь очень плоская, гор почти нет.","vi":"Đất ở đây rất bằng phẳng, hầu như không có ngọn núi nào.","fa":"زمین اینجا بسیار هموار است، کوه به سختی وجود دارد."},{"de":"Sie trägt lieber flache Schuhe als hohe Absätze.","en":"She prefers flat shoes to high heels.","ru":"Она предпочитает плоскую обувь высоким каблукам.","vi":"Cô thích đi giày bệt hơn giày cao gót.","fa":"او پوشیدن کفش های تخت را به کفش های پاشنه بلند ترجیح می دهد."}]},{"word":"die Fläche","en":"area, surface","ru":"площадь, поверхность","vi":"khu vực","fa":"منطقه","examples":[{"de":"Der Park hat eine Fläche von zehn Hektar.","en":"The park has an area of ten hectares.","ru":"Площадь парка составляет десять гектаров.","vi":"Công viên có diện tích mười ha.","fa":"این پارک ده هکتار مساحت دارد."},{"de":"Die Fläche des Tisches ist ganz glatt.","en":"The surface of the table is completely smooth.","ru":"Поверхность стола совершенно гладкая.","vi":"Bề mặt của bàn hoàn toàn mịn màng.","fa":"سطح میز کاملا صاف است."}]},{"word":"die Flasche","en":"bottle","ru":"бутылка","vi":"cái chai","fa":"بطری","examples":[{"de":"Kannst du mir bitte eine Flasche Wasser bringen?","en":"Can you bring me a bottle of water, please?","ru":"Принеси мне, пожалуйста, бутылку воды.","vi":"Bạn có thể vui lòng mang cho tôi một chai nước được không?","fa":"میشه لطفا یه بطری آب برام بیارید؟"},{"de":"Die leeren Flaschen bringen wir zum Recycling.","en":"We take the empty bottles to be recycled.","ru":"Мы отвозим пустые бутылки на переработку.","vi":"Chúng tôi lấy những chai rỗng để tái chế.","fa":"بطری های خالی را برای بازیافت می بریم."}]},{"word":"der Fleck","en":"stain","ru":"пятно","vi":"vết bẩn","fa":"لکه","examples":[{"de":"Auf meinem Hemd ist ein Fleck von der Soße.","en":"There's a stain from the sauce on my shirt.","ru":"На моей рубашке пятно от соуса.","vi":"Có vết nước sốt trên áo tôi.","fa":"روی پیراهنم لکه سس هست"},{"de":"Der Fleck geht mit warmem Wasser leicht raus.","en":"The stain comes out easily with warm water.","ru":"Пятно легко отстирывается тёплой водой.","vi":"Vết bẩn dễ dàng bong ra bằng nước ấm.","fa":"لکه به راحتی با آب گرم خارج می شود."}]},{"word":"das Fleisch","en":"meat","ru":"мясо","vi":"thịt","fa":"گوشت","examples":[{"de":"Wir kaufen unser Fleisch immer beim Metzger nebenan.","en":"We always buy our meat from the butcher next door.","ru":"Мы всегда покупаем мясо у соседнего мясника.","vi":"Chúng tôi luôn mua thịt từ người bán thịt bên cạnh.","fa":"ما همیشه گوشتمان را از قصاب همسایه می خریم."},{"de":"Sie isst kein Fleisch mehr, seit sie Vegetarierin ist.","en":"She hasn't eaten meat anymore since she became a vegetarian.","ru":"Она больше не ест мясо с тех пор, как стала вегетарианкой.","vi":"Cô ấy không còn ăn thịt kể từ khi cô ấy ăn chay.","fa":"او از زمانی که گیاهخوار شد دیگر گوشت نمی خورد."}]},{"word":"der Fleischhauer","en":"butcher","ru":"мясник","vi":"người bán thịt","fa":"قصاب","examples":[{"de":"Der Fleischhauer um die Ecke hat immer frisches Fleisch.","en":"The butcher around the corner always has fresh meat.","ru":"У мясника за углом всегда свежее мясо.","vi":"Người bán thịt quanh góc luôn có thịt tươi.","fa":"قصاب این گوشه همیشه گوشت تازه دارد."},{"de":"Ich kaufe das Fleisch für den Sonntagsbraten beim Fleischhauer.","en":"I buy the meat for the Sunday roast from the butcher.","ru":"Я покупаю мясо для воскресного жаркого у мясника.","vi":"Tôi mua thịt nướng vào Chủ nhật từ người bán thịt.","fa":"من گوشت کباب یکشنبه را از قصاب می خرم."}]},{"word":"fleißig","en":"hardworking, diligent","ru":"прилежный, трудолюбивый","vi":"chăm chỉ","fa":"سخت کوش","examples":[{"de":"Sie ist eine sehr fleißige Studentin und lernt jeden Tag.","en":"She is a very diligent student and studies every day.","ru":"Она очень прилежная студентка и учится каждый день.","vi":"Cô ấy là một học sinh rất chăm chỉ và học tập mỗi ngày.","fa":"او دانش آموز بسیار سخت کوشی است و هر روز درس می خواند."},{"de":"Wenn du fleißig übst, wirst du die Prüfung schaffen.","en":"If you practice diligently, you will pass the exam.","ru":"Если будешь усердно заниматься, ты сдашь экзамен.","vi":"Nếu bạn luyện tập chăm chỉ, bạn sẽ vượt qua kỳ thi.","fa":"اگر سخت تمرین کنید در امتحان موفق خواهید شد."}]},{"word":"flexibel","en":"flexible","ru":"гибкий","vi":"linh hoạt","fa":"قابل انعطاف","examples":[{"de":"Meine Arbeitszeiten sind zum Glück sehr flexibel.","en":"Luckily my working hours are very flexible.","ru":"К счастью, мой рабочий график очень гибкий.","vi":"May mắn thay, giờ làm việc của tôi rất linh hoạt.","fa":"خوشبختانه ساعات کاری من بسیار انعطاف پذیر است."},{"de":"Man muss im Leben flexibel bleiben und sich anpassen können.","en":"You have to stay flexible in life and be able to adapt.","ru":"В жизни нужно оставаться гибким и уметь приспосабливаться.","vi":"Bạn phải linh hoạt trong cuộc sống và có khả năng thích nghi.","fa":"شما باید در زندگی انعطاف پذیر باقی بمانید و بتوانید خود را وفق دهید."}]},{"word":"fliegen","en":"to fly","ru":"летать","vi":"bay","fa":"پرواز کن","examples":[{"de":"Wir fliegen nächste Woche nach Spanien.","en":"We are flying to Spain next week.","ru":"На следующей неделе мы летим в Испанию.","vi":"Chúng tôi sẽ bay đến Tây Ban Nha vào tuần tới.","fa":"هفته آینده به اسپانیا پرواز می کنیم."},{"de":"Der Vogel flog schnell aus dem Fenster.","en":"The bird quickly flew out of the window.","ru":"Птица быстро вылетела из окна.","vi":"Con chim nhanh chóng bay ra ngoài cửa sổ.","fa":"پرنده به سرعت از پنجره بیرون پرید."}]},{"word":"fliehen","en":"to flee","ru":"бежать, спасаться бегством","vi":"chạy trốn","fa":"فرار کن","examples":[{"de":"Viele Menschen mussten aus ihrer Heimat fliehen.","en":"Many people had to flee their homeland.","ru":"Многим людям пришлось бежать из своей родины.","vi":"Nhiều người đã phải rời bỏ nhà cửa.","fa":"بسیاری از مردم مجبور به ترک خانه های خود شدند."},{"de":"Der Dieb floh, bevor die Polizei ankam.","en":"The thief fled before the police arrived.","ru":"Вор скрылся до приезда полиции.","vi":"Tên trộm đã bỏ trốn trước khi cảnh sát đến.","fa":"دزد قبل از رسیدن پلیس متواری شد."}]},{"word":"fließen","en":"to flow","ru":"течь","vi":"dòng chảy","fa":"جریان","examples":[{"de":"Der Fluss fließt durch die ganze Stadt.","en":"The river flows through the whole city.","ru":"Река протекает через весь город.","vi":"Dòng sông chảy qua toàn bộ thành phố.","fa":"رودخانه از کل شهر می گذرد."},{"de":"Das Wasser fließt langsam den Berg hinunter.","en":"The water flows slowly down the mountain.","ru":"Вода медленно стекает с горы.","vi":"Nước từ từ chảy xuống núi.","fa":"آب به آرامی از کوه سرازیر می شود."}]},{"word":"der Flohmarkt","en":"flea market","ru":"блошиный рынок","vi":"chợ trời","fa":"بازار دستفروشی","examples":[{"de":"Am Samstag gehen wir auf den Flohmarkt.","en":"On Saturday we're going to the flea market.","ru":"В субботу мы идём на блошиный рынок.","vi":"Thứ bảy chúng tôi đi chợ trời.","fa":"شنبه میریم بازار کثافت."},{"de":"Auf dem Flohmarkt habe ich ein altes Buch billig gekauft.","en":"At the flea market I bought an old book cheaply.","ru":"На блошином рынке я дёшево купил старую книгу.","vi":"Tôi mua được một cuốn sách cũ với giá rẻ ở chợ trời.","fa":"من یک کتاب قدیمی را ارزان از بازار فروش خریدم."}]},{"word":"die Flöte","en":"flute","ru":"флейта","vi":"cây sáo","fa":"فلوت","examples":[{"de":"Meine Tochter lernt seit einem Jahr Flöte spielen.","en":"My daughter has been learning to play the flute for a year.","ru":"Моя дочь уже год учится играть на флейте.","vi":"Con gái tôi đã học thổi sáo được một năm.","fa":"دخترم یک سال است که نواختن فلوت را یاد می گیرد."},{"de":"Er spielte ein ruhiges Lied auf der Flöte.","en":"He played a calm song on the flute.","ru":"Он сыграл спокойную мелодию на флейте.","vi":"Anh ấy thổi một bài hát lặng lẽ trên cây sáo.","fa":"او یک آهنگ آرام را روی فلوت نواخت."}]},{"word":"der Flug","en":"flight","ru":"полёт, рейс","vi":"chuyến bay","fa":"پرواز","examples":[{"de":"Unser Flug nach Berlin hat sich um zwei Stunden verspätet.","en":"Our flight to Berlin was delayed by two hours.","ru":"Наш рейс в Берлин задержался на два часа.","vi":"Chuyến bay của chúng tôi đến Berlin bị hoãn hai giờ.","fa":"پرواز ما به برلین با دو ساعت تاخیر انجام شد."},{"de":"Der Flug dauert ungefähr drei Stunden.","en":"The flight takes about three hours.","ru":"Полёт длится примерно три часа.","vi":"Chuyến bay kéo dài khoảng ba giờ.","fa":"The flight lasts approximately three hours."}]},{"word":"der Flur","en":"hallway","ru":"коридор, прихожая","vi":"hành lang","fa":"راهرو","examples":[{"de":"Häng deine Jacke bitte im Flur auf.","en":"Please hang your jacket in the hallway.","ru":"Повесь, пожалуйста, куртку в прихожей.","vi":"Vui lòng treo áo khoác của bạn ở hành lang.","fa":"لطفا ژاکت خود را در راهرو آویزان کنید."},{"de":"Im Flur der Schule hängen Bilder der Schüler.","en":"Pictures by the students hang in the school hallway.","ru":"В школьном коридоре висят рисунки учеников.","vi":"Hình ảnh học sinh được treo ở hành lang trường học.","fa":"عکس های دانش آموزان در راهرو مدرسه آویزان شده است."}]},{"word":"der Fluss","en":"river","ru":"река","vi":"con sông","fa":"رودخانه","examples":[{"de":"Der Rhein ist einer der längsten Flüsse Europas.","en":"The Rhine is one of the longest rivers in Europe.","ru":"Рейн — одна из самых длинных рек Европы.","vi":"Sông Rhine là một trong những con sông dài nhất ở châu Âu.","fa":"رود راین یکی از طولانی ترین رودهای اروپاست."},{"de":"Wir sind im Sommer oft im Fluss geschwommen.","en":"In summer we often swam in the river.","ru":"Летом мы часто купались в реке.","vi":"Chúng tôi thường bơi ở sông vào mùa hè.","fa":"ما اغلب در تابستان در رودخانه شنا می کردیم."}]},{"word":"die Flüssigkeit","en":"liquid","ru":"жидкость","vi":"chất lỏng","fa":"مایع","examples":[{"de":"Man darf im Flugzeug keine großen Mengen Flüssigkeit mitnehmen.","en":"You are not allowed to bring large amounts of liquid on the plane.","ru":"В самолёт нельзя брать большое количество жидкости.","vi":"Bạn không được phép mang theo một lượng lớn chất lỏng lên máy bay.","fa":"شما مجاز نیستید مقدار زیادی مایعات را با خود در هواپیما ببرید."},{"de":"Aus der Wunde trat eine klare Flüssigkeit aus.","en":"A clear liquid came out of the wound.","ru":"Из раны сочилась прозрачная жидкость.","vi":"Một chất lỏng trong suốt chảy ra từ vết thương.","fa":"مایع شفافی از زخم خارج شد."}]},{"word":"die Folge","en":"consequence; result","ru":"следствие; последствие","vi":"hậu quả","fa":"نتیجه","examples":[{"de":"Die Folgen seiner Entscheidung waren nicht absehbar.","en":"The consequences of his decision were not foreseeable.","ru":"Последствия его решения было невозможно предвидеть.","vi":"Hậu quả của quyết định của ông là không thể lường trước được.","fa":"عواقب تصمیم او قابل پیش بینی نبود."},{"de":"Als Folge des Regens wurde das Spiel abgesagt.","en":"As a result of the rain, the game was cancelled.","ru":"Из-за дождя игру отменили.","vi":"Do trời mưa nên trò chơi đã bị hủy.","fa":"در نتیجه باران بازی لغو شد."}]},{"word":"folgen","en":"to follow","ru":"следовать","vi":"theo dõi","fa":"دنبال کنید","examples":[{"de":"Bitte folgen Sie mir, das Büro ist gleich hier.","en":"Please follow me, the office is right here.","ru":"Пожалуйста, следуйте за мной, офис прямо здесь.","vi":"Hãy đi theo tôi, văn phòng ở ngay đây.","fa":"لطفا من را دنبال کنید، دفتر اینجاست."},{"de":"Der Hund folgte seinem Besitzer auf Schritt und Tritt.","en":"The dog followed its owner everywhere.","ru":"Собака следовала за хозяином по пятам.","vi":"Con chó đi theo chủ mọi lúc mọi nơi.","fa":"The dog followed his owner wherever he went."}]},{"word":"folglich","en":"consequently; therefore","ru":"следовательно; поэтому","vi":"do đó","fa":"در نتیجه","examples":[{"de":"Er war krank und konnte folglich nicht kommen.","en":"He was ill and consequently could not come.","ru":"Он был болен и, следовательно, не смог прийти.","vi":"Anh ấy bị ốm nên không thể đến được.","fa":"او مریض بود و به همین دلیل نتوانست بیاید."},{"de":"Die Nachfrage stieg, folglich stiegen auch die Preise.","en":"Demand rose, and consequently prices rose too.","ru":"Спрос вырос, следовательно, выросли и цены.","vi":"Nhu cầu tăng lên, và kết quả là giá cả cũng tăng theo.","fa":"تقاضا افزایش یافت و در نتیجه قیمت ها نیز افزایش یافت."}]},{"word":"fordern","en":"to demand","ru":"требовать","vi":"nhu cầu","fa":"تقاضا","examples":[{"de":"Die Mitarbeiter fordern höhere Löhne.","en":"The employees are demanding higher wages.","ru":"Сотрудники требуют повышения зарплаты.","vi":"Các nhân viên đang đòi hỏi mức lương cao hơn.","fa":"کارگران خواستار افزایش دستمزد هستند."},{"de":"Der Lehrer fordert von uns pünktliche Hausaufgaben.","en":"The teacher demands that we hand in homework on time.","ru":"Учитель требует от нас сдавать домашние задания вовремя.","vi":"Giáo viên yêu cầu chúng tôi làm bài tập về nhà đúng giờ.","fa":"معلم از ما می خواهد که تکالیف خود را به موقع انجام دهیم."}]},{"word":"fördern","en":"to promote, support","ru":"поддерживать, способствовать","vi":"thúc đẩy","fa":"ترویج کنند","examples":[{"de":"Sport fördert die Gesundheit von Kindern.","en":"Sport promotes children's health.","ru":"Спорт способствует здоровью детей.","vi":"Thể thao tăng cường sức khỏe cho trẻ em.","fa":"ورزش باعث ارتقای سلامت کودکان می شود."},{"de":"Der Staat fördert junge Künstler mit Stipendien.","en":"The state supports young artists with scholarships.","ru":"Государство поддерживает молодых художников стипендиями.","vi":"Nhà nước hỗ trợ nghệ sĩ trẻ bằng học bổng.","fa":"دولت از هنرمندان جوان با بورسیه حمایت می کند."}]},{"word":"die Form","en":"shape, form","ru":"форма","vi":"hình dạng","fa":"شکل","examples":[{"de":"Der Kuchen hat die Form eines Herzens.","en":"The cake has the shape of a heart.","ru":"Торт имеет форму сердца.","vi":"Chiếc bánh có hình trái tim.","fa":"شکل کیک شبیه قلب است."},{"de":"In welcher Form möchten Sie die Information bekommen?","en":"In what form would you like to receive the information?","ru":"В какой форме вы хотите получить информацию?","vi":"Bạn muốn nhận thông tin dưới hình thức nào?","fa":"به چه شکلی می خواهید اطلاعات را دریافت کنید؟"}]},{"word":"das Formular","en":"form (document)","ru":"бланк, формуляр","vi":"hình thức","fa":"فرم","examples":[{"de":"Bitte füllen Sie dieses Formular vollständig aus.","en":"Please fill out this form completely.","ru":"Пожалуйста, заполните этот бланк полностью.","vi":"Vui lòng điền đầy đủ vào mẫu này.","fa":"لطفا این فرم را به طور کامل پر کنید."},{"de":"Das Formular für den Antrag finden Sie auf der Webseite.","en":"You can find the application form on the website.","ru":"Бланк заявления вы найдёте на сайте.","vi":"Mẫu đơn có thể được tìm thấy trên trang web.","fa":"فرم درخواست را می توان در وب سایت یافت."}]},{"word":"die Forschung","en":"research","ru":"исследование","vi":"nghiên cứu","fa":"تحقیق","examples":[{"de":"Die Forschung im Bereich der Medizin macht große Fortschritte.","en":"Research in the field of medicine is making great progress.","ru":"Исследования в области медицины делают большие успехи.","vi":"Nghiên cứu trong lĩnh vực y học đang có những tiến bộ vượt bậc.","fa":"تحقیقات در زمینه پزشکی پیشرفت زیادی دارد."},{"de":"Sie arbeitet an der Universität in der Forschung.","en":"She works in research at the university.","ru":"Она работает в сфере исследований в университете.","vi":"Cô ấy làm việc nghiên cứu ở trường đại học.","fa":"او در دانشگاه کار تحقیقاتی می کند."}]},{"word":"die Fortbildung","en":"further training","ru":"повышение квалификации","vi":"việc đào tạo","fa":"آموزش","examples":[{"de":"Meine Firma bietet regelmäßig Fortbildungen für Mitarbeiter an.","en":"My company regularly offers further training for employees.","ru":"Моя компания регулярно предлагает курсы повышения квалификации для сотрудников.","vi":"Công ty của tôi thường xuyên tổ chức đào tạo cho nhân viên.","fa":"شرکت من به طور منظم برای کارمندان آموزش ارائه می دهد."},{"de":"Nächste Woche nehme ich an einer Fortbildung zum Thema Kommunikation teil.","en":"Next week I'm taking part in a training course on communication.","ru":"На следующей неделе я участвую в курсе повышения квалификации по теме коммуникации.","vi":"Tuần tới tôi sẽ tham gia một khóa đào tạo về giao tiếp.","fa":"هفته آینده در یک دوره آموزشی در زمینه ارتباطات شرکت خواهم کرد."}]},{"word":"der Fortschritt","en":"progress","ru":"прогресс, успех","vi":"sự tiến bộ","fa":"پیشرفت","examples":[{"de":"Der Patient macht gute Fortschritte nach der Operation.","en":"The patient is making good progress after the operation.","ru":"Пациент делает хорошие успехи после операции.","vi":"Bệnh nhân đang tiến triển tốt sau phẫu thuật.","fa":"بیمار پس از جراحی پیشرفت خوبی دارد."},{"de":"In den letzten Jahren gab es großen technischen Fortschritt.","en":"In recent years there has been great technical progress.","ru":"За последние годы произошёл большой технический прогресс.","vi":"Đã có tiến bộ kỹ thuật lớn trong những năm gần đây.","fa":"در سال های اخیر پیشرفت های فنی زیادی داشته است."}]},{"word":"fortsetzen","en":"to continue","ru":"продолжать","vi":"tiếp tục","fa":"ادامه","examples":[{"de":"Wir setzen die Besprechung morgen früh fort.","en":"We will continue the meeting tomorrow morning.","ru":"Мы продолжим совещание завтра утром.","vi":"Chúng ta sẽ tiếp tục cuộc họp vào sáng mai.","fa":"فردا صبح جلسه را ادامه می دهیم."},{"de":"Nach der Pause setzte der Lehrer den Unterricht fort.","en":"After the break the teacher continued the lesson.","ru":"После перерыва учитель продолжил урок.","vi":"Sau giờ giải lao, giáo viên tiếp tục bài học.","fa":"بعد از استراحت، معلم درس را ادامه داد."}]},{"word":"das Forum","en":"forum","ru":"форум","vi":"diễn đàn","fa":"انجمن","examples":[{"de":"Im Internetforum tauschen sich viele Nutzer über das Thema aus.","en":"In the internet forum many users exchange views on the topic.","ru":"На интернет-форуме многие пользователи обмениваются мнениями по этой теме.","vi":"Nhiều người dùng trao đổi ý kiến về chủ đề này trên diễn đàn Internet.","fa":"بسیاری از کاربران در مورد این موضوع در انجمن اینترنت تبادل نظر می کنند."},{"de":"Ich habe die Antwort auf meine Frage in einem Forum gefunden.","en":"I found the answer to my question in a forum.","ru":"Я нашёл ответ на свой вопрос на форуме.","vi":"Tôi tìm thấy câu trả lời cho câu hỏi của tôi trong một diễn đàn.","fa":"جواب سوالم را در انجمن پیدا کردم."}]},{"word":"fotografieren","en":"to photograph","ru":"фотографировать","vi":"bức ảnh","fa":"عکس","examples":[{"de":"Er fotografiert gern alte Gebäude in der Stadt.","en":"He likes to photograph old buildings in the city.","ru":"Он любит фотографировать старые здания в городе.","vi":"Anh ấy thích chụp ảnh những tòa nhà cổ trong thành phố.","fa":"او از عکاسی از ساختمان های قدیمی شهر لذت می برد."},{"de":"Darf ich Sie kurz fotografieren?","en":"May I take a quick photo of you?","ru":"Можно я вас сфотографирую?","vi":"Tôi có thể chụp ảnh nhanh cho bạn được không?","fa":"میتونم سریع ازت عکس بگیرم؟"}]},{"word":"fragen","en":"to ask","ru":"спрашивать","vi":"hỏi","fa":"بپرسید","examples":[{"de":"Darf ich dich etwas fragen?","en":"May I ask you something?","ru":"Можно тебя кое о чём спросить?","vi":"Tôi có thể hỏi bạn một điều được không?","fa":"میتونم یه چیزی بپرسم؟"},{"de":"Er hat mich nach dem Weg zum Bahnhof gefragt.","en":"He asked me for directions to the train station.","ru":"Он спросил меня, как пройти к вокзалу.","vi":"Anh ấy hỏi tôi đường đến ga xe lửa.","fa":"او از من برای رسیدن به ایستگاه قطار راهنمایی خواست."}]},{"word":"die Frau","en":"woman; wife","ru":"женщина; жена","vi":"người phụ nữ","fa":"زن","examples":[{"de":"Die Frau neben mir liest ein spannendes Buch.","en":"The woman next to me is reading an exciting book.","ru":"Женщина рядом со мной читает увлекательную книгу.","vi":"Người phụ nữ bên cạnh tôi đang đọc một cuốn sách thú vị.","fa":"زن کنار من در حال خواندن یک کتاب هیجان انگیز است."},{"de":"Er stellte mir seine Frau vor.","en":"He introduced me to his wife.","ru":"Он познакомил меня со своей женой.","vi":"Anh giới thiệu tôi với vợ anh.","fa":"او مرا به همسرش معرفی کرد."}]},{"word":"frech","en":"cheeky","ru":"дерзкий, наглый","vi":"táo bạo","fa":"گستاخ","examples":[{"de":"Der kleine Junge war frech zu seiner Lehrerin.","en":"The little boy was cheeky to his teacher.","ru":"Маленький мальчик был дерзок со своей учительницей.","vi":"Cậu bé rất hỗn láo với giáo viên của mình.","fa":"پسر کوچولو با معلمش گستاخ بود."},{"de":"Sei nicht so frech, das ist unhöflich!","en":"Don't be so cheeky, that's rude!","ru":"Не будь таким дерзким, это невежливо!","vi":"Đừng táo bạo như vậy, thật thô lỗ!","fa":"اینقدر گستاخ نباش، بی ادبی است!"}]},{"word":"frei","en":"free","ru":"свободный","vi":"miễn phí","fa":"رایگان","examples":[{"de":"Ist dieser Platz noch frei?","en":"Is this seat still free?","ru":"Это место ещё свободно?","vi":"Chỗ này còn trống không?","fa":"آیا این فضا هنوز موجود است؟"},{"de":"Morgen habe ich endlich einen freien Tag.","en":"Tomorrow I finally have a day off.","ru":"Завтра у меня наконец-то выходной.","vi":"Cuối cùng ngày mai tôi cũng có một ngày nghỉ.","fa":"فردا بالاخره یک روز تعطیل دارم."}]},{"word":"die Freiheit","en":"freedom","ru":"свобода","vi":"sự tự do","fa":"آزادی","examples":[{"de":"Die Freiheit der Presse ist sehr wichtig.","en":"Freedom of the press is very important.","ru":"Свобода прессы очень важна.","vi":"Tự do báo chí là rất quan trọng.","fa":"آزادی مطبوعات بسیار مهم است."},{"de":"Nach dem Studium genoss sie ihre neue Freiheit.","en":"After graduating she enjoyed her new freedom.","ru":"После учёбы она наслаждалась своей новой свободой.","vi":"Sau khi hoàn thành việc học, cô tận hưởng sự tự do mới của mình.","fa":"پس از اتمام تحصیلات، او از آزادی جدید خود لذت برد."}]},{"word":"freiwillig","en":"voluntary","ru":"добровольный","vi":"tự nguyện","fa":"داوطلبانه","examples":[{"de":"Die Teilnahme an dem Kurs ist freiwillig.","en":"Participation in the course is voluntary.","ru":"Участие в курсе является добровольным.","vi":"Việc tham gia khóa học là tự nguyện.","fa":"شرکت در دوره داوطلبانه است."},{"de":"Er arbeitet freiwillig in einem Tierheim.","en":"He works voluntarily at an animal shelter.","ru":"Он добровольно работает в приюте для животных.","vi":"Anh ấy làm tình nguyện viên tại một nơi trú ẩn động vật.","fa":"او در یک پناهگاه حیوانات داوطلب می شود."}]},{"word":"fremd","en":"foreign, strange","ru":"чужой, незнакомый","vi":"nước ngoài","fa":"خارجی","examples":[{"de":"In einer fremden Stadt fühlt man sich am Anfang oft unsicher.","en":"In a foreign city you often feel unsure at first.","ru":"В незнакомом городе поначалу часто чувствуешь себя неуверенно.","vi":"Ở một thành phố xa lạ, ban đầu bạn thường cảm thấy không an toàn.","fa":"در یک شهر خارجی اغلب در ابتدا احساس ناامنی می کنید."},{"de":"Ein fremder Mann fragte mich nach der Uhrzeit.","en":"A stranger asked me for the time.","ru":"Незнакомый мужчина спросил меня, который час.","vi":"Một người đàn ông lạ hỏi tôi thời gian.","fa":"مرد غریبی از من ساعت را پرسید."}]},{"word":"fressen","en":"to eat (animals)","ru":"есть, жрать (о животных)","vi":"ăn","fa":"خوردن","examples":[{"de":"Die Katze frisst nur zweimal am Tag.","en":"The cat only eats twice a day.","ru":"Кошка ест только два раза в день.","vi":"Con mèo chỉ ăn hai lần một ngày.","fa":"گربه فقط دو بار در روز غذا می خورد."},{"de":"Der Hund frisst sein Futter immer sehr schnell.","en":"The dog always eats its food very fast.","ru":"Собака всегда очень быстро съедает свой корм.","vi":"Con chó luôn ăn thức ăn của mình rất nhanh.","fa":"سگ همیشه غذایش را خیلی سریع می خورد."}]},{"word":"der Freund","en":"friend; boyfriend","ru":"друг; парень (бойфренд)","vi":"người bạn","fa":"دوست","examples":[{"de":"Er ist mein bester Freund seit der Grundschule.","en":"He has been my best friend since elementary school.","ru":"Он мой лучший друг с начальной школы.","vi":"Anh ấy là bạn thân nhất của tôi từ hồi tiểu học.","fa":"او از دوران دبستان بهترین دوست من بود."},{"de":"Sie hat mir ihren neuen Freund vorgestellt.","en":"She introduced me to her new boyfriend.","ru":"Она познакомила меня со своим новым парнем.","vi":"Cô ấy giới thiệu tôi với bạn trai mới của cô ấy.","fa":"او مرا به دوست پسر جدیدش معرفی کرد."}]},{"word":"der Friede","en":"peace","ru":"мир","vi":"hòa bình","fa":"صلح","examples":[{"de":"Nach dem Krieg wünschten sich alle Frieden.","en":"After the war everyone wished for peace.","ru":"После войны все желали мира.","vi":"Sau chiến tranh, mọi người đều mong muốn hòa bình.","fa":"بعد از جنگ همه خواهان صلح بودند."},{"de":"Die beiden Länder leben seit Jahrzehnten in Frieden.","en":"The two countries have lived in peace for decades.","ru":"Обе страны живут в мире уже несколько десятилетий.","vi":"Hai nước đã chung sống hòa bình trong nhiều thập kỷ.","fa":"دو کشور ده ها سال در صلح زندگی کرده اند."}]},{"word":"frieren","en":"to freeze, be cold","ru":"мёрзнуть","vi":"đóng băng","fa":"منجمد کردن","examples":[{"de":"Ich friere, kannst du bitte das Fenster schließen?","en":"I'm cold, can you please close the window?","ru":"Мне холодно, можешь закрыть окно?","vi":"Tôi lạnh cóng, bạn có thể đóng cửa sổ được không?","fa":"دارم یخ میزنم، میشه لطفا پنجره رو ببندی؟"},{"de":"Ohne Jacke friert man im Winter schnell.","en":"Without a jacket you freeze quickly in winter.","ru":"Без куртки зимой быстро замерзаешь.","vi":"Không có áo khoác bạn sẽ nhanh chóng bị lạnh vào mùa đông.","fa":"بدون ژاکت در زمستان به سرعت سرد می شوید."}]},{"word":"frisch","en":"fresh","ru":"свежий","vi":"tươi","fa":"تازه","examples":[{"de":"Der Fisch auf dem Markt ist heute besonders frisch.","en":"The fish at the market is especially fresh today.","ru":"Рыба на рынке сегодня особенно свежая.","vi":"Cá ở chợ hôm nay đặc biệt tươi ngon.","fa":"ماهی در بازار امروز به خصوص تازه است."},{"de":"Ich brauche jeden Morgen frische Luft.","en":"I need fresh air every morning.","ru":"Мне каждое утро нужен свежий воздух.","vi":"Tôi cần không khí trong lành mỗi sáng.","fa":"من هر روز صبح به هوای تازه نیاز دارم."}]},{"word":"der Friseur","en":"hairdresser","ru":"парикмахер","vi":"thợ làm tóc","fa":"آرایشگاه","examples":[{"de":"Ich habe morgen einen Termin beim Friseur.","en":"I have an appointment at the hairdresser's tomorrow.","ru":"Завтра у меня запись к парикмахеру.","vi":"Tôi có cuộc hẹn ở tiệm làm tóc vào ngày mai.","fa":"فردا قرار آرایشگاه دارم."},{"de":"Der Friseur hat mir die Haare viel zu kurz geschnitten.","en":"The hairdresser cut my hair far too short.","ru":"Парикмахер подстриг меня слишком коротко.","vi":"Thợ làm tóc đã cắt tóc của tôi quá ngắn.","fa":"آرایشگر موهایم را خیلی کوتاه کرد."}]},{"word":"die Frist","en":"deadline","ru":"срок","vi":"thời hạn","fa":"مهلت","examples":[{"de":"Die Frist für die Anmeldung endet am Freitag.","en":"The deadline for registration ends on Friday.","ru":"Срок регистрации заканчивается в пятницу.","vi":"Hạn chót đăng ký kết thúc vào thứ Sáu.","fa":"مهلت ثبت نام روز جمعه به پایان می رسد."},{"de":"Wir müssen die Frist unbedingt einhalten.","en":"We absolutely have to meet the deadline.","ru":"Нам обязательно нужно уложиться в срок.","vi":"Chúng ta nhất định phải đáp ứng đúng thời hạn.","fa":"ما قطعا باید ضرب الاجل را رعایت کنیم."}]},{"word":"froh","en":"glad, happy","ru":"радостный, довольный","vi":"vui mừng","fa":"خوشحالم","examples":[{"de":"Ich bin froh, dass du wieder gesund bist.","en":"I'm glad that you're healthy again.","ru":"Я рад, что ты снова здоров.","vi":"Tôi mừng vì bạn đã khỏe lại.","fa":"خوشحالم که دوباره سالم هستی"},{"de":"Wir waren alle sehr froh über die gute Nachricht.","en":"We were all very happy about the good news.","ru":"Мы все очень обрадовались хорошей новости.","vi":"Tất cả chúng tôi đều rất vui mừng về tin vui này.","fa":"همه ما از این خبر خوب بسیار خوشحال شدیم."}]},{"word":"die Frucht","en":"fruit","ru":"фрукт, плод","vi":"trái cây","fa":"میوه","examples":[{"de":"Auf dem Markt gibt es viele frische Früchte.","en":"There is a lot of fresh fruit at the market.","ru":"На рынке много свежих фруктов.","vi":"Có rất nhiều trái cây tươi trên thị trường.","fa":"میوه های تازه زیادی در بازار وجود دارد."},{"de":"Diese Frucht schmeckt süß und ein bisschen sauer.","en":"This fruit tastes sweet and a bit sour.","ru":"Этот фрукт на вкус сладкий и немного кислый.","vi":"Loại quả này có vị ngọt và hơi chua.","fa":"طعم این میوه شیرین و کمی ترش است."}]},{"word":"früh","en":"early","ru":"рано","vi":"sớm","fa":"اوایل","examples":[{"de":"Am Montag muss ich sehr früh aufstehen.","en":"On Monday I have to get up very early.","ru":"В понедельник мне нужно встать очень рано.","vi":"Vào thứ Hai tôi phải dậy rất sớm.","fa":"دوشنبه باید خیلی زود بیدار بشم."},{"de":"Wir sind früh am Bahnhof angekommen.","en":"We arrived at the train station early.","ru":"Мы рано приехали на вокзал.","vi":"Chúng tôi đến ga xe lửa sớm.","fa":"زود به ایستگاه قطار رسیدیم."}]},{"word":"früher","en":"earlier, formerly","ru":"раньше, прежде","vi":"trước đó","fa":"زودتر","examples":[{"de":"Früher gab es hier keine U-Bahn.","en":"In the past there was no subway here.","ru":"Раньше здесь не было метро.","vi":"Ở đây từng không có tàu điện ngầm.","fa":"قبلا اینجا مترو نبود."},{"de":"Kannst du morgen etwas früher kommen?","en":"Can you come a bit earlier tomorrow?","ru":"Можешь завтра прийти немного раньше?","vi":"Ngày mai bạn có thể đến sớm hơn một chút được không?","fa":"میشه فردا کمی زودتر بیای؟"}]},{"word":"frühstücken","en":"to have breakfast","ru":"завтракать","vi":"ăn sáng","fa":"صبحانه بخور","examples":[{"de":"Wir frühstücken normalerweise um sieben Uhr.","en":"We usually have breakfast at seven o'clock.","ru":"Мы обычно завтракаем в семь часов.","vi":"Chúng tôi thường ăn sáng lúc bảy giờ.","fa":"ما معمولا ساعت هفت صبحانه می خوریم."},{"de":"Am Wochenende frühstücken wir gerne lange und in Ruhe.","en":"On weekends we like to have a long, relaxed breakfast.","ru":"По выходным мы любим долго и спокойно завтракать.","vi":"Vào cuối tuần, chúng tôi thích có một bữa sáng dài và yên tĩnh.","fa":"آخر هفته ها دوست داریم یک صبحانه طولانی و آرام بخوریم."}]},{"word":"fühlen","en":"to feel","ru":"чувствовать","vi":"cảm thấy","fa":"احساس کنید","examples":[{"de":"Wie fühlst du dich heute?","en":"How do you feel today?","ru":"Как ты себя чувствуешь сегодня?","vi":"Hôm nay bạn cảm thấy thế nào?","fa":"امروز چه احساسی دارید؟"},{"de":"Ich fühle mich in dieser Stadt sehr wohl.","en":"I feel very comfortable in this city.","ru":"Я чувствую себя очень уютно в этом городе.","vi":"Tôi cảm thấy rất thoải mái ở thành phố này.","fa":"من در این شهر احساس راحتی می کنم."}]},{"word":"führen","en":"to lead","ru":"вести, руководить","vi":"chì","fa":"منجر شود","examples":[{"de":"Dieser Weg führt direkt zum See.","en":"This path leads directly to the lake.","ru":"Эта тропа ведёт прямо к озеру.","vi":"Con đường này dẫn thẳng tới hồ.","fa":"این مسیر مستقیماً به دریاچه منتهی می شود."},{"de":"Sie führt seit fünf Jahren die Abteilung.","en":"She has been leading the department for five years.","ru":"Она руководит отделом уже пять лет.","vi":"Cô đã lãnh đạo bộ phận này được 5 năm.","fa":"او پنج سال است که این بخش را رهبری می کند."}]},{"word":"der Führerausweis","en":"driving licence","ru":"водительские права","vi":"giấy phép lái xe","fa":"گواهینامه رانندگی","examples":[{"de":"In der Schweiz braucht man einen Führerausweis, um Auto zu fahren.","en":"In Switzerland you need a driving licence to drive a car.","ru":"В Швейцарии нужны водительские права, чтобы водить машину.","vi":"Ở Thụy Sĩ bạn cần có bằng lái xe để lái ô tô.","fa":"در سوئیس برای رانندگی خودرو به گواهینامه رانندگی نیاز دارید."},{"de":"Er hat seinen Führerausweis letzte Woche gemacht.","en":"He got his driving licence last week.","ru":"Он получил водительские права на прошлой неделе.","vi":"Anh ấy đã lấy được bằng lái xe vào tuần trước.","fa":"او هفته گذشته گواهینامه رانندگی خود را گرفت."}]},{"word":"der Führerschein","en":"driving licence","ru":"водительские права","vi":"giấy phép lái xe","fa":"گواهینامه رانندگی","examples":[{"de":"Ich habe mit achtzehn meinen Führerschein gemacht.","en":"I got my driving licence when I was eighteen.","ru":"Я получил водительские права в восемнадцать лет.","vi":"Tôi có bằng lái xe khi tôi mười tám tuổi.","fa":"در هجده سالگی گواهینامه رانندگی گرفتم."},{"de":"Hast du deinen Führerschein dabei?","en":"Do you have your driving licence with you?","ru":"У тебя с собой водительские права?","vi":"Bạn có mang theo bằng lái xe không?","fa":"آیا گواهینامه رانندگی خود را همراه دارید؟"}]},{"word":"das Fundbüro","en":"lost and found office","ru":"бюро находок","vi":"văn phòng thất lạc và tìm thấy","fa":"دفتر گم شده و پیدا شده","examples":[{"de":"Ich habe meinen Regenschirm im Bus vergessen und muss zum Fundbüro gehen.","en":"I left my umbrella on the bus and have to go to the lost and found office.","ru":"Я забыл зонт в автобусе и должен пойти в бюро находок.","vi":"Tôi để quên ô trên xe buýt và phải đến văn phòng thất lạc tài sản.","fa":"چترم را در اتوبوس فراموش کردم و باید به دفتر اموال گمشده بروم."},{"de":"Das Fundbüro am Bahnhof hat meinen Koffer gefunden.","en":"The lost and found office at the station found my suitcase.","ru":"Бюро находок на вокзале нашло мой чемодан.","vi":"Phòng quản lý tài sản thất lạc ở nhà ga đã tìm thấy va li của tôi.","fa":"دفتر اموال گمشده در ایستگاه قطار چمدان مرا پیدا کرد."}]},{"word":"funktionieren","en":"to work, function","ru":"работать, функционировать","vi":"làm việc","fa":"کار کردن","examples":[{"de":"Mein Handy funktioniert seit gestern nicht mehr richtig.","en":"My phone hasn't been working properly since yesterday.","ru":"Мой телефон с вчерашнего дня работает неправильно.","vi":"Điện thoại di động của tôi đã không hoạt động bình thường kể từ hôm qua.","fa":"تلفن همراه من از دیروز درست کار نمی کند."},{"de":"Die neue App funktioniert wirklich gut.","en":"The new app really works well.","ru":"Новое приложение работает действительно хорошо.","vi":"Ứng dụng mới hoạt động thực sự tốt.","fa":"برنامه جدید واقعاً خوب کار می کند."}]},{"word":"für","en":"for","ru":"для, за","vi":"cho","fa":"برای","examples":[{"de":"Dieses Geschenk ist für dich.","en":"This gift is for you.","ru":"Этот подарок для тебя.","vi":"Món quà này là dành cho bạn.","fa":"این هدیه برای شماست."},{"de":"Ich habe mich für den neuen Job entschieden.","en":"I decided on the new job.","ru":"Я решил в пользу новой работы.","vi":"Tôi đã quyết định về công việc mới.","fa":"من برای کار جدید تصمیم گرفته ام."}]},{"word":"furchtbar","en":"terrible, awful","ru":"ужасный","vi":"khủng khiếp","fa":"وحشتناک","examples":[{"de":"Das Wetter heute ist furchtbar kalt.","en":"The weather today is terribly cold.","ru":"Погода сегодня ужасно холодная.","vi":"Thời tiết hôm nay lạnh khủng khiếp.","fa":"هوا امروز به طرز وحشتناکی سرد است."},{"de":"Es tut mir furchtbar leid, dass ich zu spät bin.","en":"I'm terribly sorry that I'm late.","ru":"Мне ужасно жаль, что я опоздал.","vi":"Tôi vô cùng xin lỗi tôi đến muộn.","fa":"خیلی متاسفم که دیر اومدم"}]},{"word":"der Fuß","en":"foot","ru":"нога, стопа","vi":"bàn chân","fa":"پا","examples":[{"de":"Ich habe mir gestern beim Sport am Fuß verletzt.","en":"I injured my foot yesterday while doing sports.","ru":"Вчера во время спорта я повредил ногу.","vi":"Tôi bị thương ở chân khi chơi thể thao ngày hôm qua.","fa":"دیروز در حین ورزش پایم آسیب دید."},{"de":"Wir gehen jeden Tag zu Fuß zur Arbeit.","en":"We walk to work every day.","ru":"Мы каждый день ходим на работу пешком.","vi":"Chúng tôi đi bộ đi làm hàng ngày.","fa":"ما هر روز پیاده روی سر کار می رویم."}]},{"word":"die Fußgängerzone","en":"pedestrian zone","ru":"пешеходная зона","vi":"khu vực dành cho người đi bộ","fa":"منطقه عابر پیاده","examples":[{"de":"In der Fußgängerzone dürfen keine Autos fahren.","en":"No cars are allowed to drive in the pedestrian zone.","ru":"В пешеходной зоне запрещено движение автомобилей.","vi":"Ô tô không được phép đi vào khu vực dành cho người đi bộ.","fa":"تردد خودروها در محدوده عابر پیاده ممنوع است."},{"de":"Die Geschäfte in der Fußgängerzone sind samstags gut besucht.","en":"The shops in the pedestrian zone are busy on Saturdays.","ru":"Магазины в пешеходной зоне по субботам хорошо посещаются.","vi":"Các cửa hàng ở khu vực dành cho người đi bộ luôn tấp nập vào ngày thứ Bảy.","fa":"مغازه های منطقه عابر پیاده شنبه ها شلوغ هستند."}]},{"word":"füttern","en":"to feed","ru":"кормить","vi":"thức ăn","fa":"خوراک","examples":[{"de":"Bitte füttere die Katze, bevor du zur Schule gehst.","en":"Please feed the cat before you go to school.","ru":"Покорми, пожалуйста, кошку, прежде чем идти в школу.","vi":"Hãy cho mèo ăn trước khi đến trường.","fa":"لطفا قبل از رفتن به مدرسه به گربه غذا بدهید."},{"de":"Man sollte Enten im Park nicht mit Brot füttern.","en":"You shouldn't feed ducks in the park with bread.","ru":"Не стоит кормить уток в парке хлебом.","vi":"Bạn không nên cho vịt ăn bánh mì trong công viên.","fa":"در پارک نباید به اردک ها نان بدهید."}]},{"word":"die Gabel","en":"fork","ru":"вилка","vi":"cái nĩa","fa":"چنگال","examples":[{"de":"Kannst du mir bitte eine Gabel geben?","en":"Can you give me a fork, please?","ru":"Можешь дать мне вилку?","vi":"Bạn có thể vui lòng cho tôi một cái nĩa được không?","fa":"میشه لطفا یک چنگال به من بدهید؟"},{"de":"In manchen Ländern isst man ohne Messer und Gabel.","en":"In some countries people eat without a knife and fork.","ru":"В некоторых странах едят без ножа и вилки.","vi":"Ở một số nước người ta ăn mà không dùng dao và nĩa.","fa":"در برخی کشورها مردم بدون چاقو و چنگال غذا می خورند."}]},{"word":"die Galerie","en":"gallery","ru":"галерея","vi":"phòng trưng bày","fa":"گالری","examples":[{"de":"Am Wochenende besuchen wir eine Galerie mit moderner Kunst.","en":"On the weekend we're visiting a gallery with modern art.","ru":"На выходных мы посетим галерею современного искусства.","vi":"Vào cuối tuần, chúng tôi ghé thăm một phòng trưng bày nghệ thuật hiện đại.","fa":"در آخر هفته از یک گالری با هنر مدرن بازدید می کنیم."},{"de":"Die Galerie zeigt Bilder junger Künstler.","en":"The gallery is showing paintings by young artists.","ru":"Галерея выставляет картины молодых художников.","vi":"Phòng trưng bày trưng bày hình ảnh của các nghệ sĩ trẻ.","fa":"گالری تصاویر هنرمندان جوان را نشان می دهد."}]},{"word":"der Gang","en":"corridor; gear","ru":"коридор; передача (в машине)","vi":"lối đi","fa":"راهرو","examples":[{"de":"Das Klassenzimmer liegt am Ende des Gangs.","en":"The classroom is at the end of the corridor.","ru":"Классная комната находится в конце коридора.","vi":"Lớp học nằm ở cuối hành lang.","fa":"کلاس در انتهای راهرو است."},{"de":"Beim Bergauffahren muss man einen niedrigeren Gang einlegen.","en":"When driving uphill you have to shift into a lower gear.","ru":"При подъёме в гору нужно включить более низкую передачу.","vi":"Khi lái xe lên dốc bạn phải sử dụng số thấp hơn.","fa":"هنگام رانندگی در سربالایی باید از دنده پایین تر استفاده کنید."}]},{"word":"ganz","en":"whole; entirely","ru":"весь; совсем","vi":"hoàn toàn","fa":"به طور کامل","examples":[{"de":"Ich habe den ganzen Kuchen gegessen.","en":"I ate the whole cake.","ru":"Я съел весь торт.","vi":"Tôi đã ăn hết cái bánh.","fa":"من کل کیک رو خوردم"},{"de":"Das Wetter war ganz schön schlecht.","en":"The weather was quite bad.","ru":"Погода была довольно плохой.","vi":"Thời tiết khá tệ.","fa":"هوا خیلی بد بود"}]},{"word":"gar","en":"at all (in negation); done, cooked","ru":"вовсе (при отрицании); готовый (о еде)","vi":"thậm chí","fa":"حتی","examples":[{"de":"Ich habe gar keine Zeit heute.","en":"I have no time at all today.","ru":"У меня сегодня вообще нет времени.","vi":"Hôm nay tôi không có thời gian.","fa":"امروز وقت ندارم"},{"de":"Die Kartoffeln sind noch nicht gar.","en":"The potatoes aren't cooked yet.","ru":"Картофель ещё не готов.","vi":"Khoai tây vẫn chưa chín.","fa":"سیب زمینی ها هنوز پخته نشده اند."}]},{"word":"die Garage","en":"garage","ru":"гараж","vi":"nhà để xe","fa":"گاراژ","examples":[{"de":"Wir parken das Auto in der Garage.","en":"We park the car in the garage.","ru":"Мы паркуем машину в гараже.","vi":"Chúng tôi đậu xe trong gara.","fa":"ماشین را در گاراژ پارک می کنیم."},{"de":"Die Garage ist neben dem Haus.","en":"The garage is next to the house.","ru":"Гараж находится рядом с домом.","vi":"Gara nằm cạnh nhà.","fa":"گاراژ کنار خانه است."}]},{"word":"garantieren","en":"to guarantee","ru":"гарантировать","vi":"đảm bảo","fa":"تضمین می کند","examples":[{"de":"Der Verkäufer garantiert die Qualität des Produkts.","en":"The seller guarantees the quality of the product.","ru":"Продавец гарантирует качество товара.","vi":"Người bán đảm bảo chất lượng của sản phẩm.","fa":"فروشنده کیفیت محصول را تضمین می کند."},{"de":"Ich kann dir nicht garantieren, dass alles klappt.","en":"I can't guarantee you that everything will work out.","ru":"Я не могу гарантировать тебе, что всё получится.","vi":"Tôi không thể đảm bảo với bạn rằng mọi việc sẽ ổn thỏa.","fa":"من نمی توانم به شما تضمین دهم که همه چیز درست می شود."}]},{"word":"die Garderobe","en":"cloakroom, wardrobe","ru":"гардероб","vi":"tủ quần áo","fa":"کمد لباس","examples":[{"de":"Bitte geben Sie Ihren Mantel an der Garderobe ab.","en":"Please leave your coat at the cloakroom.","ru":"Пожалуйста, сдайте пальто в гардероб.","vi":"Vui lòng để áo khoác của bạn ở phòng thay đồ.","fa":"لطفا کت خود را در رختکن بگذارید."},{"de":"Ihre Garderobe zu Hause ist sehr groß.","en":"Her wardrobe at home is very large.","ru":"Её гардероб дома очень большой.","vi":"Tủ quần áo ở nhà của bạn rất lớn.","fa":"کمد لباس شما در خانه بسیار بزرگ است."}]},{"word":"der Garten","en":"garden","ru":"сад","vi":"khu vườn","fa":"باغ","examples":[{"de":"Im Sommer arbeiten wir viel im Garten.","en":"In summer we work a lot in the garden.","ru":"Летом мы много работаем в саду.","vi":"Vào mùa hè, chúng tôi làm việc rất nhiều trong vườn.","fa":"در تابستان زیاد در باغ کار می کنیم."},{"de":"Die Kinder spielen im Garten.","en":"The children are playing in the garden.","ru":"Дети играют в саду.","vi":"Bọn trẻ đang chơi trong vườn.","fa":"بچه ها در باغ بازی می کنند."}]},{"word":"das Gas","en":"gas","ru":"газ","vi":"khí đốt","fa":"گاز","examples":[{"de":"Wir heizen die Wohnung mit Gas.","en":"We heat the apartment with gas.","ru":"Мы отапливаем квартиру газом.","vi":"Chúng tôi sưởi ấm căn hộ bằng gas.","fa":"آپارتمان را با گاز گرم می کنیم."},{"de":"Der Herd funktioniert mit Gas.","en":"The stove runs on gas.","ru":"Плита работает на газе.","vi":"Bếp hoạt động bằng gas.","fa":"اجاق گاز با گاز کار می کند."}]},{"word":"der Gast","en":"guest","ru":"гость","vi":"khách","fa":"مهمان","examples":[{"de":"Wir erwarten heute Abend Gäste.","en":"We are expecting guests tonight.","ru":"Сегодня вечером мы ждём гостей.","vi":"Chúng tôi đang mong đợi khách tối nay.","fa":"امشب منتظر مهمان هستیم."},{"de":"Der Gast bestellt ein Glas Wein.","en":"The guest orders a glass of wine.","ru":"Гость заказывает бокал вина.","vi":"Người khách gọi một ly rượu.","fa":"مهمان یک لیوان شراب سفارش می دهد."}]},{"word":"das Gebäck","en":"pastry, baked goods","ru":"выпечка","vi":"bánh ngọt","fa":"شیرینی ها","examples":[{"de":"Zum Kaffee gibt es frisches Gebäck.","en":"There's fresh pastry with the coffee.","ru":"К кофе подают свежую выпечку.","vi":"Có bánh ngọt tươi với cà phê.","fa":"شیرینی های تازه با قهوه وجود دارد."},{"de":"Sie hat für das Fest Gebäck gebacken.","en":"She baked pastries for the party.","ru":"Она испекла выпечку к празднику.","vi":"Cô nướng bánh ngọt cho lễ hội.","fa":"او برای جشنواره شیرینی پخت."}]},{"word":"das Gebäude","en":"building","ru":"здание","vi":"tòa nhà","fa":"ساختمان","examples":[{"de":"Das Gebäude ist über hundert Jahre alt.","en":"The building is over a hundred years old.","ru":"Зданию больше ста лет.","vi":"Tòa nhà đã hơn một trăm năm tuổi.","fa":"قدمت این بنا بیش از صد سال است."},{"de":"In diesem Gebäude befindet sich das Büro.","en":"The office is located in this building.","ru":"В этом здании находится офис.","vi":"Văn phòng nằm trong tòa nhà này.","fa":"دفتر در این ساختمان واقع شده است."}]},{"word":"geben","en":"to give","ru":"давать","vi":"cho","fa":"دادن","examples":[{"de":"Kannst du mir bitte das Buch geben?","en":"Can you please give me the book?","ru":"Можешь дать мне книгу, пожалуйста?","vi":"Bạn có thể vui lòng cho tôi cuốn sách được không?","fa":"میشه لطفا کتاب رو به من بدید؟"},{"de":"Es gibt heute keine Schule.","en":"There is no school today.","ru":"Сегодня нет школы.","vi":"Hôm nay không có trường học.","fa":"امروز مدرسه نیست."}]},{"word":"das Gebiet","en":"area, region","ru":"область, район","vi":"khu vực","fa":"منطقه","examples":[{"de":"In diesem Gebiet gibt es viele Wälder.","en":"There are many forests in this area.","ru":"В этой области много лесов.","vi":"Có rất nhiều rừng ở khu vực này.","fa":"جنگل های زیادی در این منطقه وجود دارد."},{"de":"Er ist Experte auf seinem Gebiet.","en":"He is an expert in his field.","ru":"Он эксперт в своей области.","vi":"Anh ấy là một chuyên gia trong lĩnh vực của mình.","fa":"او در رشته خود متخصص است."}]},{"word":"das Gebirge","en":"mountains, mountain range","ru":"горы, горный массив","vi":"những ngọn núi","fa":"کوه ها","examples":[{"de":"Wir fahren im Urlaub ins Gebirge.","en":"We're going to the mountains on vacation.","ru":"В отпуске мы едем в горы.","vi":"Chúng tôi đang đi nghỉ ở vùng núi.","fa":"ما برای تعطیلات به کوه می رویم."},{"de":"Das Gebirge ist im Winter mit Schnee bedeckt.","en":"The mountain range is covered with snow in winter.","ru":"Зимой горы покрыты снегом.","vi":"Những ngọn núi được bao phủ bởi tuyết vào mùa đông.","fa":"کوه ها در زمستان پوشیده از برف هستند."}]},{"word":"geboren werden","en":"to be born","ru":"родиться","vi":"được sinh ra","fa":"متولد شود","examples":[{"de":"Meine Schwester wurde 1995 geboren.","en":"My sister was born in 1995.","ru":"Моя сестра родилась в 1995 году.","vi":"Em gái tôi sinh năm 1995.","fa":"خواهرم متولد 1374 است."},{"de":"Wo bist du geboren?","en":"Where were you born?","ru":"Где ты родился?","vi":"Bạn sinh ra ở đâu?","fa":"کجا متولد شدی؟"}]},{"word":"gebrauchen","en":"to use","ru":"использовать, употреблять","vi":"sử dụng","fa":"استفاده کنید","examples":[{"de":"Ich kann deine Hilfe gut gebrauchen.","en":"I can really use your help.","ru":"Мне очень пригодится твоя помощь.","vi":"Tôi thực sự có thể sử dụng sự giúp đỡ của bạn.","fa":"من واقعا می توانم از کمک شما استفاده کنم."},{"de":"Dieses Werkzeug wird selten gebraucht.","en":"This tool is rarely used.","ru":"Этот инструмент используется редко.","vi":"Công cụ này hiếm khi được sử dụng.","fa":"این ابزار به ندرت استفاده می شود."}]},{"word":"die Gebrauchsanweisung","en":"instructions for use","ru":"инструкция по применению","vi":"hướng dẫn sử dụng","fa":"دستورالعمل استفاده","examples":[{"de":"Lies zuerst die Gebrauchsanweisung, bevor du das Gerät benutzt.","en":"Read the instructions first before using the device.","ru":"Сначала прочитай инструкцию, прежде чем пользоваться прибором.","vi":"Đọc hướng dẫn trước khi sử dụng thiết bị.","fa":"قبل از استفاده از دستگاه ابتدا دستورالعمل ها را بخوانید."},{"de":"Die Gebrauchsanweisung liegt der Packung bei.","en":"The instructions are included with the package.","ru":"Инструкция прилагается к упаковке.","vi":"Hướng dẫn sử dụng được bao gồm trong gói.","fa":"دستورالعمل استفاده در بسته موجود است."}]},{"word":"die Gebühr","en":"fee","ru":"сбор, плата","vi":"lệ phí","fa":"هزینه","examples":[{"de":"Für die Nutzung fällt eine kleine Gebühr an.","en":"A small fee is charged for use.","ru":"За пользование взимается небольшая плата.","vi":"Có một khoản phí nhỏ để sử dụng.","fa":"هزینه کمی برای استفاده وجود دارد."},{"de":"Die Bank erhebt Gebühren für die Kontoführung.","en":"The bank charges fees for account management.","ru":"Банк взимает плату за ведение счёта.","vi":"Ngân hàng tính phí quản lý tài khoản.","fa":"بانک برای مدیریت حساب کارمزد دریافت می کند."}]},{"word":"die Geburt","en":"birth","ru":"рождение","vi":"sự ra đời","fa":"تولد","examples":[{"de":"Die Geburt des Kindes war ein großes Glück.","en":"The birth of the child was a great joy.","ru":"Рождение ребёнка было большим счастьем.","vi":"Sự ra đời của đứa trẻ là một niềm hạnh phúc lớn lao.","fa":"تولد فرزند نعمت بزرگی بود."},{"de":"Nach der Geburt bleibt die Mutter einige Tage im Krankenhaus.","en":"After the birth, the mother stays in the hospital for a few days.","ru":"После родов мать остаётся в больнице несколько дней.","vi":"Sau khi sinh, người mẹ ở lại bệnh viện vài ngày.","fa":"پس از زایمان، مادر چند روز در بیمارستان می ماند."}]},{"word":"das Gedicht","en":"poem","ru":"стихотворение","vi":"bài thơ","fa":"شعر","examples":[{"de":"Die Schüler lernen ein Gedicht auswendig.","en":"The students are learning a poem by heart.","ru":"Ученики учат стихотворение наизусть.","vi":"Học sinh ghi nhớ một bài thơ.","fa":"دانش آموزان یک شعر را حفظ می کنند."},{"de":"Er hat seiner Frau ein Gedicht geschrieben.","en":"He wrote a poem for his wife.","ru":"Он написал стихотворение для своей жены.","vi":"Anh viết bài thơ tặng vợ.","fa":"برای همسرش شعری نوشت."}]},{"word":"die Geduld","en":"patience","ru":"терпение","vi":"sự kiên nhẫn","fa":"صبر","examples":[{"de":"Bei diesem Job braucht man viel Geduld.","en":"You need a lot of patience for this job.","ru":"Для этой работы нужно много терпения.","vi":"Công việc này đòi hỏi rất nhiều kiên nhẫn.","fa":"این کار به صبر و حوصله زیادی نیاز دارد."},{"de":"Meine Geduld ist gleich zu Ende.","en":"My patience is about to run out.","ru":"Моё терпение вот-вот закончится.","vi":"Sự kiên nhẫn của tôi sắp cạn kiệt rồi.","fa":"صبرم داره تموم میشه"}]},{"word":"geehrt","en":"honored, esteemed","ru":"уважаемый, почтённый","vi":"vinh dự","fa":"مفتخر شد","examples":[{"de":"Sehr geehrte Damen und Herren, ich schreibe Ihnen wegen meiner Bewerbung.","en":"Dear Sir or Madam, I am writing to you regarding my application.","ru":"Уважаемые дамы и господа, я пишу вам по поводу моей заявки.","vi":"Thưa ông hoặc bà, tôi viết thư này cho bạn về đơn đăng ký của tôi.","fa":"آقا یا خانم عزیز، من در مورد درخواستم برای شما می نویسم."},{"de":"Wir fühlen uns geehrt, Sie bei uns begrüßen zu dürfen.","en":"We feel honored to welcome you here.","ru":"Мы польщены возможностью приветствовать вас у себя.","vi":"Chúng tôi rất vinh dự được chào đón bạn.","fa":"استقبال از شما مفتخریم"}]},{"word":"geeignet","en":"suitable","ru":"подходящий","vi":"phù hợp","fa":"مناسب","examples":[{"de":"Dieser Film ist nicht für Kinder geeignet.","en":"This movie is not suitable for children.","ru":"Этот фильм не подходит для детей.","vi":"Bộ phim này không phù hợp với trẻ em.","fa":"این فیلم برای کودکان مناسب نیست."},{"de":"Sie ist die geeignete Person für diese Aufgabe.","en":"She is the right person for this task.","ru":"Она подходящий человек для этой задачи.","vi":"Cô ấy là người phù hợp cho nhiệm vụ này.","fa":"او فرد مناسبی برای این کار است."}]},{"word":"die Gefahr","en":"danger","ru":"опасность","vi":"sự nguy hiểm","fa":"خطر","examples":[{"de":"Bei Sturm besteht Gefahr im Wald.","en":"There is danger in the forest during a storm.","ru":"Во время шторма в лесу есть опасность.","vi":"Có mối nguy hiểm trong rừng khi có bão.","fa":"در هنگام طوفان خطری در جنگل وجود دارد."},{"de":"Rauchen ist eine Gefahr für die Gesundheit.","en":"Smoking is a danger to health.","ru":"Курение опасно для здоровья.","vi":"Hút thuốc là một mối nguy hiểm cho sức khỏe.","fa":"سیگار کشیدن یک خطر برای سلامتی است."}]},{"word":"gefährlich","en":"dangerous","ru":"опасный","vi":"nguy hiểm","fa":"خطرناک","examples":[{"de":"Das Schwimmen in diesem Fluss ist gefährlich.","en":"Swimming in this river is dangerous.","ru":"Плавать в этой реке опасно.","vi":"Bơi ở con sông này rất nguy hiểm.","fa":"شنا در این رودخانه خطرناک است."},{"de":"Bei Glatteis ist das Autofahren besonders gefährlich.","en":"Driving is especially dangerous in icy conditions.","ru":"В гололёд водить машину особенно опасно.","vi":"Lái xe đặc biệt nguy hiểm khi có băng đen.","fa":"رانندگی به ویژه در صورت وجود یخ سیاه خطرناک است."}]},{"word":"gefallen","en":"to like, to please","ru":"нравиться","vi":"thích","fa":"دوست داشت","examples":[{"de":"Das Kleid gefällt mir sehr gut.","en":"I like the dress very much.","ru":"Это платье мне очень нравится.","vi":"Tôi thích chiếc váy rất nhiều.","fa":"من لباس را خیلی دوست دارم."},{"de":"Wie hat dir der Film gefallen?","en":"How did you like the movie?","ru":"Как тебе понравился фильм?","vi":"Bạn thích bộ phim như thế nào?","fa":"فیلم را چگونه دوست داشتید؟"}]},{"word":"das Gefängnis","en":"prison","ru":"тюрьма","vi":"nhà tù","fa":"زندان","examples":[{"de":"Der Dieb wurde ins Gefängnis gebracht.","en":"The thief was taken to prison.","ru":"Вора отправили в тюрьму.","vi":"Tên trộm bị bắt vào tù.","fa":"دزد را به زندان بردند."},{"de":"Er saß drei Jahre im Gefängnis.","en":"He was in prison for three years.","ru":"Он отсидел три года в тюрьме.","vi":"Anh ta đã ngồi tù ba năm.","fa":"او سه سال در زندان سپری کرد."}]},{"word":"das Gefühl","en":"feeling","ru":"чувство","vi":"cảm giác","fa":"احساس","examples":[{"de":"Ich habe ein komisches Gefühl bei dieser Sache.","en":"I have a strange feeling about this matter.","ru":"У меня странное чувство по поводу этого дела.","vi":"Tôi có một cảm giác kỳ lạ về điều này.","fa":"احساس عجیبی در این مورد دارم."},{"de":"Sie zeigt ihre Gefühle nicht gern.","en":"She doesn't like to show her feelings.","ru":"Она не любит показывать свои чувства.","vi":"Cô ấy không thích thể hiện cảm xúc của mình.","fa":"او دوست ندارد احساسات خود را نشان دهد."}]},{"word":"gegen","en":"against; around (time)","ru":"против; около (о времени)","vi":"chống lại","fa":"علیه","examples":[{"de":"Die Mannschaft spielt heute gegen den Tabellenführer.","en":"The team is playing against the league leader today.","ru":"Сегодня команда играет против лидера таблицы.","vi":"Hôm nay đội thi đấu với đội dẫn đầu giải đấu.","fa":"این تیم امروز به مصاف رهبران لیگ می رود."},{"de":"Ich komme gegen acht Uhr nach Hause.","en":"I'll come home around eight o'clock.","ru":"Я приду домой около восьми часов.","vi":"Tôi về nhà vào khoảng tám giờ.","fa":"حوالی ساعت هشت به خانه می رسم."}]},{"word":"die Gegend","en":"area, region","ru":"местность, район","vi":"khu vực","fa":"منطقه","examples":[{"de":"Wir wohnen in einer ruhigen Gegend.","en":"We live in a quiet area.","ru":"Мы живём в тихом районе.","vi":"Chúng tôi sống trong một khu vực yên tĩnh.","fa":"ما در یک منطقه آرام زندگی می کنیم."},{"de":"Kennst du eine gute Gegend zum Wandern?","en":"Do you know a good area for hiking?","ru":"Ты знаешь хорошее место для походов?","vi":"Bạn có biết khu vực nào tốt để đi bộ đường dài không?","fa":"آیا منطقه خوبی برای پیاده روی می شناسید؟"}]},{"word":"der Gegensatz","en":"contrast, opposite","ru":"противоположность, контраст","vi":"điều ngược lại","fa":"برعکس","examples":[{"de":"Im Gegensatz zu ihrem Bruder ist sie sehr ruhig.","en":"In contrast to her brother, she is very calm.","ru":"В отличие от своего брата, она очень спокойная.","vi":"Không giống như anh trai mình, cô ấy rất bình tĩnh.","fa":"او برخلاف برادرش بسیار آرام است."},{"de":"Die beiden Meinungen stehen im Gegensatz zueinander.","en":"The two opinions are in contrast to each other.","ru":"Оба мнения противоречат друг другу.","vi":"Hai ý kiến ​​trái ngược nhau.","fa":"این دو نظر با یکدیگر متناقض هستند."}]},{"word":"gegenseitig","en":"mutual; each other","ru":"взаимный; друг друга","vi":"lẫn nhau","fa":"یکدیگر","examples":[{"de":"Sie helfen sich gegenseitig bei den Hausaufgaben.","en":"They help each other with their homework.","ru":"Они помогают друг другу с домашней работой.","vi":"Họ giúp đỡ nhau làm bài tập về nhà.","fa":"آنها در انجام تکالیف به یکدیگر کمک می کنند."},{"de":"Eine gute Beziehung beruht auf gegenseitigem Respekt.","en":"A good relationship is based on mutual respect.","ru":"Хорошие отношения основаны на взаимном уважении.","vi":"Một mối quan hệ tốt dựa trên sự tôn trọng lẫn nhau.","fa":"یک رابطه خوب مبتنی بر احترام متقابل است."}]},{"word":"der Gegenstand","en":"object","ru":"предмет","vi":"đối tượng","fa":"شی","examples":[{"de":"Auf dem Tisch liegen mehrere Gegenstände.","en":"There are several objects on the table.","ru":"На столе лежат несколько предметов.","vi":"Có một số đồ vật trên bàn.","fa":"چندین شی روی میز وجود دارد."},{"de":"Das Thema war Gegenstand einer langen Diskussion.","en":"The topic was the subject of a long discussion.","ru":"Тема была предметом долгого обсуждения.","vi":"Chủ đề này là chủ đề của một cuộc thảo luận dài.","fa":"موضوع موضوع بحث طولانی بود."}]},{"word":"das Gegenteil","en":"opposite","ru":"противоположность","vi":"điều ngược lại","fa":"برعکس","examples":[{"de":"Das Gegenteil von \"groß\" ist \"klein\".","en":"The opposite of \"big\" is \"small\".","ru":"Противоположность слова «большой» — «маленький».","vi":"Ngược lại với \"lớn\" là \"nhỏ\".","fa":"نقطه مقابل \"بزرگ\" \"کوچک\" است."},{"de":"Sie tut immer das Gegenteil von dem, was man ihr sagt.","en":"She always does the opposite of what she's told.","ru":"Она всегда делает противоположное тому, что ей говорят.","vi":"Cô ấy luôn làm ngược lại những gì được bảo.","fa":"او همیشه برخلاف آنچه به او گفته می شود عمل می کند."}]},{"word":"gegenüber","en":"opposite; towards","ru":"напротив; по отношению к","vi":"ngược lại","fa":"مقابل","examples":[{"de":"Die Bäckerei liegt gegenüber der Kirche.","en":"The bakery is located opposite the church.","ru":"Пекарня находится напротив церкви.","vi":"Tiệm bánh nằm đối diện nhà thờ.","fa":"نانوایی روبروی کلیسا است."},{"de":"Er ist seinen Kollegen gegenüber immer freundlich.","en":"He is always friendly towards his colleagues.","ru":"Он всегда дружелюбен по отношению к коллегам.","vi":"Anh ấy luôn thân thiện với đồng nghiệp.","fa":"او همیشه با همکارانش دوستانه رفتار می کند."}]},{"word":"das Gehalt","en":"salary","ru":"зарплата","vi":"tiền lương","fa":"حقوق و دستمزد","examples":[{"de":"Sie bekommt jeden Monat ein festes Gehalt.","en":"She receives a fixed salary every month.","ru":"Она каждый месяц получает фиксированную зарплату.","vi":"Cô nhận được một mức lương cố định hàng tháng.","fa":"او هر ماه حقوق ثابتی دریافت می کند."},{"de":"Das Gehalt wurde dieses Jahr erhöht.","en":"The salary was increased this year.","ru":"В этом году зарплату повысили.","vi":"Năm nay lương đã tăng.","fa":"حقوق امسال افزایش یافت."}]},{"word":"das Geheimnis","en":"secret","ru":"тайна, секрет","vi":"bí mật","fa":"راز","examples":[{"de":"Kannst du ein Geheimnis für dich behalten?","en":"Can you keep a secret?","ru":"Ты умеешь хранить тайну?","vi":"Bạn có thể giữ bí mật được không?","fa":"آیا می توانید یک راز را حفظ کنید؟"},{"de":"Sie hat mir ihr Geheimnis anvertraut.","en":"She confided her secret to me.","ru":"Она доверила мне свою тайну.","vi":"Cô ấy kể cho tôi nghe bí mật của cô ấy.","fa":"رازش را به من گفت."}]},{"word":"gehen","en":"to go, to walk","ru":"идти","vi":"đi","fa":"برو","examples":[{"de":"Ich gehe jeden Tag zu Fuß zur Arbeit.","en":"I walk to work every day.","ru":"Я каждый день хожу на работу пешком.","vi":"Tôi đi bộ đi làm mỗi ngày.","fa":"هر روز پیاده روی سر کار می روم."},{"de":"Wie geht es dir?","en":"How are you?","ru":"Как у тебя дела?","vi":"Bạn dạo này thế nào?","fa":"حال شما چطور است؟"}]},{"word":"gehören","en":"to belong","ru":"принадлежать","vi":"thuộc về","fa":"متعلق به","examples":[{"de":"Dieses Auto gehört meinem Vater.","en":"This car belongs to my father.","ru":"Эта машина принадлежит моему отцу.","vi":"Chiếc xe này thuộc về bố tôi.","fa":"این ماشین مال پدرم است."},{"de":"Zu einem guten Frühstück gehört frisches Brot.","en":"Fresh bread is part of a good breakfast.","ru":"К хорошему завтраку относится свежий хлеб.","vi":"Bữa sáng ngon miệng bao gồm bánh mì tươi.","fa":"یک صبحانه خوب شامل نان تازه است."}]},{"word":"der Gehsteig","en":"sidewalk, pavement","ru":"тротуар","vi":"vỉa hè","fa":"پیاده رو","examples":[{"de":"Fahrräder dürfen nicht auf dem Gehsteig fahren.","en":"Bicycles are not allowed to ride on the sidewalk.","ru":"Велосипедам нельзя ездить по тротуару.","vi":"Xe đạp không được phép đi trên vỉa hè.","fa":"دوچرخه سواری در پیاده رو ممنوع است."},{"de":"Die Kinder spielen auf dem Gehsteig vor dem Haus.","en":"The children are playing on the sidewalk in front of the house.","ru":"Дети играют на тротуаре перед домом.","vi":"Lũ trẻ đang chơi đùa trên vỉa hè trước nhà.","fa":"بچه ها در پیاده رو جلوی خانه بازی می کنند."}]},{"word":"geizig","en":"stingy; mean","ru":"скупой; жадный","vi":"keo kiệt","fa":"خسیس","examples":[{"de":"Er ist so geizig, dass er nie ein Trinkgeld gibt.","en":"He is so stingy that he never leaves a tip.","ru":"Он такой жадный, что никогда не оставляет чаевых.","vi":"Anh ta keo kiệt đến mức không bao giờ để lại tiền boa.","fa":"او آنقدر خسیس است که هرگز انعام نمی گذارد."},{"de":"Sei nicht so geizig und lade uns ein!","en":"Don't be so stingy and treat us!","ru":"Не будь таким жадным и угости нас!","vi":"Đừng keo kiệt thế mà hãy mời chúng tôi đi!","fa":"اینقدر خسیس نباش و ما را دعوت کن!"}]},{"word":"das Geld","en":"money","ru":"деньги","vi":"tiền","fa":"پول","examples":[{"de":"Ich habe nicht genug Geld dabei.","en":"I don't have enough money with me.","ru":"У меня с собой недостаточно денег.","vi":"Tôi không có đủ tiền bên mình.","fa":"من پول کافی با خودم ندارم."},{"de":"Er spart Geld für ein neues Auto.","en":"He is saving money for a new car.","ru":"Он копит деньги на новую машину.","vi":"Anh ấy đang tiết kiệm tiền để mua một chiếc ô tô mới.","fa":"او برای یک ماشین جدید پول پس انداز می کند."}]},{"word":"der Geldautomat","en":"ATM, cash machine","ru":"банкомат","vi":"máy ATM","fa":"دستگاه خودپرداز","examples":[{"de":"Ich hebe Geld am Geldautomaten ab.","en":"I'm withdrawing money from the ATM.","ru":"Я снимаю деньги в банкомате.","vi":"Tôi rút tiền từ máy ATM.","fa":"من از خودپرداز پول برداشت می کنم."},{"de":"Der Geldautomat vor der Bank ist gerade außer Betrieb.","en":"The ATM in front of the bank is currently out of order.","ru":"Банкомат перед банком сейчас не работает.","vi":"Máy ATM trước ngân hàng hiện không hoạt động.","fa":"دستگاه خودپرداز جلوی بانک در حال حاضر از کار افتاده است."}]},{"word":"die Geldbörse","en":"wallet, purse","ru":"кошелёк","vi":"cái ví","fa":"کیف پول","examples":[{"de":"Ich habe meine Geldbörse im Bus vergessen.","en":"I forgot my wallet on the bus.","ru":"Я забыл кошелёк в автобусе.","vi":"Tôi quên ví trên xe buýt.","fa":"کیف پولم را در اتوبوس فراموش کردم."},{"de":"In ihrer Geldbörse sind Karten und ein wenig Bargeld.","en":"There are cards and a little cash in her wallet.","ru":"В её кошельке карты и немного наличных.","vi":"Có thẻ và một ít tiền mặt trong ví của cô ấy.","fa":"در کیف پولش کارت و مقداری پول نقد هست."}]},{"word":"die Gelegenheit","en":"opportunity","ru":"возможность, случай","vi":"cơ hội","fa":"فرصت","examples":[{"de":"Das ist eine gute Gelegenheit, Deutsch zu üben.","en":"This is a good opportunity to practice German.","ru":"Это хорошая возможность попрактиковать немецкий.","vi":"Đây là cơ hội tốt để thực hành tiếng Đức.","fa":"این فرصت خوبی برای تمرین زبان آلمانی است."},{"de":"Ich hatte noch keine Gelegenheit, ihn anzurufen.","en":"I haven't had the chance to call him yet.","ru":"У меня ещё не было возможности позвонить ему.","vi":"Tôi vẫn chưa có cơ hội gọi cho anh ấy.","fa":"من هنوز فرصت نکردم با او تماس بگیرم."}]},{"word":"gelingen","en":"to succeed","ru":"удаваться","vi":"thành công","fa":"موفق شدن","examples":[{"de":"Der Kuchen ist mir dieses Mal gut gelungen.","en":"The cake turned out well for me this time.","ru":"На этот раз торт у меня хорошо получился.","vi":"Lần này chiếc bánh trở nên ngon đối với tôi.","fa":"این بار کیک برای من خوب شد."},{"de":"Es gelang ihr, die Prüfung zu bestehen.","en":"She succeeded in passing the exam.","ru":"Ей удалось сдать экзамен.","vi":"Cô đã vượt qua được kỳ thi.","fa":"او موفق به قبولی در امتحان شد."}]},{"word":"gelten","en":"to be valid, to apply","ru":"действовать, считаться","vi":"áp dụng","fa":"اعمال شود","examples":[{"de":"Das Ticket gilt nur an diesem Tag.","en":"The ticket is only valid on this day.","ru":"Билет действителен только в этот день.","vi":"Vé chỉ có giá trị trong ngày này.","fa":"بلیط فقط برای این روز معتبر است."},{"de":"Diese Regel gilt für alle Mitarbeiter.","en":"This rule applies to all employees.","ru":"Это правило распространяется на всех сотрудников.","vi":"Quy tắc này áp dụng cho tất cả nhân viên.","fa":"این قانون برای همه کارکنان اعمال می شود."}]},{"word":"gemeinsam","en":"together, joint","ru":"совместный, вместе","vi":"cùng với nhau","fa":"با هم","examples":[{"de":"Wir haben das Projekt gemeinsam geplant.","en":"We planned the project together.","ru":"Мы вместе спланировали проект.","vi":"Chúng tôi đã cùng nhau lên kế hoạch cho dự án.","fa":"پروژه را با هم برنامه ریزی کردیم."},{"de":"Die Geschwister haben viele gemeinsame Interessen.","en":"The siblings have many common interests.","ru":"У братьев с сёстрами много общих интересов.","vi":"Hai anh em có nhiều sở thích chung.","fa":"خواهر و برادر علایق مشترک زیادی دارند."}]},{"word":"die Gemeinschaft","en":"community","ru":"сообщество, общность","vi":"cộng đồng","fa":"جامعه","examples":[{"de":"Die Dorfbewohner bilden eine enge Gemeinschaft.","en":"The villagers form a close community.","ru":"Жители деревни образуют тесную общину.","vi":"Dân làng tạo thành một cộng đồng gắn bó.","fa":"روستاییان جامعه ای نزدیک به هم تشکیل می دهند."},{"de":"Die Europäische Gemeinschaft besteht aus vielen Ländern.","en":"The European Community consists of many countries.","ru":"Европейское сообщество состоит из многих стран.","vi":"Cộng đồng Châu Âu bao gồm nhiều quốc gia.","fa":"جامعه اروپا متشکل از کشورهای زیادی است."}]},{"word":"das Gemüse","en":"vegetables","ru":"овощи","vi":"các loại rau","fa":"سبزیجات","examples":[{"de":"Sie kauft jede Woche frisches Gemüse auf dem Markt.","en":"She buys fresh vegetables at the market every week.","ru":"Она каждую неделю покупает свежие овощи на рынке.","vi":"Cô ấy mua rau tươi ở chợ mỗi tuần.","fa":"او هر هفته سبزیجات تازه را از بازار می خرد."},{"de":"Man sollte täglich Obst und Gemüse essen.","en":"One should eat fruit and vegetables every day.","ru":"Нужно каждый день есть фрукты и овощи.","vi":"Bạn nên ăn trái cây và rau quả mỗi ngày.","fa":"شما باید هر روز میوه و سبزیجات بخورید."}]},{"word":"gemütlich","en":"cozy","ru":"уютный","vi":"ấm áp","fa":"دنج","examples":[{"de":"Das kleine Café hat eine sehr gemütliche Atmosphäre.","en":"The small café has a very cozy atmosphere.","ru":"В маленьком кафе очень уютная атмосфера.","vi":"Quán cà phê nhỏ có bầu không khí rất ấm cúng.","fa":"کافه کوچک فضایی بسیار دنج دارد."},{"de":"Wir haben einen gemütlichen Abend zu Hause verbracht.","en":"We spent a cozy evening at home.","ru":"Мы провели уютный вечер дома.","vi":"Chúng tôi đã có một buổi tối ấm cúng ở nhà.","fa":"یک شب دنج را در خانه گذراندیم."}]},{"word":"genau","en":"exact, exactly","ru":"точный, точно","vi":"chính xác","fa":"دقیقا","examples":[{"de":"Kannst du mir die genaue Uhrzeit sagen?","en":"Can you tell me the exact time?","ru":"Можешь сказать мне точное время?","vi":"Bạn có thể cho tôi biết thời gian chính xác được không?","fa":"میشه زمان دقیقش رو بگید"},{"de":"Ich weiß nicht genau, wo er wohnt.","en":"I don't know exactly where he lives.","ru":"Я точно не знаю, где он живёт.","vi":"Tôi không biết chính xác nơi anh ấy sống.","fa":"دقیقا نمی دانم کجا زندگی می کند."}]},{"word":"genauso","en":"just as, likewise","ru":"точно так же","vi":"giống hệt nhau","fa":"دقیقا همینطور","examples":[{"de":"Sie ist genauso groß wie ihre Mutter.","en":"She is just as tall as her mother.","ru":"Она такого же роста, как её мать.","vi":"Cô ấy có chiều cao tương đương với mẹ cô ấy.","fa":"او هم قد مادرش است."},{"de":"Ich finde den Film genauso langweilig wie du.","en":"I find the movie just as boring as you do.","ru":"Я нахожу этот фильм таким же скучным, как и ты.","vi":"Tôi thấy bộ phim cũng nhàm chán như bạn vậy.","fa":"به نظر من فیلم هم مثل شما خسته کننده است."}]},{"word":"genehmigen","en":"to approve","ru":"разрешать, одобрять","vi":"chấp thuận","fa":"تایید کند","examples":[{"de":"Der Antrag wurde von der Behörde genehmigt.","en":"The application was approved by the authority.","ru":"Заявление было одобрено ведомством.","vi":"Đơn đã được cơ quan có thẩm quyền phê duyệt.","fa":"این درخواست توسط مرجع تایید شد."},{"de":"Mein Chef hat mir zwei Tage Urlaub genehmigt.","en":"My boss approved two days of vacation for me.","ru":"Мой начальник разрешил мне два дня отпуска.","vi":"Ông chủ của tôi đã cho tôi hai ngày nghỉ phép.","fa":"رئیسم به من دو روز مرخصی داد."}]},{"word":"die Genehmigung","en":"permit; approval","ru":"разрешение","vi":"sự chấp thuận","fa":"تایید","examples":[{"de":"Für den Umbau braucht man eine Genehmigung.","en":"You need a permit for the renovation.","ru":"Для перестройки нужно разрешение.","vi":"Bạn cần có giấy phép để chuyển đổi.","fa":"برای تبدیل نیاز به مجوز دارید."},{"de":"Die Genehmigung wurde nach zwei Wochen erteilt.","en":"The approval was granted after two weeks.","ru":"Разрешение выдали через две недели.","vi":"Sự chấp thuận đã được cấp sau hai tuần.","fa":"تایید پس از دو هفته صادر شد."}]},{"word":"die Generation","en":"generation","ru":"поколение","vi":"thế hệ","fa":"نسل","examples":[{"de":"Diese Wohnung gehört seit drei Generationen unserer Familie.","en":"This apartment has belonged to our family for three generations.","ru":"Эта квартира принадлежит нашей семье уже три поколения.","vi":"Căn hộ này đã thuộc về gia đình chúng tôi đã ba thế hệ.","fa":"این آپارتمان سه نسل است که متعلق به خانواده ماست."},{"de":"Die junge Generation nutzt viel mehr digitale Medien.","en":"The younger generation uses much more digital media.","ru":"Молодое поколение гораздо больше пользуется цифровыми медиа.","vi":"Thế hệ trẻ sử dụng phương tiện kỹ thuật số nhiều hơn.","fa":"نسل جوان بیشتر از رسانه های دیجیتال استفاده می کند."}]},{"word":"genießen","en":"to enjoy","ru":"наслаждаться","vi":"thưởng thức","fa":"لذت ببرید","examples":[{"de":"Wir genießen den sonnigen Nachmittag im Park.","en":"We are enjoying the sunny afternoon in the park.","ru":"Мы наслаждаемся солнечным днём в парке.","vi":"Chúng tôi tận hưởng buổi chiều đầy nắng trong công viên.","fa":"ما از بعد از ظهر آفتابی در پارک لذت می بریم."},{"de":"Er genießt seinen wohlverdienten Urlaub.","en":"He is enjoying his well-deserved vacation.","ru":"Он наслаждается своим заслуженным отпуском.","vi":"Anh ấy đang tận hưởng kỳ nghỉ xứng đáng của mình.","fa":"او در حال لذت بردن از تعطیلات شایسته خود است."}]},{"word":"genug","en":"enough","ru":"достаточно","vi":"đủ rồi","fa":"به اندازه کافی","examples":[{"de":"Wir haben genug Essen für alle Gäste.","en":"We have enough food for all the guests.","ru":"У нас достаточно еды для всех гостей.","vi":"Chúng tôi có đủ thức ăn cho tất cả khách.","fa":"ما غذای کافی برای همه مهمانان داریم."},{"de":"Ich habe genug von diesem Lärm.","en":"I've had enough of this noise.","ru":"Мне надоел этот шум.","vi":"Tôi đã chịu đủ tiếng ồn này rồi.","fa":"من از این سروصدا به اندازه کافی خسته شدم."}]},{"word":"genügen","en":"to be enough, to suffice","ru":"быть достаточным, хватать","vi":"đủ","fa":"کافی است","examples":[{"de":"Ein kurzer Anruf genügt, um Bescheid zu geben.","en":"A short call is enough to let us know.","ru":"Короткого звонка достаточно, чтобы сообщить.","vi":"Một cuộc gọi nhanh là đủ để cho bạn biết.","fa":"یک تماس سریع برای اطلاع شما کافی است."},{"de":"Zwei Löffel Zucker genügen für den Kuchen.","en":"Two spoons of sugar are enough for the cake.","ru":"Двух ложек сахара достаточно для торта.","vi":"Hai thìa đường là đủ cho chiếc bánh.","fa":"دو قاشق شکر برای کیک کافی است."}]},{"word":"das Gepäck","en":"luggage","ru":"багаж","vi":"hành lý","fa":"چمدان","examples":[{"de":"Bitte stellen Sie Ihr Gepäck hier ab.","en":"Please put your luggage down here.","ru":"Пожалуйста, поставьте ваш багаж здесь.","vi":"Vui lòng để lại hành lý của bạn ở đây.","fa":"لطفا چمدان خود را اینجا بگذارید."},{"de":"Am Flughafen haben wir unser Gepäck verloren.","en":"We lost our luggage at the airport.","ru":"В аэропорту мы потеряли свой багаж.","vi":"Chúng tôi bị mất hành lý ở sân bay.","fa":"چمدانمان را در فرودگاه گم کردیم."}]},{"word":"gerade","en":"straight; just, right now","ru":"прямой; как раз, сейчас","vi":"thẳng","fa":"مستقیم","examples":[{"de":"Zeichne eine gerade Linie auf das Blatt.","en":"Draw a straight line on the sheet.","ru":"Нарисуй прямую линию на листе.","vi":"Vẽ một đường thẳng trên tờ giấy.","fa":"یک خط مستقیم روی برگه بکشید."},{"de":"Ich bin gerade beim Kochen.","en":"I'm cooking right now.","ru":"Я как раз готовлю.","vi":"Bây giờ tôi đang nấu ăn.","fa":"من الان دارم آشپزی میکنم"}]},{"word":"das Gerät","en":"device, appliance","ru":"прибор, устройство","vi":"thiết bị","fa":"دستگاه","examples":[{"de":"Dieses Gerät spart viel Strom.","en":"This device saves a lot of electricity.","ru":"Этот прибор экономит много электроэнергии.","vi":"Thiết bị này tiết kiệm rất nhiều điện năng.","fa":"این دستگاه در مصرف برق بسیار صرفه جویی می کند."},{"de":"Das neue Gerät ist leider kaputt.","en":"Unfortunately the new device is broken.","ru":"К сожалению, новый прибор сломан.","vi":"Thật không may, thiết bị mới bị hỏng.","fa":"متاسفانه دستگاه جدید خراب است."}]},{"word":"gerecht","en":"fair, just","ru":"справедливый","vi":"công bằng","fa":"منصفانه","examples":[{"de":"Der Lehrer behandelt alle Schüler gerecht.","en":"The teacher treats all students fairly.","ru":"Учитель справедливо относится ко всем ученикам.","vi":"Giáo viên đối xử công bằng với tất cả học sinh.","fa":"معلم با همه دانش آموزان منصفانه رفتار می کند."},{"de":"Das Urteil wurde von vielen als nicht gerecht empfunden.","en":"The verdict was seen by many as not fair.","ru":"Многие сочли приговор несправедливым.","vi":"Nhiều người cho rằng bản án này không công bằng.","fa":"این حکم از نظر بسیاری ناعادلانه بود."}]},{"word":"die Gerechtigkeit","en":"justice; fairness","ru":"справедливость","vi":"công lý","fa":"عدالت","examples":[{"de":"Er kämpft für mehr Gerechtigkeit in der Gesellschaft.","en":"He fights for more justice in society.","ru":"Он борется за большую справедливость в обществе.","vi":"Anh đấu tranh cho sự công bằng hơn trong xã hội.","fa":"او برای عدالت بیشتر در جامعه مبارزه می کند."},{"de":"Kinder haben ein feines Gespür für Gerechtigkeit.","en":"Children have a keen sense of fairness.","ru":"У детей тонкое чувство справедливости.","vi":"Trẻ em có ý thức sâu sắc về công lý.","fa":"کودکان حس عدالت خواهی شدیدی دارند."}]},{"word":"das Gericht","en":"court (of law); dish (food)","ru":"суд; блюдо (еда)","vi":"tòa án","fa":"دادگاه","examples":[{"de":"Der Fall wird vor Gericht verhandelt.","en":"The case is being tried in court.","ru":"Дело рассматривается в суде.","vi":"Vụ án đang được xét xử tại tòa án.","fa":"این پرونده در دادگاه در حال رسیدگی است."},{"de":"Das Restaurant bietet vegetarische Gerichte an.","en":"The restaurant offers vegetarian dishes.","ru":"Ресторан предлагает вегетарианские блюда.","vi":"Nhà hàng cung cấp các món ăn chay.","fa":"این رستوران غذاهای گیاهی ارائه می دهد."}]},{"word":"gering","en":"small, slight","ru":"незначительный, малый","vi":"thấp","fa":"پایین","examples":[{"de":"Die Wahrscheinlichkeit für Regen ist heute gering.","en":"The probability of rain is low today.","ru":"Вероятность дождя сегодня невелика.","vi":"Khả năng mưa hôm nay là thấp.","fa":"احتمال بارندگی امروز کم است."},{"de":"Er hat nur geringe Kenntnisse in Englisch.","en":"He has only limited knowledge of English.","ru":"У него лишь незначительные знания английского.","vi":"Anh ấy có rất ít kiến ​​thức về tiếng Anh.","fa":"او دانش کمی از زبان انگلیسی دارد."}]},{"word":"gern/gerne","en":"gladly, with pleasure","ru":"охотно, с удовольствием","vi":"vui vẻ/vui lòng","fa":"با خوشحالی/خوشحالی","examples":[{"de":"Ich helfe dir gern bei den Hausaufgaben.","en":"I'll gladly help you with your homework.","ru":"Я с удовольствием помогу тебе с домашним заданием.","vi":"Tôi rất vui được giúp bạn làm bài tập về nhà.","fa":"خوشحال می شوم در انجام تکالیف به شما کمک کنم."},{"de":"Sie trinkt gerne Kaffee am Morgen.","en":"She likes to drink coffee in the morning.","ru":"Она любит пить кофе по утрам.","vi":"Cô ấy thích uống cà phê vào buổi sáng.","fa":"او دوست دارد صبح ها قهوه بنوشد."}]},{"word":"das Gerücht","en":"rumour","ru":"слух","vi":"tin đồn","fa":"شایعه","examples":[{"de":"Es geht das Gerücht, dass die Firma schließt.","en":"There's a rumour going around that the company is closing.","ru":"Ходит слух, что компания закрывается.","vi":"Có tin đồn công ty sắp đóng cửa.","fa":"شایعه ای مبنی بر تعطیلی این شرکت وجود دارد."},{"de":"Glaub nicht jedes Gerücht, das du hörst.","en":"Don't believe every rumour you hear.","ru":"Не верь каждому слуху, который слышишь.","vi":"Đừng tin vào mọi tin đồn bạn nghe được.","fa":"هر شایعه ای که می شنوید را باور نکنید."}]},{"word":"gesamt-","en":"total, whole, entire (prefix)","ru":"общий, весь (приставка)","vi":"tổng cộng","fa":"کل","examples":[{"de":"Der Gesamtbetrag der Rechnung beträgt 250 Euro.","en":"The total amount of the bill is 250 euros.","ru":"Общая сумма счёта составляет 250 евро.","vi":"Tổng số tiền của hóa đơn là 250 euro.","fa":"مبلغ کل صورتحساب 250 یورو است."},{"de":"Die Gesamtkosten für die Reise waren höher als erwartet.","en":"The total costs for the trip were higher than expected.","ru":"Общая стоимость поездки оказалась выше ожидаемой.","vi":"Tổng chi phí của chuyến đi cao hơn dự kiến.","fa":"هزینه کل سفر بیشتر از حد انتظار بود."}]},{"word":"das Geschäft","en":"shop, store; business","ru":"магазин; дело, бизнес","vi":"việc kinh doanh","fa":"کسب و کار","examples":[{"de":"Das Geschäft an der Ecke verkauft frisches Brot.","en":"The shop on the corner sells fresh bread.","ru":"Магазин на углу продаёт свежий хлеб.","vi":"Cửa hàng ở góc phố bán bánh mì tươi.","fa":"مغازه آن گوشه نان تازه می فروشد."},{"de":"Er macht gute Geschäfte mit ausländischen Firmen.","en":"He does good business with foreign companies.","ru":"Он ведёт успешные дела с зарубежными фирмами.","vi":"Anh ấy làm ăn tốt với các công ty nước ngoài.","fa":"او تجارت خوبی با شرکت های خارجی انجام می دهد."}]},{"word":"geschehen","en":"to happen","ru":"происходить, случаться","vi":"xảy ra","fa":"اتفاق بیفتد","examples":[{"de":"Bei dem Unfall ist zum Glück nichts Schlimmes geschehen.","en":"Fortunately, nothing bad happened in the accident.","ru":"К счастью, при аварии ничего страшного не произошло.","vi":"Rất may không có điều gì đáng tiếc xảy ra trong vụ tai nạn.","fa":"خوشبختانه اتفاق بدی در این تصادف رخ نداد."},{"de":"Wie konnte das nur geschehen?","en":"How could this have happened?","ru":"Как такое вообще могло случиться?","vi":"Làm thế nào điều này có thể xảy ra?","fa":"چگونه ممکن است این اتفاق بیفتد؟"}]},{"word":"das Geschenk","en":"gift, present","ru":"подарок","vi":"món quà","fa":"هدیه","examples":[{"de":"Zum Geburtstag hat sie ein schönes Geschenk bekommen.","en":"She received a nice gift for her birthday.","ru":"На день рождения она получила красивый подарок.","vi":"Cô ấy đã nhận được một món quà tuyệt vời vào ngày sinh nhật của mình.","fa":"او برای تولدش یک هدیه خوب گرفت."},{"de":"Ich muss noch ein Geschenk für die Hochzeit kaufen.","en":"I still need to buy a gift for the wedding.","ru":"Мне ещё нужно купить подарок на свадьбу.","vi":"Tôi vẫn phải mua một món quà cho đám cưới.","fa":"هنوز باید برای عروسی هدیه بخرم."}]},{"word":"die Geschichte","en":"story; history","ru":"история (рассказ; наука)","vi":"câu chuyện","fa":"داستان","examples":[{"de":"Die Großmutter erzählt den Kindern eine Geschichte.","en":"The grandmother tells the children a story.","ru":"Бабушка рассказывает детям историю.","vi":"Bà nội kể cho trẻ nghe một câu chuyện.","fa":"مادربزرگ برای بچه ها قصه تعریف می کند."},{"de":"In der Schule lernen wir die Geschichte Europas.","en":"At school we learn about the history of Europe.","ru":"В школе мы изучаем историю Европы.","vi":"Ở trường chúng tôi học lịch sử của Châu Âu.","fa":"در مدرسه تاریخ اروپا را یاد می گیریم."}]},{"word":"geschieden","en":"divorced","ru":"разведённый","vi":"đã ly hôn","fa":"طلاق گرفته","examples":[{"de":"Meine Eltern sind seit fünf Jahren geschieden.","en":"My parents have been divorced for five years.","ru":"Мои родители в разводе уже пять лет.","vi":"Bố mẹ tôi đã ly hôn được năm năm.","fa":"پدر و مادرم پنج سال است که از هم جدا شده اند."},{"de":"Sie ist geschieden und hat zwei Kinder.","en":"She is divorced and has two children.","ru":"Она разведена и у неё двое детей.","vi":"Cô đã ly hôn và có hai con.","fa":"او طلاق گرفته و دو فرزند دارد."}]},{"word":"das Geschirr","en":"dishes, crockery","ru":"посуда","vi":"các món ăn","fa":"ظروف","examples":[{"de":"Nach dem Essen muss noch das Geschirr gespült werden.","en":"After the meal, the dishes still need to be washed.","ru":"После еды ещё нужно вымыть посуду.","vi":"Ăn xong vẫn phải rửa bát.","fa":"پس از صرف غذا، ظروف هنوز باید شسته شوند."},{"de":"Das schmutzige Geschirr steht in der Spüle.","en":"The dirty dishes are in the sink.","ru":"Грязная посуда стоит в раковине.","vi":"Bát đĩa bẩn đang ở trong bồn rửa.","fa":"ظرف های کثیف داخل سینک هستند."}]},{"word":"das Geschlecht","en":"gender, sex","ru":"пол (мужской/женский)","vi":"giới tính","fa":"جنسیت","examples":[{"de":"Auf dem Formular muss man sein Geschlecht angeben.","en":"You have to state your gender on the form.","ru":"В анкете нужно указать свой пол.","vi":"Bạn phải cho biết giới tính của mình trên mẫu đơn.","fa":"شما باید جنسیت خود را در فرم مشخص کنید."},{"de":"Das Geschlecht des Babys ist noch unbekannt.","en":"The baby's gender is not yet known.","ru":"Пол ребёнка пока неизвестен.","vi":"Giới tính của em bé vẫn chưa được biết.","fa":"جنسیت نوزاد هنوز مشخص نیست."}]},{"word":"der Geschmack","en":"taste","ru":"вкус","vi":"hương vị","fa":"طعم","examples":[{"de":"Die Suppe hat einen sehr würzigen Geschmack.","en":"The soup has a very spicy taste.","ru":"У супа очень пряный вкус.","vi":"Súp có vị rất cay.","fa":"سوپ طعم بسیار تند دارد."},{"de":"Der Kuchen ist zwar hübsch, aber der Geschmack überzeugt mich nicht.","en":"The cake looks nice, but the taste doesn't convince me.","ru":"Торт выглядит красиво, но вкус меня не убеждает.","vi":"Bánh đẹp nhưng mình không ấn tượng lắm về mùi vị.","fa":"کیک زیباست اما طعمش تحت تاثیر قرار نگرفتم."}]},{"word":"die Geschwindigkeit","en":"speed","ru":"скорость","vi":"tốc độ","fa":"سرعت","examples":[{"de":"Die erlaubte Geschwindigkeit in der Stadt beträgt 50 km/h.","en":"The permitted speed in the city is 50 km/h.","ru":"Разрешённая скорость в городе составляет 50 км/ч.","vi":"Tốc độ cho phép trong thành phố là 50 km/h.","fa":"سرعت مجاز در شهر 50 کیلومتر بر ساعت است."},{"de":"Das Auto fuhr mit hoher Geschwindigkeit an uns vorbei.","en":"The car drove past us at high speed.","ru":"Машина проехала мимо нас на высокой скорости.","vi":"Chiếc xe vượt qua chúng tôi với tốc độ cao.","fa":"ماشین با سرعت زیاد از کنار ما گذشت."}]},{"word":"die Geschwister","en":"siblings","ru":"братья и сёстры","vi":"anh chị em","fa":"خواهر و برادر","examples":[{"de":"Ich habe zwei Geschwister, einen Bruder und eine Schwester.","en":"I have two siblings, a brother and a sister.","ru":"У меня двое братьев и сестёр — брат и сестра.","vi":"Tôi có hai anh chị em, một anh trai và một em gái.","fa":"من دو خواهر و برادر دارم، یک برادر و یک خواهر."},{"de":"Hast du Geschwister oder bist du Einzelkind?","en":"Do you have siblings or are you an only child?","ru":"У тебя есть братья или сёстры, или ты единственный ребёнок?","vi":"Bạn có anh chị em ruột hay bạn là con một?","fa":"آیا شما خواهر و برادر دارید یا تک فرزند هستید؟"}]},{"word":"die Gesellschaft","en":"society; company","ru":"общество; компания","vi":"xã hội","fa":"جامعه","examples":[{"de":"Die moderne Gesellschaft verändert sich schnell.","en":"Modern society is changing quickly.","ru":"Современное общество быстро меняется.","vi":"Xã hội hiện đại đang thay đổi nhanh chóng.","fa":"جامعه مدرن به سرعت در حال تغییر است."},{"de":"Er leistet ihr gerne Gesellschaft am Abend.","en":"He gladly keeps her company in the evening.","ru":"Он с удовольствием составляет ей компанию вечером.","vi":"Anh ấy thích bầu bạn với cô ấy vào buổi tối.","fa":"او دوست دارد عصرها با او همراهی کند."}]},{"word":"das Gesetz","en":"law","ru":"закон","vi":"luật pháp","fa":"قانون","examples":[{"de":"In diesem Land gilt ein strenges Gesetz gegen Rauchen.","en":"There is a strict law against smoking in this country.","ru":"В этой стране действует строгий закон против курения.","vi":"Đất nước này có luật nghiêm khắc chống lại việc hút thuốc.","fa":"این کشور قانون سختگیرانه ای برای مبارزه با استعمال دخانیات دارد."},{"de":"Das neue Gesetz tritt nächsten Monat in Kraft.","en":"The new law comes into force next month.","ru":"Новый закон вступает в силу в следующем месяце.","vi":"Luật mới sẽ có hiệu lực vào tháng tới.","fa":"قانون جدید از ماه آینده اجرایی می شود."}]},{"word":"gesetzlich","en":"legal; statutory","ru":"законный; установленный законом","vi":"hợp pháp","fa":"قانونی","examples":[{"de":"Der gesetzliche Urlaub beträgt mindestens 20 Tage.","en":"The statutory holiday entitlement is at least 20 days.","ru":"Установленный законом отпуск составляет не менее 20 дней.","vi":"Kỳ nghỉ theo luật định ít nhất là 20 ngày.","fa":"مرخصی قانونی حداقل 20 روز است."},{"de":"Rauchen ist an diesem Ort gesetzlich verboten.","en":"Smoking is prohibited by law in this place.","ru":"Курение в этом месте запрещено законом.","vi":"Pháp luật cấm hút thuốc ở địa điểm này.","fa":"سیگار کشیدن در این مکان طبق قانون ممنوع است."}]},{"word":"das Gesicht","en":"face","ru":"лицо","vi":"khuôn mặt","fa":"صورت","examples":[{"de":"Sie hat ein freundliches Gesicht.","en":"She has a friendly face.","ru":"У неё дружелюбное лицо.","vi":"Cô ấy có khuôn mặt thân thiện.","fa":"او چهره ای دوستانه دارد."},{"de":"Er wusch sich das Gesicht mit kaltem Wasser.","en":"He washed his face with cold water.","ru":"Он умыл лицо холодной водой.","vi":"Anh rửa mặt bằng nước lạnh.","fa":"صورتش را با آب سرد شست."}]},{"word":"gespannt","en":"curious, eager","ru":"заинтригованный, с нетерпением ожидающий","vi":"vui mừng","fa":"هیجان زده","examples":[{"de":"Ich bin gespannt, wie das Spiel ausgeht.","en":"I'm curious how the game will turn out.","ru":"Мне интересно, чем закончится игра.","vi":"Tôi rất phấn khích để xem trò chơi diễn ra như thế nào.","fa":"من هیجان زده هستم که ببینم بازی چگونه پیش می رود."},{"de":"Die Kinder waren gespannt auf ihre Geschenke.","en":"The children were eager for their presents.","ru":"Дети с нетерпением ждали своих подарков.","vi":"Các em hào hứng với phần quà của mình.","fa":"بچه ها از هدیه هایشان هیجان زده بودند."}]},{"word":"das Gespräch","en":"conversation","ru":"разговор, беседа","vi":"cuộc trò chuyện","fa":"گفتگو","examples":[{"de":"Wir hatten ein langes Gespräch über die Zukunft.","en":"We had a long conversation about the future.","ru":"У нас был долгий разговор о будущем.","vi":"Chúng tôi đã có một cuộc trò chuyện dài về tương lai.","fa":"گفتگوی طولانی در مورد آینده داشتیم."},{"de":"Kann ich Sie kurz für ein Gespräch stören?","en":"May I briefly bother you for a conversation?","ru":"Могу я вас ненадолго отвлечь для разговора?","vi":"Tôi có thể làm phiền bạn một chút để trò chuyện được không?","fa":"آیا می توانم برای چت کردن یک لحظه مزاحم شما شوم؟"}]},{"word":"gestehen","en":"to confess","ru":"признаваться; сознаваться","vi":"thú nhận","fa":"اعتراف کردن","examples":[{"de":"Der Täter gestand die Tat vor Gericht.","en":"The perpetrator confessed to the crime in court.","ru":"Преступник сознался в содеянном в суде.","vi":"Thủ phạm đã thừa nhận hành vi phạm tội trước tòa.","fa":"عامل جنایت در دادگاه به جرم خود اعتراف کرد."},{"de":"Ich muss gestehen, dass ich das Buch nie gelesen habe.","en":"I have to confess that I never read the book.","ru":"Должен признаться, что я так и не прочитал эту книгу.","vi":"Tôi phải thừa nhận rằng tôi chưa bao giờ đọc cuốn sách này.","fa":"باید اعتراف کنم که هرگز کتاب را نخوانده ام."}]},{"word":"gestern","en":"yesterday","ru":"вчера","vi":"hôm qua","fa":"دیروز","examples":[{"de":"Gestern habe ich meine alte Freundin getroffen.","en":"Yesterday I met my old friend.","ru":"Вчера я встретил свою старую подругу.","vi":"Hôm qua tôi đã gặp lại người bạn cũ của tôi.","fa":"دیروز با دوست قدیمی ام آشنا شدم."},{"de":"Gestern Abend war ich im Kino.","en":"Yesterday evening I was at the cinema.","ru":"Вчера вечером я был в кино.","vi":"Tôi đã đi xem phim tối qua.","fa":"دیشب رفتم سینما."}]},{"word":"gesund","en":"healthy","ru":"здоровый","vi":"khỏe mạnh","fa":"سالم","examples":[{"de":"Obst und Gemüse sind sehr gesund.","en":"Fruit and vegetables are very healthy.","ru":"Фрукты и овощи очень полезны для здоровья.","vi":"Trái cây và rau quả rất tốt cho sức khỏe.","fa":"میوه ها و سبزیجات بسیار سالم هستند."},{"de":"Nach der Grippe fühlt er sich wieder gesund.","en":"After the flu, he feels healthy again.","ru":"После гриппа он снова чувствует себя здоровым.","vi":"Sau cơn cúm, anh ấy cảm thấy khỏe mạnh trở lại.","fa":"بعد از آنفولانزا دوباره احساس سلامتی می کند."}]},{"word":"die Gesundheit","en":"health","ru":"здоровье","vi":"sức khỏe","fa":"سلامتی","examples":[{"de":"Gesundheit ist wichtiger als Geld.","en":"Health is more important than money.","ru":"Здоровье важнее денег.","vi":"Sức khỏe quan trọng hơn tiền bạc.","fa":"سلامتی مهمتر از پول است."},{"de":"Sport ist gut für die Gesundheit.","en":"Sport is good for your health.","ru":"Спорт полезен для здоровья.","vi":"Thể thao tốt cho sức khỏe của bạn.","fa":"ورزش برای سلامتی شما مفید است."}]},{"word":"das Getränk","en":"drink, beverage","ru":"напиток","vi":"đồ uống","fa":"نوشیدنی","examples":[{"de":"Welche Getränke möchten Sie bestellen?","en":"Which drinks would you like to order?","ru":"Какие напитки вы хотите заказать?","vi":"Bạn muốn gọi đồ uống nào?","fa":"کدام نوشیدنی را دوست دارید سفارش دهید؟"},{"de":"Im Sommer trinke ich gerne kalte Getränke.","en":"In summer I like to drink cold beverages.","ru":"Летом я люблю пить холодные напитки.","vi":"Vào mùa hè tôi thích uống đồ uống lạnh.","fa":"در تابستان دوست دارم نوشیدنی های سرد بنوشم."}]},{"word":"die Gewalt","en":"violence, force","ru":"насилие, сила","vi":"bạo lực","fa":"خشونت","examples":[{"de":"In dem Film kommt viel Gewalt vor.","en":"There is a lot of violence in the movie.","ru":"В этом фильме много насилия.","vi":"Có rất nhiều cảnh bạo lực trong phim.","fa":"خشونت در فیلم زیاد است."},{"de":"Die Polizei musste Gewalt anwenden, um die Menge zu kontrollieren.","en":"The police had to use force to control the crowd.","ru":"Полиции пришлось применить силу, чтобы усмирить толпу.","vi":"Cảnh sát đã phải dùng vũ lực để kiểm soát đám đông.","fa":"پلیس مجبور شد برای کنترل جمعیت از زور استفاده کند."}]},{"word":"die Gewerkschaft","en":"trade union","ru":"профсоюз","vi":"công đoàn","fa":"اتحادیه","examples":[{"de":"Die Gewerkschaft kämpft für höhere Löhne.","en":"The trade union is fighting for higher wages.","ru":"Профсоюз борется за повышение зарплаты.","vi":"Công đoàn đang đấu tranh đòi mức lương cao hơn.","fa":"اتحادیه برای افزایش دستمزدها مبارزه می کند."},{"de":"Viele Arbeiter sind Mitglied einer Gewerkschaft.","en":"Many workers are members of a trade union.","ru":"Многие рабочие состоят в профсоюзе.","vi":"Nhiều công nhân là thành viên của công đoàn.","fa":"بسیاری از کارگران عضو اتحادیه هستند."}]},{"word":"das Gewicht","en":"weight","ru":"вес","vi":"trọng lượng","fa":"وزن","examples":[{"de":"Das Gewicht des Koffers darf 20 Kilo nicht überschreiten.","en":"The weight of the suitcase must not exceed 20 kilos.","ru":"Вес чемодана не должен превышать 20 килограммов.","vi":"Trọng lượng của vali không được vượt quá 20 kg.","fa":"وزن چمدان نباید بیشتر از 20 کیلو باشد."},{"de":"Er hat in den letzten Monaten viel Gewicht verloren.","en":"He has lost a lot of weight in the last few months.","ru":"За последние месяцы он сильно похудел.","vi":"Anh ấy đã sụt cân rất nhiều trong vài tháng qua.","fa":"او در چند ماه اخیر وزن زیادی از دست داده است."}]},{"word":"gewinnen","en":"to win","ru":"выигрывать","vi":"thắng","fa":"برنده شوید","examples":[{"de":"Unsere Mannschaft hat das Spiel gewonnen.","en":"Our team won the game.","ru":"Наша команда выиграла игру.","vi":"Đội của chúng tôi đã thắng trò chơi.","fa":"تیم ما برنده بازی شد."},{"de":"Sie hat im Lotto eine große Summe gewonnen.","en":"She won a large sum in the lottery.","ru":"Она выиграла крупную сумму в лотерею.","vi":"Cô ấy đã thắng một số tiền lớn trong cuộc xổ số.","fa":"او مبلغ زیادی را در لاتاری برنده شد."}]},{"word":"das Gewissen","en":"conscience","ru":"совесть","vi":"lương tâm","fa":"وجدان","examples":[{"de":"Er hat ein schlechtes Gewissen, weil er gelogen hat.","en":"He has a guilty conscience because he lied.","ru":"У него нечиста совесть, потому что он солгал.","vi":"Anh cảm thấy có lỗi vì đã nói dối.","fa":"او احساس گناه می کند زیرا دروغ گفته است."},{"de":"Sie handelt immer nach ihrem Gewissen.","en":"She always acts according to her conscience.","ru":"Она всегда поступает по совести.","vi":"Cô luôn hành động theo lương tâm của mình.","fa":"او همیشه طبق وجدان خود عمل می کند."}]},{"word":"das Gewitter","en":"thunderstorm","ru":"гроза","vi":"giông bão","fa":"رعد و برق","examples":[{"de":"Heute Nachmittag zieht ein starkes Gewitter auf.","en":"A strong thunderstorm is approaching this afternoon.","ru":"Сегодня днём приближается сильная гроза.","vi":"Một cơn giông mạnh đang đến gần vào chiều nay.","fa":"رعد و برق شدید امروز بعد از ظهر نزدیک است."},{"de":"Während des Gewitters blieben wir zu Hause.","en":"During the thunderstorm we stayed at home.","ru":"Во время грозы мы оставались дома.","vi":"Chúng tôi ở nhà trong cơn bão.","fa":"موقع طوفان در خانه ماندیم."}]},{"word":"gewöhnen","en":"to get used to","ru":"привыкать","vi":"làm quen với","fa":"عادت کن","examples":[{"de":"Ich muss mich noch an die neue Arbeit gewöhnen.","en":"I still have to get used to the new job.","ru":"Мне ещё нужно привыкнуть к новой работе.","vi":"Tôi vẫn phải làm quen với công việc mới.","fa":"هنوز باید به کار جدید عادت کنم."},{"de":"Kinder gewöhnen sich schnell an eine neue Umgebung.","en":"Children quickly get used to a new environment.","ru":"Дети быстро привыкают к новой обстановке.","vi":"Trẻ nhanh chóng làm quen với môi trường mới.","fa":"کودکان به سرعت به محیط جدید عادت می کنند."}]},{"word":"die Gewohnheit","en":"habit","ru":"привычка","vi":"thói quen","fa":"عادت","examples":[{"de":"Frühes Aufstehen ist bei ihm eine alte Gewohnheit.","en":"Getting up early is an old habit of his.","ru":"Ранний подъём — его давняя привычка.","vi":"Dậy sớm là thói quen cũ của anh.","fa":"زود بیدار شدن برای او یک عادت قدیمی است."},{"de":"Aus Gewohnheit trinkt sie morgens immer Tee.","en":"Out of habit, she always drinks tea in the morning.","ru":"По привычке она всегда пьёт чай по утрам.","vi":"Theo thói quen, cô luôn uống trà vào buổi sáng.","fa":"از روی عادت، همیشه صبح ها چای می نوشد."}]},{"word":"das Gewürz","en":"spice","ru":"специя, приправа","vi":"gia vị","fa":"ادویه","examples":[{"de":"In diesem Gericht sind viele Gewürze enthalten.","en":"This dish contains many spices.","ru":"В этом блюде много специй.","vi":"Có rất nhiều gia vị trong món ăn này.","fa":"ادویه های زیادی در این غذا وجود دارد."},{"de":"Pfeffer und Salz sind die häufigsten Gewürze.","en":"Pepper and salt are the most common spices.","ru":"Перец и соль — самые распространённые специи.","vi":"Hạt tiêu và muối là những loại gia vị phổ biến nhất.","fa":"فلفل و نمک رایج ترین ادویه جات هستند."}]},{"word":"gießen","en":"to water (plants); to pour","ru":"поливать; лить","vi":"đổ","fa":"ریختن","examples":[{"de":"Kannst du bitte die Blumen gießen?","en":"Can you please water the flowers?","ru":"Можешь полить цветы, пожалуйста?","vi":"Bạn có thể vui lòng tưới hoa được không?","fa":"میشه لطفا به گلها آب بدهید؟"},{"de":"Sie gießt vorsichtig Wasser in die Vase.","en":"She carefully pours water into the vase.","ru":"Она осторожно наливает воду в вазу.","vi":"Cô cẩn thận đổ nước vào bình.","fa":"او با احتیاط آب را داخل گلدان می ریزد."}]},{"word":"das Gift","en":"poison","ru":"яд","vi":"chất độc","fa":"سم","examples":[{"de":"Manche Pflanzen enthalten gefährliches Gift.","en":"Some plants contain dangerous poison.","ru":"Некоторые растения содержат опасный яд.","vi":"Một số cây có chứa chất độc nguy hiểm.","fa":"برخی از گیاهان حاوی سم خطرناک هستند."},{"de":"Die Schlange tötet ihre Beute mit Gift.","en":"The snake kills its prey with poison.","ru":"Змея убивает свою добычу ядом.","vi":"Con rắn giết chết con mồi bằng chất độc.","fa":"مار طعمه خود را با سم می کشد."}]},{"word":"die Gitarre","en":"guitar","ru":"гитара","vi":"cây đàn guitar","fa":"گیتار","examples":[{"de":"Er spielt seit zehn Jahren Gitarre.","en":"He has been playing the guitar for ten years.","ru":"Он играет на гитаре уже десять лет.","vi":"Anh ấy đã chơi guitar được mười năm.","fa":"ده سال است که گیتار می نوازد."},{"de":"Sie hat sich eine neue Gitarre gekauft.","en":"She bought herself a new guitar.","ru":"Она купила себе новую гитару.","vi":"Cô ấy đã mua một cây đàn guitar mới.","fa":"او یک گیتار جدید خرید."}]},{"word":"glatt","en":"smooth; slippery","ru":"гладкий; скользкий","vi":"mịn màng","fa":"صاف","examples":[{"de":"Die Straße ist bei Regen sehr glatt.","en":"The road is very slippery when it rains.","ru":"Дорога очень скользкая, когда идёт дождь.","vi":"Đường rất trơn khi trời mưa.","fa":"جاده هنگام بارندگی بسیار لغزنده است."},{"de":"Der Tisch hat eine glatte Oberfläche.","en":"The table has a smooth surface.","ru":"У стола гладкая поверхность.","vi":"Bàn có bề mặt nhẵn.","fa":"میز دارای سطح صاف است."}]},{"word":"glauben","en":"to believe, to think","ru":"верить, думать","vi":"tin tưởng","fa":"باور کنید","examples":[{"de":"Ich glaube, es wird morgen regnen.","en":"I think it will rain tomorrow.","ru":"Я думаю, завтра пойдёт дождь.","vi":"Tôi nghĩ ngày mai trời sẽ mưa.","fa":"فکر کنم فردا بارون بیاد"},{"de":"Sie glaubt fest an Gott.","en":"She firmly believes in God.","ru":"Она твёрдо верит в Бога.","vi":"Cô tin tưởng chắc chắn vào Chúa.","fa":"او به خدا اعتقاد راسخ دارد."}]},{"word":"gleich","en":"same, equal; immediately, right away","ru":"одинаковый, равный; сейчас же","vi":"giống nhau","fa":"همان","examples":[{"de":"Beide Kinder sind gleich groß.","en":"Both children are the same height.","ru":"Оба ребёнка одного роста.","vi":"Cả hai đứa trẻ đều có cùng kích thước.","fa":"هر دو بچه یک اندازه هستند."},{"de":"Ich komme gleich zu dir.","en":"I'll come to you right away.","ru":"Я сейчас же приду к тебе.","vi":"Tôi sẽ đến với bạn sớm.","fa":"به زودی میام پیشت"}]},{"word":"gleichzeitig","en":"at the same time; simultaneous","ru":"одновременно; одновременный","vi":"cùng lúc","fa":"در همان زمان","examples":[{"de":"Man kann nicht zwei Dinge gleichzeitig richtig machen.","en":"You can't do two things properly at the same time.","ru":"Нельзя делать два дела как следует одновременно.","vi":"Bạn không thể làm đúng hai việc cùng một lúc.","fa":"شما نمی توانید دو کار را همزمان انجام دهید."},{"de":"Die beiden kamen gleichzeitig am Ziel an.","en":"The two arrived at the finish at the same time.","ru":"Оба пришли к финишу одновременно.","vi":"Hai người đến đích cùng một lúc.","fa":"آن دو همزمان به مقصد رسیدند."}]},{"word":"das Gleis","en":"railway track, platform","ru":"путь, платформа (ж/д)","vi":"đường đua","fa":"مسیر","examples":[{"de":"Der Zug nach Berlin fährt von Gleis 5 ab.","en":"The train to Berlin departs from platform 5.","ru":"Поезд в Берлин отправляется с пути 5.","vi":"Tàu tới Berlin khởi hành từ sân ga số 5.","fa":"قطار به برلین از سکوی 5 حرکت می کند."},{"de":"Bitte bleiben Sie hinter der Linie am Gleis.","en":"Please stay behind the line on the platform.","ru":"Пожалуйста, оставайтесь за линией на платформе.","vi":"Hãy ở phía sau vạch trên đường đua.","fa":"لطفا پشت خط در مسیر بمانید."}]},{"word":"das Glück","en":"luck, happiness","ru":"удача, счастье","vi":"hạnh phúc","fa":"شادی","examples":[{"de":"Wir hatten Glück, dass es nicht geregnet hat.","en":"We were lucky that it didn't rain.","ru":"Нам повезло, что не было дождя.","vi":"Chúng tôi thật may mắn vì trời không mưa.","fa":"خوش شانس بودیم که باران نیامد."},{"de":"Ich wünsche dir viel Glück für die Prüfung.","en":"I wish you good luck for the exam.","ru":"Желаю тебе удачи на экзамене.","vi":"Tôi chúc bạn may mắn cho kỳ thi.","fa":"برای شما آرزوی موفقیت در امتحان دارم."}]},{"word":"das Gold","en":"gold","ru":"золото","vi":"vàng","fa":"طلا","examples":[{"de":"Der Ring ist aus reinem Gold.","en":"The ring is made of pure gold.","ru":"Кольцо сделано из чистого золота.","vi":"Chiếc nhẫn được làm bằng vàng nguyên chất.","fa":"انگشتر از طلای خالص ساخته شده است."},{"de":"Sie hat bei den Olympischen Spielen Gold gewonnen.","en":"She won gold at the Olympic Games.","ru":"Она выиграла золото на Олимпийских играх.","vi":"Cô đã giành huy chương vàng tại Thế vận hội.","fa":"او در المپیک طلا گرفت."}]},{"word":"Golf","en":"golf (the sport)","ru":"гольф","vi":"chơi gôn","fa":"گلف","examples":[{"de":"Mein Vater spielt jeden Samstag Golf.","en":"My father plays golf every Saturday.","ru":"Мой отец играет в гольф каждую субботу.","vi":"Bố tôi chơi gôn vào thứ Bảy hàng tuần.","fa":"پدرم هر شنبه گلف بازی می کند."},{"de":"Wir haben im Urlaub einen Golfplatz besucht.","en":"We visited a golf course on vacation.","ru":"В отпуске мы посетили поле для гольфа.","vi":"Chúng tôi đã đến thăm một sân gôn vào kỳ nghỉ.","fa":"ما در تعطیلات از یک زمین گلف بازدید کردیم."}]},{"word":"der Gott","en":"God","ru":"Бог","vi":"vị thần","fa":"خدا","examples":[{"de":"Viele Menschen glauben an einen Gott.","en":"Many people believe in a God.","ru":"Многие люди верят в Бога.","vi":"Nhiều người tin vào một Thiên Chúa.","fa":"بسیاری از مردم به خدای واحد ایمان دارند."},{"de":"In der Kirche beten die Menschen zu Gott.","en":"In church, people pray to God.","ru":"В церкви люди молятся Богу.","vi":"Trong nhà thờ mọi người cầu nguyện với Chúa.","fa":"در کلیسا مردم به خدا دعا می کنند."}]},{"word":"die Grafik","en":"graphic; chart","ru":"график, графика","vi":"đồ họa","fa":"گرافیک","examples":[{"de":"Die Grafik zeigt die Entwicklung der Preise.","en":"The chart shows the development of prices.","ru":"График показывает изменение цен.","vi":"Đồ họa cho thấy sự phát triển của giá cả.","fa":"نمودار توسعه قیمت ها را نشان می دهد."},{"de":"Der Designer hat eine neue Grafik für die Webseite erstellt.","en":"The designer created a new graphic for the website.","ru":"Дизайнер создал новую графику для сайта.","vi":"Nhà thiết kế đã tạo ra một đồ họa mới cho trang web.","fa":"طراح یک گرافیک جدید برای وب سایت ایجاد کرد."}]},{"word":"das Gras","en":"grass","ru":"трава","vi":"cỏ","fa":"چمن","examples":[{"de":"Die Kinder spielen barfuß im Gras.","en":"The children are playing barefoot in the grass.","ru":"Дети играют босиком на траве.","vi":"Những đứa trẻ chơi chân trần trên bãi cỏ.","fa":"بچه ها با پای برهنه در چمن بازی می کنند."},{"de":"Im Sommer muss man das Gras oft mähen.","en":"In summer you have to mow the grass often.","ru":"Летом траву нужно часто косить.","vi":"Vào mùa hè bạn phải cắt cỏ thường xuyên.","fa":"در تابستان باید اغلب چمن ها را درو کنید."}]},{"word":"gratis","en":"free of charge","ru":"бесплатно","vi":"miễn phí","fa":"رایگان","examples":[{"de":"Der Eintritt ins Museum ist heute gratis.","en":"Admission to the museum is free today.","ru":"Вход в музей сегодня бесплатный.","vi":"Vào cửa bảo tàng ngày hôm nay là miễn phí.","fa":"ورود به موزه امروز رایگان است."},{"de":"Kinder unter sechs Jahren fahren gratis mit dem Bus.","en":"Children under six ride the bus for free.","ru":"Дети до шести лет ездят на автобусе бесплатно.","vi":"Trẻ em dưới sáu tuổi được đi miễn phí trên xe buýt.","fa":"سفر کودکان زیر شش سال با اتوبوس رایگان است."}]},{"word":"die Gratulation","en":"congratulation","ru":"поздравление","vi":"lời chúc mừng","fa":"تبریک","examples":[{"de":"Herzliche Gratulation zu deinem neuen Job!","en":"Warm congratulations on your new job!","ru":"Сердечные поздравления с новой работой!","vi":"Xin chúc mừng công việc mới của bạn!","fa":"شغل جدیدتان را تبریک می گویم!"},{"de":"Wir haben eine Karte mit unserer Gratulation geschickt.","en":"We sent a card with our congratulations.","ru":"Мы отправили открытку с нашими поздравлениями.","vi":"Chúng tôi đã gửi một tấm thiệp với lời chúc mừng của chúng tôi.","fa":"ما یک کارت با تبریک خود فرستادیم."}]},{"word":"gratulieren","en":"to congratulate","ru":"поздравлять","vi":"chúc mừng","fa":"تبریک گفتن","examples":[{"de":"Ich möchte dir zum Geburtstag gratulieren.","en":"I would like to congratulate you on your birthday.","ru":"Я хочу поздравить тебя с днём рождения.","vi":"Tôi muốn chúc bạn sinh nhật vui vẻ.","fa":"می خواهم تولدت را تبریک بگویم."},{"de":"Alle Kollegen haben ihr zur bestandenen Prüfung gratuliert.","en":"All the colleagues congratulated her on passing the exam.","ru":"Все коллеги поздравили её со сдачей экзамена.","vi":"Tất cả các đồng nghiệp đều chúc mừng cô đã vượt qua kỳ thi.","fa":"همه همکاران قبولی در امتحان را به او تبریک گفتند."}]},{"word":"greifen","en":"to grab; to reach for","ru":"хватать, браться","vi":"chộp lấy","fa":"چنگ زدن","examples":[{"de":"Das Baby greift nach dem Spielzeug.","en":"The baby reaches for the toy.","ru":"Малыш тянется за игрушкой.","vi":"Bé với tay lấy đồ chơi.","fa":"کودک دستش را به سمت اسباب بازی می برد."},{"de":"Er griff schnell nach seiner Tasche.","en":"He quickly grabbed his bag.","ru":"Он быстро схватил свою сумку.","vi":"Anh nhanh chóng đưa tay lấy túi xách của mình.","fa":"سریع دستش را به سمت کیفش برد."}]},{"word":"die Grenze","en":"border; limit","ru":"граница","vi":"biên giới","fa":"مرز","examples":[{"de":"Wir haben die Grenze zwischen Deutschland und Österreich überquert.","en":"We crossed the border between Germany and Austria.","ru":"Мы пересекли границу между Германией и Австрией.","vi":"Chúng tôi vượt qua biên giới giữa Đức và Áo.","fa":"از مرز آلمان و اتریش گذشتیم."},{"de":"Jeder Mensch hat seine eigenen Grenzen.","en":"Every person has their own limits.","ru":"У каждого человека есть свои границы.","vi":"Mỗi người đều có những giới hạn riêng của mình.","fa":"هر فردی محدودیت های خاص خود را دارد."}]},{"word":"grillen","en":"to grill; to barbecue","ru":"жарить на гриле","vi":"nướng","fa":"کباب","examples":[{"de":"Am Wochenende grillen wir im Garten.","en":"On the weekend we grill in the garden.","ru":"На выходных мы жарим на гриле в саду.","vi":"Cuối tuần chúng tôi nướng thịt ngoài vườn.","fa":"آخر هفته در باغ کباب می کنیم."},{"de":"Er grillt gern Fleisch und Gemüse.","en":"He likes to grill meat and vegetables.","ru":"Он любит жарить на гриле мясо и овощи.","vi":"Anh ấy thích nướng thịt và rau.","fa":"او دوست دارد گوشت و سبزیجات را کباب کند."}]},{"word":"grillieren","en":"to grill; to barbecue (Swiss German)","ru":"жарить на гриле (швейц.)","vi":"nướng","fa":"کباب","examples":[{"de":"In der Schweiz sagt man oft \"grillieren\" statt \"grillen\".","en":"In Switzerland people often say \"grillieren\" instead of \"grillen\".","ru":"В Швейцарии часто говорят «grillieren» вместо «grillen».","vi":"Ở Thụy Sĩ người ta thường nói \"nướng\" thay vì \"nướng\".","fa":"در سوئیس اغلب به جای \"گریل\" می گویند \"گریل\"."},{"de":"Wir grillieren heute Abend Würste auf dem Balkon.","en":"This evening we're grilling sausages on the balcony.","ru":"Сегодня вечером мы жарим на гриле колбаски на балконе.","vi":"Tối nay chúng tôi sẽ nướng xúc xích ngoài ban công.","fa":"امروز عصر در بالکن سوسیس کباب می کنیم."}]},{"word":"die Grippe","en":"flu","ru":"грипп","vi":"bệnh cúm","fa":"آنفولانزا","examples":[{"de":"Ich habe Fieber, ich glaube, ich habe die Grippe.","en":"I have a fever, I think I have the flu.","ru":"У меня температура, кажется, у меня грипп.","vi":"Tôi bị sốt, tôi nghĩ mình bị cúm.","fa":"من تب دارم فکر کنم آنفولانزا گرفتم."},{"de":"Im Winter lassen sich viele Leute gegen die Grippe impfen.","en":"In winter many people get vaccinated against the flu.","ru":"Зимой многие люди делают прививку от гриппа.","vi":"Vào mùa đông, nhiều người được tiêm phòng cúm.","fa":"در زمستان، بسیاری از مردم علیه آنفولانزا واکسینه می شوند."}]},{"word":"groß","en":"big; large","ru":"большой","vi":"lớn","fa":"بزرگ","examples":[{"de":"Sie wohnen in einem großen Haus.","en":"They live in a big house.","ru":"Они живут в большом доме.","vi":"Họ sống trong một ngôi nhà lớn.","fa":"آنها در یک خانه بزرگ زندگی می کنند."},{"de":"Mein Bruder ist größer als ich.","en":"My brother is taller than me.","ru":"Мой брат выше меня.","vi":"Anh trai tôi cao hơn tôi.","fa":"برادرم از من بلندتر است."}]},{"word":"Groß-","en":"prefix meaning \"large, grand, great\" (e.g. in \"Großstadt\" = big city)","ru":"приставка со значением «большой, старший, главный» (напр. Großstadt — крупный город)","vi":"vốn","fa":"سرمایه","examples":[{"de":"Berlin ist eine Großstadt mit vielen Einwohnern.","en":"Berlin is a big city with many inhabitants.","ru":"Берлин — крупный город с большим количеством жителей.","vi":"Berlin là một thành phố lớn với nhiều cư dân.","fa":"برلین شهر بزرگی است که ساکنان زیادی دارد."},{"de":"Meine Großmutter wohnt bei uns in der Nähe.","en":"My grandmother lives near us.","ru":"Моя бабушка живёт рядом с нами.","vi":"Bà tôi sống gần chúng tôi.","fa":"مادربزرگم نزدیک ما زندگی می کند."}]},{"word":"großzügig","en":"generous","ru":"щедрый","vi":"hào phóng","fa":"سخاوتمندانه","examples":[{"de":"Er ist immer sehr großzügig mit seinen Freunden.","en":"He is always very generous with his friends.","ru":"Он всегда очень щедр со своими друзьями.","vi":"Anh ấy luôn rất hào phóng với bạn bè.","fa":"او همیشه با دوستانش بسیار سخاوتمند است."},{"de":"Vielen Dank für das großzügige Geschenk.","en":"Thank you very much for the generous gift.","ru":"Большое спасибо за щедрый подарок.","vi":"Cảm ơn bạn vì món quà hào phóng.","fa":"ممنون از هدیه سخاوتمندانه"}]},{"word":"der Grund","en":"reason","ru":"причина","vi":"lý do","fa":"دلیل","examples":[{"de":"Was ist der Grund für deine Verspätung?","en":"What is the reason for your lateness?","ru":"В чём причина твоего опоздания?","vi":"Lý do cho sự chậm trễ của bạn là gì?","fa":"دلیل تاخیر شما چیست؟"},{"de":"Aus welchem Grund hast du gekündigt?","en":"For what reason did you quit?","ru":"По какой причине ты уволился?","vi":"Vì lý do gì bạn đã bỏ cuộc?","fa":"به چه دلیلی استعفا دادی؟"}]},{"word":"gründen","en":"to found; to establish","ru":"основывать","vi":"thành lập","fa":"ایجاد کند","examples":[{"de":"Die beiden Freunde wollen eine eigene Firma gründen.","en":"The two friends want to found their own company.","ru":"Оба друга хотят основать собственную компанию.","vi":"Hai người bạn muốn thành lập công ty riêng.","fa":"این دو دوست می خواهند شرکت خود را راه اندازی کنند."},{"de":"Die Stadt wurde vor über 500 Jahren gegründet.","en":"The city was founded over 500 years ago.","ru":"Город был основан более 500 лет назад.","vi":"Thành phố được thành lập hơn 500 năm trước.","fa":"این شهر بیش از 500 سال پیش تاسیس شد."}]},{"word":"gründlich","en":"thorough","ru":"тщательный","vi":"triệt để","fa":"به طور کامل","examples":[{"de":"Sie hat die Wohnung gründlich geputzt.","en":"She cleaned the apartment thoroughly.","ru":"Она тщательно убрала квартиру.","vi":"Cô dọn dẹp căn hộ thật kỹ lưỡng.","fa":"او آپارتمان را کاملا تمیز کرد."},{"de":"Der Arzt hat mich gründlich untersucht.","en":"The doctor examined me thoroughly.","ru":"Врач тщательно меня осмотрел.","vi":"Bác sĩ đã khám cho tôi rất kỹ.","fa":"دکتر مرا به طور کامل معاینه کرد."}]},{"word":"das Grundstück","en":"plot of land; property","ru":"земельный участок","vi":"tài sản","fa":"ملک","examples":[{"de":"Meine Eltern haben ein Grundstück am See gekauft.","en":"My parents bought a plot of land by the lake.","ru":"Мои родители купили земельный участок у озера.","vi":"Bố mẹ tôi mua bất động sản trên hồ.","fa":"پدر و مادرم روی دریاچه ملک خریدند."},{"de":"Auf dem Grundstück soll ein neues Haus gebaut werden.","en":"A new house is supposed to be built on the property.","ru":"На этом участке планируется построить новый дом.","vi":"Một ngôi nhà mới sẽ được xây dựng trên khu đất này.","fa":"قرار است یک خانه جدید در ملک ساخته شود."}]},{"word":"die Gruppe","en":"group","ru":"группа","vi":"nhóm","fa":"گروه","examples":[{"de":"Die Schüler arbeiten heute in kleinen Gruppen.","en":"The students are working in small groups today.","ru":"Сегодня ученики работают в маленьких группах.","vi":"Hôm nay học sinh làm việc theo nhóm nhỏ.","fa":"امروزه دانش آموزان در گروه های کوچک کار می کنند."},{"de":"Eine Gruppe von Touristen besichtigt das Schloss.","en":"A group of tourists is visiting the castle.","ru":"Группа туристов осматривает замок.","vi":"Một nhóm du khách tham quan lâu đài.","fa":"گروهی از گردشگران از قلعه بازدید می کنند."}]},{"word":"grüßen","en":"to greet","ru":"приветствовать, здороваться","vi":"chào","fa":"سلام کردن","examples":[{"de":"Er grüßt jeden Morgen seine Nachbarn.","en":"He greets his neighbors every morning.","ru":"Он приветствует своих соседей каждое утро.","vi":"Anh ấy chào hàng xóm vào mỗi buổi sáng.","fa":"او هر روز صبح به همسایه هایش سلام می کند."},{"de":"Grüß deine Familie von mir!","en":"Say hello to your family for me!","ru":"Передай привет своей семье от меня!","vi":"Gửi lời chào gia đình bạn giùm tôi nhé!","fa":"برای من به خانواده خود سلام برسان!"}]},{"word":"gucken","en":"to look (colloquial)","ru":"смотреть, глядеть","vi":"Nhìn","fa":"نگاه کن","examples":[{"de":"Guck mal, wie schön der Sonnenuntergang ist!","en":"Look how beautiful the sunset is!","ru":"Смотри, какой красивый закат!","vi":"Hãy nhìn hoàng hôn đẹp làm sao!","fa":"ببین غروب چقدر زیباست"},{"de":"Die Kinder gucken abends gern fern.","en":"In the evening the children like to watch TV.","ru":"По вечерам дети любят смотреть телевизор.","vi":"Trẻ em thích xem TV vào buổi tối.","fa":"بچه ها دوست دارند عصرها تلویزیون تماشا کنند."}]},{"word":"gültig","en":"valid","ru":"действительный","vi":"hợp lệ","fa":"معتبر","examples":[{"de":"Mein Reisepass ist noch zwei Jahre gültig.","en":"My passport is still valid for two years.","ru":"Мой паспорт действителен ещё два года.","vi":"Hộ chiếu của tôi vẫn còn hiệu lực trong hai năm.","fa":"پاسپورت من هنوز دو سال اعتبار دارد."},{"de":"Das Ticket ist nur heute gültig.","en":"The ticket is only valid today.","ru":"Билет действителен только сегодня.","vi":"Vé chỉ có hiệu lực trong ngày hôm nay.","fa":"بلیط فقط امروز معتبر است."}]},{"word":"günstig","en":"cheap; favorable","ru":"выгодный, недорогой","vi":"giá rẻ","fa":"ارزان","examples":[{"de":"In diesem Geschäft sind die Preise sehr günstig.","en":"In this shop the prices are very cheap.","ru":"В этом магазине цены очень выгодные.","vi":"Ở cửa hàng này giá cả rất phải chăng.","fa":"در این فروشگاه قیمت ها بسیار مقرون به صرفه است."},{"de":"Wir haben einen günstigen Flug gefunden.","en":"We found an affordable flight.","ru":"Мы нашли недорогой авиабилет.","vi":"Chúng tôi tìm thấy một chuyến bay giá rẻ.","fa":"یک پرواز ارزان پیدا کردیم."}]},{"word":"gut","en":"good; well","ru":"хороший, хорошо","vi":"tốt","fa":"خوب","examples":[{"de":"Das Essen in diesem Restaurant ist wirklich gut.","en":"The food in this restaurant is really good.","ru":"Еда в этом ресторане действительно хорошая.","vi":"Đồ ăn ở nhà hàng này thực sự rất ngon.","fa":"غذاهای این رستوران واقعا عالی است."},{"de":"Mir geht es heute gut.","en":"I'm doing well today.","ru":"Сегодня я чувствую себя хорошо.","vi":"Hôm nay tôi ổn.","fa":"امروز خوبم"}]},{"word":"die Gymnastik","en":"gymnastics; exercise","ru":"гимнастика","vi":"thể dục dụng cụ","fa":"ژیمناستیک","examples":[{"de":"Jeden Morgen macht sie zehn Minuten Gymnastik.","en":"Every morning she does ten minutes of exercise.","ru":"Каждое утро она делает десятиминутную гимнастику.","vi":"Mỗi buổi sáng cô ấy tập thể dục mười phút.","fa":"او هر روز صبح ده دقیقه ژیمناستیک انجام می دهد."},{"de":"In der Schule haben wir zweimal pro Woche Gymnastik.","en":"At school we have gymnastics twice a week.","ru":"В школе у нас гимнастика два раза в неделю.","vi":"Ở trường chúng tôi có thể dục dụng cụ hai lần một tuần.","fa":"در مدرسه هفته ای دو بار ژیمناستیک داریم."}]},{"word":"das Haar","en":"hair","ru":"волосы","vi":"mái tóc","fa":"مو","examples":[{"de":"Sie hat lange, dunkle Haare.","en":"She has long, dark hair.","ru":"У неё длинные тёмные волосы.","vi":"Cô ấy có mái tóc dài và đen.","fa":"او موهای بلند و تیره ای دارد."},{"de":"Er kämmt sich jeden Morgen die Haare.","en":"He combs his hair every morning.","ru":"Он расчёсывает волосы каждое утро.","vi":"Anh ấy chải tóc vào mỗi buổi sáng.","fa":"هر روز صبح موهایش را شانه می کند."}]},{"word":"haben","en":"to have","ru":"иметь","vi":"có","fa":"دارند","examples":[{"de":"Ich habe heute leider keine Zeit.","en":"Unfortunately I don't have time today.","ru":"К сожалению, сегодня у меня нет времени.","vi":"Thật không may là hôm nay tôi không có thời gian.","fa":"متاسفانه امروز وقت ندارم"},{"de":"Wir haben ein kleines Auto.","en":"We have a small car.","ru":"У нас маленькая машина.","vi":"Chúng tôi có một chiếc xe nhỏ.","fa":"ما یک ماشین کوچک داریم."}]},{"word":"das Hackfleisch","en":"minced meat; ground meat","ru":"фарш","vi":"thịt băm","fa":"گوشت چرخ کرده","examples":[{"de":"Für die Soße brauchen wir 500 Gramm Hackfleisch.","en":"For the sauce we need 500 grams of minced meat.","ru":"Для соуса нам нужно 500 граммов фарша.","vi":"Đối với nước sốt chúng ta cần 500 gram thịt băm.","fa":"برای سس به 500 گرم گوشت چرخ کرده نیاز داریم."},{"de":"Sie macht aus Hackfleisch leckere Frikadellen.","en":"She makes delicious meatballs from minced meat.","ru":"Она делает вкусные котлеты из фарша.","vi":"Cô ấy làm món thịt viên thơm ngon từ thịt băm.","fa":"او از گوشت چرخ کرده کوفته های خوشمزه درست می کند."}]},{"word":"der Hafen","en":"harbor; port","ru":"порт, гавань","vi":"cảng","fa":"بندر","examples":[{"de":"Das Schiff verlässt heute den Hafen.","en":"The ship is leaving the harbor today.","ru":"Сегодня корабль покидает порт.","vi":"Hôm nay tàu rời cảng.","fa":"کشتی امروز بندر را ترک می کند."},{"de":"Hamburg hat einen der größten Häfen Europas.","en":"Hamburg has one of the largest ports in Europe.","ru":"В Гамбурге находится один из крупнейших портов Европы.","vi":"Hamburg có một trong những cảng lớn nhất ở châu Âu.","fa":"هامبورگ یکی از بزرگترین بنادر اروپا را دارد."}]},{"word":"hageln","en":"to hail","ru":"идти (о граде)","vi":"mưa đá","fa":"تگرگ","examples":[{"de":"Es hagelt so stark, dass wir zu Hause bleiben.","en":"It's hailing so hard that we're staying home.","ru":"Град такой сильный, что мы остаёмся дома.","vi":"Trời mưa đá dữ dội đến nỗi chúng tôi phải ở nhà.","fa":"آنقدر باران می بارید که مجبور شدیم در خانه بمانیم."},{"de":"Gestern hat es plötzlich gehagelt.","en":"Yesterday it suddenly hailed.","ru":"Вчера внезапно пошёл град.","vi":"Hôm qua nó đột nhiên ca ngợi.","fa":"دیروز ناگهان تگرگ آمد."}]},{"word":"das Hähnchen/Hühnchen","en":"chicken (as food)","ru":"курица, цыплёнок (как блюдо)","vi":"con gà/gà","fa":"مرغ/مرغ","examples":[{"de":"Zum Mittagessen gibt es heute Hähnchen mit Reis.","en":"For lunch today there's chicken with rice.","ru":"Сегодня на обед курица с рисом.","vi":"Bữa trưa hôm nay chúng tôi có cơm gà.","fa":"برای ناهار امروز مرغ با برنج داریم."},{"de":"Er bestellt im Restaurant gern ein gegrilltes Hühnchen.","en":"In restaurants he likes to order grilled chicken.","ru":"В ресторане он любит заказывать курицу-гриль.","vi":"Anh ấy thích gọi món gà nướng ở nhà hàng.","fa":"او دوست دارد در رستوران مرغ کبابی سفارش دهد."}]},{"word":"halb","en":"half","ru":"половина; наполовину","vi":"một nửa","fa":"نصف","examples":[{"de":"Ich nehme nur ein halbes Brot.","en":"I'll take only half a loaf of bread.","ru":"Я возьму только полбулки хлеба.","vi":"Tôi chỉ lấy nửa ổ bánh mì thôi.","fa":"من فقط نصف قرص نان می گیرم."},{"de":"Es ist jetzt halb neun.","en":"It's now half past eight.","ru":"Сейчас половина девятого.","vi":"Bây giờ là tám giờ rưỡi.","fa":"الان ساعت هشت و نیم است."}]},{"word":"die Hälfte","en":"half","ru":"половина","vi":"một nửa","fa":"نصف","examples":[{"de":"Die Hälfte der Schüler war krank.","en":"Half of the students were sick.","ru":"Половина учеников болела.","vi":"Một nửa số học sinh bị ốm.","fa":"نیمی از دانش آموزان بیمار بودند."},{"de":"Ich gebe dir die Hälfte von meinem Kuchen.","en":"I'll give you half of my cake.","ru":"Я отдам тебе половину своего пирога.","vi":"Tôi sẽ đưa cho bạn một nửa chiếc bánh của tôi.","fa":"نصف کیکم رو بهت میدم"}]},{"word":"die Halle","en":"hall","ru":"зал","vi":"hội trường","fa":"سالن","examples":[{"de":"Das Konzert findet in einer großen Halle statt.","en":"The concert takes place in a large hall.","ru":"Концерт проходит в большом зале.","vi":"Buổi hòa nhạc diễn ra trong một hội trường lớn.","fa":"کنسرت در یک سالن بزرگ برگزار می شود."},{"de":"Die Sportler trainieren in der Halle.","en":"The athletes train in the hall.","ru":"Спортсмены тренируются в зале.","vi":"Các vận động viên tập luyện trong hội trường.","fa":"ورزشکاران در سالن تمرین می کنند."}]},{"word":"hallo","en":"hello","ru":"привет","vi":"xin chào","fa":"سلام","examples":[{"de":"Hallo, wie geht es dir?","en":"Hello, how are you?","ru":"Привет, как дела?","vi":"Xin chào, bạn khỏe không?","fa":"سلام حالتون چطوره؟"},{"de":"Sie ruft \"Hallo!\" und winkt uns zu.","en":"She calls \"Hello!\" and waves to us.","ru":"Она кричит «Привет!» и машет нам рукой.","vi":"Cô ấy gọi \"Xin chào!\" và vẫy tay với chúng tôi.","fa":"او صدا می زند \"سلام!\" و برای ما دست تکان می دهد"}]},{"word":"der Hals","en":"neck; throat","ru":"шея, горло","vi":"cái cổ","fa":"گردن","examples":[{"de":"Mein Hals tut weh, ich habe wohl eine Erkältung.","en":"My throat hurts, I probably have a cold.","ru":"У меня болит горло, наверное, я простудился.","vi":"Cổ họng tôi đau quá, tôi nghĩ mình bị cảm lạnh.","fa":"گلویم درد می کند، فکر کنم سرما خورده ام."},{"de":"Sie trägt eine Kette um den Hals.","en":"She wears a necklace around her neck.","ru":"Она носит цепочку на шее.","vi":"Cô ấy đeo một sợi dây chuyền quanh cổ.","fa":"زنجیر به گردنش می بندد."}]},{"word":"halt","en":"just, simply (filler particle); stop! (interjection)","ru":"просто, именно (частица); стоп!","vi":"dừng lại","fa":"توقف","examples":[{"de":"Das ist halt so, man kann nichts ändern.","en":"That's just how it is, you can't change anything.","ru":"Так уж есть, ничего не поделаешь.","vi":"Vốn dĩ là vậy, bạn không thể thay đổi được gì cả.","fa":"همین طور است، شما نمی توانید چیزی را تغییر دهید."},{"de":"\"Halt!\", rief der Polizist dem Fahrer zu.","en":"\"Stop!\" the police officer shouted to the driver.","ru":"«Стоп!» — крикнул полицейский водителю.","vi":"\"Dừng lại!\" viên cảnh sát hét vào mặt tài xế.","fa":"\"ایست کن!\" افسر پلیس به راننده فریاد زد."}]},{"word":"haltbar","en":"durable; non-perishable, keeps well","ru":"прочный; долго хранящийся","vi":"bền bỉ","fa":"بادوام","examples":[{"de":"Diese Milch ist noch bis nächste Woche haltbar.","en":"This milk is still good until next week.","ru":"Это молоко годно ещё до следующей недели.","vi":"Sữa này sẽ kéo dài đến tuần sau.","fa":"این شیر تا هفته آینده ماندگاری دارد."},{"de":"Die Schuhe sind aus haltbarem Material.","en":"The shoes are made of durable material.","ru":"Обувь сделана из прочного материала.","vi":"Giày được làm từ chất liệu bền đẹp.","fa":"کفش ها از مواد بادوام ساخته شده اند."}]},{"word":"halten","en":"to hold; to stop (of a vehicle)","ru":"держать; останавливаться","vi":"giữ","fa":"نگه دارید","examples":[{"de":"Kannst du bitte kurz meine Tasche halten?","en":"Can you hold my bag for a moment, please?","ru":"Можешь ненадолго подержать мою сумку?","vi":"Bạn có thể giữ túi của tôi một lúc được không?","fa":"میشه لطفا یه لحظه کیفم رو نگه دارید؟"},{"de":"Der Bus hält direkt vor unserem Haus.","en":"The bus stops right in front of our house.","ru":"Автобус останавливается прямо перед нашим домом.","vi":"Xe buýt dừng ngay trước nhà chúng tôi.","fa":"اتوبوس درست جلوی خانه ما می ایستد."}]},{"word":"der Hammer","en":"hammer","ru":"молоток","vi":"cái búa","fa":"چکش","examples":[{"de":"Er braucht einen Hammer, um den Nagel einzuschlagen.","en":"He needs a hammer to drive in the nail.","ru":"Ему нужен молоток, чтобы забить гвоздь.","vi":"Anh ta cần một cái búa để đóng đinh.","fa":"او به یک چکش نیاز دارد تا در میخ بکوبد."},{"de":"Der Hammer liegt in der Werkzeugkiste.","en":"The hammer is in the toolbox.","ru":"Молоток лежит в ящике с инструментами.","vi":"Cái búa ở trong hộp dụng cụ.","fa":"چکش در جعبه ابزار است."}]},{"word":"die Hand","en":"hand","ru":"рука","vi":"bàn tay","fa":"دست","examples":[{"de":"Gib mir bitte deine Hand.","en":"Please give me your hand.","ru":"Дай мне, пожалуйста, свою руку.","vi":"Xin hãy đưa tay cho tôi.","fa":"لطفا دستت را به من بده"},{"de":"Sie wäscht sich vor dem Essen die Hände.","en":"She washes her hands before eating.","ru":"Она моет руки перед едой.","vi":"Cô rửa tay trước khi ăn.","fa":"قبل از غذا دست هایش را می شویند."}]},{"word":"handeln","en":"to act; to trade/deal","ru":"действовать; торговать","vi":"hành động","fa":"عمل کنید","examples":[{"de":"In dieser schwierigen Situation müssen wir schnell handeln.","en":"In this difficult situation we have to act quickly.","ru":"В этой сложной ситуации нам нужно действовать быстро.","vi":"Trong tình thế khó khăn này chúng ta phải hành động nhanh chóng.","fa":"در این شرایط سخت باید سریع عمل کنیم."},{"de":"Er handelt mit gebrauchten Autos.","en":"He trades in used cars.","ru":"Он торгует подержанными автомобилями.","vi":"Anh ấy kinh doanh xe cũ.","fa":"او با ماشین های دست دوم معامله می کند."}]},{"word":"die Handwerkerin","en":"craftswoman; tradeswoman","ru":"мастерица, ремесленница","vi":"người phụ nữ thủ công","fa":"صنعتگر","examples":[{"de":"Die Handwerkerin repariert das kaputte Fenster.","en":"The tradeswoman is repairing the broken window.","ru":"Мастерица чинит сломанное окно.","vi":"Người thợ thủ công sửa lại cửa sổ bị vỡ.","fa":"صنعتگر پنجره شکسته را تعمیر می کند."},{"de":"Als Handwerkerin arbeitet sie oft auf Baustellen.","en":"As a tradeswoman, she often works on construction sites.","ru":"Как мастерица, она часто работает на стройках.","vi":"Là một thợ thủ công, cô thường xuyên làm việc ở các công trường xây dựng.","fa":"به عنوان یک صنعتگر، او اغلب در سایت های ساختمانی کار می کند."}]},{"word":"das Handy","en":"mobile phone; cell phone","ru":"мобильный телефон","vi":"điện thoại di động","fa":"تلفن همراه","examples":[{"de":"Ich habe mein Handy leider zu Hause vergessen.","en":"Unfortunately I forgot my phone at home.","ru":"К сожалению, я забыл телефон дома.","vi":"Thật không may, tôi lại để quên điện thoại di động ở nhà.","fa":"متاسفانه تلفن همراهم را در خانه فراموش کردم."},{"de":"Kinder bekommen heute schon früh ein Handy.","en":"Nowadays children get a cell phone quite early.","ru":"Сегодня дети получают мобильный телефон довольно рано.","vi":"Trẻ em ngày nay có điện thoại di động sớm.","fa":"این روزها بچه ها زودتر تلفن همراه می گیرند."}]},{"word":"hängen","en":"to hang","ru":"висеть; вешать","vi":"treo","fa":"آویزان کردن","examples":[{"de":"An der Wand hängt ein altes Familienfoto.","en":"An old family photo hangs on the wall.","ru":"На стене висит старая семейная фотография.","vi":"Có một bức ảnh cũ của gia đình treo trên tường.","fa":"یک عکس خانوادگی قدیمی روی دیوار آویزان است."},{"de":"Sie hängt die Wäsche zum Trocknen auf.","en":"She hangs the laundry up to dry.","ru":"Она развешивает бельё для сушки.","vi":"Cô ấy phơi đồ giặt ra ngoài.","fa":"او لباس‌ها را آویزان می‌کند تا خشک شوند."}]},{"word":"hart","en":"hard","ru":"твёрдый, жёсткий","vi":"cứng","fa":"سخت","examples":[{"de":"Das Brot ist schon ganz hart geworden.","en":"The bread has already become quite hard.","ru":"Хлеб уже стал совсем твёрдым.","vi":"Bánh mì đã trở nên rất cứng rồi.","fa":"نان در حال حاضر بسیار سفت شده است."},{"de":"Er arbeitet sehr hart für seine Familie.","en":"He works very hard for his family.","ru":"Он очень тяжело работает ради своей семьи.","vi":"Anh ấy làm việc rất chăm chỉ cho gia đình mình.","fa":"او برای خانواده اش خیلی زحمت می کشد."}]},{"word":"hassen","en":"to hate","ru":"ненавидеть","vi":"ghét","fa":"نفرت","examples":[{"de":"Sie hasst es, morgens früh aufzustehen.","en":"She hates getting up early in the morning.","ru":"Она ненавидит рано вставать по утрам.","vi":"Cô ấy ghét việc phải dậy sớm vào buổi sáng.","fa":"او از صبح زود بیدار شدن متنفر است."},{"de":"Ich hasse Streit in der Familie.","en":"I hate arguments in the family.","ru":"Я ненавижу ссоры в семье.","vi":"Tôi ghét những cuộc cãi vã trong gia đình.","fa":"من از بحث و جدل در خانواده متنفرم."}]},{"word":"hässlich","en":"ugly","ru":"некрасивый, уродливый","vi":"xấu xí","fa":"زشت","examples":[{"de":"Das alte Gebäude sieht ziemlich hässlich aus.","en":"The old building looks quite ugly.","ru":"Старое здание выглядит довольно некрасиво.","vi":"Tòa nhà cũ trông khá xấu xí.","fa":"ساختمان قدیمی بسیار زشت به نظر می رسد."},{"de":"Er hat ein hässliches Wort benutzt.","en":"He used an ugly word.","ru":"Он использовал некрасивое слово.","vi":"Anh ta dùng một từ xấu xí.","fa":"کلمه زشتی به کار برد."}]},{"word":"häufig","en":"frequent; frequently","ru":"частый, часто","vi":"thường xuyên","fa":"اغلب","examples":[{"de":"Er macht häufig denselben Fehler.","en":"He frequently makes the same mistake.","ru":"Он часто допускает одну и ту же ошибку.","vi":"Anh ấy thường mắc phải sai lầm tương tự.","fa":"او اغلب همین اشتباه را انجام می دهد."},{"de":"Häufige Kopfschmerzen können ein Zeichen von Stress sein.","en":"Frequent headaches can be a sign of stress.","ru":"Частые головные боли могут быть признаком стресса.","vi":"Đau đầu thường xuyên có thể là dấu hiệu của căng thẳng.","fa":"سردردهای مکرر می تواند نشانه استرس باشد."}]},{"word":"Haupt-","en":"prefix meaning \"main, chief\" (e.g. \"Hauptstadt\" = capital city)","ru":"приставка со значением «главный, основной» (напр. Hauptstadt — столица)","vi":"chính","fa":"اصلی","examples":[{"de":"Berlin ist die Hauptstadt von Deutschland.","en":"Berlin is the capital of Germany.","ru":"Берлин — столица Германии.","vi":"Berlin là thủ đô của Đức.","fa":"برلین پایتخت آلمان است."},{"de":"Der Hauptbahnhof liegt im Zentrum der Stadt.","en":"The main train station is located in the city center.","ru":"Главный вокзал находится в центре города.","vi":"Nhà ga xe lửa chính nằm ở trung tâm thành phố.","fa":"ایستگاه اصلی قطار در مرکز شهر قرار دارد."}]},{"word":"das Haus","en":"house","ru":"дом","vi":"ngôi nhà","fa":"خانه","examples":[{"de":"Wir wohnen in einem kleinen Haus am Stadtrand.","en":"We live in a small house on the edge of town.","ru":"Мы живём в маленьком доме на окраине города.","vi":"Chúng tôi sống trong một ngôi nhà nhỏ ở ngoại ô thị trấn.","fa":"ما در یک خانه کوچک در حومه شهر زندگی می کنیم."},{"de":"Meine Eltern wollen ein neues Haus bauen.","en":"My parents want to build a new house.","ru":"Мои родители хотят построить новый дом.","vi":"Bố mẹ tôi muốn xây một ngôi nhà mới.","fa":"پدر و مادرم می خواهند یک خانه جدید بسازند."}]},{"word":"die Hausfrau","en":"housewife","ru":"домохозяйка","vi":"bà nội trợ","fa":"زن خانه دار","examples":[{"de":"Meine Mutter ist Hausfrau und kümmert sich um die Kinder.","en":"My mother is a housewife and takes care of the children.","ru":"Моя мама — домохозяйка и заботится о детях.","vi":"Mẹ tôi là một bà nội trợ và chăm sóc con cái.","fa":"مادرم خانه دار است و از بچه ها نگهداری می کند."},{"de":"Als Hausfrau hat sie den ganzen Tag viel zu tun.","en":"As a housewife, she has a lot to do all day.","ru":"Будучи домохозяйкой, она весь день очень занята.","vi":"Là một bà nội trợ, cô ấy có rất nhiều việc phải làm cả ngày.","fa":"او به عنوان یک زن خانه دار در تمام طول روز کارهای زیادی برای انجام دادن دارد."}]},{"word":"der Hausmeister","en":"caretaker; janitor","ru":"комендант дома, завхоз","vi":"người chăm sóc","fa":"سرایدار","examples":[{"de":"Der Hausmeister repariert die kaputte Heizung.","en":"The caretaker is repairing the broken heating.","ru":"Комендант дома чинит сломанное отопление.","vi":"Người chăm sóc sửa chữa lò sưởi bị hỏng.","fa":"سرایدار بخاری خراب را تعمیر می کند."},{"de":"Wenn etwas kaputt ist, ruft man den Hausmeister.","en":"If something is broken, you call the caretaker.","ru":"Если что-то сломалось, вызывают завхоза.","vi":"Nếu có gì bị hỏng, bạn gọi người chăm sóc.","fa":"اگر چیزی شکسته است، با نگهبان تماس بگیرید."}]},{"word":"die Hausmeisterin","en":"caretaker; janitor (female)","ru":"комендантша, завхоз (женщина)","vi":"người chăm sóc","fa":"سرایدار","examples":[{"de":"Die Hausmeisterin kümmert sich um den Garten und das Treppenhaus.","en":"The caretaker takes care of the garden and the stairwell.","ru":"Комендантша заботится о саде и лестничной клетке.","vi":"Người chăm sóc chăm sóc khu vườn và cầu thang.","fa":"سرایدار از باغ و راه پله مراقبت می کند."},{"de":"Unsere Hausmeisterin ist sehr freundlich und hilfsbereit.","en":"Our caretaker is very friendly and helpful.","ru":"Наша комендантша очень дружелюбная и отзывчивая.","vi":"Người chăm sóc của chúng tôi rất thân thiện và hữu ích.","fa":"سرایدار ما بسیار دوستانه و مفید است."}]},{"word":"die Haut","en":"skin","ru":"кожа","vi":"da","fa":"پوست","examples":[{"de":"Im Sommer sollte man die Haut vor der Sonne schützen.","en":"In summer you should protect your skin from the sun.","ru":"Летом нужно защищать кожу от солнца.","vi":"Vào mùa hè bạn nên bảo vệ da khỏi ánh nắng mặt trời.","fa":"در تابستان باید از پوست خود در برابر نور خورشید محافظت کنید."},{"de":"Sie hat eine sehr empfindliche Haut.","en":"She has very sensitive skin.","ru":"У неё очень чувствительная кожа.","vi":"Cô ấy có làn da rất nhạy cảm.","fa":"او پوست بسیار حساسی دارد."}]},{"word":"heben","en":"to lift","ru":"поднимать","vi":"nâng","fa":"بالابر","examples":[{"de":"Er kann den schweren Koffer kaum heben.","en":"He can hardly lift the heavy suitcase.","ru":"Он едва может поднять тяжёлый чемодан.","vi":"Anh gần như không thể nhấc nổi chiếc vali nặng nề.","fa":"او به سختی می تواند چمدان سنگین را بلند کند."},{"de":"Bitte hebt die Hand, wenn ihr eine Frage habt.","en":"Please raise your hand if you have a question.","ru":"Пожалуйста, поднимите руку, если у вас есть вопрос.","vi":"Hãy giơ tay nếu bạn có câu hỏi.","fa":"لطفا اگر سوالی دارید دست خود را بالا ببرید."}]},{"word":"das Heft","en":"notebook; exercise book","ru":"тетрадь","vi":"tập sách nhỏ","fa":"جزوه","examples":[{"de":"Jeder Schüler braucht ein Heft für Mathematik.","en":"Every student needs a notebook for math.","ru":"Каждому ученику нужна тетрадь по математике.","vi":"Mỗi học sinh đều cần một cuốn sổ toán.","fa":"هر دانش آموزی به یک دفتر ریاضی نیاز دارد."},{"de":"Sie schreibt die Vokabeln in ihr Heft.","en":"She writes the vocabulary in her notebook.","ru":"Она записывает слова в свою тетрадь.","vi":"Cô ấy viết từ vựng vào sổ tay của mình.","fa":"واژگان را در دفترچه اش می نویسد."}]},{"word":"heim","en":"home(ward) (going home)","ru":"домой","vi":"nhà","fa":"خانه","examples":[{"de":"Nach der Arbeit fahre ich müde heim.","en":"After work I drive home tired.","ru":"После работы я устало еду домой.","vi":"Sau giờ làm việc tôi lái xe về nhà mệt mỏi.","fa":"بعد از کار خسته به خانه می روم."},{"de":"Es wird spät, wir sollten heimgehen.","en":"It's getting late, we should go home.","ru":"Уже поздно, нам стоит пойти домой.","vi":"Cũng muộn rồi, chúng ta nên về nhà thôi.","fa":"داره دیر میشه باید بریم خونه"}]},{"word":"das Heim","en":"home (institution, e.g. residential home)","ru":"дом, приют (учреждение)","vi":"ngôi nhà","fa":"خانه","examples":[{"de":"Die alte Dame lebt jetzt in einem Heim.","en":"The old lady now lives in a residential home.","ru":"Пожилая дама теперь живёт в доме престарелых.","vi":"Bà già hiện đang sống trong một ngôi nhà.","fa":"پیرزن اکنون در یک خانه زندگی می کند."},{"de":"Das Kind wuchs in einem Heim auf.","en":"The child grew up in a children's home.","ru":"Ребёнок вырос в детском доме.","vi":"Đứa trẻ lớn lên trong một gia đình.","fa":"کودک در خانه بزرگ شد."}]},{"word":"die Heimat","en":"homeland","ru":"родина","vi":"quê hương","fa":"وطن","examples":[{"de":"Nach vielen Jahren im Ausland kehrte er in seine Heimat zurück.","en":"After many years abroad, he returned to his homeland.","ru":"После многих лет за границей он вернулся на родину.","vi":"Sau nhiều năm ở nước ngoài, anh trở về quê hương.","fa":"پس از سالها خارج از کشور به وطن بازگشت."},{"de":"Seine Heimat ist ein kleines Dorf in den Bergen.","en":"His homeland is a small village in the mountains.","ru":"Его родина — маленькая деревня в горах.","vi":"Nhà anh là một ngôi làng nhỏ trên núi.","fa":"خانه او روستایی کوچک در کوهستان است."}]},{"word":"heimlich","en":"secret; secretly","ru":"тайный, тайно","vi":"bí mật","fa":"مخفیانه","examples":[{"de":"Sie haben heimlich geheiratet, ohne es jemandem zu sagen.","en":"They got married secretly without telling anyone.","ru":"Они тайно поженились, никому не сказав.","vi":"Họ kết hôn bí mật mà không nói cho ai biết.","fa":"آنها پنهانی ازدواج کردند بدون اینکه به کسی بگویند."},{"de":"Er las heimlich das Tagebuch seiner Schwester.","en":"He secretly read his sister's diary.","ru":"Он тайком читал дневник своей сестры.","vi":"Anh bí mật đọc nhật ký của em gái mình.","fa":"او مخفیانه دفتر خاطرات خواهرش را خواند."}]},{"word":"das Heimweh","en":"homesickness","ru":"тоска по родине","vi":"nỗi nhớ nhà","fa":"دلتنگی","examples":[{"de":"Im ersten Semester im Ausland hatte sie oft Heimweh.","en":"In her first semester abroad she often felt homesick.","ru":"В первом семестре за границей она часто тосковала по родине.","vi":"Trong học kỳ đầu tiên ở nước ngoài, cô thường xuyên nhớ nhà.","fa":"در طول ترم اول تحصیل در خارج از کشور، او اغلب دلتنگ بود."},{"de":"Nach zwei Wochen bekam er starkes Heimweh.","en":"After two weeks he became very homesick.","ru":"Через две недели он сильно затосковал по дому.","vi":"Sau hai tuần, anh trở nên rất nhớ nhà.","fa":"بعد از دو هفته به شدت دلتنگ شد."}]},{"word":"heiraten","en":"to marry","ru":"жениться; выходить замуж","vi":"kết hôn","fa":"ازدواج کن","examples":[{"de":"Meine Schwester heiratet nächsten Sommer.","en":"My sister is getting married next summer.","ru":"Моя сестра выходит замуж следующим летом.","vi":"Em gái tôi sẽ kết hôn vào mùa hè tới.","fa":"خواهرم تابستان آینده ازدواج می کند."},{"de":"Sie haben sich in einer kleinen Kirche geheiratet.","en":"They got married in a small church.","ru":"Они поженились в маленькой церкви.","vi":"Họ kết hôn trong một nhà thờ nhỏ.","fa":"آنها در یک کلیسای کوچک ازدواج کردند."}]},{"word":"heiß","en":"hot","ru":"горячий, жаркий","vi":"nóng bức","fa":"داغ","examples":[{"de":"Vorsicht, der Kaffee ist noch sehr heiß!","en":"Careful, the coffee is still very hot!","ru":"Осторожно, кофе ещё очень горячий!","vi":"Hãy cẩn thận, cà phê vẫn còn rất nóng!","fa":"مراقب باشید، قهوه هنوز خیلی داغ است!"},{"de":"Im August ist es in Spanien sehr heiß.","en":"In August it's very hot in Spain.","ru":"В августе в Испании очень жарко.","vi":"Trời rất nóng ở Tây Ban Nha vào tháng 8.","fa":"در ماه اوت در اسپانیا بسیار گرم است."}]},{"word":"heißen","en":"to be called, named","ru":"зваться, называться","vi":"được gọi là","fa":"تماس گرفت","examples":[{"de":"Wie heißt du?","en":"What's your name?","ru":"Как тебя зовут?","vi":"Tên bạn là gì?","fa":"اسمت چیه؟"},{"de":"Die Straße heißt \"Bahnhofstraße\".","en":"The street is called \"Bahnhofstraße\".","ru":"Улица называется «Банхофштрассе».","vi":"Con phố được gọi là “Bahnhofstraße”.","fa":"این خیابان \"Bahnhofstraße\" نام دارد."}]},{"word":"heizen","en":"to heat","ru":"отапливать","vi":"nhiệt","fa":"گرما","examples":[{"de":"Im Winter heizen wir die Wohnung mit Gas.","en":"In winter we heat the apartment with gas.","ru":"Зимой мы отапливаем квартиру газом.","vi":"Vào mùa đông, chúng tôi sưởi ấm căn hộ bằng gas.","fa":"در زمستان آپارتمان را با گاز گرم می کنیم."},{"de":"Man sollte im Herbst nicht schon zu früh heizen.","en":"You shouldn't start heating too early in autumn.","ru":"Осенью не стоит начинать отопление слишком рано.","vi":"Bạn không nên sưởi ấm quá sớm vào mùa thu.","fa":"در پاییز نباید خیلی زود گرم کنید."}]},{"word":"der Held","en":"hero","ru":"герой","vi":"anh hùng","fa":"قهرمان","examples":[{"de":"Der Feuerwehrmann wurde als Held gefeiert.","en":"The firefighter was celebrated as a hero.","ru":"Пожарного чествовали как героя.","vi":"Người lính cứu hỏa được tôn vinh như một anh hùng.","fa":"از آتش نشان به عنوان یک قهرمان تجلیل شد."},{"de":"In dem Film ist der Held ein einfacher Fischer.","en":"In the movie, the hero is a simple fisherman.","ru":"В фильме герой — простой рыбак.","vi":"Trong phim, anh hùng là một ngư dân giản dị.","fa":"در فیلم، قهرمان یک ماهیگیر ساده است."}]},{"word":"helfen","en":"to help","ru":"помогать","vi":"giúp đỡ","fa":"کمک کند","examples":[{"de":"Kannst du mir bitte beim Umzug helfen?","en":"Can you help me with the move, please?","ru":"Можешь помочь мне с переездом?","vi":"Bạn có thể vui lòng giúp tôi di chuyển được không?","fa":"میشه لطفا کمکم کنید حرکت کنم؟"},{"de":"Die Nachbarin hilft der alten Frau beim Einkaufen.","en":"The neighbor helps the old woman with shopping.","ru":"Соседка помогает пожилой женщине с покупками.","vi":"Người hàng xóm giúp bà già đi mua sắm.","fa":"همسایه در خرید به پیرزن کمک می کند."}]},{"word":"hell","en":"bright; light","ru":"светлый","vi":"tươi sáng","fa":"روشن","examples":[{"de":"Das Wohnzimmer ist sehr hell, weil es große Fenster hat.","en":"The living room is very bright because it has large windows.","ru":"Гостиная очень светлая, потому что там большие окна.","vi":"Phòng khách rất sáng sủa vì có cửa sổ lớn.","fa":"اتاق نشیمن به دلیل داشتن پنجره های بزرگ بسیار روشن است."},{"de":"Sie trägt gern helle Farben im Sommer.","en":"She likes to wear light colors in summer.","ru":"Летом она любит носить светлые цвета.","vi":"Cô ấy thích mặc màu sắc tươi sáng vào mùa hè.","fa":"او دوست دارد در تابستان رنگ های روشن بپوشد."}]},{"word":"das Hemd","en":"shirt","ru":"рубашка","vi":"chiếc áo sơ mi","fa":"پیراهن","examples":[{"de":"Er trägt zur Arbeit immer ein weißes Hemd.","en":"He always wears a white shirt to work.","ru":"На работу он всегда носит белую рубашку.","vi":"Anh ấy luôn mặc áo sơ mi trắng đi làm.","fa":"او همیشه یک پیراهن سفید به سر کار می پوشد."},{"de":"Das Hemd muss noch gebügelt werden.","en":"The shirt still needs to be ironed.","ru":"Рубашку ещё нужно погладить.","vi":"Chiếc áo vẫn cần được ủi.","fa":"پیراهن هنوز باید اتو شود."}]},{"word":"das Hend(e)l","en":"chicken (as food, Austrian/Bavarian term)","ru":"курица (австр./баварск.)","vi":"con gà","fa":"مرغ","examples":[{"de":"In Österreich isst man gern ein knuspriges Hendl.","en":"In Austria people like to eat a crispy chicken.","ru":"В Австрии любят есть хрустящую курицу.","vi":"Ở Áo người ta thích ăn gà giòn.","fa":"در اتریش مردم دوست دارند مرغ ترد بخورند."},{"de":"Zum Mittagessen bestellen wir ein halbes Hendl mit Pommes.","en":"For lunch we order half a chicken with fries.","ru":"На обед мы заказываем половину курицы с картошкой фри.","vi":"Bữa trưa chúng tôi gọi nửa con gà với khoai tây chiên.","fa":"برای ناهار نصف مرغ با سیب زمینی سرخ شده سفارش می دهیم."}]},{"word":"her","en":"here, toward the speaker (indicates movement)","ru":"сюда","vi":"ở đây","fa":"اینجا","examples":[{"de":"Komm mal her, ich zeige dir etwas!","en":"Come here, I'll show you something!","ru":"Иди сюда, я тебе кое-что покажу!","vi":"Hãy đến đây, tôi sẽ cho bạn thấy một cái gì đó!","fa":"بیا اینجا، یه چیزی بهت نشون میدم!"},{"de":"Woher kommst du?","en":"Where do you come from?","ru":"Откуда ты?","vi":"Bạn đến từ đâu?","fa":"شما از کجا می آیید؟"}]},{"word":"herausfinden","en":"to find out","ru":"выяснять, узнавать","vi":"tìm hiểu","fa":"پیدا کردن","examples":[{"de":"Wir müssen herausfinden, wer die Tür offen gelassen hat.","en":"We need to find out who left the door open.","ru":"Нам нужно выяснить, кто оставил дверь открытой.","vi":"Chúng ta phải tìm ra ai đã để cửa mở.","fa":"باید بفهمیم چه کسی در را باز گذاشته است."},{"de":"Sie hat endlich die Wahrheit herausgefunden.","en":"She finally found out the truth.","ru":"Она наконец узнала правду.","vi":"Cuối cùng cô đã tìm ra sự thật.","fa":"او بالاخره به حقیقت پی برد."}]},{"word":"die Herausforderung","en":"challenge","ru":"вызов, трудная задача","vi":"thử thách","fa":"چالش","examples":[{"de":"Die neue Stelle ist eine große Herausforderung für mich.","en":"The new job is a big challenge for me.","ru":"Новая должность — это большой вызов для меня.","vi":"Vị trí mới là một thách thức lớn đối với tôi.","fa":"موقعیت جدید برای من چالش بزرگی است."},{"de":"Er liebt es, sich neuen Herausforderungen zu stellen.","en":"He loves facing new challenges.","ru":"Он любит принимать новые вызовы.","vi":"Anh ấy thích tham gia những thử thách mới.","fa":"او عاشق چالش های جدید است."}]},{"word":"der Herd","en":"stove; cooker","ru":"плита","vi":"cái bếp","fa":"اجاق گاز","examples":[{"de":"Der Topf steht auf dem Herd.","en":"The pot is on the stove.","ru":"Кастрюля стоит на плите.","vi":"Cái nồi đang ở trên bếp.","fa":"قابلمه روی اجاق است."},{"de":"Vergiss nicht, den Herd auszuschalten!","en":"Don't forget to turn off the stove!","ru":"Не забудь выключить плиту!","vi":"Đừng quên tắt bếp nhé!","fa":"فراموش نکنید که اجاق گاز را خاموش کنید!"}]},{"word":"herein-","en":"prefix meaning \"in(to)\" toward the speaker (e.g. \"hereinkommen\" = to come in)","ru":"приставка со значением «внутрь» (в сторону говорящего), напр. hereinkommen — входить","vi":"trong-","fa":"در-","examples":[{"de":"Bitte komm herein, die Tür ist offen.","en":"Please come in, the door is open.","ru":"Пожалуйста, входи, дверь открыта.","vi":"Mời vào, cửa đang mở.","fa":"لطفا بیا داخل، در باز است."},{"de":"Er bat den Gast, hereinzukommen.","en":"He asked the guest to come in.","ru":"Он попросил гостя войти.","vi":"Anh ta mời khách vào.","fa":"از مهمان خواست داخل شود."}]},{"word":"die Herkunft","en":"origin","ru":"происхождение","vi":"nguồn gốc","fa":"منشاء","examples":[{"de":"Seine Herkunft ist ihm sehr wichtig.","en":"His origin is very important to him.","ru":"Его происхождение очень важно для него.","vi":"Nguồn gốc của anh ấy rất quan trọng đối với anh ấy.","fa":"منشأ او برای او بسیار مهم است."},{"de":"Woher ihre Familie stammt, also ihre Herkunft, ist unbekannt.","en":"Where her family comes from, i.e. her origin, is unknown.","ru":"Откуда родом её семья, то есть её происхождение, неизвестно.","vi":"Gia đình cô ấy đến từ đâu, tức là nguồn gốc của cô ấy, vẫn chưa được biết.","fa":"خانواده او از کجا می آیند، یعنی منشأ او، مشخص نیست."}]},{"word":"der Herr","en":"Mr.; gentleman","ru":"господин, мужчина","vi":"Chúa","fa":"خداوند","examples":[{"de":"Guten Tag, Herr Müller!","en":"Good day, Mr. Müller!","ru":"Добрый день, господин Мюллер!","vi":"Chào buổi chiều, ông Müller!","fa":"ظهر بخیر آقای مولر!"},{"de":"Ein älterer Herr hat mir den Weg gezeigt.","en":"An elderly gentleman showed me the way.","ru":"Пожилой мужчина показал мне дорогу.","vi":"Một người đàn ông lớn tuổi đã chỉ đường cho tôi.","fa":"یک آقای بزرگتر راه را به من نشان داد."}]},{"word":"herstellen","en":"to produce; to manufacture","ru":"производить, изготавливать","vi":"sản xuất","fa":"تولید کنند","examples":[{"de":"Die Firma stellt Möbel aus Holz her.","en":"The company manufactures furniture from wood.","ru":"Компания производит мебель из дерева.","vi":"Công ty sản xuất đồ nội thất từ gỗ.","fa":"این شرکت مبلمان را از چوب می سازد."},{"de":"Diese Autos werden in Deutschland hergestellt.","en":"These cars are manufactured in Germany.","ru":"Эти автомобили производятся в Германии.","vi":"Những chiếc xe này được sản xuất tại Đức.","fa":"این خودروها ساخت آلمان هستند."}]},{"word":"die Herstellung","en":"production; manufacturing","ru":"изготовление; производство","vi":"sản xuất","fa":"تولید","examples":[{"de":"Die Herstellung eines Autos dauert viele Stunden.","en":"The production of a car takes many hours.","ru":"Изготовление автомобиля занимает много часов.","vi":"Làm một chiếc ô tô mất nhiều giờ.","fa":"ساخت خودرو ساعت ها طول می کشد."},{"de":"Bei der Herstellung wird auf Qualität geachtet.","en":"Quality is prioritised during production.","ru":"При производстве уделяют внимание качеству.","vi":"Chất lượng được tính đến trong quá trình sản xuất.","fa":"کیفیت در هنگام تولید در نظر گرفته می شود."}]},{"word":"herunter","en":"down (from up there, toward the speaker)","ru":"вниз (сюда)","vi":"xuống","fa":"پایین","examples":[{"de":"Der Ball rollte die Treppe herunter.","en":"The ball rolled down the stairs.","ru":"Мяч скатился по лестнице вниз.","vi":"Quả bóng lăn xuống cầu thang.","fa":"توپ از پله ها پایین آمد."},{"de":"Von hier oben kann man auf die ganze Stadt herunterschauen.","en":"From up here you can look down over the whole city.","ru":"Отсюда сверху можно смотреть вниз на весь город.","vi":"Từ trên đây có thể nhìn xuống toàn bộ thành phố.","fa":"از این بالا می توانید کل شهر را از بالا نگاه کنید."}]},{"word":"herunter-","en":"prefix meaning \"down\" toward the speaker (e.g. \"herunterkommen\" = to come down)","ru":"приставка со значением «вниз» (в сторону говорящего), напр. herunterkommen — спускаться","vi":"xuống-","fa":"پایین -","examples":[{"de":"Komm bitte herunter, das Essen ist fertig!","en":"Please come down, the food is ready!","ru":"Спустись, пожалуйста, еда готова!","vi":"Mời anh xuống, đồ ăn đã sẵn sàng rồi!","fa":"لطفا بیا پایین، غذا آماده است!"},{"de":"Die Katze wollte nicht vom Baum herunterkommen.","en":"The cat didn't want to come down from the tree.","ru":"Кошка не хотела слезать с дерева.","vi":"Con mèo không muốn rời khỏi cây.","fa":"گربه نمی خواست از درخت پایین بیاید."}]},{"word":"herunterfahren","en":"to shut down (a computer); to drive down","ru":"выключать (компьютер); спускаться (на машине)","vi":"tắt","fa":"تعطیل کردن","examples":[{"de":"Bitte fahre den Computer herunter, bevor du gehst.","en":"Please shut down the computer before you leave.","ru":"Пожалуйста, выключи компьютер, прежде чем уйти.","vi":"Hãy tắt máy tính trước khi rời đi.","fa":"لطفا قبل از خروج کامپیوتر را خاموش کنید."},{"de":"Wir sind langsam den steilen Berg heruntergefahren.","en":"We slowly drove down the steep mountain.","ru":"Мы медленно спустились с крутой горы на машине.","vi":"Chúng tôi từ từ đi xuống ngọn núi dốc.","fa":"آرام آرام از کوه شیب دار پایین آمدیم."}]},{"word":"das Herz","en":"heart","ru":"сердце","vi":"trái tim","fa":"قلب","examples":[{"de":"Ihr Herz schlägt vor Aufregung sehr schnell.","en":"Her heart is beating very fast from excitement.","ru":"Её сердце бьётся очень быстро от волнения.","vi":"Tim cô đập rất nhanh vì phấn khích.","fa":"قلبش از هیجان خیلی تند می زند."},{"de":"Er hat ein gutes Herz und hilft gern anderen.","en":"He has a good heart and likes to help others.","ru":"У него доброе сердце, и он любит помогать другим.","vi":"Anh ấy có trái tim nhân hậu và thích giúp đỡ người khác.","fa":"او قلب خوبی دارد و دوست دارد به دیگران کمک کند."}]},{"word":"herzlich","en":"warm, cordial","ru":"сердечный","vi":"nồng nhiệt","fa":"به گرمی","examples":[{"de":"Wir wurden von der Familie sehr herzlich empfangen.","en":"We were welcomed very warmly by the family.","ru":"Семья приняла нас очень сердечно.","vi":"Chúng tôi đã nhận được sự chào đón rất nồng nhiệt từ gia đình.","fa":"ما با استقبال بسیار گرم خانواده مواجه شدیم."},{"de":"Herzlichen Glückwunsch zum Geburtstag!","en":"Warm congratulations on your birthday!","ru":"Сердечно поздравляю с днём рождения!","vi":"Chúc mừng sinh nhật!","fa":"تولدت مبارک!"}]},{"word":"heute","en":"today","ru":"сегодня","vi":"hôm nay","fa":"امروز","examples":[{"de":"Heute scheint endlich wieder die Sonne.","en":"Today the sun is finally shining again.","ru":"Сегодня наконец снова светит солнце.","vi":"Hôm nay mặt trời cuối cùng cũng chiếu sáng trở lại.","fa":"امروز بالاخره خورشید دوباره می درخشد."},{"de":"Ich habe heute keine Zeit für ein Treffen.","en":"I don't have time for a meeting today.","ru":"У меня сегодня нет времени на встречу.","vi":"Hôm nay tôi không có thời gian cho cuộc họp.","fa":"امروز وقت جلسه ندارم"}]},{"word":"hier","en":"here","ru":"здесь","vi":"ở đây","fa":"اینجا","examples":[{"de":"Bitte warte hier auf mich.","en":"Please wait here for me.","ru":"Пожалуйста, подожди меня здесь.","vi":"Xin hãy đợi tôi ở đây.","fa":"لطفا اینجا منتظرم باش"},{"de":"Hier ist es viel ruhiger als in der Stadt.","en":"It's much quieter here than in the city.","ru":"Здесь гораздо тише, чем в городе.","vi":"Ở đây yên tĩnh hơn nhiều so với trong thành phố.","fa":"اینجا خلوت تر از شهر است."}]},{"word":"hierher","en":"(to) here","ru":"сюда","vi":"ở đây","fa":"اینجا","examples":[{"de":"Komm bitte hierher, ich brauche deine Hilfe.","en":"Please come here, I need your help.","ru":"Иди сюда, пожалуйста, мне нужна твоя помощь.","vi":"Hãy đến đây, tôi cần sự giúp đỡ của bạn.","fa":"لطفا بیا اینجا، من به کمک شما نیاز دارم."},{"de":"Wie bist du hierher gekommen?","en":"How did you get here?","ru":"Как ты сюда попал?","vi":"Làm thế nào bạn đến được đây?","fa":"چگونه به اینجا رسیدید؟"}]},{"word":"die Hilfe","en":"help; aid","ru":"помощь","vi":"sự giúp đỡ","fa":"کمک","examples":[{"de":"Vielen Dank für deine Hilfe!","en":"Thank you very much for your help!","ru":"Большое спасибо за твою помощь!","vi":"Cảm ơn sự giúp đỡ của bạn!","fa":"با تشکر از شما برای کمک شما!"},{"de":"Ohne fremde Hilfe hätte ich das nicht geschafft.","en":"I wouldn't have managed it without outside help.","ru":"Без посторонней помощи я бы с этим не справился.","vi":"Tôi sẽ không thể làm được điều này nếu không có sự trợ giúp từ bên ngoài.","fa":"بدون کمک خارجی نمی توانستم این کار را انجام دهم."}]},{"word":"der Himmel","en":"sky; heaven","ru":"небо","vi":"bầu trời","fa":"آسمان","examples":[{"de":"Der Himmel ist heute wolkenlos blau.","en":"The sky is cloudless blue today.","ru":"Сегодня небо безоблачно-голубое.","vi":"Bầu trời hôm nay trong xanh không một gợn mây.","fa":"آسمان امروز آبی بدون ابر است."},{"de":"Abends sieht man am Himmel viele Sterne.","en":"In the evening you can see many stars in the sky.","ru":"Вечером на небе видно много звёзд.","vi":"Vào buổi tối bạn có thể nhìn thấy nhiều ngôi sao trên bầu trời.","fa":"در شب می توانید ستاره های زیادی را در آسمان ببینید."}]},{"word":"hingegen","en":"however; on the other hand","ru":"напротив; зато","vi":"tuy nhiên","fa":"با این حال","examples":[{"de":"Mein Bruder mag Kaffee, ich hingegen trinke lieber Tee.","en":"My brother likes coffee; I, on the other hand, prefer tea.","ru":"Мой брат любит кофе, я же предпочитаю чай.","vi":"Anh trai tôi thích cà phê nhưng tôi thích trà hơn.","fa":"برادر من قهوه دوست دارد، اما من چای را ترجیح می دهم."},{"de":"Der Sommer war heiß, der Winter hingegen sehr mild.","en":"The summer was hot; the winter, however, was very mild.","ru":"Лето было жарким, зима же — очень мягкой.","vi":"Mùa hè rất nóng nhưng mùa đông lại rất ôn hòa.","fa":"تابستان گرم بود، اما زمستان بسیار معتدل بود."}]},{"word":"hinten","en":"at the back; behind","ru":"сзади","vi":"đằng sau","fa":"پشت سر","examples":[{"de":"Die Kinder sitzen hinten im Auto.","en":"The children sit in the back of the car.","ru":"Дети сидят сзади в машине.","vi":"Bọn trẻ ngồi ở phía sau xe.","fa":"بچه ها پشت ماشین می نشینند."},{"de":"Der Ausgang befindet sich ganz hinten im Gebäude.","en":"The exit is at the very back of the building.","ru":"Выход находится в самом конце здания.","vi":"Lối ra nằm ở phía sau tòa nhà.","fa":"خروجی در پشت ساختمان است."}]},{"word":"hinter/hinter-","en":"behind","ru":"за, позади","vi":"đằng sau/phía sau-","fa":"پشت / پشت -","examples":[{"de":"Das Auto steht hinter dem Haus.","en":"The car is parked behind the house.","ru":"Машина стоит за домом.","vi":"Ôtô đỗ sau nhà.","fa":"ماشین پشت خانه است."},{"de":"Er versteckte sich hinter dem Baum.","en":"He hid behind the tree.","ru":"Он спрятался за деревом.","vi":"Anh ta trốn đằng sau cái cây.","fa":"پشت درخت پنهان شد."}]},{"word":"hinterher","en":"afterward; behind, following","ru":"после этого, вслед","vi":"sau đó","fa":"پس از آن","examples":[{"de":"Er lief dem Bus hinterher, aber er war schon weg.","en":"He ran after the bus, but it was already gone.","ru":"Он побежал вслед за автобусом, но тот уже уехал.","vi":"Anh chạy theo chiếc xe buýt nhưng nó đã chạy mất rồi.","fa":"او به دنبال اتوبوس دوید، اما اتوبوس رفته بود."},{"de":"Wir gingen ins Kino und hinterher noch essen.","en":"We went to the cinema and afterward out to eat.","ru":"Мы пошли в кино, а после этого ещё поели.","vi":"Chúng tôi đi xem phim và ăn tối sau đó.","fa":"رفتیم سینما و بعدش شام خوردیم."}]},{"word":"hinterlassen","en":"to leave behind","ru":"оставлять (после себя)","vi":"bỏ lại phía sau","fa":"پشت سر گذاشتن","examples":[{"de":"Der Dieb hat keine Spuren hinterlassen.","en":"The thief left no traces behind.","ru":"Вор не оставил никаких следов.","vi":"Tên trộm không để lại dấu vết.","fa":"دزد اثری از خود برجای نگذاشت."},{"de":"Sie hat mir eine Nachricht auf dem Anrufbeantworter hinterlassen.","en":"She left me a message on the answering machine.","ru":"Она оставила мне сообщение на автоответчике.","vi":"Cô ấy để lại cho tôi một tin nhắn trên máy trả lời tự động.","fa":"روی منشی تلفنی برای من پیام گذاشت."}]},{"word":"hinweisen","en":"to point out","ru":"указывать (на что-либо)","vi":"chỉ ra","fa":"اشاره کند","examples":[{"de":"Der Lehrer weist die Schüler auf ihre Fehler hin.","en":"The teacher points out their mistakes to the students.","ru":"Учитель указывает ученикам на их ошибки.","vi":"Giáo viên chỉ ra những lỗi sai của học sinh.","fa":"معلم به اشتباهات دانش آموزان اشاره می کند."},{"de":"Ich möchte darauf hinweisen, dass die Frist morgen endet.","en":"I would like to point out that the deadline ends tomorrow.","ru":"Хочу указать на то, что срок истекает завтра.","vi":"Tôi muốn chỉ ra rằng thời hạn sẽ kết thúc vào ngày mai.","fa":"لازم به ذکر است که این مهلت فردا به پایان می رسد."}]},{"word":"historisch","en":"historical","ru":"исторический","vi":"lịch sử","fa":"تاریخی","examples":[{"de":"Die Altstadt ist ein historisches Zentrum der Stadt.","en":"The old town is a historical center of the city.","ru":"Старый город — исторический центр города.","vi":"Phố cổ là một trung tâm lịch sử của thành phố.","fa":"شهر قدیمی مرکز تاریخی شهر است."},{"de":"Das Museum zeigt historische Dokumente aus dem 19. Jahrhundert.","en":"The museum shows historical documents from the 19th century.","ru":"Музей демонстрирует исторические документы XIX века.","vi":"Bảo tàng trưng bày các tài liệu lịch sử từ thế kỷ 19.","fa":"در این موزه اسناد تاریخی مربوط به قرن نوزدهم به نمایش گذاشته شده است."}]},{"word":"die Hitze","en":"heat","ru":"жара","vi":"cái nóng","fa":"گرما","examples":[{"de":"Bei dieser Hitze kann man kaum draußen arbeiten.","en":"In this heat you can hardly work outside.","ru":"В такую жару почти невозможно работать на улице.","vi":"Hầu như không thể làm việc ngoài trời trong thời tiết nắng nóng này.","fa":"در این گرما کار کردن در بیرون تقریبا غیرممکن است."},{"de":"Die Hitze im Sommer war dieses Jahr besonders stark.","en":"The heat in summer was especially strong this year.","ru":"Летняя жара в этом году была особенно сильной.","vi":"Cái nóng vào mùa hè năm nay đặc biệt gay gắt.","fa":"گرمای تابستان امسال به ویژه شدید بود."}]},{"word":"das Hobby","en":"hobby","ru":"хобби","vi":"sở thích","fa":"سرگرمی","examples":[{"de":"Mein liebstes Hobby ist Fotografieren.","en":"My favorite hobby is photography.","ru":"Моё любимое хобби — фотография.","vi":"Sở thích yêu thích của tôi là chụp ảnh.","fa":"سرگرمی مورد علاقه من عکاسی است."},{"de":"Welche Hobbys hast du in deiner Freizeit?","en":"What hobbies do you have in your free time?","ru":"Какие у тебя хобби в свободное время?","vi":"Bạn có sở thích gì trong thời gian rảnh?","fa":"در اوقات فراغت چه سرگرمی هایی دارید؟"}]},{"word":"hoch","en":"high","ru":"высокий","vi":"cao","fa":"بالا","examples":[{"de":"Der Berg ist über zweitausend Meter hoch.","en":"The mountain is over two thousand meters high.","ru":"Гора высотой более двух тысяч метров.","vi":"Ngọn núi cao hơn hai nghìn mét.","fa":"ارتفاع این کوه بیش از دو هزار متر است."},{"de":"Die Mieten in der Stadt sind sehr hoch.","en":"The rents in the city are very high.","ru":"Арендная плата в городе очень высокая.","vi":"Giá thuê trong thành phố rất cao.","fa":"اجاره در شهر بسیار بالاست."}]},{"word":"hochladen","en":"to upload","ru":"загружать (в интернет)","vi":"tải lên","fa":"آپلود کنید","examples":[{"de":"Ich muss die Fotos noch auf die Webseite hochladen.","en":"I still need to upload the photos to the website.","ru":"Мне ещё нужно загрузить фотографии на сайт.","vi":"Tôi vẫn phải tải ảnh lên trang web.","fa":"من هنوز باید عکس ها را در سایت آپلود کنم."},{"de":"Er hat das Video gestern auf YouTube hochgeladen.","en":"He uploaded the video to YouTube yesterday.","ru":"Вчера он загрузил видео на YouTube.","vi":"Anh ấy đã tải video lên YouTube ngày hôm qua.","fa":"او دیروز این ویدئو را در یوتیوب آپلود کرد."}]},{"word":"höchstens","en":"at most","ru":"самое большее, максимум","vi":"nhiều nhất","fa":"حداکثر","examples":[{"de":"Die Fahrt dauert höchstens eine Stunde.","en":"The trip takes at most one hour.","ru":"Поездка занимает максимум один час.","vi":"Cuộc hành trình mất tối đa một giờ.","fa":"سفر حداکثر یک ساعت طول می کشد."},{"de":"Ich kann höchstens zwei Tage bleiben.","en":"I can stay for at most two days.","ru":"Я могу остаться самое большее на два дня.","vi":"Tôi chỉ có thể ở lại nhiều nhất là hai ngày.","fa":"حداکثر دو روز میتونم بمونم"}]},{"word":"die Hochzeit","en":"wedding","ru":"свадьба","vi":"đám cưới","fa":"عروسی","examples":[{"de":"Meine Schwester heiratet im Sommer, die Hochzeit findet im Garten statt.","en":"My sister is getting married in summer, the wedding takes place in the garden.","ru":"Моя сестра выходит замуж летом, свадьба состоится в саду.","vi":"Chị tôi sắp kết hôn vào mùa hè, đám cưới sẽ diễn ra ngoài vườn.","fa":"خواهرم در تابستان عروسی می کند، عروسی در باغ برگزار می شود."},{"de":"Wir waren letztes Wochenende auf einer Hochzeit eingeladen.","en":"We were invited to a wedding last weekend.","ru":"На прошлых выходных нас пригласили на свадьбу.","vi":"Chúng tôi được mời đến dự một đám cưới vào cuối tuần trước.","fa":"آخر هفته پیش به عروسی دعوت شدیم."}]},{"word":"der Hof","en":"courtyard; farm","ru":"двор; ферма","vi":"sân","fa":"حیاط","examples":[{"de":"Die Kinder spielen im Hof des Hauses.","en":"The children are playing in the courtyard of the house.","ru":"Дети играют во дворе дома.","vi":"Bọn trẻ chơi đùa trong sân nhà.","fa":"بچه ها در حیاط خانه بازی می کنند."},{"de":"Meine Großeltern haben einen Hof mit vielen Tieren.","en":"My grandparents have a farm with many animals.","ru":"У моих бабушки и дедушки ферма со множеством животных.","vi":"Ông bà tôi có một trang trại với rất nhiều động vật.","fa":"پدربزرگ و مادربزرگ من مزرعه ای با حیوانات زیادی دارند."}]},{"word":"hoffen","en":"to hope","ru":"надеяться","vi":"hy vọng","fa":"امید","examples":[{"de":"Ich hoffe, dass das Wetter morgen besser wird.","en":"I hope the weather will be better tomorrow.","ru":"Я надеюсь, что завтра погода будет лучше.","vi":"Tôi hy vọng ngày mai thời tiết sẽ tốt hơn.","fa":"امیدوارم فردا هوا بهتر بشه"},{"de":"Wir hoffen auf ein gutes Ergebnis.","en":"We are hoping for a good result.","ru":"Мы надеемся на хороший результат.","vi":"Chúng tôi hy vọng cho một kết quả tốt.","fa":"امیدواریم نتیجه خوبی بگیریم."}]},{"word":"höflich","en":"polite","ru":"вежливый","vi":"lịch sự","fa":"مودب","examples":[{"de":"Der Kellner war sehr höflich zu uns.","en":"The waiter was very polite to us.","ru":"Официант был очень вежлив с нами.","vi":"Người phục vụ rất lịch sự với chúng tôi.","fa":"گارسون با ما خیلی مودب بود."},{"de":"Man sollte immer höflich grüßen.","en":"One should always greet politely.","ru":"Всегда нужно вежливо здороваться.","vi":"Bạn nên luôn chào hỏi một cách lịch sự.","fa":"همیشه باید مودبانه سلام کرد."}]},{"word":"die Höflichkeit","en":"politeness","ru":"вежливость","vi":"sự lịch sự","fa":"ادب","examples":[{"de":"Aus Höflichkeit hat er das Geschenk angenommen.","en":"Out of politeness he accepted the gift.","ru":"Из вежливости он принял подарок.","vi":"Anh ấy nhận món quà một cách lịch sự.","fa":"او از روی ادب این هدیه را پذیرفت."},{"de":"Höflichkeit kostet nichts und öffnet viele Türen.","en":"Politeness costs nothing and opens many doors.","ru":"Вежливость ничего не стоит и открывает многие двери.","vi":"Sự lịch sự không tốn kém gì và mở ra nhiều cánh cửa.","fa":"ادب هیچ هزینه ای ندارد و درهای زیادی را باز می کند."}]},{"word":"die Höhe","en":"height","ru":"высота","vi":"chiều cao","fa":"ارتفاع","examples":[{"de":"Das Flugzeug fliegt in einer Höhe von zehntausend Metern.","en":"The plane is flying at a height of ten thousand meters.","ru":"Самолёт летит на высоте десяти тысяч метров.","vi":"Máy bay bay ở độ cao mười nghìn mét.","fa":"این هواپیما در ارتفاع ده هزار متری پرواز می کند."},{"de":"Die Höhe des Turms beträgt fünfzig Meter.","en":"The height of the tower is fifty meters.","ru":"Высота башни составляет пятьдесят метров.","vi":"Chiều cao của tháp là năm mươi mét.","fa":"ارتفاع برج پنجاه متر است."}]},{"word":"holen","en":"to fetch, to get","ru":"принести, забрать","vi":"nhận được","fa":"دریافت کنید","examples":[{"de":"Kannst du bitte Brot vom Bäcker holen?","en":"Can you please get bread from the bakery?","ru":"Можешь, пожалуйста, принести хлеб из пекарни?","vi":"Bạn có thể vui lòng lấy bánh mì từ tiệm bánh được không?","fa":"میشه لطفا از نانوایی نان تهیه کنید؟"},{"de":"Er holt seine Tochter von der Schule.","en":"He picks up his daughter from school.","ru":"Он забирает свою дочь из школы.","vi":"Anh đón con gái từ trường.","fa":"دخترش را از مدرسه می گیرد."}]},{"word":"das Holz","en":"wood","ru":"дерево, древесина","vi":"gỗ","fa":"چوب","examples":[{"de":"Der Tisch ist aus Holz gemacht.","en":"The table is made of wood.","ru":"Стол сделан из дерева.","vi":"Chiếc bàn được làm bằng gỗ.","fa":"میز از چوب ساخته شده است."},{"de":"Im Winter sammeln wir Holz für den Ofen.","en":"In winter we collect wood for the stove.","ru":"Зимой мы собираем дрова для печи.","vi":"Vào mùa đông, chúng tôi thu thập củi để đốt lò.","fa":"در زمستان برای اجاق گاز چوب جمع می کنیم."}]},{"word":"der Honig","en":"honey","ru":"мёд","vi":"mật ong","fa":"عسل","examples":[{"de":"Ich esse morgens gern Honig auf dem Brot.","en":"In the morning I like to eat honey on bread.","ru":"По утрам я люблю есть мёд на хлебе.","vi":"Tôi thích ăn mật ong trên bánh mì vào buổi sáng.","fa":"من دوست دارم صبح روی نان عسل بخورم."},{"de":"Der Honig aus dieser Region schmeckt besonders gut.","en":"The honey from this region tastes especially good.","ru":"Мёд из этого региона особенно вкусный.","vi":"Mật ong từ vùng này có vị đặc biệt ngon.","fa":"عسل این منطقه طعم و مزه خاصی دارد."}]},{"word":"hören","en":"to hear, to listen","ru":"слышать, слушать","vi":"nghe thấy","fa":"بشنو","examples":[{"de":"Ich höre gern Musik, wenn ich lerne.","en":"I like listening to music while I study.","ru":"Я люблю слушать музыку, когда учусь.","vi":"Tôi thích nghe nhạc khi học.","fa":"وقتی درس می خوانم دوست دارم موسیقی گوش کنم."},{"de":"Hast du die Nachrichten gehört?","en":"Did you hear the news?","ru":"Ты слышал новости?","vi":"Bạn đã nghe tin tức chưa?","fa":"آیا خبر را شنیده اید؟"}]},{"word":"die Hose","en":"trousers, pants","ru":"брюки","vi":"cái quần","fa":"شلوار","examples":[{"de":"Die Hose ist mir zu eng geworden.","en":"The trousers have become too tight for me.","ru":"Брюки стали мне тесны.","vi":"Chiếc quần đã trở nên quá chật đối với tôi.","fa":"شلوارم خیلی تنگ شده."},{"de":"Er trägt heute eine blaue Hose.","en":"He is wearing blue trousers today.","ru":"Сегодня он в синих брюках.","vi":"Hôm nay anh ấy mặc quần xanh.","fa":"او امروز شلوار آبی پوشیده است."}]},{"word":"das Hotel","en":"hotel","ru":"гостиница","vi":"khách sạn","fa":"هتل","examples":[{"de":"Wir übernachten drei Nächte in einem kleinen Hotel.","en":"We are staying three nights in a small hotel.","ru":"Мы ночуем три ночи в небольшой гостинице.","vi":"Chúng tôi ở trong một khách sạn nhỏ trong ba đêm.","fa":"سه شب در هتل کوچکی می مانیم."},{"de":"Das Hotel liegt direkt am Meer.","en":"The hotel is located right by the sea.","ru":"Гостиница находится прямо у моря.","vi":"Khách sạn nằm ngay cạnh biển.","fa":"هتل مستقیماً در کنار دریا واقع شده است."}]},{"word":"hübsch","en":"pretty","ru":"хорошенький, симпатичный","vi":"xinh đẹp","fa":"زیبا","examples":[{"de":"Sie trägt ein hübsches Kleid.","en":"She is wearing a pretty dress.","ru":"На ней симпатичное платье.","vi":"Cô ấy đang mặc một chiếc váy đẹp.","fa":"او یک لباس زیبا پوشیده است."},{"de":"Das ist ein hübsches kleines Dorf.","en":"That is a pretty little village.","ru":"Это симпатичная маленькая деревня.","vi":"Đây là một ngôi làng nhỏ xinh.","fa":"این یک روستای کوچک زیبا است."}]},{"word":"der Hügel","en":"hill","ru":"холм","vi":"ngọn đồi","fa":"تپه","examples":[{"de":"Von diesem Hügel hat man einen tollen Blick auf die Stadt.","en":"From this hill you have a great view of the city.","ru":"С этого холма открывается прекрасный вид на город.","vi":"Từ ngọn đồi này bạn có một cái nhìn tuyệt vời về thành phố.","fa":"از این تپه منظره ای عالی از شهر دارید."},{"de":"Wir sind auf den Hügel gewandert.","en":"We hiked up the hill.","ru":"Мы поднялись пешком на холм.","vi":"Chúng tôi đi bộ lên đồi.","fa":"از تپه بالا رفتیم."}]},{"word":"der Humor","en":"humor","ru":"юмор","vi":"sự hài hước","fa":"طنز","examples":[{"de":"Er hat einen guten Sinn für Humor.","en":"He has a good sense of humor.","ru":"У него хорошее чувство юмора.","vi":"Anh ấy có khiếu hài hước.","fa":"او حس شوخ طبعی خوبی دارد."},{"de":"Ohne Humor wäre das Leben langweilig.","en":"Without humor life would be boring.","ru":"Без юмора жизнь была бы скучной.","vi":"Nếu không có sự hài hước, cuộc sống sẽ nhàm chán.","fa":"بدون طنز، زندگی خسته کننده خواهد بود."}]},{"word":"der Hunger","en":"hunger","ru":"голод","vi":"cơn đói","fa":"گرسنگی","examples":[{"de":"Ich habe großen Hunger, lass uns essen gehen.","en":"I'm very hungry, let's go eat.","ru":"Я очень голоден, пойдём поедим.","vi":"Tôi đói quá, chúng ta đi ăn thôi.","fa":"من خیلی گرسنه ام، بریم غذا بخوریم."},{"de":"In manchen Ländern leiden viele Menschen unter Hunger.","en":"In some countries many people suffer from hunger.","ru":"В некоторых странах многие люди страдают от голода.","vi":"Ở một số nước nhiều người bị đói.","fa":"در برخی کشورها بسیاری از مردم از گرسنگی رنج می برند."}]},{"word":"hupen","en":"to honk","ru":"сигналить (клаксоном)","vi":"bấm còi","fa":"بوق زدن","examples":[{"de":"Der Fahrer hupte, weil die Ampel schon grün war.","en":"The driver honked because the light was already green.","ru":"Водитель посигналил, потому что светофор уже был зелёным.","vi":"Người lái xe bấm còi vì đèn giao thông đã xanh.","fa":"راننده بوق زد چون چراغ راهنما از قبل سبز شده بود."},{"de":"Man darf in der Stadt nicht ohne Grund hupen.","en":"You are not allowed to honk in the city without reason.","ru":"В городе нельзя сигналить без причины.","vi":"Bạn không thể bấm còi trong thành phố mà không có lý do.","fa":"بدون دلیل نمی توان در شهر بوق زد."}]},{"word":"husten","en":"to cough","ru":"кашлять","vi":"ho","fa":"سرفه","examples":[{"de":"Er hustet schon seit einer Woche.","en":"He has been coughing for a week already.","ru":"Он кашляет уже неделю.","vi":"Anh ấy đã ho được một tuần rồi.","fa":"او یک هفته است که سرفه می کند."},{"de":"Bitte halte dir die Hand vor den Mund, wenn du hustest.","en":"Please cover your mouth with your hand when you cough.","ru":"Пожалуйста, прикрывай рот рукой, когда кашляешь.","vi":"Hãy đưa tay lên miệng khi ho.","fa":"لطفا هنگام سرفه دست خود را روی دهان خود بگذارید."}]},{"word":"der Hut","en":"hat","ru":"шляпа","vi":"cái mũ","fa":"کلاه","examples":[{"de":"Sie trägt im Sommer immer einen Hut.","en":"She always wears a hat in summer.","ru":"Летом она всегда носит шляпу.","vi":"Cô ấy luôn đội mũ vào mùa hè.","fa":"او همیشه در تابستان کلاه سر می گذارد."},{"de":"Der alte Mann nahm seinen Hut ab und grüßte.","en":"The old man took off his hat and greeted us.","ru":"Старик снял шляпу и поздоровался.","vi":"Ông già bỏ mũ ra chào.","fa":"پیرمرد کلاهش را برداشت و سلام کرد."}]},{"word":"die Hütte","en":"hut, cabin","ru":"хижина","vi":"túp lều","fa":"کلبه","examples":[{"de":"Wir haben die Nacht in einer Berghütte verbracht.","en":"We spent the night in a mountain cabin.","ru":"Мы провели ночь в горной хижине.","vi":"Chúng tôi qua đêm trong một túp lều trên núi.","fa":"شب را در یک کلبه کوهستانی گذراندیم."},{"de":"Die kleine Hütte im Wald gehört meinem Onkel.","en":"The small hut in the forest belongs to my uncle.","ru":"Маленькая хижина в лесу принадлежит моему дяде.","vi":"Căn nhà gỗ nhỏ trong rừng thuộc về chú tôi.","fa":"کلبه کوچک جنگل متعلق به عمویم است."}]},{"word":"ideal","en":"ideal","ru":"идеальный","vi":"lý tưởng","fa":"ایده آل","examples":[{"de":"Dieser Ort ist ideal für einen Urlaub.","en":"This place is ideal for a vacation.","ru":"Это место идеально подходит для отпуска.","vi":"Nơi này là lý tưởng cho một kỳ nghỉ.","fa":"این مکان برای تعطیلات ایده آل است."},{"de":"Es gibt keine ideale Lösung für dieses Problem.","en":"There is no ideal solution to this problem.","ru":"Идеального решения этой проблемы не существует.","vi":"Không có giải pháp lý tưởng cho vấn đề này.","fa":"هیچ راه حل ایده آلی برای این مشکل وجود ندارد."}]},{"word":"die Idee","en":"idea","ru":"идея","vi":"ý tưởng","fa":"ایده","examples":[{"de":"Das ist eine sehr gute Idee!","en":"That's a very good idea!","ru":"Это очень хорошая идея!","vi":"Đó là một ý tưởng rất tốt!","fa":"این ایده بسیار خوبی است!"},{"de":"Ich habe keine Idee, wie wir das Problem lösen sollen.","en":"I have no idea how we should solve this problem.","ru":"Я понятия не имею, как нам решить эту проблему.","vi":"Tôi không biết chúng ta nên giải quyết vấn đề như thế nào.","fa":"من نمی دانم چگونه باید مشکل را حل کنیم."}]},{"word":"illegal","en":"illegal","ru":"нелегальный, незаконный","vi":"bất hợp pháp","fa":"غیر قانونی","examples":[{"de":"Es ist illegal, ohne Ticket mit dem Zug zu fahren.","en":"It is illegal to travel by train without a ticket.","ru":"Ехать в поезде без билета незаконно.","vi":"Việc đi tàu mà không có vé là bất hợp pháp.","fa":"سوار شدن به قطار بدون بلیط غیرقانونی است."},{"de":"Der Verkäufer wurde wegen illegaler Geschäfte verhaftet.","en":"The seller was arrested for illegal business dealings.","ru":"Продавца арестовали за незаконные сделки.","vi":"Người bán đã bị bắt vì kinh doanh trái phép.","fa":"فروشنده به دلیل تجارت غیرقانونی دستگیر شد."}]},{"word":"der Imbiss","en":"snack bar","ru":"закусочная","vi":"bữa ăn nhẹ","fa":"میان وعده","examples":[{"de":"An der Ecke gibt es einen Imbiss mit leckeren Currywürsten.","en":"There's a snack bar on the corner with delicious currywurst.","ru":"На углу есть закусочная с вкусными карривурстами.","vi":"Có một quán ăn nhanh ở góc phố với món xúc xích cà ri thơm ngon.","fa":"یک اسنک بار در گوشه ای با سوسیس های کاری خوشمزه وجود دارد."},{"de":"Wir haben schnell etwas am Imbiss gegessen.","en":"We quickly ate something at the snack bar.","ru":"Мы быстро перекусили в закусочной.","vi":"Chúng tôi nhanh chóng ăn thứ gì đó ở quầy bán đồ ăn nhanh.","fa":"ما سریع چیزی در اسنک بار خوردیم."}]},{"word":"immer","en":"always","ru":"всегда","vi":"luôn luôn","fa":"همیشه","examples":[{"de":"Er kommt immer pünktlich zur Arbeit.","en":"He always comes to work on time.","ru":"Он всегда приходит на работу вовремя.","vi":"Anh ấy luôn đi làm đúng giờ.","fa":"او همیشه سر وقت سر کار می آید."},{"de":"Ich werde dich immer unterstützen.","en":"I will always support you.","ru":"Я всегда буду тебя поддерживать.","vi":"Tôi sẽ luôn ủng hộ bạn.","fa":"من همیشه از شما حمایت خواهم کرد."}]},{"word":"die Impfung","en":"vaccination","ru":"прививка; вакцинация","vi":"tiêm chủng","fa":"واکسیناسیون","examples":[{"de":"Die Impfung schützt vor einer schweren Erkrankung.","en":"The vaccination protects against a serious illness.","ru":"Прививка защищает от тяжёлого заболевания.","vi":"Việc chủng ngừa bảo vệ chống lại bệnh tật nghiêm trọng.","fa":"واکسیناسیون در برابر بیماری های جدی محافظت می کند."},{"de":"Für die Reise brauchst du eine bestimmte Impfung.","en":"For the trip you need a certain vaccination.","ru":"Для поездки тебе нужна определённая прививка.","vi":"Bạn cần tiêm phòng cụ thể cho chuyến đi.","fa":"برای سفر به واکسیناسیون خاصی نیاز دارید."}]},{"word":"der Import","en":"import","ru":"импорт","vi":"việc nhập khẩu","fa":"واردات","examples":[{"de":"Der Import von Obst aus Südamerika hat zugenommen.","en":"The import of fruit from South America has increased.","ru":"Импорт фруктов из Южной Америки увеличился.","vi":"Việc nhập khẩu trái cây từ Nam Mỹ đã tăng lên.","fa":"واردات میوه از آمریکای جنوبی افزایش یافته است."},{"de":"Diese Firma lebt hauptsächlich vom Import und Export von Waren.","en":"This company mainly lives from the import and export of goods.","ru":"Эта фирма живёт в основном за счёт импорта и экспорта товаров.","vi":"Công ty này chủ yếu sống nhờ xuất nhập khẩu hàng hóa.","fa":"این شرکت عمدتاً از واردات و صادرات کالا زندگی می کند."}]},{"word":"in","en":"in","ru":"в","vi":"trong","fa":"در","examples":[{"de":"Die Schlüssel liegen in der Tasche.","en":"The keys are in the bag.","ru":"Ключи лежат в сумке.","vi":"Chìa khóa ở trong túi.","fa":"کلیدها داخل کیف هستند."},{"de":"Wir treffen uns in einer Stunde.","en":"We'll meet in an hour.","ru":"Мы встретимся через час.","vi":"Chúng ta sẽ gặp nhau trong một giờ nữa.","fa":"یه ساعت دیگه همدیگه رو میبینیم"}]},{"word":"in Pension/Rente gehen (pensioniert werden)","en":"to retire","ru":"выходить на пенсию","vi":"nghỉ hưu/nghỉ hưu (được nghỉ hưu)","fa":"بازنشسته/بازنشسته (بازنشسته)","examples":[{"de":"Mein Vater geht nächstes Jahr in Pension.","en":"My father is retiring next year.","ru":"Мой отец выходит на пенсию в следующем году.","vi":"Bố tôi sẽ nghỉ hưu vào năm tới.","fa":"پدرم سال آینده بازنشسته می شود."},{"de":"Sie freut sich schon darauf, in Rente zu gehen.","en":"She is already looking forward to retiring.","ru":"Она уже радуется выходу на пенсию.","vi":"Cô ấy đang mong chờ được nghỉ hưu.","fa":"او مشتاقانه منتظر بازنشستگی است."}]},{"word":"indem","en":"by (doing something)","ru":"тем, что; посредством того, что","vi":"bởi","fa":"توسط","examples":[{"de":"Du kannst Geld sparen, indem du weniger einkaufst.","en":"You can save money by shopping less.","ru":"Ты можешь экономить деньги, покупая меньше.","vi":"Bạn có thể tiết kiệm tiền bằng cách mua sắm ít hơn.","fa":"با خرید کمتر می توانید در پول خود صرفه جویی کنید."},{"de":"Er verbesserte sein Deutsch, indem er jeden Tag las.","en":"He improved his German by reading every day.","ru":"Он улучшил свой немецкий, читая каждый день.","vi":"Anh ấy đã cải thiện tiếng Đức của mình bằng cách đọc sách mỗi ngày.","fa":"او با خواندن هر روز آلمانی خود را بهبود بخشید."}]},{"word":"individuell","en":"individual","ru":"индивидуальный","vi":"cá nhân","fa":"به صورت جداگانه","examples":[{"de":"Jeder Kunde bekommt eine individuelle Beratung.","en":"Every customer gets individual advice.","ru":"Каждый клиент получает индивидуальную консультацию.","vi":"Mỗi khách hàng đều nhận được lời khuyên riêng.","fa":"هر مشتری مشاوره فردی دریافت می کند."},{"de":"Das Hotelzimmer wurde individuell eingerichtet.","en":"The hotel room was individually furnished.","ru":"Гостиничный номер был обставлен индивидуально.","vi":"Phòng khách sạn được trang bị nội thất riêng.","fa":"اتاق هتل به صورت مجزا مبله شده بود."}]},{"word":"die Industrie","en":"industry","ru":"промышленность","vi":"ngành công nghiệp","fa":"صنعت","examples":[{"de":"Die Industrie in dieser Region wächst schnell.","en":"Industry in this region is growing fast.","ru":"Промышленность в этом регионе быстро растёт.","vi":"Ngành công nghiệp ở khu vực này đang phát triển nhanh chóng.","fa":"صنعت در این منطقه به سرعت در حال رشد است."},{"de":"Viele Menschen arbeiten in der Autoindustrie.","en":"Many people work in the automotive industry.","ru":"Многие люди работают в автомобильной промышленности.","vi":"Nhiều người làm việc trong ngành công nghiệp ô tô.","fa":"افراد زیادی در صنعت خودرو کار می کنند."}]},{"word":"die Infektion","en":"infection","ru":"инфекция","vi":"nhiễm trùng","fa":"عفونت","examples":[{"de":"Der Arzt hat eine Infektion in der Wunde festgestellt.","en":"The doctor found an infection in the wound.","ru":"Врач обнаружил инфекцию в ране.","vi":"Bác sĩ phát hiện vết thương bị nhiễm trùng.","fa":"دکتر متوجه عفونت در زخم شد."},{"de":"Ohne Behandlung kann sich die Infektion ausbreiten.","en":"Without treatment, the infection can spread.","ru":"Без лечения инфекция может распространиться.","vi":"Nếu không điều trị, nhiễm trùng có thể lây lan.","fa":"بدون درمان، عفونت می تواند گسترش یابد."}]},{"word":"informieren","en":"to inform","ru":"информировать","vi":"thông báo","fa":"اطلاع رسانی کند","examples":[{"de":"Bitte informieren Sie mich, sobald Sie Neuigkeiten haben.","en":"Please inform me as soon as you have news.","ru":"Пожалуйста, проинформируйте меня, как только у вас будут новости.","vi":"Xin vui lòng cho tôi biết ngay khi bạn có tin tức.","fa":"لطفا به محض اطلاع از این خبر به من اطلاع دهید."},{"de":"Wir haben uns vor der Reise gut über das Land informiert.","en":"We informed ourselves well about the country before the trip.","ru":"Перед поездкой мы хорошо изучили информацию о стране.","vi":"Chúng tôi đã thông báo rõ về đất nước này trước chuyến đi.","fa":"قبل از سفر به خوبی از کشور مطلع شدیم."}]},{"word":"der Ingenieur","en":"engineer","ru":"инженер","vi":"kỹ sư","fa":"مهندس","examples":[{"de":"Mein Bruder arbeitet als Ingenieur bei einer Autofirma.","en":"My brother works as an engineer at a car company.","ru":"Мой брат работает инженером в автомобильной компании.","vi":"Anh trai tôi làm kỹ sư ở một công ty ô tô.","fa":"برادرم در یک شرکت خودروسازی به عنوان مهندس کار می کند."},{"de":"Sie hat Maschinenbau studiert und ist jetzt Ingenieurin.","en":"She studied mechanical engineering and is now an engineer.","ru":"Она изучала машиностроение и теперь работает инженером.","vi":"Cô học ngành cơ khí và hiện là kỹ sư.","fa":"او مهندسی مکانیک خوانده و اکنون مهندس است."}]},{"word":"der Inhalt","en":"content","ru":"содержание","vi":"nội dung","fa":"محتوا","examples":[{"de":"Der Inhalt des Buches hat mich sehr überrascht.","en":"The content of the book surprised me a lot.","ru":"Содержание книги меня очень удивило.","vi":"Nội dung của cuốn sách thực sự làm tôi ngạc nhiên.","fa":"محتوای کتاب واقعاً مرا شگفت زده کرد."},{"de":"Bitte überprüfen Sie den Inhalt der Verpackung.","en":"Please check the contents of the package.","ru":"Пожалуйста, проверьте содержимое упаковки.","vi":"Vui lòng kiểm tra nội dung của bao bì.","fa":"لطفا محتویات بسته بندی را بررسی کنید."}]},{"word":"inklusive","en":"including","ru":"включая, включительно","vi":"bao gồm","fa":"فراگیر","examples":[{"de":"Der Preis ist inklusive Frühstück.","en":"The price includes breakfast.","ru":"Цена включает завтрак.","vi":"Giá bao gồm bữa sáng.","fa":"قیمت شامل صبحانه می باشد."},{"de":"Die Miete beträgt 600 Euro inklusive Nebenkosten.","en":"The rent is 600 euros including utilities.","ru":"Аренда составляет 600 евро, включая коммунальные услуги.","vi":"Giá thuê là 600 euro bao gồm cả chi phí bổ sung.","fa":"اجاره با احتساب هزینه اضافی 600 یورو می باشد."}]},{"word":"innen","en":"inside","ru":"внутри","vi":"bên trong","fa":"داخل","examples":[{"de":"Das Haus sieht von außen alt aus, aber innen ist es modern.","en":"The house looks old from outside, but inside it is modern.","ru":"Дом снаружи выглядит старым, но внутри он современный.","vi":"Ngôi nhà nhìn bên ngoài có vẻ cũ kỹ nhưng bên trong lại hiện đại.","fa":"خانه از بیرون قدیمی به نظر می رسد، اما درون آن مدرن است."},{"de":"Die Tür lässt sich nur von innen öffnen.","en":"The door can only be opened from the inside.","ru":"Дверь можно открыть только изнутри.","vi":"Cánh cửa chỉ có thể được mở từ bên trong.","fa":"درب فقط از داخل باز می شود."}]},{"word":"die Insel","en":"island","ru":"остров","vi":"hòn đảo","fa":"جزیره","examples":[{"de":"Wir haben unseren Urlaub auf einer kleinen Insel verbracht.","en":"We spent our vacation on a small island.","ru":"Мы провели отпуск на маленьком острове.","vi":"Chúng tôi dành kỳ nghỉ của mình trên một hòn đảo nhỏ.","fa":"تعطیلاتمان را در یک جزیره کوچک گذراندیم."},{"de":"Die Insel ist nur mit dem Boot erreichbar.","en":"The island can only be reached by boat.","ru":"На остров можно добраться только на лодке.","vi":"Đảo chỉ có thể đến được bằng thuyền.","fa":"دسترسی به جزیره فقط با قایق امکان پذیر است."}]},{"word":"das Inserat","en":"advertisement, classified ad","ru":"объявление","vi":"quảng cáo","fa":"تبلیغ","examples":[{"de":"Ich habe ein Inserat für die Wohnung in der Zeitung aufgegeben.","en":"I placed an ad for the apartment in the newspaper.","ru":"Я разместил объявление о квартире в газете.","vi":"Tôi đã đăng một quảng cáo về căn hộ trên báo.","fa":"آگهی آپارتمان را در روزنامه گذاشتم."},{"de":"In dem Inserat stand, dass das Auto sehr günstig ist.","en":"The ad said that the car is very cheap.","ru":"В объявлении говорилось, что машина очень дешёвая.","vi":"Quảng cáo cho biết chiếc xe này rất rẻ.","fa":"در آگهی آمده بود که ماشین بسیار ارزان است."}]},{"word":"insgesamt","en":"in total","ru":"в общей сложности, всего","vi":"tổng thể","fa":"به طور کلی","examples":[{"de":"Wir waren insgesamt zehn Personen auf der Party.","en":"We were ten people in total at the party.","ru":"На вечеринке было в общей сложности десять человек.","vi":"Tổng cộng có mười người chúng tôi ở bữa tiệc.","fa":"در مجموع ده نفر در مهمانی بودیم."},{"de":"Die Reise hat insgesamt zwei Wochen gedauert.","en":"The trip lasted two weeks in total.","ru":"Поездка длилась в общей сложности две недели.","vi":"Chuyến đi kéo dài tổng cộng hai tuần.","fa":"این سفر در مجموع دو هفته طول کشید."}]},{"word":"installieren","en":"to install","ru":"устанавливать","vi":"cài đặt","fa":"نصب کنید","examples":[{"de":"Kannst du mir helfen, das neue Programm zu installieren?","en":"Can you help me install the new program?","ru":"Можешь помочь мне установить новую программу?","vi":"Bạn có thể giúp tôi cài đặt chương trình mới được không?","fa":"میشه کمکم کنید برنامه جدید رو نصب کنم؟"},{"de":"Der Techniker hat die neue Software auf allen Computern installiert.","en":"The technician installed the new software on all computers.","ru":"Техник установил новое программное обеспечение на все компьютеры.","vi":"Kỹ thuật viên đã cài đặt phần mềm mới trên tất cả các máy tính.","fa":"تکنسین نرم افزار جدید را روی همه رایانه ها نصب کرد."}]},{"word":"das Institut","en":"institute","ru":"институт","vi":"viện","fa":"موسسه","examples":[{"de":"Sie arbeitet an einem Institut für Sprachforschung.","en":"She works at an institute for language research.","ru":"Она работает в институте языковых исследований.","vi":"Cô làm việc tại một viện nghiên cứu ngôn ngữ.","fa":"او در یک موسسه تحقیقات زبان کار می کند."},{"de":"Das Institut bietet auch Deutschkurse für Ausländer an.","en":"The institute also offers German courses for foreigners.","ru":"Институт также предлагает курсы немецкого языка для иностранцев.","vi":"Viện cũng cung cấp các khóa học tiếng Đức cho người nước ngoài.","fa":"این موسسه همچنین دوره های زبان آلمانی را برای خارجی ها ارائه می دهد."}]},{"word":"das Instrument","en":"instrument","ru":"инструмент","vi":"nhạc cụ","fa":"ساز","examples":[{"de":"Spielst du ein musikalisches Instrument?","en":"Do you play a musical instrument?","ru":"Ты играешь на каком-нибудь музыкальном инструменте?","vi":"Bạn có chơi một nhạc cụ không?","fa":"آیا ساز موسیقی می نوازی؟"},{"de":"Die Gitarre ist mein Lieblingsinstrument.","en":"The guitar is my favorite instrument.","ru":"Гитара — мой любимый инструмент.","vi":"Guitar là nhạc cụ yêu thích của tôi.","fa":"گیتار ساز مورد علاقه من است."}]},{"word":"integrieren","en":"to integrate","ru":"интегрировать","vi":"tích hợp","fa":"ادغام کردن","examples":[{"de":"Es dauert Zeit, sich in ein neues Land zu integrieren.","en":"It takes time to integrate into a new country.","ru":"Нужно время, чтобы интегрироваться в новую страну.","vi":"Cần có thời gian để hòa nhập vào một đất nước mới.","fa":"ادغام در یک کشور جدید به زمان نیاز دارد."},{"de":"Die Schule versucht, alle Kinder gut zu integrieren.","en":"The school tries to integrate all children well.","ru":"Школа старается хорошо интегрировать всех детей.","vi":"Nhà trường cố gắng hòa nhập tốt với tất cả trẻ em.","fa":"مدرسه سعی می کند همه بچه ها را به خوبی ادغام کند."}]},{"word":"intelligent","en":"intelligent","ru":"умный","vi":"thông minh","fa":"باهوش","examples":[{"de":"Meine Kollegin ist sehr intelligent und löst Probleme schnell.","en":"My colleague is very intelligent and solves problems quickly.","ru":"Моя коллега очень умная и быстро решает проблемы.","vi":"Đồng nghiệp của tôi rất thông minh và giải quyết vấn đề nhanh chóng.","fa":"همکار من بسیار باهوش است و مشکلات را به سرعت حل می کند."},{"de":"Hunde gelten als intelligente Tiere.","en":"Dogs are considered intelligent animals.","ru":"Собаки считаются умными животными.","vi":"Chó được coi là loài động vật thông minh.","fa":"سگ ها حیوانات باهوشی محسوب می شوند."}]},{"word":"intensiv","en":"intensive","ru":"интенсивный","vi":"mãnh liệt","fa":"شدید","examples":[{"de":"Er hat sich intensiv auf die Prüfung vorbereitet.","en":"He prepared intensively for the exam.","ru":"Он интенсивно готовился к экзамену.","vi":"Anh ấy đã chuẩn bị kỹ lưỡng cho kỳ thi.","fa":"او به شدت برای امتحان آماده شد."},{"de":"Der Sprachkurs ist sehr intensiv, wir lernen jeden Tag.","en":"The language course is very intensive, we learn every day.","ru":"Языковой курс очень интенсивный, мы учимся каждый день.","vi":"Khóa học ngôn ngữ rất chuyên sâu, chúng tôi học hàng ngày.","fa":"دوره زبان بسیار فشرده است، ما هر روز یاد می گیریم."}]},{"word":"interessieren","en":"to interest","ru":"интересовать","vi":"quan tâm","fa":"علاقه مند است","examples":[{"de":"Politik interessiert mich sehr.","en":"Politics interests me a lot.","ru":"Меня очень интересует политика.","vi":"Tôi rất quan tâm đến chính trị.","fa":"من به سیاست علاقه زیادی دارم."},{"de":"Interessierst du dich für klassische Musik?","en":"Are you interested in classical music?","ru":"Ты интересуешься классической музыкой?","vi":"Bạn có quan tâm đến âm nhạc cổ điển?","fa":"آیا به موسیقی کلاسیک علاقه دارید؟"}]},{"word":"interkulturell","en":"intercultural","ru":"межкультурный","vi":"liên văn hóa","fa":"بین فرهنگی","examples":[{"de":"Der interkulturelle Austausch hilft, andere Kulturen zu verstehen.","en":"Intercultural exchange helps to understand other cultures.","ru":"Межкультурный обмен помогает понять другие культуры.","vi":"Trao đổi liên văn hóa giúp hiểu biết các nền văn hóa khác.","fa":"تبادل بین فرهنگی به درک فرهنگ های دیگر کمک می کند."},{"de":"An der Universität gibt es ein Projekt zur interkulturellen Kommunikation.","en":"There is a project on intercultural communication at the university.","ru":"В университете есть проект по межкультурной коммуникации.","vi":"Có một dự án về giao tiếp liên văn hóa tại trường đại học.","fa":"پروژه ای در زمینه ارتباطات بین فرهنگی در دانشگاه وجود دارد."}]},{"word":"international","en":"international","ru":"международный","vi":"quốc tế","fa":"بین المللی","examples":[{"de":"Er arbeitet für ein internationales Unternehmen.","en":"He works for an international company.","ru":"Он работает в международной компании.","vi":"Anh ấy làm việc cho một công ty quốc tế.","fa":"او برای یک شرکت بین المللی کار می کند."},{"de":"Morgen findet ein internationales Fußballspiel statt.","en":"Tomorrow there is an international football match.","ru":"Завтра состоится международный футбольный матч.","vi":"Có một trận đấu bóng đá quốc tế vào ngày mai.","fa":"فردا یک مسابقه بین المللی فوتبال برگزار می شود."}]},{"word":"das Interview","en":"interview","ru":"интервью","vi":"cuộc phỏng vấn","fa":"مصاحبه","examples":[{"de":"Der Journalist führte ein Interview mit dem Bürgermeister.","en":"The journalist conducted an interview with the mayor.","ru":"Журналист взял интервью у мэра.","vi":"Nhà báo đã thực hiện cuộc phỏng vấn với thị trưởng.","fa":"این روزنامه نگار با شهردار مصاحبه ای انجام داد."},{"de":"Ich habe morgen ein Interview für einen neuen Job.","en":"I have an interview for a new job tomorrow.","ru":"Завтра у меня собеседование на новую работу.","vi":"Tôi có một cuộc phỏng vấn cho công việc mới vào ngày mai.","fa":"فردا برای کار جدید مصاحبه دارم."}]},{"word":"inzwischen","en":"meanwhile","ru":"тем временем, между тем","vi":"trong khi đó","fa":"در همین حال","examples":[{"de":"Ich koche das Essen, du kannst inzwischen den Tisch decken.","en":"I'll cook the food, meanwhile you can set the table.","ru":"Я приготовлю еду, а ты пока можешь накрыть на стол.","vi":"Tôi sẽ nấu đồ ăn, trong lúc đó bạn có thể dọn bàn ăn.","fa":"من غذا را می پزم، شما می توانید در این فاصله سفره را بچینید."},{"de":"Er ist inzwischen erwachsen und wohnt allein.","en":"He is now grown up and lives alone.","ru":"Он тем временем вырос и живёт один.","vi":"Hiện anh đã trưởng thành và sống một mình.","fa":"او اکنون بالغ است و تنها زندگی می کند."}]},{"word":"irgend-","en":"some- (indefinite prefix)","ru":"какой-то, кое- (неопределённый префикс)","vi":"bằng cách nào đó-","fa":"به نحوی-","examples":[{"de":"Ich habe meinen Schlüssel irgendwo verloren.","en":"I lost my key somewhere.","ru":"Я где-то потерял свой ключ.","vi":"Tôi bị mất chìa khóa ở đâu đó.","fa":"کلیدم را جایی گم کردم."},{"de":"Frag doch irgendjemanden nach dem Weg.","en":"Just ask someone for directions.","ru":"Спроси кого-нибудь, как пройти.","vi":"Hãy hỏi bất cứ ai để được hướng dẫn.","fa":"از هر کسی راهنمایی بخواهید"}]},{"word":"ja","en":"yes","ru":"да","vi":"vâng","fa":"بله","examples":[{"de":"Möchtest du einen Kaffee? – Ja, gerne.","en":"Would you like a coffee? – Yes, please.","ru":"Хочешь кофе? — Да, с удовольствием.","vi":"Bạn có muốn uống cà phê không? - Vâng, rất hân hạnh.","fa":"آیا قهوه میل دارید؟ - بله با کمال میل."},{"de":"Ja, ich komme morgen zur Party.","en":"Yes, I'm coming to the party tomorrow.","ru":"Да, я приду завтра на вечеринку.","vi":"Vâng, ngày mai tôi sẽ đến bữa tiệc.","fa":"بله، فردا به مهمانی می آیم."}]},{"word":"die Jacke","en":"jacket","ru":"куртка","vi":"áo khoác","fa":"ژاکت","examples":[{"de":"Zieh deine Jacke an, es ist kalt draußen.","en":"Put on your jacket, it's cold outside.","ru":"Надень куртку, на улице холодно.","vi":"Mặc áo khoác vào đi, ngoài trời lạnh lắm.","fa":"ژاکتت را بپوش، بیرون سرد است."},{"de":"Ich habe meine Jacke im Restaurant vergessen.","en":"I forgot my jacket at the restaurant.","ru":"Я забыл куртку в ресторане.","vi":"Tôi quên áo khoác ở nhà hàng.","fa":"کتم را در رستوران فراموش کردم."}]},{"word":"die Jause","en":"snack (Austrian)","ru":"перекус, полдник (австр.)","vi":"bữa ăn nhẹ","fa":"میان وعده","examples":[{"de":"Die Kinder essen um zehn Uhr eine kleine Jause in der Schule.","en":"The children have a small snack at ten o'clock at school.","ru":"Дети перекусывают в десять часов в школе.","vi":"Bọn trẻ ăn một bữa ăn nhẹ ở trường lúc mười giờ.","fa":"بچه ها ساعت ده یک میان وعده کوچک در مدرسه می خورند."},{"de":"Zur Jause gibt es Brot mit Käse und Äpfel.","en":"For the snack there is bread with cheese and apples.","ru":"На перекус — хлеб с сыром и яблоки.","vi":"Đối với đồ ăn nhẹ có bánh mì với pho mát và táo.","fa":"برای میان وعده ها نان با پنیر و سیب وجود دارد."}]},{"word":"je","en":"each, per; ever","ru":"каждый, по; когда-либо","vi":"bao giờ hết","fa":"همیشه","examples":[{"de":"Die Karten kosten je zehn Euro.","en":"The tickets cost ten euros each.","ru":"Билеты стоят по десять евро каждый.","vi":"Các thẻ có giá mười euro mỗi thẻ.","fa":"قیمت هر کارت ده یورو است."},{"de":"Hast du je daran gedacht, ins Ausland zu ziehen?","en":"Have you ever thought about moving abroad?","ru":"Ты когда-нибудь думал о переезде за границу?","vi":"Bạn đã bao giờ nghĩ đến việc chuyển ra nước ngoài chưa?","fa":"آیا تا به حال به مهاجرت به خارج از کشور فکر کرده اید؟"}]},{"word":"je nachdem","en":"depending (on)","ru":"в зависимости (от)","vi":"tùy theo","fa":"بسته به","examples":[{"de":"Je nachdem, wie das Wetter ist, gehen wir wandern oder nicht.","en":"Depending on the weather, we'll go hiking or not.","ru":"В зависимости от погоды, мы пойдём в поход или нет.","vi":"Tùy thuộc vào thời tiết như thế nào mà chúng ta có đi leo núi hay không.","fa":"بسته به اینکه آب و هوا چگونه باشد، پیاده روی می کنیم یا نه."},{"de":"Der Preis ändert sich je nachdem, wie viel du bestellst.","en":"The price changes depending on how much you order.","ru":"Цена меняется в зависимости от того, сколько ты заказываешь.","vi":"Giá thay đổi tùy theo số lượng bạn đặt hàng.","fa":"قیمت بسته به مقدار سفارش شما تغییر می کند."}]},{"word":"die Jeans","en":"jeans","ru":"джинсы","vi":"quần jean","fa":"شلوار جین","examples":[{"de":"Ich trage fast jeden Tag eine Jeans.","en":"I wear jeans almost every day.","ru":"Я почти каждый день ношу джинсы.","vi":"Tôi mặc quần jean hầu như mỗi ngày.","fa":"من تقریبا هر روز شلوار جین می پوشم."},{"de":"Diese Jeans ist mir zu lang.","en":"These jeans are too long for me.","ru":"Эти джинсы мне слишком длинные.","vi":"Những chiếc quần jean này quá dài đối với tôi.","fa":"این شلوار جین برای من خیلی بلند است."}]},{"word":"jeder","en":"every, each","ru":"каждый","vi":"mọi người","fa":"همه","examples":[{"de":"Jeder Schüler muss die Hausaufgaben machen.","en":"Every student has to do the homework.","ru":"Каждый ученик должен делать домашнее задание.","vi":"Mỗi học sinh đều phải làm bài tập về nhà.","fa":"هر دانش آموزی باید تکالیف خود را انجام دهد."},{"de":"Jeder kann Fehler machen.","en":"Everyone can make mistakes.","ru":"Каждый может совершать ошибки.","vi":"Mọi người đều có thể phạm sai lầm.","fa":"همه ممکن است اشتباه کنند."}]},{"word":"jedoch","en":"however","ru":"однако","vi":"tuy nhiên","fa":"با این حال","examples":[{"de":"Das Restaurant ist teuer, jedoch ist das Essen sehr gut.","en":"The restaurant is expensive, however the food is very good.","ru":"Ресторан дорогой, однако еда очень хорошая.","vi":"Nhà hàng đắt tiền nhưng đồ ăn rất ngon.","fa":"رستوران گران است، اما غذا بسیار خوب است."},{"de":"Ich wollte kommen, jedoch hatte ich keine Zeit.","en":"I wanted to come, however I had no time.","ru":"Я хотел прийти, однако у меня не было времени.","vi":"Ich wollte kommen, jedoch hatte ich keine Zeit.","fa":"می خواستم بیام ولی وقت نکردم."}]},{"word":"jemals","en":"ever","ru":"когда-либо","vi":"bao giờ hết","fa":"همیشه","examples":[{"de":"Warst du jemals in Japan?","en":"Have you ever been to Japan?","ru":"Ты когда-нибудь был в Японии?","vi":"Have you ever been to Japan?","fa":"آیا تا به حال به ژاپن رفته اید؟"},{"de":"Ich habe so etwas noch nie jemals erlebt.","en":"I have never experienced anything like that.","ru":"Я никогда в жизни не переживал ничего подобного.","vi":"Tôi chưa bao giờ trải nghiệm bất cứ điều gì như thế này trước đây.","fa":"من قبلاً چنین چیزی را تجربه نکرده بودم."}]},{"word":"jemand","en":"someone","ru":"кто-то","vi":"ai đó","fa":"کسی","examples":[{"de":"Hat jemand meinen Regenschirm gesehen?","en":"Has anyone seen my umbrella?","ru":"Кто-нибудь видел мой зонт?","vi":"Có ai nhìn thấy chiếc ô của tôi không?","fa":"کسی چتر من را دیده است؟"},{"de":"Es klopft jemand an der Tür.","en":"Someone is knocking on the door.","ru":"Кто-то стучит в дверь.","vi":"Có người gõ cửa.","fa":"یک نفر در را می زند."}]},{"word":"jemanden erschrecken","en":"to frighten, startle someone","ru":"пугать кого-либо","vi":"dọa ai đó","fa":"کسی را بترساند","examples":[{"de":"Er wollte seine Schwester mit der Maske erschrecken.","en":"He wanted to scare his sister with the mask.","ru":"Он хотел напугать сестру маской.","vi":"Anh muốn dọa em gái mình bằng chiếc mặt nạ.","fa":"می خواست با ماسک خواهرش را بترساند."},{"de":"Die laute Explosion im Film erschreckte alle Zuschauer.","en":"The loud explosion in the movie frightened all the viewers.","ru":"Громкий взрыв в фильме напугал всех зрителей.","vi":"Tiếng nổ lớn trong phim khiến mọi người xem sợ hãi.","fa":"انفجار شدید در فیلم همه تماشاگران را ترساند."}]},{"word":"jetzt","en":"now","ru":"сейчас","vi":"bây giờ","fa":"اکنون","examples":[{"de":"Ich muss jetzt los, sonst komme ich zu spät.","en":"I have to leave now, otherwise I'll be late.","ru":"Мне нужно идти сейчас, иначе я опоздаю.","vi":"Tôi phải đi bây giờ, nếu không tôi sẽ muộn mất.","fa":"الان باید برم وگرنه دیر میرسم."},{"de":"Jetzt verstehe ich endlich, wie das funktioniert.","en":"Now I finally understand how that works.","ru":"Теперь я наконец понимаю, как это работает.","vi":"Now I finally understand how this works.","fa":"حالا بالاخره می فهمم که این چطور کار می کند."}]},{"word":"jeweils","en":"respectively, each time","ru":"соответственно, каждый раз","vi":"mỗi","fa":"هر کدام","examples":[{"de":"Die Gruppen bestehen jeweils aus fünf Personen.","en":"The groups each consist of five people.","ru":"Каждая группа состоит из пяти человек.","vi":"Mỗi nhóm gồm có năm người.","fa":"هر گروه از پنج نفر تشکیل شده است."},{"de":"Der Kurs findet jeweils am Montag und Mittwoch statt.","en":"The course takes place respectively on Monday and Wednesday.","ru":"Курс проходит соответственно по понедельникам и средам.","vi":"Khóa học diễn ra vào thứ Hai và thứ Tư.","fa":"این دوره در روزهای دوشنبه و چهارشنبه برگزار می شود."}]},{"word":"der Journalist","en":"journalist","ru":"журналист","vi":"nhà báo","fa":"روزنامه نگار","examples":[{"de":"Der Journalist schreibt einen Artikel über die Wahlen.","en":"The journalist is writing an article about the elections.","ru":"Журналист пишет статью о выборах.","vi":"Nhà báo đang viết một bài báo về cuộc bầu cử.","fa":"روزنامه نگار در حال نوشتن مقاله ای درباره انتخابات است."},{"de":"Sie möchte Journalistin werden und für eine Zeitung arbeiten.","en":"She wants to become a journalist and work for a newspaper.","ru":"Она хочет стать журналисткой и работать в газете.","vi":"Cô muốn trở thành một nhà báo và làm việc cho một tờ báo.","fa":"او می خواهد روزنامه نگار شود و در روزنامه کار کند."}]},{"word":"die Jugend","en":"youth","ru":"молодость, юность","vi":"tuổi trẻ","fa":"جوانان","examples":[{"de":"Er hat seine Jugend auf dem Land verbracht.","en":"He spent his youth in the countryside.","ru":"Он провёл свою юность в деревне.","vi":"Anh đã trải qua tuổi trẻ của mình ở quê hương.","fa":"دوران جوانی خود را در کشور گذراند."},{"de":"Die Jugend von heute nutzt viel das Internet.","en":"Today's youth use the internet a lot.","ru":"Сегодняшняя молодёжь много пользуется интернетом.","vi":"Giới trẻ ngày nay sử dụng Internet rất nhiều.","fa":"جوانان امروزی زیاد از اینترنت استفاده می کنند."}]},{"word":"die Jugendherberge","en":"youth hostel","ru":"молодёжное общежитие, хостел","vi":"ký túc xá thanh niên","fa":"خوابگاه جوانان","examples":[{"de":"Wir haben in einer Jugendherberge übernachtet, weil sie günstig ist.","en":"We stayed in a youth hostel because it's cheap.","ru":"Мы ночевали в молодёжном хостеле, потому что это дёшево.","vi":"Chúng tôi ở trong một ký túc xá thanh niên vì nó rẻ.","fa":"ما در خوابگاه جوانان ماندیم چون ارزان بود."},{"de":"Die Jugendherberge liegt nur fünf Minuten vom Bahnhof entfernt.","en":"The youth hostel is only five minutes from the train station.","ru":"Молодёжный хостел находится всего в пяти минутах от вокзала.","vi":"Ký túc xá thanh niên chỉ cách ga xe lửa năm phút.","fa":"خوابگاه جوانان تنها پنج دقیقه با ایستگاه قطار فاصله دارد."}]},{"word":"der Jugendliche","en":"young person, teenager","ru":"подросток","vi":"người trẻ","fa":"فرد جوان","examples":[{"de":"Viele Jugendliche treffen sich am Wochenende im Park.","en":"Many young people meet in the park on weekends.","ru":"Многие подростки встречаются по выходным в парке.","vi":"Nhiều bạn trẻ gặp nhau ở công viên vào cuối tuần.","fa":"بسیاری از جوانان در تعطیلات آخر هفته در پارک ملاقات می کنند."},{"de":"Der Film ist besonders bei Jugendlichen beliebt.","en":"The film is especially popular among young people.","ru":"Фильм особенно популярен среди подростков.","vi":"Bộ phim đặc biệt được giới trẻ yêu thích.","fa":"این فیلم در بین جوانان محبوبیت خاصی دارد."}]},{"word":"jung","en":"young","ru":"молодой","vi":"trẻ","fa":"جوان","examples":[{"de":"Die jungen Leute tanzen gern auf Partys.","en":"Young people like to dance at parties.","ru":"Молодые люди любят танцевать на вечеринках.","vi":"Giới trẻ thích khiêu vũ trong các bữa tiệc.","fa":"جوانان دوست دارند در مهمانی ها برقصند."},{"de":"Meine Oma sieht für ihr Alter noch sehr jung aus.","en":"My grandma still looks very young for her age.","ru":"Моя бабушка выглядит очень молодо для своего возраста.","vi":"Bà tôi trông vẫn còn rất trẻ so với tuổi của bà.","fa":"مادربزرگ من نسبت به سنش هنوز خیلی جوان به نظر می رسد."}]},{"word":"der Junge","en":"boy","ru":"мальчик","vi":"cậu bé","fa":"پسر","examples":[{"de":"Der kleine Junge spielt im Garten mit seinem Hund.","en":"The little boy is playing in the garden with his dog.","ru":"Маленький мальчик играет в саду со своей собакой.","vi":"Cậu bé chơi trong vườn với con chó của mình.","fa":"پسر کوچک با سگش در باغ بازی می کند."},{"de":"In der Klasse sind zehn Jungen und zwölf Mädchen.","en":"There are ten boys and twelve girls in the class.","ru":"В классе десять мальчиков и двенадцать девочек.","vi":"Lớp có mười nam và mười hai nữ.","fa":"در کلاس ده پسر و دوازده دختر وجود دارد."}]},{"word":"das Kabel","en":"cable","ru":"кабель, провод","vi":"cáp","fa":"کابل","examples":[{"de":"Das Kabel für den Laptop ist zu kurz.","en":"The cable for the laptop is too short.","ru":"Кабель для ноутбука слишком короткий.","vi":"Cáp cho máy tính xách tay quá ngắn.","fa":"کابل لپ تاپ خیلی کوتاه است."},{"de":"Bitte schließen Sie das Kabel an den Fernseher an.","en":"Please connect the cable to the television.","ru":"Пожалуйста, подключите кабель к телевизору.","vi":"Vui lòng kết nối cáp với TV.","fa":"لطفا کابل را به تلویزیون وصل کنید."}]},{"word":"die Kabine","en":"cabin, booth","ru":"кабина, каюта","vi":"cabin","fa":"کابین","examples":[{"de":"Die Kabine im Schiff war klein, aber gemütlich.","en":"The cabin on the ship was small but cozy.","ru":"Каюта на корабле была маленькой, но уютной.","vi":"Cabin trên tàu nhỏ nhưng tiện nghi.","fa":"کابین کشتی کوچک اما راحت بود."},{"de":"Sie probierte das Kleid in der Kabine an.","en":"She tried on the dress in the fitting room.","ru":"Она примерила платье в примерочной кабине.","vi":"Cô thử chiếc váy trong cabin.","fa":"او لباس را در کابین امتحان کرد."}]},{"word":"der Kaffee","en":"coffee","ru":"кофе","vi":"cà phê","fa":"قهوه","examples":[{"de":"Ich trinke jeden Morgen eine Tasse Kaffee.","en":"I drink a cup of coffee every morning.","ru":"Я каждое утро пью чашку кофе.","vi":"Tôi uống một tách cà phê vào mỗi buổi sáng.","fa":"من هر روز صبح یک فنجان قهوه می نوشم."},{"de":"Möchtest du einen Kaffee mit Milch?","en":"Would you like a coffee with milk?","ru":"Хочешь кофе с молоком?","vi":"Bạn có muốn uống cà phê với sữa không?","fa":"آیا می خواهید یک قهوه با شیر بخورید؟"}]},{"word":"das Kaffeehaus","en":"coffeehouse, café","ru":"кофейня","vi":"quán cà phê","fa":"قهوه خانه","examples":[{"de":"In Wien gibt es viele traditionelle Kaffeehäuser.","en":"In Vienna there are many traditional coffeehouses.","ru":"В Вене много традиционных кофеен.","vi":"Có rất nhiều quán cà phê truyền thống ở Vienna.","fa":"قهوه خانه های سنتی زیادی در وین وجود دارد."},{"de":"Wir treffen uns im Kaffeehaus um die Ecke.","en":"We're meeting at the coffeehouse around the corner.","ru":"Мы встречаемся в кофейне за углом.","vi":"Chúng ta sẽ gặp nhau ở quán cà phê ở góc phố.","fa":"در قهوه خانه اطراف همدیگر را خواهیم دید."}]},{"word":"der Kakao","en":"cocoa","ru":"какао","vi":"ca cao","fa":"کاکائو","examples":[{"de":"Die Kinder trinken gern heißen Kakao im Winter.","en":"Children like to drink hot cocoa in winter.","ru":"Дети любят пить горячее какао зимой.","vi":"Trẻ em thích uống ca cao nóng vào mùa đông.","fa":"بچه ها دوست دارند در زمستان کاکائو داغ بنوشند."},{"de":"Für den Kuchen brauchen wir zwei Löffel Kakao.","en":"For the cake we need two spoons of cocoa.","ru":"Для торта нам нужны две ложки какао.","vi":"Đối với chiếc bánh chúng ta cần hai thìa ca cao.","fa":"برای کیک به دو قاشق کاکائو نیاز داریم."}]},{"word":"der Kalender","en":"calendar","ru":"календарь","vi":"lịch","fa":"تقویم","examples":[{"de":"Ich habe den Termin schon in meinen Kalender eingetragen.","en":"I've already entered the appointment in my calendar.","ru":"Я уже внёс встречу в свой календарь.","vi":"Tôi đã nhập cuộc hẹn vào lịch của mình rồi.","fa":"من قبلاً قرار ملاقات را در تقویم خود وارد کرده ام."},{"de":"An der Wand hängt ein Kalender mit Fotos von Bergen.","en":"There is a calendar with photos of mountains hanging on the wall.","ru":"На стене висит календарь с фотографиями гор.","vi":"Có một cuốn lịch có hình ảnh những ngọn núi trên tường.","fa":"یک تقویم با عکس های کوه روی دیوار وجود دارد."}]},{"word":"kalt","en":"cold","ru":"холодный","vi":"lạnh","fa":"سرد","examples":[{"de":"Heute ist es sehr kalt, du solltest dich warm anziehen.","en":"It's very cold today, you should dress warmly.","ru":"Сегодня очень холодно, тебе стоит тепло одеться.","vi":"Hôm nay trời rất lạnh, các bạn nhớ mặc ấm nhé.","fa":"امروز هوا خیلی سرده، باید لباس گرم بپوشی."},{"de":"Die Suppe ist schon kalt geworden.","en":"The soup has already gone cold.","ru":"Суп уже остыл.","vi":"Súp đã nguội rồi.","fa":"سوپ از قبل سرد شده است."}]},{"word":"die Kamera","en":"camera","ru":"камера, фотоаппарат","vi":"máy ảnh","fa":"دوربین","examples":[{"de":"Er hat seine Kamera mit in den Urlaub genommen.","en":"He took his camera with him on vacation.","ru":"Он взял с собой камеру в отпуск.","vi":"Anh ấy mang theo máy ảnh trong kỳ nghỉ.","fa":"او در تعطیلات دوربینش را با خود برد."},{"de":"Mit dieser Kamera kann man auch Videos machen.","en":"With this camera you can also make videos.","ru":"Этой камерой можно также снимать видео.","vi":"Bạn cũng có thể tạo video bằng máy ảnh này.","fa":"همچنین می توانید با این دوربین فیلم بسازید."}]},{"word":"kämpfen","en":"to fight","ru":"бороться","vi":"chiến đấu","fa":"مبارزه کن","examples":[{"de":"Die Feuerwehrleute kämpften stundenlang gegen das Feuer.","en":"The firefighters fought against the fire for hours.","ru":"Пожарные часами боролись с огнём.","vi":"Lính cứu hỏa đã chiến đấu với ngọn lửa trong nhiều giờ.","fa":"آتش نشانان ساعت ها با آتش مبارزه کردند."},{"de":"Sie kämpft für gleiche Rechte für alle Menschen.","en":"She fights for equal rights for all people.","ru":"Она борется за равные права для всех людей.","vi":"Cô đấu tranh cho quyền bình đẳng cho tất cả mọi người.","fa":"او برای حقوق برابر برای همه مردم مبارزه می کند."}]},{"word":"der Kanal","en":"canal, channel","ru":"канал","vi":"kênh","fa":"کانال","examples":[{"de":"Das Boot fährt langsam durch den Kanal.","en":"The boat slowly moves through the canal.","ru":"Лодка медленно движется по каналу.","vi":"Thuyền di chuyển chậm rãi qua kênh.","fa":"قایق به آرامی در کانال حرکت می کند."},{"de":"Welchen Fernsehkanal siehst du am liebsten?","en":"Which TV channel do you like watching most?","ru":"Какой телеканал ты больше всего любишь смотреть?","vi":"Bạn thích xem kênh truyền hình nào nhất?","fa":"کدام کانال تلویزیونی را بیشتر دوست دارید؟"}]},{"word":"der Kandidat","en":"candidate","ru":"кандидат","vi":"ứng cử viên","fa":"نامزد","examples":[{"de":"Drei Kandidaten bewerben sich um die Stelle.","en":"Three candidates are applying for the position.","ru":"На эту должность претендуют три кандидата.","vi":"Ba ứng viên ứng tuyển vào vị trí này.","fa":"سه نامزد برای این موقعیت درخواست می کنند."},{"de":"Der Kandidat hat die Wahl klar gewonnen.","en":"The candidate clearly won the election.","ru":"Кандидат явно выиграл выборы.","vi":"Ứng cử viên rõ ràng đã thắng cử.","fa":"نامزد به وضوح در انتخابات پیروز شد."}]},{"word":"die Kanne","en":"pot, jug","ru":"чайник, кувшин","vi":"cái nồi","fa":"گلدان","examples":[{"de":"Sie stellte eine Kanne Tee auf den Tisch.","en":"She put a pot of tea on the table.","ru":"Она поставила чайник с чаем на стол.","vi":"Cô đặt bình trà lên bàn.","fa":"یک قابلمه چای روی میز گذاشت."},{"de":"Die Kanne ist voll mit frischem Kaffee.","en":"The pot is full of fresh coffee.","ru":"Кофейник полон свежего кофе.","vi":"Chiếc bình chứa đầy cà phê mới pha.","fa":"قابلمه پر از قهوه تازه است."}]},{"word":"die Kantine","en":"canteen, cafeteria","ru":"столовая","vi":"căng tin","fa":"غذاخوری","examples":[{"de":"Wir essen mittags meistens in der Kantine der Firma.","en":"We usually eat lunch in the company canteen.","ru":"Мы обычно обедаем в столовой компании.","vi":"Chúng tôi thường ăn trưa ở căng tin công ty.","fa":"ما معمولا ناهار را در غذاخوری شرکت می خوریم."},{"de":"Das Essen in der Kantine ist heute besonders gut.","en":"The food in the canteen is especially good today.","ru":"Еда в столовой сегодня особенно хороша.","vi":"Đồ ăn ở căng tin hôm nay đặc biệt ngon.","fa":"غذای غذاخوری امروز به ویژه خوب است."}]},{"word":"das Kapitel","en":"chapter","ru":"глава","vi":"chương","fa":"فصل","examples":[{"de":"Ich habe gestern das erste Kapitel des Buches gelesen.","en":"I read the first chapter of the book yesterday.","ru":"Вчера я прочитал первую главу книги.","vi":"Tôi đã đọc chương đầu tiên của cuốn sách ngày hôm qua.","fa":"من دیروز فصل اول کتاب را خواندم."},{"de":"Das letzte Kapitel war das spannendste.","en":"The last chapter was the most exciting.","ru":"Последняя глава была самой захватывающей.","vi":"Chương cuối là thú vị nhất.","fa":"فصل آخر هیجان انگیزترین بود."}]},{"word":"kaputt","en":"broken","ru":"сломанный","vi":"bị hỏng","fa":"شکسته","examples":[{"de":"Mein Handy ist kaputt, der Bildschirm funktioniert nicht mehr.","en":"My phone is broken, the screen no longer works.","ru":"Мой телефон сломан, экран больше не работает.","vi":"Điện thoại của tôi bị hỏng, màn hình không hoạt động nữa.","fa":"گوشی من خراب است، صفحه نمایش دیگر کار نمی کند."},{"de":"Die Waschmaschine ist schon wieder kaputt.","en":"The washing machine is broken again.","ru":"Стиральная машина снова сломалась.","vi":"Máy giặt lại hỏng nữa.","fa":"ماشین لباسشویی دوباره خراب است."}]},{"word":"der Karneval","en":"carnival","ru":"карнавал","vi":"lễ hội","fa":"کارناوال","examples":[{"de":"In Köln feiert man den Karneval sehr groß.","en":"In Cologne, carnival is celebrated on a big scale.","ru":"В Кёльне карнавал отмечают очень масштабно.","vi":"Lễ hội được tổ chức rất lớn ở Cologne.","fa":"کارناوال در کلن بسیار بزرگ جشن گرفته می شود."},{"de":"Die Kinder verkleiden sich zum Karneval als Piraten.","en":"The children dress up as pirates for carnival.","ru":"На карнавал дети наряжаются пиратами.","vi":"Những đứa trẻ hóa trang thành cướp biển trong lễ hội hóa trang.","fa":"بچه ها برای کارناوال لباس دزدان دریایی می پوشند."}]},{"word":"die Karotte","en":"carrot","ru":"морковь","vi":"củ cà rốt","fa":"هویج","examples":[{"de":"Ich schneide die Karotten für den Salat klein.","en":"I'm cutting the carrots small for the salad.","ru":"Я мелко режу морковь для салата.","vi":"Tôi cắt nhỏ cà rốt cho món salad.","fa":"من هویج را برای سالاد خرد می کنم."},{"de":"Karotten sind gut für die Augen.","en":"Carrots are good for the eyes.","ru":"Морковь полезна для глаз.","vi":"Cà rốt tốt cho mắt.","fa":"هویج برای چشم مفید است."}]},{"word":"die Karriere","en":"career","ru":"карьера","vi":"sự nghiệp","fa":"حرفه","examples":[{"de":"Sie hat eine erfolgreiche Karriere als Ärztin gemacht.","en":"She made a successful career as a doctor.","ru":"Она сделала успешную карьеру врача.","vi":"Cô đã có một sự nghiệp thành công là một bác sĩ.","fa":"او به عنوان یک پزشک حرفه ای موفق داشته است."},{"de":"Für seine Karriere ist er in eine andere Stadt gezogen.","en":"He moved to another city for his career.","ru":"Ради карьеры он переехал в другой город.","vi":"Anh ấy chuyển đến một thành phố khác để phát triển sự nghiệp của mình.","fa":"او برای کار خود به شهر دیگری نقل مکان کرد."}]},{"word":"die Karte","en":"card, map, ticket","ru":"карта, билет","vi":"cái thẻ","fa":"کارت","examples":[{"de":"Ich brauche eine Karte für den Bus.","en":"I need a ticket for the bus.","ru":"Мне нужен билет на автобус.","vi":"Tôi cần một vé đi xe buýt.","fa":"من به بلیط اتوبوس نیاز دارم."},{"de":"Kannst du mir auf der Karte zeigen, wo das Museum ist?","en":"Can you show me on the map where the museum is?","ru":"Можешь показать мне на карте, где находится музей?","vi":"Bạn có thể chỉ cho tôi trên bản đồ vị trí của bảo tàng được không?","fa":"می توانید روی نقشه به من نشان دهید که موزه کجاست؟"}]},{"word":"die Kartoffel","en":"potato","ru":"картофель","vi":"khoai tây","fa":"سیب زمینی","examples":[{"de":"Zum Mittagessen gibt es Kartoffeln mit Gemüse.","en":"For lunch there are potatoes with vegetables.","ru":"На обед картофель с овощами.","vi":"Bữa trưa có khoai tây với rau.","fa":"برای ناهار سیب زمینی با سبزیجات وجود دارد."},{"de":"Meine Oma macht die besten gebratenen Kartoffeln.","en":"My grandma makes the best fried potatoes.","ru":"Моя бабушка готовит самую вкусную жареную картошку.","vi":"Bà tôi làm món khoai tây chiên ngon nhất.","fa":"مادربزرگ من بهترین سیب زمینی سرخ شده را درست می کند."}]},{"word":"der Käse","en":"cheese","ru":"сыр","vi":"pho mát","fa":"پنیر","examples":[{"de":"Ich esse gern Brot mit Käse zum Frühstück.","en":"I like to eat bread with cheese for breakfast.","ru":"Я люблю есть на завтрак хлеб с сыром.","vi":"Tôi thích ăn bánh mì và phô mai vào bữa sáng.","fa":"من دوست دارم صبحانه نان و پنیر بخورم."},{"de":"Dieser Käse aus der Schweiz schmeckt sehr würzig.","en":"This cheese from Switzerland tastes very strong.","ru":"Этот сыр из Швейцарии очень пикантный на вкус.","vi":"Phô mai Thụy Sĩ này có vị rất cay.","fa":"طعم این پنیر سوئیسی بسیار تند است."}]},{"word":"die Kasse","en":"cash register, checkout","ru":"касса","vi":"máy tính tiền","fa":"صندوق فروش","examples":[{"de":"Bitte bezahlen Sie an der Kasse.","en":"Please pay at the checkout.","ru":"Пожалуйста, оплатите на кассе.","vi":"Vui lòng thanh toán khi thanh toán.","fa":"لطفا هنگام تسویه حساب پرداخت کنید."},{"de":"An der Kasse im Supermarkt war eine lange Schlange.","en":"There was a long line at the checkout in the supermarket.","ru":"У кассы в супермаркете была длинная очередь.","vi":"Có một hàng dài người xếp hàng trước quầy thanh toán ở siêu thị.","fa":"صف طولانی در صندوق در سوپرمارکت وجود داشت."}]},{"word":"die Kassette","en":"cassette","ru":"кассета","vi":"băng cassette","fa":"نوار کاست","examples":[{"de":"Früher haben wir Musik auf Kassetten aufgenommen.","en":"In the past we used to record music on cassettes.","ru":"Раньше мы записывали музыку на кассеты.","vi":"Chúng tôi đã từng ghi âm nhạc trên băng cassette.","fa":"ما قبلاً موسیقی را روی نوار کاست ضبط می کردیم."},{"de":"Er hat noch alte Kassetten von seiner Lieblingsband.","en":"He still has old cassettes of his favorite band.","ru":"У него всё ещё есть старые кассеты его любимой группы.","vi":"Anh ấy vẫn còn giữ những chiếc băng cassette cũ của ban nhạc yêu thích của mình.","fa":"او هنوز کاست های قدیمی از گروه مورد علاقه اش را دارد."}]},{"word":"der Kasten","en":"box, crate","ru":"ящик","vi":"cái hộp","fa":"جعبه","examples":[{"de":"In der Garage steht ein Kasten mit Werkzeug.","en":"In the garage there is a box with tools.","ru":"В гараже стоит ящик с инструментами.","vi":"Có một hộp đựng dụng cụ trong gara.","fa":"یک جعبه با ابزار در گاراژ وجود دارد."},{"de":"Er hat einen Kasten Bier für die Party gekauft.","en":"He bought a crate of beer for the party.","ru":"Он купил ящик пива для вечеринки.","vi":"Anh ấy đã mua một thùng bia cho bữa tiệc.","fa":"او یک جعبه آبجو برای مهمانی خرید."}]},{"word":"der Katalog","en":"catalog","ru":"каталог","vi":"danh mục","fa":"کاتالوگ","examples":[{"de":"Wir haben die neuen Möbel im Katalog ausgesucht.","en":"We picked out the new furniture from the catalog.","ru":"Мы выбрали новую мебель по каталогу.","vi":"Chúng tôi đã chọn đồ nội thất mới trong danh mục.","fa":"ما مبلمان جدید را در کاتالوگ انتخاب کردیم."},{"de":"Der Katalog zeigt alle Produkte mit Preisen.","en":"The catalog shows all products with prices.","ru":"В каталоге показаны все товары с ценами.","vi":"Danh mục hiển thị tất cả các sản phẩm có giá.","fa":"کاتالوگ تمام محصولات را با قیمت نشان می دهد."}]},{"word":"die Katastrophe","en":"catastrophe, disaster","ru":"катастрофа","vi":"thảm họa","fa":"فاجعه","examples":[{"de":"Das Erdbeben war eine große Katastrophe für die Region.","en":"The earthquake was a big catastrophe for the region.","ru":"Землетрясение стало большой катастрофой для региона.","vi":"Trận động đất là một thảm họa lớn đối với khu vực.","fa":"این زلزله یک فاجعه بزرگ برای منطقه بود."},{"de":"Zum Glück ist die Katastrophe ohne Verletzte verlaufen.","en":"Fortunately, the disaster happened without any injuries.","ru":"К счастью, катастрофа обошлась без пострадавших.","vi":"May mắn thay, thảm họa đã qua mà không có ai bị thương.","fa":"خوشبختانه این فاجعه بدون هیچ آسیبی سپری شد."}]},{"word":"kaum","en":"hardly","ru":"едва, почти не","vi":"khó","fa":"به سختی","examples":[{"de":"Ich habe heute kaum Zeit, ich muss viel arbeiten.","en":"I hardly have time today, I have to work a lot.","ru":"Сегодня у меня почти нет времени, мне нужно много работать.","vi":"Hôm nay tôi hầu như không có thời gian, tôi phải làm việc rất nhiều.","fa":"امروز به سختی وقت دارم، باید خیلی کار کنم."},{"de":"Es regnet so laut, dass man kaum etwas hört.","en":"It's raining so loudly that you can hardly hear anything.","ru":"Дождь идёт так громко, что почти ничего не слышно.","vi":"Trời đang mưa to đến nỗi bạn khó có thể nghe thấy gì.","fa":"آنقدر باران می بارد که به سختی می توانی چیزی بشنوی."}]},{"word":"kein-","en":"no, not any (negation article)","ru":"никакой, не (отрицательный артикль)","vi":"không-","fa":"نه-","examples":[{"de":"Ich habe heute keine Zeit für einen Kaffee.","en":"I have no time for a coffee today.","ru":"У меня сегодня нет времени на кофе.","vi":"Hôm nay tôi không có thời gian uống cà phê.","fa":"امروز وقت قهوه ندارم"},{"de":"Er hat kein Geld dabei.","en":"He has no money with him.","ru":"У него с собой нет денег.","vi":"Anh ta không mang theo tiền.","fa":"او هیچ پولی با خود ندارد."}]},{"word":"der Keller","en":"cellar, basement","ru":"подвал","vi":"hầm","fa":"زیرزمین","examples":[{"de":"Wir lagern das Gemüse im kühlen Keller.","en":"We store the vegetables in the cool cellar.","ru":"Мы храним овощи в прохладном подвале.","vi":"Chúng tôi bảo quản rau trong hầm mát.","fa":"سبزیجات را در انبار خنک نگهداری می کنیم."},{"de":"Im Keller unseres Hauses steht die Waschmaschine.","en":"The washing machine is in the basement of our house.","ru":"В подвале нашего дома стоит стиральная машина.","vi":"Máy giặt ở tầng hầm nhà chúng tôi.","fa":"ماشین لباسشویی در زیرزمین خانه ماست."}]},{"word":"der Kellner","en":"waiter","ru":"официант","vi":"người phục vụ","fa":"گارسون","examples":[{"de":"Der Kellner brachte uns die Speisekarte.","en":"The waiter brought us the menu.","ru":"Официант принёс нам меню.","vi":"Người phục vụ đưa cho chúng tôi thực đơn.","fa":"گارسون منو برای ما آورد."},{"de":"Ich habe den Kellner um die Rechnung gebeten.","en":"I asked the waiter for the bill.","ru":"Я попросил официанта принести счёт.","vi":"Tôi hỏi người phục vụ tính tiền.","fa":"از پیشخدمت صورتحساب را خواستم."}]},{"word":"kennen","en":"to know (be acquainted with)","ru":"знать (быть знакомым с кем-л./чем-л.)","vi":"biết","fa":"دانستن","examples":[{"de":"Ich kenne diese Stadt sehr gut.","en":"I know this city very well.","ru":"Я очень хорошо знаю этот город.","vi":"Tôi biết rất rõ thành phố này.","fa":"من این شهر را به خوبی می شناسم."},{"de":"Kennst du meinen Bruder?","en":"Do you know my brother?","ru":"Ты знаешь моего брата?","vi":"Bạn có biết anh trai tôi không?","fa":"آیا برادر من را می شناسید؟"}]},{"word":"die Kenntnis","en":"knowledge (of something)","ru":"знание","vi":"kiến thức","fa":"دانش","examples":[{"de":"Für diesen Job sind gute Englischkenntnisse nötig.","en":"Good knowledge of English is required for this job.","ru":"Для этой работы нужны хорошие знания английского.","vi":"Kỹ năng tiếng Anh tốt là cần thiết cho công việc này.","fa":"مهارت خوب انگلیسی برای این شغل مورد نیاز است."},{"de":"Ich habe erst gestern Kenntnis davon bekommen.","en":"I only became aware of it yesterday.","ru":"Я узнал об этом только вчера.","vi":"Tôi chỉ mới biết về nó ngày hôm qua.","fa":"من تازه دیروز متوجه شدم."}]},{"word":"die Kenntnisse","en":"knowledge; skills","ru":"знания; навыки","vi":"kiến thức","fa":"دانش","examples":[{"de":"Er hat gute Kenntnisse in Englisch.","en":"He has good knowledge of English.","ru":"У него хорошие знания английского языка.","vi":"Anh ấy có kiến thức tốt về tiếng Anh.","fa":"او دانش انگلیسی خوبی دارد."},{"de":"Für den Job braucht man EDV-Kenntnisse.","en":"For the job you need computer skills.","ru":"Для этой работы нужны знания компьютера.","vi":"Công việc đòi hỏi kỹ năng máy tính.","fa":"این شغل به مهارت های کامپیوتری نیاز دارد."}]},{"word":"das Kennzeichen","en":"license plate; distinguishing mark","ru":"номерной знак; отличительный признак","vi":"biển số xe","fa":"پلاک","examples":[{"de":"Ich habe mir das Kennzeichen des Autos notiert.","en":"I noted down the car's license plate.","ru":"Я записал номерной знак машины.","vi":"Tôi đã ghi lại biển số xe.","fa":"شماره پلاک ماشین رو یادداشت کردم."},{"de":"Ehrlichkeit ist ein Kennzeichen seines Charakters.","en":"Honesty is a distinguishing feature of his character.","ru":"Честность — отличительная черта его характера.","vi":"Sự trung thực là một đặc điểm nổi bật trong tính cách của anh ấy.","fa":"صداقت از ویژگی های شخصیت اوست."}]},{"word":"die Kerze","en":"candle","ru":"свеча","vi":"ngọn nến","fa":"شمع","examples":[{"de":"Sie zündete eine Kerze auf dem Tisch an.","en":"She lit a candle on the table.","ru":"Она зажгла свечу на столе.","vi":"Cô thắp một ngọn nến trên bàn.","fa":"روی میز شمعی روشن کرد."},{"de":"Die Kerze brannte die ganze Nacht.","en":"The candle burned all night.","ru":"Свеча горела всю ночь.","vi":"Ngọn nến cháy suốt đêm.","fa":"شمع تمام شب سوخت."}]},{"word":"die Kette","en":"chain; necklace","ru":"цепь; цепочка","vi":"chuỗi","fa":"زنجیره","examples":[{"de":"Sie trägt eine goldene Kette um den Hals.","en":"She wears a gold chain around her neck.","ru":"Она носит на шее золотую цепочку.","vi":"Cô ấy đeo một sợi dây chuyền vàng quanh cổ.","fa":"زنجیر طلایی به گردنش انداخته است."},{"de":"Das Fahrrad hat eine kaputte Kette.","en":"The bicycle has a broken chain.","ru":"У велосипеда сломана цепь.","vi":"Chiếc xe đạp bị đứt xích.","fa":"دوچرخه دارای زنجیر شکسته است."}]},{"word":"das Kind","en":"child","ru":"ребёнок","vi":"đứa trẻ","fa":"کودک","examples":[{"de":"Das Kind spielt im Garten.","en":"The child is playing in the garden.","ru":"Ребёнок играет в саду.","vi":"Đứa trẻ chơi trong vườn.","fa":"کودک در باغ بازی می کند."},{"de":"Sie haben drei Kinder.","en":"They have three children.","ru":"У них трое детей.","vi":"Họ có ba đứa con.","fa":"آنها سه فرزند دارند."}]},{"word":"das Kino","en":"cinema","ru":"кино, кинотеатр","vi":"rạp chiếu phim","fa":"سینما","examples":[{"de":"Wir gehen heute Abend ins Kino.","en":"We're going to the cinema tonight.","ru":"Сегодня вечером мы идём в кино.","vi":"Chúng ta sẽ đi xem phim tối nay.","fa":"امشب میریم سینما"},{"de":"Der neue Film läuft schon im Kino.","en":"The new movie is already showing at the cinema.","ru":"Новый фильм уже идёт в кинотеатре.","vi":"Bộ phim mới đã được chiếu tại các rạp chiếu phim.","fa":"فیلم جدید هم اکنون در سینماها نمایش داده می شود."}]},{"word":"der Kiosk","en":"kiosk, newsstand","ru":"киоск","vi":"ki-ốt","fa":"کیوسک","examples":[{"de":"Am Kiosk kann man Zeitungen und Getränke kaufen.","en":"You can buy newspapers and drinks at the kiosk.","ru":"В киоске можно купить газеты и напитки.","vi":"Bạn có thể mua báo và đồ uống tại ki-ốt.","fa":"از کیوسک می توانید روزنامه و نوشیدنی بخرید."},{"de":"Der Kiosk an der Ecke hat bis spät geöffnet.","en":"The kiosk on the corner is open until late.","ru":"Киоск на углу открыт допоздна.","vi":"The kiosk on the corner is open until late.","fa":"کیوسک گوشه تا دیر وقت باز است."}]},{"word":"die Kirche","en":"church","ru":"церковь","vi":"nhà thờ","fa":"کلیسا","examples":[{"de":"Am Sonntag gehen sie in die Kirche.","en":"On Sunday they go to church.","ru":"В воскресенье они ходят в церковь.","vi":"Chủ nhật họ đi nhà thờ.","fa":"روز یکشنبه به کلیسا می روند."},{"de":"Die alte Kirche steht mitten in der Stadt.","en":"The old church stands in the middle of the town.","ru":"Старая церковь стоит в центре города.","vi":"Die alte Kirche steht mitten in der Stadt.","fa":"کلیسای قدیمی در وسط شهر است."}]},{"word":"das Kissen","en":"pillow, cushion","ru":"подушка","vi":"cái gối","fa":"بالش","examples":[{"de":"Ich schlafe gern mit einem weichen Kissen.","en":"I like sleeping with a soft pillow.","ru":"Я люблю спать на мягкой подушке.","vi":"Tôi thích ngủ với một chiếc gối mềm.","fa":"من دوست دارم با یک بالش نرم بخوابم."},{"de":"Sie legte ein Kissen auf den Stuhl.","en":"She put a cushion on the chair.","ru":"Она положила подушку на стул.","vi":"Cô đặt một chiếc gối lên ghế.","fa":"بالشی روی صندلی گذاشت."}]},{"word":"die Kiste","en":"box, crate","ru":"ящик","vi":"cái hộp","fa":"جعبه","examples":[{"de":"Er trägt eine schwere Kiste in den Keller.","en":"He carries a heavy box into the cellar.","ru":"Он несёт тяжёлый ящик в подвал.","vi":"Anh ta mang một chiếc hộp nặng xuống tầng hầm.","fa":"او یک جعبه سنگین را به زیرزمین حمل می کند."},{"de":"In der Kiste sind alte Bücher.","en":"There are old books in the box.","ru":"В ящике лежат старые книги.","vi":"Có những cuốn sách cũ trong hộp.","fa":"در جعبه کتاب های قدیمی وجود دارد."}]},{"word":"klagen","en":"to complain","ru":"жаловаться","vi":"phàn nàn","fa":"شکایت کردن","examples":[{"de":"Er klagt oft über sein Gehalt.","en":"He often complains about his salary.","ru":"Он часто жалуется на свою зарплату.","vi":"Anh ấy thường phàn nàn về mức lương của mình.","fa":"او اغلب از حقوق خود شاکی است."},{"de":"Sie klagte über Kopfschmerzen.","en":"She complained of a headache.","ru":"Она жаловалась на головную боль.","vi":"Cô phàn nàn về cơn đau đầu.","fa":"او از سردرد شکایت کرد."}]},{"word":"klappen","en":"to work out, go well","ru":"удаваться, получаться","vi":"gấp lại","fa":"تا زدن","examples":[{"de":"Hoffentlich klappt alles mit dem neuen Job.","en":"Hopefully everything works out with the new job.","ru":"Надеюсь, всё получится с новой работой.","vi":"Hy vọng mọi việc sẽ suôn sẻ với công việc mới.","fa":"امیدوارم با کار جدید همه چیز درست شود."},{"de":"Es hat mit dem Termin gut geklappt.","en":"The appointment worked out well.","ru":"С назначением встречи всё удалось.","vi":"Cuộc hẹn diễn ra tốt đẹp.","fa":"قرار ملاقات به خوبی انجام شد."}]},{"word":"klar","en":"clear","ru":"ясный, понятный","vi":"rõ ràng","fa":"روشن","examples":[{"de":"Die Antwort war völlig klar.","en":"The answer was completely clear.","ru":"Ответ был совершенно ясным.","vi":"Câu trả lời đã hoàn toàn rõ ràng.","fa":"جواب کاملا واضح بود."},{"de":"Heute ist der Himmel klar und blau.","en":"Today the sky is clear and blue.","ru":"Сегодня небо ясное и голубое.","vi":"Heute ist der Himmel klar und blau.","fa":"امروز آسمان صاف و آبی است."}]},{"word":"klären","en":"to clarify, resolve","ru":"выяснять, прояснять","vi":"làm rõ","fa":"روشن کردن","examples":[{"de":"Wir müssen noch ein paar Fragen klären.","en":"We still need to clarify a few questions.","ru":"Нам нужно ещё прояснить несколько вопросов.","vi":"Chúng ta vẫn cần làm rõ một số câu hỏi.","fa":"هنوز باید چند سوال را روشن کنیم."},{"de":"Die Polizei konnte den Fall schnell klären.","en":"The police were able to solve the case quickly.","ru":"Полиция смогла быстро прояснить это дело.","vi":"The police were able to quickly clarify the case.","fa":"پلیس به سرعت توانست موضوع را روشن کند."}]},{"word":"klasse","en":"great, awesome (colloquial)","ru":"классно, отлично","vi":"lớp học","fa":"کلاس","examples":[{"de":"Das Konzert war einfach klasse!","en":"The concert was simply great!","ru":"Концерт был просто отличным!","vi":"Buổi hòa nhạc đơn giản là tuyệt vời!","fa":"کنسرت به سادگی عالی بود!"},{"de":"Ich finde deine Idee klasse.","en":"I think your idea is great.","ru":"Я считаю твою идею классной.","vi":"Tôi nghĩ ý tưởng của bạn là tuyệt vời.","fa":"به نظر من ایده شما عالی است."}]},{"word":"die Klasse","en":"class (school grade or category)","ru":"класс","vi":"lớp học","fa":"کلاس","examples":[{"de":"Meine Tochter ist in der fünften Klasse.","en":"My daughter is in the fifth grade.","ru":"Моя дочь учится в пятом классе.","vi":"Con gái tôi đang học lớp năm.","fa":"دختر من کلاس پنجم است."},{"de":"Wir fahren in der ersten Klasse.","en":"We are traveling in first class.","ru":"Мы едем в первом классе.","vi":"Chúng tôi đi du lịch ở khoang hạng nhất.","fa":"ما در کلاس اول سفر می کنیم."}]},{"word":"die Klassenarbeit","en":"class test, exam","ru":"контрольная работа","vi":"công việc của lớp","fa":"کار کلاس","examples":[{"de":"Morgen schreiben wir eine Klassenarbeit in Mathe.","en":"Tomorrow we're writing a class test in math.","ru":"Завтра мы пишем контрольную по математике.","vi":"Ngày mai chúng ta sẽ viết bài kiểm tra môn toán trên lớp.","fa":"فردا امتحان ریاضی می نویسیم."},{"de":"Die Klassenarbeit war schwerer als erwartet.","en":"The class test was harder than expected.","ru":"Контрольная оказалась сложнее, чем ожидалось.","vi":"Bài tập trên lớp khó hơn dự kiến.","fa":"کار کلاس سخت تر از حد انتظار بود."}]},{"word":"das Klavier","en":"piano","ru":"пианино","vi":"đàn piano","fa":"پیانو","examples":[{"de":"Sie spielt seit fünf Jahren Klavier.","en":"She has been playing the piano for five years.","ru":"Она играет на пианино уже пять лет.","vi":"Cô ấy đã chơi piano được 5 năm.","fa":"او پنج سال است که پیانو می نوازد."},{"de":"Im Wohnzimmer steht ein altes Klavier.","en":"There's an old piano in the living room.","ru":"В гостиной стоит старое пианино.","vi":"Có một cây đàn piano cũ trong phòng khách.","fa":"یک پیانوی قدیمی در اتاق نشیمن وجود دارد."}]},{"word":"kleben","en":"to stick, glue","ru":"клеить, приклеивать","vi":"cây gậy","fa":"چوب","examples":[{"de":"Er klebt das Poster an die Wand.","en":"He is sticking the poster on the wall.","ru":"Он клеит плакат на стену.","vi":"Anh ấy dán tấm áp phích lên tường.","fa":"پوستر را به دیوار می چسباند."},{"de":"Kannst du den Griff wieder ankleben?","en":"Can you glue the handle back on?","ru":"Можешь приклеить ручку обратно?","vi":"Bạn có thể dán lại tay cầm được không?","fa":"آیا می توانید دسته را دوباره بچسبانید؟"}]},{"word":"das Kleid","en":"dress","ru":"платье","vi":"chiếc váy","fa":"لباس","examples":[{"de":"Sie trägt ein rotes Kleid zur Party.","en":"She's wearing a red dress to the party.","ru":"Она наденет красное платье на вечеринку.","vi":"Cô mặc váy đỏ đi dự tiệc.","fa":"او برای مهمانی یک لباس قرمز پوشیده است."},{"de":"Das Kleid passt ihr sehr gut.","en":"The dress fits her very well.","ru":"Платье сидит на ней очень хорошо.","vi":"Chiếc váy rất hợp với cô ấy.","fa":"لباس خیلی بهش میاد"}]},{"word":"die Kleidung","en":"clothing, clothes","ru":"одежда","vi":"quần áo","fa":"لباس","examples":[{"de":"Im Koffer ist genug Kleidung für eine Woche.","en":"There's enough clothing in the suitcase for a week.","ru":"В чемодане достаточно одежды на неделю.","vi":"Có đủ quần áo trong vali cho một tuần.","fa":"برای یک هفته به اندازه کافی لباس داخل چمدان هست."},{"de":"Warme Kleidung ist im Winter wichtig.","en":"Warm clothing is important in winter.","ru":"Тёплая одежда важна зимой.","vi":"Quần áo ấm rất quan trọng trong mùa đông.","fa":"لباس گرم در زمستان مهم است."}]},{"word":"klein","en":"small","ru":"маленький","vi":"nhỏ bé","fa":"کوچک","examples":[{"de":"Sie wohnt in einer kleinen Wohnung.","en":"She lives in a small apartment.","ru":"Она живёт в маленькой квартире.","vi":"Cô sống trong một căn hộ nhỏ.","fa":"او در یک آپارتمان کوچک زندگی می کند."},{"de":"Das Kind ist noch sehr klein.","en":"The child is still very small.","ru":"Ребёнок ещё совсем маленький.","vi":"Đứa trẻ vẫn còn rất nhỏ.","fa":"بچه هنوز خیلی کوچک است."}]},{"word":"klettern","en":"to climb","ru":"лазить, взбираться","vi":"leo lên","fa":"صعود","examples":[{"de":"Die Kinder klettern gern auf Bäume.","en":"The children like climbing trees.","ru":"Дети любят лазить по деревьям.","vi":"Trẻ em thích trèo cây.","fa":"بچه ها دوست دارند از درخت بالا بروند."},{"de":"Wir sind letztes Jahr in den Alpen geklettert.","en":"We went climbing in the Alps last year.","ru":"В прошлом году мы лазили в Альпах.","vi":"Chúng tôi đã leo lên dãy Alps vào năm ngoái.","fa":"ما سال گذشته در کوه های آلپ صعود کردیم."}]},{"word":"klicken","en":"to click","ru":"щёлкать (мышью), нажимать","vi":"bấm vào","fa":"کلیک کنید","examples":[{"de":"Klicken Sie hier, um fortzufahren.","en":"Click here to continue.","ru":"Нажмите здесь, чтобы продолжить.","vi":"Nhấn vào đây để tiếp tục.","fa":"برای ادامه اینجا را کلیک کنید."},{"de":"Er klickte versehentlich auf den falschen Link.","en":"He accidentally clicked the wrong link.","ru":"Он случайно нажал не на ту ссылку.","vi":"Anh vô tình bấm nhầm vào link.","fa":"او به طور تصادفی روی لینک اشتباه کلیک کرد."}]},{"word":"das Klima","en":"climate","ru":"климат","vi":"khí hậu","fa":"آب و هوا","examples":[{"de":"In Spanien ist das Klima wärmer als in Deutschland.","en":"The climate in Spain is warmer than in Germany.","ru":"В Испании климат теплее, чем в Германии.","vi":"Khí hậu ở Tây Ban Nha ấm hơn ở Đức.","fa":"آب و هوای اسپانیا گرمتر از آلمان است."},{"de":"Der Klimawandel verändert das Klima weltweit.","en":"Climate change is altering the climate worldwide.","ru":"Изменение климата меняет климат во всём мире.","vi":"Biến đổi khí hậu đang làm thay đổi khí hậu trên toàn thế giới.","fa":"تغییرات آب و هوایی در حال تغییر اقلیم در سراسر جهان است."}]},{"word":"der Klimawandel","en":"climate change","ru":"изменение климата","vi":"biến đổi khí hậu","fa":"تغییرات آب و هوایی","examples":[{"de":"Der Klimawandel bedroht viele Tierarten.","en":"Climate change threatens many animal species.","ru":"Изменение климата угрожает многим видам животных.","vi":"Biến đổi khí hậu đe dọa nhiều loài động vật.","fa":"تغییرات آب و هوایی بسیاری از گونه های جانوری را تهدید می کند."},{"de":"Wissenschaftler warnen seit Jahren vor dem Klimawandel.","en":"Scientists have been warning about climate change for years.","ru":"Учёные уже много лет предупреждают об изменении климата.","vi":"Các nhà khoa học đã cảnh báo về biến đổi khí hậu trong nhiều năm.","fa":"دانشمندان سالهاست که درباره تغییرات آب و هوایی هشدار می دهند."}]},{"word":"klingeln","en":"to ring (a bell)","ru":"звонить (в звонок)","vi":"chiếc nhẫn","fa":"حلقه","examples":[{"de":"Es hat an der Tür geklingelt.","en":"The doorbell rang.","ru":"В дверь позвонили.","vi":"Chuông cửa reo.","fa":"زنگ در به صدا درآمد."},{"de":"Bitte klingeln Sie, wenn Sie ankommen.","en":"Please ring the bell when you arrive.","ru":"Пожалуйста, позвоните в звонок, когда придёте.","vi":"Vui lòng bấm chuông khi bạn đến.","fa":"لطفا وقتی رسیدید زنگ را بزنید."}]},{"word":"klingen","en":"to sound","ru":"звучать","vi":"âm thanh","fa":"صدا","examples":[{"de":"Das klingt wie eine gute Idee.","en":"That sounds like a good idea.","ru":"Это звучит как хорошая идея.","vi":"Nghe có vẻ là một ý tưởng hay.","fa":"به نظر می رسد ایده خوبی است."},{"de":"Ihre Stimme klingt heute müde.","en":"Her voice sounds tired today.","ru":"Её голос сегодня звучит устало.","vi":"Giọng nói của bạn hôm nay có vẻ mệt mỏi.","fa":"امروز صدایت خسته به نظر می رسد."}]},{"word":"die Klinik","en":"clinic","ru":"клиника","vi":"phòng khám","fa":"کلینیک","examples":[{"de":"Er wurde sofort in die Klinik gebracht.","en":"He was immediately taken to the clinic.","ru":"Его немедленно доставили в клинику.","vi":"Anh ngay lập tức được đưa đến phòng khám.","fa":"او بلافاصله به درمانگاه منتقل شد."},{"de":"Die Klinik ist auf Herzkrankheiten spezialisiert.","en":"The clinic specializes in heart diseases.","ru":"Клиника специализируется на сердечных заболеваниях.","vi":"Phòng khám chuyên về bệnh tim mạch.","fa":"این کلینیک در زمینه بیماری های قلبی تخصص دارد."}]},{"word":"klopfen","en":"to knock","ru":"стучать","vi":"gõ cửa","fa":"در زدن","examples":[{"de":"Jemand klopft an der Tür.","en":"Someone is knocking on the door.","ru":"Кто-то стучит в дверь.","vi":"Có người gõ cửa.","fa":"یک نفر در را می زند."},{"de":"Sie klopfte höflich, bevor sie eintrat.","en":"She knocked politely before entering.","ru":"Она вежливо постучала, прежде чем войти.","vi":"Cô lịch sự gõ cửa trước khi bước vào.","fa":"قبل از ورود مودبانه در زد."}]},{"word":"der Kloß","en":"dumpling","ru":"клёцка","vi":"bánh bao","fa":"پیراشکی","examples":[{"de":"Zum Braten gibt es Klöße.","en":"Dumplings are served with the roast.","ru":"К жаркому подают клёцки.","vi":"Có bánh bao để chiên.","fa":"کوفته هایی برای سرخ کردن وجود دارد."},{"de":"Meine Oma macht die besten Klöße.","en":"My grandma makes the best dumplings.","ru":"Моя бабушка делает лучшие клёцки.","vi":"Bà tôi làm bánh bao ngon nhất.","fa":"مادربزرگ من بهترین کوفته ها را درست می کند."}]},{"word":"klug","en":"clever, smart","ru":"умный","vi":"thông minh","fa":"باهوش","examples":[{"de":"Sie ist eine sehr kluge Studentin.","en":"She is a very clever student.","ru":"Она очень умная студентка.","vi":"Cô ấy là một học sinh rất thông minh.","fa":"او دانش آموز بسیار باهوشی است."},{"de":"Das war eine kluge Entscheidung.","en":"That was a smart decision.","ru":"Это было умное решение.","vi":"Đó là một quyết định sáng suốt.","fa":"این تصمیم عاقلانه ای بود."}]},{"word":"knapp","en":"scarce, tight; barely, just","ru":"ограниченный, дефицитный; едва, чуть","vi":"khan hiếm","fa":"کمیاب","examples":[{"de":"Unsere Zeit ist knapp.","en":"Our time is short.","ru":"Нашего времени в обрез.","vi":"Thời gian của chúng ta rất ngắn.","fa":"زمان ما کوتاه است."},{"de":"Er hat den Zug nur knapp geschafft.","en":"He barely made the train.","ru":"Он еле успел на поезд.","vi":"Anh ấy hầu như không thực hiện được hành động.","fa":"او به سختی حرکت را انجام داد."}]},{"word":"die Kneipe","en":"pub, bar","ru":"пивная, паб","vi":"quán rượu","fa":"میخانه","examples":[{"de":"Wir treffen uns abends in der Kneipe.","en":"We meet up at the pub in the evening.","ru":"Вечером мы встречаемся в пивной.","vi":"Chúng tôi gặp nhau ở quán rượu vào buổi tối.","fa":"عصر در میخانه همدیگر را می بینیم."},{"de":"In dieser Kneipe gibt es gutes Bier.","en":"This pub has good beer.","ru":"В этом пабе хорошее пиво.","vi":"Có bia ngon ở quán rượu này.","fa":"آبجو خوبی در این میخانه وجود دارد."}]},{"word":"das Knie","en":"knee","ru":"колено","vi":"đầu gối","fa":"زانو","examples":[{"de":"Er hat sich beim Fußball das Knie verletzt.","en":"He injured his knee playing football.","ru":"Он повредил колено, играя в футбол.","vi":"Anh ấy bị thương ở đầu gối khi chơi bóng đá.","fa":"او در بازی فوتبال زانویش آسیب دید."},{"de":"Die Kinder saßen auf dem Knie des Opas.","en":"The children sat on grandpa's knee.","ru":"Дети сидели на коленях у дедушки.","vi":"Bọn trẻ ngồi trên đầu gối của ông nội.","fa":"بچه ها روی زانوی پدربزرگ نشستند."}]},{"word":"der Knochen","en":"bone","ru":"кость","vi":"xương","fa":"استخوان","examples":[{"de":"Der Hund kaut gern an einem Knochen.","en":"The dog likes to chew on a bone.","ru":"Собака любит грызть кость.","vi":"Con chó thích nhai xương.","fa":"سگ دوست دارد استخوان بجود."},{"de":"Bei dem Sturz hat er sich einen Knochen gebrochen.","en":"He broke a bone in the fall.","ru":"При падении он сломал кость.","vi":"Anh ấy bị gãy xương vào mùa thu.","fa":"او در پاییز یک استخوان شکست."}]},{"word":"der Knödel","en":"dumpling","ru":"кнедлик","vi":"bánh bao","fa":"پیراشکی","examples":[{"de":"In Bayern isst man oft Knödel zum Fleisch.","en":"In Bavaria, dumplings are often eaten with meat.","ru":"В Баварии кнедлики часто едят с мясом.","vi":"Ở Bavaria người ta thường ăn bánh bao với thịt.","fa":"در باواریا مردم اغلب کوفته ها را با گوشت می خورند."},{"de":"Sie kocht Knödel aus Kartoffeln.","en":"She cooks dumplings made of potatoes.","ru":"Она варит кнедлики из картофеля.","vi":"Cô ấy nấu bánh bao từ khoai tây.","fa":"او از سیب زمینی کوفته می پزد."}]},{"word":"der Knopf","en":"button","ru":"пуговица; кнопка","vi":"cái nút","fa":"دکمه","examples":[{"de":"An der Jacke fehlt ein Knopf.","en":"A button is missing from the jacket.","ru":"На куртке не хватает пуговицы.","vi":"Một chiếc nút bị thiếu trên áo khoác.","fa":"یک دکمه از کت گم شده است."},{"de":"Drück auf den roten Knopf, um die Maschine zu starten.","en":"Press the red button to start the machine.","ru":"Нажми красную кнопку, чтобы запустить машину.","vi":"Nhấn nút màu đỏ để khởi động máy.","fa":"دکمه قرمز را فشار دهید تا دستگاه روشن شود."}]},{"word":"kochen","en":"to cook","ru":"готовить (еду)","vi":"nấu ăn","fa":"پختن","examples":[{"de":"Meine Mutter kocht jeden Abend das Essen.","en":"My mother cooks dinner every evening.","ru":"Моя мама готовит ужин каждый вечер.","vi":"Mẹ tôi nấu bữa tối mỗi tối.","fa":"مادرم هر روز عصر شام درست می کند."},{"de":"Kannst du gut kochen?","en":"Can you cook well?","ru":"Ты хорошо готовишь?","vi":"Bạn có giỏi nấu ăn không?","fa":"آیا در آشپزی خوب هستید؟"}]},{"word":"der Koffer","en":"suitcase","ru":"чемодан","vi":"chiếc vali","fa":"چمدان","examples":[{"de":"Ich packe meinen Koffer für die Reise.","en":"I'm packing my suitcase for the trip.","ru":"Я собираю чемодан для поездки.","vi":"Tôi đang đóng gói hành lý cho chuyến đi.","fa":"دارم چمدانم را برای سفر می بندم."},{"de":"Der Koffer war zu schwer für das Flugzeug.","en":"The suitcase was too heavy for the plane.","ru":"Чемодан оказался слишком тяжёлым для самолёта.","vi":"Chiếc vali quá nặng so với máy bay.","fa":"چمدان برای هواپیما خیلی سنگین بود."}]},{"word":"der Kollege","en":"colleague","ru":"коллега","vi":"đồng nghiệp","fa":"همکار","examples":[{"de":"Mein Kollege hilft mir bei der Arbeit.","en":"My colleague helps me with work.","ru":"Мой коллега помогает мне на работе.","vi":"Đồng nghiệp của tôi giúp đỡ tôi trong công việc.","fa":"همکارم در کار به من کمک می کند."},{"de":"Wir gehen mit den Kollegen essen.","en":"We're going out to eat with our colleagues.","ru":"Мы идём обедать с коллегами.","vi":"Chúng tôi sẽ đi ăn tối với đồng nghiệp của chúng tôi.","fa":"با همکارانمان برای شام بیرون می رویم."}]},{"word":"komisch","en":"strange, odd; funny","ru":"странный; смешной","vi":"buồn cười","fa":"خنده دار","examples":[{"de":"Das ist komisch, die Tür war doch verschlossen.","en":"That's strange, the door was locked though.","ru":"Странно, дверь ведь была заперта.","vi":"Thật kỳ lạ, cửa đã bị khóa.","fa":"عجیب است، در قفل بود."},{"de":"Er hat einen komischen Witz erzählt.","en":"He told a funny joke.","ru":"Он рассказал смешную шутку.","vi":"Anh kể một chuyện vui.","fa":"یه جوک بامزه گفت"}]},{"word":"kommen","en":"to come","ru":"приходить, приезжать","vi":"đến","fa":"بیا","examples":[{"de":"Er kommt jeden Tag pünktlich zur Arbeit.","en":"He comes to work on time every day.","ru":"Он каждый день приходит на работу вовремя.","vi":"Anh ấy đến làm việc đúng giờ mỗi ngày.","fa":"او هر روز سر وقت سر کار می آید."},{"de":"Woher kommst du?","en":"Where are you from?","ru":"Откуда ты?","vi":"Bạn đến từ đâu?","fa":"شما از کجا می آیید؟"}]},{"word":"die Kommunikation","en":"communication","ru":"коммуникация, общение","vi":"sự giao tiếp","fa":"ارتباط","examples":[{"de":"Gute Kommunikation ist im Team sehr wichtig.","en":"Good communication is very important in a team.","ru":"Хорошая коммуникация очень важна в команде.","vi":"Giao tiếp tốt là rất quan trọng trong một nhóm.","fa":"ارتباط خوب در یک تیم بسیار مهم است."},{"de":"Die Kommunikation zwischen den Abteilungen läuft über E-Mail.","en":"Communication between the departments takes place via email.","ru":"Общение между отделами происходит по электронной почте.","vi":"Việc liên lạc giữa các phòng ban diễn ra thông qua email.","fa":"ارتباط بین بخش ها از طریق ایمیل انجام می شود."}]},{"word":"komplett","en":"complete","ru":"полный, целиком","vi":"hoàn thành","fa":"کامل","examples":[{"de":"Das Formular muss komplett ausgefüllt werden.","en":"The form must be filled out completely.","ru":"Бланк нужно заполнить полностью.","vi":"Mẫu đơn phải được điền đầy đủ.","fa":"فرم باید به طور کامل پر شود."},{"de":"Die Wohnung wird komplett renoviert.","en":"The apartment is being completely renovated.","ru":"Квартира ремонтируется полностью.","vi":"Căn hộ đang được cải tạo lại hoàn toàn.","fa":"آپارتمان در حال بازسازی کامل است."}]},{"word":"kompliziert","en":"complicated","ru":"сложный","vi":"phức tạp","fa":"پیچیده","examples":[{"de":"Die Aufgabe ist ziemlich kompliziert.","en":"The task is quite complicated.","ru":"Задача довольно сложная.","vi":"Nhiệm vụ khá phức tạp.","fa":"کار کاملاً پیچیده است."},{"de":"Er erklärt alles viel zu kompliziert.","en":"He explains everything much too complicatedly.","ru":"Он объясняет всё слишком сложно.","vi":"Er erklärt alles viel zu kompliziert.","fa":"او همه چیز را با عبارات بسیار پیچیده توضیح می دهد."}]},{"word":"der Kompromiss","en":"compromise","ru":"компромисс","vi":"sự thỏa hiệp","fa":"سازش","examples":[{"de":"Am Ende haben wir einen Kompromiss gefunden.","en":"In the end we found a compromise.","ru":"В конце концов мы нашли компромисс.","vi":"Cuối cùng chúng tôi đã tìm thấy một sự thỏa hiệp.","fa":"در پایان ما یک مصالحه پیدا کردیم."},{"de":"Sie mussten einen Kompromiss eingehen.","en":"They had to make a compromise.","ru":"Им пришлось пойти на компромисс.","vi":"Họ đã phải thỏa hiệp.","fa":"آنها باید سازش می کردند."}]},{"word":"die Konferenz","en":"conference","ru":"конференция","vi":"hội nghị","fa":"کنفرانس","examples":[{"de":"Die Konferenz findet nächste Woche in Berlin statt.","en":"The conference takes place in Berlin next week.","ru":"Конференция состоится на следующей неделе в Берлине.","vi":"Hội nghị sẽ diễn ra vào tuần tới tại Berlin.","fa":"این کنفرانس هفته آینده در برلین برگزار می شود."},{"de":"Sie hält einen Vortrag auf der Konferenz.","en":"She is giving a talk at the conference.","ru":"Она выступит с докладом на конференции.","vi":"Cô ấy phát biểu tại hội nghị.","fa":"او در کنفرانس سخنرانی می کند."}]},{"word":"die Konfitüre","en":"jam","ru":"джем, варенье","vi":"chết Konfitüre","fa":"مربا","examples":[{"de":"Zum Frühstück gibt es Brötchen mit Konfitüre.","en":"For breakfast there are rolls with jam.","ru":"На завтрак булочки с джемом.","vi":"Bữa sáng có bánh cuốn với mứt.","fa":"برای صبحانه رول هایی با مربا وجود دارد."},{"de":"Sie kocht die Konfitüre selbst aus Erdbeeren.","en":"She makes the jam herself from strawberries.","ru":"Она сама варит джем из клубники.","vi":"She makes the jam herself from strawberries.","fa":"مربا را خودش از توت فرنگی درست می کند."}]},{"word":"der Konflikt","en":"conflict","ru":"конфликт","vi":"cuộc xung đột","fa":"درگیری","examples":[{"de":"Zwischen den beiden Ländern gibt es einen Konflikt.","en":"There is a conflict between the two countries.","ru":"Между двумя странами существует конфликт.","vi":"Giữa hai nước đang có xung đột.","fa":"درگیری بین دو کشور وجود دارد."},{"de":"Wir konnten den Konflikt friedlich lösen.","en":"We were able to resolve the conflict peacefully.","ru":"Мы смогли мирно разрешить конфликт.","vi":"Chúng tôi đã có thể giải quyết xung đột một cách hòa bình.","fa":"ما توانستیم درگیری را به صورت مسالمت آمیز حل کنیم."}]},{"word":"der König","en":"king","ru":"король","vi":"nhà vua","fa":"پادشاه","examples":[{"de":"Der König regierte das Land viele Jahre.","en":"The king ruled the country for many years.","ru":"Король правил страной много лет.","vi":"Nhà vua cai trị đất nước trong nhiều năm.","fa":"شاه سالها بر کشور حکومت کرد."},{"de":"Im Märchen heiratet die Prinzessin den König.","en":"In the fairy tale, the princess marries the king.","ru":"В сказке принцесса выходит замуж за короля.","vi":"Trong truyện cổ tích, công chúa kết hôn với nhà vua.","fa":"در یک افسانه، شاهزاده خانم با پادشاه ازدواج می کند."}]},{"word":"die Konkurrenz","en":"competition","ru":"конкуренция","vi":"the competition","fa":"رقابت","examples":[{"de":"Die Konkurrenz auf dem Markt ist sehr groß.","en":"Competition in the market is very strong.","ru":"Конкуренция на рынке очень высока.","vi":"Sự cạnh tranh trên thị trường là rất cao.","fa":"رقابت در بازار بسیار بالاست."},{"de":"Unsere Firma hat viel Konkurrenz.","en":"Our company has a lot of competition.","ru":"У нашей фирмы много конкурентов.","vi":"Công ty chúng tôi có rất nhiều sự cạnh tranh.","fa":"شرکت ما رقابت زیادی دارد."}]},{"word":"können","en":"can, to be able to","ru":"мочь, уметь","vi":"có thể","fa":"می تواند","examples":[{"de":"Ich kann leider nicht kommen.","en":"Unfortunately I can't come.","ru":"К сожалению, я не могу прийти.","vi":"Thật không may là tôi không thể đến được.","fa":"متاسفانه نمیتونم بیام"},{"de":"Sie kann sehr gut schwimmen.","en":"She can swim very well.","ru":"Она очень хорошо умеет плавать.","vi":"Cô ấy có thể bơi rất giỏi.","fa":"او می تواند بسیار خوب شنا کند."}]},{"word":"das Konsulat","en":"consulate","ru":"консульство","vi":"lãnh sự quán","fa":"کنسولگری","examples":[{"de":"Er muss zum Konsulat, um ein Visum zu beantragen.","en":"He has to go to the consulate to apply for a visa.","ru":"Ему нужно в консульство, чтобы подать заявление на визу.","vi":"Anh ta phải đến lãnh sự quán để xin thị thực.","fa":"او باید برای درخواست ویزا به کنسولگری برود."},{"de":"Das Konsulat hilft Bürgern im Ausland.","en":"The consulate helps citizens abroad.","ru":"Консульство помогает гражданам за рубежом.","vi":"Lãnh sự quán giúp đỡ công dân ở nước ngoài.","fa":"کنسولگری به شهروندان خارج از کشور کمک می کند."}]},{"word":"konsumieren","en":"to consume","ru":"потреблять","vi":"tiêu thụ","fa":"مصرف کنند","examples":[{"de":"Viele Menschen konsumieren zu viel Zucker.","en":"Many people consume too much sugar.","ru":"Многие люди потребляют слишком много сахара.","vi":"Nhiều người tiêu thụ quá nhiều đường.","fa":"بسیاری از مردم بیش از حد قند مصرف می کنند."},{"de":"Man sollte Alkohol nur in Maßen konsumieren.","en":"One should only consume alcohol in moderation.","ru":"Алкоголь следует потреблять только в меру.","vi":"Man sollte Alkohol nur ở Maßen konsumieren.","fa":"فقط باید الکل را در حد اعتدال مصرف کنید."}]},{"word":"der Kontakt","en":"contact","ru":"контакт","vi":"liên hệ","fa":"تماس","examples":[{"de":"Wir haben seit Jahren keinen Kontakt mehr.","en":"We haven't had any contact for years.","ru":"У нас уже много лет нет контакта.","vi":"Chúng tôi đã không liên lạc trong nhiều năm.","fa":"ما سال هاست که هیچ ارتباطی با هم نداریم."},{"de":"Bitte nehmen Sie Kontakt mit uns auf.","en":"Please get in touch with us.","ru":"Пожалуйста, свяжитесь с нами.","vi":"Vui lòng liên hệ với chúng tôi.","fa":"لطفا با ما تماس بگیرید."}]},{"word":"das Konto","en":"(bank) account","ru":"счёт (банковский)","vi":"tài khoản","fa":"حساب کاربری","examples":[{"de":"Ich habe mein Konto bei der Sparkasse.","en":"I have my account at the savings bank.","ru":"У меня счёт в сберегательной кассе.","vi":"Tôi có tài khoản ở ngân hàng tiết kiệm.","fa":"من حسابم را در بانک پس انداز دارم."},{"de":"Das Geld wurde auf mein Konto überwiesen.","en":"The money was transferred to my account.","ru":"Деньги были переведены на мой счёт.","vi":"Tiền đã được chuyển vào tài khoản của tôi.","fa":"پول به حساب من واریز شد."}]},{"word":"kontrollieren","en":"to check, control","ru":"проверять, контролировать","vi":"kiểm soát","fa":"کنترل کنید","examples":[{"de":"Der Lehrer kontrolliert die Hausaufgaben.","en":"The teacher checks the homework.","ru":"Учитель проверяет домашнее задание.","vi":"The teacher checks the homework.","fa":"معلم تکالیف را بررسی می کند."},{"de":"An der Grenze wurden unsere Pässe kontrolliert.","en":"Our passports were checked at the border.","ru":"На границе проверили наши паспорта.","vi":"Hộ chiếu của chúng tôi đã được kiểm tra ở biên giới.","fa":"پاسپورت های ما در مرز چک شد."}]},{"word":"das Konzert","en":"concert","ru":"концерт","vi":"buổi hòa nhạc","fa":"کنسرت","examples":[{"de":"Wir waren gestern auf einem tollen Konzert.","en":"We were at a great concert yesterday.","ru":"Вчера мы были на отличном концерте.","vi":"Chúng tôi đã đi đến một buổi hòa nhạc tuyệt vời ngày hôm qua.","fa":"دیروز به یک کنسرت عالی رفتیم."},{"de":"Die Band gibt nächsten Monat ein Konzert.","en":"The band is giving a concert next month.","ru":"В следующем месяце группа даёт концерт.","vi":"Ban nhạc sẽ tổ chức buổi hòa nhạc vào tháng tới.","fa":"گروه در ماه آینده کنسرت برگزار می کند."}]},{"word":"der Kopf","en":"head","ru":"голова","vi":"cái đầu","fa":"سر","examples":[{"de":"Mir tut der Kopf weh.","en":"My head hurts.","ru":"У меня болит голова.","vi":"Đầu tôi đau quá.","fa":"سرم درد میکنه"},{"de":"Er schüttelte den Kopf.","en":"He shook his head.","ru":"Он покачал головой.","vi":"Anh lắc đầu.","fa":"سرش را تکان داد."}]},{"word":"kopieren","en":"to copy","ru":"копировать","vi":"sao chép","fa":"کپی کنید","examples":[{"de":"Kannst du diese Seite für mich kopieren?","en":"Can you copy this page for me?","ru":"Можешь скопировать для меня эту страницу?","vi":"Can you copy this page for me?","fa":"آیا می توانید این صفحه را برای من کپی کنید؟"},{"de":"Er hat den Text einfach kopiert.","en":"He simply copied the text.","ru":"Он просто скопировал текст.","vi":"Anh ấy chỉ đơn giản là sao chép văn bản.","fa":"او به سادگی متن را کپی کرد."}]},{"word":"der Körper","en":"body","ru":"тело","vi":"cơ thể","fa":"بدن","examples":[{"de":"Sport ist gut für den Körper.","en":"Sport is good for the body.","ru":"Спорт полезен для тела.","vi":"Thể thao tốt cho cơ thể.","fa":"ورزش برای بدن مفید است."},{"de":"Nach dem Training spürte sie jeden Muskel im Körper.","en":"After the workout she felt every muscle in her body.","ru":"После тренировки она чувствовала каждую мышцу тела.","vi":"Sau khi tập luyện, cô cảm nhận được từng cơ bắp trên cơ thể mình.","fa":"او پس از تمرین، تمام ماهیچه های بدنش را حس کرد."}]},{"word":"korrekt","en":"correct","ru":"правильный, корректный","vi":"đúng","fa":"درست است","examples":[{"de":"Ihre Antwort war völlig korrekt.","en":"Her answer was completely correct.","ru":"Её ответ был полностью правильным.","vi":"Câu trả lời của bạn đã hoàn toàn chính xác.","fa":"پاسخ شما کاملا درست بود"},{"de":"Bitte füllen Sie das Formular korrekt aus.","en":"Please fill out the form correctly.","ru":"Пожалуйста, заполните бланк правильно.","vi":"Vui lòng điền vào mẫu một cách chính xác.","fa":"لطفا فرم را به درستی پر کنید."}]},{"word":"der Korridor","en":"corridor, hallway","ru":"коридор","vi":"the corridor","fa":"راهرو","examples":[{"de":"Die Zimmer liegen alle am selben Korridor.","en":"All the rooms are on the same corridor.","ru":"Все комнаты расположены в одном коридоре.","vi":"Các phòng đều nằm trên cùng một hành lang.","fa":"اتاق ها همه در یک راهرو قرار دارند."},{"de":"Im Korridor hängen viele Bilder.","en":"Many pictures hang in the corridor.","ru":"В коридоре висит много картин.","vi":"Có rất nhiều bức tranh được treo ở hành lang.","fa":"عکس های زیادی در راهرو آویزان است."}]},{"word":"korrigieren","en":"to correct","ru":"исправлять","vi":"đúng","fa":"درست است","examples":[{"de":"Der Lehrer korrigiert die Klassenarbeiten am Wochenende.","en":"The teacher corrects the tests over the weekend.","ru":"Учитель проверяет контрольные на выходных.","vi":"Giáo viên sửa bài tập của lớp vào cuối tuần.","fa":"معلم کار کلاس را در آخر هفته تصحیح می کند."},{"de":"Kannst du meinen Fehler korrigieren?","en":"Can you correct my mistake?","ru":"Можешь исправить мою ошибку?","vi":"Bạn có thể sửa lỗi của tôi không?","fa":"آیا می توانید اشتباه من را اصلاح کنید؟"}]},{"word":"kosten","en":"to cost","ru":"стоить","vi":"chi phí","fa":"هزینه","examples":[{"de":"Wie viel kostet das Buch?","en":"How much does the book cost?","ru":"Сколько стоит эта книга?","vi":"Cuốn sách có giá bao nhiêu?","fa":"قیمت کتاب چقدر است؟"},{"de":"Die Reparatur hat viel Geld gekostet.","en":"The repair cost a lot of money.","ru":"Ремонт стоил много денег.","vi":"Việc sửa chữa tốn rất nhiều tiền.","fa":"تعمیر هزینه زیادی دارد."}]},{"word":"kostenlos","en":"free (of charge)","ru":"бесплатный","vi":"miễn phí","fa":"رایگان","examples":[{"de":"Der Eintritt ins Museum ist heute kostenlos.","en":"Admission to the museum is free today.","ru":"Вход в музей сегодня бесплатный.","vi":"Vào cửa bảo tàng ngày hôm nay là miễn phí.","fa":"ورود به موزه امروز رایگان است."},{"de":"Die App kann man kostenlos herunterladen.","en":"You can download the app for free.","ru":"Приложение можно скачать бесплатно.","vi":"Ứng dụng có thể được tải xuống miễn phí.","fa":"برنامه را می توان به صورت رایگان دانلود کرد."}]},{"word":"das Kostüm","en":"costume; (women's) suit","ru":"костюм (маскарадный); женский костюм","vi":"trang phục","fa":"لباس","examples":[{"de":"Zu Karneval trägt sie ein buntes Kostüm.","en":"At carnival she wears a colorful costume.","ru":"На карнавале она носит яркий костюм.","vi":"Cô mặc một bộ trang phục đầy màu sắc tại lễ hội.","fa":"او در کارناوال یک لباس رنگارنگ می پوشد."},{"de":"Sie kaufte sich ein neues Kostüm für die Arbeit.","en":"She bought herself a new suit for work.","ru":"Она купила себе новый костюм для работы.","vi":"Cô ấy mua một bộ trang phục mới để đi làm.","fa":"او یک لباس جدید برای کار خرید."}]},{"word":"die Kraft","en":"strength, power","ru":"сила","vi":"sức mạnh","fa":"قدرت","examples":[{"de":"Er hat nicht mehr genug Kraft zum Heben.","en":"He no longer has enough strength to lift it.","ru":"У него больше не хватает сил, чтобы поднять это.","vi":"Anh không còn đủ sức để nâng nữa.","fa":"او دیگر قدرت کافی برای بلند کردن ندارد."},{"de":"Die Kraft des Windes war beeindruckend.","en":"The power of the wind was impressive.","ru":"Сила ветра была впечатляющей.","vi":"Sức mạnh của gió thật ấn tượng.","fa":"قدرت باد چشمگیر بود."}]},{"word":"das Kraftfahrzeug","en":"motor vehicle","ru":"автотранспортное средство","vi":"chiếc xe cơ giới","fa":"وسیله نقلیه موتوری","examples":[{"de":"Jedes Kraftfahrzeug braucht ein amtliches Kennzeichen.","en":"Every motor vehicle needs an official license plate.","ru":"Каждое автотранспортное средство должно иметь номерной знак.","vi":"Mọi phương tiện cơ giới đều cần có biển số chính thức.","fa":"هر وسیله نقلیه موتوری نیاز به پلاک رسمی دارد."},{"de":"Das Kraftfahrzeug wurde beim TÜV geprüft.","en":"The motor vehicle was inspected at the TÜV.","ru":"Автотранспортное средство прошло техосмотр.","vi":"Chiếc xe cơ giới đã được thử nghiệm bởi TÜV.","fa":"وسیله نقلیه موتوری توسط TÜV آزمایش شد."}]},{"word":"das Kraftwerk","en":"power plant","ru":"электростанция","vi":"nhà máy điện","fa":"نیروگاه","examples":[{"de":"Das Kraftwerk versorgt die ganze Region mit Strom.","en":"The power plant supplies the whole region with electricity.","ru":"Электростанция снабжает электричеством весь регион.","vi":"Nhà máy điện cung cấp điện cho toàn khu vực.","fa":"نیروگاه برق کل منطقه را تامین می کند."},{"de":"Ein neues Kraftwerk wird außerhalb der Stadt gebaut.","en":"A new power plant is being built outside the city.","ru":"За городом строится новая электростанция.","vi":"Một nhà máy điện mới đang được xây dựng bên ngoài thành phố.","fa":"یک نیروگاه جدید در خارج از شهر در حال ساخت است."}]},{"word":"krank","en":"sick, ill","ru":"больной","vi":"bị bệnh","fa":"بیمار","examples":[{"de":"Mein Sohn ist heute krank und bleibt zu Hause.","en":"My son is sick today and is staying home.","ru":"Мой сын сегодня болен и остаётся дома.","vi":"Hôm nay con trai tôi bị ốm và đang ở nhà.","fa":"پسرم امروز مریض است و در خانه است."},{"de":"Sie war letzte Woche schwer krank.","en":"She was seriously ill last week.","ru":"На прошлой неделе она была тяжело больна.","vi":"Tuần trước cô ấy bị ốm nặng.","fa":"او هفته گذشته به شدت بیمار بود."}]},{"word":"die Krankenschwester","en":"nurse","ru":"медсестра","vi":"y tá","fa":"پرستار","examples":[{"de":"Die Krankenschwester kümmert sich um die Patienten.","en":"The nurse takes care of the patients.","ru":"Медсестра заботится о пациентах.","vi":"Y tá chăm sóc bệnh nhân.","fa":"پرستار از بیماران مراقبت می کند."},{"de":"Sie möchte Krankenschwester werden.","en":"She wants to become a nurse.","ru":"Она хочет стать медсестрой.","vi":"Cô ấy muốn trở thành một y tá.","fa":"او می خواهد پرستار شود."}]},{"word":"die Krankheit","en":"illness; disease","ru":"болезнь","vi":"căn bệnh","fa":"بیماری","examples":[{"de":"Diese Krankheit ist zum Glück nicht ansteckend.","en":"Fortunately, this illness is not contagious.","ru":"К счастью, эта болезнь не заразна.","vi":"May mắn thay, căn bệnh này không lây nhiễm.","fa":"خوشبختانه این بیماری مسری نیست."},{"de":"Er musste seine Reise wegen einer Krankheit absagen.","en":"He had to cancel his trip because of an illness.","ru":"Ему пришлось отменить поездку из-за болезни.","vi":"Anh ấy phải hủy chuyến đi vì bệnh.","fa":"او مجبور شد سفر خود را به دلیل بیماری لغو کند."}]},{"word":"kreativ","en":"creative","ru":"творческий, креативный","vi":"sáng tạo","fa":"خلاق","examples":[{"de":"Bei dieser Aufgabe kannst du kreativ sein.","en":"You can be creative with this task.","ru":"В этом задании ты можешь проявить креативность.","vi":"Bạn có thể sáng tạo với nhiệm vụ này.","fa":"شما می توانید با این کار خلاق باشید."},{"de":"Sie hat viele kreative Ideen für das Projekt.","en":"She has many creative ideas for the project.","ru":"У неё много креативных идей для проекта.","vi":"Cô ấy có nhiều ý tưởng sáng tạo cho dự án.","fa":"او ایده های خلاقانه زیادی برای این پروژه دارد."}]},{"word":"der Kredit","en":"loan, credit","ru":"кредит","vi":"tín dụng","fa":"اعتبار","examples":[{"de":"Sie hat einen Kredit für das neue Auto aufgenommen.","en":"She took out a loan for the new car.","ru":"Она взяла кредит на новую машину.","vi":"Cô ấy đã vay một khoản tiền để mua chiếc xe mới.","fa":"او برای ماشین جدید وام گرفت."},{"de":"Die Bank hat ihm den Kredit genehmigt.","en":"The bank approved his loan.","ru":"Банк одобрил ему кредит.","vi":"Ngân hàng đã chấp thuận khoản vay cho anh ta.","fa":"بانک این وام را برای او تایید کرد."}]},{"word":"der Kreis","en":"circle","ru":"круг","vi":"the circle","fa":"دایره","examples":[{"de":"Die Kinder stehen im Kreis.","en":"The children are standing in a circle.","ru":"Дети стоят в кругу.","vi":"Trẻ đứng thành vòng tròn.","fa":"بچه ها در یک دایره ایستاده اند."},{"de":"Er malte einen großen Kreis auf das Papier.","en":"He drew a large circle on the paper.","ru":"Он нарисовал большой круг на бумаге.","vi":"Anh vẽ một vòng tròn lớn lên giấy.","fa":"دایره بزرگی روی کاغذ کشید."}]},{"word":"das Kreuz","en":"cross","ru":"крест","vi":"cây thánh giá","fa":"صلیب","examples":[{"de":"Über dem Altar hängt ein großes Kreuz.","en":"A large cross hangs above the altar.","ru":"Над алтарём висит большой крест.","vi":"Một cây thánh giá lớn treo phía trên bàn thờ.","fa":"صلیب بزرگی بالای محراب آویزان است."},{"de":"Setzen Sie ein Kreuz bei der richtigen Antwort.","en":"Put a cross next to the correct answer.","ru":"Поставьте крестик рядом с правильным ответом.","vi":"Hãy gạch chéo trước câu trả lời đúng.","fa":"در کنار پاسخ صحیح یک ضربدر قرار دهید."}]},{"word":"der Krieg","en":"war","ru":"война","vi":"cuộc chiến","fa":"جنگ","examples":[{"de":"Der Krieg dauerte mehrere Jahre.","en":"The war lasted several years.","ru":"Война длилась несколько лет.","vi":"Cuộc chiến kéo dài vài năm.","fa":"جنگ چندین سال طول کشید."},{"de":"Viele Menschen mussten wegen des Krieges fliehen.","en":"Many people had to flee because of the war.","ru":"Многим людям пришлось бежать из-за войны.","vi":"Nhiều người phải chạy trốn vì chiến tranh.","fa":"بسیاری از مردم به دلیل جنگ مجبور به فرار شدند."}]},{"word":"kriegen","en":"to get, receive (colloquial)","ru":"получать","vi":"nhận được","fa":"دریافت کنید","examples":[{"de":"Ich habe zum Geburtstag ein Fahrrad gekriegt.","en":"I got a bike for my birthday.","ru":"На день рождения я получил велосипед.","vi":"Tôi có một chiếc xe đạp vào ngày sinh nhật của tôi.","fa":"برای تولدم دوچرخه گرفتم."},{"de":"Kriegst du morgen frei?","en":"Are you getting a day off tomorrow?","ru":"Ты получишь завтра выходной?","vi":"Ngày mai bạn có rảnh không?","fa":"فردا آزاد هستی؟"}]},{"word":"der Krimi","en":"crime novel, thriller","ru":"детектив (фильм/книга)","vi":"the crime thriller","fa":"تریلر جنایی","examples":[{"de":"Ich lese gerade einen spannenden Krimi.","en":"I'm currently reading an exciting crime novel.","ru":"Я сейчас читаю захватывающий детектив.","vi":"Tôi hiện đang đọc một cuốn tiểu thuyết tội phạm thú vị.","fa":"در حال حاضر مشغول خواندن یک رمان جنایی هیجان انگیز هستم."},{"de":"Im Fernsehen läuft heute ein neuer Krimi.","en":"A new crime show is on TV tonight.","ru":"Сегодня по телевизору идёт новый детектив.","vi":"Có một bộ phim tội phạm mới trên TV ngày hôm nay.","fa":"امروز یک درام جنایی جدید در تلویزیون پخش می شود."}]},{"word":"die Kriminalpolizei","en":"criminal investigation department","ru":"уголовный розыск","vi":"cảnh sát hình sự","fa":"پلیس جنایی","examples":[{"de":"Die Kriminalpolizei ermittelt in dem Mordfall.","en":"The criminal investigation department is investigating the murder case.","ru":"Уголовный розыск расследует дело об убийстве.","vi":"Cảnh sát hình sự đang điều tra vụ án giết người.","fa":"پلیس جنایی در حال بررسی پرونده قتل است."},{"de":"Er arbeitet seit zehn Jahren bei der Kriminalpolizei.","en":"He has worked for the criminal investigation department for ten years.","ru":"Он работает в уголовном розыске уже десять лет.","vi":"Anh ta đã làm việc cho cục điều tra tội phạm được mười năm.","fa":"او ده سال است که در اداره تحقیقات جنایی کار می کند."}]},{"word":"kriminell","en":"criminal","ru":"криминальный, преступный","vi":"tội phạm","fa":"جنایتکار","examples":[{"de":"Er wurde in eine kriminelle Bande verwickelt.","en":"He got involved with a criminal gang.","ru":"Он оказался втянут в преступную банду.","vi":"Anh ta vướng vào một băng nhóm tội phạm.","fa":"او درگیر یک باند جنایتکار شد."},{"de":"Solches Verhalten ist eindeutig kriminell.","en":"Such behavior is clearly criminal.","ru":"Такое поведение однозначно является преступным.","vi":"Hành vi như vậy rõ ràng là tội phạm.","fa":"چنین رفتاری آشکارا مجرمانه است."}]},{"word":"die Krise","en":"crisis","ru":"кризис","vi":"cuộc khủng hoảng","fa":"بحران","examples":[{"de":"Das Land steckt in einer schweren Krise.","en":"The country is in a severe crisis.","ru":"Страна переживает тяжёлый кризис.","vi":"Đất nước đang trong tình trạng khủng hoảng nghiêm trọng.","fa":"کشور در یک بحران جدی قرار دارد."},{"de":"Die Firma hat die Krise erfolgreich überstanden.","en":"The company successfully survived the crisis.","ru":"Компания успешно пережила кризис.","vi":"Công ty đã vượt qua khủng hoảng thành công.","fa":"این شرکت با موفقیت از بحران عبور کرد."}]},{"word":"kritisieren","en":"to criticize","ru":"критиковать","vi":"chỉ trích","fa":"انتقاد کنید","examples":[{"de":"Der Chef kritisierte die schlechte Arbeit.","en":"The boss criticized the poor work.","ru":"Начальник раскритиковал плохую работу.","vi":"Ông chủ chỉ trích công việc kém.","fa":"رئیس از کار ضعیف انتقاد کرد."},{"de":"Man sollte nicht immer nur kritisieren.","en":"One shouldn't always just criticize.","ru":"Не стоит всегда только критиковать.","vi":"Bạn không nên lúc nào cũng chỉ trích.","fa":"همیشه نباید فقط انتقاد کرد."}]},{"word":"die Küche","en":"kitchen","ru":"кухня","vi":"nhà bếp","fa":"آشپزخانه","examples":[{"de":"Sie kocht gerade in der Küche.","en":"She is cooking in the kitchen right now.","ru":"Она сейчас готовит на кухне.","vi":"Hiện tại cô đang nấu ăn trong bếp.","fa":"او در حال حاضر در آشپزخانه مشغول آشپزی است."},{"de":"Unsere neue Küche ist sehr modern.","en":"Our new kitchen is very modern.","ru":"Наша новая кухня очень современная.","vi":"Nhà bếp mới của chúng tôi rất hiện đại.","fa":"آشپزخانه جدید ما بسیار مدرن است."}]},{"word":"der Kuchen","en":"cake","ru":"пирог, торт","vi":"cái bánh","fa":"کیک","examples":[{"de":"Meine Oma backt jeden Sonntag einen Kuchen.","en":"My grandma bakes a cake every Sunday.","ru":"Моя бабушка печёт пирог каждое воскресенье.","vi":"Bà tôi nướng bánh vào mỗi Chủ Nhật.","fa":"مادربزرگ من هر یکشنبه یک کیک می پزد."},{"de":"Der Kuchen schmeckt nach Schokolade.","en":"The cake tastes like chocolate.","ru":"Торт на вкус шоколадный.","vi":"Bánh có vị như sôcôla.","fa":"طعم کیک شبیه شکلات است."}]},{"word":"der Kugelschreiber","en":"ballpoint pen","ru":"шариковая ручка","vi":"bút bi","fa":"قلم توپ","examples":[{"de":"Hast du einen Kugelschreiber für mich?","en":"Do you have a pen for me?","ru":"У тебя есть для меня шариковая ручка?","vi":"Bạn có bút cho tôi không?","fa":"آیا برای من قلم داری؟"},{"de":"Der Kugelschreiber schreibt nicht mehr.","en":"The pen doesn't write anymore.","ru":"Ручка больше не пишет.","vi":"Cây bút bi không còn viết được nữa.","fa":"خودکار دیگر نمی نویسد."}]},{"word":"kühl","en":"cool","ru":"прохладный","vi":"mát mẻ","fa":"باحال","examples":[{"de":"Abends wird es hier ziemlich kühl.","en":"It gets quite cool here in the evenings.","ru":"По вечерам здесь становится довольно прохладно.","vi":"Buổi tối ở đây khá mát mẻ.","fa":"عصرها اینجا خیلی خنک می شود."},{"de":"Bewahren Sie den Saft kühl auf.","en":"Keep the juice cool.","ru":"Храните сок в прохладном месте.","vi":"Giữ nước ép mát.","fa":"آب میوه را خنک نگه دارید."}]},{"word":"die Kultur","en":"culture","ru":"культура","vi":"văn hóa","fa":"فرهنگ","examples":[{"de":"Er interessiert sich sehr für fremde Kulturen.","en":"He is very interested in foreign cultures.","ru":"Он очень интересуется чужими культурами.","vi":"Anh ấy rất quan tâm đến văn hóa nước ngoài.","fa":"او علاقه زیادی به فرهنگ های خارجی دارد."},{"de":"Musik und Kunst gehören zur Kultur eines Landes.","en":"Music and art are part of a country's culture.","ru":"Музыка и искусство — часть культуры страны.","vi":"Âm nhạc và nghệ thuật là một phần của nền văn hóa của một quốc gia.","fa":"موسیقی و هنر بخشی از فرهنگ یک کشور است."}]},{"word":"der Kunde","en":"customer","ru":"клиент","vi":"khách hàng","fa":"مشتری","examples":[{"de":"Der Kunde ist mit dem Service zufrieden.","en":"The customer is satisfied with the service.","ru":"Клиент доволен обслуживанием.","vi":"Khách hàng hài lòng với dịch vụ.","fa":"مشتری از خدمات راضی است."},{"de":"Wir haben viele treue Kunden.","en":"We have many loyal customers.","ru":"У нас много постоянных клиентов.","vi":"Chúng tôi có nhiều khách hàng trung thành.","fa":"ما مشتریان وفادار زیادی داریم."}]},{"word":"kündigen","en":"to quit, give notice, terminate","ru":"увольняться, расторгать (договор)","vi":"hủy bỏ","fa":"لغو","examples":[{"de":"Er hat seinen Job gekündigt.","en":"He quit his job.","ru":"Он уволился с работы.","vi":"Anh ấy đã nghỉ việc.","fa":"کارش را رها کرد."},{"de":"Die Firma musste ihm kündigen.","en":"The company had to lay him off.","ru":"Компании пришлось его уволить.","vi":"Công ty đã phải sa thải anh ta.","fa":"شرکت مجبور شد او را اخراج کند."}]},{"word":"die Kunst","en":"art","ru":"искусство","vi":"nghệ thuật","fa":"هنر","examples":[{"de":"Sie interessiert sich sehr für moderne Kunst.","en":"She is very interested in modern art.","ru":"Она очень интересуется современным искусством.","vi":"Cô ấy rất quan tâm đến nghệ thuật hiện đại.","fa":"او علاقه زیادی به هنر مدرن دارد."},{"de":"Im Museum kann man alte Kunst bewundern.","en":"You can admire old art in the museum.","ru":"В музее можно полюбоваться старинным искусством.","vi":"Bạn có thể chiêm ngưỡng nghệ thuật cũ trong bảo tàng.","fa":"در موزه می توانید هنرهای قدیمی را تحسین کنید."}]},{"word":"künstlich","en":"artificial","ru":"искусственный","vi":"nhân tạo","fa":"مصنوعی","examples":[{"de":"Das Getränk enthält künstliche Aromen.","en":"The drink contains artificial flavors.","ru":"Напиток содержит искусственные ароматизаторы.","vi":"Đồ uống có chứa hương vị nhân tạo.","fa":"این نوشیدنی حاوی طعم دهنده های مصنوعی است."},{"de":"Der Baum im Büro ist künstlich.","en":"The tree in the office is artificial.","ru":"Дерево в офисе искусственное.","vi":"Cây trong văn phòng là cây nhân tạo.","fa":"درخت در دفتر مصنوعی است."}]},{"word":"der Kurs","en":"course (class); exchange rate","ru":"курс (занятия); валютный курс","vi":"khóa học","fa":"دوره","examples":[{"de":"Sie besucht einen Kurs für Deutsch als Fremdsprache.","en":"She is attending a German-as-a-foreign-language course.","ru":"Она посещает курс немецкого как иностранного.","vi":"Cô ấy đang tham gia một khóa học tiếng Đức như một ngoại ngữ.","fa":"او در دوره ای برای آلمانی به عنوان زبان خارجی شرکت می کند."},{"de":"Der Kurs des Euro ist heute gestiegen.","en":"The euro exchange rate rose today.","ru":"Курс евро сегодня вырос.","vi":"Tỷ giá đồng euro hôm nay tăng.","fa":"نرخ یورو امروز افزایش یافت."}]},{"word":"die Kurve","en":"curve, bend","ru":"поворот, изгиб","vi":"đường cong","fa":"منحنی","examples":[{"de":"Fahren Sie in der Kurve langsamer.","en":"Drive slower on the bend.","ru":"На повороте езжайте медленнее.","vi":"Lái xe chậm hơn khi vào cua.","fa":"هنگام پیچیدن آهسته تر رانندگی کنید."},{"de":"Die Straße hat viele enge Kurven.","en":"The road has many sharp curves.","ru":"На дороге много крутых поворотов.","vi":"Con đường có nhiều khúc cua gấp.","fa":"جاده پیچ های بسیار تنگ دارد."}]},{"word":"kurz","en":"short","ru":"короткий","vi":"ngắn","fa":"کوتاه","examples":[{"de":"Sie hat sich die Haare kurz geschnitten.","en":"She cut her hair short.","ru":"Она коротко подстригла волосы.","vi":"Cô cắt tóc ngắn.","fa":"موهایش را کوتاه کرد."},{"de":"Ich mache nur eine kurze Pause.","en":"I'm just taking a short break.","ru":"Я сделаю лишь короткий перерыв.","vi":"Tôi chỉ đang nghỉ ngơi một lát thôi.","fa":"من فقط یک استراحت کوتاه می کنم."}]},{"word":"kürzlich","en":"recently","ru":"недавно","vi":"gần đây","fa":"اخیرا","examples":[{"de":"Wir haben uns erst kürzlich kennengelernt.","en":"We only met recently.","ru":"Мы познакомились совсем недавно.","vi":"Chúng tôi chỉ mới gặp nhau gần đây thôi.","fa":"ما اخیراً همدیگر را دیدیم."},{"de":"Kürzlich habe ich ein interessantes Buch gelesen.","en":"I recently read an interesting book.","ru":"Недавно я прочитал интересную книгу.","vi":"Gần đây tôi đọc được một cuốn sách thú vị.","fa":"اخیرا کتاب جالبی خواندم."}]},{"word":"der Kuss","en":"kiss","ru":"поцелуй","vi":"nụ hôn","fa":"بوسه","examples":[{"de":"Sie gab ihm einen Kuss auf die Wange.","en":"She gave him a kiss on the cheek.","ru":"Она поцеловала его в щёку.","vi":"Cô trao cho anh một nụ hôn lên má.","fa":"بوسه ای بر گونه اش زد."},{"de":"Zum Abschied gab es einen letzten Kuss.","en":"There was one last kiss before parting.","ru":"На прощание был последний поцелуй.","vi":"Có một nụ hôn cuối cùng để nói lời tạm biệt.","fa":"آخرین بوسه برای خداحافظی بود."}]},{"word":"küssen","en":"to kiss","ru":"целовать","vi":"hôn","fa":"بوسه","examples":[{"de":"Er küsste sie zum Abschied.","en":"He kissed her goodbye.","ru":"Он поцеловал её на прощание.","vi":"Anh hôn tạm biệt cô.","fa":"او را بوسید خداحافظی."},{"de":"Die beiden küssten sich am Bahnhof.","en":"The two of them kissed at the train station.","ru":"Они поцеловались на вокзале.","vi":"Hai người hôn nhau ở ga tàu.","fa":"آن دو در ایستگاه قطار بوسیدند."}]},{"word":"die Küste","en":"the coast","ru":"побережье","vi":"bờ biển","fa":"ساحل","examples":[{"de":"Wir haben unseren Urlaub an der Küste verbracht.","en":"We spent our vacation on the coast.","ru":"Мы провели отпуск на побережье.","vi":"Chúng tôi đã dành kỳ nghỉ của mình trên bờ biển.","fa":"تعطیلاتمان را در ساحل گذراندیم."},{"de":"Die Stadt liegt direkt an der Küste.","en":"The city is located right on the coast.","ru":"Город расположен прямо на побережье.","vi":"Thành phố nằm ngay trên bờ biển.","fa":"این شهر مستقیماً در ساحل واقع شده است."}]},{"word":"das Kuvert","en":"the envelope","ru":"конверт","vi":"phong bì","fa":"پاکت نامه","examples":[{"de":"Sie steckte den Brief in ein Kuvert.","en":"She put the letter in an envelope.","ru":"Она положила письмо в конверт.","vi":"Cô bỏ lá thư vào phong bì.","fa":"نامه را در یک پاکت گذاشت."},{"de":"Auf dem Kuvert stand keine Adresse.","en":"There was no address on the envelope.","ru":"На конверте не было адреса.","vi":"Trên phong bì không có địa chỉ.","fa":"هیچ آدرسی روی پاکت نبود."}]},{"word":"lächeln","en":"to smile","ru":"улыбаться","vi":"mỉm cười","fa":"لبخند بزن","examples":[{"de":"Das Kind lächelte glücklich.","en":"The child smiled happily.","ru":"Ребёнок счастливо улыбался.","vi":"Đứa trẻ mỉm cười hạnh phúc.","fa":"کودک با خوشحالی لبخند زد."},{"de":"Sie lächelte mir freundlich zu.","en":"She smiled at me kindly.","ru":"Она приветливо улыбнулась мне.","vi":"Cô ấy mỉm cười thân thiện với tôi.","fa":"او با مهربانی به من لبخند زد."}]},{"word":"lachen","en":"to laugh","ru":"смеяться","vi":"cười","fa":"بخند","examples":[{"de":"Wir haben den ganzen Abend gelacht.","en":"We laughed the whole evening.","ru":"Мы смеялись весь вечер.","vi":"Chúng tôi cười suốt buổi tối.","fa":"تمام غروب خندیدیم."},{"de":"Er musste über den Witz laut lachen.","en":"He had to laugh loudly at the joke.","ru":"Он громко засмеялся над шуткой.","vi":"Anh phải cười lớn trước câu nói đùa đó.","fa":"او مجبور شد به این شوخی بلند بخندد."}]},{"word":"der Laden","en":"the shop; the store","ru":"магазин","vi":"cửa hàng","fa":"فروشگاه","examples":[{"de":"Der Laden an der Ecke verkauft frisches Obst.","en":"The shop on the corner sells fresh fruit.","ru":"Магазин на углу продаёт свежие фрукты.","vi":"Cửa hàng góc bán trái cây tươi.","fa":"مغازه گوشه ای میوه تازه می فروشد."},{"de":"Der Laden öffnet um acht Uhr.","en":"The store opens at eight o'clock.","ru":"Магазин открывается в восемь часов.","vi":"Cửa hàng mở cửa lúc tám giờ.","fa":"مغازه ساعت هشت باز می شود."}]},{"word":"die Lage","en":"the situation; the location","ru":"положение; ситуация","vi":"vị trí","fa":"مکان","examples":[{"de":"Die wirtschaftliche Lage hat sich verbessert.","en":"The economic situation has improved.","ru":"Экономическая ситуация улучшилась.","vi":"Tình hình kinh tế đã được cải thiện.","fa":"وضعیت اقتصادی بهتر شده است."},{"de":"Das Hotel hat eine ruhige Lage am See.","en":"The hotel has a quiet location by the lake.","ru":"Отель имеет спокойное расположение у озера.","vi":"Khách sạn có vị trí yên tĩnh bên hồ.","fa":"این هتل دارای مکانی آرام در کنار دریاچه است."}]},{"word":"das Lager","en":"the warehouse; the camp","ru":"склад; лагерь","vi":"nhà kho","fa":"انبار","examples":[{"de":"Die Ware wird im Lager aufbewahrt.","en":"The goods are stored in the warehouse.","ru":"Товар хранится на складе.","vi":"Hàng hóa được lưu trữ trong kho.","fa":"کالا در انبار نگهداری می شود."},{"de":"Die Kinder verbrachten die Ferien in einem Lager.","en":"The children spent the holidays at a camp.","ru":"Дети провели каникулы в лагере.","vi":"Những đứa trẻ đã trải qua những ngày nghỉ trong một trại.","fa":"بچه ها تعطیلات را در کمپ سپری کردند."}]},{"word":"die Lampe","en":"the lamp","ru":"лампа","vi":"cái đèn","fa":"لامپ","examples":[{"de":"Bitte schalte die Lampe an, es ist dunkel.","en":"Please turn on the lamp, it's dark.","ru":"Пожалуйста, включи лампу, темно.","vi":"Làm ơn bật đèn lên, trời tối quá.","fa":"لطفا لامپ را روشن کنید، تاریک است."},{"de":"Die Lampe auf dem Schreibtisch ist kaputt.","en":"The lamp on the desk is broken.","ru":"Лампа на письменном столе сломана.","vi":"Đèn trên bàn bị hỏng.","fa":"لامپ روی میز خراب است."}]},{"word":"das Land","en":"the country; the land","ru":"страна; земля","vi":"đất nước","fa":"کشور","examples":[{"de":"Sie reist gerne in fremde Länder.","en":"She likes to travel to foreign countries.","ru":"Она любит путешествовать в чужие страны.","vi":"Cô thích đi du lịch nước ngoài.","fa":"او از سفر به کشورهای خارجی لذت می برد."},{"de":"Meine Großeltern leben auf dem Land.","en":"My grandparents live in the countryside.","ru":"Мои бабушка и дедушка живут в деревне.","vi":"Ông bà tôi sống ở quê.","fa":"پدربزرگ و مادربزرگ من در کشور زندگی می کنند."}]},{"word":"landen","en":"to land","ru":"приземляться","vi":"đất đai","fa":"زمین","examples":[{"de":"Das Flugzeug landet in zehn Minuten.","en":"The plane lands in ten minutes.","ru":"Самолёт приземлится через десять минут.","vi":"Máy bay sẽ hạ cánh trong mười phút nữa.","fa":"هواپیما ده دقیقه دیگر فرود می آید."},{"de":"Wir sind sicher in Wien gelandet.","en":"We landed safely in Vienna.","ru":"Мы благополучно приземлились в Вене.","vi":"Chúng tôi hạ cánh an toàn ở Vienna.","fa":"به سلامت در وین فرود آمدیم."}]},{"word":"die Landschaft","en":"the landscape","ru":"пейзаж; ландшафт","vi":"phong cảnh","fa":"چشم انداز","examples":[{"de":"Die Landschaft in den Alpen ist wunderschön.","en":"The landscape in the Alps is beautiful.","ru":"Пейзаж в Альпах прекрасен.","vi":"Phong cảnh ở dãy Alps rất đẹp.","fa":"چشم انداز کوه های آلپ زیباست."},{"de":"Wir haben die Landschaft vom Zug aus fotografiert.","en":"We photographed the landscape from the train.","ru":"Мы фотографировали пейзаж из поезда.","vi":"Chúng tôi chụp ảnh phong cảnh từ tàu.","fa":"ما از قطار از منظره عکس گرفتیم."}]},{"word":"lang","en":"long","ru":"длинный","vi":"dài","fa":"طولانی","examples":[{"de":"Sie hat lange, dunkle Haare.","en":"She has long, dark hair.","ru":"У неё длинные тёмные волосы.","vi":"Cô ấy có mái tóc dài và đen.","fa":"او موهای بلند و تیره ای دارد."},{"de":"Der Weg zur Arbeit ist sehr lang.","en":"The way to work is very long.","ru":"Дорога на работу очень длинная.","vi":"Con đường đi làm còn rất dài.","fa":"راه کار بسیار طولانی است."}]},{"word":"lange","en":"for a long time; long","ru":"долго","vi":"dài","fa":"طولانی","examples":[{"de":"Wir haben lange auf den Bus gewartet.","en":"We waited for the bus for a long time.","ru":"Мы долго ждали автобус.","vi":"Chúng tôi đã đợi xe buýt rất lâu.","fa":"مدت زیادی منتظر اتوبوس بودیم."},{"de":"Wie lange dauert der Film?","en":"How long does the movie last?","ru":"Сколько времени длится фильм?","vi":"Phim dài bao nhiêu?","fa":"مدت زمان فیلم چقدر است؟"}]},{"word":"langsam","en":"slow; slowly","ru":"медленный; медленно","vi":"từ từ","fa":"به آرامی","examples":[{"de":"Bitte sprich langsam, ich verstehe dich sonst nicht.","en":"Please speak slowly, otherwise I don't understand you.","ru":"Пожалуйста, говори медленно, иначе я тебя не пойму.","vi":"Hãy nói chậm lại, nếu không tôi sẽ không hiểu bạn.","fa":"لطفا آهسته صحبت کنید وگرنه من شما را درک نمی کنم."},{"de":"Der Zug fährt langsam in den Bahnhof ein.","en":"The train is slowly pulling into the station.","ru":"Поезд медленно въезжает на вокзал.","vi":"Đoàn tàu từ từ tiến vào ga.","fa":"قطار به آرامی وارد ایستگاه می شود."}]},{"word":"längst","en":"long ago; a long time ago","ru":"давно; уже давно","vi":"từ lâu rồi","fa":"خیلی وقت پیش","examples":[{"de":"Er wohnt schon längst nicht mehr hier.","en":"He hasn't lived here for a long time already.","ru":"Он уже давно здесь не живёт.","vi":"Anh ấy không còn sống ở đây nữa.","fa":"او دیگر اینجا زندگی نمی کند."},{"de":"Ich habe das Buch längst gelesen.","en":"I read the book a long time ago.","ru":"Я уже давно прочитал эту книгу.","vi":"Tôi đã đọc cuốn sách này từ lâu rồi.","fa":"من کتاب را خیلی وقت پیش خوانده بودم."}]},{"word":"langweilig","en":"boring","ru":"скучный","vi":"nhạt nhẽo","fa":"خسته کننده","examples":[{"de":"Der Vortrag war ziemlich langweilig.","en":"The lecture was quite boring.","ru":"Лекция была довольно скучной.","vi":"Bài giảng khá nhàm chán.","fa":"سخنرانی بسیار خسته کننده بود."},{"de":"Ohne Freunde ist das Wochenende langweilig.","en":"Without friends the weekend is boring.","ru":"Без друзей выходные скучные.","vi":"Cuối tuần thật nhàm chán khi không có bạn bè.","fa":"آخر هفته بدون دوستان خسته کننده است."}]},{"word":"der Lärm","en":"the noise","ru":"шум","vi":"tiếng ồn","fa":"سر و صدا","examples":[{"de":"Der Lärm von der Baustelle stört mich.","en":"The noise from the construction site bothers me.","ru":"Шум со стройки меня раздражает.","vi":"Tiếng ồn từ công trường xây dựng làm tôi khó chịu.","fa":"صدای محل ساخت و ساز آزارم می دهد."},{"de":"Bei so viel Lärm kann ich nicht schlafen.","en":"I can't sleep with so much noise.","ru":"При таком шуме я не могу спать.","vi":"Tôi không thể ngủ được với quá nhiều tiếng ồn.","fa":"با این همه سر و صدا نمیتونم بخوابم"}]},{"word":"lassen","en":"to let; to leave","ru":"оставлять; позволять","vi":"hãy để","fa":"اجازه دهید","examples":[{"de":"Lass mich bitte in Ruhe.","en":"Please leave me alone.","ru":"Оставь меня, пожалуйста, в покое.","vi":"Xin hãy để tôi yên.","fa":"لطفا منو تنها بذار"},{"de":"Ich habe meinen Schirm im Bus gelassen.","en":"I left my umbrella on the bus.","ru":"Я оставил зонт в автобусе.","vi":"Tôi để quên ô trên xe buýt.","fa":"چترم را در اتوبوس جا گذاشتم."}]},{"word":"der Laster","en":"the truck","ru":"грузовик","vi":"phó","fa":"معاون","examples":[{"de":"Der Laster transportiert Möbel.","en":"The truck transports furniture.","ru":"Грузовик перевозит мебель.","vi":"Xe tải chở đồ đạc.","fa":"کامیون حمل اثاثیه را انجام می دهد."},{"de":"Auf der Autobahn fuhr ein großer Laster vor uns.","en":"A big truck was driving in front of us on the highway.","ru":"На автостраде перед нами ехал большой грузовик.","vi":"Một chiếc xe tải lớn chạy trước mặt chúng tôi trên đường cao tốc.","fa":"یک کامیون بزرگ جلوی ما در بزرگراه حرکت کرد."}]},{"word":"laufen","en":"to run; to walk","ru":"бежать; идти пешком","vi":"chạy","fa":"اجرا کنید","examples":[{"de":"Jeden Morgen laufe ich eine Stunde im Park.","en":"Every morning I run for an hour in the park.","ru":"Каждое утро я бегаю час в парке.","vi":"Mỗi buổi sáng tôi chạy bộ một giờ trong công viên.","fa":"هر روز صبح یک ساعت در پارک می دوم."},{"de":"Wir sind zu Fuß zum Bahnhof gelaufen.","en":"We walked to the train station.","ru":"Мы пошли пешком на вокзал.","vi":"Chúng tôi đi bộ đến ga xe lửa.","fa":"به سمت ایستگاه قطار راه افتادیم."}]},{"word":"das Laufwerk","en":"the (disk) drive","ru":"дисковод; накопитель","vi":"ổ đĩa","fa":"درایو","examples":[{"de":"Bitte lege die CD in das Laufwerk ein.","en":"Please put the CD into the drive.","ru":"Пожалуйста, вставь диск в дисковод.","vi":"Vui lòng đưa đĩa CD vào ổ đĩa.","fa":"لطفا سی دی را داخل درایو قرار دهید."},{"de":"Mein Computer hat kein CD-Laufwerk mehr.","en":"My computer no longer has a CD drive.","ru":"В моём компьютере больше нет CD-дисковода.","vi":"Máy tính của tôi không còn ổ đĩa CD nữa.","fa":"کامپیوتر من دیگر درایو سی دی ندارد."}]},{"word":"die Laune","en":"the mood","ru":"настроение","vi":"tâm trạng","fa":"خلق و خوی","examples":[{"de":"Er hat heute schlechte Laune.","en":"He's in a bad mood today.","ru":"У него сегодня плохое настроение.","vi":"Hôm nay anh ấy có tâm trạng không tốt.","fa":"امروز حالش بد است."},{"de":"Gute Musik verbessert meine Laune.","en":"Good music improves my mood.","ru":"Хорошая музыка улучшает моё настроение.","vi":"Âm nhạc hay giúp cải thiện tâm trạng của tôi.","fa":"موسیقی خوب روحیه ام را بهتر می کند."}]},{"word":"laut","en":"loud","ru":"громкий","vi":"ồn ào","fa":"با صدای بلند","examples":[{"de":"Die Musik war viel zu laut.","en":"The music was much too loud.","ru":"Музыка была слишком громкой.","vi":"Âm nhạc quá ồn ào.","fa":"موسیقی خیلی بلند بود"},{"de":"Bitte sprich nicht so laut im Krankenhaus.","en":"Please don't speak so loudly in the hospital.","ru":"Пожалуйста, не говори так громко в больнице.","vi":"Xin đừng nói chuyện lớn tiếng trong bệnh viện.","fa":"لطفا در بیمارستان اینقدر بلند صحبت نکنید."}]},{"word":"der Lautsprecher","en":"the loudspeaker","ru":"громкоговоритель; динамик","vi":"người nói","fa":"سخنران","examples":[{"de":"Die Durchsage kam aus dem Lautsprecher am Bahnsteig.","en":"The announcement came from the loudspeaker on the platform.","ru":"Объявление прозвучало из громкоговорителя на платформе.","vi":"Thông báo được phát ra từ loa trên sân ga.","fa":"این اعلامیه از بلندگوی روی سکو منتشر شد."},{"de":"Wir haben neue Lautsprecher für die Musikanlage gekauft.","en":"We bought new speakers for the stereo system.","ru":"Мы купили новые динамики для музыкальной системы.","vi":"Chúng tôi đã mua loa mới cho hệ thống âm nhạc.","fa":"بلندگوهای جدیدی برای سیستم موسیقی خریدیم."}]},{"word":"leben","en":"to live","ru":"жить","vi":"sống","fa":"زندگی می کنند","examples":[{"de":"Meine Familie lebt in Berlin.","en":"My family lives in Berlin.","ru":"Моя семья живёт в Берлине.","vi":"Gia đình tôi sống ở Berlin.","fa":"خانواده من در برلین زندگی می کنند."},{"de":"Er möchte lange und gesund leben.","en":"He wants to live long and healthily.","ru":"Он хочет жить долго и здорово.","vi":"Ông muốn sống một cuộc sống lâu dài và khỏe mạnh.","fa":"او می خواهد زندگی طولانی و سالمی داشته باشد."}]},{"word":"der Lebenslauf","en":"CV; résumé","ru":"резюме; биография","vi":"CV","fa":"رزومه","examples":[{"de":"Bitte schicken Sie uns Ihren Lebenslauf per E-Mail.","en":"Please send us your CV by email.","ru":"Пожалуйста, пришлите нам своё резюме по электронной почте.","vi":"Vui lòng gửi CV cho chúng tôi qua email.","fa":"لطفا رزومه خود را از طریق ایمیل برای ما ارسال کنید."},{"de":"Sein Lebenslauf ist lückenlos und übersichtlich.","en":"His CV is complete and clearly laid out.","ru":"Его резюме без пробелов и хорошо структурировано.","vi":"CV của anh ấy đầy đủ và rõ ràng.","fa":"رزومه او کامل و واضح است."}]},{"word":"lecker","en":"delicious; tasty","ru":"вкусный","vi":"thơm ngon","fa":"خوشمزه","examples":[{"de":"Der Kuchen schmeckt wirklich lecker.","en":"The cake tastes really delicious.","ru":"Торт очень вкусный.","vi":"Bánh có hương vị thật sự rất ngon.","fa":"طعم کیک واقعا خوشمزه است."},{"de":"Meine Mutter kocht immer lecker.","en":"My mother always cooks deliciously.","ru":"Моя мама всегда готовит вкусно.","vi":"Mẹ tôi luôn nấu những món ăn ngon.","fa":"مادرم همیشه غذاهای خوشمزه درست می کند."}]},{"word":"das Leder","en":"the leather","ru":"кожа","vi":"da","fa":"چرم","examples":[{"de":"Diese Schuhe sind aus echtem Leder.","en":"These shoes are made of real leather.","ru":"Эта обувь сделана из настоящей кожи.","vi":"Những đôi giày này được làm bằng da thật.","fa":"این کفش ها از چرم طبیعی ساخته شده اند."},{"de":"Die Jacke aus Leder war sehr teuer.","en":"The leather jacket was very expensive.","ru":"Кожаная куртка была очень дорогой.","vi":"Chiếc áo khoác da rất đắt tiền.","fa":"کت چرم خیلی گرون بود."}]},{"word":"ledig","en":"single; unmarried","ru":"холостой; незамужняя","vi":"độc thân","fa":"مجرد","examples":[{"de":"Er ist noch ledig und hat keine Kinder.","en":"He is still single and has no children.","ru":"Он всё ещё холост и не имеет детей.","vi":"Anh vẫn độc thân và chưa có con.","fa":"او هنوز مجرد است و فرزندی ندارد."},{"de":"Im Formular musste sie ankreuzen, ob sie ledig oder verheiratet ist.","en":"In the form she had to check whether she is single or married.","ru":"В анкете ей нужно было отметить, не замужем она или замужем.","vi":"Trên mẫu đơn cô phải đánh dấu xem mình còn độc thân hay đã kết hôn.","fa":"در فرم باید تیک می زد که مجرد است یا متاهل."}]},{"word":"leer","en":"empty","ru":"пустой","vi":"trống rỗng","fa":"خالی","examples":[{"de":"Die Flasche ist schon leer.","en":"The bottle is already empty.","ru":"Бутылка уже пуста.","vi":"Cái chai đã trống rỗng.","fa":"بطری در حال حاضر خالی است."},{"de":"Der Bus war um diese Zeit fast leer.","en":"The bus was almost empty at this time.","ru":"Автобус в это время был почти пустым.","vi":"Lúc này xe buýt gần như trống rỗng.","fa":"اتوبوس در این زمان تقریبا خالی بود."}]},{"word":"legen","en":"to lay; to put","ru":"класть; положить","vi":"nằm","fa":"دراز کشیدن","examples":[{"de":"Sie legt das Buch auf den Tisch.","en":"She puts the book on the table.","ru":"Она кладёт книгу на стол.","vi":"Cô đặt cuốn sách lên bàn.","fa":"کتاب را روی میز می گذارد."},{"de":"Er legte sich müde ins Bett.","en":"He lay down in bed, tired.","ru":"Он устало лёг в постель.","vi":"Anh mệt mỏi đi ngủ.","fa":"خسته به رختخواب رفت."}]},{"word":"die Lehre","en":"the apprenticeship; the lesson","ru":"обучение (профессии); урок","vi":"việc giảng dạy","fa":"آموزش","examples":[{"de":"Nach der Schule beginnt sie eine Lehre als Bäckerin.","en":"After school she begins an apprenticeship as a baker.","ru":"После школы она начинает обучение на пекаря.","vi":"Sau giờ học, cô bắt đầu học nghề làm bánh.","fa":"پس از مدرسه، او به عنوان یک نانوا کارآموزی را آغاز می کند."},{"de":"Aus diesem Fehler sollten wir eine Lehre ziehen.","en":"We should learn a lesson from this mistake.","ru":"Из этой ошибки нам следует извлечь урок.","vi":"Chúng ta nên rút ra bài học từ sai lầm này.","fa":"ما باید از این اشتباه درس بگیریم."}]},{"word":"der Lehrer","en":"the teacher","ru":"учитель","vi":"giáo viên","fa":"معلم","examples":[{"de":"Unser Lehrer erklärt die Grammatik sehr gut.","en":"Our teacher explains grammar very well.","ru":"Наш учитель очень хорошо объясняет грамматику.","vi":"Giáo viên của chúng tôi giải thích ngữ pháp rất tốt.","fa":"معلم ما گرامر را خیلی خوب توضیح می دهد."},{"de":"Sie möchte später Lehrerin werden.","en":"She wants to become a teacher later.","ru":"Она хочет позже стать учительницей.","vi":"Cô ấy muốn trở thành một giáo viên khi lớn lên.","fa":"او می خواهد وقتی بزرگ شد معلم شود."}]},{"word":"der Lehrling","en":"the apprentice","ru":"ученик (в профессии)","vi":"người học việc","fa":"شاگرد","examples":[{"de":"Der Lehrling lernt das Handwerk vom Meister.","en":"The apprentice learns the craft from the master.","ru":"Ученик учится ремеслу у мастера.","vi":"Người học việc học nghề từ bậc thầy.","fa":"شاگرد این کار را از استاد یاد می گیرد."},{"de":"Als Lehrling verdient man noch nicht viel Geld.","en":"As an apprentice you don't earn much money yet.","ru":"Будучи учеником, зарабатываешь ещё немного денег.","vi":"Là một người học việc, bạn không kiếm được nhiều tiền.","fa":"به عنوان یک شاگرد، شما پول زیادی کسب نمی کنید."}]},{"word":"leicht","en":"light; easy","ru":"лёгкий","vi":"dễ dàng","fa":"به راحتی","examples":[{"de":"Diese Tasche ist sehr leicht.","en":"This bag is very light.","ru":"Эта сумка очень лёгкая.","vi":"Chiếc túi này rất nhẹ.","fa":"این کیف بسیار سبک است."},{"de":"Die Prüfung war leichter als erwartet.","en":"The exam was easier than expected.","ru":"Экзамен был легче, чем ожидалось.","vi":"Bài kiểm tra dễ dàng hơn mong đợi.","fa":"آزمون راحت تر از حد انتظار بود."}]},{"word":"leid tun","en":"to be sorry","ru":"быть жаль (кому-то)","vi":"làm tổn thương","fa":"صدمه زدن","examples":[{"de":"Es tut mir leid, dass ich zu spät komme.","en":"I'm sorry that I'm coming late.","ru":"Мне жаль, что я опаздываю.","vi":"Tôi xin lỗi tôi đến muộn.","fa":"ببخشید دیر اومدم"},{"de":"Tut dir das nicht leid?","en":"Aren't you sorry about that?","ru":"Тебе разве не жаль этого?","vi":"Bạn không tiếc về điều đó sao?","fa":"از این بابت متاسف نیستی؟"}]},{"word":"leiden","en":"to suffer","ru":"страдать","vi":"đau khổ","fa":"رنج می برند","examples":[{"de":"Sie leidet seit Jahren an Kopfschmerzen.","en":"She has been suffering from headaches for years.","ru":"Она годами страдает от головных болей.","vi":"Cô ấy bị chứng đau đầu trong nhiều năm.","fa":"او سال ها از سردرد رنج می برد."},{"de":"Viele Menschen leiden unter der Hitze.","en":"Many people suffer from the heat.","ru":"Многие люди страдают от жары.","vi":"Nhiều người phải chịu đựng cái nóng.","fa":"بسیاری از مردم از گرما رنج می برند."}]},{"word":"leider","en":"unfortunately","ru":"к сожалению","vi":"thật không may","fa":"متاسفانه","examples":[{"de":"Leider kann ich morgen nicht kommen.","en":"Unfortunately, I can't come tomorrow.","ru":"К сожалению, я не смогу прийти завтра.","vi":"Thật không may là tôi không thể đến vào ngày mai.","fa":"متاسفانه فردا نمیتونم بیام"},{"de":"Das Wetter war leider sehr schlecht.","en":"Unfortunately the weather was very bad.","ru":"К сожалению, погода была очень плохой.","vi":"Thật không may, thời tiết rất xấu.","fa":"متاسفانه هوا خیلی بد بود."}]},{"word":"leihen","en":"to lend; to borrow","ru":"одалживать","vi":"mượn","fa":"قرض گرفتن","examples":[{"de":"Kannst du mir zwanzig Euro leihen?","en":"Can you lend me twenty euros?","ru":"Можешь одолжить мне двадцать евро?","vi":"Bạn có thể cho tôi mượn hai mươi euro được không?","fa":"میشه بیست یورو به من قرض بدی؟"},{"de":"Ich habe mir ein Buch aus der Bibliothek geliehen.","en":"I borrowed a book from the library.","ru":"Я взял книгу в библиотеке.","vi":"Tôi mượn một cuốn sách từ thư viện.","fa":"یک کتاب از کتابخانه امانت گرفتم."}]},{"word":"leise","en":"quiet; soft","ru":"тихий","vi":"lặng lẽ","fa":"بی سر و صدا","examples":[{"de":"Bitte sei leise, das Baby schläft.","en":"Please be quiet, the baby is sleeping.","ru":"Пожалуйста, тише, ребёнок спит.","vi":"Xin hãy im lặng, em bé đang ngủ.","fa":"لطفا ساکت باش بچه خوابه"},{"de":"Sie sprach so leise, dass ich sie kaum hörte.","en":"She spoke so quietly that I could barely hear her.","ru":"Она говорила так тихо, что я едва её слышал.","vi":"Cô ấy nói nhỏ đến mức tôi khó có thể nghe thấy.","fa":"آنقدر آرام صحبت می کرد که من به سختی می توانستم صدایش را بشنوم."}]},{"word":"leisten","en":"to achieve; to afford","ru":"выполнять; позволить себе","vi":"đủ khả năng","fa":"استطاعت","examples":[{"de":"Er hat in seinem Beruf viel geleistet.","en":"He has achieved a lot in his profession.","ru":"Он многого добился в своей профессии.","vi":"Anh ấy đã đạt được rất nhiều thành tựu trong nghề nghiệp của mình.","fa":"او در حرفه خود به موفقیت های زیادی دست یافته است."},{"de":"Wir können uns diesen Urlaub leider nicht leisten.","en":"Unfortunately, we can't afford this vacation.","ru":"К сожалению, мы не можем позволить себе этот отпуск.","vi":"Thật không may, chúng tôi không đủ khả năng cho kỳ nghỉ này.","fa":"متأسفانه ما نمی توانیم این تعطیلات را بپردازیم."}]},{"word":"die Leistung","en":"performance; achievement","ru":"достижение; производительность","vi":"hiệu suất","fa":"عملکرد","examples":[{"de":"Seine Leistung im Test war ausgezeichnet.","en":"His performance in the test was excellent.","ru":"Его результат на тесте был отличным.","vi":"Thành tích của anh ấy trong bài kiểm tra rất xuất sắc.","fa":"عملکرد او در آزمون عالی بود."},{"de":"Für diese Leistung bekam sie einen Preis.","en":"She received an award for this achievement.","ru":"За это достижение она получила награду.","vi":"Cô đã nhận được giải thưởng cho thành tích này.","fa":"او برای این موفقیت جایزه دریافت کرد."}]},{"word":"leiten","en":"to lead; to manage","ru":"руководить; вести","vi":"hướng dẫn","fa":"راهنمای","examples":[{"de":"Frau Schmidt leitet die Abteilung seit zwei Jahren.","en":"Ms. Schmidt has been leading the department for two years.","ru":"Госпожа Шмидт руководит отделом уже два года.","vi":"Bà Schmidt đã đứng đầu bộ phận này được hai năm.","fa":"خانم اشمیت به مدت دو سال ریاست این بخش را بر عهده داشته است."},{"de":"Wer leitet dieses Projekt?","en":"Who is managing this project?","ru":"Кто руководит этим проектом?","vi":"Ai đang lãnh đạo dự án này?","fa":"چه کسی این پروژه را هدایت می کند؟"}]},{"word":"die Leiter","en":"the ladder","ru":"лестница (приставная)","vi":"cái thang","fa":"نردبان","examples":[{"de":"Er stieg auf die Leiter, um die Lampe zu wechseln.","en":"He climbed the ladder to change the lamp.","ru":"Он забрался на лестницу, чтобы поменять лампу.","vi":"Anh leo lên thang để thay đèn.","fa":"از نردبان بالا رفت تا چراغ را عوض کند."},{"de":"Die Leiter steht an der Wand.","en":"The ladder is standing against the wall.","ru":"Лестница стоит у стены.","vi":"Cái thang dựa vào tường.","fa":"نردبان به دیوار است."}]},{"word":"lernen","en":"to learn","ru":"учить(ся)","vi":"học hỏi","fa":"یاد بگیرند","examples":[{"de":"Sie lernt seit einem Jahr Deutsch.","en":"She has been learning German for a year.","ru":"Она учит немецкий уже год.","vi":"Cô ấy đã học tiếng Đức được một năm.","fa":"او یک سال است که آلمانی یاد می گیرد."},{"de":"Ich muss heute Abend für die Prüfung lernen.","en":"I have to study for the exam tonight.","ru":"Мне нужно сегодня вечером готовиться к экзамену.","vi":"Tối nay tôi phải học bài thi.","fa":"امشب باید برای امتحان بخونم."}]},{"word":"lesen","en":"to read","ru":"читать","vi":"đọc","fa":"خواندن","examples":[{"de":"Er liest jeden Abend eine Zeitung.","en":"He reads a newspaper every evening.","ru":"Он каждый вечер читает газету.","vi":"Anh ấy đọc báo mỗi tối.","fa":"او هر روز عصر یک روزنامه می خواند."},{"de":"Hast du das neue Buch schon gelesen?","en":"Have you already read the new book?","ru":"Ты уже прочитал новую книгу?","vi":"Bạn đã đọc cuốn sách mới chưa?","fa":"آیا هنوز کتاب جدید را خوانده اید؟"}]},{"word":"letzt-","en":"last","ru":"последний","vi":"cuối cùng-","fa":"آخرین-","examples":[{"de":"Das war ihr letzter Arbeitstag vor der Rente.","en":"That was her last working day before retirement.","ru":"Это был её последний рабочий день перед пенсией.","vi":"Đó là ngày làm việc cuối cùng của cô trước khi nghỉ hưu.","fa":"این آخرین روز کاری او قبل از بازنشستگی بود."},{"de":"Wir haben uns das letzte Mal vor zwei Jahren gesehen.","en":"We last saw each other two years ago.","ru":"Мы виделись в последний раз два года назад.","vi":"Lần cuối cùng chúng tôi gặp nhau là hai năm trước.","fa":"آخرین بار همدیگر را دو سال پیش دیدیم."}]},{"word":"die Leute","en":"people","ru":"люди","vi":"mọi người","fa":"مردم","examples":[{"de":"Auf dem Markt waren viele Leute.","en":"There were many people at the market.","ru":"На рынке было много людей.","vi":"Trong chợ đã có rất nhiều người.","fa":"افراد زیادی در بازار بودند."},{"de":"Die Leute in diesem Dorf sind sehr freundlich.","en":"The people in this village are very friendly.","ru":"Люди в этой деревне очень дружелюбны.","vi":"Người dân ở ngôi làng này rất thân thiện.","fa":"مردم این روستا بسیار صمیمی هستند."}]},{"word":"das Lexikon","en":"the encyclopedia; the dictionary","ru":"энциклопедия; словарь","vi":"từ vựng","fa":"واژگان","examples":[{"de":"Er hat das Wort im Lexikon nachgeschlagen.","en":"He looked up the word in the dictionary.","ru":"Он посмотрел слово в словаре.","vi":"Anh tra từ đó trong từ điển.","fa":"او کلمه را در فرهنگ لغت جستجو کرد."},{"de":"Zu Hause haben wir ein großes Lexikon.","en":"At home we have a large encyclopedia.","ru":"Дома у нас есть большая энциклопедия.","vi":"Chúng tôi có một bộ bách khoa toàn thư lớn ở nhà.","fa":"ما یک دایره المعارف بزرگ در خانه داریم."}]},{"word":"das Licht","en":"the light","ru":"свет","vi":"ánh sáng","fa":"نور","examples":[{"de":"Bitte mach das Licht aus, wenn du gehst.","en":"Please turn off the light when you leave.","ru":"Пожалуйста, выключи свет, когда уйдёшь.","vi":"Vui lòng tắt đèn khi bạn rời đi.","fa":"لطفاً هنگام خروج چراغ ها را خاموش کنید."},{"de":"Am Abend fällt warmes Licht durch das Fenster.","en":"In the evening warm light falls through the window.","ru":"Вечером тёплый свет падает через окно.","vi":"Vào buổi tối, ánh sáng ấm áp chiếu qua cửa sổ.","fa":"در شب، نور گرم از پنجره می تابد."}]},{"word":"lieb","en":"dear; kind","ru":"милый; дорогой","vi":"thân yêu","fa":"عزیز","examples":[{"de":"Sie ist ein sehr liebes Mädchen.","en":"She is a very sweet girl.","ru":"Она очень милая девочка.","vi":"Cô ấy là một cô gái rất ngọt ngào.","fa":"او یک دختر بسیار شیرین است."},{"de":"Liebe Grüße aus dem Urlaub!","en":"Dear greetings from vacation!","ru":"Дорогой привет из отпуска!","vi":"Lời chào từ kỳ nghỉ!","fa":"سلام از تعطیلات!"}]},{"word":"lieben","en":"to love","ru":"любить","vi":"tình yêu","fa":"عشق","examples":[{"de":"Ich liebe meine Familie über alles.","en":"I love my family more than anything.","ru":"Я люблю свою семью больше всего на свете.","vi":"Tôi yêu gia đình mình hơn bất cứ điều gì.","fa":"من خانواده ام را بیشتر از هر چیزی دوست دارم."},{"de":"Sie lieben sich seit der Schulzeit.","en":"They have loved each other since school days.","ru":"Они любят друг друга со школьных лет.","vi":"Họ yêu nhau từ khi còn đi học.","fa":"آنها از دوران مدرسه همدیگر را دوست داشتند."}]},{"word":"das Lied","en":"the song","ru":"песня","vi":"bài hát","fa":"آهنگ","examples":[{"de":"Die Kinder singen ein bekanntes Lied.","en":"The children are singing a well-known song.","ru":"Дети поют известную песню.","vi":"Trẻ hát một bài hát quen thuộc.","fa":"بچه ها آهنگ معروفی می خوانند."},{"de":"Dieses Lied hören wir im Radio ständig.","en":"We hear this song on the radio all the time.","ru":"Мы постоянно слышим эту песню по радио.","vi":"Chúng tôi nghe bài hát này trên radio mọi lúc.","fa":"ما همیشه این آهنگ را از رادیو می شنویم."}]},{"word":"liefern","en":"to deliver","ru":"поставлять; доставлять","vi":"giao hàng","fa":"تحویل دهید","examples":[{"de":"Die Firma liefert die Möbel nächste Woche.","en":"The company will deliver the furniture next week.","ru":"Компания доставит мебель на следующей неделе.","vi":"Công ty sẽ giao đồ nội thất vào tuần tới.","fa":"این شرکت مبلمان را هفته آینده تحویل خواهد داد."},{"de":"Der Pizzabote liefert das Essen direkt nach Hause.","en":"The pizza delivery person delivers the food right to your home.","ru":"Курьер доставляет еду прямо домой.","vi":"Cậu bé giao bánh pizza giao đồ ăn trực tiếp đến nhà bạn.","fa":"پسر تحویل پیتزا غذا را مستقیماً به خانه شما تحویل می دهد."}]},{"word":"liegen","en":"to lie; to be located","ru":"лежать; находиться","vi":"nói dối","fa":"دروغ","examples":[{"de":"Das Buch liegt auf dem Tisch.","en":"The book is lying on the table.","ru":"Книга лежит на столе.","vi":"Cuốn sách ở trên bàn.","fa":"کتاب روی میز است."},{"de":"Die Stadt liegt an einem See.","en":"The city is located by a lake.","ru":"Город расположен у озера.","vi":"Thành phố nằm trên một hồ nước.","fa":"این شهر روی یک دریاچه قرار دارد."}]},{"word":"der Lift","en":"the elevator; the lift","ru":"лифт","vi":"thang máy","fa":"آسانسور","examples":[{"de":"Der Lift ist heute leider kaputt.","en":"The elevator is unfortunately broken today.","ru":"Лифт сегодня, к сожалению, сломан.","vi":"Thật không may hôm nay thang máy bị hỏng.","fa":"متاسفانه آسانسور امروز خراب است."},{"de":"Wir nehmen den Lift bis in den fünften Stock.","en":"We take the elevator up to the fifth floor.","ru":"Мы поедем на лифте до пятого этажа.","vi":"Chúng tôi đi thang máy lên tầng năm.","fa":"با آسانسور به طبقه پنجم می رویم."}]},{"word":"die Limonade","en":"the lemonade; the soft drink","ru":"лимонад","vi":"nước chanh","fa":"لیموناد","examples":[{"de":"An heißen Tagen trinke ich gerne kalte Limonade.","en":"On hot days I like to drink cold lemonade.","ru":"В жаркие дни я люблю пить холодный лимонад.","vi":"Vào những ngày nắng nóng tôi thích uống nước chanh lạnh.","fa":"در روزهای گرم دوست دارم لیموناد سرد بنوشم."},{"de":"Die Kinder bekamen eine Limonade zum Essen.","en":"The children got a lemonade with their meal.","ru":"Дети получили лимонад к еде.","vi":"Bọn trẻ được cho uống nước chanh trong bữa ăn.","fa":"به بچه ها همراه غذا آبلیمو داده شد."}]},{"word":"die Linie","en":"the line","ru":"линия","vi":"dòng","fa":"خط","examples":[{"de":"Ziehe eine gerade Linie mit dem Lineal.","en":"Draw a straight line with the ruler.","ru":"Проведи прямую линию линейкой.","vi":"Vẽ một đường thẳng bằng thước kẻ.","fa":"با خط کش یک خط مستقیم بکشید."},{"de":"Die U-Bahn-Linie 3 fährt zum Hauptbahnhof.","en":"Subway line 3 goes to the main station.","ru":"Линия метро 3 идёт до главного вокзала.","vi":"Tuyến tàu điện ngầm số 3 đi đến ga chính.","fa":"خط 3 مترو به ایستگاه اصلی می رود."}]},{"word":"links","en":"left","ru":"налево; слева","vi":"trái","fa":"سمت چپ","examples":[{"de":"An der Ampel musst du links abbiegen.","en":"At the traffic light you have to turn left.","ru":"На светофоре тебе нужно повернуть налево.","vi":"Tại đèn giao thông bạn phải rẽ trái.","fa":"در چراغ راهنمایی باید به چپ بپیچید."},{"de":"Das Geschäft ist gleich links neben der Bank.","en":"The shop is right on the left next to the bank.","ru":"Магазин находится слева от банка.","vi":"Cửa hàng nằm ngay bên trái ngân hàng.","fa":"مغازه درست سمت چپ بانک است."}]},{"word":"die Lippe","en":"the lip","ru":"губа","vi":"môi","fa":"لب","examples":[{"de":"Sie hat sich beim Essen auf die Lippe gebissen.","en":"She bit her lip while eating.","ru":"Она прикусила губу во время еды.","vi":"Cô cắn môi khi ăn.","fa":"هنگام غذا خوردن لبش را گاز گرفت."},{"de":"Seine Lippen waren vor Kälte ganz blau.","en":"His lips were completely blue from the cold.","ru":"Его губы совсем посинели от холода.","vi":"Môi anh xanh xao vì lạnh.","fa":"لب هایش از سرما کبود شده بود."}]},{"word":"die Liste","en":"the list","ru":"список","vi":"danh sách","fa":"لیست","examples":[{"de":"Ich habe eine Liste mit allen Einkäufen geschrieben.","en":"I wrote a list of all the groceries.","ru":"Я составил список всех покупок.","vi":"Tôi đã viết một danh sách tất cả các giao dịch mua.","fa":"لیست تمام خریدها را نوشتم."},{"de":"Sein Name steht ganz oben auf der Liste.","en":"His name is at the very top of the list.","ru":"Его имя стоит в самом верху списка.","vi":"Tên anh ấy đứng đầu danh sách.","fa":"نام او در بالای لیست قرار دارد."}]},{"word":"die Literatur","en":"the literature","ru":"литература","vi":"văn học","fa":"ادبیات","examples":[{"de":"Sie interessiert sich sehr für russische Literatur.","en":"She is very interested in Russian literature.","ru":"Она очень интересуется русской литературой.","vi":"Cô ấy rất quan tâm đến văn học Nga.","fa":"او علاقه زیادی به ادبیات روسی دارد."},{"de":"An der Uni studiert er deutsche Literatur.","en":"At university he studies German literature.","ru":"В университете он изучает немецкую литературу.","vi":"Ở trường đại học, anh ấy nghiên cứu văn học Đức.","fa":"در دانشگاه ادبیات آلمانی می خواند."}]},{"word":"loben","en":"to praise","ru":"хвалить","vi":"khen ngợi","fa":"ستایش","examples":[{"de":"Der Lehrer lobte den Schüler für seine gute Arbeit.","en":"The teacher praised the student for his good work.","ru":"Учитель похвалил ученика за хорошую работу.","vi":"Cô giáo khen ngợi học sinh đã làm việc tốt.","fa":"معلم از شاگرد به خاطر کار خوبش تمجید کرد."},{"de":"Meine Eltern loben mich selten.","en":"My parents rarely praise me.","ru":"Мои родители редко меня хвалят.","vi":"Bố mẹ tôi hiếm khi khen ngợi tôi.","fa":"پدر و مادرم به ندرت از من تعریف می کنند."}]},{"word":"das Loch","en":"the hole","ru":"дыра","vi":"cái lỗ","fa":"سوراخ","examples":[{"de":"In meiner Hose ist ein großes Loch.","en":"There's a big hole in my pants.","ru":"В моих брюках большая дыра.","vi":"Có một cái lỗ lớn trên quần của tôi.","fa":"یک سوراخ بزرگ در شلوار من وجود دارد."},{"de":"Der Hund hat ein Loch im Garten gegraben.","en":"The dog dug a hole in the garden.","ru":"Собака вырыла яму в саду.","vi":"Con chó đào một cái lỗ trong vườn.","fa":"سگ در باغچه حفر کرد."}]},{"word":"locker","en":"loose; relaxed","ru":"свободный; расслабленный","vi":"lỏng lẻo","fa":"شل","examples":[{"de":"Die Schraube ist locker und muss festgezogen werden.","en":"The screw is loose and needs to be tightened.","ru":"Винт разболтался, его нужно затянуть.","vi":"Vít bị lỏng và cần phải siết chặt lại.","fa":"پیچ شل است و باید سفت شود."},{"de":"Bleib locker, es wird schon alles gut gehen.","en":"Stay relaxed, everything will turn out fine.","ru":"Расслабься, всё будет хорошо.","vi":"Hãy bình tĩnh, mọi thứ sẽ ổn thôi.","fa":"آرام باش، همه چیز درست خواهد شد."}]},{"word":"der Löffel","en":"the spoon","ru":"ложка","vi":"cái thìa","fa":"قاشق","examples":[{"de":"Sie rührt den Kaffee mit einem Löffel um.","en":"She stirs the coffee with a spoon.","ru":"Она размешивает кофе ложкой.","vi":"Cô ấy khuấy cà phê bằng thìa.","fa":"قهوه را با قاشق هم می‌زند."},{"de":"Kannst du mir bitte einen Löffel für die Suppe geben?","en":"Can you please give me a spoon for the soup?","ru":"Можешь дать мне ложку для супа?","vi":"Bạn có thể vui lòng cho tôi một thìa súp được không?","fa":"میشه لطفا یک قاشق برای سوپ به من بدهید؟"}]},{"word":"der Lohn","en":"the wage; the pay","ru":"заработная плата","vi":"tiền lương","fa":"دستمزدها","examples":[{"de":"Der Lohn wird am Ende des Monats bezahlt.","en":"The wages are paid at the end of the month.","ru":"Зарплата выплачивается в конце месяца.","vi":"Lương được trả vào cuối tháng.","fa":"دستمزد در پایان ماه پرداخت می شود."},{"de":"Sie bekommt einen guten Lohn für ihre Arbeit.","en":"She gets a good wage for her work.","ru":"Она получает хорошую зарплату за свою работу.","vi":"Cô ấy nhận được một mức lương tốt cho công việc của mình.","fa":"او برای کارش دستمزد خوبی می گیرد."}]},{"word":"das Lokal","en":"the restaurant; the pub","ru":"заведение (кафе, ресторан)","vi":"địa phương","fa":"محلی","examples":[{"de":"Wir treffen uns heute Abend in einem gemütlichen Lokal.","en":"We're meeting tonight at a cozy restaurant.","ru":"Мы встречаемся сегодня вечером в уютном заведении.","vi":"Tối nay chúng ta sẽ gặp nhau ở một nhà hàng ấm cúng.","fa":"امروز عصر در یک رستوران دنج همدیگر را ملاقات خواهیم کرد."},{"de":"Das Lokal um die Ecke serviert gutes Essen.","en":"The pub around the corner serves good food.","ru":"Заведение за углом подаёт хорошую еду.","vi":"Nhà hàng quanh góc phục vụ đồ ăn ngon.","fa":"رستورانی که در گوشه کناری است غذاهای خوبی سرو می کند."}]},{"word":"los","en":"loose; off; what's going on","ru":"свободный; что происходит","vi":"đi","fa":"برو","examples":[{"de":"Was ist hier los?","en":"What's going on here?","ru":"Что здесь происходит?","vi":"Chuyện gì đang xảy ra ở đây vậy?","fa":"اینجا چه خبر است؟"},{"de":"Los, wir müssen uns beeilen!","en":"Come on, we have to hurry!","ru":"Давай, нам нужно спешить!","vi":"Đi thôi, chúng ta phải nhanh lên!","fa":"بیا، باید عجله کنیم!"}]},{"word":"löschen","en":"to delete; to extinguish","ru":"удалять; тушить","vi":"xóa","fa":"حذف کنید","examples":[{"de":"Ich habe die Datei aus Versehen gelöscht.","en":"I accidentally deleted the file.","ru":"Я случайно удалил файл.","vi":"Tôi vô tình xóa tập tin.","fa":"من تصادفا فایل رو پاک کردم"},{"de":"Die Feuerwehr konnte das Feuer schnell löschen.","en":"The fire department was able to extinguish the fire quickly.","ru":"Пожарные смогли быстро потушить огонь.","vi":"Lực lượng chữa cháy đã kịp thời dập tắt đám cháy.","fa":"آتش نشانی به سرعت توانست آتش را خاموش کند."}]},{"word":"lösen","en":"to solve","ru":"решать","vi":"giải quyết","fa":"حل کند","examples":[{"de":"Er konnte die Aufgabe nicht lösen.","en":"He couldn't solve the task.","ru":"Он не смог решить задачу.","vi":"Anh ấy không thể giải quyết được vấn đề.","fa":"او نتوانست مشکل را حل کند."},{"de":"Wir müssen dieses Problem gemeinsam lösen.","en":"We have to solve this problem together.","ru":"Нам нужно решить эту проблему вместе.","vi":"Chúng ta phải cùng nhau giải quyết vấn đề này.","fa":"ما باید با هم این مشکل را حل کنیم."}]},{"word":"losfahren","en":"to set off; to depart","ru":"отправляться (в путь)","vi":"lái xe đi","fa":"راندن","examples":[{"de":"Der Bus fährt in fünf Minuten los.","en":"The bus departs in five minutes.","ru":"Автобус отправляется через пять минут.","vi":"Xe buýt khởi hành trong năm phút nữa.","fa":"اتوبوس پنج دقیقه دیگر حرکت می کند."},{"de":"Wir sind früh am Morgen losgefahren.","en":"We set off early in the morning.","ru":"Мы отправились рано утром.","vi":"Chúng tôi rời đi vào sáng sớm.","fa":"صبح زود راه افتادیم."}]},{"word":"die Lösung","en":"the solution","ru":"решение","vi":"giải pháp","fa":"راه حل","examples":[{"de":"Ich habe endlich eine Lösung für das Problem gefunden.","en":"I finally found a solution to the problem.","ru":"Я наконец нашёл решение проблемы.","vi":"Cuối cùng tôi đã tìm ra giải pháp cho vấn đề.","fa":"بالاخره راه حلی برای مشکل پیدا کردم."},{"de":"Die Lösung dieser Aufgabe war ganz einfach.","en":"The solution to this task was quite simple.","ru":"Решение этой задачи было совсем простым.","vi":"Giải pháp cho nhiệm vụ này rất đơn giản.","fa":"راه حل این کار بسیار ساده بود."}]},{"word":"die Luft","en":"the air","ru":"воздух","vi":"không khí","fa":"هوا","examples":[{"de":"Die Luft in den Bergen ist besonders frisch.","en":"The air in the mountains is especially fresh.","ru":"Воздух в горах особенно свежий.","vi":"Không khí trên núi đặc biệt trong lành.","fa":"هوای کوهستانی به خصوص تازه است."},{"de":"Mach bitte das Fenster auf, ich brauche frische Luft.","en":"Please open the window, I need fresh air.","ru":"Пожалуйста, открой окно, мне нужен свежий воздух.","vi":"Làm ơn mở cửa sổ ra, tôi cần chút không khí trong lành.","fa":"لطفا پنجره را باز کنید، من به هوای تازه نیاز دارم."}]},{"word":"lügen","en":"to lie","ru":"лгать","vi":"nói dối","fa":"دروغ","examples":[{"de":"Er lügt oft, um Probleme zu vermeiden.","en":"He often lies to avoid problems.","ru":"Он часто лжёт, чтобы избежать проблем.","vi":"Anh ấy thường nói dối để tránh rắc rối.","fa":"او اغلب برای جلوگیری از مشکلات دروغ می گوید."},{"de":"Ich weiß, dass du lügst.","en":"I know that you're lying.","ru":"Я знаю, что ты лжёшь.","vi":"Tôi biết bạn đang nói dối.","fa":"میدونم دروغ میگی"}]},{"word":"die Lust","en":"desire; the mood (to do something)","ru":"желание; охота","vi":"mong muốn","fa":"میل","examples":[{"de":"Ich habe heute keine Lust zu kochen.","en":"I don't feel like cooking today.","ru":"Мне сегодня не хочется готовить.","vi":"Hôm nay tôi không có hứng nấu ăn.","fa":"امروز حوصله آشپزی ندارم"},{"de":"Hast du Lust, ins Kino zu gehen?","en":"Do you feel like going to the cinema?","ru":"Хочешь пойти в кино?","vi":"Bạn có cảm thấy muốn đi xem phim không?","fa":"آیا دوست دارید به سینما بروید؟"}]},{"word":"lustig","en":"funny","ru":"весёлый; забавный","vi":"buồn cười","fa":"خنده دار","examples":[{"de":"Der Film war wirklich sehr lustig.","en":"The movie was really very funny.","ru":"Фильм был действительно очень смешным.","vi":"Bộ phim thực sự rất hài hước.","fa":"فیلم واقعا خیلی خنده دار بود."},{"de":"Er erzählt immer lustige Geschichten.","en":"He always tells funny stories.","ru":"Он всегда рассказывает забавные истории.","vi":"Anh ấy luôn kể những câu chuyện hài hước.","fa":"او همیشه داستان های خنده دار می گوید."}]},{"word":"machen","en":"to make; to do","ru":"делать","vi":"làm","fa":"انجام دهید","examples":[{"de":"Was machst du heute Abend?","en":"What are you doing tonight?","ru":"Что ты делаешь сегодня вечером?","vi":"Tối nay bạn đang làm gì?","fa":"امشب چیکار میکنی؟"},{"de":"Meine Mutter macht das Essen für uns alle.","en":"My mother makes the food for all of us.","ru":"Моя мама готовит еду для всех нас.","vi":"Mẹ tôi làm bữa tối cho tất cả chúng tôi.","fa":"مادرم برای همه ما شام درست می کند."}]},{"word":"das Mädchen","en":"the girl","ru":"девочка","vi":"cô gái","fa":"دختر","examples":[{"de":"Das kleine Mädchen spielt im Garten.","en":"The little girl is playing in the garden.","ru":"Маленькая девочка играет в саду.","vi":"Cô bé đang chơi trong vườn.","fa":"دخترک در باغ بازی می کند."},{"de":"Ein Mädchen aus meiner Klasse zieht bald um.","en":"A girl from my class is moving soon.","ru":"Девочка из моего класса скоро переезжает.","vi":"Một cô gái trong lớp tôi sắp chuyển đi.","fa":"دختری از کلاس من به زودی نقل مکان می کند."}]},{"word":"das Magazin","en":"the magazine","ru":"журнал","vi":"tạp chí","fa":"مجله","examples":[{"de":"Sie liest jede Woche ein neues Magazin.","en":"She reads a new magazine every week.","ru":"Она каждую неделю читает новый журнал.","vi":"Cô ấy đọc một tạp chí mới mỗi tuần.","fa":"او هر هفته یک مجله جدید می خواند."},{"de":"Im Wartezimmer lagen viele bunte Magazine.","en":"There were many colorful magazines in the waiting room.","ru":"В приёмной лежало много красочных журналов.","vi":"Có rất nhiều tạp chí đầy màu sắc trong phòng chờ.","fa":"تعداد زیادی مجلات رنگارنگ در اتاق انتظار بود."}]},{"word":"der Magen","en":"the stomach","ru":"желудок","vi":"dạ dày","fa":"معده","examples":[{"de":"Mir tut der Magen weh.","en":"My stomach hurts.","ru":"У меня болит живот.","vi":"Bụng tôi đau quá.","fa":"شکمم درد میکنه"},{"de":"Auf leeren Magen sollte man keinen Kaffee trinken.","en":"You shouldn't drink coffee on an empty stomach.","ru":"На пустой желудок не стоит пить кофе.","vi":"Bạn không nên uống cà phê khi bụng đói.","fa":"نباید با معده خالی قهوه بنوشید."}]},{"word":"mager","en":"lean; skinny","ru":"худой; постный","vi":"nạc","fa":"لاغر","examples":[{"de":"Er isst gerne mageres Fleisch.","en":"He likes to eat lean meat.","ru":"Он любит есть постное мясо.","vi":"Anh ấy thích ăn thịt nạc.","fa":"او دوست دارد گوشت بدون چربی بخورد."},{"de":"Nach der Krankheit war sie sehr mager.","en":"After the illness she was very thin.","ru":"После болезни она была очень худой.","vi":"Sau cơn bệnh, cô ấy rất gầy.","fa":"بعد از بیماری او بسیار لاغر شده بود."}]},{"word":"die Mahlzeit","en":"the meal","ru":"приём пищи; трапеза","vi":"bữa ăn","fa":"غذا","examples":[{"de":"Wir essen drei Mahlzeiten am Tag.","en":"We eat three meals a day.","ru":"Мы едим три раза в день.","vi":"Chúng tôi ăn ba bữa một ngày.","fa":"ما روزی سه وعده غذا می خوریم."},{"de":"Die letzte Mahlzeit war schon vor sechs Stunden.","en":"The last meal was already six hours ago.","ru":"Последний приём пищи был уже шесть часов назад.","vi":"Bữa ăn cuối cùng đã cách đây sáu tiếng.","fa":"آخرین وعده غذایی شش ساعت پیش بود."}]},{"word":"die Mahnung","en":"the reminder; the warning notice","ru":"напоминание; предупреждение","vi":"lời nhắc nhở","fa":"یادآوری","examples":[{"de":"Ich habe eine Mahnung bekommen, weil ich die Rechnung vergessen habe.","en":"I received a reminder because I forgot the bill.","ru":"Я получил напоминание, потому что забыл про счёт.","vi":"Tôi nhận được lời nhắc vì quên hóa đơn.","fa":"من یک یادآوری دریافت کردم زیرا فاکتور را فراموش کرده بودم."},{"de":"Nach der zweiten Mahnung habe ich sofort bezahlt.","en":"After the second reminder I paid immediately.","ru":"После второго напоминания я сразу заплатил.","vi":"Sau lần nhắc thứ hai tôi đã thanh toán ngay lập tức.","fa":"بعد از یادآوری دوم بلافاصله پرداخت کردم."}]},{"word":"mal","en":"times; once (modal particle)","ru":"раз; -ка (частица)","vi":"lần","fa":"بارها","examples":[{"de":"Kannst du mir mal helfen?","en":"Can you help me for a moment?","ru":"Можешь мне немного помочь?","vi":"Bạn có thể giúp tôi được không?","fa":"می توانید به من کمک کنید؟"},{"de":"Drei mal drei ist neun.","en":"Three times three is nine.","ru":"Трижды три равно девять.","vi":"Ba lần ba là chín.","fa":"سه ضربدر سه می شود نه."}]},{"word":"das Mal","en":"the time (occasion)","ru":"раз (случай)","vi":"thời gian","fa":"زمان","examples":[{"de":"Das war das erste Mal, dass ich Sushi gegessen habe.","en":"That was the first time I ate sushi.","ru":"Это был первый раз, когда я ел суши.","vi":"Đó là lần đầu tiên tôi ăn sushi.","fa":"اولین بار بود که سوشی خوردم."},{"de":"Beim nächsten Mal komme ich früher.","en":"Next time I'll come earlier.","ru":"В следующий раз я приду раньше.","vi":"Lần sau tôi sẽ đến sớm hơn.","fa":"دفعه بعد زودتر میام"}]},{"word":"malen","en":"to paint","ru":"рисовать (красками)","vi":"sơn","fa":"رنگ کردن","examples":[{"de":"Die Kinder malen bunte Bilder.","en":"The children are painting colorful pictures.","ru":"Дети рисуют яркие картины.","vi":"Trẻ vẽ những bức tranh đầy màu sắc.","fa":"بچه ها نقاشی های رنگارنگ می کشند."},{"de":"Sie malt gerne Landschaften in ihrer Freizeit.","en":"She likes to paint landscapes in her free time.","ru":"В свободное время она любит рисовать пейзажи.","vi":"Cô thích vẽ tranh phong cảnh vào thời gian rảnh rỗi.","fa":"او در اوقات فراغت خود از نقاشی مناظر لذت می برد."}]},{"word":"man","en":"one; you (impersonal)","ru":"безличное местоимение (кто-то, вообще)","vi":"người đàn ông","fa":"مرد","examples":[{"de":"Man kann hier gut parken.","en":"One can park well here.","ru":"Здесь удобно парковаться.","vi":"Bạn có thể đậu xe dễ dàng ở đây.","fa":"می توانید به راحتی اینجا پارک کنید."},{"de":"In Deutschland isst man gerne Brot zum Frühstück.","en":"In Germany, people like to eat bread for breakfast.","ru":"В Германии на завтрак обычно едят хлеб.","vi":"Ở Đức người ta thích ăn bánh mì vào bữa sáng.","fa":"در آلمان مردم دوست دارند برای صبحانه نان بخورند."}]},{"word":"manch-","en":"some; many a","ru":"некоторый","vi":"một số-","fa":"برخی -","examples":[{"de":"Manche Leute mögen keinen Kaffee.","en":"Some people don't like coffee.","ru":"Некоторые люди не любят кофе.","vi":"Một số người không thích cà phê.","fa":"بعضی ها قهوه دوست ندارند."},{"de":"An manchen Tagen regnet es den ganzen Tag.","en":"On some days it rains all day.","ru":"В некоторые дни идёт дождь весь день.","vi":"Có ngày trời mưa cả ngày.","fa":"بعضی روزها تمام روز باران می بارد."}]},{"word":"manchmal","en":"sometimes","ru":"иногда","vi":"đôi khi","fa":"گاهی اوقات","examples":[{"de":"Manchmal gehe ich abends spazieren.","en":"Sometimes I go for a walk in the evening.","ru":"Иногда я гуляю по вечерам.","vi":"Thỉnh thoảng tôi đi dạo vào buổi tối.","fa":"گاهی عصرها به پیاده روی می روم."},{"de":"Sie ruft mich manchmal am Wochenende an.","en":"She sometimes calls me on the weekend.","ru":"Она иногда звонит мне по выходным.","vi":"Thỉnh thoảng cô ấy gọi cho tôi vào cuối tuần.","fa":"او گاهی اوقات آخر هفته ها با من تماس می گیرد."}]},{"word":"der Mangel","en":"the lack; the shortage","ru":"недостаток; нехватка","vi":"sự thiếu sót","fa":"کمبود","examples":[{"de":"In der Stadt herrscht ein Mangel an Wohnungen.","en":"There is a shortage of apartments in the city.","ru":"В городе ощущается нехватка квартир.","vi":"Thành phố đang thiếu nhà ở.","fa":"کمبود مسکن در شهر وجود دارد."},{"de":"Der Mangel an Schlaf macht ihn müde.","en":"The lack of sleep makes him tired.","ru":"Недостаток сна делает его усталым.","vi":"Việc thiếu ngủ khiến anh mệt mỏi.","fa":"کم خوابی او را خسته می کند."}]},{"word":"der Mann","en":"the man; the husband","ru":"мужчина; муж","vi":"người đàn ông","fa":"مرد","examples":[{"de":"Der Mann dort drüben ist mein Nachbar.","en":"The man over there is my neighbor.","ru":"Мужчина вон там — мой сосед.","vi":"Người đàn ông đằng kia là hàng xóm của tôi.","fa":"اون مرد اونجا همسایه منه"},{"de":"Ihr Mann arbeitet als Ingenieur.","en":"Her husband works as an engineer.","ru":"Её муж работает инженером.","vi":"Chồng cô làm kỹ sư.","fa":"شوهرش به عنوان مهندس کار می کند."}]},{"word":"die Mannschaft","en":"the team","ru":"команда","vi":"đội","fa":"تیم","examples":[{"de":"Unsere Mannschaft hat das Spiel gewonnen.","en":"Our team won the game.","ru":"Наша команда выиграла игру.","vi":"Đội của chúng tôi đã thắng trò chơi.","fa":"تیم ما برنده بازی شد."},{"de":"Er spielt seit fünf Jahren in dieser Mannschaft.","en":"He has been playing on this team for five years.","ru":"Он играет в этой команде уже пять лет.","vi":"Anh ấy đã chơi ở đội này được 5 năm.","fa":"او پنج سال است که در این تیم بازی می کند."}]},{"word":"der Mantel","en":"the coat","ru":"пальто","vi":"chiếc áo khoác","fa":"کت","examples":[{"de":"Zieh deinen Mantel an, es ist kalt draußen.","en":"Put on your coat, it's cold outside.","ru":"Надень пальто, на улице холодно.","vi":"Mặc áo khoác vào đi, ngoài trời lạnh lắm.","fa":"کتت را بپوش، بیرون سرد است."},{"de":"Sie hängte ihren Mantel an die Garderobe.","en":"She hung her coat on the coat rack.","ru":"Она повесила пальто на вешалку.","vi":"Cô treo áo khoác lên giá treo áo khoác.","fa":"کتش را روی چوب لباسی آویزان کرد."}]},{"word":"die Mappe","en":"the folder; the briefcase","ru":"папка; портфель","vi":"thư mục","fa":"پوشه","examples":[{"de":"Er trägt alle Dokumente in einer Mappe.","en":"He carries all the documents in a folder.","ru":"Он носит все документы в папке.","vi":"Anh ta mang tất cả tài liệu vào một cặp.","fa":"او تمام اسناد را در یک پوشه حمل می کند."},{"de":"Die Schülerin legte die Hausaufgaben in ihre Mappe.","en":"The student put her homework in her folder.","ru":"Ученица положила домашнее задание в свою папку.","vi":"Học sinh cất bài tập về nhà vào cặp của mình.","fa":"دانش آموز تکالیف را در پوشه خود گذاشت."}]},{"word":"das Märchen","en":"the fairy tale","ru":"сказка","vi":"câu chuyện cổ tích","fa":"افسانه","examples":[{"de":"Meine Oma erzählt mir jeden Abend ein Märchen.","en":"My grandma tells me a fairy tale every evening.","ru":"Моя бабушка каждый вечер рассказывает мне сказку.","vi":"Bà tôi kể cho tôi nghe một câu chuyện cổ tích vào mỗi buổi tối.","fa":"مادربزرگم هر روز عصر یک افسانه برایم تعریف می کند."},{"de":"Das Märchen von Rotkäppchen kennt jedes Kind.","en":"Every child knows the fairy tale of Little Red Riding Hood.","ru":"Сказку о Красной Шапочке знает каждый ребёнок.","vi":"Mọi đứa trẻ đều biết đến câu chuyện cổ tích Cô bé quàng khăn đỏ.","fa":"هر کودکی افسانه کلاه قرمزی را می شناسد."}]},{"word":"die Margarine","en":"the margarine","ru":"маргарин","vi":"bơ thực vật","fa":"مارگارین","examples":[{"de":"Sie streicht Margarine auf das Brot.","en":"She spreads margarine on the bread.","ru":"Она намазывает маргарин на хлеб.","vi":"Cô phết bơ thực vật lên bánh mì.","fa":"او مارگارین را روی نان پخش می کند."},{"de":"Für den Kuchen brauchen wir Margarine statt Butter.","en":"For the cake we need margarine instead of butter.","ru":"Для торта нам нужен маргарин вместо масла.","vi":"Đối với bánh chúng ta cần bơ thực vật thay vì bơ.","fa":"برای کیک به جای کره به مارگارین نیاز داریم."}]},{"word":"die Marille","en":"the apricot","ru":"абрикос","vi":"quả mơ","fa":"زردآلو","examples":[{"de":"Im Sommer kaufen wir frische Marillen am Markt.","en":"In summer we buy fresh apricots at the market.","ru":"Летом мы покупаем свежие абрикосы на рынке.","vi":"Vào mùa hè, chúng tôi mua mơ tươi ở chợ.","fa":"در تابستان زردآلو تازه از بازار می خریم."},{"de":"Aus den Marillen macht meine Oma leckere Marmelade.","en":"My grandma makes delicious jam from the apricots.","ru":"Из абрикосов моя бабушка делает вкусное варенье.","vi":"Bà tôi làm món mứt ngon từ mơ.","fa":"مادربزرگ من از زردآلو مربای خوشمزه درست می کند."}]},{"word":"die Marke","en":"the brand; the stamp","ru":"марка; бренд","vi":"thương hiệu","fa":"نام تجاری","examples":[{"de":"Er kauft immer Kleidung von bekannten Marken.","en":"He always buys clothes from well-known brands.","ru":"Он всегда покупает одежду известных брендов.","vi":"Anh ấy luôn mua quần áo của những thương hiệu nổi tiếng.","fa":"او همیشه از برندهای معروف لباس می خرد."},{"de":"Ich brauche noch eine Marke für den Brief.","en":"I still need a stamp for the letter.","ru":"Мне ещё нужна марка для письма.","vi":"Tôi vẫn cần một con tem cho bức thư.","fa":"من هنوز برای نامه مهر نیاز دارم."}]},{"word":"markieren","en":"to mark","ru":"отмечать; маркировать","vi":"đánh dấu","fa":"علامت گذاری کنید","examples":[{"de":"Bitte markiere die wichtigen Wörter im Text.","en":"Please mark the important words in the text.","ru":"Пожалуйста, отметь важные слова в тексте.","vi":"Hãy đánh dấu những từ quan trọng trong văn bản.","fa":"لطفا کلمات مهم در متن را علامت بزنید."},{"de":"Der Weg im Wald ist mit gelben Zeichen markiert.","en":"The path in the forest is marked with yellow signs.","ru":"Тропа в лесу отмечена жёлтыми знаками.","vi":"Con đường trong rừng được đánh dấu bằng biển báo màu vàng.","fa":"مسیر در جنگل با علائم زرد مشخص شده است."}]},{"word":"der Markt","en":"market","ru":"рынок","vi":"thị trường","fa":"بازار","examples":[{"de":"Am Samstag gehe ich immer auf den Markt, um frisches Gemüse zu kaufen.","en":"On Saturdays I always go to the market to buy fresh vegetables.","ru":"По субботам я всегда хожу на рынок, чтобы купить свежие овощи.","vi":"Vào thứ bảy tôi luôn đi chợ mua rau tươi.","fa":"روز شنبه همیشه برای خرید سبزیجات تازه به بازار می روم."},{"de":"Der Markt für Elektroautos wächst schnell.","en":"The market for electric cars is growing quickly.","ru":"Рынок электромобилей быстро растёт.","vi":"Thị trường ô tô điện đang phát triển nhanh chóng.","fa":"بازار خودروهای الکتریکی به سرعت در حال رشد است."}]},{"word":"die Marmelade","en":"jam","ru":"варенье, джем","vi":"mứt","fa":"مربا","examples":[{"de":"Zum Frühstück esse ich gerne Brot mit Marmelade.","en":"For breakfast I like to eat bread with jam.","ru":"На завтрак я люблю есть хлеб с вареньем.","vi":"Tôi thích ăn bánh mì với mứt vào bữa sáng.","fa":"من دوست دارم صبحانه نان با مربا بخورم."},{"de":"Meine Oma kocht jedes Jahr Marmelade aus Erdbeeren.","en":"My grandma makes jam from strawberries every year.","ru":"Моя бабушка каждый год варит варенье из клубники.","vi":"Bà tôi làm mứt dâu hàng năm.","fa":"مادربزرگ من هر سال مربای توت فرنگی درست می کند."}]},{"word":"die Maschine","en":"machine","ru":"машина, станок","vi":"cái máy","fa":"دستگاه","examples":[{"de":"Die Maschine in der Fabrik produziert hundert Teile pro Stunde.","en":"The machine in the factory produces a hundred parts per hour.","ru":"Станок на фабрике производит сто деталей в час.","vi":"Máy móc trong nhà máy sản xuất được hàng trăm bộ phận mỗi giờ.","fa":"دستگاه در کارخانه صد قطعه در ساعت تولید می کند."},{"de":"Diese Waschmaschine ist eine sehr moderne Maschine.","en":"This washing machine is a very modern machine.","ru":"Эта стиральная машина — очень современная техника.","vi":"Máy giặt này là một chiếc máy rất hiện đại.","fa":"این ماشین لباسشویی یک ماشین لباسشویی بسیار مدرن است."}]},{"word":"das Material","en":"material","ru":"материал","vi":"vật liệu","fa":"مواد","examples":[{"de":"Für das Regal brauchen wir Holz als Material.","en":"For the shelf we need wood as material.","ru":"Для полки нам нужно дерево в качестве материала.","vi":"Đối với kệ chúng ta cần gỗ làm vật liệu.","fa":"برای قفسه به چوب به عنوان متریال نیاز داریم."},{"de":"Der Lehrer verteilt das Material für den Kurs.","en":"The teacher hands out the material for the course.","ru":"Преподаватель раздаёт материал для курса.","vi":"Giáo viên phát tài liệu cho khóa học.","fa":"معلم مطالب دوره را توزیع می کند."}]},{"word":"die Matura","en":"school-leaving exam (Abitur, in Austria/Switzerland)","ru":"экзамен на аттестат зрелости (аналог ЕГЭ/Abitur в Австрии и Швейцарии)","vi":"người trưởng thành","fa":"بالغ","examples":[{"de":"Nach der Matura möchte sie an der Universität studieren.","en":"After her school-leaving exam, she wants to study at university.","ru":"После сдачи экзамена на аттестат зрелости она хочет учиться в университете.","vi":"Sau khi tốt nghiệp cấp 3, cô muốn học lên đại học.","fa":"پس از فارغ التحصیلی از دبیرستان، او دوست دارد در دانشگاه تحصیل کند."},{"de":"Er hat die Matura mit sehr guten Noten bestanden.","en":"He passed his school-leaving exam with very good grades.","ru":"Он сдал выпускной экзамен с очень хорошими оценками.","vi":"Anh ấy đã đậu bằng tốt nghiệp trung học với điểm số rất tốt.","fa":"دیپلم دبیرستان را با نمرات بسیار خوب گذراند."}]},{"word":"die Mauer","en":"wall","ru":"стена","vi":"bức tường","fa":"دیوار","examples":[{"de":"Um den Garten steht eine hohe Mauer.","en":"There is a high wall around the garden.","ru":"Вокруг сада стоит высокая стена.","vi":"Xung quanh vườn có tường cao.","fa":"اطراف باغ دیوار بلندی است."},{"de":"Die Berliner Mauer fiel im Jahr 1989.","en":"The Berlin Wall fell in 1989.","ru":"Берлинская стена пала в 1989 году.","vi":"Bức tường Berlin sụp đổ năm 1989.","fa":"دیوار برلین در سال 1989 فرو ریخت."}]},{"word":"maximal","en":"maximum; at most","ru":"максимальный; максимум","vi":"tối đa","fa":"حداکثر","examples":[{"de":"Der Aufzug darf maximal acht Personen tragen.","en":"The elevator may carry a maximum of eight people.","ru":"Лифт может перевозить максимум восемь человек.","vi":"Thang máy có thể chở tối đa tám người.","fa":"این آسانسور حداکثر می تواند هشت نفر را حمل کند."},{"de":"Die Reise dauert maximal drei Stunden.","en":"The trip takes at most three hours.","ru":"Поездка длится максимум три часа.","vi":"Cuộc hành trình mất tối đa ba giờ.","fa":"سفر حداکثر سه ساعت طول می کشد."}]},{"word":"der Mechaniker","en":"mechanic","ru":"механик","vi":"thợ cơ khí","fa":"مکانیک","examples":[{"de":"Der Mechaniker repariert mein Auto in der Werkstatt.","en":"The mechanic is repairing my car in the workshop.","ru":"Механик ремонтирует мою машину в мастерской.","vi":"Người thợ sửa xe của tôi ở xưởng.","fa":"مکانیک ماشین من را در کارگاه تعمیر می کند."},{"de":"Mein Bruder arbeitet als Mechaniker bei einer Autofirma.","en":"My brother works as a mechanic at a car company.","ru":"Мой брат работает механиком в автомобильной компании.","vi":"Anh trai tôi làm thợ cơ khí ở một công ty ô tô.","fa":"برادرم به عنوان مکانیک در یک شرکت خودروسازی کار می کند."}]},{"word":"die Medien","en":"media","ru":"СМИ, медиа","vi":"phương tiện truyền thông","fa":"رسانه ها","examples":[{"de":"Die Medien berichten heute viel über die Wahl.","en":"The media are reporting a lot about the election today.","ru":"СМИ сегодня много пишут о выборах.","vi":"Các phương tiện truyền thông đang đưa tin rất nhiều về cuộc bầu cử ngày hôm nay.","fa":"رسانه ها امروز اخبار زیادی درباره انتخابات دارند."},{"de":"Soziale Medien spielen im Alltag junger Leute eine große Rolle.","en":"Social media play a big role in young people's everyday lives.","ru":"Социальные сети играют большую роль в повседневной жизни молодёжи.","vi":"Phương tiện truyền thông xã hội đóng một vai trò lớn trong cuộc sống hàng ngày của giới trẻ.","fa":"رسانه های اجتماعی نقش مهمی در زندگی روزمره جوانان ایفا می کنند."}]},{"word":"das Medikament","en":"medicine (medication)","ru":"лекарство","vi":"thuốc","fa":"دارو","examples":[{"de":"Der Arzt hat mir ein neues Medikament verschrieben.","en":"The doctor prescribed me a new medicine.","ru":"Врач прописал мне новое лекарство.","vi":"Bác sĩ kê cho tôi một loại thuốc mới.","fa":"دکتر برایم داروی جدیدی تجویز کرد."},{"de":"Du musst das Medikament dreimal am Tag nehmen.","en":"You have to take the medicine three times a day.","ru":"Тебе нужно принимать лекарство три раза в день.","vi":"Bạn phải uống thuốc ba lần một ngày.","fa":"شما باید دارو را سه بار در روز مصرف کنید."}]},{"word":"die Medizin","en":"medicine (the field/science; also medication)","ru":"медицина (также лекарство)","vi":"thuốc","fa":"دارو","examples":[{"de":"Sie studiert Medizin, um Ärztin zu werden.","en":"She is studying medicine to become a doctor.","ru":"Она изучает медицину, чтобы стать врачом.","vi":"Cô ấy đang học y khoa để trở thành bác sĩ.","fa":"او در حال تحصیل پزشکی است تا دکتر شود."},{"de":"Die moderne Medizin hat viele Krankheiten heilbar gemacht.","en":"Modern medicine has made many diseases curable.","ru":"Современная медицина сделала многие болезни излечимыми.","vi":"Y học hiện đại đã chữa được nhiều bệnh.","fa":"طب مدرن بسیاری از بیماری ها را قابل درمان کرده است."}]},{"word":"das Meer","en":"sea","ru":"море","vi":"biển","fa":"دریا","examples":[{"de":"Im Sommer fahren wir jedes Jahr ans Meer.","en":"Every summer we go to the sea.","ru":"Каждое лето мы ездим на море.","vi":"Mùa hè nào chúng tôi cũng đi biển.","fa":"هر تابستان در تابستان به دریا می رویم."},{"de":"Das Meer war heute ruhig und blau.","en":"The sea was calm and blue today.","ru":"Море сегодня было спокойным и синим.","vi":"Biển hôm nay lặng và trong xanh.","fa":"دریا امروز آرام و آبی بود."}]},{"word":"das Mehl","en":"flour","ru":"мука","vi":"bột mì","fa":"آرد","examples":[{"de":"Für den Kuchen brauchst du 500 Gramm Mehl.","en":"For the cake you need 500 grams of flour.","ru":"Для торта тебе нужно 500 граммов муки.","vi":"Đối với bánh bạn cần 500 gram bột mì.","fa":"برای کیک به 500 گرم آرد نیاز دارید."},{"de":"Sie kauft Mehl, um Brot zu backen.","en":"She buys flour to bake bread.","ru":"Она покупает муку, чтобы испечь хлеб.","vi":"Cô ấy mua bột mì để nướng bánh mì.","fa":"آرد می خرد تا نان بپزد."}]},{"word":"mehr (siehe auch viel)","en":"more","ru":"больше","vi":"hơn (xem thêm rất nhiều)","fa":"بیشتر (بسیار را نیز ببینید)","examples":[{"de":"Ich brauche mehr Zeit für die Aufgabe.","en":"I need more time for the task.","ru":"Мне нужно больше времени для этого задания.","vi":"Tôi cần thêm thời gian cho nhiệm vụ.","fa":"برای کار به زمان بیشتری نیاز دارم."},{"de":"Er verdient jetzt mehr als früher.","en":"He earns more now than before.","ru":"Сейчас он зарабатывает больше, чем раньше.","vi":"Bây giờ anh ấy kiếm được nhiều tiền hơn trước.","fa":"او الان بیشتر از قبل درآمد دارد."}]},{"word":"die Mehrheit","en":"majority","ru":"большинство","vi":"đa số","fa":"اکثریت","examples":[{"de":"Die Mehrheit der Schüler war mit dem Vorschlag einverstanden.","en":"The majority of the students agreed with the proposal.","ru":"Большинство учеников согласились с предложением.","vi":"Đa số sinh viên đồng ý với đề xuất này.","fa":"اکثریت دانشجویان با این پیشنهاد موافقت کردند."},{"de":"Bei der Wahl bekam die Partei die Mehrheit der Stimmen.","en":"In the election, the party got the majority of the votes.","ru":"На выборах партия получила большинство голосов.","vi":"Đảng đã nhận được đa số phiếu trong cuộc bầu cử.","fa":"این حزب اکثریت آرا را در انتخابات به دست آورد."}]},{"word":"die Mehrwertsteuer","en":"value-added tax (VAT)","ru":"налог на добавленную стоимость (НДС)","vi":"thuế GTGT","fa":"مالیات بر ارزش افزوده","examples":[{"de":"Die Mehrwertsteuer in Deutschland beträgt normalerweise 19 Prozent.","en":"VAT in Germany is normally 19 percent.","ru":"НДС в Германии обычно составляет 19 процентов.","vi":"VAT ở Đức thường là 19%.","fa":"مالیات بر ارزش افزوده در آلمان به طور معمول 19 درصد است."},{"de":"Der Preis auf dem Etikett enthält schon die Mehrwertsteuer.","en":"The price on the label already includes VAT.","ru":"Цена на ценнике уже включает НДС.","vi":"Giá trên nhãn đã bao gồm VAT.","fa":"قیمت روی برچسب قبلاً شامل مالیات بر ارزش افزوده است."}]},{"word":"meinen","en":"to think; to mean","ru":"думать, полагать; иметь в виду","vi":"nghĩa là","fa":"معنی","examples":[{"de":"Ich meine, dass wir früher losfahren sollten.","en":"I think we should leave earlier.","ru":"Я думаю, что нам следует выехать раньше.","vi":"Tôi nghĩ chúng ta nên rời đi sớm hơn.","fa":"فکر کنم زودتر بریم"},{"de":"Was meinst du mit diesem Satz?","en":"What do you mean by this sentence?","ru":"Что ты имеешь в виду под этим предложением?","vi":"Bạn có ý gì qua câu này?","fa":"منظور شما از این جمله چیست؟"}]},{"word":"meinetwegen","en":"because of me; as far as I'm concerned (fine by me)","ru":"из-за меня; ладно, я не против","vi":"vì lợi ích của tôi","fa":"به خاطر من","examples":[{"de":"Ihr müsst nicht meinetwegen warten.","en":"You don't have to wait because of me.","ru":"Вам не нужно ждать из-за меня.","vi":"Bạn không cần phải đợi tôi.","fa":"لازم نیست منتظر من باشی"},{"de":"Meinetwegen können wir auch ins Kino gehen.","en":"As far as I'm concerned, we can also go to the cinema.","ru":"Что касается меня, мы можем пойти и в кино.","vi":"Theo như tôi được biết, chúng ta cũng có thể đi xem phim.","fa":"تا جایی که من می توانم به سینما هم برویم."}]},{"word":"die Meinung","en":"opinion","ru":"мнение","vi":"ý kiến","fa":"نظر","examples":[{"de":"Meiner Meinung nach ist dieser Film sehr gut.","en":"In my opinion, this film is very good.","ru":"По моему мнению, этот фильм очень хороший.","vi":"Theo tôi bộ phim này rất hay.","fa":"به نظر من این فیلم خیلی خوبه"},{"de":"Wir haben unterschiedliche Meinungen zu diesem Thema.","en":"We have different opinions on this topic.","ru":"У нас разные мнения по этому вопросу.","vi":"Chúng tôi có ý kiến ​​​​khác nhau về chủ đề này.","fa":"ما نظرات مختلفی در مورد این موضوع داریم."}]},{"word":"meist-","en":"most (prefix/stem, e.g. 'die meisten' = most people/things)","ru":"большинство (основа, напр. 'die meisten' — большинство)","vi":"chủ yếu-","fa":"بیشتر-","examples":[{"de":"Die meisten Leute in meiner Klasse kommen aus der Stadt.","en":"Most of the people in my class come from the city.","ru":"Большинство людей в моём классе из города.","vi":"Hầu hết mọi người trong lớp tôi đều đến từ thành phố.","fa":"اکثر افراد کلاس من اهل شهر هستند."},{"de":"Die meisten Geschäfte schließen sonntags.","en":"Most shops close on Sundays.","ru":"Большинство магазинов закрыты по воскресеньям.","vi":"Hầu hết các cửa hàng đóng cửa vào ngày chủ nhật.","fa":"اکثر مغازه ها یکشنبه ها تعطیل می شوند."}]},{"word":"meist(ens)","en":"mostly; usually","ru":"обычно, большей частью","vi":"chủ yếu","fa":"بیشتر","examples":[{"de":"Ich fahre meistens mit dem Fahrrad zur Arbeit.","en":"I usually go to work by bike.","ru":"Обычно я езжу на работу на велосипеде.","vi":"Tôi thường đi xe đạp đi làm.","fa":"من معمولاً با دوچرخه به سر کار می روم."},{"de":"Am Wochenende bleiben wir meist zu Hause.","en":"On weekends we mostly stay at home.","ru":"По выходным мы обычно остаёмся дома.","vi":"Chúng tôi thường ở nhà vào cuối tuần.","fa":"ما معمولا آخر هفته ها در خانه می مانیم."}]},{"word":"der Meister","en":"master (craftsman); champion","ru":"мастер; чемпион","vi":"chủ nhân","fa":"استاد","examples":[{"de":"Mein Onkel ist Meister in seinem Handwerk.","en":"My uncle is a master of his craft.","ru":"Мой дядя — мастер своего ремесла.","vi":"Chú tôi là bậc thầy trong nghề của mình.","fa":"دایی من در کار خود استاد است."},{"de":"Die Mannschaft wurde dieses Jahr deutscher Meister.","en":"The team became German champion this year.","ru":"В этом году команда стала чемпионом Германии.","vi":"Đội đã trở thành nhà vô địch Đức năm nay.","fa":"این تیم امسال قهرمان آلمان شد."}]},{"word":"melden","en":"to report","ru":"сообщать, заявлять","vi":"báo cáo","fa":"گزارش دهید","examples":[{"de":"Ich möchte einen Diebstahl bei der Polizei melden.","en":"I would like to report a theft to the police.","ru":"Я хочу заявить в полицию о краже.","vi":"Tôi muốn báo cảnh sát về một vụ trộm.","fa":"من می خواهم یک سرقت را به پلیس گزارش کنم."},{"de":"Der Lehrer meldete den Vorfall der Schulleitung.","en":"The teacher reported the incident to the school management.","ru":"Учитель сообщил о происшествии руководству школы.","vi":"Cô giáo đã báo cáo sự việc với ban giám hiệu nhà trường.","fa":"معلم ماجرا را به مدیریت مدرسه گزارش داد."}]},{"word":"die Meldung","en":"report; notification; news item","ru":"сообщение; уведомление","vi":"tin nhắn","fa":"پیام","examples":[{"de":"In den Nachrichten kam eine wichtige Meldung.","en":"There was an important news item on the news.","ru":"В новостях было важное сообщение.","vi":"Có một tin nhắn quan trọng trên bản tin.","fa":"پیام مهمی در این خبر وجود داشت."},{"de":"Das Programm zeigt eine Meldung, wenn ein Fehler auftritt.","en":"The program shows a notification when an error occurs.","ru":"Программа показывает уведомление, когда возникает ошибка.","vi":"Chương trình hiển thị thông báo khi xảy ra lỗi.","fa":"در صورت بروز خطا، برنامه پیامی را نمایش می دهد."}]},{"word":"die Menge","en":"amount, quantity; crowd","ru":"количество; толпа","vi":"đám đông","fa":"جمعیت","examples":[{"de":"Wir brauchen eine große Menge Wasser für das Fest.","en":"We need a large amount of water for the festival.","ru":"Нам нужно большое количество воды для праздника.","vi":"Chúng ta cần một lượng nước lớn cho lễ hội.","fa":"برای جشنواره به مقدار زیادی آب نیاز داریم."},{"de":"Eine riesige Menge Menschen versammelte sich auf dem Platz.","en":"A huge crowd of people gathered in the square.","ru":"Огромная толпа людей собралась на площади.","vi":"Một đám đông khổng lồ tập trung tại quảng trường.","fa":"جمعیت عظیمی از مردم در میدان جمع شده بودند."}]},{"word":"die Mensa","en":"university cafeteria (canteen)","ru":"студенческая столовая","vi":"quán ăn tự phục vụ","fa":"کافه تریا","examples":[{"de":"Wir essen mittags oft in der Mensa.","en":"We often eat lunch at the university cafeteria.","ru":"Мы часто обедаем в студенческой столовой.","vi":"Chúng tôi thường ăn trưa ở căng tin.","fa":"ما اغلب ناهار را در کافه تریا می خوریم."},{"de":"Das Essen in der Mensa ist billig, aber gut.","en":"The food at the cafeteria is cheap but good.","ru":"Еда в столовой дешёвая, но хорошая.","vi":"Đồ ăn ở căng tin rẻ nhưng ngon.","fa":"غذای کافه تریا ارزان اما خوب است."}]},{"word":"der Mensch","en":"human being; person","ru":"человек","vi":"con người","fa":"انسان","examples":[{"de":"Jeder Mensch hat das Recht auf Bildung.","en":"Every human being has the right to education.","ru":"Каждый человек имеет право на образование.","vi":"Mọi người đều có quyền được giáo dục.","fa":"هر فرد حق تحصیل دارد."},{"de":"In der Stadt leben über eine Million Menschen.","en":"More than a million people live in the city.","ru":"В городе живёт более миллиона человек.","vi":"Hơn một triệu người sống ở thành phố.","fa":"بیش از یک میلیون نفر در این شهر زندگی می کنند."}]},{"word":"das Menü","en":"menu","ru":"меню","vi":"thực đơn","fa":"منو","examples":[{"de":"Der Kellner bringt uns das Menü.","en":"The waiter brings us the menu.","ru":"Официант приносит нам меню.","vi":"Người phục vụ mang thực đơn đến cho chúng tôi.","fa":"پیشخدمت منو می آورد."},{"de":"Ich nehme heute das Menü mit Suppe und Fleisch.","en":"Today I'll have the set menu with soup and meat.","ru":"Сегодня я возьму комплексный обед с супом и мясом.","vi":"Hôm nay tôi chọn thực đơn có súp và thịt.","fa":"امروز منو با سوپ و گوشت میگیرم."}]},{"word":"merken","en":"to notice; to remember","ru":"замечать; запоминать","vi":"nhớ","fa":"به یاد داشته باشید","examples":[{"de":"Ich habe gemerkt, dass die Tür offen war.","en":"I noticed that the door was open.","ru":"Я заметил, что дверь была открыта.","vi":"Tôi nhận thấy rằng cánh cửa đã mở.","fa":"متوجه شدم در باز است."},{"de":"Kannst du dir seine Telefonnummer merken?","en":"Can you remember his phone number?","ru":"Ты можешь запомнить его номер телефона?","vi":"Bạn có thể nhớ số điện thoại của anh ấy không?","fa":"آیا می توانید شماره تلفن او را به خاطر بسپارید؟"}]},{"word":"merkwürdig","en":"strange, odd","ru":"странный","vi":"kỳ lạ","fa":"عجیب","examples":[{"de":"Es ist merkwürdig, dass niemand auf meine E-Mail geantwortet hat.","en":"It's strange that nobody answered my email.","ru":"Странно, что никто не ответил на моё письмо.","vi":"Thật kỳ lạ là không ai trả lời email của tôi.","fa":"عجیب است که کسی به ایمیل من پاسخ نداد."},{"de":"Ich habe ein merkwürdiges Geräusch im Keller gehört.","en":"I heard a strange noise in the basement.","ru":"Я услышал странный звук в подвале.","vi":"Tôi nghe thấy một tiếng động lạ ở tầng hầm.","fa":"صدای عجیبی در زیرزمین شنیدم."}]},{"word":"die Messe","en":"trade fair; Mass (church service)","ru":"ярмарка, выставка; месса (церковная служба)","vi":"hội chợ","fa":"نمایشگاه","examples":[{"de":"Jedes Jahr besuchen wir die Buchmesse in Frankfurt.","en":"Every year we visit the book fair in Frankfurt.","ru":"Каждый год мы посещаем книжную ярмарку во Франкфурте.","vi":"Hàng năm chúng tôi đều đến thăm hội chợ sách ở Frankfurt.","fa":"هر سال از نمایشگاه کتاب در فرانکفورت بازدید می کنیم."},{"de":"Am Sonntag geht meine Großmutter in die Messe.","en":"On Sunday my grandmother goes to Mass.","ru":"По воскресеньям моя бабушка ходит на мессу.","vi":"Chủ nhật bà tôi đi lễ.","fa":"روز یکشنبه مادربزرگم به عشاء می رود."}]},{"word":"messen","en":"to measure","ru":"измерять","vi":"đo lường","fa":"اندازه گیری","examples":[{"de":"Der Arzt misst meinen Blutdruck.","en":"The doctor measures my blood pressure.","ru":"Врач измеряет моё давление.","vi":"Bác sĩ đo huyết áp của tôi.","fa":"دکتر فشار خونم رو اندازه میگیره"},{"de":"Wir haben die Länge des Zimmers gemessen.","en":"We measured the length of the room.","ru":"Мы измерили длину комнаты.","vi":"Chúng tôi đo chiều dài của căn phòng.","fa":"طول اتاق را اندازه گرفتیم."}]},{"word":"das Messer","en":"knife","ru":"нож","vi":"con dao","fa":"چاقو","examples":[{"de":"Kannst du mir bitte ein scharfes Messer geben?","en":"Can you give me a sharp knife, please?","ru":"Не мог бы ты дать мне острый нож?","vi":"Bạn có thể vui lòng cho tôi một con dao sắc được không?","fa":"میشه لطفا یک چاقوی تیز به من بدهید؟"},{"de":"Sie schneidet das Brot mit einem Messer.","en":"She cuts the bread with a knife.","ru":"Она режет хлеб ножом.","vi":"Cô ấy cắt bánh mì bằng một con dao.","fa":"نان را با چاقو برش می دهد."}]},{"word":"das Metall","en":"metal","ru":"металл","vi":"kim loại","fa":"فلز","examples":[{"de":"Die Brücke besteht aus Metall.","en":"The bridge is made of metal.","ru":"Мост сделан из металла.","vi":"Cây cầu được làm bằng kim loại.","fa":"پل از فلز ساخته شده است."},{"de":"Gold ist ein wertvolles Metall.","en":"Gold is a valuable metal.","ru":"Золото — ценный металл.","vi":"Vàng là một kim loại có giá trị.","fa":"طلا یک فلز ارزشمند است."}]},{"word":"die Methode","en":"method","ru":"метод","vi":"phương pháp","fa":"روش","examples":[{"de":"Diese Methode hilft beim Lernen neuer Wörter.","en":"This method helps with learning new words.","ru":"Этот метод помогает в изучении новых слов.","vi":"Phương pháp này giúp học từ mới.","fa":"این روش به یادگیری کلمات جدید کمک می کند."},{"de":"Der Wissenschaftler entwickelte eine neue Methode.","en":"The scientist developed a new method.","ru":"Учёный разработал новый метод.","vi":"Nhà khoa học đã phát triển một phương pháp mới.","fa":"این دانشمند روش جدیدی ابداع کرد."}]},{"word":"die Metropole","en":"metropolis","ru":"мегаполис","vi":"đô thị","fa":"کلان شهر","examples":[{"de":"Berlin ist eine bekannte europäische Metropole.","en":"Berlin is a well-known European metropolis.","ru":"Берлин — известный европейский мегаполис.","vi":"Berlin là một đô thị nổi tiếng của châu Âu.","fa":"برلین یک کلان شهر اروپایی شناخته شده است."},{"de":"In der Metropole gibt es viele Möglichkeiten für junge Leute.","en":"In the metropolis there are many opportunities for young people.","ru":"В мегаполисе много возможностей для молодёжи.","vi":"Có rất nhiều cơ hội cho những người trẻ tuổi ở thủ đô.","fa":"فرصت های زیادی برای جوانان در کلان شهر وجود دارد."}]},{"word":"der Metzger","en":"butcher","ru":"мясник","vi":"người bán thịt","fa":"قصاب","examples":[{"de":"Ich kaufe das Fleisch immer beim Metzger um die Ecke.","en":"I always buy meat at the butcher's around the corner.","ru":"Я всегда покупаю мясо у мясника за углом.","vi":"Tôi luôn mua thịt từ người bán thịt quanh góc phố.","fa":"من همیشه از قصابی در گوشه گوشه گوشت می خرم."},{"de":"Der Metzger empfahl uns ein gutes Stück Fleisch.","en":"The butcher recommended us a good piece of meat.","ru":"Мясник посоветовал нам хороший кусок мяса.","vi":"Người bán thịt giới thiệu cho chúng tôi một miếng thịt ngon.","fa":"قصاب یک تکه گوشت خوب به ما توصیه کرد."}]},{"word":"die Miete","en":"rent","ru":"аренда; арендная плата","vi":"tiền thuê nhà","fa":"اجاره","examples":[{"de":"Die Miete für die Wohnung ist ziemlich hoch.","en":"The rent for the flat is quite high.","ru":"Арендная плата за квартиру довольно высокая.","vi":"Giá thuê căn hộ khá cao.","fa":"اجاره آپارتمان بسیار بالاست."},{"de":"Ich überweise die Miete immer am Monatsanfang.","en":"I always transfer the rent at the beginning of the month.","ru":"Я всегда перевожу арендную плату в начале месяца.","vi":"Tôi luôn trả tiền thuê nhà vào đầu tháng.","fa":"من همیشه اول ماه اجاره را پرداخت می کنم."}]},{"word":"mieten","en":"to rent","ru":"арендовать, снимать","vi":"thuê","fa":"اجاره","examples":[{"de":"Wir möchten für den Urlaub ein Auto mieten.","en":"We would like to rent a car for the holiday.","ru":"Мы хотим арендовать машину на время отпуска.","vi":"Chúng tôi muốn thuê một chiếc xe hơi cho kỳ nghỉ của chúng tôi.","fa":"ما می خواهیم برای تعطیلات خود یک ماشین اجاره کنیم."},{"de":"Er mietet eine kleine Wohnung in der Innenstadt.","en":"He is renting a small apartment in the city center.","ru":"Он снимает маленькую квартиру в центре города.","vi":"Anh thuê một căn hộ nhỏ ở trung tâm thành phố.","fa":"او یک آپارتمان کوچک در مرکز شهر اجاره می کند."}]},{"word":"der Mieter","en":"tenant","ru":"арендатор; квартиросъёмщик","vi":"người thuê nhà","fa":"مستاجر","examples":[{"de":"Der neue Mieter zieht nächste Woche ein.","en":"The new tenant is moving in next week.","ru":"Новый арендатор въезжает на следующей неделе.","vi":"Người thuê nhà mới sẽ chuyển đến vào tuần tới.","fa":"مستاجر جدید در هفته آینده نقل مکان می کند."},{"de":"Als Mieter hat man bestimmte Rechte und Pflichten.","en":"As a tenant you have certain rights and duties.","ru":"У арендатора есть определённые права и обязанности.","vi":"Là người thuê nhà, bạn có những quyền và nghĩa vụ nhất định.","fa":"به عنوان یک مستاجر، شما حقوق و تعهدات خاصی دارید."}]},{"word":"der Migrant","en":"migrant","ru":"мигрант","vi":"người di cư","fa":"مهاجر","examples":[{"de":"Viele Migranten suchen in Deutschland Arbeit.","en":"Many migrants look for work in Germany.","ru":"Многие мигранты ищут работу в Германии.","vi":"Nhiều người di cư đang tìm kiếm việc làm ở Đức.","fa":"بسیاری از مهاجران به دنبال کار در آلمان هستند."},{"de":"Die Stadt hilft Migranten bei der Integration.","en":"The city helps migrants with integration.","ru":"Город помогает мигрантам с интеграцией.","vi":"Thành phố giúp người di cư hòa nhập.","fa":"این شهر به مهاجران کمک می کند تا ادغام شوند."}]},{"word":"die Migration","en":"migration","ru":"миграция","vi":"sự di cư","fa":"مهاجرت","examples":[{"de":"Die Migration nach Europa hat viele Ursachen.","en":"Migration to Europe has many causes.","ru":"У миграции в Европу много причин.","vi":"Di cư sang châu Âu có nhiều nguyên nhân.","fa":"مهاجرت به اروپا دلایل زیادی دارد."},{"de":"Das Land diskutiert über eine neue Politik zur Migration.","en":"The country is discussing a new policy on migration.","ru":"Страна обсуждает новую политику в отношении миграции.","vi":"Đất nước đang thảo luận về một chính sách di cư mới.","fa":"این کشور در حال بحث در مورد سیاست مهاجرتی جدید است."}]},{"word":"die Milch","en":"milk","ru":"молоко","vi":"sữa","fa":"شیر","examples":[{"de":"Ich trinke morgens gern ein Glas Milch.","en":"In the morning I like to drink a glass of milk.","ru":"Утром я люблю пить стакан молока.","vi":"Tôi thích uống một ly sữa vào buổi sáng.","fa":"من دوست دارم صبح یک لیوان شیر بخورم."},{"de":"Kannst du bitte Milch für den Kaffee kaufen?","en":"Can you please buy milk for the coffee?","ru":"Можешь купить молока для кофе?","vi":"Bạn có thể vui lòng mua sữa cho cà phê được không?","fa":"میشه لطفا برای قهوه شیر بخرید؟"}]},{"word":"mild","en":"mild","ru":"мягкий, умеренный","vi":"nhẹ nhàng","fa":"خفیف","examples":[{"de":"Der Winter war dieses Jahr sehr mild.","en":"The winter was very mild this year.","ru":"Зима в этом году была очень мягкой.","vi":"Mùa đông năm nay rất ôn hòa.","fa":"زمستان امسال بسیار معتدل بود."},{"de":"Ich mag diesen Käse, weil er mild schmeckt.","en":"I like this cheese because it tastes mild.","ru":"Мне нравится этот сыр, потому что у него мягкий вкус.","vi":"Tôi thích loại phô mai này vì nó có vị nhẹ.","fa":"من این پنیر را دوست دارم چون طعم ملایمی دارد."}]},{"word":"die Minderheit","en":"minority","ru":"меньшинство","vi":"thiểu số","fa":"اقلیت","examples":[{"de":"Nur eine Minderheit der Bevölkerung stimmte dagegen.","en":"Only a minority of the population voted against it.","ru":"Против проголосовало лишь меньшинство населения.","vi":"Chỉ có một thiểu số dân chúng bỏ phiếu chống lại nó.","fa":"تنها اقلیتی از مردم به آن رای منفی دادند."},{"de":"Der Verein schützt die Rechte nationaler Minderheiten.","en":"The association protects the rights of national minorities.","ru":"Организация защищает права национальных меньшинств.","vi":"Hiệp hội bảo vệ quyền lợi của các dân tộc thiểu số.","fa":"این انجمن از حقوق اقلیت های ملی حمایت می کند."}]},{"word":"mindestens","en":"at least","ru":"по крайней мере, как минимум","vi":"ít nhất","fa":"حداقل","examples":[{"de":"Du solltest mindestens acht Stunden schlafen.","en":"You should sleep at least eight hours.","ru":"Тебе следует спать как минимум восемь часов.","vi":"Bạn nên ngủ ít nhất tám giờ.","fa":"شما باید حداقل هشت ساعت بخوابید."},{"de":"Die Fahrt dauert mindestens zwei Stunden.","en":"The trip takes at least two hours.","ru":"Поездка длится по крайней мере два часа.","vi":"Cuộc hành trình mất ít nhất hai giờ.","fa":"سفر حداقل دو ساعت طول می کشد."}]},{"word":"das Mineralwasser","en":"mineral water","ru":"минеральная вода","vi":"nước khoáng","fa":"آب معدنی","examples":[{"de":"Bitte bringen Sie mir eine Flasche Mineralwasser.","en":"Please bring me a bottle of mineral water.","ru":"Принесите мне, пожалуйста, бутылку минеральной воды.","vi":"Vui lòng mang cho tôi một chai nước khoáng.","fa":"لطفا برای من یک بطری آب معدنی بیاورید."},{"de":"Er trinkt lieber Mineralwasser als Limonade.","en":"He prefers to drink mineral water rather than soda.","ru":"Он предпочитает пить минеральную воду, а не лимонад.","vi":"Anh ấy thích uống nước khoáng hơn nước chanh.","fa":"او نوشیدن آب معدنی را به لیموناد ترجیح می دهد."}]},{"word":"minimal","en":"minimal","ru":"минимальный","vi":"tối thiểu","fa":"حداقل","examples":[{"de":"Der Unterschied zwischen den beiden Preisen ist minimal.","en":"The difference between the two prices is minimal.","ru":"Разница между этими двумя ценами минимальна.","vi":"Sự khác biệt giữa hai mức giá là tối thiểu.","fa":"تفاوت بین این دو قیمت حداقل است."},{"de":"Wir hatten nur minimale Probleme mit dem neuen System.","en":"We only had minimal problems with the new system.","ru":"У нас были лишь минимальные проблемы с новой системой.","vi":"Chúng tôi gặp rất ít vấn đề với hệ thống mới.","fa":"ما با سیستم جدید کمترین مشکل را داشتیم."}]},{"word":"mischen","en":"to mix","ru":"смешивать","vi":"trộn","fa":"مخلوط کردن","examples":[{"de":"Man muss Mehl, Eier und Milch gut mischen.","en":"You have to mix flour, eggs and milk well.","ru":"Нужно хорошо смешать муку, яйца и молоко.","vi":"Bạn phải trộn đều bột mì, trứng và sữa.","fa":"آرد، تخم مرغ و شیر را باید خوب مخلوط کنید."},{"de":"Er mischt gern verschiedene Musikstile in seinen Songs.","en":"He likes to mix different music styles in his songs.","ru":"Он любит смешивать разные музыкальные стили в своих песнях.","vi":"Anh ấy thích kết hợp các phong cách âm nhạc khác nhau trong các bài hát của mình.","fa":"او دوست دارد سبک های مختلف موسیقی را در آهنگ هایش ترکیب کند."}]},{"word":"der Misserfolg","en":"failure","ru":"неудача; провал","vi":"sự thất bại","fa":"شکست","examples":[{"de":"Nach dem Misserfolg gab er nicht auf.","en":"After the failure he didn't give up.","ru":"После неудачи он не сдался.","vi":"Sau thất bại, anh không bỏ cuộc.","fa":"پس از شکست، او تسلیم نشد."},{"de":"Aus einem Misserfolg kann man viel lernen.","en":"You can learn a lot from a failure.","ru":"Из неудачи можно многому научиться.","vi":"Bạn có thể học được rất nhiều từ thất bại.","fa":"شما می توانید از شکست چیزهای زیادی یاد بگیرید."}]},{"word":"mit","en":"with","ru":"с (кем-л./чем-л.)","vi":"với","fa":"با","examples":[{"de":"Ich fahre mit dem Bus zur Schule.","en":"I go to school by bus.","ru":"Я езжу в школу на автобусе.","vi":"Tôi đi xe buýt đến trường.","fa":"با اتوبوس به مدرسه می روم."},{"de":"Sie spricht gern mit ihren Freunden über Filme.","en":"She likes to talk with her friends about movies.","ru":"Она любит разговаривать с друзьями о фильмах.","vi":"Cô ấy thích nói chuyện về phim ảnh với bạn bè.","fa":"او دوست دارد با دوستانش درباره فیلم صحبت کند."}]},{"word":"der Mitarbeiter","en":"employee; colleague","ru":"сотрудник","vi":"nhân viên","fa":"کارمند","examples":[{"de":"Die Firma hat über zweihundert Mitarbeiter.","en":"The company has more than two hundred employees.","ru":"В компании работает более двухсот сотрудников.","vi":"Công ty có hơn hai trăm nhân viên.","fa":"این شرکت بیش از دویست کارمند دارد."},{"de":"Ein freundlicher Mitarbeiter half mir bei meiner Frage.","en":"A friendly employee helped me with my question.","ru":"Дружелюбный сотрудник помог мне с моим вопросом.","vi":"Một nhân viên thân thiện đã giúp tôi giải đáp thắc mắc.","fa":"یک کارمند صمیمی در مورد سوالم به من کمک کرد."}]},{"word":"miteinander","en":"with each other; together","ru":"друг с другом, вместе","vi":"với nhau","fa":"با یکدیگر","examples":[{"de":"Die Kinder spielen gern miteinander im Park.","en":"The children like to play together in the park.","ru":"Дети любят играть друг с другом в парке.","vi":"Trẻ em vui chơi cùng nhau trong công viên.","fa":"بچه ها از بازی با هم در پارک لذت می برند."},{"de":"Wir sollten öfter miteinander reden.","en":"We should talk with each other more often.","ru":"Нам стоит чаще разговаривать друг с другом.","vi":"Chúng ta nên nói chuyện với nhau thường xuyên hơn.","fa":"ما باید بیشتر با هم صحبت کنیم."}]},{"word":"das Mitglied","en":"member","ru":"член (организации, клуба)","vi":"thành viên","fa":"عضو","examples":[{"de":"Er ist Mitglied in einem Fußballverein.","en":"He is a member of a football club.","ru":"Он член футбольного клуба.","vi":"Anh ấy là thành viên của một câu lạc bộ bóng đá.","fa":"او عضو یک باشگاه فوتبال است."},{"de":"Neue Mitglieder sind in unserem Verein immer willkommen.","en":"New members are always welcome in our club.","ru":"Новые члены всегда рады в нашем клубе.","vi":"Các thành viên mới luôn được chào đón trong câu lạc bộ của chúng tôi.","fa":"اعضای جدید همیشه در باشگاه ما پذیرفته می شوند."}]},{"word":"die Mitte","en":"middle, center","ru":"середина, центр","vi":"ở giữa","fa":"وسط","examples":[{"de":"Das Denkmal steht in der Mitte des Platzes.","en":"The monument stands in the middle of the square.","ru":"Памятник стоит в центре площади.","vi":"Tượng đài đứng giữa quảng trường.","fa":"بنای یادبود در وسط میدان قرار دارد."},{"de":"Wir treffen uns in der Mitte der Woche.","en":"We're meeting in the middle of the week.","ru":"Мы встречаемся в середине недели.","vi":"Chúng ta sẽ gặp nhau vào giữa tuần.","fa":"وسط هفته همدیگر را می بینیم."}]},{"word":"mitteilen","en":"to inform, to tell (communicate)","ru":"сообщать","vi":"giao tiếp","fa":"ارتباط برقرار کنند","examples":[{"de":"Der Lehrer teilte den Schülern die Prüfungstermine mit.","en":"The teacher informed the students of the exam dates.","ru":"Учитель сообщил ученикам о датах экзаменов.","vi":"Giáo viên thông báo cho học sinh về ngày thi.","fa":"معلم تاریخ امتحانات را به دانش آموزان اطلاع داد."},{"de":"Bitte teilen Sie uns Ihre Entscheidung bis Freitag mit.","en":"Please let us know your decision by Friday.","ru":"Пожалуйста, сообщите нам о своём решении до пятницы.","vi":"Vui lòng cho chúng tôi biết quyết định của bạn trước thứ Sáu.","fa":"لطفا تصمیم خود را تا جمعه به ما اطلاع دهید."}]},{"word":"das Mittel","en":"means; remedy","ru":"средство","vi":"phương tiện","fa":"وسیله","examples":[{"de":"Sport ist ein gutes Mittel gegen Stress.","en":"Sport is a good remedy against stress.","ru":"Спорт — хорошее средство от стресса.","vi":"Thể thao là một phương pháp chữa trị tốt cho căng thẳng.","fa":"ورزش درمان خوبی برای استرس است."},{"de":"Wir haben nicht genug Mittel, um das Projekt zu finanzieren.","en":"We don't have enough means to finance the project.","ru":"У нас недостаточно средств, чтобы профинансировать проект.","vi":"Chúng tôi không có đủ vốn để tài trợ cho dự án.","fa":"بودجه کافی برای تامین مالی پروژه نداریم."}]},{"word":"mitten","en":"in the middle (of)","ru":"посреди, прямо в середине","vi":"ở giữa","fa":"وسط","examples":[{"de":"Das Auto hielt mitten auf der Straße an.","en":"The car stopped right in the middle of the street.","ru":"Машина остановилась прямо посреди улицы.","vi":"Xe dừng lại giữa đường.","fa":"ماشین وسط خیابان ایستاد."},{"de":"Sie wohnen mitten in der Stadt.","en":"They live right in the middle of the city.","ru":"Они живут прямо в центре города.","vi":"Bạn sống ở giữa thành phố.","fa":"شما در وسط شهر زندگی می کنید."}]},{"word":"mittler-","en":"middle, medium (adjective stem, e.g. 'mittlere' = middle/medium)","ru":"средний (основа прилагательного, напр. 'mittlere' — средний)","vi":"trung bình","fa":"متوسط","examples":[{"de":"Er ist von mittlerer Größe.","en":"He is of medium height.","ru":"Он среднего роста.","vi":"Anh ấy có kích thước trung bình.","fa":"او سایز متوسطی دارد."},{"de":"Die mittlere Temperatur im Juli liegt bei 25 Grad.","en":"The average temperature in July is 25 degrees.","ru":"Средняя температура в июле — 25 градусов.","vi":"Nhiệt độ trung bình vào tháng 7 là 25 độ.","fa":"میانگین دما در ماه جولای 25 درجه است."}]},{"word":"mittlerweile","en":"meanwhile, by now","ru":"тем временем, к настоящему моменту","vi":"trong khi đó","fa":"در همین حال","examples":[{"de":"Mittlerweile spricht er sehr gut Deutsch.","en":"By now he speaks German very well.","ru":"К настоящему моменту он очень хорошо говорит по-немецки.","vi":"Bây giờ anh ấy nói tiếng Đức rất tốt.","fa":"او اکنون به خوبی آلمانی صحبت می کند."},{"de":"Ich habe mittlerweile eine neue Wohnung gefunden.","en":"Meanwhile, I have found a new apartment.","ru":"Тем временем я нашёл новую квартиру.","vi":"Bây giờ tôi đã tìm được một căn hộ mới.","fa":"اکنون یک آپارتمان جدید پیدا کرده ام."}]},{"word":"das Möbel","en":"piece of furniture (usually plural: furniture)","ru":"предмет мебели (обычно во мн.ч. — мебель)","vi":"đồ nội thất","fa":"مبلمان","examples":[{"de":"Wir haben neue Möbel für das Wohnzimmer gekauft.","en":"We bought new furniture for the living room.","ru":"Мы купили новую мебель для гостиной.","vi":"Chúng tôi đã mua đồ nội thất mới cho phòng khách.","fa":"مبلمان جدید برای اتاق نشیمن خریدیم."},{"de":"Dieses Möbelstück ist aus massivem Holz.","en":"This piece of furniture is made of solid wood.","ru":"Этот предмет мебели сделан из массива дерева.","vi":"Mảnh đồ nội thất này được làm bằng gỗ nguyên khối.","fa":"این تکه مبلمان از چوب جامد ساخته شده است."}]},{"word":"mobil","en":"mobile","ru":"мобильный, подвижный","vi":"di động","fa":"موبایل","examples":[{"de":"Mit dem Rollstuhl bleibt sie trotzdem mobil.","en":"With the wheelchair she still stays mobile.","ru":"С инвалидным креслом она всё равно остаётся мобильной.","vi":"Cô vẫn di chuyển bằng xe lăn.","fa":"او همچنان با ویلچر متحرک است."},{"de":"Er arbeitet oft mit seinem mobilen Gerät im Café.","en":"He often works with his mobile device at the café.","ru":"Он часто работает со своим мобильным устройством в кафе.","vi":"Anh ấy thường làm việc với thiết bị di động của mình trong quán cà phê.","fa":"او اغلب با موبایل خود در کافه کار می کند."}]},{"word":"möchten","en":"would like (to)","ru":"хотел(а) бы","vi":"muốn","fa":"می خواهم","examples":[{"de":"Ich möchte gern einen Kaffee bestellen.","en":"I would like to order a coffee.","ru":"Я хотел бы заказать кофе.","vi":"Tôi muốn gọi một ly cà phê.","fa":"من می خواهم یک قهوه سفارش بدهم."},{"de":"Möchtest du mit uns ins Kino gehen?","en":"Would you like to go to the cinema with us?","ru":"Хочешь пойти с нами в кино?","vi":"Bạn có muốn đi xem phim với chúng tôi không?","fa":"آیا دوست دارید با ما به سینما بروید؟"}]},{"word":"die Mode","en":"fashion","ru":"мода","vi":"thời trang","fa":"مد","examples":[{"de":"Sie interessiert sich sehr für Mode.","en":"She is very interested in fashion.","ru":"Она очень интересуется модой.","vi":"Cô ấy rất quan tâm đến thời trang.","fa":"او به مد علاقه زیادی دارد."},{"de":"Diese Frisur war in den Neunzigern große Mode.","en":"This hairstyle was very fashionable in the nineties.","ru":"Эта причёска была очень модной в девяностые.","vi":"Kiểu tóc này rất phổ biến vào những năm 90.","fa":"این مدل مو در دهه نود بزرگ بود."}]},{"word":"das Modell","en":"model","ru":"модель","vi":"người mẫu","fa":"مدل","examples":[{"de":"Dieses Auto ist das neueste Modell der Firma.","en":"This car is the company's newest model.","ru":"Эта машина — новейшая модель компании.","vi":"Chiếc xe này là mẫu mới nhất của hãng.","fa":"این خودرو جدیدترین مدل این شرکت است."},{"de":"Der Architekt baute ein Modell des Gebäudes.","en":"The architect built a model of the building.","ru":"Архитектор построил модель здания.","vi":"Kiến trúc sư đã xây dựng mô hình của tòa nhà.","fa":"معمار مدلی از ساختمان را ساخت."}]},{"word":"modern","en":"modern","ru":"современный","vi":"hiện đại","fa":"مدرن","examples":[{"de":"Die Wohnung ist modern eingerichtet.","en":"The apartment is furnished in a modern style.","ru":"Квартира обставлена в современном стиле.","vi":"Căn hộ được trang bị nội thất hiện đại.","fa":"آپارتمان مبله مدرن است."},{"de":"Moderne Technik erleichtert unseren Alltag.","en":"Modern technology makes our everyday life easier.","ru":"Современная техника облегчает нашу повседневную жизнь.","vi":"Công nghệ hiện đại làm cho cuộc sống hàng ngày của chúng ta dễ dàng hơn.","fa":"تکنولوژی مدرن زندگی روزمره ما را آسان تر می کند."}]},{"word":"mögen","en":"to like","ru":"нравиться, любить","vi":"thích","fa":"مانند","examples":[{"de":"Ich mag klassische Musik sehr gern.","en":"I like classical music a lot.","ru":"Мне очень нравится классическая музыка.","vi":"Ich mag klassische Musik sehr gern.","fa":"من موسیقی کلاسیک را خیلی دوست دارم."},{"de":"Magst du lieber Tee oder Kaffee?","en":"Do you prefer tea or coffee?","ru":"Что тебе больше нравится: чай или кофе?","vi":"Do you prefer tea or coffee?","fa":"چای را ترجیح می دهید یا قهوه؟"}]},{"word":"möglich","en":"possible","ru":"возможный","vi":"có thể","fa":"ممکن است","examples":[{"de":"Ist es möglich, den Termin zu verschieben?","en":"Is it possible to postpone the appointment?","ru":"Возможно ли перенести встречу?","vi":"Có thể dời lại cuộc hẹn được không?","fa":"آیا امکان تغییر نوبت وجود دارد؟"},{"de":"Wir müssen so schnell wie möglich handeln.","en":"We have to act as quickly as possible.","ru":"Нам нужно действовать как можно быстрее.","vi":"Chúng ta phải hành động càng nhanh càng tốt.","fa":"ما باید هر چه سریعتر اقدام کنیم."}]},{"word":"die Möglichkeit","en":"possibility; opportunity","ru":"возможность","vi":"khả năng","fa":"امکان","examples":[{"de":"Es gibt mehrere Möglichkeiten, dieses Problem zu lösen.","en":"There are several ways to solve this problem.","ru":"Есть несколько способов решить эту проблему.","vi":"Có một số cách để giải quyết vấn đề này.","fa":"راه های مختلفی برای حل این مشکل وجود دارد."},{"de":"Ich hatte noch nie die Möglichkeit, ins Ausland zu reisen.","en":"I have never had the opportunity to travel abroad.","ru":"У меня никогда не было возможности поехать за границу.","vi":"Tôi chưa bao giờ có cơ hội đi du lịch nước ngoài.","fa":"من هرگز فرصت سفر خارج از کشور را نداشتم."}]},{"word":"die Möhre","en":"carrot","ru":"морковь","vi":"củ cà rốt","fa":"هویج","examples":[{"de":"Sie schneidet Möhren für den Salat.","en":"She cuts carrots for the salad.","ru":"Она режет морковь для салата.","vi":"Cô ấy cắt nhỏ cà rốt để làm món salad.","fa":"او هویج را برای سالاد خرد می کند."},{"de":"Kaninchen fressen gern Möhren.","en":"Rabbits like to eat carrots.","ru":"Кролики любят есть морковь.","vi":"Rabbits like to eat carrots.","fa":"خرگوش ها دوست دارند هویج بخورند."}]},{"word":"der Moment","en":"moment","ru":"момент","vi":"khoảnh khắc","fa":"لحظه","examples":[{"de":"Einen Moment bitte, ich komme gleich.","en":"One moment please, I'll be right there.","ru":"Одну минутку, я сейчас подойду.","vi":"Chỉ một lát thôi, tôi sẽ đến ngay.","fa":"فقط یک لحظه، من همان جا خواهم بود."},{"de":"In diesem Moment klingelte das Telefon.","en":"At that moment the phone rang.","ru":"В этот момент зазвонил телефон.","vi":"In dieem Moment klingelte das Telefon.","fa":"در همان لحظه تلفن زنگ خورد."}]},{"word":"der Mond","en":"moon","ru":"луна","vi":"mặt trăng","fa":"ماه","examples":[{"de":"Heute Nacht ist der Mond besonders hell.","en":"Tonight the moon is especially bright.","ru":"Сегодня ночью луна особенно яркая.","vi":"Đêm nay trăng đặc biệt sáng.","fa":"امشب ماه بسیار روشن است."},{"de":"Der Mond bewegt sich um die Erde.","en":"The moon moves around the earth.","ru":"Луна вращается вокруг Земли.","vi":"Mặt trăng chuyển động quanh trái đất.","fa":"ماه در اطراف زمین حرکت می کند."}]},{"word":"der Monitor","en":"monitor (screen)","ru":"монитор (экран)","vi":"màn hình","fa":"مانیتور","examples":[{"de":"Der Monitor meines Computers ist kaputt.","en":"My computer's monitor is broken.","ru":"Монитор моего компьютера сломан.","vi":"My computer's monitor is broken.","fa":"مانیتور کامپیوترم خرابه"},{"de":"Sie schaut den ganzen Tag auf den Monitor.","en":"She looks at the monitor all day.","ru":"Она весь день смотрит на монитор.","vi":"Cô ấy nhìn vào màn hình cả ngày.","fa":"تمام روز به مانیتور نگاه می کند."}]},{"word":"der Motor","en":"engine, motor","ru":"двигатель, мотор","vi":"động cơ","fa":"موتور","examples":[{"de":"Der Motor des Autos macht ein komisches Geräusch.","en":"The car's engine is making a strange noise.","ru":"Двигатель машины издаёт странный звук.","vi":"Động cơ xe phát ra tiếng động lạ.","fa":"موتور ماشین صدای عجیبی می دهد."},{"de":"Dieses Boot hat einen sehr starken Motor.","en":"This boat has a very powerful motor.","ru":"У этой лодки очень мощный мотор.","vi":"Chiếc thuyền này có động cơ rất mạnh.","fa":"این قایق موتور بسیار قدرتمندی دارد."}]},{"word":"das Motorrad","en":"motorcycle","ru":"мотоцикл","vi":"chiếc xe máy","fa":"موتور سیکلت","examples":[{"de":"Er fährt jeden Tag mit dem Motorrad zur Arbeit.","en":"He rides his motorcycle to work every day.","ru":"Он каждый день ездит на работу на мотоцикле.","vi":"Anh ấy đi xe máy đi làm hàng ngày.","fa":"او هر روز با موتورش به محل کارش می رود."},{"de":"Ein neues Motorrad ist ziemlich teuer.","en":"A new motorcycle is quite expensive.","ru":"Новый мотоцикл довольно дорогой.","vi":"Một chiếc xe máy mới khá đắt tiền.","fa":"یک موتور سیکلت جدید بسیار گران است."}]},{"word":"müde","en":"tired","ru":"усталый","vi":"mệt mỏi","fa":"خسته","examples":[{"de":"Nach der Arbeit bin ich immer sehr müde.","en":"After work I am always very tired.","ru":"После работы я всегда очень устаю.","vi":"Nach der Arbeit bin ich immer sehr müde.","fa":"من همیشه بعد از کار خیلی خسته هستم."},{"de":"Das Kind wurde müde und schlief im Auto ein.","en":"The child got tired and fell asleep in the car.","ru":"Ребёнок устал и уснул в машине.","vi":"Đứa trẻ mệt mỏi và ngủ thiếp đi trong xe.","fa":"کودک خسته شد و در ماشین خوابش برد."}]},{"word":"das Müesli/Müsli","en":"muesli","ru":"мюсли","vi":"muesli/muesli","fa":"موسلی / موسلی","examples":[{"de":"Zum Frühstück esse ich meistens Müsli mit Joghurt.","en":"For breakfast I mostly eat muesli with yogurt.","ru":"На завтрак я обычно ем мюсли с йогуртом.","vi":"Tôi thường ăn muesli với sữa chua vào bữa sáng.","fa":"من معمولا صبحانه موسلی را با ماست میخورم."},{"de":"Sie mischt Nüsse und Obst in ihr Müsli.","en":"She mixes nuts and fruit into her muesli.","ru":"Она добавляет орехи и фрукты в свои мюсли.","vi":"Cô trộn các loại hạt và trái cây vào muesli của mình.","fa":"او آجیل و میوه را در موسلی خود مخلوط می کند."}]},{"word":"die Mühe","en":"effort, trouble","ru":"усилие, труд, хлопоты","vi":"nỗ lực","fa":"تلاش","examples":[{"de":"Er gab sich große Mühe, die Prüfung zu bestehen.","en":"He made a great effort to pass the exam.","ru":"Он приложил большие усилия, чтобы сдать экзамен.","vi":"Anh ấy đã cố gắng hết sức để vượt qua kỳ thi.","fa":"برای قبولی در امتحان تلاش زیادی کرد."},{"de":"Vielen Dank für Ihre Mühe!","en":"Thank you very much for your trouble!","ru":"Большое спасибо за ваши старания!","vi":"Cảm ơn bạn rất nhiều vì nỗ lực của bạn!","fa":"از تلاش شما بسیار سپاسگزارم!"}]},{"word":"der Müll","en":"garbage, trash","ru":"мусор","vi":"rác","fa":"زباله","examples":[{"de":"Bring bitte den Müll nach draußen.","en":"Please take the garbage outside.","ru":"Вынеси, пожалуйста, мусор.","vi":"Hãy mang rác ra ngoài.","fa":"لطفا زباله ها را بیرون ببرید."},{"de":"Wir trennen unseren Müll in Papier, Glas und Plastik.","en":"We separate our trash into paper, glass, and plastic.","ru":"Мы сортируем мусор на бумагу, стекло и пластик.","vi":"Chúng tôi phân loại rác thải thành giấy, thủy tinh và nhựa.","fa":"زباله های خود را به کاغذ، شیشه و پلاستیک جدا می کنیم."}]},{"word":"der Mund","en":"mouth","ru":"рот","vi":"cái miệng","fa":"دهان","examples":[{"de":"Sie öffnete den Mund, um etwas zu sagen.","en":"She opened her mouth to say something.","ru":"Она открыла рот, чтобы что-то сказать.","vi":"Cô mở miệng định nói điều gì đó.","fa":"دهانش را باز کرد تا چیزی بگوید."},{"de":"Sprich bitte nicht mit vollem Mund.","en":"Please don't talk with your mouth full.","ru":"Пожалуйста, не говори с набитым ртом.","vi":"Làm ơn đừng nói khi miệng đầy thức ăn.","fa":"لطفا با دهان پر صحبت نکنید"}]},{"word":"die Münze","en":"coin","ru":"монета","vi":"đồng xu","fa":"سکه","examples":[{"de":"Ich habe keine Münzen für den Parkautomaten.","en":"I don't have any coins for the parking meter.","ru":"У меня нет монет для парковочного автомата.","vi":"Tôi không có xu cho máy đỗ xe.","fa":"برای ماشین پارکینگ سکه ندارم."},{"de":"Er sammelt alte Münzen aus verschiedenen Ländern.","en":"He collects old coins from different countries.","ru":"Он коллекционирует старые монеты из разных стран.","vi":"Anh ấy sưu tập những đồng xu cổ từ các quốc gia khác nhau.","fa":"او سکه های قدیمی را از کشورهای مختلف جمع آوری می کند."}]},{"word":"das Museum","en":"museum","ru":"музей","vi":"bảo tàng","fa":"موزه","examples":[{"de":"Am Wochenende besuchen wir das Kunstmuseum.","en":"On the weekend we visit the art museum.","ru":"В выходные мы посещаем художественный музей.","vi":"Vào cuối tuần chúng tôi ghé thăm bảo tàng nghệ thuật.","fa":"آخر هفته از موزه هنر دیدن می کنیم."},{"de":"Der Eintritt ins Museum ist für Kinder kostenlos.","en":"Admission to the museum is free for children.","ru":"Вход в музей для детей бесплатный.","vi":"Vào bảo tàng miễn phí cho trẻ em.","fa":"ورود به موزه برای کودکان رایگان است."}]},{"word":"die Musik","en":"music","ru":"музыка","vi":"âm nhạc","fa":"موسیقی","examples":[{"de":"Ich höre gern klassische Musik beim Lernen.","en":"I like listening to classical music while studying.","ru":"Я люблю слушать классическую музыку во время учёбы.","vi":"Tôi thích nghe nhạc cổ điển trong khi học.","fa":"من دوست دارم در حین مطالعه به موسیقی کلاسیک گوش کنم."},{"de":"Auf dem Fest spielte eine Band live Musik.","en":"At the party, a band played live music.","ru":"На празднике группа играла живую музыку.","vi":"Một ban nhạc chơi nhạc sống tại lễ hội.","fa":"یک گروه موسیقی زنده در این جشنواره پخش کردند."}]},{"word":"der Muskel","en":"muscle","ru":"мышца","vi":"cơ bắp","fa":"ماهیچه","examples":[{"de":"Nach dem Training tun mir die Muskeln weh.","en":"After training, my muscles hurt.","ru":"После тренировки у меня болят мышцы.","vi":"Cơ bắp của tôi bị đau sau khi tập luyện.","fa":"بعد از تمرین عضلاتم درد می کند."},{"de":"Regelmäßiger Sport stärkt die Muskeln.","en":"Regular exercise strengthens the muscles.","ru":"Регулярные занятия спортом укрепляют мышцы.","vi":"Tập thể dục thường xuyên giúp tăng cường cơ bắp.","fa":"ورزش منظم عضلات را تقویت می کند."}]},{"word":"müssen","en":"must, to have to","ru":"быть должным, обязан","vi":"phải","fa":"باید","examples":[{"de":"Ich muss morgen früh aufstehen.","en":"I have to get up early tomorrow.","ru":"Мне нужно завтра рано встать.","vi":"Ngày mai tôi phải dậy sớm.","fa":"فردا باید زود بیدار بشم"},{"de":"Wir müssen die Miete bis zum Ersten bezahlen.","en":"We have to pay the rent by the first of the month.","ru":"Мы должны заплатить арендную плату до первого числа.","vi":"Chúng tôi phải trả tiền thuê nhà vào ngày đầu tiên.","fa":"تا روز اول باید کرایه را پرداخت کنیم."}]},{"word":"der Mut","en":"courage","ru":"смелость, мужество","vi":"sự can đảm","fa":"شجاعت","examples":[{"de":"Es braucht Mut, seine Meinung offen zu sagen.","en":"It takes courage to say your opinion openly.","ru":"Нужна смелость, чтобы открыто высказать своё мнение.","vi":"Cần phải có can đảm để bày tỏ ý kiến của mình một cách cởi mở.","fa":"ابراز صراحت نظر خود شجاعت می خواهد."},{"de":"Sie fasste all ihren Mut zusammen und sprang ins Wasser.","en":"She gathered all her courage and jumped into the water.","ru":"Она собрала всю свою смелость и прыгнула в воду.","vi":"Cô lấy hết can đảm và nhảy xuống nước.","fa":"تمام شهامتش را جمع کرد و پرید توی آب."}]},{"word":"mutig","en":"courageous, brave","ru":"смелый, храбрый","vi":"dũng cảm","fa":"شجاع","examples":[{"de":"Der Feuerwehrmann war sehr mutig und rettete das Kind.","en":"The firefighter was very brave and saved the child.","ru":"Пожарный был очень смелым и спас ребёнка.","vi":"Người lính cứu hỏa đã rất dũng cảm và cứu được đứa trẻ.","fa":"آتش نشان بسیار شجاع بود و کودک را نجات داد."},{"de":"Es war mutig von dir, die Wahrheit zu sagen.","en":"It was brave of you to tell the truth.","ru":"С твоей стороны было смело сказать правду.","vi":"Bạn thật dũng cảm khi nói ra sự thật.","fa":"این شجاعت شما بود که حقیقت را گفتید."}]},{"word":"die Mutter","en":"mother","ru":"мать","vi":"người mẹ","fa":"مادر","examples":[{"de":"Meine Mutter kocht jeden Sonntag ein großes Essen.","en":"My mother cooks a big meal every Sunday.","ru":"Моя мама готовит большой обед каждое воскресенье.","vi":"Mẹ tôi nấu một bữa ăn thịnh soạn vào mỗi Chủ nhật.","fa":"مادرم هر یکشنبه یک غذای بزرگ درست می کند."},{"de":"Sie ist Mutter von drei Kindern.","en":"She is the mother of three children.","ru":"Она мать троих детей.","vi":"Cô là mẹ của ba đứa trẻ.","fa":"او مادر سه فرزند است."}]},{"word":"nach","en":"after; to(wards) (a place)","ru":"после; в, к (направление)","vi":"sau","fa":"بعد از","examples":[{"de":"Nach der Arbeit gehe ich meistens einkaufen.","en":"After work I usually go shopping.","ru":"После работы я обычно хожу за покупками.","vi":"Sau giờ làm việc tôi thường đi mua sắm.","fa":"بعد از کار معمولاً به خرید می روم."},{"de":"Wir fliegen nächste Woche nach Spanien.","en":"We are flying to Spain next week.","ru":"На следующей неделе мы летим в Испанию.","vi":"Chúng tôi sẽ bay đến Tây Ban Nha vào tuần tới.","fa":"هفته آینده به اسپانیا پرواز می کنیم."}]},{"word":"der Nachbar","en":"neighbor","ru":"сосед","vi":"người hàng xóm","fa":"همسایه","examples":[{"de":"Unser Nachbar ist sehr freundlich und hilfsbereit.","en":"Our neighbor is very friendly and helpful.","ru":"Наш сосед очень дружелюбный и отзывчивый.","vi":"Hàng xóm của chúng tôi rất thân thiện và hữu ích.","fa":"همسایه ما بسیار صمیمی و مفید است."},{"de":"Ich habe meinen neuen Nachbarn noch nicht kennengelernt.","en":"I haven't met my new neighbor yet.","ru":"Я ещё не познакомился со своим новым соседом.","vi":"Tôi vẫn chưa gặp người hàng xóm mới của mình.","fa":"من هنوز همسایه جدیدم را ندیده ام."}]},{"word":"die Nachbarschaft","en":"neighbourhood","ru":"соседство; район","vi":"khu phố","fa":"محله","examples":[{"de":"In unserer Nachbarschaft kennt jeder jeden.","en":"In our neighbourhood everyone knows everyone.","ru":"В нашем районе все знают друг друга.","vi":"Trong khu phố của chúng tôi mọi người đều biết nhau.","fa":"در محله ما همه همه را می شناسند."},{"de":"Die Nachbarschaft hat sich in den letzten Jahren verändert.","en":"The neighbourhood has changed in recent years.","ru":"Район изменился за последние годы.","vi":"Khu phố đã thay đổi trong những năm gần đây.","fa":"محله در سال های اخیر تغییر کرده است."}]},{"word":"nachdem","en":"after (conjunction)","ru":"после того как","vi":"sau","fa":"بعد از","examples":[{"de":"Nachdem wir gegessen hatten, gingen wir spazieren.","en":"After we had eaten, we went for a walk.","ru":"После того как мы поели, мы пошли гулять.","vi":"Ăn xong chúng tôi đi dạo.","fa":"بعد از خوردن غذا رفتیم پیاده روی."},{"de":"Nachdem sie die Prüfung bestanden hatte, feierte sie mit Freunden.","en":"After she had passed the exam, she celebrated with friends.","ru":"После того как она сдала экзамен, она отпраздновала это с друзьями.","vi":"Sau khi vượt qua kỳ thi, cô đã ăn mừng cùng bạn bè.","fa":"بعد از قبولی در امتحان، با دوستانش جشن گرفت."}]},{"word":"nachdenken","en":"to think about, to reflect (on)","ru":"размышлять, обдумывать","vi":"nghĩ","fa":"فکر کن","examples":[{"de":"Ich muss noch einmal über deinen Vorschlag nachdenken.","en":"I have to think about your suggestion once more.","ru":"Мне нужно ещё раз обдумать твоё предложение.","vi":"Tôi sẽ phải suy nghĩ lại về đề nghị của bạn.","fa":"من باید دوباره در مورد پیشنهاد شما فکر کنم."},{"de":"Er saß still da und dachte über sein Leben nach.","en":"He sat quietly and reflected on his life.","ru":"Он сидел тихо и размышлял о своей жизни.","vi":"Anh ngồi lặng im và ngẫm nghĩ về cuộc đời mình.","fa":"ساکت نشسته بود و به زندگیش فکر می کرد."}]},{"word":"die Nachfrage","en":"demand","ru":"спрос","vi":"nhu cầu","fa":"تقاضا","examples":[{"de":"Die Nachfrage nach diesem Produkt ist sehr hoch.","en":"The demand for this product is very high.","ru":"Спрос на этот продукт очень высокий.","vi":"Nhu cầu về sản phẩm này rất cao.","fa":"تقاضا برای این محصول بسیار زیاد است."},{"de":"Wegen der starken Nachfrage sind die Karten schon ausverkauft.","en":"Due to strong demand, the tickets are already sold out.","ru":"Из-за высокого спроса билеты уже распроданы.","vi":"Do nhu cầu mạnh nên vé đã được bán hết.","fa":"به دلیل تقاضای زیاد، بلیط ها در حال حاضر فروخته شده است."}]},{"word":"nachhaltig","en":"sustainable","ru":"устойчивый; экологически ответственный","vi":"bền vững","fa":"پایدار","examples":[{"de":"Nachhaltiger Konsum schont die Ressourcen.","en":"Sustainable consumption conserves resources.","ru":"Ответственное потребление бережёт ресурсы.","vi":"Tiêu dùng bền vững bảo tồn tài nguyên.","fa":"مصرف پایدار باعث حفظ منابع می شود."},{"de":"Die Firma setzt auf nachhaltige Produktion.","en":"The company relies on sustainable production.","ru":"Компания делает ставку на устойчивое производство.","vi":"Công ty dựa vào sản xuất bền vững.","fa":"این شرکت بر تولید پایدار متکی است."}]},{"word":"nachher","en":"afterwards","ru":"потом, после","vi":"sau đó","fa":"پس از آن","examples":[{"de":"Wir gehen jetzt essen, nachher schauen wir einen Film.","en":"We're going to eat now, afterwards we'll watch a movie.","ru":"Сейчас мы пойдём поедим, а потом посмотрим фильм.","vi":"Bây giờ chúng ta sẽ đi ăn và sau đó chúng ta sẽ xem phim.","fa":"حالا می خوایم و بعد فیلم می بینیم."},{"de":"Ruf mich bitte nachher zurück.","en":"Please call me back afterwards.","ru":"Пожалуйста, перезвони мне потом.","vi":"Vui lòng gọi lại cho tôi sau.","fa":"لطفاً بعداً با من تماس بگیرید."}]},{"word":"die Nachhilfe","en":"tutoring, extra lessons","ru":"дополнительные занятия, репетиторство","vi":"việc dạy kèm","fa":"تدریس خصوصی","examples":[{"de":"Mein Sohn bekommt Nachhilfe in Mathematik.","en":"My son gets tutoring in mathematics.","ru":"Мой сын занимается с репетитором по математике.","vi":"Con trai tôi đang được dạy kèm môn toán.","fa":"پسرم در حال تدریس خصوصی ریاضی است."},{"de":"Sie gibt Schülern Nachhilfe in Englisch.","en":"She tutors students in English.","ru":"Она даёт ученикам дополнительные уроки английского.","vi":"Cô dạy kèm cho học sinh bằng tiếng Anh.","fa":"او به دانش آموزان آموزش زبان انگلیسی می دهد."}]},{"word":"die Nachricht","en":"message; news","ru":"сообщение; новость","vi":"tin nhắn","fa":"پیام","examples":[{"de":"Ich habe dir eine Nachricht auf dem Handy geschickt.","en":"I sent you a message on your phone.","ru":"Я отправил тебе сообщение на телефон.","vi":"Tôi đã gửi cho bạn một tin nhắn trên điện thoại di động của bạn.","fa":"با موبایلت پیام دادم"},{"de":"Im Radio hörten wir die neuesten Nachrichten.","en":"On the radio we heard the latest news.","ru":"По радио мы услышали последние новости.","vi":"Chúng tôi đã nghe tin tức mới nhất trên đài phát thanh.","fa":"آخرین اخبار را از رادیو شنیدیم."}]},{"word":"nachschlagen","en":"to look up (a word/information)","ru":"искать, смотреть (слово в словаре и т.п.)","vi":"tra cứu","fa":"به بالا نگاه کن","examples":[{"de":"Ich schlage das Wort im Wörterbuch nach.","en":"I look up the word in the dictionary.","ru":"Я ищу это слово в словаре.","vi":"Tôi tra từ đó trong từ điển.","fa":"کلمه را در فرهنگ لغت جستجو می کنم."},{"de":"Wenn du etwas nicht verstehst, kannst du es im Internet nachschlagen.","en":"If you don't understand something, you can look it up on the internet.","ru":"Если ты чего-то не понимаешь, ты можешь найти это в интернете.","vi":"Nếu bạn không hiểu điều gì đó, bạn có thể tra cứu trực tuyến.","fa":"اگر چیزی را متوجه نشدید، می توانید آن را به صورت آنلاین جستجو کنید."}]},{"word":"die Nachspeise","en":"dessert","ru":"десерт","vi":"món tráng miệng","fa":"دسر","examples":[{"de":"Als Nachspeise gibt es heute Schokoladenkuchen.","en":"Today's dessert is chocolate cake.","ru":"На десерт сегодня шоколадный торт.","vi":"Món tráng miệng hôm nay chúng tôi có bánh sô-cô-la.","fa":"برای دسر امروز کیک شکلاتی داریم."},{"de":"Möchten Sie noch eine Nachspeise bestellen?","en":"Would you like to order a dessert?","ru":"Хотите заказать десерт?","vi":"Bạn có muốn gọi món tráng miệng khác không?","fa":"آیا می خواهید دسر دیگری سفارش دهید؟"}]},{"word":"der Nachteil","en":"disadvantage","ru":"недостаток","vi":"điều bất lợi","fa":"ضرر","examples":[{"de":"Ein Nachteil dieser Wohnung ist der Lärm von der Straße.","en":"One disadvantage of this apartment is the noise from the street.","ru":"Один из недостатков этой квартиры — шум с улицы.","vi":"Một nhược điểm của căn hộ này là tiếng ồn từ đường phố.","fa":"از معایب این آپارتمان سر و صدای خیابان است."},{"de":"Jede Entscheidung hat Vor- und Nachteile.","en":"Every decision has advantages and disadvantages.","ru":"У каждого решения есть плюсы и минусы.","vi":"Mọi quyết định đều có ưu điểm và nhược điểm.","fa":"هر تصمیمی مزایا و معایبی دارد."}]},{"word":"der Nachwuchs","en":"offspring; young talent (new generation)","ru":"потомство; молодое поколение, молодые кадры","vi":"con cháu","fa":"فرزندان","examples":[{"de":"Die Firma sucht dringend qualifizierten Nachwuchs.","en":"The company urgently needs qualified young talent.","ru":"Компании срочно нужны квалифицированные молодые кадры.","vi":"Công ty đang khẩn trương tìm kiếm những người trẻ có năng lực.","fa":"این شرکت به شدت به دنبال جوانان واجد شرایط می باشد."},{"de":"Das Löwenpaar im Zoo hat Nachwuchs bekommen.","en":"The pair of lions at the zoo has had offspring.","ru":"У пары львов в зоопарке появилось потомство.","vi":"Cặp sư tử trong vườn thú đã sinh con.","fa":"جفت شیرهای باغ وحش صاحب فرزند شده اند."}]},{"word":"die Nadel","en":"needle","ru":"игла, иголка","vi":"cái kim","fa":"سوزن","examples":[{"de":"Sie näht den Knopf mit Nadel und Faden an.","en":"She sews the button on with needle and thread.","ru":"Она пришивает пуговицу иголкой с ниткой.","vi":"Cô ấy khâu chiếc cúc lại bằng kim và chỉ.","fa":"او دکمه را با نخ و سوزن می دوزد."},{"de":"Der Arzt benutzt eine sterile Nadel für die Impfung.","en":"The doctor uses a sterile needle for the vaccination.","ru":"Врач использует стерильную иглу для прививки.","vi":"Bác sĩ sử dụng kim tiêm vô trùng để tiêm chủng.","fa":"پزشک از یک سوزن استریل برای واکسیناسیون استفاده می کند."}]},{"word":"der Nagel","en":"nail","ru":"гвоздь; ноготь","vi":"cái đinh","fa":"ناخن","examples":[{"de":"Er schlägt einen Nagel in die Wand, um das Bild aufzuhängen.","en":"He hammers a nail into the wall to hang the picture.","ru":"Он забивает гвоздь в стену, чтобы повесить картину.","vi":"Anh ta đóng một chiếc đinh vào tường để treo bức tranh.","fa":"او میخ را به دیوار می کوبد تا عکس را آویزان کند."},{"de":"Sie lackiert sich jeden Monat die Nägel.","en":"She paints her nails every month.","ru":"Она красит ногти каждый месяц.","vi":"Cô ấy sơn móng tay mỗi tháng.","fa":"او هر ماه ناخن هایش را رنگ می کند."}]},{"word":"nah(e)","en":"near, close","ru":"близкий, недалёкий","vi":"đóng","fa":"بستن","examples":[{"de":"Die Schule liegt ganz nah bei unserem Haus.","en":"The school is very close to our house.","ru":"Школа находится совсем рядом с нашим домом.","vi":"Trường học rất gần nhà của chúng tôi.","fa":"مدرسه به خانه ما خیلی نزدیک است."},{"de":"Wir haben eine nahe Beziehung zu unseren Nachbarn.","en":"We have a close relationship with our neighbors.","ru":"У нас близкие отношения с нашими соседями.","vi":"Chúng tôi có mối quan hệ chặt chẽ với hàng xóm của chúng tôi.","fa":"ما با همسایگان خود رابطه نزدیک داریم."}]},{"word":"nähen","en":"to sew","ru":"шить","vi":"khâu","fa":"دوختن","examples":[{"de":"Meine Großmutter näht mir ein neues Kleid.","en":"My grandmother is sewing me a new dress.","ru":"Моя бабушка шьёт мне новое платье.","vi":"Bà tôi đang may cho tôi một chiếc váy mới.","fa":"مادربزرگم در حال دوختن لباس جدید برای من است."},{"de":"Er hat gelernt, seine Hosen selbst zu nähen.","en":"He learned to sew his own trousers.","ru":"Он научился сам шить себе брюки.","vi":"Anh ấy đã học cách tự may quần cho mình.","fa":"دوخت شلوارش را خودش یاد گرفت."}]},{"word":"das Nahrungsmittel","en":"food; foodstuff","ru":"продукт питания","vi":"thức ăn","fa":"غذا","examples":[{"de":"Obst und Gemüse sind wichtige Nahrungsmittel.","en":"Fruit and vegetables are important foods.","ru":"Фрукты и овощи — важные продукты питания.","vi":"Trái cây và rau quả là những thực phẩm quan trọng.","fa":"میوه ها و سبزیجات از مواد غذایی مهم هستند."},{"de":"Im Supermarkt gibt es viele verschiedene Nahrungsmittel.","en":"There are many different foods in the supermarket.","ru":"В супермаркете есть много разных продуктов питания.","vi":"Có rất nhiều loại thực phẩm khác nhau trong siêu thị.","fa":"در سوپرمارکت غذاهای مختلفی وجود دارد."}]},{"word":"der Name","en":"name","ru":"имя; название","vi":"cái tên","fa":"نام","examples":[{"de":"Wie ist dein Name?","en":"What is your name?","ru":"Как тебя зовут?","vi":"Tên bạn là gì?","fa":"اسمت چیه؟"},{"de":"Sie hat ihren Namen geändert.","en":"She changed her name.","ru":"Она поменяла своё имя.","vi":"Cô ấy đã đổi tên.","fa":"اسمشو عوض کرد"}]},{"word":"nämlich","en":"namely; because (explanatory)","ru":"а именно; дело в том, что","vi":"cụ thể là","fa":"یعنی","examples":[{"de":"Ich kann heute nicht kommen, ich bin nämlich krank.","en":"I can't come today, because I'm sick.","ru":"Я не могу прийти сегодня, дело в том, что я болен.","vi":"Hôm nay tôi không thể đến vì tôi bị ốm.","fa":"امروز نمیتونم بیام چون مریضم"},{"de":"Wir brauchen zwei Dinge, nämlich Zeit und Geld.","en":"We need two things, namely time and money.","ru":"Нам нужны две вещи, а именно время и деньги.","vi":"Chúng ta cần hai thứ, đó là thời gian và tiền bạc.","fa":"ما به دو چیز نیاز داریم، یعنی زمان و پول."}]},{"word":"die Nase","en":"nose","ru":"нос","vi":"cái mũi","fa":"بینی","examples":[{"de":"Meine Nase ist verstopft.","en":"My nose is blocked.","ru":"У меня заложен нос.","vi":"Mũi tôi nghẹt quá.","fa":"بینی من گرفتگی دارد."},{"de":"Das Kind putzt sich die Nase.","en":"The child blows his nose.","ru":"Ребёнок сморкается.","vi":"Đứa trẻ xì mũi.","fa":"بچه دماغش را می زند."}]},{"word":"nass","en":"wet","ru":"мокрый","vi":"ướt","fa":"مرطوب","examples":[{"de":"Meine Schuhe sind vom Regen ganz nass.","en":"My shoes are completely wet from the rain.","ru":"Мои туфли совсем мокрые от дождя.","vi":"Giày của tôi ướt hoàn toàn vì mưa.","fa":"کفش هایم از باران کاملا خیس شده است."},{"de":"Zieh die nasse Jacke aus!","en":"Take off the wet jacket!","ru":"Сними мокрую куртку!","vi":"Hãy cởi áo khoác ướt của bạn ra!","fa":"ژاکت خیس خود را در بیاور!"}]},{"word":"national","en":"national","ru":"национальный","vi":"toàn quốc","fa":"در سطح ملی","examples":[{"de":"Morgen ist ein nationaler Feiertag.","en":"Tomorrow is a national holiday.","ru":"Завтра национальный праздник.","vi":"Ngày mai là ngày lễ quốc gia.","fa":"فردا تعطیلات ملی است."},{"de":"Die Nachrichten berichten über nationale Themen.","en":"The news reports on national topics.","ru":"Новости сообщают о национальных темах.","vi":"Các tin tức đưa tin về các vấn đề quốc gia.","fa":"اخبار مربوط به مسائل ملی است."}]},{"word":"die Natur","en":"nature","ru":"природа","vi":"bản chất","fa":"طبیعت","examples":[{"de":"Wir machen gern Ausflüge in die Natur.","en":"We like to go on trips into nature.","ru":"Мы любим ездить на природу.","vi":"Chúng tôi thích đi du lịch vào thiên nhiên.","fa":"ما دوست داریم به طبیعت سفر کنیم."},{"de":"Die Natur muss geschützt werden.","en":"Nature must be protected.","ru":"Природу нужно защищать.","vi":"Thiên nhiên phải được bảo vệ.","fa":"طبیعت باید محافظت شود."}]},{"word":"natürlich","en":"naturally; of course","ru":"конечно; естественно","vi":"tất nhiên","fa":"البته","examples":[{"de":"Natürlich helfe ich dir.","en":"Of course I'll help you.","ru":"Конечно, я тебе помогу.","vi":"Tất nhiên là tôi sẽ giúp bạn.","fa":"البته من به شما کمک خواهم کرد."},{"de":"Das ist ein ganz natürliches Verhalten.","en":"That is a completely natural behavior.","ru":"Это совершенно естественное поведение.","vi":"Đây là hành vi hoàn toàn tự nhiên.","fa":"این رفتار کاملا طبیعی است."}]},{"word":"der Nebel","en":"fog","ru":"туман","vi":"sương mù","fa":"مه","examples":[{"de":"Heute Morgen war dichter Nebel.","en":"There was thick fog this morning.","ru":"Сегодня утром был густой туман.","vi":"Sáng nay có sương mù dày đặc.","fa":"امروز صبح مه غلیظی بود."},{"de":"Wegen des Nebels sieht man kaum etwas.","en":"Because of the fog you can hardly see anything.","ru":"Из-за тумана почти ничего не видно.","vi":"Vì sương mù nên bạn khó có thể nhìn thấy gì.","fa":"به دلیل مه به سختی می توانید چیزی ببینید."}]},{"word":"neben","en":"next to; beside","ru":"рядом с; возле","vi":"bên cạnh","fa":"در کنار","examples":[{"de":"Der Stuhl steht neben dem Tisch.","en":"The chair is next to the table.","ru":"Стул стоит рядом со столом.","vi":"Cái ghế ở cạnh cái bàn.","fa":"صندلی کنار میز است."},{"de":"Neben der Schule gibt es einen Park.","en":"Next to the school there is a park.","ru":"Рядом со школой есть парк.","vi":"Có công viên cạnh trường học.","fa":"پارکی در کنار مدرسه وجود دارد."}]},{"word":"nebenbei","en":"on the side; incidentally","ru":"между делом; попутно","vi":"bên cạnh","fa":"در کنار","examples":[{"de":"Er studiert und arbeitet nebenbei in einem Café.","en":"He studies and works on the side in a café.","ru":"Он учится и подрабатывает попутно в кафе.","vi":"Anh ấy học và làm việc bán thời gian ở một quán cà phê.","fa":"او درس می خواند و به صورت پاره وقت در یک کافه کار می کند."},{"de":"Nebenbei bemerkt, das Essen war ausgezeichnet.","en":"Incidentally, the food was excellent.","ru":"Кстати говоря, еда была отличной.","vi":"Bên cạnh đó, thức ăn rất tuyệt vời.","fa":"از یک طرف، غذا عالی بود."}]},{"word":"der Neffe","en":"nephew","ru":"племянник","vi":"cháu trai","fa":"برادرزاده","examples":[{"de":"Mein Neffe kommt uns am Wochenende besuchen.","en":"My nephew is coming to visit us this weekend.","ru":"Мой племянник приедет к нам в гости на выходных.","vi":"Cháu trai của tôi sẽ đến thăm chúng tôi vào cuối tuần này.","fa":"برادرزاده ام این آخر هفته به دیدن ما می آید."},{"de":"Ich habe meinem Neffen ein Geschenk gekauft.","en":"I bought my nephew a gift.","ru":"Я купил племяннику подарок.","vi":"Tôi đã mua cho cháu trai tôi một món quà.","fa":"برای برادرزاده ام هدیه خریدم."}]},{"word":"negativ","en":"negative","ru":"отрицательный; негативный","vi":"tiêu cực","fa":"منفی","examples":[{"de":"Der Test war negativ.","en":"The test was negative.","ru":"Тест был отрицательным.","vi":"Der Test chiến tranh tiêu cực.","fa":"آزمایش منفی بود."},{"de":"Bitte denk nicht so negativ über die Zukunft.","en":"Please don't think so negatively about the future.","ru":"Пожалуйста, не думай так негативно о будущем.","vi":"Xin đừng suy nghĩ tiêu cực về tương lai.","fa":"لطفا در مورد آینده اینقدر منفی فکر نکنید."}]},{"word":"nehmen","en":"to take","ru":"брать; взять","vi":"lấy","fa":"گرفتن","examples":[{"de":"Nimm bitte deine Tasche mit.","en":"Please take your bag with you.","ru":"Пожалуйста, возьми свою сумку с собой.","vi":"Vui lòng mang theo túi của bạn.","fa":"لطفا کیف خود را با خود ببرید."},{"de":"Ich nehme den Zug um acht Uhr.","en":"I'll take the train at eight o'clock.","ru":"Я поеду на поезде в восемь часов.","vi":"Tôi bắt chuyến tàu lúc tám giờ.","fa":"سوار قطار ساعت هشت می شوم."}]},{"word":"nein","en":"no","ru":"нет","vi":"không","fa":"نه","examples":[{"de":"Nein, ich habe keine Zeit heute.","en":"No, I don't have time today.","ru":"Нет, у меня сегодня нет времени.","vi":"Không, hôm nay tôi không có thời gian.","fa":"نه امروز وقت ندارم"},{"de":"Sie hat auf meine Frage nein gesagt.","en":"She said no to my question.","ru":"Она сказала нет на мой вопрос.","vi":"Cô ấy nói không với câu hỏi của tôi.","fa":"او به سوال من نه گفت."}]},{"word":"nennen","en":"to name; to call","ru":"называть","vi":"gọi","fa":"تماس بگیرید","examples":[{"de":"Wie nennt man dieses Gerät auf Deutsch?","en":"What is this device called in German?","ru":"Как называется это устройство по-немецки?","vi":"Bạn gọi thiết bị này trong tiếng Đức là gì?","fa":"به آلمانی به این دستگاه چه می گویید؟"},{"de":"Man kann mich einfach Tom nennen.","en":"You can just call me Tom.","ru":"Можешь просто называть меня Том.","vi":"Man kann mich einfach Tom nennen.","fa":"فقط میتونی منو تام صدا کنی"}]},{"word":"der Nerv","en":"nerve","ru":"нерв","vi":"dây thần kinh","fa":"عصب","examples":[{"de":"Die laute Musik geht mir auf die Nerven.","en":"The loud music gets on my nerves.","ru":"Громкая музыка действует мне на нервы.","vi":"Âm nhạc ồn ào làm tôi khó chịu.","fa":"صدای بلند موسیقی اعصابم را به هم می زند."},{"de":"Der Arzt hat einen Nerv im Rücken untersucht.","en":"The doctor examined a nerve in the back.","ru":"Врач осмотрел нерв в спине.","vi":"Bác sĩ kiểm tra dây thần kinh ở lưng.","fa":"دکتر عصب پشت را معاینه کرد."}]},{"word":"nervös","en":"nervous","ru":"нервный; взволнованный","vi":"lo lắng","fa":"عصبی","examples":[{"de":"Vor der Prüfung war ich sehr nervös.","en":"I was very nervous before the exam.","ru":"Перед экзаменом я очень нервничал.","vi":"Tôi đã rất lo lắng trước kỳ thi.","fa":"قبل از امتحان خیلی عصبی بودم."},{"de":"Werde nicht nervös, alles wird gut.","en":"Don't get nervous, everything will be fine.","ru":"Не нервничай, всё будет хорошо.","vi":"Đừng lo lắng, mọi thứ sẽ ổn thôi.","fa":"عصبی نشو همه چیز درست میشه"}]},{"word":"nett","en":"nice; kind","ru":"милый; приятный","vi":"tốt đẹp","fa":"خوب","examples":[{"de":"Meine neuen Kollegen sind sehr nett.","en":"My new colleagues are very nice.","ru":"Мои новые коллеги очень милые.","vi":"My new colleagues are very nice.","fa":"همکاران جدید من خیلی خوب هستند."},{"de":"Das war nett von dir, danke!","en":"That was nice of you, thanks!","ru":"Это было мило с твоей стороны, спасибо!","vi":"Bạn thật tử tế, cảm ơn bạn!","fa":"از شما خوب بود، متشکرم!"}]},{"word":"das Netz","en":"net; network","ru":"сеть","vi":"mạng lưới","fa":"شبکه","examples":[{"de":"Der Fischer wirft sein Netz ins Wasser.","en":"The fisherman throws his net into the water.","ru":"Рыбак забрасывает сеть в воду.","vi":"Người đánh cá ném lưới xuống nước.","fa":"ماهیگیر تور خود را در آب می اندازد."},{"de":"Ich habe hier kein Netz auf dem Handy.","en":"I have no signal on my phone here.","ru":"У меня здесь нет сети на телефоне.","vi":"Điện thoại di động của tôi ở đây không có mạng.","fa":"من اینجا شبکه ای روی تلفن همراهم ندارم."}]},{"word":"das Netzwerk","en":"network","ru":"сеть (компьютерная/социальная)","vi":"mạng lưới","fa":"شبکه","examples":[{"de":"Unser Computer ist mit dem Netzwerk verbunden.","en":"Our computer is connected to the network.","ru":"Наш компьютер подключён к сети.","vi":"Máy tính của chúng tôi được kết nối với mạng.","fa":"کامپیوتر ما به شبکه متصل است."},{"de":"Sie hat ein großes berufliches Netzwerk.","en":"She has a large professional network.","ru":"У неё большая профессиональная сеть контактов.","vi":"Cô ấy có một mạng lưới chuyên nghiệp rộng lớn.","fa":"او یک شبکه حرفه ای بزرگ دارد."}]},{"word":"neu","en":"new","ru":"новый","vi":"mới","fa":"جدید","examples":[{"de":"Ich habe mir ein neues Fahrrad gekauft.","en":"I bought myself a new bike.","ru":"Я купил себе новый велосипед.","vi":"Tôi đã mua một chiếc xe đạp mới.","fa":"من یک دوچرخه جدید خریدم."},{"de":"Das ist mein neuer Kollege.","en":"This is my new colleague.","ru":"Это мой новый коллега.","vi":"Đây là đồng nghiệp mới của tôi.","fa":"این همکار جدید من است."}]},{"word":"die Neugier","en":"curiosity","ru":"любопытство","vi":"sự tò mò","fa":"کنجکاوی","examples":[{"de":"Aus reiner Neugier öffnete er die Tür.","en":"Out of pure curiosity he opened the door.","ru":"Из чистого любопытства он открыл дверь.","vi":"Vì tò mò, anh mở cửa.","fa":"از روی کنجکاوی محض در را باز کرد."},{"de":"Kinder haben eine natürliche Neugier auf die Welt.","en":"Children have a natural curiosity about the world.","ru":"У детей есть естественное любопытство к миру.","vi":"Trẻ em có sự tò mò tự nhiên về thế giới.","fa":"کودکان نسبت به دنیا کنجکاوی طبیعی دارند."}]},{"word":"neugierig","en":"curious","ru":"любопытный","vi":"tò mò","fa":"کنجکاو","examples":[{"de":"Die Kinder sind sehr neugierig auf die Antwort.","en":"The children are very curious about the answer.","ru":"Дети очень любопытны узнать ответ.","vi":"Các em rất tò mò về câu trả lời.","fa":"بچه ها در مورد پاسخ بسیار کنجکاو هستند."},{"de":"Sei nicht so neugierig, das ist privat!","en":"Don't be so nosy, that's private!","ru":"Не будь таким любопытным, это личное!","vi":"Đừng tọc mạch thế, đây là chuyện riêng tư!","fa":"اینقدر فضول نباش، این خصوصی است!"}]},{"word":"die Neuigkeit","en":"news; a piece of news","ru":"новость","vi":"tin tức","fa":"اخبار","examples":[{"de":"Ich habe eine tolle Neuigkeit für dich!","en":"I have great news for you!","ru":"У меня для тебя отличная новость!","vi":"Tôi có tin tuyệt vời cho bạn!","fa":"من یک خبر عالی برای شما دارم!"},{"de":"Hast du schon die neueste Neuigkeit gehört?","en":"Have you already heard the latest news?","ru":"Ты уже слышал последнюю новость?","vi":"Bạn đã nghe tin tức mới nhất chưa?","fa":"آیا تا به حال آخرین اخبار را شنیده اید؟"}]},{"word":"neulich","en":"recently; the other day","ru":"недавно; на днях","vi":"gần đây","fa":"اخیرا","examples":[{"de":"Neulich habe ich einen alten Freund getroffen.","en":"The other day I met an old friend.","ru":"Недавно я встретил старого друга.","vi":"Gần đây tôi đã gặp một người bạn cũ.","fa":"اخیراً با یک دوست قدیمی آشنا شدم."},{"de":"Neulich gab es einen interessanten Bericht im Fernsehen.","en":"Recently there was an interesting report on TV.","ru":"На днях по телевизору был интересный репортаж.","vi":"Gần đây có một bản tin thú vị trên truyền hình.","fa":"اخیرا گزارش جالبی در تلویزیون پخش شد."}]},{"word":"nicht","en":"not","ru":"не","vi":"không","fa":"نه","examples":[{"de":"Ich verstehe das nicht.","en":"I don't understand that.","ru":"Я этого не понимаю.","vi":"Tôi không hiểu điều đó.","fa":"من این را نمی فهمم."},{"de":"Er ist heute nicht zu Hause.","en":"He is not at home today.","ru":"Его сегодня нет дома.","vi":"Hôm nay anh ấy không có nhà.","fa":"امروز خونه نیست"}]},{"word":"die Nichte","en":"niece","ru":"племянница","vi":"cháu gái","fa":"خواهرزاده","examples":[{"de":"Meine Nichte wird nächste Woche zehn Jahre alt.","en":"My niece will turn ten next week.","ru":"Моей племяннице на следующей неделе исполнится десять лет.","vi":"Cháu gái tôi tròn mười tuổi vào tuần tới.","fa":"خواهرزاده من هفته آینده ده ساله می شود."},{"de":"Ich schreibe meiner Nichte oft Briefe.","en":"I often write letters to my niece.","ru":"Я часто пишу письма своей племяннице.","vi":"Tôi thường viết thư cho cháu gái của tôi.","fa":"من اغلب برای خواهرزاده ام نامه می نویسم."}]},{"word":"der Nichtraucher","en":"non-smoker","ru":"некурящий","vi":"người không hút thuốc","fa":"غیر سیگاری","examples":[{"de":"Er ist seit einem Jahr Nichtraucher.","en":"He has been a non-smoker for a year.","ru":"Он не курит уже год.","vi":"Anh ấy đã không hút thuốc được một năm.","fa":"او یک سال است که سیگار نمی کشد."},{"de":"Dieser Wagen ist nur für Nichtraucher.","en":"This carriage is only for non-smokers.","ru":"Этот вагон только для некурящих.","vi":"Chiếc xe này chỉ dành cho người không hút thuốc.","fa":"این خودرو فقط برای افراد غیر سیگاری است."}]},{"word":"nichts","en":"nothing","ru":"ничего","vi":"không có gì","fa":"هیچ چیز","examples":[{"de":"Ich habe heute nichts gegessen.","en":"I haven't eaten anything today.","ru":"Я сегодня ничего не ел.","vi":"Hôm nay tôi chưa ăn gì cả.","fa":"امروز هیچی نخوردم"},{"de":"Das macht nichts, kein Problem.","en":"It doesn't matter, no problem.","ru":"Ничего страшного, нет проблем.","vi":"Điều đó không quan trọng, không có vấn đề gì.","fa":"این مهم نیست، مشکلی نیست."}]},{"word":"nie","en":"never","ru":"никогда","vi":"không bao giờ","fa":"هرگز","examples":[{"de":"Ich war noch nie in Japan.","en":"I have never been to Japan.","ru":"Я никогда не был в Японии.","vi":"Tôi chưa bao giờ đến Nhật Bản.","fa":"من هرگز به ژاپن نرفته ام."},{"de":"Er kommt nie pünktlich.","en":"He never comes on time.","ru":"Он никогда не приходит вовремя.","vi":"Anh ấy không bao giờ đến đúng giờ.","fa":"او هرگز به موقع نمی آید."}]},{"word":"niedrig","en":"low","ru":"низкий","vi":"thấp","fa":"پایین","examples":[{"de":"Die Preise in diesem Geschäft sind sehr niedrig.","en":"The prices in this shop are very low.","ru":"Цены в этом магазине очень низкие.","vi":"Giá ở cửa hàng này rất thấp.","fa":"قیمت ها در این فروشگاه بسیار پایین است."},{"de":"Die Decke im Keller ist ziemlich niedrig.","en":"The ceiling in the basement is quite low.","ru":"Потолок в подвале довольно низкий.","vi":"Trần ở tầng hầm khá thấp.","fa":"سقف در زیرزمین بسیار کم است."}]},{"word":"niemand","en":"nobody; no one","ru":"никто","vi":"không ai","fa":"هیچ کس","examples":[{"de":"Niemand hat mir geholfen.","en":"Nobody helped me.","ru":"Никто мне не помог.","vi":"Không ai giúp tôi cả.","fa":"هیچکس به من کمک نکرد"},{"de":"Im Büro war heute niemand.","en":"There was nobody in the office today.","ru":"В офисе сегодня никого не было.","vi":"Hôm nay ở văn phòng không có ai cả.","fa":"امروز کسی در دفتر نبود."}]},{"word":"nirgends","en":"nowhere","ru":"нигде","vi":"hư không","fa":"هیچ جا","examples":[{"de":"Ich kann meinen Schlüssel nirgends finden.","en":"I can't find my key anywhere.","ru":"Я нигде не могу найти свой ключ.","vi":"Tôi không thể tìm thấy chìa khóa của mình ở đâu cả.","fa":"من هیچ جا کلیدم را پیدا نمی کنم."},{"de":"Sie fühlt sich nirgends so wohl wie zu Hause.","en":"She feels nowhere as comfortable as at home.","ru":"Ей нигде не так хорошо, как дома.","vi":"Cô ấy không cảm thấy thoải mái ở bất cứ đâu như ở nhà.","fa":"او در هیچ کجا به اندازه خانه احساس راحتی نمی کند."}]},{"word":"nirgendwo","en":"nowhere","ru":"нигде","vi":"hư không","fa":"هیچ جا","examples":[{"de":"Diesen Artikel gibt es nirgendwo zu kaufen.","en":"This item can be bought nowhere.","ru":"Этот товар нигде не купить.","vi":"Mặt hàng này không có sẵn để mua ở bất cứ đâu.","fa":"این کالا در هیچ کجا قابل خرید نیست."},{"de":"Wir konnten nirgendwo einen Parkplatz finden.","en":"We couldn't find a parking spot anywhere.","ru":"Мы нигде не смогли найти парковку.","vi":"Chúng tôi không thể tìm thấy chỗ đậu xe ở bất cứ đâu.","fa":"هیچ جا جای پارک پیدا نکردیم."}]},{"word":"noch","en":"still; yet","ru":"ещё","vi":"chưa","fa":"هنوز","examples":[{"de":"Ich bin noch nicht fertig.","en":"I'm not finished yet.","ru":"Я ещё не закончил.","vi":"Tôi vẫn chưa xong việc.","fa":"من هنوز تمام نشده ام."},{"de":"Möchtest du noch einen Kaffee?","en":"Would you like another coffee?","ru":"Хочешь ещё кофе?","vi":"Bạn có muốn một ly cà phê khác không?","fa":"آیا قهوه دیگری می خواهید؟"}]},{"word":"noch mal","en":"once more; again","ru":"ещё раз","vi":"một lần nữa","fa":"دوباره","examples":[{"de":"Kannst du das bitte noch mal erklären?","en":"Can you please explain that once more?","ru":"Можешь объяснить это ещё раз, пожалуйста?","vi":"Bạn có thể vui lòng giải thích điều đó một lần nữa?","fa":"میشه لطفا دوباره توضیح بدید؟"},{"de":"Wir sehen uns noch mal am Freitag.","en":"We'll see each other again on Friday.","ru":"Мы увидимся ещё раз в пятницу.","vi":"Chúng ta sẽ gặp lại nhau vào thứ Sáu.","fa":"جمعه دوباره همدیگر را می بینیم."}]},{"word":"nochmals","en":"once again; once more","ru":"ещё раз; повторно","vi":"một lần nữa","fa":"دوباره","examples":[{"de":"Ich möchte mich nochmals bei Ihnen bedanken.","en":"I would like to thank you once again.","ru":"Я хотел бы ещё раз поблагодарить вас.","vi":"Tôi muốn cảm ơn bạn một lần nữa.","fa":"باز هم می خواهم از شما تشکر کنم."},{"de":"Bitte prüfen Sie das Formular nochmals.","en":"Please check the form once more.","ru":"Пожалуйста, проверьте форму ещё раз.","vi":"Vui lòng kiểm tra lại biểu mẫu.","fa":"لطفا دوباره فرم را بررسی کنید."}]},{"word":"normal","en":"normal","ru":"нормальный","vi":"bình thường","fa":"عادی","examples":[{"de":"Ist es normal, dass die Heizung so laut ist?","en":"Is it normal for the heating to be this loud?","ru":"Это нормально, что отопление такое шумное?","vi":"Máy sưởi kêu to như vậy có phải là bình thường không?","fa":"آیا صدای بخاری اینقدر طبیعی است؟"},{"de":"Heute war ein ganz normaler Arbeitstag.","en":"Today was a completely normal working day.","ru":"Сегодня был совершенно обычный рабочий день.","vi":"Hôm nay là một ngày làm việc bình thường.","fa":"امروز یک روز کاری عادی بود."}]},{"word":"Not-","en":"emergency- (prefix)","ru":"аварийный-; экстренный- (приставка)","vi":"trường hợp khẩn cấp","fa":"اضطراری","examples":[{"de":"Im Notfall wählen Sie die Nummer 112.","en":"In an emergency, dial 112.","ru":"В экстренном случае звоните по номеру 112.","vi":"Trong trường hợp khẩn cấp, hãy quay số 112.","fa":"در مواقع اضطراری 112 را شماره گیری کنید."},{"de":"Der Notausgang befindet sich links neben der Tür.","en":"The emergency exit is on the left next to the door.","ru":"Аварийный выход находится слева от двери.","vi":"Lối thoát hiểm nằm ở bên trái cửa.","fa":"خروجی اضطراری در سمت چپ در است."}]},{"word":"die Note","en":"grade; mark (school); (musical) note","ru":"оценка; нота","vi":"ghi chú","fa":"یادداشت","examples":[{"de":"Ich habe in Mathe eine gute Note bekommen.","en":"I got a good grade in math.","ru":"Я получил хорошую оценку по математике.","vi":"Tôi đạt điểm cao môn toán.","fa":"من در ریاضی نمره خوبی گرفتم."},{"de":"Er kann die Noten auf dem Klavier nicht lesen.","en":"He can't read the notes on the piano.","ru":"Он не умеет читать ноты на пианино.","vi":"Anh ấy không thể đọc nhạc trên đàn piano.","fa":"او نمی تواند موسیقی را روی پیانو بخواند."}]},{"word":"notieren","en":"to note down; to write down","ru":"записывать","vi":"ghi chú lại","fa":"یادداشت کنید","examples":[{"de":"Ich notiere mir die wichtigsten Punkte.","en":"I note down the most important points.","ru":"Я записываю самые важные моменты.","vi":"Tôi ghi lại những điểm quan trọng nhất.","fa":"مهم ترین نکات را یادداشت می کنم."},{"de":"Können Sie sich bitte meine Telefonnummer notieren?","en":"Could you please write down my phone number?","ru":"Не могли бы вы записать мой номер телефона?","vi":"Bạn có thể vui lòng ghi lại số điện thoại của tôi được không?","fa":"میشه لطفا شماره تلفن منو یادداشت کنید"}]},{"word":"nötig","en":"necessary","ru":"необходимый; нужный","vi":"cần thiết","fa":"لازم است","examples":[{"de":"Es ist nicht nötig, dass du dich entschuldigst.","en":"It is not necessary for you to apologize.","ru":"Тебе не обязательно извиняться.","vi":"Bạn không cần phải xin lỗi đâu.","fa":"نیازی به عذرخواهی نیست"},{"de":"Wir haben alle nötigen Unterlagen dabei.","en":"We have all the necessary documents with us.","ru":"У нас с собой все необходимые документы.","vi":"Chúng tôi có tất cả các tài liệu cần thiết với chúng tôi.","fa":"ما تمام مدارک لازم را با خود داریم."}]},{"word":"die Notiz","en":"note (written)","ru":"заметка; записка","vi":"ghi chú","fa":"یادداشت","examples":[{"de":"Ich habe mir eine Notiz gemacht, damit ich es nicht vergesse.","en":"I made a note so I wouldn't forget it.","ru":"Я сделал заметку, чтобы не забыть.","vi":"Mình đã note lại để khỏi quên.","fa":"یادداشت کردم که فراموش نکنم"},{"de":"Auf dem Tisch liegt eine Notiz von meiner Mutter.","en":"There is a note from my mother on the table.","ru":"На столе лежит записка от моей мамы.","vi":"Có một tờ giấy của mẹ tôi trên bàn.","fa":"یادداشتی از مادرم روی میز است."}]},{"word":"notwendig","en":"necessary","ru":"необходимый","vi":"cần thiết","fa":"لازم است","examples":[{"de":"Ein Regenschirm ist heute notwendig.","en":"An umbrella is necessary today.","ru":"Сегодня необходим зонт.","vi":"Một chiếc ô là cần thiết ngày hôm nay.","fa":"امروز یک چتر ضروری است."},{"de":"Ist es wirklich notwendig, so früh aufzustehen?","en":"Is it really necessary to get up this early?","ru":"Действительно ли необходимо вставать так рано?","vi":"Có thực sự cần thiết phải dậy sớm như vậy không?","fa":"آیا واقعاً لازم است اینقدر زود بیدار شویم؟"}]},{"word":"die Nudel","en":"noodle; pasta","ru":"лапша; макароны","vi":"mì","fa":"رشته فرنگی","examples":[{"de":"Zum Abendessen gibt es Nudeln mit Tomatensoße.","en":"For dinner there are noodles with tomato sauce.","ru":"На ужин макароны с томатным соусом.","vi":"Bữa tối có mì ống sốt cà chua.","fa":"برای شام پاستا با سس گوجه فرنگی وجود دارد."},{"de":"Die Nudeln müssen zehn Minuten kochen.","en":"The pasta needs to cook for ten minutes.","ru":"Макароны нужно варить десять минут.","vi":"Mì ống cần nấu trong mười phút.","fa":"پاستا باید ده دقیقه بپزد."}]},{"word":"die Nummer","en":"number","ru":"номер","vi":"số","fa":"شماره","examples":[{"de":"Kannst du mir deine Nummer geben?","en":"Can you give me your number?","ru":"Можешь дать мне свой номер?","vi":"Bạn có thể cho tôi số của bạn được không?","fa":"میشه شماره ات رو بهم بدی"},{"de":"Ich wohne in der Straße Nummer zwölf.","en":"I live at number twelve on this street.","ru":"Я живу в доме номер двенадцать на этой улице.","vi":"Tôi sống trên đường số mười hai.","fa":"من در خیابان شماره دوازده زندگی می کنم."}]},{"word":"nun","en":"now","ru":"теперь; ну","vi":"bây giờ","fa":"اکنون","examples":[{"de":"Nun müssen wir eine Entscheidung treffen.","en":"Now we have to make a decision.","ru":"Теперь нам нужно принять решение.","vi":"Bây giờ chúng ta phải đưa ra quyết định.","fa":"حالا باید تصمیم بگیریم."},{"de":"Was machen wir nun?","en":"What do we do now?","ru":"Что же нам теперь делать?","vi":"Chúng ta phải làm gì bây giờ?","fa":"حالا چیکار کنیم؟"}]},{"word":"nur","en":"only; just","ru":"только","vi":"chỉ","fa":"فقط","examples":[{"de":"Ich habe nur zehn Euro dabei.","en":"I only have ten euros with me.","ru":"У меня с собой только десять евро.","vi":"Tôi chỉ có mười euro bên mình.","fa":"من فقط ده یورو با خودم دارم."},{"de":"Das war nur ein Scherz.","en":"That was just a joke.","ru":"Это была всего лишь шутка.","vi":"Đó chỉ là một trò đùa thôi.","fa":"این فقط یک شوخی بود."}]},{"word":"nutzen","en":"to use","ru":"использовать; пользоваться","vi":"sử dụng","fa":"استفاده کنید","examples":[{"de":"Wir nutzen die Bibliothek regelmäßig.","en":"We use the library regularly.","ru":"Мы регулярно пользуемся библиотекой.","vi":"Chúng tôi sử dụng thư viện thường xuyên.","fa":"ما به طور منظم از کتابخانه استفاده می کنیم."},{"de":"Man sollte die Zeit gut nutzen.","en":"One should use time well.","ru":"Нужно хорошо использовать время.","vi":"Bạn nên sử dụng thời gian thật tốt.","fa":"باید از زمان به خوبی استفاده کرد."}]},{"word":"nützen","en":"to be useful; to benefit","ru":"приносить пользу","vi":"lợi ích","fa":"منفعت","examples":[{"de":"Diese Erfahrung wird dir später nützen.","en":"This experience will benefit you later.","ru":"Этот опыт пригодится тебе позже.","vi":"Kinh nghiệm này sẽ có ích cho bạn sau này.","fa":"این تجربه بعدا برای شما مفید خواهد بود."},{"de":"Es nützt nichts, sich zu beschweren.","en":"It's no use complaining.","ru":"Нет смысла жаловаться.","vi":"Chẳng ích gì khi phàn nàn.","fa":"شکایت فایده ای ندارد"}]},{"word":"ob","en":"whether; if","ru":"ли","vi":"liệu","fa":"آیا","examples":[{"de":"Ich weiß nicht, ob er heute kommt.","en":"I don't know whether he's coming today.","ru":"Я не знаю, придёт ли он сегодня.","vi":"Tôi không biết hôm nay anh ấy có đến không.","fa":"نمیدونم امروز میاد یا نه"},{"de":"Frag ihn, ob er Zeit hat.","en":"Ask him if he has time.","ru":"Спроси его, есть ли у него время.","vi":"Hỏi xem anh ấy có thời gian không.","fa":"از او بپرسید که آیا وقت دارد؟"}]},{"word":"oben","en":"above; upstairs","ru":"наверху","vi":"ở trên","fa":"بالا","examples":[{"de":"Mein Zimmer ist oben im ersten Stock.","en":"My room is upstairs on the first floor.","ru":"Моя комната наверху, на втором этаже.","vi":"Phòng của tôi ở trên lầu một.","fa":"اتاق من طبقه اول است."},{"de":"Schau mal, ganz oben auf dem Berg liegt Schnee.","en":"Look, there's snow right at the top of the mountain.","ru":"Смотри, на самой вершине горы лежит снег.","vi":"Nhìn kìa, có tuyết trên đỉnh núi.","fa":"ببین، بالای کوه برف آمده است."}]},{"word":"das Obst","en":"fruit","ru":"фрукты","vi":"trái cây","fa":"میوه","examples":[{"de":"Ich esse jeden Tag frisches Obst.","en":"I eat fresh fruit every day.","ru":"Я каждый день ем свежие фрукты.","vi":"I eat fresh fruit every day.","fa":"من هر روز میوه تازه می خورم."},{"de":"Auf dem Markt gibt es viel Obst und Gemüse.","en":"There is a lot of fruit and vegetables at the market.","ru":"На рынке много фруктов и овощей.","vi":"Có rất nhiều trái cây và rau quả trên thị trường.","fa":"میوه ها و سبزیجات زیادی در بازار وجود دارد."}]},{"word":"obwohl","en":"although","ru":"хотя","vi":"mặc dù","fa":"اگرچه","examples":[{"de":"Obwohl es regnet, gehen wir spazieren.","en":"Although it's raining, we're going for a walk.","ru":"Хотя идёт дождь, мы идём гулять.","vi":"Nếu bạn muốn đăng ký, bạn sẽ có được không gian rộng rãi.","fa":"با وجود اینکه باران می بارد، میریم پیاده روی."},{"de":"Er ist zur Arbeit gegangen, obwohl er krank war.","en":"He went to work, although he was sick.","ru":"Он пошёл на работу, хотя был болен.","vi":"Anh ấy đi làm mặc dù anh ấy bị ốm.","fa":"با اینکه مریض بود سر کار رفت."}]},{"word":"oder","en":"or","ru":"или","vi":"hoặc","fa":"یا","examples":[{"de":"Möchtest du Tee oder Kaffee?","en":"Would you like tea or coffee?","ru":"Хочешь чай или кофе?","vi":"Bạn muốn uống trà hay cà phê?","fa":"آیا چای یا قهوه میل دارید؟"},{"de":"Kommst du mit, oder bleibst du zu Hause?","en":"Are you coming with us, or are you staying home?","ru":"Ты идёшь с нами или остаёшься дома?","vi":"Bạn sẽ đi cùng chúng tôi hay bạn đang ở nhà?","fa":"با ما می آیی یا در خانه می مانی؟"}]},{"word":"offen","en":"open","ru":"открытый","vi":"mở","fa":"باز کردن","examples":[{"de":"Die Tür ist offen, du kannst reinkommen.","en":"The door is open, you can come in.","ru":"Дверь открыта, можешь войти.","vi":"Cửa đang mở, bạn có thể vào.","fa":"در باز است، می توانید وارد شوید."},{"de":"Der Laden hat bis 20 Uhr offen.","en":"The shop is open until 8 pm.","ru":"Магазин открыт до 20 часов.","vi":"The shop is open until 8 p.m.","fa":"مغازه تا ساعت 8 شب باز است."}]},{"word":"offenbar","en":"apparently","ru":"очевидно; по-видимому","vi":"rõ ràng","fa":"ظاهرا","examples":[{"de":"Offenbar hat er den Termin vergessen.","en":"Apparently he forgot the appointment.","ru":"Очевидно, он забыл о встрече.","vi":"Offenbar hat er den Termin Vergessen.","fa":"ظاهراً قرار ملاقات را فراموش کرده است."},{"de":"Sie ist offenbar schon nach Hause gegangen.","en":"She has apparently already gone home.","ru":"Она, по-видимому, уже ушла домой.","vi":"Có vẻ như cô ấy đã về nhà rồi.","fa":"ظاهراً او قبلاً به خانه رفته است."}]},{"word":"offensichtlich","en":"obvious; apparently","ru":"очевидный; очевидно","vi":"rõ ràng","fa":"بدیهی است","examples":[{"de":"Es war offensichtlich, dass er log.","en":"It was obvious that he was lying.","ru":"Было очевидно, что он лжёт.","vi":"Rõ ràng là anh ta đang nói dối.","fa":"معلوم بود که داره دروغ میگه"},{"de":"Offensichtlich hat sie den Termin vergessen.","en":"Apparently she forgot the appointment.","ru":"Очевидно, она забыла о встрече.","vi":"Có vẻ như cô ấy đã quên cuộc hẹn.","fa":"ظاهراً قرار ملاقات را فراموش کرده است."}]},{"word":"öffentlich","en":"public","ru":"общественный; публичный","vi":"công khai","fa":"عمومی","examples":[{"de":"Ich fahre meistens mit öffentlichen Verkehrsmitteln.","en":"I mostly travel by public transport.","ru":"Я в основном езжу на общественном транспорте.","vi":"Tôi chủ yếu đi phương tiện công cộng.","fa":"من بیشتر از وسایل نقلیه عمومی استفاده می کنم."},{"de":"Das Konzert findet auf einem öffentlichen Platz statt.","en":"The concert takes place in a public square.","ru":"Концерт проходит на общественной площади.","vi":"The concert takes place in a public square.","fa":"کنسرت در یک میدان عمومی برگزار می شود."}]},{"word":"die Öffentlichkeit","en":"the public","ru":"общественность","vi":"công chúng","fa":"عمومی","examples":[{"de":"Der Politiker trat vor die Öffentlichkeit.","en":"The politician appeared before the public.","ru":"Политик выступил перед общественностью.","vi":"Chính trị gia xuất hiện trước công chúng.","fa":"این سیاستمدار در برابر مردم ظاهر شد."},{"de":"Diese Information ist nicht für die Öffentlichkeit bestimmt.","en":"This information is not intended for the public.","ru":"Эта информация не предназначена для общественности.","vi":"Thông tin này không dành cho công chúng.","fa":"این اطلاعات برای عموم در نظر گرفته نشده است."}]},{"word":"offiziell","en":"official","ru":"официальный","vi":"chính thức","fa":"رسمی","examples":[{"de":"Die offizielle Eröffnung ist am Samstag.","en":"The official opening is on Saturday.","ru":"Официальное открытие состоится в субботу.","vi":"Ngày khai mạc chính thức là vào thứ bảy.","fa":"افتتاحیه رسمی روز شنبه است."},{"de":"Das ist noch keine offizielle Entscheidung.","en":"That is not an official decision yet.","ru":"Это ещё не официальное решение.","vi":"Đây vẫn chưa phải là quyết định chính thức.","fa":"این هنوز یک تصمیم رسمی نیست."}]},{"word":"öffnen","en":"to open","ru":"открывать","vi":"mở","fa":"باز کردن","examples":[{"de":"Kannst du bitte das Fenster öffnen?","en":"Can you please open the window?","ru":"Можешь открыть окно, пожалуйста?","vi":"Bạn có thể vui lòng mở cửa sổ được không?","fa":"میشه لطفا پنجره رو باز کن"},{"de":"Die Bank öffnet um neun Uhr.","en":"The bank opens at nine o'clock.","ru":"Банк открывается в девять часов.","vi":"Ngân hàng mở cửa lúc chín giờ.","fa":"بانک ساعت نه باز می شود."}]},{"word":"oft","en":"often","ru":"часто","vi":"thường xuyên","fa":"اغلب","examples":[{"de":"Ich gehe oft ins Kino.","en":"I often go to the cinema.","ru":"Я часто хожу в кино.","vi":"Tôi thường đi xem phim.","fa":"من اغلب به سینما می روم."},{"de":"Wie oft trainierst du in der Woche?","en":"How often do you train per week?","ru":"Как часто ты тренируешься в неделю?","vi":"Bạn tập luyện bao nhiêu lần một tuần?","fa":"چند بار در هفته تمرین می کنید؟"}]},{"word":"ohne","en":"without","ru":"без","vi":"không có","fa":"بدون","examples":[{"de":"Ich trinke meinen Kaffee ohne Zucker.","en":"I drink my coffee without sugar.","ru":"Я пью кофе без сахара.","vi":"Tôi uống cà phê không đường.","fa":"من قهوه ام را بدون قند می نوشم."},{"de":"Ohne dich wäre die Party langweilig gewesen.","en":"Without you the party would have been boring.","ru":"Без тебя вечеринка была бы скучной.","vi":"Nếu không có bạn bữa tiệc sẽ trở nên nhàm chán.","fa":"بدون شما مهمانی خسته کننده بود."}]},{"word":"das Ohr","en":"ear","ru":"ухо","vi":"cái tai","fa":"گوش","examples":[{"de":"Mir tut das Ohr weh.","en":"My ear hurts.","ru":"У меня болит ухо.","vi":"Tai tôi đau quá.","fa":"گوشم درد میکنه"},{"de":"Er hat sich die Ohren zugehalten, weil es so laut war.","en":"He covered his ears because it was so loud.","ru":"Он закрыл уши, потому что было так громко.","vi":"Anh bịt tai lại vì quá ồn ào.","fa":"چون صدایش خیلی بلند بود گوش هایش را گرفت."}]},{"word":"Öko- (ökologisch)","en":"eco- (ecological)","ru":"эко- (экологический)","vi":"eco- (sinh thái)","fa":"زیست محیطی (اکولوژیک)","examples":[{"de":"Wir kaufen gern Ökoprodukte im Bioladen.","en":"We like to buy eco products at the organic shop.","ru":"Мы любим покупать эко-продукты в магазине органических товаров.","vi":"Chúng tôi thích mua sản phẩm hữu cơ ở các cửa hàng hữu cơ.","fa":"ما دوست داریم محصولات ارگانیک را در فروشگاه های ارگانیک بخریم."},{"de":"Ökologisches Handeln ist heute sehr wichtig.","en":"Ecological behavior is very important today.","ru":"Экологичное поведение сегодня очень важно.","vi":"Hành động sinh thái ngày nay rất quan trọng.","fa":"اقدامات زیست محیطی امروزه بسیار مهم است."}]},{"word":"das Öl","en":"oil","ru":"масло; нефть","vi":"dầu","fa":"روغن","examples":[{"de":"Gib etwas Öl in die Pfanne.","en":"Put some oil in the pan.","ru":"Налей немного масла на сковороду.","vi":"Thêm một ít dầu vào chảo.","fa":"مقداری روغن به تابه اضافه کنید."},{"de":"Der Preis für Öl ist gestiegen.","en":"The price of oil has risen.","ru":"Цена на нефть выросла.","vi":"Giá dầu đã tăng.","fa":"قیمت نفت افزایش یافته است."}]},{"word":"die Oma","en":"grandma","ru":"бабушка","vi":"bà ngoại","fa":"مادربزرگ","examples":[{"de":"Meine Oma backt jeden Sonntag einen Kuchen.","en":"My grandma bakes a cake every Sunday.","ru":"Моя бабушка печёт пирог каждое воскресенье.","vi":"Bà tôi nướng bánh vào mỗi Chủ Nhật.","fa":"مادربزرگ من هر یکشنبه یک کیک می پزد."},{"de":"Wir besuchen unsere Oma am Wochenende.","en":"We visit our grandma on the weekend.","ru":"Мы навещаем бабушку на выходных.","vi":"Chúng tôi đến thăm bà của chúng tôi vào cuối tuần.","fa":"آخر هفته به دیدن مادربزرگمان می رویم."}]},{"word":"der Onkel","en":"uncle","ru":"дядя","vi":"chú","fa":"عمو","examples":[{"de":"Mein Onkel lebt in Kanada.","en":"My uncle lives in Canada.","ru":"Мой дядя живёт в Канаде.","vi":"Chú tôi sống ở Canada.","fa":"دایی من در کانادا زندگی می کند."},{"de":"Ich habe von meinem Onkel ein Geschenk bekommen.","en":"I got a gift from my uncle.","ru":"Я получил подарок от дяди.","vi":"Tôi đã nhận được một món quà từ chú tôi.","fa":"از عمویم هدیه گرفتم."}]},{"word":"der Opa","en":"grandpa","ru":"дедушка","vi":"ông nội","fa":"پدربزرگ","examples":[{"de":"Mein Opa erzählt gerne Geschichten aus seiner Jugend.","en":"My grandpa likes to tell stories from his youth.","ru":"Мой дедушка любит рассказывать истории из своей молодости.","vi":"Ông tôi thích kể những câu chuyện thời trẻ.","fa":"پدربزرگم دوست دارد از دوران جوانی اش قصه بگوید."},{"de":"Der Opa spielt mit den Enkelkindern im Garten.","en":"Grandpa plays with the grandchildren in the garden.","ru":"Дедушка играет с внуками в саду.","vi":"Ông nội chơi với các cháu trong vườn.","fa":"پدربزرگ با نوه هایش در باغ بازی می کند."}]},{"word":"die Oper","en":"opera","ru":"опера","vi":"vở opera","fa":"اپرا","examples":[{"de":"Am Samstag gehen wir in die Oper.","en":"On Saturday we're going to the opera.","ru":"В субботу мы идём в оперу.","vi":"Vào thứ bảy chúng tôi đi xem opera.","fa":"شنبه می رویم اپرا."},{"de":"Diese Oper von Mozart ist sehr bekannt.","en":"This opera by Mozart is very famous.","ru":"Эта опера Моцарта очень известна.","vi":"Vở opera này của Mozart rất nổi tiếng.","fa":"این اپرای موتسارت بسیار شناخته شده است."}]},{"word":"operieren","en":"to operate (surgically)","ru":"оперировать","vi":"vận hành","fa":"عمل کنند","examples":[{"de":"Der Arzt muss den Patienten sofort operieren.","en":"The doctor has to operate on the patient immediately.","ru":"Врач должен немедленно прооперировать пациента.","vi":"Bác sĩ phải phẫu thuật cho bệnh nhân ngay lập tức.","fa":"پزشک باید بلافاصله بیمار را جراحی کند."},{"de":"Sie wurde letzte Woche am Knie operiert.","en":"She had knee surgery last week.","ru":"На прошлой неделе ей сделали операцию на колене.","vi":"Cô ấy đã phẫu thuật đầu gối vào tuần trước.","fa":"او هفته گذشته زانو را جراحی کرد."}]},{"word":"das Opfer","en":"victim; sacrifice","ru":"жертва","vi":"nạn nhân","fa":"قربانی","examples":[{"de":"Die Feuerwehr rettete alle Opfer des Unfalls.","en":"The fire brigade rescued all victims of the accident.","ru":"Пожарные спасли всех жертв аварии.","vi":"Lực lượng cứu hỏa đã giải cứu toàn bộ nạn nhân trong vụ tai nạn.","fa":"آتش نشانی تمامی مصدومان این حادثه را نجات داد."},{"de":"Für ihren Erfolg musste sie viele Opfer bringen.","en":"She had to make many sacrifices for her success.","ru":"Ради своего успеха ей пришлось пойти на многие жертвы.","vi":"Cô đã phải hy sinh rất nhiều để có được thành công.","fa":"او باید برای موفقیتش فداکاری های زیادی می کرد."}]},{"word":"optimistisch","en":"optimistic","ru":"оптимистичный","vi":"lạc quan","fa":"خوش بینانه","examples":[{"de":"Trotz der Probleme bleibt er optimistisch.","en":"Despite the problems, he remains optimistic.","ru":"Несмотря на проблемы, он остаётся оптимистичным.","vi":"Bất chấp những vấn đề, anh vẫn lạc quan.","fa":"با وجود مشکلات، او همچنان خوشبین است."},{"de":"Ich bin optimistisch, dass wir die Prüfung schaffen.","en":"I'm optimistic that we'll pass the exam.","ru":"Я оптимистично настроен, что мы сдадим экзамен.","vi":"Tôi lạc quan rằng chúng tôi sẽ vượt qua kỳ thi.","fa":"من خوشبین هستم که در این آزمون موفق شویم."}]},{"word":"die Orange","en":"orange (fruit)","ru":"апельсин","vi":"quả cam","fa":"پرتقال","examples":[{"de":"Zum Frühstück esse ich gern eine Orange.","en":"For breakfast I like to eat an orange.","ru":"На завтрак я люблю есть апельсин.","vi":"Tôi thích ăn một quả cam vào bữa sáng.","fa":"من دوست دارم صبحانه یک پرتقال بخورم."},{"de":"Die Orangen aus Spanien schmecken sehr süß.","en":"The oranges from Spain taste very sweet.","ru":"Апельсины из Испании очень сладкие на вкус.","vi":"Cam từ Tây Ban Nha có vị rất ngọt.","fa":"پرتقال های اسپانیایی طعم بسیار شیرینی دارند."}]},{"word":"das Orchester","en":"orchestra","ru":"оркестр","vi":"dàn nhạc","fa":"ارکستر","examples":[{"de":"Das Orchester spielt heute Abend im Konzertsaal.","en":"The orchestra is playing tonight in the concert hall.","ru":"Оркестр играет сегодня вечером в концертном зале.","vi":"Dàn nhạc đang chơi trong phòng hòa nhạc tối nay.","fa":"این ارکستر عصر امروز در سالن کنسرت می نوازد."},{"de":"Sie spielt Geige in einem bekannten Orchester.","en":"She plays violin in a famous orchestra.","ru":"Она играет на скрипке в известном оркестре.","vi":"Cô chơi violin trong một dàn nhạc nổi tiếng.","fa":"او در یک ارکستر معروف ویولن می نوازد."}]},{"word":"ordentlich","en":"tidy; neat","ru":"аккуратный; опрятный","vi":"gọn gàng","fa":"مرتب","examples":[{"de":"Bitte räum dein Zimmer ordentlich auf.","en":"Please tidy up your room neatly.","ru":"Пожалуйста, аккуратно убери свою комнату.","vi":"Hãy dọn dẹp phòng của bạn đúng cách.","fa":"لطفا اتاق خود را به درستی مرتب کنید."},{"de":"Er ist immer sehr ordentlich gekleidet.","en":"He is always dressed very neatly.","ru":"Он всегда одет очень опрятно.","vi":"Anh ấy luôn ăn mặc rất gọn gàng.","fa":"او همیشه خیلی مرتب لباس می پوشد."}]},{"word":"die Ordination","en":"doctor's office/practice (Austrian)","ru":"врачебный кабинет (австр.)","vi":"lễ tấn phong","fa":"انتصاب","examples":[{"de":"Die Ordination des Arztes ist von acht bis zwölf Uhr geöffnet.","en":"The doctor's office is open from eight to twelve.","ru":"Врачебный кабинет открыт с восьми до двенадцати часов.","vi":"Văn phòng bác sĩ mở cửa từ tám giờ sáng đến mười hai giờ tối.","fa":"مطب دکتر از هشت صبح تا دوازده شب باز است."},{"de":"Ich habe heute einen Termin in der Ordination.","en":"I have an appointment at the doctor's office today.","ru":"У меня сегодня приём в врачебном кабинете.","vi":"Hôm nay tôi có hẹn ở văn phòng.","fa":"امروز در دفتر قرار دارم."}]},{"word":"ordnen","en":"to arrange; to put in order","ru":"упорядочивать; приводить в порядок","vi":"sắp xếp","fa":"ترتیب دهید","examples":[{"de":"Sie ordnet die Bücher nach dem Alphabet.","en":"She arranges the books alphabetically.","ru":"Она расставляет книги по алфавиту.","vi":"Cô sắp xếp sách theo bảng chữ cái.","fa":"او کتاب ها را بر اساس حروف الفبا مرتب می کند."},{"de":"Ich muss meine Unterlagen noch ordnen.","en":"I still need to sort out my documents.","ru":"Мне ещё нужно привести в порядок свои документы.","vi":"Tôi vẫn phải sắp xếp tài liệu của mình.","fa":"من هنوز باید مدارکم را مرتب کنم."}]},{"word":"organisieren","en":"to organize","ru":"организовывать","vi":"tổ chức","fa":"سازماندهی","examples":[{"de":"Wir organisieren eine Geburtstagsparty für sie.","en":"We are organizing a birthday party for her.","ru":"Мы организуем для неё вечеринку по случаю дня рождения.","vi":"Chúng tôi đang tổ chức một bữa tiệc sinh nhật cho cô ấy.","fa":"ما در حال برگزاری جشن تولد برای او هستیم."},{"de":"Er hat die ganze Reise selbst organisiert.","en":"He organized the whole trip himself.","ru":"Он сам организовал всю поездку.","vi":"Anh ấy tự tổ chức toàn bộ chuyến đi.","fa":"کل سفر را خودش سازماندهی کرد."}]},{"word":"das Original","en":"original","ru":"оригинал","vi":"bản gốc","fa":"اصلی","examples":[{"de":"Dieses Gemälde ist ein echtes Original.","en":"This painting is a real original.","ru":"Эта картина — настоящий оригинал.","vi":"Bức tranh này là một bản gốc thực sự.","fa":"این نقاشی یک اصل واقعی است."},{"de":"Bitte bringen Sie das Original des Dokuments mit.","en":"Please bring the original of the document.","ru":"Пожалуйста, принесите оригинал документа.","vi":"Vui lòng mang theo tài liệu gốc.","fa":"لطفا اصل سند را به همراه داشته باشید."}]},{"word":"der Ort","en":"place; location","ru":"место","vi":"nơi","fa":"مکان","examples":[{"de":"Das ist ein schöner Ort für ein Picknick.","en":"This is a nice place for a picnic.","ru":"Это красивое место для пикника.","vi":"Đây là một nơi tốt đẹp cho một chuyến dã ngoại.","fa":"این یک مکان خوب برای پیک نیک است."},{"de":"An welchem Ort wollen wir uns treffen?","en":"At which place do we want to meet?","ru":"В каком месте мы встретимся?","vi":"Chúng ta muốn gặp nhau ở đâu?","fa":"کجا می خواهیم ملاقات کنیم؟"}]},{"word":"der Ozean","en":"ocean","ru":"океан","vi":"đại dương","fa":"اقیانوس","examples":[{"de":"Der Atlantische Ozean liegt zwischen Europa und Amerika.","en":"The Atlantic Ocean lies between Europe and America.","ru":"Атлантический океан находится между Европой и Америкой.","vi":"Đại Tây Dương nằm giữa châu Âu và châu Mỹ.","fa":"اقیانوس اطلس بین اروپا و آمریکا قرار دارد."},{"de":"Sie träumt davon, den Ozean zu überqueren.","en":"She dreams of crossing the ocean.","ru":"Она мечтает пересечь океан.","vi":"Cô mơ ước được vượt đại dương.","fa":"او رویای عبور از اقیانوس را در سر می پروراند."}]},{"word":"das Paar","en":"pair; couple","ru":"пара","vi":"cặp đôi","fa":"زوج","examples":[{"de":"Ich brauche ein neues Paar Schuhe.","en":"I need a new pair of shoes.","ru":"Мне нужна новая пара обуви.","vi":"Tôi cần một đôi giày mới.","fa":"من به یک جفت کفش نو نیاز دارم."},{"de":"Das Paar tanzt sehr elegant.","en":"The couple dances very elegantly.","ru":"Пара танцует очень элегантно.","vi":"Cặp đôi nhảy rất sang chảnh.","fa":"این زوج بسیار شیک می رقصند."}]},{"word":"packen","en":"to pack","ru":"паковать; упаковывать","vi":"gói","fa":"بسته","examples":[{"de":"Ich muss noch meinen Koffer packen.","en":"I still have to pack my suitcase.","ru":"Мне ещё нужно упаковать чемодан.","vi":"Tôi vẫn phải đóng gói hành lý của mình.","fa":"هنوز باید چمدانم را ببندم."},{"de":"Hast du schon deine Sachen für die Reise gepackt?","en":"Have you already packed your things for the trip?","ru":"Ты уже упаковал свои вещи для поездки?","vi":"Bạn đã chuẩn bị đồ đạc cho chuyến đi chưa?","fa":"آیا قبلاً وسایل خود را برای سفر جمع کرده اید؟"}]},{"word":"das Paket","en":"package; parcel","ru":"посылка; пакет","vi":"gói","fa":"بسته","examples":[{"de":"Heute ist ein Paket für dich angekommen.","en":"A package arrived for you today.","ru":"Сегодня для тебя пришла посылка.","vi":"Hôm nay có một gói hàng đã đến cho bạn.","fa":"امروز یک بسته برای شما رسید."},{"de":"Ich muss das Paket zur Post bringen.","en":"I have to take the package to the post office.","ru":"Мне нужно отнести посылку на почту.","vi":"Tôi phải mang gói hàng đến bưu điện.","fa":"باید بسته را به اداره پست ببرم."}]},{"word":"die Panne","en":"breakdown (mechanical); mishap","ru":"поломка; авария","vi":"sự cố","fa":"خرابی","examples":[{"de":"Unser Auto hatte auf der Autobahn eine Panne.","en":"Our car broke down on the highway.","ru":"Наша машина сломалась на автомагистрали.","vi":"Xe của chúng tôi bị hỏng trên đường cao tốc.","fa":"ماشین ما در بزرگراه خراب شد."},{"de":"Wegen einer technischen Panne fiel der Strom aus.","en":"Due to a technical malfunction, the power went out.","ru":"Из-за технической неполадки отключилось электричество.","vi":"Mất điện do trục trặc kỹ thuật.","fa":"برق به دلیل نقص فنی قطع شد."}]},{"word":"das Papier","en":"paper","ru":"бумага","vi":"tờ giấy","fa":"کاغذ","examples":[{"de":"Ich brauche ein Blatt Papier.","en":"I need a sheet of paper.","ru":"Мне нужен лист бумаги.","vi":"Tôi cần một mảnh giấy.","fa":"من به یک تکه کاغذ نیاز دارم."},{"de":"Bitte werfen Sie das Papier in den Recyclingcontainer.","en":"Please throw the paper into the recycling container.","ru":"Пожалуйста, выбросьте бумагу в контейнер для переработки.","vi":"Vui lòng vứt giấy vào thùng tái chế.","fa":"لطفا کاغذ را داخل ظرف بازیافت بیندازید."}]},{"word":"der Paradeiser","en":"tomato (Austrian)","ru":"помидор (австр.)","vi":"cà chua","fa":"گوجه فرنگی","examples":[{"de":"Für die Soße brauchen wir frische Paradeiser.","en":"We need fresh tomatoes for the sauce.","ru":"Для соуса нам нужны свежие помидоры.","vi":"Đối với nước sốt chúng ta cần cà chua tươi.","fa":"برای سس به گوجه فرنگی تازه نیاز داریم."},{"de":"Im Garten wachsen dieses Jahr viele Paradeiser.","en":"This year many tomatoes are growing in the garden.","ru":"В этом году в саду растёт много помидоров.","vi":"Có rất nhiều cà chua trồng trong vườn năm nay.","fa":"امسال گوجه فرنگی های زیادی در باغ می روید."}]},{"word":"parallel","en":"parallel","ru":"параллельный; параллельно","vi":"song song","fa":"موازی","examples":[{"de":"Die beiden Straßen verlaufen parallel zueinander.","en":"The two streets run parallel to each other.","ru":"Обе улицы идут параллельно друг другу.","vi":"Hai con đường chạy song song với nhau.","fa":"این دو خیابان به موازات یکدیگر قرار دارند."},{"de":"Er arbeitet parallel an zwei Projekten.","en":"He is working on two projects in parallel.","ru":"Он работает параллельно над двумя проектами.","vi":"Anh ấy đang thực hiện song song hai dự án.","fa":"او به طور موازی روی دو پروژه کار می کند."}]},{"word":"das Parfüm","en":"perfume","ru":"духи","vi":"nước hoa","fa":"عطر","examples":[{"de":"Sie trägt immer das gleiche Parfüm.","en":"She always wears the same perfume.","ru":"Она всегда носит одни и те же духи.","vi":"Cô ấy luôn xức cùng một loại nước hoa.","fa":"او همیشه از همان عطر استفاده می کند."},{"de":"Ich habe mir ein neues Parfüm gekauft.","en":"I bought myself a new perfume.","ru":"Я купила себе новые духи.","vi":"Tôi đã mua cho mình một loại nước hoa mới.","fa":"یک عطر جدید برای خودم خریدم."}]},{"word":"der Park","en":"park","ru":"парк","vi":"công viên","fa":"پارک","examples":[{"de":"Wir gehen im Park spazieren.","en":"We go for a walk in the park.","ru":"Мы гуляем в парке.","vi":"Chúng tôi đi dạo trong công viên.","fa":"میریم تو پارک قدم بزنیم."},{"de":"Die Kinder spielen im Park Fußball.","en":"The children play football in the park.","ru":"Дети играют в футбол в парке.","vi":"Bọn trẻ chơi bóng đá trong công viên.","fa":"بچه ها در پارک فوتبال بازی می کنند."}]},{"word":"parken","en":"to park","ru":"парковаться","vi":"công viên","fa":"پارک","examples":[{"de":"Hier darf man nicht parken.","en":"You are not allowed to park here.","ru":"Здесь нельзя парковаться.","vi":"Bạn không được phép đậu xe ở đây.","fa":"شما اجازه ندارید اینجا پارک کنید."},{"de":"Ich habe das Auto vor dem Haus geparkt.","en":"I parked the car in front of the house.","ru":"Я припарковал машину перед домом.","vi":"Tôi đỗ xe trước nhà.","fa":"ماشین رو جلوی خونه پارک کردم."}]},{"word":"parkieren","en":"to park (Swiss/Austrian)","ru":"парковаться (швейц./австр.)","vi":"công viên","fa":"پارک","examples":[{"de":"In der Innenstadt kann man das Auto schwer parkieren.","en":"It's hard to park the car in the city center.","ru":"В центре города трудно припарковать машину.","vi":"Thật khó để đỗ xe ở trung tâm thành phố.","fa":"پارک کردن ماشین در مرکز شهر سخت است."},{"de":"Bitte parkieren Sie nur auf den markierten Plätzen.","en":"Please park only in the marked spaces.","ru":"Пожалуйста, паркуйтесь только на обозначенных местах.","vi":"Vui lòng chỉ đỗ xe ở những chỗ được đánh dấu.","fa":"لطفا فقط در فضاهای مشخص شده پارک کنید."}]},{"word":"die Partei","en":"(political) party","ru":"партия","vi":"bữa tiệc","fa":"حزب","examples":[{"de":"Welche Partei hast du gewählt?","en":"Which party did you vote for?","ru":"За какую партию ты проголосовал?","vi":"Bạn đã bỏ phiếu cho đảng nào?","fa":"به کدام حزب رای دادید؟"},{"de":"Die Partei hat bei der Wahl viele Stimmen verloren.","en":"The party lost many votes in the election.","ru":"Партия потеряла много голосов на выборах.","vi":"Đảng đã mất nhiều phiếu trong cuộc bầu cử.","fa":"این حزب در انتخابات آرای زیادی را از دست داد."}]},{"word":"der Partner","en":"partner","ru":"партнёр","vi":"đối tác","fa":"شریک","examples":[{"de":"Mein Partner arbeitet in einer anderen Stadt.","en":"My partner works in a different city.","ru":"Мой партнёр работает в другом городе.","vi":"Đối tác của tôi làm việc ở một thành phố khác.","fa":"شریک زندگی من در شهر دیگری کار می کند."},{"de":"Wir suchen einen zuverlässigen Partner für das Projekt.","en":"We are looking for a reliable partner for the project.","ru":"Мы ищем надёжного партнёра для проекта.","vi":"Chúng tôi đang tìm kiếm đối tác tin cậy cho dự án.","fa":"ما به دنبال یک شریک قابل اعتماد برای پروژه هستیم."}]},{"word":"die Party","en":"party","ru":"вечеринка","vi":"bữa tiệc","fa":"حزب","examples":[{"de":"Am Samstag feiern wir eine große Party.","en":"On Saturday we're having a big party.","ru":"В субботу мы устраиваем большую вечеринку.","vi":"Chúng tôi sẽ có một bữa tiệc lớn vào thứ bảy.","fa":"ما شنبه یک جشن بزرگ داریم."},{"de":"Warst du auf der Party gestern?","en":"Were you at the party yesterday?","ru":"Ты был на вечеринке вчера?","vi":"Bạn có ở bữa tiệc ngày hôm qua không?","fa":"دیروز تو مهمونی بودی؟"}]},{"word":"der Pass","en":"passport","ru":"паспорт","vi":"hộ chiếu","fa":"پاسپورت","examples":[{"de":"Ich muss meinen Pass verlängern lassen.","en":"I need to get my passport renewed.","ru":"Мне нужно продлить паспорт.","vi":"Tôi cần gia hạn hộ chiếu của mình.","fa":"باید پاسپورتم را تمدید کنم"},{"de":"Bitte zeigen Sie mir Ihren Pass.","en":"Please show me your passport.","ru":"Пожалуйста, покажите мне ваш паспорт.","vi":"Vui lòng cho tôi xem hộ chiếu của bạn.","fa":"لطفا پاسپورت خود را به من نشان دهید."}]},{"word":"der Passagier","en":"passenger","ru":"пассажир","vi":"hành khách","fa":"مسافر","examples":[{"de":"Alle Passagiere müssen sich anschnallen.","en":"All passengers must fasten their seatbelts.","ru":"Все пассажиры должны пристегнуть ремни.","vi":"Tất cả hành khách phải thắt dây an toàn.","fa":"همه مسافران باید کمربند ایمنی خود را ببندند."},{"de":"Der Zug hatte heute nur wenige Passagiere.","en":"The train had only few passengers today.","ru":"В поезде сегодня было мало пассажиров.","vi":"Chuyến tàu hôm nay chỉ có vài hành khách.","fa":"قطار امروز فقط چند مسافر داشت."}]},{"word":"passen","en":"to fit; to suit","ru":"подходить; годиться","vi":"phù hợp","fa":"مناسب","examples":[{"de":"Die Hose passt mir nicht mehr.","en":"The trousers don't fit me anymore.","ru":"Брюки мне больше не подходят.","vi":"Chiếc quần không còn vừa với tôi nữa.","fa":"شلوار دیگه بهم نمیاد"},{"de":"Passt es dir, wenn wir uns am Freitag treffen?","en":"Does it suit you if we meet on Friday?","ru":"Тебе удобно, если мы встретимся в пятницу?","vi":"Sẽ ổn chứ nếu chúng ta gặp nhau vào thứ Sáu?","fa":"اگر جمعه همدیگر را ببینیم اشکالی ندارد؟"}]},{"word":"passieren","en":"to happen","ru":"случаться, происходить","vi":"xảy ra","fa":"اتفاق بیفتد","examples":[{"de":"Was ist gestern Abend passiert?","en":"What happened yesterday evening?","ru":"Что случилось вчера вечером?","vi":"Chuyện gì đã xảy ra tối qua?","fa":"دیشب چه اتفاقی افتاد؟"},{"de":"Bei dem Unfall ist zum Glück nichts Schlimmes passiert.","en":"Luckily nothing bad happened in the accident.","ru":"К счастью, во время аварии ничего плохого не произошло.","vi":"Rất may không có điều gì đáng tiếc xảy ra trong vụ tai nạn.","fa":"خوشبختانه اتفاق بدی در این تصادف رخ نداد."}]},{"word":"passiv","en":"passive","ru":"пассивный","vi":"thụ động","fa":"منفعل","examples":[{"de":"Er sitzt nur passiv da und hilft nicht mit.","en":"He just sits there passively and doesn't help.","ru":"Он просто пассивно сидит и не помогает.","vi":"Anh ta chỉ ngồi đó một cách thụ động và không giúp đỡ.","fa":"او فقط منفعلانه آنجا می نشیند و کمکی نمی کند."},{"de":"In der Diskussion war sie sehr passiv.","en":"She was very passive in the discussion.","ru":"В дискуссии она была очень пассивна.","vi":"Cô ấy rất thụ động trong cuộc thảo luận.","fa":"او در بحث بسیار منفعل بود."}]},{"word":"der Patient","en":"patient","ru":"пациент","vi":"bệnh nhân","fa":"بیمار","examples":[{"de":"Der Arzt untersucht den Patienten sehr gründlich.","en":"The doctor examines the patient very thoroughly.","ru":"Врач очень тщательно осматривает пациента.","vi":"Bác sĩ khám bệnh nhân rất cẩn thận.","fa":"پزشک بیمار را بسیار دقیق معاینه می کند."},{"de":"Im Wartezimmer sitzen viele Patienten.","en":"Many patients are sitting in the waiting room.","ru":"В приёмной сидит много пациентов.","vi":"Có rất nhiều bệnh nhân đang ngồi trong phòng chờ.","fa":"بیماران زیادی در اتاق انتظار نشسته اند."}]},{"word":"pauschal","en":"flat-rate; blanket (general, all-inclusive)","ru":"паушальный, общий (без учёта деталей)","vi":"tỷ giá cố định","fa":"نرخ ثابت","examples":[{"de":"Die Reise kostet pauschal 500 Euro pro Person.","en":"The trip costs a flat rate of 500 euros per person.","ru":"Поездка стоит паушально 500 евро с человека.","vi":"Chuyến đi có giá cố định là 500 euro mỗi người.","fa":"هزینه سفر برای هر نفر 500 یورو است."},{"de":"Man kann das nicht pauschal beantworten.","en":"You can't answer that in a blanket way.","ru":"На это нельзя ответить в общем виде.","vi":"Bạn không thể đưa ra một câu trả lời chung chung cho điều đó.","fa":"شما نمی توانید یک پاسخ کلی به آن بدهید."}]},{"word":"die Pause","en":"break, pause","ru":"перерыв, пауза","vi":"giờ nghỉ","fa":"استراحت","examples":[{"de":"In der Pause trinken wir einen Kaffee.","en":"During the break we drink a coffee.","ru":"На перерыве мы пьём кофе.","vi":"Chúng tôi uống cà phê trong giờ giải lao.","fa":"در زمان استراحت قهوه می نوشیم."},{"de":"Nach zwei Stunden Arbeit brauche ich eine Pause.","en":"After two hours of work I need a break.","ru":"После двух часов работы мне нужен перерыв.","vi":"Sau hai giờ làm việc, tôi cần nghỉ ngơi.","fa":"بعد از دو ساعت کار نیاز به استراحت دارم."}]},{"word":"das Pech","en":"bad luck","ru":"неудача, невезение","vi":"điều xui xẻo","fa":"بدشانسی","examples":[{"de":"So ein Pech, dass es heute regnet!","en":"What bad luck that it's raining today!","ru":"Какая неудача, что сегодня идёт дождь!","vi":"Thật xui xẻo vì hôm nay trời mưa!","fa":"آنقدر بدشانسی که امروز باران می بارد!"},{"de":"Er hatte Pech und verlor sein ganzes Geld.","en":"He had bad luck and lost all his money.","ru":"Ему не повезло, и он потерял все свои деньги.","vi":"Anh ta không may mắn và mất hết tiền.","fa":"او بدشانس بود و تمام پول خود را از دست داد."}]},{"word":"peinlich","en":"embarrassing","ru":"неловкий, постыдный","vi":"đáng xấu hổ","fa":"شرم آور","examples":[{"de":"Es war mir sehr peinlich, dass ich zu spät kam.","en":"It was very embarrassing for me that I arrived late.","ru":"Мне было очень неловко, что я опоздал.","vi":"Tôi rất xấu hổ vì đã đến muộn.","fa":"از اینکه دیر اومدم خیلی خجالت کشیدم."},{"de":"Das war eine peinliche Situation für alle.","en":"That was an embarrassing situation for everyone.","ru":"Это была неловкая ситуация для всех.","vi":"Đây là một tình huống đáng xấu hổ cho tất cả mọi người.","fa":"این وضعیت برای همه شرم آور بود."}]},{"word":"die Pension","en":"guesthouse; pension (retirement)","ru":"пансион; пенсия","vi":"nhà khách","fa":"مهمانخانه","examples":[{"de":"Wir übernachten in einer kleinen Pension am See.","en":"We are staying overnight in a small guesthouse by the lake.","ru":"Мы ночуем в маленьком пансионе у озера.","vi":"Chúng tôi qua đêm tại một nhà khách nhỏ bên hồ.","fa":"شب را در مهمانخانه کوچکی در کنار دریاچه می گذرانیم."},{"de":"Nach vierzig Arbeitsjahren bekommt sie eine gute Pension.","en":"After forty years of work she gets a good pension.","ru":"После сорока лет работы она получает хорошую пенсию.","vi":"Sau bốn mươi năm làm việc, cô nhận được một khoản lương hưu khá tốt.","fa":"بعد از چهل سال کار حقوق بازنشستگی خوبی می گیرد."}]},{"word":"der Pensionist","en":"pensioner, retiree","ru":"пенсионер","vi":"người về hưu","fa":"مستمری بگیر","examples":[{"de":"Viele Pensionisten machen morgens einen Spaziergang im Park.","en":"Many pensioners take a walk in the park in the morning.","ru":"Многие пенсионеры утром гуляют в парке.","vi":"Nhiều người về hưu đi dạo buổi sáng trong công viên.","fa":"بسیاری از بازنشستگان صبحگاهی در پارک قدم می زنند."},{"de":"Als Pensionist hat er endlich Zeit für sein Hobby.","en":"As a pensioner he finally has time for his hobby.","ru":"Как пенсионер, он наконец нашёл время для своего хобби.","vi":"Là một người hưu trí, cuối cùng anh cũng có thời gian cho sở thích của mình.","fa":"او به عنوان یک مستمری بگیر بالاخره برای سرگرمی خود وقت دارد."}]},{"word":"per","en":"by, via","ru":"посредством, через","vi":"mỗi","fa":"در هر","examples":[{"de":"Ich schicke dir die Fotos per E-Mail.","en":"I'll send you the photos by email.","ru":"Я пришлю тебе фотографии по электронной почте.","vi":"Tôi sẽ gửi cho bạn những bức ảnh qua email.","fa":"عکس ها رو برات ایمیل میکنم"},{"de":"Die Ware wird per Post geliefert.","en":"The goods are delivered by mail.","ru":"Товар доставляется по почте.","vi":"Hàng được giao qua đường bưu điện.","fa":"کالا از طریق پست تحویل داده می شود."}]},{"word":"perfekt","en":"perfect","ru":"идеальный, совершенный","vi":"hoàn hảo","fa":"کامل","examples":[{"de":"Ihre Präsentation war einfach perfekt.","en":"Her presentation was simply perfect.","ru":"Её презентация была просто идеальной.","vi":"Bài thuyết trình của bạn thật hoàn hảo.","fa":"ارائه شما فقط عالی بود."},{"de":"Niemand ist perfekt.","en":"Nobody is perfect.","ru":"Никто не идеален.","vi":"Không ai là hoàn hảo.","fa":"هیچکس کامل نیست"}]},{"word":"der Perron","en":"platform (railway)","ru":"платформа, перрон","vi":"nền tảng","fa":"پلت فرم","examples":[{"de":"Der Zug fährt auf Perron 3 ab.","en":"The train departs from platform 3.","ru":"Поезд отправляется с платформы 3.","vi":"Tàu khởi hành ở sân ga số 3.","fa":"قطار روی سکوی 3 حرکت می کند."},{"de":"Wir warten auf dem Perron auf unseren Zug.","en":"We are waiting on the platform for our train.","ru":"Мы ждём наш поезд на платформе.","vi":"Chúng tôi đợi chuyến tàu của mình trên sân ga.","fa":"روی سکو منتظر قطارمان هستیم."}]},{"word":"die Person","en":"person","ru":"человек, лицо","vi":"người đó","fa":"شخص","examples":[{"de":"An dem Tisch sitzen vier Personen.","en":"Four people are sitting at the table.","ru":"За столом сидят четыре человека.","vi":"Bốn người đang ngồi ở bàn.","fa":"چهار نفر پشت میز نشسته اند."},{"de":"Sie ist eine sehr freundliche Person.","en":"She is a very friendly person.","ru":"Она очень дружелюбный человек.","vi":"Cô ấy là một người rất thân thiện.","fa":"او فردی بسیار صمیمی است."}]},{"word":"das Personal","en":"staff, personnel","ru":"персонал","vi":"nhân viên","fa":"کارکنان","examples":[{"de":"Das Hotel sucht neues Personal für die Küche.","en":"The hotel is looking for new staff for the kitchen.","ru":"Отель ищет новый персонал для кухни.","vi":"Khách sạn đang tìm kiếm nhân viên mới cho nhà bếp.","fa":"هتل به دنبال کارکنان جدید برای آشپزخانه می باشد."},{"de":"Das Personal ist sehr freundlich und hilfsbereit.","en":"The staff is very friendly and helpful.","ru":"Персонал очень дружелюбный и готов помочь.","vi":"Các nhân viên rất thân thiện và hữu ích.","fa":"کارکنان بسیار دوستانه و مفید هستند."}]},{"word":"der Personenstand","en":"marital/civil status","ru":"семейное (гражданское) состояние","vi":"tình trạng dân sự","fa":"وضعیت مدنی","examples":[{"de":"Bitte geben Sie im Formular Ihren Personenstand an.","en":"Please state your marital status on the form.","ru":"Пожалуйста, укажите в анкете ваше семейное положение.","vi":"Vui lòng cho biết hộ tịch của bạn trong mẫu đơn.","fa":"لطفا وضعیت مدنی خود را در فرم ذکر کنید."},{"de":"Ihr Personenstand hat sich nach der Heirat geändert.","en":"Her civil status changed after the wedding.","ru":"Её гражданское состояние изменилось после свадьбы.","vi":"Hộ tịch của bạn đã thay đổi sau khi kết hôn.","fa":"وضعیت مدنی شما بعد از ازدواج تغییر کرد."}]},{"word":"die Pfanne","en":"frying pan","ru":"сковорода","vi":"cái chảo","fa":"تابه","examples":[{"de":"Ich brate das Ei in der Pfanne.","en":"I fry the egg in the pan.","ru":"Я жарю яйцо на сковороде.","vi":"Tôi chiên trứng trong chảo.","fa":"تخم مرغ را در تابه سرخ می کنم."},{"de":"Die Pfanne ist noch heiß, pass auf!","en":"The pan is still hot, be careful!","ru":"Сковорода ещё горячая, будь осторожен!","vi":"Chảo vẫn còn nóng, hãy cẩn thận!","fa":"تابه هنوز داغ است، مراقب باشید!"}]},{"word":"der Pfeffer","en":"pepper","ru":"перец","vi":"hạt tiêu","fa":"فلفل","examples":[{"de":"Gib etwas Salz und Pfeffer an die Suppe.","en":"Add some salt and pepper to the soup.","ru":"Добавь немного соли и перца в суп.","vi":"Thêm một ít muối và hạt tiêu vào súp.","fa":"مقداری نمک و فلفل به سوپ اضافه کنید."},{"de":"Der Pfeffer steht neben dem Salz auf dem Tisch.","en":"The pepper is next to the salt on the table.","ru":"Перец стоит на столе рядом с солью.","vi":"Hạt tiêu ở trên bàn cạnh muối.","fa":"فلفل روی میز کنار نمک است."}]},{"word":"pflanzen","en":"to plant","ru":"сажать (растения)","vi":"thực vật","fa":"گیاهان","examples":[{"de":"Im Frühling pflanzen wir Blumen im Garten.","en":"In spring we plant flowers in the garden.","ru":"Весной мы сажаем цветы в саду.","vi":"Vào mùa xuân, chúng tôi trồng hoa trong vườn.","fa":"در بهار در باغ گل می کاریم."},{"de":"Mein Opa hat diesen Baum vor fünfzig Jahren gepflanzt.","en":"My grandpa planted this tree fifty years ago.","ru":"Мой дедушка посадил это дерево пятьдесят лет назад.","vi":"Ông tôi đã trồng cây này cách đây năm mươi năm.","fa":"پدربزرگ من پنجاه سال پیش این درخت را کاشت."}]},{"word":"das Pflaster","en":"plaster, adhesive bandage","ru":"пластырь","vi":"vỉa hè","fa":"پیاده رو","examples":[{"de":"Ich klebe ein Pflaster auf die kleine Wunde.","en":"I put a plaster on the small wound.","ru":"Я наклеиваю пластырь на маленькую рану.","vi":"Tôi dán một miếng thạch cao lên vết thương nhỏ.","fa":"روی زخم کوچک گچ گذاشتم."},{"de":"Hast du ein Pflaster für meinen Finger?","en":"Do you have a plaster for my finger?","ru":"У тебя есть пластырь для моего пальца?","vi":"Bạn có miếng dán cho ngón tay của tôi không?","fa":"برای انگشت من گچ داری؟"}]},{"word":"die Pflaume","en":"plum","ru":"слива","vi":"quả mận","fa":"آلو","examples":[{"de":"Im Garten wachsen süße Pflaumen.","en":"Sweet plums grow in the garden.","ru":"В саду растут сладкие сливы.","vi":"Mận ngọt mọc trong vườn.","fa":"آلوهای شیرین در باغ می رویند."},{"de":"Sie backt einen Kuchen mit Pflaumen.","en":"She is baking a cake with plums.","ru":"Она печёт пирог со сливами.","vi":"Cô ấy nướng một chiếc bánh với mận.","fa":"او یک کیک با آلو می پزد."}]},{"word":"pflegen","en":"to take care of, to nurse","ru":"ухаживать, заботиться","vi":"duy trì","fa":"حفظ کند","examples":[{"de":"Sie pflegt ihre kranke Mutter zu Hause.","en":"She takes care of her sick mother at home.","ru":"Она ухаживает за своей больной матерью дома.","vi":"Cô ấy chăm sóc mẹ ốm ở nhà.","fa":"او در خانه از مادر بیمارش مراقبت می کند."},{"de":"Man muss die Pflanzen regelmäßig pflegen.","en":"You have to take care of the plants regularly.","ru":"За растениями нужно регулярно ухаживать.","vi":"Bạn phải chăm sóc cây thường xuyên.","fa":"شما باید به طور منظم از گیاهان مراقبت کنید."}]},{"word":"die Pflicht","en":"duty, obligation","ru":"долг, обязанность","vi":"nhiệm vụ","fa":"وظیفه","examples":[{"de":"Es ist meine Pflicht, dir zu helfen.","en":"It is my duty to help you.","ru":"Это мой долг — помочь тебе.","vi":"Nhiệm vụ của tôi là giúp đỡ bạn.","fa":"این وظیفه من است که به شما کمک کنم."},{"de":"Pünktlichkeit gehört zu seinen Pflichten als Angestellter.","en":"Punctuality is one of his duties as an employee.","ru":"Пунктуальность — одна из его обязанностей как сотрудника.","vi":"Đúng giờ là một trong những nhiệm vụ của anh ấy với tư cách là một nhân viên.","fa":"وقت شناسی یکی از وظایف او به عنوان یک کارمند است."}]},{"word":"das Picknick","en":"picnic","ru":"пикник","vi":"buổi dã ngoại","fa":"پیک نیک","examples":[{"de":"Am Sonntag machen wir ein Picknick im Park.","en":"On Sunday we're having a picnic in the park.","ru":"В воскресенье мы устраиваем пикник в парке.","vi":"Vào chủ nhật chúng tôi đi dã ngoại ở công viên.","fa":"یکشنبه یک پیک نیک در پارک داریم."},{"de":"Für das Picknick packen wir Brot, Käse und Obst ein.","en":"For the picnic we pack bread, cheese and fruit.","ru":"Для пикника мы берём хлеб, сыр и фрукты.","vi":"Chúng tôi gói bánh mì, phô mai và trái cây cho chuyến dã ngoại.","fa":"نان، پنیر و میوه را برای پیک نیک بسته بندی می کنیم."}]},{"word":"der Pilz","en":"mushroom","ru":"гриб","vi":"nấm","fa":"قارچ","examples":[{"de":"Im Wald haben wir viele Pilze gefunden.","en":"We found many mushrooms in the forest.","ru":"В лесу мы нашли много грибов.","vi":"Chúng tôi tìm thấy rất nhiều nấm trong rừng.","fa":"ما قارچ های زیادی در جنگل پیدا کردیم."},{"de":"Man sollte nur Pilze essen, die man kennt.","en":"You should only eat mushrooms that you know.","ru":"Есть следует только те грибы, которые знаешь.","vi":"Bạn chỉ nên ăn nấm mà bạn biết.","fa":"فقط باید قارچ هایی بخورید که می شناسید."}]},{"word":"die Pizza","en":"pizza","ru":"пицца","vi":"bánh pizza","fa":"پیتزا","examples":[{"de":"Wir bestellen heute Abend eine Pizza.","en":"We are ordering a pizza tonight.","ru":"Сегодня вечером мы заказываем пиццу.","vi":"Chúng tôi sẽ đặt pizza tối nay.","fa":"ما امشب پیتزا سفارش می دهیم."},{"de":"Die Pizza mit Käse und Tomaten schmeckt mir am besten.","en":"I like the pizza with cheese and tomatoes best.","ru":"Мне больше всего нравится пицца с сыром и помидорами.","vi":"Tôi thích pizza với phô mai và cà chua nhất.","fa":"من پیتزا را با پنیر و گوجه فرنگی بیشتر دوست دارم."}]},{"word":"das Plakat","en":"poster","ru":"плакат, афиша","vi":"áp phích","fa":"پوستر","examples":[{"de":"An der Wand hängt ein großes Plakat vom Konzert.","en":"A big concert poster hangs on the wall.","ru":"На стене висит большой плакат с концерта.","vi":"Có một tấm áp phích lớn về buổi hòa nhạc treo trên tường.","fa":"یک پوستر بزرگ از کنسرت روی دیوار آویزان شده است."},{"de":"Wir haben Plakate für unser Schulfest gemacht.","en":"We made posters for our school festival.","ru":"Мы сделали плакаты для нашего школьного праздника.","vi":"Chúng tôi làm áp phích cho lễ hội trường của chúng tôi.","fa":"ما برای جشنواره مدرسه خود پوستر درست کردیم."}]},{"word":"planen","en":"to plan","ru":"планировать","vi":"kế hoạch","fa":"برنامه ریزی کنید","examples":[{"de":"Wir planen eine Reise nach Italien.","en":"We are planning a trip to Italy.","ru":"Мы планируем поездку в Италию.","vi":"Chúng tôi đang lên kế hoạch cho một chuyến đi đến Ý.","fa":"ما قصد سفر به ایتالیا را داریم."},{"de":"Er plant seinen Tag immer genau.","en":"He always plans his day precisely.","ru":"Он всегда точно планирует свой день.","vi":"Anh ấy luôn lên kế hoạch cho ngày của mình một cách cẩn thận.","fa":"او همیشه روز خود را با دقت برنامه ریزی می کند."}]},{"word":"das Plastik","en":"plastic","ru":"пластик, пластмасса","vi":"nhựa","fa":"پلاستیک","examples":[{"de":"Die Flasche ist aus Plastik.","en":"The bottle is made of plastic.","ru":"Бутылка сделана из пластика.","vi":"Chai được làm bằng nhựa.","fa":"بطری از پلاستیک ساخته شده است."},{"de":"Wir sollten weniger Plastik verwenden.","en":"We should use less plastic.","ru":"Нам следует использовать меньше пластика.","vi":"Chúng ta nên sử dụng ít nhựa hơn.","fa":"باید از پلاستیک کمتر استفاده کنیم."}]},{"word":"der Platz","en":"place; square; seat","ru":"место; площадь","vi":"nơi","fa":"مکان","examples":[{"de":"Ist dieser Platz noch frei?","en":"Is this seat still free?","ru":"Это место ещё свободно?","vi":"Chỗ này còn trống không?","fa":"آیا این فضا هنوز موجود است؟"},{"de":"Auf dem Marktplatz gibt es heute viele Stände.","en":"There are many stalls on the market square today.","ru":"Сегодня на рыночной площади много ларьков.","vi":"Quảng trường chợ ngày nay có rất nhiều quầy hàng.","fa":"امروزه در میدان بازار غرفه های زیادی وجود دارد."}]},{"word":"plötzlich","en":"suddenly","ru":"внезапно, вдруг","vi":"đột nhiên","fa":"به طور ناگهانی","examples":[{"de":"Plötzlich begann es stark zu regnen.","en":"Suddenly it started to rain heavily.","ru":"Внезапно начался сильный дождь.","vi":"Đột nhiên trời bắt đầu mưa to.","fa":"ناگهان باران شدیدی شروع به باریدن کرد."},{"de":"Er stand plötzlich vor der Tür.","en":"He suddenly stood at the door.","ru":"Он вдруг оказался у двери.","vi":"Anh chợt đứng trước cửa.","fa":"ناگهان جلوی در ایستاد."}]},{"word":"die Politik","en":"politics, policy","ru":"политика","vi":"chính trị","fa":"سیاست","examples":[{"de":"Sie interessiert sich sehr für Politik.","en":"She is very interested in politics.","ru":"Она очень интересуется политикой.","vi":"Cô ấy rất quan tâm đến chính trị.","fa":"او علاقه زیادی به سیاست دارد."},{"de":"Die Politik der Regierung wird viel diskutiert.","en":"The government's policy is much discussed.","ru":"Политику правительства широко обсуждают.","vi":"Các chính sách của chính phủ được thảo luận rộng rãi.","fa":"سیاست های دولت به طور گسترده مورد بحث قرار می گیرد."}]},{"word":"die Polizei","en":"police","ru":"полиция","vi":"cảnh sát","fa":"پلیس","examples":[{"de":"Wir haben den Unfall der Polizei gemeldet.","en":"We reported the accident to the police.","ru":"Мы сообщили о происшествии в полицию.","vi":"Chúng tôi đã báo cáo vụ tai nạn cho cảnh sát.","fa":"تصادف را به پلیس اطلاع دادیم."},{"de":"Die Polizei kontrolliert die Ausweise.","en":"The police check the IDs.","ru":"Полиция проверяет документы.","vi":"Cảnh sát kiểm tra giấy tờ tùy thân.","fa":"پلیس شناسنامه ها را بررسی می کند."}]},{"word":"die Pommes frites","en":"French fries","ru":"картофель фри","vi":"khoai tây chiên","fa":"سیب زمینی سرخ کرده","examples":[{"de":"Zum Mittagessen gibt es Pommes frites mit Ketchup.","en":"For lunch there are French fries with ketchup.","ru":"На обед картофель фри с кетчупом.","vi":"Bữa trưa chúng tôi dùng khoai tây chiên với sốt cà chua.","fa":"برای ناهار سیب زمینی سرخ کرده با سس کچاپ می خوریم."},{"de":"Die Kinder essen gern Pommes frites.","en":"The children like to eat French fries.","ru":"Дети любят есть картофель фри.","vi":"Bọn trẻ thích ăn khoai tây chiên kiểu Pháp.","fa":"بچه ها دوست دارند سیب زمینی سرخ کرده بخورند."}]},{"word":"populär","en":"popular","ru":"популярный","vi":"phổ biến","fa":"محبوب","examples":[{"de":"Dieser Sänger ist bei Jugendlichen sehr populär.","en":"This singer is very popular with young people.","ru":"Этот певец очень популярен среди молодёжи.","vi":"Ca sĩ này rất được giới trẻ yêu thích.","fa":"این خواننده محبوبیت زیادی در بین جوانان دارد."},{"de":"Fußball ist der populärste Sport in Deutschland.","en":"Football is the most popular sport in Germany.","ru":"Футбол — самый популярный вид спорта в Германии.","vi":"Bóng đá là môn thể thao phổ biến nhất ở Đức.","fa":"فوتبال محبوب ترین ورزش در آلمان است."}]},{"word":"das Portemonnaie/Portmonee","en":"wallet, purse","ru":"кошелёк","vi":"cái ví/ví","fa":"کیف پول / کیف پول","examples":[{"de":"Ich habe mein Portemonnaie zu Hause vergessen.","en":"I forgot my wallet at home.","ru":"Я забыл свой кошелёк дома.","vi":"Tôi quên ví ở nhà.","fa":"کیف پولم را در خانه فراموش کردم."},{"de":"In meinem Portmonee habe ich nur wenig Bargeld.","en":"I only have a little cash in my wallet.","ru":"В моём кошельке совсем мало наличных.","vi":"Tôi chỉ có một ít tiền mặt trong ví.","fa":"فقط کمی پول نقد در کیفم دارم."}]},{"word":"die Portion","en":"portion, serving","ru":"порция","vi":"phần","fa":"بخش","examples":[{"de":"Ich hätte gern eine Portion Pommes.","en":"I would like a portion of fries.","ru":"Я хотел бы одну порцию картофеля фри.","vi":"Tôi muốn một phần khoai tây chiên.","fa":"من یک قسمت سیب زمینی سرخ کرده می خواهم."},{"de":"Die Portionen in diesem Restaurant sind sehr groß.","en":"The portions in this restaurant are very large.","ru":"Порции в этом ресторане очень большие.","vi":"Các phần trong nhà hàng này rất lớn.","fa":"وعده های غذایی این رستوران بسیار زیاد است."}]},{"word":"positiv","en":"positive","ru":"положительный","vi":"tích cực","fa":"مثبت","examples":[{"de":"Sie denkt immer positiv, auch in schweren Zeiten.","en":"She always thinks positively, even in hard times.","ru":"Она всегда мыслит позитивно, даже в трудные времена.","vi":"Cô luôn suy nghĩ tích cực, ngay cả trong những thời điểm khó khăn.","fa":"او همیشه مثبت فکر می کند، حتی در شرایط سخت."},{"de":"Der Test war positiv.","en":"The test was positive.","ru":"Тест оказался положительным.","vi":"Thử nghiệm cho kết quả dương tính.","fa":"آزمایش مثبت بود."}]},{"word":"die Post","en":"post office; mail","ru":"почта","vi":"bưu điện","fa":"اداره پست","examples":[{"de":"Ich gehe zur Post, um ein Paket abzuholen.","en":"I am going to the post office to pick up a package.","ru":"Я иду на почту забрать посылку.","vi":"Tôi đang đến bưu điện để lấy một gói hàng.","fa":"من میرم اداره پست تا یه بسته تحویل بگیرم."},{"de":"Heute habe ich viel Post bekommen.","en":"Today I got a lot of mail.","ru":"Сегодня я получил много почты.","vi":"Hôm nay tôi nhận được rất nhiều thư.","fa":"امروز نامه های زیادی دریافت کردم."}]},{"word":"der Pöstler","en":"postman, mail carrier","ru":"почтальон","vi":"người đưa thư","fa":"پستچی","examples":[{"de":"Der Pöstler bringt jeden Morgen die Briefe.","en":"The postman brings the letters every morning.","ru":"Почтальон приносит письма каждое утро.","vi":"Người đưa thư mang thư đến mỗi sáng.","fa":"پستچی هر روز صبح نامه ها را می آورد."},{"de":"Ich habe den Pöstler heute vor dem Haus getroffen.","en":"I met the postman in front of the house today.","ru":"Сегодня я встретил почтальона перед домом.","vi":"Hôm nay tôi gặp người đưa thư trước nhà.","fa":"امروز جلوی در خانه با پستچی ملاقات کردم."}]},{"word":"das Poulet","en":"chicken (meat)","ru":"курица (мясо)","vi":"con gà","fa":"مرغ","examples":[{"de":"Zum Abendessen gibt es Poulet mit Reis.","en":"For dinner there is chicken with rice.","ru":"На ужин курица с рисом.","vi":"Bữa tối có cơm gà.","fa":"برای شام مرغ با برنج وجود دارد."},{"de":"Sie kauft frisches Poulet auf dem Markt.","en":"She buys fresh chicken at the market.","ru":"Она покупает свежую курицу на рынке.","vi":"Cô ấy mua gà tươi ở chợ.","fa":"او مرغ تازه را از بازار می خرد."}]},{"word":"das Praktikum","en":"internship","ru":"стажировка, практика","vi":"thực tập","fa":"کارآموزی","examples":[{"de":"Ich mache im Sommer ein Praktikum bei einer Bank.","en":"I am doing an internship at a bank this summer.","ru":"Летом я прохожу стажировку в банке.","vi":"Tôi đang thực tập tại một ngân hàng vào mùa hè này.","fa":"تابستان امسال در یک بانک کارآموزی می کنم."},{"de":"Das Praktikum dauert drei Monate.","en":"The internship lasts three months.","ru":"Стажировка длится три месяца.","vi":"Thời gian thực tập kéo dài ba tháng.","fa":"دوره کارآموزی سه ماه به طول می انجامد."}]},{"word":"praktisch","en":"practical","ru":"практичный, удобный","vi":"thiết thực","fa":"عملی","examples":[{"de":"Diese Tasche ist sehr praktisch für die Reise.","en":"This bag is very practical for the trip.","ru":"Эта сумка очень удобна для поездки.","vi":"Chiếc túi này rất thiết thực cho việc đi du lịch.","fa":"این کیف برای مسافرت بسیار کاربردی است."},{"de":"Er löst Probleme immer praktisch und schnell.","en":"He always solves problems practically and quickly.","ru":"Он всегда решает проблемы практично и быстро.","vi":"Anh ấy luôn giải quyết vấn đề một cách thực tế và nhanh chóng.","fa":"او همیشه مشکلات را به صورت عملی و سریع حل می کند."}]},{"word":"präsentieren","en":"to present","ru":"представлять, презентовать","vi":"hiện tại","fa":"حاضر","examples":[{"de":"Sie präsentiert ihr Projekt vor der ganzen Klasse.","en":"She presents her project to the whole class.","ru":"Она представляет свой проект перед всем классом.","vi":"Cô trình bày dự án của mình cho cả lớp.","fa":"او پروژه خود را به کل کلاس ارائه می دهد."},{"de":"Wir müssen unsere Ergebnisse morgen präsentieren.","en":"We have to present our results tomorrow.","ru":"Завтра нам нужно представить наши результаты.","vi":"Chúng ta phải trình bày kết quả vào ngày mai.","fa":"ما باید فردا نتایج خود را ارائه دهیم."}]},{"word":"die Praxis","en":"practice; doctor's office","ru":"практика; врачебный кабинет","vi":"thực hành","fa":"تمرین","examples":[{"de":"In der Praxis ist es oft anders als in der Theorie.","en":"In practice it is often different than in theory.","ru":"На практике часто всё иначе, чем в теории.","vi":"Trong thực tế nó thường khác so với lý thuyết.","fa":"در عمل اغلب با تئوری متفاوت است."},{"de":"Der Arzt hat seine Praxis in der Stadtmitte.","en":"The doctor has his practice in the city center.","ru":"У врача кабинет в центре города.","vi":"Bác sĩ có phòng khám ở trung tâm thành phố.","fa":"دکتر مطب خود را در مرکز شهر دارد."}]},{"word":"der Preis","en":"price; prize","ru":"цена; приз","vi":"giá cả","fa":"قیمت","examples":[{"de":"Der Preis für das Buch ist sehr hoch.","en":"The price of the book is very high.","ru":"Цена этой книги очень высока.","vi":"Giá sách rất cao.","fa":"قیمت کتاب بسیار بالاست."},{"de":"Sie hat den ersten Preis beim Wettbewerb gewonnen.","en":"She won first prize in the competition.","ru":"Она выиграла первый приз в конкурсе.","vi":"Cô đã giành giải nhất trong cuộc thi.","fa":"او در این مسابقه برنده جایزه اول شد."}]},{"word":"die Presse","en":"the press (media)","ru":"пресса (СМИ)","vi":"báo chí","fa":"مطبوعات","examples":[{"de":"Die Presse berichtet heute über das Fußballspiel.","en":"The press reports on the football match today.","ru":"Пресса сегодня сообщает о футбольном матче.","vi":"Báo chí đang đưa tin về trận đấu bóng đá ngày hôm nay.","fa":"مطبوعات از بازی فوتبال امروز خبر می دهند."},{"de":"Viele Journalisten der Presse waren bei der Pressekonferenz.","en":"Many journalists from the press were at the press conference.","ru":"Много журналистов из прессы было на пресс-конференции.","vi":"Nhiều phóng viên báo chí có mặt tại buổi họp báo.","fa":"بسیاری از خبرنگاران مطبوعاتی در این نشست خبری حضور داشتند."}]},{"word":"prima","en":"great, excellent","ru":"отлично, здорово","vi":"tuyệt vời","fa":"عالی","examples":[{"de":"Das hast du prima gemacht!","en":"You did that great!","ru":"Ты отлично справился!","vi":"Bạn đã làm rất tốt!","fa":"عالی کار کردی"},{"de":"Das Wetter heute ist einfach prima.","en":"The weather today is simply excellent.","ru":"Погода сегодня просто отличная.","vi":"Thời tiết hôm nay thật tuyệt vời.","fa":"هوا امروز فقط عالیه"}]},{"word":"privat","en":"private","ru":"частный, личный","vi":"riêng tư","fa":"خصوصی","examples":[{"de":"Das ist eine private Angelegenheit.","en":"That is a private matter.","ru":"Это личное дело.","vi":"Đây là một vấn đề riêng tư.","fa":"این یک موضوع خصوصی است."},{"de":"Er wohnt in einem privaten Haus außerhalb der Stadt.","en":"He lives in a private house outside the city.","ru":"Он живёт в частном доме за городом.","vi":"Anh sống ở một ngôi nhà riêng ở ngoại ô thành phố.","fa":"او در یک خانه شخصی خارج از شهر زندگی می کند."}]},{"word":"pro","en":"per","ru":"за, на (каждый)","vi":"mỗi","fa":"در هر","examples":[{"de":"Das Zimmer kostet 80 Euro pro Nacht.","en":"The room costs 80 euros per night.","ru":"Номер стоит 80 евро за ночь.","vi":"Phòng có giá 80 euro mỗi đêm.","fa":"هزینه اتاق برای هر شب 80 یورو است."},{"de":"Wir treffen uns einmal pro Woche.","en":"We meet once per week.","ru":"Мы встречаемся раз в неделю.","vi":"Chúng tôi gặp nhau mỗi tuần một lần.","fa":"هفته ای یک بار همدیگر را ملاقات می کنیم."}]},{"word":"probieren","en":"to try, to taste","ru":"пробовать","vi":"thử","fa":"سعی کنید","examples":[{"de":"Möchtest du meinen Kuchen probieren?","en":"Would you like to try my cake?","ru":"Хочешь попробовать мой пирог?","vi":"Bạn có muốn thử bánh của tôi không?","fa":"دوست داری کیک منو امتحان کنی؟"},{"de":"Ich probiere gern neue Rezepte aus.","en":"I like to try out new recipes.","ru":"Я люблю пробовать новые рецепты.","vi":"Tôi thích thử công thức nấu ăn mới.","fa":"من دوست دارم دستور العمل های جدید را امتحان کنم."}]},{"word":"das Problem","en":"problem","ru":"проблема","vi":"vấn đề","fa":"مشکل","examples":[{"de":"Wir haben ein kleines Problem mit dem Auto.","en":"We have a small problem with the car.","ru":"У нас небольшая проблема с машиной.","vi":"Chúng tôi có một chút vấn đề với chiếc xe.","fa":"ما با ماشین کمی مشکل داریم."},{"de":"Kein Problem, ich helfe dir gern.","en":"No problem, I'm happy to help you.","ru":"Не проблема, я с радостью помогу тебе.","vi":"Không có vấn đề gì, tôi rất sẵn lòng trợ giúp bạn.","fa":"مشکلی نیست، خوشحال می شوم به شما کمک کنم."}]},{"word":"produzieren","en":"to produce","ru":"производить","vi":"sản xuất","fa":"تولید کنند","examples":[{"de":"Die Fabrik produziert Autos für den ganzen Kontinent.","en":"The factory produces cars for the whole continent.","ru":"Фабрика производит автомобили для всего континента.","vi":"Nhà máy sản xuất ô tô cho toàn lục địa.","fa":"این کارخانه برای کل قاره خودرو تولید می کند."},{"de":"Dieser Bauer produziert biologisches Gemüse.","en":"This farmer produces organic vegetables.","ru":"Этот фермер производит органические овощи.","vi":"Nông dân này sản xuất rau hữu cơ.","fa":"این کشاورز سبزیجات ارگانیک تولید می کند."}]},{"word":"der Professor","en":"professor","ru":"профессор","vi":"giáo sư","fa":"پروفسور","examples":[{"de":"Der Professor hält heute eine Vorlesung über Geschichte.","en":"The professor is giving a lecture on history today.","ru":"Профессор сегодня читает лекцию по истории.","vi":"Hôm nay giáo sư sẽ giảng về lịch sử.","fa":"استاد امروز در مورد تاریخ سخنرانی می کند."},{"de":"Ich habe eine Frage an den Professor.","en":"I have a question for the professor.","ru":"У меня есть вопрос к профессору.","vi":"Tôi có một câu hỏi cho giáo sư.","fa":"من یک سوال از استاد دارم."}]},{"word":"der Profi","en":"professional, pro","ru":"профессионал","vi":"chuyên nghiệp","fa":"حرفه ای","examples":[{"de":"Er spielt Tennis wie ein echter Profi.","en":"He plays tennis like a real professional.","ru":"Он играет в теннис как настоящий профессионал.","vi":"Anh ấy chơi quần vợt như một tay vợt chuyên nghiệp thực thụ.","fa":"او مانند یک حرفه ای واقعی تنیس بازی می کند."},{"de":"Für diese Arbeit brauchen wir einen Profi.","en":"For this job we need a professional.","ru":"Для этой работы нам нужен профессионал.","vi":"Chúng tôi cần một chuyên gia cho công việc này.","fa":"به یک متخصص برای این کار نیازمندیم."}]},{"word":"die Profisportlerin","en":"professional female athlete","ru":"профессиональная спортсменка","vi":"vận động viên chuyên nghiệp","fa":"ورزشکار حرفه ای","examples":[{"de":"Sie ist eine bekannte Profisportlerin aus Deutschland.","en":"She is a well-known professional athlete from Germany.","ru":"Она известная профессиональная спортсменка из Германии.","vi":"Cô là một vận động viên chuyên nghiệp nổi tiếng đến từ Đức.","fa":"او یک ورزشکار حرفه ای شناخته شده از آلمان است."},{"de":"Als Profisportlerin trainiert sie jeden Tag mehrere Stunden.","en":"As a professional athlete she trains for several hours every day.","ru":"Как профессиональная спортсменка, она тренируется по несколько часов каждый день.","vi":"Là một vận động viên chuyên nghiệp, cô tập luyện vài giờ mỗi ngày.","fa":"او به عنوان یک ورزشکار حرفه ای، هر روز چندین ساعت تمرین می کند."}]},{"word":"das Programm","en":"program","ru":"программа","vi":"chương trình","fa":"برنامه","examples":[{"de":"Das Programm für den Abend beginnt um acht Uhr.","en":"The program for the evening starts at eight o'clock.","ru":"Программа вечера начинается в восемь часов.","vi":"Chương trình buổi tối bắt đầu lúc tám giờ.","fa":"برنامه عصر از ساعت هشت شروع می شود."},{"de":"Ich habe ein neues Programm auf meinem Computer installiert.","en":"I installed a new program on my computer.","ru":"Я установил новую программу на свой компьютер.","vi":"Tôi đã cài đặt một chương trình mới trên máy tính của tôi.","fa":"من یک برنامه جدید روی کامپیوترم نصب کردم."}]},{"word":"das Projekt","en":"project","ru":"проект","vi":"dự án","fa":"پروژه","examples":[{"de":"Wir arbeiten zusammen an einem neuen Projekt.","en":"We are working together on a new project.","ru":"Мы вместе работаем над новым проектом.","vi":"Chúng tôi đang cùng nhau thực hiện một dự án mới.","fa":"ما با هم روی یک پروژه جدید کار می کنیم."},{"de":"Das Projekt soll bis Ende des Jahres fertig sein.","en":"The project is supposed to be finished by the end of the year.","ru":"Проект должен быть завершён до конца года.","vi":"Dự kiến ​​dự án sẽ hoàn thành vào cuối năm nay.","fa":"پیش بینی می شود این پروژه تا پایان سال به اتمام برسد."}]},{"word":"der Prospekt","en":"brochure, prospectus","ru":"проспект, брошюра","vi":"bản cáo bạch","fa":"دفترچه","examples":[{"de":"Im Reisebüro liegen viele bunte Prospekte.","en":"There are many colorful brochures in the travel agency.","ru":"В турагентстве лежит много красочных брошюр.","vi":"Có rất nhiều tài liệu quảng cáo đầy màu sắc trong công ty du lịch.","fa":"بروشورهای رنگارنگ زیادی در آژانس مسافرتی وجود دارد."},{"de":"Ich habe einen Prospekt über die neuen Möbel mitgenommen.","en":"I took a brochure about the new furniture.","ru":"Я взял брошюру о новой мебели.","vi":"Tôi mang theo một tập tài liệu quảng cáo về đồ nội thất mới.","fa":"یک بروشور در مورد مبلمان جدید با خودم بردم."}]},{"word":"Prost","en":"cheers!","ru":"будем здоровы!, ваше здоровье!","vi":"Chúc mừng","fa":"به سلامتی","examples":[{"de":"Prost! Auf deine Gesundheit!","en":"Cheers! To your health!","ru":"Будем здоровы! За твоё здоровье!","vi":"Chúc mừng! Vì sức khỏe của bạn!","fa":"به سلامتی به سلامتی شما!"},{"de":"Wir heben die Gläser und rufen: Prost!","en":"We raise our glasses and shout: Cheers!","ru":"Мы поднимаем бокалы и кричим: Будем здоровы!","vi":"Chúng tôi nâng ly và hét lên: Chúc mừng!","fa":"عینکمان را بلند می کنیم و فریاد می زنیم: به سلامتی!"}]},{"word":"protestieren","en":"to protest","ru":"протестовать","vi":"phản đối","fa":"اعتراض","examples":[{"de":"Die Studenten protestieren gegen die neuen Regeln.","en":"The students are protesting against the new rules.","ru":"Студенты протестуют против новых правил.","vi":"Các sinh viên đang phản đối các quy định mới.","fa":"اعتراض دانشجویان به قوانین جدید"},{"de":"Er protestierte laut gegen die Entscheidung.","en":"He protested loudly against the decision.","ru":"Он громко протестовал против этого решения.","vi":"Anh lớn tiếng phản đối quyết định này.","fa":"او با صدای بلند به این تصمیم اعتراض کرد."}]},{"word":"der Prozess","en":"process; trial (legal)","ru":"процесс; судебный процесс","vi":"quá trình","fa":"روند","examples":[{"de":"Der Prozess des Lernens dauert das ganze Leben.","en":"The process of learning lasts a whole lifetime.","ru":"Процесс обучения длится всю жизнь.","vi":"Quá trình học tập kéo dài suốt cuộc đời.","fa":"فرآیند یادگیری در طول زندگی ادامه دارد."},{"de":"Der Prozess gegen den Mann beginnt nächste Woche.","en":"The trial against the man begins next week.","ru":"Судебный процесс над этим человеком начинается на следующей неделе.","vi":"Phiên tòa xét xử người đàn ông này sẽ bắt đầu vào tuần tới.","fa":"محاکمه این مرد هفته آینده آغاز می شود."}]},{"word":"prüfen","en":"to check, to examine","ru":"проверять","vi":"kiểm tra","fa":"بررسی کنید","examples":[{"de":"Der Lehrer prüft die Hausaufgaben der Schüler.","en":"The teacher checks the students' homework.","ru":"Учитель проверяет домашние задания учеников.","vi":"Giáo viên kiểm tra bài tập về nhà của học sinh.","fa":"معلم تکالیف دانش آموزان را بررسی می کند."},{"de":"Bitte prüfen Sie Ihre Angaben, bevor Sie das Formular abschicken.","en":"Please check your details before you send the form.","ru":"Пожалуйста, проверьте свои данные, прежде чем отправить форму.","vi":"Vui lòng kiểm tra thông tin chi tiết của bạn trước khi gửi biểu mẫu.","fa":"لطفا قبل از ارسال فرم مشخصات خود را بررسی کنید."}]},{"word":"die Prüfung","en":"exam; test","ru":"экзамен; проверка","vi":"kỳ thi","fa":"امتحان","examples":[{"de":"Ich habe die Prüfung mit einer guten Note bestanden.","en":"I passed the exam with a good grade.","ru":"Я сдал экзамен на хорошую оценку.","vi":"Tôi đã vượt qua kỳ thi với điểm cao.","fa":"من در امتحان با نمره خوب قبول شدم."},{"de":"Vor der Prüfung war sie sehr nervös.","en":"Before the exam she was very nervous.","ru":"Перед экзаменом она сильно нервничала.","vi":"Cô ấy rất lo lắng trước kỳ thi.","fa":"قبل از امتحان خیلی عصبی بود."}]},{"word":"das Publikum","en":"audience","ru":"публика, зрители","vi":"khán giả","fa":"مخاطب","examples":[{"de":"Das Publikum applaudierte lange nach dem Konzert.","en":"The audience applauded for a long time after the concert.","ru":"Публика долго аплодировала после концерта.","vi":"Khán giả vỗ tay rất lâu sau buổi hòa nhạc.","fa":"تماشاگران مدت ها بعد از کنسرت کف زدند."},{"de":"Im Theater saß ein großes Publikum.","en":"A large audience sat in the theater.","ru":"В театре сидела большая публика.","vi":"Có một lượng lớn khán giả trong rạp.","fa":"تماشاگران زیادی در تئاتر حضور داشتند."}]},{"word":"der Pullover","en":"sweater, pullover","ru":"свитер, пуловер","vi":"chiếc áo len","fa":"ژاکت","examples":[{"de":"Im Winter trage ich einen warmen Pullover.","en":"In winter I wear a warm sweater.","ru":"Зимой я ношу тёплый свитер.","vi":"Vào mùa đông tôi mặc áo len ấm áp.","fa":"در زمستان یک ژاکت گرم می پوشم."},{"de":"Sie hat mir einen blauen Pullover geschenkt.","en":"She gave me a blue sweater as a present.","ru":"Она подарила мне синий свитер.","vi":"Cô ấy đưa cho tôi một chiếc áo len màu xanh.","fa":"یک ژاکت آبی به من داد."}]},{"word":"der Punkt","en":"point; dot","ru":"точка; пункт","vi":"điểm","fa":"نقطه","examples":[{"de":"Setz am Ende des Satzes einen Punkt.","en":"Put a period at the end of the sentence.","ru":"Поставь точку в конце предложения.","vi":"Đặt dấu chấm ở cuối câu.","fa":"در پایان جمله نقطه بگذارید."},{"de":"Das war ein wichtiger Punkt in der Diskussion.","en":"That was an important point in the discussion.","ru":"Это был важный пункт в дискуссии.","vi":"Đó là một điểm quan trọng trong cuộc thảo luận.","fa":"این یک نکته مهم در بحث بود."}]},{"word":"die Puppe","en":"doll","ru":"кукла","vi":"con búp bê","fa":"عروسک","examples":[{"de":"Das Mädchen spielt gern mit ihrer Puppe.","en":"The girl likes to play with her doll.","ru":"Девочка любит играть со своей куклой.","vi":"Cô bé thích chơi với búp bê của mình.","fa":"دختر دوست دارد با عروسکش بازی کند."},{"de":"Zum Geburtstag hat sie eine neue Puppe bekommen.","en":"For her birthday she got a new doll.","ru":"На день рождения она получила новую куклу.","vi":"Cô ấy có một con búp bê mới vào ngày sinh nhật của mình.","fa":"او برای تولدش یک عروسک جدید گرفت."}]},{"word":"putzen","en":"to clean","ru":"убирать, чистить","vi":"sạch sẽ","fa":"تمیز کردن","examples":[{"de":"Am Samstag putze ich immer die ganze Wohnung.","en":"On Saturdays I always clean the whole apartment.","ru":"По субботам я всегда убираю всю квартиру.","vi":"Tôi luôn dọn dẹp toàn bộ căn hộ vào thứ bảy.","fa":"من همیشه شنبه کل آپارتمان را تمیز می کنم."},{"de":"Kannst du bitte die Fenster putzen?","en":"Can you please clean the windows?","ru":"Ты можешь, пожалуйста, помыть окна?","vi":"Bạn có thể vui lòng lau cửa sổ được không?","fa":"میشه لطفا پنجره ها رو تمیز کنید؟"}]},{"word":"die Qualifikation","en":"qualification","ru":"квалификация","vi":"trình độ chuyên môn","fa":"صلاحیت","examples":[{"de":"Für diese Stelle braucht man eine besondere Qualifikation.","en":"For this position you need a special qualification.","ru":"Для этой должности нужна особая квалификация.","vi":"Bạn cần có bằng cấp đặc biệt cho vị trí này.","fa":"برای این موقعیت به مدرک خاصی نیاز دارید."},{"de":"Seine Qualifikation als Techniker hilft ihm im neuen Job.","en":"His qualification as a technician helps him in the new job.","ru":"Его квалификация техника помогает ему на новой работе.","vi":"Trình độ kỹ thuật viên của anh ấy giúp anh ấy trong công việc mới.","fa":"صلاحیت های او به عنوان یک تکنسین به او در شغل جدید کمک می کند."}]},{"word":"die Qualität","en":"quality","ru":"качество","vi":"chất lượng","fa":"کیفیت","examples":[{"de":"Dieses Produkt hat eine sehr gute Qualität.","en":"This product has very good quality.","ru":"У этого продукта очень хорошее качество.","vi":"Sản phẩm này có chất lượng rất tốt.","fa":"این محصول کیفیت بسیار خوبی دارد."},{"de":"Wir legen großen Wert auf Qualität.","en":"We place great value on quality.","ru":"Мы придаём большое значение качеству.","vi":"Chúng tôi rất coi trọng chất lượng.","fa":"ما به کیفیت اهمیت زیادی می دهیم."}]},{"word":"das Quartier","en":"neighborhood, quarter; accommodation","ru":"квартал, район; жильё","vi":"quý","fa":"ربع","examples":[{"de":"Wir wohnen in einem ruhigen Quartier der Stadt.","en":"We live in a quiet neighborhood of the city.","ru":"Мы живём в тихом районе города.","vi":"Chúng tôi sống ở một khu vực yên tĩnh của thành phố.","fa":"ما در یک منطقه آرام از شهر زندگی می کنیم."},{"de":"Die Soldaten suchten ein Quartier für die Nacht.","en":"The soldiers looked for accommodation for the night.","ru":"Солдаты искали ночлег на ночь.","vi":"Những người lính đang tìm nơi trú ẩn qua đêm.","fa":"سربازان به دنبال محل اقامت شبانه بودند."}]},{"word":"die Quelle","en":"source; spring","ru":"источник","vi":"nguồn","fa":"منبع","examples":[{"de":"Die Sonne ist eine wichtige Quelle für saubere Energie.","en":"The sun is an important source of clean energy.","ru":"Солнце — важный источник чистой энергии.","vi":"Mặt trời là nguồn năng lượng sạch quan trọng.","fa":"خورشید منبع مهم انرژی پاک است."},{"de":"Bitte gib in deinem Text immer die Quelle an.","en":"Please always cite the source in your text.","ru":"Пожалуйста, всегда указывай источник в своём тексте.","vi":"Hãy luôn trích dẫn nguồn trong văn bản của bạn.","fa":"لطفا همیشه منبع را در متن خود ذکر کنید."}]},{"word":"quer","en":"diagonally, crosswise","ru":"поперёк, наискосок","vi":"ngang qua","fa":"در سراسر","examples":[{"de":"Das Auto stand quer auf der Straße.","en":"The car was parked crosswise on the street.","ru":"Машина стояла поперёк улицы.","vi":"Chiếc xe đã đậu bên kia đường.","fa":"ماشین آن طرف خیابان پارک شده بود."},{"de":"Wir gehen quer durch den Park.","en":"We are walking diagonally across the park.","ru":"Мы идём наискосок через парк.","vi":"Chúng tôi đi bộ ngang qua công viên.","fa":"از پارک عبور می کنیم."}]},{"word":"die Quittung","en":"receipt","ru":"квитанция, чек","vi":"biên nhận","fa":"رسید","examples":[{"de":"Bitte geben Sie mir eine Quittung für den Einkauf.","en":"Please give me a receipt for the purchase.","ru":"Пожалуйста, дайте мне чек за покупку.","vi":"Vui lòng đưa cho tôi biên lai mua hàng.","fa":"لطفا رسید خرید را به من بدهید."},{"de":"Ich habe die Quittung leider verloren.","en":"Unfortunately I lost the receipt.","ru":"К сожалению, я потерял чек.","vi":"Thật không may tôi đã làm mất biên nhận.","fa":"متأسفانه رسید را گم کردم."}]},{"word":"das Quiz","en":"quiz","ru":"викторина","vi":"bài kiểm tra","fa":"مسابقه","examples":[{"de":"Wir spielen heute Abend ein Quiz über Geografie.","en":"This evening we are playing a quiz about geography.","ru":"Сегодня вечером мы играем в викторину по географии.","vi":"Tối nay chúng ta sẽ chơi bài kiểm tra địa lý.","fa":"ما امشب در حال انجام یک مسابقه جغرافیا هستیم."},{"de":"Bei dem Quiz im Fernsehen kann man Geld gewinnen.","en":"In the TV quiz you can win money.","ru":"В телевизионной викторине можно выиграть деньги.","vi":"Bạn có thể kiếm được tiền bằng cách làm bài kiểm tra trên TV.","fa":"با شرکت در مسابقه تلویزیونی می توانید برنده شوید."}]},{"word":"der Rabatt","en":"discount","ru":"скидка","vi":"giảm giá","fa":"تخفیف","examples":[{"de":"Auf Schuhe gibt es diese Woche zwanzig Prozent Rabatt.","en":"This week there is a twenty percent discount on shoes.","ru":"На этой неделе на обувь скидка двадцать процентов.","vi":"Tuần này có đợt giảm giá 20% cho giày.","fa":"در این هفته کفش بیست درصد تخفیف داده شده است."},{"de":"Studenten bekommen in diesem Kino einen Rabatt.","en":"Students get a discount at this cinema.","ru":"Студенты получают скидку в этом кинотеатре.","vi":"Sinh viên được giảm giá tại rạp chiếu phim này.","fa":"دانشجویان در این سینما از تخفیف برخوردار می شوند."}]},{"word":"das Rad","en":"wheel; bicycle","ru":"колесо; велосипед","vi":"bánh xe","fa":"چرخ","examples":[{"de":"Das Rad meines Fahrrads ist kaputt.","en":"The wheel of my bicycle is broken.","ru":"Колесо моего велосипеда сломано.","vi":"Bánh xe đạp của tôi bị hỏng.","fa":"چرخ دوچرخه ام خراب است."},{"de":"Ich fahre jeden Tag mit dem Rad zur Arbeit.","en":"I ride my bike to work every day.","ru":"Каждый день я езжу на велосипеде на работу.","vi":"Tôi đạp xe đi làm hàng ngày.","fa":"من هر روز با دوچرخه به سر کار می روم."}]},{"word":"das Radio","en":"radio","ru":"радио","vi":"đài phát thanh","fa":"رادیو","examples":[{"de":"Am Morgen höre ich immer Radio.","en":"In the morning I always listen to the radio.","ru":"По утрам я всегда слушаю радио.","vi":"Tôi luôn nghe radio vào buổi sáng.","fa":"من همیشه صبح ها به رادیو گوش می دهم."},{"de":"Im Radio kommt gerade meine Lieblingsmusik.","en":"My favorite music is playing on the radio right now.","ru":"Сейчас по радио звучит моя любимая музыка.","vi":"Bản nhạc yêu thích của tôi hiện đang có trên đài phát thanh.","fa":"موسیقی مورد علاقه من در حال حاضر در رادیو پخش می شود."}]},{"word":"der Rand","en":"edge, border","ru":"край, граница","vi":"rìa","fa":"لبه","examples":[{"de":"Das Haus steht am Rand der Stadt.","en":"The house stands at the edge of the city.","ru":"Дом стоит на окраине города.","vi":"Ngôi nhà nằm ở ngoại ô thành phố.","fa":"خانه در حومه شهر است."},{"de":"Schreib die Notiz an den Rand des Blattes.","en":"Write the note in the margin of the page.","ru":"Напиши заметку на полях листа.","vi":"Viết ghi chú vào mép giấy.","fa":"یادداشت را در لبه کاغذ بنویسید."}]},{"word":"der Rasen","en":"lawn","ru":"газон","vi":"bãi cỏ","fa":"چمنزار","examples":[{"de":"Er mäht jeden Samstag den Rasen.","en":"He mows the lawn every Saturday.","ru":"Он подстригает газон каждую субботу.","vi":"Anh ấy cắt cỏ vào thứ Bảy hàng tuần.","fa":"او هر شنبه چمن را می کند."},{"de":"Auf dem Rasen liegen die Kinder in der Sonne.","en":"The children are lying on the lawn in the sun.","ru":"Дети лежат на газоне на солнце.","vi":"Bọn trẻ nằm phơi nắng trên bãi cỏ.","fa":"بچه ها روی چمن زیر آفتاب دراز می کشند."}]},{"word":"raten","en":"to guess; to advise","ru":"угадывать; советовать","vi":"khuyên nhủ","fa":"نصیحت کردن","examples":[{"de":"Rate mal, wer heute zu Besuch kommt!","en":"Guess who is coming to visit today!","ru":"Угадай, кто сегодня придёт в гости!","vi":"Đoán xem hôm nay ai sẽ đến thăm nào!","fa":"حدس بزنید چه کسی امروز برای بازدید می آید!"},{"de":"Der Arzt riet ihr, mehr Sport zu treiben.","en":"The doctor advised her to do more sport.","ru":"Врач посоветовал ей больше заниматься спортом.","vi":"Bác sĩ khuyên cô nên tập thể dục nhiều hơn.","fa":"دکتر به او توصیه کرد بیشتر ورزش کند."}]},{"word":"das Rathaus","en":"town hall, city hall","ru":"ратуша, мэрия","vi":"tòa thị chính","fa":"تالار شهر","examples":[{"de":"Das Rathaus steht mitten auf dem Marktplatz.","en":"The town hall stands in the middle of the market square.","ru":"Ратуша стоит в центре рыночной площади.","vi":"Tòa thị chính nằm giữa quảng trường chợ.","fa":"تالار شهر در وسط میدان بازار است."},{"de":"Wir haben im Rathaus geheiratet.","en":"We got married at the town hall.","ru":"Мы поженились в ратуше.","vi":"Chúng tôi kết hôn ở tòa thị chính.","fa":"در شهرداری ازدواج کردیم."}]},{"word":"rauchen","en":"to smoke","ru":"курить","vi":"khói","fa":"دود","examples":[{"de":"Hier darf man nicht rauchen.","en":"You are not allowed to smoke here.","ru":"Здесь нельзя курить.","vi":"Bạn không được phép hút thuốc ở đây.","fa":"اینجا اجازه سیگار کشیدن ندارید."},{"de":"Er hat vor einem Jahr mit dem Rauchen aufgehört.","en":"He quit smoking a year ago.","ru":"Он бросил курить год назад.","vi":"Anh ấy đã ngừng hút thuốc cách đây một năm.","fa":"او یک سال پیش سیگار را ترک کرد."}]},{"word":"rauf","en":"up (colloquial, up here/there)","ru":"наверх (разг.)","vi":"lên","fa":"بالا","examples":[{"de":"Komm rauf, das Essen ist fertig!","en":"Come up, the food is ready!","ru":"Поднимайся наверх, еда готова!","vi":"Mau lên, đồ ăn đã sẵn sàng rồi!","fa":"بیا بالا، غذا آماده است!"},{"de":"Wir gehen den Berg rauf.","en":"We are going up the mountain.","ru":"Мы идём в гору.","vi":"Chúng tôi đi lên núi.","fa":"از کوه بالا می رویم."}]},{"word":"der Raum","en":"room, space","ru":"помещение, пространство","vi":"căn phòng","fa":"اتاق","examples":[{"de":"Der Raum ist zu klein für so viele Leute.","en":"The room is too small for so many people.","ru":"Помещение слишком маленькое для стольких людей.","vi":"Căn phòng quá nhỏ cho rất nhiều người.","fa":"اتاق برای این همه آدم خیلی کوچک است."},{"de":"Im Weltraum gibt es keine Luft.","en":"There is no air in space.","ru":"В космосе нет воздуха.","vi":"Không có không khí trong không gian.","fa":"هوا در فضا وجود ندارد."}]},{"word":"raus","en":"out (colloquial)","ru":"наружу, вон (разг.)","vi":"ra ngoài","fa":"بیرون","examples":[{"de":"Geh bitte raus und spiel im Garten.","en":"Please go outside and play in the garden.","ru":"Пожалуйста, иди на улицу и играй в саду.","vi":"Hãy ra ngoài và chơi trong vườn.","fa":"لطفا بیرون بروید و در باغ بازی کنید."},{"de":"Der Hund will raus.","en":"The dog wants to go out.","ru":"Собака хочет выйти на улицу.","vi":"Con chó muốn đi ra ngoài.","fa":"سگ می خواهد برود بیرون."}]},{"word":"realisieren","en":"to realize, to carry out","ru":"реализовывать, осуществлять","vi":"nhận ra","fa":"متوجه شدن","examples":[{"de":"Wir wollen unsere Idee bald realisieren.","en":"We want to realize our idea soon.","ru":"Мы хотим скоро реализовать нашу идею.","vi":"Chúng tôi muốn sớm hiện thực hóa ý tưởng của mình.","fa":"ما می خواهیم به زودی ایده خود را محقق کنیم."},{"de":"Das Projekt konnte leider nicht realisiert werden.","en":"Unfortunately the project could not be realized.","ru":"К сожалению, проект не удалось реализовать.","vi":"Thật không may, dự án không thể thực hiện được.","fa":"متاسفانه پروژه محقق نشد."}]},{"word":"die Recherche","en":"research","ru":"исследование, поиск информации","vi":"nghiên cứu","fa":"تحقیق","examples":[{"de":"Für den Artikel machte die Journalistin eine gründliche Recherche.","en":"For the article, the journalist did thorough research.","ru":"Для статьи журналистка провела тщательное исследование.","vi":"Nhà báo đã nghiên cứu kỹ lưỡng cho bài báo.","fa":"روزنامه نگار برای مقاله تحقیقات کاملی انجام داد."},{"de":"Meine Recherche im Internet hat lange gedauert.","en":"My research on the internet took a long time.","ru":"Мой поиск информации в интернете занял много времени.","vi":"Nghiên cứu của tôi trên internet mất một thời gian dài.","fa":"تحقیق من در اینترنت خیلی طول کشید."}]},{"word":"rechnen","en":"to calculate","ru":"считать, вычислять","vi":"tính toán","fa":"محاسبه کنید","examples":[{"de":"Die Kinder lernen in der Schule rechnen.","en":"The children learn to do math at school.","ru":"Дети учатся считать в школе.","vi":"Trẻ em học số học ở trường.","fa":"بچه ها در مدرسه حساب را یاد می گیرند."},{"de":"Ich rechne mit deiner Hilfe morgen.","en":"I am counting on your help tomorrow.","ru":"Я рассчитываю на твою помощь завтра.","vi":"Tôi trông cậy vào sự giúp đỡ của bạn vào ngày mai.","fa":"من فردا روی کمک شما حساب می کنم."}]},{"word":"die Rechnung","en":"bill; invoice","ru":"счёт","vi":"hóa đơn","fa":"صورت حساب","examples":[{"de":"Können wir bitte die Rechnung haben?","en":"Could we have the bill, please?","ru":"Можно нам, пожалуйста, счёт?","vi":"Làm ơn cho chúng tôi xin hóa đơn được không?","fa":"آیا می توانیم صورتحساب را داشته باشیم؟"},{"de":"Die Rechnung muss innerhalb von 14 Tagen bezahlt werden.","en":"The invoice must be paid within 14 days.","ru":"Счёт должен быть оплачен в течение 14 дней.","vi":"Hóa đơn phải được thanh toán trong vòng 14 ngày.","fa":"فاکتور باید ظرف 14 روز پرداخت شود."}]},{"word":"das Recht","en":"right; law","ru":"право","vi":"bên phải","fa":"حق","examples":[{"de":"Jeder Mensch hat das Recht auf Bildung.","en":"Every person has the right to education.","ru":"Каждый человек имеет право на образование.","vi":"Mọi người đều có quyền được giáo dục.","fa":"هر فرد حق تحصیل دارد."},{"de":"Er studiert Recht an der Universität.","en":"He studies law at the university.","ru":"Он изучает право в университете.","vi":"Anh ấy học luật ở trường đại học.","fa":"او در دانشگاه حقوق می خواند."}]},{"word":"recht","en":"right, correct; quite","ru":"правый, верный; довольно","vi":"đúng","fa":"درست است","examples":[{"de":"Du hast recht, das war ein Fehler.","en":"You are right, that was a mistake.","ru":"Ты прав, это была ошибка.","vi":"Bạn nói đúng, đó là một sai lầm.","fa":"حق با شماست، اشتباه بود"},{"de":"Das Wetter ist heute recht schön.","en":"The weather is quite nice today.","ru":"Погода сегодня довольно хорошая.","vi":"Thời tiết hôm nay khá đẹp.","fa":"امروز هوا خیلی خوبه"}]},{"word":"rechts","en":"on the right, to the right","ru":"справа, направо","vi":"đúng","fa":"درست است","examples":[{"de":"An der Ampel musst du rechts abbiegen.","en":"You have to turn right at the traffic light.","ru":"На светофоре тебе нужно повернуть направо.","vi":"Tại đèn giao thông bạn phải rẽ phải.","fa":"در چراغ راهنمایی باید به راست بپیچید."},{"de":"Das Geschäft liegt rechts neben der Bank.","en":"The shop is to the right of the bank.","ru":"Магазин находится справа от банка.","vi":"Cửa hàng nằm bên phải ngân hàng.","fa":"مغازه در سمت راست بانک است."}]},{"word":"rechtzeitig","en":"on time, in time","ru":"своевременно, вовремя","vi":"đúng lúc","fa":"در زمان","examples":[{"de":"Wir müssen rechtzeitig am Flughafen sein.","en":"We have to be at the airport on time.","ru":"Нам нужно вовремя быть в аэропорту.","vi":"Chúng ta phải có mặt ở sân bay đúng giờ.","fa":"ما باید به موقع در فرودگاه باشیم."},{"de":"Er kam rechtzeitig zur Prüfung.","en":"He arrived on time for the exam.","ru":"Он вовремя пришёл на экзамен.","vi":"Anh ấy đến thi đúng giờ.","fa":"به موقع سر امتحان آمد."}]},{"word":"reden","en":"to talk, to speak","ru":"говорить, разговаривать","vi":"nói chuyện","fa":"صحبت کنید","examples":[{"de":"Wir müssen dringend über das Problem reden.","en":"We urgently need to talk about the problem.","ru":"Нам срочно нужно поговорить о проблеме.","vi":"Chúng tôi cần khẩn trương nói về vấn đề này.","fa":"ما باید فوراً در مورد مشکل صحبت کنیم."},{"de":"Er redet gern über Politik.","en":"He likes to talk about politics.","ru":"Он любит разговаривать о политике.","vi":"Anh ấy thích nói về chính trị.","fa":"او دوست دارد در مورد سیاست صحبت کند."}]},{"word":"reduzieren","en":"to reduce","ru":"снижать, сокращать","vi":"giảm bớt","fa":"کاهش دهد","examples":[{"de":"Der Laden hat die Preise stark reduziert.","en":"The shop reduced the prices significantly.","ru":"Магазин сильно снизил цены.","vi":"Cửa hàng đã giảm giá đáng kể.","fa":"این فروشگاه قیمت ها را به میزان قابل توجهی کاهش داده است."},{"de":"Wir sollten unseren Stress reduzieren.","en":"We should reduce our stress.","ru":"Нам следует сократить свой стресс.","vi":"Chúng ta nên giảm bớt căng thẳng.","fa":"ما باید استرس خود را کاهش دهیم."}]},{"word":"das Referat","en":"presentation, report (oral/written)","ru":"доклад, реферат","vi":"báo cáo","fa":"گزارش","examples":[{"de":"Sie hält morgen ein Referat über Klimawandel.","en":"Tomorrow she is giving a presentation about climate change.","ru":"Завтра она делает доклад об изменении климата.","vi":"Cô ấy sẽ có buổi nói chuyện về biến đổi khí hậu vào ngày mai.","fa":"او فردا در مورد تغییرات آب و هوایی سخنرانی می کند."},{"de":"Ich muss noch mein Referat vorbereiten.","en":"I still have to prepare my presentation.","ru":"Мне ещё нужно подготовить свой доклад.","vi":"Tôi vẫn phải chuẩn bị bài thuyết trình của mình.","fa":"من هنوز باید ارائه خود را آماده کنم."}]},{"word":"die Reform","en":"reform","ru":"реформа","vi":"cải cách","fa":"اصلاحات","examples":[{"de":"Die Regierung plant eine Reform des Bildungssystems.","en":"The government is planning a reform of the education system.","ru":"Правительство планирует реформу системы образования.","vi":"Chính phủ đang lên kế hoạch cải cách hệ thống giáo dục.","fa":"دولت در حال برنامه ریزی برای اصلاح نظام آموزشی است."},{"de":"Die neue Reform wird viel diskutiert.","en":"The new reform is much discussed.","ru":"Новая реформа широко обсуждается.","vi":"Cuộc cải cách mới đang được thảo luận rất nhiều.","fa":"اصلاحات جدید بسیار مورد بحث است."}]},{"word":"das Regal","en":"shelf, shelving unit","ru":"полка, стеллаж","vi":"cái kệ","fa":"قفسه","examples":[{"de":"Die Bücher stehen ordentlich im Regal.","en":"The books are neatly arranged on the shelf.","ru":"Книги аккуратно стоят на полке.","vi":"Sách được xếp gọn gàng trên kệ.","fa":"کتاب ها به طور مرتب روی قفسه هستند."},{"de":"Ich brauche ein neues Regal für die Küche.","en":"I need a new shelf for the kitchen.","ru":"Мне нужна новая полка для кухни.","vi":"Tôi cần một cái kệ mới cho nhà bếp.","fa":"به یک قفسه جدید برای آشپزخانه نیاز دارم."}]},{"word":"die Regel","en":"rule","ru":"правило","vi":"quy tắc","fa":"قانون","examples":[{"de":"In der Schule gibt es viele Regeln, die man beachten muss.","en":"At school there are many rules that you have to follow.","ru":"В школе есть много правил, которые нужно соблюдать.","vi":"Có rất nhiều quy tắc ở trường mà bạn phải tuân theo.","fa":"قوانین زیادی در مدرسه وجود دارد که باید آنها را رعایت کنید."},{"de":"Als Ausnahme von der Regel darf er heute später kommen.","en":"As an exception to the rule, he is allowed to come later today.","ru":"В качестве исключения из правила ему разрешено сегодня прийти позже.","vi":"Như một ngoại lệ đối với quy định, hôm nay anh ấy được phép đến muộn hơn.","fa":"به عنوان یک استثنا از قاعده، او اجازه دارد بعداً امروز بیاید."}]},{"word":"regeln","en":"to regulate; to settle/arrange","ru":"регулировать; улаживать","vi":"điều tiết","fa":"تنظیم کند","examples":[{"de":"Der Verkehr wird an dieser Kreuzung von einer Ampel geregelt.","en":"Traffic at this intersection is regulated by a traffic light.","ru":"Движение на этом перекрёстке регулируется светофором.","vi":"Giao thông tại ngã tư này được điều khiển bởi đèn giao thông.","fa":"ترافیک در این تقاطع توسط چراغ راهنمایی کنترل می شود."},{"de":"Wir müssen die Details noch vor der Reise regeln.","en":"We still need to settle the details before the trip.","ru":"Нам ещё нужно уладить детали перед поездкой.","vi":"Chúng tôi phải sắp xếp các chi tiết trước chuyến đi.","fa":"قبل از سفر باید جزئیات را مرتب کنیم."}]},{"word":"die Regierung","en":"government","ru":"правительство","vi":"chính phủ","fa":"دولت","examples":[{"de":"Die Regierung hat ein neues Gesetz beschlossen.","en":"The government has passed a new law.","ru":"Правительство приняло новый закон.","vi":"Chính phủ đã thông qua một luật mới.","fa":"دولت قانون جدیدی تصویب کرده است."},{"de":"Viele Bürger sind mit der Regierung unzufrieden.","en":"Many citizens are dissatisfied with the government.","ru":"Многие граждане недовольны правительством.","vi":"Nhiều người dân không hài lòng với chính phủ.","fa":"بسیاری از شهروندان از دولت ناراضی هستند."}]},{"word":"die Region","en":"region","ru":"регион","vi":"khu vực","fa":"منطقه","examples":[{"de":"In dieser Region gibt es viele Weinberge.","en":"There are many vineyards in this region.","ru":"В этом регионе много виноградников.","vi":"Có rất nhiều vườn nho ở vùng này.","fa":"در این منطقه تاکستان های زیادی وجود دارد."},{"de":"Das Klima ist von Region zu Region sehr unterschiedlich.","en":"The climate varies greatly from region to region.","ru":"Климат сильно отличается от региона к региону.","vi":"Khí hậu thay đổi rất nhiều từ vùng này sang vùng khác.","fa":"آب و هوا از منطقه ای به منطقه دیگر بسیار متفاوت است."}]},{"word":"regnen","en":"to rain","ru":"идти (о дожде)","vi":"mưa","fa":"باران","examples":[{"de":"Draußen regnet es seit dem Morgen.","en":"It has been raining outside since morning.","ru":"На улице идёт дождь с самого утра.","vi":"Ngoài trời đang mưa từ sáng.","fa":"از صبح بیرون باران می بارد."},{"de":"Nimm einen Schirm mit, es soll heute regnen.","en":"Take an umbrella with you, it's supposed to rain today.","ru":"Возьми с собой зонт, сегодня обещают дождь.","vi":"Hãy mang ô theo nhé, hôm nay trời sẽ mưa.","fa":"یه چتر با خودت ببر، قراره امروز بارون بباره."}]},{"word":"reich","en":"rich","ru":"богатый","vi":"giàu có","fa":"ثروتمند","examples":[{"de":"Seine Familie ist sehr reich.","en":"His family is very rich.","ru":"Его семья очень богатая.","vi":"Gia đình anh ấy rất giàu có.","fa":"خانواده او بسیار ثروتمند هستند."},{"de":"Das Land ist reich an Bodenschätzen.","en":"The country is rich in natural resources.","ru":"Страна богата полезными ископаемыми.","vi":"Đất nước này rất giàu tài nguyên khoáng sản.","fa":"این کشور از نظر منابع معدنی غنی است."}]},{"word":"reichen","en":"to be enough; to hand/pass","ru":"хватать; подавать/протягивать","vi":"đủ rồi","fa":"به اندازه کافی","examples":[{"de":"Das Geld reicht nicht für ein neues Auto.","en":"The money isn't enough for a new car.","ru":"Денег не хватает на новую машину.","vi":"Không có đủ tiền để mua một chiếc xe mới.","fa":"پول کافی برای یک ماشین جدید وجود ندارد."},{"de":"Kannst du mir bitte das Salz reichen?","en":"Can you pass me the salt, please?","ru":"Можешь передать мне соль, пожалуйста?","vi":"Bạn có thể vui lòng đưa cho tôi muối được không?","fa":"میشه لطفا نمک را به من بدهید؟"}]},{"word":"reif","en":"ripe; mature","ru":"спелый; зрелый","vi":"chín muồi","fa":"رسیده","examples":[{"de":"Die Bananen sind noch nicht reif.","en":"The bananas are not ripe yet.","ru":"Бананы ещё не спелые.","vi":"Chuối vẫn chưa chín.","fa":"موز هنوز نرسیده است."},{"de":"Er ist für sein Alter schon sehr reif.","en":"He is already very mature for his age.","ru":"Он уже очень зрелый для своего возраста.","vi":"Anh ấy rất trưởng thành so với tuổi của mình.","fa":"او نسبت به سن خود بسیار بالغ است."}]},{"word":"der Reifen","en":"tire","ru":"шина","vi":"lốp xe","fa":"لاستیک","examples":[{"de":"Im Winter braucht man andere Reifen.","en":"In winter you need different tires.","ru":"Зимой нужны другие шины.","vi":"Vào mùa đông, bạn cần những loại lốp khác nhau.","fa":"در زمستان به لاستیک های مختلفی نیاز دارید."},{"de":"Der Reifen ist platt, wir müssen ihn wechseln.","en":"The tire is flat, we have to change it.","ru":"Шина спущена, нам нужно её поменять.","vi":"Lốp bị xẹp, chúng ta phải thay nó.","fa":"لاستیک پنچر شده باید عوضش کنیم"}]},{"word":"die Reihe","en":"row; series","ru":"ряд; серия","vi":"hàng","fa":"ردیف","examples":[{"de":"Wir sitzen in der ersten Reihe im Kino.","en":"We are sitting in the first row at the cinema.","ru":"Мы сидим в первом ряду в кино.","vi":"Chúng tôi đang ngồi ở hàng ghế đầu của rạp chiếu phim.","fa":"ما در ردیف اول سینما نشسته ایم."},{"de":"Er ist jetzt an der Reihe.","en":"It's his turn now.","ru":"Теперь его очередь.","vi":"Bây giờ đến lượt anh ấy.","fa":"حالا نوبت اوست"}]},{"word":"die Reihenfolge","en":"order; sequence","ru":"последовательность; порядок","vi":"thứ tự","fa":"سفارش","examples":[{"de":"Bitte beachten Sie die Reihenfolge der Aufgaben.","en":"Please pay attention to the order of the tasks.","ru":"Пожалуйста, соблюдайте порядок выполнения заданий.","vi":"Hãy lưu ý thứ tự các công việc.","fa":"لطفا به ترتیب وظایف توجه کنید."},{"de":"Die Namen stehen in alphabetischer Reihenfolge.","en":"The names are in alphabetical order.","ru":"Имена расположены в алфавитном порядке.","vi":"Các tên được sắp xếp theo thứ tự bảng chữ cái.","fa":"اسامی به ترتیب حروف الفبا می باشد."}]},{"word":"rein","en":"pure; clean","ru":"чистый","vi":"tinh khiết","fa":"خالص","examples":[{"de":"Das ist reines Gold.","en":"This is pure gold.","ru":"Это чистое золото.","vi":"Đây là vàng nguyên chất.","fa":"این طلای خالص است."},{"de":"Die Luft in den Bergen ist sehr rein.","en":"The air in the mountains is very clean.","ru":"Воздух в горах очень чистый.","vi":"Không khí trên núi rất trong lành.","fa":"هوای کوهستان بسیار تمیز است."}]},{"word":"reinigen","en":"to clean","ru":"чистить","vi":"sạch sẽ","fa":"تمیز کردن","examples":[{"de":"Wir lassen den Teppich professionell reinigen.","en":"We have the carpet cleaned professionally.","ru":"Мы отдаём ковёр на профессиональную чистку.","vi":"Chúng tôi giặt thảm một cách chuyên nghiệp.","fa":"ما فرش را به صورت حرفه ای تمیز می کنیم."},{"de":"Reinige die Wunde vorsichtig mit Wasser.","en":"Clean the wound carefully with water.","ru":"Аккуратно промой рану водой.","vi":"Nhẹ nhàng làm sạch vết thương bằng nước.","fa":"به آرامی زخم را با آب تمیز کنید."}]},{"word":"der Reis","en":"rice","ru":"рис","vi":"cơm","fa":"برنج","examples":[{"de":"Zum Mittagessen gibt es Reis mit Gemüse.","en":"For lunch there is rice with vegetables.","ru":"На обед рис с овощами.","vi":"Bữa trưa có cơm với rau.","fa":"برای ناهار برنج با سبزیجات وجود دارد."},{"de":"In Asien ist Reis ein Grundnahrungsmittel.","en":"In Asia, rice is a staple food.","ru":"В Азии рис — основной продукт питания.","vi":"Ở châu Á, gạo là lương thực chính.","fa":"در آسیا، برنج یک غذای اصلی است."}]},{"word":"reisen","en":"to travel","ru":"путешествовать","vi":"du lịch","fa":"سفر","examples":[{"de":"Wir reisen jedes Jahr in ein anderes Land.","en":"We travel to a different country every year.","ru":"Мы каждый год путешествуем в другую страну.","vi":"Chúng tôi đi du lịch đến một đất nước khác nhau mỗi năm.","fa":"ما هر سال به کشور دیگری سفر می کنیم."},{"de":"Sie reist gern allein.","en":"She likes to travel alone.","ru":"Она любит путешествовать одна.","vi":"Cô ấy thích đi du lịch một mình.","fa":"او دوست دارد به تنهایی سفر کند."}]},{"word":"reiten","en":"to ride (a horse)","ru":"ездить верхом","vi":"đi xe","fa":"سوار شدن","examples":[{"de":"Meine Tochter reitet jeden Samstag.","en":"My daughter rides a horse every Saturday.","ru":"Моя дочь катается верхом каждую субботу.","vi":"Con gái tôi đi xe vào thứ Bảy hàng tuần.","fa":"دخترم هر شنبه سوار می شود."},{"de":"Kannst du reiten?","en":"Can you ride a horse?","ru":"Ты умеешь ездить верхом?","vi":"Bạn có thể đi xe không?","fa":"آیا می توانید سوار شوید؟"}]},{"word":"die Reklame","en":"advertisement","ru":"реклама","vi":"quảng cáo","fa":"تبلیغ","examples":[{"de":"Im Fernsehen läuft ständig Reklame.","en":"There are constantly advertisements on TV.","ru":"По телевизору постоянно идёт реклама.","vi":"Có những quảng cáo liên tục trên truyền hình.","fa":"تبلیغات دائمی در تلویزیون وجود دارد."},{"de":"Diese Reklame gefällt mir gar nicht.","en":"I don't like this advertisement at all.","ru":"Мне совсем не нравится эта реклама.","vi":"Tôi không thích quảng cáo này chút nào.","fa":"من اصلا از این تبلیغ خوشم نمیاد"}]},{"word":"der Rekord","en":"record","ru":"рекорд","vi":"kỷ lục","fa":"رکورد","examples":[{"de":"Er hat einen neuen Rekord im Weitsprung aufgestellt.","en":"He set a new record in the long jump.","ru":"Он установил новый рекорд в прыжках в длину.","vi":"Anh lập kỷ lục mới ở nội dung nhảy xa.","fa":"او رکورد جدیدی در پرش طول به ثبت رساند."},{"de":"Dieses Jahr wurde ein Hitzerekord gemessen.","en":"This year a heat record was measured.","ru":"В этом году был зафиксирован рекорд жары.","vi":"Một đợt nắng nóng kỷ lục đã được ghi nhận trong năm nay.","fa":"رکورد گرمای امسال ثبت شد."}]},{"word":"relativ","en":"relative; relatively","ru":"относительный; относительно","vi":"tương đối","fa":"نسبی","examples":[{"de":"Die Wohnung ist relativ klein, aber gemütlich.","en":"The apartment is relatively small but cozy.","ru":"Квартира относительно маленькая, но уютная.","vi":"Căn hộ tương đối nhỏ nhưng ấm cúng.","fa":"آپارتمان نسبتا کوچک اما دنج است."},{"de":"Alles ist relativ, sagt man.","en":"Everything is relative, as they say.","ru":"Всё относительно, как говорится.","vi":"Mọi thứ đều tương đối, họ nói.","fa":"می گویند همه چیز نسبی است."}]},{"word":"die Religion","en":"religion","ru":"религия","vi":"tôn giáo","fa":"دین","examples":[{"de":"In der Schule haben wir auch Religion als Fach.","en":"At school we also have religion as a subject.","ru":"В школе у нас есть предмет «религия».","vi":"Chúng tôi cũng lấy tôn giáo làm môn học ở trường.","fa":"در مدرسه هم درس دین داریم."},{"de":"Er interessiert sich sehr für verschiedene Religionen.","en":"He is very interested in different religions.","ru":"Он очень интересуется разными религиями.","vi":"Anh ấy rất quan tâm đến các tôn giáo khác nhau.","fa":"علاقه زیادی به ادیان مختلف دارد."}]},{"word":"rennen","en":"to run","ru":"бежать","vi":"chạy","fa":"اجرا کنید","examples":[{"de":"Die Kinder rennen über die Wiese.","en":"The children are running across the meadow.","ru":"Дети бегут по лугу.","vi":"Những đứa trẻ chạy qua đồng cỏ.","fa":"بچه ها از آن سوی چمنزار می دوند."},{"de":"Ich musste zum Bus rennen, um ihn noch zu erreichen.","en":"I had to run to the bus to still catch it.","ru":"Мне пришлось бежать к автобусу, чтобы успеть на него.","vi":"Tôi phải chạy ra xe buýt để bắt nó.","fa":"مجبور شدم به سمت اتوبوس بروم تا آن را بگیرم."}]},{"word":"die Rente","en":"pension","ru":"пенсия","vi":"lương hưu","fa":"حقوق بازنشستگی","examples":[{"de":"Mein Opa bekommt seit fünf Jahren Rente.","en":"My grandpa has been receiving a pension for five years.","ru":"Мой дедушка получает пенсию уже пять лет.","vi":"Ông tôi đã nhận được tiền trợ cấp được 5 năm rồi.","fa":"پدربزرگ من پنج سال است که مستمری می گیرد."},{"de":"Sie geht nächstes Jahr in Rente.","en":"She is retiring next year.","ru":"В следующем году она выходит на пенсию.","vi":"Cô ấy sẽ nghỉ hưu vào năm tới.","fa":"او سال آینده بازنشسته می شود."}]},{"word":"reparieren","en":"to repair","ru":"ремонтировать","vi":"sửa chữa","fa":"تعمیر","examples":[{"de":"Der Mechaniker repariert mein Auto.","en":"The mechanic is repairing my car.","ru":"Механик ремонтирует мою машину.","vi":"Người thợ sửa xe của tôi.","fa":"مکانیک ماشین من را تعمیر می کند."},{"de":"Kannst du das kaputte Fahrrad reparieren?","en":"Can you repair the broken bicycle?","ru":"Ты можешь починить сломанный велосипед?","vi":"Bạn có thể sửa chiếc xe đạp bị hỏng không?","fa":"آیا می توانید دوچرخه شکسته را تعمیر کنید؟"}]},{"word":"die Reportage","en":"report; documentary","ru":"репортаж","vi":"báo cáo","fa":"گزارش","examples":[{"de":"Im Radio lief eine interessante Reportage über den Klimawandel.","en":"There was an interesting report about climate change on the radio.","ru":"По радио шёл интересный репортаж об изменении климата.","vi":"Có một báo cáo thú vị về biến đổi khí hậu trên đài phát thanh.","fa":"گزارش جالبی در مورد تغییرات آب و هوایی از رادیو پخش شد."},{"de":"Sie schreibt eine Reportage über das Leben auf dem Land.","en":"She is writing a report about life in the countryside.","ru":"Она пишет репортаж о жизни в деревне.","vi":"Cô ấy viết một bản báo cáo về cuộc sống ở đất nước.","fa":"او گزارشی از زندگی در کشور می نویسد."}]},{"word":"reservieren","en":"to reserve; to book","ru":"бронировать","vi":"dự trữ","fa":"رزرو کنید","examples":[{"de":"Ich habe einen Tisch für zwei Personen reserviert.","en":"I have reserved a table for two people.","ru":"Я забронировал столик на двоих.","vi":"Tôi đã đặt bàn cho hai người.","fa":"من یک میز برای دو نفر رزرو کردم."},{"de":"Reservieren Sie bitte die Karten im Voraus.","en":"Please book the tickets in advance.","ru":"Пожалуйста, забронируйте билеты заранее.","vi":"Vui lòng đặt vé trước.","fa":"لطفا بلیط را از قبل رزرو کنید."}]},{"word":"der Respekt","en":"respect","ru":"уважение","vi":"sự tôn trọng","fa":"احترام","examples":[{"de":"Man sollte immer Respekt vor älteren Menschen haben.","en":"One should always have respect for older people.","ru":"Нужно всегда уважать пожилых людей.","vi":"Người ta phải luôn tôn trọng người lớn tuổi.","fa":"همیشه باید به افراد مسن احترام گذاشت."},{"de":"Er hat großen Respekt vor seiner Lehrerin.","en":"He has great respect for his teacher.","ru":"Он очень уважает свою учительницу.","vi":"Anh ấy rất tôn trọng giáo viên của mình.","fa":"او برای معلمش احترام زیادی قائل است."}]},{"word":"der Rest","en":"rest; remainder","ru":"остаток","vi":"phần còn lại","fa":"بقیه","examples":[{"de":"Den Rest des Kuchens können wir morgen essen.","en":"We can eat the rest of the cake tomorrow.","ru":"Остаток торта мы можем съесть завтра.","vi":"Chúng ta có thể ăn phần còn lại của chiếc bánh vào ngày mai.","fa":"بقیه کیک را فردا می توانیم بخوریم."},{"de":"Ich habe nur noch den Rest meines Geldes dabei.","en":"I only have the rest of my money with me.","ru":"У меня с собой остались только остатки денег.","vi":"Tôi chỉ mang theo số tiền còn lại.","fa":"من فقط بقیه پولم را با خودم دارم."}]},{"word":"das Restaurant","en":"restaurant","ru":"ресторан","vi":"nhà hàng","fa":"رستوران","examples":[{"de":"Wir gehen heute Abend in ein neues Restaurant.","en":"We are going to a new restaurant tonight.","ru":"Сегодня вечером мы идём в новый ресторан.","vi":"Tối nay chúng ta sẽ đi đến một nhà hàng mới.","fa":"ما امشب به یک رستوران جدید می رویم."},{"de":"Das Restaurant ist für seine Pasta bekannt.","en":"The restaurant is known for its pasta.","ru":"Ресторан известен своей пастой.","vi":"Nhà hàng được biết đến với món mì ống.","fa":"این رستوران به خاطر پاستاهایش معروف است."}]},{"word":"retten","en":"to save; to rescue","ru":"спасать","vi":"lưu lại","fa":"ذخیره کنید","examples":[{"de":"Die Feuerwehr konnte alle Bewohner retten.","en":"The fire department was able to save all the residents.","ru":"Пожарные смогли спасти всех жителей.","vi":"Sở cứu hỏa đã có thể cứu tất cả cư dân.","fa":"آتش نشانی توانست همه ساکنان را نجات دهد."},{"de":"Er hat dem Kind das Leben gerettet.","en":"He saved the child's life.","ru":"Он спас ребёнку жизнь.","vi":"Anh ấy đã cứu mạng đứa trẻ.","fa":"او جان کودک را نجات داد."}]},{"word":"die Rettung","en":"rescue; salvation","ru":"спасение","vi":"cuộc giải cứu","fa":"نجات","examples":[{"de":"Die Rettung der Bergsteiger dauerte mehrere Stunden.","en":"The rescue of the climbers took several hours.","ru":"Спасение альпинистов заняло несколько часов.","vi":"Việc giải cứu những người leo núi mất vài giờ.","fa":"نجات کوهنوردان چند ساعت طول کشید."},{"de":"In letzter Sekunde kam die Rettung.","en":"Rescue came at the last second.","ru":"Спасение пришло в последнюю секунду.","vi":"Sự giải cứu đến vào giây cuối cùng.","fa":"نجات در آخرین ثانیه آمد."}]},{"word":"das Rezept","en":"recipe; prescription","ru":"рецепт","vi":"công thức","fa":"دستور غذا","examples":[{"de":"Meine Oma hat mir ihr Rezept für Apfelkuchen gegeben.","en":"My grandma gave me her recipe for apple cake.","ru":"Бабушка дала мне свой рецепт яблочного пирога.","vi":"Bà tôi đã cho tôi công thức làm bánh táo của bà.","fa":"مادربزرگم دستور پای سیب را به من داد."},{"de":"Dieses Medikament bekommt man nur auf Rezept.","en":"You can only get this medicine with a prescription.","ru":"Это лекарство можно получить только по рецепту.","vi":"Thuốc này chỉ có sẵn với một toa thuốc.","fa":"این دارو فقط با نسخه در دسترس است."}]},{"word":"die Rezeption/Reception","en":"reception (desk)","ru":"стойка регистрации; ресепшн","vi":"sự đón tiếp/sự đón tiếp","fa":"پذیرش / پذیرایی","examples":[{"de":"Den Schlüssel bekommen Sie an der Rezeption.","en":"You will get the key at the reception.","ru":"Ключ вы получите на стойке регистрации.","vi":"Bạn có thể lấy chìa khóa tại quầy lễ tân.","fa":"می توانید کلید را در پذیرش دریافت کنید."},{"de":"Bitte melden Sie sich zuerst an der Reception.","en":"Please check in at reception first.","ru":"Пожалуйста, сначала обратитесь на ресепшн.","vi":"Vui lòng báo cáo cho lễ tân trước.","fa":"لطفا ابتدا به پذیرش گزارش دهید."}]},{"word":"der Richter","en":"judge","ru":"судья","vi":"thẩm phán","fa":"قاضی","examples":[{"de":"Der Richter entscheidet über den Fall.","en":"The judge decides the case.","ru":"Судья принимает решение по делу.","vi":"Thẩm phán quyết định vụ án.","fa":"قاضی در مورد پرونده تصمیم گیری می کند."},{"de":"Sie möchte später Richterin werden.","en":"She wants to become a judge later.","ru":"Позже она хочет стать судьёй.","vi":"Cô bé muốn trở thành thẩm phán khi lớn lên.","fa":"او می خواهد وقتی بزرگ شد قاضی شود."}]},{"word":"richtig","en":"correct; right","ru":"правильный","vi":"đúng","fa":"درست است","examples":[{"de":"Deine Antwort ist richtig.","en":"Your answer is correct.","ru":"Твой ответ правильный.","vi":"Câu trả lời của bạn là chính xác.","fa":"پاسخ شما درست است."},{"de":"Das war die richtige Entscheidung.","en":"That was the right decision.","ru":"Это было правильное решение.","vi":"Đó là quyết định đúng đắn.","fa":"این تصمیم درستی بود."}]},{"word":"die Richtung","en":"direction","ru":"направление","vi":"phương hướng","fa":"جهت","examples":[{"de":"Wir fahren in die falsche Richtung.","en":"We are driving in the wrong direction.","ru":"Мы едем в неправильном направлении.","vi":"Chúng ta đang đi sai hướng.","fa":"ما در مسیر اشتباهی می رویم."},{"de":"Können Sie mir die Richtung zum Bahnhof zeigen?","en":"Can you show me the direction to the train station?","ru":"Можете показать мне направление к вокзалу?","vi":"Bạn có thể chỉ cho tôi đường đến ga xe lửa được không?","fa":"آیا می توانید مسیر ایستگاه قطار را به من نشان دهید؟"}]},{"word":"riechen","en":"to smell","ru":"пахнуть; чувствовать запах","vi":"mùi","fa":"بو","examples":[{"de":"Die Blumen riechen sehr gut.","en":"The flowers smell very good.","ru":"Цветы очень хорошо пахнут.","vi":"Hoa có mùi rất thơm.","fa":"گلها بوی بسیار خوبی دارند."},{"de":"Ich rieche Rauch, brennt hier etwas?","en":"I smell smoke, is something burning here?","ru":"Я чувствую запах дыма, здесь что-то горит?","vi":"Tôi ngửi thấy mùi khói, có thứ gì đang cháy ở đây à?","fa":"بوی دود می دهم، چیزی اینجا می سوزد؟"}]},{"word":"riesig","en":"huge; enormous","ru":"огромный","vi":"to lớn","fa":"بزرگ","examples":[{"de":"Sie wohnen in einem riesigen Haus.","en":"They live in a huge house.","ru":"Они живут в огромном доме.","vi":"Họ sống trong một ngôi nhà lớn.","fa":"آنها در یک خانه بزرگ زندگی می کنند."},{"de":"Das war ein riesiger Erfolg.","en":"That was a huge success.","ru":"Это был огромный успех.","vi":"Đó là một thành công lớn.","fa":"این یک موفقیت بزرگ بود."}]},{"word":"das Rind","en":"cattle; beef","ru":"крупный рогатый скот; говядина","vi":"thịt bò","fa":"گوشت گاو","examples":[{"de":"Auf dem Bauernhof stehen viele Rinder auf der Weide.","en":"There are many cattle grazing on the farm.","ru":"На ферме на пастбище пасётся много коров.","vi":"Trong trang trại có rất nhiều gia súc đang chăn thả.","fa":"گاوهای زیادی در مزرعه در حال چرا هستند."},{"de":"Zum Abendessen gibt es Rind mit Kartoffeln.","en":"For dinner there is beef with potatoes.","ru":"На ужин говядина с картофелем.","vi":"Bữa tối có thịt bò với khoai tây.","fa":"برای شام گوشت گاو با سیب زمینی وجود دارد."}]},{"word":"der Ring","en":"ring","ru":"кольцо","vi":"chiếc nhẫn","fa":"حلقه","examples":[{"de":"Er hat ihr einen goldenen Ring geschenkt.","en":"He gave her a golden ring.","ru":"Он подарил ей золотое кольцо.","vi":"Anh tặng cô một chiếc nhẫn vàng.","fa":"یک انگشتر طلا به او داد."},{"de":"Sie trägt den Ring an der rechten Hand.","en":"She wears the ring on her right hand.","ru":"Она носит кольцо на правой руке.","vi":"Cô đeo chiếc nhẫn ở tay phải.","fa":"او حلقه را در دست راست خود می بندد."}]},{"word":"das Risiko","en":"risk","ru":"риск","vi":"rủi ro","fa":"خطر","examples":[{"de":"Das ist ein zu großes Risiko für mich.","en":"That is too big a risk for me.","ru":"Это слишком большой риск для меня.","vi":"Đó là một rủi ro quá lớn đối với tôi.","fa":"این برای من یک ریسک بزرگ است."},{"de":"Rauchen erhöht das Risiko für Krankheiten.","en":"Smoking increases the risk of diseases.","ru":"Курение повышает риск заболеваний.","vi":"Hút thuốc làm tăng nguy cơ mắc bệnh.","fa":"سیگار خطر ابتلا به بیماری را افزایش می دهد."}]},{"word":"der Rock","en":"skirt","ru":"юбка","vi":"váy","fa":"دامن","examples":[{"de":"Sie trägt einen kurzen Rock.","en":"She is wearing a short skirt.","ru":"Она носит короткую юбку.","vi":"Cô ấy đang mặc một chiếc váy ngắn.","fa":"او یک دامن کوتاه پوشیده است."},{"de":"Der Rock passt gut zu der Bluse.","en":"The skirt goes well with the blouse.","ru":"Юбка хорошо сочетается с блузкой.","vi":"Chiếc váy rất hợp với áo cánh.","fa":"دامن به خوبی با بلوز ست می شود."}]},{"word":"roh","en":"raw","ru":"сырой (необработанный)","vi":"thô","fa":"خام","examples":[{"de":"Man sollte kein rohes Fleisch essen.","en":"One should not eat raw meat.","ru":"Не следует есть сырое мясо.","vi":"Bạn không nên ăn thịt sống.","fa":"شما نباید گوشت خام بخورید."},{"de":"Das Gemüse schmeckt roh am besten.","en":"The vegetables taste best raw.","ru":"Овощи вкуснее всего в сыром виде.","vi":"Các loại rau có vị tươi ngon nhất.","fa":"طعم سبزیجات خام بهتر است."}]},{"word":"die Rolle","en":"role","ru":"роль","vi":"vai trò","fa":"نقش","examples":[{"de":"Er spielt die Hauptrolle in dem neuen Film.","en":"He plays the main role in the new film.","ru":"Он играет главную роль в новом фильме.","vi":"Anh đóng vai chính trong bộ phim mới.","fa":"او در فیلم جدید نقش اصلی را بازی می کند."},{"de":"Geld spielt für ihn keine große Rolle.","en":"Money doesn't play a big role for him.","ru":"Деньги не играют для него большой роли.","vi":"Tiền không đóng một vai trò lớn đối với anh ta.","fa":"پول برای او نقش چندانی ندارد."}]},{"word":"der Roman","en":"novel","ru":"роман (книга)","vi":"cuốn tiểu thuyết","fa":"رمان","examples":[{"de":"Ich lese gerade einen spannenden Roman.","en":"I am currently reading an exciting novel.","ru":"Я сейчас читаю увлекательный роман.","vi":"Tôi hiện đang đọc một cuốn tiểu thuyết thú vị.","fa":"در حال حاضر در حال خواندن یک رمان هیجان انگیز هستم."},{"de":"Sie hat ihren ersten Roman mit 25 Jahren veröffentlicht.","en":"She published her first novel at the age of 25.","ru":"Она опубликовала свой первый роман в 25 лет.","vi":"Cô xuất bản cuốn tiểu thuyết đầu tiên của mình ở tuổi 25.","fa":"او اولین رمان خود را در 25 سالگی منتشر کرد."}]},{"word":"die Rose","en":"rose","ru":"роза","vi":"hoa hồng","fa":"گل رز","examples":[{"de":"Er schenkte ihr einen Strauß roter Rosen.","en":"He gave her a bouquet of red roses.","ru":"Он подарил ей букет красных роз.","vi":"Anh tặng cô một bó hoa hồng đỏ.","fa":"او یک دسته گل رز قرمز به او داد."},{"de":"Im Garten blühen die Rosen im Juni.","en":"The roses bloom in the garden in June.","ru":"Розы в саду цветут в июне.","vi":"Hoa hồng nở trong vườn vào tháng Sáu.","fa":"گل های رز در ماه ژوئن در باغ شکوفا می شوند."}]},{"word":"rück-","en":"back-; return-","ru":"обратно-; назад-","vi":"quay lại-","fa":"پشت -","examples":[{"de":"Bitte geben Sie mir eine Rückmeldung, wenn Sie Zeit haben.","en":"Please give me feedback when you have time.","ru":"Пожалуйста, дайте мне обратную связь, когда у вас будет время.","vi":"Hãy cho tôi phản hồi khi bạn có thời gian.","fa":"لطفا در صورت داشتن وقت به من بازخورد بدهید."},{"de":"Nach dem Konzert machen wir uns auf den Rückweg.","en":"After the concert we head back.","ru":"После концерта мы отправляемся в обратный путь.","vi":"Sau buổi hòa nhạc, chúng tôi lên đường trở về.","fa":"بعد از کنسرت راه برگشت را طی می کنیم."}]},{"word":"der Rücken","en":"back (body part)","ru":"спина","vi":"mặt sau","fa":"پشت","examples":[{"de":"Mir tut der Rücken weh.","en":"My back hurts.","ru":"У меня болит спина.","vi":"Lưng tôi đau quá.","fa":"کمرم درد میکنه"},{"de":"Er trägt den Rucksack auf dem Rücken.","en":"He carries the backpack on his back.","ru":"Он несёт рюкзак на спине.","vi":"Anh ta đeo ba lô trên lưng.","fa":"او کوله پشتی را بر پشت خود حمل می کند."}]},{"word":"der Rucksack","en":"backpack","ru":"рюкзак","vi":"ba lô","fa":"کوله پشتی","examples":[{"de":"Er packt seinen Rucksack für die Wanderung.","en":"He is packing his backpack for the hike.","ru":"Он собирает рюкзак для похода.","vi":"Anh ấy xách ba lô lên để đi bộ đường dài.","fa":"او کوله پشتی خود را برای پیاده روی می بندد."},{"de":"Mein Rucksack ist heute sehr schwer.","en":"My backpack is very heavy today.","ru":"Сегодня мой рюкзак очень тяжёлый.","vi":"Ba lô của tôi hôm nay rất nặng.","fa":"کوله پشتی من امروز خیلی سنگین است."}]},{"word":"die Rücksicht","en":"consideration","ru":"внимание к другим; тактичность","vi":"sự cân nhắc","fa":"در نظر گرفتن","examples":[{"de":"Bitte nimm Rücksicht auf die anderen Gäste.","en":"Please be considerate of the other guests.","ru":"Пожалуйста, будь внимателен к другим гостям.","vi":"Xin hãy quan tâm đến những vị khách khác.","fa":"لطفا مراقب سایر مهمانان باشید."},{"de":"Er fährt ohne jede Rücksicht auf andere Verkehrsteilnehmer.","en":"He drives without any consideration for other road users.","ru":"Он ездит совершенно не считаясь с другими участниками движения.","vi":"Anh ta lái xe mà không quan tâm đến những người tham gia giao thông khác.","fa":"او بدون توجه به سایر کاربران جاده رانندگی می کند."}]},{"word":"rücksichtsvoll","en":"considerate; thoughtful","ru":"внимательный; тактичный","vi":"ân cần","fa":"با ملاحظه","examples":[{"de":"Bitte sei rücksichtsvoll gegenüber den Nachbarn.","en":"Please be considerate towards the neighbours.","ru":"Пожалуйста, будь внимателен к соседям.","vi":"Xin hãy quan tâm đến hàng xóm.","fa":"لطفا مراقب همسایه ها باشید"},{"de":"Ein rücksichtsvoller Fahrer bremst rechtzeitig.","en":"A considerate driver brakes in good time.","ru":"Тактичный водитель тормозит вовремя.","vi":"Một người lái xe ân cần phanh đúng lúc.","fa":"یک راننده با ملاحظه به موقع ترمز می کند."}]},{"word":"das Rüebli","en":"carrot (Swiss German)","ru":"морковь (швейцарский немецкий)","vi":"củ cà rốt","fa":"هویج","examples":[{"de":"In der Schweiz sagt man Rüebli statt Karotte.","en":"In Switzerland people say 'Rüebli' instead of 'Karotte'.","ru":"В Швейцарии говорят «Rüebli» вместо «Karotte».","vi":"Ở Thụy Sĩ họ nói cà rốt thay vì cà rốt.","fa":"در سوئیس به جای هویج هویج می گویند."},{"de":"Zum Znacht gibt es Rüeblisuppe.","en":"For dinner there is carrot soup.","ru":"На ужин суп из моркови.","vi":"Bữa tối có súp cà rốt.","fa":"برای شام سوپ هویج وجود دارد."}]},{"word":"rufen","en":"to call; to shout","ru":"звать; кричать","vi":"gọi","fa":"تماس بگیرید","examples":[{"de":"Die Mutter ruft die Kinder zum Essen.","en":"The mother calls the children to eat.","ru":"Мать зовёт детей есть.","vi":"Mẹ gọi các con đi ăn.","fa":"مادر بچه ها را صدا می کند که غذا بخورند."},{"de":"Er rief laut um Hilfe.","en":"He shouted loudly for help.","ru":"Он громко звал на помощь.","vi":"Anh lớn tiếng kêu cứu.","fa":"با صدای بلند کمک خواست."}]},{"word":"die Ruhe","en":"calm; quiet; rest","ru":"покой; тишина","vi":"sự bình tĩnh","fa":"آرامش","examples":[{"de":"Nach der Arbeit brauche ich etwas Ruhe.","en":"After work I need some rest.","ru":"После работы мне нужен покой.","vi":"Sau giờ làm việc tôi cần nghỉ ngơi.","fa":"بعد از کار به استراحت نیاز دارم."},{"de":"In der Bibliothek muss man Ruhe bewahren.","en":"You have to keep quiet in the library.","ru":"В библиотеке нужно соблюдать тишину.","vi":"You have to stay calm in the library.","fa":"شما باید در کتابخانه آرامش خود را حفظ کنید."}]},{"word":"rund","en":"round","ru":"круглый","vi":"tròn","fa":"گرد","examples":[{"de":"Der Tisch in der Küche ist rund.","en":"The table in the kitchen is round.","ru":"Стол на кухне круглый.","vi":"Der Tisch in der Küche ist rund.","fa":"میز آشپزخانه گرد است."},{"de":"Die Erde ist rund.","en":"The Earth is round.","ru":"Земля круглая.","vi":"Trái đất tròn.","fa":"زمین گرد است."}]},{"word":"die Runde","en":"round; lap","ru":"круг; раунд","vi":"vòng","fa":"دور","examples":[{"de":"Wir sind zwei Runden um den See gelaufen.","en":"We walked two laps around the lake.","ru":"Мы прошли два круга вокруг озера.","vi":"Chúng tôi đi dạo hai vòng quanh hồ.","fa":"دو دور دور دریاچه قدم زدیم."},{"de":"In der nächsten Runde spielen die besten zwei Teams gegeneinander.","en":"In the next round, the two best teams play against each other.","ru":"В следующем раунде две лучшие команды играют друг против друга.","vi":"Ở vòng tiếp theo, hai đội có thành tích tốt nhất sẽ đấu với nhau.","fa":"در دور بعد دو تیم برتر به مصاف یکدیگر می روند."}]},{"word":"die Rundfahrt","en":"sightseeing tour","ru":"экскурсия (обзорная поездка)","vi":"chuyến tham quan","fa":"تور","examples":[{"de":"Wir machen morgen eine Rundfahrt durch die Altstadt.","en":"Tomorrow we are going on a sightseeing tour through the old town.","ru":"Завтра мы едем на экскурсию по старому городу.","vi":"Ngày mai chúng ta sẽ đi tham quan phố cổ.","fa":"فردا یه گشتی در شهر قدیمی میزنیم."},{"de":"Die Rundfahrt mit dem Bus dauert zwei Stunden.","en":"The bus tour takes two hours.","ru":"Экскурсия на автобусе длится два часа.","vi":"Chuyến tham quan bằng xe buýt mất hai giờ.","fa":"تور با اتوبوس دو ساعت طول می کشد."}]},{"word":"runterwerfen","en":"to throw down (colloquial)","ru":"сбрасывать, скидывать вниз","vi":"throw down","fa":"انداختن پایین","examples":[{"de":"Wirf mir bitte die Schlüssel vom Balkon runter!","en":"Please throw the keys down to me from the balcony!","ru":"Скинь мне, пожалуйста, ключи с балкона!","vi":"Hãy ném cho tôi chìa khóa từ ban công!","fa":"لطفا کلیدها را از بالکن به من بیندازید!"},{"de":"Er hat seine Tasche einfach auf den Boden runtergeworfen.","en":"He just threw his bag down on the floor.","ru":"Он просто швырнул свою сумку на пол.","vi":"Anh ta vừa ném chiếc túi của mình xuống đất.","fa":"فقط کیفش را روی زمین انداخت."}]},{"word":"der Saal","en":"hall","ru":"зал","vi":"hội trường","fa":"سالن","examples":[{"de":"Die Konferenz findet im großen Saal statt.","en":"The conference takes place in the large hall.","ru":"Конференция проходит в большом зале.","vi":"Die Konferenz đã tìm thấy điều tuyệt vời nhất về Saal.","fa":"کنفرانس در سالن بزرگ برگزار می شود."},{"de":"Der Saal war bis auf den letzten Platz gefüllt.","en":"The hall was filled to the last seat.","ru":"Зал был заполнен до последнего места.","vi":"Der Saal war bis auf den letzten Platz gefüllt.","fa":"ظرفیت سالن پر شد."}]},{"word":"die Sache","en":"thing; matter","ru":"вещь; дело","vi":"điều đó","fa":"چیز","examples":[{"de":"Das ist eine wichtige Sache für mich.","en":"This is an important matter for me.","ru":"Это важное дело для меня.","vi":"Đây là một điều quan trọng đối với tôi.","fa":"این برای من یک چیز مهم است."},{"de":"Pack deine Sachen zusammen, wir müssen los.","en":"Pack your things together, we have to go.","ru":"Собери свои вещи, нам пора идти.","vi":"Hãy thu dọn đồ đạc của bạn, chúng ta phải đi.","fa":"وسایلت را جمع کن، باید برویم."}]},{"word":"der Sack","en":"sack; bag","ru":"мешок","vi":"cái túi","fa":"کیف","examples":[{"de":"Er trägt einen Sack Kartoffeln in den Keller.","en":"He carries a sack of potatoes into the cellar.","ru":"Он несёт мешок картошки в подвал.","vi":"Anh ta mang một bao khoai tây vào hầm.","fa":"او یک گونی سیب زمینی را به داخل سرداب می برد."},{"de":"Der Müll ist im Sack vor der Tür.","en":"The trash is in the bag in front of the door.","ru":"Мусор в мешке перед дверью.","vi":"Rác nằm trong túi trước cửa.","fa":"زباله ها در کیسه جلوی در هستند."}]},{"word":"der Saft","en":"juice","ru":"сок","vi":"nước trái cây","fa":"آب میوه","examples":[{"de":"Zum Frühstück trinke ich immer einen Saft.","en":"For breakfast I always drink a juice.","ru":"На завтрак я всегда пью сок.","vi":"Tôi luôn uống nước trái cây vào bữa sáng.","fa":"من همیشه برای صبحانه یک آب میوه می خورم."},{"de":"Dieser Apfelsaft schmeckt sehr frisch.","en":"This apple juice tastes very fresh.","ru":"Этот яблочный сок очень свежий на вкус.","vi":"Nước táo này có vị rất tươi.","fa":"این آب سیب طعم بسیار تازه ای دارد."}]},{"word":"sagen","en":"to say","ru":"говорить; сказать","vi":"nói","fa":"بگو","examples":[{"de":"Kannst du mir sagen, wie spät es ist?","en":"Can you tell me what time it is?","ru":"Можешь сказать мне, который час?","vi":"Bạn có thể cho tôi biết bây giờ là mấy giờ không?","fa":"میشه بگی ساعت چنده؟"},{"de":"Er hat nichts dazu gesagt.","en":"He didn't say anything about it.","ru":"Он ничего не сказал по этому поводу.","vi":"Anh ấy không nói gì về chuyện đó.","fa":"او چیزی در این مورد نگفت."}]},{"word":"die Saison","en":"season","ru":"сезон","vi":"mùa giải","fa":"فصل","examples":[{"de":"Im Sommer ist die Hauptsaison für Touristen.","en":"Summer is the main tourist season.","ru":"Лето — основной туристический сезон.","vi":"Mùa hè là mùa cao điểm của khách du lịch.","fa":"تابستان فصل اوج گردشگران است."},{"de":"Diese Früchte gibt es nur in der Saison.","en":"These fruits are only available in season.","ru":"Эти фрукты бывают только в сезон.","vi":"Những loại trái cây này chỉ có theo mùa.","fa":"این میوه ها فقط در فصل در دسترس هستند."}]},{"word":"der Salat","en":"salad; lettuce","ru":"салат","vi":"món salad","fa":"سالاد","examples":[{"de":"Ich hätte gern einen gemischten Salat.","en":"I would like a mixed salad.","ru":"Я бы хотел смешанный салат.","vi":"Tôi muốn một món salad trộn.","fa":"من یک سالاد مخلوط می خواهم."},{"de":"Im Garten wächst frischer Salat.","en":"Fresh lettuce is growing in the garden.","ru":"В саду растёт свежий салат.","vi":"Rau diếp tươi mọc trong vườn.","fa":"کاهوی تازه در باغ می روید."}]},{"word":"die Salbe","en":"ointment","ru":"мазь","vi":"thuốc mỡ","fa":"پماد","examples":[{"de":"Trag die Salbe zweimal täglich auf die Wunde auf.","en":"Apply the ointment to the wound twice a day.","ru":"Наноси мазь на рану дважды в день.","vi":"Bôi thuốc mỡ lên vết thương hai lần mỗi ngày.","fa":"پماد را دو بار در روز روی زخم بمالید."},{"de":"Der Arzt hat mir eine Salbe gegen die Schmerzen verschrieben.","en":"The doctor prescribed me an ointment for the pain.","ru":"Врач прописал мне мазь от боли.","vi":"Bác sĩ kê cho tôi một loại thuốc mỡ để giảm đau.","fa":"دکتر برای من پماد برای درد تجویز کرد."}]},{"word":"der Salon","en":"salon","ru":"салон","vi":"thẩm mỹ viện","fa":"سالن","examples":[{"de":"Sie lässt sich die Haare im Salon schneiden.","en":"She has her hair cut at the salon.","ru":"Она стрижётся в салоне.","vi":"Cô ấy cắt tóc ở tiệm.","fa":"او موهایش را در سالن کوتاه می کند."},{"de":"In der Stadt gibt es einen neuen Schönheitssalon.","en":"There is a new beauty salon in the city.","ru":"В городе открылся новый салон красоты.","vi":"Có một thẩm mỹ viện mới trong thị trấn.","fa":"یک سالن زیبایی جدید در شهر وجود دارد."}]},{"word":"das Salz","en":"salt","ru":"соль","vi":"muối","fa":"نمک","examples":[{"de":"Die Suppe braucht noch etwas Salz.","en":"The soup needs a bit more salt.","ru":"Супу нужно ещё немного соли.","vi":"Súp vẫn cần một chút muối.","fa":"سوپ همچنان به نمک کمی نیاز دارد."},{"de":"Bitte reich mir das Salz.","en":"Please pass me the salt.","ru":"Пожалуйста, передай мне соль.","vi":"Làm ơn đưa cho tôi muối.","fa":"لطفا نمک را به من بدهید"}]},{"word":"sammeln","en":"to collect","ru":"собирать","vi":"thu thập","fa":"جمع آوری کنید","examples":[{"de":"Als Kind habe ich Briefmarken gesammelt.","en":"As a child I collected stamps.","ru":"В детстве я собирал марки.","vi":"Tôi đã sưu tập tem khi còn nhỏ.","fa":"از بچگی تمبر جمع می کردم."},{"de":"Wir sammeln Geld für einen guten Zweck.","en":"We are collecting money for a good cause.","ru":"Мы собираем деньги на доброе дело.","vi":"Chúng tôi đang thu tiền vì một lý do chính đáng.","fa":"ما برای یک هدف خوب پول جمع می کنیم."}]},{"word":"sämtliche","en":"all; entire","ru":"все; весь","vi":"tất cả","fa":"همه","examples":[{"de":"Er hat sämtliche Bücher aus dem Regal genommen.","en":"He took all the books off the shelf.","ru":"Он взял все книги с полки.","vi":"Anh ấy lấy tất cả sách ra khỏi kệ.","fa":"همه کتاب ها را از قفسه برداشت."},{"de":"Sämtliche Mitarbeiter wurden über die Änderung informiert.","en":"All employees were informed about the change.","ru":"Все сотрудники были проинформированы об изменении.","vi":"Tất cả nhân viên đã được thông báo về sự thay đổi.","fa":"همه کارکنان در مورد تغییر مطلع شدند."}]},{"word":"der Sand","en":"sand","ru":"песок","vi":"cát","fa":"شن و ماسه","examples":[{"de":"Die Kinder spielen am Strand im Sand.","en":"The children are playing in the sand on the beach.","ru":"Дети играют в песке на пляже.","vi":"Những đứa trẻ đang chơi đùa trên bãi cát trên bãi biển.","fa":"بچه ها در شن های ساحل بازی می کنند."},{"de":"Der Wind wehte den Sand in unsere Augen.","en":"The wind blew sand into our eyes.","ru":"Ветер задувал песок нам в глаза.","vi":"Gió thổi cát bay vào mắt chúng tôi.","fa":"باد شن ها را در چشمانمان فرو برد."}]},{"word":"der Sänger","en":"singer","ru":"певец","vi":"ca sĩ","fa":"خواننده","examples":[{"de":"Der Sänger begeisterte das Publikum.","en":"The singer thrilled the audience.","ru":"Певец привёл публику в восторг.","vi":"Nam ca sĩ khiến khán giả thích thú.","fa":"این خواننده حضار را به وجد آورد."},{"de":"Sie ist eine bekannte Sängerin aus Österreich.","en":"She is a well-known singer from Austria.","ru":"Она известная певица из Австрии.","vi":"Cô là một ca sĩ nổi tiếng đến từ Áo.","fa":"او یک خواننده سرشناس اهل اتریش است."}]},{"word":"satt","en":"full (not hungry)","ru":"сытый","vi":"chán ngấy","fa":"خسته","examples":[{"de":"Danke, ich bin satt.","en":"Thanks, I'm full.","ru":"Спасибо, я сыт.","vi":"Cảm ơn, tôi no rồi.","fa":"ممنون من سیر شدم"},{"de":"Nach dem großen Essen waren alle satt.","en":"After the big meal everyone was full.","ru":"После обильной еды все были сыты.","vi":"Sau bữa ăn thịnh soạn, mọi người đều no nê.","fa":"بعد از غذای بزرگ همه سیر شدند."}]},{"word":"der Satz","en":"sentence","ru":"предложение (грамм.)","vi":"câu","fa":"جمله","examples":[{"de":"Bitte bilden Sie einen Satz mit diesem Wort.","en":"Please form a sentence with this word.","ru":"Пожалуйста, составьте предложение с этим словом.","vi":"Hãy đặt câu với từ này.","fa":"لطفا با این کلمه یک جمله بسازید."},{"de":"Dieser Satz ist grammatisch nicht richtig.","en":"This sentence is not grammatically correct.","ru":"Это предложение грамматически неправильное.","vi":"Câu này sai ngữ pháp.","fa":"این جمله از نظر گرامری نادرست است."}]},{"word":"sauber","en":"clean","ru":"чистый","vi":"sạch sẽ","fa":"تمیز کردن","examples":[{"de":"Die Küche ist wieder sauber.","en":"The kitchen is clean again.","ru":"Кухня снова чистая.","vi":"Nhà bếp sạch sẽ trở lại.","fa":"آشپزخانه دوباره تمیز است."},{"de":"Zieh bitte saubere Kleidung an.","en":"Please put on clean clothes.","ru":"Пожалуйста, надень чистую одежду.","vi":"Hãy mặc quần áo sạch sẽ.","fa":"لطفا لباس تمیز بپوشید"}]},{"word":"sauer","en":"sour; angry (informal)","ru":"кислый; сердитый (разг.)","vi":"chua","fa":"ترش","examples":[{"de":"Die Zitrone schmeckt sehr sauer.","en":"The lemon tastes very sour.","ru":"Лимон очень кислый на вкус.","vi":"chanh có vị rất chua.","fa":"طعم لیمو بسیار ترش است."},{"de":"Sie war sauer, weil er zu spät kam.","en":"She was annoyed because he came too late.","ru":"Она разозлилась, потому что он опоздал.","vi":"Cô tức giận vì anh đến muộn.","fa":"او عصبانی بود زیرا او دیر کرده بود."}]},{"word":"die Schachtel","en":"box","ru":"коробка; пачка","vi":"cái hộp","fa":"جعبه","examples":[{"de":"Er raucht eine Schachtel Zigaretten am Tag.","en":"He smokes a pack of cigarettes a day.","ru":"Он выкуривает пачку сигарет в день.","vi":"Anh ấy hút một gói thuốc lá mỗi ngày.","fa":"او روزی یک پاکت سیگار می کشد."},{"de":"Die Schokolade liegt in einer bunten Schachtel.","en":"The chocolate is in a colorful box.","ru":"Шоколад лежит в яркой коробке.","vi":"Sô cô la được đựng trong một chiếc hộp đầy màu sắc.","fa":"شکلات در یک جعبه رنگارنگ است."}]},{"word":"schade","en":"a pity; too bad","ru":"жаль","vi":"quá tệ","fa":"خیلی بد","examples":[{"de":"Schade, dass du nicht kommen kannst.","en":"It's a pity that you can't come.","ru":"Жаль, что ты не можешь прийти.","vi":"Thật tiếc là bạn không thể đến được.","fa":"حیف که نمیتونی بیای"},{"de":"Es wäre schade, das Konzert zu verpassen.","en":"It would be a shame to miss the concert.","ru":"Было бы жаль пропустить концерт.","vi":"Sẽ thật đáng tiếc nếu bỏ lỡ buổi hòa nhạc.","fa":"حیف است که کنسرت را از دست بدهیم."}]},{"word":"schaden","en":"to harm; to damage","ru":"вредить","vi":"làm hại","fa":"آسیب","examples":[{"de":"Rauchen schadet der Gesundheit.","en":"Smoking is harmful to your health.","ru":"Курение вредит здоровью.","vi":"Hút thuốc có hại cho sức khỏe của bạn.","fa":"سیگار برای سلامتی مضر است."},{"de":"Ein bisschen Bewegung schadet nie.","en":"A bit of exercise never hurts.","ru":"Немного физической активности никогда не помешает.","vi":"Một bài tập nhỏ không bao giờ đau.","fa":"کمی ورزش هرگز ضرری ندارد."}]},{"word":"schaffen","en":"to manage; to accomplish","ru":"успевать; справляться","vi":"tạo ra","fa":"ایجاد کنید","examples":[{"de":"Ich glaube, wir schaffen den Zug noch.","en":"I think we can still catch the train.","ru":"Я думаю, мы ещё успеем на поезд.","vi":"Tôi nghĩ chúng ta vẫn có thể di chuyển được.","fa":"فکر می کنم هنوز هم می توانیم حرکت کنیم."},{"de":"Sie hat die Prüfung mit Bravour geschafft.","en":"She passed the exam with flying colors.","ru":"Она блестяще сдала экзамен.","vi":"Cô đã vượt qua kỳ thi với thành tích xuất sắc.","fa":"او امتحان را با رنگ آمیزی پشت سر گذاشت."}]},{"word":"schalten","en":"to switch; to shift (gears)","ru":"переключать","vi":"chuyển đổi","fa":"سوئیچ","examples":[{"de":"Er muss beim Autofahren oft schalten.","en":"He often has to shift gears while driving.","ru":"Ему часто приходится переключать передачи во время вождения.","vi":"Anh ấy thường xuyên phải sang số khi lái xe.","fa":"او اغلب باید هنگام رانندگی دنده را عوض کند."},{"de":"Bitte schalte das Licht aus, wenn du gehst.","en":"Please switch off the light when you leave.","ru":"Пожалуйста, выключи свет, когда уйдёшь.","vi":"Vui lòng tắt đèn khi bạn rời đi.","fa":"لطفاً هنگام خروج چراغ ها را خاموش کنید."}]},{"word":"scharf","en":"sharp; spicy","ru":"острый","vi":"nhọn","fa":"تیز","examples":[{"de":"Das Messer ist sehr scharf.","en":"The knife is very sharp.","ru":"Нож очень острый.","vi":"Con dao rất sắc.","fa":"چاقو بسیار تیز است."},{"de":"Mir ist das Essen zu scharf.","en":"The food is too spicy for me.","ru":"Еда для меня слишком острая.","vi":"Thức ăn quá cay đối với tôi.","fa":"غذا برای من خیلی تند است."}]},{"word":"der Schatten","en":"shadow; shade","ru":"тень","vi":"cái bóng","fa":"سایه","examples":[{"de":"Wir setzen uns lieber in den Schatten.","en":"We prefer to sit in the shade.","ru":"Мы лучше сядем в тень.","vi":"Chúng tôi thích ngồi trong bóng râm hơn.","fa":"ما ترجیح می دهیم در سایه بنشینیم."},{"de":"Der Baum wirft einen langen Schatten.","en":"The tree casts a long shadow.","ru":"Дерево отбрасывает длинную тень.","vi":"Cây đổ bóng dài.","fa":"درخت سایه بلندی می اندازد."}]},{"word":"schätzen","en":"to estimate; to appreciate","ru":"оценивать; ценить","vi":"đánh giá cao","fa":"قدردانی","examples":[{"de":"Ich schätze sein Alter auf etwa vierzig Jahre.","en":"I estimate his age to be about forty years.","ru":"Я оцениваю его возраст примерно в сорок лет.","vi":"Tôi ước chừng tuổi của anh ấy khoảng bốn mươi tuổi.","fa":"سن او را حدود چهل سال تخمین می زنم."},{"de":"Ich schätze deine Hilfe sehr.","en":"I really appreciate your help.","ru":"Я очень ценю твою помощь.","vi":"Tôi thực sự đánh giá cao sự giúp đỡ của bạn.","fa":"من واقعا از کمک شما قدردانی می کنم."}]},{"word":"schauen","en":"to look","ru":"смотреть","vi":"nhìn","fa":"نگاه کن","examples":[{"de":"Schau mal, wie schön der Sonnenuntergang ist!","en":"Look how beautiful the sunset is!","ru":"Смотри, какой красивый закат!","vi":"Hãy nhìn hoàng hôn đẹp làm sao!","fa":"ببین غروب چقدر زیباست"},{"de":"Er schaut jeden Abend die Nachrichten.","en":"He watches the news every evening.","ru":"Он каждый вечер смотрит новости.","vi":"Anh ấy xem tin tức mỗi tối.","fa":"او هر روز عصر اخبار را تماشا می کند."}]},{"word":"der Schauspieler","en":"actor","ru":"актёр","vi":"diễn viên","fa":"بازیگر","examples":[{"de":"Er ist ein bekannter Schauspieler aus Deutschland.","en":"He is a well-known actor from Germany.","ru":"Он известный актёр из Германии.","vi":"Anh là một diễn viên nổi tiếng đến từ Đức.","fa":"او بازیگر سرشناس آلمانی است."},{"de":"Der Schauspieler spielte seine Rolle sehr überzeugend.","en":"The actor played his role very convincingly.","ru":"Актёр очень убедительно сыграл свою роль.","vi":"Nam diễn viên đã nhập vai rất thuyết phục.","fa":"این بازیگر نقش خود را بسیار متقاعد کننده بازی کرد."}]},{"word":"die Scheibe","en":"slice; (window) pane","ru":"ломтик; стекло (оконное)","vi":"cái đĩa","fa":"دیسک","examples":[{"de":"Ich hätte gern noch eine Scheibe Brot.","en":"I would like another slice of bread.","ru":"Я бы хотел ещё один ломтик хлеба.","vi":"Tôi muốn một lát bánh mì nữa.","fa":"من یک تکه نان دیگر می خواهم."},{"de":"Die Scheibe des Fensters ist zerbrochen.","en":"The window pane is broken.","ru":"Оконное стекло разбито.","vi":"Ô cửa sổ bị vỡ.","fa":"شیشه پنجره شکسته است."}]},{"word":"die Scheidung","en":"divorce","ru":"развод","vi":"vụ ly hôn","fa":"طلاق","examples":[{"de":"Die Scheidung wurde vor Gericht ausgesprochen.","en":"The divorce was granted in court.","ru":"Развод был оформлен в суде.","vi":"Việc ly hôn được công bố tại tòa án.","fa":"طلاق در دادگاه اعلام شد."},{"de":"Nach der Scheidung blieben sie trotzdem Freunde.","en":"After the divorce they still remained friends.","ru":"После развода они всё же остались друзьями.","vi":"Sau khi ly hôn, họ vẫn là bạn bè.","fa":"پس از طلاق، آنها همچنان دوست بودند."}]},{"word":"der Schein","en":"certificate; banknote; glow/light","ru":"справка; банкнота; свет/сияние","vi":"sự xuất hiện","fa":"ظاهر","examples":[{"de":"Er hat mir einen Fünfzig-Euro-Schein gegeben.","en":"He gave me a fifty-euro note.","ru":"Он дал мне купюру в пятьдесят евро.","vi":"Anh ấy đưa cho tôi tờ năm mươi euro.","fa":"یک اسکناس پنجاه یورویی به من داد."},{"de":"Im Schein der Kerze konnten wir kaum lesen.","en":"In the glow of the candle we could hardly read.","ru":"При свете свечи мы едва могли читать.","vi":"Chúng tôi hầu như không thể đọc được dưới ánh nến.","fa":"در نور شمع به سختی می توانستیم بخوانیم."}]},{"word":"scheinen","en":"to seem; to shine","ru":"казаться; светить","vi":"dường như","fa":"به نظر می رسد","examples":[{"de":"Die Sonne scheint heute den ganzen Tag.","en":"The sun is shining all day today.","ru":"Сегодня солнце светит весь день.","vi":"Hôm nay mặt trời chiếu sáng cả ngày.","fa":"امروز تمام روز خورشید می درخشد."},{"de":"Es scheint, dass er nicht kommen wird.","en":"It seems that he won't come.","ru":"Кажется, что он не придёт.","vi":"Có vẻ như anh ấy sẽ không đến.","fa":"انگار نمیاد"}]},{"word":"scheitern","en":"to fail","ru":"терпеть неудачу; проваливаться","vi":"thất bại","fa":"شکست بخورد","examples":[{"de":"Das Projekt ist am Geld gescheitert.","en":"The project failed because of money.","ru":"Проект провалился из-за денег.","vi":"Dự án thất bại vì tiền.","fa":"این پروژه به دلیل پول شکست خورد."},{"de":"Auch wenn du scheiterst, solltest du es weiter versuchen.","en":"Even if you fail, you should keep trying.","ru":"Даже если ты потерпишь неудачу, стоит продолжать пытаться.","vi":"Ngay cả khi bạn thất bại, bạn vẫn nên tiếp tục cố gắng.","fa":"حتی اگر شکست خوردید، باید به تلاش ادامه دهید."}]},{"word":"schenken","en":"to give (as a gift)","ru":"дарить","vi":"cho","fa":"دادن","examples":[{"de":"Zum Geburtstag schenke ich ihr ein Buch.","en":"For her birthday I'm giving her a book.","ru":"На день рождения я подарю ей книгу.","vi":"Tôi đang tặng cô ấy một cuốn sách vào ngày sinh nhật của cô ấy.","fa":"برای تولدش به او کتاب می دهم."},{"de":"Was schenkst du deinem Vater zu Weihnachten?","en":"What are you giving your father for Christmas?","ru":"Что ты подаришь отцу на Рождество?","vi":"Bạn sẽ tặng gì cho bố vào dịp Giáng sinh?","fa":"برای کریسمس چه چیزی برای پدرت می گیری؟"}]},{"word":"die Schere","en":"scissors","ru":"ножницы","vi":"cái kéo","fa":"قیچی","examples":[{"de":"Ich brauche eine Schere, um das Papier zu schneiden.","en":"I need scissors to cut the paper.","ru":"Мне нужны ножницы, чтобы разрезать бумагу.","vi":"Tôi cần kéo để cắt giấy.","fa":"برای بریدن کاغذ به قیچی نیاز دارم."},{"de":"Die Schere liegt in der Schublade.","en":"The scissors are in the drawer.","ru":"Ножницы лежат в ящике.","vi":"Chiếc kéo đang ở trong ngăn kéo.","fa":"قیچی در کشو است."}]},{"word":"schicken","en":"to send","ru":"отправлять","vi":"gửi","fa":"ارسال کنید","examples":[{"de":"Ich schicke dir die Fotos per E-Mail.","en":"I'll send you the photos by email.","ru":"Я отправлю тебе фотографии по электронной почте.","vi":"Tôi sẽ gửi cho bạn những bức ảnh qua email.","fa":"عکس ها رو برات ایمیل میکنم"},{"de":"Er hat mir gestern eine Nachricht geschickt.","en":"He sent me a message yesterday.","ru":"Вчера он отправил мне сообщение.","vi":"Anh ấy đã gửi cho tôi một tin nhắn ngày hôm qua.","fa":"دیروز به من پیام داد."}]},{"word":"schieben","en":"to push","ru":"толкать","vi":"đẩy","fa":"فشار دهید","examples":[{"de":"Wir müssen das Auto schieben, der Motor springt nicht an.","en":"We have to push the car, the engine won't start.","ru":"Нам нужно толкать машину, двигатель не заводится.","vi":"Chúng ta phải đẩy xe, máy không nổ.","fa":"ما باید ماشین را فشار دهیم، موتور روشن نمی شود."},{"de":"Sie schiebt den Kinderwagen durch den Park.","en":"She is pushing the stroller through the park.","ru":"Она катит коляску по парку.","vi":"Cô đẩy xe đẩy qua công viên.","fa":"او کالسکه را در پارک هل می دهد."}]},{"word":"schief","en":"crooked; tilted","ru":"кривой; косой","vi":"quanh co","fa":"کج","examples":[{"de":"Das Bild an der Wand hängt schief.","en":"The picture on the wall is hanging crooked.","ru":"Картина на стене висит криво.","vi":"Bức tranh trên tường bị cong.","fa":"عکس روی دیوار کج است."},{"de":"Der alte Zaun steht ganz schief.","en":"The old fence is standing quite crooked.","ru":"Старый забор стоит совсем криво.","vi":"Hàng rào cũ cong queo.","fa":"حصار قدیمی کج است."}]},{"word":"schießen","en":"to shoot","ru":"стрелять","vi":"bắn","fa":"شلیک کنید","examples":[{"de":"Der Jäger hat auf das Tier geschossen.","en":"The hunter shot at the animal.","ru":"Охотник выстрелил в животное.","vi":"Người thợ săn đã bắn con vật.","fa":"شکارچی به حیوان شلیک کرد."},{"de":"Der Spieler schoss das entscheidende Tor.","en":"The player scored the decisive goal.","ru":"Игрок забил решающий гол.","vi":"Cầu thủ này đã ghi bàn thắng quyết định.","fa":"این بازیکن گل تعیین کننده را به ثمر رساند."}]},{"word":"das Schiff","en":"ship","ru":"корабль","vi":"con tàu","fa":"کشتی","examples":[{"de":"Das Schiff fährt von Hamburg nach New York.","en":"The ship sails from Hamburg to New York.","ru":"Корабль плывёт из Гамбурга в Нью-Йорк.","vi":"Con tàu đi từ Hamburg đến New York.","fa":"این کشتی از هامبورگ به نیویورک سفر می کند."},{"de":"Wir machten eine Reise mit einem großen Schiff.","en":"We took a trip on a big ship.","ru":"Мы совершили путешествие на большом корабле.","vi":"Chúng tôi đã có một chuyến đi trên một con tàu lớn.","fa":"با یک کشتی بزرگ به سفر رفتیم."}]},{"word":"das Schild","en":"sign","ru":"табличка; знак","vi":"dấu hiệu","fa":"علامت","examples":[{"de":"An der Tür hängt ein Schild mit den Öffnungszeiten.","en":"There is a sign on the door with the opening hours.","ru":"На двери висит табличка с часами работы.","vi":"Trên cửa có tấm bảng ghi giờ mở cửa.","fa":"روی در تابلویی با ساعات کار وجود دارد."},{"de":"Beachte das Verkehrsschild an der Kreuzung.","en":"Pay attention to the traffic sign at the intersection.","ru":"Обрати внимание на дорожный знак на перекрёстке.","vi":"Hãy chú ý biển báo giao thông ở ngã tư.","fa":"به تابلوی راهنمایی و رانندگی در تقاطع توجه کنید."}]},{"word":"schimpfen","en":"to scold; to grumble","ru":"ругать(ся); браниться","vi":"la mắng","fa":"سرزنش کردن","examples":[{"de":"Die Mutter schimpft mit dem Kind, weil es die Regel gebrochen hat.","en":"The mother scolds the child because it broke the rule.","ru":"Мать ругает ребёнка за то, что он нарушил правило.","vi":"Mẹ mắng con vì vi phạm nội quy.","fa":"مادر کودک را به خاطر قانون شکنی سرزنش می کند."},{"de":"Er schimpft immer über das schlechte Wetter.","en":"He always grumbles about the bad weather.","ru":"Он всегда ворчит из-за плохой погоды.","vi":"Anh ấy luôn phàn nàn về thời tiết xấu.","fa":"او همیشه از بدی آب و هوا شاکی است."}]},{"word":"der Schinken","en":"ham","ru":"ветчина","vi":"giăm bông","fa":"ژامبون","examples":[{"de":"Ich hätte gern ein Brötchen mit Schinken.","en":"I would like a roll with ham.","ru":"Я бы хотел булочку с ветчиной.","vi":"Tôi muốn một cuộn với giăm bông.","fa":"من یک رول با ژامبون می خواهم."},{"de":"Der Schinken wird in dünne Scheiben geschnitten.","en":"The ham is cut into thin slices.","ru":"Ветчину нарезают тонкими ломтиками.","vi":"Thịt giăm bông được cắt thành lát mỏng.","fa":"ژامبون به برش های نازک بریده می شود."}]},{"word":"der Schirm","en":"umbrella","ru":"зонт","vi":"chiếc ô","fa":"چتر","examples":[{"de":"Nimm deinen Schirm mit, es könnte regnen.","en":"Take your umbrella with you, it might rain.","ru":"Возьми зонт, может пойти дождь.","vi":"Hãy mang theo chiếc ô của bạn, trời có thể sẽ mưa.","fa":"چتر خود را با خود ببرید، ممکن است باران ببارد."},{"de":"Der Wind hat meinen Schirm kaputt gemacht.","en":"The wind broke my umbrella.","ru":"Ветер сломал мой зонт.","vi":"Gió làm gãy chiếc ô của tôi.","fa":"باد چترم را شکست."}]},{"word":"schlagen","en":"to hit; to beat","ru":"бить; ударять","vi":"đánh","fa":"ضربه بزنید","examples":[{"de":"Man darf keine anderen Menschen schlagen.","en":"You must not hit other people.","ru":"Нельзя бить других людей.","vi":"Bạn không nên đánh người khác.","fa":"نباید دیگران را بزنی"},{"de":"Unsere Mannschaft hat das andere Team klar geschlagen.","en":"Our team clearly beat the other team.","ru":"Наша команда явно обыграла другую команду.","vi":"Đội của chúng tôi rõ ràng đã đánh bại đội kia.","fa":"تیم ما به وضوح تیم دیگر را شکست داد."}]},{"word":"die Schlange","en":"snake; (also) queue","ru":"змея; очередь","vi":"con rắn","fa":"مار","examples":[{"de":"Im Zoo haben wir eine große Schlange gesehen.","en":"At the zoo we saw a big snake.","ru":"В зоопарке мы видели большую змею.","vi":"Chúng tôi nhìn thấy một con rắn lớn ở sở thú.","fa":"ما یک مار بزرگ را در باغ وحش دیدیم."},{"de":"Vor der Kasse stand eine lange Schlange.","en":"There was a long queue in front of the checkout.","ru":"У кассы стояла длинная очередь.","vi":"Có một hàng dài trước quầy thanh toán.","fa":"یک صف طولانی جلوی صندوق بود."}]},{"word":"schlank","en":"slim","ru":"стройный","vi":"mảnh khảnh","fa":"باریک","examples":[{"de":"Sie ist groß und schlank.","en":"She is tall and slim.","ru":"Она высокая и стройная.","vi":"Cô ấy cao và mảnh khảnh.","fa":"او قد بلند و لاغر است."},{"de":"Er treibt viel Sport, um schlank zu bleiben.","en":"He does a lot of sports to stay slim.","ru":"Он много занимается спортом, чтобы оставаться стройным.","vi":"Anh ấy chơi rất nhiều môn thể thao để giữ dáng.","fa":"او برای لاغر ماندن ورزش های زیادی انجام می دهد."}]},{"word":"schlecht","en":"bad","ru":"плохой","vi":"tệ","fa":"بد","examples":[{"de":"Das Essen im Restaurant hat schlecht geschmeckt.","en":"The food in the restaurant tasted bad.","ru":"Еда в ресторане была невкусной.","vi":"Đồ ăn trong nhà hàng có vị rất tệ.","fa":"غذای رستوران مزه بدی داشت."},{"de":"Mir geht es heute schlecht, ich bleibe zu Hause.","en":"I feel bad today, I'm staying home.","ru":"Сегодня я плохо себя чувствую, я останусь дома.","vi":"Hôm nay tôi cảm thấy tồi tệ, tôi đang ở nhà.","fa":"امروز حالم بد است، در خانه می مانم."}]},{"word":"schließen","en":"to close","ru":"закрывать","vi":"đóng","fa":"بستن","examples":[{"de":"Bitte schließen Sie die Tür, es zieht.","en":"Please close the door, there's a draft.","ru":"Пожалуйста, закройте дверь, дует.","vi":"Hãy đóng cửa lại, có gió lùa.","fa":"لطفا در را ببندید، پیش نویس وجود دارد."},{"de":"Das Geschäft schließt um achtzehn Uhr.","en":"The shop closes at six p.m.","ru":"Магазин закрывается в шесть часов вечера.","vi":"Cửa hàng đóng cửa lúc 6 giờ chiều.","fa":"ساعت 6 عصر مغازه بسته می شود."}]},{"word":"schließlich","en":"finally; after all","ru":"наконец; в конце концов","vi":"cuối cùng","fa":"در نهایت","examples":[{"de":"Nach langer Suche fanden wir schließlich einen Parkplatz.","en":"After a long search, we finally found a parking spot.","ru":"После долгих поисков мы наконец нашли парковочное место.","vi":"Sau một hồi tìm kiếm cuối cùng chúng tôi cũng tìm được chỗ đậu xe.","fa":"بعد از جستجوی طولانی بالاخره یک جای پارک پیدا کردیم."},{"de":"Du solltest ihm helfen, schließlich ist er dein Bruder.","en":"You should help him, after all, he's your brother.","ru":"Тебе следует помочь ему, ведь он твой брат.","vi":"Bạn nên giúp anh ấy, dù sao anh ấy cũng là anh trai của bạn.","fa":"شما باید به او کمک کنید، بالاخره او برادر شماست."}]},{"word":"schlimm","en":"bad; serious","ru":"плохой; серьёзный","vi":"tệ","fa":"بد","examples":[{"de":"Der Unfall war nicht so schlimm, wie wir dachten.","en":"The accident wasn't as bad as we thought.","ru":"Авария оказалась не такой серьёзной, как мы думали.","vi":"Tai nạn không tệ như chúng ta tưởng.","fa":"تصادف آنقدرها هم که فکر می کردیم بد نبود."},{"de":"Es ist schlimm, dass so viele Menschen keine Arbeit haben.","en":"It's bad that so many people don't have a job.","ru":"Плохо, что у стольких людей нет работы.","vi":"Thật tệ khi có quá nhiều người không có việc làm.","fa":"بد است که بسیاری از مردم شغل ندارند."}]},{"word":"das Schloss","en":"castle; lock","ru":"замок (крепость / устройство)","vi":"lâu đài","fa":"قلعه","examples":[{"de":"Wir haben am Wochenende ein altes Schloss besichtigt.","en":"We visited an old castle at the weekend.","ru":"На выходных мы осмотрели старый замок.","vi":"Chúng tôi đến thăm một lâu đài cổ vào cuối tuần.","fa":"آخر هفته از یک قلعه قدیمی بازدید کردیم."},{"de":"Das Schloss an der Tür ist kaputt.","en":"The lock on the door is broken.","ru":"Замок на двери сломан.","vi":"Ổ khóa trên cửa bị hỏng.","fa":"قفل در شکسته است."}]},{"word":"der Schluss","en":"end; conclusion","ru":"конец; заключение","vi":"kết luận","fa":"نتیجه گیری","examples":[{"de":"Am Schluss des Films weinten alle Zuschauer.","en":"At the end of the film, all the viewers cried.","ru":"В конце фильма все зрители плакали.","vi":"Cuối phim, tất cả khán giả đều khóc.","fa":"در پایان فیلم همه حاضران گریه می کردند."},{"de":"Zum Schluss möchte ich mich bei allen bedanken.","en":"In conclusion, I would like to thank everyone.","ru":"В заключение я хочу поблагодарить всех.","vi":"Cuối cùng tôi xin gửi lời cảm ơn tới tất cả mọi người.","fa":"در پایان از همه تشکر می کنم."}]},{"word":"der Schlüssel","en":"key","ru":"ключ","vi":"chìa khóa","fa":"کلید","examples":[{"de":"Ich habe meinen Schlüssel verloren und komme nicht in die Wohnung.","en":"I lost my key and can't get into the apartment.","ru":"Я потерял ключ и не могу попасть в квартиру.","vi":"Tôi bị mất chìa khóa và không thể vào căn hộ.","fa":"کلیدم را گم کردم و نمی توانم وارد آپارتمان شوم."},{"de":"Kannst du mir bitte den Schlüssel für das Büro geben?","en":"Can you please give me the key to the office?","ru":"Можешь дать мне ключ от офиса?","vi":"Bạn có thể vui lòng đưa cho tôi chìa khóa văn phòng được không?","fa":"میشه لطفا کلید دفتر را به من بدهید؟"}]},{"word":"schmal","en":"narrow","ru":"узкий","vi":"thu hẹp","fa":"باریک","examples":[{"de":"Die Straße in der Altstadt ist sehr schmal.","en":"The street in the old town is very narrow.","ru":"Улица в старом городе очень узкая.","vi":"Đường phố trong phố cổ rất hẹp.","fa":"خیابان در شهر قدیمی بسیار باریک است."},{"de":"Er trägt gern schmale Hosen.","en":"He likes to wear narrow trousers.","ru":"Он любит носить узкие брюки.","vi":"Anh ấy thích mặc quần mỏng.","fa":"او دوست دارد شلوار باریک بپوشد."}]},{"word":"schmecken","en":"to taste","ru":"быть на вкус; нравиться на вкус","vi":"hương vị","fa":"طعم","examples":[{"de":"Die Suppe schmeckt sehr lecker.","en":"The soup tastes very delicious.","ru":"Суп очень вкусный.","vi":"Súp có vị rất ngon.","fa":"طعم سوپ بسیار خوشمزه است."},{"de":"Schmeckt dir der Kuchen?","en":"Do you like the taste of the cake?","ru":"Тебе нравится вкус торта?","vi":"Bạn có thích bánh không?","fa":"کیک رو دوست داری؟"}]},{"word":"der Schmerz","en":"pain","ru":"боль","vi":"nỗi đau","fa":"درد","examples":[{"de":"Sie hat starke Schmerzen im Rücken.","en":"She has severe pain in her back.","ru":"У неё сильные боли в спине.","vi":"Cô ấy bị đau nặng ở lưng.","fa":"او درد شدیدی در کمر دارد."},{"de":"Nimm eine Tablette gegen den Schmerz.","en":"Take a pill for the pain.","ru":"Прими таблетку от боли.","vi":"Uống một viên thuốc để giảm đau.","fa":"برای درد قرص بخور"}]},{"word":"schminken","en":"to put on makeup","ru":"краситься, наносить макияж","vi":"trang điểm","fa":"آرایش کردن","examples":[{"de":"Sie schminkt sich jeden Morgen vor der Arbeit.","en":"She puts on makeup every morning before work.","ru":"Она красится каждое утро перед работой.","vi":"Cô ấy trang điểm vào mỗi buổi sáng trước khi đi làm.","fa":"او هر روز صبح قبل از کار آرایش می کند."},{"de":"Für die Party hat sie sich besonders schön geschminkt.","en":"For the party, she did her makeup especially nicely.","ru":"Для вечеринки она сделала особенно красивый макияж.","vi":"Cô trang điểm đặc biệt xinh đẹp cho bữa tiệc.","fa":"او برای مهمانی آرایش زیبایی انجام داد."}]},{"word":"der Schmuck","en":"jewelry","ru":"украшения","vi":"đồ trang sức","fa":"جواهرات","examples":[{"de":"Meine Großmutter hat mir wertvollen Schmuck geschenkt.","en":"My grandmother gave me valuable jewelry.","ru":"Бабушка подарила мне ценные украшения.","vi":"Bà tôi đã cho tôi đồ trang sức có giá trị.","fa":"مادربزرگم جواهرات ارزشمندی به من داد."},{"de":"Sie trägt gern goldenen Schmuck.","en":"She likes to wear gold jewelry.","ru":"Она любит носить золотые украшения.","vi":"Cô ấy thích đeo đồ trang sức bằng vàng.","fa":"او دوست دارد جواهرات طلا بپوشد."}]},{"word":"der Schmutz","en":"dirt","ru":"грязь","vi":"bụi bẩn","fa":"خاک","examples":[{"de":"Nach der Arbeit im Garten war seine Kleidung voller Schmutz.","en":"After working in the garden, his clothes were full of dirt.","ru":"После работы в саду его одежда была вся в грязи.","vi":"Sau khi làm vườn xong, quần áo của ông đầy bụi bẩn.","fa":"بعد از کار در باغ لباس هایش پر از خاک بود."},{"de":"Bitte putz den Schmutz von deinen Schuhen ab.","en":"Please clean the dirt off your shoes.","ru":"Пожалуйста, очисти грязь с обуви.","vi":"Hãy làm sạch bụi bẩn trên giày của bạn.","fa":"لطفا کثیفی کفش هایتان را پاک کنید."}]},{"word":"der Schnee","en":"snow","ru":"снег","vi":"tuyết","fa":"برف","examples":[{"de":"Im Winter liegt hier oft viel Schnee.","en":"In winter, there is often a lot of snow here.","ru":"Зимой здесь часто лежит много снега.","vi":"Ở đây thường có rất nhiều tuyết vào mùa đông.","fa":"اغلب در زمستان اینجا برف زیادی می بارد."},{"de":"Die Kinder spielen gern im Schnee.","en":"The children like to play in the snow.","ru":"Дети любят играть в снегу.","vi":"Trẻ em thích chơi trong tuyết.","fa":"بچه ها دوست دارند در برف بازی کنند."}]},{"word":"schneien","en":"to snow","ru":"идти (о снеге)","vi":"tuyết","fa":"برف","examples":[{"de":"Draußen schneit es schon seit dem Morgen.","en":"It has been snowing outside since morning.","ru":"На улице идёт снег с самого утра.","vi":"Ngoài trời tuyết đã rơi từ sáng.","fa":"از صبح بیرون برف می بارد."},{"de":"Im Dezember schneit es hier meistens.","en":"In December, it usually snows here.","ru":"В декабре здесь обычно идёт снег.","vi":"Ở đây thường có tuyết vào tháng 12.","fa":"معمولاً در ماه دسامبر اینجا برف می بارد."}]},{"word":"schnell","en":"fast; quickly","ru":"быстрый; быстро","vi":"nhanh chóng","fa":"به سرعت","examples":[{"de":"Er fährt immer sehr schnell mit dem Auto.","en":"He always drives the car very fast.","ru":"Он всегда очень быстро водит машину.","vi":"Anh ấy luôn lái xe rất nhanh.","fa":"او همیشه ماشینش را خیلی سریع می راند."},{"de":"Komm schnell, der Bus fährt gleich ab!","en":"Come quickly, the bus is about to leave!","ru":"Иди быстрее, автобус вот-вот уедет!","vi":"Hãy đến nhanh lên, xe buýt sắp rời đi rồi!","fa":"سریع بیا، اتوبوس به زودی می رود!"}]},{"word":"das Schnitzel","en":"schnitzel (breaded cutlet)","ru":"шницель","vi":"schnitzel","fa":"شنیسل","examples":[{"de":"Wir haben im Restaurant ein Wiener Schnitzel bestellt.","en":"We ordered a Wiener schnitzel at the restaurant.","ru":"Мы заказали в ресторане венский шницель.","vi":"Chúng tôi gọi món Wiener Schnitzel trong nhà hàng.","fa":"ما یک وینر شنیتسل در رستوران سفارش دادیم."},{"de":"Das Schnitzel wird meistens mit Pommes serviert.","en":"Schnitzel is usually served with fries.","ru":"Шницель обычно подают с картофелем фри.","vi":"Schnitzel thường được ăn kèm với khoai tây chiên.","fa":"شنیسل معمولا با سیب زمینی سرخ شده سرو می شود."}]},{"word":"der Schnupfen","en":"cold (runny nose)","ru":"насморк","vi":"cái lạnh","fa":"سرما","examples":[{"de":"Ich habe einen Schnupfen und kann kaum atmen.","en":"I have a cold and can hardly breathe.","ru":"У меня насморк, я едва могу дышать.","vi":"Tôi bị cảm lạnh và khó thở.","fa":"سرما خورده ام و به سختی نفس می کشم."},{"de":"Bei diesem Wetter bekommt man leicht einen Schnupfen.","en":"In this weather, you easily catch a cold.","ru":"В такую погоду легко подхватить насморк.","vi":"Thời tiết này rất dễ bị cảm lạnh.","fa":"سرماخوردگی در این هوا آسان است."}]},{"word":"die Schokolade","en":"chocolate","ru":"шоколад","vi":"sô cô la","fa":"شکلات","examples":[{"de":"Die Kinder essen sehr gern Schokolade.","en":"The children really like eating chocolate.","ru":"Дети очень любят есть шоколад.","vi":"Bọn trẻ thực sự thích ăn sôcôla.","fa":"بچه ها خیلی دوست دارند شکلات بخورند."},{"de":"Ich habe ihr eine Tafel Schokolade zum Geburtstag geschenkt.","en":"I gave her a bar of chocolate for her birthday.","ru":"Я подарил ей плитку шоколада на день рождения.","vi":"Tôi đã tặng cô ấy một thanh sô cô la vào ngày sinh nhật của cô ấy.","fa":"برای تولدش یک شکلات به او دادم."}]},{"word":"schon","en":"already","ru":"уже","vi":"rồi","fa":"در حال حاضر","examples":[{"de":"Ich habe die Hausaufgaben schon gemacht.","en":"I have already done my homework.","ru":"Я уже сделал домашнее задание.","vi":"Tôi đã làm xong bài tập về nhà rồi.","fa":"من قبلاً تکالیفم را انجام داده ام."},{"de":"Bist du schon fertig?","en":"Are you already finished?","ru":"Ты уже закончил?","vi":"Bạn đã sẵn sàng chưa?","fa":"هنوز آماده ای؟"}]},{"word":"schön","en":"beautiful; nice","ru":"красивый; хороший","vi":"đẹp","fa":"زیبا","examples":[{"de":"Das Wetter ist heute wirklich schön.","en":"The weather is really nice today.","ru":"Погода сегодня действительно прекрасная.","vi":"Thời tiết hôm nay thật sự rất đẹp.","fa":"امروز هوا واقعا خوبه"},{"de":"Sie hat ein sehr schönes Kleid gekauft.","en":"She bought a very beautiful dress.","ru":"Она купила очень красивое платье.","vi":"Cô ấy đã mua một chiếc váy rất đẹp.","fa":"او یک لباس بسیار زیبا خرید."}]},{"word":"der Schrank","en":"cupboard; wardrobe","ru":"шкаф","vi":"tủ quần áo","fa":"گنجه","examples":[{"de":"Ich hänge meine Kleider in den Schrank.","en":"I hang my clothes in the wardrobe.","ru":"Я вешаю свою одежду в шкаф.","vi":"Tôi treo quần áo của mình vào tủ.","fa":"لباس هایم را در کمد آویزان می کنم."},{"de":"Der Schrank in der Küche ist voller Geschirr.","en":"The cupboard in the kitchen is full of dishes.","ru":"Шкаф на кухне полон посуды.","vi":"Chiếc tủ trong bếp chứa đầy bát đĩa.","fa":"کمد آشپزخانه پر از ظرف است."}]},{"word":"der Schreck(en)","en":"fright; shock","ru":"испуг, шок","vi":"(những) nỗi sợ hãi","fa":"ترس (ها)","examples":[{"de":"Der laute Knall hat mir einen großen Schrecken eingejagt.","en":"The loud bang gave me a big fright.","ru":"Громкий хлопок сильно меня напугал.","vi":"Tiếng nổ lớn làm tôi vô cùng sợ hãi.","fa":"صدای هق هق بلند باعث ترس شدید من شد."},{"de":"Sie erholte sich schnell von dem Schrecken.","en":"She quickly recovered from the shock.","ru":"Она быстро оправилась от испуга.","vi":"Cô nhanh chóng hồi phục sau cú sốc.","fa":"او به سرعت از شوک خارج شد."}]},{"word":"schreiben","en":"to write","ru":"писать","vi":"viết","fa":"نوشتن","examples":[{"de":"Ich schreibe meiner Freundin jeden Tag eine Nachricht.","en":"I write a message to my girlfriend every day.","ru":"Я каждый день пишу сообщение своей подруге.","vi":"Tôi nhắn tin cho bạn gái tôi mỗi ngày.","fa":"هر روز به دوست دخترم پیام می دهم."},{"de":"Er schreibt gerade an einem neuen Buch.","en":"He is currently writing a new book.","ru":"Он сейчас пишет новую книгу.","vi":"Hiện tại anh ấy đang viết một cuốn sách mới.","fa":"او در حال حاضر مشغول نوشتن کتاب جدیدی است."}]},{"word":"schreien","en":"to shout, scream","ru":"кричать","vi":"hét lên","fa":"فریاد زدن","examples":[{"de":"Das Baby hat die ganze Nacht geschrien.","en":"The baby screamed all night.","ru":"Ребёнок кричал всю ночь.","vi":"Bé khóc suốt đêm.","fa":"بچه تمام شب گریه کرد."},{"de":"Du musst nicht so schreien, ich höre dich gut.","en":"You don't need to shout like that, I can hear you well.","ru":"Не нужно так кричать, я хорошо тебя слышу.","vi":"Bạn không cần phải hét lên như vậy, tôi có thể nghe thấy bạn.","fa":"لازم نیست اینطور جیغ بزنی، من صدایت را خوب می شنوم."}]},{"word":"die Schrift","en":"writing; script","ru":"письмо, почерк, шрифт","vi":"văn bản","fa":"نوشته","examples":[{"de":"Seine Schrift ist so klein, dass ich sie kaum lesen kann.","en":"His handwriting is so small that I can hardly read it.","ru":"Его почерк такой мелкий, что я едва могу его прочитать.","vi":"Chữ viết của anh ấy quá nhỏ đến nỗi tôi khó có thể đọc được.","fa":"نوشته هایش آنقدر کوچک است که به سختی می توانم آن را بخوانم."},{"de":"Das Dokument ist in einer alten Schrift verfasst.","en":"The document is written in an old script.","ru":"Документ написан старинным шрифтом.","vi":"Tài liệu này được viết bằng chữ cổ.","fa":"این سند به خط باستانی نوشته شده است."}]},{"word":"die Schriftstellerin","en":"writer (female)","ru":"писательница","vi":"nhà văn","fa":"نویسنده","examples":[{"de":"Die bekannte Schriftstellerin hat einen neuen Roman veröffentlicht.","en":"The famous (female) writer has published a new novel.","ru":"Известная писательница выпустила новый роман.","vi":"Nhà văn nổi tiếng đã xuất bản một cuốn tiểu thuyết mới.","fa":"این نویسنده سرشناس رمان جدیدی منتشر کرده است."},{"de":"Meine Tante ist Schriftstellerin und schreibt vor allem Kinderbücher.","en":"My aunt is a writer and mainly writes children's books.","ru":"Моя тётя писательница и в основном пишет детские книги.","vi":"Dì tôi là nhà văn và chủ yếu viết sách cho trẻ em.","fa":"عمه من نویسنده است و بیشتر کتاب های کودک می نویسد."}]},{"word":"der Schritt","en":"step","ru":"шаг","vi":"bước","fa":"مرحله","examples":[{"de":"Er machte einen Schritt zurück, um besser zu sehen.","en":"He took a step back to see better.","ru":"Он сделал шаг назад, чтобы лучше видеть.","vi":"Anh lùi lại một bước để nhìn rõ hơn.","fa":"یک قدم به عقب رفت تا بهتر ببیند."},{"de":"Das ist ein wichtiger Schritt für unsere Firma.","en":"This is an important step for our company.","ru":"Это важный шаг для нашей фирмы.","vi":"Đây là một bước quan trọng đối với công ty chúng tôi.","fa":"این یک گام مهم برای شرکت ما است."}]},{"word":"der Schuh","en":"shoe","ru":"туфля, ботинок","vi":"chiếc giày","fa":"کفش","examples":[{"de":"Diese Schuhe sind sehr bequem zum Laufen.","en":"These shoes are very comfortable for walking.","ru":"Эти туфли очень удобны для ходьбы.","vi":"Những đôi giày này rất thoải mái khi chạy.","fa":"این کفش ها برای دویدن بسیار راحت هستند."},{"de":"Zieh bitte die Schuhe aus, bevor du reinkommst.","en":"Please take off your shoes before coming in.","ru":"Пожалуйста, сними обувь, прежде чем войти.","vi":"Vui lòng cởi giày trước khi vào.","fa":"لطفا قبل از ورود کفش های خود را در بیاورید."}]},{"word":"die Schularbeit","en":"test (written classroom exam, Austrian)","ru":"контрольная работа (в школе, австр.)","vi":"công việc ở trường","fa":"کار مدرسه","examples":[{"de":"Er hat morgen eine Schularbeit in Mathematik.","en":"He has a test in maths tomorrow.","ru":"Завтра у него контрольная по математике.","vi":"Ngày mai anh ấy có bài kiểm tra toán.","fa":"فردا امتحان ریاضی داره"},{"de":"Für die Schularbeit am Montag muss ich noch viel üben.","en":"I still need to practice a lot for the test on Monday.","ru":"Мне нужно ещё много позаниматься перед контрольной в понедельник.","vi":"Tôi vẫn phải luyện tập rất nhiều cho bài tập ở trường vào thứ Hai.","fa":"من هنوز باید برای کارهای مدرسه ام در روز دوشنبه خیلی تمرین کنم."}]},{"word":"die Schuld","en":"guilt; debt; fault","ru":"вина; долг","vi":"tội lỗi","fa":"گناه","examples":[{"de":"Er hat die Schuld auf sich genommen.","en":"He took the blame on himself.","ru":"Он взял вину на себя.","vi":"Anh ấy đã nhận lỗi.","fa":"او تقصیر را به عهده گرفت."},{"de":"Wir haben noch Schulden bei der Bank.","en":"We still have debts at the bank.","ru":"У нас ещё есть долги перед банком.","vi":"Chúng tôi vẫn còn nợ ngân hàng.","fa":"ما هنوز به بانک بدهکاریم."}]},{"word":"die Schule","en":"school","ru":"школа","vi":"trường học","fa":"مدرسه","examples":[{"de":"Meine Tochter geht seit September in die Schule.","en":"My daughter has been going to school since September.","ru":"Моя дочь ходит в школу с сентября.","vi":"Con gái tôi đã đi học từ tháng 9.","fa":"دخترم از شهریور به مدرسه می رود."},{"de":"Nach der Schule spielen die Kinder im Park.","en":"After school, the children play in the park.","ru":"После школы дети играют в парке.","vi":"Sau giờ học bọn trẻ chơi ở công viên.","fa":"بعد از مدرسه بچه ها در پارک بازی می کنند."}]},{"word":"die Schulter","en":"shoulder","ru":"плечо","vi":"vai","fa":"شانه","examples":[{"de":"Er trägt die Tasche immer über der linken Schulter.","en":"He always carries the bag over his left shoulder.","ru":"Он всегда носит сумку на левом плече.","vi":"Anh ấy luôn mang túi qua vai trái.","fa":"او همیشه کیف را روی شانه چپ خود حمل می کند."},{"de":"Meine Schulter tut seit dem Training weh.","en":"My shoulder has hurt since the training.","ru":"У меня болит плечо после тренировки.","vi":"Vai của tôi đã bị đau kể từ khi tập luyện.","fa":"شانه ام از زمان تمرین درد می کند."}]},{"word":"die Schüssel","en":"bowl","ru":"миска","vi":"cái bát","fa":"کاسه","examples":[{"de":"Sie mischt den Teig in einer großen Schüssel.","en":"She mixes the dough in a large bowl.","ru":"Она замешивает тесто в большой миске.","vi":"Cô trộn bột vào một cái tô lớn.","fa":"او خمیر را در یک کاسه بزرگ مخلوط می کند."},{"de":"Stell die Salatschüssel bitte auf den Tisch.","en":"Please put the salad bowl on the table.","ru":"Поставь, пожалуйста, миску с салатом на стол.","vi":"Vui lòng đặt bát salad lên bàn.","fa":"لطفا کاسه سالاد را روی میز بگذارید."}]},{"word":"schütteln","en":"to shake","ru":"трясти","vi":"lắc","fa":"تکان دادن","examples":[{"de":"Bitte schütteln Sie die Flasche vor dem Öffnen.","en":"Please shake the bottle before opening.","ru":"Пожалуйста, встряхните бутылку перед открытием.","vi":"Hãy lắc chai trước khi mở.","fa":"لطفا قبل از باز کردن بطری را تکان دهید."},{"de":"Er schüttelte mir zur Begrüßung die Hand.","en":"He shook my hand in greeting.","ru":"Он пожал мне руку в знак приветствия.","vi":"Anh bắt tay tôi chào hỏi.","fa":"به نشانه سلام دستم را فشرد."}]},{"word":"schützen","en":"to protect","ru":"защищать","vi":"bảo vệ","fa":"محافظت کنید","examples":[{"de":"Eine Sonnencreme schützt die Haut vor Sonnenbrand.","en":"Sunscreen protects the skin from sunburn.","ru":"Солнцезащитный крем защищает кожу от солнечных ожогов.","vi":"Kem chống nắng bảo vệ da khỏi bị cháy nắng.","fa":"کرم ضد آفتاب از پوست در برابر آفتاب سوختگی محافظت می کند."},{"de":"Wir müssen die Umwelt besser schützen.","en":"We need to protect the environment better.","ru":"Мы должны лучше защищать окружающую среду.","vi":"Chúng ta phải bảo vệ môi trường tốt hơn.","fa":"ما باید از محیط زیست بهتر محافظت کنیم."}]},{"word":"schwach","en":"weak","ru":"слабый","vi":"yếu đuối","fa":"ضعیف","examples":[{"de":"Nach der Krankheit fühlte er sich noch sehr schwach.","en":"After the illness, he still felt very weak.","ru":"После болезни он ещё чувствовал себя очень слабым.","vi":"Sau cơn bệnh, ông vẫn cảm thấy rất yếu.","fa":"بعد از این بیماری همچنان احساس ضعف می کرد."},{"de":"Das Signal des Handys ist hier ziemlich schwach.","en":"The phone signal is quite weak here.","ru":"Сигнал телефона здесь довольно слабый.","vi":"Tín hiệu điện thoại di động ở đây khá yếu.","fa":"سیگنال تلفن همراه در اینجا بسیار ضعیف است."}]},{"word":"das Schwammerl","en":"mushroom (Austrian)","ru":"гриб (австр.)","vi":"nấm","fa":"قارچ","examples":[{"de":"Im Herbst sammeln wir gern Schwammerl im Wald.","en":"In autumn, we like to pick mushrooms in the forest.","ru":"Осенью мы любим собирать грибы в лесу.","vi":"Vào mùa thu, chúng tôi thích hái nấm trong rừng.","fa":"در پاییز ما دوست داریم قارچ ها را در جنگل جمع آوری کنیم."},{"de":"Aus den Schwammerln hat sie eine leckere Suppe gekocht.","en":"She cooked a delicious soup from the mushrooms.","ru":"Из грибов она сварила вкусный суп.","vi":"Cô ấy đã nấu một món súp ngon từ nấm.","fa":"او یک سوپ خوشمزه از قارچ درست کرد."}]},{"word":"die Schwangerschaft","en":"pregnancy","ru":"беременность","vi":"mang thai","fa":"بارداری","examples":[{"de":"Während der Schwangerschaft geht sie regelmäßig zum Arzt.","en":"During her pregnancy, she regularly goes to the doctor.","ru":"Во время беременности она регулярно ходит к врачу.","vi":"Cô đến gặp bác sĩ thường xuyên trong thời gian mang thai.","fa":"او در دوران بارداری به طور منظم به پزشک مراجعه می کند."},{"de":"Die Schwangerschaft dauert normalerweise neun Monate.","en":"A pregnancy usually lasts nine months.","ru":"Беременность обычно длится девять месяцев.","vi":"Mang thai thường kéo dài chín tháng.","fa":"بارداری معمولا نه ماه طول می کشد."}]},{"word":"schweigen","en":"to be silent","ru":"молчать","vi":"im lặng","fa":"ساکت","examples":[{"de":"Er schwieg lange, bevor er antwortete.","en":"He was silent for a long time before answering.","ru":"Он долго молчал, прежде чем ответить.","vi":"Anh im lặng một lúc lâu trước khi trả lời.","fa":"قبل از جواب دادن مدتها سکوت کرد."},{"de":"Bitte schweig, ich muss mich konzentrieren.","en":"Please be quiet, I need to concentrate.","ru":"Пожалуйста, помолчи, мне нужно сосредоточиться.","vi":"Làm ơn im lặng đi, tôi cần tập trung.","fa":"لطفا ساکت باشید، من باید تمرکز کنم."}]},{"word":"schwer","en":"heavy; difficult","ru":"тяжёлый; трудный","vi":"khó khăn","fa":"دشوار است","examples":[{"de":"Der Koffer ist zu schwer, ich kann ihn nicht tragen.","en":"The suitcase is too heavy, I can't carry it.","ru":"Чемодан слишком тяжёлый, я не могу его нести.","vi":"Vali nặng quá, tôi không xách nổi.","fa":"چمدان خیلی سنگین است، نمی توانم آن را حمل کنم."},{"de":"Die Prüfung war sehr schwer.","en":"The exam was very difficult.","ru":"Экзамен был очень трудным.","vi":"Bài kiểm tra rất khó khăn.","fa":"امتحان خیلی سخت بود."}]},{"word":"die Schwester","en":"sister","ru":"сестра","vi":"chị gái","fa":"خواهر","examples":[{"de":"Meine Schwester wohnt in einer anderen Stadt.","en":"My sister lives in another city.","ru":"Моя сестра живёт в другом городе.","vi":"Em gái tôi sống ở một thành phố khác.","fa":"خواهر من در شهر دیگری زندگی می کند."},{"de":"Ich habe zwei Schwestern und einen Bruder.","en":"I have two sisters and one brother.","ru":"У меня две сестры и один брат.","vi":"Tôi có hai chị gái và một anh trai.","fa":"من دو خواهر و یک برادر دارم."}]},{"word":"Schwieger-","en":"in-law (prefix)","ru":"приставка «...по браку» (тесть, тёща и т.п.)","vi":"con rể","fa":"شوهر شوهر","examples":[{"de":"Meine Schwiegermutter kocht sehr gut.","en":"My mother-in-law cooks very well.","ru":"Моя тёща (свекровь) очень хорошо готовит.","vi":"Mẹ chồng tôi nấu ăn rất ngon.","fa":"مادرشوهرم خیلی خوب آشپزی می کند."},{"de":"Am Sonntag besuchen wir meinen Schwiegervater.","en":"On Sunday we are visiting my father-in-law.","ru":"В воскресенье мы навещаем моего тестя (свёкра).","vi":"Vào Chủ Nhật, chúng tôi đến thăm bố vợ tôi.","fa":"یکشنبه به دیدن پدرشوهرم می رویم."}]},{"word":"schwierig","en":"difficult","ru":"трудный, сложный","vi":"khó khăn","fa":"دشوار است","examples":[{"de":"Diese Aufgabe ist für mich zu schwierig.","en":"This task is too difficult for me.","ru":"Это задание для меня слишком сложное.","vi":"Nhiệm vụ này quá khó đối với tôi.","fa":"این کار برای من خیلی سخت است."},{"de":"Es war eine schwierige Entscheidung, aber ich bereue sie nicht.","en":"It was a difficult decision, but I don't regret it.","ru":"Это было трудное решение, но я о нём не жалею.","vi":"Đó là một quyết định khó khăn nhưng tôi không hối hận.","fa":"تصمیم سختی بود، اما پشیمان نیستم."}]},{"word":"schwimmen","en":"to swim","ru":"плавать","vi":"bơi lội","fa":"شنا کردن","examples":[{"de":"Im Sommer gehen wir oft im See schwimmen.","en":"In summer, we often go swimming in the lake.","ru":"Летом мы часто ходим плавать на озеро.","vi":"Vào mùa hè chúng tôi thường đi bơi ở hồ.","fa":"در تابستان ما اغلب برای شنا در دریاچه می رویم."},{"de":"Meine Tochter kann noch nicht schwimmen.","en":"My daughter can't swim yet.","ru":"Моя дочь ещё не умеет плавать.","vi":"Con gái tôi vẫn chưa biết bơi.","fa":"دخترم هنوز شنا بلد نیست."}]},{"word":"schwitzen","en":"to sweat","ru":"потеть","vi":"mồ hôi","fa":"عرق","examples":[{"de":"Bei dieser Hitze schwitze ich sehr stark.","en":"In this heat, I sweat a lot.","ru":"В такую жару я сильно потею.","vi":"Tôi đổ mồ hôi rất nhiều trong cái nóng này.","fa":"تو این گرما خیلی عرق می کنم."},{"de":"Nach dem Sport schwitzt er immer.","en":"He always sweats after sports.","ru":"После спорта он всегда потеет.","vi":"Anh ấy luôn đổ mồ hôi sau khi tập thể dục.","fa":"او همیشه بعد از ورزش عرق می کند."}]},{"word":"der See","en":"lake","ru":"озеро","vi":"hồ","fa":"دریاچه","examples":[{"de":"Wir machen am Wochenende einen Ausflug an den See.","en":"We are taking a trip to the lake this weekend.","ru":"На выходных мы едем на озеро.","vi":"Chúng tôi đang có một chuyến đi đến hồ vào cuối tuần này.","fa":"آخر این هفته به دریاچه سفر می کنیم."},{"de":"Der See ist im Sommer sehr warm.","en":"The lake is very warm in summer.","ru":"Летом озеро очень тёплое.","vi":"Hồ rất ấm áp vào mùa hè.","fa":"این دریاچه در تابستان بسیار گرم است."}]},{"word":"sehen","en":"to see","ru":"видеть","vi":"xem","fa":"ببینید","examples":[{"de":"Kannst du das Schild von hier aus sehen?","en":"Can you see the sign from here?","ru":"Ты видишь отсюда эту табличку?","vi":"Bạn có thể nhìn thấy biển báo từ đây không?","fa":"آیا می توانید علامت را از اینجا ببینید؟"},{"de":"Ich habe ihn gestern im Supermarkt gesehen.","en":"I saw him yesterday at the supermarket.","ru":"Я видел его вчера в супермаркете.","vi":"Hôm qua tôi nhìn thấy anh ấy ở siêu thị.","fa":"دیروز او را در سوپرمارکت دیدم."}]},{"word":"die Sehenswürdigkeit","en":"sight; tourist attraction","ru":"достопримечательность","vi":"cảnh tượng","fa":"دید","examples":[{"de":"Der Stephansdom ist die bekannteste Sehenswürdigkeit von Wien.","en":"St. Stephen's Cathedral is the most famous sight in Vienna.","ru":"Собор Святого Стефана — самая известная достопримечательность Вены.","vi":"Nhà thờ St. Stephen là điểm thu hút nổi tiếng nhất ở Vienna.","fa":"کلیسای جامع سنت استفان معروف ترین جاذبه در وین است."},{"de":"Wir haben in Paris viele Sehenswürdigkeiten besucht.","en":"We visited many tourist attractions in Paris.","ru":"В Париже мы посетили много достопримечательностей.","vi":"Chúng tôi đã đến thăm nhiều thắng cảnh ở Paris.","fa":"از دیدنی های پاریس دیدن کردیم."}]},{"word":"die Sehnsucht","en":"longing; yearning","ru":"тоска; страстное желание","vi":"sự khao khát","fa":"اشتیاق","examples":[{"de":"Er hatte große Sehnsucht nach seiner Heimat.","en":"He had a great longing for his homeland.","ru":"Он сильно тосковал по родине.","vi":"Anh có một niềm khao khát mãnh liệt đối với quê hương.","fa":"اشتیاق زیادی به وطن داشت."},{"de":"Die Sehnsucht nach dem Meer wurde immer stärker.","en":"The longing for the sea grew ever stronger.","ru":"Тоска по морю становилась всё сильнее.","vi":"Niềm khao khát biển ngày càng mãnh liệt.","fa":"حسرت دریا بیشتر و قوی تر می شد."}]},{"word":"sehr","en":"very","ru":"очень","vi":"rất","fa":"خیلی","examples":[{"de":"Das Buch ist sehr interessant.","en":"The book is very interesting.","ru":"Книга очень интересная.","vi":"Cuốn sách rất thú vị.","fa":"کتاب بسیار جالبی است."},{"de":"Ich danke dir sehr für deine Hilfe.","en":"I thank you very much for your help.","ru":"Я очень благодарен тебе за помощь.","vi":"Cảm ơn bạn rất nhiều vì sự giúp đỡ của bạn.","fa":"از کمک شما بسیار سپاسگزارم."}]},{"word":"die Seife","en":"soap","ru":"мыло","vi":"xà phòng","fa":"صابون","examples":[{"de":"Bitte wasch dir die Hände mit Seife.","en":"Please wash your hands with soap.","ru":"Пожалуйста, помой руки с мылом.","vi":"Hãy rửa tay bằng xà phòng.","fa":"لطفا دست های خود را با صابون بشویید."},{"de":"Im Bad steht eine neue Seife.","en":"There is a new bar of soap in the bathroom.","ru":"В ванной лежит новое мыло.","vi":"Có xà phòng mới trong phòng tắm.","fa":"صابون جدید در حمام وجود دارد."}]},{"word":"sein","en":"to be","ru":"быть","vi":"được","fa":"باشد","examples":[{"de":"Er ist mein bester Freund.","en":"He is my best friend.","ru":"Он мой лучший друг.","vi":"Anh ấy là người bạn tốt nhất của tôi.","fa":"او بهترین دوست من است."},{"de":"Wir sind seit zwei Jahren verheiratet.","en":"We have been married for two years.","ru":"Мы женаты уже два года.","vi":"Chúng tôi đã kết hôn được hai năm.","fa":"ما دو سال است که ازدواج کرده ایم."}]},{"word":"seit","en":"since; for (time)","ru":"с (какого-то времени); в течение","vi":"kể từ khi","fa":"از آنجایی که","examples":[{"de":"Ich lerne seit drei Jahren Deutsch.","en":"I have been learning German for three years.","ru":"Я учу немецкий уже три года.","vi":"Tôi đã học tiếng Đức được ba năm.","fa":"من سه سال است که آلمانی یاد می گیرم."},{"de":"Seit dem Umzug fühlt sie sich viel wohler.","en":"Since the move, she feels much better.","ru":"С момента переезда она чувствует себя намного лучше.","vi":"Cô ấy đã cảm thấy tốt hơn nhiều kể từ khi chuyển đi.","fa":"او از زمان جابجایی احساس بسیار بهتری داشته است."}]},{"word":"die Seite","en":"page; side","ru":"страница; сторона","vi":"trang","fa":"صفحه","examples":[{"de":"Bitte schlagen Sie das Buch auf Seite zwanzig auf.","en":"Please open the book to page twenty.","ru":"Пожалуйста, откройте книгу на двадцатой странице.","vi":"Hãy mở cuốn sách đến trang hai mươi.","fa":"لطفاً کتاب را تا صفحه بیستم باز کنید."},{"de":"Auf der anderen Seite der Straße ist ein Supermarkt.","en":"On the other side of the street, there is a supermarket.","ru":"На другой стороне улицы есть супермаркет.","vi":"Có một siêu thị ở phía bên kia đường.","fa":"در سمت دیگر خیابان یک سوپرمارکت وجود دارد."}]},{"word":"der Sekretär","en":"secretary","ru":"секретарь","vi":"thư ký","fa":"منشی","examples":[{"de":"Der Sekretär organisiert alle Termine des Chefs.","en":"The secretary organizes all the boss's appointments.","ru":"Секретарь организует все встречи начальника.","vi":"Thư ký sắp xếp mọi cuộc hẹn của sếp.","fa":"منشی همه قرارهای رئیس را سازماندهی می کند."},{"de":"Er arbeitet seit fünf Jahren als Sekretär in dieser Firma.","en":"He has been working as a secretary at this company for five years.","ru":"Он уже пять лет работает секретарём в этой фирме.","vi":"Anh ấy đã làm thư ký ở công ty này được 5 năm.","fa":"او پنج سال است که به عنوان منشی در این شرکت مشغول به کار است."}]},{"word":"selb-","en":"same (the same)","ru":"тот же самый","vi":"tự","fa":"خود","examples":[{"de":"Wir wohnen im selben Haus wie meine Eltern.","en":"We live in the same house as my parents.","ru":"Мы живём в том же доме, что и мои родители.","vi":"Chúng tôi sống cùng nhà với bố mẹ tôi.","fa":"ما با پدر و مادرم در یک خانه زندگی می کنیم."},{"de":"Er trägt jeden Tag dasselbe T-Shirt.","en":"He wears the same T-shirt every day.","ru":"Он каждый день носит одну и ту же футболку.","vi":"Anh ấy mặc cùng một chiếc áo phông mỗi ngày.","fa":"او هر روز همان تی شرت را می پوشد."}]},{"word":"selbst","en":"oneself; even","ru":"сам; даже","vi":"chính bạn","fa":"خودت","examples":[{"de":"Ich habe den Kuchen selbst gebacken.","en":"I baked the cake myself.","ru":"Я сам испёк торт.","vi":"Tôi tự tay nướng bánh.","fa":"کیک رو خودم پختم"},{"de":"Selbst mein Vater konnte die Aufgabe nicht lösen.","en":"Even my father couldn't solve the task.","ru":"Даже мой отец не смог решить эту задачу.","vi":"Ngay cả bố tôi cũng không thể giải quyết được vấn đề.","fa":"حتی پدرم هم نتوانست مشکل را حل کند."}]},{"word":"selbstständig","en":"independent","ru":"самостоятельный","vi":"độc lập","fa":"مستقل","examples":[{"de":"Meine Tochter ist schon sehr selbstständig für ihr Alter.","en":"My daughter is already very independent for her age.","ru":"Моя дочь уже очень самостоятельна для своего возраста.","vi":"Con gái tôi vốn đã rất tự lập so với tuổi của nó.","fa":"دخترم نسبت به سنش خیلی مستقل است."},{"de":"Er möchte sich beruflich selbstständig machen.","en":"He wants to become self-employed.","ru":"Он хочет стать самостоятельным предпринимателем.","vi":"Anh ấy muốn trở thành người tự kinh doanh.","fa":"او می خواهد خوداشتغالی شود."}]},{"word":"selbstverständlich","en":"of course; naturally","ru":"само собой разумеется; конечно","vi":"tất nhiên","fa":"البته","examples":[{"de":"Selbstverständlich helfe ich dir bei den Hausaufgaben.","en":"Of course I will help you with your homework.","ru":"Конечно, я помогу тебе с домашним заданием.","vi":"Tất nhiên là tôi sẽ giúp bạn làm bài tập về nhà.","fa":"البته من در انجام تکالیف به شما کمک خواهم کرد."},{"de":"Es ist für mich selbstverständlich, pünktlich zu sein.","en":"It is a matter of course for me to be punctual.","ru":"Для меня само собой разумеется быть пунктуальным.","vi":"Việc tôi đến đúng giờ là điều đương nhiên.","fa":"طبیعی است که به موقع بروم."}]},{"word":"selten","en":"rare; rarely","ru":"редкий; редко","vi":"hiếm","fa":"نادر","examples":[{"de":"Ein so schönes Wetter ist im November selten.","en":"Such nice weather is rare in November.","ru":"Такая хорошая погода редка в ноябре.","vi":"Thời tiết đẹp như vậy hiếm có vào tháng 11.","fa":"چنین هوای زیبایی در ماه نوامبر نادر است."},{"de":"Wir sehen uns nur noch selten.","en":"We only rarely see each other anymore.","ru":"Мы теперь видимся только редко.","vi":"Chúng tôi hiếm khi gặp nhau nữa.","fa":"ما دیگر به ندرت همدیگر را می بینیم."}]},{"word":"seltsam","en":"strange","ru":"странный","vi":"kỳ lạ","fa":"عجیب","examples":[{"de":"Er hat sich in letzter Zeit sehr seltsam benommen.","en":"He has behaved very strangely lately.","ru":"В последнее время он вёл себя очень странно.","vi":"Gần đây anh ấy cư xử rất lạ.","fa":"او اخیراً بسیار عجیب رفتار می کند."},{"de":"Das war ein seltsames Geräusch aus dem Keller.","en":"That was a strange noise from the basement.","ru":"Это был странный звук из подвала.","vi":"Đó là một tiếng động lạ phát ra từ tầng hầm.","fa":"صدای عجیبی از زیرزمین می آمد."}]},{"word":"das Semester","en":"semester","ru":"семестр","vi":"học kỳ","fa":"ترم","examples":[{"de":"Das neue Semester beginnt im Oktober.","en":"The new semester begins in October.","ru":"Новый семестр начинается в октябре.","vi":"Học kỳ mới bắt đầu vào tháng 10.","fa":"ترم جدید در ماه اکتبر شروع می شود."},{"de":"Sie studiert im dritten Semester Medizin.","en":"She is studying medicine in her third semester.","ru":"Она учится на третьем семестре медицины.","vi":"Cô ấy đang học y khoa trong học kỳ thứ ba.","fa":"او در ترم سوم پزشکی تحصیل می کند."}]},{"word":"das Seminar","en":"seminar","ru":"семинар","vi":"hội thảo","fa":"سمینار","examples":[{"de":"Ich besuche jede Woche ein Seminar an der Universität.","en":"I attend a seminar at the university every week.","ru":"Я каждую неделю посещаю семинар в университете.","vi":"Tôi tham dự một buổi hội thảo tại trường đại học mỗi tuần.","fa":"من هر هفته در یک سمینار در دانشگاه شرکت می کنم."},{"de":"Das Seminar zum Thema Kommunikation war sehr hilfreich.","en":"The seminar on the topic of communication was very helpful.","ru":"Семинар на тему общения был очень полезен.","vi":"Buổi hội thảo về giao tiếp rất hữu ích.","fa":"سمینار ارتباطات بسیار مفید بود."}]},{"word":"die Semmel","en":"bread roll (Austrian)","ru":"булочка (австр.)","vi":"cuộn","fa":"رول","examples":[{"de":"Zum Frühstück essen wir gern frische Semmeln.","en":"For breakfast, we like to eat fresh bread rolls.","ru":"На завтрак мы любим есть свежие булочки.","vi":"Chúng tôi thích ăn bánh mì tươi vào bữa sáng.","fa":"ما دوست داریم برای صبحانه رول های تازه بخوریم."},{"de":"Ich kaufe jeden Morgen Semmeln beim Bäcker.","en":"I buy bread rolls at the bakery every morning.","ru":"Я каждое утро покупаю булочки в пекарне.","vi":"Tôi mua bánh mì ở tiệm bánh vào mỗi buổi sáng.","fa":"من هر روز صبح از نانوایی رول می خرم."}]},{"word":"senden","en":"to send; to broadcast","ru":"отправлять; транслировать","vi":"gửi","fa":"ارسال کنید","examples":[{"de":"Ich sende dir die Dokumente per E-Mail.","en":"I will send you the documents by email.","ru":"Я отправлю тебе документы по электронной почте.","vi":"Tôi sẽ gửi tài liệu cho bạn qua email.","fa":"من مدارک را از طریق ایمیل برای شما ارسال می کنم."},{"de":"Das Fernsehen sendet heute Abend ein wichtiges Fußballspiel.","en":"The TV is broadcasting an important football match tonight.","ru":"Телевидение сегодня вечером транслирует важный футбольный матч.","vi":"TV đang phát sóng một trận bóng đá quan trọng tối nay.","fa":"تلویزیون امشب یک بازی مهم فوتبال را پخش می کند."}]},{"word":"die Sendung","en":"programme; broadcast","ru":"передача; программа","vi":"chương trình phát sóng","fa":"پخش","examples":[{"de":"Diese Sendung läuft jeden Sonntagabend.","en":"This programme is on every Sunday evening.","ru":"Эта передача выходит каждый воскресный вечер.","vi":"Chương trình này diễn ra vào tối chủ nhật hàng tuần.","fa":"این نمایش هر یکشنبه عصر اجرا می شود."},{"de":"Die Sendung über Tiere gefällt den Kindern sehr.","en":"The children really like the programme about animals.","ru":"Передача о животных очень нравится детям.","vi":"Các em rất thích chương trình biểu diễn về động vật.","fa":"بچه ها واقعاً نمایش حیوانات را دوست دارند."}]},{"word":"die Senioren","en":"senior citizens","ru":"пожилые люди","vi":"người cao niên","fa":"سالمندان","examples":[{"de":"Im Park gibt es viele Bänke für Senioren.","en":"There are many benches for senior citizens in the park.","ru":"В парке много скамеек для пожилых людей.","vi":"Có rất nhiều ghế dài dành cho người cao tuổi trong công viên.","fa":"نیمکت های زیادی برای سالمندان در پارک وجود دارد."},{"de":"Das Zentrum bietet spezielle Kurse für Senioren an.","en":"The center offers special courses for senior citizens.","ru":"Центр предлагает специальные курсы для пожилых людей.","vi":"Trung tâm cung cấp các khóa học đặc biệt dành cho người cao tuổi.","fa":"این مرکز دوره های ویژه ای را برای سالمندان برگزار می کند."}]},{"word":"senkrecht","en":"vertical","ru":"вертикальный","vi":"theo chiều dọc","fa":"عمودی","examples":[{"de":"Die Linie auf dem Papier muss senkrecht sein.","en":"The line on the paper must be vertical.","ru":"Линия на бумаге должна быть вертикальной.","vi":"Dòng trên giấy phải thẳng đứng.","fa":"خط روی کاغذ باید عمودی باشد."},{"de":"Der Fels fällt senkrecht ins Meer ab.","en":"The cliff drops vertically into the sea.","ru":"Скала обрывается вертикально в море.","vi":"Tảng đá rơi thẳng đứng xuống biển.","fa":"سنگ به صورت عمودی به دریا می ریزد."}]},{"word":"die Serie","en":"series","ru":"сериал; серия","vi":"loạt phim","fa":"سریال","examples":[{"de":"Meine Lieblingsserie kommt jeden Freitagabend im Fernsehen.","en":"My favorite series is on TV every Friday evening.","ru":"Мой любимый сериал показывают каждую пятницу вечером.","vi":"Bộ phim yêu thích của tôi được chiếu trên TV vào tối thứ Sáu hàng tuần.","fa":"سریال مورد علاقه من هر جمعه عصر از تلویزیون پخش می شود."},{"de":"Diese Serie hat schon sieben Staffeln.","en":"This series already has seven seasons.","ru":"У этого сериала уже семь сезонов.","vi":"This series has already had seven seasons.","fa":"این سریال قبلاً هفت فصل داشته است."}]},{"word":"der Service","en":"service","ru":"сервис, обслуживание","vi":"dịch vụ","fa":"خدمات","examples":[{"de":"Der Service in diesem Hotel ist ausgezeichnet.","en":"The service in this hotel is excellent.","ru":"Обслуживание в этом отеле превосходное.","vi":"Dịch vụ tại khách sạn này là tuyệt vời.","fa":"خدمات در این هتل عالی است."},{"de":"Wir haben uns über den freundlichen Service gefreut.","en":"We were pleased with the friendly service.","ru":"Мы были рады дружелюбному обслуживанию.","vi":"Chúng tôi hài lòng với dịch vụ thân thiện.","fa":"ما از خدمات دوستانه راضی بودیم."}]},{"word":"der Serviceangestellte","en":"service employee","ru":"сотрудник сферы обслуживания","vi":"nhân viên phục vụ","fa":"کارمند خدمات","examples":[{"de":"Der Serviceangestellte hat uns höflich geholfen.","en":"The service employee helped us politely.","ru":"Сотрудник обслуживания вежливо нам помог.","vi":"Nhân viên phục vụ lịch sự giúp đỡ chúng tôi.","fa":"کارمند خدمات مودبانه به ما کمک کرد."},{"de":"Als Serviceangestellter muss man freundlich zu den Kunden sein.","en":"As a service employee, you have to be friendly to customers.","ru":"Работая сотрудником сферы обслуживания, нужно быть вежливым с клиентами.","vi":"Là nhân viên phục vụ bạn phải thân thiện với khách hàng.","fa":"به عنوان یک کارمند خدمات باید با مشتریان دوستانه رفتار کنید."}]},{"word":"der Sessel","en":"armchair (Austrian: chair)","ru":"кресло","vi":"chiếc ghế bành","fa":"صندلی راحتی","examples":[{"de":"Er sitzt jeden Abend im Sessel und liest Zeitung.","en":"Every evening he sits in the armchair and reads the newspaper.","ru":"Каждый вечер он сидит в кресле и читает газету.","vi":"Anh ấy ngồi trên ghế bành mỗi tối và đọc báo.","fa":"هر روز غروب روی صندلی راحتی می نشیند و روزنامه می خواند."},{"de":"Der bequeme Sessel steht im Wohnzimmer.","en":"The comfortable armchair is in the living room.","ru":"Удобное кресло стоит в гостиной.","vi":"Chiếc ghế bành thoải mái được đặt trong phòng khách.","fa":"صندلی راحتی در اتاق نشیمن است."}]},{"word":"sich amüsieren","en":"to enjoy oneself, to have fun","ru":"веселиться, развлекаться","vi":"chúc vui vẻ","fa":"خوش بگذره","examples":[{"de":"Die Kinder haben sich auf dem Fest prächtig amüsiert.","en":"The children had a wonderful time at the party.","ru":"Дети прекрасно повеселились на празднике.","vi":"The children had a great time at the festival.","fa":"بچه ها در جشنواره خیلی خوش گذشت."},{"de":"Wir haben uns gestern Abend im Kino sehr amüsiert.","en":"We had a lot of fun at the cinema last night.","ru":"Вчера вечером мы отлично повеселились в кино.","vi":"Wir haben uns gestern Abend im Kino sehr amüsiert.","fa":"دیشب در سینما خیلی خوش گذشت."}]},{"word":"sich anstrengen","en":"to make an effort, to try hard","ru":"стараться, прилагать усилия","vi":"nỗ lực","fa":"تلاش کن","examples":[{"de":"Du musst dich mehr anstrengen, um die Prüfung zu bestehen.","en":"You have to try harder to pass the exam.","ru":"Тебе нужно больше стараться, чтобы сдать экзамен.","vi":"Bạn phải cố gắng hơn nữa để vượt qua kỳ thi.","fa":"برای قبولی در امتحان باید بیشتر تلاش کنید."},{"de":"Sie strengte sich sehr an, pünktlich fertig zu werden.","en":"She made a great effort to finish on time.","ru":"Она очень старалась закончить вовремя.","vi":"Cô đã cố gắng rất nhiều để hoàn thành đúng thời hạn.","fa":"او خیلی تلاش کرد تا به موقع تمام شود."}]},{"word":"sich anziehen","en":"to get dressed","ru":"одеваться","vi":"mặc quần áo","fa":"لباس بپوش","examples":[{"de":"Zieh dich schnell an, wir müssen los!","en":"Get dressed quickly, we have to go!","ru":"Одевайся быстрее, нам пора идти!","vi":"Mặc quần áo nhanh lên, chúng ta phải đi!","fa":"سریع لباس بپوش، باید بریم!"},{"de":"Das Kind kann sich schon allein anziehen.","en":"The child can already get dressed by itself.","ru":"Ребёнок уже умеет одеваться самостоятельно.","vi":"Bé có thể tự mặc quần áo.","fa":"کودک می تواند خودش لباس بپوشد."}]},{"word":"sich ärgern","en":"to be annoyed, get angry","ru":"злиться, раздражаться","vi":"tức giận","fa":"عصبانی شدن","examples":[{"de":"Ich ärgere mich über den langsamen Internetanschluss.","en":"I'm annoyed about the slow internet connection.","ru":"Я злюсь из-за медленного интернет-соединения.","vi":"Tôi khó chịu vì kết nối internet chậm.","fa":"من از سرعت پایین اینترنت ناراحتم."},{"de":"Er ärgert sich, weil der Bus wieder Verspätung hat.","en":"He is annoyed because the bus is late again.","ru":"Он раздражается, потому что автобус снова опаздывает.","vi":"Er ärgert sich, weil der Bus wieder Verspätung hat.","fa":"او اذیت می شود چون اتوبوس دوباره دیر می شود."}]},{"word":"sich ausruhen","en":"to rest","ru":"отдыхать","vi":"nghỉ ngơi","fa":"برای استراحت","examples":[{"de":"Nach der langen Reise muss ich mich ausruhen.","en":"After the long journey I need to rest.","ru":"После долгого путешествия мне нужно отдохнуть.","vi":"Sau cuộc hành trình dài tôi cần phải nghỉ ngơi.","fa":"بعد از سفر طولانی نیاز به استراحت دارم."},{"de":"Setz dich hin und ruh dich ein bisschen aus.","en":"Sit down and rest a little.","ru":"Присядь и немного отдохни.","vi":"Sit down and rest a bit.","fa":"بنشین و کمی استراحت کن."}]},{"word":"sich bedanken","en":"to thank someone","ru":"благодарить","vi":"cảm ơn bạn","fa":"متشکرم","examples":[{"de":"Ich möchte mich bei Ihnen für die Hilfe bedanken.","en":"I would like to thank you for your help.","ru":"Я хотел бы поблагодарить вас за помощь.","vi":"Tôi muốn cảm ơn sự giúp đỡ của bạn.","fa":"من می خواهم از شما برای کمک تشکر کنم."},{"de":"Sie bedankte sich herzlich für das Geschenk.","en":"She thanked him warmly for the gift.","ru":"Она сердечно поблагодарила за подарок.","vi":"Cô cảm ơn anh rất nhiều vì món quà.","fa":"او از او برای هدیه بسیار تشکر کرد."}]},{"word":"sich beeilen","en":"to hurry","ru":"спешить, торопиться","vi":"nhanh lên","fa":"عجله کن","examples":[{"de":"Wir müssen uns beeilen, sonst verpassen wir den Zug.","en":"We have to hurry, or we'll miss the train.","ru":"Нам нужно поторопиться, иначе мы опоздаем на поезд.","vi":"Chúng ta phải nhanh lên nếu không chúng ta sẽ lỡ chuyến tàu.","fa":"باید عجله کنیم وگرنه قطار را از دست می دهیم."},{"de":"Beeil dich, das Essen wird kalt!","en":"Hurry up, the food is getting cold!","ru":"Поторопись, еда остывает!","vi":"Nhanh lên, đồ ăn sắp nguội rồi!","fa":"عجله کن غذا داره سرد میشه!"}]},{"word":"sich befinden","en":"to be located","ru":"находиться","vi":"được đặt","fa":"واقع شده اند","examples":[{"de":"Das Museum befindet sich im Stadtzentrum.","en":"The museum is located in the city center.","ru":"Музей находится в центре города.","vi":"Bảo tàng nằm ở trung tâm thành phố.","fa":"این موزه در مرکز شهر واقع شده است."},{"de":"Wo befindet sich der nächste Bahnhof?","en":"Where is the nearest train station located?","ru":"Где находится ближайший вокзал?","vi":"Ga xe lửa gần nhất ở đâu?","fa":"نزدیکترین ایستگاه قطار کجاست؟"}]},{"word":"sich bemühen","en":"to make an effort, try hard","ru":"стараться","vi":"nỗ lực","fa":"تلاش کن","examples":[{"de":"Ich bemühe mich, jeden Tag Deutsch zu üben.","en":"I make an effort to practice German every day.","ru":"Я стараюсь заниматься немецким каждый день.","vi":"Tôi cố gắng luyện tập tiếng Đức mỗi ngày.","fa":"سعی می کنم هر روز آلمانی تمرین کنم."},{"de":"Sie bemüht sich sehr um gute Noten.","en":"She tries very hard to get good grades.","ru":"Она очень старается получить хорошие оценки.","vi":"Cô ấy cố gắng rất nhiều để đạt được điểm cao.","fa":"او خیلی تلاش می کند تا نمرات خوبی بگیرد."}]},{"word":"sich beschweren","en":"to complain","ru":"жаловаться","vi":"phàn nàn","fa":"شکایت کردن","examples":[{"de":"Der Gast beschwerte sich über den Lärm.","en":"The guest complained about the noise.","ru":"Гость пожаловался на шум.","vi":"Khách phàn nàn về tiếng ồn.","fa":"مهمان از سر و صدا شکایت کرد."},{"de":"Ich möchte mich über den schlechten Service beschweren.","en":"I would like to complain about the poor service.","ru":"Я хотел бы пожаловаться на плохое обслуживание.","vi":"Tôi muốn phàn nàn về dịch vụ kém.","fa":"من می خواهم از خدمات ضعیف شکایت کنم."}]},{"word":"sich beteiligen","en":"to participate, take part","ru":"участвовать","vi":"tham gia","fa":"شرکت کنند","examples":[{"de":"Viele Studenten beteiligen sich an der Diskussion.","en":"Many students take part in the discussion.","ru":"Многие студенты участвуют в дискуссии.","vi":"Nhiều sinh viên tham gia thảo luận.","fa":"بسیاری از دانش آموزان در بحث شرکت می کنند."},{"de":"Ich möchte mich an dem Projekt beteiligen.","en":"I would like to participate in the project.","ru":"Я хотел бы принять участие в проекте.","vi":"Tôi muốn tham gia vào dự án.","fa":"من دوست دارم در پروژه شرکت کنم."}]},{"word":"sich bewerben","en":"to apply (for a job)","ru":"подавать заявку, претендовать (на работу)","vi":"áp dụng","fa":"اعمال شود","examples":[{"de":"Ich habe mich um eine Stelle als Lehrer beworben.","en":"I applied for a position as a teacher.","ru":"Я подал заявку на должность учителя.","vi":"Tôi đã nộp đơn xin việc làm giáo viên.","fa":"من برای شغل معلمی درخواست دادم."},{"de":"Viele Studenten bewerben sich um dieses Stipendium.","en":"Many students apply for this scholarship.","ru":"Многие студенты подают заявки на эту стипендию.","vi":"Rất nhiều sinh viên nộp đơn xin học bổng này.","fa":"بسیاری از دانشجویان برای این بورسیه درخواست می کنند."}]},{"word":"sich duschen","en":"to shower","ru":"принимать душ","vi":"đi tắm","fa":"دوش بگیر","examples":[{"de":"Ich dusche mich jeden Morgen kalt.","en":"I take a cold shower every morning.","ru":"Я каждое утро принимаю холодный душ.","vi":"Tôi tắm nước lạnh vào mỗi buổi sáng.","fa":"من هر روز صبح دوش آب سرد میگیرم."},{"de":"Nach dem Training duscht er sich sofort.","en":"After training he showers immediately.","ru":"После тренировки он сразу принимает душ.","vi":"Sau khi tập luyện, anh ấy đi tắm ngay lập tức.","fa":"بعد از تمرین بلافاصله دوش می گیرد."}]},{"word":"sich eignen","en":"to be suitable","ru":"подходить, годиться","vi":"phù hợp","fa":"مناسب هستند","examples":[{"de":"Dieser Stoff eignet sich gut für Sommerkleidung.","en":"This fabric is well suited for summer clothing.","ru":"Эта ткань хорошо подходит для летней одежды.","vi":"Loại vải này rất tốt cho quần áo mùa hè.","fa":"این پارچه برای لباس های تابستانی مناسب است."},{"de":"Er eignet sich nicht für diesen Job.","en":"He is not suited for this job.","ru":"Он не подходит для этой работы.","vi":"Anh ấy không phù hợp với công việc này.","fa":"او برای این کار مناسب نیست"}]},{"word":"sich einigen","en":"to agree, to come to an agreement","ru":"договариваться","vi":"đồng ý","fa":"موافق","examples":[{"de":"Die beiden Firmen haben sich auf einen Preis geeinigt.","en":"The two companies agreed on a price.","ru":"Обе компании договорились о цене.","vi":"Hai công ty đã thống nhất được giá cả.","fa":"دو شرکت بر سر قیمت به توافق رسیده اند."},{"de":"Wir konnten uns nicht einigen, wohin wir fahren.","en":"We couldn't agree on where to go.","ru":"Мы не смогли договориться, куда поехать.","vi":"Chúng tôi không thể đồng ý về nơi sẽ đi.","fa":"نمی توانستیم به توافق برسیم که کجا برویم."}]},{"word":"sich entschließen","en":"to decide, make up one's mind","ru":"решиться, принять решение","vi":"quyết định","fa":"تصمیم بگیرند","examples":[{"de":"Nach langem Überlegen entschloss sie sich, das Studium zu wechseln.","en":"After much thought, she decided to change her studies.","ru":"После долгих раздумий она решилась сменить учёбу.","vi":"Sau nhiều cân nhắc, cô quyết định thay đổi việc học.","fa":"او پس از بررسی های زیاد تصمیم گرفت که درسش را تغییر دهد."},{"de":"Wir haben uns entschlossen, umzuziehen.","en":"We have decided to move.","ru":"Мы решились переехать.","vi":"Chúng tôi đã quyết định di chuyển.","fa":"ما تصمیم گرفته ایم که حرکت کنیم."}]},{"word":"sich entwickeln","en":"to develop; to evolve","ru":"развиваться","vi":"phát triển","fa":"توسعه دهد","examples":[{"de":"Die Stadt hat sich in zehn Jahren stark entwickelt.","en":"The city has developed a lot in ten years.","ru":"Город сильно изменился за десять лет.","vi":"Thành phố đã phát triển rất nhiều trong mười năm.","fa":"این شهر در ده سال پیشرفت زیادی کرده است."},{"de":"Das Kind entwickelt sich ganz normal.","en":"The child is developing quite normally.","ru":"Ребёнок развивается совершенно нормально.","vi":"Bé đang phát triển bình thường.","fa":"کودک در حال رشد طبیعی است."}]},{"word":"sich erholen","en":"to recover; to relax","ru":"отдыхать, восстанавливаться","vi":"phục hồi","fa":"بهبود می یابند","examples":[{"de":"Nach der Krankheit musste er sich lange erholen.","en":"After the illness he had to recover for a long time.","ru":"После болезни ему пришлось долго восстанавливаться.","vi":"Sau cơn bệnh, anh phải hồi phục một thời gian dài.","fa":"پس از این بیماری او برای مدت طولانی مجبور به بهبودی شد."},{"de":"Im Urlaub kann man sich gut erholen.","en":"On vacation you can relax well.","ru":"В отпуске можно хорошо отдохнуть.","vi":"Bạn có thể thư giãn tốt trong kỳ nghỉ.","fa":"در تعطیلات می توانید به خوبی استراحت کنید."}]},{"word":"sich erkälten","en":"to catch a cold","ru":"простудиться","vi":"bị cảm lạnh","fa":"سرماخوردگی","examples":[{"de":"Zieh dich warm an, sonst erkältest du dich.","en":"Dress warmly, otherwise you'll catch a cold.","ru":"Одевайся теплее, иначе простудишься.","vi":"Mặc ấm vào nếu không bạn sẽ bị cảm lạnh đấy.","fa":"لباس گرم بپوشید وگرنه سرما می خورید."},{"de":"Ich habe mich letzte Woche erkältet.","en":"I caught a cold last week.","ru":"На прошлой неделе я простудился.","vi":"Tôi bị cảm lạnh tuần trước.","fa":"هفته پیش سرما خوردم"}]},{"word":"sich erkundigen","en":"to inquire, ask about","ru":"справляться, узнавать (информацию)","vi":"hỏi thăm","fa":"پرس و جو کنید","examples":[{"de":"Ich möchte mich nach den Öffnungszeiten erkundigen.","en":"I would like to inquire about the opening hours.","ru":"Я хотел бы узнать о часах работы.","vi":"Tôi muốn hỏi về thời gian mở cửa.","fa":"من می خواهم در مورد زمان باز کردن پرس و جو کنم."},{"de":"Er hat sich beim Arzt nach den Testergebnissen erkundigt.","en":"He inquired with the doctor about the test results.","ru":"Он справился у врача о результатах анализов.","vi":"Anh ấy hỏi bác sĩ về kết quả xét nghiệm.","fa":"او از دکتر در مورد نتایج آزمایش پرسید."}]},{"word":"sich etwas gefallen lassen","en":"to put up with something, to tolerate something","ru":"мириться с чем-либо, терпеть что-либо","vi":"chịu đựng cái gì đó","fa":"تحمل کردن چیزی","examples":[{"de":"Ich lasse mir diese Unhöflichkeit nicht länger gefallen.","en":"I won't put up with this rudeness any longer.","ru":"Я больше не буду мириться с этой грубостью.","vi":"Tôi sẽ không chịu đựng sự thô lỗ này nữa.","fa":"من دیگر این بی ادبی را تحمل نمی کنم."},{"de":"Warum lässt du dir das gefallen?","en":"Why do you put up with that?","ru":"Почему ты это терпишь?","vi":"Tại sao bạn lại chịu đựng điều này?","fa":"چرا این را تحمل می کنید؟"}]},{"word":"sich freuen","en":"to be happy, look forward to","ru":"радоваться","vi":"hãy hạnh phúc","fa":"شاد باش","examples":[{"de":"Ich freue mich schon sehr auf die Ferien.","en":"I'm already really looking forward to the holidays.","ru":"Я уже очень жду каникул.","vi":"Tôi thực sự mong chờ những ngày nghỉ lễ.","fa":"من واقعاً منتظر تعطیلات هستم."},{"de":"Sie freute sich riesig über das Geschenk.","en":"She was overjoyed about the gift.","ru":"Она очень обрадовалась подарку.","vi":"Cô ấy rất vui về món quà.","fa":"او از این هدیه بسیار خوشحال شد."}]},{"word":"sich fürchten","en":"to be afraid","ru":"бояться","vi":"sợ hãi","fa":"بترس","examples":[{"de":"Kleine Kinder fürchten sich oft vor der Dunkelheit.","en":"Small children are often afraid of the dark.","ru":"Маленькие дети часто боятся темноты.","vi":"Trẻ nhỏ thường sợ bóng tối.","fa":"بچه های کوچک اغلب از تاریکی می ترسند."},{"de":"Ich fürchte mich vor Spinnen.","en":"I'm afraid of spiders.","ru":"Я боюсь пауков.","vi":"Tôi sợ nhện.","fa":"من از عنکبوت می ترسم"}]},{"word":"sich irren","en":"to be mistaken","ru":"ошибаться","vi":"sai","fa":"اشتباه کن","examples":[{"de":"Entschuldigung, ich habe mich geirrt, das ist die falsche Nummer.","en":"Sorry, I was mistaken, that's the wrong number.","ru":"Извините, я ошибся, это неправильный номер.","vi":"Xin lỗi, tôi nhầm, nhầm số rồi.","fa":"ببخشید اشتباه کردم، این شماره اشتباه است."},{"de":"Jeder kann sich mal irren.","en":"Everyone can be wrong sometimes.","ru":"Каждый может иногда ошибаться.","vi":"Mọi người đôi khi có thể sai.","fa":"همه ممکن است گاهی اشتباه کنند."}]},{"word":"sich konzentrieren","en":"to concentrate","ru":"концентрироваться, сосредотачиваться","vi":"tập trung","fa":"متمرکز کردن","examples":[{"de":"Ich kann mich bei Lärm nicht konzentrieren.","en":"I can't concentrate when there's noise.","ru":"Я не могу сосредоточиться при шуме.","vi":"Tôi không thể tập trung trong tiếng ồn.","fa":"من نمی توانم در سر و صدا تمرکز کنم."},{"de":"Konzentriere dich bitte auf die Aufgabe.","en":"Please concentrate on the task.","ru":"Пожалуйста, сосредоточься на задании.","vi":"Hãy tập trung vào nhiệm vụ.","fa":"لطفا روی کار تمرکز کنید"}]},{"word":"sich kümmern","en":"to take care of, look after","ru":"заботиться","vi":"chăm sóc","fa":"مراقبت از","examples":[{"de":"Sie kümmert sich liebevoll um ihre kranke Mutter.","en":"She lovingly takes care of her sick mother.","ru":"Она с любовью заботится о своей больной матери.","vi":"Cô tận tình chăm sóc người mẹ ốm yếu của mình.","fa":"او با عشق از مادر بیمارش مراقبت می کند."},{"de":"Wer kümmert sich um den Hund, wenn ihr im Urlaub seid?","en":"Who will take care of the dog while you're on vacation?","ru":"Кто позаботится о собаке, пока вы в отпуске?","vi":"Ai sẽ chăm sóc con chó khi bạn đi nghỉ?","fa":"وقتی در تعطیلات هستید چه کسی از سگ مراقبت می کند؟"}]},{"word":"sich langweilen","en":"to be bored","ru":"скучать","vi":"chán nản","fa":"خسته شدن","examples":[{"de":"Die Kinder langweilen sich im Regen.","en":"The children are bored in the rain.","ru":"Дети скучают под дождём.","vi":"Lũ trẻ buồn chán dưới mưa.","fa":"بچه ها زیر باران خسته شده اند."},{"de":"Ich habe mich auf der Party gelangweilt.","en":"I was bored at the party.","ru":"Мне было скучно на вечеринке.","vi":"Tôi cảm thấy chán ở bữa tiệc.","fa":"در مهمانی حوصله ام سر رفته بود."}]},{"word":"sich lohnen","en":"to be worth it","ru":"стоить (того); окупаться","vi":"đáng giá","fa":"ارزشش را دارد","examples":[{"de":"Es lohnt sich, früh aufzustehen und die Sonne zu sehen.","en":"It's worth getting up early to see the sun.","ru":"Стоит встать пораньше, чтобы увидеть солнце.","vi":"Thật đáng để dậy sớm và ngắm mặt trời.","fa":"ارزش این را دارد که زود بیدار شوید و خورشید را ببینید."},{"de":"Diese Investition hat sich wirklich gelohnt.","en":"This investment really paid off.","ru":"Эта инвестиция действительно окупилась.","vi":"Khoản đầu tư này thực sự đáng giá.","fa":"این سرمایه گذاری واقعا ارزشش را داشت."}]},{"word":"sich nähern","en":"to approach, to come closer","ru":"приближаться","vi":"cách tiếp cận","fa":"رویکرد","examples":[{"de":"Der Zug nähert sich langsam dem Bahnhof.","en":"The train is slowly approaching the station.","ru":"Поезд медленно приближается к вокзалу.","vi":"Con tàu đang dần tiến đến ga.","fa":"قطار کم کم به ایستگاه نزدیک می شود."},{"de":"Die Prüfung nähert sich, deshalb lerne ich jeden Tag.","en":"The exam is approaching, so I study every day.","ru":"Экзамен приближается, поэтому я занимаюсь каждый день.","vi":"Kỳ thi đang đến gần nên tôi học mỗi ngày.","fa":"امتحان نزدیک است، بنابراین من هر روز مطالعه می کنم."}]},{"word":"sich rasieren","en":"to shave (oneself)","ru":"бриться","vi":"tự cạo râu","fa":"خود را بتراش","examples":[{"de":"Mein Vater rasiert sich jeden Morgen.","en":"My father shaves every morning.","ru":"Мой отец бреется каждое утро.","vi":"Bố tôi cạo râu mỗi sáng.","fa":"پدرم هر روز صبح اصلاح می کند."},{"de":"Ich habe mich heute noch nicht rasiert.","en":"I haven't shaved yet today.","ru":"Я сегодня ещё не побрился.","vi":"Hôm nay tôi chưa cạo râu.","fa":"من امروز اصلاح نکردم"}]},{"word":"sich scheiden lassen","en":"to get divorced","ru":"разводиться","vi":"ly hôn","fa":"طلاق گرفتن","examples":[{"de":"Meine Eltern haben sich vor zwei Jahren scheiden lassen.","en":"My parents got divorced two years ago.","ru":"Мои родители развелись два года назад.","vi":"Bố mẹ tôi ly hôn cách đây hai năm.","fa":"پدر و مادرم دو سال پیش طلاق گرفتند."},{"de":"Sie will sich von ihrem Mann scheiden lassen.","en":"She wants to divorce her husband.","ru":"Она хочет развестись с мужем.","vi":"Cô ấy muốn ly hôn với chồng.","fa":"او می خواهد از شوهرش طلاق بگیرد."}]},{"word":"sich schneiden","en":"to cut oneself","ru":"порезаться","vi":"cắt nhau","fa":"یکدیگر را قطع کنید","examples":[{"de":"Beim Kochen hat sie sich in den Finger geschnitten.","en":"While cooking, she cut her finger.","ru":"Готовя еду, она порезала палец.","vi":"Cô ấy bị đứt tay khi đang nấu ăn.","fa":"هنگام آشپزی انگشتش را برید."},{"de":"Pass auf, dass du dich mit dem Messer nicht schneidest.","en":"Be careful not to cut yourself with the knife.","ru":"Будь осторожен, не порежься ножом.","vi":"Hãy cẩn thận để không tự cắt mình bằng dao.","fa":"مراقب باشید خود را با چاقو نبرید."}]},{"word":"sich setzen","en":"to sit down","ru":"садиться","vi":"ngồi xuống","fa":"بنشین","examples":[{"de":"Bitte setzen Sie sich auf diesen Stuhl.","en":"Please sit down on this chair.","ru":"Пожалуйста, садитесь на этот стул.","vi":"Xin hãy ngồi lên chiếc ghế này.","fa":"لطفا روی این صندلی بنشینید"},{"de":"Er setzte sich neben seine Schwester.","en":"He sat down next to his sister.","ru":"Он сел рядом со своей сестрой.","vi":"Anh ngồi xuống cạnh em gái mình.","fa":"کنار خواهرش نشست."}]},{"word":"sich siezen","en":"to address each other formally (with \"Sie\")","ru":"обращаться друг к другу на «вы»","vi":"ngồi xuống","fa":"بنشین","examples":[{"de":"Kollegen siezen sich in dieser Firma meistens.","en":"Colleagues usually address each other formally in this company.","ru":"Коллеги в этой фирме обычно обращаются друг к другу на «вы».","vi":"Đồng nghiệp chủ yếu ngồi cùng nhau trong công ty này.","fa":"همکاران بیشتر در این شرکت دور هم می نشینند."},{"de":"Sollen wir uns siezen oder duzen?","en":"Should we address each other formally or informally?","ru":"Нам обращаться друг к другу на «вы» или на «ты»?","vi":"Chúng ta nên sử dụng thuật ngữ tên riêng hay tên riêng?","fa":"آیا باید بر اساس اصطلاحات اسمی باشیم یا از نظر اسمی؟"}]},{"word":"sich stoßen","en":"to bump oneself; to knock (against something)","ru":"удариться (обо что-л.)","vi":"va vào nhau","fa":"به یکدیگر برخورد کنند","examples":[{"de":"Ich habe mich am Tisch gestoßen.","en":"I bumped myself on the table.","ru":"Я ударился о стол.","vi":"Tôi va vào bàn.","fa":"به میز برخورد کردم."},{"de":"Pass auf, dass du dir nicht den Kopf stößt.","en":"Watch out that you don't bump your head.","ru":"Смотри не ударься головой.","vi":"Hãy cẩn thận để không bị đánh vào đầu.","fa":"مواظب باش سرت نخورد."}]},{"word":"sich streiten","en":"to argue; to quarrel","ru":"ссориться; спорить","vi":"tranh luận","fa":"بحث کنید","examples":[{"de":"Die Geschwister streiten sich oft um das Spielzeug.","en":"The siblings often argue over the toy.","ru":"Братья и сёстры часто ссорятся из-за игрушки.","vi":"Hai anh em thường xuyên tranh nhau đồ chơi.","fa":"خواهر و برادر اغلب بر سر اسباب بازی با هم دعوا می کنند."},{"de":"Wir haben uns gestern über Politik gestritten.","en":"We argued about politics yesterday.","ru":"Мы вчера спорили о политике.","vi":"Hôm qua chúng tôi đã tranh luận về chính trị.","fa":"دیروز سر سیاست بحث کردیم."}]},{"word":"sich trennen","en":"to separate, to break up","ru":"расставаться, разводиться","vi":"riêng biệt","fa":"جدا کردن","examples":[{"de":"Meine Eltern haben sich vor zwei Jahren getrennt.","en":"My parents separated two years ago.","ru":"Мои родители расстались два года назад.","vi":"Bố mẹ tôi đã ly thân cách đây hai năm.","fa":"پدر و مادرم دو سال پیش از هم جدا شدند."},{"de":"Wir trennen uns hier, ich muss nach Hause.","en":"We part here, I have to go home.","ru":"Здесь мы расстаёмся, мне нужно домой.","vi":"Chúng ta chia tay ở đây, tôi phải về nhà.","fa":"اینجا داریم از هم جدا میشیم، باید برم خونه."}]},{"word":"sich überzeugen","en":"to convince oneself, make sure","ru":"убеждаться","vi":"thuyết phục bản thân","fa":"خودت را متقاعد کن","examples":[{"de":"Ich habe mich selbst von der Qualität überzeugt.","en":"I convinced myself of the quality.","ru":"Я сам убедился в качестве.","vi":"Tôi đã thuyết phục bản thân về chất lượng.","fa":"من خودم را به کیفیت متقاعد کردم."},{"de":"Überzeug dich am besten selbst davon.","en":"You'd best see for yourself.","ru":"Лучше убедись в этом сам.","vi":"Tốt nhất là bạn nên tự mình xem.","fa":"بهتر است خودتان ببینید."}]},{"word":"sich umdrehen","en":"to turn around","ru":"оборачиваться","vi":"quay lại","fa":"برگرد","examples":[{"de":"Sie drehte sich um und lächelte mich an.","en":"She turned around and smiled at me.","ru":"Она обернулась и улыбнулась мне.","vi":"Cô ấy quay lại và mỉm cười với tôi.","fa":"برگشت و به من لبخند زد."},{"de":"Dreh dich bitte nicht um!","en":"Please don't turn around!","ru":"Пожалуйста, не оборачивайся!","vi":"Làm ơn đừng quay lại!","fa":"لطفا برنگردید!"}]},{"word":"sich umziehen","en":"to change clothes","ru":"переодеваться","vi":"thay quần áo","fa":"لباس عوض کن","examples":[{"de":"Ich muss mich noch umziehen, bevor wir gehen.","en":"I still need to change clothes before we go.","ru":"Мне нужно ещё переодеться, прежде чем мы пойдём.","vi":"Tôi phải thay đồ trước khi chúng ta rời đi.","fa":"قبل از رفتن باید تغییر کنم."},{"de":"Zieh dich schnell um, wir sind spät dran!","en":"Change quickly, we're running late!","ru":"Быстро переоденься, мы опаздываем!","vi":"Mau thay đồ đi, chúng ta muộn rồi!","fa":"زود عوضش کن دیر رسیدیم"}]},{"word":"sich unterhalten","en":"to converse, chat","ru":"беседовать","vi":"trò chuyện","fa":"چت کنید","examples":[{"de":"Wir haben uns lange über Politik unterhalten.","en":"We talked for a long time about politics.","ru":"Мы долго беседовали о политике.","vi":"Chúng tôi đã nói chuyện rất lâu về chính trị.","fa":"ما مدت زیادی در مورد سیاست صحبت کردیم."},{"de":"Die beiden unterhalten sich sehr gern miteinander.","en":"The two of them really like chatting with each other.","ru":"Эти двое очень любят беседовать друг с другом.","vi":"Hai người họ thực sự rất thích nói chuyện với nhau.","fa":"آن دو واقعا از صحبت کردن با یکدیگر لذت می برند."}]},{"word":"sich verabreden","en":"to arrange to meet, make a date","ru":"договариваться о встрече","vi":"sắp xếp gặp nhau","fa":"قرار ملاقات","examples":[{"de":"Wir haben uns für morgen Abend verabredet.","en":"We arranged to meet tomorrow evening.","ru":"Мы договорились встретиться завтра вечером.","vi":"Chúng tôi đã sắp xếp để gặp nhau vào tối mai.","fa":"قرار گذاشتیم فردا عصر همدیگر را ببینیم."},{"de":"Ich habe mich mit einer Freundin zum Kaffee verabredet.","en":"I arranged to meet a friend for coffee.","ru":"Я договорилась встретиться с подругой за кофе.","vi":"Tôi hẹn gặp một người bạn để uống cà phê.","fa":"قرار گذاشتم برای قهوه با یکی از دوستانم ملاقات کنم."}]},{"word":"sich verabschieden","en":"to say goodbye","ru":"прощаться","vi":"nói lời tạm biệt","fa":"خداحافظی کن","examples":[{"de":"Wir haben uns herzlich voneinander verabschiedet.","en":"We said goodbye to each other warmly.","ru":"Мы тепло попрощались друг с другом.","vi":"Chúng tôi chào tạm biệt nhau một cách ấm áp.","fa":"به گرمی از هم خداحافظی کردیم."},{"de":"Ich muss mich jetzt verabschieden, mein Bus kommt gleich.","en":"I have to say goodbye now, my bus is coming soon.","ru":"Мне нужно попрощаться, мой автобус скоро придёт.","vi":"Bây giờ tôi phải nói lời tạm biệt, xe buýt của tôi sắp đến rồi.","fa":"الان باید خداحافظی کنم، اتوبوسم به زودی می آید."}]},{"word":"sich verändern","en":"to change","ru":"меняться, изменяться","vi":"thay đổi","fa":"تغییر دهید","examples":[{"de":"Die Stadt hat sich in den letzten Jahren stark verändert.","en":"The city has changed a lot in recent years.","ru":"Город сильно изменился за последние годы.","vi":"Thành phố đã thay đổi rất nhiều trong những năm gần đây.","fa":"این شهر در سال های اخیر تغییرات زیادی کرده است."},{"de":"Er hat sich seit der Schulzeit kaum verändert.","en":"He has hardly changed since school days.","ru":"Он почти не изменился со школьных времён.","vi":"Anh ấy không thay đổi nhiều kể từ khi còn đi học.","fa":"از زمانی که در مدرسه بوده تغییر چندانی نکرده است."}]},{"word":"sich verbessern","en":"to improve","ru":"улучшаться","vi":"cải thiện","fa":"بهبود بخشد","examples":[{"de":"Meine Deutschkenntnisse haben sich verbessert.","en":"My German skills have improved.","ru":"Мои знания немецкого улучшились.","vi":"Kỹ năng tiếng Đức của tôi đã được cải thiện.","fa":"مهارت های آلمانی من بهبود یافته است."},{"de":"Er möchte sich im Sport verbessern.","en":"He wants to improve in sports.","ru":"Он хочет улучшить свои результаты в спорте.","vi":"Anh ấy muốn tiến bộ trong thể thao.","fa":"او می خواهد در ورزش پیشرفت کند."}]},{"word":"sich verbrennen","en":"to burn oneself","ru":"обжигаться","vi":"đốt cháy chính mình","fa":"خودت را بسوزان","examples":[{"de":"Ich habe mir am Herd die Hand verbrannt.","en":"I burned my hand on the stove.","ru":"Я обжёг руку о плиту.","vi":"Tôi bị bỏng tay trên bếp.","fa":"دستم را روی اجاق گاز سوزاندم."},{"de":"Pass auf, dass du dich nicht verbrennst!","en":"Watch out that you don't burn yourself!","ru":"Смотри, не обожгись!","vi":"Hãy cẩn thận để không bị bỏng!","fa":"مواظب باش خودت نسوزی!"}]},{"word":"sich vergnügen","en":"to enjoy oneself, have fun","ru":"развлекаться, веселиться","vi":"chúc vui vẻ","fa":"خوش بگذره","examples":[{"de":"Die Kinder vergnügen sich am Strand mit einem Ball.","en":"The children enjoy themselves at the beach with a ball.","ru":"Дети развлекаются на пляже с мячом.","vi":"Trẻ em vui đùa với quả bóng trên bãi biển.","fa":"بچه ها با یک توپ در ساحل مشغول تفریح هستند."},{"de":"Wir haben uns auf dem Fest königlich vergnügt.","en":"We had a wonderful time at the party.","ru":"Мы прекрасно повеселились на празднике.","vi":"Chúng tôi đã có một thời gian tuyệt vời tại lễ hội.","fa":"در جشنواره به ما خوش گذشت."}]},{"word":"sich verhalten","en":"to behave","ru":"вести себя","vi":"cư xử","fa":"رفتار کن","examples":[{"de":"Die Schüler haben sich im Unterricht ruhig verhalten.","en":"The students behaved quietly during class.","ru":"Ученики вели себя спокойно на уроке.","vi":"Học sinh cư xử yên lặng trong lớp.","fa":"دانش آموزان در کلاس آرام رفتار می کردند."},{"de":"Wie soll man sich in einem Notfall verhalten?","en":"How should one behave in an emergency?","ru":"Как нужно вести себя в чрезвычайной ситуации?","vi":"Bạn nên cư xử thế nào trong trường hợp khẩn cấp?","fa":"در مواقع اضطراری چگونه باید رفتار کرد؟"}]},{"word":"sich verlassen","en":"to rely (on someone)","ru":"полагаться (на кого-либо)","vi":"rời bỏ chính mình","fa":"خودت را رها کن","examples":[{"de":"Auf ihn kann man sich immer verlassen.","en":"You can always rely on him.","ru":"На него всегда можно положиться.","vi":"Bạn luôn có thể dựa vào anh ấy.","fa":"همیشه می توانید به او تکیه کنید."},{"de":"Verlass dich nicht zu sehr auf dein Glück.","en":"Don't rely too much on your luck.","ru":"Не полагайся слишком на удачу.","vi":"Đừng dựa quá nhiều vào vận may của mình.","fa":"زیاد به شانس خود تکیه نکنید."}]},{"word":"sich verlaufen","en":"to get lost (on foot)","ru":"заблудиться","vi":"bị lạc","fa":"گم شدن","examples":[{"de":"Wir haben uns im Wald verlaufen.","en":"We got lost in the forest.","ru":"Мы заблудились в лесу.","vi":"Chúng tôi bị lạc trong rừng.","fa":"ما در جنگل گم شدیم."},{"de":"Ohne Karte hätte ich mich in der fremden Stadt verlaufen.","en":"Without a map I would have gotten lost in the unfamiliar city.","ru":"Без карты я бы заблудился в незнакомом городе.","vi":"Nếu không có bản đồ chắc tôi đã lạc vào thành phố xa lạ này.","fa":"بدون نقشه در شهر غریب گم می شدم."}]},{"word":"sich verletzen","en":"to injure oneself, get hurt","ru":"получить травму, пораниться","vi":"làm tổn thương chính mình","fa":"به خود صدمه بزن","examples":[{"de":"Beim Fußballspielen hat er sich am Bein verletzt.","en":"He injured his leg while playing football.","ru":"Играя в футбол, он повредил ногу.","vi":"Anh ấy bị thương ở chân khi chơi bóng đá.","fa":"او در حین بازی فوتبال از ناحیه پای خود آسیب دید."},{"de":"Pass auf, dass du dich mit dem Messer nicht verletzt.","en":"Be careful not to hurt yourself with the knife.","ru":"Осторожно, не пораньтесь ножом.","vi":"Hãy cẩn thận để không làm tổn thương chính mình bằng con dao.","fa":"مراقب باشید با چاقو به خودتان آسیب نزنید."}]},{"word":"sich verlieben","en":"to fall in love","ru":"влюбиться","vi":"yêu","fa":"عاشق شدن","examples":[{"de":"Sie hat sich auf den ersten Blick in ihn verliebt.","en":"She fell in love with him at first sight.","ru":"Она влюбилась в него с первого взгляда.","vi":"Cô đã yêu anh ngay từ cái nhìn đầu tiên.","fa":"در همان نگاه اول عاشق او شد."},{"de":"Die beiden haben sich im Urlaub ineinander verliebt.","en":"The two fell in love with each other during the vacation.","ru":"Они влюбились друг в друга во время отпуска.","vi":"Hai người yêu nhau khi đi nghỉ.","fa":"این دو در تعطیلات عاشق یکدیگر شدند."}]},{"word":"sich verschlechtern","en":"to get worse; to deteriorate","ru":"ухудшаться","vi":"xấu đi","fa":"بدتر شدن","examples":[{"de":"Sein Gesundheitszustand hat sich verschlechtert.","en":"His state of health has deteriorated.","ru":"Его состояние здоровья ухудшилось.","vi":"Sức khỏe của anh ấy đã xấu đi.","fa":"وضعیت سلامتی او بدتر شده است."},{"de":"Wenn du nicht übst, verschlechtert sich dein Deutsch.","en":"If you don't practise, your German gets worse.","ru":"Если ты не будешь заниматься, твой немецкий ухудшится.","vi":"Nếu bạn không luyện tập, tiếng Đức của bạn sẽ kém đi.","fa":"اگر تمرین نکنید، آلمانی شما خراب می شود."}]},{"word":"sich verstecken","en":"to hide (oneself)","ru":"прятаться","vi":"trốn","fa":"پنهان کردن","examples":[{"de":"Die Kinder haben sich im Garten versteckt.","en":"The children hid in the garden.","ru":"Дети спрятались в саду.","vi":"Bọn trẻ trốn trong vườn.","fa":"بچه ها در باغ پنهان شدند."},{"de":"Er versteckte sich hinter dem Vorhang.","en":"He hid behind the curtain.","ru":"Он спрятался за занавеской.","vi":"Anh trốn sau tấm rèm.","fa":"پشت پرده پنهان شد."}]},{"word":"sich verstehen","en":"to get along (with someone), to understand each other","ru":"ладить, понимать друг друга","vi":"hiểu nhau","fa":"یکدیگر را درک کنند","examples":[{"de":"Wir verstehen uns sehr gut mit unseren Nachbarn.","en":"We get along very well with our neighbors.","ru":"Мы очень хорошо ладим с нашими соседями.","vi":"Chúng tôi rất hòa thuận với hàng xóm của mình.","fa":"ما با همسایه هایمان خیلی خوب هستیم."},{"de":"Trotz der Sprachbarriere haben wir uns gut verstanden.","en":"Despite the language barrier, we understood each other well.","ru":"Несмотря на языковой барьер, мы хорошо понимали друг друга.","vi":"Bất chấp rào cản ngôn ngữ, chúng tôi rất hợp nhau.","fa":"با وجود مانع زبانی، با هم خوب بودیم."}]},{"word":"sich vorbereiten","en":"to prepare (oneself)","ru":"готовиться","vi":"chuẩn bị cho mình","fa":"خودت را آماده کن","examples":[{"de":"Ich bereite mich gerade auf die Prüfung vor.","en":"I'm currently preparing for the exam.","ru":"Я сейчас готовлюсь к экзамену.","vi":"Ich bereite mich gerade auf die Prüfung vor.","fa":"در حال حاضر برای امتحان آماده می شوم."},{"de":"Wir müssen uns gut auf das Gespräch vorbereiten.","en":"We need to prepare well for the interview.","ru":"Нам нужно хорошо подготовиться к беседе.","vi":"Chúng ta phải chuẩn bị tốt cho cuộc phỏng vấn.","fa":"باید برای مصاحبه خوب آماده شویم."}]},{"word":"sich vorstellen","en":"to imagine; to introduce oneself","ru":"представлять себе; представляться","vi":"tưởng tượng","fa":"تصور کنید","examples":[{"de":"Ich kann mir nicht vorstellen, wie das funktionieren soll.","en":"I can't imagine how that's supposed to work.","ru":"Я не могу представить, как это должно работать.","vi":"Tôi không thể tưởng tượng được nó sẽ hoạt động như thế nào.","fa":"من نمی توانم تصور کنم که چگونه این قرار است کار کند."},{"de":"Darf ich mich kurz vorstellen? Ich heiße Anna.","en":"May I briefly introduce myself? My name is Anna.","ru":"Позвольте представиться. Меня зовут Анна.","vi":"Tôi có thể giới thiệu ngắn gọn về bản thân được không? Tên tôi là Anna.","fa":"ممکن است به طور خلاصه خودم را معرفی کنم؟ اسم من آنا است."}]},{"word":"sich waschen","en":"to wash oneself","ru":"мыться","vi":"rửa mình","fa":"خود را بشویید","examples":[{"de":"Ich wasche mich jeden Morgen kalt.","en":"I wash myself with cold water every morning.","ru":"Я умываюсь холодной водой каждое утро.","vi":"Tôi giặt nước lạnh vào mỗi buổi sáng.","fa":"من هر روز صبح سرد می شوم."},{"de":"Die Kinder waschen sich vor dem Essen die Hände.","en":"The children wash their hands before eating.","ru":"Дети моют руки перед едой.","vi":"Trẻ rửa tay trước khi ăn.","fa":"بچه ها قبل از غذا دست های خود را می شویند."}]},{"word":"sich weigern","en":"to refuse","ru":"отказываться","vi":"refuse","fa":"رد کردن","examples":[{"de":"Er weigert sich, die Regeln zu akzeptieren.","en":"He refuses to accept the rules.","ru":"Он отказывается принимать правила.","vi":"Anh ta từ chối chấp nhận các quy tắc.","fa":"او از پذیرش قوانین خودداری می کند."},{"de":"Sie weigerte sich, die Tür zu öffnen.","en":"She refused to open the door.","ru":"Она отказалась открыть дверь.","vi":"Cô từ chối mở cửa.","fa":"او حاضر نشد در را باز کند."}]},{"word":"sich wundern","en":"to be surprised","ru":"удивляться","vi":"ngạc nhiên","fa":"تعجب","examples":[{"de":"Ich wundere mich über sein Verhalten.","en":"I'm surprised by his behavior.","ru":"Я удивляюсь его поведению.","vi":"Tôi ngạc nhiên trước hành vi của anh ấy.","fa":"من از رفتار او تعجب می کنم."},{"de":"Wir wunderten uns, dass niemand da war.","en":"We were surprised that no one was there.","ru":"Мы удивились, что там никого не было.","vi":"Chúng tôi rất ngạc nhiên khi không có ai ở đó.","fa":"ما تعجب کردیم که کسی آنجا نبود."}]},{"word":"sich wünschen","en":"to wish for","ru":"желать себе, хотеть","vi":"ước gì","fa":"آرزو کن","examples":[{"de":"Ich wünsche mir einen ruhigen Urlaub.","en":"I wish for a relaxing vacation.","ru":"Я хочу спокойный отпуск.","vi":"Tôi chúc bạn một kỳ nghỉ yên bình.","fa":"برای شما تعطیلات آرامی آرزو می کنم."},{"de":"Was wünschst du dir zu Weihnachten?","en":"What do you wish for for Christmas?","ru":"Что ты хочешь на Рождество?","vi":"Bạn muốn gì cho Giáng sinh?","fa":"برای کریسمس چه می خواهید؟"}]},{"word":"sich zwingen","en":"to force oneself","ru":"заставлять себя","vi":"sich zwingen","fa":"خودت را مجبور کن","examples":[{"de":"Ich musste mich zwingen, früh aufzustehen.","en":"I had to force myself to get up early.","ru":"Мне пришлось заставить себя рано встать.","vi":"Tôi buộc mình phải dậy sớm.","fa":"مجبور شدم به زور خودم را زود بیدار کنم."},{"de":"Er zwingt sich jeden Tag zum Sport.","en":"He forces himself to exercise every day.","ru":"Он каждый день заставляет себя заниматься спортом.","vi":"Anh buộc mình phải tập thể dục mỗi ngày.","fa":"او خود را مجبور می کند که هر روز ورزش کند."}]},{"word":"sicher","en":"safe; certain","ru":"безопасный; уверенный","vi":"chắc chắn rồi","fa":"مطمئن","examples":[{"de":"Bist du sicher, dass das der richtige Weg ist?","en":"Are you sure that this is the right way?","ru":"Ты уверен, что это правильная дорога?","vi":"Bạn có chắc chắn đây là cách đúng đắn?","fa":"مطمئنی این راه درسته؟"},{"de":"In diesem Viertel fühlen sich die Menschen sicher.","en":"People feel safe in this neighborhood.","ru":"В этом районе люди чувствуют себя в безопасности.","vi":"People feel safe in this neighborhood.","fa":"مردم در این محله احساس امنیت می کنند."}]},{"word":"die Sicherheit","en":"safety; security; certainty","ru":"безопасность; уверенность","vi":"an ninh","fa":"امنیت","examples":[{"de":"Die Sicherheit der Passagiere hat oberste Priorität.","en":"The safety of the passengers is the top priority.","ru":"Безопасность пассажиров — главный приоритет.","vi":"An toàn của hành khách là ưu tiên hàng đầu.","fa":"ایمنی مسافران در اولویت قرار دارد."},{"de":"Ich kann nicht mit Sicherheit sagen, ob er kommt.","en":"I can't say for certain whether he's coming.","ru":"Я не могу сказать с уверенностью, придёт ли он.","vi":"Tôi không thể nói chắc chắn liệu anh ấy có đến hay không.","fa":"نمی توانم با اطمینان بگویم که او می آید یا نه."}]},{"word":"sichern","en":"to secure; to save (data)","ru":"защищать; сохранять (данные)","vi":"an toàn","fa":"امن","examples":[{"de":"Vergiss nicht, deine Daten regelmäßig zu sichern.","en":"Don't forget to back up your data regularly.","ru":"Не забывай регулярно сохранять свои данные.","vi":"Đừng quên sao lưu dữ liệu của bạn thường xuyên.","fa":"فراموش نکنید که به طور منظم از اطلاعات خود نسخه پشتیبان تهیه کنید."},{"de":"Die Polizei sichert den Tatort.","en":"The police are securing the crime scene.","ru":"Полиция охраняет место преступления.","vi":"Cảnh sát bảo vệ hiện trường vụ án.","fa":"پلیس محل جنایت را ایمن می کند."}]},{"word":"sichtbar","en":"visible","ru":"видимый","vi":"có thể nhìn thấy","fa":"قابل مشاهده است","examples":[{"de":"Von hier aus ist der Berg gut sichtbar.","en":"From here, the mountain is clearly visible.","ru":"Отсюда гора хорошо видна.","vi":"Từ đây có thể nhìn thấy rõ ngọn núi.","fa":"از اینجا کوه به وضوح قابل مشاهده است."},{"de":"Die Narbe ist kaum noch sichtbar.","en":"The scar is hardly visible anymore.","ru":"Шрам теперь едва заметен.","vi":"Vết sẹo hầu như không nhìn thấy được.","fa":"جای زخم به سختی قابل مشاهده است."}]},{"word":"siegen","en":"to win; to be victorious","ru":"побеждать","vi":"thắng","fa":"برنده شوید","examples":[{"de":"Unsere Mannschaft hat gestern klar gesiegt.","en":"Our team clearly won yesterday.","ru":"Наша команда вчера уверенно победила.","vi":"Đội của chúng tôi đã thắng rõ ràng ngày hôm qua.","fa":"تیم ما دیروز به وضوح پیروز شد."},{"de":"Wer wird bei diesem Wettbewerb siegen?","en":"Who will win this competition?","ru":"Кто победит в этом соревновании?","vi":"Ai sẽ giành chiến thắng trong cuộc thi này?","fa":"چه کسی برنده این رقابت خواهد شد؟"}]},{"word":"singen","en":"to sing","ru":"петь","vi":"hát","fa":"بخوان","examples":[{"de":"Meine Tochter singt sehr gern im Chor.","en":"My daughter really likes to sing in the choir.","ru":"Моя дочь очень любит петь в хоре.","vi":"Con gái tôi thực sự thích hát trong dàn hợp xướng.","fa":"دخترم از خواندن در گروه کر بسیار لذت می برد."},{"de":"Er singt jeden Abend seinem Baby ein Lied vor.","en":"He sings his baby a song every evening.","ru":"Он каждый вечер поёт своему малышу песню.","vi":"Anh ấy hát một bài hát cho con mình nghe vào mỗi buổi tối.","fa":"او هر روز غروب برای نوزادش آهنگی می خواند."}]},{"word":"sinken","en":"to sink; to decrease","ru":"тонуть; снижаться","vi":"bồn rửa","fa":"غرق شدن","examples":[{"de":"Die Preise für Energie sind im letzten Monat gesunken.","en":"Energy prices have decreased over the last month.","ru":"Цены на энергию снизились за последний месяц.","vi":"Giá năng lượng đã giảm trong tháng qua.","fa":"قیمت انرژی در ماه گذشته کاهش یافته است."},{"de":"Das Schiff begann langsam zu sinken.","en":"The ship began to sink slowly.","ru":"Корабль начал медленно тонуть.","vi":"Con tàu bắt đầu chìm dần.","fa":"کشتی کم کم شروع به غرق شدن کرد."}]},{"word":"der Sinn","en":"sense; meaning","ru":"смысл; чувство","vi":"ý nghĩa","fa":"معنی","examples":[{"de":"Diese Regel ergibt für mich keinen Sinn.","en":"This rule doesn't make sense to me.","ru":"Это правило не имеет для меня смысла.","vi":"Quy tắc này không có ý nghĩa với tôi.","fa":"این قانون برای من معنی ندارد."},{"de":"Der Geruchssinn ist bei Hunden sehr gut entwickelt.","en":"The sense of smell is very well developed in dogs.","ru":"Обоняние у собак очень хорошо развито.","vi":"Khứu giác ở chó rất phát triển.","fa":"حس بویایی در سگ ها بسیار توسعه یافته است."}]},{"word":"die Situation","en":"situation","ru":"ситуация","vi":"tình hình","fa":"وضعیت","examples":[{"de":"Die wirtschaftliche Situation hat sich in den letzten Jahren verbessert.","en":"The economic situation has improved in recent years.","ru":"Экономическая ситуация улучшилась за последние годы.","vi":"Tình hình kinh tế đã được cải thiện trong những năm gần đây.","fa":"وضعیت اقتصادی در سال های اخیر بهبود یافته است."},{"de":"In dieser schwierigen Situation brauchen wir Ihre Hilfe.","en":"In this difficult situation, we need your help.","ru":"В этой сложной ситуации нам нужна ваша помощь.","vi":"Trong tình huống khó khăn này, chúng tôi cần sự giúp đỡ của bạn.","fa":"در این شرایط سخت نیازمند کمک شما هستیم."}]},{"word":"sitzen","en":"to sit","ru":"сидеть","vi":"ngồi","fa":"بنشین","examples":[{"de":"Er sitzt den ganzen Tag am Computer.","en":"He sits at the computer all day.","ru":"Он весь день сидит за компьютером.","vi":"Anh ấy ngồi trước máy tính cả ngày.","fa":"تمام روز پشت کامپیوتر می نشیند."},{"de":"Wir haben lange auf der Bank im Park gesessen.","en":"We sat on the bench in the park for a long time.","ru":"Мы долго сидели на скамейке в парке.","vi":"Chúng tôi ngồi trên băng ghế trong công viên một lúc lâu.","fa":"مدت زیادی روی نیمکت پارک نشستیم."}]},{"word":"der Ski/Schi","en":"ski","ru":"лыжа","vi":"trượt tuyết/trượt tuyết","fa":"اسکی/اسکی","examples":[{"de":"Im Winter fahren wir jedes Jahr Ski in den Alpen.","en":"In winter, we go skiing in the Alps every year.","ru":"Зимой мы каждый год катаемся на лыжах в Альпах.","vi":"Chúng tôi trượt tuyết trên dãy Alps hàng năm vào mùa đông.","fa":"ما هر سال در زمستان در کوه های آلپ اسکی می کنیم."},{"de":"Er hat sich neue Skier für die Saison gekauft.","en":"He bought new skis for the season.","ru":"Он купил новые лыжи для сезона.","vi":"Anh ấy đã mua ván trượt mới cho mùa giải.","fa":"او برای فصل اسکی جدید خرید."}]},{"word":"so","en":"so; like this","ru":"так; таким образом","vi":"như thế","fa":"مانند آن","examples":[{"de":"Mach es bitte genau so, wie ich es dir gezeigt habe.","en":"Please do it exactly like this, as I showed you.","ru":"Пожалуйста, сделай это именно так, как я тебе показал.","vi":"Hãy làm chính xác như tôi đã chỉ cho bạn.","fa":"لطفا این کار را دقیقا همانطور که به شما نشان دادم انجام دهید."},{"de":"Sie war so müde, dass sie sofort einschlief.","en":"She was so tired that she fell asleep immediately.","ru":"Она была так устала, что сразу же уснула.","vi":"Cô mệt đến nỗi ngủ ngay lập tức.","fa":"آنقدر خسته بود که بلافاصله خوابش برد."}]},{"word":"so viel/so viel wie","en":"as much (as)","ru":"столько (же), сколько","vi":"nhiều/nhiều như","fa":"به اندازه/به اندازه","examples":[{"de":"Er verdient nicht so viel wie sein Bruder.","en":"He doesn't earn as much as his brother.","ru":"Он зарабатывает не столько, сколько его брат.","vi":"Anh ấy không kiếm được nhiều tiền như anh trai mình.","fa":"او به اندازه برادرش درآمد ندارد."},{"de":"Iss so viel du willst.","en":"Eat as much as you want.","ru":"Ешь столько, сколько хочешь.","vi":"Ăn nhiều như bạn muốn.","fa":"هرچقدر میخوای بخور"}]},{"word":"sobald","en":"as soon as","ru":"как только","vi":"ngay khi","fa":"به محض","examples":[{"de":"Ich rufe dich an, sobald ich zu Hause bin.","en":"I will call you as soon as I get home.","ru":"Я позвоню тебе, как только буду дома.","vi":"Tôi sẽ gọi cho bạn ngay khi tôi về đến nhà.","fa":"به محض اینکه رسیدم خونه بهت زنگ میزنم"},{"de":"Sobald es regnet, machen wir die Fenster zu.","en":"As soon as it rains, we close the windows.","ru":"Как только начинается дождь, мы закрываем окна.","vi":"Ngay khi trời mưa, chúng tôi đóng cửa sổ lại.","fa":"به محض اینکه باران می بارد، پنجره ها را می بندیم."}]},{"word":"die Socke","en":"sock","ru":"носок","vi":"chiếc tất","fa":"جوراب","examples":[{"de":"Ich habe im Trockner nur eine Socke gefunden.","en":"I only found one sock in the dryer.","ru":"Я нашёл в сушилке только один носок.","vi":"Tôi chỉ tìm thấy một chiếc tất trong máy sấy.","fa":"من فقط یک جوراب در خشک کن پیدا کردم."},{"de":"Im Winter trage ich immer warme Socken.","en":"In winter, I always wear warm socks.","ru":"Зимой я всегда ношу тёплые носки.","vi":"Vào mùa đông tôi luôn mang tất ấm.","fa":"در زمستان همیشه جوراب گرم می پوشم."}]},{"word":"sodass","en":"so that","ru":"так что","vi":"vậy đó","fa":"به طوری که","examples":[{"de":"Es regnete stark, sodass wir zu Hause bleiben mussten.","en":"It rained heavily, so that we had to stay home.","ru":"Шёл сильный дождь, так что нам пришлось остаться дома.","vi":"Trời mưa to nên chúng tôi phải ở nhà.","fa":"باران شدیدی می بارید و مجبور شدیم در خانه بمانیم."},{"de":"Er lernte fleißig, sodass er die Prüfung bestand.","en":"He studied diligently, so that he passed the exam.","ru":"Он усердно учился, так что сдал экзамен.","vi":"Anh ấy học tập chăm chỉ nên anh ấy đã vượt qua kỳ thi.","fa":"به سختی درس خواند تا در امتحان قبول شد."}]},{"word":"das Sofa","en":"sofa","ru":"диван","vi":"ghế sofa","fa":"مبل","examples":[{"de":"Nach der Arbeit legt er sich gern aufs Sofa.","en":"After work, he likes to lie down on the sofa.","ru":"После работы он любит прилечь на диван.","vi":"Sau giờ làm việc anh ấy thích nằm dài trên ghế sofa.","fa":"بعد از کار دوست دارد روی مبل دراز بکشد."},{"de":"Wir haben ein neues Sofa fürs Wohnzimmer gekauft.","en":"We bought a new sofa for the living room.","ru":"Мы купили новый диван для гостиной.","vi":"Chúng tôi đã mua một chiếc ghế sofa mới cho phòng khách.","fa":"یک مبل جدید برای اتاق نشیمن خریدیم."}]},{"word":"sofort","en":"immediately","ru":"немедленно","vi":"ngay lập tức","fa":"بلافاصله","examples":[{"de":"Ruf mich bitte sofort an, wenn du ankommst.","en":"Please call me immediately when you arrive.","ru":"Пожалуйста, позвони мне сразу, как только приедешь.","vi":"Hãy gọi cho tôi ngay khi bạn đến.","fa":"لطفاً وقتی رسیدید فوراً با من تماس بگیرید."},{"de":"Der Arzt kam sofort, als er von dem Unfall hörte.","en":"The doctor came immediately when he heard about the accident.","ru":"Врач пришёл немедленно, как только узнал об аварии.","vi":"Bác sĩ đến ngay lập tức khi nghe tin về vụ tai nạn.","fa":"دکتر با شنیدن خبر تصادف بلافاصله آمد."}]},{"word":"sogar","en":"even","ru":"даже","vi":"thậm chí","fa":"حتی","examples":[{"de":"Er hat sogar am Sonntag gearbeitet.","en":"He even worked on Sunday.","ru":"Он даже работал в воскресенье.","vi":"Anh ấy thậm chí còn làm việc cả ngày chủ nhật.","fa":"حتی یکشنبه ها هم کار می کرد."},{"de":"Sogar meine kleine Schwester kann schon schwimmen.","en":"Even my little sister can already swim.","ru":"Даже моя младшая сестра уже умеет плавать.","vi":"Ngay cả em gái tôi bây giờ cũng có thể bơi được.","fa":"حتی خواهر کوچکم هم اکنون می تواند شنا کند."}]},{"word":"sogenannt-","en":"so-called","ru":"так называемый","vi":"cái gọi là-","fa":"به اصطلاح","examples":[{"de":"Er wohnt in einem sogenannten Passivhaus.","en":"He lives in a so-called passive house.","ru":"Он живёт в так называемом пассивном доме.","vi":"Anh ta sống trong một ngôi nhà được gọi là thụ động.","fa":"او در یک خانه به اصطلاح منفعل زندگی می کند."},{"de":"Die sogenannten Experten hatten alle eine andere Meinung.","en":"The so-called experts all had a different opinion.","ru":"У так называемых экспертов у всех было разное мнение.","vi":"Những người được gọi là chuyên gia đều có ý kiến ​​​​khác nhau.","fa":"به اصطلاح کارشناسان همه نظر متفاوتی داشتند."}]},{"word":"der Sohn","en":"son","ru":"сын","vi":"con trai","fa":"پسر","examples":[{"de":"Unser Sohn geht seit diesem Jahr in die Schule.","en":"Our son has been going to school since this year.","ru":"Наш сын с этого года ходит в школу.","vi":"Con trai chúng tôi đã đi học năm nay.","fa":"پسر ما امسال به مدرسه می رود."},{"de":"Sie hat zwei Söhne und eine Tochter.","en":"She has two sons and one daughter.","ru":"У неё два сына и одна дочь.","vi":"Cô có hai con trai và một con gái.","fa":"او دو پسر و یک دختر دارد."}]},{"word":"solange","en":"as long as","ru":"пока; до тех пор пока","vi":"miễn là","fa":"تا زمانی که","examples":[{"de":"Du darfst hier bleiben, solange du willst.","en":"You can stay here as long as you want.","ru":"Ты можешь оставаться здесь, пока хочешь.","vi":"Bạn có thể ở đây bao lâu tùy thích.","fa":"شما می توانید تا زمانی که بخواهید اینجا بمانید."},{"de":"Solange es regnet, spielen wir drinnen.","en":"As long as it rains, we play indoors.","ru":"Пока идёт дождь, мы играем в помещении.","vi":"Chỉ cần trời mưa là chúng tôi chơi trong nhà.","fa":"تا زمانی که باران می بارد، ما در داخل خانه بازی می کنیم."}]},{"word":"solch-","en":"such","ru":"такой","vi":"như vậy-","fa":"چنین -","examples":[{"de":"Ich habe noch nie ein solches Chaos gesehen.","en":"I have never seen such chaos before.","ru":"Я никогда не видел такого хаоса.","vi":"Tôi chưa bao giờ thấy sự hỗn loạn như vậy.","fa":"من هرگز چنین هرج و مرج را ندیده بودم."},{"de":"Mit solchen Problemen hatten wir nicht gerechnet.","en":"We hadn't expected such problems.","ru":"Мы не ожидали таких проблем.","vi":"Chúng tôi không mong đợi những vấn đề như vậy.","fa":"ما انتظار چنین مشکلاتی را نداشتیم."}]},{"word":"sollen","en":"should; to be supposed to","ru":"должен (следует)","vi":"nên","fa":"باید","examples":[{"de":"Du sollst nicht so viel Zucker essen.","en":"You shouldn't eat so much sugar.","ru":"Тебе не следует есть так много сахара.","vi":"Bạn không nên ăn quá nhiều đường.","fa":"اینقدر شکر نباید بخوری"},{"de":"Was soll ich tun, wenn er nicht anruft?","en":"What should I do if he doesn't call?","ru":"Что мне делать, если он не позвонит?","vi":"Tôi nên làm gì nếu anh ấy không gọi?","fa":"اگه زنگ نزنه چیکار کنم؟"}]},{"word":"Sonder-","en":"special (prefix)","ru":"специальный, особый (приставка)","vi":"đặc biệt","fa":"خاص","examples":[{"de":"Wegen der Bauarbeiten fährt der Bus heute eine Sonderroute.","en":"Due to the construction work, the bus is taking a special route today.","ru":"Из-за строительных работ автобус сегодня едет по специальному маршруту.","vi":"Do đang thi công nên hôm nay xe buýt sẽ đi một tuyến đường đặc biệt.","fa":"به دلیل کار ساخت و ساز، اتوبوس امروز مسیر خاصی را طی می کند."},{"de":"Im Zug gibt es einen Sonderwagen für Familien.","en":"There is a special car for families on the train.","ru":"В поезде есть специальный вагон для семей.","vi":"Trên tàu có toa đặc biệt dành cho gia đình.","fa":"در قطار واگن مخصوص خانواده ها وجود دارد."}]},{"word":"das Sonderangebot","en":"special offer","ru":"специальное предложение, акция","vi":"ưu đãi đặc biệt","fa":"پیشنهاد ویژه","examples":[{"de":"Diese Woche gibt es im Supermarkt ein Sonderangebot für Kaffee.","en":"This week there is a special offer on coffee at the supermarket.","ru":"На этой неделе в супермаркете действует акция на кофе.","vi":"Tuần này có một ưu đãi đặc biệt về cà phê tại siêu thị.","fa":"این هفته یک پیشنهاد ویژه برای قهوه در سوپرمارکت وجود دارد."},{"de":"Ich habe die Jacke im Sonderangebot günstig gekauft.","en":"I bought the jacket cheaply as a special offer.","ru":"Я купил куртку недорого по акции.","vi":"Tôi đã mua chiếc áo khoác với giá rẻ nhờ ưu đãi đặc biệt.","fa":"من کت را ارزان در پیشنهاد ویژه خریدم."}]},{"word":"sondern","en":"but (rather)","ru":"а, но (напротив)","vi":"nhưng","fa":"اما","examples":[{"de":"Ich trinke keinen Kaffee, sondern Tee.","en":"I don't drink coffee, but tea.","ru":"Я пью не кофе, а чай.","vi":"Tôi không uống cà phê, tôi uống trà.","fa":"من قهوه نمیخورم چای میخورم"},{"de":"Er ist nicht müde, sondern einfach nur gelangweilt.","en":"He isn't tired, but just bored.","ru":"Он не устал, а просто скучает.","vi":"Anh không mệt, chỉ là chán thôi.","fa":"او خسته نیست، فقط حوصله اش سر رفته است."}]},{"word":"die Sonne","en":"sun","ru":"солнце","vi":"mặt trời","fa":"خورشید","examples":[{"de":"Die Sonne scheint heute den ganzen Tag.","en":"The sun is shining all day today.","ru":"Сегодня солнце светит весь день.","vi":"Hôm nay mặt trời chiếu sáng cả ngày.","fa":"امروز تمام روز خورشید می درخشد."},{"de":"Wir haben uns in den Schatten gesetzt, weil die Sonne so stark schien.","en":"We sat in the shade because the sun was shining so strongly.","ru":"Мы сели в тень, потому что солнце светило так сильно.","vi":"Chúng tôi ngồi trong bóng râm vì nắng quá chói.","fa":"ما زیر سایه نشستیم زیرا خورشید به شدت می تابد."}]},{"word":"sonst","en":"otherwise; else","ru":"иначе; а то","vi":"mặt khác","fa":"در غیر این صورت","examples":[{"de":"Beeil dich, sonst verpasst du den Bus.","en":"Hurry up, otherwise you'll miss the bus.","ru":"Поторопись, а то опоздаешь на автобус.","vi":"Nhanh lên nếu không bạn sẽ lỡ xe buýt.","fa":"عجله کنید وگرنه اتوبوس را از دست خواهید داد."},{"de":"Hast du sonst noch Fragen?","en":"Do you have any other questions?","ru":"У тебя есть ещё какие-нибудь вопросы?","vi":"Bạn có câu hỏi nào khác không?","fa":"آیا سوال دیگری دارید؟"}]},{"word":"die Sorge","en":"worry; concern","ru":"забота; беспокойство","vi":"sự lo lắng","fa":"نگرانی","examples":[{"de":"Mach dir keine Sorgen, alles wird gut.","en":"Don't worry, everything will be fine.","ru":"Не беспокойся, всё будет хорошо.","vi":"Đừng lo lắng, mọi thứ sẽ ổn thôi.","fa":"نگران نباش همه چی درست میشه"},{"de":"Die Eltern machten sich große Sorgen um ihr Kind.","en":"The parents were very worried about their child.","ru":"Родители очень беспокоились о своём ребёнке.","vi":"Cha mẹ rất lo lắng cho con mình.","fa":"والدین به شدت نگران فرزندشان بودند."}]},{"word":"sorgen","en":"to take care of; to see to (something)","ru":"заботиться (о ком-л./чём-л.)","vi":"lo lắng","fa":"نگرانی","examples":[{"de":"Meine Eltern sorgen für mich, solange ich studiere.","en":"My parents take care of me while I study.","ru":"Мои родители заботятся обо мне, пока я учусь.","vi":"Bố mẹ tôi sẽ chăm sóc tôi miễn là tôi học tập.","fa":"پدر و مادرم تا زمانی که درس می خوانم از من مراقبت خواهند کرد."},{"de":"Kannst du dafür sorgen, dass die Tür abgeschlossen ist?","en":"Can you make sure the door is locked?","ru":"Можешь позаботиться о том, чтобы дверь была заперта?","vi":"Bạn có thể chắc chắn rằng cửa đã khóa?","fa":"آیا می توانید مطمئن شوید که در قفل است؟"}]},{"word":"die Soße/Sauce","en":"sauce; gravy","ru":"соус","vi":"nước xốt/nước sốt","fa":"سس / سس","examples":[{"de":"Die Nudeln schmecken mit dieser Soße besonders gut.","en":"The pasta tastes especially good with this sauce.","ru":"Паста особенно вкусна с этим соусом.","vi":"Mì có hương vị đặc biệt ngon với nước sốt này.","fa":"نودل ها با این سس طعم خوبی دارند."},{"de":"Sie hat die Sauce selbst gekocht.","en":"She made the sauce herself.","ru":"Она сама приготовила соус.","vi":"Cô ấy tự làm nước sốt.","fa":"سس را خودش درست کرد."}]},{"word":"das Souvenir","en":"souvenir","ru":"сувенир","vi":"quà lưu niệm","fa":"سوغات","examples":[{"de":"Wir haben ein Souvenir aus Wien mitgebracht.","en":"We brought back a souvenir from Vienna.","ru":"Мы привезли сувенир из Вены.","vi":"Chúng tôi mang theo một món quà lưu niệm từ Vienna.","fa":"از وین با خودمان سوغاتی آوردیم."},{"de":"Auf dem Markt gibt es viele kleine Souvenirs.","en":"There are many small souvenirs at the market.","ru":"На рынке много маленьких сувениров.","vi":"Có rất nhiều món quà lưu niệm nhỏ trên thị trường.","fa":"سوغاتی های کوچک زیادی در بازار وجود دارد."}]},{"word":"soviel","en":"as far as (soviel ich weiß = as far as I know)","ru":"насколько (soviel ich weiß = насколько я знаю)","vi":"rất nhiều","fa":"خیلی","examples":[{"de":"Soviel ich weiß, kommt er morgen.","en":"As far as I know, he's coming tomorrow.","ru":"Насколько я знаю, он придёт завтра.","vi":"As far as I know, he's coming tomorrow.","fa":"تا اونجایی که من میدونم فردا میاد"},{"de":"Soviel ich gehört habe, ist der Laden geschlossen.","en":"As far as I've heard, the shop is closed.","ru":"Насколько я слышал, магазин закрыт.","vi":"Theo những gì tôi nghe được thì cửa hàng đã đóng cửa.","fa":"طبق شنیده ها فروشگاه تعطیل است."}]},{"word":"sowieso","en":"anyway; in any case","ru":"всё равно; в любом случае","vi":"dù sao đi nữa","fa":"به هر حال","examples":[{"de":"Ich wollte sowieso einkaufen gehen.","en":"I wanted to go shopping anyway.","ru":"Я всё равно собирался идти за покупками.","vi":"Dù sao thì tôi cũng muốn đi mua sắm.","fa":"به هر حال می خواستم برم خرید."},{"de":"Es ist sowieso zu spät, um heute noch anzufangen.","en":"It's too late to start today anyway.","ru":"В любом случае, уже слишком поздно начинать сегодня.","vi":"Đó là điều tôi muốn nói, um heute noch anzufangen.","fa":"به هر حال برای شروع امروز خیلی دیر است."}]},{"word":"sowohl … als auch","en":"both ... and","ru":"как ..., так и ...","vi":"cả...và","fa":"هر دو ... و","examples":[{"de":"Sie spricht sowohl Deutsch als auch Englisch.","en":"She speaks both German and English.","ru":"Она говорит как по-немецки, так и по-английски.","vi":"Cô ấy nói được cả tiếng Đức và tiếng Anh.","fa":"او به دو زبان آلمانی و انگلیسی صحبت می کند."},{"de":"Sowohl meine Mutter als auch mein Vater arbeiten in der Stadt.","en":"Both my mother and my father work in the city.","ru":"Как моя мать, так и мой отец работают в городе.","vi":"Cả bố và mẹ tôi đều làm việc ở thành phố.","fa":"مادر و پدرم هر دو در شهر کار می کنند."}]},{"word":"sozial","en":"social","ru":"социальный","vi":"xã hội","fa":"اجتماعی","examples":[{"de":"Er engagiert sich für soziale Projekte.","en":"He is involved in social projects.","ru":"Он занимается социальными проектами.","vi":"Anh ấy cam kết thực hiện các dự án xã hội.","fa":"او به پروژه های اجتماعی متعهد است."},{"de":"Die sozialen Unterschiede sind in dieser Stadt groß.","en":"The social differences in this city are large.","ru":"Социальные различия в этом городе велики.","vi":"Sự khác biệt xã hội là rất lớn ở thành phố này.","fa":"تفاوت های اجتماعی در این شهر زیاد است."}]},{"word":"die Sozialarbeiterin","en":"social worker (female)","ru":"социальный работник (женщина)","vi":"nhân viên xã hội","fa":"مددکار اجتماعی","examples":[{"de":"Die Sozialarbeiterin hilft Familien in schwierigen Situationen.","en":"The social worker helps families in difficult situations.","ru":"Социальный работник помогает семьям в трудных ситуациях.","vi":"Nhân viên xã hội giúp đỡ các gia đình có hoàn cảnh khó khăn.","fa":"مددکار اجتماعی به خانواده ها در شرایط سخت کمک می کند."},{"de":"Sie arbeitet seit fünf Jahren als Sozialarbeiterin.","en":"She has been working as a social worker for five years.","ru":"Она работает социальным работником уже пять лет.","vi":"Cô đã làm nhân viên xã hội được 5 năm.","fa":"او پنج سال است که به عنوان مددکار اجتماعی کار می کند."}]},{"word":"spannend","en":"exciting; suspenseful","ru":"увлекательный; захватывающий","vi":"thú vị","fa":"هیجان انگیز","examples":[{"de":"Der Film war wirklich spannend.","en":"The movie was really exciting.","ru":"Фильм был по-настоящему захватывающим.","vi":"Der Film war wirklich spannend.","fa":"فیلم واقعا هیجان انگیز بود."},{"de":"Sie liest gerade ein spannendes Buch.","en":"She's currently reading an exciting book.","ru":"Она сейчас читает увлекательную книгу.","vi":"Cô ấy hiện đang đọc một cuốn sách thú vị.","fa":"او در حال حاضر در حال خواندن یک کتاب هیجان انگیز است."}]},{"word":"sparen","en":"to save (money/time)","ru":"экономить; копить","vi":"lưu lại","fa":"ذخیره کنید","examples":[{"de":"Wir sparen Geld für den Urlaub.","en":"We're saving money for vacation.","ru":"Мы копим деньги на отпуск.","vi":"Chúng tôi tiết kiệm tiền cho kỳ nghỉ.","fa":"ما برای تعطیلات پول پس انداز می کنیم."},{"de":"Man kann viel Energie sparen, wenn man das Licht ausschaltet.","en":"You can save a lot of energy by turning off the light.","ru":"Можно сэкономить много энергии, выключая свет.","vi":"Bạn có thể tiết kiệm rất nhiều năng lượng bằng cách tắt đèn.","fa":"با خاموش کردن چراغ ها می توانید در مصرف انرژی صرفه جویی کنید."}]},{"word":"der Spaß","en":"fun","ru":"удовольствие; веселье","vi":"niềm vui","fa":"سرگرمی","examples":[{"de":"Das Spiel macht den Kindern großen Spaß.","en":"The game is a lot of fun for the children.","ru":"Игра доставляет детям огромное удовольствие.","vi":"Trò chơi mang lại niềm vui lớn cho trẻ em.","fa":"این بازی برای کودکان بسیار سرگرم کننده است."},{"de":"Viel Spaß beim Feiern!","en":"Have fun at the party!","ru":"Хорошо повеселиться на празднике!","vi":"Have fun celebrating!","fa":"از جشن گرفتن لذت ببرید!"}]},{"word":"spät","en":"late","ru":"поздний; поздно","vi":"muộn","fa":"دیر","examples":[{"de":"Es ist schon spät, wir sollten nach Hause gehen.","en":"It's already late, we should go home.","ru":"Уже поздно, нам пора домой.","vi":"Đã muộn rồi, chúng ta nên về nhà thôi.","fa":"دیر شده باید بریم خونه"},{"de":"Er kommt oft zu spät zur Arbeit.","en":"He often comes to work too late.","ru":"Он часто опаздывает на работу.","vi":"Anh ấy thường xuyên đi làm muộn.","fa":"او اغلب دیر سر کار می آید."}]},{"word":"spazieren gehen","en":"to go for a walk","ru":"гулять; идти на прогулку","vi":"đi dạo","fa":"برو پیاده روی","examples":[{"de":"Am Sonntag gehen wir im Park spazieren.","en":"On Sunday we go for a walk in the park.","ru":"В воскресенье мы гуляем в парке.","vi":"Chủ nhật chúng tôi đi dạo trong công viên.","fa":"یکشنبه میریم تو پارک قدم بزنیم."},{"de":"Nach dem Essen gehen sie gerne spazieren.","en":"After eating they like to go for a walk.","ru":"После еды они любят гулять.","vi":"Họ thích đi dạo sau khi ăn xong.","fa":"آنها دوست دارند بعد از صرف غذا به پیاده روی بروند."}]},{"word":"speichern","en":"to save (data)","ru":"сохранять (данные)","vi":"cứu","fa":"ذخیره کنید","examples":[{"de":"Vergiss nicht, das Dokument zu speichern.","en":"Don't forget to save the document.","ru":"Не забудь сохранить документ.","vi":"Đừng quên lưu tài liệu.","fa":"فراموش نکنید که سند را ذخیره کنید."},{"de":"Die Fotos werden automatisch auf dem Handy gespeichert.","en":"The photos are automatically saved on the phone.","ru":"Фотографии автоматически сохраняются на телефоне.","vi":"Các bức ảnh sẽ được lưu tự động trên điện thoại.","fa":"عکس ها به صورت خودکار در گوشی ذخیره می شوند."}]},{"word":"Speise-/-speise","en":"food; dish (combining form, e.g. Speisekarte = menu)","ru":"еда; блюдо (словообразовательный элемент, напр. Speisekarte = меню)","vi":"Thức ăn/món ăn","fa":"غذا / ظرف","examples":[{"de":"Der Kellner bringt uns die Speisekarte.","en":"The waiter brings us the menu.","ru":"Официант приносит нам меню.","vi":"Người phục vụ mang thực đơn đến cho chúng tôi.","fa":"پیشخدمت منو می آورد."},{"de":"Im Speisewagen des Zuges kann man essen.","en":"You can eat in the dining car of the train.","ru":"В вагоне-ресторане поезда можно поесть.","vi":"Bạn có thể ăn trong toa ăn của tàu.","fa":"می توانید در واگن ناهار خوری قطار غذا بخورید."}]},{"word":"die Spende","en":"donation","ru":"пожертвование","vi":"sự quyên góp","fa":"کمک مالی","examples":[{"de":"Mit einer kleinen Spende kann man viel bewirken.","en":"You can achieve a lot with a small donation.","ru":"Небольшим пожертвованием можно многого добиться.","vi":"Với một khoản đóng góp nhỏ, bạn có thể tạo ra sự khác biệt lớn.","fa":"با یک کمک مالی کوچک می توانید تفاوت بزرگی ایجاد کنید."},{"de":"Die Organisation lebt von Spenden.","en":"The organisation survives on donations.","ru":"Организация живёт за счёт пожертвований.","vi":"Tổ chức này sống nhờ vào sự quyên góp.","fa":"این سازمان از کمک های مالی زندگی می کند."}]},{"word":"Spezial-","en":"special (combining form, e.g. Spezialangebot = special offer)","ru":"специальный (словообразовательный элемент, напр. Spezialangebot = специальное предложение)","vi":"đặc biệt","fa":"خاص","examples":[{"de":"Der Supermarkt hat diese Woche ein Spezialangebot.","en":"The supermarket has a special offer this week.","ru":"В супермаркете на этой неделе специальное предложение.","vi":"Tuần này siêu thị có ưu đãi đặc biệt.","fa":"سوپرمارکت این هفته یک پیشنهاد ویژه دارد."},{"de":"Er ist Arzt und hat ein Spezialgebiet für Kinderkrankheiten.","en":"He is a doctor and has a specialty in children's diseases.","ru":"Он врач и специализируется на детских болезнях.","vi":"Ông là bác sĩ và chuyên về bệnh trẻ em.","fa":"او پزشک است و متخصص بیماری های کودکان است."}]},{"word":"speziell","en":"special; specific","ru":"особый; специальный","vi":"đặc biệt","fa":"خاص","examples":[{"de":"Für dieses Problem brauchen wir eine spezielle Lösung.","en":"We need a special solution for this problem.","ru":"Для этой проблемы нам нужно особое решение.","vi":"Chúng ta cần một giải pháp đặc biệt cho vấn đề này.","fa":"برای این مشکل به یک راه حل ویژه نیاز داریم."},{"de":"Sie hat spezielle Wünsche für das Essen.","en":"She has specific requests for the food.","ru":"У неё особые пожелания насчёт еды.","vi":"Cô ấy có những yêu cầu đặc biệt về đồ ăn.","fa":"او درخواست های ویژه ای برای غذا دارد."}]},{"word":"der Spiegel","en":"mirror","ru":"зеркало","vi":"cái gương","fa":"آینه","examples":[{"de":"Sie schaut sich im Spiegel an.","en":"She looks at herself in the mirror.","ru":"Она смотрит на себя в зеркало.","vi":"Cô nhìn mình trong gương.","fa":"او در آینه به خود نگاه می کند."},{"de":"Der Spiegel im Bad ist zu klein.","en":"The mirror in the bathroom is too small.","ru":"Зеркало в ванной слишком маленькое.","vi":"Gương trong phòng tắm quá nhỏ.","fa":"آینه حمام خیلی کوچک است."}]},{"word":"spielen","en":"to play","ru":"играть","vi":"chơi","fa":"بازی کردن","examples":[{"de":"Die Kinder spielen im Garten.","en":"The children are playing in the garden.","ru":"Дети играют в саду.","vi":"Bọn trẻ đang chơi trong vườn.","fa":"بچه ها در باغ بازی می کنند."},{"de":"Er spielt seit Jahren Gitarre.","en":"He has been playing guitar for years.","ru":"Он играет на гитаре уже много лет.","vi":"Anh ấy đã chơi guitar được nhiều năm.","fa":"او سال هاست که گیتار می نوازد."}]},{"word":"spitz","en":"pointed; sharp","ru":"острый; заострённый","vi":"nhọn","fa":"اشاره کرد","examples":[{"de":"Pass auf, das Messer ist spitz!","en":"Be careful, the knife is sharp!","ru":"Осторожно, нож острый!","vi":"Hãy cẩn thận, con dao rất sắc!","fa":"مراقب باشید، چاقو تیز است!"},{"de":"Der Turm hat ein spitzes Dach.","en":"The tower has a pointed roof.","ru":"У башни остроконечная крыша.","vi":"Tháp có mái nhọn.","fa":"برج سقفی نوک تیز دارد."}]},{"word":"der Sport","en":"sport","ru":"спорт","vi":"môn thể thao","fa":"ورزش","examples":[{"de":"Er treibt jeden Tag Sport.","en":"He does sports every day.","ru":"Он занимается спортом каждый день.","vi":"Anh ấy chơi thể thao mỗi ngày.","fa":"او هر روز ورزش می کند."},{"de":"Welchen Sport magst du am liebsten?","en":"Which sport do you like best?","ru":"Какой вид спорта тебе нравится больше всего?","vi":"Bạn thích môn thể thao nào nhất?","fa":"کدام ورزش را بیشتر دوست دارید؟"}]},{"word":"die Sprache","en":"language","ru":"язык (речь)","vi":"ngôn ngữ","fa":"زبان","examples":[{"de":"Sie spricht drei Sprachen fließend.","en":"She speaks three languages fluently.","ru":"Она свободно говорит на трёх языках.","vi":"Cô ấy nói trôi chảy ba thứ tiếng.","fa":"او سه زبان را روان صحبت می کند."},{"de":"Deutsch ist eine schwierige Sprache für viele Anfänger.","en":"German is a difficult language for many beginners.","ru":"Немецкий — трудный язык для многих начинающих.","vi":"Tiếng Đức là một ngôn ngữ khó đối với nhiều người mới bắt đầu.","fa":"آلمانی برای بسیاری از مبتدیان زبان دشواری است."}]},{"word":"sprechen","en":"to speak","ru":"говорить","vi":"nói","fa":"صحبت کنید","examples":[{"de":"Kannst du bitte langsamer sprechen?","en":"Can you please speak more slowly?","ru":"Можешь, пожалуйста, говорить медленнее?","vi":"Bạn có thể vui lòng nói chậm hơn được không?","fa":"میشه لطفا آهسته تر صحبت کنید؟"},{"de":"Wir müssen dringend über das Problem sprechen.","en":"We urgently need to talk about the problem.","ru":"Нам срочно нужно поговорить об этой проблеме.","vi":"Chúng tôi cần khẩn trương nói về vấn đề này.","fa":"ما باید فوراً در مورد مشکل صحبت کنیم."}]},{"word":"die Sprechstunde","en":"office hours; consultation hours","ru":"приёмные часы; часы приёма","vi":"giờ tư vấn","fa":"ساعت مشاوره","examples":[{"de":"Der Professor hat mittwochs Sprechstunde.","en":"The professor has office hours on Wednesdays.","ru":"У профессора приёмные часы по средам.","vi":"Giáo sư có giờ hành chính vào thứ Tư.","fa":"استاد چهارشنبه ها ساعت اداری دارد."},{"de":"Die Sprechstunde des Arztes beginnt um neun Uhr.","en":"The doctor's consultation hours begin at nine o'clock.","ru":"Часы приёма врача начинаются в девять часов.","vi":"Cuộc tư vấn của bác sĩ bắt đầu lúc chín giờ.","fa":"مشاوره دکتر از ساعت نه شروع می شود."}]},{"word":"springen","en":"to jump","ru":"прыгать","vi":"nhảy","fa":"پرش","examples":[{"de":"Die Kinder springen fröhlich über die Pfützen.","en":"The children happily jump over the puddles.","ru":"Дети весело прыгают через лужи.","vi":"Lũ trẻ vui vẻ nhảy qua vũng nước.","fa":"بچه ها با خوشحالی از روی گودال ها می پرند."},{"de":"Er ist ins Wasser gesprungen.","en":"He jumped into the water.","ru":"Он прыгнул в воду.","vi":"Anh ta nhảy xuống nước.","fa":"پرید توی آب."}]},{"word":"die Spritze","en":"injection; syringe","ru":"укол; шприц","vi":"ống tiêm","fa":"سرنگ","examples":[{"de":"Der Arzt gibt dem Patienten eine Spritze.","en":"The doctor gives the patient an injection.","ru":"Врач делает пациенту укол.","vi":"Bác sĩ tiêm thuốc cho bệnh nhân.","fa":"پزشک به بیمار تزریق می کند."},{"de":"Vor der Reise brauchte sie eine Spritze gegen Gelbfieber.","en":"Before the trip she needed a shot against yellow fever.","ru":"Перед поездкой ей понадобилась прививка от жёлтой лихорадки.","vi":"Trước chuyến đi, cô cần tiêm một mũi chống sốt vàng da.","fa":"قبل از سفر او برای تب زرد نیاز به تزریق داشت."}]},{"word":"spülen","en":"to rinse; to wash (dishes)","ru":"мыть (посуду); полоскать","vi":"rửa sạch","fa":"آبکشی کنید","examples":[{"de":"Nach dem Essen muss noch das Geschirr gespült werden.","en":"After eating, the dishes still need to be washed.","ru":"После еды нужно ещё помыть посуду.","vi":"Ăn xong vẫn phải rửa bát.","fa":"پس از صرف غذا، ظروف هنوز باید شسته شوند."},{"de":"Sie spült die Gläser mit warmem Wasser.","en":"She rinses the glasses with warm water.","ru":"Она моет стаканы тёплой водой.","vi":"Cô rửa kính bằng nước ấm.","fa":"لیوان‌ها را با آب گرم می‌شوید."}]},{"word":"die Spur","en":"trace; track; lane (road)","ru":"след; полоса (движения)","vi":"con đường","fa":"دنباله رو","examples":[{"de":"Die Polizei fand keine Spur von dem Dieb.","en":"The police found no trace of the thief.","ru":"Полиция не нашла и следа вора.","vi":"Cảnh sát không tìm thấy dấu vết của tên trộm.","fa":"پلیس هیچ اثری از دزد پیدا نکرد."},{"de":"Bleib auf deiner Spur, bis die Ausfahrt kommt.","en":"Stay in your lane until the exit comes.","ru":"Оставайся на своей полосе, пока не появится съезд.","vi":"Đi trong làn đường của bạn cho đến khi có lối ra.","fa":"تا زمانی که خروجی بیاید در لاین خود بمانید."}]},{"word":"spüren","en":"to feel; to sense","ru":"чувствовать; ощущать","vi":"cảm thấy","fa":"احساس کنید","examples":[{"de":"Ich spüre, dass etwas nicht stimmt.","en":"I sense that something is wrong.","ru":"Я чувствую, что что-то не так.","vi":"Tôi cảm thấy có điều gì đó không ổn.","fa":"احساس می کنم چیزی اشتباه است."},{"de":"Sie spürte den kalten Wind im Gesicht.","en":"She felt the cold wind on her face.","ru":"Она почувствовала холодный ветер на лице.","vi":"Cô cảm thấy gió lạnh phả vào mặt.","fa":"باد سرد را روی صورتش احساس کرد."}]},{"word":"das Stadion","en":"stadium","ru":"стадион","vi":"sân vận động","fa":"استادیوم","examples":[{"de":"Am Samstag treffen wir uns im Stadion zum Fußballspiel.","en":"On Saturday we're meeting at the stadium for the football match.","ru":"В субботу мы встречаемся на стадионе на футбольный матч.","vi":"Vào thứ bảy, chúng tôi gặp nhau ở sân vận động để xem trận bóng đá.","fa":"شنبه برای بازی فوتبال در استادیوم همدیگر را ملاقات می کنیم."},{"de":"Das neue Stadion bietet Platz für 50.000 Zuschauer.","en":"The new stadium holds 50,000 spectators.","ru":"Новый стадион вмещает 50 000 зрителей.","vi":"Sân vận động mới có sức chứa 50.000 khán giả.","fa":"ورزشگاه جدید فضایی برای 50000 تماشاگر دارد."}]},{"word":"die Stadt","en":"city; town","ru":"город","vi":"thành phố","fa":"شهر","examples":[{"de":"Berlin ist die Hauptstadt von Deutschland.","en":"Berlin is the capital city of Germany.","ru":"Берлин — столица Германии.","vi":"Berlin là thủ đô của Đức.","fa":"برلین پایتخت آلمان است."},{"de":"Wir fahren morgen in die Stadt, um einzukaufen.","en":"We're going into town tomorrow to shop.","ru":"Завтра мы едем в город за покупками.","vi":"Ngày mai chúng ta sẽ vào thị trấn để mua sắm.","fa":"فردا میریم شهر تا خرید کنیم."}]},{"word":"stammen","en":"to come from; to originate","ru":"происходить (из/от)","vi":"bắt nguồn","fa":"سرچشمه می گیرند","examples":[{"de":"Meine Familie stammt ursprünglich aus Italien.","en":"My family originally comes from Italy.","ru":"Моя семья родом из Италии.","vi":"Gia đình tôi có nguồn gốc từ Ý.","fa":"خانواده من اصالتا ایتالیایی هستند."},{"de":"Dieses Wort stammt aus dem Lateinischen.","en":"This word comes from Latin.","ru":"Это слово происходит из латыни.","vi":"Từ này xuất phát từ tiếng Latin.","fa":"این کلمه از لاتین آمده است."}]},{"word":"ständig","en":"constantly; continually","ru":"постоянно","vi":"liên tục","fa":"دائما","examples":[{"de":"Er beschwert sich ständig über das Wetter.","en":"He constantly complains about the weather.","ru":"Он постоянно жалуется на погоду.","vi":"Anh ấy liên tục phàn nàn về thời tiết.","fa":"مدام از آب و هوا شاکی است."},{"de":"Meine Schwester ruft mich ständig an.","en":"My sister calls me constantly.","ru":"Моя сестра постоянно мне звонит.","vi":"Chị tôi gọi điện cho tôi suốt.","fa":"خواهرم مدام با من تماس می گیرد."}]},{"word":"der Standpunkt","en":"point of view; standpoint","ru":"точка зрения","vi":"quan điểm","fa":"نقطه نظر","examples":[{"de":"Von meinem Standpunkt aus ist das keine gute Idee.","en":"From my point of view, that's not a good idea.","ru":"С моей точки зрения, это не очень хорошая идея.","vi":"Theo quan điểm của tôi, đây không phải là một ý tưởng hay.","fa":"از دیدگاه من، این ایده خوبی نیست."},{"de":"Er vertritt in dieser Frage einen klaren Standpunkt.","en":"He holds a clear position on this issue.","ru":"У него чёткая позиция по этому вопросу.","vi":"Ông có quan điểm rõ ràng về vấn đề này.","fa":"او موضع روشنی در این مورد دارد."}]},{"word":"der Star","en":"star (celebrity)","ru":"звезда (знаменитость)","vi":"ngôi sao","fa":"ستاره","examples":[{"de":"Der Schauspieler ist ein großer Star in Hollywood.","en":"The actor is a big star in Hollywood.","ru":"Этот актёр — большая звезда Голливуда.","vi":"Nam diễn viên là một ngôi sao lớn ở Hollywood.","fa":"این بازیگر یک ستاره بزرگ در هالیوود است."},{"de":"Viele Fans warteten vor dem Konzert auf ihren Star.","en":"Many fans waited outside the concert for their star.","ru":"Многие фанаты ждали перед концертом свою звезду.","vi":"Người hâm mộ Viele chiến đấu với Konzert auf ihren Star.","fa":"بسیاری از هواداران قبل از کنسرت منتظر ستاره خود بودند."}]},{"word":"stark","en":"strong","ru":"сильный","vi":"mạnh mẽ","fa":"قوی","examples":[{"de":"Er ist körperlich sehr stark.","en":"He is physically very strong.","ru":"Он физически очень сильный.","vi":"He is physically very strong.","fa":"او از نظر بدنی بسیار قوی است."},{"de":"Der Kaffee heute Morgen war zu stark für mich.","en":"The coffee this morning was too strong for me.","ru":"Кофе сегодня утром был для меня слишком крепким.","vi":"Cà phê sáng nay quá mạnh đối với tôi.","fa":"قهوه امروز صبح برای من خیلی قوی بود."}]},{"word":"starten","en":"to start; to launch; to take off","ru":"стартовать; запускать(ся)","vi":"bắt đầu","fa":"شروع کنید","examples":[{"de":"Das Flugzeug startet um sieben Uhr.","en":"The plane takes off at seven o'clock.","ru":"Самолёт вылетает в семь часов.","vi":"Máy bay cất cánh lúc bảy giờ.","fa":"هواپیما ساعت هفت بلند می شود."},{"de":"Wir starten das Projekt nächste Woche.","en":"We're launching the project next week.","ru":"Мы запускаем проект на следующей неделе.","vi":"Chúng tôi bắt đầu dự án vào tuần tới.","fa":"هفته آینده پروژه را شروع می کنیم."}]},{"word":"die Station","en":"station (hospital ward, transit stop)","ru":"станция; отделение (в больнице)","vi":"nhà ga","fa":"ایستگاه","examples":[{"de":"Mein Onkel liegt auf der Station im dritten Stock.","en":"My uncle is on the ward on the third floor.","ru":"Мой дядя лежит в отделении на третьем этаже.","vi":"Chú tôi ở phòng bệnh trên tầng ba.","fa":"عمویم در بند طبقه سوم است."},{"de":"An der nächsten Station müssen wir aussteigen.","en":"We have to get off at the next stop.","ru":"На следующей остановке нам нужно выходить.","vi":"Chúng ta phải xuống ở ga tiếp theo.","fa":"باید در ایستگاه بعدی پیاده شویم."}]},{"word":"die Statistik","en":"statistics","ru":"статистика","vi":"số liệu thống kê","fa":"آمار","examples":[{"de":"Laut Statistik sinkt die Zahl der Raucher.","en":"According to statistics, the number of smokers is declining.","ru":"Согласно статистике, число курящих снижается.","vi":"Theo thống kê, số lượng người hút thuốc đang giảm dần.","fa":"طبق آمار، تعداد افراد سیگاری در حال کاهش است."},{"de":"Sie muss für ihr Studium ein Fach in Statistik belegen.","en":"She has to take a statistics course for her studies.","ru":"Ей нужно пройти курс статистики в рамках учёбы.","vi":"Cô ấy phải học một môn về thống kê để học.","fa":"او باید برای تحصیلاتش موضوعی را در آمار بگذراند."}]},{"word":"statt","en":"instead of","ru":"вместо","vi":"thay vào đó","fa":"در عوض","examples":[{"de":"Statt Kaffee trinke ich lieber Tee.","en":"Instead of coffee, I prefer to drink tea.","ru":"Вместо кофе я предпочитаю пить чай.","vi":"Tôi thích uống trà hơn là cà phê.","fa":"من ترجیح می دهم به جای قهوه چای بنوشم."},{"de":"Er kam statt seines Bruders zur Feier.","en":"He came to the celebration instead of his brother.","ru":"Он пришёл на праздник вместо своего брата.","vi":"Anh ấy đến dự lễ kỷ niệm thay vì anh trai mình.","fa":"او به جای برادرش به جشن آمد."}]},{"word":"stattfinden","en":"to take place","ru":"происходить; состояться","vi":"diễn ra","fa":"برگزار شود","examples":[{"de":"Die Konferenz findet nächsten Monat statt.","en":"The conference takes place next month.","ru":"Конференция состоится в следующем месяце.","vi":"Die Konferenz đã tìm thấy Monat statt.","fa":"این کنفرانس در ماه آینده برگزار می شود."},{"de":"Wegen des Regens fand das Fest nicht im Freien statt.","en":"Because of the rain, the festival did not take place outdoors.","ru":"Из-за дождя праздник не проходил на улице.","vi":"Vì trời mưa nên lễ hội không được tổ chức ngoài trời.","fa":"به دلیل بارندگی، جشنواره در فضای باز برگزار نشد."}]},{"word":"der Stau","en":"traffic jam","ru":"пробка (на дороге)","vi":"ùn tắc giao thông","fa":"ترافیک","examples":[{"de":"Wir standen zwei Stunden im Stau.","en":"We were stuck in a traffic jam for two hours.","ru":"Мы простояли в пробке два часа.","vi":"Chúng tôi bị kẹt xe suốt hai tiếng đồng hồ.","fa":"دو ساعت در ترافیک گیر کرده بودیم."},{"de":"Auf der Autobahn gibt es heute einen langen Stau.","en":"There's a long traffic jam on the highway today.","ru":"Сегодня на автобане длинная пробка.","vi":"Hôm nay đường cao tốc bị ùn tắc kéo dài.","fa":"امروز یک ترافیک طولانی در بزرگراه وجود دارد."}]},{"word":"der Staub","en":"dust","ru":"пыль","vi":"bụi","fa":"گرد و غبار","examples":[{"de":"Auf dem Regal liegt viel Staub.","en":"There's a lot of dust on the shelf.","ru":"На полке много пыли.","vi":"Có rất nhiều bụi trên kệ.","fa":"گرد و غبار زیادی روی قفسه وجود دارد."},{"de":"Sie wischt jeden Tag den Staub von den Möbeln.","en":"She wipes the dust off the furniture every day.","ru":"Она каждый день вытирает пыль с мебели.","vi":"She wipes the dust off the furniture every day.","fa":"او هر روز گرد و غبار مبلمان را پاک می کند."}]},{"word":"staubsaugen","en":"to vacuum","ru":"пылесосить","vi":"chân không","fa":"خلاء","examples":[{"de":"Am Samstag muss ich die ganze Wohnung staubsaugen.","en":"On Saturday I have to vacuum the whole apartment.","ru":"В субботу мне нужно пропылесосить всю квартиру.","vi":"Vào thứ bảy tôi phải hút bụi toàn bộ căn hộ.","fa":"شنبه باید کل آپارتمان را جاروبرقی بکشم."},{"de":"Er saugt jeden Tag Staub im Wohnzimmer.","en":"He vacuums the living room every day.","ru":"Он каждый день пылесосит гостиную.","vi":"Anh ấy hút bụi phòng khách mỗi ngày.","fa":"او هر روز اتاق نشیمن را جاروبرقی می کشد."}]},{"word":"stechen","en":"to sting; to prick; to stab","ru":"колоть; жалить","vi":"đốt","fa":"نیش زدن","examples":[{"de":"Eine Biene hat mich in den Arm gestochen.","en":"A bee stung me on the arm.","ru":"Пчела ужалила меня в руку.","vi":"Một con ong chích vào tay tôi.","fa":"زنبوری روی بازویم نیش زد."},{"de":"Pass auf, die Rosen stechen!","en":"Watch out, the roses prick!","ru":"Осторожно, розы колются!","vi":"Coi chừng, hoa hồng chích!","fa":"مراقب باشید، گل رز نیش می زند!"}]},{"word":"die Steckdose","en":"electrical socket; outlet","ru":"розетка","vi":"ổ cắm","fa":"سوکت","examples":[{"de":"Die Lampe passt nicht in diese Steckdose.","en":"The lamp doesn't fit this socket.","ru":"Лампа не подходит к этой розетке.","vi":"Đèn không vừa với ổ cắm này.","fa":"لامپ در این سوکت جا نمی شود."},{"de":"In jedem Zimmer gibt es mindestens zwei Steckdosen.","en":"There are at least two outlets in every room.","ru":"В каждой комнате есть как минимум две розетки.","vi":"Có ít nhất hai ổ cắm điện trong mỗi phòng.","fa":"در هر اتاق حداقل دو پریز برق وجود دارد."}]},{"word":"stecken","en":"to put; to stick; to be (somewhere)","ru":"класть; втыкать; находиться","vi":"bị mắc kẹt","fa":"گیر کرده","examples":[{"de":"Sie steckt den Schlüssel ins Schloss.","en":"She puts the key in the lock.","ru":"Она вставляет ключ в замок.","vi":"Cô tra chìa khóa vào ổ khóa.","fa":"او کلید را در قفل می گذارد."},{"de":"Wo steckst du denn die ganze Zeit?","en":"Where have you been all this time?","ru":"Где ты вообще всё это время пропадал?","vi":"Bạn đã ở đâu suốt thời gian qua?","fa":"این همه مدت کجا بودی؟"}]},{"word":"der Stecker","en":"plug (electrical)","ru":"вилка (электрическая), штепсель","vi":"phích cắm","fa":"دوشاخه","examples":[{"de":"Zieh den Stecker aus der Steckdose, bevor du das Gerät reparierst.","en":"Pull the plug out of the socket before repairing the device.","ru":"Вынь вилку из розетки, прежде чем ремонтировать прибор.","vi":"Rút phích cắm thiết bị trước khi sửa chữa thiết bị.","fa":"قبل از تعمیر دستگاه، دستگاه را از برق بکشید."},{"de":"Der Stecker meines Ladegeräts ist kaputt.","en":"The plug of my charger is broken.","ru":"Вилка моего зарядного устройства сломана.","vi":"Ổ cắm trên bộ sạc của tôi bị hỏng.","fa":"دوشاخه شارژر من خرابه"}]},{"word":"stehen","en":"to stand","ru":"стоять","vi":"đứng","fa":"ایستادن","examples":[{"de":"Die Flasche steht auf dem Tisch.","en":"The bottle is standing on the table.","ru":"Бутылка стоит на столе.","vi":"Cái chai ở trên bàn.","fa":"بطری روی میز است."},{"de":"Wir mussten eine Stunde in der Schlange stehen.","en":"We had to stand in line for an hour.","ru":"Нам пришлось стоять в очереди целый час.","vi":"Chúng tôi phải xếp hàng chờ cả tiếng đồng hồ.","fa":"مجبور شدیم یک ساعت در صف بمانیم."}]},{"word":"stehen bleiben","en":"to stop; to remain standing","ru":"останавливаться; оставаться стоять","vi":"vẫn đứng","fa":"ایستاده بماند","examples":[{"de":"Die Uhr ist gestern stehen geblieben.","en":"The clock stopped yesterday.","ru":"Часы вчера остановились.","vi":"Đồng hồ đã dừng ngày hôm qua.","fa":"ساعت دیروز متوقف شد."},{"de":"Bleib stehen, ich muss dir etwas sagen!","en":"Stop, I need to tell you something!","ru":"Остановись, мне нужно тебе кое-что сказать!","vi":"Dừng lại, tôi phải nói với bạn một điều!","fa":"بس کن، باید یه چیزی بهت بگم!"}]},{"word":"stehlen","en":"to steal","ru":"красть","vi":"ăn trộm","fa":"سرقت","examples":[{"de":"Jemand hat ihm das Fahrrad gestohlen.","en":"Someone stole his bicycle.","ru":"Кто-то украл у него велосипед.","vi":"Ai đó đã lấy trộm chiếc xe đạp của anh ấy.","fa":"یک نفر دوچرخه اش را دزدید."},{"de":"Man soll nicht stehlen.","en":"One should not steal.","ru":"Нельзя воровать.","vi":"Bạn không nên ăn trộm.","fa":"تو نباید دزدی کنی"}]},{"word":"steigen","en":"to climb; to rise; to increase","ru":"подниматься; расти","vi":"tăng lên","fa":"بالا آمدن","examples":[{"de":"Die Preise steigen jedes Jahr.","en":"Prices rise every year.","ru":"Цены растут каждый год.","vi":"Giá tăng hàng năm.","fa":"قیمت ها هر سال افزایش می یابد."},{"de":"Wir sind auf den Berg gestiegen.","en":"We climbed the mountain.","ru":"Мы поднялись на гору.","vi":"Chúng tôi leo lên núi.","fa":"از کوه بالا رفتیم."}]},{"word":"steil","en":"steep","ru":"крутой","vi":"dốc","fa":"شیب دار","examples":[{"de":"Der Weg zum Gipfel ist sehr steil.","en":"The path to the summit is very steep.","ru":"Тропа к вершине очень крутая.","vi":"Đường lên đỉnh rất dốc.","fa":"مسیر قله بسیار شیب دار است."},{"de":"Sei vorsichtig, die Treppe ist steil.","en":"Be careful, the stairs are steep.","ru":"Будь осторожен, лестница крутая.","vi":"Hãy cẩn thận, cầu thang dốc.","fa":"مراقب باشید، پله ها شیب دار هستند."}]},{"word":"der Stein","en":"stone","ru":"камень","vi":"hòn đá","fa":"سنگ","examples":[{"de":"Die Kinder haben Steine in den See geworfen.","en":"The children threw stones into the lake.","ru":"Дети бросали камни в озеро.","vi":"Bọn trẻ ném đá xuống hồ.","fa":"بچه ها به دریاچه سنگ پرتاب کردند."},{"de":"Das alte Haus ist aus Stein gebaut.","en":"The old house is built of stone.","ru":"Старый дом построен из камня.","vi":"Ngôi nhà cổ được xây bằng đá.","fa":"خانه قدیمی از سنگ ساخته شده است."}]},{"word":"die Stelle","en":"place; spot; job/position","ru":"место; должность","vi":"nơi","fa":"مکان","examples":[{"de":"An dieser Stelle stand früher ein altes Gebäude.","en":"There used to be an old building at this spot.","ru":"На этом месте раньше стояло старое здание.","vi":"Đã từng có một tòa nhà cũ trên trang web này.","fa":"قبلا یک ساختمان قدیمی در این سایت وجود داشت."},{"de":"Sie hat endlich eine feste Stelle gefunden.","en":"She has finally found a permanent job.","ru":"Она наконец нашла постоянную должность.","vi":"Cuối cùng cô đã tìm được một công việc lâu dài.","fa":"او بالاخره یک شغل دائمی پیدا کرده است."}]},{"word":"stellen","en":"to put; to place","ru":"ставить","vi":"đặt","fa":"قرار دادن","examples":[{"de":"Stell die Tasche bitte neben die Tür.","en":"Please put the bag next to the door.","ru":"Поставь, пожалуйста, сумку рядом с дверью.","vi":"Vui lòng đặt túi cạnh cửa.","fa":"لطفا کیف را کنار در بگذارید."},{"de":"Er stellt immer viele Fragen im Unterricht.","en":"He always asks a lot of questions in class.","ru":"Он всегда задаёт много вопросов на уроке.","vi":"Anh ấy luôn hỏi rất nhiều câu hỏi trong lớp.","fa":"او همیشه در کلاس سوالات زیادی می پرسد."}]},{"word":"der Stempel","en":"stamp (rubber stamp)","ru":"печать; штамп","vi":"con tem","fa":"تمبر","examples":[{"de":"Der Beamte drückte einen Stempel auf das Dokument.","en":"The official stamped the document.","ru":"Чиновник поставил печать на документ.","vi":"Viên chức đóng dấu vào tài liệu.","fa":"افسر روی سند مهر زد."},{"de":"Ohne Stempel ist das Formular nicht gültig.","en":"Without a stamp the form is not valid.","ru":"Без печати бланк недействителен.","vi":"Mẫu đơn không hợp lệ nếu không có tem.","fa":"فرم بدون مهر معتبر نیست."}]},{"word":"sterben","en":"to die","ru":"умирать","vi":"chết","fa":"بمیر","examples":[{"de":"Ihr Großvater ist letztes Jahr gestorben.","en":"Her grandfather died last year.","ru":"Её дедушка умер в прошлом году.","vi":"Ông nội cô qua đời năm ngoái.","fa":"پدربزرگش سال گذشته فوت کرد."},{"de":"Viele Tierarten sterben aus.","en":"Many animal species are dying out.","ru":"Многие виды животных вымирают.","vi":"Nhiều loài động vật đang bị tuyệt chủng.","fa":"بسیاری از گونه های جانوری در حال انقراض هستند."}]},{"word":"der Stern","en":"star (sky)","ru":"звезда (небесное тело)","vi":"ngôi sao","fa":"ستاره","examples":[{"de":"Nachts kann man am Himmel viele Sterne sehen.","en":"At night you can see many stars in the sky.","ru":"Ночью на небе можно увидеть много звёзд.","vi":"Vào ban đêm bạn có thể nhìn thấy nhiều ngôi sao trên bầu trời.","fa":"در شب می توانید ستاره های زیادی را در آسمان ببینید."},{"de":"Am Himmel leuchtete ein heller Stern.","en":"A bright star shone in the sky.","ru":"На небе сияла яркая звезда.","vi":"Một ngôi sao sáng tỏa sáng trên bầu trời.","fa":"ستاره ای درخشان در آسمان می درخشید."}]},{"word":"die Steuer","en":"tax","ru":"налог","vi":"thuế","fa":"مالیات","examples":[{"de":"Jeder Arbeitnehmer muss Steuern zahlen.","en":"Every employee has to pay taxes.","ru":"Каждый работник должен платить налоги.","vi":"Mọi nhân viên đều phải đóng thuế.","fa":"هر کارمند باید مالیات بپردازد."},{"de":"Die Steuer auf Benzin ist in diesem Land hoch.","en":"The tax on gasoline is high in this country.","ru":"Налог на бензин в этой стране высокий.","vi":"Thuế xăng ở nước này rất cao.","fa":"مالیات بر بنزین در این کشور بالاست."}]},{"word":"der Steward","en":"steward (flight attendant)","ru":"стюард","vi":"người quản lý","fa":"مهماندار","examples":[{"de":"Der Steward bringt uns während des Fluges etwas zu trinken.","en":"The steward brings us something to drink during the flight.","ru":"Стюард приносит нам что-нибудь попить во время полёта.","vi":"Tiếp viên mang cho chúng tôi thứ gì đó để uống trong suốt chuyến bay.","fa":"مهماندار در طول پرواز برای ما چیزی برای نوشیدن می آورد."},{"de":"Er arbeitet seit zwei Jahren als Steward bei einer Fluggesellschaft.","en":"He has been working as a steward for an airline for two years.","ru":"Он уже два года работает стюардом в авиакомпании.","vi":"Anh ấy đã làm tiếp viên tại một hãng hàng không được hai năm.","fa":"او دو سال است که به عنوان مهماندار در یک شرکت هواپیمایی کار می کند."}]},{"word":"der Stiefel","en":"boot","ru":"сапог; ботинок","vi":"chiếc ủng","fa":"چکمه","examples":[{"de":"Im Winter trage ich immer warme Stiefel.","en":"In winter I always wear warm boots.","ru":"Зимой я всегда ношу тёплые сапоги.","vi":"Vào mùa đông tôi luôn đi ủng ấm.","fa":"در زمستان همیشه چکمه های گرم می پوشم."},{"de":"Diese Stiefel sind wasserdicht.","en":"These boots are waterproof.","ru":"Эти сапоги водонепроницаемые.","vi":"Những đôi ủng này không thấm nước.","fa":"این چکمه ها ضد آب هستند."}]},{"word":"die Stiege","en":"staircase (Austrian usage)","ru":"лестница","vi":"cầu thang","fa":"پله ها","examples":[{"de":"Die Stiege zum Dachboden ist sehr schmal.","en":"The staircase to the attic is very narrow.","ru":"Лестница на чердак очень узкая.","vi":"Cầu thang lên gác mái rất hẹp.","fa":"پله های اتاق زیر شیروانی بسیار باریک است."},{"de":"Er ist über die Stiege nach oben gegangen.","en":"He went up the stairs.","ru":"Он поднялся наверх по лестнице.","vi":"Anh ấy đi lên cầu thang.","fa":"از پله ها بالا رفت."}]},{"word":"das Stiegenhaus","en":"stairwell (Austrian usage)","ru":"лестничная клетка","vi":"cầu thang","fa":"راه پله","examples":[{"de":"Im Stiegenhaus riecht es nach frischer Farbe.","en":"The stairwell smells of fresh paint.","ru":"В подъезде пахнет свежей краской.","vi":"Cầu thang thơm mùi sơn mới.","fa":"راه پله بوی رنگ تازه می دهد."},{"de":"Die Nachbarn treffen sich oft im Stiegenhaus.","en":"The neighbors often meet in the stairwell.","ru":"Соседи часто встречаются на лестничной клетке.","vi":"Hàng xóm thường gặp nhau ở cầu thang.","fa":"همسایه ها اغلب در راه پله ملاقات می کنند."}]},{"word":"der Stift","en":"pen; pencil","ru":"карандаш; ручка","vi":"cây bút","fa":"قلم","examples":[{"de":"Kannst du mir bitte einen Stift leihen?","en":"Can you lend me a pen, please?","ru":"Можешь одолжить мне карандаш, пожалуйста?","vi":"Bạn có thể cho tôi mượn một cây bút được không?","fa":"میشه یه خودکار بهم قرض بدی لطفا؟"},{"de":"Der Stift ist leer, ich brauche einen neuen.","en":"The pen is empty, I need a new one.","ru":"Ручка кончилась, мне нужна новая.","vi":"Cây bút đã hết, tôi cần một cái mới.","fa":"خودکار خالی است، به یک قلم جدید نیاز دارم."}]},{"word":"der Stil","en":"style","ru":"стиль","vi":"phong cách","fa":"سبک","examples":[{"de":"Sie hat einen sehr eigenen Stil beim Schreiben.","en":"She has a very individual style of writing.","ru":"У неё очень своеобразный стиль письма.","vi":"Cô ấy có phong cách viết rất độc đáo.","fa":"او سبک نوشتاری بسیار منحصر به فردی دارد."},{"de":"Das Haus ist im modernen Stil eingerichtet.","en":"The house is furnished in a modern style.","ru":"Дом обставлен в современном стиле.","vi":"Ngôi nhà được trang bị nội thất theo phong cách hiện đại.","fa":"خانه به سبک مدرن مبله شده است."}]},{"word":"still","en":"quiet; silent; still","ru":"тихий; спокойный","vi":"im lặng","fa":"ساکت","examples":[{"de":"In der Bibliothek muss man still sein.","en":"You have to be quiet in the library.","ru":"В библиотеке нужно вести себя тихо.","vi":"Bạn phải im lặng trong thư viện.","fa":"شما باید در کتابخانه ساکت باشید."},{"de":"Der See lag still und ruhig vor uns.","en":"The lake lay still and calm before us.","ru":"Озеро лежало перед нами тихое и спокойное.","vi":"Mặt hồ nằm tĩnh lặng trước mặt chúng tôi.","fa":"دریاچه در مقابل ما آرام و آرام بود."}]},{"word":"die Stimme","en":"voice","ru":"голос","vi":"giọng nói","fa":"صدا","examples":[{"de":"Sie hat eine sehr schöne Singstimme.","en":"She has a very beautiful singing voice.","ru":"У неё очень красивый певческий голос.","vi":"Cô ấy có giọng hát rất hay.","fa":"او صدای خوانندگی بسیار زیبایی دارد."},{"de":"Ich habe seine Stimme sofort am Telefon erkannt.","en":"I recognized his voice on the phone immediately.","ru":"Я сразу узнал его голос по телефону.","vi":"Tôi nhận ra giọng nói của anh ngay trên điện thoại.","fa":"بلافاصله صدایش را در تلفن تشخیص دادم."}]},{"word":"stimmen","en":"to be correct/right; to vote","ru":"быть верным; голосовать","vi":"đồng ý","fa":"موافق","examples":[{"de":"Deine Rechnung stimmt leider nicht.","en":"Unfortunately, your calculation is not correct.","ru":"К сожалению, твой расчёт неверен.","vi":"Thật không may, tính toán của bạn không chính xác.","fa":"متأسفانه محاسبه شما نادرست است."},{"de":"Bei der Wahl stimmten viele Bürger für den neuen Kandidaten.","en":"In the election, many citizens voted for the new candidate.","ru":"На выборах многие граждане проголосовали за нового кандидата.","vi":"Trong cuộc bầu cử, nhiều người dân đã bỏ phiếu cho ứng cử viên mới.","fa":"در انتخابات بسیاری از شهروندان به نامزد جدید رای دادند."}]},{"word":"die Stimmung","en":"mood; atmosphere","ru":"настроение; атмосфера","vi":"tâm trạng","fa":"خلق و خوی","examples":[{"de":"Auf der Party herrschte eine tolle Stimmung.","en":"There was a great atmosphere at the party.","ru":"На вечеринке царило отличное настроение.","vi":"Có một bầu không khí tuyệt vời tại bữa tiệc.","fa":"فضای بسیار خوبی در مهمانی حاکم بود."},{"de":"Er ist heute schlechter Stimmung.","en":"He's in a bad mood today.","ru":"Сегодня у него плохое настроение.","vi":"Hôm nay anh ấy có tâm trạng không tốt.","fa":"امروز حالش بد است."}]},{"word":"stinken","en":"to stink","ru":"вонять","vi":"hôi thối","fa":"بوی تعفن","examples":[{"de":"Der Müll im Hof stinkt schon seit Tagen.","en":"The trash in the yard has been stinking for days.","ru":"Мусор во дворе воняет уже несколько дней.","vi":"Rác trong sân đã bốc mùi mấy ngày nay.","fa":"زباله های حیاط چند روزی است که بو می دهد."},{"de":"Es stinkt hier nach Zigarettenrauch.","en":"It stinks of cigarette smoke here.","ru":"Здесь воняет сигаретным дымом.","vi":"Ở đây có mùi khói thuốc lá.","fa":"اینجا بوی دود سیگار می دهد."}]},{"word":"der Stock/die Etage","en":"floor; story (of a building)","ru":"этаж","vi":"sàn/tầng","fa":"کف / کف","examples":[{"de":"Unsere Wohnung liegt im dritten Stock.","en":"Our apartment is on the third floor.","ru":"Наша квартира находится на третьем этаже.","vi":"Căn hộ của chúng tôi ở trên tầng ba.","fa":"آپارتمان ما در طبقه سوم است."},{"de":"Der Aufzug fährt bis in die oberste Etage.","en":"The elevator goes up to the top floor.","ru":"Лифт едет до самого верхнего этажа.","vi":"Thang máy đi lên tầng trên cùng.","fa":"آسانسور به طبقه بالا می رود."}]},{"word":"der Stoff","en":"fabric; material; substance","ru":"ткань; материал; вещество","vi":"vật liệu","fa":"مواد","examples":[{"de":"Das Kleid ist aus einem weichen Stoff genäht.","en":"The dress is sewn from a soft fabric.","ru":"Платье сшито из мягкой ткани.","vi":"Chiếc váy được may từ chất liệu vải mềm mại.","fa":"لباس از پارچه نرم دوخته شده است."},{"de":"Dieser Stoff ist für den Menschen giftig.","en":"This substance is toxic to humans.","ru":"Это вещество токсично для человека.","vi":"Chất này độc hại đối với con người.","fa":"این ماده برای انسان سمی است."}]},{"word":"stolz","en":"proud","ru":"гордый","vi":"tự hào","fa":"افتخار","examples":[{"de":"Die Eltern sind sehr stolz auf ihre Tochter.","en":"The parents are very proud of their daughter.","ru":"Родители очень гордятся своей дочерью.","vi":"Cha mẹ rất tự hào về con gái mình.","fa":"والدین به دختر خود بسیار افتخار می کنند."},{"de":"Er ist stolz auf seine Arbeit.","en":"He is proud of his work.","ru":"Он гордится своей работой.","vi":"Anh ấy tự hào về công việc của mình.","fa":"او به کار خود افتخار می کند."}]},{"word":"der Stolz","en":"pride","ru":"гордость","vi":"niềm tự hào","fa":"غرور","examples":[{"de":"Mit Stolz zeigte sie ihr Zeugnis.","en":"She proudly showed her report card.","ru":"С гордостью она показала свой табель.","vi":"Cô tự hào đưa ra lời khai của mình.","fa":"او با افتخار شهادت خود را نشان داد."},{"de":"Sein Stolz erlaubte ihm nicht, um Hilfe zu bitten.","en":"His pride wouldn't let him ask for help.","ru":"Его гордость не позволяла ему просить о помощи.","vi":"Niềm tự hào của anh không cho phép anh yêu cầu giúp đỡ.","fa":"غرورش اجازه نمی داد کمک بخواهد."}]},{"word":"stoppen","en":"to stop","ru":"останавливать(ся); стопорить","vi":"dừng lại","fa":"توقف","examples":[{"de":"Der Fahrer musste plötzlich stoppen.","en":"The driver had to stop suddenly.","ru":"Водителю пришлось резко остановиться.","vi":"Tài xế phải dừng lại đột ngột.","fa":"راننده مجبور شد ناگهان توقف کند."},{"de":"Die Polizei stoppte das Auto an der Grenze.","en":"The police stopped the car at the border.","ru":"Полиция остановила машину на границе.","vi":"Cảnh sát dừng xe ở biên giới.","fa":"پلیس ماشین را در مرز متوقف کرد."}]},{"word":"stören","en":"to disturb; to bother","ru":"мешать; беспокоить","vi":"làm phiền","fa":"مزاحم","examples":[{"de":"Entschuldigung, störe ich dich gerade?","en":"Excuse me, am I disturbing you right now?","ru":"Извини, я тебе сейчас не мешаю?","vi":"Xin lỗi, tôi có làm phiền bạn không?","fa":"ببخشید مزاحم شما هستم؟"},{"de":"Der Lärm von der Baustelle stört die Nachbarn.","en":"The noise from the construction site disturbs the neighbors.","ru":"Шум со стройки мешает соседям.","vi":"Tiếng ồn từ công trường xây dựng làm phiền hàng xóm.","fa":"سر و صدا از محل ساخت و ساز همسایه ها را آزار می دهد."}]},{"word":"die Strafe","en":"punishment; fine; penalty","ru":"наказание; штраф","vi":"sự trừng phạt","fa":"مجازات","examples":[{"de":"Für Falschparken muss man eine Strafe zahlen.","en":"You have to pay a fine for parking illegally.","ru":"За неправильную парковку нужно платить штраф.","vi":"Bạn phải trả tiền phạt cho việc đỗ xe trái phép.","fa":"برای پارک غیرقانونی باید جریمه بپردازید."},{"de":"Die Strafe für dieses Verbrechen ist sehr hoch.","en":"The punishment for this crime is very severe.","ru":"Наказание за это преступление очень суровое.","vi":"Mức án cho tội này rất cao.","fa":"مجازات این جنایت بسیار زیاد است."}]},{"word":"der Strand","en":"beach","ru":"пляж","vi":"bãi biển","fa":"ساحل","examples":[{"de":"Im Sommer verbringen wir viel Zeit am Strand.","en":"In summer we spend a lot of time at the beach.","ru":"Летом мы проводим много времени на пляже.","vi":"Vào mùa hè, chúng tôi dành nhiều thời gian trên bãi biển.","fa":"در تابستان زمان زیادی را در ساحل می گذرانیم."},{"de":"Der Strand war heute sehr voll.","en":"The beach was very crowded today.","ru":"Пляж сегодня был очень многолюдным.","vi":"Bãi biển hôm nay rất đông người.","fa":"امروز ساحل خیلی شلوغ بود."}]},{"word":"die Straße","en":"street; road","ru":"улица; дорога","vi":"đường phố","fa":"خیابان","examples":[{"de":"Wir wohnen in einer ruhigen Straße.","en":"We live on a quiet street.","ru":"Мы живём на тихой улице.","vi":"Chúng tôi sống trên một con phố yên tĩnh.","fa":"ما در یک خیابان ساکت زندگی می کنیم."},{"de":"Auf der Straße war heute viel Verkehr.","en":"There was a lot of traffic on the road today.","ru":"На дороге сегодня было много машин.","vi":"Hôm nay trên đường phố có rất nhiều xe cộ qua lại.","fa":"امروز ترافیک زیادی در خیابان وجود داشت."}]},{"word":"die Straßenbahn","en":"tram; streetcar","ru":"трамвай","vi":"xe điện","fa":"تراموا","examples":[{"de":"Ich fahre jeden Tag mit der Straßenbahn zur Arbeit.","en":"I take the tram to work every day.","ru":"Я каждый день езжу на работу на трамвае.","vi":"Tôi đi xe điện đi làm hàng ngày.","fa":"من هر روز با تراموا سر کار می روم."},{"de":"Die Straßenbahn hält direkt vor unserem Haus.","en":"The tram stops right in front of our house.","ru":"Трамвай останавливается прямо перед нашим домом.","vi":"Xe điện dừng ngay trước nhà chúng tôi.","fa":"تراموا درست جلوی خانه ما می ایستد."}]},{"word":"die Strecke","en":"distance; route; stretch","ru":"маршрут; расстояние; участок пути","vi":"tuyến đường","fa":"مسیر","examples":[{"de":"Die Strecke von Wien nach Salzburg dauert etwa drei Stunden.","en":"The route from Vienna to Salzburg takes about three hours.","ru":"Путь из Вены в Зальцбург занимает около трёх часов.","vi":"Tuyến đường từ Vienna đến Salzburg mất khoảng ba giờ.","fa":"مسیر وین تا سالزبورگ حدود سه ساعت طول می کشد."},{"de":"Wir sind eine lange Strecke zu Fuß gelaufen.","en":"We walked a long distance on foot.","ru":"Мы прошли пешком длинное расстояние.","vi":"Chúng tôi đi bộ một quãng đường dài.","fa":"مسافت زیادی را پیاده رفتیم."}]},{"word":"das Streichholz","en":"match (for lighting)","ru":"спичка","vi":"trận đấu","fa":"مسابقه","examples":[{"de":"Er zündete die Kerze mit einem Streichholz an.","en":"He lit the candle with a match.","ru":"Он зажёг свечу спичкой.","vi":"Anh ta thắp nến bằng một que diêm.","fa":"شمع را با کبریت روشن کرد."},{"de":"Hast du zufällig ein Streichholz dabei?","en":"Do you happen to have a match with you?","ru":"У тебя случайно нет с собой спички?","vi":"Bạn có tình cờ có một trận đấu với bạn?","fa":"آیا اتفاقاً با شما مسابقه ای دارید؟"}]},{"word":"streiken","en":"to (go on) strike","ru":"бастовать","vi":"đánh đập","fa":"اعتصاب","examples":[{"de":"Die Fluglotsen streiken morgen den ganzen Tag.","en":"The air traffic controllers are on strike all day tomorrow.","ru":"Авиадиспетчеры завтра бастуют весь день.","vi":"Ngày mai các nhân viên kiểm soát không lưu sẽ đình công cả ngày.","fa":"اعتصاب ناظران هوايي فردا تمام روز است."},{"de":"Die Arbeiter streiken für höhere Löhne.","en":"The workers are striking for higher wages.","ru":"Рабочие бастуют за повышение зарплаты.","vi":"Công nhân đình công đòi tăng lương.","fa":"کارگران برای افزایش دستمزد اعتصاب می کنند."}]},{"word":"streng","en":"strict","ru":"строгий","vi":"nghiêm khắc","fa":"سختگیر","examples":[{"de":"Unser Lehrer ist sehr streng.","en":"Our teacher is very strict.","ru":"Наш учитель очень строгий.","vi":"Giáo viên của chúng tôi rất nghiêm khắc.","fa":"معلم ما خیلی سخت گیر است."},{"de":"In dieser Firma gelten strenge Regeln.","en":"Strict rules apply in this company.","ru":"В этой компании действуют строгие правила.","vi":"Các quy tắc nghiêm ngặt được áp dụng trong công ty này.","fa":"قوانین سختگیرانه ای در این شرکت اعمال می شود."}]},{"word":"der Stress","en":"stress","ru":"стресс","vi":"sự căng thẳng","fa":"استرس","examples":[{"de":"Sie hat wegen der Prüfung viel Stress.","en":"She has a lot of stress because of the exam.","ru":"У неё сильный стресс из-за экзамена.","vi":"Cô ấy đang bị căng thẳng rất nhiều vì kỳ thi.","fa":"او به دلیل امتحان استرس زیادی دارد."},{"de":"Zu viel Stress ist schlecht für die Gesundheit.","en":"Too much stress is bad for your health.","ru":"Слишком сильный стресс вреден для здоровья.","vi":"Căng thẳng quá mức sẽ có hại cho sức khỏe của bạn.","fa":"استرس زیاد برای سلامتی مضر است."}]},{"word":"der Strom","en":"electricity; power; current","ru":"электричество; ток","vi":"dòng suối","fa":"جریان","examples":[{"de":"Bei dem Sturm ist der Strom ausgefallen.","en":"The power went out during the storm.","ru":"Во время шторма отключилось электричество.","vi":"Mất điện trong cơn bão.","fa":"هنگام طوفان برق قطع شد."},{"de":"Wir versuchen, weniger Strom zu verbrauchen.","en":"We're trying to use less electricity.","ru":"Мы стараемся потреблять меньше электроэнергии.","vi":"Chúng tôi đang cố gắng sử dụng ít điện hơn.","fa":"سعی می کنیم کمتر از برق استفاده کنیم."}]},{"word":"der Strumpf","en":"stocking","ru":"чулок","vi":"việc thả giống","fa":"جوراب ساق بلند","examples":[{"de":"Sie zieht warme Strümpfe an, bevor sie hinausgeht.","en":"She puts on warm stockings before going outside.","ru":"Она надевает тёплые чулки, прежде чем выйти на улицу.","vi":"Cô ấy đi tất ấm trước khi ra ngoài.","fa":"قبل از بیرون رفتن جوراب گرم می پوشد."},{"de":"Ein Strumpf hat ein Loch bekommen.","en":"One stocking got a hole in it.","ru":"На одном чулке появилась дыра.","vi":"Một chiếc tất bị thủng một lỗ.","fa":"یک جوراب ساق بلند سوراخ شد."}]},{"word":"das Stück/-stück","en":"piece","ru":"кусок; штука","vi":"mảnh / mảnh","fa":"قطعه / قطعه","examples":[{"de":"Möchtest du noch ein Stück Kuchen?","en":"Would you like another piece of cake?","ru":"Хочешь ещё кусочек торта?","vi":"Bạn có muốn một miếng bánh khác không?","fa":"آیا یک تکه کیک دیگر می خواهید؟"},{"de":"Er hat sich ein Geldstück aus der Tasche geholt.","en":"He took a coin out of his pocket.","ru":"Он достал монету из кармана.","vi":"Anh ta lấy một đồng xu ra khỏi túi.","fa":"یک سکه از جیبش در آورد."}]},{"word":"die Studie","en":"study (research)","ru":"исследование (научное)","vi":"nghiên cứu","fa":"مطالعه","examples":[{"de":"Eine neue Studie zeigt die Vorteile von regelmäßigem Sport.","en":"A new study shows the benefits of regular exercise.","ru":"Новое исследование показывает пользу регулярных занятий спортом.","vi":"Một nghiên cứu mới cho thấy lợi ích của việc tập thể dục thường xuyên.","fa":"یک مطالعه جدید فواید ورزش منظم را نشان می دهد."},{"de":"Die Studie wurde von Wissenschaftlern der Universität durchgeführt.","en":"The study was conducted by scientists at the university.","ru":"Исследование было проведено учёными университета.","vi":"Nghiên cứu được thực hiện bởi các nhà khoa học từ trường đại học.","fa":"این مطالعه توسط دانشمندان دانشگاه انجام شد."}]},{"word":"der Studiengang","en":"degree programme; course of study","ru":"направление обучения; специальность","vi":"quá trình học tập","fa":"دوره تحصیلی","examples":[{"de":"Dieser Studiengang dauert sechs Semester.","en":"This degree programme lasts six semesters.","ru":"Это направление обучения длится шесть семестров.","vi":"Khóa học này kéo dài sáu học kỳ.","fa":"این دوره شش ترم به طول می انجامد."},{"de":"Sie hat den Studiengang gewechselt.","en":"She changed her course of study.","ru":"Она сменила направление обучения.","vi":"Cô ấy đã thay đổi khóa học của mình.","fa":"او رشته تحصیلی خود را تغییر داد."}]},{"word":"studieren","en":"to study (at university)","ru":"учиться (в университете)","vi":"học tập","fa":"مطالعه کنید","examples":[{"de":"Meine Schwester studiert Medizin in Berlin.","en":"My sister is studying medicine in Berlin.","ru":"Моя сестра изучает медицину в Берлине.","vi":"Em gái tôi đang học y khoa ở Berlin.","fa":"خواهرم در برلین پزشکی می خواند."},{"de":"Nach dem Abitur möchte er Jura studieren.","en":"After finishing school, he wants to study law.","ru":"После окончания школы он хочет изучать право.","vi":"Sau khi tốt nghiệp trung học, anh muốn học luật.","fa":"او پس از پایان دبیرستان، دوست دارد در رشته حقوق تحصیل کند."}]},{"word":"das Studio","en":"studio","ru":"студия","vi":"studio","fa":"استودیو","examples":[{"de":"Die Band nimmt ihr neues Album im Studio auf.","en":"The band is recording their new album in the studio.","ru":"Группа записывает свой новый альбом в студии.","vi":"Ban nhạc đang thu âm album mới trong phòng thu.","fa":"گروه در حال ضبط آلبوم جدید خود در استودیو است."},{"de":"Sie wohnt in einem kleinen Studio in der Innenstadt.","en":"She lives in a small studio apartment in the city center.","ru":"Она живёт в маленькой студии в центре города.","vi":"Cô sống trong một studio nhỏ ở trung tâm thành phố.","fa":"او در یک استودیوی کوچک در مرکز شهر زندگی می کند."}]},{"word":"das Studium","en":"studies; degree course","ru":"учёба (в вузе)","vi":"nghiên cứu","fa":"مطالعه","examples":[{"de":"Nach dem Studium möchte er im Ausland arbeiten.","en":"After his studies he wants to work abroad.","ru":"После учёбы он хочет работать за границей.","vi":"Sau khi học xong anh ấy muốn làm việc ở nước ngoài.","fa":"پس از تحصیل او دوست دارد در خارج از کشور کار کند."},{"de":"Das Studium der Medizin ist sehr anspruchsvoll.","en":"Studying medicine is very demanding.","ru":"Учёба на медицинском очень требовательная.","vi":"Nghiên cứu y học là rất khắt khe.","fa":"تحصیل در رشته پزشکی بسیار سخت است."}]},{"word":"die Stufe","en":"step (stair); level","ru":"ступень(ка); уровень","vi":"sân khấu","fa":"صحنه","examples":[{"de":"Vorsicht, die Stufe ist hoch!","en":"Careful, the step is high!","ru":"Осторожно, ступенька высокая!","vi":"Hãy cẩn thận, mức độ cao!","fa":"مراقب باشید، سطح بالاست!"},{"de":"Der Kurs ist in mehrere Stufen unterteilt.","en":"The course is divided into several levels.","ru":"Курс разделён на несколько уровней.","vi":"Khóa học được chia thành nhiều cấp độ.","fa":"این دوره به چند سطح تقسیم می شود."}]},{"word":"der Stuhl","en":"chair","ru":"стул","vi":"cái ghế","fa":"صندلی","examples":[{"de":"Bitte setz dich auf diesen Stuhl.","en":"Please sit down on this chair.","ru":"Пожалуйста, сядь на этот стул.","vi":"Xin hãy ngồi vào chiếc ghế này.","fa":"لطفا روی این صندلی بنشینید."},{"de":"Der Stuhl ist kaputt, ein Bein wackelt.","en":"The chair is broken, one leg is wobbly.","ru":"Стул сломан, одна ножка шатается.","vi":"Ghế gãy, một chân lung lay.","fa":"صندلی شکسته است، یک پا تکان می خورد."}]},{"word":"stumm","en":"mute; silent","ru":"немой; безмолвный","vi":"im lặng","fa":"ساکت","examples":[{"de":"Der Junge saß stumm in der Ecke.","en":"The boy sat silently in the corner.","ru":"Мальчик сидел молча в углу.","vi":"Cậu bé ngồi im lặng trong góc.","fa":"پسر ساکت در گوشه ای نشست."},{"de":"Nach dem Unfall war sie für einige Tage stumm vor Schock.","en":"After the accident she was mute with shock for a few days.","ru":"После аварии она несколько дней была нема от шока.","vi":"Sau vụ tai nạn, cô im lặng vì sốc vài ngày.","fa":"بعد از تصادف چند روزی در شوک سکوت کرد."}]},{"word":"die Stunde","en":"hour; lesson","ru":"час; урок","vi":"giờ","fa":"ساعت","examples":[{"de":"Der Film dauert etwa zwei Stunden.","en":"The movie lasts about two hours.","ru":"Фильм длится около двух часов.","vi":"Bộ phim kéo dài khoảng hai giờ.","fa":"فیلم حدود دو ساعت طول می کشد."},{"de":"Wir haben jeden Montag eine Stunde Mathematik.","en":"We have a math lesson every Monday.","ru":"У нас каждый понедельник урок математики.","vi":"Chúng tôi có một giờ học toán vào thứ Hai hàng tuần.","fa":"هر دوشنبه یک ساعت ریاضی داریم."}]},{"word":"der Sturm","en":"storm","ru":"шторм; буря","vi":"cơn bão","fa":"طوفان","examples":[{"de":"Ein starker Sturm hat letzte Nacht viele Bäume umgeworfen.","en":"A strong storm knocked down many trees last night.","ru":"Сильная буря вчера ночью повалила много деревьев.","vi":"Đêm qua một cơn bão mạnh đã quật đổ nhiều cây cối.","fa":"طوفان شدید شب گذشته درختان زیادی را فرو ریخت."},{"de":"Wegen des Sturms wurden alle Flüge gestrichen.","en":"Because of the storm, all flights were cancelled.","ru":"Из-за шторма все рейсы были отменены.","vi":"Vì cơn bão nên tất cả các chuyến bay đều bị hủy.","fa":"به دلیل طوفان همه پروازها لغو شد."}]},{"word":"stürzen","en":"to fall (heavily); to crash","ru":"падать, рухнуть","vi":"ngã","fa":"سقوط","examples":[{"de":"Der alte Mann ist auf der Treppe gestürzt.","en":"The old man fell on the stairs.","ru":"Пожилой мужчина упал на лестнице.","vi":"Ông già bị ngã ở cầu thang.","fa":"پیرمرد روی پله ها افتاد."},{"de":"Pass auf, dass du nicht stürzt!","en":"Be careful not to fall!","ru":"Осторожно, не упади!","vi":"Hãy cẩn thận để không bị ngã!","fa":"مراقب باشید زمین نخورید!"}]},{"word":"suchen","en":"to look for, to search","ru":"искать","vi":"tìm kiếm","fa":"جستجو کنید","examples":[{"de":"Ich suche meinen Schlüssel.","en":"I am looking for my key.","ru":"Я ищу свой ключ.","vi":"Tôi đang tìm chìa khóa của mình.","fa":"من دنبال کلیدم هستم"},{"de":"Wir suchen eine neue Wohnung.","en":"We are looking for a new apartment.","ru":"Мы ищем новую квартиру.","vi":"Chúng tôi đang tìm kiếm một căn hộ mới.","fa":"ما به دنبال یک آپارتمان جدید هستیم."}]},{"word":"die Sucht","en":"addiction","ru":"зависимость","vi":"sự nghiện ngập","fa":"اعتیاد","examples":[{"de":"Seine Sucht nach Zigaretten war schwer zu besiegen.","en":"His addiction to cigarettes was hard to overcome.","ru":"Его зависимость от сигарет было трудно преодолеть.","vi":"Chứng nghiện thuốc lá của anh rất khó vượt qua.","fa":"غلبه بر اعتیاد او به سیگار دشوار بود."},{"de":"Die Ärzte warnen vor der Sucht nach dem Handy.","en":"Doctors warn about smartphone addiction.","ru":"Врачи предупреждают о зависимости от смартфона.","vi":"Các bác sĩ cảnh báo chống nghiện điện thoại di động.","fa":"هشدار پزشکان نسبت به اعتیاد به تلفن همراه"}]},{"word":"die Summe","en":"sum, total amount","ru":"сумма","vi":"tổng","fa":"مجموع","examples":[{"de":"Die Summe aller Kosten beträgt tausend Euro.","en":"The sum of all costs amounts to a thousand euros.","ru":"Сумма всех расходов составляет тысячу евро.","vi":"Tổng cộng tất cả các chi phí là một nghìn euro.","fa":"مجموع تمام هزینه ها هزار یورو است."},{"de":"Er hat eine hohe Summe gespart.","en":"He has saved a large sum.","ru":"Он накопил большую сумму.","vi":"Anh ấy đã tiết kiệm được một khoản tiền lớn.","fa":"او مبلغ زیادی پس انداز کرده است."}]},{"word":"super","en":"great, super","ru":"супер, отлично","vi":"tuyệt vời","fa":"عالی","examples":[{"de":"Der Film war super!","en":"The movie was great!","ru":"Фильм был супер!","vi":"Bộ phim thật tuyệt vời!","fa":"فیلم عالی بود!"},{"de":"Das hast du super gemacht.","en":"You did that great.","ru":"Ты сделал это отлично.","vi":"Bạn đã làm rất tốt.","fa":"عالی کار کردی"}]},{"word":"der Supermarkt","en":"supermarket","ru":"супермаркет","vi":"siêu thị","fa":"سوپرمارکت","examples":[{"de":"Ich kaufe im Supermarkt ein.","en":"I shop at the supermarket.","ru":"Я делаю покупки в супермаркете.","vi":"Tôi mua sắm ở siêu thị.","fa":"من از سوپرمارکت خرید می کنم."},{"de":"Der Supermarkt hat bis 20 Uhr geöffnet.","en":"The supermarket is open until 8 p.m.","ru":"Супермаркет открыт до 20 часов.","vi":"Siêu thị mở cửa đến 8 giờ tối.","fa":"سوپرمارکت تا ساعت 8 شب باز است."}]},{"word":"die Suppe","en":"soup","ru":"суп","vi":"súp","fa":"سوپ","examples":[{"de":"Meine Mutter kocht eine leckere Suppe.","en":"My mother is cooking a delicious soup.","ru":"Моя мама варит вкусный суп.","vi":"Mẹ tôi nấu một món súp ngon.","fa":"مادرم یک سوپ خوشمزه درست می کند."},{"de":"Ich esse gern Suppe im Winter.","en":"I like to eat soup in winter.","ru":"Я люблю есть суп зимой.","vi":"Tôi thích ăn súp vào mùa đông.","fa":"من دوست دارم در زمستان سوپ بخورم."}]},{"word":"süß","en":"sweet; cute","ru":"сладкий; милый","vi":"ngọt ngào","fa":"شیرین","examples":[{"de":"Der Kuchen ist sehr süß.","en":"The cake is very sweet.","ru":"Торт очень сладкий.","vi":"Bánh rất ngọt.","fa":"کیک خیلی شیرینه"},{"de":"Das kleine Kätzchen ist so süß!","en":"The little kitten is so cute!","ru":"Этот маленький котёнок такой милый!","vi":"Con mèo nhỏ đáng yêu quá!","fa":"بچه گربه کوچولو خیلی بامزه است!"}]},{"word":"das Symbol","en":"symbol","ru":"символ","vi":"biểu tượng","fa":"نماد","examples":[{"de":"Die Taube ist ein Symbol für Frieden.","en":"The dove is a symbol of peace.","ru":"Голубь — символ мира.","vi":"Chim bồ câu là biểu tượng của hòa bình.","fa":"کبوتر نماد صلح است."},{"de":"Auf dem Bildschirm siehst du ein neues Symbol.","en":"You see a new symbol on the screen.","ru":"На экране ты видишь новый значок.","vi":"Bạn sẽ thấy một biểu tượng mới trên màn hình.","fa":"یک نماد جدید روی صفحه نمایش خواهید دید."}]},{"word":"sympathisch","en":"likeable, nice","ru":"симпатичный, приятный","vi":"thông cảm","fa":"دلسوز","examples":[{"de":"Meine neue Kollegin ist sehr sympathisch.","en":"My new colleague is very likeable.","ru":"Моя новая коллега очень приятная.","vi":"Đồng nghiệp mới của tôi rất dễ mến.","fa":"همکار جدید من خیلی دوست داشتنی است."},{"de":"Er wirkt auf mich sympathisch.","en":"He seems likeable to me.","ru":"Он производит на меня приятное впечатление.","vi":"Anh ấy có vẻ dễ mến đối với tôi.","fa":"او برای من دوست داشتنی به نظر می رسد."}]},{"word":"das System","en":"system","ru":"система","vi":"hệ thống","fa":"سیستم","examples":[{"de":"Das politische System hat sich verändert.","en":"The political system has changed.","ru":"Политическая система изменилась.","vi":"Hệ thống chính trị đã thay đổi.","fa":"نظام سیاسی تغییر کرده است."},{"de":"Unser Computer hat ein neues System.","en":"Our computer has a new system.","ru":"У нашего компьютера новая система.","vi":"Máy tính của chúng tôi có một hệ thống mới.","fa":"کامپیوتر ما یک سیستم جدید دارد."}]},{"word":"die Szene","en":"scene","ru":"сцена, эпизод","vi":"bối cảnh","fa":"صحنه","examples":[{"de":"Diese Szene im Film hat mich sehr berührt.","en":"This scene in the movie touched me a lot.","ru":"Эта сцена в фильме меня очень тронула.","vi":"Cảnh này trong phim thực sự làm tôi cảm động.","fa":"این صحنه در فیلم واقعاً مرا تحت تأثیر قرار داد."},{"de":"Die Schauspieler proben die letzte Szene.","en":"The actors are rehearsing the last scene.","ru":"Актёры репетируют последнюю сцену.","vi":"Các diễn viên diễn tập cảnh cuối cùng.","fa":"بازیگران صحنه پایانی را تمرین می کنند."}]},{"word":"die Tabelle","en":"table, chart","ru":"таблица","vi":"cái bàn","fa":"جدول","examples":[{"de":"Die Ergebnisse stehen in der Tabelle.","en":"The results are in the table.","ru":"Результаты указаны в таблице.","vi":"Kết quả có trong bảng.","fa":"نتایج در جدول آمده است."},{"de":"Er trägt die Zahlen in eine Tabelle ein.","en":"He enters the numbers into a table.","ru":"Он вносит числа в таблицу.","vi":"Anh ta nhập các số vào một bảng.","fa":"او اعداد را در جدول وارد می کند."}]},{"word":"die Tablette","en":"pill, tablet","ru":"таблетка","vi":"máy tính bảng","fa":"تبلت","examples":[{"de":"Nimm diese Tablette gegen die Kopfschmerzen.","en":"Take this pill for the headache.","ru":"Прими эту таблетку от головной боли.","vi":"Dùng máy tính bảng này để giảm đau đầu.","fa":"این قرص را برای سردرد مصرف کنید."},{"de":"Der Arzt hat mir Tabletten verschrieben.","en":"The doctor prescribed me pills.","ru":"Врач прописал мне таблетки.","vi":"Bác sĩ kê cho tôi thuốc viên.","fa":"دکتر برام قرص تجویز کرد."}]},{"word":"die Tafel","en":"blackboard; bar (of chocolate)","ru":"доска; плитка (шоколада)","vi":"bảng","fa":"هیئت مدیره","examples":[{"de":"Der Lehrer schreibt die Wörter an die Tafel.","en":"The teacher writes the words on the blackboard.","ru":"Учитель пишет слова на доске.","vi":"Giáo viên viết các từ lên bảng.","fa":"معلم کلمات را روی تخته می نویسد."},{"de":"Ich habe eine Tafel Schokolade gekauft.","en":"I bought a bar of chocolate.","ru":"Я купил плитку шоколада.","vi":"Tôi đã mua một thanh sô cô la.","fa":"من یک تخته شکلات خریدم."}]},{"word":"der Tagesablauf","en":"daily routine","ru":"распорядок дня","vi":"thói quen hàng ngày","fa":"روال روزانه","examples":[{"de":"Mein Tagesablauf beginnt um sechs Uhr.","en":"My daily routine starts at six o'clock.","ru":"Мой распорядок дня начинается в шесть часов.","vi":"Công việc hàng ngày của tôi bắt đầu lúc sáu giờ.","fa":"برنامه روزانه من از ساعت شش شروع می شود."},{"de":"Der Tagesablauf im Kindergarten ist gut organisiert.","en":"The daily routine in the kindergarten is well organized.","ru":"Распорядок дня в детском саду хорошо организован.","vi":"Thói quen hàng ngày ở trường mẫu giáo được tổ chức tốt.","fa":"برنامه روزانه در مهدکودک به خوبی سازماندهی شده است."}]},{"word":"das Tal","en":"valley","ru":"долина","vi":"thung lũng","fa":"دره","examples":[{"de":"Das Dorf liegt in einem schönen Tal.","en":"The village lies in a beautiful valley.","ru":"Деревня расположена в красивой долине.","vi":"Ngôi làng nằm trong một thung lũng xinh đẹp.","fa":"این روستا در دره ای زیبا واقع شده است."},{"de":"Wir wanderten durch das grüne Tal.","en":"We hiked through the green valley.","ru":"Мы шли пешком по зелёной долине.","vi":"Chúng tôi đi bộ qua thung lũng xanh.","fa":"از میان دره سرسبز پیاده روی کردیم."}]},{"word":"das Talent","en":"talent","ru":"талант","vi":"tài năng","fa":"استعداد","examples":[{"de":"Sie hat ein großes Talent für Musik.","en":"She has a great talent for music.","ru":"У неё большой талант к музыке.","vi":"Cô ấy có năng khiếu âm nhạc tuyệt vời.","fa":"او استعداد زیادی در موسیقی دارد."},{"de":"Er zeigt schon als Kind sein Talent.","en":"He already shows his talent as a child.","ru":"Он проявляет свой талант уже в детстве.","vi":"Anh ấy thể hiện tài năng của mình ngay cả khi còn nhỏ.","fa":"او حتی در کودکی استعداد خود را نشان می دهد."}]},{"word":"tanken","en":"to fill up (with fuel)","ru":"заправляться (топливом)","vi":"tiếp nhiên liệu","fa":"سوخت گیری","examples":[{"de":"Wir müssen noch tanken, bevor wir losfahren.","en":"We still need to fill up before we leave.","ru":"Нам нужно заправиться, прежде чем ехать.","vi":"Chúng tôi vẫn phải tiếp nhiên liệu trước khi khởi hành.","fa":"هنوز باید قبل از حرکت بنزین بزنیم."},{"de":"Er tankt sein Auto an der Tankstelle.","en":"He fills up his car at the gas station.","ru":"Он заправляет машину на заправке.","vi":"Anh ta đổ đầy xe ở trạm xăng.","fa":"ماشینش را در پمپ بنزین پر می کند."}]},{"word":"die Tante","en":"aunt","ru":"тётя","vi":"dì","fa":"عمه","examples":[{"de":"Meine Tante wohnt in Berlin.","en":"My aunt lives in Berlin.","ru":"Моя тётя живёт в Берлине.","vi":"Dì tôi sống ở Berlin.","fa":"عمه من در برلین زندگی می کند."},{"de":"Ich besuche meine Tante jedes Jahr.","en":"I visit my aunt every year.","ru":"Я навещаю свою тётю каждый год.","vi":"Tôi đến thăm dì của tôi hàng năm.","fa":"من هر سال به عمه ام سر می زنم."}]},{"word":"tanzen","en":"to dance","ru":"танцевать","vi":"khiêu vũ","fa":"رقصیدن","examples":[{"de":"Wir tanzen gern auf Partys.","en":"We like to dance at parties.","ru":"Мы любим танцевать на вечеринках.","vi":"Chúng tôi thích khiêu vũ ở các bữa tiệc.","fa":"ما رقصیدن در مهمانی ها را دوست داریم."},{"de":"Sie tanzt seit zehn Jahren Ballett.","en":"She has been dancing ballet for ten years.","ru":"Она танцует балет уже десять лет.","vi":"Cô ấy đã nhảy múa ba lê được mười năm.","fa":"او ده سال است که باله می رقصد."}]},{"word":"die Tasche","en":"bag","ru":"сумка","vi":"cái túi","fa":"کیف","examples":[{"de":"Ich habe meine Tasche im Bus vergessen.","en":"I forgot my bag on the bus.","ru":"Я забыл свою сумку в автобусе.","vi":"Tôi quên túi trên xe buýt.","fa":"کیفم را در اتوبوس فراموش کردم."},{"de":"In der Tasche sind meine Bücher.","en":"My books are in the bag.","ru":"В сумке лежат мои книги.","vi":"Sách của tôi ở trong túi.","fa":"کتاب های من در کیف است."}]},{"word":"das Taschengeld","en":"pocket money, allowance","ru":"карманные деньги","vi":"tiền tiêu vặt","fa":"پول جیبی","examples":[{"de":"Die Kinder bekommen jede Woche Taschengeld.","en":"The children get pocket money every week.","ru":"Дети получают карманные деньги каждую неделю.","vi":"Trẻ em được nhận tiền tiêu vặt hàng tuần.","fa":"بچه ها هر هفته پول تو جیبی می گیرند."},{"de":"Er spart sein Taschengeld für ein neues Fahrrad.","en":"He saves his pocket money for a new bike.","ru":"Он копит карманные деньги на новый велосипед.","vi":"Anh ấy tiết kiệm tiền tiêu vặt để mua một chiếc xe đạp mới.","fa":"او پول جیبی خود را برای یک دوچرخه جدید پس انداز می کند."}]},{"word":"das Taschentuch","en":"handkerchief, tissue","ru":"носовой платок, салфетка","vi":"chiếc khăn tay","fa":"دستمال","examples":[{"de":"Hast du ein Taschentuch für mich?","en":"Do you have a tissue for me?","ru":"У тебя есть для меня платок?","vi":"Bạn có khăn giấy cho tôi không?","fa":"دستمال کاغذی برای من داری؟"},{"de":"Sie putzt sich die Nase mit einem Taschentuch.","en":"She blows her nose with a tissue.","ru":"Она вытирает нос платком.","vi":"Cô ấy xì mũi bằng khăn giấy.","fa":"بینی اش را با دستمال باد می کند."}]},{"word":"die Tasse","en":"cup","ru":"чашка","vi":"cái cốc","fa":"فنجان","examples":[{"de":"Ich trinke eine Tasse Kaffee zum Frühstück.","en":"I drink a cup of coffee for breakfast.","ru":"Я пью чашку кофе на завтрак.","vi":"Tôi uống một tách cà phê cho bữa sáng.","fa":"برای صبحانه یک فنجان قهوه می نوشم."},{"de":"Kannst du mir eine Tasse Tee machen?","en":"Can you make me a cup of tea?","ru":"Можешь сделать мне чашку чая?","vi":"Bạn có thể pha cho tôi một tách trà được không?","fa":"میشه یه فنجان چای برام درست کنی؟"}]},{"word":"die Tastatur","en":"keyboard","ru":"клавиатура","vi":"bàn phím","fa":"صفحه کلید","examples":[{"de":"Meine Tastatur funktioniert nicht mehr richtig.","en":"My keyboard no longer works properly.","ru":"Моя клавиатура больше не работает как следует.","vi":"Bàn phím của tôi không còn hoạt động bình thường nữa.","fa":"صفحه کلید من دیگر درست کار نمی کند."},{"de":"Er tippt sehr schnell auf der Tastatur.","en":"He types very fast on the keyboard.","ru":"Он очень быстро печатает на клавиатуре.","vi":"Anh ấy gõ bàn phím rất nhanh.","fa":"او خیلی سریع روی صفحه کلید تایپ می کند."}]},{"word":"die Taste","en":"key, button","ru":"клавиша, кнопка","vi":"cái nút","fa":"دکمه","examples":[{"de":"Drück die grüne Taste, um anzurufen.","en":"Press the green button to call.","ru":"Нажми зелёную кнопку, чтобы позвонить.","vi":"Nhấn nút xanh để gọi.","fa":"برای تماس دکمه سبز رنگ را فشار دهید."},{"de":"Diese Taste auf der Tastatur ist kaputt.","en":"This key on the keyboard is broken.","ru":"Эта клавиша на клавиатуре сломана.","vi":"Phím này trên bàn phím bị hỏng.","fa":"این کلید روی کیبورد خراب است."}]},{"word":"die Tat","en":"act, deed","ru":"поступок, деяние","vi":"hành động","fa":"عمل","examples":[{"de":"Das war eine mutige Tat.","en":"That was a brave deed.","ru":"Это был смелый поступок.","vi":"Đó là một hành động dũng cảm.","fa":"این یک اقدام شجاعانه بود."},{"de":"Er wurde für seine gute Tat belohnt.","en":"He was rewarded for his good deed.","ru":"Его наградили за его добрый поступок.","vi":"Anh ấy đã được khen thưởng vì hành động tốt của mình.","fa":"او پاداش عمل نیکش را گرفت."}]},{"word":"die Tatsache","en":"fact","ru":"факт","vi":"sự thật","fa":"واقعیت","examples":[{"de":"Es ist eine Tatsache, dass die Erde rund ist.","en":"It is a fact that the Earth is round.","ru":"Это факт, что Земля круглая.","vi":"Sự thật là trái đất tròn.","fa":"این یک واقعیت است که زمین گرد است."},{"de":"Wir müssen die Tatsachen akzeptieren.","en":"We have to accept the facts.","ru":"Мы должны принять факты.","vi":"Chúng ta phải chấp nhận sự thật.","fa":"ما باید واقعیت ها را بپذیریم."}]},{"word":"taub","en":"deaf","ru":"глухой","vi":"điếc","fa":"ناشنوا","examples":[{"de":"Mein Großvater ist auf einem Ohr taub.","en":"My grandfather is deaf in one ear.","ru":"Мой дедушка глухой на одно ухо.","vi":"Ông tôi bị điếc một bên tai.","fa":"پدربزرگ من از یک گوش ناشنوا است."},{"de":"Sie ist von Geburt an taub.","en":"She has been deaf since birth.","ru":"Она глухая с рождения.","vi":"Cô bị điếc từ khi mới sinh ra.","fa":"او از بدو تولد ناشنوا بوده است."}]},{"word":"tauchen","en":"to dive","ru":"нырять","vi":"lặn","fa":"غواصی","examples":[{"de":"Die Kinder tauchen gern im See.","en":"The children like to dive in the lake.","ru":"Дети любят нырять в озере.","vi":"Trẻ em thích thú lặn xuống hồ.","fa":"بچه ها از غواصی در دریاچه لذت می برند."},{"de":"Er hat gelernt, mit Sauerstoffflasche zu tauchen.","en":"He learned to dive with an oxygen tank.","ru":"Он научился нырять с аквалангом.","vi":"Anh ấy đã học cách lặn bằng bình dưỡng khí.","fa":"او یاد گرفت که با مخزن اکسیژن شیرجه بزند."}]},{"word":"tauschen","en":"to exchange, to swap","ru":"обменивать(ся)","vi":"trao đổi","fa":"مبادله","examples":[{"de":"Wir haben unsere Plätze getauscht.","en":"We swapped our seats.","ru":"Мы поменялись местами.","vi":"Chúng tôi đổi chỗ cho nhau.","fa":"جای خود را عوض کردیم."},{"de":"Die Kinder tauschen ihre Sticker.","en":"The children are swapping their stickers.","ru":"Дети обмениваются наклейками.","vi":"Trẻ em trao đổi nhãn dán của mình.","fa":"بچه ها برچسب هایشان را عوض می کنند."}]},{"word":"die Technik","en":"technology; technique","ru":"техника; технология","vi":"công nghệ","fa":"تکنولوژی","examples":[{"de":"Die moderne Technik verändert unser Leben.","en":"Modern technology changes our lives.","ru":"Современная техника меняет нашу жизнь.","vi":"Công nghệ hiện đại đang thay đổi cuộc sống của chúng ta.","fa":"تکنولوژی مدرن زندگی ما را تغییر می دهد."},{"de":"Er hat eine gute Technik beim Schwimmen.","en":"He has a good technique in swimming.","ru":"У него хорошая техника плавания.","vi":"Anh ấy có kỹ thuật bơi tốt.","fa":"او تکنیک شنای خوبی دارد."}]},{"word":"der Tee","en":"tea","ru":"чай","vi":"trà","fa":"چای","examples":[{"de":"Ich trinke jeden Morgen eine Tasse Tee.","en":"I drink a cup of tea every morning.","ru":"Я пью чашку чая каждое утро.","vi":"Tôi uống một tách trà mỗi sáng.","fa":"من هر روز صبح یک فنجان چای می نوشم."},{"de":"Möchtest du grünen oder schwarzen Tee?","en":"Would you like green or black tea?","ru":"Хочешь зелёный или чёрный чай?","vi":"Bạn muốn trà xanh hay trà đen?","fa":"چای سبز میخوای یا سیاه؟"}]},{"word":"teilen","en":"to share, to divide","ru":"делить(ся)","vi":"chia sẻ","fa":"به اشتراک بگذارید","examples":[{"de":"Wir teilen uns die Kosten für das Geschenk.","en":"We split the cost of the gift.","ru":"Мы делим расходы на подарок.","vi":"Chúng tôi chia sẻ chi phí của món quà.","fa":"ما هزینه هدیه را تقسیم می کنیم."},{"de":"Sie teilt ihr Zimmer mit ihrer Schwester.","en":"She shares her room with her sister.","ru":"Она делит комнату со своей сестрой.","vi":"Cô ở chung phòng với chị gái.","fa":"او اتاقش را با خواهرش تقسیم می کند."}]},{"word":"die Teilnahme","en":"participation; attendance","ru":"участие","vi":"sự tham gia","fa":"مشارکت","examples":[{"de":"Die Teilnahme am Seminar ist kostenlos.","en":"Participation in the seminar is free.","ru":"Участие в семинаре бесплатное.","vi":"Việc tham gia hội thảo là miễn phí.","fa":"شرکت در سمینار رایگان است."},{"de":"Wir freuen uns über deine Teilnahme.","en":"We're glad you're taking part.","ru":"Мы рады твоему участию.","vi":"Chúng tôi mong chờ sự tham gia của bạn.","fa":"منتظر مشارکت شما هستیم"}]},{"word":"teilnehmen","en":"to take part, to participate","ru":"участвовать","vi":"tham gia","fa":"شرکت کنند","examples":[{"de":"Ich möchte an dem Kurs teilnehmen.","en":"I would like to take part in the course.","ru":"Я хотел бы принять участие в курсе.","vi":"Tôi muốn tham gia khóa học.","fa":"من دوست دارم در دوره شرکت کنم."},{"de":"Viele Schüler nehmen an dem Wettbewerb teil.","en":"Many students take part in the competition.","ru":"Многие ученики участвуют в конкурсе.","vi":"Nhiều sinh viên tham gia cuộc thi.","fa":"دانش آموزان زیادی در این مسابقه شرکت می کنند."}]},{"word":"die Teilnehmerin","en":"participant (female)","ru":"участница","vi":"người tham gia","fa":"شرکت کننده","examples":[{"de":"Jede Teilnehmerin bekommt eine Urkunde.","en":"Every participant gets a certificate.","ru":"Каждая участница получает сертификат.","vi":"Mỗi người tham gia đều nhận được một giấy chứng nhận.","fa":"هر شرکت کننده گواهینامه دریافت می کند."},{"de":"Die Teilnehmerin aus Spanien hat gewonnen.","en":"The participant from Spain won.","ru":"Участница из Испании победила.","vi":"Thí sinh đến từ Tây Ban Nha đã thắng.","fa":"شرکت کننده از اسپانیا برنده شد."}]},{"word":"telefonieren","en":"to make a phone call, to talk on the phone","ru":"разговаривать по телефону","vi":"gọi điện thoại","fa":"تماس تلفنی برقرار کن","examples":[{"de":"Ich telefoniere gerade mit meiner Mutter.","en":"I am on the phone with my mother right now.","ru":"Я сейчас разговариваю по телефону с мамой.","vi":"Hiện giờ tôi đang nói chuyện điện thoại với mẹ tôi.","fa":"من الان با مادرم تلفنی دارم."},{"de":"Er telefoniert jeden Abend mit seiner Freundin.","en":"He talks on the phone with his girlfriend every evening.","ru":"Он каждый вечер разговаривает по телефону со своей девушкой.","vi":"Anh ấy nói chuyện với bạn gái qua điện thoại mỗi tối.","fa":"او هر روز عصر با دوست دخترش تلفنی صحبت می کند."}]},{"word":"der Teller","en":"plate","ru":"тарелка","vi":"cái đĩa","fa":"بشقاب","examples":[{"de":"Stell die Teller bitte auf den Tisch.","en":"Please put the plates on the table.","ru":"Поставь, пожалуйста, тарелки на стол.","vi":"Vui lòng đặt những chiếc đĩa lên bàn.","fa":"لطفا بشقاب ها را روی میز بگذارید."},{"de":"Mein Teller ist schon leer.","en":"My plate is already empty.","ru":"Моя тарелка уже пуста.","vi":"Đĩa của tôi đã trống rồi.","fa":"بشقاب من در حال حاضر خالی است."}]},{"word":"die Temperatur","en":"temperature","ru":"температура","vi":"nhiệt độ","fa":"دما","examples":[{"de":"Die Temperatur steigt heute auf 30 Grad.","en":"The temperature rises to 30 degrees today.","ru":"Сегодня температура поднимется до 30 градусов.","vi":"Nhiệt độ hôm nay sẽ tăng lên 30 độ.","fa":"دمای هوا امروز به 30 درجه می رسد."},{"de":"Der Arzt misst die Temperatur des Patienten.","en":"The doctor measures the patient's temperature.","ru":"Врач измеряет температуру пациента.","vi":"Bác sĩ đo nhiệt độ cho bệnh nhân.","fa":"پزشک دمای بدن بیمار را اندازه گیری می کند."}]},{"word":"das Tempo","en":"speed, pace","ru":"темп, скорость","vi":"tốc độ","fa":"سرعت","examples":[{"de":"Bitte reduzieren Sie das Tempo in der Stadt.","en":"Please reduce your speed in the city.","ru":"Пожалуйста, снизьте скорость в городе.","vi":"Hãy giảm tốc độ trong thành phố.","fa":"لطفا سرعت خود را در شهر کم کنید."},{"de":"Das Tempo des Films war zu langsam.","en":"The pace of the movie was too slow.","ru":"Темп фильма был слишком медленным.","vi":"Nhịp phim quá chậm.","fa":"سرعت فیلم خیلی کند بود."}]},{"word":"das Tennis","en":"tennis","ru":"теннис","vi":"quần vợt","fa":"تنیس","examples":[{"de":"Am Wochenende spielen wir Tennis.","en":"On the weekend we play tennis.","ru":"На выходных мы играем в теннис.","vi":"Vào cuối tuần chúng tôi chơi quần vợt.","fa":"آخر هفته تنیس بازی می کنیم."},{"de":"Sie trainiert dreimal pro Woche Tennis.","en":"She trains tennis three times a week.","ru":"Она тренируется по теннису три раза в неделю.","vi":"Cô ấy tập tennis ba lần một tuần.","fa":"او هفته ای سه بار تنیس تمرین می کند."}]},{"word":"der Teppich","en":"carpet, rug","ru":"ковёр","vi":"tấm thảm","fa":"فرش","examples":[{"de":"Der Teppich im Wohnzimmer ist sehr weich.","en":"The carpet in the living room is very soft.","ru":"Ковёр в гостиной очень мягкий.","vi":"Thảm trong phòng khách rất mềm.","fa":"فرش اتاق نشیمن بسیار نرم است."},{"de":"Wir haben einen neuen Teppich gekauft.","en":"We bought a new carpet.","ru":"Мы купили новый ковёр.","vi":"Chúng tôi đã mua một tấm thảm mới.","fa":"فرش نو خریدیم."}]},{"word":"der Termin","en":"appointment","ru":"назначенная встреча, приём","vi":"cuộc hẹn","fa":"قرار ملاقات","examples":[{"de":"Ich habe morgen einen Termin beim Zahnarzt.","en":"I have an appointment at the dentist's tomorrow.","ru":"У меня завтра приём у стоматолога.","vi":"Tôi có cuộc hẹn với nha sĩ vào ngày mai.","fa":"فردا وقت دندانپزشکی دارم."},{"de":"Können wir einen anderen Termin vereinbaren?","en":"Can we arrange another appointment?","ru":"Можем ли мы назначить другую встречу?","vi":"Chúng ta có thể sắp xếp một cuộc hẹn khác được không?","fa":"آیا می توانیم تاریخ دیگری را ترتیب دهیم؟"}]},{"word":"die Terrasse","en":"terrace, patio","ru":"терраса","vi":"sân thượng","fa":"تراس","examples":[{"de":"Im Sommer essen wir oft auf der Terrasse.","en":"In summer we often eat on the terrace.","ru":"Летом мы часто едим на террасе.","vi":"Vào mùa hè chúng tôi thường ăn trên sân thượng.","fa":"در تابستان اغلب در تراس غذا می خوریم."},{"de":"Die Wohnung hat eine große Terrasse.","en":"The apartment has a large terrace.","ru":"В квартире большая терраса.","vi":"Căn hộ có sân hiên rộng.","fa":"آپارتمان دارای تراس بزرگ است."}]},{"word":"testen","en":"to test","ru":"тестировать, испытывать","vi":"kiểm tra","fa":"تست کنید","examples":[{"de":"Der Techniker testet das neue Gerät.","en":"The technician tests the new device.","ru":"Техник тестирует новое устройство.","vi":"Kỹ thuật viên kiểm tra thiết bị mới.","fa":"تکنسین دستگاه جدید را آزمایش می کند."},{"de":"Wir haben das Auto vor dem Kauf getestet.","en":"We tested the car before buying it.","ru":"Мы протестировали машину перед покупкой.","vi":"Chúng tôi đã kiểm tra chiếc xe trước khi mua nó.","fa":"ما قبل از خرید ماشین را تست کردیم."}]},{"word":"teuer","en":"expensive","ru":"дорогой","vi":"đắt tiền","fa":"گران قیمت","examples":[{"de":"Dieses Restaurant ist mir zu teuer.","en":"This restaurant is too expensive for me.","ru":"Этот ресторан для меня слишком дорогой.","vi":"Nhà hàng này quá đắt đối với tôi.","fa":"این رستوران برای من خیلی گران است."},{"de":"Die Mieten in der Stadt sind sehr teuer geworden.","en":"Rents in the city have become very expensive.","ru":"Аренда в городе стала очень дорогой.","vi":"Giá thuê nhà trong thành phố đã trở nên rất đắt đỏ.","fa":"اجاره در شهر بسیار گران شده است."}]},{"word":"der Text","en":"text","ru":"текст","vi":"văn bản","fa":"متن","examples":[{"de":"Bitte lesen Sie den Text genau durch.","en":"Please read the text carefully.","ru":"Пожалуйста, внимательно прочитайте текст.","vi":"Xin vui lòng đọc văn bản một cách cẩn thận.","fa":"لطفا متن را با دقت بخوانید."},{"de":"Der Text ist sehr lang.","en":"The text is very long.","ru":"Текст очень длинный.","vi":"Văn bản rất dài.","fa":"متن بسیار طولانی است."}]},{"word":"das Theater","en":"theater","ru":"театр","vi":"nhà hát","fa":"تئاتر","examples":[{"de":"Wir gehen heute Abend ins Theater.","en":"We are going to the theater tonight.","ru":"Мы идём сегодня вечером в театр.","vi":"Tối nay chúng ta sẽ đến rạp hát.","fa":"امشب میریم تئاتر"},{"de":"Das Stück im Theater war sehr spannend.","en":"The play at the theater was very exciting.","ru":"Спектакль в театре был очень захватывающим.","vi":"Vở kịch trong rạp rất thú vị.","fa":"بازی در تئاتر بسیار هیجان انگیز بود."}]},{"word":"das Thema","en":"topic, theme","ru":"тема","vi":"chủ đề","fa":"موضوع","examples":[{"de":"Das Thema der Diskussion ist Klimaschutz.","en":"The topic of the discussion is climate protection.","ru":"Тема дискуссии — защита климата.","vi":"Chủ đề của cuộc thảo luận là bảo vệ khí hậu.","fa":"موضوع بحث حفاظت از اقلیم است."},{"de":"Wir haben in der Schule über ein interessantes Thema gesprochen.","en":"We talked about an interesting topic at school.","ru":"Мы говорили об интересной теме в школе.","vi":"Chúng tôi đã nói về một chủ đề thú vị ở trường.","fa":"در مدرسه درباره موضوع جالبی صحبت کردیم."}]},{"word":"theoretisch","en":"theoretical","ru":"теоретический","vi":"về mặt lý thuyết","fa":"به صورت تئوری","examples":[{"de":"Theoretisch könnte das funktionieren.","en":"Theoretically, that could work.","ru":"Теоретически это могло бы сработать.","vi":"Về lý thuyết điều này có thể hoạt động.","fa":"در تئوری این می تواند کار کند."},{"de":"Wir haben viel theoretisches Wissen, aber wenig Praxis.","en":"We have a lot of theoretical knowledge but little practice.","ru":"У нас много теоретических знаний, но мало практики.","vi":"Chúng ta có rất nhiều kiến ​​thức lý thuyết nhưng lại có rất ít thực hành.","fa":"ما دانش نظری زیادی داریم، اما عمل کمی داریم."}]},{"word":"die Therapie","en":"therapy","ru":"терапия","vi":"liệu pháp","fa":"درمان","examples":[{"de":"Nach dem Unfall begann seine Therapie.","en":"His therapy began after the accident.","ru":"После аварии началась его терапия.","vi":"Sau vụ tai nạn, quá trình trị liệu của anh bắt đầu.","fa":"پس از تصادف، درمان او شروع شد."},{"de":"Sie macht eine Therapie gegen ihre Angst.","en":"She is undergoing therapy for her anxiety.","ru":"Она проходит терапию от своего страха.","vi":"Cô ấy đang được điều trị chứng lo âu của mình.","fa":"او تحت درمان برای اضطراب خود است."}]},{"word":"das Ticket","en":"ticket","ru":"билет","vi":"vé","fa":"بلیط","examples":[{"de":"Ich habe ein Ticket für den Zug gekauft.","en":"I bought a ticket for the train.","ru":"Я купил билет на поезд.","vi":"Tôi đã mua vé tàu.","fa":"بلیت قطار خریدم."},{"de":"Die Tickets für das Konzert sind schon ausverkauft.","en":"The tickets for the concert are already sold out.","ru":"Билеты на концерт уже распроданы.","vi":"Vé cho buổi hòa nhạc đã được bán hết.","fa":"بلیت های کنسرت از قبل فروخته شده است."}]},{"word":"tief","en":"deep","ru":"глубокий","vi":"sâu","fa":"عمیق","examples":[{"de":"Der See ist an dieser Stelle sehr tief.","en":"The lake is very deep at this spot.","ru":"Озеро в этом месте очень глубокое.","vi":"Hồ lúc này rất sâu.","fa":"دریاچه در این نقطه بسیار عمیق است."},{"de":"Er atmete tief durch.","en":"He took a deep breath.","ru":"Он глубоко вдохнул.","vi":"Anh hít một hơi thật sâu.","fa":"نفس عمیقی کشید."}]},{"word":"das Tier","en":"animal","ru":"животное","vi":"con vật","fa":"حیوان","examples":[{"de":"Der Hund ist mein Lieblingstier.","en":"The dog is my favorite animal.","ru":"Собака — моё любимое животное.","vi":"Con chó là động vật yêu thích của tôi.","fa":"سگ حیوان مورد علاقه من است."},{"de":"Im Zoo kann man viele Tiere sehen.","en":"You can see many animals in the zoo.","ru":"В зоопарке можно увидеть много животных.","vi":"Bạn có thể nhìn thấy nhiều loài động vật trong sở thú.","fa":"شما می توانید حیوانات زیادی را در باغ وحش ببینید."}]},{"word":"der Tipp","en":"tip, hint","ru":"совет, подсказка","vi":"tiền boa","fa":"نوک","examples":[{"de":"Kannst du mir einen Tipp geben?","en":"Can you give me a tip?","ru":"Можешь дать мне совет?","vi":"Bạn có thể cho tôi một lời khuyên?","fa":"میشه راهنماییم کنید"},{"de":"Danke für den guten Tipp.","en":"Thanks for the good tip.","ru":"Спасибо за хороший совет.","vi":"Cảm ơn vì lời khuyên tốt.","fa":"ممنون از راهنمایی خوب"}]},{"word":"tippen","en":"to type","ru":"печатать (на клавиатуре)","vi":"gõ nhẹ","fa":"ضربه بزنید","examples":[{"de":"Sie tippt sehr schnell auf dem Computer.","en":"She types very fast on the computer.","ru":"Она очень быстро печатает на компьютере.","vi":"Cô ấy gõ rất nhanh trên máy tính.","fa":"او خیلی سریع روی کامپیوتر تایپ می کند."},{"de":"Ich muss noch eine E-Mail tippen.","en":"I still need to type an email.","ru":"Мне ещё нужно напечатать письмо.","vi":"Tôi vẫn phải gõ email.","fa":"من هنوز باید یک ایمیل تایپ کنم."}]},{"word":"der Tisch","en":"table","ru":"стол","vi":"cái bàn","fa":"جدول","examples":[{"de":"Das Essen steht auf dem Tisch.","en":"The food is on the table.","ru":"Еда стоит на столе.","vi":"Thức ăn ở trên bàn.","fa":"غذا روی میز است."},{"de":"Wir haben einen neuen Tisch für die Küche gekauft.","en":"We bought a new table for the kitchen.","ru":"Мы купили новый стол для кухни.","vi":"Chúng tôi đã mua một chiếc bàn mới cho nhà bếp.","fa":"یک میز جدید برای آشپزخانه خریدیم."}]},{"word":"der Titel","en":"title","ru":"название, заголовок","vi":"tiêu đề","fa":"عنوان","examples":[{"de":"Wie lautet der Titel des Buches?","en":"What is the title of the book?","ru":"Как называется книга?","vi":"Tiêu đề của cuốn sách là gì?","fa":"عنوان کتاب چیست؟"},{"de":"Der Film hat einen interessanten Titel.","en":"The movie has an interesting title.","ru":"У фильма интересное название.","vi":"Phim có tựa đề khá thú vị.","fa":"این فیلم عنوان جالبی دارد."}]},{"word":"die Tochter","en":"daughter","ru":"дочь","vi":"con gái","fa":"دختر","examples":[{"de":"Meine Tochter geht in die dritte Klasse.","en":"My daughter is in third grade.","ru":"Моя дочь учится в третьем классе.","vi":"Con gái tôi đang học lớp ba.","fa":"دختر من کلاس سوم است."},{"de":"Sie hat zwei Töchter und einen Sohn.","en":"She has two daughters and a son.","ru":"У неё две дочери и один сын.","vi":"Cô có hai con gái và một con trai.","fa":"او دو دختر و یک پسر دارد."}]},{"word":"der Tod","en":"death","ru":"смерть","vi":"cái chết","fa":"مرگ","examples":[{"de":"Der Tod ihres Vaters war ein großer Schock.","en":"Her father's death was a big shock.","ru":"Смерть её отца стала большим шоком.","vi":"Cái chết của cha cô là một cú sốc lớn.","fa":"مرگ پدرش شوک بزرگی بود."},{"de":"Nach seinem Tod übernahm sein Sohn die Firma.","en":"After his death, his son took over the company.","ru":"После его смерти сын принял на себя управление фирмой.","vi":"Sau khi ông qua đời, con trai ông tiếp quản công ty.","fa":"پس از مرگ او، پسرش مسئولیت شرکت را بر عهده گرفت."}]},{"word":"die Toilette","en":"toilet, restroom","ru":"туалет","vi":"nhà vệ sinh","fa":"توالت","examples":[{"de":"Wo ist hier bitte die Toilette?","en":"Where is the restroom here, please?","ru":"Где здесь туалет, пожалуйста?","vi":"Xin hỏi nhà vệ sinh ở đây ở đâu?","fa":"توالت اینجا کجاست لطفا؟"},{"de":"Die Toilette im Zug war sauber.","en":"The toilet on the train was clean.","ru":"Туалет в поезде был чистым.","vi":"Nhà vệ sinh trên tàu sạch sẽ.","fa":"توالت داخل قطار تمیز بود."}]},{"word":"tolerant","en":"tolerant","ru":"терпимый, толерантный","vi":"khoan dung","fa":"متحمل","examples":[{"de":"Meine Eltern sind sehr tolerant gegenüber anderen Meinungen.","en":"My parents are very tolerant of other opinions.","ru":"Мои родители очень терпимы к другим мнениям.","vi":"Cha mẹ tôi rất khoan dung với những ý kiến khác.","fa":"پدر و مادرم نسبت به نظرات دیگر بسیار تحمل می کنند."},{"de":"Man sollte gegenüber fremden Kulturen tolerant sein.","en":"One should be tolerant towards foreign cultures.","ru":"Нужно быть терпимым к чужим культурам.","vi":"Người ta phải khoan dung với các nền văn hóa nước ngoài.","fa":"باید با فرهنگ های بیگانه مدارا کرد."}]},{"word":"toll","en":"great, awesome","ru":"классный, потрясающий","vi":"tuyệt vời","fa":"عالی","examples":[{"de":"Das Konzert war wirklich toll!","en":"The concert was really great!","ru":"Концерт был действительно классным!","vi":"Buổi hòa nhạc thực sự tuyệt vời!","fa":"کنسرت واقعا عالی بود!"},{"de":"Wir hatten einen tollen Urlaub.","en":"We had a great vacation.","ru":"У нас был потрясающий отпуск.","vi":"Chúng tôi đã có một kỳ nghỉ tuyệt vời.","fa":"تعطیلات عالی داشتیم"}]},{"word":"die Tomate","en":"tomato","ru":"помидор","vi":"cà chua","fa":"گوجه فرنگی","examples":[{"de":"Ich schneide die Tomaten für den Salat.","en":"I am cutting the tomatoes for the salad.","ru":"Я нарезаю помидоры для салата.","vi":"Tôi cắt cà chua cho món salad.","fa":"برای سالاد گوجه فرنگی را برش دادم."},{"de":"Die Tomaten aus dem Garten schmecken besonders gut.","en":"The tomatoes from the garden taste especially good.","ru":"Помидоры из огорода особенно вкусные.","vi":"Cà chua từ vườn có hương vị đặc biệt ngon.","fa":"گوجه‌فرنگی‌های باغ به‌ویژه طعم خوبی دارند."}]},{"word":"der Topf","en":"pot","ru":"кастрюля","vi":"cái nồi","fa":"گلدان","examples":[{"de":"Der Topf mit der Suppe steht auf dem Herd.","en":"The pot with the soup is on the stove.","ru":"Кастрюля с супом стоит на плите.","vi":"Nồi súp đang ở trên bếp.","fa":"قابلمه سوپ روی اجاق است."},{"de":"Sie kocht die Kartoffeln in einem großen Topf.","en":"She cooks the potatoes in a large pot.","ru":"Она варит картошку в большой кастрюле.","vi":"Cô ấy nấu khoai tây trong một cái nồi lớn.","fa":"او سیب زمینی ها را در یک قابلمه بزرگ می پزد."}]},{"word":"das Tor","en":"gate; goal (sports)","ru":"ворота","vi":"cánh cổng","fa":"دروازه","examples":[{"de":"Das Tor zum Garten war offen.","en":"The gate to the garden was open.","ru":"Ворота в сад были открыты.","vi":"Cánh cổng vào vườn đã mở.","fa":"دروازه باغ باز بود."},{"de":"Er hat in der letzten Minute das entscheidende Tor geschossen.","en":"He scored the decisive goal in the last minute.","ru":"Он забил решающий гол в последнюю минуту.","vi":"Anh ghi bàn thắng quyết định ở phút cuối cùng.","fa":"او در آخرین دقیقه گل تعیین کننده را به ثمر رساند."}]},{"word":"die Torte","en":"cake, gateau","ru":"торт","vi":"cái bánh","fa":"کیک","examples":[{"de":"Zum Geburtstag hat sie eine Torte gebacken.","en":"She baked a cake for the birthday.","ru":"На день рождения она испекла торт.","vi":"Cô ấy đã nướng một chiếc bánh cho ngày sinh nhật của mình.","fa":"برای تولدش کیک پخت."},{"de":"Die Torte mit Schokolade war köstlich.","en":"The chocolate cake was delicious.","ru":"Шоколадный торт был восхитительным.","vi":"Bánh sô cô la rất ngon.","fa":"کیک شکلاتی خوشمزه بود."}]},{"word":"tot","en":"dead","ru":"мёртвый","vi":"đã chết","fa":"مرده","examples":[{"de":"Die Pflanze ist leider tot.","en":"The plant is unfortunately dead.","ru":"К сожалению, растение погибло.","vi":"Thật không may là cây đã chết.","fa":"متأسفانه گیاه مرده است."},{"de":"Der Vogel lag tot auf der Straße.","en":"The bird lay dead on the street.","ru":"Птица лежала мёртвой на дороге.","vi":"Con chim nằm chết trên đường phố.","fa":"پرنده مرده در خیابان افتاده بود."}]},{"word":"total","en":"totally, completely","ru":"совершенно, полностью","vi":"hoàn toàn","fa":"کاملا","examples":[{"de":"Ich bin total müde.","en":"I am totally tired.","ru":"Я совершенно устал.","vi":"Tôi hoàn toàn mệt mỏi.","fa":"من کلا خسته ام"},{"de":"Das Konzert war total überfüllt.","en":"The concert was totally crowded.","ru":"Концерт был совершенно переполнен.","vi":"Buổi hòa nhạc hoàn toàn đông đúc.","fa":"کنسرت کاملا شلوغ بود."}]},{"word":"der Tourismus","en":"tourism","ru":"туризм","vi":"du lịch","fa":"گردشگری","examples":[{"de":"Der Tourismus ist wichtig für die Wirtschaft der Stadt.","en":"Tourism is important for the city's economy.","ru":"Туризм важен для экономики города.","vi":"Du lịch rất quan trọng đối với nền kinh tế của thành phố.","fa":"گردشگری برای اقتصاد شهر مهم است."},{"de":"Der Tourismus hat in den letzten Jahren stark zugenommen.","en":"Tourism has increased sharply in recent years.","ru":"Туризм значительно вырос за последние годы.","vi":"Du lịch đã tăng lên đáng kể trong những năm gần đây.","fa":"گردشگری در سال های اخیر افزایش چشمگیری داشته است."}]},{"word":"die Tradition","en":"tradition","ru":"традиция","vi":"truyền thống","fa":"سنت","examples":[{"de":"Diese Tradition wird seit Generationen gepflegt.","en":"This tradition has been kept for generations.","ru":"Эта традиция поддерживается на протяжении поколений.","vi":"Truyền thống này đã được duy trì qua nhiều thế hệ.","fa":"این سنت برای نسل ها حفظ شده است."},{"de":"Es ist eine alte Tradition, zu Weihnachten einen Baum aufzustellen.","en":"It is an old tradition to put up a tree at Christmas.","ru":"Ставить ёлку на Рождество — старая традиция.","vi":"Việc dựng cây thông vào dịp Giáng sinh là một truyền thống lâu đời.","fa":"کاشتن درخت در کریسمس یک سنت قدیمی است."}]},{"word":"tragen","en":"to carry; to wear","ru":"нести; носить","vi":"mặc","fa":"پوشیدن","examples":[{"de":"Er trägt die schweren Taschen in die Wohnung.","en":"He carries the heavy bags into the apartment.","ru":"Он несёт тяжёлые сумки в квартиру.","vi":"Anh xách những chiếc túi nặng nề vào căn hộ.","fa":"او کیسه های سنگین را به داخل آپارتمان می برد."},{"de":"Sie trägt heute ein rotes Kleid.","en":"She is wearing a red dress today.","ru":"Сегодня она носит красное платье.","vi":"Hôm nay cô ấy mặc một chiếc váy màu đỏ.","fa":"او امروز یک لباس قرمز پوشیده است."}]},{"word":"trainieren","en":"to train, to practice","ru":"тренироваться","vi":"xe lửa","fa":"قطار","examples":[{"de":"Er trainiert jeden Tag im Fitnessstudio.","en":"He trains every day at the gym.","ru":"Он тренируется каждый день в спортзале.","vi":"Anh ấy tập luyện ở phòng gym mỗi ngày.","fa":"او هر روز در باشگاه تمرین می کند."},{"de":"Die Mannschaft trainiert für das nächste Spiel.","en":"The team is training for the next game.","ru":"Команда тренируется к следующей игре.","vi":"Toàn đội đang tập luyện cho trận đấu tiếp theo.","fa":"این تیم برای بازی بعدی تمرین می کند."}]},{"word":"die Träne","en":"tear","ru":"слеза","vi":"nước mắt","fa":"اشک","examples":[{"de":"Ihr liefen die Tränen über das Gesicht.","en":"Tears ran down her face.","ru":"Слёзы текли по её лицу.","vi":"Nước mắt chảy dài trên khuôn mặt cô.","fa":"اشک روی صورتش جاری بود."},{"de":"Er konnte seine Tränen nicht zurückhalten.","en":"He couldn't hold back his tears.","ru":"Он не мог сдержать слёзы.","vi":"Anh không thể cầm được nước mắt.","fa":"نتوانست جلوی اشک هایش را بگیرد."}]},{"word":"transportieren","en":"to transport","ru":"перевозить, транспортировать","vi":"vận chuyển","fa":"حمل و نقل","examples":[{"de":"Der Lkw transportiert Möbel in die neue Stadt.","en":"The truck transports furniture to the new city.","ru":"Грузовик перевозит мебель в новый город.","vi":"Xe tải chở đồ đạc vào thành phố mới.","fa":"کامیون اثاثیه را به شهر جدید حمل می کند."},{"de":"Die Waren werden per Schiff transportiert.","en":"The goods are transported by ship.","ru":"Товары перевозятся на корабле.","vi":"Hàng hóa được vận chuyển bằng tàu.","fa":"حمل و نقل کالا با کشتی انجام می شود."}]},{"word":"die Trauer","en":"grief; mourning","ru":"скорбь; печаль","vi":"nỗi buồn","fa":"غم و اندوه","examples":[{"de":"Nach dem Verlust brauchte sie Zeit für ihre Trauer.","en":"After the loss she needed time for her grief.","ru":"После утраты ей было нужно время для скорби.","vi":"Sau mất mát, cô cần thời gian để đau buồn.","fa":"پس از فقدان، او به زمان نیاز داشت تا غصه بخورد."},{"de":"Die ganze Stadt war in Trauer.","en":"The whole town was in mourning.","ru":"Весь город был в трауре.","vi":"Cả thành phố chìm trong tang thương.","fa":"تمام شهر در ماتم بود."}]},{"word":"träumen","en":"to dream","ru":"мечтать, видеть сны","vi":"giấc mơ","fa":"رویا","examples":[{"de":"Letzte Nacht habe ich von meiner Kindheit geträumt.","en":"Last night I dreamed about my childhood.","ru":"Прошлой ночью мне снилось моё детство.","vi":"Đêm qua tôi mơ về tuổi thơ của mình.","fa":"دیشب خواب کودکی ام را دیدم."},{"de":"Sie träumt davon, einmal die Welt zu bereisen.","en":"She dreams of traveling the world someday.","ru":"Она мечтает когда-нибудь путешествовать по миру.","vi":"Cô mơ ước một ngày được đi du lịch khắp thế giới.","fa":"او آرزو دارد روزی به دور دنیا سفر کند."}]},{"word":"traurig","en":"sad","ru":"грустный","vi":"buồn","fa":"غمگین","examples":[{"de":"Nach dem Abschied war sie sehr traurig.","en":"After the farewell she was very sad.","ru":"После прощания она была очень грустной.","vi":"Sau khi chia tay, cô ấy rất buồn.","fa":"بعد از خداحافظی خیلی ناراحت شد."},{"de":"Der traurige Film hat mich zum Weinen gebracht.","en":"The sad movie made me cry.","ru":"Грустный фильм заставил меня плакать.","vi":"Bộ phim buồn đã làm tôi khóc.","fa":"فیلم غمگین مرا به گریه انداخت."}]},{"word":"treffen","en":"to meet","ru":"встречать(ся)","vi":"gặp gỡ","fa":"ملاقات کنید","examples":[{"de":"Ich treffe meine Freunde heute Abend.","en":"I am meeting my friends tonight.","ru":"Я встречаюсь с друзьями сегодня вечером.","vi":"Tôi sẽ gặp bạn bè của tôi tối nay.","fa":"من امروز عصر با دوستانم ملاقات می کنم."},{"de":"Wir haben uns zufällig in der Stadt getroffen.","en":"We met by chance in the city.","ru":"Мы случайно встретились в городе.","vi":"Chúng tôi tình cờ gặp nhau ở thành phố.","fa":"به طور اتفاقی در شهر با هم آشنا شدیم."}]},{"word":"treiben","en":"to do (sports); to drive, to push","ru":"заниматься (спортом); гнать","vi":"lái xe","fa":"رانندگی کنید","examples":[{"de":"Er treibt regelmäßig Sport.","en":"He does sports regularly.","ru":"Он регулярно занимается спортом.","vi":"Anh ấy tập thể dục thường xuyên.","fa":"او به طور منظم ورزش می کند."},{"de":"Der Wind trieb die Wolken über den Himmel.","en":"The wind drove the clouds across the sky.","ru":"Ветер гнал облака по небу.","vi":"Gió đưa mây bay khắp trời.","fa":"باد ابرها را در آسمان می راند."}]},{"word":"die Trennung","en":"separation; break-up","ru":"разлука; расставание","vi":"sự chia ly","fa":"جدایی","examples":[{"de":"Nach der Trennung zog er in eine andere Stadt.","en":"After the break-up he moved to another city.","ru":"После расставания он переехал в другой город.","vi":"Sau khi chia tay, anh chuyển đến thành phố khác.","fa":"پس از جدایی به شهر دیگری نقل مکان کرد."},{"de":"Die Trennung von den Kindern fiel ihr sehr schwer.","en":"The separation from the children was very hard for her.","ru":"Разлука с детьми далась ей очень тяжело.","vi":"Việc cô phải xa các con là điều vô cùng khó khăn.","fa":"جدا شدن از فرزندانش برایش خیلی سخت بود."}]},{"word":"die Treppe","en":"stairs, staircase","ru":"лестница","vi":"cầu thang","fa":"پله ها","examples":[{"de":"Die Treppe führt in den zweiten Stock.","en":"The stairs lead to the second floor.","ru":"Лестница ведёт на третий этаж.","vi":"Cầu thang dẫn lên tầng hai.","fa":"پله ها به طبقه دوم منتهی می شوند."},{"de":"Sei vorsichtig auf der Treppe, sie ist rutschig.","en":"Be careful on the stairs, they are slippery.","ru":"Будь осторожен на лестнице, она скользкая.","vi":"Hãy cẩn thận trên cầu thang, chúng trơn trượt.","fa":"مراقب پله ها باشید، آنها لیز هستند."}]},{"word":"das Treppenhaus","en":"stairwell","ru":"лестничная клетка","vi":"cầu thang","fa":"راه پله","examples":[{"de":"Das Treppenhaus ist alt, aber gut beleuchtet.","en":"The stairwell is old but well lit.","ru":"Лестничная клетка старая, но хорошо освещена.","vi":"Cầu thang đã cũ nhưng đủ ánh sáng.","fa":"راه پله قدیمی است اما نور خوبی دارد."},{"de":"Im Treppenhaus riecht es nach frischer Farbe.","en":"The stairwell smells of fresh paint.","ru":"В подъезде пахнет свежей краской.","vi":"Cầu thang thơm mùi sơn mới.","fa":"راه پله بوی رنگ تازه می دهد."}]},{"word":"treten","en":"to step; to kick","ru":"наступать; пинать","vi":"cú đá","fa":"لگد زدن","examples":[{"de":"Pass auf, dass du nicht in die Pfütze trittst.","en":"Be careful not to step in the puddle.","ru":"Осторожно, не наступи в лужу.","vi":"Hãy cẩn thận đừng bước vào vũng nước.","fa":"مراقب باشید وارد گودال نشوید."},{"de":"Der Spieler hat den Ball ins Tor getreten.","en":"The player kicked the ball into the goal.","ru":"Игрок ударом отправил мяч в ворота.","vi":"Cầu thủ này đã sút bóng vào khung thành.","fa":"بازیکن توپ را وارد دروازه کرد."}]},{"word":"treu","en":"faithful, loyal","ru":"верный","vi":"trung thành","fa":"وفادار","examples":[{"de":"Ein Hund ist ein treuer Freund.","en":"A dog is a loyal friend.","ru":"Собака — верный друг.","vi":"Một con chó là một người bạn trung thành.","fa":"سگ یک دوست وفادار است."},{"de":"Sie war ihrem Mann immer treu.","en":"She was always faithful to her husband.","ru":"Она всегда была верна своему мужу.","vi":"Cô luôn chung thủy với chồng.","fa":"او همیشه به شوهرش وفادار بود."}]},{"word":"trinken","en":"to drink","ru":"пить","vi":"uống","fa":"نوشیدنی","examples":[{"de":"Ich trinke jeden Tag viel Wasser.","en":"I drink a lot of water every day.","ru":"Я пью много воды каждый день.","vi":"Tôi uống rất nhiều nước mỗi ngày.","fa":"من هر روز مقدار زیادی آب می نوشم."},{"de":"Möchtest du etwas trinken?","en":"Would you like something to drink?","ru":"Хочешь что-нибудь выпить?","vi":"Bạn có muốn uống gì không?","fa":"آیا می خواهید چیزی بنوشید؟"}]},{"word":"trocken","en":"dry","ru":"сухой","vi":"khô","fa":"خشک","examples":[{"de":"Im Sommer ist das Wetter hier sehr trocken.","en":"In summer the weather here is very dry.","ru":"Летом погода здесь очень сухая.","vi":"Vào mùa hè thời tiết ở đây rất khô.","fa":"در تابستان هوای اینجا بسیار خشک است."},{"de":"Die Wäsche ist schon trocken.","en":"The laundry is already dry.","ru":"Бельё уже высохло.","vi":"Đồ giặt đã khô rồi.","fa":"لباسشویی در حال حاضر خشک شده است."}]},{"word":"trocknen","en":"to dry","ru":"сушить, сохнуть","vi":"khô","fa":"خشک","examples":[{"de":"Ich hänge die Wäsche zum Trocknen auf.","en":"I hang the laundry up to dry.","ru":"Я вешаю бельё сушиться.","vi":"Tôi treo đồ giặt lên cho khô.","fa":"لباس‌ها را آویزان می‌کنم تا خشک شوند."},{"de":"Die Haare trocknen schnell in der Sonne.","en":"Hair dries quickly in the sun.","ru":"Волосы быстро сохнут на солнце.","vi":"Tóc khô nhanh dưới ánh nắng mặt trời.","fa":"موها در آفتاب به سرعت خشک می شوند."}]},{"word":"die Tropfen","en":"drops (medicine)","ru":"капли (лекарство)","vi":"những giọt","fa":"قطره ها","examples":[{"de":"Nimm dreimal täglich zehn Tropfen von dieser Medizin.","en":"Take ten drops of this medicine three times a day.","ru":"Принимай по десять капель этого лекарства три раза в день.","vi":"Uống mười giọt thuốc này ba lần một ngày.","fa":"ده قطره از این دارو را سه بار در روز میل کنید."},{"de":"Der Arzt hat mir Tropfen gegen den Husten verschrieben.","en":"The doctor prescribed me drops for the cough.","ru":"Врач прописал мне капли от кашля.","vi":"Bác sĩ kê cho tôi thuốc nhỏ trị ho.","fa":"دکتر برای من قطره برای سرفه تجویز کرد."}]},{"word":"das Trottoir","en":"sidewalk, pavement","ru":"тротуар","vi":"vỉa hè","fa":"پیاده رو","examples":[{"de":"Die Kinder fahren mit dem Fahrrad auf dem Trottoir.","en":"The children ride their bikes on the sidewalk.","ru":"Дети катаются на велосипеде по тротуару.","vi":"Trẻ em đạp xe trên vỉa hè.","fa":"بچه ها در پیاده رو دوچرخه سواری می کنند."},{"de":"Parken auf dem Trottoir ist verboten.","en":"Parking on the sidewalk is prohibited.","ru":"Парковка на тротуаре запрещена.","vi":"Cấm đậu xe trên vỉa hè.","fa":"پارک کردن در پیاده رو ممنوع است."}]},{"word":"trotz","en":"despite, in spite of","ru":"несмотря на","vi":"mặc dù","fa":"با وجود","examples":[{"de":"Trotz des schlechten Wetters gingen wir spazieren.","en":"Despite the bad weather, we went for a walk.","ru":"Несмотря на плохую погоду, мы пошли гулять.","vi":"Mặc dù thời tiết xấu, chúng tôi vẫn đi dạo.","fa":"با وجود بدی هوا رفتیم پیاده روی."},{"de":"Trotz seiner Krankheit arbeitet er weiter.","en":"Despite his illness, he keeps working.","ru":"Несмотря на свою болезнь, он продолжает работать.","vi":"Bất chấp bệnh tật, anh vẫn tiếp tục làm việc.","fa":"او با وجود بیماری به کار خود ادامه می دهد."}]},{"word":"trotzdem","en":"nevertheless, still","ru":"тем не менее, всё же","vi":"dù sao đi nữa","fa":"به هر حال","examples":[{"de":"Es regnete stark, trotzdem gingen wir raus.","en":"It was raining hard, but we went out anyway.","ru":"Шёл сильный дождь, но мы всё равно пошли гулять.","vi":"Trời mưa rất to nhưng chúng tôi vẫn đi ra ngoài.","fa":"باران شدیدی می بارید، اما به هر حال ما بیرون رفتیم."},{"de":"Sie war müde, trotzdem lernte sie weiter.","en":"She was tired, nevertheless she kept studying.","ru":"Она устала, но всё равно продолжала учиться.","vi":"Cô mệt mỏi nhưng vẫn tiếp tục học.","fa":"خسته بود اما به درس خواندن ادامه داد."}]},{"word":"das Tuch","en":"cloth","ru":"платок, ткань","vi":"tấm vải","fa":"پارچه","examples":[{"de":"Sie wischt den Tisch mit einem feuchten Tuch ab.","en":"She wipes the table with a damp cloth.","ru":"Она вытирает стол влажной тряпкой.","vi":"Cô ấy lau bàn bằng một miếng vải ẩm.","fa":"میز را با یک پارچه مرطوب پاک می کند."},{"de":"Im Winter trägt sie ein warmes Tuch um den Hals.","en":"In winter she wears a warm scarf around her neck.","ru":"Зимой она носит тёплый платок на шее.","vi":"Vào mùa đông, cô quàng một chiếc khăn ấm quanh cổ.","fa":"در زمستان یک روسری گرم به گردن می اندازد."}]},{"word":"tun","en":"to do","ru":"делать","vi":"làm","fa":"انجام دهید","examples":[{"de":"Was tust du gerade?","en":"What are you doing right now?","ru":"Что ты сейчас делаешь?","vi":"Bây giờ bạn đang làm gì?","fa":"الان چیکار میکنی؟"},{"de":"Ich habe heute nichts zu tun.","en":"I have nothing to do today.","ru":"Мне сегодня нечего делать.","vi":"Hôm nay tôi không có gì để làm.","fa":"امروز کاری ندارم."}]},{"word":"die Tür","en":"door","ru":"дверь","vi":"cánh cửa","fa":"درب","examples":[{"de":"Bitte mach die Tür zu.","en":"Please close the door.","ru":"Пожалуйста, закрой дверь.","vi":"Hãy đóng cửa lại.","fa":"لطفا در را ببندید."},{"de":"Jemand klopft an der Tür.","en":"Someone is knocking on the door.","ru":"Кто-то стучит в дверь.","vi":"Có người gõ cửa.","fa":"یک نفر در را می زند."}]},{"word":"der Turm","en":"tower","ru":"башня","vi":"tòa tháp","fa":"برج","examples":[{"de":"Von dem Turm hat man eine tolle Aussicht.","en":"There is a great view from the tower.","ru":"С башни открывается прекрасный вид.","vi":"Bạn có một cái nhìn tuyệt vời từ tòa tháp.","fa":"از برج منظره عالی دارید."},{"de":"Der alte Turm der Kirche ist weithin sichtbar.","en":"The church's old tower is visible from afar.","ru":"Старая башня церкви видна издалека.","vi":"Tháp cũ của nhà thờ có thể nhìn thấy từ xa.","fa":"برج قدیمی کلیسا از دور نمایان است."}]},{"word":"die Tüte","en":"bag (paper/plastic)","ru":"пакет","vi":"cái túi","fa":"کیف","examples":[{"de":"Kannst du mir bitte eine Tüte für die Einkäufe geben?","en":"Can you please give me a bag for the groceries?","ru":"Можешь дать мне пакет для покупок?","vi":"Bạn có thể vui lòng cho tôi một chiếc túi để mua sắm được không?","fa":"میشه لطفا یک کیف برای خرید به من بدهید؟"},{"de":"Die Tüte ist voller Äpfel.","en":"The bag is full of apples.","ru":"Пакет полон яблок.","vi":"Túi đầy táo.","fa":"کیسه پر از سیب است."}]},{"word":"der Typ","en":"guy; type","ru":"тип, парень","vi":"anh chàng","fa":"مرد","examples":[{"de":"Der Typ da drüben ist mein Nachbar.","en":"That guy over there is my neighbor.","ru":"Вон тот парень — мой сосед.","vi":"Anh chàng đằng kia là hàng xóm của tôi.","fa":"اون پسر اونجا همسایه منه"},{"de":"Welcher Typ von Auto gefällt dir am besten?","en":"Which type of car do you like best?","ru":"Какой тип машины тебе нравится больше всего?","vi":"Bạn thích loại xe nào nhất?","fa":"چه نوع ماشینی را بیشتر دوست دارید؟"}]},{"word":"die U-Bahn","en":"subway, underground (train)","ru":"метро","vi":"tàu điện ngầm","fa":"مترو","examples":[{"de":"Ich fahre jeden Tag mit der U-Bahn zur Arbeit.","en":"I take the subway to work every day.","ru":"Я каждый день езжу на работу на метро.","vi":"Tôi đi tàu điện ngầm đi làm hàng ngày.","fa":"من هر روز با مترو سر کار می روم."},{"de":"Die nächste U-Bahn kommt in fünf Minuten.","en":"The next subway train arrives in five minutes.","ru":"Следующий поезд метро прибудет через пять минут.","vi":"Chuyến tàu điện ngầm tiếp theo sẽ đến trong năm phút nữa.","fa":"متروی بعدی پنج دقیقه دیگر می رسد."}]},{"word":"üben","en":"to practice","ru":"тренироваться, упражняться","vi":"luyện tập","fa":"تمرین کنید","examples":[{"de":"Sie übt jeden Tag eine Stunde Klavier.","en":"She practices piano for an hour every day.","ru":"Она каждый день по часу упражняется на пианино.","vi":"Cô ấy tập piano một giờ mỗi ngày.","fa":"او هر روز یک ساعت پیانو تمرین می کند."},{"de":"Wir müssen die neuen Wörter noch üben.","en":"We still need to practice the new words.","ru":"Нам ещё нужно потренировать новые слова.","vi":"Chúng ta vẫn phải thực hành những từ mới.","fa":"ما هنوز باید کلمات جدید را تمرین کنیم."}]},{"word":"über","en":"over; about","ru":"над; о (чём-л.)","vi":"về","fa":"در مورد","examples":[{"de":"Das Bild hängt über dem Sofa.","en":"The picture hangs above the sofa.","ru":"Картина висит над диваном.","vi":"Bức tranh treo phía trên ghế sofa.","fa":"عکس بالای مبل آویزان است."},{"de":"Wir haben über das Wetter gesprochen.","en":"We talked about the weather.","ru":"Мы говорили о погоде.","vi":"Chúng tôi đã nói chuyện về thời tiết.","fa":"در مورد آب و هوا صحبت کردیم."}]},{"word":"überall","en":"everywhere","ru":"везде, повсюду","vi":"ở khắp mọi nơi","fa":"همه جا","examples":[{"de":"Überall liegt Schnee.","en":"Snow lies everywhere.","ru":"Везде лежит снег.","vi":"Có tuyết ở khắp mọi nơi.","fa":"همه جا برف است."},{"de":"Ich habe dich überall gesucht.","en":"I looked for you everywhere.","ru":"Я искал тебя везде.","vi":"Tôi đã tìm kiếm bạn khắp mọi nơi.","fa":"همه جا دنبالت گشتم"}]},{"word":"überfahren","en":"to run over (with a vehicle)","ru":"переехать (кого-л./что-л.)","vi":"chạy qua","fa":"فرار کردن","examples":[{"de":"Der Fahrer hat fast eine Katze überfahren.","en":"The driver almost ran over a cat.","ru":"Водитель чуть не переехал кошку.","vi":"Người lái xe suýt tông phải một con mèo.","fa":"نزدیک بود راننده به گربه برخورد کند."},{"de":"Pass auf, dass du niemanden überfährst!","en":"Watch out that you don't run anyone over!","ru":"Смотри, не переезжай никого!","vi":"Hãy cẩn thận để không chạy qua bất cứ ai!","fa":"مراقب باشید کسی را زیر پا نگذارید!"}]},{"word":"überhaupt","en":"at all; anyway, in general","ru":"вообще","vi":"tất cả","fa":"اصلا","examples":[{"de":"Ich habe überhaupt keine Zeit.","en":"I have no time at all.","ru":"У меня вообще нет времени.","vi":"Tôi không có thời gian chút nào.","fa":"من اصلا وقت ندارم"},{"de":"Warum machst du das überhaupt?","en":"Why are you doing that anyway?","ru":"Зачем ты вообще это делаешь?","vi":"Tại sao bạn lại làm điều này?","fa":"اصلا چرا این کار را می کنی؟"}]},{"word":"überholen","en":"to overtake, pass","ru":"обгонять","vi":"vượt qua","fa":"سبقت گرفتن","examples":[{"de":"Der Lkw hat uns gefährlich überholt.","en":"The truck overtook us dangerously.","ru":"Грузовик опасно обогнал нас.","vi":"Chiếc xe tải đã vượt qua chúng tôi một cách nguy hiểm.","fa":"کامیون به طرز خطرناکی از ما سبقت گرفت."},{"de":"Man darf hier nicht überholen.","en":"You're not allowed to overtake here.","ru":"Здесь нельзя обгонять.","vi":"Bạn không được phép vượt ở đây.","fa":"اینجا اجازه سبقت گرفتن ندارید."}]},{"word":"überlegen","en":"to think over, consider","ru":"обдумывать, размышлять","vi":"xem xét","fa":"در نظر بگیرید","examples":[{"de":"Ich muss mir das noch überlegen.","en":"I still need to think it over.","ru":"Мне нужно ещё это обдумать.","vi":"Tôi vẫn phải suy nghĩ về nó.","fa":"هنوز باید به آن فکر کنم."},{"de":"Überleg gut, bevor du eine Entscheidung triffst.","en":"Think carefully before you make a decision.","ru":"Хорошо подумай, прежде чем принять решение.","vi":"Hãy suy nghĩ kỹ trước khi đưa ra quyết định.","fa":"قبل از تصمیم گیری خوب فکر کنید."}]},{"word":"übermorgen","en":"the day after tomorrow","ru":"послезавтра","vi":"ngày mốt","fa":"پس فردا","examples":[{"de":"Übermorgen fahre ich nach Berlin.","en":"The day after tomorrow I'm going to Berlin.","ru":"Послезавтра я еду в Берлин.","vi":"Ngày kia tôi sẽ đi Berlin.","fa":"پس فردا به برلین می روم."},{"de":"Wir treffen uns übermorgen um zehn Uhr.","en":"We're meeting the day after tomorrow at ten o'clock.","ru":"Мы встретимся послезавтра в десять часов.","vi":"Chúng ta sẽ gặp nhau vào ngày mốt lúc 10 giờ.","fa":"پس فردا ساعت ده همدیگر را می بینیم."}]},{"word":"übernachten","en":"to stay overnight","ru":"ночевать","vi":"ở lại qua đêm","fa":"شب بمانید","examples":[{"de":"Wir übernachten in einem kleinen Hotel.","en":"We're staying overnight in a small hotel.","ru":"Мы ночуем в маленькой гостинице.","vi":"Chúng tôi nghỉ qua đêm tại một khách sạn nhỏ.","fa":"شب را در یک هتل کوچک می مانیم."},{"de":"Kann ich bei dir übernachten?","en":"Can I stay overnight at your place?","ru":"Могу я переночевать у тебя?","vi":"Tôi có thể ở lại qua đêm với bạn được không?","fa":"آیا می توانم یک شب با شما بمانم؟"}]},{"word":"übernehmen","en":"to take over","ru":"принимать на себя, брать (обязанности)","vi":"tiếp quản","fa":"را بر عهده بگیرد","examples":[{"de":"Sie übernimmt nächstes Jahr die Firma.","en":"She's taking over the company next year.","ru":"Она возьмёт на себя управление компанией в следующем году.","vi":"Cô ấy sẽ tiếp quản công ty vào năm tới.","fa":"او سال آینده این شرکت را برعهده خواهد گرفت."},{"de":"Wer übernimmt die Verantwortung dafür?","en":"Who takes responsibility for that?","ru":"Кто берёт на себя ответственность за это?","vi":"Ai chịu trách nhiệm về việc này?","fa":"چه کسی مسئولیت این کار را بر عهده می گیرد؟"}]},{"word":"überprüfen","en":"to check, verify","ru":"проверять","vi":"kiểm tra","fa":"بررسی کنید","examples":[{"de":"Der Techniker überprüft die Maschine.","en":"The technician checks the machine.","ru":"Техник проверяет машину.","vi":"Kỹ thuật viên kiểm tra máy.","fa":"تکنسین دستگاه را چک می کند."},{"de":"Bitte überprüfen Sie Ihre Angaben noch einmal.","en":"Please check your details once more.","ru":"Пожалуйста, проверьте ещё раз свои данные.","vi":"Vui lòng kiểm tra lại thông tin của bạn.","fa":"لطفا اطلاعات خود را دوباره بررسی کنید."}]},{"word":"überqueren","en":"to cross (a street, etc.)","ru":"переходить, пересекать","vi":"chéo","fa":"متقاطع","examples":[{"de":"Wir überqueren die Straße an der Ampel.","en":"We cross the street at the traffic light.","ru":"Мы переходим улицу на светофоре.","vi":"Chúng tôi băng qua đường ở đèn giao thông.","fa":"از خیابان در چراغ راهنمایی عبور می کنیم."},{"de":"Sei vorsichtig, wenn du die Kreuzung überquerst.","en":"Be careful when you cross the intersection.","ru":"Будь осторожен, переходя перекрёсток.","vi":"Hãy cẩn thận khi băng qua ngã tư.","fa":"هنگام عبور از تقاطع مراقب باشید."}]},{"word":"überraschen","en":"to surprise","ru":"удивлять, делать сюрприз","vi":"ngạc nhiên","fa":"تعجب","examples":[{"de":"Die Nachricht hat mich sehr überrascht.","en":"The news surprised me a lot.","ru":"Эта новость меня очень удивила.","vi":"Tin tức này thực sự làm tôi ngạc nhiên.","fa":"این خبر واقعاً مرا شگفت زده کرد."},{"de":"Wir wollen unsere Oma zum Geburtstag überraschen.","en":"We want to surprise our grandma for her birthday.","ru":"Мы хотим сделать сюрприз бабушке на день рождения.","vi":"Chúng tôi muốn gây bất ngờ cho bà của chúng tôi nhân dịp sinh nhật của bà.","fa":"می خواهیم مادربزرگمان را برای تولدش سورپرایز کنیم."}]},{"word":"überreden","en":"to persuade, talk into","ru":"уговаривать","vi":"thuyết phục","fa":"متقاعد کردن","examples":[{"de":"Er hat mich überredet, mitzukommen.","en":"He persuaded me to come along.","ru":"Он уговорил меня пойти с ним.","vi":"Anh ấy đã thuyết phục tôi đi cùng anh ấy.","fa":"او مرا متقاعد کرد که با او بیایم."},{"de":"Lass dich nicht zu etwas überreden, was du nicht willst.","en":"Don't let yourself be talked into something you don't want.","ru":"Не дай себя уговорить на то, чего ты не хочешь.","vi":"Đừng để bản thân bị thuyết phục làm điều gì đó mà bạn không muốn.","fa":"به خودتان اجازه ندهید که برای انجام کاری که نمی خواهید متقاعد شوید."}]},{"word":"die Überschrift","en":"the headline, heading","ru":"заголовок","vi":"tiêu đề","fa":"سرفصل","examples":[{"de":"Lies zuerst die Überschrift des Artikels.","en":"First read the headline of the article.","ru":"Сначала прочитай заголовок статьи.","vi":"Đọc tiêu đề của bài viết đầu tiên.","fa":"ابتدا عنوان مقاله را بخوانید."},{"de":"Die Überschrift ist sehr auffällig.","en":"The heading is very eye-catching.","ru":"Заголовок очень бросается в глаза.","vi":"Tiêu đề rất ấn tượng.","fa":"تیتر بسیار چشمگیر است."}]},{"word":"übersetzen","en":"to translate","ru":"переводить","vi":"dịch","fa":"ترجمه کنید","examples":[{"de":"Kannst du diesen Text ins Englische übersetzen?","en":"Can you translate this text into English?","ru":"Можешь перевести этот текст на английский?","vi":"Bạn có thể dịch văn bản này sang tiếng Anh?","fa":"آیا می توانید این متن را به انگلیسی ترجمه کنید؟"},{"de":"Sie übersetzt Bücher aus dem Französischen.","en":"She translates books from French.","ru":"Она переводит книги с французского.","vi":"Cô dịch sách từ tiếng Pháp.","fa":"او کتاب هایی را از فرانسه ترجمه می کند."}]},{"word":"die Übersetzerin","en":"the (female) translator","ru":"переводчица","vi":"người phiên dịch","fa":"مترجم","examples":[{"de":"Meine Schwester arbeitet als Übersetzerin.","en":"My sister works as a translator.","ru":"Моя сестра работает переводчицей.","vi":"Chị tôi làm nghề phiên dịch.","fa":"خواهرم مترجم کار می کند."},{"de":"Die Übersetzerin hat den Roman sehr genau übersetzt.","en":"The translator translated the novel very precisely.","ru":"Переводчица очень точно перевела роман.","vi":"Người dịch đã dịch cuốn tiểu thuyết rất chính xác.","fa":"مترجم این رمان را بسیار دقیق ترجمه کرده است."}]},{"word":"die Überstunde","en":"the overtime hour","ru":"сверхурочный час","vi":"làm thêm giờ","fa":"اضافه کاری","examples":[{"de":"Ich musste gestern zwei Überstunden machen.","en":"I had to work two hours of overtime yesterday.","ru":"Вчера мне пришлось отработать два часа сверхурочно.","vi":"Hôm qua tôi phải làm thêm hai giờ.","fa":"دیروز باید دو ساعت اضافه کار می کردم."},{"de":"Werden Überstunden bei euch bezahlt?","en":"Is overtime paid at your company?","ru":"У вас оплачиваются сверхурочные?","vi":"Bạn có trả tiền làm thêm giờ không?","fa":"اضافه کاری پرداخت می کنید؟"}]},{"word":"übertreiben","en":"to exaggerate","ru":"преувеличивать","vi":"phóng đại","fa":"اغراق کردن","examples":[{"de":"Du übertreibst mal wieder!","en":"You're exaggerating again!","ru":"Ты снова преувеличиваешь!","vi":"Bạn lại phóng đại nữa rồi!","fa":"بازم اغراق میکنی!"},{"de":"Er übertreibt gern, wenn er Geschichten erzählt.","en":"He likes to exaggerate when he tells stories.","ru":"Он любит преувеличивать, когда рассказывает истории.","vi":"Anh ấy thích phóng đại khi kể chuyện.","fa":"او دوست دارد وقتی داستان می گوید اغراق کند."}]},{"word":"überweisen","en":"to transfer (money)","ru":"переводить (деньги)","vi":"chuyển nhượng","fa":"انتقال","examples":[{"de":"Ich habe das Geld schon überwiesen.","en":"I've already transferred the money.","ru":"Я уже перевёл деньги.","vi":"Tôi đã chuyển tiền rồi.","fa":"من قبلاً پول را منتقل کردم."},{"de":"Bitte überweisen Sie die Miete bis zum Ersten.","en":"Please transfer the rent by the first of the month.","ru":"Пожалуйста, переведите арендную плату до первого числа.","vi":"Vui lòng chuyển tiền thuê trước ngày đầu tiên.","fa":"لطفا اجاره را تا روز اول انتقال دهید."}]},{"word":"überzeugen","en":"to convince","ru":"убеждать","vi":"thuyết phục","fa":"متقاعد کردن","examples":[{"de":"Mit guten Argumenten konnte er alle überzeugen.","en":"With good arguments he was able to convince everyone.","ru":"Хорошими аргументами он смог убедить всех.","vi":"Anh ấy đã có thể thuyết phục mọi người bằng những lý lẽ thuyết phục.","fa":"او توانست با استدلال های خوبی همه را متقاعد کند."},{"de":"Das Angebot hat mich nicht ganz überzeugt.","en":"The offer didn't fully convince me.","ru":"Предложение не до конца меня убедило.","vi":"Lời đề nghị không hoàn toàn thuyết phục được tôi.","fa":"این پیشنهاد کاملاً من را متقاعد نکرد."}]},{"word":"überzeugend","en":"convincing","ru":"убедительный","vi":"thuyết phục","fa":"متقاعد کننده","examples":[{"de":"Seine Argumente waren sehr überzeugend.","en":"His arguments were very convincing.","ru":"Его аргументы были очень убедительными.","vi":"Những lập luận của ông rất thuyết phục.","fa":"استدلال های او بسیار قانع کننده بود."},{"de":"Die Schauspielerin war in ihrer Rolle überzeugend.","en":"The actress was convincing in her role.","ru":"Актриса была убедительна в своей роли.","vi":"Nữ diễn viên thể hiện rất thuyết phục trong vai diễn của mình.","fa":"این بازیگر در نقش خود قانع کننده بود."}]},{"word":"üblich","en":"usual, customary","ru":"обычный, принятый","vi":"thông thường","fa":"معمولی","examples":[{"de":"Das ist hier so üblich.","en":"That's customary here.","ru":"Это здесь принято.","vi":"Đó là điều phổ biến ở đây.","fa":"این در اینجا رایج است."},{"de":"Es ist üblich, sich zur Begrüßung die Hand zu geben.","en":"It's customary to shake hands as a greeting.","ru":"Принято пожимать руку в качестве приветствия.","vi":"Bắt tay như một phong tục là một phong tục.","fa":"رسم بر این است که برای احوالپرسی دست دادن."}]},{"word":"übrig","en":"remaining, left over","ru":"оставшийся","vi":"trái","fa":"سمت چپ","examples":[{"de":"Ist noch Kuchen übrig?","en":"Is there still cake left?","ru":"Ещё остался торт?","vi":"Có còn cái bánh nào không?","fa":"کیک مونده؟"},{"de":"Nach dem Essen war nichts mehr übrig.","en":"After the meal nothing was left.","ru":"После еды ничего не осталось.","vi":"Ăn xong chẳng còn gì nữa.","fa":"بعد از غذا چیزی نمانده بود."}]},{"word":"übrigens","en":"by the way","ru":"кстати","vi":"Nhân tiện","fa":"به هر حال","examples":[{"de":"Übrigens, hast du meine E-Mail bekommen?","en":"By the way, did you get my email?","ru":"Кстати, ты получил моё письмо?","vi":"Nhân tiện, bạn có nhận được email của tôi không?","fa":"راستی ایمیل من رو گرفتی؟"},{"de":"Das Restaurant ist übrigens sehr gut.","en":"By the way, the restaurant is very good.","ru":"Кстати, ресторан очень хороший.","vi":"Nhân tiện, nhà hàng rất ngon.","fa":"اتفاقا رستوران خیلی خوبیه."}]},{"word":"das Ufer","en":"the (river/lake) bank, shore","ru":"берег","vi":"bờ biển","fa":"ساحل","examples":[{"de":"Wir sind am Ufer des Sees spazieren gegangen.","en":"We went for a walk along the shore of the lake.","ru":"Мы гуляли по берегу озера.","vi":"Chúng tôi đi dạo trên bờ hồ.","fa":"رفتیم کنار دریاچه قدم زدیم."},{"de":"Das Boot liegt am Ufer.","en":"The boat lies on the shore.","ru":"Лодка стоит на берегу.","vi":"Thuyền đang ở trên bờ.","fa":"قایق در ساحل است."}]},{"word":"die Uhr","en":"the clock, watch; o'clock","ru":"часы; час (при указании времени)","vi":"đồng hồ","fa":"ساعت","examples":[{"de":"Meine Uhr geht falsch.","en":"My watch is wrong.","ru":"Мои часы идут неправильно.","vi":"Đồng hồ của tôi sai rồi.","fa":"ساعت من اشتباه است"},{"de":"Es ist jetzt acht Uhr.","en":"It is eight o'clock now.","ru":"Сейчас восемь часов.","vi":"Bây giờ là tám giờ.","fa":"الان ساعت هشت است."}]},{"word":"um","en":"around; at (time)","ru":"вокруг; в (при времени)","vi":"xung quanh","fa":"اطراف","examples":[{"de":"Das Fest beginnt um acht Uhr.","en":"The party starts at eight o'clock.","ru":"Праздник начинается в восемь часов.","vi":"Lễ hội bắt đầu lúc tám giờ.","fa":"این جشنواره از ساعت هشت آغاز می شود."},{"de":"Wir sitzen um den Tisch herum.","en":"We are sitting around the table.","ru":"Мы сидим вокруг стола.","vi":"Chúng tôi ngồi quanh bàn.","fa":"دور میز می نشینیم."}]},{"word":"um … zu","en":"in order to","ru":"чтобы (с инфинитивом)","vi":"đến…đến","fa":"به… به","examples":[{"de":"Ich lerne Deutsch, um in Deutschland zu studieren.","en":"I'm learning German in order to study in Germany.","ru":"Я учу немецкий, чтобы учиться в Германии.","vi":"Tôi đang học tiếng Đức để du học ở Đức.","fa":"در حال یادگیری زبان آلمانی برای تحصیل در آلمان هستم."},{"de":"Er steht früh auf, um pünktlich zur Arbeit zu kommen.","en":"He gets up early in order to arrive at work on time.","ru":"Он встаёт рано, чтобы вовремя прийти на работу.","vi":"Anh ấy dậy sớm để đi làm đúng giờ.","fa":"او زود بیدار می شود تا به موقع به محل کارش برسد."}]},{"word":"umarmen","en":"to hug, embrace","ru":"обнимать","vi":"ôm","fa":"بغل کردن","examples":[{"de":"Sie umarmte ihn zur Begrüßung.","en":"She hugged him as a greeting.","ru":"Она обняла его в знак приветствия.","vi":"Cô ôm anh chào hỏi.","fa":"به نشانه سلام او را در آغوش گرفت."},{"de":"Die Kinder umarmten ihre Mutter.","en":"The children hugged their mother.","ru":"Дети обняли свою маму.","vi":"Những đứa trẻ ôm chặt lấy mẹ.","fa":"بچه ها مادرشان را در آغوش گرفتند."}]},{"word":"die Umfrage","en":"the survey, poll","ru":"опрос","vi":"cuộc khảo sát","fa":"نظرسنجی","examples":[{"de":"Wir haben eine Umfrage unter den Studenten gemacht.","en":"We conducted a survey among the students.","ru":"Мы провели опрос среди студентов.","vi":"Chúng tôi đã tiến hành một cuộc khảo sát giữa các sinh viên.","fa":"ما یک نظرسنجی بین دانش آموزان انجام دادیم."},{"de":"Laut der Umfrage sind die meisten zufrieden.","en":"According to the survey, most people are satisfied.","ru":"Согласно опросу, большинство довольны.","vi":"Theo khảo sát, hầu hết đều hài lòng.","fa":"بر اساس نظرسنجی، اکثر آنها راضی هستند."}]},{"word":"die Umgebung","en":"the surroundings, area","ru":"окрестности, окружение","vi":"môi trường xung quanh","fa":"محیط اطراف","examples":[{"de":"Die Umgebung des Schlosses ist sehr schön.","en":"The surroundings of the castle are very beautiful.","ru":"Окрестности замка очень красивы.","vi":"Khung cảnh xung quanh lâu đài rất đẹp.","fa":"محیط اطراف قلعه بسیار زیباست."},{"de":"Wir haben die Umgebung der Stadt erkundet.","en":"We explored the surrounding area of the city.","ru":"Мы исследовали окрестности города.","vi":"Chúng tôi khám phá khu vực xung quanh thành phố.","fa":"اطراف شهر را گشتیم."}]},{"word":"umgehen","en":"to handle, deal with","ru":"обращаться (с кем-л./чем-л.)","vi":"đối phó với","fa":"با","examples":[{"de":"Er kann gut mit Kindern umgehen.","en":"He can handle children well.","ru":"Он умеет хорошо ладить с детьми.","vi":"Anh ấy tốt với trẻ em.","fa":"او با بچه ها خوب است."},{"de":"Wie gehst du mit Stress um?","en":"How do you deal with stress?","ru":"Как ты справляешься со стрессом?","vi":"Làm thế nào để bạn đối phó với căng thẳng?","fa":"چگونه با استرس مقابله می کنید؟"}]},{"word":"umgekehrt","en":"the other way around, vice versa","ru":"наоборот","vi":"ngược lại","fa":"برعکس","examples":[{"de":"Es war genau umgekehrt, als du denkst.","en":"It was exactly the opposite of what you think.","ru":"Всё было как раз наоборот, чем ты думаешь.","vi":"Nó hoàn toàn trái ngược với những gì bạn nghĩ.","fa":"دقیقا برعکس چیزی بود که شما فکر می کنید."},{"de":"Normalerweise mache ich es umgekehrt.","en":"Usually I do it the other way around.","ru":"Обычно я делаю наоборот.","vi":"Tôi thường làm theo cách khác.","fa":"من معمولا این کار را برعکس انجام می دهم."}]},{"word":"die Umleitung","en":"the detour, diversion","ru":"объезд","vi":"sự chuyển hướng","fa":"تغییر مسیر","examples":[{"de":"Wegen der Bauarbeiten gibt es eine Umleitung.","en":"There's a detour because of the construction work.","ru":"Из-за строительных работ есть объезд.","vi":"Có đường vòng do công trình xây dựng.","fa":"انحراف به دلیل کار ساختمانی وجود دارد."},{"de":"Wir mussten der Umleitung folgen.","en":"We had to follow the detour.","ru":"Нам пришлось следовать объезду.","vi":"Chúng tôi phải đi theo đường vòng.","fa":"باید مسیر انحرافی را دنبال می کردیم."}]},{"word":"umso","en":"all the more (the ... the more)","ru":"тем (более)","vi":"hơn thế nữa","fa":"هر چه بیشتر","examples":[{"de":"Je später es wird, umso müder werde ich.","en":"The later it gets, the more tired I become.","ru":"Чем позже становится, тем более уставшим я становлюсь.","vi":"Càng về sau tôi càng mệt mỏi.","fa":"هر چه دیرتر می شود، بیشتر خسته می شوم."},{"de":"Umso besser, wenn du auch kommst!","en":"All the better if you come too!","ru":"Тем лучше, если ты тоже придёшь!","vi":"Sẽ tốt hơn nếu bạn cũng đến!","fa":"اگر شما هم بیای خیلی بهتر!"}]},{"word":"umsonst","en":"for free; in vain","ru":"бесплатно; напрасно","vi":"miễn phí","fa":"به صورت رایگان","examples":[{"de":"Der Eintritt ist heute umsonst.","en":"Admission is free today.","ru":"Сегодня вход бесплатный.","vi":"Vào cửa miễn phí ngày hôm nay.","fa":"ورود امروز رایگان است"},{"de":"Alle Mühe war umsonst.","en":"All the effort was in vain.","ru":"Все усилия были напрасны.","vi":"Mọi nỗ lực đều vô ích.","fa":"تمام تلاش ها بیهوده بود."}]},{"word":"umsteigen","en":"to change (trains/buses), transfer","ru":"делать пересадку","vi":"chuyển đổi","fa":"سوئیچ","examples":[{"de":"In München müssen wir umsteigen.","en":"We have to change trains in Munich.","ru":"В Мюнхене нам нужно сделать пересадку.","vi":"Chúng ta phải đổi tàu ở Munich.","fa":"باید در مونیخ قطار عوض کنیم."},{"de":"Steigen wir hier in die U-Bahn um?","en":"Do we transfer to the subway here?","ru":"Мы здесь пересаживаемся на метро?","vi":"Chúng ta có nên đổi sang tàu điện ngầm ở đây không?","fa":"آیا باید اینجا را به مترو تغییر دهیم؟"}]},{"word":"umstritten","en":"controversial; disputed","ru":"спорный","vi":"gây tranh cãi","fa":"بحث برانگیز","examples":[{"de":"Das neue Gesetz ist sehr umstritten.","en":"The new law is very controversial.","ru":"Новый закон весьма спорный.","vi":"Luật mới đang gây nhiều tranh cãi.","fa":"قانون جدید بسیار بحث برانگیز است."},{"de":"Ob die Methode wirkt, ist unter Experten umstritten.","en":"Whether the method works is disputed among experts.","ru":"Работает ли этот метод, среди экспертов спорно.","vi":"Liệu phương pháp này có hiệu quả hay không vẫn còn gây tranh cãi giữa các chuyên gia.","fa":"اینکه آیا این روش کار می کند یا خیر، در میان کارشناسان بحث برانگیز است."}]},{"word":"umtauschen","en":"to exchange (goods)","ru":"обменивать (товар)","vi":"trao đổi","fa":"مبادله","examples":[{"de":"Ich möchte dieses Hemd umtauschen.","en":"I would like to exchange this shirt.","ru":"Я хотел бы обменять эту рубашку.","vi":"Tôi muốn đổi chiếc áo này.","fa":"من می خواهم این پیراهن را عوض کنم."},{"de":"Kann man das Geschenk umtauschen?","en":"Can the gift be exchanged?","ru":"Можно обменять этот подарок?","vi":"Quà tặng có thể đổi được không?","fa":"آیا هدیه قابل تعویض است؟"}]},{"word":"die Umwelt","en":"the environment","ru":"окружающая среда","vi":"môi trường","fa":"محیط زیست","examples":[{"de":"Wir müssen die Umwelt besser schützen.","en":"We need to protect the environment better.","ru":"Нам нужно лучше защищать окружающую среду.","vi":"Chúng ta phải bảo vệ môi trường tốt hơn.","fa":"ما باید از محیط زیست بهتر محافظت کنیم."},{"de":"Plastik schadet der Umwelt.","en":"Plastic harms the environment.","ru":"Пластик вредит окружающей среде.","vi":"Nhựa gây hại cho môi trường.","fa":"پلاستیک به محیط زیست آسیب می رساند."}]},{"word":"umweltfreundlich","en":"environmentally friendly","ru":"экологичный; экологически чистый","vi":"thân thiện với môi trường","fa":"سازگار با محیط زیست","examples":[{"de":"Mit dem Fahrrad zu fahren ist umweltfreundlich.","en":"Riding a bike is environmentally friendly.","ru":"Ездить на велосипеде экологично.","vi":"Đi xe đạp là thân thiện với môi trường.","fa":"دوچرخه سواری دوستدار محیط زیست است."},{"de":"Wir kaufen möglichst umweltfreundliche Produkte.","en":"We buy environmentally friendly products where possible.","ru":"Мы по возможности покупаем экологичные товары.","vi":"Chúng tôi mua những sản phẩm thân thiện với môi trường nhất có thể.","fa":"ما محصولاتی را خریداری می کنیم که تا حد امکان سازگار با محیط زیست باشند."}]},{"word":"der Umweltschutz","en":"environmental protection","ru":"охрана окружающей среды","vi":"bảo vệ môi trường","fa":"حفاظت از محیط زیست","examples":[{"de":"Umweltschutz beginnt schon im eigenen Haushalt.","en":"Environmental protection begins in your own household.","ru":"Охрана окружающей среды начинается уже в собственном доме.","vi":"Bảo vệ môi trường bắt đầu từ chính ngôi nhà của bạn.","fa":"حفاظت از محیط زیست از خانه شما آغاز می شود."},{"de":"Die Regierung investiert mehr Geld in den Umweltschutz.","en":"The government is investing more money in environmental protection.","ru":"Правительство вкладывает больше денег в охрану окружающей среды.","vi":"Chính phủ đang đầu tư nhiều tiền hơn vào việc bảo vệ môi trường.","fa":"دولت پول بیشتری برای حفاظت از محیط زیست سرمایه گذاری می کند."}]},{"word":"umziehen","en":"to move (house)","ru":"переезжать (менять место жительства)","vi":"di chuyển","fa":"حرکت کنید","examples":[{"de":"Wir ziehen nächsten Monat um.","en":"We're moving next month.","ru":"Мы переезжаем в следующем месяце.","vi":"Chúng tôi sẽ chuyển đi vào tháng tới.","fa":"ماه آینده حرکت می کنیم."},{"de":"Sie sind in eine größere Wohnung umgezogen.","en":"They moved into a bigger apartment.","ru":"Они переехали в квартиру побольше.","vi":"Họ chuyển đến một căn hộ lớn hơn.","fa":"آنها به یک آپارتمان بزرگتر نقل مکان کردند."}]},{"word":"unbedingt","en":"absolutely, definitely","ru":"обязательно, непременно","vi":"tuyệt đối","fa":"مطلقا","examples":[{"de":"Du musst diesen Film unbedingt sehen.","en":"You absolutely must see this film.","ru":"Тебе обязательно нужно посмотреть этот фильм.","vi":"Bạn nhất định phải xem bộ phim này.","fa":"این فیلم را حتما ببینید"},{"de":"Ich möchte unbedingt nach Japan reisen.","en":"I definitely want to travel to Japan.","ru":"Я непременно хочу поехать в Японию.","vi":"Tôi thực sự muốn đi du lịch đến Nhật Bản.","fa":"من واقعاً می خواهم به ژاپن سفر کنم."}]},{"word":"und","en":"and","ru":"и","vi":"và","fa":"و","examples":[{"de":"Ich kaufe Brot und Milch.","en":"I'm buying bread and milk.","ru":"Я покупаю хлеб и молоко.","vi":"Tôi mua bánh mì và sữa.","fa":"نان و شیر می خرم."},{"de":"Sie ist klug und freundlich.","en":"She is smart and friendly.","ru":"Она умная и дружелюбная.","vi":"Cô ấy thông minh và tốt bụng.","fa":"او باهوش و مهربان است."}]},{"word":"der Unfall","en":"the accident","ru":"авария, несчастный случай","vi":"vụ tai nạn","fa":"تصادف","examples":[{"de":"Gestern gab es einen Unfall auf der Autobahn.","en":"Yesterday there was an accident on the highway.","ru":"Вчера на автомагистрали произошла авария.","vi":"Hôm qua có một vụ tai nạn trên đường cao tốc.","fa":"دیروز تصادفی در بزرگراه رخ داد."},{"de":"Zum Glück wurde bei dem Unfall niemand verletzt.","en":"Fortunately, nobody was injured in the accident.","ru":"К счастью, в аварии никто не пострадал.","vi":"Rất may không có ai bị thương trong vụ tai nạn.","fa":"خوشبختانه در این حادثه به کسی آسیبی نرسید."}]},{"word":"ungefähr","en":"approximately, about","ru":"примерно, приблизительно","vi":"xấp xỉ","fa":"تقریبا","examples":[{"de":"Die Fahrt dauert ungefähr zwei Stunden.","en":"The trip takes approximately two hours.","ru":"Поездка занимает примерно два часа.","vi":"Cuộc hành trình mất khoảng hai giờ.","fa":"سفر تقریبا دو ساعت طول می کشد."},{"de":"Ich habe ungefähr hundert Euro dabei.","en":"I have about a hundred euros with me.","ru":"У меня с собой примерно сто евро.","vi":"Tôi mang theo khoảng một trăm euro.","fa":"من حدود صد یورو با خودم دارم."}]},{"word":"ungewöhnlich","en":"unusual","ru":"необычный","vi":"bất thường","fa":"غیر معمول","examples":[{"de":"Das Wetter ist heute ungewöhnlich warm.","en":"The weather is unusually warm today.","ru":"Сегодня погода необычно тёплая.","vi":"Thời tiết hôm nay ấm áp lạ thường.","fa":"امروز هوا به طور غیرعادی گرم است."},{"de":"Sie hatte eine ungewöhnliche Idee.","en":"She had an unusual idea.","ru":"У неё была необычная идея.","vi":"Cô ấy có một ý tưởng khác thường.","fa":"او یک ایده غیر معمول داشت."}]},{"word":"unglaublich","en":"unbelievable, incredible","ru":"невероятный","vi":"không thể tin được","fa":"باور نکردنی","examples":[{"de":"Das ist ja unglaublich!","en":"That's just unbelievable!","ru":"Это просто невероятно!","vi":"Thật không thể tin được!","fa":"این باور نکردنی است!"},{"de":"Er hat eine unglaubliche Geschichte erzählt.","en":"He told an incredible story.","ru":"Он рассказал невероятную историю.","vi":"Anh ấy đã kể một câu chuyện đáng kinh ngạc.","fa":"او یک داستان باورنکردنی تعریف کرد."}]},{"word":"das Unglück","en":"the accident, misfortune","ru":"несчастье, несчастный случай","vi":"sự bất hạnh","fa":"بدبختی","examples":[{"de":"Bei dem Unglück wurden viele Menschen verletzt.","en":"Many people were injured in the accident.","ru":"В результате несчастного случая пострадало много людей.","vi":"Nhiều người bị thương trong vụ tai nạn.","fa":"در این حادثه افراد زیادی مجروح شدند."},{"de":"Es brachte ihm Unglück, an dem Tag zu reisen.","en":"It brought him bad luck to travel that day.","ru":"Ему принесло несчастье путешествовать в тот день.","vi":"Thật là xui xẻo cho anh ta khi đi du lịch vào ngày hôm đó.","fa":"سفر آن روز برایش بدشانسی بود."}]},{"word":"unheimlich","en":"creepy, eerie; (colloquial) extremely","ru":"жуткий; (разг.) невероятно, очень","vi":"đáng sợ","fa":"ترسناک","examples":[{"de":"Das alte Haus wirkt unheimlich.","en":"The old house seems creepy.","ru":"Старый дом выглядит жутко.","vi":"Ngôi nhà cũ trông thật kỳ lạ.","fa":"خانه قدیمی ترسناک به نظر می رسد."},{"de":"Ich habe mich unheimlich gefreut.","en":"I was extremely happy.","ru":"Я невероятно обрадовался.","vi":"Tôi đã vô cùng hạnh phúc.","fa":"من فوق العاده خوشحال بودم."}]},{"word":"unhöflich","en":"impolite; rude","ru":"невежливый; грубый","vi":"thô lỗ","fa":"بی ادب","examples":[{"de":"Es ist unhöflich, andere zu unterbrechen.","en":"It is rude to interrupt others.","ru":"Невежливо перебивать других.","vi":"Thật thô lỗ khi ngắt lời người khác.","fa":"بی ادبی است که حرف دیگران را قطع کنید."},{"de":"Der Verkäufer war ziemlich unhöflich zu uns.","en":"The salesperson was quite rude to us.","ru":"Продавец был довольно груб с нами.","vi":"Người bán khá thô lỗ với chúng tôi.","fa":"فروشنده نسبت به ما بسیار بی ادب بود."}]},{"word":"die Uniform","en":"the uniform","ru":"форма, униформа","vi":"đồng phục","fa":"لباس فرم","examples":[{"de":"Der Polizist trägt eine Uniform.","en":"The policeman wears a uniform.","ru":"Полицейский носит форму.","vi":"Viên cảnh sát đang mặc đồng phục.","fa":"افسر پلیس یونیفرم پوشیده است."},{"de":"In dieser Schule tragen die Schüler eine Uniform.","en":"In this school the students wear a uniform.","ru":"В этой школе ученики носят форму.","vi":"Ở trường này, học sinh mặc đồng phục.","fa":"در این مدرسه دانش آموزان لباس فرم می پوشند."}]},{"word":"die Universität","en":"the university","ru":"университет","vi":"trường đại học","fa":"دانشگاه","examples":[{"de":"Meine Schwester studiert an der Universität München.","en":"My sister studies at the University of Munich.","ru":"Моя сестра учится в Мюнхенском университете.","vi":"Em gái tôi đang học tại Đại học Munich.","fa":"خواهرم در دانشگاه مونیخ درس می خواند."},{"de":"Er hat gerade sein Studium an der Universität begonnen.","en":"He has just started his studies at the university.","ru":"Он только что начал учёбу в университете.","vi":"Anh ấy mới bắt đầu học tại trường đại học.","fa":"او به تازگی تحصیلات خود را در دانشگاه آغاز کرده است."}]},{"word":"unter","en":"under, below; among","ru":"под; среди","vi":"dưới","fa":"زیر","examples":[{"de":"Die Katze schläft unter dem Tisch.","en":"The cat is sleeping under the table.","ru":"Кошка спит под столом.","vi":"Con mèo ngủ dưới gầm bàn.","fa":"گربه زیر میز می خوابد."},{"de":"Unter den Gästen war auch der Bürgermeister.","en":"Among the guests was also the mayor.","ru":"Среди гостей был и мэр.","vi":"Thị trưởng cũng nằm trong số khách mời.","fa":"شهردار نیز در جمع مهمانان حضور داشت."}]},{"word":"unter-","en":"prefix meaning 'under, sub-'","ru":"приставка со значением 'под-'","vi":"dưới-","fa":"زیر-","examples":[{"de":"Die U-Bahn fährt unterirdisch durch die Stadt.","en":"The subway runs underground through the city.","ru":"Метро проходит под землёй через город.","vi":"Tàu điện ngầm chạy ngầm xuyên qua thành phố.","fa":"مترو از زیر زمین در شهر عبور می کند."},{"de":"Der Tunnel liegt tief unterirdisch.","en":"The tunnel lies deep underground.","ru":"Туннель расположен глубоко под землёй.","vi":"Đường hầm nằm sâu dưới lòng đất.","fa":"تونل در اعماق زمین است."}]},{"word":"unterbrechen","en":"to interrupt","ru":"прерывать","vi":"làm gián đoạn","fa":"قطع کردن","examples":[{"de":"Entschuldigung, darf ich dich kurz unterbrechen?","en":"Excuse me, may I interrupt you briefly?","ru":"Извини, можно я тебя ненадолго прерву?","vi":"Xin lỗi, tôi có thể ngắt lời bạn một lát được không?","fa":"ببخشید میتونم یه لحظه حرفتونو قطع کنم؟"},{"de":"Der Redner wurde mehrmals unterbrochen.","en":"The speaker was interrupted several times.","ru":"Докладчика несколько раз перебивали.","vi":"Người nói bị gián đoạn nhiều lần.","fa":"سخنران چندین بار قطع شد."}]},{"word":"die Unterkunft","en":"the accommodation, lodging","ru":"жильё, ночлег","vi":"chỗ ở","fa":"محل اقامت","examples":[{"de":"Wir haben eine günstige Unterkunft in der Altstadt gefunden.","en":"We found affordable accommodation in the old town.","ru":"Мы нашли недорогое жильё в старом городе.","vi":"Chúng tôi tìm được chỗ ở giá rẻ ở phố cổ.","fa":"اقامتگاه ارزانی در شهر قدیمی پیدا کردیم."},{"de":"Die Unterkunft war sauber und gemütlich.","en":"The accommodation was clean and cozy.","ru":"Жильё было чистым и уютным.","vi":"Chỗ ở sạch sẽ và thoải mái.","fa":"محل اقامت تمیز و راحت بود."}]},{"word":"die Unterlagen","en":"the documents, papers","ru":"документы","vi":"các tài liệu","fa":"اسناد","examples":[{"de":"Bitte bringen Sie alle nötigen Unterlagen mit.","en":"Please bring all the necessary documents.","ru":"Пожалуйста, принесите все необходимые документы.","vi":"Vui lòng mang theo tất cả các tài liệu cần thiết với bạn.","fa":"لطفا تمام مدارک لازم را همراه داشته باشید."},{"de":"Ich habe meine Unterlagen für die Bewerbung vorbereitet.","en":"I've prepared my documents for the application.","ru":"Я подготовил свои документы для заявки.","vi":"Tôi đã chuẩn bị đầy đủ hồ sơ để nộp đơn.","fa":"من مدارکم را برای درخواست آماده کرده ام."}]},{"word":"unterlassen","en":"to refrain from, omit doing","ru":"воздерживаться (от чего-л.)","vi":"kiềm chế","fa":"خودداری از","examples":[{"de":"Bitte unterlassen Sie das Rauchen hier.","en":"Please refrain from smoking here.","ru":"Пожалуйста, воздержитесь здесь от курения.","vi":"Vui lòng không hút thuốc ở đây.","fa":"لطفا در اینجا از کشیدن سیگار خودداری کنید."},{"de":"Er hat es unterlassen, mich zu informieren.","en":"He failed to inform me.","ru":"Он не удосужился сообщить мне.","vi":"Anh ấy đã quên thông báo cho tôi.","fa":"از اطلاع دادن من غافل شد."}]},{"word":"unternehmen","en":"to undertake, do (an activity)","ru":"предпринимать","vi":"công ty","fa":"شرکت","examples":[{"de":"Was wollen wir heute Abend unternehmen?","en":"What do we want to do tonight?","ru":"Чем мы займёмся сегодня вечером?","vi":"Chúng ta muốn làm gì tối nay?","fa":"امروز عصر می خواهیم چه کنیم؟"},{"de":"Die Regierung muss endlich etwas unternehmen.","en":"The government must finally take action.","ru":"Правительство должно наконец что-то предпринять.","vi":"Chính phủ cuối cùng phải làm điều gì đó.","fa":"بالاخره دولت باید کاری بکند."}]},{"word":"die Unternehmerin","en":"the (female) entrepreneur, businesswoman","ru":"предпринимательница","vi":"doanh nhân","fa":"کارآفرین","examples":[{"de":"Sie ist eine erfolgreiche Unternehmerin.","en":"She is a successful entrepreneur.","ru":"Она успешная предпринимательница.","vi":"Cô ấy là một doanh nhân thành đạt.","fa":"او یک کارآفرین موفق است."},{"de":"Die Unternehmerin hat vor fünf Jahren ihre eigene Firma gegründet.","en":"The businesswoman founded her own company five years ago.","ru":"Предпринимательница основала свою компанию пять лет назад.","vi":"Nữ doanh nhân này đã thành lập công ty riêng của mình cách đây 5 năm.","fa":"این کارآفرین پنج سال پیش شرکت خود را تأسیس کرد."}]},{"word":"unterrichten","en":"to teach","ru":"преподавать","vi":"dạy","fa":"آموزش دهید","examples":[{"de":"Sie unterrichtet Mathematik an einem Gymnasium.","en":"She teaches math at a high school.","ru":"Она преподаёт математику в гимназии.","vi":"Cô dạy toán ở một trường trung học.","fa":"او در دبیرستان ریاضیات تدریس می کند."},{"de":"Wer unterrichtet euch in Deutsch?","en":"Who teaches you German?","ru":"Кто преподаёт вам немецкий?","vi":"Ai dạy bạn tiếng Đức?","fa":"چه کسی به شما آلمانی یاد می دهد؟"}]},{"word":"untersagt","en":"forbidden, prohibited","ru":"запрещено","vi":"bị cấm","fa":"ممنوع است","examples":[{"de":"Das Fotografieren ist hier untersagt.","en":"Photography is prohibited here.","ru":"Фотографировать здесь запрещено.","vi":"Chụp ảnh bị cấm ở đây.","fa":"عکاسی در اینجا ممنوع است."},{"de":"Der Zutritt für Unbefugte ist untersagt.","en":"Access for unauthorized persons is forbidden.","ru":"Вход посторонним запрещён.","vi":"Truy cập cho những người không có thẩm quyền đều bị cấm.","fa":"دسترسی افراد غیر مجاز ممنوع است."}]},{"word":"unterscheiden","en":"to distinguish, differentiate","ru":"различать","vi":"phân biệt","fa":"متمایز کردن","examples":[{"de":"Kannst du diese beiden Weine unterscheiden?","en":"Can you distinguish between these two wines?","ru":"Можешь различить эти два вина?","vi":"Bạn có thể phân biệt được hai loại rượu này không?","fa":"آیا می توانید این دو شراب را از هم جدا کنید؟"},{"de":"Die Zwillinge sind kaum zu unterscheiden.","en":"The twins are hardly distinguishable.","ru":"Близнецов едва можно различить.","vi":"Cặp song sinh khó có thể được phân biệt.","fa":"دوقلوها به سختی قابل تشخیص هستند."}]},{"word":"unterschiedlich","en":"different; varying","ru":"различный; разный","vi":"khác nhau","fa":"متفاوت است","examples":[{"de":"Die Meinungen dazu sind sehr unterschiedlich.","en":"Opinions on this vary widely.","ru":"Мнения по этому поводу очень разные.","vi":"Các ý kiến ​​về điều này rất khác nhau.","fa":"نظرات در این مورد بسیار متفاوت است."},{"de":"Die Zwillinge haben ganz unterschiedliche Charaktere.","en":"The twins have completely different characters.","ru":"У близнецов совершенно разные характеры.","vi":"Cặp song sinh có tính cách rất khác nhau.","fa":"دوقلوها شخصیت های بسیار متفاوتی دارند."}]},{"word":"unterschreiben","en":"to sign","ru":"подписывать","vi":"ký tên","fa":"علامت بزنید","examples":[{"de":"Bitte unterschreiben Sie hier unten.","en":"Please sign here at the bottom.","ru":"Пожалуйста, подпишите здесь внизу.","vi":"Vui lòng ký tên bên dưới.","fa":"لطفا زیر را امضا کنید"},{"de":"Ich habe den Vertrag noch nicht unterschrieben.","en":"I haven't signed the contract yet.","ru":"Я ещё не подписал договор.","vi":"Tôi vẫn chưa ký hợp đồng.","fa":"من هنوز قرارداد را امضا نکرده ام."}]},{"word":"die Unterschrift","en":"the signature","ru":"подпись","vi":"chữ ký","fa":"امضا","examples":[{"de":"Ich brauche noch Ihre Unterschrift.","en":"I still need your signature.","ru":"Мне ещё нужна ваша подпись.","vi":"Tôi vẫn cần chữ ký của bạn.","fa":"من هنوز به امضای شما نیاز دارم"},{"de":"Ohne Unterschrift ist das Dokument ungültig.","en":"Without a signature the document is invalid.","ru":"Без подписи документ недействителен.","vi":"Không có chữ ký, tài liệu không hợp lệ.","fa":"بدون امضا سند نامعتبر است."}]},{"word":"unterstreichen","en":"to underline","ru":"подчёркивать","vi":"gạch chân","fa":"زیر خط بکش","examples":[{"de":"Unterstreiche die wichtigen Wörter im Text.","en":"Underline the important words in the text.","ru":"Подчеркни важные слова в тексте.","vi":"Gạch dưới những từ quan trọng trong văn bản.","fa":"زیر کلمات مهم متن خط بکشید."},{"de":"Der Lehrer hat die Fehler rot unterstrichen.","en":"The teacher underlined the mistakes in red.","ru":"Учитель подчеркнул ошибки красным.","vi":"Giáo viên gạch chân những lỗi sai bằng cách tô đỏ.","fa":"معلم زیر اشتباهات قرمز خط کشید."}]},{"word":"unterstützen","en":"to support","ru":"поддерживать","vi":"hỗ trợ","fa":"پشتیبانی کنید","examples":[{"de":"Meine Eltern unterstützen mich finanziell.","en":"My parents support me financially.","ru":"Мои родители поддерживают меня финансово.","vi":"Bố mẹ tôi hỗ trợ tôi về mặt tài chính.","fa":"پدر و مادرم از من حمایت مالی می کنند."},{"de":"Wir unterstützen dieses Projekt seit Jahren.","en":"We have been supporting this project for years.","ru":"Мы поддерживаем этот проект уже много лет.","vi":"Chúng tôi đã hỗ trợ dự án này trong nhiều năm.","fa":"ما سال ها از این پروژه حمایت می کنیم."}]},{"word":"die Unterstützung","en":"the support","ru":"поддержка","vi":"sự hỗ trợ","fa":"پشتیبانی","examples":[{"de":"Vielen Dank für Ihre Unterstützung!","en":"Thank you very much for your support!","ru":"Большое спасибо за вашу поддержку!","vi":"Cảm ơn sự hỗ trợ của bạn!","fa":"از حمایت شما متشکرم"},{"de":"Ohne die Unterstützung meiner Familie hätte ich es nicht geschafft.","en":"Without my family's support I wouldn't have made it.","ru":"Без поддержки своей семьи я бы не справился.","vi":"Tôi không thể làm được điều đó nếu không có sự hỗ trợ của gia đình.","fa":"بدون حمایت خانواده ام نمی توانستم این کار را انجام دهم."}]},{"word":"untersuchen","en":"to examine, investigate","ru":"исследовать, обследовать","vi":"điều tra","fa":"بررسی کنید","examples":[{"de":"Der Arzt hat mich gründlich untersucht.","en":"The doctor examined me thoroughly.","ru":"Врач тщательно меня осмотрел.","vi":"Bác sĩ đã khám cho tôi rất kỹ.","fa":"دکتر مرا به طور کامل معاینه کرد."},{"de":"Die Polizei untersucht den Fall genau.","en":"The police are investigating the case closely.","ru":"Полиция тщательно расследует это дело.","vi":"Cảnh sát đang điều tra vụ việc chặt chẽ.","fa":"پلیس در حال بررسی دقیق این پرونده است."}]},{"word":"die Untersuchung","en":"examination; investigation","ru":"обследование; исследование","vi":"cuộc điều tra","fa":"تحقیق","examples":[{"de":"Der Arzt empfiehlt eine gründliche Untersuchung.","en":"The doctor recommends a thorough examination.","ru":"Врач рекомендует тщательное обследование.","vi":"Bác sĩ đề nghị kiểm tra kỹ lưỡng.","fa":"پزشک معاینه کامل را توصیه می کند."},{"de":"Die Untersuchung des Unfalls dauert noch an.","en":"The investigation into the accident is still ongoing.","ru":"Расследование аварии всё ещё продолжается.","vi":"Cuộc điều tra về vụ tai nạn vẫn đang được tiếp tục.","fa":"تحقیقات درباره این حادثه همچنان ادامه دارد."}]},{"word":"unterwegs","en":"on the way, out and about","ru":"в пути, в дороге","vi":"trên đường","fa":"در راه","examples":[{"de":"Wir sind schon seit Stunden unterwegs.","en":"We've been on the road for hours already.","ru":"Мы уже несколько часов в пути.","vi":"Chúng tôi đã đi du lịch hàng giờ liền.","fa":"ما ساعت ها در سفر بودیم."},{"de":"Er ist beruflich viel unterwegs.","en":"He travels a lot for work.","ru":"Он много ездит по работе.","vi":"Anh ấy đi công tác rất nhiều.","fa":"او برای کار زیاد سفر می کند."}]},{"word":"die Urkunde","en":"the certificate, document","ru":"грамота, свидетельство","vi":"giấy chứng nhận","fa":"گواهی","examples":[{"de":"Für den Sieg bekam er eine Urkunde.","en":"He got a certificate for winning.","ru":"За победу он получил грамоту.","vi":"Anh đã nhận được giấy chứng nhận chiến thắng.","fa":"او برای این پیروزی گواهینامه دریافت کرد."},{"de":"Die Urkunde wurde von der Stadt ausgestellt.","en":"The certificate was issued by the city.","ru":"Свидетельство было выдано городом.","vi":"Giấy chứng nhận do thành phố cấp.","fa":"این گواهی توسط شهرستان صادر شده است."}]},{"word":"der Urlaub","en":"the vacation, holiday","ru":"отпуск","vi":"kỳ nghỉ","fa":"تعطیلات","examples":[{"de":"Wir fahren im Sommer in den Urlaub.","en":"We're going on vacation in the summer.","ru":"Летом мы едем в отпуск.","vi":"Chúng tôi đang đi nghỉ vào mùa hè.","fa":"ما در تابستان به تعطیلات می رویم."},{"de":"Wie viele Tage Urlaub hast du dieses Jahr?","en":"How many vacation days do you have this year?","ru":"Сколько дней отпуска у тебя в этом году?","vi":"Năm nay bạn có bao nhiêu ngày nghỉ phép?","fa":"امسال چند روز مرخصی دارید؟"}]},{"word":"die Ursache","en":"the cause, reason","ru":"причина","vi":"nguyên nhân","fa":"علت","examples":[{"de":"Die Ursache des Feuers ist noch unbekannt.","en":"The cause of the fire is still unknown.","ru":"Причина пожара пока неизвестна.","vi":"Hiện vẫn chưa rõ nguyên nhân vụ cháy.","fa":"علت آتش سوزی هنوز مشخص نیست."},{"de":"Man konnte die Ursache des Problems nicht finden.","en":"They couldn't find the cause of the problem.","ru":"Не удалось найти причину проблемы.","vi":"Nguyên nhân của vấn đề không thể được tìm thấy.","fa":"علت مشکل پیدا نشد."}]},{"word":"ursprünglich","en":"originally","ru":"изначально, первоначально","vi":"ban đầu","fa":"در اصل","examples":[{"de":"Ursprünglich wollten wir nach Italien fahren.","en":"Originally we wanted to go to Italy.","ru":"Изначально мы хотели поехать в Италию.","vi":"Ban đầu chúng tôi muốn đến Ý.","fa":"در ابتدا می خواستیم به ایتالیا برویم."},{"de":"Das Haus sah ursprünglich ganz anders aus.","en":"The house originally looked completely different.","ru":"Изначально дом выглядел совершенно иначе.","vi":"Ngôi nhà ban đầu trông hoàn toàn khác.","fa":"خانه در ابتدا کاملاً متفاوت به نظر می رسید."}]},{"word":"das Urteil","en":"the verdict, judgment","ru":"приговор, суждение","vi":"bản án","fa":"حکم","examples":[{"de":"Das Gericht hat sein Urteil gefällt.","en":"The court has passed its verdict.","ru":"Суд вынес свой приговор.","vi":"Tòa án đã đưa ra phán quyết của mình.","fa":"دادگاه حکم خود را داده است."},{"de":"Ich möchte mir kein Urteil über ihn erlauben.","en":"I don't want to allow myself to judge him.","ru":"Я не хочу позволять себе судить о нём.","vi":"Tôi không muốn phán xét anh ấy.","fa":"من نمی خواهم او را قضاوت کنم."}]},{"word":"die Vase","en":"the vase","ru":"ваза","vi":"cái bình","fa":"گلدان","examples":[{"de":"Sie stellte die Blumen in eine Vase.","en":"She put the flowers in a vase.","ru":"Она поставила цветы в вазу.","vi":"Cô cắm hoa vào bình.","fa":"او گل ها را در گلدان گذاشت."},{"de":"Die Vase ist aus Glas und sehr zerbrechlich.","en":"The vase is made of glass and very fragile.","ru":"Ваза стеклянная и очень хрупкая.","vi":"Chiếc bình được làm bằng thủy tinh và rất dễ vỡ.","fa":"گلدان شیشه ای است و بسیار شکننده است."}]},{"word":"der Vater","en":"the father","ru":"отец","vi":"người cha","fa":"پدر","examples":[{"de":"Mein Vater arbeitet als Lehrer.","en":"My father works as a teacher.","ru":"Мой отец работает учителем.","vi":"Bố tôi làm giáo viên.","fa":"پدرم به عنوان معلم کار می کند."},{"de":"Er ist stolz auf seinen Vater.","en":"He is proud of his father.","ru":"Он гордится своим отцом.","vi":"Anh ấy tự hào về cha mình.","fa":"او به پدرش افتخار می کند."}]},{"word":"vegetarisch","en":"vegetarian","ru":"вегетарианский","vi":"ăn chay","fa":"گیاهخواری","examples":[{"de":"Ich esse seit einem Jahr vegetarisch.","en":"I've been eating vegetarian for a year.","ru":"Я уже год питаюсь вегетариански.","vi":"Tôi đã ăn chay được một năm.","fa":"من یک سال است که گیاهخواری می کنم."},{"de":"Das Restaurant bietet auch vegetarische Gerichte an.","en":"The restaurant also offers vegetarian dishes.","ru":"Ресторан также предлагает вегетарианские блюда.","vi":"Nhà hàng còn cung cấp các món ăn chay.","fa":"این رستوران غذاهای گیاهی نیز ارائه می دهد."}]},{"word":"das Velo","en":"the bicycle (Swiss German)","ru":"велосипед (в швейцарском варианте немецкого)","vi":"chiếc xe đạp","fa":"دوچرخه","examples":[{"de":"In der Schweiz sagt man 'Velo' statt 'Fahrrad'.","en":"In Switzerland people say 'Velo' instead of 'Fahrrad'.","ru":"В Швейцарии говорят 'Velo' вместо 'Fahrrad'.","vi":"Ở Thụy Sĩ chúng tôi nói 'velo' thay vì 'xe đạp'.","fa":"در سوئیس به جای «دوچرخه» «velo» می گوییم."},{"de":"Ich fahre jeden Tag mit dem Velo zur Arbeit.","en":"I ride my bike to work every day.","ru":"Я каждый день езжу на велосипеде на работу.","vi":"Tôi đạp xe đi làm hàng ngày.","fa":"من هر روز با دوچرخه به سر کار می روم."}]},{"word":"die Veranstaltung","en":"the event","ru":"мероприятие","vi":"sự kiện","fa":"رویداد","examples":[{"de":"Die Veranstaltung findet im Stadtpark statt.","en":"The event takes place in the city park.","ru":"Мероприятие проходит в городском парке.","vi":"Sự kiện diễn ra tại công viên thành phố.","fa":"این رویداد در پارک شهر برگزار می شود."},{"de":"Viele Besucher kamen zu der Veranstaltung.","en":"Many visitors came to the event.","ru":"На мероприятие пришло много посетителей.","vi":"Rất nhiều du khách đã đến tham dự sự kiện.","fa":"بازدیدکنندگان زیادی به این رویداد آمدند."}]},{"word":"verantwortlich","en":"responsible","ru":"ответственный","vi":"chịu trách nhiệm","fa":"مسئول","examples":[{"de":"Wer ist für dieses Projekt verantwortlich?","en":"Who is responsible for this project?","ru":"Кто отвечает за этот проект?","vi":"Ai chịu trách nhiệm cho dự án này?","fa":"چه کسی مسئول این پروژه است؟"},{"de":"Sie fühlt sich für ihre Mitarbeiter verantwortlich.","en":"She feels responsible for her employees.","ru":"Она чувствует ответственность за своих сотрудников.","vi":"Cô ấy cảm thấy có trách nhiệm với nhân viên của mình.","fa":"او نسبت به کارمندان خود احساس مسئولیت می کند."}]},{"word":"die Verantwortung","en":"responsibility","ru":"ответственность","vi":"trách nhiệm","fa":"مسئولیت","examples":[{"de":"Als Chef trägt er die Verantwortung für das ganze Team.","en":"As the boss, he bears responsibility for the whole team.","ru":"Как начальник, он несёт ответственность за всю команду.","vi":"Là ông chủ, anh ấy chịu trách nhiệm cho toàn bộ đội.","fa":"به عنوان رئیس، او مسئول کل تیم است."},{"de":"Niemand wollte die Verantwortung für den Fehler übernehmen.","en":"Nobody wanted to take responsibility for the mistake.","ru":"Никто не хотел брать на себя ответственность за ошибку.","vi":"Không ai muốn chịu trách nhiệm về sai lầm.","fa":"هیچ کس نمی خواست مسئولیت این اشتباه را بپذیرد."}]},{"word":"verbieten","en":"to forbid, prohibit","ru":"запрещать","vi":"lệnh cấm","fa":"ممنوع کردن","examples":[{"de":"Meine Eltern haben mir das Rauchen verboten.","en":"My parents forbade me to smoke.","ru":"Мои родители запретили мне курить.","vi":"Bố mẹ tôi cấm tôi hút thuốc.","fa":"پدر و مادرم من را از کشیدن سیگار منع کردند."},{"de":"Hier ist das Parken verboten.","en":"Parking is forbidden here.","ru":"Здесь парковка запрещена.","vi":"Bãi đậu xe bị cấm ở đây.","fa":"پارک کردن در اینجا ممنوع است."}]},{"word":"verbinden","en":"to connect, link","ru":"соединять","vi":"kết nối","fa":"اتصال","examples":[{"de":"Die Brücke verbindet die beiden Stadtteile.","en":"The bridge connects the two city districts.","ru":"Мост соединяет два района города.","vi":"Cây cầu nối hai phần của thành phố.","fa":"این پل دو قسمت شهر را به هم متصل می کند."},{"de":"Können Sie mich bitte mit Herrn Müller verbinden?","en":"Could you please connect me to Mr. Müller?","ru":"Не могли бы вы соединить меня с господином Мюллером?","vi":"Bạn có thể vui lòng kết nối tôi với ông Müller được không?","fa":"میشه لطفا من رو با آقای مولر وصل کنید؟"}]},{"word":"der Verbrauch","en":"consumption","ru":"потребление; расход","vi":"sự tiêu thụ","fa":"مصرف","examples":[{"de":"Dieses Auto hat einen niedrigen Verbrauch.","en":"This car has low fuel consumption.","ru":"У этой машины низкий расход топлива.","vi":"Chiếc xe này có mức tiêu thụ thấp.","fa":"این خودرو کم مصرف است."},{"de":"Wir versuchen, unseren Verbrauch von Strom zu senken.","en":"We are trying to reduce our electricity consumption.","ru":"Мы стараемся снизить потребление электроэнергии.","vi":"Chúng tôi đang cố gắng giảm mức tiêu thụ điện.","fa":"تلاش می کنیم مصرف برق را کاهش دهیم."}]},{"word":"verbrauchen","en":"to consume, use up","ru":"расходовать, потреблять","vi":"tiêu thụ","fa":"مصرف کنند","examples":[{"de":"Unser Auto verbraucht wenig Benzin.","en":"Our car uses little gasoline.","ru":"Наша машина потребляет мало бензина.","vi":"Xe của chúng tôi sử dụng ít xăng.","fa":"ماشین ما بنزین کمی مصرف می کند."},{"de":"Wir haben schon das ganze Wasser verbraucht.","en":"We've already used up all the water.","ru":"Мы уже израсходовали всю воду.","vi":"Chúng tôi đã sử dụng hết nước rồi.","fa":"ما قبلاً از تمام آب استفاده کرده ایم."}]},{"word":"der Verbrecher","en":"the criminal","ru":"преступник","vi":"tên tội phạm","fa":"جنایتکار","examples":[{"de":"Die Polizei hat den Verbrecher gefasst.","en":"The police caught the criminal.","ru":"Полиция поймала преступника.","vi":"Cảnh sát đã bắt được tội phạm.","fa":"پلیس جنایتکار را دستگیر کرد."},{"de":"Der Verbrecher wurde zu fünf Jahren Haft verurteilt.","en":"The criminal was sentenced to five years in prison.","ru":"Преступника приговорили к пяти годам заключения.","vi":"Tên tội phạm đã bị kết án năm năm tù.","fa":"مجرم به پنج سال زندان محکوم شد."}]},{"word":"verbringen","en":"to spend (time)","ru":"проводить (время)","vi":"chi tiêu","fa":"خرج کردن","examples":[{"de":"Wir haben den Urlaub am Meer verbracht.","en":"We spent the vacation at the sea.","ru":"Мы провели отпуск на море.","vi":"Chúng tôi đã trải qua kỳ nghỉ bên bờ biển.","fa":"تعطیلات را کنار دریا گذراندیم."},{"de":"Sie verbringt viel Zeit mit ihren Kindern.","en":"She spends a lot of time with her children.","ru":"Она проводит много времени со своими детьми.","vi":"Cô dành nhiều thời gian cho con cái.","fa":"او زمان زیادی را با فرزندانش می گذراند."}]},{"word":"der Verdacht","en":"the suspicion","ru":"подозрение","vi":"sự nghi ngờ","fa":"سوء ظن","examples":[{"de":"Die Polizei hat einen Verdacht gegen ihn.","en":"The police have a suspicion against him.","ru":"У полиции есть подозрение против него.","vi":"Cảnh sát có những nghi ngờ chống lại anh ta.","fa":"پلیس به او مشکوک است."},{"de":"Es besteht der Verdacht, dass er gelogen hat.","en":"There is a suspicion that he lied.","ru":"Есть подозрение, что он солгал.","vi":"Có nghi ngờ rằng anh ta đã nói dối.","fa":"این شبهه وجود دارد که او دروغ گفته است."}]},{"word":"verdienen","en":"to earn","ru":"зарабатывать","vi":"kiếm tiền","fa":"کسب کنید","examples":[{"de":"Sie verdient sehr gut in ihrem neuen Job.","en":"She earns very well in her new job.","ru":"Она очень хорошо зарабатывает на новой работе.","vi":"Cô ấy kiếm được rất tốt trong công việc mới của mình.","fa":"او در شغل جدیدش درآمد بسیار خوبی دارد."},{"de":"Er verdient nicht genug, um eine Familie zu ernähren.","en":"He doesn't earn enough to support a family.","ru":"Он зарабатывает недостаточно, чтобы содержать семью.","vi":"Anh ấy không kiếm đủ tiền để nuôi sống gia đình.","fa":"او آنقدر درآمد ندارد که بتواند خانواده اش را تامین کند."}]},{"word":"der Verein","en":"the club, association","ru":"клуб, объединение","vi":"câu lạc bộ","fa":"باشگاه","examples":[{"de":"Ich bin Mitglied in einem Sportverein.","en":"I am a member of a sports club.","ru":"Я член спортивного клуба.","vi":"Tôi là thành viên của một câu lạc bộ thể thao.","fa":"من عضو یک باشگاه ورزشی هستم."},{"de":"Der Verein organisiert jedes Jahr ein großes Fest.","en":"The club organizes a big festival every year.","ru":"Клуб каждый год организует большой праздник.","vi":"Câu lạc bộ tổ chức một lễ hội lớn hàng năm.","fa":"این باشگاه هر ساله یک جشنواره بزرگ برگزار می کند."}]},{"word":"vereinbaren","en":"to agree on, arrange","ru":"договариваться, согласовывать","vi":"đồng ý","fa":"موافق","examples":[{"de":"Wir haben einen Termin für nächste Woche vereinbart.","en":"We arranged an appointment for next week.","ru":"Мы договорились о встрече на следующую неделю.","vi":"Chúng tôi đã hẹn nhau vào tuần tới.","fa":"برای هفته آینده قرار گذاشتیم."},{"de":"Können wir einen anderen Preis vereinbaren?","en":"Can we agree on a different price?","ru":"Можем мы договориться о другой цене?","vi":"Chúng ta có thể thỏa thuận một mức giá khác được không?","fa":"آیا می توانیم روی قیمت متفاوتی به توافق برسیم؟"}]},{"word":"die Vergangenheit","en":"the past","ru":"прошлое","vi":"quá khứ","fa":"گذشته","examples":[{"de":"In der Vergangenheit war das Leben hier viel schwerer.","en":"In the past, life here was much harder.","ru":"В прошлом жизнь здесь была намного тяжелее.","vi":"Ngày xưa cuộc sống ở đây khó khăn hơn nhiều.","fa":"در گذشته زندگی اینجا خیلی سخت تر بود."},{"de":"Er spricht selten über seine Vergangenheit.","en":"He rarely talks about his past.","ru":"Он редко говорит о своём прошлом.","vi":"Anh ấy hiếm khi nói về quá khứ của mình.","fa":"او به ندرت از گذشته خود صحبت می کند."}]},{"word":"vergeblich","en":"in vain, futile","ru":"напрасный, тщетный","vi":"vô ích","fa":"بیهوده","examples":[{"de":"Alle Versuche waren vergeblich.","en":"All attempts were in vain.","ru":"Все попытки были напрасны.","vi":"Mọi nỗ lực đều vô ích.","fa":"همه تلاش ها بی نتیجه بود."},{"de":"Wir haben vergeblich auf ihn gewartet.","en":"We waited for him in vain.","ru":"Мы напрасно ждали его.","vi":"Chúng tôi chờ đợi anh ấy trong vô vọng.","fa":"بیهوده منتظرش بودیم."}]},{"word":"vergessen","en":"to forget","ru":"забывать","vi":"bị lãng quên","fa":"فراموش شده","examples":[{"de":"Ich habe meinen Regenschirm zu Hause vergessen.","en":"I forgot my umbrella at home.","ru":"Я забыл дома свой зонт.","vi":"Tôi quên ô ở nhà.","fa":"چترم را در خانه فراموش کردم."},{"de":"Vergiss nicht, die Tür abzuschließen!","en":"Don't forget to lock the door!","ru":"Не забудь запереть дверь!","vi":"Đừng quên khóa cửa!","fa":"فراموش نکنید که در را قفل کنید!"}]},{"word":"vergleichen","en":"to compare","ru":"сравнивать","vi":"so sánh","fa":"مقایسه کنید","examples":[{"de":"Man kann die beiden Angebote nicht direkt vergleichen.","en":"You can't directly compare the two offers.","ru":"Нельзя напрямую сравнивать эти два предложения.","vi":"Bạn không thể so sánh trực tiếp hai ưu đãi.","fa":"شما نمی توانید این دو پیشنهاد را مستقیماً مقایسه کنید."},{"de":"Vergleich die Preise, bevor du etwas kaufst.","en":"Compare the prices before you buy something.","ru":"Сравни цены, прежде чем что-то покупать.","vi":"So sánh giá trước khi bạn mua bất cứ điều gì.","fa":"قبل از خرید هر چیزی قیمت ها را مقایسه کنید."}]},{"word":"vergrößern","en":"to enlarge, to increase","ru":"увеличивать","vi":"phóng to","fa":"بزرگ کردن","examples":[{"de":"Der Fotograf möchte das Bild vergrößern lassen.","en":"The photographer wants to have the picture enlarged.","ru":"Фотограф хочет увеличить фотографию.","vi":"Nhiếp ảnh gia muốn hình ảnh được phóng to.","fa":"عکاس می خواهد تصویر بزرگ شود."},{"de":"Die Firma plant, ihre Produktion zu vergrößern.","en":"The company plans to increase its production.","ru":"Компания планирует увеличить производство.","vi":"Công ty có kế hoạch mở rộng sản xuất.","fa":"این شرکت قصد دارد تولید خود را گسترش دهد."}]},{"word":"verhaften","en":"to arrest","ru":"арестовывать","vi":"bắt giữ","fa":"دستگیری","examples":[{"de":"Die Polizei hat den Dieb verhaftet.","en":"The police arrested the thief.","ru":"Полиция арестовала вора.","vi":"Cảnh sát đã bắt giữ tên trộm.","fa":"پلیس سارق را دستگیر کرد."},{"de":"Er wurde wegen Betrugs verhaftet.","en":"He was arrested for fraud.","ru":"Его арестовали за мошенничество.","vi":"Anh ta bị bắt vì tội lừa đảo.","fa":"به جرم کلاهبرداری دستگیر شد."}]},{"word":"das Verhältnis","en":"relationship; ratio","ru":"отношение; соотношение","vi":"mối quan hệ","fa":"رابطه","examples":[{"de":"Sie hat ein gutes Verhältnis zu ihren Eltern.","en":"She has a good relationship with her parents.","ru":"У неё хорошие отношения с родителями.","vi":"Cô ấy có mối quan hệ tốt với bố mẹ mình.","fa":"او رابطه خوبی با پدر و مادرش دارد."},{"de":"Das Verhältnis von Preis und Leistung stimmt hier nicht.","en":"The price-to-performance ratio isn't right here.","ru":"Соотношение цены и качества здесь не соответствует.","vi":"Mối quan hệ giữa giá cả và hiệu suất không ổn ở đây.","fa":"رابطه بین قیمت و عملکرد در اینجا درست نیست."}]},{"word":"verheiratet","en":"married","ru":"женатый / замужняя","vi":"kết hôn","fa":"متاهل","examples":[{"de":"Meine Schwester ist seit fünf Jahren verheiratet.","en":"My sister has been married for five years.","ru":"Моя сестра замужем уже пять лет.","vi":"Chị gái tôi đã lấy chồng được năm năm.","fa":"خواهر من پنج سال است که ازدواج کرده است."},{"de":"Sind Sie verheiratet oder ledig?","en":"Are you married or single?","ru":"Вы женаты/замужем или холосты/не замужем?","vi":"Bạn đang độc thân hay đã kết hôn?","fa":"متاهل هستی یا مجرد؟"}]},{"word":"verhindern","en":"to prevent","ru":"предотвращать","vi":"ngăn chặn","fa":"جلوگیری کند","examples":[{"de":"Wir konnten den Unfall leider nicht verhindern.","en":"Unfortunately, we couldn't prevent the accident.","ru":"К сожалению, мы не смогли предотвратить аварию.","vi":"Thật không may, chúng tôi đã không thể ngăn chặn vụ tai nạn.","fa":"متاسفانه نتوانستیم از وقوع حادثه جلوگیری کنیم."},{"de":"Regelmäßiges Händewaschen kann Infektionen verhindern.","en":"Regular handwashing can prevent infections.","ru":"Регулярное мытьё рук может предотвратить инфекции.","vi":"Rửa tay thường xuyên có thể ngăn ngừa nhiễm trùng.","fa":"شستن مرتب دست ها می تواند از عفونت جلوگیری کند."}]},{"word":"verkaufen","en":"to sell","ru":"продавать","vi":"bán","fa":"فروش","examples":[{"de":"Er will sein altes Auto verkaufen.","en":"He wants to sell his old car.","ru":"Он хочет продать свою старую машину.","vi":"Anh ấy muốn bán chiếc xe cũ của mình.","fa":"او می خواهد ماشین قدیمی خود را بفروشد."},{"de":"Im Laden werden frisches Obst und Gemüse verkauft.","en":"Fresh fruit and vegetables are sold in the shop.","ru":"В магазине продают свежие фрукты и овощи.","vi":"Trái cây và rau quả tươi được bán trong cửa hàng.","fa":"میوه و سبزیجات تازه در مغازه به فروش می رسد."}]},{"word":"der Verkäufer","en":"salesman, shop assistant","ru":"продавец","vi":"người bán","fa":"فروشنده","examples":[{"de":"Der Verkäufer half mir bei der Auswahl der Schuhe.","en":"The salesman helped me choose the shoes.","ru":"Продавец помог мне выбрать обувь.","vi":"Người bán đã giúp tôi chọn giày.","fa":"فروشنده به من در انتخاب کفش کمک کرد."},{"de":"Der Verkäufer im Elektronikladen war sehr freundlich.","en":"The salesman in the electronics store was very friendly.","ru":"Продавец в магазине электроники был очень дружелюбным.","vi":"Nhân viên bán hàng ở cửa hàng điện máy rất thân thiện.","fa":"فروشنده در فروشگاه لوازم الکترونیکی بسیار خوش برخورد بود."}]},{"word":"der Verkehr","en":"traffic","ru":"движение, транспорт","vi":"giao thông","fa":"ترافیک","examples":[{"de":"Der Verkehr in der Innenstadt ist heute sehr stark.","en":"Traffic in the city center is very heavy today.","ru":"Движение в центре города сегодня очень плотное.","vi":"Giao thông ở trung tâm thành phố ngày nay rất đông đúc.","fa":"امروز ترافیک در مرکز شهر بسیار سنگین است."},{"de":"Wegen des Unfalls kam es zu einem Stau im Verkehr.","en":"Because of the accident there was a traffic jam.","ru":"Из-за аварии образовалась пробка в движении.","vi":"Vụ tai nạn khiến giao thông ùn tắc.","fa":"این تصادف باعث ایجاد ترافیک شد."}]},{"word":"das Verkehrszeichen","en":"traffic sign","ru":"дорожный знак","vi":"biển báo giao thông","fa":"علامت راهنمایی و رانندگی","examples":[{"de":"Beachte immer die Verkehrszeichen auf der Straße.","en":"Always pay attention to the traffic signs on the road.","ru":"Всегда обращай внимание на дорожные знаки.","vi":"Luôn chú ý đến các biển báo giao thông trên đường.","fa":"همیشه به علائم راهنمایی و رانندگی در جاده توجه کنید."},{"de":"Dieses Verkehrszeichen bedeutet Vorfahrt gewähren.","en":"This traffic sign means yield.","ru":"Этот дорожный знак означает «уступи дорогу».","vi":"Biển báo giao thông này có nghĩa là nhường đường.","fa":"این علامت راهنمایی و رانندگی به معنای راه دادن است."}]},{"word":"der Verlag","en":"publishing house, publisher","ru":"издательство","vi":"nhà xuất bản","fa":"ناشر","examples":[{"de":"Das Buch erscheint in einem bekannten Verlag.","en":"The book is being published by a well-known publisher.","ru":"Книга выходит в известном издательстве.","vi":"Sách được xuất bản bởi một nhà xuất bản nổi tiếng.","fa":"این کتاب توسط یک ناشر معروف منتشر شده است."},{"de":"Sie arbeitet als Lektorin bei einem Verlag.","en":"She works as an editor at a publishing house.","ru":"Она работает редактором в издательстве.","vi":"Cô ấy làm biên tập viên ở một nhà xuất bản.","fa":"او به عنوان ویراستار در یک انتشارات کار می کند."}]},{"word":"verlangen","en":"to demand, to require","ru":"требовать","vi":"nhu cầu","fa":"تقاضا","examples":[{"de":"Der Chef verlangt pünktliches Erscheinen.","en":"The boss demands punctual arrival.","ru":"Начальник требует приходить вовремя.","vi":"Sếp yêu cầu bạn phải đến đúng giờ.","fa":"رئیس از شما می خواهد که به موقع برسید."},{"de":"Diese Arbeit verlangt viel Geduld.","en":"This work requires a lot of patience.","ru":"Эта работа требует большого терпения.","vi":"Công việc này đòi hỏi rất nhiều sự kiên nhẫn.","fa":"این کار به صبر و حوصله زیادی نیاز دارد."}]},{"word":"verlängern","en":"to extend, to prolong","ru":"продлевать","vi":"mở rộng","fa":"تمدید کنید","examples":[{"de":"Ich möchte meinen Vertrag um ein Jahr verlängern.","en":"I would like to extend my contract by one year.","ru":"Я хотел бы продлить свой договор на год.","vi":"Tôi muốn gia hạn hợp đồng thêm một năm.","fa":"دوست دارم قراردادم را یک سال تمدید کنم."},{"de":"Kannst du bitte meinen Aufenthalt im Hotel verlängern?","en":"Could you please extend my stay at the hotel?","ru":"Не могли бы вы продлить моё проживание в отеле?","vi":"Bạn có thể vui lòng kéo dài thời gian lưu trú của tôi tại khách sạn được không?","fa":"لطفاً می توانید اقامت من در هتل را تمدید کنید؟"}]},{"word":"verlassen","en":"to leave","ru":"покидать","vi":"rời đi","fa":"ترک","examples":[{"de":"Er hat das Haus früh am Morgen verlassen.","en":"He left the house early in the morning.","ru":"Он покинул дом рано утром.","vi":"Anh rời khỏi nhà vào sáng sớm.","fa":"صبح زود از خانه بیرون رفت."},{"de":"Sie musste ihre Heimatstadt wegen der Arbeit verlassen.","en":"She had to leave her hometown because of work.","ru":"Ей пришлось покинуть родной город из-за работы.","vi":"Cô phải rời quê hương để đi làm.","fa":"او مجبور شد برای کار زادگاهش را ترک کند."}]},{"word":"verlieren","en":"to lose","ru":"терять; проигрывать","vi":"thua","fa":"از دست دادن","examples":[{"de":"Ich habe meinen Schlüssel verloren.","en":"I lost my key.","ru":"Я потерял свой ключ.","vi":"Tôi bị mất chìa khóa.","fa":"کلیدم را گم کردم"},{"de":"Unsere Mannschaft hat das Spiel knapp verloren.","en":"Our team narrowly lost the game.","ru":"Наша команда с небольшим отрывом проиграла игру.","vi":"Đội của chúng tôi suýt thua trận.","fa":"تیم ما بازی را با اختلاف کمی باخت."}]},{"word":"vermeiden","en":"to avoid","ru":"избегать","vi":"tránh","fa":"اجتناب کنید","examples":[{"de":"Er versucht, Stress im Alltag zu vermeiden.","en":"He tries to avoid stress in everyday life.","ru":"Он старается избегать стресса в повседневной жизни.","vi":"Anh ấy cố gắng tránh căng thẳng trong cuộc sống hàng ngày.","fa":"او سعی می کند از استرس در زندگی روزمره خودداری کند."},{"de":"Um Fehler zu vermeiden, sollten Sie die Anleitung lesen.","en":"To avoid mistakes, you should read the instructions.","ru":"Чтобы избежать ошибок, вам следует прочитать инструкцию.","vi":"Để tránh sai sót, bạn nên đọc hướng dẫn.","fa":"برای جلوگیری از اشتباه، باید دستورالعمل ها را بخوانید."}]},{"word":"vermieten","en":"to rent out, to let","ru":"сдавать в аренду","vi":"thuê","fa":"اجاره","examples":[{"de":"Die Familie vermietet ein Zimmer an Studenten.","en":"The family rents out a room to students.","ru":"Семья сдаёт комнату студентам.","vi":"Gia đình cho sinh viên thuê phòng.","fa":"خانواده اتاقی را به دانش آموزان اجاره می دهند."},{"de":"Wir vermieten unsere Wohnung während des Urlaubs.","en":"We rent out our apartment during the vacation.","ru":"Мы сдаём свою квартиру во время отпуска.","vi":"Chúng tôi thuê căn hộ của mình khi đi nghỉ.","fa":"ما در تعطیلات آپارتمان خود را اجاره می دهیم."}]},{"word":"der Vermieter","en":"landlord","ru":"арендодатель; хозяин квартиры","vi":"chủ nhà","fa":"صاحبخانه","examples":[{"de":"Der Vermieter hat die Miete schon wieder erhöht.","en":"The landlord has raised the rent again.","ru":"Арендодатель снова поднял плату.","vi":"Chủ nhà lại tăng tiền thuê nhà rồi.","fa":"صاحبخانه قبلاً اجاره را دوباره افزایش داده است."},{"de":"Bei Problemen mit der Heizung rufe ich den Vermieter an.","en":"If there are problems with the heating, I call the landlord.","ru":"Если возникают проблемы с отоплением, я звоню арендодателю.","vi":"Nếu tôi gặp vấn đề với hệ thống sưởi, tôi sẽ gọi cho chủ nhà.","fa":"اگر با گرمایش مشکلی داشته باشم با صاحبخانه تماس می گیرم."}]},{"word":"vermissen","en":"to miss (someone/something)","ru":"скучать (по кому-то), недосчитаться","vi":"nhớ","fa":"خانم","examples":[{"de":"Ich vermisse meine Familie sehr, seit ich im Ausland lebe.","en":"I miss my family a lot since I've been living abroad.","ru":"Я очень скучаю по семье с тех пор, как живу за границей.","vi":"Tôi nhớ gia đình tôi rất nhiều kể từ khi tôi sống ở nước ngoài.","fa":"از زمانی که خارج از کشور زندگی می کنم دلم برای خانواده ام بسیار تنگ شده است."},{"de":"Er hat erst später bemerkt, dass er seine Brille vermisst.","en":"He only noticed later that his glasses were missing.","ru":"Он заметил лишь позже, что не хватает его очков.","vi":"Sau này anh mới nhận ra rằng mình đã đánh mất chiếc kính.","fa":"او فقط بعداً متوجه شد که عینکش را از دست داده است."}]},{"word":"die Vermittlung","en":"mediation; agency","ru":"посредничество; агентство","vi":"sự hòa giải","fa":"میانجیگری","examples":[{"de":"Durch die Vermittlung eines Freundes fand sie eine neue Stelle.","en":"Through a friend's mediation, she found a new job.","ru":"Благодаря посредничеству друга она нашла новую работу.","vi":"Nhờ sự giúp đỡ của một người bạn, cô đã tìm được một công việc mới.","fa":"او با کمک یکی از دوستانش شغل جدیدی پیدا کرد."},{"de":"Die Wohnung wurde über eine Vermittlung gefunden.","en":"The apartment was found through an agency.","ru":"Квартиру нашли через агентство.","vi":"Căn hộ được tìm thấy thông qua một cơ quan.","fa":"آپارتمان از طریق آژانس پیدا شد."}]},{"word":"vermuten","en":"to suspect, to assume","ru":"предполагать","vi":"nghi ngờ","fa":"مشکوک","examples":[{"de":"Ich vermute, dass er den Termin vergessen hat.","en":"I suspect that he forgot the appointment.","ru":"Я предполагаю, что он забыл о встрече.","vi":"Tôi nghi ngờ anh ấy đã quên cuộc hẹn.","fa":"من فکر می کنم او قرار ملاقات را فراموش کرده است."},{"de":"Die Polizei vermutet einen Zusammenhang zwischen den beiden Fällen.","en":"The police suspect a connection between the two cases.","ru":"Полиция предполагает связь между этими двумя делами.","vi":"Cảnh sát nghi ngờ có mối liên hệ giữa hai vụ án.","fa":"پلیس به ارتباط بین این دو مورد مشکوک است."}]},{"word":"vernünftig","en":"reasonable, sensible","ru":"разумный","vi":"hợp lý","fa":"منطقی","examples":[{"de":"Sei vernünftig und iss nicht so viel Süßes.","en":"Be sensible and don't eat so much candy.","ru":"Будь благоразумен и не ешь так много сладкого.","vi":"Hãy tỉnh táo và đừng ăn quá nhiều đồ ngọt.","fa":"عاقل باشید و اینقدر شیرینی نخورید."},{"de":"Das war eine vernünftige Entscheidung.","en":"That was a reasonable decision.","ru":"Это было разумное решение.","vi":"Đó là một quyết định sáng suốt.","fa":"این یک تصمیم معقول بود."}]},{"word":"veröffentlichen","en":"to publish","ru":"публиковать","vi":"xuất bản","fa":"منتشر کند","examples":[{"de":"Der Autor hat sein neues Buch veröffentlicht.","en":"The author published his new book.","ru":"Автор опубликовал свою новую книгу.","vi":"Tác giả đã xuất bản cuốn sách mới của mình.","fa":"این نویسنده کتاب جدید خود را منتشر کرده است."},{"de":"Die Fotos wurden im Internet veröffentlicht.","en":"The photos were published on the internet.","ru":"Фотографии были опубликованы в интернете.","vi":"Những bức ảnh được công bố trên Internet.","fa":"عکس ها در اینترنت منتشر شد."}]},{"word":"verpacken","en":"to pack, to wrap","ru":"упаковывать","vi":"gói","fa":"بسته","examples":[{"de":"Sie hat die Geschenke schön verpackt.","en":"She wrapped the presents nicely.","ru":"Она красиво упаковала подарки.","vi":"Cô gói quà thật đẹp.","fa":"او کادوها را به زیبایی پیچید."},{"de":"Die Ware wird sicher verpackt und verschickt.","en":"The goods are securely packed and shipped.","ru":"Товар надёжно упаковывают и отправляют.","vi":"Hàng hóa sẽ được đóng gói và vận chuyển an toàn.","fa":"کالا به صورت ایمن بسته بندی و ارسال می شود."}]},{"word":"verpassen","en":"to miss (a bus, opportunity, etc.)","ru":"упустить, опоздать на","vi":"nhớ","fa":"خانم","examples":[{"de":"Ich habe den Bus verpasst und musste laufen.","en":"I missed the bus and had to walk.","ru":"Я опоздал на автобус и пришлось идти пешком.","vi":"Tôi bị lỡ xe buýt và phải đi bộ.","fa":"اتوبوس را از دست دادم و مجبور شدم پیاده بروم."},{"de":"Verpass nicht die Chance, dich zu bewerben!","en":"Don't miss the chance to apply!","ru":"Не упусти шанс подать заявку!","vi":"Đừng bỏ lỡ cơ hội ứng tuyển!","fa":"فرصت درخواست را از دست ندهید!"}]},{"word":"verpflegen","en":"to feed, to cater for","ru":"обеспечивать питанием","vi":"phục vụ","fa":"تهیه کردن","examples":[{"de":"Im Hotel werden die Gäste mit Halbpension verpflegt.","en":"At the hotel, guests are catered for with half board.","ru":"В отеле гостей обеспечивают питанием по системе полупансион.","vi":"Trong khách sạn, khách được cung cấp bao bữa sáng và tối.","fa":"در هتل به میهمانان با نیم تخته ارائه می شود."},{"de":"Die Helfer verpflegten die Flüchtlinge mit warmem Essen.","en":"The helpers provided the refugees with warm food.","ru":"Волонтёры обеспечивали беженцев горячей едой.","vi":"Những người giúp đỡ đã cung cấp thức ăn ấm cho người tị nạn.","fa":"امدادگران غذای گرم برای پناهندگان فراهم کردند."}]},{"word":"verpflichtet","en":"obliged, committed","ru":"обязан","vi":"bắt buộc","fa":"موظف است","examples":[{"de":"Als Mieter sind Sie verpflichtet, die Miete pünktlich zu zahlen.","en":"As a tenant, you are obliged to pay the rent on time.","ru":"Как арендатор вы обязаны вовремя платить арендную плату.","vi":"Là người thuê nhà, bạn có nghĩa vụ phải trả tiền thuê đúng hạn.","fa":"شما به عنوان مستاجر موظف هستید اجاره بها را به موقع پرداخت کنید."},{"de":"Ich fühle mich ihm gegenüber sehr verpflichtet.","en":"I feel very obligated to him.","ru":"Я чувствую себя очень обязанным перед ним.","vi":"Tôi cảm thấy có nghĩa vụ lớn lao với anh ấy.","fa":"نسبت به او احساس وظیفه بزرگی می کنم."}]},{"word":"verraten","en":"to betray; to reveal (a secret)","ru":"предавать; выдавать (тайну)","vi":"bị phản bội","fa":"خیانت کرده","examples":[{"de":"Er hat seinen besten Freund verraten.","en":"He betrayed his best friend.","ru":"Он предал своего лучшего друга.","vi":"Anh ta đã phản bội người bạn thân nhất của mình.","fa":"او به بهترین دوستش خیانت کرد."},{"de":"Verrate mir nicht, wie der Film endet!","en":"Don't tell me how the movie ends!","ru":"Не выдавай мне, чем закончится фильм!","vi":"Đừng nói cho tôi biết bộ phim kết thúc như thế nào!","fa":"به من نگو ​​فیلم چگونه تمام می شود!"}]},{"word":"verreisen","en":"to go on a trip, to travel away","ru":"уезжать в поездку","vi":"du lịch","fa":"سفر","examples":[{"de":"Wir verreisen dieses Jahr im Sommer nach Italien.","en":"We're going on a trip to Italy this summer.","ru":"В этом году летом мы уезжаем в Италию.","vi":"Chúng tôi đang đi du lịch đến Ý vào mùa hè này.","fa":"تابستان امسال به ایتالیا سفر می کنیم."},{"de":"Meine Nachbarn sind für zwei Wochen verreist.","en":"My neighbors have gone away for two weeks.","ru":"Мои соседи уехали на две недели.","vi":"Hàng xóm của tôi đã đi vắng được hai tuần.","fa":"همسایه های من دو هفته رفتند."}]},{"word":"verringern","en":"to reduce; to lessen","ru":"уменьшать; сокращать","vi":"giảm bớt","fa":"کاهش دهد","examples":[{"de":"Wir müssen unseren Müll deutlich verringern.","en":"We have to significantly reduce our waste.","ru":"Мы должны существенно сократить количество мусора.","vi":"Chúng ta cần giảm đáng kể chất thải của mình.","fa":"ما باید زباله های خود را به میزان قابل توجهی کاهش دهیم."},{"de":"Durch die neue Regel verringerte sich die Zahl der Unfälle.","en":"The new rule reduced the number of accidents.","ru":"Благодаря новому правилу число аварий уменьшилось.","vi":"Quy định mới làm giảm số vụ tai nạn.","fa":"قانون جدید تعداد تصادفات را کاهش داد."}]},{"word":"verrückt","en":"crazy","ru":"сумасшедший","vi":"điên rồ","fa":"دیوانه","examples":[{"de":"Das ist eine verrückte Idee, aber sie könnte funktionieren.","en":"That's a crazy idea, but it might work.","ru":"Это сумасшедшая идея, но она может сработать.","vi":"Đó là một ý tưởng điên rồ, nhưng nó có thể thành công.","fa":"این یک ایده دیوانه کننده است، اما می تواند کار کند."},{"de":"Er wird verrückt, wenn er im Stau steht.","en":"He goes crazy when he's stuck in traffic.","ru":"Он сходит с ума, когда стоит в пробке.","vi":"Anh ấy phát điên khi bị kẹt xe.","fa":"وقتی در ترافیک گیر می کند دیوانه می شود."}]},{"word":"die Versammlung","en":"assembly, meeting","ru":"собрание","vi":"hội đồng","fa":"مجمع","examples":[{"de":"Die Bewohner treffen sich zur jährlichen Versammlung.","en":"The residents meet for the annual assembly.","ru":"Жители собираются на ежегодное собрание.","vi":"Các cư dân họp mặt trong cuộc họp thường niên.","fa":"ساکنان برای جلسه سالانه گرد هم می آیند."},{"de":"In der Versammlung wurden wichtige Entscheidungen getroffen.","en":"Important decisions were made at the meeting.","ru":"На собрании были приняты важные решения.","vi":"Các quyết định quan trọng đã được đưa ra trong cuộc họp.","fa":"در این جلسه تصمیمات مهمی اتخاذ شد."}]},{"word":"versäumen","en":"to miss, to fail to do (something)","ru":"упустить, пропустить","vi":"nhớ","fa":"خانم","examples":[{"de":"Er hat es versäumt, sich rechtzeitig anzumelden.","en":"He failed to register in time.","ru":"Он не успел вовремя зарегистрироваться.","vi":"Anh ấy đã không đăng ký đúng hạn.","fa":"او نتوانست به موقع ثبت نام کند."},{"de":"Wegen Krankheit hat sie viele Schulstunden versäumt.","en":"Due to illness, she missed many school lessons.","ru":"Из-за болезни она пропустила много уроков.","vi":"Cô đã bỏ lỡ nhiều bài học ở trường vì bệnh tật.","fa":"او بسیاری از دروس مدرسه را به دلیل بیماری از دست داد."}]},{"word":"verschieben","en":"to postpone; to move, shift","ru":"переносить, откладывать; сдвигать","vi":"di chuyển","fa":"حرکت کنید","examples":[{"de":"Wir müssen das Treffen auf nächste Woche verschieben.","en":"We have to postpone the meeting until next week.","ru":"Нам нужно перенести встречу на следующую неделю.","vi":"Chúng ta phải hoãn cuộc họp sang tuần sau.","fa":"باید جلسه را به هفته آینده موکول کنیم."},{"de":"Kannst du den Schrank ein Stück nach links verschieben?","en":"Can you shift the wardrobe a bit to the left?","ru":"Можешь сдвинуть шкаф немного влево?","vi":"Bạn có thể di chuyển cái tủ sang bên trái một chút được không?","fa":"آیا می توانید کمد را کمی به سمت چپ حرکت دهید؟"}]},{"word":"verschieden","en":"different, various","ru":"различный, разный","vi":"khác nhau","fa":"متفاوت است","examples":[{"de":"Die Geschwister haben ganz verschiedene Charaktere.","en":"The siblings have very different characters.","ru":"У братьев и сестёр совершенно разные характеры.","vi":"Hai anh em có tính cách rất khác nhau.","fa":"خواهر و برادر شخصیت های بسیار متفاوتی دارند."},{"de":"Im Laden gibt es verschiedene Sorten Käse.","en":"The shop has various kinds of cheese.","ru":"В магазине есть разные сорта сыра.","vi":"Có nhiều loại phô mai khác nhau trong cửa hàng.","fa":"انواع پنیر در فروشگاه موجود است."}]},{"word":"die Verschmutzung","en":"pollution","ru":"загрязнение","vi":"sự ô nhiễm","fa":"آلودگی","examples":[{"de":"Die Verschmutzung der Meere ist ein großes Problem.","en":"The pollution of the oceans is a big problem.","ru":"Загрязнение океанов — большая проблема.","vi":"Ô nhiễm đại dương là một vấn đề lớn.","fa":"آلودگی اقیانوس ها یک مشکل بزرگ است."},{"de":"Der Verkehr trägt stark zur Verschmutzung der Luft bei.","en":"Traffic contributes greatly to air pollution.","ru":"Транспорт сильно способствует загрязнению воздуха.","vi":"Giao thông góp phần nặng nề vào ô nhiễm không khí.","fa":"ترافیک به شدت در آلودگی هوا نقش دارد."}]},{"word":"verschreiben","en":"to prescribe (medicine)","ru":"прописывать (лекарство)","vi":"quy định","fa":"تجویز کند","examples":[{"de":"Der Arzt hat mir ein Antibiotikum verschrieben.","en":"The doctor prescribed me an antibiotic.","ru":"Врач прописал мне антибиотик.","vi":"Bác sĩ kê cho tôi một loại thuốc kháng sinh.","fa":"دکتر برام آنتی بیوتیک تجویز کرد."},{"de":"Welche Tabletten hat Ihnen der Arzt verschrieben?","en":"Which pills did the doctor prescribe for you?","ru":"Какие таблетки прописал вам врач?","vi":"Bác sĩ kê đơn thuốc gì cho bạn?","fa":"دکتر کدام قرص را برای شما تجویز کرده است؟"}]},{"word":"verschwinden","en":"to disappear","ru":"исчезать","vi":"biến mất","fa":"ناپدید می شوند","examples":[{"de":"Die Sonne verschwand hinter den Wolken.","en":"The sun disappeared behind the clouds.","ru":"Солнце исчезло за облаками.","vi":"Mặt trời biến mất sau những đám mây.","fa":"خورشید پشت ابرها ناپدید شد."},{"de":"Mein Portemonnaie ist plötzlich verschwunden.","en":"My wallet suddenly disappeared.","ru":"Мой кошелёк вдруг пропал.","vi":"Ví của tôi đột nhiên biến mất.","fa":"کیف پولم ناگهان ناپدید شد."}]},{"word":"versichern","en":"to insure; to assure","ru":"страховать; уверять","vi":"bảo đảm","fa":"بیمه کنند","examples":[{"de":"Er hat sein Auto gegen Diebstahl versichert.","en":"He insured his car against theft.","ru":"Он застраховал свою машину от кражи.","vi":"Anh ta đã mua bảo hiểm cho chiếc xe của mình chống trộm.","fa":"او خودروی خود را در برابر سرقت بیمه کرده است."},{"de":"Ich versichere Ihnen, dass alles in Ordnung ist.","en":"I assure you that everything is fine.","ru":"Я уверяю вас, что всё в порядке.","vi":"Tôi đảm bảo với bạn rằng mọi thứ đều ổn.","fa":"من به شما اطمینان می دهم که همه چیز خوب است."}]},{"word":"die Versichertenkarte","en":"health insurance card","ru":"карта медицинского страхования","vi":"thẻ bảo hiểm","fa":"کارت بیمه","examples":[{"de":"Bitte zeigen Sie mir Ihre Versichertenkarte beim Arztbesuch.","en":"Please show me your health insurance card at the doctor's visit.","ru":"Пожалуйста, покажите вашу карту медицинского страхования на приёме у врача.","vi":"Vui lòng cho tôi xem thẻ bảo hiểm của bạn khi bạn đến gặp bác sĩ.","fa":"لطفاً هنگام مراجعه به پزشک کارت بیمه خود را به من نشان دهید."},{"de":"Ich habe meine Versichertenkarte zu Hause vergessen.","en":"I forgot my health insurance card at home.","ru":"Я забыл дома свою карту медицинского страхования.","vi":"Tôi quên thẻ bảo hiểm ở nhà.","fa":"کارت بیمه ام را در خانه فراموش کردم."}]},{"word":"die Versicherung","en":"insurance","ru":"страховка","vi":"bảo hiểm","fa":"بیمه","examples":[{"de":"Ohne Versicherung darf man nicht Auto fahren.","en":"You are not allowed to drive a car without insurance.","ru":"Без страховки нельзя водить машину.","vi":"Bạn không được phép lái xe mà không có bảo hiểm.","fa":"شما مجاز به رانندگی بدون بیمه نیستید."},{"de":"Die Versicherung zahlt den Schaden nicht.","en":"The insurance won't pay for the damage.","ru":"Страховка не покрывает ущерб.","vi":"Bảo hiểm không bồi thường thiệt hại.","fa":"بیمه خسارت را پرداخت نمی کند."}]},{"word":"die Verspätung","en":"delay","ru":"опоздание, задержка","vi":"sự chậm trễ","fa":"تاخیر","examples":[{"de":"Der Zug hat heute zwanzig Minuten Verspätung.","en":"The train is twenty minutes late today.","ru":"Поезд сегодня опаздывает на двадцать минут.","vi":"Hôm nay tàu trễ hai mươi phút.","fa":"قطار امروز بیست دقیقه تاخیر دارد."},{"de":"Wegen der Verspätung habe ich meinen Anschlussflug verpasst.","en":"Because of the delay, I missed my connecting flight.","ru":"Из-за задержки я пропустил стыковочный рейс.","vi":"Vì sự chậm trễ nên tôi đã lỡ chuyến bay nối chuyến.","fa":"به دلیل تاخیر، پرواز اتصالم را از دست دادم."}]},{"word":"versprechen","en":"to promise","ru":"обещать","vi":"lời hứa","fa":"قول دادن","examples":[{"de":"Er hat mir versprochen, pünktlich zu sein.","en":"He promised me to be on time.","ru":"Он пообещал мне быть вовремя.","vi":"Anh ấy đã hứa với tôi là sẽ đến đúng giờ.","fa":"او به من قول داد که به موقع خواهد آمد."},{"de":"Versprich mir, dass du auf dich aufpasst.","en":"Promise me that you'll take care of yourself.","ru":"Обещай мне, что будешь беречь себя.","vi":"Hãy hứa với tôi là bạn sẽ tự chăm sóc bản thân.","fa":"به من قول بده که مواظب خودت باشی"}]},{"word":"verständlich","en":"understandable, comprehensible","ru":"понятный","vi":"có thể hiểu được","fa":"قابل درک","examples":[{"de":"Der Lehrer erklärt die Grammatik sehr verständlich.","en":"The teacher explains the grammar very understandably.","ru":"Учитель объясняет грамматику очень понятно.","vi":"Thầy giảng ngữ pháp rất rõ ràng.","fa":"معلم گرامر را خیلی واضح توضیح می دهد."},{"de":"Es ist verständlich, dass du enttäuscht bist.","en":"It's understandable that you're disappointed.","ru":"Понятно, что ты разочарован.","vi":"Việc bạn thất vọng là điều dễ hiểu.","fa":"قابل درک است که شما ناامید شده اید."}]},{"word":"versuchen","en":"to try","ru":"пытаться, пробовать","vi":"thử","fa":"سعی کنید","examples":[{"de":"Ich versuche, jeden Tag Sport zu machen.","en":"I try to exercise every day.","ru":"Я стараюсь заниматься спортом каждый день.","vi":"Tôi cố gắng tập thể dục mỗi ngày.","fa":"سعی می کنم هر روز ورزش کنم."},{"de":"Versuch doch mal dieses neue Rezept!","en":"Try this new recipe!","ru":"Попробуй этот новый рецепт!","vi":"Hãy thử công thức mới này!","fa":"این دستور جدید را امتحان کنید!"}]},{"word":"verteilen","en":"to distribute, to hand out","ru":"распределять, раздавать","vi":"phân phối","fa":"توزیع کنید","examples":[{"de":"Der Lehrer verteilte die Arbeitsblätter an die Schüler.","en":"The teacher handed out the worksheets to the students.","ru":"Учитель раздал ученикам рабочие листы.","vi":"Giáo viên phát bài tập cho học sinh.","fa":"معلم برگه ها را بین دانش آموزان توزیع کرد."},{"de":"Die Aufgaben wurden gleichmäßig unter den Kollegen verteilt.","en":"The tasks were distributed evenly among the colleagues.","ru":"Задачи были равномерно распределены между коллегами.","vi":"Nhiệm vụ được phân bổ đều cho các đồng nghiệp.","fa":"وظایف به طور مساوی بین همکاران توزیع شد."}]},{"word":"der Vertrag","en":"contract","ru":"договор","vi":"hợp đồng","fa":"قرارداد","examples":[{"de":"Bitte lesen Sie den Vertrag genau, bevor Sie unterschreiben.","en":"Please read the contract carefully before signing.","ru":"Пожалуйста, внимательно прочитайте договор, прежде чем подписать.","vi":"Vui lòng đọc kỹ hợp đồng trước khi ký.","fa":"لطفا قبل از امضا قرارداد را با دقت مطالعه کنید."},{"de":"Ihr Vertrag läuft am Ende des Jahres aus.","en":"Your contract expires at the end of the year.","ru":"Ваш договор истекает в конце года.","vi":"Hợp đồng của bạn sẽ hết hạn vào cuối năm.","fa":"قرارداد شما در پایان سال به پایان می رسد."}]},{"word":"vertrauen","en":"to trust","ru":"доверять","vi":"tin tưởng","fa":"اعتماد","examples":[{"de":"Ich vertraue meinem besten Freund vollkommen.","en":"I trust my best friend completely.","ru":"Я полностью доверяю своему лучшему другу.","vi":"Tôi hoàn toàn tin tưởng người bạn thân nhất của mình.","fa":"من به بهترین دوستم کاملاً اعتماد دارم."},{"de":"Man sollte nicht jeder Werbung vertrauen.","en":"One shouldn't trust every advertisement.","ru":"Не стоит доверять каждой рекламе.","vi":"Bạn không nên tin tưởng mọi quảng cáo.","fa":"نباید به هر تبلیغی اعتماد کرد."}]},{"word":"das Vertrauen","en":"trust; confidence","ru":"доверие","vi":"sự tin tưởng","fa":"اعتماد","examples":[{"de":"Ohne Vertrauen funktioniert keine Beziehung.","en":"No relationship works without trust.","ru":"Без доверия не работают никакие отношения.","vi":"Không có mối quan hệ nào hoạt động mà không có sự tin tưởng.","fa":"هیچ رابطه ای بدون اعتماد کار نمی کند."},{"de":"Er hat mein Vertrauen leider missbraucht.","en":"Unfortunately he abused my trust.","ru":"К сожалению, он злоупотребил моим доверием.","vi":"Thật không may, anh ấy đã phản bội lòng tin của tôi.","fa":"متاسفانه او به اعتماد من خیانت کرد."}]},{"word":"vertreten","en":"to represent; to stand in for (someone)","ru":"представлять; замещать (кого-то)","vi":"đại diện","fa":"نمایندگی کرد","examples":[{"de":"Der Anwalt vertritt seinen Mandanten vor Gericht.","en":"The lawyer represents his client in court.","ru":"Адвокат представляет своего клиента в суде.","vi":"Luật sư đại diện cho khách hàng của mình tại tòa án.","fa":"وکیل مدافع موکل خود در دادگاه است."},{"de":"Frau Müller vertritt heute den kranken Kollegen.","en":"Ms. Müller is standing in for the sick colleague today.","ru":"Госпожа Мюллер сегодня замещает заболевшего коллегу.","vi":"Hôm nay cô Müller đại diện cho đồng nghiệp bị ốm.","fa":"خانم مولر امروز نماینده همکار بیمار است."}]},{"word":"verursachen","en":"to cause","ru":"вызывать, быть причиной","vi":"nguyên nhân","fa":"علت","examples":[{"de":"Der Unfall wurde durch Glatteis verursacht.","en":"The accident was caused by black ice.","ru":"Авария была вызвана гололёдом.","vi":"Vụ tai nạn xảy ra do băng đen.","fa":"علت این حادثه یخ سیاه بوده است."},{"de":"Rauchen kann viele Krankheiten verursachen.","en":"Smoking can cause many illnesses.","ru":"Курение может вызывать много болезней.","vi":"Hút thuốc có thể gây ra nhiều bệnh tật.","fa":"سیگار می تواند باعث بسیاری از بیماری ها شود."}]},{"word":"verurteilen","en":"to convict, to condemn","ru":"осуждать, приговаривать","vi":"lên án","fa":"محکوم کردن","examples":[{"de":"Das Gericht hat ihn zu einer Geldstrafe verurteilt.","en":"The court sentenced him to a fine.","ru":"Суд приговорил его к штрафу.","vi":"Tòa án đã kết án anh ta phạt tiền.","fa":"دادگاه او را به جریمه نقدی محکوم کرد."},{"de":"Viele Menschen verurteilen Gewalt in jeder Form.","en":"Many people condemn violence in any form.","ru":"Многие люди осуждают насилие в любой форме.","vi":"Nhiều người lên án bạo lực dưới mọi hình thức.","fa":"بسیاری از مردم خشونت را در همه اشکال محکوم می کنند."}]},{"word":"die Verwaltung","en":"administration","ru":"администрация, управление","vi":"chính quyền","fa":"اداره","examples":[{"de":"Die Verwaltung der Stadt ist für die Straßen zuständig.","en":"The city's administration is responsible for the streets.","ru":"Администрация города отвечает за дороги.","vi":"Chính quyền thành phố chịu trách nhiệm về đường bộ.","fa":"مدیریت شهری مسئول راه هاست."},{"de":"Sie arbeitet in der Verwaltung eines Krankenhauses.","en":"She works in the administration of a hospital.","ru":"Она работает в администрации больницы.","vi":"Cô ấy làm việc ở bộ phận hành chính tại một bệnh viện.","fa":"او در بخش مدیریت در بیمارستان کار می کند."}]},{"word":"verwandt","en":"related (family)","ru":"родственный, состоящий в родстве","vi":"liên quan","fa":"مرتبط","examples":[{"de":"Wir sind entfernt miteinander verwandt.","en":"We are distantly related to each other.","ru":"Мы дальние родственники.","vi":"Chúng tôi có họ hàng xa.","fa":"ما از دور با هم مرتبطیم."},{"de":"Ist er mit dir verwandt oder nur ein Freund?","en":"Is he related to you or just a friend?","ru":"Он твой родственник или просто друг?","vi":"Anh ấy có họ hàng với bạn hay chỉ là một người bạn?","fa":"آیا او با شما نسبت دارد یا فقط یک دوست؟"}]},{"word":"verwechseln","en":"to confuse, to mix up","ru":"путать","vi":"trộn lẫn","fa":"مخلوط کردن","examples":[{"de":"Entschuldigung, ich habe Sie mit jemand anderem verwechselt.","en":"Sorry, I mixed you up with someone else.","ru":"Извините, я перепутал вас с кем-то другим.","vi":"Xin lỗi, tôi đã nhầm lẫn bạn với người khác.","fa":"ببخشید من شما رو با یکی دیگه اشتباه گرفتم"},{"de":"Die Zwillinge sehen sich so ähnlich, dass man sie leicht verwechseln kann.","en":"The twins look so alike that you can easily confuse them.","ru":"Близнецы так похожи, что их легко перепутать.","vi":"Cặp song sinh trông giống nhau đến mức dễ bị nhầm lẫn.","fa":"دوقلوها آنقدر شبیه به هم هستند که به راحتی می توان آنها را گیج کرد."}]},{"word":"verwenden","en":"to use","ru":"использовать","vi":"sử dụng","fa":"استفاده کنید","examples":[{"de":"Für den Kuchen verwende ich frische Eier.","en":"I use fresh eggs for the cake.","ru":"Для торта я использую свежие яйца.","vi":"Tôi sử dụng trứng tươi cho bánh.","fa":"من از تخم مرغ تازه برای کیک استفاده می کنم."},{"de":"Man kann diese App kostenlos verwenden.","en":"You can use this app for free.","ru":"Этим приложением можно пользоваться бесплатно.","vi":"Người ta có thể sử dụng ứng dụng này miễn phí.","fa":"می توانید از این برنامه به صورت رایگان استفاده کنید."}]},{"word":"verzeihen","en":"to forgive","ru":"прощать","vi":"tha thứ","fa":"ببخش","examples":[{"de":"Kannst du mir meinen Fehler verzeihen?","en":"Can you forgive me for my mistake?","ru":"Ты можешь простить мне мою ошибку?","vi":"Bạn có thể tha thứ cho lỗi lầm của tôi được không?","fa":"آیا می توانی مرا به خاطر اشتباهم ببخشی؟"},{"de":"Sie hat ihm nie verziehen, dass er sie belogen hat.","en":"She never forgave him for lying to her.","ru":"Она так и не простила ему, что он её обманул.","vi":"Cô không bao giờ tha thứ cho anh vì đã nói dối cô.","fa":"هرگز او را به خاطر دروغ گفتن به او نبخشید."}]},{"word":"der Verzicht","en":"doing without; renunciation","ru":"отказ (от чего-либо)","vi":"sự từ bỏ","fa":"چشم پوشی","examples":[{"de":"Der Verzicht auf Zucker fiel ihm schwer.","en":"Giving up sugar was hard for him.","ru":"Отказ от сахара дался ему тяжело.","vi":"Rất khó để anh ấy từ bỏ đường.","fa":"ترک شکر برایش سخت بود."},{"de":"Umweltschutz bedeutet oft einen Verzicht auf Bequemlichkeit.","en":"Protecting the environment often means giving up convenience.","ru":"Охрана природы часто означает отказ от удобства.","vi":"Bảo vệ môi trường thường có nghĩa là từ bỏ sự tiện lợi.","fa":"حفاظت از محیط زیست اغلب به معنای کنار گذاشتن راحتی است."}]},{"word":"verzichten","en":"to do without, to forgo","ru":"отказываться (от чего-то)","vi":"từ bỏ","fa":"چشم پوشی","examples":[{"de":"Ich versuche, auf Zucker zu verzichten.","en":"I'm trying to do without sugar.","ru":"Я стараюсь отказаться от сахара.","vi":"Tôi đang cố gắng tránh đường.","fa":"من سعی می کنم از شکر اجتناب کنم."},{"de":"Er hat auf seinen Urlaub verzichtet, um zu arbeiten.","en":"He forwent his vacation in order to work.","ru":"Он отказался от отпуска, чтобы работать.","vi":"Anh ấy đã bỏ kỳ nghỉ của mình để đi làm.","fa":"او مرخصی خود را رها کرد تا کار کند."}]},{"word":"das Video","en":"video","ru":"видео","vi":"đoạn video","fa":"ویدئو","examples":[{"de":"Ich habe ein lustiges Video im Internet gesehen.","en":"I saw a funny video on the internet.","ru":"Я посмотрел смешное видео в интернете.","vi":"Tôi thấy một video hài hước trên internet.","fa":"من یک ویدیوی خنده دار در اینترنت دیدم."},{"de":"Sie hat ein Video von der Hochzeit gemacht.","en":"She made a video of the wedding.","ru":"Она сняла видео со свадьбы.","vi":"Cô ấy đã quay video đám cưới.","fa":"او از عروسی فیلم گرفت."}]},{"word":"viel/viele","en":"much / many","ru":"много","vi":"nhiều / nhiều","fa":"زیاد/خیلی","examples":[{"de":"Ich habe heute viel Arbeit.","en":"I have a lot of work today.","ru":"У меня сегодня много работы.","vi":"Hôm nay tôi có rất nhiều việc.","fa":"امروز خیلی کار دارم."},{"de":"Auf dem Fest waren viele Gäste.","en":"There were many guests at the party.","ru":"На празднике было много гостей.","vi":"Có rất nhiều khách mời tại lễ hội.","fa":"مهمانان زیادی در این جشنواره حضور داشتند."}]},{"word":"vielleicht","en":"maybe, perhaps","ru":"может быть, возможно","vi":"có lẽ","fa":"شاید","examples":[{"de":"Vielleicht komme ich morgen zu Besuch.","en":"Maybe I'll come to visit tomorrow.","ru":"Может быть, я приду в гости завтра.","vi":"Có lẽ ngày mai tôi sẽ đến thăm.","fa":"شاید فردا بیام دیدار"},{"de":"Er ist vielleicht schon zu Hause.","en":"Perhaps he's already at home.","ru":"Возможно, он уже дома.","vi":"Có thể anh ấy đã về nhà rồi.","fa":"او ممکن است قبلاً در خانه باشد."}]},{"word":"das Viertel","en":"quarter; district, neighborhood","ru":"четверть; квартал (района)","vi":"quý","fa":"ربع","examples":[{"de":"Es ist Viertel nach neun.","en":"It's a quarter past nine.","ru":"Сейчас четверть десятого.","vi":"Bây giờ là chín giờ mười lăm.","fa":"ساعت نه و ربع است"},{"de":"Wir wohnen in einem ruhigen Viertel der Stadt.","en":"We live in a quiet district of the city.","ru":"Мы живём в тихом квартале города.","vi":"Chúng tôi sống ở một khu vực yên tĩnh của thành phố.","fa":"ما در یک منطقه آرام از شهر زندگی می کنیم."}]},{"word":"virtuell","en":"virtual","ru":"виртуальный","vi":"ảo","fa":"مجازی","examples":[{"de":"Die Ausstellung kann man auch virtuell besuchen.","en":"The exhibition can also be visited virtually.","ru":"Выставку можно посетить также виртуально.","vi":"Bạn cũng có thể tham quan triển lãm ảo.","fa":"همچنین می توانید به صورت مجازی از نمایشگاه دیدن کنید."},{"de":"Er hat viele Freunde in der virtuellen Welt der Spiele.","en":"He has many friends in the virtual world of games.","ru":"У него много друзей в виртуальном мире игр.","vi":"Anh ấy có nhiều bạn bè trong thế giới ảo của trò chơi.","fa":"او در دنیای مجازی بازی دوستان زیادی دارد."}]},{"word":"der Virus","en":"virus","ru":"вирус","vi":"virus","fa":"ویروس","examples":[{"de":"Ein Virus hat meinen Computer infiziert.","en":"A virus infected my computer.","ru":"Вирус заразил мой компьютер.","vi":"Một loại virus đã lây nhiễm vào máy tính của tôi.","fa":"یک ویروس کامپیوتر من را آلوده کرده است."},{"de":"Der Arzt vermutet, dass sie sich mit einem Virus angesteckt hat.","en":"The doctor suspects that she caught a virus.","ru":"Врач предполагает, что она заразилась вирусом.","vi":"Bác sĩ nghi ngờ cô đã bị nhiễm virus.","fa":"دکتر مشکوک است که او به ویروس آلوده شده است."}]},{"word":"die Visitenkarte","en":"business card","ru":"визитная карточка","vi":"thẻ kinh doanh","fa":"کارت ویزیت","examples":[{"de":"Er gab mir seine Visitenkarte nach dem Gespräch.","en":"He gave me his business card after the conversation.","ru":"После разговора он дал мне свою визитку.","vi":"Anh ấy đưa cho tôi danh thiếp của anh ấy sau cuộc trò chuyện.","fa":"بعد از صحبت کارت ویزیتش را به من داد."},{"de":"Auf der Visitenkarte stehen seine Telefonnummer und E-Mail-Adresse.","en":"His phone number and email address are on the business card.","ru":"На визитке указаны его номер телефона и электронная почта.","vi":"Số điện thoại và địa chỉ email của anh ấy có trên danh thiếp.","fa":"شماره تلفن و آدرس ایمیل او در کارت ویزیت موجود است."}]},{"word":"das Visum","en":"visa","ru":"виза","vi":"thị thực","fa":"ویزا","examples":[{"de":"Für die Reise nach Russland brauche ich ein Visum.","en":"I need a visa for the trip to Russia.","ru":"Для поездки в Россию мне нужна виза.","vi":"Tôi cần visa để đi du lịch đến Nga.","fa":"برای سفر به روسیه به ویزا نیاز دارم."},{"de":"Das Visum wurde für drei Monate ausgestellt.","en":"The visa was issued for three months.","ru":"Виза была выдана на три месяца.","vi":"Thị thực đã được cấp trong ba tháng.","fa":"ویزا برای سه ماه صادر شد."}]},{"word":"das Vitamin","en":"vitamin","ru":"витамин","vi":"vitamin","fa":"ویتامین","examples":[{"de":"Orangen enthalten viel Vitamin C.","en":"Oranges contain a lot of vitamin C.","ru":"Апельсины содержат много витамина С.","vi":"Cam chứa rất nhiều vitamin C.","fa":"پرتقال حاوی مقدار زیادی ویتامین C است."},{"de":"Im Winter nehme ich manchmal Vitamintabletten.","en":"In winter I sometimes take vitamin tablets.","ru":"Зимой я иногда принимаю витаминные таблетки.","vi":"Vào mùa đông thỉnh thoảng tôi uống viên vitamin.","fa":"در زمستان گاهی قرص ویتامین مصرف می کنم."}]},{"word":"voll","en":"full","ru":"полный","vi":"đầy đủ","fa":"کامل","examples":[{"de":"Der Bus war so voll, dass ich stehen musste.","en":"The bus was so full that I had to stand.","ru":"Автобус был настолько полным, что мне пришлось стоять.","vi":"Xe buýt đông đến mức tôi phải đứng.","fa":"اتوبوس آنقدر پر بود که مجبور شدم بایستم."},{"de":"Das Glas ist bis zum Rand voll.","en":"The glass is full to the brim.","ru":"Стакан полон до краёв.","vi":"Kính đã đầy tới miệng.","fa":"لیوان تا لبه پر است."}]},{"word":"Volleyball","en":"volleyball","ru":"волейбол","vi":"bóng chuyền","fa":"والیبال","examples":[{"de":"Am Strand spielen wir gern Volleyball.","en":"We like playing volleyball at the beach.","ru":"На пляже мы любим играть в волейбол.","vi":"Chúng tôi thích chơi bóng chuyền trên bãi biển.","fa":"ما دوست داریم در ساحل والیبال بازی کنیم."},{"de":"Sie ist Mitglied im Volleyball-Verein.","en":"She is a member of the volleyball club.","ru":"Она состоит в волейбольном клубе.","vi":"Cô là thành viên của câu lạc bộ bóng chuyền.","fa":"او عضو باشگاه والیبال است."}]},{"word":"völlig","en":"completely","ru":"полностью, совершенно","vi":"hoàn toàn","fa":"به طور کامل","examples":[{"de":"Das ist mir völlig egal.","en":"That's completely irrelevant to me.","ru":"Мне это совершенно всё равно.","vi":"Tôi không quan tâm chút nào.","fa":"اصلا برام مهم نیست"},{"de":"Nach dem Marathon war er völlig erschöpft.","en":"After the marathon he was completely exhausted.","ru":"После марафона он был совершенно измотан.","vi":"Sau cuộc chạy marathon, anh ấy hoàn toàn kiệt sức.","fa":"پس از ماراتن او کاملا خسته بود."}]},{"word":"von","en":"from, of, by","ru":"от, из, о","vi":"từ","fa":"از","examples":[{"de":"Dieses Geschenk ist von meiner Mutter.","en":"This gift is from my mother.","ru":"Этот подарок от моей матери.","vi":"Món quà này là của mẹ tôi.","fa":"این هدیه از طرف مادرم است."},{"de":"Der Roman wurde von einem berühmten Autor geschrieben.","en":"The novel was written by a famous author.","ru":"Роман был написан известным автором.","vi":"Cuốn tiểu thuyết được viết bởi một tác giả nổi tiếng.","fa":"این رمان توسط یک نویسنده مشهور نوشته شده است."}]},{"word":"voneinander","en":"from each other, of each other","ru":"друг от друга, друг о друге","vi":"từ nhau","fa":"از یکدیگر","examples":[{"de":"Die Freunde haben lange nichts voneinander gehört.","en":"The friends hadn't heard from each other for a long time.","ru":"Друзья долго ничего не слышали друг о друге.","vi":"Bạn bè đã lâu không liên lạc với nhau.","fa":"دوستان مدت زیادی است که از یکدیگر خبری ندارند."},{"de":"Die Zwillinge sind kaum voneinander zu unterscheiden.","en":"The twins can hardly be distinguished from each other.","ru":"Близнецов едва можно отличить друг от друга.","vi":"Cặp song sinh khó có thể phân biệt được với nhau.","fa":"دوقلوها را به سختی می توان از یکدیگر تشخیص داد."}]},{"word":"vor","en":"before, in front of, ago","ru":"перед, до, назад (о времени)","vi":"trước đây","fa":"قبل از","examples":[{"de":"Das Auto steht vor dem Haus.","en":"The car is parked in front of the house.","ru":"Машина стоит перед домом.","vi":"Ôtô đậu trước nhà.","fa":"ماشین جلوی خانه است."},{"de":"Vor zwei Jahren habe ich meinen Job gewechselt.","en":"Two years ago I changed my job.","ru":"Два года назад я сменил работу.","vi":"Hai năm trước tôi đã thay đổi công việc của mình.","fa":"دو سال پیش شغلم را عوض کردم."}]},{"word":"voraus","en":"ahead, in advance","ru":"заранее, вперёд","vi":"phía trước","fa":"جلوتر","examples":[{"de":"Vielen Dank im Voraus für Ihre Hilfe.","en":"Thank you in advance for your help.","ru":"Заранее спасибо за вашу помощь.","vi":"Cảm ơn bạn trước sự giúp đỡ của bạn.","fa":"پیشاپیش از کمک شما سپاسگزارم."},{"de":"Er ist seiner Zeit weit voraus.","en":"He is far ahead of his time.","ru":"Он далеко опережает своё время.","vi":"Anh ấy đã đi trước thời đại rất nhiều.","fa":"او بسیار جلوتر از زمان خود است."}]},{"word":"voraussetzen","en":"to presuppose; to require","ru":"предполагать; требовать (как условие)","vi":"giả sử","fa":"فرض کنید","examples":[{"de":"Diese Aufgabe setzt gute Vorkenntnisse voraus.","en":"This task requires good prior knowledge.","ru":"Это задание требует хороших предварительных знаний.","vi":"Nhiệm vụ này đòi hỏi kiến thức tốt trước đó.","fa":"این کار مستلزم دانش قبلی خوب است."},{"de":"Ich setze voraus, dass alle pünktlich sind.","en":"I assume that everyone will be on time.","ru":"Я исхожу из того, что все будут вовремя.","vi":"Tôi cho rằng mọi người đều đúng giờ.","fa":"من فرض می کنم که همه به موقع هستند."}]},{"word":"die Voraussetzung","en":"prerequisite, requirement","ru":"предпосылка, условие","vi":"điều kiện tiên quyết","fa":"پیش نیاز","examples":[{"de":"Gute Deutschkenntnisse sind Voraussetzung für diesen Job.","en":"Good German skills are a prerequisite for this job.","ru":"Хорошее знание немецкого языка — обязательное условие для этой работы.","vi":"Kiến thức tốt về tiếng Đức là điều kiện tiên quyết cho công việc này.","fa":"آشنایی با زبان آلمانی پیش نیاز این شغل می باشد."},{"de":"Welche Voraussetzungen muss ich für das Studium erfüllen?","en":"What requirements do I need to meet for the studies?","ru":"Каким требованиям я должен соответствовать для обучения?","vi":"Tôi phải đáp ứng những yêu cầu gì để học?","fa":"برای تحصیل چه شرایطی را باید رعایت کنم؟"}]},{"word":"voraussichtlich","en":"probably, expected (to happen)","ru":"предположительно, ожидаемо","vi":"dự kiến","fa":"انتظار می رود","examples":[{"de":"Der Flug landet voraussichtlich um 18 Uhr.","en":"The flight is expected to land at 6 p.m.","ru":"Самолёт предположительно приземлится в 18:00.","vi":"Dự kiến chuyến bay sẽ hạ cánh lúc 18h.","fa":"انتظار می رود این پرواز ساعت 6 بعد از ظهر به زمین بنشیند."},{"de":"Die Bauarbeiten werden voraussichtlich im Herbst fertig.","en":"The construction work is expected to be finished in autumn.","ru":"Строительные работы предположительно завершатся осенью.","vi":"Công việc xây dựng dự kiến ​​sẽ hoàn thành vào mùa thu.","fa":"انتظار می رود کار ساخت و ساز در پاییز به پایان برسد."}]},{"word":"vorbei","en":"past, over, by","ru":"мимо, окончен(о)","vi":"kết thúc","fa":"تمام","examples":[{"de":"Der Sommer ist schon vorbei.","en":"Summer is already over.","ru":"Лето уже прошло.","vi":"Mùa hè đã kết thúc rồi.","fa":"تابستان دیگر تمام شده است."},{"de":"Er lief schnell an mir vorbei.","en":"He ran quickly past me.","ru":"Он быстро пробежал мимо меня.","vi":"Anh ấy nhanh chóng chạy qua tôi.","fa":"سریع از کنارم رد شد."}]},{"word":"vorder-","en":"front- (prefix meaning 'front')","ru":"передний- (приставка)","vi":"phía trước","fa":"جلو","examples":[{"de":"Bitte setzen Sie sich auf den Vordersitz.","en":"Please sit in the front seat.","ru":"Пожалуйста, садитесь на переднее сиденье.","vi":"Xin vui lòng ngồi ở ghế trước.","fa":"لطفا روی صندلی جلو بنشینید"},{"de":"Die Vordertür des Hauses war abgeschlossen.","en":"The front door of the house was locked.","ru":"Входная дверь дома была заперта.","vi":"Cửa trước của ngôi nhà đã bị khóa.","fa":"درب ورودی خانه قفل بود."}]},{"word":"die Vorfahrt","en":"right of way (traffic)","ru":"право преимущественного проезда","vi":"quyền đi đường","fa":"حق تقدم","examples":[{"de":"An dieser Kreuzung habe ich Vorfahrt.","en":"I have the right of way at this intersection.","ru":"На этом перекрёстке у меня преимущество проезда.","vi":"Tôi có quyền ưu tiên ở ngã tư này.","fa":"من در این تقاطع حق تقدم دارم."},{"de":"Er hat die Vorfahrt missachtet und fast einen Unfall verursacht.","en":"He ignored the right of way and almost caused an accident.","ru":"Он не уступил дорогу и чуть не стал причиной аварии.","vi":"Anh ta đã phớt lờ quyền ưu tiên và suýt gây ra tai nạn.","fa":"حق تقدم را نادیده گرفت و نزدیک بود تصادف کند."}]},{"word":"vorgestern","en":"the day before yesterday","ru":"позавчера","vi":"ngày hôm kia","fa":"پریروز","examples":[{"de":"Vorgestern habe ich meine Großeltern besucht.","en":"I visited my grandparents the day before yesterday.","ru":"Позавчера я навещал своих бабушку и дедушку.","vi":"Hôm kia tôi đến thăm ông bà tôi.","fa":"دیروز به پدربزرگ و مادربزرگم سر زدم."},{"de":"Das Paket ist schon vorgestern angekommen.","en":"The package already arrived the day before yesterday.","ru":"Посылка уже пришла позавчера.","vi":"Gói hàng đã đến vào ngày hôm kia.","fa":"بسته پریروز رسید."}]},{"word":"vorhaben","en":"to plan, to intend","ru":"планировать, намереваться","vi":"kế hoạch","fa":"برنامه ریزی کنید","examples":[{"de":"Was hast du am Wochenende vor?","en":"What do you have planned for the weekend?","ru":"Что ты планируешь на выходные?","vi":"Cuối tuần này bạn định làm gì?","fa":"این آخر هفته چه کاره ای؟"},{"de":"Wir haben vor, nächstes Jahr nach Japan zu reisen.","en":"We plan to travel to Japan next year.","ru":"Мы планируем поехать в Японию в следующем году.","vi":"Chúng tôi đang có kế hoạch đi du lịch Nhật Bản vào năm tới.","fa":"ما قصد داریم سال آینده به ژاپن سفر کنیم."}]},{"word":"vorher","en":"before, beforehand","ru":"раньше, заранее, до этого","vi":"trước đây","fa":"قبل از","examples":[{"de":"Ruf mich bitte vorher an, bevor du kommst.","en":"Please call me beforehand before you come.","ru":"Пожалуйста, позвони мне заранее, прежде чем прийти.","vi":"Hãy gọi cho tôi trước khi bạn đến.","fa":"لطفا قبل از آمدن با من تماس بگیرید."},{"de":"Ich kannte ihn schon vorher.","en":"I already knew him from before.","ru":"Я знал его ещё раньше.","vi":"Tôi biết anh ấy trước đây.","fa":"من او را قبلا می شناختم."}]},{"word":"vorhin","en":"a short while ago, just now","ru":"недавно, только что","vi":"trước đó","fa":"زودتر","examples":[{"de":"Vorhin hat es noch geregnet, jetzt scheint die Sonne.","en":"It was raining just now, now the sun is shining.","ru":"Только что шёл дождь, а сейчас светит солнце.","vi":"Vừa nãy trời còn mưa, bây giờ trời đã nắng.","fa":"چند لحظه پیش باران می بارید، حالا خورشید می درخشد."},{"de":"Ich habe dich vorhin schon angerufen, aber du hast nicht abgenommen.","en":"I already called you a little while ago, but you didn't pick up.","ru":"Я уже звонил тебе недавно, но ты не ответил.","vi":"Lúc trước tôi gọi cho bạn nhưng bạn không bắt máy.","fa":"من زودتر بهت زنگ زدم اما نگرفتی"}]},{"word":"vorkommen","en":"to occur, to happen","ru":"случаться, встречаться","vi":"xảy ra","fa":"رخ دهد","examples":[{"de":"So ein Fehler darf nicht noch einmal vorkommen.","en":"Such a mistake must not happen again.","ru":"Такая ошибка не должна повториться.","vi":"Một sai lầm như thế này không được phép xảy ra lần nữa.","fa":"چنین اشتباهی نباید دوباره تکرار شود."},{"de":"Diese Pflanze kommt nur in den Bergen vor.","en":"This plant only occurs in the mountains.","ru":"Это растение встречается только в горах.","vi":"Loại cây này chỉ được tìm thấy ở vùng núi.","fa":"این گیاه فقط در کوهستان یافت می شود."}]},{"word":"vorläufig","en":"temporary, provisional, for now","ru":"временный, предварительный","vi":"tạm thời","fa":"به طور موقت","examples":[{"de":"Das ist nur eine vorläufige Lösung.","en":"This is only a temporary solution.","ru":"Это лишь временное решение.","vi":"Đây chỉ là giải pháp tạm thời.","fa":"این فقط یک راه حل موقت است."},{"de":"Vorläufig bleiben wir in dieser Wohnung.","en":"For now, we're staying in this apartment.","ru":"Пока что мы остаёмся в этой квартире.","vi":"Bây giờ chúng ta sẽ ở trong căn hộ này.","fa":"فعلاً در این آپارتمان خواهیم ماند."}]},{"word":"vorlesen","en":"to read aloud","ru":"читать вслух","vi":"đọc to","fa":"خواندن","examples":[{"de":"Die Mutter liest ihrem Kind jeden Abend eine Geschichte vor.","en":"The mother reads a story aloud to her child every evening.","ru":"Мать каждый вечер читает ребёнку сказку вслух.","vi":"Mẹ đọc truyện cho con nghe vào mỗi buổi tối.","fa":"مادر هر روز عصر برای فرزندش قصه می خواند."},{"de":"Kannst du mir bitte den Brief vorlesen?","en":"Can you please read the letter aloud to me?","ru":"Можешь прочитать мне это письмо вслух?","vi":"Bạn có thể vui lòng đọc thư cho tôi được không?","fa":"میشه لطفا نامه رو برای من بخونید؟"}]},{"word":"vorn","en":"in front, at the front","ru":"впереди","vi":"phía trước","fa":"جلو","examples":[{"de":"Setz dich vorn ins Auto.","en":"Sit in the front of the car.","ru":"Садись впереди в машине.","vi":"Ngồi ở phía trước xe.","fa":"جلوی ماشین بنشینید."},{"de":"In der Schlange stand er ganz vorn.","en":"He stood right at the front of the line.","ru":"В очереди он стоял совсем впереди.","vi":"Anh ấy đã ở phía trước của hàng đợi.","fa":"جلوی صف بود."}]},{"word":"der Vorort","en":"suburb","ru":"пригород","vi":"vùng ngoại ô","fa":"حومه شهر","examples":[{"de":"Wir wohnen in einem Vorort von München.","en":"We live in a suburb of Munich.","ru":"Мы живём в пригороде Мюнхена.","vi":"Chúng tôi sống ở ngoại ô Munich.","fa":"ما در حومه مونیخ زندگی می کنیم."},{"de":"In den Vororten sind die Mieten günstiger als in der Stadt.","en":"Rents are cheaper in the suburbs than in the city.","ru":"В пригородах аренда дешевле, чем в городе.","vi":"Giá thuê nhà ở ngoại ô rẻ hơn trong thành phố.","fa":"اجاره در حومه شهر ارزان تر از شهر است."}]},{"word":"der Vorschlag","en":"suggestion; proposal","ru":"предложение","vi":"lời đề nghị","fa":"پیشنهاد","examples":[{"de":"Ich möchte einen Vorschlag machen.","en":"I would like to make a suggestion.","ru":"Я хотел бы внести предложение.","vi":"Tôi muốn đưa ra một đề nghị.","fa":"من می خواهم یک پیشنهاد بدهم."},{"de":"Ihr Vorschlag wurde von allen sofort angenommen.","en":"Your proposal was immediately accepted by everyone.","ru":"Ваше предложение сразу приняли все.","vi":"Đề nghị của cô ngay lập tức được mọi người chấp nhận.","fa":"پیشنهاد او بلافاصله مورد قبول همه قرار گرفت."}]},{"word":"vorschlagen","en":"to suggest, to propose","ru":"предлагать","vi":"đề nghị","fa":"پیشنهاد می کند","examples":[{"de":"Ich schlage vor, dass wir uns morgen treffen.","en":"I suggest that we meet tomorrow.","ru":"Я предлагаю встретиться завтра.","vi":"Tôi đề nghị chúng ta gặp nhau vào ngày mai.","fa":"پیشنهاد میکنم فردا همدیگه رو ببینیم"},{"de":"Er hat einen guten Kompromiss vorgeschlagen.","en":"He proposed a good compromise.","ru":"Он предложил хороший компромисс.","vi":"Ông đề nghị một sự thỏa hiệp tốt.","fa":"او یک سازش خوب را پیشنهاد کرد."}]},{"word":"die Vorschrift","en":"regulation, rule","ru":"предписание, правило","vi":"quy định","fa":"مقررات","examples":[{"de":"Man muss sich an die Vorschriften halten.","en":"You have to follow the regulations.","ru":"Нужно соблюдать предписания.","vi":"Bạn phải tuân theo các quy tắc.","fa":"شما باید قوانین را رعایت کنید."},{"de":"Diese Vorschrift gilt für alle Mitarbeiter.","en":"This regulation applies to all employees.","ru":"Это правило действует для всех сотрудников.","vi":"Quy định này áp dụng cho tất cả nhân viên.","fa":"این آیین نامه برای همه کارکنان اعمال می شود."}]},{"word":"die Vorsicht","en":"caution, care","ru":"осторожность","vi":"sự thận trọng","fa":"احتیاط","examples":[{"de":"Vorsicht, die Straße ist glatt!","en":"Caution, the road is slippery!","ru":"Осторожно, дорога скользкая!","vi":"Hãy cẩn thận, đường trơn trượt!","fa":"مراقب باشید، جاده لغزنده است!"},{"de":"Mit Vorsicht sollte man solche Angebote betrachten.","en":"You should view such offers with caution.","ru":"К таким предложениям следует относиться с осторожностью.","vi":"Những đề nghị như vậy nên được xem xét một cách thận trọng.","fa":"چنین پیشنهادهایی را باید با احتیاط دید."}]},{"word":"die Vorstellung","en":"idea; performance; introduction","ru":"представление; показ","vi":"ý tưởng","fa":"ایده","examples":[{"de":"Ich habe keine Vorstellung, wie teuer das ist.","en":"I have no idea how expensive that is.","ru":"Я понятия не имею, насколько это дорого.","vi":"Tôi không biết nó đắt thế nào.","fa":"من نمی دانم چقدر گران است."},{"de":"Die Vorstellung im Theater beginnt um acht.","en":"The performance at the theatre starts at eight.","ru":"Спектакль в театре начинается в восемь.","vi":"Buổi biểu diễn ở nhà hát bắt đầu lúc tám giờ.","fa":"اجرا در تئاتر از ساعت هشت شروع می شود."}]},{"word":"das Vorstellungsgespräch","en":"job interview","ru":"собеседование","vi":"cuộc phỏng vấn","fa":"مصاحبه","examples":[{"de":"Morgen habe ich ein Vorstellungsgespräch bei einer neuen Firma.","en":"Tomorrow I have a job interview at a new company.","ru":"Завтра у меня собеседование в новой компании.","vi":"Ngày mai tôi có cuộc phỏng vấn ở một công ty mới.","fa":"فردا در یک شرکت جدید مصاحبه دارم."},{"de":"Sie hat sich gut auf das Vorstellungsgespräch vorbereitet.","en":"She prepared well for the job interview.","ru":"Она хорошо подготовилась к собеседованию.","vi":"Cô ấy đã chuẩn bị tốt cho cuộc phỏng vấn.","fa":"او به خوبی برای مصاحبه آماده شد."}]},{"word":"der Vorteil","en":"advantage","ru":"преимущество","vi":"lợi thế","fa":"مزیت","examples":[{"de":"Ein großer Vorteil dieser Wohnung ist die zentrale Lage.","en":"A big advantage of this apartment is its central location.","ru":"Большое преимущество этой квартиры — центральное расположение.","vi":"Một lợi thế lớn của căn hộ này là vị trí trung tâm.","fa":"مزیت بزرگ این آپارتمان موقعیت مرکزی آن است."},{"de":"Welche Vorteile hat das neue System?","en":"What advantages does the new system have?","ru":"Какие преимущества у новой системы?","vi":"Ưu điểm của hệ thống mới là gì?","fa":"مزایای سیستم جدید چیست؟"}]},{"word":"der Vortrag","en":"lecture, presentation","ru":"доклад, лекция","vi":"bài giảng","fa":"سخنرانی","examples":[{"de":"Der Professor hielt einen interessanten Vortrag über Klimawandel.","en":"The professor gave an interesting lecture on climate change.","ru":"Профессор прочитал интересный доклад об изменении климата.","vi":"Giáo sư đã có một bài giảng thú vị về biến đổi khí hậu.","fa":"استاد سخنرانی جالبی در مورد تغییرات آب و هوا ارائه کرد."},{"de":"Ich muss morgen einen Vortrag vor der Klasse halten.","en":"I have to give a presentation in front of the class tomorrow.","ru":"Завтра мне нужно выступить с докладом перед классом.","vi":"Ngày mai tôi phải giảng bài cho lớp.","fa":"فردا باید سر کلاس سخنرانی کنم."}]},{"word":"die Vorwahl","en":"area code, dial code","ru":"код города/страны (телефонный)","vi":"mã vùng","fa":"کد منطقه","examples":[{"de":"Wie lautet die Vorwahl von Berlin?","en":"What is the area code for Berlin?","ru":"Какой телефонный код у Берлина?","vi":"Mã vùng của Berlin là gì?","fa":"کد منطقه ای برلین چیست؟"},{"de":"Ohne die richtige Vorwahl kann ich dich nicht anrufen.","en":"Without the correct dial code, I can't call you.","ru":"Без правильного кода я не смогу тебе позвонить.","vi":"Tôi không thể gọi cho bạn nếu không có mã vùng chính xác.","fa":"من نمی توانم بدون کد منطقه صحیح با شما تماس بگیرم."}]},{"word":"vorwärts","en":"forward","ru":"вперёд","vi":"phía trước","fa":"به جلو","examples":[{"de":"Geh drei Schritte vorwärts.","en":"Take three steps forward.","ru":"Сделай три шага вперёд.","vi":"Tiến lên phía trước ba bước.","fa":"سه قدم به جلو بردارید."},{"de":"Das Projekt kommt langsam vorwärts.","en":"The project is slowly moving forward.","ru":"Проект медленно продвигается вперёд.","vi":"Dự án đang dần tiến triển.","fa":"این پروژه کم کم در حال پیشرفت است."}]},{"word":"der Vorwurf","en":"reproach, accusation","ru":"упрёк, обвинение","vi":"lời buộc tội","fa":"اتهام","examples":[{"de":"Sie machte ihm den Vorwurf, nie zuzuhören.","en":"She accused him of never listening.","ru":"Она упрекнула его в том, что он никогда не слушает.","vi":"Cô buộc tội anh không bao giờ lắng nghe.","fa":"او را متهم کرد که هرگز گوش نمی دهد."},{"de":"Ich mache dir keinen Vorwurf, es war nicht deine Schuld.","en":"I'm not blaming you, it wasn't your fault.","ru":"Я не упрекаю тебя, это была не твоя вина.","vi":"Tôi không trách bạn, đó không phải lỗi của bạn.","fa":"من تو را سرزنش نمی کنم، تقصیر تو نبود."}]},{"word":"waagerecht","en":"horizontal","ru":"горизонтальный","vi":"theo chiều ngang","fa":"به صورت افقی","examples":[{"de":"Bitte hängen Sie das Bild waagerecht auf.","en":"Please hang the picture horizontally.","ru":"Пожалуйста, повесьте картину горизонтально.","vi":"Hãy treo bức tranh theo chiều ngang.","fa":"لطفا تصویر را به صورت افقی آویزان کنید."},{"de":"Die Linie muss genau waagerecht verlaufen.","en":"The line must run exactly horizontally.","ru":"Линия должна идти строго горизонтально.","vi":"Đường này phải nằm ngang chính xác.","fa":"خط باید دقیقاً افقی باشد."}]},{"word":"wach","en":"awake","ru":"бодрствующий, не спящий","vi":"thức dậy","fa":"بیدار","examples":[{"de":"Um sechs Uhr war ich schon wach.","en":"I was already awake at six o'clock.","ru":"В шесть часов я уже не спал.","vi":"Tôi đã thức dậy lúc sáu giờ.","fa":"من قبلاً ساعت شش بیدار بودم."},{"de":"Der Kaffee hilft mir, wach zu bleiben.","en":"Coffee helps me stay awake.","ru":"Кофе помогает мне не засыпать.","vi":"Cà phê giúp tôi tỉnh táo.","fa":"قهوه به من کمک می کند بیدار بمانم."}]},{"word":"wachsen","en":"to grow","ru":"расти","vi":"phát triển","fa":"رشد کنند","examples":[{"de":"Die Pflanze wächst sehr schnell im Sommer.","en":"The plant grows very quickly in summer.","ru":"Растение очень быстро растёт летом.","vi":"Cây phát triển rất nhanh vào mùa hè.","fa":"این گیاه در تابستان خیلی سریع رشد می کند."},{"de":"Kinder wachsen in den ersten Jahren am schnellsten.","en":"Children grow the fastest in the first years.","ru":"Дети растут быстрее всего в первые годы.","vi":"Trẻ em phát triển nhanh nhất trong những năm đầu đời.","fa":"بچه ها در سال های اول زندگی سریع ترین رشد می کنند."}]},{"word":"der Wagen","en":"car; carriage","ru":"машина; вагон","vi":"chiếc xe","fa":"ماشین","examples":[{"de":"Er parkt seinen Wagen vor dem Haus.","en":"He parks his car in front of the house.","ru":"Он паркует свою машину перед домом.","vi":"Anh đậu xe trước nhà.","fa":"ماشینش را جلوی در خانه پارک می کند."},{"de":"Der Zug hat zehn Wagen.","en":"The train has ten carriages.","ru":"У поезда десять вагонов.","vi":"Đoàn tàu có mười toa.","fa":"قطار ده واگن دارد."}]},{"word":"die Wahl","en":"election; choice","ru":"выборы; выбор","vi":"sự lựa chọn","fa":"انتخاب","examples":[{"de":"Bei der Wahl haben viele Menschen abgestimmt.","en":"Many people voted in the election.","ru":"На выборах проголосовало много людей.","vi":"Nhiều người đã bỏ phiếu trong cuộc bầu cử.","fa":"افراد زیادی در انتخابات رای دادند."},{"de":"Du hast die Wahl zwischen Tee und Kaffee.","en":"You have the choice between tea and coffee.","ru":"У тебя есть выбор между чаем и кофе.","vi":"Bạn có sự lựa chọn giữa trà và cà phê.","fa":"شما بین چای و قهوه انتخاب دارید."}]},{"word":"wählen","en":"to choose; to vote","ru":"выбирать; голосовать","vi":"chọn","fa":"انتخاب کنید","examples":[{"de":"Ich muss zwischen zwei Angeboten wählen.","en":"I have to choose between two offers.","ru":"Мне нужно выбрать между двумя предложениями.","vi":"Tôi phải lựa chọn giữa hai lời đề nghị.","fa":"من باید بین دو پیشنهاد یکی را انتخاب کنم."},{"de":"Am Sonntag wählen die Bürger einen neuen Bürgermeister.","en":"On Sunday the citizens vote for a new mayor.","ru":"В воскресенье граждане выбирают нового мэра.","vi":"Vào Chủ nhật, người dân sẽ bầu một thị trưởng mới.","fa":"روز یکشنبه شهروندان شهردار جدید را انتخاب خواهند کرد."}]},{"word":"wahnsinnig","en":"crazy; incredibly (intensifier)","ru":"сумасшедший; ужасно, очень","vi":"mất trí","fa":"مجنون","examples":[{"de":"Das Konzert war wahnsinnig laut.","en":"The concert was incredibly loud.","ru":"Концерт был ужасно громким.","vi":"Buổi hòa nhạc cực kỳ ồn ào.","fa":"کنسرت فوق العاده بلند بود."},{"de":"Er wurde wahnsinnig vor Wut.","en":"He went crazy with rage.","ru":"Он сошёл с ума от ярости.","vi":"Anh ta nổi điên lên vì giận dữ.","fa":"از عصبانیت دیوانه شد."}]},{"word":"wahr","en":"true","ru":"истинный, правдивый","vi":"đúng","fa":"درست است","examples":[{"de":"Ist es wahr, dass du umziehst?","en":"Is it true that you're moving?","ru":"Правда ли, что ты переезжаешь?","vi":"Có đúng là bạn đang di chuyển?","fa":"آیا این درست است که شما در حال حرکت هستید؟"},{"de":"Seine Geschichte war leider nicht wahr.","en":"Unfortunately, his story wasn't true.","ru":"К сожалению, его история была неправдой.","vi":"Thật không may, câu chuyện của anh ấy không có thật.","fa":"متاسفانه داستان او درست نبود."}]},{"word":"während","en":"during; while","ru":"во время; пока","vi":"trong khi","fa":"در حالی که","examples":[{"de":"Während des Urlaubs habe ich viel gelesen.","en":"During the vacation I read a lot.","ru":"Во время отпуска я много читал.","vi":"Tôi đọc rất nhiều trong kỳ nghỉ.","fa":"در تعطیلات زیاد مطالعه می کنم."},{"de":"Während sie kochte, deckte er den Tisch.","en":"While she was cooking, he set the table.","ru":"Пока она готовила, он накрывал на стол.","vi":"Trong khi cô nấu ăn, anh dọn bàn ăn.","fa":"در حالی که او آشپزی می کرد، سفره را چید."}]},{"word":"wahrnehmen","en":"to perceive; to notice; to take up","ru":"воспринимать; замечать","vi":"nhận thức","fa":"درک کنند","examples":[{"de":"Aus der Ferne konnte er nur Umrisse wahrnehmen.","en":"From a distance he could only make out outlines.","ru":"Издалека он мог различить лишь очертания.","vi":"Từ xa anh chỉ có thể nhìn thấy những đường nét.","fa":"از دور فقط می توانست خطوط کلی را ببیند."},{"de":"Sie hat den Termin leider nicht wahrgenommen.","en":"Unfortunately she didn't keep the appointment.","ru":"К сожалению, она не явилась на назначенную встречу.","vi":"Thật không may là cô ấy đã không giữ lời hẹn.","fa":"متأسفانه او قرار ملاقات را رعایت نکرد."}]},{"word":"wahrscheinlich","en":"probably","ru":"вероятно","vi":"có lẽ","fa":"احتمالا","examples":[{"de":"Es wird wahrscheinlich morgen regnen.","en":"It will probably rain tomorrow.","ru":"Завтра, вероятно, пойдёт дождь.","vi":"Có lẽ ngày mai trời sẽ mưa.","fa":"احتمالا فردا باران خواهد بارید."},{"de":"Er kommt wahrscheinlich zu spät.","en":"He'll probably be late.","ru":"Он, вероятно, опоздает.","vi":"Có lẽ anh ấy đến muộn.","fa":"احتمالا دیر کرده"}]},{"word":"der Wald","en":"forest","ru":"лес","vi":"rừng","fa":"جنگل","examples":[{"de":"Wir machen einen Spaziergang im Wald.","en":"We're going for a walk in the forest.","ru":"Мы гуляем в лесу.","vi":"Chúng tôi đi dạo trong rừng.","fa":"در جنگل قدم می زنیم."},{"de":"Im Wald leben viele Tiere.","en":"Many animals live in the forest.","ru":"В лесу живёт много животных.","vi":"Nhiều loài động vật sống trong rừng.","fa":"حیوانات زیادی در جنگل زندگی می کنند."}]},{"word":"die Wand","en":"wall","ru":"стена","vi":"bức tường","fa":"دیوار","examples":[{"de":"An der Wand hängt ein Bild.","en":"A picture hangs on the wall.","ru":"На стене висит картина.","vi":"Có một bức tranh treo trên tường.","fa":"یک عکس روی دیوار آویزان است."},{"de":"Wir streichen die Wände neu.","en":"We're repainting the walls.","ru":"Мы заново красим стены.","vi":"Chúng tôi đang sơn lại các bức tường.","fa":"ما دیوارها را دوباره رنگ می کنیم."}]},{"word":"wandern","en":"to hike","ru":"путешествовать пешком, ходить в поход","vi":"đi lang thang","fa":"پیاده روی","examples":[{"de":"Am Wochenende wandern wir in den Bergen.","en":"On the weekend we hike in the mountains.","ru":"На выходных мы ходим в поход в горы.","vi":"Vào cuối tuần chúng tôi đi leo núi.","fa":"آخر هفته در کوه پیاده روی می کنیم."},{"de":"Sie wandert gern durch den Wald.","en":"She likes hiking through the forest.","ru":"Она любит гулять по лесу.","vi":"Cô ấy thích đi bộ xuyên rừng.","fa":"او پیاده روی در جنگل را دوست دارد."}]},{"word":"wann","en":"when","ru":"когда","vi":"khi nào","fa":"چه زمانی","examples":[{"de":"Wann beginnt der Film?","en":"When does the movie start?","ru":"Когда начинается фильм?","vi":"Khi nào bộ phim bắt đầu?","fa":"فیلم کی شروع میشه؟"},{"de":"Ich weiß nicht, wann er ankommt.","en":"I don't know when he'll arrive.","ru":"Я не знаю, когда он приедет.","vi":"Tôi không biết khi nào anh ấy sẽ đến.","fa":"نمی دانم کی می آید."}]},{"word":"die Ware","en":"goods; merchandise","ru":"товар","vi":"hàng hóa","fa":"کالاها","examples":[{"de":"Die Ware wird morgen geliefert.","en":"The goods will be delivered tomorrow.","ru":"Товар доставят завтра.","vi":"Hàng hóa sẽ được giao vào ngày mai.","fa":"کالا فردا تحویل داده می شود."},{"de":"Im Laden gibt es viele verschiedene Waren.","en":"The shop has many different goods.","ru":"В магазине много разных товаров.","vi":"Có rất nhiều hàng hóa khác nhau trong cửa hàng.","fa":"اجناس مختلف زیادی در فروشگاه وجود دارد."}]},{"word":"warm","en":"warm","ru":"тёплый","vi":"ấm áp","fa":"گرم","examples":[{"de":"Heute ist es sehr warm draußen.","en":"It's very warm outside today.","ru":"Сегодня на улице очень тепло.","vi":"Hôm nay ngoài trời rất ấm áp.","fa":"امروز بیرون خیلی گرمه"},{"de":"Ich trinke gern warmen Tee.","en":"I like drinking warm tea.","ru":"Я люблю пить тёплый чай.","vi":"Tôi thích uống trà ấm.","fa":"من دوست دارم چای گرم بنوشم."}]},{"word":"warnen","en":"to warn","ru":"предупреждать","vi":"cảnh báo","fa":"هشدار دهد","examples":[{"de":"Der Arzt warnt vor zu viel Zucker.","en":"The doctor warns against too much sugar.","ru":"Врач предупреждает об избытке сахара.","vi":"Bác sĩ cảnh báo không nên ăn quá nhiều đường.","fa":"پزشک نسبت به مصرف بیش از حد قند هشدار می دهد."},{"de":"Sie warnte mich vor der Gefahr.","en":"She warned me about the danger.","ru":"Она предупредила меня об опасности.","vi":"Cô ấy đã cảnh báo tôi về sự nguy hiểm.","fa":"او به من در مورد خطر هشدار داد."}]},{"word":"warten","en":"to wait","ru":"ждать","vi":"chờ đã","fa":"صبر کن","examples":[{"de":"Ich warte seit einer Stunde auf den Bus.","en":"I've been waiting for the bus for an hour.","ru":"Я жду автобус уже час.","vi":"Tôi đã đợi xe buýt được một giờ rồi.","fa":"یک ساعتی است که منتظر اتوبوس هستم."},{"de":"Bitte warten Sie einen Moment.","en":"Please wait a moment.","ru":"Пожалуйста, подождите минутку.","vi":"Xin vui lòng chờ một lát.","fa":"لطفا یک لحظه صبر کنید."}]},{"word":"warum","en":"why","ru":"почему","vi":"tại sao","fa":"چرا","examples":[{"de":"Warum bist du so traurig?","en":"Why are you so sad?","ru":"Почему ты такой грустный?","vi":"Tại sao bạn lại buồn thế?","fa":"چرا اینقدر غمگینی؟"},{"de":"Ich verstehe nicht, warum er nicht anruft.","en":"I don't understand why he doesn't call.","ru":"Я не понимаю, почему он не звонит.","vi":"Tôi không hiểu tại sao anh ấy không gọi.","fa":"نمیفهمم چرا زنگ نمیزنه"}]},{"word":"was","en":"what","ru":"что","vi":"cái gì","fa":"چی","examples":[{"de":"Was machst du heute Abend?","en":"What are you doing tonight?","ru":"Что ты делаешь сегодня вечером?","vi":"Tối nay bạn đang làm gì?","fa":"امشب چیکار میکنی؟"},{"de":"Was hast du gesagt?","en":"What did you say?","ru":"Что ты сказал?","vi":"Bạn đã nói gì?","fa":"چی گفتی؟"}]},{"word":"was für ein-","en":"what kind of","ru":"какой, что за","vi":"cái gì-","fa":"چی الف-","examples":[{"de":"Was für ein Auto hast du?","en":"What kind of car do you have?","ru":"Какая у тебя машина?","vi":"Bạn có loại xe nào?","fa":"چه نوع ماشینی دارید؟"},{"de":"Was für eine gute Idee!","en":"What a good idea!","ru":"Какая хорошая идея!","vi":"Thật là một ý tưởng hay!","fa":"چه ایده خوبی!"}]},{"word":"das Wasser","en":"water","ru":"вода","vi":"nước","fa":"آب","examples":[{"de":"Ich trinke jeden Tag viel Wasser.","en":"I drink a lot of water every day.","ru":"Я пью много воды каждый день.","vi":"Tôi uống rất nhiều nước mỗi ngày.","fa":"من هر روز مقدار زیادی آب می نوشم."},{"de":"Das Wasser im See ist sehr kalt.","en":"The water in the lake is very cold.","ru":"Вода в озере очень холодная.","vi":"Nước trong hồ rất lạnh.","fa":"آب دریاچه بسیار سرد است."}]},{"word":"wechseln","en":"to change; to exchange","ru":"менять; обменивать","vi":"chuyển đổi","fa":"سوئیچ","examples":[{"de":"Ich muss den Reifen wechseln.","en":"I have to change the tire.","ru":"Мне нужно поменять шину.","vi":"Tôi phải thay lốp.","fa":"باید لاستیک رو عوض کنم"},{"de":"Wo kann ich Geld wechseln?","en":"Where can I exchange money?","ru":"Где я могу обменять деньги?","vi":"Tôi có thể đổi tiền ở đâu?","fa":"کجا پول عوض کنم؟"}]},{"word":"wecken","en":"to wake (someone) up","ru":"будить","vi":"thức dậy","fa":"بیدار شو","examples":[{"de":"Der Wecker weckt mich um sechs Uhr.","en":"The alarm clock wakes me up at six.","ru":"Будильник будит меня в шесть.","vi":"Đồng hồ báo thức đánh thức tôi dậy lúc sáu giờ.","fa":"ساعت زنگ دار من را ساعت شش بیدار می کند."},{"de":"Bitte weck mich nicht so früh.","en":"Please don't wake me up so early.","ru":"Пожалуйста, не буди меня так рано.","vi":"Làm ơn đừng đánh thức tôi dậy sớm thế.","fa":"لطفا اینقدر زود بیدارم نکن"}]},{"word":"weder … noch","en":"neither ... nor","ru":"ни ... ни","vi":"không…cũng không","fa":"نه… نه","examples":[{"de":"Ich mag weder Kaffee noch Tee.","en":"I like neither coffee nor tea.","ru":"Я не люблю ни кофе, ни чай.","vi":"Tôi không thích cà phê hay trà.","fa":"من قهوه یا چای دوست ندارم."},{"de":"Er hat weder angerufen noch geschrieben.","en":"He neither called nor wrote.","ru":"Он ни позвонил, ни написал.","vi":"Anh ấy không gọi điện hay viết thư.","fa":"نه زنگ زد و نه نوشت."}]},{"word":"der Weg","en":"way; path","ru":"путь, дорога","vi":"con đường","fa":"راه","examples":[{"de":"Können Sie mir den Weg zum Bahnhof zeigen?","en":"Can you show me the way to the station?","ru":"Вы можете показать мне дорогу к вокзалу?","vi":"Bạn có thể chỉ cho tôi đường đến ga xe lửa được không?","fa":"می توانید راه ایستگاه قطار را به من نشان دهید؟"},{"de":"Der Weg durch den Wald ist sehr schön.","en":"The path through the forest is very beautiful.","ru":"Тропа через лес очень красивая.","vi":"Con đường xuyên rừng rất đẹp.","fa":"مسیر میان جنگل بسیار زیباست."}]},{"word":"weg/weg-","en":"away, gone","ru":"прочь, отсутствующий","vi":"đi/đi xa-","fa":"دور / دور -","examples":[{"de":"Meine Tasche ist plötzlich weg.","en":"My bag is suddenly gone.","ru":"Моя сумка вдруг пропала.","vi":"Túi của tôi đột nhiên biến mất.","fa":"کیف من ناگهان از بین رفت."},{"de":"Geh weg von der Straße!","en":"Get away from the street!","ru":"Отойди от дороги!","vi":"Hãy ra khỏi đường phố!","fa":"از خیابان برو!"}]},{"word":"wegen","en":"because of","ru":"из-за","vi":"bởi vì","fa":"به دلیل","examples":[{"de":"Wegen des Regens bleiben wir zu Hause.","en":"Because of the rain we're staying home.","ru":"Из-за дождя мы остаёмся дома.","vi":"Vì trời mưa nên chúng tôi ở nhà.","fa":"به خاطر باران در خانه می مانیم."},{"de":"Sie ist wegen der Prüfung sehr nervös.","en":"She's very nervous because of the exam.","ru":"Она очень нервничает из-за экзамена.","vi":"Cô ấy rất lo lắng về kỳ thi.","fa":"او در مورد امتحان بسیار عصبی است."}]},{"word":"wehtun","en":"to hurt","ru":"болеть, причинять боль","vi":"đau","fa":"صدمه دیده","examples":[{"de":"Mein Kopf tut weh.","en":"My head hurts.","ru":"У меня болит голова.","vi":"Đầu tôi đau quá.","fa":"سرم درد میکنه"},{"de":"Seine Worte haben mir sehr wehgetan.","en":"His words hurt me a lot.","ru":"Его слова очень меня задели.","vi":"Lời nói của anh làm tôi tổn thương rất nhiều.","fa":"حرف هایش مرا خیلی آزار داد."}]},{"word":"weiblich","en":"female; feminine","ru":"женский","vi":"nữ","fa":"زن","examples":[{"de":"Das weibliche Geschlecht ist hier in der Mehrheit.","en":"The female sex is in the majority here.","ru":"Женский пол здесь в большинстве.","vi":"Ở đây giới tính nữ chiếm đa số.","fa":"جنس زن در اینجا اکثریت است."},{"de":"„die“ ist ein weiblicher Artikel.","en":"'die' is a feminine article.","ru":"«die» — женский артикль.","vi":"“die” là một mạo từ nữ tính.","fa":"«بمیر» یک مقاله زنانه است."}]},{"word":"weich","en":"soft","ru":"мягкий","vi":"mềm mại","fa":"نرم","examples":[{"de":"Das Kissen ist sehr weich.","en":"The pillow is very soft.","ru":"Подушка очень мягкая.","vi":"Gối rất mềm.","fa":"بالش بسیار نرم است."},{"de":"Ich mag weiches Brot lieber als hartes.","en":"I prefer soft bread to hard bread.","ru":"Я предпочитаю мягкий хлеб твёрдому.","vi":"Tôi thích bánh mì mềm hơn bánh mì cứng.","fa":"من نان نرم را بهتر از نان سفت دوست دارم."}]},{"word":"weil","en":"because","ru":"потому что","vi":"bởi vì","fa":"چون","examples":[{"de":"Ich bleibe zu Hause, weil ich krank bin.","en":"I'm staying home because I'm sick.","ru":"Я остаюсь дома, потому что я болен.","vi":"Tôi đang ở nhà vì tôi bị ốm.","fa":"من در خانه می مانم چون مریض هستم."},{"de":"Wir gehen früh, weil der Zug bald fährt.","en":"We're leaving early because the train departs soon.","ru":"Мы уходим рано, потому что поезд скоро отправляется.","vi":"Chúng tôi khởi hành sớm vì tàu sắp khởi hành.","fa":"ما زود حرکت می کنیم زیرا قطار به زودی حرکت می کند."}]},{"word":"der Wein","en":"wine","ru":"вино","vi":"rượu vang","fa":"شراب","examples":[{"de":"Zum Essen trinken wir ein Glas Wein.","en":"We drink a glass of wine with the meal.","ru":"За едой мы пьём бокал вина.","vi":"Chúng tôi uống một ly rượu trong bữa ăn.","fa":"با غذا یک لیوان شراب می نوشیم."},{"de":"Dieser Wein kommt aus Italien.","en":"This wine is from Italy.","ru":"Это вино из Италии.","vi":"Loại rượu này đến từ Ý.","fa":"این شراب از ایتالیا می آید."}]},{"word":"weinen","en":"to cry","ru":"плакать","vi":"khóc","fa":"گریه کن","examples":[{"de":"Das Baby weint, weil es Hunger hat.","en":"The baby is crying because it's hungry.","ru":"Малыш плачет, потому что голоден.","vi":"Bé khóc vì đói.","fa":"نوزاد به دلیل گرسنگی گریه می کند."},{"de":"Sie musste vor Freude weinen.","en":"She had to cry with joy.","ru":"Она заплакала от радости.","vi":"Cô đã phải khóc vì sung sướng.","fa":"مجبور شد از خوشحالی گریه کند."}]},{"word":"weit","en":"far; wide","ru":"далёкий, широкий","vi":"xa","fa":"دور","examples":[{"de":"Die Schule ist nicht weit von hier.","en":"The school is not far from here.","ru":"Школа недалеко отсюда.","vi":"Trường học cách đây không xa.","fa":"مدرسه از اینجا دور نیست."},{"de":"Er trägt gern weite Hosen.","en":"He likes wearing wide, loose pants.","ru":"Он любит носить широкие брюки.","vi":"Anh ấy thích mặc quần rộng.","fa":"او دوست دارد شلوار گشاد بپوشد."}]},{"word":"weiter","en":"further; on, continuing","ru":"дальше, далее","vi":"hơn nữa","fa":"بیشتر","examples":[{"de":"Bitte lesen Sie weiter.","en":"Please continue reading.","ru":"Пожалуйста, читайте дальше.","vi":"Xin vui lòng đọc tiếp.","fa":"لطفا به ادامه مطلب بروید"},{"de":"Der nächste Ort liegt zehn Kilometer weiter.","en":"The next town is ten kilometers further.","ru":"Следующий населённый пункт находится на десять километров дальше.","vi":"Thị trấn tiếp theo cách xa hơn mười km.","fa":"شهر بعدی ده کیلومتر جلوتر است."}]},{"word":"die Weiterbildung","en":"further education, training","ru":"повышение квалификации","vi":"đào tạo thêm","fa":"آموزش بیشتر","examples":[{"de":"Meine Firma bietet Kurse zur Weiterbildung an.","en":"My company offers courses for further training.","ru":"Моя фирма предлагает курсы повышения квалификации.","vi":"Công ty của tôi cung cấp các khóa học giáo dục thường xuyên.","fa":"شرکت من دوره های آموزش مداوم را ارائه می دهد."},{"de":"Sie macht eine Weiterbildung im Bereich Informatik.","en":"She's doing further training in IT.","ru":"Она проходит повышение квалификации в сфере информатики.","vi":"Cô đang được đào tạo thêm trong lĩnh vực khoa học máy tính.","fa":"او در حال گذراندن دوره های آموزشی بیشتر در زمینه علوم کامپیوتر است."}]},{"word":"welcher","en":"which","ru":"который, какой","vi":"cái nào","fa":"کدام یک","examples":[{"de":"Welcher Bus fährt zum Zentrum?","en":"Which bus goes to the center?","ru":"Какой автобус едет в центр?","vi":"Xe buýt nào đi vào trung tâm?","fa":"کدام اتوبوس به مرکز می رود؟"},{"de":"Welche Farbe gefällt dir am besten?","en":"Which color do you like best?","ru":"Какой цвет тебе нравится больше всего?","vi":"Bạn thích màu nào nhất?","fa":"کدام رنگ را بیشتر دوست دارید؟"}]},{"word":"die Welt","en":"world","ru":"мир","vi":"thế giới","fa":"جهان","examples":[{"de":"Er möchte die ganze Welt bereisen.","en":"He wants to travel the whole world.","ru":"Он хочет объездить весь мир.","vi":"Anh ấy muốn đi du lịch khắp thế giới.","fa":"او می خواهد تمام دنیا را سفر کند."},{"de":"Das Internet hat die Welt verändert.","en":"The internet has changed the world.","ru":"Интернет изменил мир.","vi":"Internet đã thay đổi thế giới.","fa":"اینترنت دنیا را تغییر داده است."}]},{"word":"wenden","en":"to turn","ru":"поворачивать, разворачивать","vi":"rẽ","fa":"چرخش","examples":[{"de":"Er musste auf der schmalen Straße wenden.","en":"He had to turn around on the narrow street.","ru":"Ему пришлось развернуться на узкой улице.","vi":"Anh phải quay đầu lại trên con đường hẹp.","fa":"مجبور شد در جاده باریک بپیچد."},{"de":"Bitte wenden Sie sich an die Rezeption.","en":"Please turn to the reception desk.","ru":"Пожалуйста, обратитесь на ресепшн.","vi":"Vui lòng liên hệ lễ tân.","fa":"لطفا با پذیرش تماس بگیرید"}]},{"word":"wenig/wenige","en":"little; few","ru":"мало, немного","vi":"ít/ít","fa":"کم/کم","examples":[{"de":"Ich habe heute wenig Zeit.","en":"I have little time today.","ru":"У меня сегодня мало времени.","vi":"Hôm nay tôi có ít thời gian.","fa":"امروز وقت کمی دارم"},{"de":"Nur wenige Leute kamen zur Party.","en":"Only a few people came to the party.","ru":"На вечеринку пришло лишь немного людей.","vi":"Chỉ có một vài người đến dự bữa tiệc.","fa":"فقط چند نفر به مهمانی آمدند."}]},{"word":"wenigstens","en":"at least","ru":"по крайней мере","vi":"ít nhất","fa":"حداقل","examples":[{"de":"Ruf mich wenigstens kurz an.","en":"At least give me a quick call.","ru":"Позвони мне хотя бы ненадолго.","vi":"Ít nhất hãy gọi cho tôi nhanh nhé.","fa":"حداقل یه زنگ سریع بزن"},{"de":"Wenigstens hat es nicht geregnet.","en":"At least it didn't rain.","ru":"По крайней мере, дождя не было.","vi":"Ít nhất thì trời không mưa.","fa":"حداقل باران نبارید."}]},{"word":"wenn","en":"if; when","ru":"если; когда","vi":"nếu","fa":"اگر","examples":[{"de":"Wenn es regnet, bleiben wir zu Hause.","en":"If it rains, we'll stay home.","ru":"Если пойдёт дождь, мы останемся дома.","vi":"Nếu trời mưa thì chúng ta ở nhà.","fa":"اگر باران ببارد، ما در خانه می مانیم."},{"de":"Wenn ich Zeit habe, rufe ich dich an.","en":"When I have time, I'll call you.","ru":"Когда у меня будет время, я тебе позвоню.","vi":"Khi nào có thời gian tôi sẽ gọi cho bạn.","fa":"وقتی وقت کنم بهت زنگ میزنم"}]},{"word":"wer","en":"who","ru":"кто","vi":"ai","fa":"چه کسی","examples":[{"de":"Wer ist diese Frau?","en":"Who is this woman?","ru":"Кто эта женщина?","vi":"Người phụ nữ này là ai?","fa":"این زن کیست؟"},{"de":"Ich weiß nicht, wer angerufen hat.","en":"I don't know who called.","ru":"Я не знаю, кто звонил.","vi":"Tôi không biết ai đã gọi.","fa":"نمیدونم کی زنگ زد"}]},{"word":"die Werbung","en":"advertising","ru":"реклама","vi":"quảng cáo","fa":"تبلیغات","examples":[{"de":"Im Fernsehen läuft viel Werbung.","en":"There's a lot of advertising on TV.","ru":"По телевизору много рекламы.","vi":"Có rất nhiều quảng cáo trên truyền hình.","fa":"تبلیغات زیادی در تلویزیون پخش می شود."},{"de":"Die Firma macht Werbung für ihr neues Produkt.","en":"The company is advertising its new product.","ru":"Компания рекламирует свой новый продукт.","vi":"Công ty đang quảng cáo sản phẩm mới của mình.","fa":"این شرکت در حال تبلیغ محصول جدید خود است."}]},{"word":"werden","en":"to become","ru":"становиться","vi":"trở thành","fa":"تبدیل شود","examples":[{"de":"Sie will Ärztin werden.","en":"She wants to become a doctor.","ru":"Она хочет стать врачом.","vi":"Cô ấy muốn trở thành một bác sĩ.","fa":"او می خواهد دکتر شود."},{"de":"Es wird langsam dunkel.","en":"It's slowly becoming dark.","ru":"Постепенно темнеет.","vi":"Trời đang dần tối.","fa":"کم کم داره تاریک میشه"}]},{"word":"werfen","en":"to throw","ru":"бросать","vi":"ném","fa":"پرتاب","examples":[{"de":"Er wirft den Ball zu seinem Freund.","en":"He throws the ball to his friend.","ru":"Он бросает мяч своему другу.","vi":"Anh ấy ném quả bóng cho bạn mình.","fa":"او توپ را به طرف دوستش پرتاب می کند."},{"de":"Wirf das Papier nicht auf den Boden!","en":"Don't throw the paper on the floor!","ru":"Не бросай бумагу на пол!","vi":"Đừng ném tờ giấy xuống sàn nhà!","fa":"کاغذ را روی زمین نریزید!"}]},{"word":"das Werk","en":"work, piece of work; factory, plant","ru":"произведение; завод","vi":"công việc","fa":"کار","examples":[{"de":"Dieses Gemälde ist ein bekanntes Werk des Künstlers.","en":"This painting is a well-known work of the artist.","ru":"Эта картина — известное произведение художника.","vi":"Bức tranh này là một tác phẩm nổi tiếng của họa sĩ.","fa":"این نقاشی از آثار شناخته شده این هنرمند است."},{"de":"Mein Vater arbeitet im Werk am Stadtrand.","en":"My father works at the plant on the edge of town.","ru":"Мой отец работает на заводе на окраине города.","vi":"Bố tôi làm việc tại nhà máy ở ngoại ô thị trấn.","fa":"پدرم در کارخانه ای در حومه شهر کار می کند."}]},{"word":"wert","en":"worth","ru":"стоящий, ценный","vi":"giá trị","fa":"ارزش","examples":[{"de":"Der alte Ring ist viel Geld wert.","en":"The old ring is worth a lot of money.","ru":"Старое кольцо стоит много денег.","vi":"Chiếc nhẫn cũ có giá trị rất nhiều tiền.","fa":"انگشتر قدیمی ارزش پول زیادی دارد."},{"de":"Der Film ist es wert, gesehen zu werden.","en":"The movie is worth watching.","ru":"Фильм стоит того, чтобы его посмотреть.","vi":"Bộ phim rất đáng xem.","fa":"فیلم ارزش دیدن را دارد."}]},{"word":"der Wert","en":"value","ru":"ценность, значение","vi":"giá trị","fa":"ارزش","examples":[{"de":"Der Wert des Hauses ist gestiegen.","en":"The value of the house has increased.","ru":"Стоимость дома выросла.","vi":"Giá trị của ngôi nhà đã tăng lên.","fa":"ارزش خانه افزایش یافته است."},{"de":"Sie legt großen Wert auf Pünktlichkeit.","en":"She places great value on punctuality.","ru":"Она придаёт большое значение пунктуальности.","vi":"Cô ấy rất coi trọng việc đúng giờ.","fa":"او به وقت شناسی اهمیت زیادی می دهد."}]},{"word":"wesentlich","en":"essential; considerably","ru":"существенный; значительно","vi":"thiết yếu","fa":"ضروری است","examples":[{"de":"Das ist ein wesentlicher Unterschied.","en":"That is an essential difference.","ru":"Это существенное различие.","vi":"Đó là một sự khác biệt quan trọng.","fa":"این یک تفاوت کلیدی است."},{"de":"Heute geht es mir wesentlich besser.","en":"I feel considerably better today.","ru":"Сегодня мне значительно лучше.","vi":"Hôm nay tôi cảm thấy tốt hơn nhiều rồi.","fa":"امروز حالم خیلی بهتر است."}]},{"word":"weshalb","en":"why","ru":"почему, по какой причине","vi":"tại sao","fa":"چرا","examples":[{"de":"Weshalb bist du so spät gekommen?","en":"Why did you come so late?","ru":"Почему ты пришёл так поздно?","vi":"Tại sao bạn đến muộn thế?","fa":"چرا اینقدر دیر اومدی؟"},{"de":"Ich weiß nicht, weshalb er böse ist.","en":"I don't know why he's angry.","ru":"Я не знаю, почему он злится.","vi":"Tôi không biết tại sao anh ấy lại tức giận.","fa":"نمی دانم چرا عصبانی است."}]},{"word":"der Wettbewerb","en":"competition","ru":"конкурс, соревнование","vi":"cuộc thi","fa":"رقابت","examples":[{"de":"Sie hat den Wettbewerb gewonnen.","en":"She won the competition.","ru":"Она выиграла конкурс.","vi":"Cô ấy đã thắng cuộc thi.","fa":"او برنده مسابقه شد."},{"de":"An dem Wettbewerb nehmen viele Schüler teil.","en":"Many students take part in the competition.","ru":"В конкурсе участвует много учеников.","vi":"Nhiều sinh viên tham gia cuộc thi.","fa":"دانش آموزان زیادی در این مسابقه شرکت می کنند."}]},{"word":"wetten","en":"to bet","ru":"спорить, держать пари","vi":"cá cược","fa":"شرط بندی","examples":[{"de":"Ich wette, dass es morgen regnet.","en":"I bet it will rain tomorrow.","ru":"Спорим, завтра пойдёт дождь.","vi":"Tôi cá là ngày mai trời sẽ mưa.","fa":"شرط میبندم فردا بارون میاد"},{"de":"Sie haben um zehn Euro gewettet.","en":"They bet ten euros.","ru":"Они поспорили на десять евро.","vi":"Bạn đặt cược mười euro.","fa":"ده یورو شرط کردی"}]},{"word":"das Wetter","en":"weather","ru":"погода","vi":"thời tiết","fa":"آب و هوا","examples":[{"de":"Das Wetter ist heute wunderschön.","en":"The weather is beautiful today.","ru":"Сегодня прекрасная погода.","vi":"Thời tiết hôm nay thật đẹp.","fa":"هوا امروز قشنگه"},{"de":"Bei schlechtem Wetter bleiben wir drinnen.","en":"In bad weather we stay indoors.","ru":"В плохую погоду мы остаёмся дома.","vi":"Nếu thời tiết xấu, chúng tôi ở trong nhà.","fa":"اگر هوا بد باشد داخل می مانیم."}]},{"word":"die Wettervorhersage","en":"weather forecast","ru":"прогноз погоды","vi":"dự báo thời tiết","fa":"پیش بینی آب و هوا","examples":[{"de":"Laut Wettervorhersage wird es morgen sonnig.","en":"According to the weather forecast, it will be sunny tomorrow.","ru":"Согласно прогнозу погоды, завтра будет солнечно.","vi":"Theo dự báo thời tiết thì ngày mai trời sẽ nắng.","fa":"طبق پیش بینی هواشناسی فردا هوا آفتابی خواهد بود."},{"de":"Ich schaue jeden Abend die Wettervorhersage.","en":"I watch the weather forecast every evening.","ru":"Я каждый вечер смотрю прогноз погоды.","vi":"Tôi kiểm tra dự báo thời tiết vào mỗi buổi tối.","fa":"من هر شب پیش بینی آب و هوا را چک می کنم."}]},{"word":"wichtig","en":"important","ru":"важный","vi":"quan trọng","fa":"مهم است","examples":[{"de":"Diese Entscheidung ist sehr wichtig für mich.","en":"This decision is very important to me.","ru":"Это решение очень важно для меня.","vi":"Quyết định này rất quan trọng đối với tôi.","fa":"این تصمیم برای من بسیار مهم است."},{"de":"Es ist wichtig, pünktlich zu sein.","en":"It's important to be punctual.","ru":"Важно быть пунктуальным.","vi":"Điều quan trọng là phải đúng giờ.","fa":"مهم این است که به موقع باشد."}]},{"word":"widersprechen","en":"to contradict","ru":"противоречить","vi":"mâu thuẫn","fa":"تناقض دارند","examples":[{"de":"Er widerspricht seinem Chef nie.","en":"He never contradicts his boss.","ru":"Он никогда не противоречит своему начальнику.","vi":"Anh ấy không bao giờ mâu thuẫn với sếp của mình.","fa":"او هرگز با رئیس خود مخالفت نمی کند."},{"de":"Diese Aussage widerspricht den Fakten.","en":"This statement contradicts the facts.","ru":"Это заявление противоречит фактам.","vi":"Tuyên bố này mâu thuẫn với sự thật.","fa":"این گفته با واقعیت ها تناقض دارد."}]},{"word":"wie","en":"how; as, like","ru":"как","vi":"thích","fa":"مانند","examples":[{"de":"Wie geht es dir?","en":"How are you?","ru":"Как дела?","vi":"Bạn dạo này thế nào?","fa":"حال شما چطور است؟"},{"de":"Sie singt wie eine Profisängerin.","en":"She sings like a professional singer.","ru":"Она поёт как профессиональная певица.","vi":"Cô ấy hát như một ca sĩ chuyên nghiệp.","fa":"او مانند یک خواننده حرفه ای می خواند."}]},{"word":"wie viel(e)","en":"how much; how many","ru":"сколько","vi":"bao nhiêu","fa":"چقدر(ها)","examples":[{"de":"Wie viel kostet das Ticket?","en":"How much does the ticket cost?","ru":"Сколько стоит билет?","vi":"Giá vé là bao nhiêu?","fa":"هزینه بلیط چقدر است؟"},{"de":"Wie viele Geschwister hast du?","en":"How many siblings do you have?","ru":"Сколько у тебя братьев и сестёр?","vi":"Bạn có bao nhiêu anh chị em?","fa":"چند تا خواهر و برادر داری؟"}]},{"word":"wieder","en":"again","ru":"снова, опять","vi":"một lần nữa","fa":"دوباره","examples":[{"de":"Er kommt morgen wieder.","en":"He's coming again tomorrow.","ru":"Он снова придёт завтра.","vi":"Anh ấy sẽ quay lại vào ngày mai.","fa":"فردا برمیگرده"},{"de":"Ich habe meinen Schlüssel wieder gefunden.","en":"I found my key again.","ru":"Я снова нашёл свой ключ.","vi":"Tôi lại tìm thấy chìa khóa của mình.","fa":"دوباره کلیدم را پیدا کردم."}]},{"word":"wiederholen","en":"to repeat","ru":"повторять","vi":"lặp lại","fa":"تکرار کنید","examples":[{"de":"Können Sie die Frage bitte wiederholen?","en":"Could you please repeat the question?","ru":"Не могли бы вы повторить вопрос?","vi":"Bạn có thể vui lòng lặp lại câu hỏi được không?","fa":"میشه لطفا سوال رو تکرار کنید"},{"de":"Wir wiederholen den Wortschatz vor der Prüfung.","en":"We're reviewing the vocabulary before the exam.","ru":"Мы повторяем словарный запас перед экзаменом.","vi":"Chúng tôi ôn lại từ vựng trước kỳ thi.","fa":"قبل از امتحان دایره لغات را مرور می کنیم."}]},{"word":"wiegen","en":"to weigh","ru":"весить, взвешивать","vi":"cân","fa":"وزن کردن","examples":[{"de":"Das Paket wiegt zwei Kilo.","en":"The package weighs two kilos.","ru":"Посылка весит два килограмма.","vi":"Gói hàng nặng hai kg.","fa":"وزن بسته دو کیلو می باشد."},{"de":"Der Verkäufer wiegt das Obst.","en":"The seller weighs the fruit.","ru":"Продавец взвешивает фрукты.","vi":"Người bán cân trái cây.","fa":"فروشنده میوه را وزن می کند."}]},{"word":"die Wiese","en":"meadow","ru":"луг","vi":"đồng cỏ","fa":"چمنزار","examples":[{"de":"Die Kühe stehen auf der Wiese.","en":"The cows are standing in the meadow.","ru":"Коровы стоят на лугу.","vi":"Những con bò đang đứng trên đồng cỏ.","fa":"گاوها در چمنزار ایستاده اند."},{"de":"Wir haben auf der Wiese gepicknickt.","en":"We had a picnic in the meadow.","ru":"Мы устроили пикник на лугу.","vi":"Chúng tôi đã có một buổi dã ngoại trên bãi cỏ.","fa":"ما یک پیک نیک روی چمن داشتیم."}]},{"word":"wieso","en":"why","ru":"почему","vi":"sao thế","fa":"چطور","examples":[{"de":"Wieso hast du das getan?","en":"Why did you do that?","ru":"Почему ты это сделал?","vi":"Tại sao bạn làm điều đó?","fa":"چرا این کار را کردی؟"},{"de":"Wieso kommst du nicht mit?","en":"Why aren't you coming along?","ru":"Почему ты не идёшь с нами?","vi":"Tại sao bạn không đi cùng tôi?","fa":"چرا با من نمی آیی؟"}]},{"word":"wild","en":"wild","ru":"дикий","vi":"hoang dã","fa":"وحشی","examples":[{"de":"Im Park leben wilde Tiere.","en":"Wild animals live in the park.","ru":"В парке живут дикие животные.","vi":"Động vật hoang dã sống trong công viên.","fa":"حیوانات وحشی در پارک زندگی می کنند."},{"de":"Die Kinder spielten wild im Garten.","en":"The children played wildly in the garden.","ru":"Дети дико резвились в саду.","vi":"Bọn trẻ đang chơi đùa trong vườn.","fa":"بچه ها در باغ وحشی بازی می کردند."}]},{"word":"willkommen","en":"welcome","ru":"добро пожаловать","vi":"chào mừng","fa":"خوش آمدید","examples":[{"de":"Herzlich willkommen in unserem Haus!","en":"Warm welcome to our house!","ru":"Добро пожаловать в наш дом!","vi":"Chào mừng đến với ngôi nhà của chúng tôi!","fa":"به خانه ما خوش آمدید!"},{"de":"Neue Mitarbeiter sind immer willkommen.","en":"New employees are always welcome.","ru":"Новые сотрудники всегда желанны.","vi":"Nhân viên mới luôn được chào đón.","fa":"کارکنان جدید همیشه خوش آمدید."}]},{"word":"der Wind","en":"wind","ru":"ветер","vi":"gió","fa":"باد","examples":[{"de":"Draußen weht ein starker Wind.","en":"A strong wind is blowing outside.","ru":"На улице дует сильный ветер.","vi":"Một cơn gió mạnh đang thổi bên ngoài.","fa":"در بیرون باد شدیدی می وزد."},{"de":"Der Wind hat den Regenschirm zerstört.","en":"The wind destroyed the umbrella.","ru":"Ветер сломал зонт.","vi":"Gió đã phá hủy chiếc ô.","fa":"باد چتر را خراب کرد."}]},{"word":"winken","en":"to wave","ru":"махать","vi":"làn sóng","fa":"موج","examples":[{"de":"Die Kinder winken dem Zug hinterher.","en":"The children wave after the train.","ru":"Дети машут вслед поезду.","vi":"Những đứa trẻ vẫy tay sau chuyến tàu.","fa":"بچه ها بعد از قطار دست تکان می دهند."},{"de":"Sie winkte mir vom Fenster aus zu.","en":"She waved to me from the window.","ru":"Она помахала мне из окна.","vi":"Cô ấy vẫy tay chào tôi từ cửa sổ.","fa":"از پنجره برایم دست تکان داد."}]},{"word":"wirken","en":"to seem, appear; to have an effect","ru":"казаться; действовать (об эффекте)","vi":"hành động","fa":"عمل کنید","examples":[{"de":"Er wirkte heute sehr müde.","en":"He seemed very tired today.","ru":"Сегодня он казался очень уставшим.","vi":"Hôm nay anh có vẻ rất mệt mỏi.","fa":"امروز خیلی خسته به نظر می رسید."},{"de":"Die Medizin wirkt schnell.","en":"The medicine works quickly.","ru":"Лекарство действует быстро.","vi":"Thuốc có tác dụng nhanh chóng.","fa":"دارو به سرعت عمل می کند."}]},{"word":"wirklich","en":"really","ru":"действительно, правда","vi":"thực sự","fa":"واقعا","examples":[{"de":"Das ist wirklich eine gute Idee.","en":"That's really a good idea.","ru":"Это действительно хорошая идея.","vi":"Đó thực sự là một ý tưởng tốt.","fa":"این یک ایده واقعا خوب است."},{"de":"Ist das wirklich passiert?","en":"Did that really happen?","ru":"Это действительно произошло?","vi":"Điều đó có thực sự xảy ra không?","fa":"واقعا این اتفاق افتاد؟"}]},{"word":"der Wirt","en":"host, innkeeper","ru":"хозяин (трактира), трактирщик","vi":"chủ nhà","fa":"میزبان","examples":[{"de":"Der Wirt begrüßte uns freundlich.","en":"The innkeeper greeted us kindly.","ru":"Хозяин трактира приветливо нас встретил.","vi":"Người chủ quán chào đón chúng tôi thân thiện.","fa":"صاحب مسافرخانه با دوستانه از ما استقبال کرد."},{"de":"Wir fragten den Wirt nach der Speisekarte.","en":"We asked the innkeeper for the menu.","ru":"Мы спросили хозяина о меню.","vi":"Chúng tôi hỏi chủ quán về thực đơn.","fa":"از مسافرخانه داری منو خواستیم."}]},{"word":"die Wirtschaft","en":"economy","ru":"экономика","vi":"nền kinh tế","fa":"اقتصاد","examples":[{"de":"Die Wirtschaft wächst in diesem Jahr stark.","en":"The economy is growing strongly this year.","ru":"В этом году экономика сильно растёт.","vi":"Nền kinh tế đang phát triển mạnh mẽ trong năm nay.","fa":"اقتصاد امسال به شدت در حال رشد است."},{"de":"Viele Menschen arbeiten in der Wirtschaft des Landes.","en":"Many people work in the country's economy.","ru":"Многие люди работают в экономике страны.","vi":"Nhiều người làm việc trong nền kinh tế của đất nước.","fa":"افراد زیادی در اقتصاد کشور کار می کنند."}]},{"word":"wissen","en":"to know","ru":"знать","vi":"biết","fa":"دانستن","examples":[{"de":"Ich weiß die Antwort nicht.","en":"I don't know the answer.","ru":"Я не знаю ответа.","vi":"Tôi không biết câu trả lời.","fa":"من جواب را نمی دانم."},{"de":"Weißt du, wo der Bahnhof ist?","en":"Do you know where the station is?","ru":"Ты знаешь, где вокзал?","vi":"Bạn có biết nhà ga xe lửa ở đâu không?","fa":"آیا می دانید ایستگاه قطار کجاست؟"}]},{"word":"die Wissenschaft","en":"science","ru":"наука","vi":"khoa học","fa":"علم","examples":[{"de":"Die Wissenschaft hat große Fortschritte gemacht.","en":"Science has made great progress.","ru":"Наука сделала большие успехи.","vi":"Khoa học đã có những tiến bộ vượt bậc.","fa":"علم پیشرفت زیادی کرده است."},{"de":"Sie interessiert sich sehr für Wissenschaft.","en":"She's very interested in science.","ru":"Она очень интересуется наукой.","vi":"Cô ấy rất quan tâm đến khoa học.","fa":"او علاقه زیادی به علم دارد."}]},{"word":"die Wissenschaftlerin","en":"female scientist","ru":"учёная, женщина-учёный","vi":"nhà khoa học","fa":"دانشمند","examples":[{"de":"Die Wissenschaftlerin forscht an einer neuen Impfung.","en":"The scientist is researching a new vaccine.","ru":"Учёная исследует новую вакцину.","vi":"Nhà khoa học đang nghiên cứu một loại vắc xin mới.","fa":"این دانشمند در حال تحقیق بر روی یک واکسن جدید است."},{"de":"Eine bekannte Wissenschaftlerin hielt den Vortrag.","en":"A famous scientist gave the lecture.","ru":"Известная учёная прочитала лекцию.","vi":"Một nhà khoa học nổi tiếng đã giảng bài.","fa":"یک دانشمند معروف این سخنرانی را ایراد کرد."}]},{"word":"der Witz","en":"joke","ru":"шутка, анекдот","vi":"trò đùa","fa":"شوخی","examples":[{"de":"Er erzählt gern Witze.","en":"He likes telling jokes.","ru":"Он любит рассказывать анекдоты.","vi":"Anh ấy thích kể chuyện cười.","fa":"او دوست دارد جوک بگوید."},{"de":"Das war kein guter Witz.","en":"That wasn't a good joke.","ru":"Это была не очень удачная шутка.","vi":"Đó không phải là một trò đùa hay.","fa":"این شوخی خوبی نبود"}]},{"word":"wo","en":"where","ru":"где","vi":"ở đâu","fa":"کجا","examples":[{"de":"Wo wohnst du?","en":"Where do you live?","ru":"Где ты живёшь?","vi":"Bạn sống ở đâu?","fa":"شما کجا زندگی می کنید؟"},{"de":"Ich weiß nicht, wo meine Brille ist.","en":"I don't know where my glasses are.","ru":"Я не знаю, где мои очки.","vi":"Tôi không biết kính của tôi ở đâu.","fa":"نمیدونم عینکم کجاست"}]},{"word":"woher","en":"where from","ru":"откуда","vi":"từ đâu đến","fa":"از کجا","examples":[{"de":"Woher kommst du?","en":"Where are you from?","ru":"Откуда ты?","vi":"Bạn đến từ đâu?","fa":"شما از کجا می آیید؟"},{"de":"Woher weißt du das?","en":"How do you know that?","ru":"Откуда ты это знаешь?","vi":"Làm sao bạn biết điều đó?","fa":"شما از کجا می دانید؟"}]},{"word":"wohin","en":"where to","ru":"куда","vi":"ở đâu","fa":"کجا","examples":[{"de":"Wohin fährst du im Urlaub?","en":"Where are you going on vacation?","ru":"Куда ты едешь в отпуск?","vi":"Bạn đang đi đâu vào kỳ nghỉ?","fa":"تعطیلات کجا میری؟"},{"de":"Wohin hast du meine Schlüssel gelegt?","en":"Where did you put my keys?","ru":"Куда ты положил мои ключи?","vi":"Bạn đã để chìa khóa của tôi ở đâu?","fa":"کلیدهای مرا کجا گذاشتی؟"}]},{"word":"wohl","en":"probably; well","ru":"вероятно; хорошо","vi":"có lẽ","fa":"احتمالا","examples":[{"de":"Er ist wohl schon zu Hause.","en":"He's probably already home.","ru":"Он, наверное, уже дома.","vi":"Có lẽ anh ấy đã về nhà rồi.","fa":"او احتمالاً در خانه است."},{"de":"Fühlst du dich heute wohl?","en":"Do you feel well today?","ru":"Ты хорошо себя чувствуешь сегодня?","vi":"Hôm nay bạn có khỏe không?","fa":"آیا امروز احساس خوبی دارید؟"}]},{"word":"wohnen","en":"to live, reside","ru":"жить, проживать","vi":"sống","fa":"زندگی می کنند","examples":[{"de":"Ich wohne seit fünf Jahren in Berlin.","en":"I've lived in Berlin for five years.","ru":"Я живу в Берлине уже пять лет.","vi":"Tôi đã sống ở Berlin được năm năm.","fa":"من پنج سال است که در برلین زندگی می کنم."},{"de":"Wo wohnt deine Familie?","en":"Where does your family live?","ru":"Где живёт твоя семья?","vi":"Gia đình bạn sống ở đâu?","fa":"خانواده شما کجا زندگی می کنند؟"}]},{"word":"die Wohnung","en":"flat; apartment","ru":"квартира","vi":"căn hộ","fa":"آپارتمان","examples":[{"de":"Wir suchen eine größere Wohnung im Zentrum.","en":"We are looking for a bigger flat in the centre.","ru":"Мы ищем квартиру побольше в центре.","vi":"Chúng tôi đang tìm một căn hộ lớn hơn ở trung tâm.","fa":"ما به دنبال یک آپارتمان بزرگتر در مرکز هستیم."},{"de":"Ihre Wohnung liegt im dritten Stock.","en":"Her flat is on the third floor.","ru":"Её квартира на третьем этаже.","vi":"Căn hộ của bạn ở trên tầng ba.","fa":"آپارتمان شما در طبقه سوم است."}]},{"word":"die Wolke","en":"cloud","ru":"облако","vi":"đám mây","fa":"ابر","examples":[{"de":"Am Himmel sind viele dunkle Wolken.","en":"There are many dark clouds in the sky.","ru":"В небе много тёмных облаков.","vi":"Trên bầu trời có rất nhiều đám mây đen.","fa":"ابرهای سیاه زیادی در آسمان وجود دارد."},{"de":"Die Wolken verdecken die Sonne.","en":"The clouds are hiding the sun.","ru":"Облака закрывают солнце.","vi":"Mây che khuất mặt trời.","fa":"ابرها خورشید را پنهان می کنند."}]},{"word":"die Wolle","en":"wool","ru":"шерсть","vi":"len","fa":"پشم","examples":[{"de":"Der Pullover ist aus reiner Wolle.","en":"The sweater is made of pure wool.","ru":"Свитер сделан из чистой шерсти.","vi":"Chiếc áo len được làm bằng len nguyên chất.","fa":"ژاکت از پشم خالص ساخته شده است."},{"de":"Meine Oma strickt gern mit Wolle.","en":"My grandma likes to knit with wool.","ru":"Моя бабушка любит вязать из шерсти.","vi":"Bà tôi thích đan len.","fa":"مادربزرگم دوست دارد با پشم ببافد."}]},{"word":"wollen","en":"to want","ru":"хотеть","vi":"muốn","fa":"خواستن","examples":[{"de":"Ich will heute Abend ins Kino gehen.","en":"I want to go to the cinema tonight.","ru":"Я хочу пойти в кино сегодня вечером.","vi":"Tôi muốn đi xem phim tối nay.","fa":"امشب میخوام برم سینما."},{"de":"Was willst du zum Geburtstag?","en":"What do you want for your birthday?","ru":"Что ты хочешь на день рождения?","vi":"Bạn muốn gì cho ngày sinh nhật của mình?","fa":"برای تولدت چی میخوای؟"}]},{"word":"das Wort","en":"word","ru":"слово","vi":"từ","fa":"کلمه","examples":[{"de":"Ich kenne dieses Wort nicht.","en":"I don't know this word.","ru":"Я не знаю этого слова.","vi":"Tôi không biết từ này.","fa":"من این کلمه را نمی دانم"},{"de":"Er hat nur wenige Worte gesagt.","en":"He said only a few words.","ru":"Он сказал лишь несколько слов.","vi":"Anh ấy chỉ nói vài lời thôi.","fa":"فقط چند کلمه گفت."}]},{"word":"worüber","en":"about what","ru":"о чём","vi":"về cái gì","fa":"در مورد چه چیزی","examples":[{"de":"Worüber sprecht ihr gerade?","en":"What are you talking about right now?","ru":"О чём вы сейчас разговариваете?","vi":"Hiện tại bạn đang nói về điều gì?","fa":"در حال حاضر در مورد چه چیزی صحبت می کنید؟"},{"de":"Worüber hast du dich so gefreut?","en":"What were you so happy about?","ru":"Чему ты так обрадовался?","vi":"Bạn đã rất vui mừng về điều gì?","fa":"برای چی اینقدر خوشحال بودی؟"}]},{"word":"worum","en":"about what; regarding what","ru":"о чём, насчёт чего","vi":"thế còn","fa":"چه در مورد","examples":[{"de":"Worum geht es in dem Film?","en":"What is the movie about?","ru":"О чём этот фильм?","vi":"Bộ phim nói về cái gì?","fa":"فیلم درباره چیست؟"},{"de":"Worum bittest du mich?","en":"What are you asking me for?","ru":"О чём ты меня просишь?","vi":"Bạn đang hỏi tôi điều gì?","fa":"از من چه می خواهی؟"}]},{"word":"die Wunde","en":"wound","ru":"рана","vi":"vết thương","fa":"زخم","examples":[{"de":"Die Wunde am Bein muss verbunden werden.","en":"The wound on the leg needs to be bandaged.","ru":"Рану на ноге нужно перевязать.","vi":"Vết thương ở chân cần được băng bó.","fa":"زخم روی پا باید بانداژ شود."},{"de":"Die Wunde heilt langsam.","en":"The wound is healing slowly.","ru":"Рана заживает медленно.","vi":"Vết thương đang dần lành lại.","fa":"زخم کم کم خوب می شود."}]},{"word":"das Wunder","en":"miracle, wonder","ru":"чудо","vi":"điều kỳ diệu","fa":"معجزه","examples":[{"de":"Es grenzt an ein Wunder, dass er überlebt hat.","en":"It's almost a miracle that he survived.","ru":"То, что он выжил, почти чудо.","vi":"Thật là một phép lạ khi anh ấy sống sót.","fa":"این یک معجزه است که او زنده مانده است."},{"de":"Kein Wunder, dass du müde bist.","en":"No wonder you're tired.","ru":"Неудивительно, что ты устал.","vi":"Không có gì ngạc nhiên khi bạn mệt mỏi.","fa":"جای تعجب نیست که شما خسته هستید."}]},{"word":"die Wurst","en":"sausage","ru":"колбаса","vi":"xúc xích","fa":"سوسیس","examples":[{"de":"Zum Frühstück isst er gern Wurst und Brot.","en":"For breakfast he likes to eat sausage and bread.","ru":"На завтрак он любит есть колбасу с хлебом.","vi":"Anh ấy thích ăn xúc xích và bánh mì vào bữa sáng.","fa":"دوست دارد صبحانه سوسیس و نان بخورد."},{"de":"Auf dem Grill liegen mehrere Würste.","en":"There are several sausages on the grill.","ru":"На гриле лежит несколько колбасок.","vi":"Có một số xúc xích trên vỉ nướng.","fa":"چندین سوسیس روی کباب وجود دارد."}]},{"word":"die Wut","en":"anger; rage","ru":"гнев; ярость","vi":"sự tức giận","fa":"خشم","examples":[{"de":"Vor Wut konnte er kaum sprechen.","en":"He could hardly speak out of anger.","ru":"От гнева он едва мог говорить.","vi":"Anh khó có thể nói được vì tức giận.","fa":"از عصبانیت به سختی می توانست حرف بزند."},{"de":"Ihre Wut verflog so schnell, wie sie gekommen war.","en":"Her anger faded as quickly as it had come.","ru":"Её гнев прошёл так же быстро, как и появился.","vi":"Cơn giận của cô biến mất nhanh chóng như khi nó xuất hiện.","fa":"عصبانیت او به سرعت از بین رفت."}]},{"word":"wütend","en":"furious, angry","ru":"разъярённый, злой","vi":"tức giận","fa":"عصبانی","examples":[{"de":"Er war wütend, weil der Zug Verspätung hatte.","en":"He was furious because the train was delayed.","ru":"Он был в ярости, потому что поезд опоздал.","vi":"Anh ấy tức giận vì tàu đến muộn.","fa":"او عصبانی بود زیرا قطار دیر کرده بود."},{"de":"Sie schaute mich wütend an.","en":"She looked at me angrily.","ru":"Она злобно посмотрела на меня.","vi":"Cô ấy nhìn tôi giận dữ.","fa":"با عصبانیت به من نگاه کرد."}]},{"word":"die Zahl","en":"number","ru":"число, цифра","vi":"số","fa":"شماره","examples":[{"de":"Die Zahl der Studenten steigt jedes Jahr.","en":"The number of students increases every year.","ru":"Число студентов растёт каждый год.","vi":"Số lượng sinh viên tăng lên hàng năm.","fa":"هر سال بر تعداد دانش آموزان افزوده می شود."},{"de":"Kannst du diese Zahl laut vorlesen?","en":"Can you read this number out loud?","ru":"Можешь прочитать это число вслух?","vi":"Bạn có thể đọc to con số này không?","fa":"آیا می توانید این عدد را با صدای بلند بخوانید؟"}]},{"word":"zahlen","en":"to pay","ru":"платить","vi":"trả tiền","fa":"پرداخت کنید","examples":[{"de":"Ich möchte bitte zahlen.","en":"I would like to pay, please.","ru":"Я хотел бы оплатить, пожалуйста.","vi":"Tôi muốn trả tiền xin vui lòng.","fa":"من می خواهم پرداخت کنم لطفا"},{"de":"Er zahlt die Miete immer pünktlich.","en":"He always pays the rent on time.","ru":"Он всегда платит арендную плату вовремя.","vi":"Anh ấy luôn trả tiền thuê nhà đúng hạn.","fa":"او همیشه کرایه خانه را به موقع پرداخت می کند."}]},{"word":"zählen","en":"to count","ru":"считать","vi":"đếm","fa":"شمارش","examples":[{"de":"Das Kind kann schon bis hundert zählen.","en":"The child can already count to a hundred.","ru":"Ребёнок уже умеет считать до ста.","vi":"Đứa trẻ đã có thể đếm đến một trăm.","fa":"کودک می تواند تا صد بشمارد."},{"de":"Ich zähle auf deine Hilfe.","en":"I'm counting on your help.","ru":"Я рассчитываю на твою помощь.","vi":"Tôi đang trông cậy vào sự giúp đỡ của bạn.","fa":"من روی کمک شما حساب می کنم."}]},{"word":"der Zahn","en":"tooth","ru":"зуб","vi":"cái răng","fa":"دندان","examples":[{"de":"Ich muss zum Zahnarzt, mein Zahn tut weh.","en":"I have to go to the dentist, my tooth hurts.","ru":"Мне нужно к стоматологу, у меня болит зуб.","vi":"Tôi phải đến nha sĩ, răng tôi đau quá.","fa":"من باید برم دندانپزشک، دندانم درد می کند."},{"de":"Putz dir jeden Abend die Zähne.","en":"Brush your teeth every evening.","ru":"Чисти зубы каждый вечер.","vi":"Đánh răng vào mỗi buổi tối.","fa":"هر شب دندان های خود را مسواک بزنید."}]},{"word":"die Zange","en":"pliers, tongs","ru":"клещи, щипцы","vi":"cái kìm","fa":"انبردست","examples":[{"de":"Er zieht den Nagel mit einer Zange heraus.","en":"He pulls out the nail with pliers.","ru":"Он вытаскивает гвоздь клещами.","vi":"Anh ta rút chiếc đinh ra bằng kìm.","fa":"میخ را با انبردست بیرون می آورد."},{"de":"Ich brauche eine Zange, um den Draht zu schneiden.","en":"I need pliers to cut the wire.","ru":"Мне нужны клещи, чтобы перерезать проволоку.","vi":"Tôi cần cái kìm để cắt dây.","fa":"برای بریدن سیم به انبردست نیاز دارم."}]},{"word":"das Zeichen","en":"sign, signal","ru":"знак, сигнал","vi":"dấu hiệu","fa":"علامت","examples":[{"de":"Der Polizist gibt den Autos ein Zeichen zum Anhalten.","en":"The police officer gives the cars a signal to stop.","ru":"Полицейский даёт машинам сигнал остановиться.","vi":"Viên cảnh sát ra hiệu cho các xe dừng lại.","fa":"افسر پلیس به ماشین ها علامت می دهد که بایستند."},{"de":"Ein Lächeln ist oft ein Zeichen der Freundlichkeit.","en":"A smile is often a sign of friendliness.","ru":"Улыбка часто является знаком дружелюбия.","vi":"Một nụ cười thường là dấu hiệu của sự thân thiện.","fa":"لبخند اغلب نشانه دوستی است."}]},{"word":"zeichnen","en":"to draw","ru":"рисовать","vi":"vẽ","fa":"قرعه کشی","examples":[{"de":"Meine Tochter zeichnet gern Tiere.","en":"My daughter likes to draw animals.","ru":"Моя дочь любит рисовать животных.","vi":"Con gái tôi thích vẽ động vật.","fa":"دخترم دوست دارد حیوانات نقاشی کند."},{"de":"Er zeichnet einen Plan für das neue Haus.","en":"He's drawing a plan for the new house.","ru":"Он рисует план нового дома.","vi":"Anh ấy vẽ một kế hoạch cho ngôi nhà mới.","fa":"او برای خانه جدید نقشه می کشد."}]},{"word":"zeigen","en":"to show","ru":"показывать","vi":"hiển thị","fa":"نشان می دهد","examples":[{"de":"Kannst du mir bitte den Weg zeigen?","en":"Can you please show me the way?","ru":"Ты можешь, пожалуйста, показать мне дорогу?","vi":"Bạn có thể vui lòng chỉ đường cho tôi được không?","fa":"میشه لطفا راه رو به من نشون بدی؟"},{"de":"Er zeigt seinen Freunden die neuen Fotos.","en":"He shows his friends the new photos.","ru":"Он показывает друзьям новые фотографии.","vi":"Anh ấy cho bạn bè xem những bức ảnh mới.","fa":"او عکس های جدید را به دوستانش نشان می دهد."}]},{"word":"die Zeile","en":"line (of text)","ru":"строка (текста)","vi":"dòng","fa":"خط","examples":[{"de":"Lies bitte die erste Zeile noch einmal.","en":"Please read the first line again.","ru":"Пожалуйста, прочитай ещё раз первую строку.","vi":"Xin vui lòng đọc lại dòng đầu tiên.","fa":"لطفا سطر اول را دوباره بخوانید."},{"de":"In diesem Brief fehlt eine Zeile.","en":"A line is missing in this letter.","ru":"В этом письме не хватает строки.","vi":"Có một dòng bị thiếu trong bức thư này.","fa":"در این نامه خطی وجود ندارد."}]},{"word":"die Zeit","en":"time","ru":"время","vi":"thời gian","fa":"زمان","examples":[{"de":"Ich habe heute leider keine Zeit.","en":"I unfortunately have no time today.","ru":"У меня, к сожалению, сегодня нет времени.","vi":"Thật không may là hôm nay tôi không có thời gian.","fa":"متاسفانه امروز وقت ندارم"},{"de":"Die Zeit vergeht sehr schnell.","en":"Time passes very quickly.","ru":"Время проходит очень быстро.","vi":"Thời gian trôi qua rất nhanh.","fa":"زمان خیلی سریع می گذرد."}]},{"word":"die Zeitschrift","en":"magazine","ru":"журнал","vi":"tạp chí","fa":"مجله","examples":[{"de":"Meine Mutter liest gern eine Zeitschrift über Mode.","en":"My mother likes reading a fashion magazine.","ru":"Моя мама любит читать журнал о моде.","vi":"Mẹ tôi thích đọc tạp chí về thời trang.","fa":"مادرم دوست دارد یک مجله درباره مد بخواند."},{"de":"Diese Zeitschrift erscheint einmal im Monat.","en":"This magazine is published once a month.","ru":"Этот журнал выходит раз в месяц.","vi":"Tạp chí này được xuất bản mỗi tháng một lần.","fa":"این مجله ماهی یک بار منتشر می شود."}]},{"word":"die Zeitung","en":"newspaper","ru":"газета","vi":"tờ báo","fa":"روزنامه","examples":[{"de":"Mein Vater liest jeden Morgen die Zeitung.","en":"My father reads the newspaper every morning.","ru":"Мой отец каждое утро читает газету.","vi":"Bố tôi đọc báo mỗi sáng.","fa":"پدرم هر روز صبح روزنامه می خواند."},{"de":"In der Zeitung stand ein interessanter Artikel.","en":"There was an interesting article in the newspaper.","ru":"В газете была интересная статья.","vi":"Có một bài viết thú vị trên báo.","fa":"مطلب جالبی در روزنامه بود."}]},{"word":"das Zelt","en":"tent","ru":"палатка","vi":"cái lều","fa":"چادر","examples":[{"de":"Wir haben unser Zelt am See aufgebaut.","en":"We set up our tent by the lake.","ru":"Мы поставили нашу палатку у озера.","vi":"Chúng tôi dựng lều bên hồ.","fa":"چادرمان را کنار دریاچه برپا کردیم."},{"de":"Das Zelt ist für vier Personen groß genug.","en":"The tent is big enough for four people.","ru":"Палатка достаточно велика для четырёх человек.","vi":"Lều đủ lớn cho bốn người.","fa":"چادر برای چهار نفر بزرگ است."}]},{"word":"zelten","en":"to camp","ru":"разбивать лагерь, ночевать в палатке","vi":"cắm trại","fa":"کمپینگ","examples":[{"de":"Im Sommer zelten wir oft in den Bergen.","en":"In summer we often go camping in the mountains.","ru":"Летом мы часто ночуем в палатке в горах.","vi":"Vào mùa hè chúng tôi thường cắm trại trên núi.","fa":"در تابستان اغلب در کوهستان چادر می زنیم."},{"de":"Hier darf man nicht zelten.","en":"Camping is not allowed here.","ru":"Здесь нельзя разбивать палатку.","vi":"Bạn không được phép cắm trại ở đây.","fa":"شما اجازه ندارید اینجا کمپ بزنید."}]},{"word":"zentral","en":"central","ru":"центральный","vi":"trung ương","fa":"مرکزی","examples":[{"de":"Die Wohnung liegt sehr zentral.","en":"The apartment is located very centrally.","ru":"Квартира расположена очень центрально.","vi":"Căn hộ nằm rất trung tâm.","fa":"آپارتمان بسیار مرکزی است."},{"de":"Der Bahnhof ist ein zentraler Treffpunkt in der Stadt.","en":"The train station is a central meeting point in the city.","ru":"Вокзал — центральное место встречи в городе.","vi":"Nhà ga xe lửa là điểm tập trung của thành phố.","fa":"ایستگاه قطار یک نقطه ملاقات مرکزی در شهر است."}]},{"word":"das Zentrum","en":"center","ru":"центр","vi":"trung tâm","fa":"مرکز","examples":[{"de":"Wir treffen uns im Zentrum der Stadt.","en":"We are meeting in the city center.","ru":"Мы встречаемся в центре города.","vi":"Chúng tôi gặp nhau ở trung tâm thành phố.","fa":"در مرکز شهر همدیگر را می بینیم."},{"de":"Das Einkaufszentrum liegt nicht weit vom Zentrum.","en":"The shopping center is not far from the center.","ru":"Торговый центр находится недалеко от центра.","vi":"Trung tâm mua sắm cách trung tâm không xa.","fa":"مرکز خرید فاصله چندانی با مرکز ندارد."}]},{"word":"zerstören","en":"to destroy","ru":"разрушать","vi":"phá hủy","fa":"نابود کردن","examples":[{"de":"Der Sturm hat viele Häuser zerstört.","en":"The storm destroyed many houses.","ru":"Буря разрушила много домов.","vi":"Cơn bão đã phá hủy nhiều ngôi nhà.","fa":"طوفان خانه های زیادی را ویران کرد."},{"de":"Bitte zerstöre nicht meine Arbeit!","en":"Please don't destroy my work!","ru":"Пожалуйста, не разрушай мою работу!","vi":"Làm ơn đừng phá hủy tác phẩm của tôi!","fa":"لطفا کار من را خراب نکنید!"}]},{"word":"das Zertifikat","en":"certificate","ru":"сертификат","vi":"giấy chứng nhận","fa":"گواهی","examples":[{"de":"Nach dem Kurs bekommen Sie ein Zertifikat.","en":"After the course you will receive a certificate.","ru":"После курса вы получите сертификат.","vi":"Sau khóa học bạn sẽ nhận được chứng chỉ.","fa":"پس از پایان دوره گواهینامه دریافت خواهید کرد."},{"de":"Ich brauche das Zertifikat für meine Bewerbung.","en":"I need the certificate for my application.","ru":"Мне нужен сертификат для моего заявления.","vi":"Tôi cần giấy chứng nhận cho đơn đăng ký của mình.","fa":"برای درخواستم به گواهی نیاز دارم"}]},{"word":"der Zettel","en":"note (piece of paper)","ru":"записка, листок","vi":"ghi chú","fa":"یادداشت","examples":[{"de":"Sie hat mir einen Zettel auf den Tisch gelegt.","en":"She left me a note on the table.","ru":"Она оставила мне записку на столе.","vi":"Cô ấy đặt một mảnh giấy lên bàn cho tôi.","fa":"او یک تکه کاغذ برای من روی میز گذاشت."},{"de":"Ich schreibe die Adresse auf einen Zettel.","en":"I'll write the address on a piece of paper.","ru":"Я запишу адрес на листке бумаги.","vi":"Tôi viết địa chỉ lên một tờ giấy.","fa":"آدرس را روی یک کاغذ می نویسم."}]},{"word":"das Zeug/-zeug","en":"stuff, things","ru":"вещи, барахло","vi":"thứ/thứ đó","fa":"چیز/مواد","examples":[{"de":"Räum dein Zeug endlich auf!","en":"Finally tidy up your stuff!","ru":"Наконец-то убери свои вещи!","vi":"Cuối cùng hãy dọn dẹp đồ đạc của bạn!","fa":"بالاخره وسایلت را تمیز کن!"},{"de":"Wir brauchen Werkzeug, um das Regal zu reparieren.","en":"We need tools to repair the shelf.","ru":"Нам нужны инструменты, чтобы починить полку.","vi":"Chúng tôi cần các công cụ để sửa chữa kệ.","fa":"برای تعمیر قفسه به ابزار نیاز داریم."}]},{"word":"der Zeuge","en":"witness","ru":"свидетель","vi":"nhân chứng","fa":"شاهد","examples":[{"de":"Der Zeuge hat den Unfall genau beobachtet.","en":"The witness observed the accident closely.","ru":"Свидетель точно наблюдал за аварией.","vi":"Nhân chứng đã quan sát kỹ vụ tai nạn.","fa":"شاهد حادثه را از نزدیک مشاهده کرد."},{"de":"Die Polizei sucht Zeugen des Diebstahls.","en":"The police are looking for witnesses to the theft.","ru":"Полиция ищет свидетелей кражи.","vi":"Cảnh sát đang tìm kiếm nhân chứng của vụ trộm.","fa":"پلیس به دنبال شاهدان این سرقت است."}]},{"word":"das Zeugnis","en":"report card; certificate","ru":"свидетельство, табель (об успеваемости)","vi":"lời khai","fa":"شهادت","examples":[{"de":"Mein Sohn hat ein gutes Zeugnis bekommen.","en":"My son got a good report card.","ru":"Мой сын получил хороший табель.","vi":"Con trai tôi đã nhận được một phiếu báo điểm tốt.","fa":"پسرم کارنامه خوبی گرفت."},{"de":"Für die Bewerbung brauche ich mein Abschlusszeugnis.","en":"For the application I need my final certificate.","ru":"Для заявления мне нужен мой выпускной аттестат.","vi":"Tôi cần bằng tốt nghiệp của tôi để nộp đơn.","fa":"برای درخواست به مدرک دیپلمم نیاز دارم."}]},{"word":"ziehen","en":"to pull; to move (relocate)","ru":"тянуть; переезжать","vi":"kéo","fa":"کشیدن","examples":[{"de":"Bitte zieh die Tür zu, es zieht.","en":"Please pull the door shut, there's a draft.","ru":"Пожалуйста, закрой дверь, сквозит.","vi":"Hãy đóng cửa lại, có gió lùa.","fa":"لطفا در را ببندید، پیش نویس وجود دارد."},{"de":"Nächsten Monat ziehen wir nach Berlin.","en":"Next month we are moving to Berlin.","ru":"В следующем месяце мы переезжаем в Берлин.","vi":"Tháng tới chúng tôi sẽ chuyển đến Berlin.","fa":"ماه آینده به برلین نقل مکان می کنیم."}]},{"word":"das Ziel","en":"goal; destination","ru":"цель; пункт назначения","vi":"mục tiêu","fa":"هدف","examples":[{"de":"Mein Ziel ist es, die Prüfung zu bestehen.","en":"My goal is to pass the exam.","ru":"Моя цель — сдать экзамен.","vi":"Mục tiêu của tôi là vượt qua kỳ thi.","fa":"هدف من قبولی در امتحان است."},{"de":"Wir haben unser Ziel endlich erreicht.","en":"We finally reached our destination.","ru":"Мы наконец достигли нашей цели.","vi":"Cuối cùng chúng tôi đã đạt được mục tiêu của mình.","fa":"بالاخره به هدفمون رسیدیم."}]},{"word":"ziemlich","en":"quite, rather","ru":"довольно, весьма","vi":"khá","fa":"کاملا","examples":[{"de":"Das Wetter ist heute ziemlich kalt.","en":"The weather is quite cold today.","ru":"Погода сегодня довольно холодная.","vi":"Thời tiết hôm nay khá lạnh.","fa":"امروز هوا خیلی سرده"},{"de":"Die Prüfung war ziemlich schwer.","en":"The exam was rather difficult.","ru":"Экзамен был довольно трудным.","vi":"Bài kiểm tra khá khó khăn.","fa":"آزمون بسیار سخت بود."}]},{"word":"die Zigarette","en":"cigarette","ru":"сигарета","vi":"điếu thuốc","fa":"سیگار","examples":[{"de":"Er raucht zu viele Zigaretten am Tag.","en":"He smokes too many cigarettes a day.","ru":"Он курит слишком много сигарет в день.","vi":"Anh ấy hút quá nhiều thuốc lá mỗi ngày.","fa":"او در روز بیش از حد سیگار می کشد."},{"de":"Kannst du mir eine Zigarette geben?","en":"Can you give me a cigarette?","ru":"Ты можешь дать мне сигарету?","vi":"Bạn có thể cho tôi một điếu thuốc được không?","fa":"میشه یه سیگار بهم بدی؟"}]},{"word":"das Zimmer","en":"room","ru":"комната","vi":"căn phòng","fa":"اتاق","examples":[{"de":"Mein Zimmer ist klein, aber gemütlich.","en":"My room is small but cozy.","ru":"Моя комната маленькая, но уютная.","vi":"Phòng của tôi nhỏ nhưng ấm cúng.","fa":"اتاق من کوچک اما دنج است."},{"de":"Wir haben ein Zimmer im Hotel reserviert.","en":"We booked a room at the hotel.","ru":"Мы забронировали номер в отеле.","vi":"Chúng tôi đặt phòng ở khách sạn.","fa":"ما یک اتاق در هتل رزرو کردیم."}]},{"word":"die Zinsen (nur Pl.)","en":"interest (financial)","ru":"проценты (банковские)","vi":"tiền lãi (chỉ pl.)","fa":"بهره (فقط pl.)","examples":[{"de":"Die Bank zahlt niedrige Zinsen auf das Sparkonto.","en":"The bank pays low interest on the savings account.","ru":"Банк платит низкие проценты по сберегательному счёту.","vi":"Ngân hàng trả lãi suất thấp cho tài khoản tiết kiệm.","fa":"بانک به حساب پس انداز سود کم می پردازد."},{"de":"Wenn man einen Kredit aufnimmt, muss man Zinsen zahlen.","en":"When you take out a loan, you have to pay interest.","ru":"Если берёшь кредит, нужно платить проценты.","vi":"Khi bạn vay tiền, bạn phải trả lãi.","fa":"وقتی وام می گیرید باید بهره پرداخت کنید."}]},{"word":"der Zirkus","en":"circus","ru":"цирк","vi":"rạp xiếc","fa":"سیرک","examples":[{"de":"Die Kinder waren begeistert vom Zirkus.","en":"The children were thrilled by the circus.","ru":"Дети были в восторге от цирка.","vi":"Bọn trẻ yêu thích rạp xiếc.","fa":"بچه ها سیرک را دوست داشتند."},{"de":"Am Wochenende gehen wir in den Zirkus.","en":"On the weekend we are going to the circus.","ru":"В выходные мы идём в цирк.","vi":"Vào cuối tuần chúng tôi đi xem xiếc.","fa":"آخر هفته به سیرک می رویم."}]},{"word":"die Zitrone","en":"lemon","ru":"лимон","vi":"quả chanh","fa":"لیمو","examples":[{"de":"Der Tee schmeckt gut mit etwas Zitrone.","en":"The tea tastes good with a bit of lemon.","ru":"Чай вкусный с небольшим количеством лимона.","vi":"Trà có vị ngon với một chút chanh.","fa":"چای با کمی لیمو طعم خوبی دارد."},{"de":"Ich kaufe frische Zitronen für das Rezept.","en":"I'm buying fresh lemons for the recipe.","ru":"Я покупаю свежие лимоны для рецепта.","vi":"Tôi mua chanh tươi cho công thức nấu ăn.","fa":"من برای دستور غذا لیموی تازه می خرم."}]},{"word":"der Zivilstand","en":"marital status","ru":"семейное положение","vi":"tình trạng hôn nhân","fa":"وضعیت تاهل","examples":[{"de":"Bitte geben Sie Ihren Zivilstand im Formular an.","en":"Please state your marital status on the form.","ru":"Пожалуйста, укажите ваше семейное положение в анкете.","vi":"Vui lòng cho biết tình trạng hôn nhân của bạn trong mẫu đơn.","fa":"لطفا وضعیت تاهل خود را در فرم ذکر کنید."},{"de":"Ihr Zivilstand hat sich nach der Heirat geändert.","en":"Her marital status changed after the marriage.","ru":"Её семейное положение изменилось после свадьбы.","vi":"Tình trạng hôn nhân của cô thay đổi sau khi kết hôn.","fa":"وضعیت تاهل او پس از ازدواج تغییر کرد."}]},{"word":"der Zoll","en":"customs","ru":"таможня","vi":"hải quan","fa":"گمرک","examples":[{"de":"Am Flughafen mussten wir durch den Zoll.","en":"At the airport we had to go through customs.","ru":"В аэропорту нам пришлось пройти таможню.","vi":"Chúng tôi phải làm thủ tục hải quan ở sân bay.","fa":"باید در فرودگاه از گمرک عبور می کردیم."},{"de":"Der Zoll hat das Gepäck kontrolliert.","en":"Customs checked the luggage.","ru":"Таможня проверила багаж.","vi":"Hải quan đã kiểm tra hành lý.","fa":"گمرک چمدان ها را چک کرد."}]},{"word":"die Zone","en":"zone","ru":"зона","vi":"khu vực","fa":"منطقه","examples":[{"de":"Hier beginnt die Fußgängerzone.","en":"The pedestrian zone starts here.","ru":"Здесь начинается пешеходная зона.","vi":"Khu vực dành cho người đi bộ bắt đầu từ đây.","fa":"منطقه عابر پیاده از اینجا شروع می شود."},{"de":"In dieser Zone darf man nicht parken.","en":"Parking is not allowed in this zone.","ru":"В этой зоне нельзя парковаться.","vi":"Bạn không được phép đậu xe ở khu vực này.","fa":"شما مجاز به پارک در این منطقه نیستید."}]},{"word":"der Zoo","en":"zoo","ru":"зоопарк","vi":"sở thú","fa":"باغ وحش","examples":[{"de":"Am Sonntag besuchen wir den Zoo.","en":"On Sunday we are visiting the zoo.","ru":"В воскресенье мы посещаем зоопарк.","vi":"Vào chủ nhật chúng tôi đi thăm sở thú.","fa":"یکشنبه از باغ وحش بازدید می کنیم."},{"de":"Im Zoo gibt es viele exotische Tiere.","en":"There are many exotic animals at the zoo.","ru":"В зоопарке много экзотических животных.","vi":"Có rất nhiều động vật kỳ lạ trong sở thú.","fa":"حیوانات عجیب و غریب زیادی در باغ وحش وجود دارد."}]},{"word":"zu","en":"to; too","ru":"к, в; слишком","vi":"để","fa":"به","examples":[{"de":"Ich gehe heute Abend zu meiner Freundin.","en":"I'm going to my girlfriend's place tonight.","ru":"Сегодня вечером я иду к своей подруге.","vi":"Tối nay tôi sẽ đến nhà bạn gái tôi.","fa":"من امشب میرم پیش دوست دخترم"},{"de":"Der Kaffee ist mir zu heiß.","en":"The coffee is too hot for me.","ru":"Кофе для меня слишком горячий.","vi":"Cà phê quá nóng đối với tôi.","fa":"قهوه برای من خیلی داغ است."}]},{"word":"zu sein","en":"to be closed","ru":"быть закрытым","vi":"được","fa":"بودن","examples":[{"de":"Das Geschäft ist sonntags immer zu.","en":"The shop is always closed on Sundays.","ru":"Магазин всегда закрыт по воскресеньям.","vi":"Cửa hàng luôn đóng cửa vào ngày chủ nhật.","fa":"فروشگاه همیشه یکشنبه ها تعطیل است."},{"de":"Die Tür war die ganze Nacht zu.","en":"The door was closed all night.","ru":"Дверь была закрыта всю ночь.","vi":"Cánh cửa đóng suốt đêm.","fa":"در تمام شب بسته بود."}]},{"word":"zubereiten","en":"to prepare (food)","ru":"готовить (еду)","vi":"chuẩn bị","fa":"آماده کردن","examples":[{"de":"Meine Oma bereitet das Essen mit viel Liebe zu.","en":"My grandma prepares the food with a lot of love.","ru":"Моя бабушка готовит еду с большой любовью.","vi":"Bà tôi chuẩn bị đồ ăn với rất nhiều tình yêu thương.","fa":"مادربزرگم با عشق زیاد غذا درست می کند."},{"de":"Wie bereitet man diese Suppe zu?","en":"How do you prepare this soup?","ru":"Как готовят этот суп?","vi":"Bạn chuẩn bị món súp này như thế nào?","fa":"این سوپ را چگونه تهیه می کنید؟"}]},{"word":"der Zucker","en":"sugar","ru":"сахар","vi":"đường","fa":"شکر","examples":[{"de":"Ich trinke meinen Kaffee ohne Zucker.","en":"I drink my coffee without sugar.","ru":"Я пью свой кофе без сахара.","vi":"Tôi uống cà phê không đường.","fa":"من قهوه ام را بدون قند می نوشم."},{"de":"Zu viel Zucker ist ungesund.","en":"Too much sugar is unhealthy.","ru":"Слишком много сахара вредно для здоровья.","vi":"Quá nhiều đường không tốt cho sức khỏe.","fa":"قند بیش از حد ناسالم است."}]},{"word":"zudem","en":"moreover; in addition","ru":"кроме того; к тому же","vi":"cũng","fa":"همچنین","examples":[{"de":"Das Hotel ist günstig; zudem liegt es sehr zentral.","en":"The hotel is cheap; moreover it is very central.","ru":"Отель недорогой; к тому же он расположен в центре.","vi":"Khách sạn rẻ; Nó cũng nằm rất trung tâm.","fa":"هتل ارزان است؛ همچنین بسیار در مرکز قرار دارد."},{"de":"Er ist klug und zudem sehr fleißig.","en":"He is clever and, in addition, very hard-working.","ru":"Он умён и к тому же очень трудолюбив.","vi":"Anh ấy thông minh và cũng rất chăm chỉ.","fa":"او باهوش است و همچنین بسیار سخت کوش است."}]},{"word":"zuerst","en":"first, at first","ru":"сначала","vi":"đầu tiên","fa":"اول","examples":[{"de":"Zuerst müssen wir die Karten kaufen.","en":"First we have to buy the tickets.","ru":"Сначала нам нужно купить билеты.","vi":"Đầu tiên chúng ta phải mua vé.","fa":"ابتدا باید بلیط ها را بخریم."},{"de":"Ich dachte zuerst, er scherzt.","en":"At first I thought he was joking.","ru":"Сначала я подумал, что он шутит.","vi":"Lúc đầu tôi tưởng anh ấy nói đùa.","fa":"اول فکر کردم شوخی می کند."}]},{"word":"der Zufall","en":"coincidence","ru":"случайность, совпадение","vi":"sự trùng hợp ngẫu nhiên","fa":"تصادف","examples":[{"de":"Es war reiner Zufall, dass wir uns getroffen haben.","en":"It was pure coincidence that we met.","ru":"Это было чистой случайностью, что мы встретились.","vi":"Việc chúng tôi gặp nhau hoàn toàn là sự trùng hợp ngẫu nhiên.","fa":"این کاملا تصادفی بود که با هم آشنا شدیم."},{"de":"So ein Zufall, dich hier zu sehen!","en":"What a coincidence to see you here!","ru":"Какое совпадение увидеть тебя здесь!","vi":"Thật trùng hợp khi gặp bạn ở đây!","fa":"چنین تصادفی است که شما را اینجا می بینم!"}]},{"word":"zufällig","en":"by chance; random","ru":"случайный; случайно","vi":"ngẫu nhiên","fa":"تصادفی","examples":[{"de":"Wir haben uns rein zufällig getroffen.","en":"We met purely by chance.","ru":"Мы встретились совершенно случайно.","vi":"Chúng tôi gặp nhau hoàn toàn tình cờ.","fa":"ما کاملا تصادفی با هم آشنا شدیم."},{"de":"Weißt du zufällig, wie spät es ist?","en":"Do you happen to know what time it is?","ru":"Ты, случайно, не знаешь, который час?","vi":"Bạn có biết bây giờ là mấy giờ không?","fa":"آیا می دانید ساعت چند است؟"}]},{"word":"zufrieden","en":"satisfied, content","ru":"довольный","vi":"hài lòng","fa":"راضی","examples":[{"de":"Ich bin mit meiner neuen Arbeit sehr zufrieden.","en":"I am very satisfied with my new job.","ru":"Я очень доволен своей новой работой.","vi":"Tôi rất hài lòng với công việc mới của tôi.","fa":"من از شغل جدیدم بسیار راضی هستم."},{"de":"Der Kunde war mit dem Service nicht zufrieden.","en":"The customer was not satisfied with the service.","ru":"Клиент был недоволен обслуживанием.","vi":"Khách hàng không hài lòng với dịch vụ.","fa":"مشتری از خدمات راضی نبود."}]},{"word":"die Zufriedenheit","en":"satisfaction; contentment","ru":"удовлетворённость; довольство","vi":"sự hài lòng","fa":"رضایت","examples":[{"de":"Die Zufriedenheit der Kunden ist uns wichtig.","en":"Customer satisfaction is important to us.","ru":"Удовлетворённость клиентов важна для нас.","vi":"Sự hài lòng của khách hàng là quan trọng đối với chúng tôi.","fa":"رضایت مشتری برای ما مهم است."},{"de":"Er strahlte vor Zufriedenheit.","en":"He was beaming with contentment.","ru":"Он сиял от довольства.","vi":"Anh cười rạng rỡ với sự hài lòng.","fa":"او از رضایت برق زد."}]},{"word":"der Zug","en":"train","ru":"поезд","vi":"tàu","fa":"قطار","examples":[{"de":"Der Zug nach München fährt um acht Uhr ab.","en":"The train to Munich departs at eight o'clock.","ru":"Поезд в Мюнхен отправляется в восемь часов.","vi":"Chuyến tàu tới Munich khởi hành lúc 8 giờ.","fa":"قطار به مونیخ ساعت هشت حرکت می کند."},{"de":"Ich habe den Zug verpasst.","en":"I missed the train.","ru":"Я опоздал на поезд.","vi":"Tôi đã lỡ chuyến tàu.","fa":"قطار را از دست دادم."}]},{"word":"der Zugang","en":"access","ru":"доступ","vi":"quyền truy cập","fa":"دسترسی","examples":[{"de":"Der Zugang zum Gebäude ist nur mit Ausweis möglich.","en":"Access to the building is only possible with an ID.","ru":"Доступ в здание возможен только с удостоверением личности.","vi":"Chỉ có thể vào tòa nhà bằng ID.","fa":"دسترسی به ساختمان فقط با شناسه امکان پذیر است."},{"de":"Wir haben keinen Zugang zum Internet.","en":"We have no access to the internet.","ru":"У нас нет доступа к интернету.","vi":"Chúng tôi không có quyền truy cập vào internet.","fa":"ما به اینترنت دسترسی نداریم"}]},{"word":"zugeben","en":"to admit","ru":"признавать","vi":"thừa nhận","fa":"اعتراف","examples":[{"de":"Er wollte seinen Fehler zuerst nicht zugeben.","en":"At first he didn't want to admit his mistake.","ru":"Сначала он не хотел признавать свою ошибку.","vi":"Lúc đầu anh ấy không muốn thừa nhận sai lầm của mình.","fa":"او ابتدا نمی خواست اشتباه خود را بپذیرد."},{"de":"Ich muss zugeben, dass du recht hattest.","en":"I have to admit that you were right.","ru":"Я должен признать, что ты был прав.","vi":"Tôi phải thừa nhận rằng bạn đã đúng.","fa":"باید اعتراف کنم که حق با شما بود."}]},{"word":"zugehen","en":"to close; to approach","ru":"закрываться; приближаться","vi":"cách tiếp cận","fa":"رویکرد","examples":[{"de":"Die Tür geht nicht richtig zu.","en":"The door doesn't close properly.","ru":"Дверь не закрывается как следует.","vi":"Cửa không đóng đúng cách.","fa":"در به درستی بسته نمی شود."},{"de":"Er ging langsam auf mich zu.","en":"He slowly approached me.","ru":"Он медленно подходил ко мне.","vi":"Anh ấy từ từ bước về phía tôi.","fa":"آهسته به سمتم رفت."}]},{"word":"das Zuhause","en":"home","ru":"дом, домашний очаг","vi":"ngôi nhà","fa":"خانه","examples":[{"de":"Nach der langen Reise war ich froh, wieder zu Hause zu sein.","en":"After the long journey I was happy to be home again.","ru":"После долгого путешествия я был рад снова оказаться дома.","vi":"Sau chuyến đi dài, tôi vui mừng được trở về nhà.","fa":"بعد از سفر طولانی، خوشحال شدم که دوباره به خانه برگشتم."},{"de":"Jedes Kind braucht ein sicheres Zuhause.","en":"Every child needs a safe home.","ru":"Каждому ребёнку нужен безопасный дом.","vi":"Mỗi đứa trẻ đều cần một ngôi nhà an toàn.","fa":"هر کودکی به یک خانه امن نیاز دارد."}]},{"word":"zuhören","en":"to listen","ru":"слушать","vi":"lắng nghe","fa":"گوش کن","examples":[{"de":"Bitte hör mir kurz zu.","en":"Please listen to me for a moment.","ru":"Пожалуйста, послушай меня минутку.","vi":"Xin hãy lắng nghe tôi một lát.","fa":"لطفا یک لحظه به من گوش کن"},{"de":"Er hört seinen Schülern immer aufmerksam zu.","en":"He always listens attentively to his students.","ru":"Он всегда внимательно слушает своих учеников.","vi":"Ông luôn lắng nghe cẩn thận các học trò của mình.","fa":"او همیشه با دقت به صحبت های شاگردانش گوش می دهد."}]},{"word":"die Zukunft","en":"future","ru":"будущее","vi":"tương lai","fa":"آینده","examples":[{"de":"Niemand weiß genau, was die Zukunft bringt.","en":"Nobody knows exactly what the future will bring.","ru":"Никто точно не знает, что принесёт будущее.","vi":"Không ai biết chính xác những gì tương lai sẽ mang lại.","fa":"هیچ کس دقیقاً نمی داند آینده چه چیزی را به همراه خواهد داشت."},{"de":"Sie plant ihre Zukunft sehr sorgfältig.","en":"She plans her future very carefully.","ru":"Она очень тщательно планирует своё будущее.","vi":"Cô ấy lên kế hoạch cho tương lai của mình rất cẩn thận.","fa":"او با دقت زیادی برای آینده خود برنامه ریزی می کند."}]},{"word":"zukünftig","en":"future (adj.)","ru":"будущий","vi":"trong tương lai","fa":"در آینده","examples":[{"de":"Mein zukünftiger Mann kommt aus Spanien.","en":"My future husband is from Spain.","ru":"Мой будущий муж родом из Испании.","vi":"Chồng tương lai của tôi đến từ Tây Ban Nha.","fa":"شوهر آینده من اهل اسپانیا است."},{"de":"Zukünftig werde ich früher aufstehen.","en":"In the future I will get up earlier.","ru":"В будущем я буду вставать раньше.","vi":"Trong tương lai tôi sẽ dậy sớm hơn.","fa":"در آینده زودتر بیدار خواهم شد."}]},{"word":"zuletzt","en":"last, finally","ru":"в конце концов, напоследок","vi":"cuối cùng","fa":"آخرین","examples":[{"de":"Zuletzt möchte ich mich bei allen bedanken.","en":"Finally, I would like to thank everyone.","ru":"Напоследок я хотел бы поблагодарить всех.","vi":"Cuối cùng tôi xin gửi lời cảm ơn tới tất cả mọi người.","fa":"در آخر از همه تشکر می کنم."},{"de":"Wann hast du sie zuletzt gesehen?","en":"When did you last see her?","ru":"Когда ты видел её в последний раз?","vi":"Lần cuối cùng bạn nhìn thấy cô ấy là khi nào?","fa":"آخرین بار کی او را دیدی؟"}]},{"word":"zumachen","en":"to close","ru":"закрывать","vi":"đóng","fa":"بستن","examples":[{"de":"Kannst du bitte das Fenster zumachen?","en":"Can you please close the window?","ru":"Ты можешь, пожалуйста, закрыть окно?","vi":"Bạn có thể vui lòng đóng cửa sổ được không?","fa":"میشه لطفا پنجره رو ببندید؟"},{"de":"Der Laden macht um achtzehn Uhr zu.","en":"The shop closes at six p.m.","ru":"Магазин закрывается в шесть вечера.","vi":"Cửa hàng đóng cửa lúc 6 giờ chiều.","fa":"ساعت 6 عصر مغازه بسته می شود."}]},{"word":"zumindest","en":"at least","ru":"по крайней мере","vi":"ít nhất","fa":"حداقل","examples":[{"de":"Wir sollten zumindest versuchen, pünktlich zu sein.","en":"We should at least try to be on time.","ru":"Нам следует хотя бы попытаться быть вовремя.","vi":"Ít nhất chúng ta nên cố gắng đến đúng giờ.","fa":"حداقل باید سعی کنیم به موقع برسیم."},{"de":"Er hat zumindest angerufen, um sich zu entschuldigen.","en":"He at least called to apologize.","ru":"Он хотя бы позвонил, чтобы извиниться.","vi":"Ít nhất thì anh ấy cũng gọi điện để xin lỗi.","fa":"حداقل زنگ زد تا عذرخواهی کند."}]},{"word":"zunächst","en":"first of all, for now","ru":"сначала, прежде всего","vi":"ban đầu","fa":"در ابتدا","examples":[{"de":"Zunächst möchte ich Ihnen unser Team vorstellen.","en":"First of all, I would like to introduce our team to you.","ru":"Прежде всего я хотел бы представить вам нашу команду.","vi":"Trước hết, tôi muốn giới thiệu đội ngũ của chúng tôi với bạn.","fa":"اول از همه می خواهم تیم ما را به شما معرفی کنم."},{"de":"Zunächst bleibt alles beim Alten.","en":"For now, everything stays the same.","ru":"Пока всё остаётся по-старому.","vi":"Lúc đầu mọi thứ vẫn như cũ.","fa":"در ابتدا همه چیز ثابت می ماند."}]},{"word":"die Zünder","en":"detonator, fuse","ru":"запал, детонатор","vi":"ngòi nổ","fa":"چاشنی ها","examples":[{"de":"Die Feuerwerkskörper haben einen empfindlichen Zünder.","en":"The fireworks have a sensitive fuse.","ru":"У этих фейерверков чувствительный запал.","vi":"Pháo hoa có bộ phận đánh lửa nhạy cảm.","fa":"آتش بازی دارای یک محترقه حساس است."},{"de":"Die Polizei fand mehrere Zünder in der Fabrik.","en":"The police found several detonators in the factory.","ru":"Полиция нашла несколько детонаторов на фабрике.","vi":"Cảnh sát tìm thấy một số ngòi nổ trong nhà máy.","fa":"پلیس چندین چاشنی را در کارخانه پیدا کرد."}]},{"word":"das Zündholz","en":"match","ru":"спичка","vi":"trận đấu","fa":"مسابقه","examples":[{"de":"Hast du ein Zündholz, um die Kerze anzuzünden?","en":"Do you have a match to light the candle?","ru":"У тебя есть спичка, чтобы зажечь свечу?","vi":"Bạn có diêm để thắp nến không?","fa":"آیا برای روشن کردن شمع کبریت دارید؟"},{"de":"Die Zündhölzer liegen in der Küchenschublade.","en":"The matches are in the kitchen drawer.","ru":"Спички лежат в кухонном ящике.","vi":"Que diêm ở trong ngăn kéo nhà bếp.","fa":"کبریت ها در کشوی آشپزخانه هستند."}]},{"word":"zunehmen","en":"to gain weight; to increase","ru":"набирать вес; увеличиваться","vi":"tăng lên","fa":"افزایش دهد","examples":[{"de":"Im Urlaub habe ich leider drei Kilo zugenommen.","en":"Unfortunately I gained three kilos on vacation.","ru":"К сожалению, во время отпуска я набрал три килограмма.","vi":"Thật không may, tôi đã tăng ba kg trong kỳ nghỉ của mình.","fa":"متأسفانه در تعطیلاتم سه کیلو اضافه وزن پیدا کردم."},{"de":"Die Zahl der Touristen nimmt jedes Jahr zu.","en":"The number of tourists increases every year.","ru":"Число туристов увеличивается каждый год.","vi":"Số lượng khách du lịch đang tăng lên hàng năm.","fa":"هر سال بر تعداد گردشگران افزوده می شود."}]},{"word":"zurechtkommen","en":"to cope, to manage","ru":"справляться","vi":"đối phó","fa":"کنار آمدن","examples":[{"de":"Kommst du mit dem neuen Programm gut zurecht?","en":"Are you coping well with the new program?","ru":"Ты хорошо справляешься с новой программой?","vi":"Bạn có hòa nhập tốt với chương trình mới không?","fa":"آیا با برنامه جدید به خوبی کنار می آیید؟"},{"de":"Sie kommt mit wenig Geld gut zurecht.","en":"She manages well with little money.","ru":"Она хорошо справляется с небольшими деньгами.","vi":"Cô ấy sống tốt với ít tiền.","fa":"او با پول کم به خوبی کنار می آید."}]},{"word":"zurück","en":"back","ru":"назад, обратно","vi":"trở lại","fa":"برگشت","examples":[{"de":"Wann kommst du von der Arbeit zurück?","en":"When are you coming back from work?","ru":"Когда ты вернёшься с работы?","vi":"Khi nào bạn đi làm về?","fa":"کی از سر کار برمیگردی؟"},{"de":"Ich gebe dir das Buch morgen zurück.","en":"I'll give the book back to you tomorrow.","ru":"Я верну тебе книгу завтра.","vi":"Tôi sẽ trả lại bạn cuốn sách vào ngày mai.","fa":"کتاب را فردا به شما پس می دهم."}]},{"word":"zurzeit","en":"currently, at the moment","ru":"в настоящее время, сейчас","vi":"hiện tại","fa":"در حال حاضر","examples":[{"de":"Zurzeit arbeite ich an einem neuen Projekt.","en":"I am currently working on a new project.","ru":"Сейчас я работаю над новым проектом.","vi":"Tôi hiện đang làm việc trên một dự án mới.","fa":"من در حال حاضر روی یک پروژه جدید کار می کنم."},{"de":"Zurzeit ist sie im Urlaub.","en":"At the moment she is on vacation.","ru":"В настоящее время она в отпуске.","vi":"Cô ấy hiện đang đi nghỉ.","fa":"او در حال حاضر در تعطیلات است."}]},{"word":"zusagen","en":"to accept (an invitation); to promise","ru":"соглашаться, обещать","vi":"lời hứa","fa":"قول دادن","examples":[{"de":"Ich habe der Einladung schon zugesagt.","en":"I have already accepted the invitation.","ru":"Я уже принял приглашение.","vi":"Tôi đã chấp nhận lời mời rồi.","fa":"من قبلا دعوت را پذیرفته ام."},{"de":"Er hat mir zugesagt, pünktlich zu kommen.","en":"He promised me to come on time.","ru":"Он пообещал мне прийти вовремя.","vi":"Anh ấy hứa với tôi rằng anh ấy sẽ đến đúng giờ.","fa":"او به من قول داد که به موقع بیاید."}]},{"word":"zusammen","en":"together","ru":"вместе","vi":"cùng với nhau","fa":"با هم","examples":[{"de":"Wir kochen heute Abend zusammen.","en":"We are cooking together tonight.","ru":"Сегодня вечером мы готовим вместе.","vi":"Tối nay chúng ta cùng nấu ăn nhé.","fa":"امشب با هم آشپزی می کنیم."},{"de":"Sie leben seit fünf Jahren zusammen.","en":"They have been living together for five years.","ru":"Они живут вместе уже пять лет.","vi":"Họ đã sống với nhau được năm năm.","fa":"آنها پنج سال است که با هم زندگی می کنند."}]},{"word":"der Zusammenhang","en":"context, connection","ru":"связь, контекст","vi":"sự kết nối","fa":"اتصال","examples":[{"de":"Ich verstehe den Zusammenhang zwischen diesen beiden Ereignissen nicht.","en":"I don't understand the connection between these two events.","ru":"Я не понимаю связь между этими двумя событиями.","vi":"Tôi không hiểu mối liên hệ giữa hai sự kiện này.","fa":"من ارتباط بین این دو رویداد را درک نمی کنم."},{"de":"In diesem Zusammenhang ist der Bericht sehr wichtig.","en":"In this context, the report is very important.","ru":"В этом контексте отчёт очень важен.","vi":"Trong bối cảnh này, báo cáo là rất quan trọng.","fa":"در این زمینه، گزارش بسیار مهم است."}]},{"word":"zusätzlich","en":"additional","ru":"дополнительный","vi":"thêm vào đó","fa":"علاوه بر این","examples":[{"de":"Wir brauchen zusätzliche Informationen.","en":"We need additional information.","ru":"Нам нужна дополнительная информация.","vi":"Chúng tôi cần thêm thông tin.","fa":"به اطلاعات تکمیلی نیاز داریم"},{"de":"Für den Kurs fallen zusätzliche Kosten an.","en":"Additional costs arise for the course.","ru":"За курс взимаются дополнительные расходы.","vi":"Có thêm chi phí cho khóa học.","fa":"هزینه های اضافی برای دوره وجود دارد."}]},{"word":"zuschauen","en":"to watch, to look on","ru":"наблюдать, смотреть","vi":"xem","fa":"تماشا کن","examples":[{"de":"Die Kinder schauen den Vögeln im Park zu.","en":"The children are watching the birds in the park.","ru":"Дети наблюдают за птицами в парке.","vi":"Bọn trẻ ngắm chim trong công viên.","fa":"بچه ها در پارک به تماشای پرندگان می پردازند."},{"de":"Ich schaue gern zu, wie meine Mutter kocht.","en":"I like watching my mother cook.","ru":"Я люблю смотреть, как моя мама готовит.","vi":"Tôi thích xem mẹ nấu ăn.","fa":"من دوست دارم مادرم را ببینم که آشپزی می کند."}]},{"word":"der Zuschlag","en":"surcharge","ru":"доплата, надбавка","vi":"phụ phí","fa":"هزینه اضافی","examples":[{"de":"Für den Schnellzug musst du einen Zuschlag zahlen.","en":"You have to pay a surcharge for the express train.","ru":"За скоростной поезд нужно доплатить.","vi":"Bạn phải trả phụ phí cho tàu tốc hành.","fa":"برای قطار سریع السیر باید هزینه اضافی بپردازید."},{"de":"Am Wochenende gibt es einen Zuschlag auf den Preis.","en":"There is a surcharge on the price on weekends.","ru":"По выходным есть надбавка к цене.","vi":"Có một khoản phụ phí vào giá vào cuối tuần.","fa":"در تعطیلات آخر هفته هزینه اضافی برای قیمت وجود دارد."}]},{"word":"der Zustand","en":"condition, state","ru":"состояние","vi":"điều kiện","fa":"شرط","examples":[{"de":"Das Auto ist in einem guten Zustand.","en":"The car is in good condition.","ru":"Машина в хорошем состоянии.","vi":"Chiếc xe đang trong tình trạng tốt.","fa":"ماشین در وضعیت خوبی است."},{"de":"Der Patient befindet sich in einem stabilen Zustand.","en":"The patient is in a stable condition.","ru":"Пациент находится в стабильном состоянии.","vi":"Bệnh nhân đang trong tình trạng ổn định.","fa":"وضعیت بیمار پایدار است."}]},{"word":"zuständig","en":"responsible (for)","ru":"ответственный (за)","vi":"chịu trách nhiệm","fa":"مسئول","examples":[{"de":"Wer ist für diese Abteilung zuständig?","en":"Who is responsible for this department?","ru":"Кто отвечает за этот отдел?","vi":"Ai chịu trách nhiệm về bộ phận này?","fa":"چه کسی مسئول این بخش است؟"},{"de":"Dafür bin ich nicht zuständig.","en":"I am not responsible for that.","ru":"За это я не отвечаю.","vi":"Tôi không chịu trách nhiệm về điều đó.","fa":"من مسئول آن نیستم."}]},{"word":"zustimmen","en":"to agree","ru":"соглашаться","vi":"đồng ý","fa":"موافق","examples":[{"de":"Ich stimme deinem Vorschlag zu.","en":"I agree with your proposal.","ru":"Я согласен с твоим предложением.","vi":"Tôi đồng ý với đề nghị của bạn.","fa":"من با پیشنهاد شما موافقم"},{"de":"Die Eltern müssen dem Ausflug zustimmen.","en":"The parents have to agree to the trip.","ru":"Родители должны согласиться на поездку.","vi":"Cha mẹ phải đồng ý cho chuyến tham quan.","fa":"والدین باید با سفر موافقت کنند."}]},{"word":"die Zutaten","en":"ingredients","ru":"ингредиенты","vi":"các thành phần","fa":"مواد تشکیل دهنده","examples":[{"de":"Welche Zutaten brauchen wir für den Kuchen?","en":"What ingredients do we need for the cake?","ru":"Какие ингредиенты нам нужны для торта?","vi":"Làm bánh chúng ta cần những nguyên liệu gì?","fa":"چه موادی برای کیک لازم داریم؟"},{"de":"Alle Zutaten liegen schon auf dem Tisch.","en":"All the ingredients are already on the table.","ru":"Все ингредиенты уже на столе.","vi":"Tất cả nguyên liệu đã có sẵn trên bàn.","fa":"همه مواد از قبل روی میز هستند."}]},{"word":"zuverlässig","en":"reliable","ru":"надёжный","vi":"đáng tin cậy","fa":"قابل اعتماد","examples":[{"de":"Mein Kollege ist sehr zuverlässig.","en":"My colleague is very reliable.","ru":"Мой коллега очень надёжный.","vi":"Đồng nghiệp của tôi rất đáng tin cậy.","fa":"همکار من بسیار قابل اعتماد است."},{"de":"Wir suchen einen zuverlässigen Babysitter.","en":"We are looking for a reliable babysitter.","ru":"Мы ищем надёжную няню.","vi":"Chúng tôi đang tìm kiếm một người giữ trẻ đáng tin cậy.","fa":"ما به دنبال یک پرستار کودک مطمئن هستیم."}]},{"word":"zwar","en":"indeed, admittedly","ru":"правда, хотя","vi":"mặc dù","fa":"اگرچه","examples":[{"de":"Er ist zwar müde, aber er arbeitet trotzdem weiter.","en":"He is indeed tired, but he keeps working anyway.","ru":"Он, правда, устал, но всё равно продолжает работать.","vi":"Anh ấy có thể mệt mỏi nhưng vẫn tiếp tục làm việc.","fa":"او ممکن است خسته باشد، اما همچنان به کارش ادامه می دهد."},{"de":"Das Kleid ist zwar teuer, aber sehr schön.","en":"The dress is admittedly expensive, but very beautiful.","ru":"Платье, конечно, дорогое, но очень красивое.","vi":"Chiếc váy đắt tiền nhưng rất đẹp.","fa":"لباس گران است، اما بسیار زیبا است."}]},{"word":"der Zweck","en":"purpose","ru":"цель, назначение","vi":"mục đích","fa":"هدف","examples":[{"de":"Was ist der Zweck dieses Treffens?","en":"What is the purpose of this meeting?","ru":"Какова цель этой встречи?","vi":"Mục đích của cuộc họp này là gì?","fa":"هدف از این جلسه چیست؟"},{"de":"Dieses Gerät dient einem bestimmten Zweck.","en":"This device serves a specific purpose.","ru":"Это устройство служит определённой цели.","vi":"Thiết bị này phục vụ một mục đích cụ thể.","fa":"این دستگاه هدف خاصی را دنبال می کند."}]},{"word":"der Zweifel","en":"doubt","ru":"сомнение","vi":"sự nghi ngờ","fa":"شک","examples":[{"de":"Ich habe keinen Zweifel an seiner Ehrlichkeit.","en":"I have no doubt about his honesty.","ru":"У меня нет сомнений в его честности.","vi":"Tôi không nghi ngờ gì về sự trung thực của anh ấy.","fa":"در صداقتش شک ندارم."},{"de":"Ohne Zweifel ist das die beste Lösung.","en":"Without doubt, this is the best solution.","ru":"Без сомнения, это лучшее решение.","vi":"Không còn nghi ngờ gì nữa, đây là giải pháp tốt nhất.","fa":"بدون شک این بهترین راه حل است."}]},{"word":"zweifeln","en":"to doubt","ru":"сомневаться","vi":"nghi ngờ","fa":"شک","examples":[{"de":"Ich zweifle, ob er die Wahrheit sagt.","en":"I doubt whether he is telling the truth.","ru":"Я сомневаюсь, говорит ли он правду.","vi":"Tôi nghi ngờ liệu anh ấy có nói sự thật hay không.","fa":"من شک دارم که راست می گوید."},{"de":"Sie zweifelt manchmal an sich selbst.","en":"She sometimes doubts herself.","ru":"Она иногда сомневается в себе.","vi":"Đôi khi cô nghi ngờ chính mình.","fa":"او گاهی اوقات به خودش شک می کند."}]},{"word":"die Zwiebel","en":"onion","ru":"лук (репчатый)","vi":"củ hành","fa":"پیاز","examples":[{"de":"Für die Suppe brauche ich zwei Zwiebeln.","en":"I need two onions for the soup.","ru":"Для супа мне нужны две луковицы.","vi":"Tôi cần hai củ hành cho món súp.","fa":"برای سوپ دو عدد پیاز لازم دارم."},{"de":"Beim Schneiden der Zwiebel musste ich weinen.","en":"I had to cry while cutting the onion.","ru":"Я плакал, когда резал лук.","vi":"Tôi đã khóc khi cắt hành tây.","fa":"در حین بریدن پیاز گریه کردم."}]},{"word":"zwischen","en":"between","ru":"между","vi":"giữa","fa":"بین","examples":[{"de":"Das Café liegt zwischen der Bank und der Post.","en":"The café is located between the bank and the post office.","ru":"Кафе находится между банком и почтой.","vi":"Quán cà phê nằm giữa ngân hàng và bưu điện.","fa":"کافه بین بانک و اداره پست قرار دارد."},{"de":"Zwischen den beiden Ländern gibt es gute Beziehungen.","en":"There are good relations between the two countries.","ru":"Между этими двумя странами хорошие отношения.","vi":"Có mối quan hệ tốt đẹp giữa hai nước.","fa":"روابط خوبی بین دو کشور وجود دارد."}]}];
